/****** Object:  StoredProcedure [dbo].[Plan_ActivitySearch_sp]    Script Date: 2026/03/10 7:23:24 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO



-- =============================================
-- Author:		Chris Moodley
-- Create date: 11 August 2014
-- Description:	Search for activities
-- Modifications:
-- 20180426 by CM: Return dates as date time 
-- =============================================
CREATE PROCEDURE [dbo].[Plan_ActivitySearch_sp] 
	-- Add the parameters for the stored procedure here
	@activityID INT,	
	@idpItemID INT,
	@responsiblePersonID INT,
	@startDate DATETIME,
	@endDate DATETIME

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	SELECT 
		 activity.Activity_ID
		,activity.IDPItemID
		,item.ItemDesc
		,activity.ActivityDesc
		,activity.ActivityEndDate AS EndDate  
		,activity.ActivityStartDate AS StartDate 
		,employee.FirstName + ' ' + employee.Surname AS ResponsiblePerson
	FROM 
		Plan_Activity activity LEFT JOIN 
			IDP_Item item ON
				activity.IDPItemID = item.Item_ID LEFT JOIN
			Payroll_Employee employee ON 
				activity.ResponsiblePersonID = employee.Employee_ID
	WHERE 
		((DATEDIFF(d, @startDate, activity.ActivityEndDate) >= 0) OR (@startDate = '')) AND  
		((DATEDIFF(d, @endDate, activity.ActivityEndDate) <= 0) OR (@endDate = '')) AND 
		((Activity_ID = @activityID) OR (@activityID = 0 )) AND
		((IDPItemID = @idpItemID) OR (@idpItemID = 0)) AND
		((ResponsiblePersonID = @responsiblePersonID)  OR (@responsiblePersonID = 0)) 
		
END



GO

/****** Object:  StoredProcedure [dbo].[Plan_ActualProcurementPlanVsBudgetRpt_sp]    Script Date: 2026/03/10 7:23:25 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 31/03/2016
-- Description:	SSRS Report - The Annual Procurement Plan - Actual versus Budget.
-- calls : Plan_ActualProcurementPlanVsBudgetRpt_sp '2018/2019',0,2499,24
-- 14-08-2017 SNagpal: 60572 Add query to get CapitaloperationTypes from Const_PlanCapitalOperationalTypes_sys
-- 29-08-2018 SNagpal: 77728 Remove LEFT JOIN dbo.SCM_Requisition & Add LEFT JOIN dbo.SCM_RequisitionServiceDetails 
-- 10-10-2018 SNagpal: 80434 Comment condition getting actual based upon project i.e. p.Project_ID = @ProjectNumber. It should be based upon PlanprojectItem
-- 10-10-2018 SNagpal: 80434 Add group by with ppi.PlanProjectItem_Id and remove Sum(BudgetAmount) it should be BudgetAmount, Remove left join of SCM_ServiceInvoice
-- 10-10-2018 SNagpal: 80434 Add extra condition of AND gl.PlanProjectItemID = ppi.PlanProjectItem_Id & ExtraLinkDesc='SCM Invoice' with Led_GeneralLedger
-- 21-01-2019 SNagpal: 83558 Remove Unncessary Join which use to getting Ledger details. Direct Join of PlanProjectItem 
						--WITH gl.PlanProjectItemID = ppi.PlanProjectItem_Id & ExtraLinkDesc='SCM Invoice' with Led_GeneralLedger
-- 10-12-2019 Volodymyr Stovba: 7334 CR_Project Code Change throughout system_SCM Screens as per document attached. Added ProjectNameWithCode.
-- 04-02-2020 Volodymyr Stovba: 27190 Alpha02: Please add a space between the project code and the pipe and the pipe and project name 
-- =============================================
CREATE PROCEDURE [dbo].[Plan_ActualProcurementPlanVsBudgetRpt_sp]
	@FinYear NVARCHAR(10),
	@ProcurementPlanNumber INT = 0,
	@ProjectNumber INT = 0,
	@StatusID INT = 0
AS
BEGIN


SELECT ppn.ProcurementPlan_ID,ppn.ProcurmentStatemnet, p.Project_ID, p.ProjectName, LTRIM(STR(p.ProjectCode))+' | '+p.ProjectName as ProjectNameWithCode ,cs.StatusDesc as ProjectStatus,ppi.PlanProjectItem_Id,
 ( SELECT    TypeName
   FROM      dbo.Const_PlanCapitalOperationalTypes_sys
   WHERE     TypeValue = p.CapitalOperation) AS CapitalOperation ,
  
ISNULL(BudgetAmount,0) AS BudgetAmount,
ppd.EstimatedCost, 
 ISNULL(SUM(gl.debit),0) AS ActualBudget,
(ISNULL(BudgetAmount,0) - ISNULL(SUM(gl.debit),0)) AS DiffBudgetAmount,
(ppd.EstimatedCost - ISNULL(SUM(gl.debit),0)) AS DiffPlanActual

FROM Plan_Project p
INNER JOIN Plan_ProjectItem ppi ON p.Project_ID = ppi.ProjectID
INNER JOIN SCM_ProcurementPlanNew ppn ON p.Project_ID = ppn.PlanProjectID
INNER JOIN SCM_ProcurementPlanDetails ppd ON ppn.ProcurementPlan_ID = ppd.ProcurementPlanID AND ppd.PlanProjectItemID = ppi.PlanProjectItem_Id
----LEFT JOIN dbo.SCM_Requisition sr ON ppn.ProcurementPlan_ID = sr.ProcurementID
--LEFT JOIN dbo.SCM_RequisitionServiceDetails sr ON ppd.PlanProjectItemID = sr.PlanProjectItemId
--LEFT JOIN dbo.SCM_QuotationRequistion sqr ON sr.RequisitionID = sqr.RequisitionID
--LEFT JOIN dbo.SCM_Tender st ON sqr.RequisitionID = st.RequisitionID
--LEFT JOIN dbo.SCM_Order so ON (st.Tender_ID = so.TenderId or sqr.QuotationID = so.QuotationId)
--LEFT JOIN dbo.SCM_Invoice si ON so.Order_ID = si.OrderID 
--LEFT Join dbo.Led_GeneralLedger gl ON si.Invoice_ID=gl.ExtraLinkID_1 AND gl.PlanProjectItemID = ppi.PlanProjectItem_Id AND ExtraLinkDesc='SCM Invoice'
LEFT Join dbo.Led_GeneralLedger gl ON gl.PlanProjectItemID = ppi.PlanProjectItem_Id AND ExtraLinkDesc='SCM Invoice'
LEFT Join dbo.Const_Status cs ON p.ProjectStatus=cs.Status_ID
WHERE p.FinYear=@FinYear AND
(ppn.ProcurementPlan_ID = @ProcurementPlanNumber or @ProcurementPlanNumber = 0)
--AND  (p.Project_ID = @ProjectNumber or @ProjectNumber = 0)
AND  (ppi.planProjectItem_Id = @ProjectNumber or @ProjectNumber = 0)
AND  (p.ProjectStatus = @StatusID or @StatusID = 0) 
GROUP BY ppn.ProcurementPlan_ID,ppn.ProcurmentStatemnet, 
p.Project_ID, p.ProjectName,p.ProjectCode,cs.StatusDesc,p.CapitalOperation, ppn.PlanProjectID,ppn.FinYear,
ppd.EstimatedCost,ppi.PlanProjectItem_Id, ppi.BudgetAmount
END
GO

/****** Object:  StoredProcedure [dbo].[Plan_AdjustmentFundingSourceBudget_sp]    Script Date: 2026/03/10 7:23:25 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- ==============================================================
-- Author:  Nirav Parikh
-- Create date: 13 November 2017
-- Description: Return Adjustment funding source budgets per financial year
-- Plan_AdjustmentFundingSourceBudget_sp '2018/2019', '2018/2019'
-- 11-Apr-18 : 70718 Add where condition for   AND fundBudgetHeader.AdjustmentFundingVersionId = @AdjustmentFundingVersionId;
-- SNagpal 17-05-2019: Add new MultiYear concept
-- ==============================================================
CREATE PROCEDURE [dbo].[Plan_AdjustmentFundingSourceBudget_sp]
    @financialYear NVARCHAR(50),
    @UserFinYear NVARCHAR(10)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @AdjustmentFundingVersionId INT;

    SELECT TOP 1
        @AdjustmentFundingVersionId = AdjustmentFundingBudgetVersion_ID
    FROM Plan_AdjustmentFundingBudgetVersion
    WHERE VersionName LIKE @UserFinYear + '%'
    ORDER BY AdjustmentFundingBudgetVersion_ID DESC;

    SELECT fundBudgetHeader.AdjustmentFundingSourceBudgetHeader_ID,
           fundBudgetDetail.AdjustmentFundingSourceBudgetDetail_ID,
           fundBudgetHeader.FinancialYear,
           fundBudgetDetail.AdjustmentFundingSourceID,
           ISNULL(fundSource.FundingSourceDesc, '') AS FundingSourceDesc,
           fundBudgetDetail.ScoaID,
           scoaFund.ScoaCode,
           scoaFund.ScoaDesc,
           fundBudgetDetail.FundingSourceBudget,
           scoaFund.ScoaShortDesc,
           fundBudgetHeader.Submitted
    FROM dbo.Plan_AdjustmentFundingSourceBudget_Header fundBudgetHeader
        LEFT JOIN dbo.Plan_AdjustmentFundingSourceBudget_Detail fundBudgetDetail
            ON fundBudgetHeader.AdjustmentFundingSourceBudgetHeader_ID = fundBudgetDetail.AdjustmentFundingSourceBudgetHeaderID
        LEFT JOIN Const_FundingSource fundSource
            ON fundBudgetDetail.AdjustmentFundingSourceID = fundSource.FundingSource_ID
        INNER JOIN dbo.Const_Scoa_Funds_Structure_ByYear(@UserFinYear) scoaFund
            ON fundBudgetDetail.ScoaID = scoaFund.ScoaID
    WHERE (
              FinancialYear = @financialYear
              OR ISNULL(fundBudgetHeader.FinancialYear, '') = ISNULL(
                                                                        @financialYear,
                                                                        ISNULL(fundBudgetHeader.FinancialYear, '')
                                                                    )
          )
          AND fundBudgetDetail.AdjustmentFundingVersionId = @AdjustmentFundingVersionId
		  AND fundBudgetHeader.AdjustmentFundingVersionId = @AdjustmentFundingVersionId;
END;


GO

/****** Object:  StoredProcedure [dbo].[Plan_AdjustmentFundingSourceBudgetMultiYear_sp]    Script Date: 2026/03/10 7:23:25 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- ==============================================================
-- Author:    Nirav Parikh
-- Create date: 13 Nov 2017
-- Plan_AdjustmentFundingSourceBudgetMultiYear_sp '2016/2017',0,'2016/2017'
-- SNagpal 22-Jan-2018 : Fix various issues in SP related to versioning and Plan_GetAdjustmentFundAllocatedAmount_fxn
-- RChetty 02-Feb-2018 : Issue with outer month budget if FundingSource is null fixed.
-- 05 Apr 2018 SNagpal: 70472 Inner join with Plan_AdjustmentProject & Plan_AdjustmentFundingSourceBudget_Detail to get related Verion
-- 23 Apr 2019 SNagpal: 89170 Update Const_Scoa_Funds_Structure by Const_Scoa_Funds_Structure_ByYear to get Multiyear based desc
-- ==============================================================
CREATE PROCEDURE [dbo].[Plan_AdjustmentFundingSourceBudgetMultiYear_sp]
    @FinYear NVARCHAR(50),
    @ShowOnlyZerovaluedFunds INT = 0,
    @UserFinYear NVARCHAR(10)
AS
BEGIN
    SET NOCOUNT ON;
		DECLARE @AdjustmentVersionId INT, @AdjustmentFundingVersionId INT;

		SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion papv
		INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentVersionId = papv.AdjustmentBudgetVersion_ID
		WHERE VersionName LIKE @UserFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

    SELECT TOP 1
        @AdjustmentFundingVersionId = AdjustmentFundingBudgetVersion_ID FROM Plan_AdjustmentFundingBudgetVersion papv
		INNER JOIN dbo.Plan_AdjustmentFundingSourceBudget_Detail pap ON pap.AdjustmentFundingVersionId = papv.AdjustmentFundingBudgetVersion_ID
         WHERE VersionName LIKE @UserFinYear + '%' ORDER BY AdjustmentFundingBudgetVersion_ID DESC;

    DECLARE @FinYearP1 NVARCHAR(9),
            @FinYearP2 NVARCHAR(9),
            @yearp1 INT,
            @yearp2 INT,
            @yearp3 INT;

    SELECT @yearp1 = CAST(SUBSTRING(@FinYear, 6, 4) AS INT);
    SELECT @yearp2 = @yearp1 + 1;
    SELECT @yearp3 = @yearp1 + 2;
    SELECT @FinYearP1 = CONVERT(VARCHAR(4), @yearp1) + '/' + CONVERT(VARCHAR(4), @yearp2);
    SELECT @FinYearP2 = CONVERT(VARCHAR(4), @yearp2) + '/' + CONVERT(VARCHAR(4), @yearp3);

    SELECT *,
           (ISNULL(FundDetails.FundingSourceBudget, 0) - ISNULL(FundDetails.AllocatedCurrFinYear, 0)) AS RemainingCurrFinYear,
           (ISNULL(FundDetails.FundingSourceBudgetCurrYearPlus1, 0) - ISNULL(FundDetails.AllocatedCurrYearPlus1, 0)) AS RemainingCurrFinYearPlus1,
           (ISNULL(FundDetails.FundingSourceBudgetCurrYearPlus2, 0) - ISNULL(FundDetails.AllocatedCurrYearPlus2, 0)) AS RemainingCurrFinYearPlus2
    FROM
    (
        SELECT currentYear.RefFundingSourceDetailId,
				currentYear.AdjustmentFundingSourceBudgetHeader_ID,
               currentYear.AdjustmentFundingSourceBudgetDetail_ID,
               currentYear.FinancialYear,
               currentYear.AdjustmentFundingSourceID,
               ISNULL(currentYear.FundingSourceDesc, '') AS FundingSourceDesc,
               currentYear.ScoaID,
               currentYear.ScoaCode,
               currentYear.ScoaDesc,
               currentYear.FundingSourceBudget,
               dbo.Plan_GetAdjustmentFundAllocatedAmount_fxn(
                                                     currentYear.ScoaID,
                                                     currentYear.FinancialYear,
                                                     currentYear.FinancialYear,@AdjustmentVersionId
                                                 ) AS AllocatedCurrFinYear,
               currentYear.ScoaShortDesc,
               ISNULL(currentYear.Submitted, 0) AS Submitted,
               currentYear.UploadedDocument AS UploadedDocument,
               @FinYearP1 AS FinancialYearCurrYearPlus1,
               ISNULL(
               (
                   SELECT SUM(D.FundingSourceBudget)
                   FROM dbo.Plan_AdjustmentFundingSourceBudget_Detail AS D
                       INNER JOIN dbo.Plan_AdjustmentFundingSourceBudget_Header AS H
                           ON D.AdjustmentFundingSourceBudgetHeaderID = H.AdjustmentFundingSourceBudgetHeader_ID
                              AND H.FinancialYear = @FinYearP1
                              AND ISNULL(D.AdjustmentFundingSourceID,0) = ISNULL(currentYear.AdjustmentFundingSourceID,0)
                              AND D.ScoaID = currentYear.ScoaID
							  AND D.AdjustmentFundingVersionId = @AdjustmentFundingVersionId
							  AND H.AdjustmentFundingVersionId = @AdjustmentFundingVersionId
                   GROUP BY D.AdjustmentFundingSourceBudgetHeaderID,
      D.AdjustmentFundingSourceID,
                            D.ScoaID
               ),
               0
                     ) AS FundingSourceBudgetCurrYearPlus1,
               dbo.Plan_GetAdjustmentFundAllocatedAmount_fxn(currentYear.ScoaID, @FinYearP1, currentYear.FinancialYear,@AdjustmentVersionId) AS AllocatedCurrYearPlus1,
               @FinYearP2 AS FinancialYearCurrYearPlus2,
               ISNULL(
               (
                   SELECT SUM(D.FundingSourceBudget)
                   FROM dbo.Plan_AdjustmentFundingSourceBudget_Detail AS D
                       INNER JOIN dbo.Plan_AdjustmentFundingSourceBudget_Header AS H
                           ON D.AdjustmentFundingSourceBudgetHeaderID = H.AdjustmentFundingSourceBudgetHeader_ID
                              AND H.FinancialYear = @FinYearP2
                              AND ISNULL(D.AdjustmentFundingSourceID,0) = ISNULL(currentYear.AdjustmentFundingSourceID,0)
                              AND D.ScoaID = currentYear.ScoaID
							  AND D.AdjustmentFundingVersionId = @AdjustmentFundingVersionId
							  AND H.AdjustmentFundingVersionId = @AdjustmentFundingVersionId
                   GROUP BY D.AdjustmentFundingSourceBudgetHeaderID,
                            D.AdjustmentFundingSourceID,
                            D.ScoaID
               ),
               0
                     ) AS FundingSourceBudgetCurrYearPlus2,
               dbo.Plan_GetAdjustmentFundAllocatedAmount_fxn(currentYear.ScoaID, @FinYearP2, currentYear.FinancialYear,@AdjustmentVersionId) AS AllocatedCurrYearPlus2,
               (
                   SELECT Value FROM dbo.Split_fxn(currentYear.ScoaDesc, ':') WHERE ID = 2
               ) AS Category
        FROM
        (
            SELECT fundBudgetDetail.RefFundingSourceDetailId,
			fundBudgetHeader.AdjustmentFundingSourceBudgetHeader_ID,
                   fundBudgetDetail.AdjustmentFundingSourceBudgetDetail_ID,
                   fundBudgetHeader.FinancialYear,
                   fundBudgetDetail.AdjustmentFundingSourceID,
                   ISNULL(fundSource.FundingSourceDesc, '') AS FundingSourceDesc,
                   fundBudgetDetail.ScoaID,
                   scoaFund.ScoaCode,
                   scoaFund.ScoaDesc,
                   fundBudgetDetail.FundingSourceBudget,
                   scoaFund.ScoaShortDesc,
                   ISNULL(fundBudgetDetail.IsHidden, 0) AS Submitted,
                   fundBudgetDetail.UploadedDocument
            FROM dbo.Plan_AdjustmentFundingSourceBudget_Header fundBudgetHeader
                LEFT JOIN dbo.Plan_AdjustmentFundingSourceBudget_Detail fundBudgetDetail
                    ON fundBudgetHeader.AdjustmentFundingSourceBudgetHeader_ID = fundBudgetDetail.AdjustmentFundingSourceBudgetHeaderID
                LEFT JOIN Const_FundingSource fundSource
                    ON fundBudgetDetail.AdjustmentFundingSourceID = fundSource.FundingSource_ID
                INNER JOIN dbo.Const_Scoa_Funds_Structure_ByYear(@FinYear) scoaFund
                    ON fundBudgetDetail.ScoaID = scoaFund.ScoaID
            WHERE fundBudgetHeader.FinancialYear = @FinYear
			AND fundBudgetDetail.AdjustmentFundingVersionId = @AdjustmentFundingVersionId
			 AND fundBudgetHeader.AdjustmentFundingVersionId = @AdjustmentFundingVersionId
        ) currentYear
    ) AS FundDetails
    WHERE (
              (
                  FundDetails.FundingSourceBudget = 0
                  AND FundDetails.FundingSourceBudgetCurrYearPlus1 = 0
                  AND FundDetails.FundingSourceBudgetCurrYearPlus2 = 0
              )
              OR ((ISNULL(FundDetails.Submitted, 0) = 0))
          );
END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_AdjustmentProjectBudgetingExport_sp]    Script Date: 2026/03/10 7:23:25 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Nirav Parikh
-- Create date: 12 Dec 2017
-- Description:	Get project budgeting details for Export
-- Plan_AdjustmentProjectBudgetingExport_sp '',0,0,'2019/2020'
-- 19-04-2018 SNagpal: 71151 Budget report extract is incorrect - Lepelle Nkumpi -- REPLACE(REPLACE(pp.ProjectName, ';', ''),'|','_') AS ProjectName
-- 01-06-2018 SNagpal: 73625 add replace code for ItemDescription & also fix calculations
-- 04-06-2018 SNagpal: 73625 add replace code for ProjectName
-- 07-06-2018 Chirag Patel:Const_ProjectItem table Join changes
-- 02 Nov 2018 SNagpal: 81527 Fix Where condition for @Information to get all adjusted projects
-- 24-Jan-2019 SNagpal: #61596 - #83633 - Add functionality to get ProjectCode. Replace AdjustmentProject_Id to ProjectCode, As User want to see ProjectCode in report
-- 20-May-2019 SNagpal: Add multiyear concept to get SCOA segments based upon finyear & also add ,ISNULL(ppi.ProjectItemID,0) AS ProjectItemID to get distinct results
-- 12-June-2019 SNagpal: #61596 - #83633 - Append ProjectCode with Project Name and Replace ProjectCode to AdjustmentProject_Id
-- 13-Aug-2020 ChrisM: 4727 - Standardise formatting for project name
-- 08 Sep 2020	PragnaP #41698 - used latest versionID record from Plan_AdjustmentProject to dispay budget for project.
-- 01 Oct 2020  CMoodley: #45884 Fix replace code so no space after comma replace
-- 06 Oct 2021  CMoodley: #58943 Remove temp table filter and reference Plan_BudgetConsumption table for available budget
-- 07-Aug-2023 CMoodley: #105236 Include CostingProject field
-- 20-Oct-2023 CMoodley: #107449 Left join to budget consumption table so new items not excluded, If @VersionID = 0 get the max adjustment version ID for the Fin year
-- 16-Oct-2024 CMoodley: #113360 Remove derived table for divisions
-- [dbo].[Plan_AdjustmentProjectBudgetingExport_sp] '', 0, 0, '2024/2025', '1,2,3,4,5,0', 0, 0, 0, 0, 0, 0, 0, '', 0
-- =============================================
CREATE PROCEDURE [dbo].[Plan_AdjustmentProjectBudgetingExport_sp]
    @strDivisionID NVARCHAR(10) = '',
    @ProjectID INT = 0,
    @ScoaFunctionID INT = 0,
    @FinYear NVARCHAR(9) ='2019/2020',
    @BudgetType NVARCHAR(20) = '1,2,3,4,5,0',
    @DepartmentID INT = 0 ,
    @ProjectTypeID INT = 0,
    @ScoaRegionID INT = 0,
    @ScoaFundID INT = 0,
    @ScoaItemID INT = 0,
	@ProjectStatusId INT = 0,
	@VersionId INT = 0,
	@SingleMultiYear VARCHAR(5) = '',
	@Information INT = 0

AS
BEGIN

	SET NOCOUNT ON;
    
	DECLARE @FinYear2 NVARCHAR(9), @FinYear3 NVARCHAR(9);
	DECLARE @StartFYear INT, @EndFYear INT, @DivisionID INT;
	
	SELECT @DivisionID = IIF(@strDivisionID = '', NULL, CAST(@strDivisionID AS INT));
	SELECT @StartFYear = CAST(Data AS INT) FROM dbo.Split(@FinYear, '/') WHERE Id = 1;
	SELECT @EndFYear = CAST(Data AS INT) FROM dbo.Split(@FinYear, '/') WHERE Id = 2;

	SET @FinYear2 = CAST(@EndFYear AS NVARCHAR(9)) +'/' + CAST((@EndFYear+1) AS NVARCHAR(9));
	SET @FinYear3 = CAST((@EndFYear + 1)AS NVARCHAR(9)) +'/' + CAST((@EndFYear+2) AS NVARCHAR(9));

	IF (@VersionId = 0) BEGIN SELECT @VersionId = MAX(AdjustmentVersionID) FROM Plan_AdjustmentProject WHERE FinYear = @FinYear END;

	CREATE TABLE #Const_SCOA_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
	CREATE INDEX idxItemScoaID ON #Const_SCOA_Structure(ScoaID)
	CREATE INDEX idxItemNTScoaID ON #Const_SCOA_Structure(NTScoaID)
	INSERT INTO #Const_SCOA_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @FinYear

	DECLARE @tblBudgetType TABLE ( BudgetTypeID INT );

    IF ISNULL(@BudgetType, '') <> ''
        BEGIN
            INSERT  INTO @tblBudgetType
                    SELECT  Data
                    FROM    dbo.Split(@BudgetType, ',');
        END;

	DECLARE @Tbl TABLE
	(
		FinYear1 NVARCHAR(10),
		FinYear2 NVARCHAR(10),
		FinYear3 NVARCHAR(10),
		ProjectId INT,
		ProjectName NVARCHAR(500),
		BudgetType NVARCHAR(50),
		SCOAProjectCode NVARCHAR(50),
		SCOAProject NVARCHAR(600),
		SCOAFuctionCode NVARCHAR(50),
		SCOAFunction NVARCHAR(600),
		MSCDepartmentCode NVARCHAR(50),
		MSCDepartment NVARCHAR(200),
		MSCDivisionCode NVARCHAR(50),
		MSCDivision NVARCHAR(200),
		MunicipleClassification NVARCHAR(600),
		SCOAFundCode NVARCHAR(50),
		SCOAFund NVARCHAR(600),
		SCOARegionCode NVARCHAR(50),
		SCOARegion NVARCHAR(600),
		SCOACostingCode NVARCHAR(50),
		SCOACosting NVARCHAR(600),
		SCOAItemCode NVARCHAR(50),
		SCOAItem NVARCHAR(600),
		ItemDescription NVARCHAR(500),
		CurrentBudgetFinYear1 DECIMAL(18,2),
		CurrentBudgetFinYear2 DECIMAL(18,2),
		CurrentBudgetFinYear3 DECIMAL(18,2),
		AvailableBudgetFinYear1 DECIMAL(18,2),
		CapitalOperation INT,
		BudgetVersionID INT,
		PlanProjectItemID INT,
		CostingProject BIT
	)
		
	INSERT INTO @Tbl
		( FinYear1 ,
			FinYear2 ,
			FinYear3 ,
			ProjectId ,
			ProjectName ,
			BudgetType ,
			SCOAProjectCode ,
			SCOAProject ,
			SCOAFuctionCode ,
			SCOAFunction ,
			MSCDepartmentCode ,
			MSCDepartment ,
			MSCDivisionCode ,
			MSCDivision ,
			MunicipleClassification ,
			SCOAFundCode ,
			SCOAFund ,
			SCOARegionCode ,
			SCOARegion ,
			SCOACostingCode ,
			SCOACosting ,
			SCOAItemCode ,
			SCOAItem ,
			ItemDescription ,
			CurrentBudgetFinYear1 ,
			CurrentBudgetFinYear2 ,
			CurrentBudgetFinYear3 ,
			AvailableBudgetFinYear1,
			CapitalOperation,
			BudgetVersionID,
			PlanProjectItemID,
			CostingProject
		)
	SELECT DISTINCT
		@FinYear AS FinYear1 ,
		@FinYear2 AS FinYear2 ,
		@FinYear3 AS FinYear3 ,
		pp.AdjustmentProject_ID AS ProjectId,
		(CAST(COALESCE(pp.ProjectCode,pp.ReferenceProject_ID,pp.AdjustmentProject_ID) AS VARCHAR(50)) + ' ' +
							+ REPLACE(REPLACE(REPLACE(pp.AdjustmentProjectName, ';', ''),'|','_'),',',';'))  AS ProjectName ,
		PCOT.TypeName AS BudgetType ,
		project.ScoaCode AS SCOAProjectCode ,
		REPLACE(REPLACE(REPLACE(REPLACE(project.ScoaDesc, CHAR(10), ' '),
                            CHAR(13), ' '), CHAR(09), ' '),',',';')  AS SCOAProject ,
		func.ScoaCode AS SCOAFuctionCode ,
		REPLACE(REPLACE(REPLACE(REPLACE(func.ScoaDesc , CHAR(10), ' '),
                            CHAR(13), ' '), CHAR(09), ' '),',',';') AS SCOAFunction ,
		dep.DepartmentCode AS MSCDepartmentCode,
		dep.DepartmentDesc AS MSCDepartment ,
		cd.DivisionCode AS MSCDivisionCode,
		REPLACE(cd.DivisionDesc,',',' _') AS MSCDivision,
		dep.DepartmentCode + ' - ' + REPLACE(dep.DepartmentDesc,',','_') + ' / ' + cd.DivisionCode + ' - ' + REPLACE(cd.DivisionDesc,',',' _') AS MunicipleClassification ,
		fs.ScoaCode AS SCOAFundCode ,
		REPLACE(REPLACE(REPLACE(REPLACE(fs.ScoaDesc , CHAR(10), ' '),
                            CHAR(13), ' '), CHAR(09), ' '),',',';') AS SCOAFund ,
		region.ScoaCode AS SCOARegionCode ,
		REPLACE(REPLACE(REPLACE(REPLACE(region.ScoaDesc  , CHAR(10), ' '),
                            CHAR(13), ' '), CHAR(09), ' '),',',';') AS SCOARegion ,
		costing.ScoaCode AS SCOACostingCode ,
		REPLACE(REPLACE(REPLACE(REPLACE(costing.ScoaDesc , CHAR(10), ' '),
                            CHAR(13), ' '), CHAR(09), ' '),',',';') AS SCOACosting ,
		css.ScoaCode AS SCOAItemCode,
		REPLACE(REPLACE(REPLACE(REPLACE(css.ScoaDesc, CHAR(10), ' '),
                            CHAR(13), ' '), CHAR(09), ' '),',',';')  AS SCOAItem ,
		REPLACE(REPLACE(REPLACE(REPLACE(cpi.ItemDescription, CHAR(10), ' '),
                            CHAR(13), ' '), CHAR(09), ' '),',','_')  AS ItemDescription ,
		CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation IN (0, 1, 2)) OR ppi.CreditDebit = 'C') THEN -ISNULL(AdjustedBudgetAmount, BudgetAmount) ELSE ISNULL(AdjustedBudgetAmount, BudgetAmount) END AS CurrentBudgetFinYear1,
		CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation IN (0, 1, 2)) OR ppi.CreditDebit = 'C') THEN -ISNULL(AdjustedBudgetAmountCurP1, BudgetAmountCurP1) ELSE ISNULL(AdjustedBudgetAmountCurP1, BudgetAmountCurP1) END AS CurrentBudgetFinYear2,
		CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation IN (0, 1, 2)) OR ppi.CreditDebit = 'C') THEN -ISNULL(AdjustedBudgetAmountCurP2, BudgetAmountCurP2) ELSE ISNULL(AdjustedBudgetAmountCurP2, BudgetAmountCurP2) END AS CurrentBudgetFinYear3,
		CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation IN (0, 1, 2)) OR ppi.CreditDebit = 'C') THEN -ISNULL(ISNULL(bc.AvailBudget, 0), BudgetAmount) ELSE ISNULL(ISNULL(bc.AvailBudget, 0), BudgetAmount) END AS AvailableBudgetFinYear1,
		0,
		0, 
		ISNULL(ppi.ReferencePlanProjectItem_ID, 0) AS PlanProjectItemID,
		ISNULL(CostingProject, 0) AS CostingProject
	FROM    Plan_AdjustmentProject pp
		INNER JOIN Plan_AdjustmentProjectItem ppi on pp.AdjustmentProject_ID = ppi.AdjustmentProjectID
		INNER JOIN dbo.Const_Status cs ON cs.Status_ID = pp.ProjectStatus
		LEFT JOIN
			(
				SELECT bc.PlanProjectItemID, bc.AvailableBudget AS AvailBudget
				FROM 
					(SELECT MAX(BudgetConsumption_ID) BudgetConsumptionID, PlanProjectItemID FROM Plan_BudgetConsumption WHERE FinYear = @FinYear GROUP BY PlanProjectItemID) maxBC
					INNER JOIN Plan_BudgetConsumption bc ON maxBC.BudgetConsumptionID = bc.BudgetConsumption_ID
			) bc ON bc.PlanProjectItemID = ppi.ReferencePlanProjectItem_ID
		INNER JOIN dbo.Const_Division cd ON cd.Division_ID = ppi.DivisionId
		INNER JOIN dbo.Const_Department dep ON cd.DepartmentID = dep.Department_ID
		INNER JOIN dbo.Const_SCOA_Function_Structure_Consolidated AS func ON func.ScoaID = ppi.SCOAFunctionId AND func.FinYearText = @FinYear
		INNER JOIN dbo.Const_SCOA_Regional_Structure_Consolidated AS region ON region.ScoaID = ppi.SCOARegionId AND region.FinYearText = @FinYear
		INNER JOIN dbo.Const_SCOA_Costing_Structure_Consolidated AS costing ON costing.ScoaID = ppi.SCOACostingID AND costing.FinYearText = @FinYear
		INNER JOIN dbo.Const_SCOA_Project_Structure_Consolidated AS project ON project.ScoaID = pp.ScoaProjectID AND project.FinYearText = @FinYear
		LEFT JOIN dbo.Const_ProjectItem cpi ON ppi.ProjectItemID = cpi.ProjectItem_ID
		INNER JOIN #Const_SCOA_Structure AS css ON ppi.SCOAItemID = css.ScoaID
		INNER JOIN dbo.Const_SCOA_Funds_Structure_Consolidated AS fs ON ppi.SCOAFundId = fs.ScoaID AND fs.FinYearText = @FinYear
		INNER JOIN dbo.Const_PlanCapitalOperationalTypes_sys PCOT ON PCOT.TypeValue = pp.CapitalOperation  
	WHERE 
			( CASE WHEN @ProjectID = 0 THEN 0 ELSE pp.AdjustmentProject_ID END = @ProjectID ) AND
			( CASE WHEN @ScoaFundID = 0 THEN 0 ELSE fs.ScoaID END = @ScoaFundID ) AND
			( CASE WHEN @ScoaFunctionID = 0 THEN 0 ELSE func.ScoaID END = @ScoaFunctionID ) AND
			( CASE WHEN @ScoaRegionID = 0 THEN 0 ELSE region.ScoaID END = @ScoaRegionID ) AND
			( CASE WHEN @ScoaItemID = 0 THEN 0 ELSE css.ScoaID END = @ScoaItemID ) AND
			( CASE WHEN @DepartmentID = 0 THEN 0 ELSE dep.Department_ID END = @DepartmentID ) AND
			( CASE WHEN @ProjectTypeID = 0 THEN 0 ELSE pp.ProjectTypeID END = @ProjectTypeID ) AND
			( CASE WHEN @FinYear = '' THEN '' ELSE pp.FinYear END = @FinYear ) AND
			( CASE WHEN @FinYear = '' THEN '' ELSE ppi.FinYear END = @FinYear ) AND
			( CASE WHEN @ProjectStatusId = 0 THEN 0 ELSE pp.ProjectStatus END = @ProjectStatusId ) AND
			( CASE WHEN @SingleMultiYear = '' THEN '' ELSE pp.SingleMultiYear END = @SingleMultiYear ) AND
			( CASE WHEN @VersionId > 0 THEN pp.AdjustmentVersionId ELSE @VersionId END = @VersionId ) AND
			((@Information = 1 AND ISNULL(pp.ReferenceProject_ID,0) >= 0 AND (( ISNULL(ppi.AdjustedBudgetAmount, 0)
                    + ISNULL(ppi.AdjustedBudgetAmountCurP1, 0)
                    + ISNULL(ppi.AdjustedBudgetAmountCurP2, 0) ) <> 0 or ppi.AdjustedBudgetAmount IS NOT NULL))
						OR 
				(@Information <> 1 AND (( ISNULL(ppi.BudgetAmount, 0)
                    + ISNULL(ppi.BudgetAmountCurP1, 0)
                    + ISNULL(ppi.BudgetAmountCurP2, 0) ) <> 0 OR (( ISNULL(ppi.AdjustedBudgetAmount, 0)
                    + ISNULL(ppi.AdjustedBudgetAmountCurP1, 0)
                    + ISNULL(ppi.AdjustedBudgetAmountCurP2, 0) ) <> 0) OR ppi.AdjustedBudgetAmount IS NOT NULL)))
				
			AND
			ISNULL(pp.IsDeleted, 0) <> 1 AND pp.CapitalOperation IN (SELECT BudgetTypeID FROM @tblBudgetType)
	ORDER BY MunicipleClassification;

	SELECT 
		FinYear1,
        FinYear2,
        FinYear3,
        ProjectId,
        ProjectName,
        BudgetType,
        SCOAProjectCode,
        SCOAProject,
        SCOAFuctionCode,
        SCOAFunction,
        MSCDepartmentCode,
        MSCDepartment,
        MSCDivisionCode,
        MSCDivision,
        MunicipleClassification,
        SCOAFundCode,
        SCOAFund,
        SCOARegionCode,
        SCOARegion,
        SCOACostingCode,
        SCOACosting,
        SCOAItemCode,
        SCOAItem,
        ItemDescription,
        CurrentBudgetFinYear1,
        CurrentBudgetFinYear2,
        CurrentBudgetFinYear3,
        AvailableBudgetFinYear1,
        CapitalOperation,
        BudgetVersionID,
		PlanProjectItemID,
		CostingProject
	FROM @Tbl

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_ApprovedVirementByCapturerID_sp]    Script Date: 2026/03/10 7:23:25 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 2016-04-16
-- Description:	Get Approved Virement
-- Call SP: Plan_ApprovedVirementByCapturerID_sp '',2647
-- 2016-04-23 by JP: Correct condition to check Approval user
-- =============================================
CREATE PROCEDURE [dbo].[Plan_ApprovedVirementByCapturerID_sp]
	-- Add the parameters for the stored procedure here
    @FinYear NVARCHAR(9) = '' ,
    @CapturerId INT
AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;

    -- Insert statements for procedure here
        SELECT  V.VirementId ,
                PrjFrom.ProjectName AS FromProject ,
                PrjTo.ProjectName AS ToProject ,
                ISNULL(CSPSFrom.ScoaDesc, '') AS FromSCOAProject ,
                ISNULL(CSPSTo.ScoaDesc, '') AS ToSCOAProject ,
                ISNULL(CSFSFrom.ScoaDesc, '') AS FromSCOAFunction ,
                ISNULL(CSFSTo.ScoaDesc, '') AS ToSCOAFunction ,
                ISNULL(CDFrom.DivisionDesc, '') AS FromDivision ,
                ISNULL(CDTo.DivisionDesc, '') AS ToDivision ,
                ISNULL(CSFDSFrom.ScoaDesc, '') AS FromSCOAFund ,
                ISNULL(CSFDSTo.ScoaDesc, '') AS ToSCOAFund ,
                ISNULL(CSRSFrom.ScoaDesc, '') AS FromSCOARegion ,
                ISNULL(CSRSTo.ScoaDesc, '') AS ToSCOARegion ,
                ISNULL(CSSFrom.ScoaDesc, '') AS FromSCOAItem ,
                ISNULL(CSSTo.ScoaDesc, '') AS ToSCOAItem ,
                ISNULL(V.FromVirementAmount, 0) AS FromVirementAmount ,
                ISNULL(V.ToVirementAmount, 0) AS ToVirementAmount
        FROM    dbo.Plan_Project PrjFrom
                INNER JOIN dbo.Plan_Virements V ON V.FromProjectId = PrjFrom.Project_ID
                LEFT OUTER JOIN Plan_Project PrjTo ON V.ToProjectId = PrjTo.Project_ID
                LEFT OUTER JOIN dbo.Const_SCOA_Project_Structure CSPSFrom ON CSPSFrom.ScoaID = V.FromSCOAProjectID
                LEFT OUTER JOIN dbo.Const_SCOA_Project_Structure CSPSTo ON CSPSTo.ScoaID = V.ToSCOAProjectID
                LEFT OUTER JOIN dbo.Const_SCOA_Function_Structure CSFSFrom ON CSFSFrom.ScoaID = V.FromSCOAFunctionId
                LEFT OUTER JOIN dbo.Const_SCOA_Function_Structure CSFSTo ON CSFSTo.ScoaID = V.ToSCOAFunctionId
                LEFT OUTER JOIN dbo.Const_Division CDFrom ON CDFrom.Division_ID = V.FromDivisionId
                LEFT OUTER JOIN dbo.Const_Division CDTo ON CDTo.Division_ID = V.ToDivisionId
                LEFT OUTER JOIN dbo.Const_SCOA_Funds_Structure CSFDSFrom ON CSFDSFrom.ScoaID = V.FromSCOAFundID
                LEFT OUTER JOIN dbo.Const_SCOA_Funds_Structure CSFDSTo ON CSFDSTo.ScoaID = V.ToSCOAFundID
                LEFT OUTER JOIN dbo.Const_SCOA_Regional_Structure CSRSFrom ON CSRSFrom.ScoaID = V.FromSCOARegion
                LEFT OUTER JOIN dbo.Const_SCOA_Regional_Structure CSRSTo ON CSRSTo.ScoaID = V.ToSCOARegion
                LEFT OUTER JOIN dbo.Const_SCOA_Structure CSSFrom ON CSSFrom.ScoaID = V.FromSCOAItem
                LEFT OUTER JOIN dbo.Const_SCOA_Structure CSSTo ON CSSTo.ScoaID = V.ToSCOAItem
                INNER JOIN dbo.Plan_VirementApprovalRejections PVAR ON PVAR.VirementId = V.VirementId
                                                              AND PVAR.ApprovedBy = @CapturerId
        WHERE   ( @FinYear = ''
                  OR V.FinYear = @FinYear
                )
                AND ( V.CapturerID = @CapturerId
                      OR PVAR.ApprovedBy = @CapturerId
                    )
                AND PVAR.IsApproved = 1;
    END;

	
GO

/****** Object:  StoredProcedure [dbo].[Plan_AutoCreateActivationVotesByProject_sp]    Script Date: 2026/03/10 7:23:25 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO




-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 04 March 2017
-- Description:	
-- CALLS : Plan_AutoCreateActivationVotesByProject_sp 44,'2016/2017'
-- 06/03/2017 RChetty: Commented out GL posting as per Gansen needs to be done by GL expert & also comment out related variables
-- 08/06/2017 RChetty: As per Travis Parent_Vote_ID=NULL
-- 14/06/2017 JigneshP: Add Call to SP - Led_AutoCreateGLAndPositionStatmentByProject_sp for GL Entry and Position Statement
-- 24/06/2017 JigneshP: Position for Calling SP - Led_AutoCreateGLAndPositionStatmentByProject_sp is set out of IF Exist Statement
--						Add Condition (AND ppi.FinYear = lv.FinYear) for checking led_vote FinYear to insert into #Temp
-- 11/07/2017 JigneshP: Check SCOA Item from LedVote Only, Remove Join with Plan_ProjectItem
-- 13/07/2017 JigneshP: Remove ProjectItemId and SCOA Segments fields (Fund, Region, Costing, Project, Function and Division) to get Distinct Item for Vote Entry
--						Add Condition not to Insert Duplicate VoteOpening Balance and Vote Section
-- 04/07/2019 CMoodley: Add multiyear concept to SCOA segments based upon financial year
-- =============================================
CREATE PROCEDURE [dbo].[Plan_AutoCreateActivationVotesByProject_sp] --2485, '2019/2020'
    @ProjectID INT ,
    @FinYear VARCHAR(9)
AS
    BEGIN	
	SET NOCOUNT ON;

    DECLARE @ErrorCode INT ,
        @OutputResult NVARCHAR(MAX)= '';

    BEGIN TRANSACTION;
        CREATE TABLE #Temp
            (
              --PlanProjectItemID INT NULL,
			  SCOAItemID INT NULL,
			  SCOAItemCode NVARCHAR(500) NULL,
              SCOAItemDescription NVARCHAR(500) NULL,
              VoteStatusId INT NULL,
			  FinYear VARCHAR(10) NULL,
			  VatIndicatorID INT NULL,
			  VoteTypeID INT NULL,
			  ControlVote BIT NULL,
			  IsBrokenDown	BIT NULL,
			  CapitalTimePeriodID INT NULL,
			  Parent_Vote_ID INT NULL
            );


        INSERT INTO #Temp
        SELECT DISTINCT --i.PlanProjectItem_ID ,
			i.SCOAItemID ,
			css.ScoaCode,
            css.ScoaShortDesc ,
            1, 
			i.FinYear,
			css.VatIndicatorID,
			css.VoteTypeID,
			css.IsControlVote,
			CASE WHEN css.BreakDownAllowed = 'Yes' THEN 1 ELSE 0 END AS BreakDownAllowed ,
			css.CapitalTimePeriodID,
			css.ScoaParentID
        FROM	dbo.Plan_Project pp INNER JOIN
				dbo.[Plan_ProjectItem] i ON i.ProjectID = pp.Project_ID
                INNER JOIN dbo.Const_Scoa_Structure_ByYear(@FinYear) css ON css.ScoaID = i.SCOAItemID
        WHERE   pp.Project_ID = @ProjectID
                AND i.FinYear = @FinYear
                AND i.SCOAItemID NOT IN ((SELECT  lv.SCOAItemID FROM dbo.Led_Vote AS lv WHERE lv.FinYear = @FinYear));


		IF EXISTS (SELECT 1 FROM #Temp)
		BEGIN

--Insert into LED_VOTE
		INSERT INTO dbo.Led_Vote
			( 
				Vote ,
				VoteDesc ,
				VoteStatusID ,
				FinYear ,
				CapturerID ,
				DateCaptured ,
				VatIndicatorID ,
				VoteTypeID ,
				ControlVote ,
				SCOAItemID ,
				SCOAItemCode ,
				IsBrokenDown ,
				OldVoteNumber ,
				Vote1 ,
				OldFms56VoteNumber ,
				CapitalTimePeriodID ,
				Parent_Vote_ID
			)
		SELECT DISTINCT 
			SCOAItemCode, 
			SCOAItemDescription , 
			VoteStatusId , 
			FinYear , 
			1 , 
			GETDATE() , 
			VatIndicatorID , 
			VoteTypeID , 
			ISNULL(ControlVote, 0) , 
			SCOAItemID , 
			SCOAItemCode , 
			IsBrokenDown , 
			NULL , 
			SCOAItemCode , 
			NULL , 
			CapitalTimePeriodID , 
			NULL  
		 FROM #Temp

		--Insert into Led_VoteSection
		INSERT INTO dbo.Led_VoteSection
			( VoteID, VoteSectionID )
		SELECT T.Vote_ID,T1.VoteSection_ID 
		FROM 
			(SELECT lv.Vote_ID 
			 FROM dbo.Led_Vote lv INNER JOIN  #Temp T ON lv.SCOAItemID = T.SCOAItemID) T
			 CROSS APPLY	dbo.Const_VoteSection_Sys T1
			EXCEPT (SELECT VoteID, VoteSectionID FROM dbo.Led_VoteSection)		

		--Insert into Led_Vote_OpeningBalance
		INSERT INTO dbo.Led_Vote_OpeningBalance
			( VoteID ,
			  FinYear ,
			  OpeningBalanceAmt ,
			  CapturerID ,
			  DateCaptured 
			)
		SELECT lv.Vote_ID, lv.FinYear,0.00,1,GETDATE() 
		FROM dbo.Led_Vote lv INNER JOIN  #Temp T ON lv.SCOAItemID = T.SCOAItemID
		WHERE lv.Vote_ID NOT IN (SELECT VoteID FROM Led_Vote_OpeningBalance WHERE FinYear = @FinYear) AND lv.FinYear = @FinYear

	END
       
	DROP TABLE #Temp;

	--Insert into Led_GeneralLedger & Position Statement (Led_Project)
	EXEC Led_AutoCreateGLAndPositionStatmentByProject_sp @ProjectID,@FinYear

    SET @OutputResult = 'Success';

    COMMIT TRANSACTION;
    PROBLEM:
        IF ( @ErrorCode <> 0 )
            BEGIN
                DECLARE @Err NVARCHAR(1000);
                SET @Err = ERROR_MESSAGE();
                RAISERROR (@Err, 16,1);
                SET @OutputResult = @Err;
                ROLLBACK TRAN;
            END;

        SELECT  @OutputResult AS Result ,
                @ProjectID AS ProjectID;

		--Uncomment below Query & comment all above script when we need to update the same sp into EDMX model--
		--SELECT ProjectName AS Result, Project_ID AS ProjectID FROM dbo.Plan_Project
    END;




GO

/****** Object:  StoredProcedure [dbo].[Plan_AutoCreateActivationVotesByProjectForAdjustmentBudget_sp]    Script Date: 2026/03/10 7:23:25 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO





-- =============================================
-- Author:	Nirav Parikh
-- Create date: 01 Dec 2017
-- 04/07/2019 CMoodley: Add multiyear concept to SCOA segments based upon financial year
-- CALLS : Plan_AutoCreateActivationVotesByProjectForAdjustmentBudget_sp 44,'2016/2017'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_AutoCreateActivationVotesByProjectForAdjustmentBudget_sp]
    @ProjectID INT,
    @FinYear VARCHAR(9)
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        BEGIN TRANSACTION;
        CREATE TABLE #Temp
        (
            SCOAItemID INT NULL,
            SCOAItemCode NVARCHAR(500) NULL,
            SCOAItemDescription NVARCHAR(500) NULL,
            VoteStatusId INT NULL,
            FinYear VARCHAR(10) NULL,
            VatIndicatorID INT NULL,
            VoteTypeID INT NULL,
            ControlVote BIT NULL,
            IsBrokenDown BIT NULL,
            CapitalTimePeriodID INT NULL,
            Parent_Vote_ID INT NULL
        );

        INSERT INTO #Temp
        SELECT DISTINCT
            i.SCOAItemID,
            css.ScoaCode,
            css.ScoaShortDesc,
            1,
            i.FinYear,
            css.VatIndicatorID,
            css.VoteTypeID,
            css.IsControlVote,
            (CASE
                 WHEN css.BreakDownAllowed = 'Yes' THEN
                     1
                 ELSE
                     0
             END
            ) AS BreakDownAllowed,
            css.CapitalTimePeriodID,
            css.ScoaParentID
        FROM dbo.Plan_Project pp
            INNER JOIN dbo.[Plan_ProjectItem] i
                ON i.ProjectID = pp.Project_ID
            INNER JOIN dbo.Const_Scoa_Structure_ByYear(@FinYear) css
                ON css.ScoaID = i.SCOAItemID
        WHERE pp.Project_ID = @ProjectID
              AND i.FinYear = @FinYear
              AND i.SCOAItemID NOT IN ((
                                           SELECT lv.SCOAItemID FROM dbo.Led_Vote AS lv WHERE lv.FinYear = @FinYear
                                       )
                                      );

        IF EXISTS (SELECT 1 FROM #Temp)
        BEGIN
            --Insert into LED_VOTE
            INSERT INTO dbo.Led_Vote
            (
                Vote,
                VoteDesc,
                VoteStatusID,
                FinYear,
                CapturerID,
                DateCaptured,
                VatIndicatorID,
                VoteTypeID,
                ControlVote,
                SCOAItemID,
                SCOAItemCode,
                IsBrokenDown,
                OldVoteNumber,
                Vote1,
                OldFms56VoteNumber,
                CapitalTimePeriodID,
                Parent_Vote_ID
            )
            SELECT DISTINCT
				SCOAItemCode, 
				SCOAItemDescription , 
				VoteStatusId , 
				FinYear , 
				1 , 
				GETDATE() , 
				VatIndicatorID , 
				VoteTypeID , 
				ISNULL(ControlVote, 0) , 
				SCOAItemID , 
				SCOAItemCode , 
				IsBrokenDown , 
				NULL , 
				SCOAItemCode , 
				NULL , 
				CapitalTimePeriodID , 
				NULL 
            FROM #Temp;

            --Insert into Led_VoteSection
            INSERT INTO dbo.Led_VoteSection
            (
                VoteID,
                VoteSectionID
            )
            SELECT T.Vote_ID,
                   T1.VoteSection_ID
            FROM
            (
                SELECT lv.Vote_ID
                FROM dbo.Led_Vote lv
                    INNER JOIN #Temp T
                        ON lv.SCOAItemID = T.SCOAItemID
            ) T
                CROSS APPLY dbo.Const_VoteSection_Sys T1
            EXCEPT
            (SELECT VoteID,
                    VoteSectionID
             FROM dbo.Led_VoteSection);

            --Insert into Led_Vote_OpeningBalance
            INSERT INTO dbo.Led_Vote_OpeningBalance
            (
                VoteID,
                FinYear,
                OpeningBalanceAmt,
                CapturerID,
                DateCaptured
            )
            SELECT lv.Vote_ID,
                   lv.FinYear,
                   0.00,
                   1,
                   GETDATE()
            FROM dbo.Led_Vote lv
                INNER JOIN #Temp T
                    ON lv.SCOAItemID = T.SCOAItemID
            WHERE lv.Vote_ID NOT IN (
                                        SELECT VoteID FROM Led_Vote_OpeningBalance WHERE FinYear = @FinYear
                                    )
                  AND lv.FinYear = @FinYear;
        END;
        DROP TABLE #Temp;

        --Insert into Led_GeneralLedger & Position Statement (Led_Project)
        EXEC Led_AutoCreateGLAndPositionStatmentByProject_sp @ProjectID, @FinYear;

        COMMIT TRANSACTION;

    END TRY
    BEGIN CATCH

        ROLLBACK TRANSACTION;

    END CATCH;
END;

GO

/****** Object:  StoredProcedure [dbo].[Plan_AutoCreateActivationVotesByYear_sp]    Script Date: 2026/03/10 7:23:25 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- =============================================
-- Author:	Sahil Nagpal/Raindree Chetty
-- Create date: 29 Ma6 2017
-- Description:	copied from Plan_AutoCreateActivationVotesByProject_sp
-- CALLS : Plan_AutoCreateActivationVotesByYear_sp '2015/2016'
-- 06/03/2017 RChetty: Commented out GL posting as per Gansen needs to be done by GL expert & also comment out related variables
-- 24/06/2017 JigneshP: Add Call to SP - Led_AutoCreateGLAndPositionStatmentByProject_sp for GL Entry and Position Statement
--						Add Condition (AND ppi.FinYear = lv.FinYear) for checking led_vote FinYear to insert into #Temp
-- 25 Feb 2020 Pipko V. US 21222 : use the user Processing Month for Ledger Postings
-- =============================================
CREATE PROCEDURE [dbo].[Plan_AutoCreateActivationVotesByYear_sp]
  @FinYear VARCHAR(9)
AS
    BEGIN	
	SET NOCOUNT ON;
        DECLARE @ErrorCode INT ,
            @OutputResult NVARCHAR(MAX)= '';
			--@UserProcessingMonth INT -- must be queried for the current user id @CapturerID when required
			--@TransactionType_ID INT ,
			--@DocumentTypeID INT, 
			--@TransactionDetail VARCHAR(100) = 'Opening Balance Ledger',
			--@DefaultSCOAItemID INT = 2212,
			--@ExistDocumentNumber INT;

        BEGIN TRANSACTION;
        CREATE TABLE #Temp
            (
              PlanProjectItemID INT NULL,
			  SCOAItemID INT NULL,
			  SCOAItemCode NVARCHAR(500) NULL,
              SCOAItemDescription NVARCHAR(500) NULL,
              VoteStatusId INT NULL,
			  FinYear VARCHAR(10) NULL,
			  VatIndicatorID INT NULL,
			  VoteTypeID INT NULL,
			  ControlVote BIT NULL,
			  IsBrokenDown	BIT NULL,
			  CapitalTimePeriodID INT NULL,
			  Parent_Vote_ID INT NULL,
			  SCOAFundsID INT NULL,
              SCOARegionID INT NULL,
              SCOACostingID INT NULL,
              SCOAProjectID INT NULL,
              SCOAFunctionID INT NULL,
              DivisionID INT NULL
            );
--SET @UserProcessingMonth = dbo.[GetProcessingMonthByUserID_fxn](@CapturerID);

--SELECT  @TransactionType_ID = TransactionType_ID, @DocumentTypeID = DocumentTypeID 
--FROM dbo.Const_CashbookTransactionType WHERE TransactionDesc = 'Opening Balance Ledger - Planning'

----Get Maximum Document Number for transaction
--SELECT @ExistDocumentNumber = MAX(CONVERT(INT, SUBSTRING( DocumentNumber , LEN(DocumentNumber) -  CHARINDEX('/',REVERSE(DocumentNumber)) + 2  , LEN(DocumentNumber))))
--FROM dbo.Led_GeneralLedger WHERE DocumentNumber LIKE  CONVERT(VARCHAR(10),@DocumentTypeID) + '/%'


        INSERT  INTO #Temp
                SELECT  i.PlanProjectItem_ID ,
						i.SCOAItemID ,
						css.ScoaCode,
                        css.ScoaShortDesc ,
                        1, 
						i.FinYear,
						css.VatIndicatorID,
						css.VoteTypeID,
						css.IsControlVote,
					(CASE WHEN css.BreakDownAllowed = 'Yes'
					THEN 1	ELSE 0
					END) AS BreakDownAllowed ,
						css.CapitalTimePeriodID,
						css.ScoaParentID,
						i.SCOAFundId ,
						i.SCOARegionID ,
						i.SCOACostingID ,
						pp.SCOAProjectID ,
						i.SCOAFunctionID ,
						i.DivisionID 
                FROM	dbo.Plan_Project pp INNER JOIN
						dbo.[Plan_ProjectItem] i ON i.ProjectID = pp.Project_ID
                        INNER JOIN dbo.Const_SCOA_Structure css ON css.ScoaID = i.SCOAItemID
                WHERE    i.FinYear = @FinYear
                        AND i.SCOAItemID NOT IN (
                     (SELECT  lv.SCOAItemID FROM    dbo.Plan_ProjectItem ppi 
					 INNER JOIN dbo.Led_Vote lv ON lv.SCOAItemID = ppi.SCOAItemID AND ppi.FinYear = lv.FinYear
                     WHERE    ppi.FinYear = @FinYear)); 

IF EXISTS (SELECT 1 FROM #Temp)
BEGIN

--Insert into LED_VOTE
		INSERT INTO dbo.Led_Vote
				        ( Vote ,
