/****** Object:  StoredProcedure [dbo].[Plan_AutoCreateProcurementByProject_sp]    Script Date: 2026/03/10 7:23:25 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- =============================================
-- Author:	Raindree
-- Create date: 19 August 2015 
-- Description:	Create procurement plan using project details.  Pass through project id and procurement plan
--              will be created.  Cannot duplicate items.  Each project item can only be added to the procurement
--              plan once per year.
-- CALLS : Plan_AutoCreateProcurementByProject_sp 1120
-- 31/08/2015 RC: error when multiple items
-- 01/09/2015 RC: project items have one fund linked to it.
-- 27/01/2015 RC: Project Manager is now allowed to be null. cannot use project manager when creating procurement plans
-- 04/04/2016 JP: DivisionID, SCOAFunctionID, SCOARegionID Removed from Plan_Project and Update join as Plan_ProjectItem gives these columns for Reference
-- 06/04/2016 JP: Add One more return value for ProjectId for Output to get Result as Object in EDMX instead of Int Value
-- 08/04/2016 JP: Reference for Const_ProjectItem has been changed to LEFT OUTER Instead of INNER
-- 08/04/2016 JP: EstimatedCost calcualtion Changed as that we get from Plan_ProjectItem's BudgetAmount
-- 08/04/2016 JP: Set 1 as Quantity default and Remove Join with Plan_ProjectItemMonth
-- 08/04/2016 JP: Remove Group by as there is no Sum required in Script
-- 22/04/2016 SN: Apply INNER JOIN dbo.Const_SCOA_Structure css ON css.ScoaID = i.SCOAItemID and apply condition AND css.ScoaCode not LIKE 'IR%'
-- 22/11/2016 SNagpal: Change the way of getting SCOACosting (Now from Plan_ProjectItem Table)
-- 13/01/2017 RC: Procurment statement changed to plan project item description or scoa item short description
-- 23/06/2017 RC: Duplicates created on procurment plan new
-- 28-Sept-2018 SNagpal: Insert NULL For [RequestedBy],[ApprovalBy],[SupervisorID], 
-- 04/07/2019 CMoodley: Add multiyear concept to SCOA segments based upon financial year
-- =============================================
CREATE PROCEDURE [dbo].[Plan_AutoCreateProcurementByProject_sp]
    @ProjectID INT ,
    @FinYear VARCHAR(9)
AS
    BEGIN	
        DECLARE @ErrorCode INT ,
            @OutputResult NVARCHAR(MAX)= '';

        BEGIN TRANSACTION;
        CREATE TABLE #Temp
            (
              PlanProjectItemID INT ,
              ItemDescription NVARCHAR(500) ,
              EstimatedCost DECIMAL(16, 2) ,
              SCOAFunctionID INT ,
              SCOAItemID INT ,
              SCOARegionID INT ,
              SCOACostingID INT ,
              ScoaProjectID INT ,
              Quantity DECIMAL(16, 2)
            );


        INSERT  INTO #Temp
                SELECT  i.PlanProjectItem_ID ,
                        ISNULL(c.ItemDescription, css.ScoaShortDesc) AS ItemDescription ,
					  --  p.ProjectDesc AS ItemDescription ,
                        ISNULL(i.BudgetAmount,0) AS [EstimatedCost] ,
                        i.SCOAFunctionId ,
                        i.SCOAItemID ,
                        i.SCOARegionId ,
                        i.SCOACostingID ,
                        p.ScoaProjectID ,
                        1 AS Quantity
                FROM    Plan_Project p
                        INNER JOIN [Plan_ProjectItem] i ON p.Project_ID = i.ProjectID
                        INNER JOIN dbo.Const_Scoa_Structure_ByYear(@FinYear) css ON css.ScoaID = i.SCOAItemID
                        LEFT OUTER JOIN [Const_ProjectItem] c ON i.ProjectItemID = c.ProjectItem_ID
                WHERE   p.Project_ID = @ProjectID
                        AND i.FinYear = @FinYear AND css.ScoaCode not LIKE 'IR%'
                        AND PlanProjectItem_ID NOT IN (
                        SELECT  d.PlanProjectItemID
                        FROM    SCM_ProcurementPlanNew pp
                                INNER JOIN SCM_ProcurementPlanDetails d ON pp.ProcurementPlan_ID = d.ProcurementPlanID
                        WHERE   pp.PlanProjectID = @ProjectID
                                AND pp.FinYear = @FinYear )
                        AND CASE WHEN  p.ProjectDesc like '%Virtual%'
						  THEN
						        1
						  ELSE
						        CASE WHEN ISNULL(i.BudgetAmount,0) > 1 
                                    THEN 1 
                                    ELSE 0 
                                    END
						  END = 1;

        DECLARE @PlanProjectItemID INT ,
            @ItemDescription NVARCHAR(500) ,
            @EstimatedCost DECIMAL(16, 2) ,
            @SCOAFunctionID INT ,
            @SCOAItemID INT ,
            @SCOARegionID INT ,
   @SCOACostingID INT ,
            @ScoaProjectID INT ,
            @Quantity DECIMAL(16, 2);

        DECLARE @ProcurementPlanID INT;
        DECLARE @ProcurementPlanDetailID INT;

        WHILE EXISTS ( SELECT   *
                       FROM     #Temp )
            BEGIN

                SELECT TOP 1
                        @PlanProjectItemID = PlanProjectItemID ,
                        @ItemDescription = ItemDescription ,
                        @EstimatedCost = EstimatedCost ,
                        @SCOAFunctionID = SCOAFunctionID ,
                        @SCOAItemID = SCOAItemID ,
                        @SCOARegionID = SCOARegionID ,
                        @SCOACostingID = SCOACostingID ,
                        @ScoaProjectID = ScoaProjectID ,
                        @Quantity = Quantity
                FROM    #Temp
                ORDER BY PlanProjectItemID ASC;

                INSERT  SCM_ProcurementPlanNew
                        ( [PlanProjectID] ,
                          [ProjectID] ,
                          [ProcurmentStatemnet] ,
                          [ProcurementType] ,
                          [ProcessCriteria] ,
                          [MunicClassificationID] --(=DepartmentID)
                          ,
                          [ServiceProvider] ,
                          [RequestedBy] ,
                          [ApprovalBy] ,
                          [SupervisorID] ,
                          [StatusID] ,
                          [DateCaptured] ,
                          [CapturerID] ,
                          [FinYear]
                        )
                        SELECT DISTINCT
                                p.Project_ID ,
                                p.ScoaProjectID ,
								  p.ProjectDesc AS ProcurmentStatemnet ,
                              --  ISNULL(c.ItemDescription, css.ScoaShortDesc) AS ProcurmentStatemnet ,
                                p.CapitalOperation ,
                                'N/A' ,
                                cd.DepartmentID ,
                                'N/A' ,
                                NULL ,
                                NULL ,
                                NULL ,
                                2 ,
                                p.DateCaptured ,
                                p.CapturerID ,
                                p.FinYear
                        FROM    Plan_Project p
                                INNER JOIN Plan_ProjectItem ppi ON ppi.ProjectID = p.Project_ID
                                INNER JOIN Const_Division cd ON cd.Division_ID = ppi.DivisionId
								INNER JOIN dbo.Const_Scoa_Structure_ByYear(@FinYear) css ON css.ScoaID = ppi.SCOAItemID
								LEFT OUTER JOIN [Const_ProjectItem] c ON ppi.ProjectItemID = c.ProjectItem_ID
                        WHERE   p.Project_ID = @ProjectID AND css.ScoaCode not LIKE 'IR%'
                                AND p.FinYear = @FinYear;
                SELECT  @ProcurementPlanID = SCOPE_IDENTITY(); 
--	-- by the end of this stored proc all procurement steps would be done.

                INSERT  INTO Sys_WorkFlowSectionAudit
                        SELECT  @ProcurementPlanID ,
                                23 ,
                                'ProcPlan' ,
                                pp.CapturerID ,
                                pp.DateCaptured ,
                                1
                        FROM    Plan_Project pp
                        WHERE   pp.Project_ID = @ProjectID
                                AND pp.FinYear = @FinYear;

                INSERT  INTO Sys_WorkFlowSectionAudit
                        SELECT  @ProcurementPlanID ,
                                23 ,
                                'ProcTeam' ,
                                pp.CapturerID ,
                                pp.DateCaptured ,
                                1
                        FROM    Plan_Project pp
                        WHERE   pp.Project_ID = @ProjectID
                                AND pp.FinYear = @FinYear;

                INSERT  INTO Sys_WorkFlowSectionAudit
                        SELECT  @ProcurementPlanID ,
                                23 ,
                                'ProcDetail' ,
                                pp.CapturerID ,
                                pp.DateCaptured ,
                                1
                        FROM    Plan_Project pp
                        WHERE   pp.Project_ID = @ProjectID
                                AND pp.FinYear = @FinYear;

                INSERT  INTO SCM_ProcurementPlanDetails
                        ( [ProcurementPlanID] ,
                          [Description] ,
                          [EstimatedCost] ,
                          [SCOAFunctionID] ,
                          [SCOAItemID] ,
                          [SCOARegionID] ,
                          [SCOACostingID] ,
                          [SCOAProjectID] ,
                          [PlanProjectItemID] ,
                          [Quantity]
	                    )
                        SELECT  @ProcurementPlanID ,
                                @ItemDescription ,
                                @EstimatedCost ,
                                @SCOAFunctionID ,
                                @SCOAItemID ,
                                @SCOARegionID ,
                                @SCOACostingID ,
                                @ScoaProjectID ,
                                @PlanProjectItemID ,
                                @Quantity;
                SELECT  @ProcurementPlanDetailID = SCOPE_IDENTITY(); 
	 
                INSERT  INTO SCM_ProcurementPlanDetailsFund
                        ( [ProcurementPlanID] ,
                          [ProcurementPlanDetailID] ,
                          [SCOAFundID] ,
                          [PercentageValue]
	                    )
                        SELECT  @ProcurementPlanID ,
                                @ProcurementPlanDetailID ,
                                f.ScoaFundID ,
                                100
                        FROM    Plan_ProjectItem i
                                INNER JOIN Plan_ProjectFundYear fy ON i.ProjectFundYearID = fy.ProjectFundYear_ID
                                INNER JOIN Plan_ProjectFund f ON fy.ProjectFundID = f.ProjectFund_ID
								INNER JOIN dbo.Const_Scoa_Structure_ByYear(@FinYear) css ON css.ScoaID = i.SCOAItemID
                        WHERE   f.ProjectID = @ProjectID AND css.ScoaCode not LIKE 'IR%'
                                AND fy.FinYear = @FinYear
                                AND i.PlanProjectItem_ID = @PlanProjectItemID;

                DELETE  #Temp
                WHERE   PlanProjectItemID = @PlanProjectItemID;
            END;

        DROP TABLE #Temp;
        SET @OutputResult = 'Success';

        COMMIT TRANSACTION;
        PROBLEM:
        IF ( @ErrorCode <> 0 )
            BEGIN
                DECLARE @Err NVARCHAR(1000);
                SET @Err = ERROR_MESSAGE();
                RAISERROR (@Err, 16,1);
                SET @OutputResult = @Err;
                ROLLBACK TRAN;
            END;

        SELECT  @OutputResult AS Result ,
                @ProjectID AS ProjectID;
    END;
GO

