                                100
                        FROM    Plan_ProjectItem i
                                INNER JOIN Plan_ProjectFundYear fy ON i.ProjectFundYearID = fy.ProjectFundYear_ID
                                INNER JOIN Plan_ProjectFund f ON fy.ProjectFundID = f.ProjectFund_ID
								INNER JOIN dbo.Const_SCOA_Structure css ON css.ScoaID = i.SCOAItemID
                        WHERE   f.ProjectID = @ProjectID AND css.ScoaCode not LIKE 'IR%'
                                AND fy.FinYear = @FinYear
                                AND i.PlanProjectItem_ID = @PlanProjectItemID;

                DELETE  #Temp
                WHERE   PlanProjectItemID = @PlanProjectItemID;
            END;

        DROP TABLE #Temp;
        SET @OutputResult = 'Success';

        COMMIT TRANSACTION;
        PROBLEM:
        IF ( @ErrorCode <> 0 )
            BEGIN
                DECLARE @Err NVARCHAR(1000);
                SET @Err = ERROR_MESSAGE();
                RAISERROR (@Err, 16,1);
                SET @OutputResult = @Err;
                ROLLBACK TRAN;
            END;

        SELECT  @OutputResult AS Result ,
                @ProjectID AS ProjectID;
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_AutoCreateProcurementByProjectForAdjustmentBudget_sp]    Script Date: 2026/03/10 7:23:25 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- =============================================
-- Author:	Nirav Parikh
-- Create date: 01 December 2017
-- CALLS : Plan_AutoCreateProcurementByProjectForAdjustmentBudget_sp 2036, '2018/2019'
-- 12-Apr-2018 SNagpal: #70916 Nquthu6_1 (approving Adjustment budget)
-- 28-Sept-2018 SNagpal: Insert NULL For [RequestedBy],[ApprovalBy],[SupervisorID], 
-- 04/07/2019 CMoodley: Add multiyear concept to SCOA segments based upon financial year
-- =============================================
CREATE PROCEDURE [dbo].[Plan_AutoCreateProcurementByProjectForAdjustmentBudget_sp]
    @ProjectID INT,
    @FinYear VARCHAR(9)
AS
BEGIN
BEGIN TRY
    BEGIN TRANSACTION PlanAutoCreateProc

	DECLARE @ErrorResultproc NVARCHAR(max);
		CREATE TABLE #Temp
		(
			PlanProjectItemID INT,
			ItemDescription NVARCHAR(500),
			EstimatedCost DECIMAL(16, 2),
			SCOAFunctionID INT,
			SCOAItemID INT,
			SCOARegionID INT,
			SCOACostingID INT,
			ScoaProjectID INT,
			Quantity DECIMAL(16, 2)
		);

		INSERT INTO #Temp
		SELECT i.PlanProjectItem_ID,
			   ISNULL(c.ItemDescription, css.ScoaShortDesc) AS ItemDescription,
			   ISNULL(i.BudgetAmount, 0) AS [EstimatedCost],
			   i.SCOAFunctionId,
			   i.SCOAItemID,
			   i.SCOARegionId,
			   i.SCOACostingID,
			   p.ScoaProjectID,
			   1 AS Quantity
		FROM Plan_Project p
			INNER JOIN [Plan_ProjectItem] i
				ON p.Project_ID = i.ProjectID
			INNER JOIN dbo.Const_Scoa_Structure_ByYear(@FinYear) css
				ON css.ScoaID = i.SCOAItemID
			LEFT OUTER JOIN [Const_ProjectItem] c
				ON i.ProjectItemID = c.ProjectItem_ID
		WHERE p.Project_ID = @ProjectID
			  AND i.FinYear = @FinYear
			  AND css.ScoaCode NOT LIKE 'IR%'
			  AND PlanProjectItem_ID NOT IN (
												SELECT d.PlanProjectItemID
												FROM SCM_ProcurementPlanNew pp
													INNER JOIN SCM_ProcurementPlanDetails d
														ON pp.ProcurementPlan_ID = d.ProcurementPlanID
												WHERE pp.PlanProjectID = @ProjectID
													  AND pp.FinYear = @FinYear
											)
			  AND ISNULL(i.BudgetAmount, 0) > 0;

		DECLARE @PlanProjectItemID INT,
				@ItemDescription NVARCHAR(500),
				@EstimatedCost DECIMAL(16, 2),
				@SCOAFunctionID INT,
				@SCOAItemID INT,
				@SCOARegionID INT,
				@SCOACostingID INT,
				@ScoaProjectID INT,
				@Quantity DECIMAL(16, 2);

		DECLARE @ProcurementPlanID INT;
		DECLARE @ProcurementPlanDetailID INT;

		WHILE EXISTS (SELECT * FROM #Temp)
		BEGIN
			SELECT TOP 1
				@PlanProjectItemID = PlanProjectItemID,
				@ItemDescription = ItemDescription,
				@EstimatedCost = EstimatedCost,
				@SCOAFunctionID = SCOAFunctionID,
				@SCOAItemID = SCOAItemID,
				@SCOARegionID = SCOARegionID,
				@SCOACostingID = SCOACostingID,
				@ScoaProjectID = ScoaProjectID,
				@Quantity = Quantity
			FROM #Temp
			ORDER BY PlanProjectItemID ASC;

			INSERT SCM_ProcurementPlanNew
			(
				[PlanProjectID],
				[ProjectID],
				[ProcurmentStatemnet],
				[ProcurementType],
				[ProcessCriteria],
				[MunicClassificationID], --(=DepartmentID)
				[ServiceProvider],
				[RequestedBy],
				[ApprovalBy],
				[SupervisorID],
				[StatusID],
				[DateCaptured],
				[CapturerID],
				[FinYear]
			)
			SELECT DISTINCT
				p.Project_ID,
				p.ScoaProjectID,
				p.ProjectDesc AS ProcurmentStatemnet,
				--  ISNULL(c.ItemDescription, css.ScoaShortDesc) AS ProcurmentStatemnet ,
				p.CapitalOperation,
				'N/A',
				cd.DepartmentID,
				'N/A',
				NULL,
				NULL,
				NULL,
				2,
				p.DateCaptured,
				p.CapturerID,
				p.FinYear
			FROM Plan_Project p
				INNER JOIN Plan_ProjectItem ppi
					ON ppi.ProjectID = p.Project_ID
				INNER JOIN Const_Division cd
					ON cd.Division_ID = ppi.DivisionId
				INNER JOIN dbo.Const_Scoa_Structure_ByYear(@FinYear) css
					ON css.ScoaID = ppi.SCOAItemID
				LEFT OUTER JOIN [Const_ProjectItem] c
					ON ppi.ProjectItemID = c.ProjectItem_ID
			WHERE p.Project_ID = @ProjectID
				  AND css.ScoaCode NOT LIKE 'IR%'
				  AND p.FinYear = @FinYear;
			SELECT @ProcurementPlanID = SCOPE_IDENTITY();
			--	-- by the end of this stored proc all procurement steps would be done.

			INSERT INTO Sys_WorkFlowSectionAudit
			SELECT @ProcurementPlanID,
				   23,
				   'ProcPlan',
				   pp.CapturerID,
				   pp.DateCaptured,
				   1
			FROM Plan_Project pp
			WHERE pp.Project_ID = @ProjectID
				  AND pp.FinYear = @FinYear;

			INSERT INTO Sys_WorkFlowSectionAudit
			SELECT @ProcurementPlanID,
				   23,
				   'ProcTeam',
				   pp.CapturerID,
				   pp.DateCaptured,
				   1
			FROM Plan_Project pp
			WHERE pp.Project_ID = @ProjectID
				  AND pp.FinYear = @FinYear;

			INSERT INTO Sys_WorkFlowSectionAudit
			SELECT @ProcurementPlanID,
				   23,
				   'ProcDetail',
				   pp.CapturerID,
				   pp.DateCaptured,
				   1
			FROM Plan_Project pp
			WHERE pp.Project_ID = @ProjectID
				  AND pp.FinYear = @FinYear;

			INSERT INTO SCM_ProcurementPlanDetails
			(
				[ProcurementPlanID],
				[Description],
				[EstimatedCost],
				[SCOAFunctionID],
				[SCOAItemID],
				[SCOARegionID],
				[SCOACostingID],
				[SCOAProjectID],
				[PlanProjectItemID],
				[Quantity]
			)
			SELECT @ProcurementPlanID,
				   @ItemDescription,
				   @EstimatedCost,
				   @SCOAFunctionID,
				   @SCOAItemID,
				   @SCOARegionID,
				   @SCOACostingID,
				   @ScoaProjectID,
				   @PlanProjectItemID,
				   @Quantity;
			SELECT @ProcurementPlanDetailID = SCOPE_IDENTITY();

			INSERT INTO SCM_ProcurementPlanDetailsFund
			(
				[ProcurementPlanID],
				[ProcurementPlanDetailID],
				[SCOAFundID],
				[PercentageValue]
			)
			SELECT @ProcurementPlanID,
				   @ProcurementPlanDetailID,
				   f.ScoaFundID,
				   100
			FROM Plan_ProjectItem i
				INNER JOIN Plan_ProjectFundYear fy
					ON i.ProjectFundYearID = fy.ProjectFundYear_ID
				INNER JOIN Plan_ProjectFund f
					ON fy.ProjectFundID = f.ProjectFund_ID
				INNER JOIN dbo.Const_Scoa_Structure_ByYear(@FinYear) css
					ON css.ScoaID = i.SCOAItemID
			WHERE f.ProjectID = @ProjectID
				  AND css.ScoaCode NOT LIKE 'IR%'
				  AND fy.FinYear = @FinYear
				  AND i.PlanProjectItem_ID = @PlanProjectItemID;

			DELETE #Temp
			WHERE PlanProjectItemID = @PlanProjectItemID;
		END;

		DROP TABLE #Temp;

    COMMIT TRANSACTION PlanAutoCreateProc
END TRY
BEGIN CATCH
	SET @ErrorResultproc = ERROR_MESSAGE()
		RAISERROR(@ErrorResultproc, 16, 1)
	    ROLLBACK TRANSACTION PlanAutoCreateProc

END CATCH
END


GO

/****** Object:  StoredProcedure [dbo].[Plan_AutoCreateProcurementForVirtualProject_sp]    Script Date: 2026/03/10 7:23:25 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- =============================================  
-- Author: Sahil Nagpal  
-- Create date: 04 OCT 2016  
-- Description: Create procurement plan using project details.  Pass through project id and procurement plan  
--              will be created.  Cannot duplicate items.  Each project item can only be added to the procurement  
--              plan once per year. This procedure is for Virtual Projects only and used externally.  
-- Note: This procedure is using for Insert Virtual Project externally AND not used in Project source code solution, So Don't delete this by anyway.  
-- 22/11/2016 SNagpal: Change the way of getting SCOACosting (Now from Plan_ProjectItem Table)  
-- 10/05/2017 Rchetty: when procurement plan is created need to add budget register  
-- 11/05/2017 SNagpal: Call Sp : Plan_AutoCreateActivationVotesByProject_sp as need to activate the vote if the scoa Item does not exist in led_Vote  
-- 05 FEB 2019 - NParikh - Employee_ID Passed 0 so get ID from Payroll_Employee table
-- =============================================  
CREATE PROCEDURE [dbo].[Plan_AutoCreateProcurementForVirtualProject_sp]
    @ProjectID INT,
    @FinYear VARCHAR(9)
AS
BEGIN
    DECLARE @ErrorCode INT,
            @OutputResult NVARCHAR(MAX) = '';

    BEGIN TRANSACTION;
    CREATE TABLE #Temp
    (
        PlanProjectItemID INT,
        ItemDescription NVARCHAR(500),
        EstimatedCost DECIMAL(16, 2),
        SCOAFunctionID INT,
        SCOAItemID INT,
        SCOARegionID INT,
        SCOACostingID INT,
        ScoaProjectID INT,
        Quantity DECIMAL(16, 2)
    );


    INSERT INTO #Temp
    SELECT i.PlanProjectItem_ID,
           ISNULL(c.ItemDescription, css.ScoaDesc) AS ItemDescription,
           ISNULL(i.BudgetAmount, 0) AS [EstimatedCost],
           i.SCOAFunctionId,
           i.SCOAItemID,
           i.SCOARegionId,
           i.SCOACostingID,
           p.ScoaProjectID,
           1 AS Quantity
    FROM Plan_Project p
        INNER JOIN [Plan_ProjectItem] i
            ON p.Project_ID = i.ProjectID
        INNER JOIN dbo.Const_SCOA_Structure css
            ON css.ScoaID = i.SCOAItemID
        LEFT OUTER JOIN [Const_ProjectItem] c
            ON i.ProjectItemID = c.ProjectItem_ID
    WHERE p.Project_ID = @ProjectID
          AND i.FinYear = @FinYear
          AND css.ScoaCode NOT LIKE 'IR%'
          AND PlanProjectItem_ID NOT IN
              (
                  SELECT d.PlanProjectItemID
                  FROM SCM_ProcurementPlanNew pp
                      INNER JOIN SCM_ProcurementPlanDetails d
                          ON pp.ProcurementPlan_ID = d.ProcurementPlanID
                  WHERE pp.PlanProjectID = @ProjectID
                        AND pp.FinYear = @FinYear
              )
          AND ISNULL(i.BudgetAmount, 0) > 0;

    DECLARE @PlanProjectItemID INT,
            @ItemDescription NVARCHAR(500),
            @EstimatedCost DECIMAL(16, 2),
            @SCOAFunctionID INT,
            @SCOAItemID INT,
            @SCOARegionID INT,
            @SCOACostingID INT,
            @ScoaProjectID INT,
            @Quantity DECIMAL(16, 2);

    DECLARE @ProcurementPlanID INT;
    DECLARE @ProcurementPlanDetailID INT;
    DECLARE @Employee_ID INT;

    SELECT @Employee_ID = Employee_ID
    FROM dbo.Payroll_Employee;

    INSERT INTO Plan_BudgetRegister
    SELECT PlanProjectItem_ID,
           1,
           10,
           PlanProjectItem_ID,
           'Plan_ProjectItem',
           BudgetAmount,
           BudgetAmount,
           1,
           GETDATE(),
           NULL,
           NULL,
           FinYear
    FROM Plan_ProjectItem
    WHERE ProjectID = @ProjectID
          AND PlanProjectItem_ID NOT IN
              (
                  SELECT PlanProjectItemID FROM Plan_BudgetRegister
              );
    WHILE EXISTS (SELECT * FROM #Temp)
    BEGIN
        SELECT TOP 1
               @PlanProjectItemID = PlanProjectItemID,
               @ItemDescription = ItemDescription,
               @EstimatedCost = EstimatedCost,
               @SCOAFunctionID = SCOAFunctionID,
               @SCOAItemID = SCOAItemID,
               @SCOARegionID = SCOARegionID,
               @SCOACostingID = SCOACostingID,
               @ScoaProjectID = ScoaProjectID,
               @Quantity = Quantity
        FROM #Temp
        ORDER BY PlanProjectItemID ASC;

        INSERT SCM_ProcurementPlanNew
        (
            [PlanProjectID],
            [ProjectID],
            [ProcurmentStatemnet],
            [ProcurementType],
            [ProcessCriteria],
            [MunicClassificationID], --(=DepartmentID)  
            [ServiceProvider],
            [RequestedBy],
            [ApprovalBy],
            [SupervisorID],
            [StatusID],
            [DateCaptured],
            [CapturerID],
            [FinYear]
        )
        SELECT DISTINCT
               p.Project_ID,
               p.ScoaProjectID,
               'Virtual Procurement ' + @ItemDescription,
               p.CapitalOperation,
               'N/A',
               cd.DepartmentID,
               'N/A',
               @Employee_ID,
               @Employee_ID,
               @Employee_ID,
               2,
               p.DateCaptured,
               p.CapturerID,
               p.FinYear
        FROM Plan_Project p
            INNER JOIN Plan_ProjectItem ppi
                ON ppi.ProjectID = p.Project_ID
            INNER JOIN Const_Division cd
                ON cd.Division_ID = ppi.DivisionId
            INNER JOIN dbo.Const_SCOA_Structure css
                ON css.ScoaID = ppi.SCOAItemID
        WHERE p.Project_ID = @ProjectID
              AND css.ScoaCode NOT LIKE 'IR%'
              AND p.FinYear = @FinYear;

        SELECT @ProcurementPlanID = SCOPE_IDENTITY();
        -- -- by the end of this stored proc all procurement steps would be done.  

        INSERT INTO Sys_WorkFlowSectionAudit
        SELECT @ProcurementPlanID,
               23,
               'ProcPlan',
               pp.CapturerID,
               pp.DateCaptured,
               1
        FROM Plan_Project pp
        WHERE pp.Project_ID = @ProjectID
              AND pp.FinYear = @FinYear;

        INSERT INTO Sys_WorkFlowSectionAudit
        SELECT @ProcurementPlanID,
               23,
               'ProcTeam',
               pp.CapturerID,
               pp.DateCaptured,
               1
        FROM Plan_Project pp
        WHERE pp.Project_ID = @ProjectID
              AND pp.FinYear = @FinYear;

        INSERT INTO Sys_WorkFlowSectionAudit
        SELECT @ProcurementPlanID,
               23,
               'ProcDetail',
               pp.CapturerID,
               pp.DateCaptured,
               1
        FROM Plan_Project pp
        WHERE pp.Project_ID = @ProjectID
              AND pp.FinYear = @FinYear;

        INSERT INTO SCM_ProcurementPlanDetails
        (
            [ProcurementPlanID],
            [Description],
            [EstimatedCost],
            [SCOAFunctionID],
            [SCOAItemID],
            [SCOARegionID],
            [SCOACostingID],
            [SCOAProjectID],
            [PlanProjectItemID],
            [Quantity]
        )
        SELECT @ProcurementPlanID,
               'Virtual Procurement ' + @ItemDescription,
               @EstimatedCost,
               @SCOAFunctionID,
               @SCOAItemID,
               @SCOARegionID,
               @SCOACostingID,
               @ScoaProjectID,
               @PlanProjectItemID,
               @Quantity;
        SELECT @ProcurementPlanDetailID = SCOPE_IDENTITY();

        INSERT INTO SCM_ProcurementPlanDetailsFund
        (
            [ProcurementPlanID],
            [ProcurementPlanDetailID],
            [SCOAFundID],
            [PercentageValue]
        )
        SELECT @ProcurementPlanID,
               @ProcurementPlanDetailID,
               f.ScoaFundID,
               100
        FROM Plan_ProjectItem i
            INNER JOIN Plan_ProjectFundYear fy
                ON i.ProjectFundYearID = fy.ProjectFundYear_ID
            INNER JOIN Plan_ProjectFund f
                ON fy.ProjectFundID = f.ProjectFund_ID
            INNER JOIN dbo.Const_SCOA_Structure css
                ON css.ScoaID = i.SCOAItemID
        WHERE f.ProjectID = @ProjectID
              AND css.ScoaCode NOT LIKE 'IR%'
              AND fy.FinYear = @FinYear
              AND i.PlanProjectItem_ID = @PlanProjectItemID;

        DELETE #Temp
        WHERE PlanProjectItemID = @PlanProjectItemID;
    END;

    DROP TABLE #Temp;

    --need to activate the vote if the scoa Item does not exist in led_Vote  
    EXEC Plan_AutoCreateActivationVotesByProject_sp @ProjectID, @FinYear;

    SET @OutputResult = N'Success';

    COMMIT TRANSACTION;
    PROBLEM:
    IF (@ErrorCode <> 0)
    BEGIN
        DECLARE @Err NVARCHAR(1000);
        SET @Err = ERROR_MESSAGE();
        RAISERROR(@Err, 16, 1);
        SET @OutputResult = @Err;
        ROLLBACK TRAN;
    END;

    SELECT @OutputResult AS Result,
           @ProjectID AS ProjectID;
END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_AutoCreateProcurementInitProject_sp]    Script Date: 2026/03/10 7:23:25 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Raindree Chetty
-- Create date: 19 August 2014
-- Description:	Auto create procurement plans for projects that are already in initialized status but
--              do not have procurement plans created yet.
-- 
-- =============================================
CREATE PROCEDURE [dbo].[Plan_AutoCreateProcurementInitProject_sp]
	@FinYear varchar(9)
AS
BEGIN
	SELECT Project_ID
	INTO #ControlTable 
	FROM Plan_Project WHERE ProjectStatus =24
	AND Project_ID NOT IN (SELECT  PlanProjectID FROM [dbo].[SCM_ProcurementPlanNew])
	AND Project_ID in (select ProjectID from Plan_ProjectItem)

	DECLARE @TableID int

	WHILE EXISTS (SELECT * FROM #ControlTable)
	BEGIN

		SELECT TOP 1 @TableID = Project_ID
		FROM #ControlTable
		ORDER BY Project_ID ASC

	   EXECUTE Plan_AutoCreateProcurementByProject_sp @TableID,@FinYear

		DELETE #ControlTable
		WHERE Project_ID = @TableID

	END
	DROP TABLE #ControlTable
END
GO

/****** Object:  StoredProcedure [dbo].[Plan_BuddgetRegister_sp]    Script Date: 2026/03/10 7:23:25 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


--===========================================================  
-- 2019-07-22 #91927 CMoodley: Reference correct SCOA version by financial year   
-- 09 Sep 2019 - 93738 Beaufort West - Budget consumption report
--===========================================================  
CREATE PROCEDURE [dbo].[Plan_BuddgetRegister_sp]
    -- Add the parameters for the stored procedure here  
    @ProjectId INT,
    @ShowDetail BIT,
    @RecalcBudget BIT = 0,
    @FinYear VARCHAR(10) = ''
AS
BEGIN
    IF (@FinYear = '')
    BEGIN
        SELECT @FinYear = FinYear
        FROM dbo.Plan_Project
        WHERE Project_ID = @ProjectId;
    END;

    IF @RecalcBudget = 1
    BEGIN
        EXEC dbo.Plan_RecalcBudgetRegister_sp;
    END;
    IF @ShowDetail = 1
    BEGIN
        SELECT br.DateCaptured,
               br.BudgetRegister_ID,
               Project_ID,
               ProjectName,
               pitem.PlanProjectItem_ID,
               ProjectDesc,
               bType.BudgetTransDesc,
               BudgetTransactionTypeID,
               PK_TransactionID,
               TransactionTableName,
               TransactionAmount,
               AvailableBudget,
               (
                   SELECT DocType
                   FROM Plan_GetBudgetDocumentDetail(br.TransactionTableName, br.PK_TransactionID)
               ) DocType,
               (
                   SELECT DocNumber
                   FROM Plan_GetBudgetDocumentDetail(br.TransactionTableName, br.PK_TransactionID)
               ) DocNumber,
               struc.ScoaCode scoaCode,
               struc.ScoaShortDesc scoaDesc,
               func.ScoaCode functionCode,
               func.ScoaShortDesc functionDesc,
               fund.ScoaCode fundCode,
               fund.ScoaShortDesc fundDesc,
               reg.ScoaCode regCode,
               reg.ScoaShortDesc regDesc,
               div.DivisionCode,
               div.DivisionDesc,
               cost.ScoaCode costCode,
               cost.ScoaShortDesc costDes
        FROM Plan_BudgetRegister br
            JOIN Plan_ProjectItem pitem
                ON pitem.PlanProjectItem_ID = br.PlanProjectItemID
            JOIN Plan_Project pproject
                ON pproject.Project_ID = pitem.ProjectID
            JOIN Const_BudgetTransactionType_sys bType
                ON bType.BudgetTransactionType_ID = br.BudgetTransactionTypeID
            JOIN Const_Scoa_Structure_ByYear(@FinYear) struc
                ON struc.ScoaID = SCOAItemID
            JOIN Const_Scoa_Function_Structure_ByYear(@FinYear) func
                ON func.ScoaID = SCOAFunctionID
            JOIN Const_Scoa_Funds_Structure_ByYear(@FinYear) fund
                ON fund.ScoaID = SCOAFundId
            JOIN Const_Scoa_Regional_Structure_ByYear(@FinYear) reg
                ON reg.ScoaID = SCOARegionId
            JOIN Const_Division div
                ON div.Division_ID = DivisionId
            JOIN Const_Scoa_Costing_Structure_ByYear(@FinYear) cost
                ON cost.ScoaID = SCOACostingID
        WHERE (
                  pproject.Project_ID = @ProjectId
                  OR ISNULL(@ProjectId, 0) = 0
              )
        ORDER BY br.DateCaptured,
                 TransactionAmount;
    END;
    ELSE
    BEGIN
        SELECT br.BudgetRegister_ID,
               Project_ID,
               ProjectName,
               pitem.PlanProjectItem_ID,
               ProjectDesc,
               bType.BudgetTransDesc,
               BudgetTransactionTypeID,
               PK_TransactionID,
               TransactionTableName,
               TransactionAmount,
               AvailableBudget,
               (
                   SELECT DocType
                   FROM Plan_GetBudgetDocumentDetail(br.TransactionTableName, br.PK_TransactionID)
               ) DocType,
               (
                   SELECT DocNumber
                   FROM Plan_GetBudgetDocumentDetail(br.TransactionTableName, br.PK_TransactionID)
               ) DocNumber,
               struc.ScoaCode scoaCode,
               struc.ScoaShortDesc scoaDesc,
               func.ScoaCode functionCode,
               func.ScoaShortDesc functionDesc,
               fund.ScoaCode fundCode,
               fund.ScoaShortDesc fundDesc,
               reg.ScoaCode regCode,
               reg.ScoaShortDesc regDesc,
               div.DivisionCode,
               div.DivisionDesc,
               cost.ScoaCode costCode,
               cost.ScoaShortDesc costDes
        FROM
        (
            SELECT reg.*
            FROM
            (
                SELECT *
                FROM
                (
                    SELECT PlanProjectItemID,
                           TransactionTableName,
                           SUM(TransactionAmount) TransactionAmount,
                           PK_TransactionID
                    FROM Plan_BudgetRegister budget

                    --Where  (budget.PlanProjectItemId = 307198 OR IsNull(307198,0) = 0)   

                    GROUP BY PlanProjectItemID,
                             TransactionTableName,
                             PK_TransactionID
                ) budgetSummary
                WHERE TransactionAmount <> 0
            ) summary
                JOIN Plan_BudgetRegister reg
                    ON reg.PlanProjectItemID = summary.PlanProjectItemID
                       AND reg.TransactionTableName = summary.TransactionTableName
                       AND reg.PK_TransactionID = summary.PK_TransactionID
        ) br
            JOIN Plan_ProjectItem pitem
                ON pitem.PlanProjectItem_ID = br.PlanProjectItemID
            JOIN Plan_Project pproject
                ON pproject.Project_ID = pitem.ProjectID
            JOIN Const_BudgetTransactionType_sys bType
                ON bType.BudgetTransactionType_ID = br.BudgetTransactionTypeID
            JOIN Const_Scoa_Structure_ByYear(@FinYear) struc
                ON struc.ScoaID = SCOAItemID
            JOIN Const_Scoa_Function_Structure_ByYear(@FinYear) func
                ON func.ScoaID = SCOAFunctionID
            JOIN Const_Scoa_Funds_Structure_ByYear(@FinYear) fund
                ON fund.ScoaID = SCOAFundId
            JOIN Const_Scoa_Regional_Structure_ByYear(@FinYear) reg
                ON reg.ScoaID = SCOARegionId
            JOIN Const_Division div
                ON div.Division_ID = DivisionId
            JOIN Const_Scoa_Costing_Structure_ByYear(@FinYear) cost
                ON cost.ScoaID = SCOACostingID
        WHERE (
                  pproject.Project_ID = @ProjectId
                  OR ISNULL(@ProjectId, 0) = 0
              )
        ORDER BY Project_ID,
                 PlanProjectItem_ID,
                 br.DateCaptured;
    END;
END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetAdjustmentExportVersion_Detail_sp]    Script Date: 2026/03/10 7:23:26 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Chris Moodley
-- Create date: October 2022
-- Description:	Adjustment budget version detail
-- [dbo].[Plan_BudgetAdjustmentExportVersion_Detail_sp] 259, '2022/2023'
-- 230222 by CM: 97683 - Handle null values where no items may be captured against project
-- 230807 by CM:105236 - Include CostingProject field
-- =============================================
CREATE   PROCEDURE [dbo].[Plan_BudgetAdjustmentExportVersion_Detail_sp]
	-- Add the parameters for the stored procedure here
	@adjustmentVersionID INT, 
	@finYear NVARCHAR(50),
	@budgetAdjustmentExportImportVersionHeaderID INT,
	@userID INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE 
		 @FinYearP1 NVARCHAR(9)
		,@FinYearP2 NVARCHAR(9)
		,@FinYearP3 NVARCHAR(9)
		,@Yearp1 INT 
		,@Yearp2 INT
		,@Yearp3 INT 
		,@Yearp4 INT 

	SELECT  @Yearp1 = CAST(SUBSTRING(@FinYear, 1, 4) AS INT);
	SELECT  @Yearp2 = @Yearp1 + 1;
	SELECT  @Yearp3 = @Yearp1 + 2;
	SELECT  @Yearp4 = @Yearp1 + 3;

	SELECT  @FinYearP1 = CONVERT(VARCHAR(4), @Yearp1) + '/' + CONVERT(VARCHAR(4), @Yearp2);
	SELECT  @FinYearP2 = CONVERT(VARCHAR(4), @Yearp2) + '/' + CONVERT(VARCHAR(4), @Yearp3);
	SELECT  @FinYearP3 = CONVERT(VARCHAR(4), @Yearp3) + '/' + CONVERT(VARCHAR(4), @Yearp4);

	WITH cteIDP AS 
	(
		SELECT pap.AdjustmentProject_ID, ItemDesc 
		FROM Plan_AdjustmentProject pap 
			 LEFT JOIN Plan_AdjustmentProjectIDP pidp ON pap.AdjustmentProject_ID = pidp.AdjustmentProjectID 
			 LEFT JOIN IDP_Item idp ON pidp.ParentIDPItemID = idp.Item_ID
		WHERE pap.AdjustmentVersionId = @AdjustmentVersionID
	)

	INSERT INTO Plan_BudgetAdjustmentExportVersion_Detail
	SELECT
		 @budgetAdjustmentExportImportVersionHeaderID
		,@FinYearP1 FinYear1
		,@FinYearP2 FinYear2
		,@FinYearP3 FinYear3
		,@AdjustmentVersionID AdjustmentVersionID
		,pp.AdjustmentProject_ID AdjustmentProjectID
		,ISNULL(STUFF(( SELECT  '| ' + idp.ItemDesc
                FROM    cteIDP idp
                WHERE   idp.AdjustmentProject_ID = pp.AdjustmentProject_ID
                FOR
                XML PATH('')
			), 1, 1, ''), '') AS IDPItem
		,ISNULL(ReferenceProject_ID, -1) ProjectID
		,ISNULL(ProjectCode, 0) ProjectCode
		,AdjustmentProjectName ProjectName
		,AdjustmentProjectDesc ProjectDesc
		,ISNULL(SingleMultiYear, 'S') SingleMultiYear
		,CASE WHEN scoaItem.ScoaCode IS NULL THEN 0 ELSE ISNULL(ReferencePlanProjectItem_ID, -1) END PlanProjectItemID
		,ISNULL(pcot.TypeName, '') BudgetType
		,ISNULL(scoaProj.ScoaCode, '') SCOAProjectCode
		,ISNULL(scoaProj.ScoaDesc, '') SCOAProject
		,ISNULL(scoaFunc.ScoaCode, '') SCOAFuctionCode
		,ISNULL(scoaFunc.ScoaDesc, '') SCOAFunction
		,ISNULL(dept.DepartmentCode, '') MSCDepartmentCode
		,ISNULL(dept.DepartmentDesc, '') MSCDepartment
		,ISNULL(div.DivisionCode, '')  MSCDivisionCode
		,ISNULL(div.DivisionDesc, '') MSCDivision
		,ISNULL(dept.DepartmentCode + ' - ' + dept.DepartmentDesc + ' / ' + div.DivisionCode + ' - ' + div.DivisionDesc, '') MunicipalClassification
		,ISNULL(scoaFund.ScoaCode, '') SCOAFundCode
		,ISNULL(scoaFund.ScoaDesc, '') SCOAFund
		,ISNULL(scoaRegion.ScoaCode, '') SCOARegionCode
		,ISNULL(scoaRegion.ScoaDesc, '') SCOARegion
		,ISNULL(scoaCost.ScoaCode, '') SCOACostingCode
		,ISNULL(scoaCost.ScoaDesc, '') SCOACosting
		,ISNULL(scoaItem.ScoaCode, '') SCOAItemCode
		,ISNULL(scoaItem.ScoaDesc, '') SCOAItem
		,ISNULL(cpi.ItemDescription, '') ItemDescription
		,ISNULL(CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(AdjustedBudgetAmount, BudgetAmount) ELSE ISNULL(AdjustedBudgetAmount, BudgetAmount) END, 0.00) CurrentBudgetFinYear1
		,ISNULL(CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(AdjustedBudgetAmountCurP1, BudgetAmountCurP1) ELSE ISNULL(AdjustedBudgetAmountCurP1, BudgetAmountCurP1) END, 0.00)  CurrentBudgetFinYear2
		,ISNULL(CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(AdjustedBudgetAmountCurP2, BudgetAmountCurP2) ELSE ISNULL(AdjustedBudgetAmountCurP2, BudgetAmountCurP2) END, 0.00)  CurrentBudgetFinYear3
		,ISNULL(ISNULL(CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -AvailableBudget ELSE AvailableBudget END, CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(AdjustedBudgetAmount, BudgetAmount) ELSE ISNULL(AdjustedBudgetAmount, BudgetAmount) END), 0.00)  AvailableBudgetFinYear1
		,ISNULL(bso.BudgetSplitDesc, '') SplitType
		,ISNULL(CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(ppim1.AdjustedUnitPrice, ppim1.UnitPrice) ELSE ISNULL(ppim1.AdjustedUnitPrice, ppim1.UnitPrice) END, 0.00) M1
		,ISNULL(CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(ppim2.AdjustedUnitPrice, ppim2.UnitPrice) ELSE ISNULL(ppim2.AdjustedUnitPrice, ppim2.UnitPrice) END, 0.00) M2
		,ISNULL(CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(ppim3.AdjustedUnitPrice, ppim3.UnitPrice) ELSE ISNULL(ppim3.AdjustedUnitPrice, ppim3.UnitPrice) END, 0.00) M3
		,ISNULL(CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(ppim4.AdjustedUnitPrice, ppim4.UnitPrice) ELSE ISNULL(ppim4.AdjustedUnitPrice, ppim4.UnitPrice) END, 0.00) M4
		,ISNULL(CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(ppim5.AdjustedUnitPrice, ppim5.UnitPrice) ELSE ISNULL(ppim5.AdjustedUnitPrice, ppim5.UnitPrice) END, 0.00) M5
		,ISNULL(CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(ppim6.AdjustedUnitPrice, ppim6.UnitPrice) ELSE ISNULL(ppim6.AdjustedUnitPrice, ppim6.UnitPrice) END, 0.00) M6
		,ISNULL(CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(ppim7.AdjustedUnitPrice, ppim7.UnitPrice) ELSE ISNULL(ppim7.AdjustedUnitPrice, ppim7.UnitPrice) END, 0.00) M7
		,ISNULL(CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(ppim8.AdjustedUnitPrice, ppim8.UnitPrice) ELSE ISNULL(ppim8.AdjustedUnitPrice, ppim8.UnitPrice) END, 0.00) M8
		,ISNULL(CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(ppim9.AdjustedUnitPrice, ppim9.UnitPrice) ELSE ISNULL(ppim9.AdjustedUnitPrice, ppim9.UnitPrice) END, 0.00) M9
		,ISNULL(CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(ppim10.AdjustedUnitPrice, ppim10.UnitPrice) ELSE ISNULL(ppim10.AdjustedUnitPrice, ppim10.UnitPrice) END, 0.00) M10
		,ISNULL(CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(ppim11.AdjustedUnitPrice, ppim11.UnitPrice) ELSE ISNULL(ppim11.AdjustedUnitPrice, ppim11.UnitPrice) END, 0.00) M11
		,ISNULL(CASE WHEN (((scoaItem.ScoaCode LIKE 'IR%' OR scoaItem.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(ppim12.AdjustedUnitPrice, ppim12.UnitPrice) ELSE ISNULL(ppim12.AdjustedUnitPrice, ppim12.UnitPrice) END, 0.00) M12
		,ISNULL(CreditDebit, '') CreditDebit
		,ISNULL(adjType.AdjustmentType, '') AdjustmentType
		,ISNULL(adjReason.AdjustmentReason, '') LegislativeAdjustmentReason
		,ISNULL(ppi.ReasonForAdjustment, '') ReasonForAdjustment
		,@userID
		,GETDATE()
		,NULL
		,NULL		
		,ISNULL(GRAPClassification, '') GRAPClassification
		,ISNULL(GRAPClassificationNote, '') GRAPClassificationNote
		,ISNULL(MainSegmentReporting, '') MainSegmentReporting
		,ISNULL(SubSegmentReporting, '') SubSegmentReporting
		,ISNULL(CostingProject, 0) CostingProject
	FROM
		Plan_AdjustmentProject pp		
		LEFT JOIN Const_PlanCapitalOperationalTypes_sys pcot ON pp.CapitalOperation = pcot.TypeValue
		LEFT JOIN Const_Scoa_Project_Structure_Consolidated scoaProj ON pp.ScoaProjectID = scoaProj.ScoaID AND scoaProj.FinYearText = @finYear
		LEFT JOIN Plan_AdjustmentProjectItem ppi ON pp.AdjustmentProject_ID = ppi.AdjustmentProjectID
		LEFT JOIN Const_SCOA_Function_Structure_Consolidated scoaFunc ON ppi.SCOAFunctionId = scoaFunc.ScoaID AND scoaFunc.FinYearText = @finYear
		LEFT JOIN Const_Scoa_Funds_Structure_Consolidated scoaFund ON ppi.SCOAFundId = scoaFund.ScoaID AND scoaFund.FinYearText = @finYear
		LEFT JOIN Const_Scoa_Regional_Structure_Consolidated scoaRegion ON ppi.SCOARegionId = scoaRegion.ScoaID AND scoaRegion.FinYearText = @finYear
		LEFT JOIN Const_Scoa_Costing_Structure_Consolidated scoaCost ON ppi.SCOACostingID = scoaCost.ScoaID AND scoaCost.FinYearText = @finYear
		LEFT JOIN Const_Scoa_Structure_Consolidated scoaItem ON ppi.SCOAItemID = scoaItem.ScoaID AND scoaItem.FinYearText = @finYear
		LEFT JOIN Const_BudgetSplitOptions bso ON ppi.BudgetSplitID = bso.DivideBy_ID
		LEFT JOIN Const_ProjectItem cpi ON ppi.ProjectItemID = cpi.ProjectItem_ID
		LEFT JOIN Plan_AdjustmentProjectItemMonth ppim1 ON ppi.PlanAdjustmentProjectItem_ID = ppim1.PlanAdjustmentProjectItemID AND ppim1.MonthID = 7
		LEFT JOIN Plan_AdjustmentProjectItemMonth ppim2 ON ppi.PlanAdjustmentProjectItem_ID = ppim2.PlanAdjustmentProjectItemID AND ppim2.MonthID = 8
		LEFT JOIN Plan_AdjustmentProjectItemMonth ppim3 ON ppi.PlanAdjustmentProjectItem_ID = ppim3.PlanAdjustmentProjectItemID AND ppim3.MonthID = 9
		LEFT JOIN Plan_AdjustmentProjectItemMonth ppim4 ON ppi.PlanAdjustmentProjectItem_ID = ppim4.PlanAdjustmentProjectItemID AND ppim4.MonthID = 10
		LEFT JOIN Plan_AdjustmentProjectItemMonth ppim5 ON ppi.PlanAdjustmentProjectItem_ID = ppim5.PlanAdjustmentProjectItemID AND ppim5.MonthID = 11
		LEFT JOIN Plan_AdjustmentProjectItemMonth ppim6 ON ppi.PlanAdjustmentProjectItem_ID = ppim6.PlanAdjustmentProjectItemID AND ppim6.MonthID = 12
		LEFT JOIN Plan_AdjustmentProjectItemMonth ppim7 ON ppi.PlanAdjustmentProjectItem_ID = ppim7.PlanAdjustmentProjectItemID AND ppim7.MonthID = 1
		LEFT JOIN Plan_AdjustmentProjectItemMonth ppim8 ON ppi.PlanAdjustmentProjectItem_ID = ppim8.PlanAdjustmentProjectItemID AND ppim8.MonthID = 2
		LEFT JOIN Plan_AdjustmentProjectItemMonth ppim9 ON ppi.PlanAdjustmentProjectItem_ID = ppim9.PlanAdjustmentProjectItemID AND ppim9.MonthID = 3
		LEFT JOIN Plan_AdjustmentProjectItemMonth ppim10 ON ppi.PlanAdjustmentProjectItem_ID = ppim10.PlanAdjustmentProjectItemID AND ppim10.MonthID = 4
		LEFT JOIN Plan_AdjustmentProjectItemMonth ppim11 ON ppi.PlanAdjustmentProjectItem_ID = ppim11.PlanAdjustmentProjectItemID AND ppim11.MonthID = 5
		LEFT JOIN Plan_AdjustmentProjectItemMonth ppim12 ON ppi.PlanAdjustmentProjectItem_ID = ppim12.PlanAdjustmentProjectItemID AND ppim12.MonthID = 6
		LEFT JOIN Const_PlanAdjustmentType_sys adjType ON ppi.AdjutmentType = adjType.AdjustmentType_ID
		LEFT JOIN Const_PlanAdjustmentReason_sys adjReason ON ppi.LegislativeReasonAdjustment = adjReason.AdjustmentReason_ID
		LEFT JOIN Const_Division div ON ppi.DivisionId = div.Division_ID
		LEFT JOIN Const_Department dept ON div.DepartmentID = dept.Department_ID
		LEFT JOIN (SELECT MAX(BudgetConsumption_ID) BudgetConsumptionID, PlanProjectItemID FROM Plan_BudgetConsumption WHERE FinYear = @finYear GROUP BY PlanProjectItemID) BCMax ON ppi.ReferencePlanProjectItem_ID = BCMax.PlanProjectItemID
		LEFT JOIN Plan_BudgetConsumption BC ON BCMax.BudgetConsumptionID = BC.BudgetConsumption_ID
	WHERE
		pp.AdjustmentVersionId = @adjustmentVersionID AND ISNULL(IsDeleted, 0) <> 1
	ORDER BY
		ProjectCode

	SELECT
		 FinYear1
		,FinYear2
		,FinYear3
		,AdjustmentVersionID
		,AdjustmentProjectID
		,IDPItem
		,ProjectID
		,ProjectCode
		,ProjectName
		,ProjectDesc
		,SingleMultiYear
		,CostingProject
		,PlanProjectItemID
		,BudgetType
		,SCOAProjectCode
		,SCOAProject
		,SCOAFunctionCode
		,SCOAFunction
		,MSCDepartmentCode
		,MSCDepartment
		,MSCDivisionCode
		,MSCDivision
		,MunicipalClassification
		,SCOAFundCode
		,SCOAFund
		,SCOARegionCode
		,SCOARegion
		,SCOACostingCode
		,SCOACosting
		,SCOAItemCode
		,SCOAItem
		,ItemDescription
		,CurrentBudgetFinYear1
		,CurrentBudgetFinYear2
		,CurrentBudgetFinYear3
		,AvailableBudgetFinYear1
		,SplitType
		,M1
		,M2
		,M3
		,M4
		,M5
		,M6
		,M7
		,M8
		,M9
		,M10
		,M11
		,M12
		,ISNULL(CreditDebit, '') CreditDebit
		,AdjustmentType
		,LegislativeAdjustmentReason
		,ReasonForAdjustment
		,GRAPClassification
		,GRAPClassificationNote
		,MainSegmentReporting
		,SubSegmentReporting
	FROM
		Plan_BudgetAdjustmentExportVersion_Detail
	WHERE
		BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID
	ORDER BY
		ProjectCode

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetAdjustmentExportVersion_sp]    Script Date: 2026/03/10 7:23:26 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- ==================================================================
-- Author:		Chris Moodley
-- Create date: October 2022
-- Description:	Return adjustment version details per financial year
-- 231017 by CM - Use SCOA consolidated tables
-- [dbo].[Plan_BudgetAdjustmentExportVersion_sp] '2022/2023'
-- ==================================================================
CREATE PROCEDURE [dbo].[Plan_BudgetAdjustmentExportVersion_sp]
	-- Add the parameters for the stored procedure here
	@FinYear NVARCHAR(50)
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	SELECT 
		 adjVersion.AdjustmentBudgetVersion_ID
		,ISNULL(adjApproval.AdjustmentBudgetApproval_Id, 0) AdjustmentBudgetApproval_ID
		,adjVersion.DateCaptured AdjustmentPolicyApprovalDate
		,userDetail.FirstName + ' ' + userDetail.LastName ApproverName
		,@FinYear FinYear
		,COUNT(pap.AdjustmentProject_ID) NumProjects
		,SUM(CASE WHEN (((item.ScoaCode LIKE 'IR%' OR item.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(AdjustedBudgetAmount, BudgetAmount) ELSE ISNULL(AdjustedBudgetAmount, BudgetAmount) END) TotalBudgetY1
		,SUM(CASE WHEN (((item.ScoaCode LIKE 'IR%' OR item.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(AdjustedBudgetAmountCurP1, BudgetAmountCurP1) ELSE ISNULL(AdjustedBudgetAmountCurP1, BudgetAmountCurP1) END) TotalBudgetY2
		,SUM(CASE WHEN (((item.ScoaCode LIKE 'IR%' OR item.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ISNULL(AdjustedBudgetAmountCurP2, BudgetAmountCurP2) ELSE ISNULL(AdjustedBudgetAmountCurP2, BudgetAmountCurP2) END) TotalBudgetY3
	FROM
		(
			SELECT DISTINCT AdjustmentVersionID
			FROM Plan_AdjustmentProjectItem
			WHERE FinYear = @FinYear
		) adjItemVersion

		LEFT JOIN Plan_AdjustmentBudgetVersion adjVersion ON adjItemVersion.AdjustmentVersionId = adjVersion.AdjustmentBudgetVersion_ID
		LEFT JOIN Plan_AdjustmentBudgetApproval adjApproval ON adjVersion.AdjustmentBudgetVersion_ID = adjApproval.AdjustmentVersionId
		LEFT JOIN User_UserDetail userDetail ON adjVersion.CapturerID = userDetail.User_ID
		LEFT JOIN Plan_AdjustmentProject pap ON adjVersion.AdjustmentBudgetVersion_ID = pap.AdjustmentVersionId
		LEFT JOIN Plan_AdjustmentProjectItem papi ON pap.AdjustmentProject_ID = papi.AdjustmentProjectID
		INNER JOIN Plan_Const_Scoa_Structure_Consolidated_vw item ON papi.SCOAItemID = item.ScoaID AND item.FinYearText = @FinYear
	WHERE
		ProjectStatus <> 5 and ISNULL(IsDeleted, 0) <> 1
	GROUP BY
		adjVersion.AdjustmentBudgetVersion_ID, adjApproval.AdjustmentBudgetApproval_Id, adjVersion.DateCaptured, userDetail.FirstName, userDetail.LastName
	ORDER BY
		adjVersion.AdjustmentBudgetVersion_ID 

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetAdjustmentFieldValidation_sp]    Script Date: 2026/03/10 7:23:26 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Chris Moodley
-- Create date: October 2022
-- Description:	Adjustment Budget Field Validation
-- 230425 by CM: 97722 - Check that SCOA segments, municipal classification and CreditDebit flag have not changed for existing plan project item IDs
-- 241016 by CM: 112987 - Allow existing items to have zero budget if no actuals captured
-- 250916 by CM: 123686 - Include validation for budget type 
-- 251027 by CM: 124473 - Check if IDP Item exists for new projects
-- =============================================
CREATE PROCEDURE [dbo].[Plan_BudgetAdjustmentFieldValidation_sp] 
	-- Add the parameters for the stored procedure here
	 @BudgetAdjustmentExportImportVersionHeaderID INT 
	,@BudgetAdjustmentImportVersionNumber INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE @finYear NVARCHAR(10), @versionID INT, @idpNumLevel INT
	
	SELECT @finYear = FinYear, @versionID = AdjustmentVersionID 
	FROM Plan_BudgetAdjustmentExportImportVersion_Header 
	WHERE BudgetAdjustmentExportImportVersionHeader_ID = @BudgetAdjustmentExportImportVersionHeaderID

	SELECT @idpNumLevel = IDPNumLevel
	FROM Const_IDPLevelDescription_Header
	WHERE FinancialYear = @finYear

	CREATE TABLE #Const_SCOA_Project_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6))
	CREATE INDEX idxProjectScoaID ON #Const_SCOA_Project_Structure(ScoaID)
	CREATE INDEX idxProjectScoaCode ON #Const_SCOA_Project_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Project_Structure SELECT ScoaID, ScoaCode, PostingLevel FROM Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @finYear

	CREATE TABLE #Const_SCOA_Function_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6))
	CREATE INDEX idxFunctionScoaID ON #Const_SCOA_Function_Structure(ScoaID)
	CREATE INDEX idxFunctionScoaCode ON #Const_SCOA_Function_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Function_Structure SELECT ScoaID, ScoaCode, PostingLevel FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @finYear

	CREATE TABLE #Const_SCOA_Fund_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6))
	CREATE INDEX idxFundScoaID ON #Const_SCOA_Fund_Structure(ScoaID)
	CREATE INDEX idxFundScoaCode ON #Const_SCOA_Fund_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Fund_Structure SELECT ScoaID, ScoaCode, PostingLevel FROM Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @finYear

	CREATE TABLE #Const_SCOA_Region_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6))
	CREATE INDEX idxRegionScoaID ON #Const_SCOA_Region_Structure(ScoaID)
	CREATE INDEX idxRegionScoaCode ON #Const_SCOA_Region_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Region_Structure SELECT ScoaID, ScoaCode, PostingLevel FROM Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @finYear

	CREATE TABLE #Const_SCOA_Costing_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6))
	CREATE INDEX idxCostingScoaID ON #Const_SCOA_Costing_Structure(ScoaID)
	CREATE INDEX idxCostingScoaCode ON #Const_SCOA_Costing_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Costing_Structure SELECT ScoaID, ScoaCode, PostingLevel FROM Const_SCOA_Costing_Structure_Consolidated WHERE FinYearText = @finYear

	CREATE TABLE #Const_SCOA_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6))
	CREATE INDEX idxItemScoaID ON #Const_SCOA_Structure(ScoaID)
	CREATE INDEX idxItemScoaCode ON #Const_SCOA_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Structure SELECT ScoaID, ScoaCode, PostingLevel FROM Const_SCOA_Structure_Consolidated WHERE FinYearText = @finYear

	SELECT *
	INTO #Import
	FROM Plan_BudgetAdjustmentImportVersion_Detail
	WHERE BudgetAdjustmentExportImportVersionHeaderID = @BudgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @BudgetAdjustmentImportVersionNumber

	--Budget Type Incorrect
	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'Incorrect Budget Type'
	FROM 
		#Import imp
		LEFT JOIN (SELECT * FROM Const_PlanCapitalOperationalTypes_sys WHERE Enabled = 1) budType ON imp.BudgetType = budType.TypeName
	WHERE
		(imp.BudgetType IS NOT NULL AND imp.BudgetType <> '') AND  budType.TypeName IS NULL

	--Adjustment fields captured correctly
	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'Incorrect Adjustment Type'
	FROM 
		#Import imp
		LEFT JOIN (SELECT * FROM Const_PlanAdjustmentType_sys WHERE FinYear = @finYear AND Enabled = 1) adjType ON imp.AdjustmentType = adjType.AdjustmentType
	WHERE
		(imp.AdjustmentType IS NOT NULL AND imp.AdjustmentType <> '') AND  adjType.AdjustmentType IS NULL

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'Missing Adjustment Type'
	FROM 
		#Import imp
		LEFT JOIN (SELECT * FROM Const_PlanAdjustmentType_sys WHERE FinYear = @finYear AND Enabled = 1) adjType ON imp.AdjustmentType = adjType.AdjustmentType
	WHERE
		(imp.PlanProjectItemID IS NULL OR imp.PlanProjectItemID = 0)
		AND (imp.AdjustmentType IS NULL OR imp.AdjustmentType = '') 

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'Incorrect Legislative Adjustment Reason'
	FROM 
		#Import imp
		LEFT JOIN (SELECT * FROM Const_PlanAdjustmentReason_sys WHERE FinYear = @finYear AND Enabled = 1) adjLegReason ON imp.LegislativeAdjustmentReason = adjLegReason.AdjustmentReason
	WHERE
		(imp.AdjustmentType IS NOT NULL AND imp.AdjustmentType <> '') AND  adjLegReason.AdjustmentReason IS NULL

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'Legislative Adjustment Reason and Reason for Adjustment required'
	FROM #Import imp
	WHERE (imp.AdjustmentType IS NOT NULL AND imp.AdjustmentType <> '') AND (LegislativeAdjustmentReason IS NULL OR LegislativeAdjustmentReason = '' OR ReasonForAdjustment IS NULL OR ReasonForAdjustment = '')

	--Budget Amounts differ but not adjustment type captured
	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'Budget Amounts Changed but not all Adjustment fields captured'
	FROM 
		#Import impDetail
		 INNER JOIN Plan_BudgetAdjustmentExportVersion_Detail expDetail ON impDetail.PlanProjectItemID = expDetail.PlanProjectItemID AND expDetail.BudgetAdjustmentExportImportVersionHeaderID = @BudgetAdjustmentExportImportVersionHeaderID
	WHERE 
		(impDetail.CurrentBudgetFinYear1 <> expDetail.CurrentBudgetFinYear1 OR impDetail.CurrentBudgetFinYear2 <> expDetail.CurrentBudgetFinYear2 OR impDetail.CurrentBudgetFinYear3 <> expDetail.CurrentBudgetFinYear3)
		AND (impDetail.AdjustmentType = '' OR impDetail.AdjustmentType IS NULL OR impDetail.LegislativeAdjustmentReason IS NULL OR impDetail.LegislativeAdjustmentReason = '' OR impDetail.ReasonForAdjustment IS NULL OR impDetail.ReasonForAdjustment = '')
		AND expDetail.PlanProjectItemID <> -1

	--SCOA segment does not exist
	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Project Segment does not exist'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Project_Structure proj ON imp.SCOAProjectCode = proj.ScoaCode
	WHERE
		proj.Scoacode IS NULL AND imp.ScoaProjectCode <> ''

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Function Segment does not exist'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Function_Structure func ON imp.SCOAFunctionCode = func.ScoaCode
	WHERE
		func.Scoacode IS NULL AND imp.ScoaFunctionCode <> ''

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Fund Segment does not exist'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Fund_Structure fund ON imp.SCOAFundCode = fund.ScoaCode
	WHERE
		fund.Scoacode IS NULL AND imp.ScoaFundCode <> ''

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Region Segment does not exist'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Region_Structure region ON imp.SCOARegionCode = region.ScoaCode
	WHERE
		region.Scoacode IS NULL AND imp.ScoaRegionCode <> ''

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Costing Segment does not exist'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Costing_Structure cost ON imp.SCOACostingCode = cost.ScoaCode
	WHERE
		cost.Scoacode IS NULL AND imp.ScoaCostingCode <> ''

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Item Segment does not exist'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
	WHERE
		item.Scoacode IS NULL AND imp.ScoaItemCode <> ''

	--SCOA segment not at posting level
	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Project Segment not at Posting Level'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Project_Structure proj ON imp.SCOAProjectCode = proj.ScoaCode
	WHERE
		proj.Scoacode IS NOT NULL AND imp.ScoaProjectCode <> '' AND PostingLevel <> 'Yes'

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Function Segment not at Posting Level'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Function_Structure func ON imp.SCOAFunctionCode = func.ScoaCode
	WHERE
		func.Scoacode IS NOT NULL AND imp.ScoaFunctionCode <> '' AND PostingLevel <> 'Yes'

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Fund Segment not at Posting Level'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Fund_Structure fund ON imp.SCOAFundCode = fund.ScoaCode
	WHERE
		fund.Scoacode IS NOT NULL AND imp.ScoaItemCode <> '' AND PostingLevel <> 'Yes'

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Region Segment not at Posting Level'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Region_Structure region ON imp.SCOARegionCode = region.ScoaCode
	WHERE
		region.Scoacode IS NOT NULL AND imp.ScoaRegionCode <> '' AND PostingLevel <> 'Yes'

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Costing Segment not at Posting Level'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Costing_Structure cost ON imp.SCOACostingCode = cost.ScoaCode
	WHERE
		cost.Scoacode IS NOT NULL AND imp.ScoaCostingCode <> '' AND PostingLevel <> 'Yes'

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Item Segment not at Posting Level'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
	WHERE
		item.Scoacode IS NOT NULL AND imp.ScoaItemCode <> '' AND PostingLevel <> 'Yes'

	--SCOA segments changed on existing Plan Project Item IDs
	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Project Segment cannot be changed on existing project'
	FROM 
		#Import impDetail
		 INNER JOIN Plan_BudgetAdjustmentExportVersion_Detail expDetail ON impDetail.PlanProjectItemID = expDetail.PlanProjectItemID AND expDetail.BudgetAdjustmentExportImportVersionHeaderID = @BudgetAdjustmentExportImportVersionHeaderID
	WHERE 
		impDetail.SCOAProjectCode <> expDetail.SCOAProjectCode
		AND expDetail.PlanProjectItemID <> -1

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Function Segment cannot be changed on existing plan project item'
	FROM 
		#Import impDetail
		 INNER JOIN Plan_BudgetAdjustmentExportVersion_Detail expDetail ON impDetail.PlanProjectItemID = expDetail.PlanProjectItemID AND expDetail.BudgetAdjustmentExportImportVersionHeaderID = @BudgetAdjustmentExportImportVersionHeaderID
	WHERE 
		impDetail.SCOAFunctionCode <> expDetail.SCOAFunctionCode
		AND expDetail.PlanProjectItemID <> -1

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Fund Segment cannot be changed on existing plan project item'
	FROM 
		#Import impDetail
		 INNER JOIN Plan_BudgetAdjustmentExportVersion_Detail expDetail ON impDetail.PlanProjectItemID = expDetail.PlanProjectItemID AND expDetail.BudgetAdjustmentExportImportVersionHeaderID = @BudgetAdjustmentExportImportVersionHeaderID
	WHERE 
		impDetail.SCOAFundCode <> expDetail.SCOAFundCode
		AND expDetail.PlanProjectItemID <> -1

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Region Segment cannot be changed on existing plan project item'
	FROM 
		#Import impDetail
		 INNER JOIN Plan_BudgetAdjustmentExportVersion_Detail expDetail ON impDetail.PlanProjectItemID = expDetail.PlanProjectItemID AND expDetail.BudgetAdjustmentExportImportVersionHeaderID = @BudgetAdjustmentExportImportVersionHeaderID
	WHERE 
		impDetail.SCOARegionCode <> expDetail.SCOARegionCode
		AND expDetail.PlanProjectItemID <> -1

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Costing Segment cannot be changed on existing plan project item'
	FROM 
		#Import impDetail
		 INNER JOIN Plan_BudgetAdjustmentExportVersion_Detail expDetail ON impDetail.PlanProjectItemID = expDetail.PlanProjectItemID AND expDetail.BudgetAdjustmentExportImportVersionHeaderID = @BudgetAdjustmentExportImportVersionHeaderID
	WHERE 
		impDetail.SCOACostingCode <> expDetail.SCOACostingCode
		AND expDetail.PlanProjectItemID <> -1

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'SCOA Item Segment cannot be changed on existing plan project item'
	FROM 
		#Import impDetail
		 INNER JOIN Plan_BudgetAdjustmentExportVersion_Detail expDetail ON impDetail.PlanProjectItemID = expDetail.PlanProjectItemID AND expDetail.BudgetAdjustmentExportImportVersionHeaderID = @BudgetAdjustmentExportImportVersionHeaderID
	WHERE 
		impDetail.SCOAItemCode <> expDetail.SCOAItemCode
		AND expDetail.PlanProjectItemID <> -1

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'MSC Department Code cannot be changed on existing plan project item'
	FROM 
		#Import impDetail
		 INNER JOIN Plan_BudgetAdjustmentExportVersion_Detail expDetail ON impDetail.PlanProjectItemID = expDetail.PlanProjectItemID AND expDetail.BudgetAdjustmentExportImportVersionHeaderID = @BudgetAdjustmentExportImportVersionHeaderID
	WHERE 
		REPLACE(impDetail.MSCDepartmentCode, CHAR(9), '') <> REPLACE(expDetail.MSCDepartmentCode, CHAR(9), '')
		AND expDetail.PlanProjectItemID <> -1

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'MSC Division Code cannot be changed on existing plan project item'
	FROM 
		#Import impDetail
		 INNER JOIN Plan_BudgetAdjustmentExportVersion_Detail expDetail ON impDetail.PlanProjectItemID = expDetail.PlanProjectItemID AND expDetail.BudgetAdjustmentExportImportVersionHeaderID = @BudgetAdjustmentExportImportVersionHeaderID
	WHERE 
		REPLACE(impDetail.MSCDivisionCode, CHAR(9), '') <> REPLACE(expDetail.MSCDivisionCode, CHAR(9), '')
		AND expDetail.PlanProjectItemID <> -1

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'Credit/Debit flag cannot be changed on existing plan project item'
	FROM 
		#Import impDetail
		 INNER JOIN Plan_BudgetAdjustmentExportVersion_Detail expDetail ON impDetail.PlanProjectItemID = expDetail.PlanProjectItemID AND expDetail.BudgetAdjustmentExportImportVersionHeaderID = @BudgetAdjustmentExportImportVersionHeaderID
	WHERE 
		impDetail.CreditDebit <> expDetail.CreditDebit
		AND expDetail.PlanProjectItemID <> -1

	--Budget amounts cannot all be zero
	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'Budget Amounts cannot all be zero'
	FROM
		#Import
	WHERE
		(CurrentBudgetFinYear1 = 0 AND CurrentBudgetFinYear2 = 0 AND CurrentBudgetFinYear3 = 0) AND ISNULL(PlanProjectItemID, 0) = 0

	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'Budget Amounts cannot all be zero'
	FROM
		#Import imp
		INNER JOIN 
			(
				 SELECT PlanProjectItemID, SUM(Debit) - SUM(Credit) AS Actual
				 FROM Led_GeneralLedger
				 WHERE FinYear = @finYear
				 GROUP BY PlanProjectItemID
			) led ON imp.PlanProjectItemID = led.PlanProjectItemID
	WHERE
		(CurrentBudgetFinYear1 = 0 AND CurrentBudgetFinYear2 = 0 AND CurrentBudgetFinYear3 = 0) AND ISNULL(imp.PlanProjectItemID, 0) <> 0 AND ISNULL(led.Actual, 0) <> 0

	--Monthly breakdown not equal to CurrentBudgetFinYear1
	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'Monthly breakdown does not equal to CurrentBudgetFinYear1'
	FROM
		#Import
	WHERE
		ABS(CurrentBudgetFinYear1) <> ABS(M1) + ABS(M2) + ABS(M3) + ABS(M4) + ABS(M5) + ABS(M6) + ABS(M7) + ABS(M8) + ABS(M9) + ABS(M10) + ABS(M11) + ABS(M12) 

	--No IDP 
	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'Project is not linked to the IDP'
	FROM
		#Import imp 
		LEFT JOIN Plan_AdjustmentProjectIDP pidp ON imp.AdjustmentProjectID = pidp.AdjustmentProjectID
	WHERE   
		(imp.ProjectID IS NOT NULL AND imp.ProjectID <> 0) AND pidp.AdjustmentProjectID IS NULL

	--Project Name already exists
	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT DISTINCT BudgetAdjustmentImportVersionDetail_ID, 'Project name already exists'
	FROM
		#Import imp 
		INNER JOIN Plan_AdjustmentProject pap ON imp.ProjectName = pap.AdjustmentProjectName
	WHERE   
		(imp.ProjectID IS NULL OR imp.ProjectID = 0) 
		AND pap.AdjustmentVersionId = @versionID

	--CreditDebit Flag
	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'Incorrect Debit/Credit flag'
	FROM
		#Import imp 
	WHERE   
		ISNULL(CreditDebit, '')  NOT IN ('C', 'D') 

	--Division does not exist
	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'Division Code does not exist'
	FROM 
		#Import imp	
		LEFT JOIN Const_Division div ON imp.MSCDivisionCode = div.DivisionCode
	WHERE
		div.Division_ID IS NULL

	--Check that IDP exists for new projects
	INSERT INTO Plan_BudgetAdjustmentImportVersion_DetailException
	SELECT BudgetAdjustmentImportVersionDetail_ID, 'IDP Item does not exist'
	FROM 
		#Import imp	
		LEFT JOIN IDP_Item idp ON (SELECT [Value] FROM [dbo].[Split_fxn](IDPItem, '|') WHERE ID = 1) = idp.ItemDesc and FinancialYear = @finYear AND IDPLevelNumber = @idpNumLevel
	WHERE
		(imp.ProjectID IS NULL OR imp.ProjectID = 0) 
		AND Item_ID IS NULL

	DROP TABLE #Import, #Const_SCOA_Structure, #Const_SCOA_Costing_Structure, #Const_SCOA_Function_Structure, #Const_SCOA_Fund_Structure, #Const_SCOA_Project_Structure, #Const_SCOA_Region_Structure

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetAdjustmentImportResult_sp]    Script Date: 2026/03/10 7:23:26 AM ******/
