-- =============================================
-- Author:		Chris Moodley
-- Create date: December 2022
-- Description:	Return ADJB import results
-- =============================================
CREATE PROCEDURE [dbo].[Plan_BudgetAdjustmentImportResult_sp] 
	-- Add the parameters for the stored procedure here
	 @budgetAdjustmentExportImportVersionHeaderID INT
	,@budgetAdjustmentImportVersionNumber INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE 
		 @countProjectExisting INT
		,@countProjectNew INT
		,@countErrorRecordIndividual INT
		,@countErrorRecordOverall INT
		,@finYear NVARCHAR(10)
		,@budgetY1 DECIMAL(18, 2)
		,@budgetY2 DECIMAL(18, 2)
		,@budgetY3 DECIMAL(18, 2)
		,@fileName NVARCHAR(200)

	SELECT @finYear = FinYear FROM Plan_BudgetAdjustmentExportImportVersion_Header WHERE BudgetAdjustmentExportImportVersionHeader_ID = @budgetAdjustmentExportImportVersionHeaderID

	SELECT 
		 @budgetY1 = SUM(CASE WHEN (((item.ScoaCode LIKE 'IR%' OR item.ScoaCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(CurrentBudgetFinYear1) ELSE ABS(CurrentBudgetFinYear1) END)
		,@budgetY2 = SUM(CASE WHEN (((item.ScoaCode LIKE 'IR%' OR item.ScoaCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(CurrentBudgetFinYear2) ELSE ABS(CurrentBudgetFinYear2) END)
		,@budgetY3 = SUM(CASE WHEN (((item.ScoaCode LIKE 'IR%' OR item.ScoaCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(CurrentBudgetFinYear3) ELSE ABS(CurrentBudgetFinYear3) END)
	FROM
		Plan_BudgetAdjustmentImportVersion_Detail det
		INNER JOIN Const_PlanCapitalOperationalTypes_sys capOp ON det.BudgetType = capOp.TypeName
		INNER JOIN Const_Scoa_Structure_ByYear(@finYear) item ON det.SCOAItemCode = item.ScoaCode
	WHERE
		det.BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND det.BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber

	SELECT @countProjectExisting = COUNT(DISTINCT det.ProjectID)
	FROM 
		Plan_BudgetAdjustmentImportVersion_Detail det
	WHERE
		det.BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND det.BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
		AND det.AdjustmentProjectID IS NOT NULL

	SELECT @countProjectNew = COUNT(DISTINCT det.ProjectName)
	FROM 
		Plan_BudgetAdjustmentImportVersion_Detail det
	WHERE
		det.BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND det.BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
		AND det.AdjustmentProjectID IS NULL

	SELECT @fileName = BudgetAdjustmentImportVersionFileName
	FROM Plan_BudgetAdjustmentImportVersion_File
	WHERE BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber

	SELECT @countErrorRecordIndividual = COUNT(DISTINCT detEx.BudgetAdjustmentImportVersionDetailID)
	FROM 
		Plan_BudgetAdjustmentImportVersion_DetailException detEx
		INNER JOIN Plan_BudgetAdjustmentImportVersion_Detail det on detEx.BudgetAdjustmentImportVersionDetailID = det.BudgetAdjustmentImportVersionDetail_ID
	WHERE	
		det.BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND det.BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
	
	SELECT @countErrorRecordOverall = COUNT(DISTINCT BudgetAdjustmentImportVersionException_ID)
	FROM 
		Plan_BudgetAdjustmentImportVersion_OverallException 
	WHERE	
		BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber

	SELECT 
		 ProjectCount = @countProjectExisting + @countProjectNew
		,BudgetTotalY1 = @budgetY1
		,BudgetTotalY2 = @budgetY2
		,BudgetTotalY3 = @budgetY3
		,ErrorRecord = CONVERT(VARCHAR, @countErrorRecordIndividual + @countErrorRecordOverall) + ' (Includes Overall Budget Errors)'
		,ImportFileName = @fileName
		,ImportStatus = CASE WHEN @countErrorRecordIndividual + @countErrorRecordOverall > 0 THEN 'Error' ELSE 'Success' END
		,BudgetExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID
		,BudgetImportVersionNumber = @budgetAdjustmentImportVersionNumber

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetAdjustmentImportVersion_Exception_sp]    Script Date: 2026/03/10 7:23:26 AM ******/
SET ANSI_NULLS ON
GO

