-- =============================================
-- Author:		Chris Moodley
-- Create date: December 2022
-- Description:	Return adjustment budget import exceptions
-- 230807 by CM:105236 - Include CostingProject field
-- =============================================
CREATE PROCEDURE [dbo].[Plan_BudgetAdjustmentImportVersion_Exception_sp]
	-- Add the parameters for the stored procedure here
	 @budgetAdjustmentExportImportVersionHeaderID INT 
	,@budgetAdjustmentImportVersionNumber INT 
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE @finYear NVARCHAR(10) 
	
	SELECT @finYear = FinYear FROM Plan_BudgetAdjustmentExportImportVersion_Header WHERE BudgetAdjustmentExportImportVersionHeader_ID = @budgetAdjustmentExportImportVersionHeaderID;

	WITH cte AS (SELECT det.*, ex.ExceptionDetail FROM Plan_BudgetAdjustmentImportVersion_Detail det LEFT JOIN Plan_BudgetAdjustmentImportVersion_DetailException ex ON det.BudgetAdjustmentImportVersionDetail_ID = ISNULL(ex.BudgetAdjustmentImportVersionDetailID, 0))

	SELECT 
		 FinYear1
		,FinYear2
		,FinYear3
		,AdjustmentVersionID
		,AdjustmentProjectID
		,IDPItem
		,ProjectID
		,ProjectCode
		,ProjectName
		,ProjectDesc
		,SingleMultiYear
		,CASE WHEN CostingProject IS NULL OR CostingProject = 0 THEN 'No'ELSE 'Yes' END CostingProject
		,PlanProjectItemID
		,BudgetType
		,SCOAProjectCode
		,SCOAProject
		,SCOAFunctionCode
		,SCOAFunction
		,MSCDepartmentCode
		,MSCDepartment
		,MSCDivisionCode
		,MSCDivision
		,MunicipalClassification
		,SCOAFundCode
		,SCOAFund
		,SCOARegionCode
		,SCOARegion
		,SCOACostingCode
		,SCOACosting
		,SCOAItemCode
		,SCOAItem
		,ItemDescription
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(CurrentBudgetFinYear1) ELSE ABS(CurrentBudgetFinYear1) END CurrentBudgetFinYear1
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(CurrentBudgetFinYear2) ELSE ABS(CurrentBudgetFinYear2) END CurrentBudgetFinYear2
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(CurrentBudgetFinYear3) ELSE ABS(CurrentBudgetFinYear3) END CurrentBudgetFinYear3
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(AvailableBudgetFinYear1) ELSE ABS(AvailableBudgetFinYear1) END AvailableBudgetFinYear1
		,SplitType
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M1) ELSE ABS(M1) END M1
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M2) ELSE ABS(M2) END M2
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M3) ELSE ABS(M3) END M3
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M4) ELSE ABS(M4) END M4
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M5) ELSE ABS(M5) END M5
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M6) ELSE ABS(M6) END M6
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M7) ELSE ABS(M7) END M7
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M8) ELSE ABS(M8) END M8
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M9) ELSE ABS(M9) END M9
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M10) ELSE ABS(M10) END M10
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M11) ELSE ABS(M11) END M11
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M12) ELSE ABS(M12) END M12
		,CreditDebit
		,GRAPClassification
		,GRAPClassificationNote
		,MainSegmentReporting
		,SubSegmentReporting
		,AdjustmentType
		,LegislativeAdjustmentReason
		,ReasonForAdjustment
		,ISNULL(STUFF(( SELECT  '; ' + US.ExceptionDetail
                        FROM    cte US
                        WHERE   US.BudgetAdjustmentImportVersionDetail_ID = det.BudgetAdjustmentImportVersionDetail_ID
                        FOR
                        XML PATH('')
                        ), 1, 1, ''), '') AS ExceptionDetail
	FROM 
		Plan_BudgetAdjustmentImportVersion_Detail det		
		LEFT JOIN Const_PlanCapitalOperationalTypes_sys pcot ON det.BudgetType = pcot.TypeName
	WHERE 
		BudgetAdjustmentExportImportVersionHeaderID = @BudgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @BudgetAdjustmentImportVersionNumber	

	UNION ALL

	SELECT 
		 '' FinYear1
		,'' FinYear2
		,'' FinYear3
		,0 AdjustmentVersionID
		,0 AdjustmentProjectID
		,'' IDPItem
		,0 ProjectID
		,0 ProjectCode
		,'' ProjectName
		,'' ProjectDesc
		,'' SingleMultiYear
		,'' CostingProject
		,0 PlanProjectItemID
		,'' BudgetType
		,'' SCOAProjectCode		
		,'' SCOAProject
		,'' SCOAFunctionCode
		,'' SCOAFunction
		,'' MSCDepartmentCode
		,'' MSCDepartment
		,'' MSCDivisionCode
		,'' MSCDivision
		,'' MunicipalClassification
		,'' SCOAFundCode
		,'' SCOAFund
		,'' SCOARegionCode
		,'' SCOARegion
		,'' SCOACostingCode
		,'' SCOACosting
		,'' SCOAItemCode
		,'' SCOAItem
		,'' ItemDescription
		,0 CurrentBudgetFinYear1
		,0 CurrentBudgetFinYear2
		,0 CurrentBudgetFinYear3
		,0  AvailableBudgetFinYear1
		,'' SplitType
		,0 M1
		,0 M2
		,0 M3
		,0 M4
		,0 M5
		,0 M6
		,0 M7
		,0 M8
		,0 M9
		,0 M10
		,0 M11
		,0 M12
		,'' CreditDebit
		,'' GRAPClassification
		,'' GRAPClassificationNote
		,'' MainSegmentReporting
		,'' SubSegmentReporting
		,'' AdjustmentType
		,'' LegislativeAdjustmentReason
		,'' ReasonForAdjustment
		,det.ExceptionDetail
	FROM 
		Plan_BudgetAdjustmentImportVersion_OverallException det		
	WHERE 
		BudgetAdjustmentExportImportVersionHeaderID = @BudgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @BudgetAdjustmentImportVersionNumber

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetAdjustmentImportVersion_sp]    Script Date: 2026/03/10 7:23:26 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Chris Moodley
-- Create date: November 2022
-- Description:	Import adjustment budget
-- 230220 by CM:  97614 - Set ProjectManagerID, SupplyChainOfficialID to NULL for new projects
-- 230511 by CM: 102604 - Fix month 8 insert for new plan project items for existing projects
-- 230807 by CM: 105236 - Include CostingProject field
-- =============================================
CREATE   PROCEDURE [dbo].[Plan_BudgetAdjustmentImportVersion_sp] 
	-- Add the parameters for the stored procedure here
	 @budgetAdjustmentExportImportVersionHeaderID INT
	,@budgetAdjustmentImportVersionNumber INT
	,@userID INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
               
    DECLARE 
        @currFinYear NVARCHAR(9) ,
        @currFinYearPlus1 NVARCHAR(9) ,
        @currFinYearPlus2 NVARCHAR(9) ,
		@versionIDmax INT,
        @IDPNumLevel NVARCHAR(5) = '0'

	SELECT 
		 @versionIDmax = AdjustmentVersionID
		,@currFinYear = FinYear
		,@currFinYearPlus1 = CAST(RIGHT(FinYear, 4) AS VARCHAR(50)) + '/' + CAST((RIGHT(FinYear, 4) + 1) AS VARCHAR(50))
		,@currFinYearPlus2 = CAST((RIGHT(FinYear, 4) + 1) AS VARCHAR(50)) + '/' + CAST((RIGHT(FinYear, 4) + 2) AS VARCHAR(50))
	FROM 
		Plan_BudgetAdjustmentExportImportVersion_Header 
	WHERE 
		BudgetAdjustmentExportImportVersionHeader_ID = @budgetAdjustmentExportImportVersionHeaderID

    SELECT @IDPNumLevel = IDPNumLevel
    FROM Const_IDPLevelDescription_Header
    WHERE FinancialYear = @CurrFinYear

	SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,ScoaDesc INTO #projectTable FROM Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @currFinYear
	SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,ScoaDesc INTO #functionTable FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @currFinYear
	SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,ScoaDesc,ScoaShortDesc INTO #itemTable FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @currFinYear
	SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,ScoaDesc INTO #fundsTable FROM dbo.Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @currFinYear
	SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,ScoaDesc INTO #costingTable FROM dbo.Const_SCOA_Costing_Structure_Consolidated WHERE FinYearText = @currFinYear
	SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,ScoaDesc INTO #regionalTable FROM dbo.Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @currFinYear             
               
	/* New Projects */
    /* Add data for Plan Project */
	INSERT  INTO dbo.Plan_AdjustmentProject
	( 
		ReferenceProject_ID,
		AdjustmentProjectName,
		AdjustmentProjectDesc,
		ProjectManagerID,
		SupplyChainOfficialID,
		CapitalOperation,
		CostEstimate,
		ScoaProjectID,
		EstimatedStartDate,
		EstimatedEndDate,
		ProjectStatus,
		CommencementDate,
		FinYear,
		ProjectDetailDesc,
		ProjectCategoryID,
		ProjectImplementAgentID,
		Longitude,
		Latitude,
		ProgrammeManagerID,
		FinancialControllerID,
		ProjectTypeID,
		EstimatedDuration,
		ProjectDistinctionID,
		IsDeleted,
		HistoricalProjectCode,
		ProjectParentID,
		SingleMultiYear,
		CapturerID,
		DateCaptured,
		ModifierID,
		DateModified,
		AdjustmentVersionId,
		IsRecommended,
		ProjectCode,
		CostingProject
	)
	SELECT DISTINCT 
		NULL,
		ProjectName,
		ProjectDesc,
		NULL,
		NULL,
		TypeValue,
		0,
		csps.ScoaID,
		NULL,
		NULL,
		6,
		NULL,
		@currFinYear,
		NULL,
		NULL,
		NULL,
		NULL,
		NULL,
		NULL,
		NULL,
		NULL,
		NULL,
		NULL,
		NULL,
		NULL,
		NULL,
		SingleMultiYear,
		@userID,
		GETDATE(),
		NULL,
		NULL,
		@versionIDmax,
		NULL,
		ProjectCode,
		CostingProject
	FROM    
		Plan_BudgetAdjustmentImportVersion_Detail p 
		INNER JOIN #projectTable csps on p.SCOAProjectCode = csps.ScoaCode 
		INNER JOIN Const_PlanCapitalOperationalTypes_sys pCot ON p.BudgetType = pcot.TypeName
	WHERE
		BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
		AND (ProjectID IS NULL OR ProjectID = 0) 
                       
	print 'project'	

     /* Add data for IDP Item */
    INSERT INTO dbo.IDP_Item
    ( 
		ItemDesc ,
        FinancialYear ,
        ItemParentID ,
        IDPLevelNumber ,
        ItemOrderID ,
        CapturerID ,
        DateCaptured ,
        ActProjID ,
        isProj 
    )
    SELECT DISTINCT
        pp.AdjustmentProjectName ,
        p.FinYear1 ,
        ( SELECT TOP 1 Item_ID FROM IDP_Item WHERE ItemDesc = p.IDPItem and FinancialYear = @currFinYear AND IDPLevelNumber = @IDPNumLevel ) ,
        50 ,
        ISNULL(( SELECT TOP 1
                        ItemOrderID + 1
                    FROM   IDP_Item
                    WHERE  ItemParentID = ( SELECT TOP 1
                                        Item_ID
                                        FROM
                                        IDP_Item
                                        WHERE
                                        ItemDesc = p.IDPItem
                                        )
                        AND IDPLevelNumber = 50
                        AND FinancialYear = p.FinYear1
                    ORDER BY ItemOrderID DESC
                ), 0) ,
        @userID ,
        GETDATE() ,
        NULL ,
        1
    FROM    
		Plan_BudgetAdjustmentImportVersion_Detail p
        INNER JOIN Plan_AdjustmentProject pp ON pp.AdjustmentProjectName = p.ProjectName
	WHERE
		BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
		AND (ProjectID IS NULL OR ProjectID = 0);
                                             
    /* Add data into Plan Project IDP */
    INSERT INTO dbo.Plan_AdjustmentProjectIDP
    ( 
		 ReferenceProjectIDPID
		,AdjustmentProjectID
		,ParentIDPItemID
		,AdjustmentProjectIDPItemID
		,[Percentage]
		,CapturerID
		,DateCaptured
		,ModifierID
		,DateModified
		,Latitude
		,Longitude
		,AdjustmentVersionId
    )
    SELECT DISTINCT
		NULL,
		pp.AdjustmentProject_ID ,
        ii.ItemParentID,
        ii.Item_ID,
        100.0 ,
        @userID ,
        GETDATE(),
		NULL,
		NULL,
		NULL,
		NULL,
		@versionIDmax
    FROM    
		Plan_BudgetAdjustmentImportVersion_Detail p
        INNER JOIN Plan_AdjustmentProject pp ON pp.AdjustmentProjectName = p.ProjectName AND p.FinYear1 = pp.FinYear
		INNER JOIN dbo.IDP_Item ii ON ii.ItemDesc = pp.AdjustmentProjectName AND FinancialYear = pp.FinYear
    WHERE
		BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
		AND (ProjectID IS NULL OR ProjectID = 0);


	print 'idp'	

    /* Add data into Project Costing */
    INSERT  INTO dbo.Plan_AdjustmentProjectCosting
    ( 
		 ReferenceProjectCostingID
		,AdjustmentProjectID
		,ScoaCostingID
		,CapturerID
		,DateCaptured
		,ModifierID
		,DateModified
		,AdjustmentVersionId
	)
    SELECT DISTINCT
		NULL,
        pp.AdjustmentProject_ID ,
        CSFS.ScoaID ,
        1 ,
        GETDATE(),
		null,
		null,
		@versionIDmax
    FROM    
		Plan_BudgetAdjustmentImportVersion_Detail p
        INNER JOIN Plan_AdjustmentProject pp ON pp.AdjustmentProjectName = p.ProjectName AND p.FinYear1 = pp.FinYear
        INNER JOIN #costingTable csfs ON p.SCOACostingCode = csfs.ScoaCode    
	WHERE
		BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
		AND (ProjectID IS NULL OR ProjectID = 0)
		AND pp.AdjustmentVersionId = @versionIDmax;

	print 'costing'	

    /* Add data into Project Function */
    INSERT  INTO dbo.Plan_AdjustmentProjectFunctions
    ( 
		 ReferenceProjectFunctionID
		,AdjustmentProjectID
		,ScoaFunctionID
		,CapturerID
		,DateCaptured
		,ModifierID
		,DateModified
		,AdjustmentVersionId
	)
    SELECT DISTINCT
		NULL,
        pp.AdjustmentProject_ID ,
        CSFS.ScoaID ,
        1 ,
        GETDATE(),
		null,
		null,
		@VersionIDmax                                                                                                         
    FROM    
		Plan_BudgetAdjustmentImportVersion_Detail p
        INNER JOIN Plan_AdjustmentProject pp ON pp.AdjustmentProjectName = p.ProjectName AND p.FinYear1 = pp.FinYear
        INNER JOIN #functionTable CSFS ON p.SCOAFunctionCode = csfs.ScoaCode
	WHERE
		BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
		AND (ProjectID IS NULL OR ProjectID = 0)
		AND pp.AdjustmentVersionId = @versionIDmax;

	print 'function'	

    /* Add data into Plan Project Region */
    INSERT  INTO dbo.Plan_AdjustmentProjectRegions
    (
		 ReferenceProjectRegionID
		,AdjustmentProjectID
		,ScoaRegionID
		,RegionPercent
		,CapturerID
		,DateCaptured
		,ModifierID
		,DateModified
		,AdjustmentVersionId
	)
    SELECT DISTINCT
		NULL,
        pp.AdjustmentProject_ID ,
        CSRS.ScoaID ,
        100.0 ,
        1 ,
        GETDATE(),
		null,
		null,
		@VersionIDmax
    FROM    
		Plan_BudgetAdjustmentImportVersion_Detail p
        INNER JOIN Plan_AdjustmentProject pp ON pp.AdjustmentProjectName = p.ProjectName  AND p.FinYear1 = pp.FinYear
        INNER JOIN #regionalTable CSRS ON p.SCOARegionCode = csrs.ScoaCode
	WHERE
		BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
		AND (ProjectID IS NULL OR ProjectID = 0)
		AND pp.AdjustmentVersionId = @versionIDmax;

	print 'region'	
                                                            
	/* Add data into Plan Project Divisions */
    INSERT  INTO dbo.Plan_AdjustmentProjectDivisions
    ( 
		 ReferenceProjectDivisionID
		,AdjustmentProjectID
		,DivisionID
		,CapturerID
		,DateCaptured
		,ModifierID
		,DateModified
		,AdjustmentVersionId
	)
    SELECT DISTINCT
		NULL,
        pp.AdjustmentProject_ID ,
        Division_ID ,
        1 ,
        GETDATE(),
		null,
		null,
		@VersionIDmax
    FROM    
		Plan_BudgetAdjustmentImportVersion_Detail p
        INNER JOIN Plan_AdjustmentProject pp ON pp.AdjustmentProjectName = p.ProjectName  AND p.FinYear1 = pp.FinYear 
		INNER JOIN Const_Division div ON p.MSCDivisionCode = div.DivisionCode
	WHERE
		BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
		AND (p.ProjectID IS NULL OR p.ProjectID = 0)
		AND pp.AdjustmentVersionId = @versionIDmax;

	print 'divisions'	
                                             
	/* Add data into Plan Project Fund */
    INSERT  INTO dbo.Plan_AdjustmentProjectFund
    ( 						
		 ReferenceProjectFundID
		,AdjustmentProjectID
		,ScoaFundID
		,FundAmount
		,FundReference
		,VirementId
		,AdjustmentId
		,CapturerID
		,DateCaptured
		,ModifierID
		,DateModified
		,AdjustmentVersionId
	)
    SELECT DISTINCT
		NULL,
        pp.AdjustmentProject_ID ,
        CSFS.ScoaID ,
        CASE When TypeValue in (0, 1, 4) THEN SUM(ABS(p.CurrentBudgetFinYear1) + ABS(p.CurrentBudgetFinYear2) + ABS(p.CurrentBudgetFinYear3)) ELSE 0 END,
		'',
		NULL,
		NULL,
        @userID,
        GETDATE() ,
		NULL,
		NULL,
		@VersionIDmax
    FROM    
		Plan_BudgetAdjustmentImportVersion_Detail p
        INNER JOIN Plan_AdjustmentProject pp ON pp.AdjustmentProjectName = p.ProjectName AND p.FinYear1 = pp.FinYear
        INNER JOIN #fundsTable CSFS ON p.ScoaFundCode = CSFS.ScoaCode  
		INNER JOIN Const_PlanCapitalOperationalTypes_sys pCot ON p.BudgetType = pCot.TypeName
	WHERE 
		BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
		AND (p.ProjectID IS NULL OR p.ProjectID = 0)
		AND pp.AdjustmentVersionId = @versionIDmax
    GROUP BY 
		pp.AdjustmentProject_ID ,
        CSFS.ScoaID ,
		TypeValue
                              
	print 'fund'	

    /* Add data into Plan Project Fund Yaer */
    INSERT  INTO dbo.Plan_AdjustmentProjectFundYear
    ( 
		 ReferenceProjectFundYearID
		,AdjustmentProjectFundID
		,FinYear
		,YearFundAmount
		,VirementId
		,AdjustmentId
		,CapturerID
		,DateCaptured
		,ModifierID
		,DateModified
		,AdjustmentVersionId
	)
    SELECT DISTINCT
		NULL,
        PF.AdjustmentProjectFund_ID ,
        FinYear1 ,
		CASE When TypeValue in (0, 1, 4) THEN SUM(ABS(p.CurrentBudgetFinYear1)) ELSE 0 END,
		NULL,
		NULL,
        @userID,
        GETDATE(),
		NULL,
		NULL,
		@VersionIDmax
    FROM    
		Plan_BudgetAdjustmentImportVersion_Detail p
        INNER JOIN Plan_AdjustmentProject pp ON pp.AdjustmentProjectName = p.ProjectName  AND p.FinYear1 = pp.FinYear
        INNER JOIN Plan_AdjustmentProjectFund PF ON PF.AdjustmentProjectID = pp.AdjustmentProject_ID 
		INNER JOIN Const_PlanCapitalOperationalTypes_sys pCot ON p.BudgetType = pCot.TypeName
	WHERE 
		BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
		AND (p.ProjectID IS NULL OR p.ProjectID = 0)
		AND pp.AdjustmentVersionId = @versionIDmax
    GROUP BY 
        TypeValue, 
        FinYear1,
		pf.AdjustmentProjectFund_ID

    UNION ALL

    SELECT DISTINCT
		NULL,
        PF.AdjustmentProjectFund_ID ,
        FinYear2 ,
		CASE When TypeValue in (0, 1, 4) THEN SUM(ABS(p.CurrentBudgetFinYear2)) ELSE 0 END,
		NULL,
		NULL,
        @userID,
        GETDATE(),
		NULL,
		NULL,
		@VersionIDmax
    FROM    
		Plan_BudgetAdjustmentImportVersion_Detail p
        INNER JOIN Plan_AdjustmentProject pp ON pp.AdjustmentProjectName = p.ProjectName  AND p.FinYear1 = pp.FinYear
        INNER JOIN Plan_AdjustmentProjectFund PF ON PF.AdjustmentProjectID = pp.AdjustmentProject_ID 
		INNER JOIN Const_PlanCapitalOperationalTypes_sys pCot ON p.BudgetType = pCot.TypeName
	WHERE 
		BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
		AND (p.ProjectID IS NULL OR p.ProjectID = 0)
		AND pp.AdjustmentVersionId = @versionIDmax
    GROUP BY 
        TypeValue, 
        FinYear2,
		pf.AdjustmentProjectFund_ID

    UNION ALL

    SELECT DISTINCT
		NULL,
        PF.AdjustmentProjectFund_ID ,
        FinYear3 ,
		CASE When TypeValue in (0, 1, 4) THEN SUM(ABS(p.CurrentBudgetFinYear3)) ELSE 0 END,
		NULL,
		NULL,
        @userID,
        GETDATE(),
		NULL,
		NULL,
		@VersionIDmax
    FROM    
		Plan_BudgetAdjustmentImportVersion_Detail p
        INNER JOIN Plan_AdjustmentProject pp ON pp.AdjustmentProjectName = p.ProjectName  AND p.FinYear1 = pp.FinYear
        INNER JOIN Plan_AdjustmentProjectFund PF ON PF.AdjustmentProjectID = pp.AdjustmentProject_ID 
		INNER JOIN Const_PlanCapitalOperationalTypes_sys pCot ON p.BudgetType = pCot.TypeName
	WHERE 
		BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
		AND (p.ProjectID IS NULL OR p.ProjectID = 0)
		AND pp.AdjustmentVersionId = @versionIDmax
    GROUP BY 
        TypeValue, 
        FinYear3,
		pf.AdjustmentProjectFund_ID

	print 'fund year'	

    /* Add data into Plan Project Item */
    INSERT  INTO dbo.Const_ProjectItem
    ( 
		ItemDescription ,
        [Enabled] ,
        DateCaptured ,
        CapturerID,
		DateModified,
		ModifierID,
		FinYear,
		PreviousReferenceID
    )
    SELECT DISTINCT
        p.ItemDescription ,
        1 ,
        GETDATE() ,
        1,
		NULL,
		NULL,
		FinYear1,
		NULL
    FROM    
		Plan_BudgetAdjustmentImportVersion_Detail p
        LEFT JOIN Const_ProjectItem CPI ON CPI.ItemDescription = p.ItemDescription AND CPI.FinYear = @currFinYear
    WHERE   
		CPI.ProjectItem_ID IS NULL;

	print 'project item'	

    INSERT  INTO dbo.Plan_AdjustmentProjectItem
    ( 
		 ReferencePlanProjectItem_ID
		,AdjustmentProjectID
		,ProjectItemID
		,SCOAItemID
		,FinYear
		,ProjectFundYearID
		,SCOAFundId
		,BudgetAmount
		,BudgetAmountCurP1
		,BudgetAmountCurP2
		,AdjustedBudgetAmount
		,AdjustedBudgetAmountCurP1
		,AdjustedBudgetAmountCurP2
		,SCOAFunctionId
		,SCOARegionId
		,DivisionId
		,BudgetSplitID
		,VirementId
		,HistoricalProjectCode
		,AdjustmentId
		,ModificationNumber
		,SCOACostingID
		,IsItemLocked
		,CreditDebit
		,AdjutmentType
		,LegislativeReasonAdjustment
		,ReasonForAdjustment
		,CapturerID
		,DateCaptured
		,ModifierID
		,DateModified
		,AdjustmentVersionId
		,GRAPClassification
		,GRAPClassificationNote
		,MainSegmentReporting
		,SubSegmentReporting
	)
    SELECT DISTINCT
		NULL,
        pp.AdjustmentProject_ID ,
        CPI.ProjectItem_ID ,
        item.ScoaID ,
        p.FinYear1 ,
        PPF.AdjustmentProjectFundYear_ID ,
		fund.ScoaID ,
		NULL,
		NULL,
		NULL,
        SUM(ABS(ISNULL(p.CurrentBudgetFinYear1, 0))) ,
        SUM(ABS(ISNULL(p.CurrentBudgetFinYear2, 0))) ,
        SUM(ABS(ISNULL(p.CurrentBudgetFinYear3, 0))) ,
        func.ScoaID ,
		region.ScoaID,
        div.Division_ID ,
		budSplit.DivideBy_ID,
		NULL,
		'',
		NULL,
		NULL,                                                                                     
        cost.ScoaID ,
		NULL,
		p.CreditDebit,
		adjType.AdjustmentType_ID,
		adjReason.AdjustmentReason_ID,
		p.ReasonForAdjustment,
		@userID,
		GETDATE(),
		NULL,
		NULL,
		@VersionIDmax,
		GRAPClassification,
		GRAPClassificationNote,
		MainSegmentReporting,
		SubSegmentReporting
    FROM    
		Plan_BudgetAdjustmentImportVersion_Detail p
        INNER JOIN Plan_AdjustmentProject pp ON pp.AdjustmentProjectName = p.ProjectName  AND p.FinYear1 = pp.FinYear
        INNER JOIN #fundsTable fund ON fund.ScoaCode = p.ScoaFundCode
        INNER JOIN (SELECT MIN(ProjectItem_ID) ProjectItem_ID, ItemDescription, FinYear FROM Const_ProjectItem WHERE FinYear = @currFinYear GROUP BY ItemDescription, FinYear) CPI ON CPI.ItemDescription = p.ItemDescription and CPI.FinYear = p.FinYear1
        INNER JOIN #itemTable item ON item.ScoaCode = p.SCOAItemCode
        INNER JOIN (SELECT MIN (AdjustmentProjectFund_ID) AdjustmentProjectFund_ID, AdjustmentProjectID, ScoaFundID FROM Plan_AdjustmentProjectFund group by AdjustmentProjectID, ScoaFundID) PF ON PF.AdjustmentProjectID = pp.AdjustmentProject_ID and PF.ScoaFundID = fund.ScoaID                                                 
        INNER JOIN (SELECT MIN(AdjustmentProjectFundYear_ID) AdjustmentProjectFundYear_ID, AdjustmentProjectFundID, FinYear FROM dbo.Plan_AdjustmentProjectFundYear WHERE FinYear = @currFinYear GROUP BY AdjustmentProjectFundID, FinYear) PPF ON PPF.AdjustmentProjectFundID = PF.AdjustmentProjectFund_ID AND PPF.FinYear = @currFinYear
        INNER JOIN #functionTable func ON func.ScoaCode = p.SCOAFunctionCode
        INNER JOIN #regionalTable region ON region.ScoaCode = p.SCOARegionCode
        INNER JOIN #costingTable cost ON cost.ScoaCode = p.SCOACostingCode
		INNER JOIN Const_Division div ON p.MSCDivisionCode = div.DivisionCode
		INNER JOIN Const_PlanAdjustmentType_sys adjType ON p.AdjustmentType = adjType.AdjustmentType AND adjType.FinYear = @currFinYear
		INNER JOIN Const_PlanAdjustmentReason_sys adjReason ON p.LegislativeAdjustmentReason = adjReason.AdjustmentReason AND adjReason.FinYear = @currFinYear
		INNER JOIN Const_BudgetSplitOptions budSplit ON p.SplitType = budSplit.BudgetSplitDesc
    WHERE 
		BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
		AND (p.ProjectID IS NULL OR p.ProjectID = 0)
		AND pp.AdjustmentVersionId = @versionIDmax
    GROUP BY 
		pp.AdjustmentProject_ID ,
        CPI.ProjectItem_ID ,
        item.ScoaID ,
        p.FinYear1 ,
        PPF.AdjustmentProjectFundYear_ID ,
        func.ScoaID ,
        fund.ScoaID ,
        region.ScoaID ,
        cost.ScoaID ,
        div.Division_ID ,
		budSplit.DivideBy_ID ,
		p.CreditDebit ,
		adjType.AdjustmentType_ID,
		adjReason.AdjustmentReason_ID,
		p.ReasonForAdjustment,
		GRAPClassification,
		GRAPClassificationNote,
		MainSegmentReporting,
		SubSegmentReporting

	print 'project ppi'	

	/* Add data into Plan Project Item Month wise*/
    INSERT  INTO dbo.Plan_AdjustmentProjectItemMonth
    ( 
		 ReferenceProjectItemMonthID
		,PlanAdjustmentProjectItemID
		,MonthID
		,UnitQuantity
		,UnitPrice
		,CaptureID
		,DateCaptured
		,ModifierID
		,DateModified
		,VirementId
		,AdjustmentId
		,AdjustmentVersionId
		,AdjustedUnitPrice
    )
                                                                           
    /* Add data into Plan Project Item Month 1*/
    SELECT DISTINCT
		NULL,
        PPI.PlanAdjustmentProjectItem_ID,
        7 AS MonthID ,
        1 AS UnitQuantity ,
		0 as UnitPrice,
        @userID AS CaptureID ,
        GETDATE() AS DateCaptured ,
        NULL AS ModifierID ,
        NULL AS DateModified,
		NULL,
		NULL,
		@versionIDmax,
		ABS(ISNULL(p.M1, 0)) AS AdjustedUnitPrice                                                                                                     
    FROM    
		Plan_BudgetAdjustmentImportVersion_Detail p
        INNER JOIN Plan_AdjustmentProject pp ON pp.AdjustmentProjectName = p.ProjectName AND p.FinYear1 = pp.FinYear
        INNER JOIN #fundsTable fund ON fund.ScoaCode = p.ScoaFundCode
