        INNER JOIN Plan_AdjustmentProject pp ON pp.AdjustmentProjectName = p.ProjectName AND p.FinYear1 = pp.FinYear
        INNER JOIN #fundsTable fund ON fund.ScoaCode = p.ScoaFundCode
        INNER JOIN (SELECT MIN(ProjectItem_ID) ProjectItem_ID, ItemDescription, FinYear FROM Const_ProjectItem WHERE FinYear = @currFinYear GROUP BY ItemDescription, FinYear) CPI ON CPI.ItemDescription = p.ItemDescription and CPI.FinYear = p.FinYear1
        INNER JOIN #itemTable item ON item.Scoacode = p.SCOAItemcode
		INNER JOIN (SELECT MIN (AdjustmentProjectFund_ID) AdjustmentProjectFund_ID, AdjustmentProjectID, ScoaFundID FROM Plan_AdjustmentProjectFund group by AdjustmentProjectID, ScoaFundID) PF ON PF.AdjustmentProjectID = pp.AdjustmentProject_ID and PF.ScoaFundID = fund.ScoaID                                              
        INNER JOIN (SELECT MIN(AdjustmentProjectFundYear_ID) AdjustmentProjectFundYear_ID, AdjustmentProjectFundID, FinYear FROM dbo.Plan_AdjustmentProjectFundYear WHERE FinYear = @currFinYear GROUP BY AdjustmentProjectFundID, FinYear) PPF ON PPF.AdjustmentProjectFundID = PF.AdjustmentProjectFund_ID AND PPF.FinYear = @currFinYear
        INNER JOIN #functionTable func ON func.ScoaCode = p.SCOAFunctionCode
        INNER JOIN #regionalTable region ON region.ScoaCode = p.SCOARegionCode
        INNER JOIN #costingTable cost ON cost.ScoaCode = p.SCOACostingCode
		INNER JOIN Const_Division div ON p.MSCDivisionCode = div.DivisionCode
        INNER JOIN Plan_AdjustmentProjectItem PPI ON PPI.AdjustmentProjectID = pp.AdjustmentProject_ID
                                            AND PPI.ProjectItemID = CPI.ProjectItem_ID
                                            AND PPI.SCOAItemID = item.ScoaID
                                            AND PPI.FinYear = p.FinYear1
                                            AND PPI.ProjectFundYearID = PPF.AdjustmentProjectFundYear_ID
