	/* Adjustment Plan Project Item */
	UPDATE pp
	SET
		AdjustedBudgetAmount = ABS(ISNULL(CurrentBudgetFinYear1, 0)),
		AdjustedBudgetAmountCurP1 = ABS(ISNULL(CurrentBudgetFinYear2, 0)),
		AdjustedBudgetAmountCurP2 = ABS(ISNULL(CurrentBudgetFinYear3, 0)),
		AdjutmentType = adjType.AdjustmentType_ID,
		LegislativeReasonAdjustment = adjReason.AdjustmentReason_ID,
		ReasonForAdjustment = p.ReasonForAdjustment,
		ModifierID = @userID,
		DateModified = GETDATE(),
		GRAPClassification = p.GRAPClassification,
		GRAPClassificationNote = p.GRAPClassificationNote,
		MainSegmentReporting = p.MainSegmentReporting,
		SubSegmentReporting = p.SubSegmentReporting
