	-- Plan_AdjustmentProjectFund
	UPDATE 
		ppf
	SET 
		FundAmount = ISNULL(YTot, 0)
	FROM
		(
			SELECT 
				AdjustmentProjectID, 
				ScoaFundID, 
				CASE WHEN CapitalOperation IN (0, 1, 4) THEN SUM(ISNULL(AdjustedBudgetAmount, BudgetAmount)) ELSE 0 END Y1, 
				CASE WHEN CapitalOperation IN (0, 1, 4) THEN SUM(ISNULL(AdjustedBudgetAmountCurP1, BudgetAmountCurP1)) ELSE 0 END Y2, 
				CASE WHEN CapitalOperation IN (0, 1, 4) THEN SUM(ISNULL(AdjustedBudgetAmountCurP2, BudgetAmountCurP1)) ELSE 0 END Y3, 
				CASE WHEN CapitalOperation IN (0, 1, 4) 
					THEN SUM(ISNULL(AdjustedBudgetAmount, BudgetAmount)) + SUM(ISNULL(AdjustedBudgetAmountCurP1, BudgetAmountCurP1)) + SUM(ISNULL(AdjustedBudgetAmountCurP2, BudgetAmountCurP2)) 
					ELSE 0 
				END YTot
			FROM 
				Plan_AdjustmentProjectItem papi 
				INNER JOIN Plan_AdjustmentProject pap ON papi.AdjustmentProjectID = pap.AdjustmentProject_ID
			WHERE 
				papi.AdjutmentType IS NOT NULL AND papi.AdjustmentVersionId = @versionIDmax
			GROUP BY 
				AdjustmentProjectID, ScoafundID, CapitalOperation
		) ppi

		LEFT JOIN Plan_AdjustmentProjectFund ppf ON ppi.AdjustmentProjectID = ppf.AdjustmentProjectID AND ppi.ScoafundId = ppf.ScoafundID

	UPDATE 
		ppfy
	SET 
		YearFundAmount = ISNULL(Y1,0)
	from
		(
			SELECT 
				AdjustmentProjectID, 
				ScoaFundID, 
				CASE WHEN CapitalOperation IN (0, 1, 4) THEN SUM(ISNULL(AdjustedBudgetAmount, BudgetAmount)) ELSE 0 END Y1
			FROM 
				Plan_AdjustmentProjectItem papi 
				INNER JOIN Plan_AdjustmentProject pap ON papi.AdjustmentProjectID = pap.AdjustmentProject_ID
			WHERE 
				papi.AdjutmentType IS NOT NULL AND papi.AdjustmentVersionId = @versionIDmax
			GROUP BY 
				AdjustmentProjectID, ScoafundID, CapitalOperation
		) ppi

		LEFT JOIN Plan_AdjustmentProjectFund ppf ON ppi.AdjustmentProjectID = ppf.AdjustmentProjectId AND ppi.ScoafundId = ppf.ScoafundID

		LEFT JOIN Plan_AdjustmentProjectFundYear ppfy ON ppf.AdjustmentProjectFund_ID = ppfy.AdjustmentProjectFundID AND FinYear = @currFinYear

	UPDATE 
		ppfy
	SET 
		YearFundAmount = ISNULL(Y2,0)
	from
		(
			SELECT 
				AdjustmentProjectID, 
				ScoaFundID, 
				CASE WHEN CapitalOperation IN (0, 1, 4) THEN SUM(ISNULL(AdjustedBudgetAmountCurP1, BudgetAmountCurP1)) ELSE 0 END Y2
			FROM 
				Plan_AdjustmentProjectItem papi 
				INNER JOIN Plan_AdjustmentProject pap ON papi.AdjustmentProjectID = pap.AdjustmentProject_ID
			WHERE 
				papi.AdjutmentType IS NOT NULL AND papi.AdjustmentVersionId = @versionIDmax
			GROUP BY 
				AdjustmentProjectID, ScoafundID, CapitalOperation
		) ppi

		LEFT JOIN Plan_AdjustmentProjectFund ppf ON ppi.AdjustmentProjectID = ppf.AdjustmentProjectId AND ppi.ScoafundId = ppf.ScoafundID

		LEFT JOIN Plan_AdjustmentProjectFundYear ppfy ON ppf.AdjustmentProjectFund_ID = ppfy.AdjustmentProjectFundID AND FinYear = @currFinYearPlus1

	UPDATE 
		ppfy
	SET 
		YearFundAmount = ISNULL(Y3,0)
	from
		(
			SELECT 
				AdjustmentProjectID, 
				ScoaFundID, 
				CASE WHEN CapitalOperation IN (0, 1, 4) THEN SUM(ISNULL(AdjustedBudgetAmountCurP2, BudgetAmountCurP2)) ELSE 0 END Y3
			FROM 
