				INNER JOIN Plan_AdjustmentProject pap ON papi.AdjustmentProjectID = pap.AdjustmentProject_ID
			WHERE 
				papi.AdjutmentType IS NOT NULL AND papi.AdjustmentVersionId = @versionIDmax
			GROUP BY 
				AdjustmentProjectID, ScoafundID, CapitalOperation
		) ppi

		LEFT JOIN Plan_AdjustmentProjectFund ppf ON ppi.AdjustmentProjectID = ppf.AdjustmentProjectId AND ppi.ScoafundId = ppf.ScoafundID

		LEFT JOIN Plan_AdjustmentProjectFundYear ppfy ON ppf.AdjustmentProjectFund_ID = ppfy.AdjustmentProjectFundID AND FinYear = @currFinYearPlus2

	--Import Status
	UPDATE Plan_BudgetAdjustmentExportImportVersion_Header
	SET StatusID = 321
	WHERE BudgetAdjustmentExportImportVersionHeader_ID = @budgetAdjustmentExportImportVersionHeaderID

	--Project Code
	DECLARE @projectCode INT  = (SELECT GREATEST(( SELECT MAX(ProjectCode) FROM Plan_Project ), ( SELECT MAX(ProjectCode) FROM Plan_AdjustmentProject )) + 1)

	UPDATE Plan_AdjustmentProject 
	SET ProjectCode  = @projectCode , @projectCode = @projectCode + 1
	WHERE ISNULL(ProjectCode, 0) = 0 AND AdjustmentVersionId = @versionIDmax

	-- funding sources
	DECLARE @FundSourceHeaderID INT = 0;
    DECLARE @StartFinYear INT = 0;
    DECLARE @CurrFinYear1 VARCHAR(50), @FinYear VARCHAR(50);
    SELECT @FinYear = @currFinYear

	WHILE ( @StartFinYear <= 2 )
    BEGIN                                                            
                                                            
		SELECT  
			@CurrFinYear1 = 
				CASE WHEN @StartFinYear = 0 THEN @currFinYear
                     WHEN @StartFinYear = 1 THEN @currFinYearPlus1
                     WHEN @StartFinYear = 2 THEN @currFinYearPlus2
                     ELSE @currFinYear
                END;

        SELECT TOP 1
                @FundSourceHeaderID = AdjustmentFundingSourceBudgetHeader_ID
        FROM    Plan_AdjustmentFundingSourceBudget_Header
        WHERE   FinancialYear = @CurrFinYear1;

        IF @FundSourceHeaderID = 0
        BEGIN
            INSERT INTO Plan_AdjustmentFundingSourceBudget_Header
            SELECT @CurrFinYear1, 1, GETDATE() , @userID , NULL, NULL, NULL, @versionIDmax 

            SELECT TOP 1 @FundSourceHeaderID = AdjustmentFundingSourceBudgetHeader_ID
            FROM    Plan_AdjustmentFundingSourceBudget_Header
            WHERE   FinancialYear = @CurrFinYear1;
         END;

	------------------------------------------------------------------------------
	-- Update Budget Amount for Existing Fund Id
	------------------------------------------------------------------------------

        UPDATE  
			dbo.Plan_AdjustmentFundingSourceBudget_Detail
        SET     
			FundingSourceBudget = FundingSourceBudget
                + CASE WHEN FundBal.Remain < 0
                        THEN ( FundBal.Remain * -1 )
                            + FundBal.NwAllocAmount
                        WHEN FundBal.Remain > 0
                            AND FundBal.Actual < FundBal.NwAllocAmount
                        THEN FundBal.NwAllocAmount
                        ELSE 0
                    END
        FROM    
			( SELECT    
				SCOAFundID ,
                @FundSourceHeaderID AS FundSourceHeaderId ,
                HRBudget.NwAllocAmount ,
                HRBudget.Budget AS Actual ,
                HRBudget.Budget - HRBudget.Allocated AS Remain
             FROM      
				( SELECT    
					F.ScoaID AS SCOAFundID ,
                    ( CASE
                        WHEN @StartFinYear = 0
							THEN SUM(ABS(ISNULL(R.CurrentBudgetFinYear1, 0)))
                        WHEN @StartFinYear = 1
							THEN SUM(ABS(ISNULL(R.CurrentBudgetFinYear2, 0)))
                        WHEN @StartFinYear = 2
						 THEN SUM(ABS(ISNULL(R.CurrentBudgetFinYear3, 0)))
					END ) AS NwAllocAmount ,
					ISNULL(dbo.Planing_GetFundAvailableAmount(F.ScoaID,
                        @CurrFinYear1),
                        0) AS Budget ,
					ISNULL(dbo.Planing_GetFundAllocatedAmount(F.ScoaID,
                        @CurrFinYear1,@FinYear),
                        0) AS Allocated
					FROM      
						Plan_BudgetAdjustmentImportVersion_Detail R
						INNER JOIN #fundsTable F ON R.ScoaFundCode = F.ScoaCode
						INNER JOIN Const_PlanCapitalOperationalTypes_sys cPot ON R.BudgetType = cPot.TypeName
					WHERE 
						BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
						AND TypeValue  in (0, 1, 4)
					GROUP BY  
						R.ScoaFundCode ,
						F.ScoaID
				) AS HRBudget
            ) AS FundBal
				INNER JOIN 
				( SELECT ScoaID AS FundId ,
                                AdjustmentFundingSourceBudgetHeaderID AS BudgetHeaderId ,
                                MIN(AdjustmentFundingSourceBudgetDetail_ID) AS UpdateFundingSourceBudgetDetailID
                            FROM   Plan_AdjustmentFundingSourceBudget_Detail
                            WHERE  AdjustmentFundingSourceBudgetHeaderID = @FundSourceHeaderID
                            GROUP BY ScoaID ,
                                AdjustmentFundingSourceBudgetHeaderID
                        ) AS UpdateBal ON FundBal.SCOAFundID = UpdateBal.FundId
                                        AND FundBal.FundSourceHeaderId = UpdateBal.BudgetHeaderId
						-- Condition to get Data to be Updated for Plan_FundingSourceBudget_Detail
                        WHERE   Plan_AdjustmentFundingSourceBudget_Detail.AdjustmentFundingSourceBudgetHeaderID = @FundSourceHeaderID
                                AND ScoaID = FundBal.SCOAFundID
                                AND Plan_AdjustmentFundingSourceBudget_Detail.AdjustmentFundingSourceBudgetDetail_ID = UpdateFundingSourceBudgetDetailID;
                                                                                                         
------------------------------------------------------------------------------
-- Create Budget Detail for Budget Amount for Fund Id not found 
------------------------------------------------------------------------------
                        INSERT  INTO dbo.Plan_AdjustmentFundingSourceBudget_Detail
                                ( AdjustmentFundingSourceBudgetHeaderID ,
                                  AdjustmentFundingSourceID ,
                                  ScoaID ,
                                  FundingSourceBudget ,
                                  DateCaptured ,
                                  CapturerID ,
                                  DateModified ,
                                  ModifierID,
								  isHidden,
								  UploadedDocument,
								  RefFundingSourceDetailId,
								  AdjustmentFundingVersionId
                                )
                                SELECT  @FundSourceHeaderID ,
                                        NULL ,
                                        F.ScoaID AS SCOAFundID ,
                                        ( CASE
											WHEN @StartFinYear = 0
												THEN SUM(ABS(ISNULL(R.CurrentBudgetFinYear1, 0)))
											WHEN @StartFinYear = 1
												THEN SUM(ABS(ISNULL(R.CurrentBudgetFinYear2, 0)))
											WHEN @StartFinYear = 2
												THEN SUM(ABS(ISNULL(R.CurrentBudgetFinYear3, 0)))
										END ) AS NwAllocAmount ,
                                        GETDATE() ,
                                        @userID ,
										NULL,
										NULL,
                                        0,
                                        NULL,
										NULL,
										@versionIDmax
                                FROM    Plan_BudgetAdjustmentImportVersion_Detail R
                                        INNER JOIN #fundsTable F ON R.ScoaFundCode = F.ScoaCode
										INNER JOIN Const_PlanCapitalOperationalTypes_sys cPot ON R.BudgetType = cPot.TypeName
                                WHERE   ISNULL(dbo.Planing_GetFundAvailableAmount(F.ScoaID,
                                                              @CurrFinYear1),
                                               0) = 0
										AND BudgetAdjustmentExportImportVersionHeaderID = @budgetAdjustmentExportImportVersionHeaderID AND BudgetAdjustmentImportVersionNumber = @budgetAdjustmentImportVersionNumber
                                        AND TypeValue  in (0, 1, 4)
                                GROUP BY F.ScoaID;

                        SET @StartFinYear = @StartFinYear + 1;
                    END;
                                           

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetAdjustmentNTValidation_sp]    Script Date: 2026/03/10 7:23:26 AM ******/
