				INNER JOIN (SELECT MIN(ProjectItem_ID) ProjectItem_ID, ItemDescription, FinYear FROM Const_ProjectItem WHERE FinYear = @currFinYear GROUP BY ItemDescription, FinYear) CPI ON CPI.ItemDescription = p.ItemDescription and CPI.FinYear = p.FinYear1
				INNER JOIN #itemTable item ON item.Scoacode = p.SCOAItemcode
				INNER JOIN (SELECT MIN (ProjectFund_ID) ProjectFund_ID, ProjectID, ScoaFundID FROM Plan_ProjectFund group by ProjectID, ScoaFundID) PF ON PF.ProjectID = pp.Project_ID and PF.ScoaFundID = fund.ScoaID                                              
				INNER JOIN (SELECT MIN(ProjectFundYear_ID) ProjectFundYear_ID, ProjectFundID, FinYear FROM dbo.Plan_ProjectFundYear WHERE FinYear = @currFinYear GROUP BY ProjectFundID, FinYear) PPF ON PPF.ProjectFundID = PF.ProjectFund_ID AND PPF.FinYear = @currFinYear
				INNER JOIN #functionTable func ON func.ScoaCode = p.SCOAFunctionCode
				INNER JOIN #regionalTable region ON region.ScoaCode = p.SCOARegionCode
				INNER JOIN #costingTable cost ON cost.ScoaCode = p.SCOACostingCode
				INNER JOIN Const_Division div ON p.MSCDivisionCode = div.DivisionCode
				INNER JOIN Plan_ProjectItem PPI ON PPI.ProjectID = pp.Project_ID
													AND PPI.ProjectItemID = CPI.ProjectItem_ID
													AND PPI.SCOAItemID = item.ScoaID
													AND PPI.FinYear = p.FinYear1
													AND PPI.ProjectFundYearID = PPF.ProjectFundYear_ID
													AND PPI.SCOAFunctionId = func.ScoaID
													AND PPI.SCOAFundId = fund.ScoaID
													AND PPI.SCOARegionId = region.ScoaID
													AND PPI.SCOACostingId = cost.ScoaID
													AND PPI.DivisionID = div.Division_ID                                                                                                                                                                                                                                   
			WHERE 
