				SUM(ABS(ISNULL(p.M12, 0))) AS UnitPrice,
				@userID AS CaptureID ,
				GETDATE() AS DateCaptured ,
				NULL AS ModifierID ,
				NULL AS DateModified,
				NULL,
				NULL,
				NULL                                                                                                    
			FROM    
				Plan_BudgetOriginalImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.ProjectName = p.ProjectName AND p.FinYear1 = pp.FinYear
