			/* Add data for Plan Project */
	
			/* Add data into Project Costing */
			INSERT  INTO dbo.Plan_ProjectCosting
			( 
				 ProjectID
				,ScoaCostingID
				,CapturerID
				,DateCaptured
				,ModifierID
				,DateModified
				,PreviousReferenceId
			)
			SELECT DISTINCT
				pp.Project_ID ,
				CSFS.ScoaID ,
				1 ,
				GETDATE(),
				NULL,
				NULL,
				NULL
			FROM    
