				INNER JOIN #costingTable csfs ON p.SCOACostingCode = csfs.ScoaCode    
				LEFT JOIN Plan_ProjectCosting adjCost ON pp.Project_ID = adjCost.ProjectID AND csfs.ScoaID = adjCost.ScoaCostingID
			WHERE
				BudgetOriginalExportImportVersionHeaderID = @budgetOriginalExportImportVersionHeaderID AND BudgetOriginalImportVersionNumber = @budgetOriginalImportVersionNumber
				AND ((p.ProjectID IS NOT NULL OR p.ProjectID <> 0) AND (p.PlanProjectItemID IS NULL OR p.PlanProjectItemID = 0))
				AND adjcost.ProjectCosting_ID IS NULL;

			print 'costing'	

			/* Add data into Project Function */
			INSERT  INTO dbo.Plan_ProjectFunctions
			( 
				 ProjectID
				,ScoaFunctionID
				,CapturerID
				,DateCaptured
				,ModifierID
				,DateModified
				,PreviousReferenceId
			)
			SELECT DISTINCT
				pp.Project_ID ,
				CSFS.ScoaID ,
				1 ,
				GETDATE(),
				NULL,
				NULL,
				NULL                                                                                                         
			FROM    
				Plan_BudgetOriginalImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.Project_ID = p.ProjectID
				INNER JOIN #functionTable CSFS ON p.SCOAFunctionCode = csfs.ScoaCode
