			/* Add data into Plan Project Region */
			INSERT  INTO dbo.Plan_ProjectRegions
			(
				 ProjectID
				,ScoaRegionID
				,RegionPercent
				,CapturerID
				,DateCaptured
				,ModifierID
				,DateModified
				,PreviousReferenceId
			)
			SELECT DISTINCT
				pp.Project_ID ,
				CSRS.ScoaID ,
				100.0 ,
				1 ,
				GETDATE(),
				NULL,
				NULL,
				NULL
			FROM    
				Plan_BudgetOriginalImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.Project_ID = p.ProjectID
