			/* Add data into Plan Project Divisions */
			INSERT  INTO dbo.Plan_ProjectDivisions
			( 
				 ProjectID
				,DivisionID
				,CapturerID
				,DateCaptured
				,ModifierID
				,DateModified
				,PreviousReferenceId
			)
			SELECT DISTINCT
				pp.Project_ID ,
				Division_ID ,
				1 ,
				GETDATE(),
				NULL,
				NULL,
				NULL
			FROM    
