				INNER JOIN Plan_Project pp ON pp.Project_ID = p.ProjectID 
				INNER JOIN Const_Division div ON p.MSCDivisionCode = div.DivisionCode
				LEFT JOIN Plan_ProjectDivisions adjDiv ON pp.Project_ID = adjDiv.ProjectID AND div.Division_ID = adjDiv.DivisionID
			WHERE
				BudgetOriginalExportImportVersionHeaderID = @budgetOriginalExportImportVersionHeaderID AND BudgetOriginalImportVersionNumber = @budgetOriginalImportVersionNumber
				AND ((p.ProjectID IS NOT NULL OR p.ProjectID <> 0) AND (p.PlanProjectItemID IS NULL OR p.PlanProjectItemID = 0))
				AND adjDiv.ProjectDivision_ID IS NULL;

			print 'divisions'	
                                             
			/* Add data into Plan Project Fund */
			INSERT  INTO dbo.Plan_ProjectFund
			( 						
				 ProjectID
				,ScoaFundID
				,FundAmount
				,FundReference
				,VirementId
				,AdjustmentId
				,CapturerID
				,DateCaptured
				,ModifierID
				,DateModified
				,PreviousReferenceId
			)
			SELECT DISTINCT
				pp.Project_ID ,
				CSFS.ScoaID ,
				CASE WHEN TypeValue in (0, 1, 4) THEN SUM(ABS(p.CurrentBudgetFinYear1) + ABS(p.CurrentBudgetFinYear2) + ABS(p.CurrentBudgetFinYear3)) ELSE 0 END,
				'',
				NULL,
				NULL,
				@userID,
				GETDATE() ,
				NULL,
				NULL,
				NULL
			FROM    
				Plan_BudgetOriginalImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.Project_ID = p.ProjectID 
				INNER JOIN #fundsTable CSFS ON p.ScoaFundCode = CSFS.ScoaCode  
				INNER JOIN Const_PlanCapitalOperationalTypes_sys pCot ON p.BudgetType = pCot.TypeName
				LEFT JOIN Plan_ProjectFund adjFund ON pp.Project_ID = adjFund.ProjectID AND CSFS.ScoaID = adjFund.ScoaFundID
			WHERE 
				BudgetOriginalExportImportVersionHeaderID = @budgetOriginalExportImportVersionHeaderID AND BudgetOriginalImportVersionNumber = @budgetOriginalImportVersionNumber
				AND ((p.ProjectID IS NOT NULL OR p.ProjectID <> 0) AND (p.PlanProjectItemID IS NULL OR p.PlanProjectItemID = 0))
				AND adjFund.ProjectFund_ID IS NULL
			GROUP BY 
				pp.Project_ID ,
				CSFS.ScoaID,
				TypeValue
                              
			print 'fund'	

			/* Add data into Plan Project Fund Yaer */
			INSERT  INTO dbo.Plan_ProjectFundYear
			( 
				 ProjectFundID
				,FinYear
				,YearFundAmount
				,VirementId
				,AdjustmentId
				,CapturerID
				,DateCaptured
				,ModifierID
				,DateModified
				,PreviousReferenceId
			)
			SELECT DISTINCT
				PF.ProjectFund_ID ,
				FinYear1 ,
				CASE WHEN TypeValue in (0, 1, 4) THEN SUM(ABS(p.CurrentBudgetFinYear1)) ELSE 0 END,
				NULL,
				NULL,
				@userID,
				GETDATE(),
				NULL,
				NULL,
				NULL
			FROM    
				Plan_BudgetOriginalImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.Project_ID = p.ProjectID
				INNER JOIN Plan_ProjectFund PF ON PF.ProjectID = pp.Project_ID 
				INNER JOIN Const_PlanCapitalOperationalTypes_sys pCot ON p.BudgetType = pCot.TypeName
				LEFT JOIN Plan_ProjectFundYear PFY ON PF.ProjectFund_ID = PFY.ProjectFundID 
			WHERE 
				BudgetOriginalExportImportVersionHeaderID = @budgetOriginalExportImportVersionHeaderID AND BudgetOriginalImportVersionNumber = @budgetOriginalImportVersionNumber
				AND ((p.ProjectID IS NOT NULL OR p.ProjectID <> 0) AND (p.PlanProjectItemID IS NULL OR p.PlanProjectItemID = 0))
				AND PFY.ProjectFundYear_ID IS NULL
			GROUP BY 
				TypeValue, 
				FinYear1,
				pf.ProjectFund_ID

			UNION ALL

			SELECT DISTINCT
				PF.ProjectFund_ID ,
				FinYear2 ,
				CASE WHEN TypeValue in (0, 1, 4) THEN SUM(ABS(p.CurrentBudgetFinYear2)) ELSE 0 END,
				NULL,
				NULL,
				@userID,
				GETDATE(),
				NULL,
				NULL,
				NULL
			FROM    
				Plan_BudgetOriginalImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.Project_ID = p.ProjectID
				INNER JOIN Plan_ProjectFund PF ON PF.ProjectID = pp.Project_ID 
				INNER JOIN Const_PlanCapitalOperationalTypes_sys pCot ON p.BudgetType = pCot.TypeName
				LEFT JOIN Plan_ProjectFundYear PFY ON PF.ProjectFund_ID = PFY.ProjectFundID 
			WHERE 
				BudgetOriginalExportImportVersionHeaderID = @budgetOriginalExportImportVersionHeaderID AND BudgetOriginalImportVersionNumber = @budgetOriginalImportVersionNumber
				AND ((p.ProjectID IS NOT NULL OR p.ProjectID <> 0) AND (p.PlanProjectItemID IS NULL OR p.PlanProjectItemID = 0))
				AND PFY.ProjectFundYear_ID IS NULL
			GROUP BY 
				TypeValue, 
				FinYear2,
				pf.ProjectFund_ID

			UNION ALL

			SELECT DISTINCT
				PF.ProjectFund_ID ,
				FinYear3 ,
				CASE WHEN TypeValue in (0, 1, 4) THEN SUM(ABS(p.CurrentBudgetFinYear3)) ELSE 0 END,
				NULL,
				NULL,
				@userID,
				GETDATE(),
				NULL,
				NULL,
				NULL
			FROM    
				Plan_BudgetOriginalImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.Project_ID = p.ProjectID
				INNER JOIN Plan_ProjectFund PF ON PF.ProjectID = pp.Project_ID 
				INNER JOIN Const_PlanCapitalOperationalTypes_sys pCot ON p.BudgetType = pCot.TypeName
				LEFT JOIN Plan_ProjectFundYear PFY ON PF.ProjectFund_ID = PFY.ProjectFundID 
			WHERE 
				BudgetOriginalExportImportVersionHeaderID = @budgetOriginalExportImportVersionHeaderID AND BudgetOriginalImportVersionNumber = @budgetOriginalImportVersionNumber
				AND ((p.ProjectID IS NOT NULL OR p.ProjectID <> 0) AND (p.PlanProjectItemID IS NULL OR p.PlanProjectItemID = 0))
				AND PFY.ProjectFundYear_ID IS NULL
			GROUP BY 
				TypeValue, 
				FinYear3,
				pf.ProjectFund_ID

			print 'fund year'	

			CREATE TABLE #InsertedRowsExistingProjectNewPPI (ID INT)

			INSERT  INTO dbo.Plan_ProjectItem
			( 
				 ProjectID
				,ProjectItemID
				,SCOAItemID
				,FinYear
				,ProjectFundYearID
				,SCOAFundId
				,BudgetAmount
				,BudgetAmountCurP1
				,BudgetAmountCurP2
				,SCOAFunctionId
				,SCOARegionId
				,DivisionId
				,BudgetSplitID
				,VirementId
				,HistoricalProjectCode
				,AdjustmentId
				,ModificationNumber
				,SCOACostingID
				,IsItemLocked
				,CreditDebit
				,CapturerID
				,DateCaptured
				,ModifierID
				,DateModified
				,PreviousReferenceId
				,GRAPClassification
				,GRAPClassificationNote
				,MainSegmentReporting
				,SubSegmentReporting
			)
			OUTPUT Inserted.PlanProjectItem_ID INTO #InsertedRowsExistingProjectNewPPI
			SELECT DISTINCT
				pp.Project_ID ,
				CPI.ProjectItem_ID ,
				item.ScoaID ,
				p.FinYear1 ,
				PPF.ProjectFundYear_ID ,
				fund.ScoaID ,
				SUM(ABS(ISNULL(p.CurrentBudgetFinYear1, 0))) ,
				SUM(ABS(ISNULL(p.CurrentBudgetFinYear2, 0))) ,
				SUM(ABS(ISNULL(p.CurrentBudgetFinYear3, 0))) ,
				func.ScoaID ,
				region.ScoaID,
				div.Division_ID ,
				budSplit.DivideBy_ID,
				NULL,
				'',
				NULL,
				NULL,                                                                                     
				cost.ScoaID ,
				NULL,
				p.CreditDebit,
				@userID,
				GETDATE(),
				NULL,
				NULL,
				NULL,
				GRAPClassification,
				GRAPClassificationNote,
				MainSegmentReporting,
				SubSegmentReporting
			FROM    
				Plan_BudgetOriginalImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.Project_ID = p.ProjectID
				INNER JOIN #fundsTable fund ON fund.ScoaCode = p.ScoaFundCode
				INNER JOIN (SELECT MIN(ProjectItem_ID) ProjectItem_ID, ItemDescription, FinYear FROM Const_ProjectItem WHERE FinYear = @currFinYear GROUP BY ItemDescription, FinYear) CPI ON CPI.ItemDescription = p.ItemDescription and CPI.FinYear = p.FinYear1
				INNER JOIN #itemTable item ON item.ScoaCode = p.SCOAItemCode
				INNER JOIN (SELECT MIN (ProjectFund_ID) ProjectFund_ID, ProjectID, ScoaFundID FROM Plan_ProjectFund group by ProjectID, ScoaFundID) PF ON PF.ProjectID = pp.Project_ID and PF.ScoaFundID = fund.ScoaID                                                 
				INNER JOIN (SELECT MIN(ProjectFundYear_ID) ProjectFundYear_ID, ProjectFundID, FinYear FROM dbo.Plan_ProjectFundYear WHERE FinYear = @currFinYear GROUP BY ProjectFundID, FinYear) PPF ON PPF.ProjectFundID = PF.ProjectFund_ID AND PPF.FinYear = @currFinYear
				INNER JOIN #functionTable func ON func.ScoaCode = p.SCOAFunctionCode
				INNER JOIN #regionalTable region ON region.ScoaCode = p.SCOARegionCode
				INNER JOIN #costingTable cost ON cost.ScoaCode = p.SCOACostingCode
				INNER JOIN Const_Division div ON p.MSCDivisionCode = div.DivisionCode
				INNER JOIN Const_BudgetSplitOptions budSplit ON p.SplitType = budSplit.BudgetSplitDesc
			WHERE 
				BudgetOriginalExportImportVersionHeaderID = @budgetOriginalExportImportVersionHeaderID AND BudgetOriginalImportVersionNumber = @budgetOriginalImportVersionNumber
				AND ((p.ProjectID IS NOT NULL OR p.ProjectID <> 0) AND (p.PlanProjectItemID IS NULL OR p.PlanProjectItemID = 0))
			GROUP BY 
				pp.Project_ID ,
				CPI.ProjectItem_ID ,
				item.ScoaID ,
				p.FinYear1 ,
				PPF.ProjectFundYear_ID ,
				func.ScoaID ,
				fund.ScoaID ,
				region.ScoaID ,
				cost.ScoaID ,
				div.Division_ID ,
				budSplit.DivideBy_ID ,
				p.CreditDebit,
				GRAPClassification,
				GRAPClassificationNote,
				MainSegmentReporting,
				SubSegmentReporting

			--Update HistoricalProjectCode
			UPDATE ppi
			SET HistoricalProjectCode = CONVERT(VARCHAR, PlanProjectItem_ID) + '|' + ISNULL(HistoricalProjectCode, '0') 
			FROM
				#InsertedRowsExistingProjectNewPPI newPPI
				inner join Plan_ProjectItem ppi ON newPPI.ID = ppi.PlanProjectItem_ID

