				AND (p.PlanProjectItemID IS NOT NULL AND p.PlanProjectItemID <> 0)
				AND MonthID = 6

			-- Plan_ProjectFund
			UPDATE 
				ppf
			SET 
				FundAmount = ISNULL(YTot, 0)
				,DateModified = GETDATE()
				,ModifierID = @userID
			FROM
				(
					SELECT 
						ProjectID, 
						ScoaFundID, 
						CASE WHEN CapitalOperation IN (0, 1, 4) THEN SUM(ABS(ISNULL(BudgetAmount, 0))) ELSE 0 END Y1, 
						CASE WHEN CapitalOperation IN (0, 1, 4) THEN SUM(ABS(ISNULL(BudgetAmountCurP1, 0))) ELSE 0 END Y2, 
						CASE WHEN CapitalOperation IN (0, 1, 4) THEN SUM(ABS(ISNULL(BudgetAmountCurP1, 0))) ELSE 0 END Y3, 
						CASE WHEN CapitalOperation IN (0, 1, 4) 
							THEN SUM(ABS(ISNULL(BudgetAmount, 0))) + SUM(ABS(ISNULL(BudgetAmountCurP1, 0))) + SUM(ABS(ISNULL(BudgetAmountCurP2, 0))) 
							ELSE 0 
						END YTot
					FROM 
						Plan_ProjectItem papi 
						INNER JOIN Plan_Project pap ON papi.ProjectID = pap.Project_ID
					WHERE 
						papi.FinYear = @currFinYear
					GROUP BY 
						ProjectID, ScoafundID, CapitalOperation
				) ppi

				LEFT JOIN Plan_ProjectFund ppf ON ppi.ProjectID = ppf.ProjectID AND ppi.ScoafundId = ppf.ScoafundID

			UPDATE 
				ppfy
			SET 
				YearFundAmount = ISNULL(Y1,0)
				,DateModified = GETDATE()
				,ModifierID = @userID
			from
				(
					SELECT 
						ProjectID, 
						ScoaFundID, 
						CASE WHEN CapitalOperation IN (0, 1, 4) THEN SUM(ABS(ISNULL(BudgetAmount, 0))) ELSE 0 END Y1
					FROM 
						Plan_ProjectItem papi 
						INNER JOIN Plan_Project pap ON papi.ProjectID = pap.Project_ID
					WHERE 
						papi.FinYear = @currFinYear
					GROUP BY 
						ProjectID, ScoafundID, CapitalOperation
				) ppi

				LEFT JOIN Plan_ProjectFund ppf ON ppi.ProjectID = ppf.ProjectId AND ppi.ScoafundId = ppf.ScoafundID

				LEFT JOIN Plan_ProjectFundYear ppfy ON ppf.ProjectFund_ID = ppfy.ProjectFundID AND FinYear = @currFinYear

			UPDATE 
				ppfy
			SET 
				YearFundAmount = ISNULL(Y2,0)
				,DateModified = GETDATE()
				,ModifierID = @userID
			from
				(
					SELECT 
						ProjectID, 
						ScoaFundID, 
						CASE WHEN CapitalOperation IN (0, 1, 4) THEN SUM(ABS(ISNULL(BudgetAmountCurP1, 0))) ELSE 0 END Y2
