				) ppi

				LEFT JOIN Plan_ProjectFund ppf ON ppi.ProjectID = ppf.ProjectId AND ppi.ScoafundId = ppf.ScoafundID

				LEFT JOIN Plan_ProjectFundYear ppfy ON ppf.ProjectFund_ID = ppfy.ProjectFundID AND FinYear = @currFinYearPlus1

			UPDATE 
				ppfy
			SET 
