				) ppi

				LEFT JOIN Plan_ProjectFund ppf ON ppi.ProjectID = ppf.ProjectId AND ppi.ScoafundId = ppf.ScoafundID

				LEFT JOIN Plan_ProjectFundYear ppfy ON ppf.ProjectFund_ID = ppfy.ProjectFundID AND FinYear = @currFinYearPlus2

			--Import Status
			UPDATE Plan_BudgetOriginalExportImportVersion_Header
			SET StatusID = 321
			WHERE BudgetOriginalExportImportVersionHeader_ID = @budgetOriginalExportImportVersionHeaderID

			--Project Code
			DECLARE @projectCode INT  = (SELECT GREATEST(( SELECT MAX(ProjectCode) FROM Plan_Project ), ( SELECT MAX(ProjectCode) FROM Plan_AdjustmentProject )) + 1)

			UPDATE Plan_Project 
			SET ProjectCode  = @projectCode , @projectCode = @projectCode + 1
			WHERE ISNULL(ProjectCode, 0) = 0 AND FinYear = @currFinYear

			--Plan_ProjectReportExclude
			INSERT INTO Plan_ProjectReportExclude
			(
				ProjectID,
				DateCaptured,
				CapturerID,
				DateModified,
				ModifierID,
				WaterProject
			)
			SELECT 
				Project_ID,
				GETDATE(),
				@userID,
				NULL,
				NULL,
				0
			FROM 
				Plan_Project pp
				LEFT JOIN Plan_ProjectReportExclude ppre ON pp.Project_ID = ppre.ProjectID
			WHERE
				pp.FinYear = @currFinYear AND ISNULL(CostingProject, 0) = 1 AND ISNULL(IsDeleted, 0) <> 1 and ppre.ProjectID IS NULL

			DELETE Plan_ProjectReportExclude 
			WHERE	
				ProjectID IN (SELECT Project_ID FROM Plan_Project WHERE FinYear = @currFinYear AND ISNULL(IsDeleted, 0) <> 1 AND ISNULL(CostingProject, 0) <> 1)
				AND ISNULL(WaterProject, 0) <> 1

			--Delete Plan_ProjectItems
			DELETE 
				Plan_ProjectItemMonth
			WHERE 
				PlanProjectItemID IN
					(
						SELECT PlanProjectItemID
						FROM Plan_BudgetOriginalImportVersion_Detail
						WHERE BudgetOriginalExportImportVersionHeaderID = @budgetOriginalExportImportVersionHeaderID AND BudgetOriginalImportVersionNumber = @budgetOriginalImportVersionNumber
								   AND ISNULL(DeleteItem, 0) = 1
					)

			DELETE 
				Plan_ProjectItem
			WHERE 
				PlanProjectItem_ID IN
					(
						SELECT PlanProjectItemID
						FROM Plan_BudgetOriginalImportVersion_Detail
						WHERE BudgetOriginalExportImportVersionHeaderID = @budgetOriginalExportImportVersionHeaderID AND BudgetOriginalImportVersionNumber = @budgetOriginalImportVersionNumber
								   AND ISNULL(DeleteItem, 0) = 1
					)

			-- funding sources
			DECLARE @FundSourceHeaderID INT = 0;
			DECLARE @StartFinYear INT = 0;
			DECLARE @CurrFinYear1 VARCHAR(50), @FinYear VARCHAR(50);
			SELECT @FinYear = @currFinYear

			WHILE ( @StartFinYear <= 2 )
			BEGIN                                                            
                                                            
				SELECT  
					@CurrFinYear1 = 
						CASE WHEN @StartFinYear = 0 THEN @currFinYear
							 WHEN @StartFinYear = 1 THEN @currFinYearPlus1
							 WHEN @StartFinYear = 2 THEN @currFinYearPlus2
							 ELSE @currFinYear
						END;

				SELECT TOP 1
						@FundSourceHeaderID = FundingSourceBudgetHeader_ID
				FROM    Plan_FundingSourceBudget_Header
				WHERE   FinancialYear = @CurrFinYear1;

				IF @FundSourceHeaderID = 0
				BEGIN
					INSERT INTO Plan_FundingSourceBudget_Header
					SELECT @CurrFinYear1, 1, GETDATE() , @userID , NULL, NULL, NULL 

					SELECT TOP 1 @FundSourceHeaderID = FundingSourceBudgetHeader_ID
					FROM    Plan_FundingSourceBudget_Header
					WHERE   FinancialYear = @CurrFinYear1;
				 END;

			------------------------------------------------------------------------------
			-- Update Budget Amount for Existing Fund Id
			------------------------------------------------------------------------------

				UPDATE  
					dbo.Plan_FundingSourceBudget_Detail
				SET     
					FundingSourceBudget = FundingSourceBudget
						+ CASE WHEN FundBal.Remain < 0
								THEN ( FundBal.Remain * -1 )
									+ FundBal.NwAllocAmount
								WHEN FundBal.Remain > 0
									AND FundBal.Actual < FundBal.NwAllocAmount
								THEN FundBal.NwAllocAmount
								ELSE 0
							END
				FROM    
					( SELECT    
						SCOAFundID ,
						@FundSourceHeaderID AS FundSourceHeaderId ,
						HRBudget.NwAllocAmount ,
						HRBudget.Budget AS Actual ,
						HRBudget.Budget - HRBudget.Allocated AS Remain
					 FROM      
						( SELECT    
							F.ScoaID AS SCOAFundID ,
							( CASE WHEN @StartFinYear = 0
									THEN SUM(ABS(ISNULL(CurrentBudgetFinYear1, 0)))
									WHEN @StartFinYear = 1
									THEN SUM(ABS(ISNULL(R.CurrentBudgetFinYear2, 0)))
									WHEN @StartFinYear = 2
									THEN SUM(ABS(ISNULL(R.CurrentBudgetFinYear3, 0)))
								END ) AS NwAllocAmount ,
								ISNULL(dbo.Planing_GetFundAvailableAmount(F.ScoaID,
									@CurrFinYear1),
									0) AS Budget ,
								ISNULL(dbo.Planing_GetFundAllocatedAmount(F.ScoaID,
									@CurrFinYear1,@FinYear),
									0) AS Allocated
							FROM      
								Plan_BudgetOriginalImportVersion_Detail R
								INNER JOIN #fundsTable F ON R.ScoaFundCode = F.ScoaCode
								INNER JOIN Const_PlanCapitalOperationalTypes_sys cPot ON R.BudgetType = cPot.TypeName
							WHERE 
								BudgetOriginalExportImportVersionHeaderID = @budgetOriginalExportImportVersionHeaderID AND BudgetOriginalImportVersionNumber = @budgetOriginalImportVersionNumber
								AND TypeValue IN (0, 1, 4)
							GROUP BY  
								R.ScoaFundCode ,
								F.ScoaID
						) AS HRBudget
					) AS FundBal
						INNER JOIN 
						( SELECT ScoaID AS FundId ,
										FundingSourceBudgetHeaderID AS BudgetHeaderId ,
										MIN(FundingSourceBudgetDetail_ID) AS UpdateFundingSourceBudgetDetailID
									FROM   Plan_FundingSourceBudget_Detail
									WHERE  FundingSourceBudgetHeaderID = @FundSourceHeaderID
									GROUP BY ScoaID ,
										FundingSourceBudgetHeaderID
								) AS UpdateBal ON FundBal.SCOAFundID = UpdateBal.FundId
												AND FundBal.FundSourceHeaderId = UpdateBal.BudgetHeaderId
								-- Condition to get Data to be Updated for Plan_FundingSourceBudget_Detail
								WHERE   Plan_FundingSourceBudget_Detail.FundingSourceBudgetHeaderID = @FundSourceHeaderID
										AND ScoaID = FundBal.SCOAFundID
										AND Plan_FundingSourceBudget_Detail.FundingSourceBudgetDetail_ID = UpdateFundingSourceBudgetDetailID;
                                                                                                         
		------------------------------------------------------------------------------
		-- Create Budget Detail for Budget Amount for Fund Id not found 
		------------------------------------------------------------------------------
								INSERT  INTO dbo.Plan_FundingSourceBudget_Detail
										( FundingSourceBudgetHeaderID ,
										  FundingSourceID ,
										  ScoaID ,
										  FundingSourceBudget ,
										  DateCaptured ,
										  CapturerID ,
										  DateModified ,
										  ModifierID,
										  isHidden,
										  UploadedDocument,
										  PreviousReferenceId
										)
										SELECT  @FundSourceHeaderID ,
												NULL ,
												F.ScoaID AS SCOAFundID ,
												( CASE WHEN @StartFinYear = 0
													   THEN SUM(ABS(ISNULL(CurrentBudgetFinYear1, 0)))
													   WHEN @StartFinYear = 1
													   THEN SUM(ABS(ISNULL(R.CurrentBudgetFinYear2, 0)))
													   WHEN @StartFinYear = 2
													   THEN SUM(ABS(ISNULL(R.CurrentBudgetFinYear3, 0)))
												  END ) AS NwAllocAmount ,
												GETDATE() ,
												@userID ,
												NULL,
												NULL,
												0,
												NULL,
												NULL
										FROM    Plan_BudgetOriginalImportVersion_Detail R
												INNER JOIN #fundsTable F ON R.ScoaFundCode = F.ScoaCode
												INNER JOIN Const_PlanCapitalOperationalTypes_sys cPot ON R.BudgetType = cPot.TypeName
										WHERE   ISNULL(dbo.Planing_GetFundAvailableAmount(F.ScoaID,
																	  @CurrFinYear1),
													   0) = 0
												AND TypeValue  in (0, 1, 4)
												AND BudgetOriginalExportImportVersionHeaderID = @budgetOriginalExportImportVersionHeaderID AND BudgetOriginalImportVersionNumber = @budgetOriginalImportVersionNumber
										GROUP BY F.ScoaID;

								SET @StartFinYear = @StartFinYear + 1;
							END;
                                           
			COMMIT TRANSACTION Import

	END TRY
	BEGIN CATCH
		ROLLBACK TRANSACTION Import
        SET @errorResult = ERROR_MESSAGE();

        INSERT INTO Sys_ErrorLog
        (
            moduleName,
            pageName,
            procedureName,
            errorMessage,
            errorType,
            detailedErrorMessage,
            errorDate,
            userName
        )
        VALUES
        ('Planning', 'SQL Server', 'Plan_BudgetOriginalImportVersion_sp', ERROR_MESSAGE(), 'SQL', ERROR_MESSAGE(), GETDATE(), 'SQL');

		RAISERROR(@ErrorResult, 16, 1);

	END CATCH

	SELECT @errorResult AS ErrorResult

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetOriginalNTValidation_sp]    Script Date: 2026/03/10 7:23:27 AM ******/
