-- Description:	Register ORGB projects and create budget version
-- =============================================
CREATE PROCEDURE [dbo].[Plan_BudgetOriginalProjectRegister_sp] 
	-- Add the parameters for the stored procedure here
	@versionNumber NVARCHAR(50) ,
    @versionName NVARCHAR(1000) ,
    @comments NVARCHAR(1000) ,
    @budgetOriginalExportImportVersionHeaderID INT ,
	@budgetOriginalImportVersionNumber INT ,
    @userId INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE 
		@budgetVersionId INT = 0 ,
		@finYear NVARCHAR(50) ,
        @createBudgetVersionResult NVARCHAR(MAX)= '';

    BEGIN TRY
        BEGIN TRANSACTION;

        IF NOT EXISTS ( SELECT * FROM Plan_BudgetVersion WHERE VersionNumber = @versionNumber )
        BEGIN
			SELECT @finYear = finYear FROM Plan_BudgetOriginalExportImportVersion_Header WHERE BudgetOriginalExportImportVersionHeader_ID = @budgetOriginalExportImportVersionHeaderID

			UPDATE 
				Plan_Project
			SET 
				ProjectStatus = 23
			WHERE
				FinYear = @finYear 
				AND ISNULL(IsDeleted, 0) = 0
				AND ProjectName IN 
					(
						SELECT DISTINCT ProjectName 
						FROM Plan_BudgetOriginalImportVersion_Detail 
						WHERE BudgetOriginalExportImportVersionHeaderID = @budgetOriginalExportImportVersionHeaderID AND BudgetOriginalImportVersionNumber = @budgetOriginalImportVersionNumber
					)

            INSERT  INTO Plan_BudgetVersion
                (   
					VersionNumber ,
                    VersionName ,
                    Comments ,
                    CapturerID ,
                    DateCaptured
	            )
            VALUES  
				( 
					@versionNumber ,
					@versionName ,
					@comments ,
					@userId ,
					GETDATE()
				);                

            SELECT  @budgetVersionId = SCOPE_IDENTITY();

			IF ( @budgetVersionId <> 0 )
            BEGIN
				UPDATE Plan_BudgetOriginalExportImportVersion_Header 
				SET BudgetVersionID = @budgetVersionID, IsProjectRegistered = 1
				WHERE BudgetOriginalExportImportVersionHeader_ID = @budgetOriginalExportImportVersionHeaderID

                INSERT INTO Plan_BudgetVersionDetail
					( 
						BudgetVersionID ,
						ProjectID ,
						FinYear ,
						IDPItemID ,
						CapitalOperation ,
						ScoaProjectID ,
						SCOACostingID ,
						ProjectTypeID ,
						PlanProjectItemID ,
						ProjectItemID ,
						SCOAItemID ,
						SCOAFundId ,
						BudgetAmount ,
						BudgetAmountCurP1 ,
						BudgetAmountCurP2 ,
						SCOAFunctionId ,
						SCOARegionId ,
						DivisionId ,
						CapturerID ,
						DateCaptured
					)
                SELECT  
					@budgetVersionId , 
                    PP.Project_ID , 
                    PP.FinYear , 
					0, 
                    ISNULL(PP.CapitalOperation,0) , 
                    ISNULL(PP.ScoaProjectID,0) , 
                    ISNULL(PPI.SCOACostingID,0) , 
                    ISNULL(PP.ProjectTypeID,0) , 
                    ISNULL(PPI.PlanProjectItem_ID,0) , 
                    ISNULL(PPI.ProjectItemID,0) , 
                    ISNULL(PPI.SCOAItemID,0) , 
                    ISNULL(PPI.SCOAFundId,0) , 
                    ISNULL(PPI.BudgetAmount,0) , 
                    ISNULL(PPI.BudgetAmountCurP1,0) , 
                    ISNULL(PPI.BudgetAmountCurP2,0) , 
                    ISNULL(PPI.SCOAFunctionId,0) , 
                    ISNULL(PPI.SCOARegionId,0) , 
                    ISNULL(PPI.DivisionId,0) , 
                    @userId , 
                    GETDATE()  
				FROM    
					Plan_Project PP
                    INNER JOIN Plan_ProjectItem PPI ON PP.Project_ID = PPI.ProjectID
				WHERE   
					PP.FinYear = @finYear
                    AND ISNULL(PP.IsDeleted, 0) = 0;

				INSERT INTO Plan_BudgetVersionMonths
				(
					BudgetVersionID, 
					ProjectItemMonth_ID ,
					PlanProjectItemID ,
					MonthID ,
					UnitQuantity ,
					UnitPrice ,
					CaptureID ,
					DateCaptured ,
					VirementId ,
					AdjustmentId
				)
				SELECT 
					@budgetVersionId ,
					ppim.ProjectItemMonth_ID ,
					ppim.PlanProjectItemID ,
					ppim.MonthID ,
					ppim.UnitQuantity ,
					ppim.UnitPrice ,
					@userId ,
					GETDATE(),  
					ppim.VirementId ,
					ppim.AdjustmentId 
				FROM    
					Plan_Project PP
                    INNER JOIN Plan_ProjectItem PPI ON PP.Project_ID = PPI.ProjectID
					INNER JOIN Plan_ProjectItemMonth ppim ON ppim.PlanProjectItemID = PPI.PlanProjectItem_ID
                WHERE   
					PP.FinYear = @finYear
                    AND ISNULL(PP.IsDeleted, 0) = 0;

				COMMIT TRANSACTION;
				SET @createBudgetVersionResult = 'Success';
			END;
		ELSE
        BEGIN
            ROLLBACK TRANSACTION;
            SET @createBudgetVersionResult = 'Budget Version id not found & Budget Version Detail Entry Skipped';
        END;
	END;
	ELSE
	BEGIN
		ROLLBACK TRANSACTION;
		SET @createBudgetVersionResult = 'Budget Version - '
			+ @versionNumber + ' is already generated';
	END;
    END TRY
    BEGIN CATCH
        SET @createBudgetVersionResult = ERROR_MESSAGE();
        RAISERROR (@createBudgetVersionResult, 16,1);
        ROLLBACK TRANSACTION;
    END CATCH;

    SELECT  @createBudgetVersionResult AS Result ,
            @budgetVersionId AS BudgetVersionId ,
            @versionNumber AS VersionNumber;

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetRolloverByFinYear_Sp]    Script Date: 2026/03/10 7:23:28 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author: Sahil Nagpal
-- Create date: 2018-10-16
-- Description:	#61596 Planning Financial Year Budget rollover
-- EXEC Plan_BudgetRolloverByFinYear_Sp '2018/2019',4919 
-- =============================================

CREATE PROCEDURE [dbo].[Plan_BudgetRolloverByFinYear_Sp]
    @FinYear NVARCHAR(9),
    @UserID INT,
	@BudgetRolloverFileName NVARCHAR(500)
AS
BEGIN 
DECLARE @ErrorResult NVARCHAR(Max), @yearp1 INT,@yearp2 INT, @NextFinYear NVARCHAR(9), @BudgetRollOverId INT;

BEGIN TRY
    BEGIN TRANSACTION BudgetRolloverTran

	SELECT  @yearp1 = CAST(SUBSTRING(@FinYear, 6, 4) AS INT);
	SELECT  @yearp2 = @yearp1 + 1; -- 2020
	SELECT  @NextFinYear = CONVERT(VARCHAR(4), @yearp1) + '/'  + CONVERT(VARCHAR(4), @yearp2);

	/*-------------------------------------------------------- */

	EXEC Plan_BudgetRolloverForConstants_sp @FinYear,@UserID;
	EXEC Plan_BudgetRolloverForPlanTables_sp @FinYear,@UserID;

	/*-------------------------------------------------------- */

	INSERT INTO dbo.Plan_BudgetRollover
	(
		FromFinYear,ToFinYear,IsBudgetRollover,BudgetRolloverFileName,
		CapturerID,DateCaptured
	)
	SELECT @FinYear, @NextFinYear, 1,@BudgetRolloverFileName, @UserID,GETDATE()

	SELECT @BudgetRollOverId = SCOPE_IDENTITY();

	COMMIT TRANSACTION BudgetRolloverTran

SET @ErrorResult = 'Success'

END TRY
BEGIN CATCH
	
	SET @ErrorResult = ERROR_MESSAGE()

	INSERT into Sys_ErrorLog (moduleName, pageName, procedureName, errorMessage, errorType, detailedErrorMessage, errorDate, userName)
		Values ('Planning','SQL Server','Plan_BudgetRolloverByFinYear_Sp', ERROR_MESSAGE(), 'SQL', ERROR_MESSAGE(), GETDATE(), 'SQL')

    RAISERROR(@ErrorResult, 16, 1)
    ROLLBACK TRANSACTION BudgetRolloverTran

END CATCH

SELECT ISNULL(@BudgetRollOverId,0) AS BudgetRollOver_Id, @ErrorResult AS Result --Comment All above Before update edmx
--SELECT CapturerID AS BudgetRollOver_Id, FromFinYear AS Result FROM dbo.Plan_BudgetRollover --Uncomment this Before update edmx

END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetRolloverForConstants_sp]    Script Date: 2026/03/10 7:23:28 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
