-- =============================================
-- Author: Sahil Nagpal
-- Create date: 2018-10-01
-- Description:	#61596 Planning Financial Year Budget rollover
-- EXEC Plan_BudgetRolloverForConstants_sp '2018/2019',4906
-- DO NOT APPLY REDGATE SQL FORMAT
-- DO NOT APPLY REDGATE SQL FORMAT
-- 17-12-2018: SNagpal #61596 Add FinYear conditions to All SCOA constants. Add constant for Const_NTStringSCOAProject
-- 18-12-2018: SNagpal #61596 add NationalKPANumber condition in Const_IDPNationalKPA_Detail -- Add finyear to Const_ProjectTypeItem
-- 17-03-2021: CM #84697 - For Const_PlanSCOA tables only rollover SCOAIds if they exist in the new SCOA version 
-- ============================================= 
CREATE PROCEDURE [dbo].[Plan_BudgetRolloverForConstants_sp]
    @FinYear NVARCHAR(9),
    @UserID INT
AS

BEGIN 
BEGIN TRY
   -- BEGIN TRANSACTION BudgetRolloverTran


DECLARE @ErrorResult NVARCHAR(MAX), @NextFinYear NVARCHAR(9),@yearp1 INT, @yearp2 INT,
		@PreviousIDPLevelDescHeaderID INT, @NewIDPLevelDescHeaderID INT,  @PreviousIDPNationalKPAID INT ,@NewIDPNationalKPAID INT; ;

SELECT  @yearp1 = CAST(SUBSTRING(@FinYear, 6, 4) AS INT);
SELECT  @yearp2 = @yearp1 + 1;
SELECT  @NextFinYear = CONVERT(VARCHAR(4), @yearp1) + '/'  + CONVERT(VARCHAR(4), @yearp2);


--==========================================
--INSERT INTO Const_IDPLevelDescription_Header
--==========================================

IF NOT EXISTS (SELECT FinancialYear FROM Const_IDPLevelDescription_Header WHERE FinancialYear = @NextFinYear)
	BEGIN
      INSERT  INTO dbo.Const_IDPLevelDescription_Header
				( FinancialYear ,IDPNumLevel ,
				IDPLevelDescSubmitted ,DateCaptured ,CapturerID ,PreviousReferenceId)
				SELECT  @NextFinYear ,IDPNumLevel ,IDPLevelDescSubmitted ,
						GETDATE(),@UserID,IDPLevelDescHeader_ID
				FROM  dbo.Const_IDPLevelDescription_Header
				WHERE FinancialYear = @FinYear
				AND @NextFinYear NOT IN (SELECT FinancialYear FROM Const_IDPLevelDescription_Header)

		SET @NewIDPLevelDescHeaderID = SCOPE_IDENTITY();
	END
ELSE
	BEGIN
		SELECT @NewIDPLevelDescHeaderID =  IDPLevelDescHeader_ID FROM Const_IDPLevelDescription_Header WHERE FinancialYear = @NextFinYear 
	END;

 SELECT  @PreviousIDPLevelDescHeaderID = IDPLevelDescHeader_ID FROM Const_IDPLevelDescription_Header  WHERE FinancialYear = @FinYear 

 --==========================================
--INSERT INTO Sys_WorkFlowSectionAudit
--==========================================
IF(@NewIDPLevelDescHeaderID NOT IN ( SELECT RecordID FROM Sys_WorkFlowSectionAudit WHERE WorkFlowID = 22 AND WorkFlowSectionID = 'IDPLevelCount'))
BEGIN
INSERT INTO dbo.Sys_WorkFlowSectionAudit
(
    RecordID,WorkFlowID,WorkFlowSectionID,
    CapturerID,DateCaptured,Completed
)
VALUES ( @NewIDPLevelDescHeaderID,22,N'IDPLevelCount',
	@UserID,GETDATE(),1 )
END

IF(@NewIDPLevelDescHeaderID NOT IN ( SELECT RecordID FROM Sys_WorkFlowSectionAudit WHERE WorkFlowID = 22 AND WorkFlowSectionID = 'IDPLevelDescriptions'))
BEGIN
INSERT INTO dbo.Sys_WorkFlowSectionAudit
(
    RecordID,WorkFlowID,WorkFlowSectionID,
    CapturerID,DateCaptured,Completed
)
VALUES ( @NewIDPLevelDescHeaderID,22,N'IDPLevelDescriptions',
	@UserID,GETDATE(),1 )
END

--==========================================
--INSERT INTO Const_IDPLevelDescription_Detail
--==========================================

	INSERT  INTO dbo.Const_IDPLevelDescription_Detail
	             ( IDPLevelDescHeaderID ,IDPLevelNumber ,
	               IDPLevelDesc ,DateCaptured ,CapturerID ,PreviousReferenceId)
	             SELECT  @NewIDPLevelDescHeaderID ,IDPLevelNumber ,IDPLevelDesc ,
	                     GETDATE(),@UserID,IDPLevelDescDetail_ID
	             FROM dbo.Const_IDPLevelDescription_Detail
	             WHERE IDPLevelDescHeaderID = @PreviousIDPLevelDescHeaderID
				AND IDPLevelDesc NOT IN (SELECT IDPLevelDesc FROM Const_IDPLevelDescription_Detail WHERE IDPLevelDescHeaderID = @NewIDPLevelDescHeaderID) ;


--==========================================
--INSERT INTO Const_NationalKPA_Sys
--==========================================

 INSERT  INTO dbo.Const_NationalKPA_Sys
( 
	NKPANumber ,NKPADesc ,FinancialYear ,Enabled ,
	DateCaptured ,CapturerID ,PreviousReferenceId
)
SELECT  NKPANumber ,NKPADesc ,@NextFinYear ,Enabled ,
        GETDATE() ,@UserID ,NKPA_ID 
		FROM dbo.Const_NationalKPA_Sys
        WHERE FinancialYear = @FinYear AND NKPADesc NOT IN 
		(SELECT NKPADesc FROM Const_NationalKPA_Sys WHERE FinancialYear = @NextFinYear);

--==========================================
--INSERT INTO Const_FundingSource
--==========================================

INSERT  INTO dbo.Const_FundingSource
( 
	FundingSourceDesc ,Enabled ,DateCaptured ,CapturerID ,
    FinYear ,PreviousReferenceId
)
SELECT FundingSourceDesc ,Enabled ,GETDATE(),@UserID ,
       @NextFinYear ,FundingSource_ID 
	   FROM dbo.Const_FundingSource
       WHERE   FinYear = @FinYear AND FundingSourceDesc NOT IN 
	   (SELECT FundingSourceDesc FROM Const_FundingSource WHERE FinYear = @NextFinYear );


--==========================================
--INSERT INTO Const_FundSourceChange
--==========================================

INSERT  INTO dbo.Const_FundSourceChange
( 
	FundSourceChangeDesc, Enabled, DateCaptured, CapturerID,
    FinYear, PreviousReferenceId
)
SELECT  FundSourceChangeDesc ,Enabled ,GETDATE() ,@UserID,
		@NextFinYear, FundSourceChange_ID 
		FROM dbo.Const_FundSourceChange
        WHERE FinYear = @FinYear AND FundSourceChangeDesc NOT IN (
		SELECT  FundSourceChangeDesc FROM Const_FundSourceChange WHERE   FinYear = @NextFinYear );


--==========================================
--INSERT INTO Const_SCOAItemLock
--==========================================

 INSERT  INTO dbo.Const_SCOAItemLock
( 
	SCOAItemID ,LockEnabled ,DateCaptured ,CapturerID ,
	FinYear ,PreviousReferenceId
)
SELECT SCOAItemID, LockEnabled, GETDATE(), @UserID ,
       @NextFinYear, SCOAItemLock_ID 
	   FROM dbo.Const_SCOAItemLock
       WHERE FinYear = @FinYear AND SCOAItemID NOT IN (
       SELECT  SCOAItemID FROM    Const_SCOAItemLock WHERE   FinYear = @NextFinYear);


--==========================================
--INSERT INTO Const_PlanVirementRules_sys
--==========================================

INSERT  INTO dbo.Const_PlanVirementRules_sys
( 
	[Priority] ,VirementDesc ,VirementDefinition ,VirementRuleDesc ,
	BusinessRule ,[Enabled] ,[Option] ,Lockdown ,DateCaptured ,
	CapturerID , FinYear ,PreviousReferenceId
)
SELECT [Priority] ,VirementDesc ,VirementDefinition ,VirementRuleDesc ,
		BusinessRule ,[Enabled] ,[Option] ,Lockdown ,GETDATE() ,
		@UserID ,@NextFinYear ,VirementRule_ID
		FROM dbo.Const_PlanVirementRules_sys 
		WHERE FinYear = @FinYear
		AND VirementRuleDesc NOT IN (SELECT VirementRuleDesc FROM Const_PlanVirementRules_sys WHERE FinYear = @NextFinYear );


--==========================================
--INSERT INTO Const_PlanAdjustmentReason_sys
--==========================================

INSERT INTO dbo.Const_PlanAdjustmentReason_sys
(
    Number,AdjustmentReason,Enabled,Lockdown,DateCaptured,CapturerID,
    Reference,FinYear,PreviousReferenceId
)
SELECT Number,AdjustmentReason,Enabled,Lockdown,GETDATE(),@UserID,Reference,
       @NextFinYear, AdjustmentReason_ID 
	   FROM Const_PlanAdjustmentReason_sys
	   WHERE FinYear = @FinYear AND AdjustmentReason NOT IN
       (SELECT c.AdjustmentReason FROM dbo.Const_PlanAdjustmentReason_sys c WHERE c.FinYear = @NextFinYear) 

--==========================================
--INSERT INTO Const_PlanAdjustmentType_sys
--==========================================
INSERT INTO dbo.Const_PlanAdjustmentType_sys
(
    Number,AdjustmentType,Enabled,Lockdown,DateCaptured,CapturerID,
    FinYear,PreviousReferenceId
)
SELECT Number,AdjustmentType,Enabled,Lockdown,GETDATE(),@UserID,
		@NextFinYear,AdjustmentType_ID 
		FROM Const_PlanAdjustmentType_sys
		WHERE FinYear = @FinYear AND AdjustmentType NOT IN
       (SELECT c.AdjustmentType FROM dbo.Const_PlanAdjustmentType_sys c WHERE c.FinYear = @NextFinYear)

--==========================================
--INSERT INTO Const_ProjectItem
--==========================================
INSERT INTO dbo.Const_ProjectItem
(
    ItemDescription,Enabled,DateCaptured,CapturerID, 
	FinYear,PreviousReferenceId
)
SELECT ItemDescription,Enabled,GETDATE(),@UserID,
		@NextFinYear, ProjectItem_ID 
		FROM Const_ProjectItem
		WHERE FinYear = @FinYear AND ItemDescription NOT IN
       (SELECT c.ItemDescription FROM dbo.Const_ProjectItem c WHERE c.FinYear = @NextFinYear)

--==========================================
--INSERT INTO Const_ProjectType
--==========================================
INSERT INTO dbo.Const_ProjectType
(
    ProjectTypeDescrip,Enabled,DateCaptured,CapturerID,
	FinYear,PreviousReferenceId
)
SELECT ProjectTypeDescrip,Enabled,GETDATE(),@UserID,
       @NextFinYear,ProjectType_ID 
	   FROM Const_ProjectType
	   WHERE FinYear = @FinYear AND ProjectTypeDescrip NOT IN
       (SELECT c.ProjectTypeDescrip FROM dbo.Const_ProjectType c WHERE c.FinYear = @NextFinYear)

--==========================================
--INSERT INTO Const_ProjectTypeItem
--==========================================
INSERT INTO dbo.Const_ProjectTypeItem
(
    ProjectTypeID,ProjectItemID,ScoaItemID,
    DateCaptured,CapturerID,PreviousReferenceId, FinYear
)
SELECT t.ProjectType_ID,i.ProjectItem_ID,
       ScoaItemID,GETDATE(),@UserID,
       pti.ProjectTypeItem_ID, 	@NextFinYear
	   FROM Const_ProjectTypeItem pti
	   INNER JOIN Const_ProjectType t ON pti.ProjectTypeID = t.PreviousReferenceId AND t.FinYear= @NextFinYear
       INNER JOIN Const_ProjectItem i ON pti.ProjectItemID = i.PreviousReferenceId AND i.FinYear= @NextFinYear
	  WHERE CAST(t.ProjectType_ID AS VARCHAR(9)) + '-' + CAST(i.ProjectItem_ID AS VARCHAR(9)) 
	  NOT IN (SELECT CAST(c.ProjectTypeID AS VARCHAR(9)) + '-' + CAST(c.ProjectItemID AS VARCHAR(9)) FROM Const_ProjectTypeItem c)

--==========================================
--INSERT INTO Const_PlanSCOAProjectFBS
--==========================================

INSERT INTO dbo.Const_NTStringSCOAProject
(
    SCOAProjectId,FinYear,IsEnable,
    CapturerID,DateCaptured,MTSFCode,IUDFCode
)
SELECT SCOAProjectId,@NextFinYear, IsEnable,
      @UserID,GETDATE(),MTSFCode,IUDFCode
	  FROM Const_NTStringSCOAProject
	  WHERE SCOAProjectId NOT IN (SELECT c.SCOAProjectId FROM Const_NTStringSCOAProject c WHERE c.FinYear = @NextFinYear)
	  AND FinYear = @FinYear

--==========================================
--INSERT INTO Const_PlanSCOAProjectFBS
--==========================================

INSERT INTO dbo.Const_PlanSCOAProjectFBS
(
    ScoaId,IsEnable,
    CapturerID,DateCaptured,FinYear
)
SELECT ScoaId,IsEnable,
      @UserID,GETDATE(),@NextFinYear 
	  FROM Const_PlanSCOAProjectFBS
	  WHERE ScoaId NOT IN (SELECT c.ScoaId FROM Const_PlanSCOAProjectFBS c WHERE c.FinYear = @NextFinYear)
	  AND FinYear = @FinYear

--==========================================
--INSERT INTO Const_PlanSCOAItemRevenueFBS
--==========================================

INSERT INTO dbo.Const_PlanSCOAItemRevenueFBS
(
    ScoaItemId,IsEnable,BudgetType,CreditDebit,
    FinYear,CapturerID,DateCaptured
)
SELECT ScoaItemId,IsEnable,BudgetType,CreditDebit,
      @NextFinYear,@UserID,GETDATE() 
	  FROM Const_PlanSCOAItemRevenueFBS
	  WHERE ScoaItemId NOT IN (SELECT c.ScoaItemId FROM Const_PlanSCOAItemRevenueFBS c WHERE c.FinYear = @NextFinYear)
      AND ScoaItemId IN (SELECT ScoaID FROM Const_SCOA_Structure_ByYear(@NextFinYear))
	  AND FinYear = @FinYear


--==========================================
--INSERT INTO Const_PlanSCOAItemAssetFBS
--==========================================

INSERT INTO dbo.Const_PlanSCOAItemAssetFBS
(
    ScoaItemId,IsEnable,BudgetType,CreditDebit,
    FinYear,CapturerID,DateCaptured
)
SELECT ScoaItemId,IsEnable,BudgetType,CreditDebit,
      @NextFinYear,@UserID,GETDATE() 
	  FROM Const_PlanSCOAItemAssetFBS
	  WHERE ScoaItemId NOT IN (SELECT c.ScoaItemId FROM Const_PlanSCOAItemAssetFBS c WHERE c.FinYear = @NextFinYear)
	  AND ScoaItemId IN (SELECT ScoaID FROM Const_SCOA_Structure_ByYear(@NextFinYear))
	  AND FinYear = @FinYear

--==========================================
--INSERT INTO Const_PlanSCOAItemGainOR
--==========================================

INSERT INTO dbo.Const_PlanSCOAItemGainOR
(
    ScoaItemId,IsEnable,BudgetType,CreditDebit,
    FinYear,CapturerID,DateCaptured
)
SELECT ScoaItemId,IsEnable,BudgetType,CreditDebit,
      @NextFinYear,@UserID,GETDATE() 
	  FROM Const_PlanSCOAItemGainOR
	  WHERE ScoaItemId NOT IN (SELECT c.ScoaItemId FROM Const_PlanSCOAItemGainOR c WHERE c.FinYear = @NextFinYear)
	  AND ScoaItemId IN (SELECT ScoaID FROM Const_SCOA_Structure_ByYear(@NextFinYear))
	  AND FinYear = @FinYear

	  
--==========================================
--INSERT INTO Const_PlanSCOAItemLossOE
--==========================================

INSERT INTO dbo.Const_PlanSCOAItemLossOE
(
    ScoaItemId,IsEnable,BudgetType,CreditDebit,
    FinYear,CapturerID,DateCaptured
)
SELECT ScoaItemId,IsEnable,BudgetType,CreditDebit,
      @NextFinYear,@UserID,GETDATE() 
	  FROM Const_PlanSCOAItemLossOE
	  WHERE ScoaItemId NOT IN (SELECT c.ScoaItemId FROM Const_PlanSCOAItemLossOE c WHERE c.FinYear = @NextFinYear)
	  AND ScoaItemId IN (SELECT ScoaID FROM Const_SCOA_Structure_ByYear(@NextFinYear))
	  AND FinYear = @FinYear

--==========================================
--INSERT INTO Const_PlanSCOAFundCapital
--==========================================

INSERT INTO dbo.Const_PlanSCOAFundCapital
(
    ScoaFundId,IsEnable,BudgetType,
    FinYear,CapturerID,DateCaptured
)
SELECT ScoaFundId,IsEnable,BudgetType,
      @NextFinYear,@UserID,GETDATE() 
	  FROM Const_PlanSCOAFundCapital
	  WHERE ScoaFundId NOT IN (SELECT c.ScoaFundId FROM Const_PlanSCOAFundCapital c WHERE c.FinYear = @NextFinYear)
	  AND ScoaFundId IN (SELECT ScoaID FROM Const_SCOA_Funds_Structure_ByYear(@NextFinYear))
	  AND FinYear = @FinYear
	  
--==========================================
--INSERT INTO Const_PlanSCOAFundOperational
--==========================================

INSERT INTO dbo.Const_PlanSCOAFundOperational
(
    ScoaFundId,IsEnable,BudgetType,
    FinYear,CapturerID,DateCaptured
)
SELECT ScoaFundId,IsEnable,BudgetType,
      @NextFinYear,@UserID,GETDATE() 
	  FROM Const_PlanSCOAFundOperational
	  WHERE ScoaFundId NOT IN (SELECT c.ScoaFundId FROM Const_PlanSCOAFundOperational c WHERE c.FinYear = @NextFinYear)
	  AND ScoaFundId IN (SELECT ScoaID FROM Const_SCOA_Funds_Structure_ByYear(@NextFinYear))
	  AND FinYear = @FinYear
  
--==========================================
--INSERT INTO Const_PlanNTValidations
--==========================================

INSERT INTO dbo.Const_PlanNTValidations
(
    ScoaItemId,ScoaFunctionId,IsEnable,BudgetType,
    FinYear,CapturerID,DateCaptured
)
SELECT ScoaItemId,ScoaFunctionId,IsEnable,BudgetType,
       @NextFinYear, @UserID, GETDATE() 
	   FROM Const_PlanNTValidations
	   WHERE ScoaItemId NOT IN (SELECT c.ScoaItemId FROM Const_PlanNTValidations c WHERE c.FinYear = @NextFinYear)
	   AND ScoaItemId IN (SELECT ScoaID FROM Const_SCOA_Structure_ByYear(@NextFinYear))
	   AND ScoaFunctionId IN (SELECT ScoaID FROM Const_SCOA_Function_Structure_ByYear(@NextFinYear))
	   AND FinYear = @FinYear

--==========================================
--INSERT INTO Const_IDPNationalKPA_Header & Const_IDPNationalKPA_Detail
--==========================================
IF NOT EXISTS (SELECT FinancialYear FROM Const_IDPNationalKPA_Header WHERE FinancialYear = @NextFinYear )
	BEGIN
         INSERT  INTO dbo.Const_IDPNationalKPA_Header
                            ( FinancialYear ,NationalKPASubmitted ,
                              DateCaptured ,CapturerID ,PreviousReferenceId
                            )
                            SELECT  @NextFinYear ,NationalKPASubmitted ,
                                    GETDATE() ,@UserID ,NationalKPAHeader_ID
                            FROM    dbo.Const_IDPNationalKPA_Header
                            WHERE   FinancialYear = @FinYear AND @NextFinYear NOT IN ( SELECT FinancialYear FROM Const_IDPNationalKPA_Header );

                    SET @NewIDPNationalKPAID = SCOPE_IDENTITY();
                END;
            ELSE
                BEGIN
                    SELECT  @NewIDPNationalKPAID = NationalKPAHeader_ID FROM    Const_IDPNationalKPA_Header
                    WHERE   FinancialYear = @NextFinYear; 
                END;

            SELECT  @PreviousIDPNationalKPAID = NationalKPAHeader_ID FROM    Const_IDPNationalKPA_Header
            WHERE   FinancialYear = @FinYear;

/*------Const_IDPNationalKPA_Detail-------*/

INSERT  INTO dbo.Const_IDPNationalKPA_Detail
(	
	NationalKPAHeaderID ,NationalKPANumber ,NationalKPADesc ,NationalKPAEnabled ,
	DateCaptured ,CapturerID ,PreviousReferenceId
)
SELECT  @NewIDPNationalKPAID ,NationalKPANumber ,NationalKPADesc ,NationalKPAEnabled ,
		GETDATE() ,@UserID ,NationalKPADetail_ID
FROM    dbo.Const_IDPNationalKPA_Detail
WHERE   NationalKPAHeaderID = @PreviousIDPNationalKPAID
--AND NationalKPAHeaderID NOT IN (SELECT  NationalKPAHeaderID FROM Const_IDPNationalKPA_Detail WHERE NationalKPAHeaderID = @NewIDPNationalKPAID );
AND NationalKPANumber NOT IN (SELECT  NationalKPANumber FROM Const_IDPNationalKPA_Detail WHERE NationalKPAHeaderID = @NewIDPNationalKPAID );


--==========================================
--INSERT & Update INTO IDP_Item
--==========================================

INSERT  INTO dbo.IDP_Item
( 
	ItemDesc ,FinancialYear ,ItemParentID ,IDPLevelNumber ,ItemOrderID ,
	CapturerID ,DateCaptured ,ActProjID ,isProj ,KpiID ,NationalKPADetailID ,IDPInitialized ,PreviousReferenceId
)
SELECT  II.ItemDesc ,@NextFinYear ,II.ItemParentID ,II.IDPLevelNumber ,II.ItemOrderID ,
			@UserID ,GETDATE() ,II.ActProjID ,II.isProj ,II.KpiID ,IKD.NationalKPADetail_ID ,NULL ,II.Item_ID
            FROM  dbo.IDP_Item II
            LEFT JOIN Const_IDPNationalKPA_Detail IKD ON IKD.PreviousReferenceId = II.NationalKPADetailID
            LEFT JOIN dbo.IDP_Item IIM ON IIM.FinancialYear = @NextFinYear
            AND IIM.ItemDesc = II.ItemDesc AND IIM.IDPLevelNumber = II.IDPLevelNumber
            WHERE   II.IDPLevelNumber NOT IN ( 50, 80, 100 ) AND II.FinancialYear = @FinYear
                    AND IIM.Item_ID IS NULL
            ORDER BY II.Item_ID;
--//It's Required for same data order in Table 
					
UPDATE  IIM
SET     IIM.ItemParentID = A.Item_ID
FROM    dbo.IDP_Item IIM
            INNER JOIN ( SELECT II.Item_ID ,II.PreviousReferenceId
                         FROM   dbo.IDP_Item II
                         INNER JOIN IDP_Item IM ON IM.ItemParentID = II.PreviousReferenceId
                         WHERE  IM.PreviousReferenceId IS NOT NULL
                       ) A ON A.PreviousReferenceId = IIM.ItemParentID
                              WHERE IIM.FinancialYear = @NextFinYear


--COMMIT TRANSACTION BudgetRolloverTran

SET @ErrorResult = 'Success'

END TRY
BEGIN CATCH
	
	SET @ErrorResult = ERROR_MESSAGE();
	
	INSERT into Sys_ErrorLog (moduleName, pageName, procedureName, errorMessage, errorType, detailedErrorMessage, errorDate, userName)
		Values ('Planning','SQL Server','Plan_BudgetRolloverForConstants_sp', ERROR_MESSAGE(), 'SQL', ERROR_MESSAGE(), GETDATE(), 'SQL')

    RAISERROR(@ErrorResult, 16, 1);
 --   ROLLBACK TRANSACTION BudgetRolloverTran

END CATCH

END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetRolloverForPlanTables_sp]    Script Date: 2026/03/10 7:23:28 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author: Sahil Nagpal
-- Create date: 2018-10-16
-- Description:	#61596 Planning Financial Year Budget rollover
-- EXEC Plan_BudgetRolloverForPlanTables_sp '2018/2019',101
-- 24-Jan-2019 by SNagpal: #61596 - #83633 - Add functionality to Copy ProjectCode
-- 13-Mar-2019 by SNagpal: #85624 Add code for Enable/Disable FK relations
-- 15-Mar-2019 by SNagpal: #85776 Fix code of saving FundingHeader Details and Add where conditions while saving ProjectFunds
-- 15-Mar-2019 by SNagpal: #85777 Update Plan_Project Status to Capture (4) if Sum of Amount is 0
-- 30-Apr-2019 by SNagpal: #87950 Add script to insert NewSCOAID from Plan_SCOAFundingExceptions tables. Also verify & Insert missing SCOAFundIds.
-- 14-May-2019 by CMoodley: #88658	Check if constraints exist before enabling/disabling
-- 14-Jun-2019 by CMoodley: #90209  Change to INT TO BIGINT when updating UnitPrice in Plan_ProjectItemMonth
-- 10-Mar-2021 by CMoodley: #60192 Handle issue where FinYear is null in Plan_ProjectFundYear table
-- 19-Mar-2021 by CMoodley: #60880 Only set ProjectStatus to Captured when sum of all plan project items per project over the 3 years is zero
-- 18-Mar-2022 by CMoodley: #84763 Update ProjectTypeId in Plan_Project table as per new rolled over ID in Const_ProjectType
-- 12-May-2022 by CMoodley: #86919 Exclude projects in ProjectStatus = 5 when setting ProjectStatus to Captured (when sum of all plan project items per project over the 3 years is zero)
-- 17-July-202 by SN: #58285, Added new Column IsActiveForSCM
-- 07-Aug-2023 by CMoodley: #105236 Include CostingProject field
-- ============================================= 
CREATE PROCEDURE [dbo].[Plan_BudgetRolloverForPlanTables_sp]
    @FinYear NVARCHAR(9),
    @UserID INT
AS

SET NOCOUNT ON;

BEGIN 
BEGIN TRY
    --BEGIN TRANSACTION BudgetRolloverTran

DECLARE @ErrorResult NVARCHAR(MAX), @NextFinYear NVARCHAR(9),@NextFinYearP3 NVARCHAR(9) , @NextFinYearP4 NVARCHAR(9), 
		@yearp1 INT, @yearp2 INT,@yearp3 INT ,@yearp4 INT ,
		@PreviousIDPLevelDescHeaderID INT, @NewIDPLevelDescHeaderID INT, @ProjectStatus INT = 23,@CaptureProjectStatus INT = 4, @NewFundingSourceBudgetID INT,@PreviousFundingSourceBudgetID INT ;

SELECT  @yearp1 = CAST(SUBSTRING(@FinYear, 6, 4) AS INT);
SELECT  @yearp2 = @yearp1 + 1; -- 2020
SELECT  @yearp3 = @yearp2 + 1; --2021
SELECT  @yearp4 = @yearp3 + 1; --2022

SELECT  @NextFinYear = CONVERT(VARCHAR(4), @yearp1) + '/'  + CONVERT(VARCHAR(4), @yearp2);
SELECT  @NextFinYearP3 = CONVERT(VARCHAR(4), @yearp2) + '/' + CONVERT(VARCHAR(4), @yearp3);
SELECT  @NextFinYearP4 = CONVERT(VARCHAR(4), @yearp3) + '/' + CONVERT(VARCHAR(4), @yearp4);


--=================Disable FK relations
IF OBJECT_ID('FK_Plan_Project_Const_SCOA_Project_Structure') IS NOT NULL
BEGIN
	ALTER TABLE Plan_Project 
	NOCHECK CONSTRAINT FK_Plan_Project_Const_SCOA_Project_Structure
END

IF OBJECT_ID('FK_Plan_ProjectFunctions_Const_SCOA_Function_Structure') IS NOT NULL
BEGIN
	ALTER TABLE Plan_ProjectFunctions 
	NOCHECK CONSTRAINT FK_Plan_ProjectFunctions_Const_SCOA_Function_Structure; 
END

IF OBJECT_ID('FK_Plan_ProjectItem_Const_SCOA_Structure') IS NOT NULL
BEGIN
	ALTER TABLE Plan_ProjectItem 
	NOCHECK CONSTRAINT FK_Plan_ProjectItem_Const_SCOA_Structure;
END

IF OBJECT_ID('FK_Plan_ProjectFund_Const_SCOA_Funds_Structure') IS NOT NULL
BEGIN
	ALTER TABLE  Plan_ProjectFund
	NOCHECK CONSTRAINT FK_Plan_ProjectFund_Const_SCOA_Funds_Structure
END

IF OBJECT_ID('FK_Plan_ProjectRegions_Const_SCOA_Regional_Structure') IS NOT NULL
BEGIN
	ALTER TABLE  Plan_ProjectRegions
	NOCHECK CONSTRAINT FK_Plan_ProjectRegions_Const_SCOA_Regional_Structure
END

IF OBJECT_ID('FK_Plan_ProjectCosting_Const_SCOA_Costing_Structure') IS NOT NULL
BEGIN
	ALTER TABLE  Plan_ProjectCosting
	NOCHECK CONSTRAINT FK_Plan_ProjectCosting_Const_SCOA_Costing_Structure
END

IF OBJECT_ID('FK_Plan_FundingSourceBudget_Const_SCOA_Funds_Structure') IS NOT NULL
BEGIN
	ALTER TABLE [dbo].[Plan_FundingSourceBudget_Detail] 
	NOCHECK CONSTRAINT [FK_Plan_FundingSourceBudget_Const_SCOA_Funds_Structure]
END

--========================================
-- INSERT INTO Plan_FundingSourceBudget_Header && Plan_FundingSourceBudget_Detail
--========================================

IF NOT EXISTS ( SELECT FinancialYear FROM Plan_FundingSourceBudget_Header WHERE FinancialYear = @NextFinYearP4 )
  BEGIN
	 INSERT  INTO dbo.Plan_FundingSourceBudget_Header
      ( 
		FinancialYear ,Submitted ,
		DateCaptured ,CapturerID ,PreviousReferenceId                             
      )
	SELECT  @NextFinYearP4 ,Submitted ,
            GETDATE() ,@UserID ,FundingSourceBudgetHeader_ID
    FROM    dbo.Plan_FundingSourceBudget_Header
    WHERE   FinancialYear = @NextFinYearP3 AND @NextFinYearP4 NOT IN (SELECT FinancialYear FROM Plan_FundingSourceBudget_Header );

    SET @NewFundingSourceBudgetID = SCOPE_IDENTITY();
  END;
ELSE
  BEGIN
     SELECT @NewFundingSourceBudgetID = FundingSourceBudgetHeader_ID FROM Plan_FundingSourceBudget_Header WHERE FinancialYear = @NextFinYearP4; 
  END;

/*----------------Plan_FundingSourceBudget_Detail--------------------*/

SELECT @PreviousFundingSourceBudgetID = FundingSourceBudgetHeader_ID FROM Plan_FundingSourceBudget_Header WHERE FinancialYear = @NextFinYearP3;

INSERT  INTO dbo.Plan_FundingSourceBudget_Detail
( 
	FundingSourceBudgetHeaderID ,FundingSourceID ,ScoaID ,
	FundingSourceBudget ,DateCaptured ,CapturerID ,PreviousReferenceId
)
SELECT  @NewFundingSourceBudgetID ,FundingSourceID ,ScoaID ,
FundingSourceBudget ,GETDATE() ,@UserID ,FundingSourceBudgetDetail_ID
FROM    dbo.Plan_FundingSourceBudget_Detail
WHERE   FundingSourceBudgetHeaderID = @PreviousFundingSourceBudgetID AND ScoaID NOT IN (
                            SELECT  ScoaID FROM Plan_FundingSourceBudget_Detail
                            WHERE   FundingSourceBudgetHeaderID = @NewFundingSourceBudgetID );



--===================================================
-- INSERT INTO & UPDATE Plan_Project For Non Virtual
--===================================================

INSERT INTO dbo.Plan_Project
(
    ProjectName,ProjectDesc,ProjectManagerID,SupplyChainOfficialID,CapitalOperation,CostEstimate,
	ScoaProjectID,EstimatedStartDate,EstimatedEndDate,ProjectStatus,CommencementDate,CapturerID,DateCaptured,
	FinYear,ProjectDetailDesc,ProjectCategoryID,ProjectImplementAgentID,Longitude,Latitude,ProgrammeManagerID,
	FinancialControllerID,ProjectTypeID,EstimatedDuration,ProjectDistinctionID,IsDeleted,HistoricalProjectCode,
	ProjectParentID,SingleMultiYear,PreviousReferenceId,ProjectCode,CostingProject
)
SELECT ProjectName,ProjectDesc,ProjectManagerID,SupplyChainOfficialID,CapitalOperation,CostEstimate,
		ScoaProjectID,EstimatedStartDate,EstimatedEndDate,@ProjectStatus,CommencementDate,@UserID ,GETDATE(),
		@NextFinYear,ProjectDetailDesc,ProjectCategoryID,ProjectImplementAgentID,Longitude,Latitude,ProgrammeManagerID,
		FinancialControllerID,ProjectTypeID,EstimatedDuration,ProjectDistinctionID,IsDeleted,HistoricalProjectCode,
		ProjectParentID,SingleMultiYear,Project_ID,ProjectCode,CostingProject
		FROM dbo.Plan_Project 
		WHERE FinYear = @FinYear
		AND ProjectName NOT IN (SELECT p.ProjectName FROM dbo.Plan_Project p WHERE p.FinYear = @NextFinYear)
		AND ProjectName NOT LIKE '%Virtual%'
		ORDER BY Project_ID

--===================================================
-- INSERT INTO & UPDATE Plan_Project For Virtual
--===================================================
INSERT INTO dbo.Plan_Project
(
    ProjectName,ProjectDesc,ProjectManagerID,SupplyChainOfficialID,CapitalOperation,CostEstimate,
	ScoaProjectID,EstimatedStartDate,EstimatedEndDate,ProjectStatus,CommencementDate,CapturerID,DateCaptured,
	FinYear,ProjectDetailDesc,ProjectCategoryID,ProjectImplementAgentID,Longitude,Latitude,ProgrammeManagerID,
	FinancialControllerID,ProjectTypeID,EstimatedDuration,ProjectDistinctionID,IsDeleted,HistoricalProjectCode,
	ProjectParentID,SingleMultiYear,PreviousReferenceId,ProjectCode,CostingProject
)
SELECT ProjectName,ProjectDesc,ProjectManagerID,SupplyChainOfficialID,CapitalOperation,CostEstimate,
		ScoaProjectID,EstimatedStartDate,EstimatedEndDate,23,CommencementDate,@UserID ,GETDATE(),
		@NextFinYear,ProjectDetailDesc,ProjectCategoryID,ProjectImplementAgentID,Longitude,Latitude,ProgrammeManagerID,
		FinancialControllerID,ProjectTypeID,EstimatedDuration,ProjectDistinctionID,0,HistoricalProjectCode,
		ProjectParentID,SingleMultiYear,Project_ID,ProjectCode,CostingProject
		FROM dbo.Plan_Project 
		WHERE FinYear = @FinYear
		AND ProjectName NOT IN (SELECT p.ProjectName FROM dbo.Plan_Project p WHERE p.FinYear = @NextFinYear)
		AND ProjectName LIKE '%Virtual%'
		ORDER BY Project_ID


UPDATE A SET A.ScoaProjectID =B.NewSCOAID
	   FROM Plan_Project A
	   INNER JOIN Plan_SCOAProjectExceptions B ON A.ScoaProjectID = B.ActiveSCOAId
	   WHERE A.FinYear = @NextFinYear AND B.NewSCOAID IS NOT NULL

--========================================
-- INSERT INTO & UPDATE IDP_Item
--========================================

INSERT  INTO dbo.IDP_Item
( 
	ItemDesc ,FinancialYear ,ItemParentID ,IDPLevelNumber ,ItemOrderID ,
	CapturerID ,DateCaptured ,ActProjID ,isProj ,KpiID ,NationalKPADetailID ,IDPInitialized ,PreviousReferenceId
)
SELECT  II.ItemDesc ,@NextFinYear ,II.ItemParentID ,II.IDPLevelNumber ,II.ItemOrderID ,
		@UserID ,GETDATE() ,II.ActProjID ,II.isProj ,II.KpiID ,IKD.NationalKPADetail_ID ,NULL ,II.Item_ID
        FROM dbo.IDP_Item II
        LEFT JOIN Const_IDPNationalKPA_Detail IKD ON IKD.PreviousReferenceId = II.NationalKPADetailID
        LEFT JOIN dbo.IDP_Item IIM ON IIM.FinancialYear = @NextFinYear AND IIM.ItemDesc = II.ItemDesc
									AND IIM.IDPLevelNumber = II.IDPLevelNumber
        WHERE   II.IDPLevelNumber IN ( 50, 80, 100 ) AND II.FinancialYear = @FinYear AND IIM.Item_ID IS NULL
        ORDER BY II.Item_ID;

/*-------- ParentID Update --------*/

UPDATE  IIM
SET     IIM.ItemParentID = A.Item_ID
FROM    dbo.IDP_Item IIM
        INNER JOIN ( SELECT II.Item_ID ,II.PreviousReferenceId
                     FROM   dbo.IDP_Item II
                     INNER JOIN IDP_Item IM ON IM.ItemParentID = II.PreviousReferenceId
                     WHERE  IM.PreviousReferenceId IS NOT NULL
                   ) A ON A.PreviousReferenceId = IIM.ItemParentID AND IIM.FinancialYear = @NextFinYear
				   WHERE 1 = 1;


/*------- ActProjID Update -------*/

UPDATE  II
SET     II.ActProjID = PP.Project_ID
FROM    dbo.IDP_Item II
        INNER JOIN Plan_Project PP ON PP.PreviousReferenceId = II.ActProjID
WHERE   II.FinancialYear = @NextFinYear AND PP.PreviousReferenceId IS NOT NULL;


--========================================
-- INSERT INTO & UPDATE Plan_ProjectIDP
--========================================

INSERT  INTO dbo.Plan_ProjectIDP
( 
	ProjectID ,ParentIDPItemID ,ProjectIDPItemID ,Percentage ,CapturerID ,
	DateCaptured ,Latitude ,Longitude ,PreviousReferenceId
)
SELECT  PP.Project_ID ,II.ItemParentID , II.Item_ID ,
        PPP.Percentage ,@UserID ,GETDATE() ,PPP.Latitude ,PPP.Longitude ,PPP.ProjectIDP_ID
        FROM    dbo.Plan_ProjectIDP PPP
        INNER JOIN Plan_Project PP ON PP.PreviousReferenceId = PPP.ProjectID
        INNER JOIN IDP_Item II ON II.PreviousReferenceId = PPP.ProjectIDPItemID
        WHERE   PP.FinYear = @NextFinYear
        AND II.FinancialYear = @NextFinYear AND PP.PreviousReferenceId IS NOT NULL
        AND CAST(PP.Project_ID AS VARCHAR(9)) + '-' + CAST(II.Item_ID AS VARCHAR(9)) NOT IN (
        SELECT  CAST(PIP.ProjectID AS VARCHAR(9)) + '-' + CAST(PIP.ProjectIDPItemID AS VARCHAR(9)) FROM    Plan_ProjectIDP PIP );


--========================================
-- INSERT INTO Plan_ProjectFunctions
--========================================

INSERT INTO dbo.Plan_ProjectFunctions
(
    ProjectID,
    ScoaFunctionID,
    CapturerID,
    DateCaptured,
    PreviousReferenceId
)
SELECT pp.Project_ID,
       ppf.ScoaFunctionID,
       @UserID,GETDATE(),
       ppf.ProjectFunction_ID FROM dbo.Plan_ProjectFunctions ppf 
INNER JOIN dbo.Plan_Project pp ON pp.PreviousReferenceId = ppf.ProjectID
LEFT JOIN dbo.Plan_ProjectFunctions p ON p.ProjectID = pp.Project_ID AND p.ScoaFunctionID = ppf.ScoaFunctionID 
WHERE pp.FinYear = @NextFinYear and ISNULL(p.ProjectID,0) <> ppf.ProjectID AND ISNULL(p.ScoaFunctionID,0) <> ppf.ScoaFunctionID
--(SELECT pf.ScoaFunctionID FROM dbo.Plan_ProjectFunctions pf WHERE pf.ProjectID = pp.Project_ID)


/*------- Update Exceptions for Plan_ProjectFunctions -------*/

UPDATE A SET A.ScoaFunctionID =B.NewSCOAID
	   FROM Plan_ProjectFunctions A
	   INNER JOIN dbo.Plan_Project pp ON pp.Project_ID = A.ProjectID
	   INNER JOIN Plan_SCOAFunctionExceptions B ON A.ScoaFunctionID = B.ActiveSCOAId
	   WHERE B.FinYear = @NextFinYear AND pp.FinYear = @NextFinYear  AND B.NewSCOAID IS NOT NULL


--========================================
-- INSERT INTO Plan_ProjectCosting
--========================================

INSERT INTO dbo.Plan_ProjectCosting
(
    ProjectID,
    ScoaCostingID,
    CapturerID,
    DateCaptured,
    PreviousReferenceId
)
SELECT pp.Project_ID,
       ppf.ScoaCostingID,
       @UserID,GETDATE(),
       ppf.ProjectCosting_ID FROM dbo.Plan_ProjectCosting ppf 
INNER JOIN dbo.Plan_Project pp ON pp.PreviousReferenceId = ppf.ProjectID
LEFT JOIN dbo.Plan_ProjectCosting p ON p.ProjectID = pp.Project_ID AND p.ScoaCostingID = ppf.ScoaCostingID 
WHERE pp.FinYear = @NextFinYear AND p.ProjectID IS NULL -- ISNULL(p.ProjectID,0) <> pp.Project_ID AND p.ScoaCostingID <> ppf.ScoaCostingID

/*------- Update Exceptions for Plan_ProjectCosting -------*/

UPDATE A SET A.ScoaCostingID =B.NewSCOAID
	   FROM Plan_ProjectCosting A
	   INNER JOIN dbo.Plan_Project pp ON pp.Project_ID = A.ProjectID
	   INNER JOIN Plan_SCOACostingExceptions B ON A.ScoaCostingID = B.ActiveSCOAId
	   WHERE B.FinYear = @NextFinYear AND pp.FinYear = @NextFinYear AND B.NewSCOAID IS NOT NULL


--========================================
-- INSERT INTO Plan_ProjectRegions
--========================================

INSERT INTO dbo.Plan_ProjectRegions
(
    ProjectID,
    ScoaRegionID,
    RegionPercent,
    CapturerID,
    DateCaptured,
    PreviousReferenceId
)
SELECT pp.Project_ID,
       ppr.ScoaRegionID,
	   ppr.RegionPercent,
       @UserID,GETDATE(),
       ppr.ProjectRegion_ID FROM dbo.Plan_ProjectRegions ppr 
INNER JOIN dbo.Plan_Project pp ON pp.PreviousReferenceId = ppr.ProjectID
LEFT JOIN dbo.Plan_ProjectRegions p ON p.ProjectID = pp.Project_ID AND p.ScoaRegionID = ppr.ScoaRegionID 
WHERE pp.FinYear = @NextFinYear AND p.ProjectID IS NULL -- AND  ISNULL(p.ProjectID,0) <> pp.Project_ID AND p.ScoaRegionID <> ppr.ScoaRegionID


/*------- Update Exceptions for Plan_ProjectRegions -------*/

UPDATE A SET A.ScoaRegionID =B.NewSCOAID
	   FROM Plan_ProjectRegions A
	   INNER JOIN dbo.Plan_Project pp ON pp.Project_ID = A.ProjectID
	   INNER JOIN Plan_SCOARegionExceptions B ON A.ScoaRegionID = B.ActiveSCOAId
	   WHERE B.FinYear = @NextFinYear AND pp.FinYear = @NextFinYear AND B.NewSCOAID IS NOT NULL


--========================================
-- INSERT INTO Plan_ProjectDivisions
--========================================

INSERT INTO dbo.Plan_ProjectDivisions
(
    ProjectID,
    DivisionID,
    CapturerID,
    DateCaptured,
    PreviousReferenceId
)
SELECT pp.Project_ID,
       ppr.DivisionID,
       @UserID,GETDATE(),
       ppr.ProjectDivision_ID FROM dbo.Plan_ProjectDivisions ppr 
INNER JOIN dbo.Plan_Project pp ON pp.PreviousReferenceId = ppr.ProjectID
LEFT JOIN dbo.Plan_ProjectDivisions p ON p.ProjectID = pp.Project_ID AND p.DivisionID = ppr.DivisionID 
WHERE pp.FinYear = @NextFinYear  AND p.ProjectID IS NULL --AND ISNULL(p.ProjectID,0) <> pp.Project_ID AND p.DivisionID <> ppr.DivisionID


--========================================
-- INSERT INTO Plan_ProjectItem & Plan_ProjectItemMonth
--========================================

INSERT INTO dbo.Plan_ProjectItem 
(
    ProjectID,ProjectItemID,SCOAItemID,FinYear,CapturerID,DateCaptured,
	ProjectFundYearID,SCOAFundId,BudgetAmount,BudgetAmountCurP1,BudgetAmountCurP2,
	SCOAFunctionId,SCOARegionId,DivisionId,BudgetSplitID,HistoricalProjectCode,
	SCOACostingID,CreditDebit,PreviousReferenceId,GRAPClassification,GRAPClassificationNote,
	MainSegmentReporting,SubSegmentReporting, IsActiveForSCM
)
SELECT	pp.Project_ID,ppi.ProjectItemID,ppi.SCOAItemID,pp.FinYear,@UserID,GETDATE(),
		ppi.ProjectFundYearID,ppi.SCOAFundId,ppi.BudgetAmountCurP1,ppi.BudgetAmountCurP2,ppi.BudgetAmountCurP2,
		ppi.SCOAFunctionId,ppi.SCOARegionId,ppi.DivisionId,ppi.BudgetSplitID,ppi.HistoricalProjectCode,
		ppi.SCOACostingID,ppi.CreditDebit,ppi.PlanProjectItem_ID,ppi.GRAPClassification,ppi.GRAPClassificationNote,
		ppi.MainSegmentReporting,ppi.SubSegmentReporting, ppi.IsActiveForSCM
		FROM Plan_ProjectItem ppi
		INNER JOIN dbo.Plan_Project pp ON pp.PreviousReferenceId = ppi.ProjectID 
		LEFT JOIN dbo.Plan_ProjectItem A ON A.ProjectID = pp.Project_ID AND A.DivisionID = ppi.DivisionID 
		AND A.ProjectItemID = ppi.ProjectItemID AND A.SCOAItemID = ppi.SCOAItemID AND a.SCOAFundId = ppi.SCOAFundId
		AND a.SCOAFunctionId = ppi.SCOAFunctionId AND a.SCOARegionId = ppi.SCOARegionId AND a.SCOACostingID = ppi.SCOACostingID
		WHERE pp.FinYear = @NextFinYear AND A.ProjectID IS NULL
        AND pp.ProjectName NOT like '%Virtual%'

--========================================
-- INSERT INTO Plan_ProjectItem & Plan_ProjectItemMonth VIRTUAL
--========================================

INSERT INTO dbo.Plan_ProjectItem
(
    ProjectID,ProjectItemID,SCOAItemID,FinYear,CapturerID,DateCaptured,
	ProjectFundYearID,SCOAFundId,BudgetAmount,BudgetAmountCurP1,BudgetAmountCurP2,
	SCOAFunctionId,SCOARegionId,DivisionId,BudgetSplitID,HistoricalProjectCode,
	SCOACostingID,CreditDebit,PreviousReferenceId,GRAPClassification,GRAPClassificationNote,
	MainSegmentReporting,SubSegmentReporting, IsActiveForSCM
)
SELECT	pp.Project_ID,ppi.ProjectItemID,ppi.SCOAItemID,pp.FinYear,@UserID,GETDATE(),
		ppi.ProjectFundYearID,ppi.SCOAFundId,0,0,0,
		ppi.SCOAFunctionId,ppi.SCOARegionId,ppi.DivisionId,ppi.BudgetSplitID,ppi.HistoricalProjectCode,
		ppi.SCOACostingID,ppi.CreditDebit,ppi.PlanProjectItem_ID,ppi.GRAPClassification,ppi.GRAPClassificationNote,
		ppi.MainSegmentReporting,ppi.SubSegmentReporting, ppi.IsActiveForSCM
		FROM Plan_ProjectItem ppi
		INNER JOIN dbo.Plan_Project pp ON pp.PreviousReferenceId = ppi.ProjectID 
		LEFT JOIN dbo.Plan_ProjectItem A ON A.ProjectID = pp.Project_ID AND A.DivisionID = ppi.DivisionID 
		AND A.ProjectItemID = ppi.ProjectItemID AND A.SCOAItemID = ppi.SCOAItemID AND a.SCOAFundId = ppi.SCOAFundId
		AND a.SCOAFunctionId = ppi.SCOAFunctionId AND a.SCOARegionId = ppi.SCOARegionId AND a.SCOACostingID = ppi.SCOACostingID
		WHERE pp.FinYear = @NextFinYear AND A.ProjectID IS NULL
        AND pp.ProjectName like '%Virtual%'
        
        /* -- This for Virtual Items Inventory --*/

        IF NOT EXISTS ( SELECT 1 FROM Const_Inventory_CommodityClassification_SCOAItem_CostFormula WHERE FinYear = @NextFinYear )
        BEGIN
	        INSERT INTO [dbo].[Const_Inventory_CommodityClassification_SCOAItem_CostFormula]
			           ([CommodityClassification_ID]
			           ,[SCOA_Item_ID]
			           ,[CostFormula_ID]
			           ,[DateCaptured]
			           ,[CapturerID]
			           ,[DateModified]
			           ,[ModifierID]
			           ,[FinYear])
		         Select [CommodityClassification_ID]
			           ,[SCOA_Item_ID]
			           ,[CostFormula_ID]
			           ,[DateCaptured]
			           ,[CapturerID]
			           ,[DateModified]
			           ,[ModifierID]
			           ,@NextFinYear
			           from 
			           Const_Inventory_CommodityClassification_SCOAItem_CostFormula where FinYear = @FinYear
        END

        IF NOT EXISTS ( SELECT 1 FROM [Const_Inventory_CommodityClassification_SCOAItem_Expense] WHERE FinYear = @NextFinYear )
        BEGIN
	        INSERT INTO [dbo].[Const_Inventory_CommodityClassification_SCOAItem_Expense]
			           ([CommodityClassification_ID]
			           ,[SCOA_Item_ID]
			           ,[CommodityClassificationSubClass]
			           ,[DateCaptured]
			           ,[CapturerID]
			           ,[DateModified]
			           ,[ModifierID]
			           ,[FinYear])
		         Select [CommodityClassification_ID]
			           ,[SCOA_Item_ID]
			           ,[CommodityClassificationSubClass]
			           ,[DateCaptured]
			           ,[CapturerID]
			           ,[DateModified]
			           ,[ModifierID]
			           ,@NextFinYear
			           from 
			           Const_Inventory_CommodityClassification_SCOAItem_Expense where FinYear = @FinYear
        END



/*================= ***** Insert Plan_ProjectItem Month ***** =================*/

INSERT  INTO dbo.Plan_ProjectItemMonth
( 
	PlanProjectItemID ,MonthID ,UnitQuantity ,UnitPrice ,
	CaptureID ,DateCaptured ,PreviousReferenceId
)
SELECT  PPI.PlanProjectItem_ID ,MonthID ,UnitQuantity ,UnitPrice ,
		@UserID ,GETDATE() ,PPM.ProjectItemMonth_ID
        FROM    dbo.Plan_ProjectItemMonth PPM
        INNER JOIN Plan_ProjectItem PPI ON PPI.PreviousReferenceId = PPM.PlanProjectItemID
        WHERE   PPI.FinYear = @NextFinYear;


/*---------------- Update PlanProjectItemID -------------------*/

DECLARE @MonthIDForUpdate INT;

SELECT  @MonthIDForUpdate = KeyValue FROM    dbo.AAAA_ConfigSettings
WHERE   KeyName LIKE '%FinYearStartMonth%';

UPDATE  PPM
SET    PPM.UnitPrice = ISNULL(CASE WHEN ISNULL(PPM.MonthID, 0) != @MonthIDForUpdate
                                    THEN CONVERT(NUMERIC(18, 2), CONVERT(BIGINT, PPI.BudgetAmount/ 12))
                                    ELSE (CONVERT(BIGINT, PPI.BudgetAmount / 12) + ( PPI.BudgetAmount - ( CONVERT(BIGINT, PPI.BudgetAmount / 12) * 12 ) ) )
                               END, 0)
FROM    dbo.Plan_ProjectItemMonth PPM
        INNER JOIN dbo.Plan_ProjectItem PPI ON PPI.PlanProjectItem_ID = PPM.PlanProjectItemID
WHERE   PPM.PreviousReferenceId IS NOT NULL AND PPI.FinYear = @NextFinYear;


--========================================
-- INSERT INTO Plan_ProjectFund
--========================================

INSERT  INTO dbo.Plan_ProjectFund
( 
	ProjectID ,ScoaFundID ,FundAmount ,
	CapturerID ,DateCaptured ,FundReference ,PreviousReferenceId
)
SELECT DISTINCT PPA.Project_ID ,PPF.ScoaFundID ,FundAmount ,
		@UserID ,GETDATE() ,FundReference ,ProjectFund_ID
        FROM    dbo.Plan_ProjectFund PPF
		INNER JOIN dbo.Plan_Project PPA ON PPA.PreviousReferenceId = PPF.ProjectID AND PPA.PreviousReferenceId IS NOT NULL
        WHERE   PPF.PreviousReferenceId IS NULL AND PPA.FinYear = @NextFinYear;

--/*=============================== Update Budget Amount Plan_ProjectFund ==========================*/                

UPDATE  PP
SET     PP.FundAmount = A.FundAmount
FROM    dbo.Plan_ProjectFund PP
        INNER JOIN ( SELECT PPI.ProjectID AS ProjectID ,
                            PPI.SCOAFundId ,
                            ( SUM(ISNULL(PPI.BudgetAmount, 0))
                              + SUM(ISNULL(PPI.BudgetAmountCurP1, 0))
                              + SUM(ISNULL(PPI.BudgetAmountCurP2, 0)) ) AS FundAmount
                     FROM   Plan_ProjectFund PPF
                            INNER JOIN dbo.Plan_ProjectItem PPI ON PPI.ProjectID = PPF.ProjectID
                                                              AND PPI.SCOAFundId = PPF.ScoaFundID
							INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                     WHERE  PPF.PreviousReferenceId IS NOT NULL
                            AND PPI.FinYear = @NextFinYear AND PP.CapitalOperation IN (0,1)
                     GROUP BY PPI.ProjectID ,
                            PPI.SCOAFundId
                   ) A ON A.ProjectID = PP.ProjectID
                          AND A.SCOAFundId = PP.ScoaFundID
						  WHERE 1 = 1;

INSERT  INTO dbo.Plan_ProjectFundYear
( 
	ProjectFundID ,FinYear ,YearFundAmount ,
	CapturerID ,DateCaptured ,PreviousReferenceId
)
SELECT  DISTINCT PF.ProjectFund_ID ,
                ISNULL(CASE PPF.FinYear
                  WHEN @FinYear THEN @NextFinYear
                  WHEN @NextFinYear THEN @NextFinYearP3
                  WHEN @NextFinYearP3 THEN @NextFinYearP4
                END, @NextFinYear),
                YearFundAmount ,@UserID ,GETDATE() ,ProjectFundYear_ID
        FROM    dbo.Plan_ProjectFundYear PPF
                INNER JOIN Plan_ProjectFund PF ON PF.PreviousReferenceId = PPF.ProjectFundID
                INNER JOIN Plan_Project PP ON PP.Project_ID = PF.ProjectID
        WHERE   PP.FinYear = @NextFinYear;



/*=============================== Update YearFundAmount Plan_ProjectFundYear ==========================*/ 

UPDATE  PPJ
SET     PPJ.YearFundAmount = ( CASE PPJ.FinYear
                                 WHEN @NextFinYear
                                 THEN ISNULL(BudgetAmount, 0)
                                 WHEN @NextFinYearP3
                                 THEN ISNULL(A.BudgetAmountCurP1, 0)
                                 WHEN @NextFinYearP4
                                 THEN ISNULL(A.BudgetAmountCurP2, 0)
                               END )
FROM    Plan_ProjectFundYear PPJ
        INNER JOIN ( SELECT PPF.FinYear ,
                            PF.ProjectID AS ProjectID_PF ,
                            PPF.ProjectFundID ,
                            PPI.SCOAFundId ,
                            MAX(PPI.ProjectItemID) AS ProjectItemID ,
                            SUM(ISNULL(PPI.BudgetAmount, 0)) AS BudgetAmount ,
                            SUM(ISNULL(PPI.BudgetAmountCurP1, 0)) AS BudgetAmountCurP1 ,
                            SUM(ISNULL(PPI.BudgetAmountCurP2, 0)) AS BudgetAmountCurP2
                     FROM   Plan_ProjectFundYear PPF
                            INNER JOIN Plan_ProjectFund PF ON PF.ProjectFund_ID = PPF.ProjectFundID
                            INNER JOIN Plan_ProjectItem PPI ON PPI.ProjectID = PF.ProjectID
                                                              AND PPI.SCOAFundId = PF.ScoaFundID
							INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                     WHERE  PPF.PreviousReferenceId IS NOT NULL
                            AND PPI.FinYear = @NextFinYear AND PP.CapitalOperation IN (0,1)
                     GROUP BY PPI.SCOAFundId ,
                            PF.ProjectID ,
                            PPF.ProjectFundID ,
                            PPF.FinYear
                   ) A ON A.FinYear = PPJ.FinYear
                          AND A.ProjectFundID = PPJ.ProjectFundID
						   WHERE 1 = 1;

/*=============================== Update Plan_ProjectItem Plan_ProjectFundYear ==========================*/ 

UPDATE  PPI
SET     PPI.ProjectFundYearID = PPF.ProjectFundYear_ID
FROM    Plan_ProjectItem PPI
        INNER JOIN Plan_ProjectFundYear PPF ON PPF.PreviousReferenceId = PPI.ProjectFundYearID
                                               AND PPF.PreviousReferenceId IS NOT NULL
											   WHERE PPI.FinYear = @NextFinYear;

/*=============================== Update Plan_ProjectItem (SCOA Item) ==========================*/ 


UPDATE  PP
SET     PP.SCOAItemID = PSE.NewSCOAId
FROM    Plan_ProjectItem PP
        INNER JOIN Plan_SCOAItemExceptions PSE ON PSE.ActiveSCOAId = PP.SCOAItemID
WHERE   PP.FinYear = @NextFinYear AND PSE.FinYear = @NextFinYear AND NewSCOAId IS NOT NULL
        AND PP.PreviousReferenceId IS NOT NULL;

/*=============================== Update Plan_ProjectItem,Plan_ProjectFund (SCOA Funding) ==========================*/ 


UPDATE  PP
SET     PP.SCOAFundId = PSE.NewSCOAId
FROM    Plan_ProjectFund PP
		INNER JOIN dbo.Plan_Project PPA ON PPA.Project_ID = PP.ProjectID 
        INNER JOIN Plan_SCOAFundingExceptions PSE ON PSE.ActiveSCOAId = PP.SCOAFundId
WHERE   PPA.FinYear = @NextFinYear AND PSE.FinYear = @NextFinYear AND NewSCOAId IS NOT NULL
        AND PP.PreviousReferenceId IS NOT NULL;

UPDATE  PP
SET     PP.SCOAFundId = PSE.NewSCOAId
FROM    Plan_ProjectItem PP
        INNER JOIN Plan_SCOAFundingExceptions PSE ON PSE.ActiveSCOAId = PP.SCOAFundId
WHERE   PP.FinYear = @NextFinYear AND PSE.FinYear = @NextFinYear AND NewSCOAId IS NOT NULL
        AND PP.PreviousReferenceId IS NOT NULL;

/*=============================== Update Plan_ProjectItem,Plan_ProjectFunctions (SCOA Function) ==========================*/ 

UPDATE  PP
SET     PP.SCOAFunctionId = PSE.NewSCOAId
FROM    Plan_ProjectFunctions PP
		INNER JOIN dbo.Plan_Project PPA ON PPA.Project_ID = PP.ProjectID 
        INNER JOIN Plan_SCOAFunctionExceptions PSE ON PSE.ActiveSCOAId = PP.SCOAFunctionId
WHERE   PPA.FinYear = @NextFinYear AND PSE.FinYear = @NextFinYear AND NewSCOAId IS NOT NULL
        AND PP.PreviousReferenceId IS NOT NULL;

UPDATE  PP
SET     PP.SCOAFunctionId = PSE.NewSCOAId
FROM    Plan_ProjectItem PP
        INNER JOIN Plan_SCOAFunctionExceptions PSE ON PSE.ActiveSCOAId = PP.SCOAFunctionId
WHERE   PP.FinYear = @NextFinYear AND PSE.FinYear = @NextFinYear AND NewSCOAId IS NOT NULL
        AND PP.PreviousReferenceId IS NOT NULL;


/*=============================== Update Plan_ProjectItem,Plan_ProjectRegions (SCOA Region) ==========================*/ 

UPDATE  PP
SET     PP.SCOARegionId = PSE.NewSCOAId
FROM    Plan_ProjectRegions PP
        INNER JOIN dbo.Plan_Project PPA ON PPA.Project_ID = PP.ProjectID 
		INNER JOIN Plan_SCOARegionExceptions PSE ON PSE.ActiveSCOAId = PP.SCOARegionId
WHERE   PPA.FinYear = @NextFinYear AND PSE.FinYear = @NextFinYear AND NewSCOAId IS NOT NULL
        AND PP.PreviousReferenceId IS NOT NULL;

UPDATE  PP
SET     PP.SCOARegionId = PSE.NewSCOAId
FROM    Plan_ProjectItem PP
        INNER JOIN Plan_SCOARegionExceptions PSE ON PSE.ActiveSCOAId = PP.SCOARegionId
WHERE   PP.FinYear = @NextFinYear AND PSE.FinYear = @NextFinYear AND NewSCOAId IS NOT NULL
        AND PP.PreviousReferenceId IS NOT NULL;

/*=============================== Update Plan_ProjectItem,Plan_ProjectCosting (SCOA Costing) ==========================*/ 

UPDATE  PP
SET     PP.SCOACostingID = PSE.NewSCOAId
FROM    Plan_ProjectCosting PP
        INNER JOIN dbo.Plan_Project PPA ON PPA.Project_ID = PP.ProjectID 
		INNER JOIN Plan_SCOACostingExceptions PSE ON PSE.ActiveSCOAId = PP.SCOACostingID
WHERE   PPA.FinYear = @NextFinYear AND PSE.FinYear = @NextFinYear AND NewSCOAId IS NOT NULL
        AND PP.PreviousReferenceId IS NOT NULL;

UPDATE  PP
SET     PP.SCOACostingID = PSE.NewSCOAId
FROM    Plan_ProjectItem PP
        INNER JOIN Plan_SCOACostingExceptions PSE ON PSE.ActiveSCOAId = PP.SCOACostingID
WHERE   PP.FinYear = @NextFinYear AND PSE.FinYear = @NextFinYear AND NewSCOAId IS NOT NULL
        AND PP.PreviousReferenceId IS NOT NULL;


/*=============================== Update Plan_ProjectItem (Const Project Item) ==========================*/ 

UPDATE  PP
SET     PP.ProjectItemID = CPI.ProjectItem_ID
FROM    Plan_ProjectItem PP
        INNER JOIN Const_ProjectItem CPI ON CPI.PreviousReferenceId = PP.ProjectItemID
WHERE   CPI.FinYear = @NextFinYear AND PP.FinYear = @NextFinYear;


/*=============================== #85777 Update Plan_Project Status to Capture Id Amounts are 0 ==========================*/ 
UPDATE  Plan_Project
SET		ProjectStatus = @CaptureProjectStatus
WHERE   Project_ID IN 
		(
			SELECT Project_ID
			FROM Plan_Project P
				 INNER JOIN dbo.Plan_ProjectItem PP ON PP.ProjectID = P.Project_ID
			WHERE P.FinYear = @NextFinYear AND P.PreviousReferenceId IS NOT NULL
				  AND P.ProjectDesc NOT LIKE '%Virtual%' AND ProjectStatus <> 5
			GROUP BY Project_ID
			HAVING SUM(PP.BudgetAmount) + SUM(PP.BudgetAmountCurP1) + SUM(PP.BudgetAmountCurP2) = 0 
		)


/*=============================== #84763 Update Plan_Project ProjectTypeID ==========================*/ 
UPDATE  PP
SET     PP.ProjectTypeID = CPT.ProjectType_ID
FROM    Plan_Project PP
            LEFT JOIN Const_ProjectType CPT ON CPT.PreviousReferenceId = PP.ProjectTypeID
WHERE   CPT.FinYear = @NextFinYear AND PP.FinYear = @NextFinYear;


/*=============================== #87950 Insert New Funds into Funding Source Details ==========================*/ 

--  fix Funding sources

 DECLARE @FundSourceHeaderID INT = 0;
 DECLARE @StartFinYear INT = 0;
 DECLARE @CurrFinYear1 VARCHAR(20);

	WHILE ( @StartFinYear <= 2 )
		BEGIN
			SELECT  @CurrFinYear1 = CASE WHEN @StartFinYear = 0 THEN @NextFinYear
                                    WHEN @StartFinYear = 1 THEN @NextFinYearP3
                                    WHEN @StartFinYear = 2 THEN @NextFinYearP4
                                    END;

                        SELECT TOP 1
                                @FundSourceHeaderID = isnull(FundingSourceBudgetHeader_ID,0)
                        FROM    Plan_FundingSourceBudget_Header
                        WHERE   FinancialYear = @CurrFinYear1;

						IF @FundSourceHeaderID=0
						BEGIN
							INSERT INTO Plan_FundingSourceBudget_Header
							SELECT @CurrFinYear1,1,getdate(),1,null,null,null

							SELECT TOP 1
                                @FundSourceHeaderID = FundingSourceBudgetHeader_ID
							FROM    Plan_FundingSourceBudget_Header
							WHERE   FinancialYear = @CurrFinYear1;
						END;
                       
------------------------------------------------------------------------------
-- Create Budget Detail for Budget Amount for Fund Id not found 
------------------------------------------------------------------------------
                        INSERT  INTO dbo.Plan_FundingSourceBudget_Detail
                                ( FundingSourceBudgetHeaderID ,
                                  FundingSourceID ,
                                  ScoaID ,
                                  FundingSourceBudget ,
                                  DateCaptured ,
                                  CapturerID ,
                                  DateModified ,
                                  ModifierID
                                )
                                SELECT  @FundSourceHeaderID ,
                                        NULL ,
                                        R.SCOAFundId AS SCOAFundID ,
                                        ( CASE WHEN @StartFinYear = 0
                                               THEN SUM(R.BudgetAmount)
                                               WHEN @StartFinYear = 1
                                               THEN SUM(R.BudgetAmountCurP1)
                                               WHEN @StartFinYear = 2
                                               THEN SUM(R.BudgetAmountCurP2)
                                          END ) AS NwAllocAmount ,
                                        GETDATE() ,
                                        1 ,
                                        NULL ,
                                        NULL
                                FROM    [dbo].Plan_Project pp 
										INNER JOIN Plan_ProjectItem R ON pp.Project_ID=R.ProjectID	
                                WHERE   ISNULL(dbo.Planing_GetFundAvailableAmount(R.SCOAFundId,
                                                              @CurrFinYear1),
                                               0) = 0
											    AND CapitalOperation  in (0,1)
					AND R.SCOAFundId NOT IN(SELECT ScoaID FROM Plan_FundingSourceBudget_Detail WHERE FundingSourceBudgetHeaderID = @FundSourceHeaderID)
					AND R.SCOAFundId IN(SELECT NewSCOAId FROM dbo.Plan_SCOAFundingExceptions WHERE FinYear = @NextFinYear)
                                GROUP BY R.SCOAFundId;

                        SET @StartFinYear = @StartFinYear + 1;
                    END;

--=================Enable FK relations
IF OBJECT_ID('FK_Plan_Project_Const_SCOA_Project_Structure') IS NOT NULL
BEGIN
	ALTER TABLE Plan_Project 
	CHECK CONSTRAINT FK_Plan_Project_Const_SCOA_Project_Structure
END

IF OBJECT_ID('FK_Plan_ProjectFunctions_Const_SCOA_Function_Structure') IS NOT NULL
BEGIN
	ALTER TABLE Plan_ProjectFunctions 
	CHECK CONSTRAINT FK_Plan_ProjectFunctions_Const_SCOA_Function_Structure; 
END

IF OBJECT_ID('FK_Plan_ProjectItem_Const_SCOA_Structure') IS NOT NULL
BEGIN
	ALTER TABLE Plan_ProjectItem 
	CHECK CONSTRAINT FK_Plan_ProjectItem_Const_SCOA_Structure;
END

IF OBJECT_ID('FK_Plan_ProjectFund_Const_SCOA_Funds_Structure') IS NOT NULL
BEGIN
	ALTER TABLE  Plan_ProjectFund
	CHECK CONSTRAINT FK_Plan_ProjectFund_Const_SCOA_Funds_Structure
END

IF OBJECT_ID('FK_Plan_ProjectRegions_Const_SCOA_Regional_Structure') IS NOT NULL
BEGIN
	ALTER TABLE  Plan_ProjectRegions
	CHECK CONSTRAINT FK_Plan_ProjectRegions_Const_SCOA_Regional_Structure
END

IF OBJECT_ID('FK_Plan_ProjectCosting_Const_SCOA_Costing_Structure') IS NOT NULL
BEGIN
	ALTER TABLE  Plan_ProjectCosting
	CHECK CONSTRAINT FK_Plan_ProjectCosting_Const_SCOA_Costing_Structure
END

IF OBJECT_ID('FK_Plan_FundingSourceBudget_Const_SCOA_Funds_Structure') IS NOT NULL
BEGIN
	ALTER TABLE [dbo].[Plan_FundingSourceBudget_Detail] 
	CHECK CONSTRAINT [FK_Plan_FundingSourceBudget_Const_SCOA_Funds_Structure]
END

SET @ErrorResult = 'Success'

--COMMIT TRANSACTION BudgetRolloverTran

END TRY
BEGIN CATCH
	
	SET @ErrorResult = ERROR_MESSAGE();

	INSERT into Sys_ErrorLog (moduleName, pageName, procedureName, errorMessage, errorType, detailedErrorMessage, errorDate, userName)
		Values ('Planning','SQL Server','Plan_BudgetRolloverForPlanTables_sp', ERROR_MESSAGE(), 'SQL', ERROR_MESSAGE(), GETDATE(), 'SQL')

    RAISERROR(@ErrorResult, 16, 1)
   -- ROLLBACK TRANSACTION BudgetRolloverTran

END CATCH

END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetZeroBudgetConsumptionEntry_sp]    Script Date: 2026/03/10 7:23:28 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Chris Moodley
-- Create date: September 2025
-- Description:	 Insert zero budget items into budget consumption table
-- =============================================
CREATE PROCEDURE [dbo].[Plan_BudgetZeroBudgetConsumptionEntry_sp]
	-- Add the parameters for the stored procedure here
	@finYear NVARCHAR(9),
	@userID INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE @ProcessingMonth INT
	SELECT @ProcessingMonth = (SELECT CONVERT(INT, KeyValue) FROM AAAA_ConfigSettings WHERE KeyName = 'ActiveProcessingMonth')

	INSERT INTO Plan_BudgetConsumption
	SELECT 
		ppi.FinYear,--FinYear
		PlanProjectItem_ID,--PlanProjectItemID
		1,--BudgetTransactionTypeID
		10,--ModuleID
		PlanProjectItem_ID,--PK_TransactionID
		'Plan_ProjectItem',--TransactionTableName
		BudgetAmount,--ConsumingTransactionAmount
		BudgetAmountCurP1 + BudgetAmountCurP2,--ConsumingTransactionAmountMultiyear
		BudgetAmount,--AdjustedTansactionAmount
		BudgetAmount,--AvailableBudget
		BudgetAmountCurP1 + BudgetAmountCurP2,--AvailableBudgetMultiyear
		@ProcessingMonth,--ProcessingMonth
		200,--BudgetConsumptionProcessID
		BudgetAmount,--OriginalBudgetToDate
		0,--AdjustedBudgetToDate
		0,--CapturedExpenditureToDate
		0,--CapturedExpenditureToDateMultiyear
		0,--ReserveToDate
		0,--ReserveToDateMultiyear
		0,--CommitToDate
		0,--ActualToDate
		-BudgetAmount,--CurrentlyConsumedAmount
		NULL,--CurrentlyConsumedAmountMultiYear
		'Plan_ProjectItem_' + CONVERT(VARCHAR, PlanProjectItem_ID),--InitialLine
		@userID,--CapturerID
		GETDATE(),--DateCaptured
		NULL,--ModifierID
		NULL--DateModified 	
	FROM
		Plan_ProjectItem ppi
		inner join Plan_Project pp on ppi.ProjectID = pp.Project_ID
	WHERE
		pp.FinYear = @finYear AND ProjectStatus = 24 and ISNULL(IsDeleted, 0) <> 1
		AND PlanProjectItem_ID not in (select PlanProjectItemID from Plan_BudgetConsumption where FinYear = @finYear)

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetZeroFieldValidation_sp]    Script Date: 2026/03/10 7:23:28 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- ========================================================
-- Author:		Chris Moodley
-- Create date: September 2025
-- Description:	Zero Budget Field Validation
-- 250916 by CM: 123686 - Include validation for budget type and zero budget reason
--								    - Validate if item already exists in the budget
-- 250922 by CM: 123686 - Fix Validation check where item already exists in the budget
--								    - Check that Plan Project Item ID = 0
-- 251001 by CM: 123815 - Do insert for items existing in budget check
-- 251027 by CM: 124473 - Check if IDP Item exists for new projects
-- ========================================================
CREATE PROCEDURE [dbo].[Plan_BudgetZeroFieldValidation_sp]
	-- Add the parameters for the stored procedure here
	 @BudgetZeroExportImportVersionHeaderID INT 
	,@BudgetZeroImportVersionNumber INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE @finYear NVARCHAR(10), @versionID INT, @idpNumLevel INT
	
	SELECT @finYear = FinYear, @versionID = ZeroVersionID 
	FROM Plan_BudgetZeroExportImportVersion_Header 
	WHERE BudgetZeroExportImportVersionHeader_ID = @BudgetZeroExportImportVersionHeaderID

	SELECT @idpNumLevel = IDPNumLevel
	FROM Const_IDPLevelDescription_Header
	WHERE FinancialYear = @finYear

	CREATE TABLE #Const_SCOA_Project_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6))
	CREATE INDEX idxProjectScoaID ON #Const_SCOA_Project_Structure(ScoaID)
	CREATE INDEX idxProjectScoaCode ON #Const_SCOA_Project_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Project_Structure SELECT ScoaID, ScoaCode, PostingLevel FROM Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @finYear

	CREATE TABLE #Const_SCOA_Function_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6))
	CREATE INDEX idxFunctionScoaID ON #Const_SCOA_Function_Structure(ScoaID)
	CREATE INDEX idxFunctionScoaCode ON #Const_SCOA_Function_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Function_Structure SELECT ScoaID, ScoaCode, PostingLevel FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @finYear

	CREATE TABLE #Const_SCOA_Fund_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6))
	CREATE INDEX idxFundScoaID ON #Const_SCOA_Fund_Structure(ScoaID)
	CREATE INDEX idxFundScoaCode ON #Const_SCOA_Fund_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Fund_Structure SELECT ScoaID, ScoaCode, PostingLevel FROM Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @finYear

	CREATE TABLE #Const_SCOA_Region_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6))
	CREATE INDEX idxRegionScoaID ON #Const_SCOA_Region_Structure(ScoaID)
	CREATE INDEX idxRegionScoaCode ON #Const_SCOA_Region_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Region_Structure SELECT ScoaID, ScoaCode, PostingLevel FROM Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @finYear

	CREATE TABLE #Const_SCOA_Costing_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6))
	CREATE INDEX idxCostingScoaID ON #Const_SCOA_Costing_Structure(ScoaID)
	CREATE INDEX idxCostingScoaCode ON #Const_SCOA_Costing_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Costing_Structure SELECT ScoaID, ScoaCode, PostingLevel FROM Const_SCOA_Costing_Structure_Consolidated WHERE FinYearText = @finYear

	CREATE TABLE #Const_SCOA_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6))
	CREATE INDEX idxItemScoaID ON #Const_SCOA_Structure(ScoaID)
	CREATE INDEX idxItemScoaCode ON #Const_SCOA_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Structure SELECT ScoaID, ScoaCode, PostingLevel FROM Const_SCOA_Structure_Consolidated WHERE FinYearText = @finYear

	SELECT *
	INTO #Import
	FROM Plan_BudgetZeroImportVersion_Detail
	WHERE BudgetZeroExportImportVersionHeaderID = @BudgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @BudgetZeroImportVersionNumber

	--Budget Type Incorrect
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'Incorrect Budget Type'
	FROM 
		#Import imp
		LEFT JOIN (SELECT * FROM Const_PlanCapitalOperationalTypes_sys WHERE Enabled = 1) budType ON imp.BudgetType = budType.TypeName
	WHERE
		(imp.BudgetType IS NOT NULL AND imp.BudgetType <> '') AND  budType.TypeName IS NULL

	--No reason for zero budget
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'Zero Budget reason required'
	FROM #Import imp
	WHERE (ZeroBudgetItemReason IS NULL OR ZeroBudgetItemReason = '')

	--SCOA segment does not exist
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'SCOA Project Segment does not exist'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Project_Structure proj ON imp.SCOAProjectCode = proj.ScoaCode
	WHERE
		proj.Scoacode IS NULL

	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'SCOA Function Segment does not exist'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Function_Structure func ON imp.SCOAFunctionCode = func.ScoaCode
	WHERE
		func.Scoacode IS NULL

	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'SCOA Fund Segment does not exist'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Fund_Structure fund ON imp.SCOAFundCode = fund.ScoaCode
	WHERE
		fund.Scoacode IS NULL

	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'SCOA Region Segment does not exist'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Region_Structure region ON imp.SCOARegionCode = region.ScoaCode
	WHERE
		region.Scoacode IS NULL

	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'SCOA Costing Segment does not exist'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Costing_Structure cost ON imp.SCOACostingCode = cost.ScoaCode
	WHERE
		cost.Scoacode IS NULL

	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'SCOA Item Segment does not exist'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
	WHERE
		item.Scoacode IS NULL

	--SCOA segment not at posting level
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'SCOA Project Segment not at Posting Level'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Project_Structure proj ON imp.SCOAProjectCode = proj.ScoaCode
	WHERE
		proj.Scoacode IS NOT NULL AND PostingLevel <> 'Yes'

	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'SCOA Function Segment not at Posting Level'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Function_Structure func ON imp.SCOAFunctionCode = func.ScoaCode
	WHERE
		func.Scoacode IS NOT NULL AND PostingLevel <> 'Yes'

	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'SCOA Fund Segment not at Posting Level'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Fund_Structure fund ON imp.SCOAFundCode = fund.ScoaCode
	WHERE
		fund.Scoacode IS NOT NULL AND PostingLevel <> 'Yes'

	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'SCOA Region Segment not at Posting Level'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Region_Structure region ON imp.SCOARegionCode = region.ScoaCode
	WHERE
		region.Scoacode IS NOT NULL AND PostingLevel <> 'Yes'

	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'SCOA Costing Segment not at Posting Level'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Costing_Structure cost ON imp.SCOACostingCode = cost.ScoaCode
	WHERE
		cost.Scoacode IS NOT NULL AND PostingLevel <> 'Yes'

	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'SCOA Item Segment not at Posting Level'
	FROM 
		#Import imp
		LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
	WHERE
		item.Scoacode IS NOT NULL AND PostingLevel <> 'Yes'

	--Check that IDP exists for new projects
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'IDPItem does not exist'
	FROM
		#Import imp 
		LEFT JOIN IDP_Item idp ON (SELECT [Value] FROM [dbo].[Split_fxn](IDPItem, '|') WHERE ID = 1) = idp.ItemDesc and FinancialYear = @finYear AND IDPLevelNumber = @idpNumLevel
	WHERE   
		(imp.ProjectID IS NULL OR imp.ProjectID = 0)
		AND Item_ID IS NULL

	--Budget amounts must all be zero
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'Budget Amounts must all be zero'
	FROM
		#Import
	WHERE
		CurrentBudgetFinYear1 <> 0 AND CurrentBudgetFinYear2 <> 0 AND CurrentBudgetFinYear3 <> 0

	--Monthly breakdown not equal to CurrentBudgetFinYear1
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'Monthly breakdown does not equal to CurrentBudgetFinYear1'
	FROM
		#Import
	WHERE
		ABS(CurrentBudgetFinYear1) <> ABS(M1) + ABS(M2) + ABS(M3) + ABS(M4) + ABS(M5) + ABS(M6) + ABS(M7) + ABS(M8) + ABS(M9) + ABS(M10) + ABS(M11) + ABS(M12) 

	--Project Name already exists
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT DISTINCT BudgetZeroImportVersionDetail_ID, 'Project name already exists'
	FROM
		#Import imp 
		INNER JOIN Plan_Project pap ON imp.ProjectName = pap.ProjectName
	WHERE   
		(imp.ProjectID IS NULL OR imp.ProjectID = 0) 
		AND pap.FinYear = @finYear

	--CreditDebit Flag
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'Incorrect Debit/Credit flag'
	FROM
		#Import imp 
	WHERE   
		ISNULL(CreditDebit, '')  NOT IN ('C', 'D')

	--PlanProjectItemID
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'Plan Project Item ID must be zero for new items'
	FROM
		#Import imp 
	WHERE   
		ISNULL(PlanProjectItemID, 0) <> 0

	--Division does not exist
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'Division Code does not exist'
	FROM 
		#Import imp	
		LEFT JOIN Const_Division div ON imp.MSCDivisionCode = div.DivisionCode
	WHERE
		div.Division_ID IS NULL

	--Multiple SCOA Project
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'Multiple SCOA Project per project name on Import Sheet'
	FROM    
		#Import bvd
		LEFT JOIN 
			( 
				SELECT DISTINCT 
					bvd.ProjectName  , bvd.ScoaProjectCode
				FROM    
					#Import bvd
				WHERE   
					ProjectName IN 
						(
							SELECT  ProjectName
							FROM    
								( 
									SELECT DISTINCT
										p.ProjectName ,
										p.ScoaProjectCode
									FROM
										#Import p
								) dup
							GROUP BY ProjectName
							HAVING  COUNT(*) > 1 
						)
				) dup 
			ON 
				bvd.ProjectName = dup.ProjectName
				AND bvd.ScoaProjectCode = dup.ScoaProjectCode
	WHERE  
		dup.ScoaProjectCode IS NOT NULL

	--Multiple Project Description
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'Multiple Project Description per project name on Import Sheet'
	FROM    
		#Import bvd
		LEFT JOIN 
			( 
				SELECT DISTINCT 
					bvd.ProjectName , bvd.ProjectDesc 
				FROM    
					#Import bvd
				WHERE   
					ProjectName IN 
						(
							SELECT  ProjectName
							FROM    
								( 
									SELECT DISTINCT
										p.ProjectName ,
										p.ProjectDesc
									FROM
										#Import p
								) dup
							GROUP BY ProjectName
							HAVING  COUNT(*) > 1 
						)
				) dup 
			ON 
				bvd.ProjectName = dup.ProjectName
				AND bvd.ProjectDesc = dup.ProjectDesc
	WHERE   
		dup.ProjectDesc IS NOT NULL

	--Multiple Budget Type
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'Multiple Budget Type per project name on Import Sheet'
	FROM    
		#Import bvd
		LEFT JOIN 
			( 
				SELECT DISTINCT 
					bvd.ProjectName , bvd.BudgetType 
				FROM    
					#Import bvd
				WHERE   
					ProjectName IN 
						(
							SELECT  ProjectName
							FROM    
								( 
									SELECT DISTINCT
										p.ProjectName ,
										p.BudgetType
									FROM
										#Import p
								) dup
							GROUP BY ProjectName
							HAVING  COUNT(*) > 1 
						)
				) dup 
			ON 
				bvd.ProjectName = dup.ProjectName
				AND bvd.BudgetType = dup.BudgetType
	WHERE   
		dup.BudgetType IS NOT NULL

	--Multiple Single Multi Year
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'Multiple Single Multi Year per project name on Import Sheet'
	FROM    
		#Import bvd
		LEFT JOIN 
			( 
				SELECT DISTINCT 
					bvd.ProjectName , bvd.SingleMultiYear 
				FROM    
					#Import bvd
				WHERE   
					ProjectName IN 
						(
							SELECT  ProjectName
							FROM    
								( 
									SELECT DISTINCT
										p.ProjectName ,
										p.SingleMultiYear
									FROM
										#Import p
								) dup
							GROUP BY ProjectName
							HAVING  COUNT(*) > 1 
						)
				) dup 
			ON 
				bvd.ProjectName = dup.ProjectName
				AND bvd.SingleMultiYear = dup.SingleMultiYear
	WHERE   
		dup.SingleMultiYear IS NOT NULL

	--Duplicate values
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'Duplicate Values on Import Sheet'
	FROM
		#Import imp
		INNER JOIN 
			(
				SELECT 
					IDPItem,
					ProjectName,
					ProjectDesc,
					BudgetType,
					SCOAProjectCode,
					SCOAFunctionCode,
					SCOAFundCode,
					SCOARegionCode,
					SCOACostingCode,
					SCOAItemCode,
					MSCDivisionCode,
					CreditDebit
				FROM	
					#Import
				GROUP BY
					IDPItem,
					ProjectName,
					ProjectDesc,
					BudgetType,
					SCOAProjectCode,
					SCOAFunctionCode,
					SCOAFundCode,
					SCOARegionCode,
					SCOACostingCode,
					SCOAItemCode,
					MSCDivisionCode,
					CreditDebit
				HAVING	
					COUNT(*) > 1
			) impDup

			ON
				imp.IDPItem = impDup.IDPItem
				AND imp.ProjectName = impDup.ProjectName
				AND imp.ProjectDesc = impDup.ProjectDesc
				AND imp.BudgetType = impDup.BudgetType
				AND imp.SCOAProjectCode = impDup.SCOAProjectCode
				AND imp.SCOAFunctionCode = impDup.SCOAFunctionCode
				AND imp.SCOAFundCode = impDup.SCOAFundCode
				AND imp.SCOARegionCode = impDup.SCOARegionCode
				AND imp.SCOACostingCode = impDup.SCOACostingCode
				AND imp.SCOAItemCode = impDup.SCOAItemCode
				AND imp.MSCDivisionCode = impDup.MSCDivisionCode
				AND imp.CreditDebit = impDup.CreditDebit

	--Item already exists in budget
	INSERT INTO Plan_BudgetZeroImportVersion_DetailException
	SELECT BudgetZeroImportVersionDetail_ID, 'Item already exists in Budget'
	FROM
		#Import imp
		INNER JOIN 
			(
				SELECT 
					ProjectName,
					ProjectDesc,
					TypeName BudgetType,
					proj.ScoaCode SCOAProjectCode,
					func.ScoaCode SCOAFunctionCode,
					fund.ScoaCode SCOAFundCode,
					region.ScoaCode SCOARegionCode,
					cost.ScoaCode SCOACostingCode,
					item.ScoaCode SCOAItemCode,
					div.DivisionCode MSCDivisionCode,
					CreditDebit
				FROM	
					Plan_ProjectItem ppi
					INNER JOIN Plan_Project pp ON ppi.ProjectID = pp.Project_ID
					INNER JOIN #Const_SCOA_Costing_Structure cost ON ppi.SCOACostingID = cost.ScoaID
					INNER JOIN #Const_SCOA_Function_Structure func ON ppi.SCOAFunctionId = func.ScoaID
					INNER JOIN #Const_SCOA_Fund_Structure fund ON ppi.SCOAFundId = fund.ScoaID
					INNER JOIN #Const_SCOA_Project_Structure proj ON pp.ScoaProjectID = proj.ScoaID
					INNER JOIN #Const_SCOA_Region_Structure region ON ppi.SCOARegionId = region.ScoaID
					INNER JOIN #Const_SCOA_Structure item ON ppi.SCOAItemID = item.ScoaID
					INNER JOIN Const_Division div ON ppi.DivisionId = div.Division_ID
					INNER JOIN Const_PlanCapitalOperationalTypes_sys budType ON pp.CapitalOperation = budType.TypeValue
				WHERE
					pp.FinYear = @finYear AND ISNULL(IsDeleted, 0) <> 1 AND ProjectStatus = 24
				GROUP BY
					ProjectName,
					ProjectDesc,
					TypeName,
					proj.ScoaCode,
					func.ScoaCode,
					fund.ScoaCode,
					region.ScoaCode,
					cost.ScoaCode,
					item.ScoaCode,
					div.DivisionCode,
					CreditDebit
			) impDup

			ON
				imp.ProjectName = impDup.ProjectName
				AND imp.ProjectDesc = impDup.ProjectDesc
				AND imp.BudgetType = impDup.BudgetType
				AND imp.SCOAProjectCode = impDup.SCOAProjectCode
				AND imp.SCOAFunctionCode = impDup.SCOAFunctionCode
				AND imp.SCOAFundCode = impDup.SCOAFundCode
				AND imp.SCOARegionCode = impDup.SCOARegionCode
				AND imp.SCOACostingCode = impDup.SCOACostingCode
				AND imp.SCOAItemCode = impDup.SCOAItemCode
				AND imp.MSCDivisionCode = impDup.MSCDivisionCode
				AND imp.CreditDebit = impDup.CreditDebit

	DROP TABLE #Import, #Const_SCOA_Structure, #Const_SCOA_Costing_Structure, #Const_SCOA_Function_Structure, #Const_SCOA_Fund_Structure, #Const_SCOA_Project_Structure, #Const_SCOA_Region_Structure

END
GO

