-- =============================================
-- Author:		Chris Moodley
-- Create date: September 2025
-- Description:	Return zero budget import results
-- =============================================
CREATE PROCEDURE [dbo].[Plan_BudgetZeroImportResult_sp] 
	-- Add the parameters for the stored procedure here
	 @budgetZeroExportImportVersionHeaderID INT
	,@budgetZeroImportVersionNumber INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE 
		 @countProjectExisting INT
		,@countProjectNew INT
		,@countErrorRecordIndividual INT
		,@finYear NVARCHAR(10)
		,@budgetY1 DECIMAL(18, 2)
		,@budgetY2 DECIMAL(18, 2)
		,@budgetY3 DECIMAL(18, 2)
		,@fileName NVARCHAR(200)

	SELECT @finYear = FinYear FROM Plan_BudgetZeroExportImportVersion_Header WHERE BudgetZeroExportImportVersionHeader_ID = @budgetZeroExportImportVersionHeaderID

	SELECT 
		 @budgetY1 = SUM(CASE WHEN (((item.ScoaCode LIKE 'IR%' OR item.ScoaCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(CurrentBudgetFinYear1) ELSE ABS(CurrentBudgetFinYear1) END)
		,@budgetY2 = SUM(CASE WHEN (((item.ScoaCode LIKE 'IR%' OR item.ScoaCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(CurrentBudgetFinYear2) ELSE ABS(CurrentBudgetFinYear2) END)
		,@budgetY3 = SUM(CASE WHEN (((item.ScoaCode LIKE 'IR%' OR item.ScoaCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(CurrentBudgetFinYear3) ELSE ABS(CurrentBudgetFinYear3) END)
	FROM
		Plan_BudgetZeroImportVersion_Detail det
		INNER JOIN Const_PlanCapitalOperationalTypes_sys capOp ON det.BudgetType = capOp.TypeName
		INNER JOIN Const_Scoa_Structure_ByYear(@finYear) item ON det.SCOAItemCode = item.ScoaCode
	WHERE
		det.BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND det.BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
		AND ISNULL(ProjectID, -1) NOT IN (SELECT ProjectID FROM Plan_ProjectReportExclude WHERE ISNULL(WaterProject, 0) = 1)
		AND ISNULL(CostingProject, 0) = 0

	SELECT @countProjectExisting = COUNT(DISTINCT det.ProjectID)
	FROM 
		Plan_BudgetZeroImportVersion_Detail det
	WHERE
		det.BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND det.BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
		AND ISNULL(det.ProjectID, 0) <> 0

	SELECT @countProjectNew = COUNT(DISTINCT det.ProjectName)
	FROM 
		Plan_BudgetZeroImportVersion_Detail det
	WHERE
		det.BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND det.BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
		AND ISNULL(det.ProjectID, 0) = 0

	SELECT @fileName = BudgetZeroImportVersionFileName
	FROM Plan_BudgetZeroImportVersion_File
	WHERE BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber

	SELECT @countErrorRecordIndividual = COUNT(DISTINCT detEx.BudgetZeroImportVersionDetailID)
	FROM 
		Plan_BudgetZeroImportVersion_DetailException detEx
		INNER JOIN Plan_BudgetZeroImportVersion_Detail det on detEx.BudgetZeroImportVersionDetailID = det.BudgetZeroImportVersionDetail_ID
	WHERE	
		det.BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND det.BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber

	SELECT 
		 ProjectCount = @countProjectExisting + @countProjectNew
		,BudgetTotalY1 = @budgetY1
		,BudgetTotalY2 = @budgetY2
		,BudgetTotalY3 = @budgetY3
		,ErrorRecord = CONVERT(VARCHAR, @countErrorRecordIndividual)
		,ImportFileName = @fileName
		,ImportStatus = CASE WHEN @countErrorRecordIndividual > 0 THEN 'Error' ELSE 'Success' END
		,BudgetExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID
		,BudgetImportVersionNumber = @budgetZeroImportVersionNumber

END
GO

