-- =============================================
-- Author:		Chris Moodley
-- Create date: September 2025
-- Description:	Return Zero budget import exceptions
-- =============================================
CREATE PROCEDURE [dbo].[Plan_BudgetZeroImportVersion_Exception_sp] 
	-- Add the parameters for the stored procedure here
	 @budgetZeroExportImportVersionHeaderID INT 
	,@budgetZeroImportVersionNumber INT 
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE @finYear NVARCHAR(10) 
	
	SELECT @finYear = FinYear FROM Plan_BudgetZeroExportImportVersion_Header WHERE BudgetZeroExportImportVersionHeader_ID = @budgetZeroExportImportVersionHeaderID;

	WITH cte AS (SELECT det.*, ex.ExceptionDetail FROM Plan_BudgetZeroImportVersion_Detail det LEFT JOIN Plan_BudgetZeroImportVersion_DetailException ex ON det.BudgetZeroImportVersionDetail_ID = ISNULL(ex.BudgetZeroImportVersionDetailID, 0))

	SELECT 
		 FinYear1
		,FinYear2
		,FinYear3
		,VersionID
		,IDPItem
		,ProjectID
		,ProjectCode
		,ProjectName
		,ProjectDesc
		,SingleMultiYear
		,CASE WHEN CostingProject IS NULL OR CostingProject = 0 THEN 'No' ELSE 'Yes' END CostingProject
		,PlanProjectItemID
		,BudgetType
		,SCOAProjectCode
		,SCOAProject
		,SCOAFunctionCode
		,SCOAFunction
		,MSCDepartmentCode
		,MSCDepartment
		,MSCDivisionCode
		,MSCDivision
		,MunicipalClassification
		,SCOAFundCode
		,SCOAFund
		,SCOARegionCode
		,SCOARegion
		,SCOACostingCode
		,SCOACosting
		,SCOAItemCode
		,SCOAItem
		,ItemDescription
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(CurrentBudgetFinYear1) ELSE ABS(CurrentBudgetFinYear1) END CurrentBudgetFinYear1
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(CurrentBudgetFinYear2) ELSE ABS(CurrentBudgetFinYear2) END CurrentBudgetFinYear2
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(CurrentBudgetFinYear3) ELSE ABS(CurrentBudgetFinYear3) END CurrentBudgetFinYear3
		,SplitType
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M1) ELSE ABS(M1) END M1
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M2) ELSE ABS(M2) END M2
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M3) ELSE ABS(M3) END M3
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M4) ELSE ABS(M4) END M4
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M5) ELSE ABS(M5) END M5
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M6) ELSE ABS(M6) END M6
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M7) ELSE ABS(M7) END M7
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M8) ELSE ABS(M8) END M8
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M9) ELSE ABS(M9) END M9
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M10) ELSE ABS(M10) END M10
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M11) ELSE ABS(M11) END M11
		,CASE WHEN (((det.ScoaItemCode LIKE 'IR%' OR det.ScoaItemCode LIKE 'IL%') AND TypeValue in (0,1,2)) OR CreditDebit = 'C') THEN -ABS(M12) ELSE ABS(M12) END M12
		,CreditDebit
		,GRAPClassification
		,GRAPClassificationNote
		,MainSegmentReporting
		,SubSegmentReporting
		,CASE WHEN ActiveForSCM IS NULL OR ActiveForSCM = 0 THEN 'No' ELSE 'Yes' END ActiveForSCM
		,ZeroBudgetItemReason
		,ISNULL(STUFF(( SELECT  '; ' + US.ExceptionDetail
                        FROM    cte US
                        WHERE   US.BudgetZeroImportVersionDetail_ID = det.BudgetZeroImportVersionDetail_ID
                        FOR
                        XML PATH('')
                        ), 1, 1, ''), '') AS ExceptionDetail
	FROM 
		Plan_BudgetZeroImportVersion_Detail det		
		LEFT JOIN Const_PlanCapitalOperationalTypes_sys pcot ON det.BudgetType = pcot.TypeName
	WHERE 
		BudgetZeroExportImportVersionHeaderID = @BudgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @BudgetZeroImportVersionNumber	

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetZeroImportVersion_sp]    Script Date: 2026/03/10 7:23:28 AM ******/
SET ANSI_NULLS ON
GO

