-- ========================================================================
-- Author:		Chris Moodley
-- Create date: September 2025
-- Description:	Import Zero budget items
-- 260308 by CM: 127606 - Set HistoricalProjectCode to PlanProjectItem_ID|0 for new PPIs in Plan_ProjectItem
-- [dbo].[Plan_BudgetZeroImportVersion_sp] 1, 3, 1
-- ========================================================================
CREATE PROCEDURE [dbo].[Plan_BudgetZeroImportVersion_sp] 
	-- Add the parameters for the stored procedure here
	 @budgetZeroExportImportVersionHeaderID INT
	,@budgetZeroImportVersionNumber INT
	,@userID INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
    BEGIN TRY
		BEGIN TRANSACTION Import
			DECLARE 
				@currFinYear NVARCHAR(9) ,
				@currFinYearPlus1 NVARCHAR(9) ,
				@currFinYearPlus2 NVARCHAR(9) ,
				@IDPNumLevel NVARCHAR(5) = '0',
				@errorResult NVARCHAR(MAX) = ''

			SELECT
				 @currFinYear = FinYear
				,@currFinYearPlus1 = CAST(RIGHT(FinYear, 4) AS VARCHAR(50)) + '/' + CAST((RIGHT(FinYear, 4) + 1) AS VARCHAR(50))
				,@currFinYearPlus2 = CAST((RIGHT(FinYear, 4) + 1) AS VARCHAR(50)) + '/' + CAST((RIGHT(FinYear, 4) + 2) AS VARCHAR(50))
			FROM 
				Plan_BudgetZeroExportImportVersion_Header 
			WHERE 
				BudgetZeroExportImportVersionHeader_ID = @budgetZeroExportImportVersionHeaderID

			SELECT @IDPNumLevel = IDPNumLevel
			FROM Const_IDPLevelDescription_Header
			WHERE FinancialYear = @currFinYear

			SELECT ScoaID, ScoaCode INTO #projectTable FROM Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @currFinYear
			CREATE INDEX idxProjectScoaCode ON #projectTable(ScoaCode)

			SELECT ScoaID, ScoaCode INTO #functionTable FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @currFinYear
			CREATE INDEX idxFunctionScoaCode ON #functionTable(ScoaCode)
			
			SELECT ScoaID, ScoaCode INTO #itemTable FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @currFinYear
			CREATE INDEX idxItemScoaCode ON #itemTable(ScoaCode)
			
			SELECT ScoaID, ScoaCode INTO #fundsTable FROM dbo.Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @currFinYear
			CREATE INDEX idxFundScoaCode ON #fundsTable(ScoaCode)
			
			SELECT ScoaID, ScoaCode INTO #costingTable FROM dbo.Const_SCOA_Costing_Structure_Consolidated WHERE FinYearText = @currFinYear
			CREATE INDEX idxCostingScoaCode ON #costingTable(ScoaCode)
			
			SELECT ScoaID, ScoaCode INTO #regionalTable FROM dbo.Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @currFinYear             
            CREATE INDEX idxRegionScoaCode ON #regionalTable(ScoaCode)            
               
			/* New Projects */
			/* Add data for Plan Project */
			INSERT  INTO dbo.Plan_Project
			( 
				ProjectName,
				ProjectDesc,
				ProjectManagerID,
				SupplyChainOfficialID,
				CapitalOperation,
				CostEstimate,
				ScoaProjectID,
				EstimatedStartDate,
				EstimatedEndDate,
				ProjectStatus,
				CommencementDate,
				FinYear,
				ProjectDetailDesc,
				ProjectCategoryID,
				ProjectImplementAgentID,
				Longitude,
				Latitude,
				ProgrammeManagerID,
				FinancialControllerID,
				ProjectTypeID,
				EstimatedDuration,
				ProjectDistinctionID,
				IsDeleted,
				HistoricalProjectCode,
				ProjectParentID,
				SingleMultiYear,
				CapturerID,
				DateCaptured,
				ModifierID,
				DateModified,
				ProjectCode,
				PreviousReferenceId,
				CostingProject
			)
			SELECT DISTINCT 
				ProjectName,
				ProjectDesc,
				NULL,
				NULL,
				TypeValue,
				0,
				csps.ScoaID,
				NULL,
				NULL,
				23,
				NULL,
				@currFinYear,
				NULL,
				NULL,
				NULL,
				NULL,
				NULL,
				NULL,
				NULL,
				NULL,
				NULL,
				NULL,
				NULL,
				NULL,
				NULL,
				SingleMultiYear,
				@userID,
				GETDATE(),
				NULL,
				NULL,
				ProjectCode,
				NULL,
				CostingProject
			FROM    
				Plan_BudgetZeroImportVersion_Detail p 
