				AND (ProjectID IS NULL OR ProjectID = 0) 
                       
			print 'project'	

			 /* Add data for IDP Item */
			INSERT INTO dbo.IDP_Item
			( 
				ItemDesc ,
				FinancialYear ,
				ItemParentID ,
				IDPLevelNumber ,
				ItemOrderID ,
				CapturerID ,
				DateCaptured ,
				ActProjID ,
				isProj ,
				PreviousReferenceId
			)
			SELECT DISTINCT
				pp.ProjectName ,
				p.FinYear1 ,
				( SELECT TOP 1 Item_ID FROM IDP_Item WHERE ItemDesc = p.IDPItem and FinancialYear = @currFinYear AND IDPLevelNumber = @IDPNumLevel ) ,
				50 ,
				ISNULL(( SELECT TOP 1
								ItemOrderID + 1
							FROM   IDP_Item
							WHERE  ItemParentID = ( SELECT TOP 1 Item_ID FROM IDP_Item WHERE ItemDesc = (SELECT [Value] FROM [dbo].[Split_fxn](p.IDPItem, '|') WHERE ID = 1) )
								AND IDPLevelNumber = 50
								AND FinancialYear = p.FinYear1
							ORDER BY ItemOrderID DESC
						), 0) ,
				@userID ,
				GETDATE() ,
				pp.Project_ID ,
				1 ,
				NULL
			FROM    
				Plan_BudgetZeroImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.ProjectName = p.ProjectName
			WHERE
				BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
				AND (ProjectID IS NULL OR ProjectID = 0);
                                             
