				,ScoaFunctionID
				,CapturerID
				,DateCaptured
				,ModifierID
				,DateModified
				,PreviousReferenceId
			)
			SELECT DISTINCT
				pp.Project_ID ,
				CSFS.ScoaID ,
				@userID ,
				GETDATE(),
				NULL,
				NULL,
				NULL
			FROM    
				Plan_BudgetZeroImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.ProjectName = p.ProjectName AND p.FinYear1 = pp.FinYear
				INNER JOIN #functionTable CSFS ON p.SCOAFunctionCode = csfs.ScoaCode
