			/* Add data into Plan Project Fund */
			INSERT  INTO dbo.Plan_ProjectFund
			( 						
				 ProjectID
				,ScoaFundID
				,FundAmount
				,FundReference
				,VirementId
				,AdjustmentId
				,CapturerID
				,DateCaptured
				,ModifierID
				,DateModified
				,PreviousReferenceId
			)
			SELECT DISTINCT
				pp.Project_ID ,
				CSFS.ScoaID ,
				CASE When TypeValue in (0, 1, 4) THEN SUM(ABS(p.CurrentBudgetFinYear1) + ABS(p.CurrentBudgetFinYear2) + ABS(p.CurrentBudgetFinYear3)) ELSE 0 END,
				'',
				NULL,
				NULL,
				@userID,
				GETDATE() ,
				NULL,
				NULL,
				NULL
			FROM    
				Plan_BudgetZeroImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.ProjectName = p.ProjectName AND p.FinYear1 = pp.FinYear
				INNER JOIN #fundsTable CSFS ON p.ScoaFundCode = CSFS.ScoaCode  
				INNER JOIN Const_PlanCapitalOperationalTypes_sys pCot ON p.BudgetType = pCot.TypeName
			WHERE 
				BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
				AND (p.ProjectID IS NULL OR p.ProjectID = 0)
			GROUP BY 
				pp.Project_ID ,
				CSFS.ScoaID ,
				TypeValue
                              
			print 'fund'	

			/* Add data into Plan Project Fund Yaer */
			INSERT  INTO dbo.Plan_ProjectFundYear
			( 
				 ProjectFundID
				,FinYear
				,YearFundAmount
				,VirementId
				,AdjustmentId
				,CapturerID
				,DateCaptured
				,ModifierID
				,DateModified
				,PreviousReferenceId
			)
			SELECT DISTINCT
				PF.ProjectFund_ID ,
				FinYear1 ,
				CASE When TypeValue in (0, 1, 4) THEN SUM(ABS(p.CurrentBudgetFinYear1)) ELSE 0 END,
				NULL,
				NULL,
				@userID,
				GETDATE(),
				NULL,
				NULL,
				NULL
			FROM    
				Plan_BudgetZeroImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.ProjectName = p.ProjectName  AND p.FinYear1 = pp.FinYear
				INNER JOIN Plan_ProjectFund PF ON PF.ProjectID = pp.Project_ID 
				INNER JOIN Const_PlanCapitalOperationalTypes_sys pCot ON p.BudgetType = pCot.TypeName
			WHERE 
				BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
				AND (p.ProjectID IS NULL OR p.ProjectID = 0)
			GROUP BY 
				TypeValue, 
				FinYear1,
				pf.ProjectFund_ID

			UNION ALL

			SELECT DISTINCT
				PF.ProjectFund_ID ,
				FinYear2 ,
				CASE When TypeValue in (0, 1, 4) THEN SUM(ABS(p.CurrentBudgetFinYear2)) ELSE 0 END,
				NULL,
				NULL,
				@userID,
				GETDATE(),
				NULL,
				NULL,
				NULL
			FROM    
				Plan_BudgetZeroImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.ProjectName = p.ProjectName  AND p.FinYear1 = pp.FinYear
				INNER JOIN Plan_ProjectFund PF ON PF.ProjectID = pp.Project_ID 
				INNER JOIN Const_PlanCapitalOperationalTypes_sys pCot ON p.BudgetType = pCot.TypeName
			WHERE 
				BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
				AND (p.ProjectID IS NULL OR p.ProjectID = 0)
			GROUP BY 
				TypeValue, 
				FinYear2,
				pf.ProjectFund_ID

			UNION ALL

			SELECT DISTINCT
				PF.ProjectFund_ID ,
				FinYear3 ,
				CASE When TypeValue in (0, 1, 4) THEN SUM(ABS(p.CurrentBudgetFinYear3)) ELSE 0 END,
				NULL,
				NULL,
				@userID,
				GETDATE(),
				NULL,
				NULL,
				NULL
			FROM    
				Plan_BudgetZeroImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.ProjectName = p.ProjectName  AND p.FinYear1 = pp.FinYear
				INNER JOIN Plan_ProjectFund PF ON PF.ProjectID = pp.Project_ID 
				INNER JOIN Const_PlanCapitalOperationalTypes_sys pCot ON p.BudgetType = pCot.TypeName
			WHERE 
				BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
				AND (p.ProjectID IS NULL OR p.ProjectID = 0)
			GROUP BY 
				TypeValue, 
				FinYear3,
				pf.ProjectFund_ID

			print 'fund year'	

			/* Add data into Plan Project Item */
			INSERT  INTO dbo.Const_ProjectItem
			( 
				ItemDescription ,
				[Enabled] ,
				DateCaptured ,
				CapturerID,
				DateModified,
				ModifierID,
				FinYear,
				PreviousReferenceID
			)
			SELECT DISTINCT
				p.ItemDescription ,
				1 ,
				GETDATE() ,
				@userID ,
				NULL,
				NULL,
				FinYear1,
				NULL
			FROM    
				Plan_BudgetZeroImportVersion_Detail p
				LEFT JOIN Const_ProjectItem CPI ON CPI.ItemDescription = p.ItemDescription AND CPI.FinYear = @currFinYear
			WHERE   
				CPI.ProjectItem_ID IS NULL;

			print 'project item'	

			CREATE TABLE #InsertedRowsNewProjectNewPPI (ID INT)

			INSERT  INTO dbo.Plan_ProjectItem
			( 
				 ProjectID
				,ProjectItemID
				,SCOAItemID
				,FinYear
				,ProjectFundYearID
				,SCOAFundId
				,BudgetAmount
				,BudgetAmountCurP1
				,BudgetAmountCurP2
				,SCOAFunctionId
				,SCOARegionId
				,DivisionId
				,BudgetSplitID
				,VirementId
				,HistoricalProjectCode
				,AdjustmentId
				,ModificationNumber
				,SCOACostingID
				,IsItemLocked
				,CreditDebit
				,CapturerID
				,DateCaptured
				,ModifierID
				,DateModified
				,PreviousReferenceId
				,GRAPClassification
				,GRAPClassificationNote
				,MainSegmentReporting
				,SubSegmentReporting
				,IsActiveForSCM
				,ZeroBudgetItem
				,ZeroBudgetItemReason
			)
			OUTPUT INSERTED.PlanProjectItem_ID INTO #InsertedRowsNewProjectNewPPI
			SELECT DISTINCT
				pp.Project_ID ,
				CPI.ProjectItem_ID ,
				item.ScoaID ,
				p.FinYear1 ,
				PPF.ProjectFundYear_ID ,
				fund.ScoaID ,
				SUM(ABS(ISNULL(p.CurrentBudgetFinYear1, 0))) ,
				SUM(ABS(ISNULL(p.CurrentBudgetFinYear2, 0))) ,
				SUM(ABS(ISNULL(p.CurrentBudgetFinYear3, 0))) ,
				func.ScoaID ,
				region.ScoaID,
				div.Division_ID ,
				budSplit.DivideBy_ID,
				NULL,
				'',
				NULL,
				NULL,                                                                                     
				cost.ScoaID ,
				NULL,
				p.CreditDebit,
				@userID,
				GETDATE(),
				NULL,
				NULL,
				NULL,
				GRAPClassification,
				GRAPClassificationNote,
				MainSegmentReporting,
				SubSegmentReporting,
				ActiveForSCM,
				1,
				ZeroBudgetItemReason
			FROM    
				Plan_BudgetZeroImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.ProjectName = p.ProjectName  AND p.FinYear1 = pp.FinYear
				INNER JOIN #fundsTable fund ON fund.ScoaCode = p.ScoaFundCode
				INNER JOIN (SELECT MIN(ProjectItem_ID) ProjectItem_ID, ItemDescription, FinYear FROM Const_ProjectItem WHERE FinYear = @currFinYear GROUP BY ItemDescription, FinYear) CPI ON CPI.ItemDescription = p.ItemDescription and CPI.FinYear = p.FinYear1
				INNER JOIN #itemTable item ON item.ScoaCode = p.SCOAItemCode
				INNER JOIN (SELECT MIN (ProjectFund_ID) ProjectFund_ID, ProjectID, ScoaFundID FROM Plan_ProjectFund group by ProjectID, ScoaFundID) PF ON PF.ProjectID = pp.Project_ID and PF.ScoaFundID = fund.ScoaID                                                 
				INNER JOIN (SELECT MIN(ProjectFundYear_ID) ProjectFundYear_ID, ProjectFundID, FinYear FROM dbo.Plan_ProjectFundYear WHERE FinYear = @currFinYear GROUP BY ProjectFundID, FinYear) PPF ON PPF.ProjectFundID = PF.ProjectFund_ID AND PPF.FinYear = @currFinYear
				INNER JOIN #functionTable func ON func.ScoaCode = p.SCOAFunctionCode
				INNER JOIN #regionalTable region ON region.ScoaCode = p.SCOARegionCode
				INNER JOIN #costingTable cost ON cost.ScoaCode = p.SCOACostingCode
				INNER JOIN Const_Division div ON p.MSCDivisionCode = div.DivisionCode
				INNER JOIN Const_BudgetSplitOptions budSplit ON p.SplitType = budSplit.BudgetSplitDesc
			WHERE 
				BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
				AND (p.ProjectID IS NULL OR p.ProjectID = 0)
			GROUP BY 
				pp.Project_ID ,
				CPI.ProjectItem_ID ,
				item.ScoaID ,
				p.FinYear1 ,
				PPF.ProjectFundYear_ID ,
				func.ScoaID ,
				fund.ScoaID ,
				region.ScoaID ,
				cost.ScoaID ,
				div.Division_ID ,
				budSplit.DivideBy_ID ,
				p.CreditDebit,
				GRAPClassification,
				GRAPClassificationNote,
				MainSegmentReporting,
				SubSegmentReporting,
				ActiveForSCM,
				ZeroBudgetItemReason

			--Update HistoricalProjectCode
			UPDATE ppi
			SET HistoricalProjectCode = CONVERT(VARCHAR, PlanProjectItem_ID) + '|' + ISNULL(HistoricalProjectCode, '0') 
			FROM
				#InsertedRowsNewProjectNewPPI newPPI
				inner join Plan_ProjectItem ppi ON newPPI.ID = ppi.PlanProjectItem_ID

			print 'project ppi'	

			/* Add data into Plan Project Item Month wise*/
			INSERT  INTO dbo.Plan_ProjectItemMonth
			( 
				 PlanProjectItemID
				,MonthID
				,UnitQuantity
				,UnitPrice
				,CaptureID
				,DateCaptured
				,ModifierID
				,DateModified
				,VirementId
				,AdjustmentId
				,PreviousReferenceId
			)
                                                                           
			/* Add data into Plan Project Item Month 1*/
			SELECT DISTINCT
				PPI.PlanProjectItem_ID,
				7 AS MonthID ,
				1 AS UnitQuantity ,
				SUM(ABS(ISNULL(p.M1, 0))) AS UnitPrice,
				@userID AS CaptureID ,
				GETDATE() AS DateCaptured ,
				NULL AS ModifierID ,
				NULL AS DateModified,
				NULL,
				NULL,
				NULL                                                                                                     
			FROM    
				Plan_BudgetZeroImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.ProjectName = p.ProjectName AND p.FinYear1 = pp.FinYear
				INNER JOIN #fundsTable fund ON fund.ScoaCode = p.ScoaFundCode
				INNER JOIN (SELECT MIN(ProjectItem_ID) ProjectItem_ID, ItemDescription, FinYear FROM Const_ProjectItem WHERE FinYear = @currFinYear GROUP BY ItemDescription, FinYear) CPI ON CPI.ItemDescription = p.ItemDescription and CPI.FinYear = p.FinYear1
				INNER JOIN #itemTable item ON item.Scoacode = p.SCOAItemcode
				INNER JOIN #functionTable func ON func.ScoaCode = p.SCOAFunctionCode
				INNER JOIN #regionalTable region ON region.ScoaCode = p.SCOARegionCode
				INNER JOIN #costingTable cost ON cost.ScoaCode = p.SCOACostingCode
				INNER JOIN Const_Division div ON p.MSCDivisionCode = div.DivisionCode
				INNER JOIN Plan_ProjectItem PPI ON PPI.ProjectID = pp.Project_ID
													AND PPI.ProjectItemID = CPI.ProjectItem_ID
													AND PPI.SCOAItemID = item.ScoaID
													AND PPI.FinYear = p.FinYear1
													AND PPI.SCOAFunctionId = func.ScoaID
													AND PPI.SCOAFundId = fund.ScoaID
													AND PPI.SCOARegionId = region.ScoaID
													AND PPI.SCOACostingId = cost.ScoaID
													AND PPI.DivisionID = div.Division_ID                                                                                                                                                                                                                                   
			WHERE 
				BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
				AND (p.ProjectID IS NULL OR p.ProjectID = 0)
			GROUP BY
				PPI.PlanProjectItem_ID
                                                                                                                                                                                                                                   
			UNION
			/* Add data into Plan Project Item Month 2*/
			SELECT DISTINCT
				PPI.PlanProjectItem_ID,
				8 AS MonthID ,
				1 AS UnitQuantity ,
				SUM(ABS(ISNULL(p.M2, 0))) AS UnitPrice,
				@userID AS CaptureID ,
				GETDATE() AS DateCaptured ,
				NULL AS ModifierID ,
				NULL AS DateModified,
				NULL,
				NULL,
				NULL                                                                                                   
			FROM    
				Plan_BudgetZeroImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.ProjectName = p.ProjectName AND p.FinYear1 = pp.FinYear
				INNER JOIN #fundsTable fund ON fund.ScoaCode = p.ScoaFundCode
				INNER JOIN (SELECT MIN(ProjectItem_ID) ProjectItem_ID, ItemDescription, FinYear FROM Const_ProjectItem WHERE FinYear = @currFinYear GROUP BY ItemDescription, FinYear) CPI ON CPI.ItemDescription = p.ItemDescription and CPI.FinYear = p.FinYear1
				INNER JOIN #itemTable item ON item.Scoacode = p.SCOAItemcode
				INNER JOIN #functionTable func ON func.ScoaCode = p.SCOAFunctionCode
				INNER JOIN #regionalTable region ON region.ScoaCode = p.SCOARegionCode
				INNER JOIN #costingTable cost ON cost.ScoaCode = p.SCOACostingCode
				INNER JOIN Const_Division div ON p.MSCDivisionCode = div.DivisionCode
				INNER JOIN Plan_ProjectItem PPI ON PPI.ProjectID = pp.Project_ID
													AND PPI.ProjectItemID = CPI.ProjectItem_ID
													AND PPI.SCOAItemID = item.ScoaID
													AND PPI.FinYear = p.FinYear1
													AND PPI.SCOAFunctionId = func.ScoaID
													AND PPI.SCOAFundId = fund.ScoaID
													AND PPI.SCOARegionId = region.ScoaID
													AND PPI.SCOACostingId = cost.ScoaID
													AND PPI.DivisionID = div.Division_ID                                                                                                                                                                                                                                   
			WHERE 
				BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
				AND (p.ProjectID IS NULL OR p.ProjectID = 0)  
			GROUP BY
				PPI.PlanProjectItem_ID

			UNION
			/* Add data into Plan Project Item Month 3*/
			SELECT DISTINCT		
				PPI.PlanProjectItem_ID,
				9 AS MonthID ,
				1 AS UnitQuantity ,
				SUM(ABS(ISNULL(p.M3, 0))) AS UnitPrice,
				@userID AS CaptureID ,
				GETDATE() AS DateCaptured ,
				NULL AS ModifierID ,
				NULL AS DateModified,
				NULL,
				NULL,
				NULL                                                                                                    
			FROM    
				Plan_BudgetZeroImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.ProjectName = p.ProjectName AND p.FinYear1 = pp.FinYear
				INNER JOIN #fundsTable fund ON fund.ScoaCode = p.ScoaFundCode
				INNER JOIN (SELECT MIN(ProjectItem_ID) ProjectItem_ID, ItemDescription, FinYear FROM Const_ProjectItem WHERE FinYear = @currFinYear GROUP BY ItemDescription, FinYear) CPI ON CPI.ItemDescription = p.ItemDescription and CPI.FinYear = p.FinYear1
				INNER JOIN #itemTable item ON item.Scoacode = p.SCOAItemcode
				INNER JOIN #functionTable func ON func.ScoaCode = p.SCOAFunctionCode
				INNER JOIN #regionalTable region ON region.ScoaCode = p.SCOARegionCode
				INNER JOIN #costingTable cost ON cost.ScoaCode = p.SCOACostingCode
				INNER JOIN Const_Division div ON p.MSCDivisionCode = div.DivisionCode
				INNER JOIN Plan_ProjectItem PPI ON PPI.ProjectID = pp.Project_ID
													AND PPI.ProjectItemID = CPI.ProjectItem_ID
													AND PPI.SCOAItemID = item.ScoaID
													AND PPI.FinYear = p.FinYear1
													AND PPI.SCOAFunctionId = func.ScoaID
													AND PPI.SCOAFundId = fund.ScoaID
													AND PPI.SCOARegionId = region.ScoaID
													AND PPI.SCOACostingId = cost.ScoaID
													AND PPI.DivisionID = div.Division_ID                                                                                                                                                                                                                                   
			WHERE 
				BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
				AND (p.ProjectID IS NULL OR p.ProjectID = 0)   
			GROUP BY
				PPI.PlanProjectItem_ID

			UNION
			/* Add data into Plan Project Item Month 4*/
			SELECT DISTINCT		
				PPI.PlanProjectItem_ID,
				10 AS MonthID ,
				1 AS UnitQuantity ,
				SUM(ABS(ISNULL(p.M4, 0))) AS UnitPrice,
				@userID AS CaptureID ,
				GETDATE() AS DateCaptured ,
				NULL AS ModifierID ,
				NULL AS DateModified,
				NULL,
				NULL,
				NULL                                                                                                    
			FROM    
				Plan_BudgetZeroImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.ProjectName = p.ProjectName AND p.FinYear1 = pp.FinYear
				INNER JOIN #fundsTable fund ON fund.ScoaCode = p.ScoaFundCode
				INNER JOIN (SELECT MIN(ProjectItem_ID) ProjectItem_ID, ItemDescription, FinYear FROM Const_ProjectItem WHERE FinYear = @currFinYear GROUP BY ItemDescription, FinYear) CPI ON CPI.ItemDescription = p.ItemDescription and CPI.FinYear = p.FinYear1
				INNER JOIN #itemTable item ON item.Scoacode = p.SCOAItemcode
				INNER JOIN #functionTable func ON func.ScoaCode = p.SCOAFunctionCode
