				INNER JOIN Plan_Project pp ON pp.Project_ID = p.ProjectID
				INNER JOIN #costingTable csfs ON p.SCOACostingCode = csfs.ScoaCode    
				LEFT JOIN Plan_ProjectCosting adjCost ON pp.Project_ID = adjCost.ProjectID AND csfs.ScoaID = adjCost.ScoaCostingID
			WHERE
				BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
				AND ((p.ProjectID IS NOT NULL OR p.ProjectID <> 0) AND (p.PlanProjectItemID IS NULL OR p.PlanProjectItemID = 0))
				AND adjcost.ProjectCosting_ID IS NULL;

