				cost.ScoaID ,
				div.Division_ID ,
				budSplit.DivideBy_ID ,
				p.CreditDebit,
				GRAPClassification,
				GRAPClassificationNote,
				MainSegmentReporting,
				SubSegmentReporting,
				ActiveForSCM,
				ZeroBudgetItemReason

