													AND PPI.SCOAFundId = fund.ScoaID
													AND PPI.SCOARegionId = region.ScoaID
													AND PPI.SCOACostingId = cost.ScoaID
													AND PPI.DivisionID = div.Division_ID                                                                                                                                                                                                                                   
			WHERE 
				BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
				AND ((p.ProjectID IS NOT NULL OR p.ProjectID <> 0) AND (p.PlanProjectItemID IS NULL OR p.PlanProjectItemID = 0))
                                                                                                                         
			UNION
			/* Add data into Plan Project Item Month 9*/
			SELECT DISTINCT
				PPI.PlanProjectItem_ID,
				3 AS MonthID ,
				1 AS UnitQuantity ,
				ABS(ISNULL(p.M9, 0)) as UnitPrice,
				@userID AS CaptureID ,
				GETDATE() AS DateCaptured ,
				NULL AS ModifierID ,
				NULL AS DateModified,
				NULL,
				NULL,
				NULL                                                                                                   
			FROM    
				Plan_BudgetZeroImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.Project_ID = p.ProjectID
				INNER JOIN #fundsTable fund ON fund.ScoaCode = p.ScoaFundCode
				INNER JOIN (SELECT MIN(ProjectItem_ID) ProjectItem_ID, ItemDescription, FinYear FROM Const_ProjectItem WHERE FinYear = @currFinYear GROUP BY ItemDescription, FinYear) CPI ON CPI.ItemDescription = p.ItemDescription and CPI.FinYear = p.FinYear1
				INNER JOIN #itemTable item ON item.Scoacode = p.SCOAItemcode
				INNER JOIN #functionTable func ON func.ScoaCode = p.SCOAFunctionCode
				INNER JOIN #regionalTable region ON region.ScoaCode = p.SCOARegionCode
				INNER JOIN #costingTable cost ON cost.ScoaCode = p.SCOACostingCode
				INNER JOIN Const_Division div ON p.MSCDivisionCode = div.DivisionCode
				INNER JOIN Plan_ProjectItem PPI ON PPI.ProjectID = pp.Project_ID
													AND PPI.ProjectItemID = CPI.ProjectItem_ID
													AND PPI.SCOAItemID = item.ScoaID
													AND PPI.FinYear = p.FinYear1
													AND PPI.SCOAFunctionId = func.ScoaID
													AND PPI.SCOAFundId = fund.ScoaID
													AND PPI.SCOARegionId = region.ScoaID
													AND PPI.SCOACostingId = cost.ScoaID
													AND PPI.DivisionID = div.Division_ID                                                                                                                                                                                                                                   
			WHERE 
				BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
				AND ((p.ProjectID IS NOT NULL OR p.ProjectID <> 0) AND (p.PlanProjectItemID IS NULL OR p.PlanProjectItemID = 0))                                                                                                                  
                
			UNION
			/* Add data into Plan Project Item Month 10*/
			SELECT DISTINCT
				PPI.PlanProjectItem_ID,
				4 AS MonthID ,
				1 AS UnitQuantity ,
				ABS(ISNULL(p.M10, 0)) AS UnitPrice,
				@userID AS CaptureID ,
				GETDATE() AS DateCaptured ,
				NULL AS ModifierID ,
				NULL AS DateModified,
				NULL,
				NULL,
				NULL                                                                                                    
			FROM    
				Plan_BudgetZeroImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.Project_ID = p.ProjectID
				INNER JOIN #fundsTable fund ON fund.ScoaCode = p.ScoaFundCode
				INNER JOIN (SELECT MIN(ProjectItem_ID) ProjectItem_ID, ItemDescription, FinYear FROM Const_ProjectItem WHERE FinYear = @currFinYear GROUP BY ItemDescription, FinYear) CPI ON CPI.ItemDescription = p.ItemDescription and CPI.FinYear = p.FinYear1
				INNER JOIN #itemTable item ON item.Scoacode = p.SCOAItemcode
				INNER JOIN #functionTable func ON func.ScoaCode = p.SCOAFunctionCode
				INNER JOIN #regionalTable region ON region.ScoaCode = p.SCOARegionCode
				INNER JOIN #costingTable cost ON cost.ScoaCode = p.SCOACostingCode
				INNER JOIN Const_Division div ON p.MSCDivisionCode = div.DivisionCode
				INNER JOIN Plan_ProjectItem PPI ON PPI.ProjectID = pp.Project_ID
													AND PPI.ProjectItemID = CPI.ProjectItem_ID
													AND PPI.SCOAItemID = item.ScoaID
													AND PPI.FinYear = p.FinYear1
													AND PPI.SCOAFunctionId = func.ScoaID
													AND PPI.SCOAFundId = fund.ScoaID
													AND PPI.SCOARegionId = region.ScoaID
													AND PPI.SCOACostingId = cost.ScoaID
													AND PPI.DivisionID = div.Division_ID                                                                                                                                                                                                                                   
			WHERE 
				BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
				AND ((p.ProjectID IS NOT NULL OR p.ProjectID <> 0) AND (p.PlanProjectItemID IS NULL OR p.PlanProjectItemID = 0))
                
			UNION
			/* Add data into Plan Project Item Month 11*/
			SELECT DISTINCT
				PPI.PlanProjectItem_ID,
				5 AS MonthID ,
				1 AS UnitQuantity ,
				ABS(ISNULL(p.M11, 0)) AS UnitPrice,
				@userID AS CaptureID ,
				GETDATE() AS DateCaptured ,
				NULL AS ModifierID ,
				NULL AS DateModified,
				NULL,
				NULL,
				NULL                                                                                                    
			FROM    
				Plan_BudgetZeroImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.Project_ID = p.ProjectID
				INNER JOIN #fundsTable fund ON fund.ScoaCode = p.ScoaFundCode
				INNER JOIN (SELECT MIN(ProjectItem_ID) ProjectItem_ID, ItemDescription, FinYear FROM Const_ProjectItem WHERE FinYear = @currFinYear GROUP BY ItemDescription, FinYear) CPI ON CPI.ItemDescription = p.ItemDescription and CPI.FinYear = p.FinYear1
				INNER JOIN #itemTable item ON item.Scoacode = p.SCOAItemcode
				INNER JOIN #functionTable func ON func.ScoaCode = p.SCOAFunctionCode
				INNER JOIN #regionalTable region ON region.ScoaCode = p.SCOARegionCode
				INNER JOIN #costingTable cost ON cost.ScoaCode = p.SCOACostingCode
				INNER JOIN Const_Division div ON p.MSCDivisionCode = div.DivisionCode
				INNER JOIN Plan_ProjectItem PPI ON PPI.ProjectID = pp.Project_ID
													AND PPI.ProjectItemID = CPI.ProjectItem_ID
													AND PPI.SCOAItemID = item.ScoaID
													AND PPI.FinYear = p.FinYear1
													AND PPI.SCOAFunctionId = func.ScoaID
													AND PPI.SCOAFundId = fund.ScoaID
													AND PPI.SCOARegionId = region.ScoaID
													AND PPI.SCOACostingId = cost.ScoaID
													AND PPI.DivisionID = div.Division_ID                                                                                                                                                                                                                                   
			WHERE 
				BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
				AND ((p.ProjectID IS NOT NULL OR p.ProjectID <> 0) AND (p.PlanProjectItemID IS NULL OR p.PlanProjectItemID = 0))
		
			UNION
			/* Add data into Plan Project Item Month 12*/
			SELECT DISTINCT
				PPI.PlanProjectItem_ID,
				6 AS MonthID ,
				1 AS UnitQuantity ,
				ABS(ISNULL(p.M12, 0)) AS UnitPrice,
				@userID AS CaptureID ,
				GETDATE() AS DateCaptured ,
				NULL AS ModifierID ,
				NULL AS DateModified,
				NULL,
				NULL,
				NULL                                                                                                     
			FROM    
				Plan_BudgetZeroImportVersion_Detail p
				INNER JOIN Plan_Project pp ON pp.Project_ID = p.ProjectID
				INNER JOIN #fundsTable fund ON fund.ScoaCode = p.ScoaFundCode
				INNER JOIN (SELECT MIN(ProjectItem_ID) ProjectItem_ID, ItemDescription, FinYear FROM Const_ProjectItem WHERE FinYear = @currFinYear GROUP BY ItemDescription, FinYear) CPI ON CPI.ItemDescription = p.ItemDescription and CPI.FinYear = p.FinYear1
				INNER JOIN #itemTable item ON item.Scoacode = p.SCOAItemcode
				INNER JOIN #functionTable func ON func.ScoaCode = p.SCOAFunctionCode
				INNER JOIN #regionalTable region ON region.ScoaCode = p.SCOARegionCode
				INNER JOIN #costingTable cost ON cost.ScoaCode = p.SCOACostingCode
				INNER JOIN Const_Division div ON p.MSCDivisionCode = div.DivisionCode
				INNER JOIN Plan_ProjectItem PPI ON PPI.ProjectID = pp.Project_ID
													AND PPI.ProjectItemID = CPI.ProjectItem_ID
													AND PPI.SCOAItemID = item.ScoaID
													AND PPI.FinYear = p.FinYear1
													AND PPI.SCOAFunctionId = func.ScoaID
													AND PPI.SCOAFundId = fund.ScoaID
													AND PPI.SCOARegionId = region.ScoaID
													AND PPI.SCOACostingId = cost.ScoaID
													AND PPI.DivisionID = div.Division_ID                                                                                                                                                                                                                                   
			WHERE 
				BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
				AND ((p.ProjectID IS NOT NULL OR p.ProjectID <> 0) AND (p.PlanProjectItemID IS NULL OR p.PlanProjectItemID = 0))                                                                                                      

			print 'project ppi month'	

			--Import Status
			UPDATE Plan_BudgetZeroExportImportVersion_Header
			SET StatusID = 321
			WHERE BudgetZeroExportImportVersionHeader_ID = @budgetZeroExportImportVersionHeaderID

			--Project Code
			DECLARE @projectCode INT  = (SELECT GREATEST(( SELECT MAX(ProjectCode) FROM Plan_Project ), ( SELECT MAX(ProjectCode) FROM Plan_AdjustmentProject )) + 1)

			UPDATE Plan_Project 
			SET ProjectCode  = @projectCode , @projectCode = @projectCode + 1
			WHERE ISNULL(ProjectCode, 0) = 0 AND FinYear = @currFinYear

			--Plan_ProjectReportExclude
			INSERT INTO Plan_ProjectReportExclude
			(
				ProjectID,
				DateCaptured,
				CapturerID,
				DateModified,
				ModifierID,
				WaterProject
			)
			SELECT 
				Project_ID,
				GETDATE(),
				@userID,
				NULL,
				NULL,
				0
			FROM 
				Plan_Project pp
				LEFT JOIN Plan_ProjectReportExclude ppre ON pp.Project_ID = ppre.ProjectID
			WHERE
				pp.FinYear = @currFinYear AND ISNULL(CostingProject, 0) = 1 AND ISNULL(IsDeleted, 0) <> 1 and ppre.ProjectID IS NULL

			DELETE Plan_ProjectReportExclude 
			WHERE	
				ProjectID IN (SELECT Project_ID FROM Plan_Project WHERE FinYear = @currFinYear AND ISNULL(IsDeleted, 0) <> 1 AND ISNULL(CostingProject, 0) <> 1)
				AND ISNULL(WaterProject, 0) <> 1

			-- funding sources
			DECLARE @FundSourceHeaderID INT = 0;
			DECLARE @StartFinYear INT = 0;
			DECLARE @CurrFinYear1 VARCHAR(50), @FinYear VARCHAR(50);
			SELECT @FinYear = @currFinYear

			WHILE ( @StartFinYear <= 2 )
			BEGIN                                                            
                                                            
				SELECT  
					@CurrFinYear1 = 
						CASE WHEN @StartFinYear = 0 THEN @currFinYear
							 WHEN @StartFinYear = 1 THEN @currFinYearPlus1
							 WHEN @StartFinYear = 2 THEN @currFinYearPlus2
							 ELSE @currFinYear
						END;

				SELECT TOP 1
						@FundSourceHeaderID = FundingSourceBudgetHeader_ID
				FROM    Plan_FundingSourceBudget_Header
				WHERE   FinancialYear = @CurrFinYear1;

				IF @FundSourceHeaderID = 0
				BEGIN
					INSERT INTO Plan_FundingSourceBudget_Header
					SELECT @CurrFinYear1, 1, GETDATE() , @userID , NULL, NULL, NULL 

					SELECT TOP 1 @FundSourceHeaderID = FundingSourceBudgetHeader_ID
					FROM    Plan_FundingSourceBudget_Header
					WHERE   FinancialYear = @CurrFinYear1;
				 END;
                                           
		------------------------------------------------------------------------------
		-- Create Budget Detail for Budget Amount for Fund Id not found 
		------------------------------------------------------------------------------
				INSERT  INTO dbo.Plan_FundingSourceBudget_Detail
						( FundingSourceBudgetHeaderID ,
							FundingSourceID ,
							ScoaID ,
							FundingSourceBudget ,
							DateCaptured ,
							CapturerID ,
							DateModified ,
							ModifierID,
							isHidden,
							UploadedDocument,
							PreviousReferenceId
						)
						SELECT  @FundSourceHeaderID ,
								NULL ,
								F.ScoaID AS SCOAFundID ,
								( CASE WHEN @StartFinYear = 0
										THEN SUM(ABS(ISNULL(CurrentBudgetFinYear1, 0)))
										WHEN @StartFinYear = 1
										THEN SUM(ABS(ISNULL(R.CurrentBudgetFinYear2, 0)))
										WHEN @StartFinYear = 2
										THEN SUM(ABS(ISNULL(R.CurrentBudgetFinYear3, 0)))
									END ) AS NwAllocAmount ,
								GETDATE() ,
								@userID ,
								NULL,
								NULL,
								0,
								NULL,
								NULL
						FROM    Plan_BudgetZeroImportVersion_Detail R
								INNER JOIN #fundsTable F ON R.ScoaFundCode = F.ScoaCode
								INNER JOIN Const_PlanCapitalOperationalTypes_sys cPot ON R.BudgetType = cPot.TypeName
						WHERE   ISNULL(dbo.Planing_GetFundAvailableAmount(F.ScoaID,
														@CurrFinYear1),
										0) = 0
								AND TypeValue  in (0, 1, 4)
								AND BudgetZeroExportImportVersionHeaderID = @budgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @budgetZeroImportVersionNumber
						GROUP BY F.ScoaID;

				SET @StartFinYear = @StartFinYear + 1;
			END;
                                           
		COMMIT TRANSACTION Import

	END TRY
	BEGIN CATCH
		ROLLBACK TRANSACTION Import
        SET @errorResult = ERROR_MESSAGE();

        INSERT INTO Sys_ErrorLog
        (
            moduleName,
            pageName,
            procedureName,
            errorMessage,
            errorType,
            detailedErrorMessage,
            errorDate,
            userName
        )
        VALUES
        ('Planning', 'SQL Server', 'Plan_BudgetZeroImportVersion_sp', ERROR_MESSAGE(), 'SQL', ERROR_MESSAGE(), GETDATE(), 'SQL');

		RAISERROR(@errorResult, 16, 1);

	END CATCH
 
	SELECT @errorResult AS ErrorResult

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetZeroInitiateProject_sp]    Script Date: 2026/03/10 7:23:28 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Chris Moodley
-- Create date: September 2025
-- Description:	Initiate Zero Budget Projects
-- =============================================
CREATE PROCEDURE [dbo].[Plan_BudgetZeroInitiateProject_sp]
	-- Add the parameters for the stored procedure here
	@FinYear VARCHAR(10),
	@UserID INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE 
		@RowProjectCount INT,
		@RowProjectItemCount INT,
		@ProjectID INT,
		@PlanProjectItemID INT,
		@CapitalOperation INT,
		@ProcessingMonth INT,
		@BudgetAmount DECIMAL(18,2),
		@BudgetAmountMulti DECIMAL(18,2),
		@ErrorResult NVARCHAR(MAX) = ''

	SELECT ScoaID, ScoaShortDesc, ScoaCode, VatIndicatorID, VoteTypeID, IsControlVote, BreakDownAllowed, CapitalTimePeriodID, ScoaParentID INTO #Const_SCOA_Structure FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @FinYear

	SELECT @ProcessingMonth = (SELECT CONVERT(INT, KeyValue) FROM AAAA_ConfigSettings WHERE KeyName = 'ActiveProcessingMonth')

	CREATE TABLE #Project
	(
		CountRow INT IDENTITY(1,1) NOT NULL,
		ProjectID INT,
		CapitalOperation INT
	)

	INSERT INTO #Project
	SELECT TOP 100 Project_ID, CapitalOperation FROM Plan_Project(NOLOCK) WHERE ProjectStatus = 23 AND FinYear = @FinYear  AND ISNULL(IsDeleted, 0) <> 1 

	SET @RowProjectCount = 1

	WHILE @RowProjectCount <= (SELECT MAX(CountRow) FROM #Project)
	BEGIN

		BEGIN TRY

			BEGIN TRANSACTION 

				SELECT @ProjectID = ProjectID, @CapitalOperation = CapitalOperation FROM #Project WHERE CountRow = @RowProjectCount

				PRINT 'ProjectID = ' + CONVERT(VARCHAR, @ProjectID)

				--Initialise
				UPDATE Plan_Project
				SET ProjectStatus = 24, ModifierID = @UserID, DateModified = GETDATE()
				WHERE Project_ID = @ProjectID
	
				CREATE TABLE #PlanProjectItem
				(
					CountRowItem INT IDENTITY(1,1) NOT NULL,
					ProjectID INT,
					PlanProjectItemID INT,
					BudgetAmount DECIMAL(18,2),
					BudgetAmountCurP1 DECIMAL(18, 2),
					BudgetAmountCurP2 DECIMAL(18, 2)
				)

				INSERT INTO #PlanProjectItem
				SELECT ProjectID, PlanProjectItem_ID, BudgetAmount, BudgetAmountCurP1, BudgetAmountCurP2 FROM Plan_ProjectItem (NOLOCK) WHERE ProjectID = @ProjectID

				SET @RowProjectItemCount = 1

				WHILE @RowProjectItemCount <= (SELECT MAX(CountRowItem) FROM #PlanProjectItem)
				BEGIN

					SELECT @PlanProjectItemID = PlanProjectItemID, @BudgetAmount = BudgetAmount, @BudgetAmountMulti = BudgetAmountCurP1 + BudgetAmountCurP2 FROM #PlanProjectItem WHERE CountRowItem = @RowProjectItemCount

					--BudgetRegister
					IF NOT EXISTS (SELECT 1 FROM Plan_BudgetRegister WHERE PlanProjectItemID = @PlanProjectItemID AND FinYear = @FinYear AND BudgetTransactionTypeID = 1)
					BEGIN
						INSERT INTO Plan_BudgetRegister
						SELECT @PlanProjectItemID, 1, 10, @PlanProjectItemID, 'Plan_ProjectItem', @BudgetAmount, @BudgetAmount, @UserID, GETDATE(), NULL, NULL, @FinYear
					END

					--BudgetConsumption
					IF NOT EXISTS (SELECT 1 FROM Plan_BudgetConsumption WHERE PlanProjectItemID = @PlanProjectItemID AND FinYear = @FinYear AND BudgetTransactionTypeID = 1)
					BEGIN
						INSERT INTO Plan_BudgetConsumption
						SELECT
							@FinYear,--FinYear
							@PlanProjectItemID,--PlanProjectItemID
							1,--BudgetTransactionTypeID
							10,--ModuleID
							@PlanProjectItemID,--PK_TransactionID
							'Plan_ProjectItem',--TransactionTableName
							@BudgetAmount,--ConsumingTransactionAmount
							@BudgetAmountMulti,--ConsumingTransactionAmountMultiyear
							@BudgetAmount,--AdjustedTansactionAmount
							@BudgetAmount,--AvailableBudget
							@BudgetAmountMulti,--AvailableBudgetMultiyear
							@ProcessingMonth,--ProcessingMonth
							200,--BudgetConsumptionProcessID
							@BudgetAmount,--OriginalBudgetToDate
							0,--AdjustedBudgetToDate
							0,--CapturedExpenditureToDate
							0,--CapturedExpenditureToDateMultiyear
							0,--ReserveToDate
							0,--ReserveToDateMultiyear
							0,--CommitToDate
							0,--ActualToDate
							0,--CurrentlyConsumedAmount
							NULL,--CurrentlyConsumedAmountMultiYear
							'Plan_ProjectItem_' + CONVERT(VARCHAR, @PlanProjectItemID),--InitialLine
							@UserID,--CapturerID
							GETDATE(),--DateCaptured
							NULL,--ModifierID
							NULL--DateModified 		
					END

					SET @RowProjectItemCount = @RowProjectItemCount + 1
				END

				DROP TABLE #PlanProjectItem 

				IF (@CapitalOperation IN (0, 1, 3))
				BEGIN
					--EXEC Plan_AutoCreateProcurementByProject_sp @ProjectID, @FinYear	
					--[Plan_AutoCreateProcurementByProject_sp]

							  CREATE TABLE #Temp
								(
								  PlanProjectItemID INT ,
								  ItemDescription NVARCHAR(500) ,
								  EstimatedCost DECIMAL(16, 2) ,
								  SCOAFunctionID INT ,
								  SCOAItemID INT ,
								  SCOARegionID INT ,
								  SCOACostingID INT ,
								  ScoaProjectID INT ,
								  Quantity DECIMAL(16, 2)
								);


							INSERT  INTO #Temp
									SELECT  i.PlanProjectItem_ID ,
											ISNULL(c.ItemDescription, css.ScoaShortDesc) AS ItemDescription ,
										  --  p.ProjectDesc AS ItemDescription ,
											ISNULL(i.BudgetAmount,0) AS [EstimatedCost] ,
											i.SCOAFunctionId ,
											i.SCOAItemID ,
											i.SCOARegionId ,
											i.SCOACostingID ,
											p.ScoaProjectID ,
											1 AS Quantity
									FROM    Plan_Project p
											INNER JOIN [Plan_ProjectItem] i ON p.Project_ID = i.ProjectID
											INNER JOIN #Const_SCOA_Structure css ON css.ScoaID = i.SCOAItemID
											LEFT OUTER JOIN [Const_ProjectItem] c ON i.ProjectItemID = c.ProjectItem_ID
									WHERE   p.Project_ID = @ProjectID
											AND i.FinYear = @FinYear AND css.ScoaCode not LIKE 'IR%'
											AND PlanProjectItem_ID NOT IN (
											SELECT  d.PlanProjectItemID
											FROM    SCM_ProcurementPlanNew pp
													INNER JOIN SCM_ProcurementPlanDetails d ON pp.ProcurementPlan_ID = d.ProcurementPlanID
											WHERE   pp.PlanProjectID = @ProjectID
													AND pp.FinYear = @FinYear )
											----AND ISNULL(i.BudgetAmount,0) > 0;

							DECLARE @PlanProjectItemIDPP INT ,
								@ItemDescription NVARCHAR(500) ,
								@EstimatedCost DECIMAL(16, 2) ,
								@SCOAFunctionID INT ,
								@SCOAItemID INT ,
								@SCOARegionID INT ,
								@SCOACostingID INT ,
								@ScoaProjectID INT ,
								@Quantity DECIMAL(16, 2);

							DECLARE @ProcurementPlanID INT;
							DECLARE @ProcurementPlanDetailID INT;

							WHILE EXISTS ( SELECT   *
										   FROM     #Temp )
								BEGIN

									SELECT TOP 1
											@PlanProjectItemIDPP = PlanProjectItemID ,
											@ItemDescription = ItemDescription ,
											@EstimatedCost = EstimatedCost ,
											@SCOAFunctionID = SCOAFunctionID ,
											@SCOAItemID = SCOAItemID ,
											@SCOARegionID = SCOARegionID ,
											@SCOACostingID = SCOACostingID ,
											@ScoaProjectID = ScoaProjectID ,
											@Quantity = Quantity
									FROM    #Temp
									ORDER BY PlanProjectItemID ASC;

									INSERT  SCM_ProcurementPlanNew
											( [PlanProjectID] ,
											  [ProjectID] ,
											  [ProcurmentStatemnet] ,
											  [ProcurementType] ,
											  [ProcessCriteria] ,
											  [MunicClassificationID] --(=DepartmentID)
											  ,
											  [ServiceProvider] ,
											  [RequestedBy] ,
											  [ApprovalBy] ,
											  [SupervisorID] ,
											  [StatusID] ,
											  [DateCaptured] ,
											  [CapturerID] ,
											  [FinYear]
											)
											SELECT DISTINCT
													p.Project_ID ,
													p.ScoaProjectID ,
													  p.ProjectDesc AS ProcurmentStatemnet ,
												  --  ISNULL(c.ItemDescription, css.ScoaShortDesc) AS ProcurmentStatemnet ,
													p.CapitalOperation ,
													'N/A' ,
													cd.DepartmentID ,
													'N/A' ,
													NULL ,
													NULL ,
													NULL ,
													2 ,
													p.DateCaptured ,
													p.CapturerID ,
													p.FinYear
											FROM    Plan_Project p
													INNER JOIN Plan_ProjectItem ppi ON ppi.ProjectID = p.Project_ID
													INNER JOIN Const_Division cd ON cd.Division_ID = ppi.DivisionId
													INNER JOIN #Const_SCOA_Structure css ON css.ScoaID = ppi.SCOAItemID
													LEFT OUTER JOIN [Const_ProjectItem] c ON ppi.ProjectItemID = c.ProjectItem_ID
											WHERE   p.Project_ID = @ProjectID AND css.ScoaCode not LIKE 'IR%'
													AND p.FinYear = @FinYear;
									SELECT  @ProcurementPlanID = SCOPE_IDENTITY(); 
					--	-- by the end of this stored proc all procurement steps would be done.

									INSERT  INTO Sys_WorkFlowSectionAudit
											SELECT  @ProcurementPlanID ,
													23 ,
													'ProcPlan' ,
													pp.CapturerID ,
													pp.DateCaptured ,
													1
											FROM    Plan_Project pp
											WHERE   pp.Project_ID = @ProjectID
													AND pp.FinYear = @FinYear;

									INSERT  INTO Sys_WorkFlowSectionAudit
											SELECT  @ProcurementPlanID ,
													23 ,
													'ProcTeam' ,
													pp.CapturerID ,
													pp.DateCaptured ,
													1
											FROM    Plan_Project pp
											WHERE   pp.Project_ID = @ProjectID
													AND pp.FinYear = @FinYear;

									INSERT  INTO Sys_WorkFlowSectionAudit
											SELECT  @ProcurementPlanID ,
													23 ,
													'ProcDetail' ,
													pp.CapturerID ,
													pp.DateCaptured ,
													1
											FROM    Plan_Project pp
											WHERE   pp.Project_ID = @ProjectID
													AND pp.FinYear = @FinYear;

									INSERT  INTO SCM_ProcurementPlanDetails
											( [ProcurementPlanID] ,
											  [Description] ,
											  [EstimatedCost] ,
											  [SCOAFunctionID] ,
											  [SCOAItemID] ,
											  [SCOARegionID] ,
											  [SCOACostingID] ,
											  [SCOAProjectID] ,
											  [PlanProjectItemID] ,
											  [Quantity]
											)
											SELECT  @ProcurementPlanID ,
													@ItemDescription ,
													@EstimatedCost ,
													@SCOAFunctionID ,
													@SCOAItemID ,
													@SCOARegionID ,
													@SCOACostingID ,
													@ScoaProjectID ,
													@PlanProjectItemIDPP ,
													@Quantity;
									SELECT  @ProcurementPlanDetailID = SCOPE_IDENTITY(); 
	 
									INSERT  INTO SCM_ProcurementPlanDetailsFund
											( [ProcurementPlanID] ,
											  [ProcurementPlanDetailID] ,
											  [SCOAFundID] ,
											  [PercentageValue]
											)
											SELECT  @ProcurementPlanID ,
													@ProcurementPlanDetailID ,
													f.ScoaFundID ,
													100
											FROM    Plan_ProjectItem i
													INNER JOIN Plan_ProjectFundYear fy ON i.ProjectFundYearID = fy.ProjectFundYear_ID
													INNER JOIN Plan_ProjectFund f ON fy.ProjectFundID = f.ProjectFund_ID
													INNER JOIN #Const_SCOA_Structure css ON css.ScoaID = i.SCOAItemID
											WHERE   f.ProjectID = @ProjectID AND css.ScoaCode not LIKE 'IR%'
													AND fy.FinYear = @FinYear
													AND i.PlanProjectItem_ID = @PlanProjectItemIDPP;

									DELETE  #Temp
									WHERE   PlanProjectItemID = @PlanProjectItemIDPP;
								END;

							DROP TABLE #Temp;			
				END

				--EXEC Plan_AutoCreateActivationVotesByProject_sp @ProjectID, @FinYear
				--[Plan_AutoCreateActivationVotesByProject_sp] 


						CREATE TABLE #tempVote
							(
							  --PlanProjectItemID INT NULL,
							  SCOAItemID INT NULL,
							  SCOAItemCode NVARCHAR(500) NULL,
							  SCOAItemDescription NVARCHAR(500) NULL,
							  VoteStatusId INT NULL,
							  FinYear VARCHAR(10) NULL,
							  VatIndicatorID INT NULL,
							  VoteTypeID INT NULL,
							  ControlVote BIT NULL,
							  IsBrokenDown	BIT NULL,
							  CapitalTimePeriodID INT NULL,
							  Parent_Vote_ID INT NULL
							);


						INSERT INTO #tempVote
						SELECT DISTINCT --i.PlanProjectItem_ID ,
							i.SCOAItemID ,
							css.ScoaCode,
							css.ScoaShortDesc ,
							1, 
							i.FinYear,
							CASE WHEN ISNULL(css.VatIndicatorID, 0) = 0 THEN 1 ELSE css.VatIndicatorID END,
							CASE WHEN ISNULL(css.VoteTypeID, 0) = 0 THEN 2 ELSE css.VoteTypeID END,
							css.IsControlVote,
							CASE WHEN css.BreakDownAllowed = 'Yes' THEN 1 ELSE 0 END AS BreakDownAllowed ,
							CASE WHEN ISNULL(css.CapitalTimePeriodID, 0) = 0 THEN 3 ELSE css.CapitalTimePeriodID END,
							css.ScoaParentID
						FROM	dbo.Plan_Project pp INNER JOIN
								dbo.[Plan_ProjectItem] i ON i.ProjectID = pp.Project_ID
								INNER JOIN #Const_SCOA_Structure css ON css.ScoaID = i.SCOAItemID
						WHERE   pp.Project_ID = @ProjectID
								AND i.FinYear = @FinYear
								AND i.SCOAItemID NOT IN ((SELECT  lv.SCOAItemID FROM dbo.Led_Vote AS lv WHERE lv.FinYear = @FinYear));


						IF EXISTS (SELECT 1 FROM #tempVote)
						BEGIN

				--Insert into LED_VOTE
						INSERT INTO dbo.Led_Vote
							( 
								Vote ,
								VoteDesc ,
								VoteStatusID ,
								FinYear ,
								CapturerID ,
								DateCaptured ,
								VatIndicatorID ,
								VoteTypeID ,
								ControlVote ,
								SCOAItemID ,
								SCOAItemCode ,
								IsBrokenDown ,
								OldVoteNumber ,
								Vote1 ,
								OldFms56VoteNumber ,
								CapitalTimePeriodID ,
								Parent_Vote_ID
							)
						SELECT DISTINCT 
							SCOAItemCode, 
							SCOAItemDescription , 
							VoteStatusId , 
							FinYear , 
							1 , 
							GETDATE() , 
							VatIndicatorID , 
							VoteTypeID , 
							ISNULL(ControlVote, 0) , 
							SCOAItemID , 
							SCOAItemCode , 
							IsBrokenDown , 
							NULL , 
							SCOAItemCode , 
							NULL , 
							CapitalTimePeriodID , 
							NULL  
						 FROM #tempVote

						--Insert into Led_VoteSection
						INSERT INTO dbo.Led_VoteSection
							( VoteID, VoteSectionID )
						SELECT T.Vote_ID,T1.VoteSection_ID 
						FROM 
							(SELECT lv.Vote_ID 
							 FROM dbo.Led_Vote lv INNER JOIN  #tempVote T ON lv.SCOAItemID = T.SCOAItemID) T
							 CROSS APPLY	dbo.Const_VoteSection_Sys T1
							EXCEPT (SELECT VoteID, VoteSectionID FROM dbo.Led_VoteSection)		

						--Insert into Led_Vote_OpeningBalance
						INSERT INTO dbo.Led_Vote_OpeningBalance
							( VoteID ,
							  FinYear ,
							  OpeningBalanceAmt ,
							  CapturerID ,
							  DateCaptured 
							)
						SELECT lv.Vote_ID, lv.FinYear,0.00,1,GETDATE() 
						FROM dbo.Led_Vote lv INNER JOIN  #tempVote T ON lv.SCOAItemID = T.SCOAItemID
						WHERE lv.Vote_ID NOT IN (SELECT VoteID FROM Led_Vote_OpeningBalance WHERE FinYear = @FinYear) AND lv.FinYear = @FinYear

					END
       
					DROP TABLE #tempVote;


					--Led_AutoCreateGLAndPositionStatmentByProject_sp
					INSERT INTO dbo.Led_Project
						( FinYear ,
						  SCOAItemID ,
						  SCOAFundID ,
						  SCOARegionID ,
						  SCOAFunctionID ,
						  SCOACostingID ,
						  DivisionID ,
						  IsActive ,
						  CapturerID ,
						  DateCaptured ,
						  ModifierID ,
						  DateModified ,
						  IsDeleted ,
						  IsImported ,
						  PositionClassificationID ,
						  SCOAProjectID,
						  Plan_ProjectID
						)
				SELECT DISTINCT
						@FinYear AS FinYear , -- FinYear - nvarchar(9)
						MissingPositionStatemnt.SCOAItemID AS SCOAItemID , -- SCOAItemID - int
						MissingPositionStatemnt.SCOAFundID AS SCOAFundID , -- SCOAFundID - int
						MissingPositionStatemnt.SCOARegionID AS SCOARegionID , -- SCOARegionID - int
						MissingPositionStatemnt.SCOAFunctionID AS SCOAFunctionID , -- SCOAFunctionID - int
						MissingPositionStatemnt.SCOACostingID AS SCOACostingID , -- SCOACostingID - int
						MissingPositionStatemnt.DivisionID AS DivisionID , -- DivisionID - int
						1 AS IsActive , -- IsActive - bit
						1 AS CapturerID , -- CapturerID - int
						GETDATE() AS DateCaptured , -- DateCaptured - datetime
						NULL AS ModifierID , -- ModifierID - int
						NULL AS DateModified , -- DateModified - datetime
						0 AS IsDeleted , -- IsDeleted - bit
						0 AS IsImported , -- IsImported - bit
						MissingPositionStatemnt.PositionClassificationID AS PositionClassificationID , -- PositionClassificationID - int
						MissingPositionStatemnt.SCOAProjectID AS SCOAProjectID, -- SCOAProjectID - int
						MissingPositionStatemnt.Plan_ProjectID
				FROM    ( SELECT    PPI.SCOAItemID AS SCOAItemID , -- SCOAItemID - int
									PPI.SCOAFundId AS SCOAFundID , -- SCOAFundID - int
									PPI.SCOARegionId AS SCOARegionID , -- SCOARegionID - int
									PPI.SCOAFunctionId AS SCOAFunctionID , -- SCOAFunctionID - int
									PPI.SCOACostingID AS SCOACostingID , -- SCOACostingID - int
									PPI.DivisionId AS DivisionID , -- DivisionID - int
									CSSPositionClassification.ScoaID AS PositionClassificationID , -- PositionClassificationID - int
									PP.ScoaProjectID AS SCOAProjectID, -- SCOAProjectID - int
									PP.Project_ID AS Plan_ProjectID
						  FROM      Plan_Project AS PP
									INNER JOIN dbo.Plan_ProjectItem AS PPI ON PPI.ProjectID = PP.Project_ID
									INNER JOIN Led_Vote AS LV ON LV.SCOAItemID = PPI.SCOAItemID AND LV.FinYear = PPI.FinYear
									INNER JOIN #Const_Scoa_Structure AS CSS ON CSS.ScoaID = PPI.SCOAItemID
									INNER JOIN Led_ProjectItem AS LPI ON SUBSTRING(LPI.ScoaCode,
																			  1, 2) = SUBSTRING(CSS.ScoaCode,
																			  1, 2)
									INNER JOIN #Const_Scoa_Structure AS CSSPositionClassification ON LPI.ScoaCode = CSSPositionClassification.ScoaCode
									INNER JOIN Const_VoteType AS CVT ON CVT.VoteType_ID = LV.VoteTypeID
						  WHERE     PP.FinYear = @FinYear
									AND PPI.FinYear = @FinYear
									AND PP.ProjectStatus = 24
									AND ( PPI.ProjectID = @ProjectID
										  OR @ProjectID = 0
										)
									AND ISNULL(PP.IsDeleted, 0) = 0
									AND CVT.VoteType = 'Balance Sheet'
									--AND (ISNULL(PPI.BudgetAmount,0) + ISNULL(PPI.BudgetAmountCurP1,0) + ISNULL(PPI.BudgetAmountCurP2,0) ) <> 0
						  EXCEPT
						  SELECT    SCOAItemID ,
									SCOAFundID ,
									SCOARegionID ,
									SCOAFunctionID ,
									SCOACostingID ,
									DivisionID ,
									PositionClassificationID ,
									SCOAProjectID,
									Plan_ProjectID
						  FROM      Led_Project
						  WHERE     FinYear = @FinYear
									AND IsActive = 1
									AND IsDeleted = 0
						) AS MissingPositionStatemnt;


				SET @RowProjectCount = @RowProjectCount + 1

			COMMIT TRANSACTION 	

		END TRY
		BEGIN CATCH
	
			SET @ErrorResult = ERROR_MESSAGE()
			RAISERROR(@ErrorResult, 16, 1)
			ROLLBACK TRANSACTION 

		END CATCH
	END

	DROP TABLE #Project
	DROP TABLE #Const_Scoa_Structure

	SELECT @ErrorResult AS ErrorResult

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetZeroItemReport_sp]    Script Date: 2026/03/10 7:23:28 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- ====================================================================================
-- Author:		Chris Moodley
-- Create date: September 2025
-- Description:	Zero Budget Item Report
-- [dbo].[Plan_BudgetZeroItemReport_sp] '2025/2026'
-- ====================================================================================
CREATE PROCEDURE [dbo].[Plan_BudgetZeroItemReport_sp] 
	-- Add the parameters for the stored procedure here
	@finYear NVARCHAR(10)
AS
BEGIN

	SET NOCOUNT ON;

	WITH cteIDP AS 
		(
			SELECT pap.Project_ID, ItemDesc 
			FROM Plan_Project pap 
					LEFT JOIN Plan_ProjectIDP pidp ON pap.Project_ID = pidp.ProjectID 
					LEFT JOIN IDP_Item idp ON pidp.ParentIDPItemID = idp.Item_ID
		)

	SELECT DISTINCT
		 pp.Project_ID
		,ppi.PlanProjectItem_ID AS PlanProjectItemID
		,STUFF(( SELECT  '|' + idp.ItemDesc
					FROM    cteIDP idp
					WHERE   idp.Project_ID = pp.Project_ID
					FOR XML PATH (''), TYPE).value('.','varchar(max)'), 1, 1, '') AS IDPDescription
		,ppi.AdjustmentId AS PlanAdjustmentProjectItemID
		,ISNULL(ppi.HistoricalProjectCode,'') as HistoricalProjectCode	
		,pp.ProjectName
		, REPLACE(REPLACE(REPLACE(pp.ProjectDesc, CHAR(10), ' '),
									CHAR(13), ' '), CHAR(09), ' ') AS ProjectDesc
		,pp.ProjectManagerID
		,pp.SupplyChainOfficialID
		,pp.CapitalOperation AS CapitalOperation 
		,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
							OR ppi.CreditDebit = 'C')
			THEN -ppi.BudgetAmount
			ELSE ppi.BudgetAmount
			END 
		 )  AS CostEstimate 
		,project.ScoaCode AS ScoaProjectLongCode
		,project.ScoaDesc AS ScoaProjectDesc
		,project.NTScoaID AS ScoaProjectGUID
		,pp.EstimatedStartDate
		,pp.EstimatedEndDate
		,pp.ProjectStatus 
		,pp.CommencementDate
		,pp.FinYear
		,cd.Division_ID
		,dep.DepartmentCode
		,dep.DepartmentDesc 
		,cd.DivisionCode 
		,cd.DivisionDesc
		,func.ScoaCode AS SCOAFunctionLongCode
		,func.ScoaDesc AS SCOAFunctionDesc
		,func.NTScoaID AS SCOAFunctionGUID
		,region.ScoaCode AS SCOARegionLongCode
		,region.ScoaDesc AS SCOARegionDesc
		,region.NTScoaID AS SCOARegionGUID
		,costing.ScoaCode AS SCOACostingLongCode
		,costing.SCOADesc AS SCOACostingDesc
		,costing.NTScoaID AS SCOACostingGUID
		,pp.ProjectTypeID 
		,COALESCE(cpi.ItemDescription, css.ScoaDesc) AS ItemDescription
		,css.ScoaDesc AS SCOAItemDesc
	    ,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](css.ScoaDesc, ':') WHERE ID = 1),'')  AS 'SCOAItemDescLevel1'
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](css.ScoaDesc, ':') WHERE ID = 2),'')  AS 'SCOAItemDescLevel2'
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](css.ScoaDesc, ':') WHERE ID = 3),'')  AS 'SCOAItemDescLevel3'
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](css.ScoaDesc, ':') WHERE ID = 4),'')  AS 'SCOAItemDescLevel4'
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](css.ScoaDesc, ':') WHERE ID = 5),'')  AS 'SCOAItemDescLevel5'
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](css.ScoaDesc, ':') WHERE ID = 6),'')  AS 'SCOAItemDescLevel6'
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](css.ScoaDesc, ':') WHERE ID = 7),'')  AS 'SCOAItemDescLevel7'
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](css.ScoaDesc, ':') WHERE ID = 8),'')  AS 'SCOAItemDescLevel8'
	    ,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](css.ScoaDesc, ':') WHERE ID = 9),'')  AS 'SCOAItemDescLevel9'
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](css.ScoaDesc, ':') WHERE ID = 10),'') AS 'SCOAItemDescLevel10'
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](css.ScoaDesc, ':') WHERE ID = 11),'') AS 'SCOAItemDescLevel11'
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](css.ScoaDesc, ':') WHERE ID = 12),'') AS 'SCOAItemDescLevel12'
		,css.NTScoaID AS SCOAItemGUID 
		,css.ScoaCode AS SCOAItemLongCode
		, SUBSTRING(css.SCOACode,1,2) AS Prefix
		,fund.ScoaDesc AS SCOAFundDesc
		,fund.NTScoaID AS SCOAFundGUID
		,fund.ScoaCode AS ScoaFundLongCode
		,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
							OR ppi.CreditDebit = 'C')
																	THEN -ppim7.UnitPrice
																	ELSE ppim7.UnitPrice
																	END ) AS Month1Budget
		,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
							OR ppi.CreditDebit = 'C')
																	THEN -ppim8.UnitPrice
																	ELSE ppim8.UnitPrice
																	END ) AS Month2Budget
		,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
							OR ppi.CreditDebit = 'C')
																	THEN -ppim9.UnitPrice
																	ELSE ppim9.UnitPrice
																	END ) AS Month3Budget
		,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
							OR ppi.CreditDebit = 'C')
																	THEN -ppim10.UnitPrice
																	ELSE ppim10.UnitPrice
																	END ) AS Month4Budget
		,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
							OR ppi.CreditDebit = 'C')
																	THEN -ppim11.UnitPrice
																	ELSE ppim11.UnitPrice
																	END ) AS Month5Budget
		,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
							OR ppi.CreditDebit = 'C')
																	THEN -ppim12.UnitPrice
																	ELSE ppim12.UnitPrice
																	END ) AS Month6Budget
		,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
							OR ppi.CreditDebit = 'C')
																	THEN -ppim1.UnitPrice
																	ELSE ppim1.UnitPrice
																	END ) AS Month7Budget
		,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
							OR ppi.CreditDebit = 'C')
																	THEN -ppim2.UnitPrice
																	ELSE ppim2.UnitPrice
																	END ) AS Month8Budget
		,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
							OR ppi.CreditDebit = 'C')
																	THEN -ppim3.UnitPrice
																	ELSE ppim3.UnitPrice
																	END ) AS Month9Budget
		,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
							OR ppi.CreditDebit = 'C')
																	THEN -ppim4.UnitPrice
																	ELSE ppim4.UnitPrice
																	END ) AS Month10Budget
		,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
							OR ppi.CreditDebit = 'C')
																	THEN -ppim5.UnitPrice
																	ELSE ppim5.UnitPrice
																	END ) AS Month11Budget
		,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
							OR ppi.CreditDebit = 'C')
																	THEN -ppim6.UnitPrice
																	ELSE ppim6.UnitPrice
																	END ) AS Month12Budget
		,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
							OR ppi.CreditDebit = 'C')
																	THEN -ppi.BudgetAmountCurP1
																	ELSE ppi.BudgetAmountCurP1
																	END ) AS ReqCurrentYearP1Amt 
		,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
							OR ppi.CreditDebit = 'C')
																	THEN -ppi.BudgetAmountCurP2
																	ELSE ppi.BudgetAmountCurP2
																	END ) AS ReqCurrentYearP2Amt 
		,Actual
		,ISNULL(pp.HistoricalProjectCode,'') AS [FileName]
		,ppi.CreditDebit
		,pp.ProjectCode
		,bvd.BudgetAmount AS OrginalBudgetAmount
		,ppiPrev.ProjectID AS PreviousYearProjectID
		,ppi.PreviousReferenceId AS PreviousYearPlanProjectItemID		
		,ISNULL(ppi.GRAPClassification, '') AS GRAPClassification
		,ISNULL(ppi.GRAPClassificationNote, '') AS GRAPClassificationNote
		,ud.FirstName + ' ' + ud.LastName AS Capturer
		,ISNULL(ppi.ZeroBudgetItemReason , '') AS ZeroBudgetItemReason
	FROM    
		Plan_Project pp
        INNER JOIN dbo.Plan_ProjectItem ppi ON pp.Project_ID = ppi.ProjectID
        INNER JOIN Const_Status cs ON cs.Status_ID = pp.ProjectStatus
        INNER JOIN Const_Division cd ON cd.Division_ID = ppi.DivisionId
        INNER JOIN Const_Department dep ON cd.DepartmentID = dep.Department_ID
		INNER JOIN Const_SCOA_Function_Structure_Consolidated func ON func.ScoaID = ppi.SCOAFunctionId AND func.FinYearText = @finYear
		INNER JOIN Const_SCOA_Funds_Structure_Consolidated fund ON fund.ScoaID = ppi.SCOAFundId AND fund.FinYearText = @finYear
		INNER JOIN Const_SCOA_Regional_Structure_Consolidated region ON region.ScoaID = ppi.SCOARegionId AND region.FinYearText = @finYear
		INNER JOIN Const_SCOA_Costing_Structure_Consolidated costing ON costing.ScoaID = ppi.SCOACostingID AND costing.FinYearText = @finYear
		INNER JOIN Const_SCOA_Project_Structure_Consolidated project ON project.ScoaID = pp.ScoaProjectID AND project.FinYearText = @finYear
        LEFT JOIN Const_ProjectItem cpi ON ppi.ProjectItemID = cpi.ProjectItem_ID
		INNER JOIN Plan_Const_SCOA_Structure_Consolidated_vw css ON ppi.SCOAItemID = css.ScoaID AND css.FinYearText = @finYear
		INNER JOIN Plan_ProjectItemMonth ppim1 ON ppi.PlanProjectItem_ID = ppim1.PlanProjectItemID AND ppim1.MonthID = 1 
		INNER JOIN Plan_ProjectItemMonth ppim2 ON ppi.PlanProjectItem_ID = ppim2.PlanProjectItemID AND ppim2.MonthID = 2 
		INNER JOIN Plan_ProjectItemMonth ppim3 ON ppi.PlanProjectItem_ID = ppim3.PlanProjectItemID AND ppim3.MonthID = 3 
		INNER JOIN Plan_ProjectItemMonth ppim4 ON ppi.PlanProjectItem_ID = ppim4.PlanProjectItemID AND ppim4.MonthID = 4 
		INNER JOIN Plan_ProjectItemMonth ppim5 ON ppi.PlanProjectItem_ID = ppim5.PlanProjectItemID AND ppim5.MonthID = 5 
		INNER JOIN Plan_ProjectItemMonth ppim6 ON ppi.PlanProjectItem_ID = ppim6.PlanProjectItemID AND ppim6.MonthID = 6 
		INNER JOIN Plan_ProjectItemMonth ppim7 ON ppi.PlanProjectItem_ID = ppim7.PlanProjectItemID AND ppim7.MonthID = 7 
		INNER JOIN Plan_ProjectItemMonth ppim8 ON ppi.PlanProjectItem_ID = ppim8.PlanProjectItemID AND ppim8.MonthID = 8 
		INNER JOIN Plan_ProjectItemMonth ppim9 ON ppi.PlanProjectItem_ID = ppim9.PlanProjectItemID AND ppim9.MonthID = 9 
		INNER JOIN Plan_ProjectItemMonth ppim10 ON ppi.PlanProjectItem_ID = ppim10.PlanProjectItemID AND ppim10.MonthID = 10 
		INNER JOIN Plan_ProjectItemMonth ppim11 ON ppi.PlanProjectItem_ID = ppim11.PlanProjectItemID AND ppim11.MonthID = 11 
		INNER JOIN Plan_ProjectItemMonth ppim12 ON ppi.PlanProjectItem_ID = ppim12.PlanProjectItemID AND ppim12.MonthID = 12
		LEFT JOIN (select * from Plan_BudgetVersionDetail where BudgetVersionID = dbo.Section71_BudgetOriginalVersionID_fxn(@FinYear)) bvd ON ppi.PlanProjectItem_ID = bvd.PlanProjectItemID 
		LEFT JOIN Plan_ProjectItem ppiPrev ON ppi.PreviousReferenceId = ppiPrev.PlanProjectItem_ID
		INNER JOIN User_UserDetail ud ON ppi.CapturerID = ud.User_ID
		LEFT JOIN 
			(
				SELECT PlanProjectItemID, SUM(Debit) - SUM(Credit) AS Actual
				FROM Led_GeneralLedger 
				WHERE FinYear = @finYear
				GROUP BY PlanProjectItemID
			) gl ON ppi.PlanProjectItem_ID = gl.PlanProjectItemID
	WHERE
		pp.Finyear = @FinYear
		AND ISNULL(pp.IsDeleted, 0) <> 1 
		AND ISNULL(ppi.ZeroBudgetItem, 0) = 1
	ORDER BY 
		ppi.PlanProjectItem_ID

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetZeroItemWithActual_sp]    Script Date: 2026/03/10 7:23:28 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- ====================================================
-- Author:		Chris Moodley
-- Create date: September 2025
-- Description:	Return count of zero budget items with actuals but still zero budget
-- Plan_BudgetZeroItemWithActual_sp '2025/2026' 
-- ====================================================
CREATE PROCEDURE [dbo].[Plan_BudgetZeroItemWithActual_sp]
	-- Add the parameters for the stored procedure here
	@finYear NVARCHAR(9)
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE @adjustmentVersionID INT = 1

	SELECT @adjustmentVersionID = ISNULL(MAX(AdjustmentVersionID), -1)
	FROM Plan_AdjustmentProject
	WHERE FinYear = @finYear

	SELECT ISNULL(COUNT(*), 0) AS BudgetZeroItemActual
	FROM
		Plan_AdjustmentProjectItem papi
		INNER JOIN Plan_ProjectItem ppi ON papi.ReferencePlanProjectItem_ID = ppi.PlanProjectItem_ID
		LEFT JOIN
			(
				SELECT PlanProjectItemID, SUM(Debit) - SUM(Credit) AS Actual
				FROM Led_GeneralLedger
				WHERE FinYear = @finYear
				GROUP BY PlanProjectItemID
			) gl ON ppi.PlanProjectItem_ID = gl.PlanProjectItemID
	WHERE
		papi.AdjustmentVersionID = @adjustmentVersionID 
		AND ISNULL(ZeroBudgetItem, 0) = 1
		AND ISNULL(papi.AdjustedBudgetAmount, papi.BudgetAmount) = 0
		AND Actual <> 0

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_BudgetZeroNTValidation_sp]    Script Date: 2026/03/10 7:23:28 AM ******/
