-- =============================================
-- Author:		Chris Moodley
-- Create date: September 2025
-- Description:	Zero Budget NT Validation
-- 250922 by CM - Remove check that budget > 0 for some checks
-- =============================================
CREATE PROCEDURE [dbo].[Plan_BudgetZeroNTValidation_sp]
	-- Add the parameters for the stored procedure here
	 @BudgetZeroExportImportVersionHeaderID INT 
	,@BudgetZeroImportVersionNumber INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE @FinYear NVARCHAR(10) 
	
	SELECT @FinYear = FinYear FROM Plan_BudgetZeroExportImportVersion_Header WHERE BudgetZeroExportImportVersionHeader_ID = @BudgetZeroExportImportVersionHeaderID

	CREATE TABLE #BudgetValidationRule (RowID INT IDENTITY(1,1) NOT NULL, BudgetValidationRuleID INT, BudgetValidationRuleDesc NVARCHAR(500), BudgetValidationRuleApplicableOverallBudget BIT)

	CREATE TABLE #Const_SCOA_Project_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6), ScoaDesc NVARCHAR(1200), ScoaShortDesc NVARCHAR(800))
	CREATE INDEX idxProjectScoaID ON #Const_SCOA_Project_Structure(ScoaID)
	CREATE INDEX idxProjectScoaCode ON #Const_SCOA_Project_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Project_Structure SELECT ScoaID, ScoaCode, PostingLevel, ScoaDesc, ScoaShortDesc FROM Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @FinYear

	CREATE TABLE #Const_SCOA_Function_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6), ScoaDesc NVARCHAR(1200), ScoaShortDesc NVARCHAR(800))
	CREATE INDEX idxFunctionScoaID ON #Const_SCOA_Function_Structure(ScoaID)
	CREATE INDEX idxFunctionScoaCode ON #Const_SCOA_Function_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Function_Structure SELECT ScoaID, ScoaCode, PostingLevel, ScoaDesc, ScoaShortDesc FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @FinYear

	CREATE TABLE #Const_SCOA_Fund_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6), ScoaDesc NVARCHAR(1200), ScoaShortDesc NVARCHAR(800))
	CREATE INDEX idxFundScoaID ON #Const_SCOA_Fund_Structure(ScoaID)
	CREATE INDEX idxFundScoaCode ON #Const_SCOA_Fund_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Fund_Structure SELECT ScoaID, ScoaCode, PostingLevel, ScoaDesc, ScoaShortDesc FROM Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @FinYear

	CREATE TABLE #Const_SCOA_Region_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6), ScoaDesc NVARCHAR(1200), ScoaShortDesc NVARCHAR(800))
	CREATE INDEX idxRegionScoaID ON #Const_SCOA_Region_Structure(ScoaID)
	CREATE INDEX idxRegionScoaCode ON #Const_SCOA_Region_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Region_Structure SELECT ScoaID, ScoaCode, PostingLevel, ScoaDesc, ScoaShortDesc FROM Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @FinYear

	CREATE TABLE #Const_SCOA_Costing_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6), ScoaDesc NVARCHAR(1200), ScoaShortDesc NVARCHAR(800))
	CREATE INDEX idxCostingScoaID ON #Const_SCOA_Costing_Structure(ScoaID)
	CREATE INDEX idxCostingScoaCode ON #Const_SCOA_Costing_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Costing_Structure SELECT ScoaID, ScoaCode, PostingLevel, ScoaDesc, ScoaShortDesc FROM Const_SCOA_Costing_Structure_Consolidated WHERE FinYearText = @FinYear

	CREATE TABLE #Const_SCOA_Structure (ScoaID INT, ScoaCode NVARCHAR(100), PostingLevel NVARCHAR(6), ScoaDesc NVARCHAR(1200), ScoaShortDesc NVARCHAR(800))
	CREATE INDEX idxItemScoaID ON #Const_SCOA_Structure(ScoaID)
	CREATE INDEX idxItemScoaCode ON #Const_SCOA_Structure(ScoaCode)
	INSERT INTO #Const_SCOA_Structure SELECT ScoaID, ScoaCode, PostingLevel, ScoaDesc, ScoaShortDesc FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @FinYear

	INSERT INTO #BudgetValidationRule
	SELECT BudgetValidationRule_ID, BudgetValidationRuleDesc, BudgetValidationRuleApplicableOverallBudget FROM Const_BudgetValidationRule_Sys WHERE BudgetValidationRuleEnabled = 1

	SELECT *
	INTO #Import
	FROM Plan_BudgetZeroImportVersion_Detail
	WHERE BudgetZeroExportImportVersionHeaderID = @BudgetZeroExportImportVersionHeaderID AND BudgetZeroImportVersionNumber = @BudgetZeroImportVersionNumber

	DECLARE @Counter INT = 1
	DECLARE @BudgetValidationRuleDesc NVARCHAR(500)
	DECLARE @BudgetValidationRuleID INT
	DECLARE @BudgetValidationRuleApplicableOverallBudget BIT

	WHILE (@Counter <= (SELECT MAX(RowID) FROM #BudgetValidationRule))
	BEGIN
	
		SELECT @BudgetValidationRuleDesc = BudgetValidationRuleDesc, @BudgetValidationRuleID = BudgetValidationRuleID, @BudgetValidationRuleApplicableOverallBudget = BudgetValidationRuleApplicableOverallBudget FROM #BudgetValidationRule WHERE RowID = @Counter

		IF (@BudgetValidationRuleID = 1)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Project_Structure proj ON imp.SCOAProjectCode = proj.ScoaCode
			WHERE  
				(item.Scoacode NOT LIKE 'IA%' AND item.ScoaCode NOT LIKE 'IL001006011%' AND item.ScoaCode NOT LIKE 'IL001006023%' AND item.ScoaCode NOT LIKE 'IL001006024%' AND item.ScoaCode NOT LIKE 'IL001006006%')
				AND proj.ScoaDesc LIKE 'Capital%'
		END

		IF (@BudgetValidationRuleID = 2)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Project_Structure proj ON imp.SCOAProjectCode = proj.ScoaCode
			WHERE
				proj.ScoaDesc LIKE 'Operational%'
				AND ((item.ScoaCode LIKE 'IA002%' AND item.ScoaDesc LIKE '%additions%') OR (item.ScoaCode LIKE 'IA002%' AND item.ScoaDesc LIKE '%acquisitions'))
		END

		IF (@BudgetValidationRuleID = 3)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Project_Structure proj ON imp.SCOAProjectCode = proj.ScoaCode
			WHERE
				(proj.ScoaCode LIKE 'PO003057%' OR proj.ScoaCode LIKE 'PO003058%' OR proj.ScoaCode LIKE 'PO003059%')
				AND (item.ScoaCode NOT LIKE 'IR%' AND item.ScoaCode NOT LIKE 'IA001010%' AND item.ScoaCode NOT LIKE 'IA001004%')
		END

		IF (@BudgetValidationRuleID = 4)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Project_Structure proj ON imp.SCOAProjectCode = proj.ScoaCode
			WHERE
				proj.ScoaDesc NOT LIKE '%Cost of Free Basic Services%' AND  proj.ScoaDesc NOT LIKE '%Revenue Cost of Free Services%'
				AND proj.ScoaDesc NOT LIKE '%property rates rebate%' AND proj.scoacode LIKE 'PO%'
				AND item.scoadesc LIKE 'Revenue%' 
		END

		IF (@BudgetValidationRuleID = 5)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT imp.BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN
					(
						SELECT BudgetZeroImportVersionDetail_ID, ScoaItemCode, ScoaFundCode, item.ScoaDesc ScoaItemDesc
						FROM 
							#Import imp
							LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
							LEFT JOIN #Const_SCOA_Project_Structure proj ON imp.SCOAProjectCode = proj.ScoaCode
						WHERE
							(item.ScoaDesc like 'Expenditure%' or item.ScoaDesc LIKE 'Assets%')
							AND proj.ScoaDesc like 'default%'
					) impA ON imp.BudgetZeroImportVersionDetail_ID = impA.BudgetZeroImportVersionDetail_ID 
			WHERE
				impA.scoaitemdesc NOT LIKE 'Expenditure:Default%'
				AND impA.scoaitemdesc NOT LIKE 'Assets:current Assets%' 
				AND impA.scoaitemdesc NOT LIKE 'Assets:Non-current Assets%' 
				AND impA.scoaitemdesc NOT LIKE '%Accumulated%'
				AND impA.scoaitemdesc NOT LIKE '%Opening Balance'
		
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Project_Structure proj ON imp.SCOAProjectCode = proj.ScoaCode
			WHERE
				(item.ScoaDesc LIKE 'Assets:Non-current Assets%' AND item.ScoaDesc LIKE '%acquisitions%' AND item.ScoaDesc NOT LIKE '%Work-in-progress%')
				AND proj.ScoaDesc LIKE 'Default%'
		END

		IF (@BudgetValidationRuleID = 6)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Function_Structure func ON imp.SCOAFunctionCode = func.ScoaCode
			WHERE
				item.ScoaCode LIKE 'IE008%'
				AND func.ScoaDesc NOT LIKE 'Function:Executive and Council:Core Function:Mayor and Council'
		END

		IF (@BudgetValidationRuleID = 7)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Function_Structure func ON imp.SCOAFunctionCode = func.ScoaCode
			WHERE
				item.ScoaCode LIKE 'IE002001%'
				AND func.ScoaCode NOT LIKE 'FX002001001%' AND func.ScoaCode NOT LIKE 'FX002002001%'
		END

		IF (@BudgetValidationRuleID = 8)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Function_Structure func ON imp.SCOAFunctionCode = func.ScoaCode
			WHERE
				item.ScoaCode like 'IE002002%'
				AND func.ScoaCode NOT LIKE 'FX016001002%'
				AND func.ScoaCode NOT LIKE 'FX016002002%'
		END

		IF (@BudgetValidationRuleID = 9)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Function_Structure func ON imp.SCOAFunctionCode = func.ScoaCode
			WHERE
				item.ScoaCode LIKE 'IE007004%'
				AND func.ScoaCode NOT LIKE 'FX016001002%'
				AND func.ScoaCode NOT LIKE 'FX016002002%'
		END

		IF (@BudgetValidationRuleID = 10)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Project_Structure proj ON imp.SCOAProjectCode = proj.ScoaCode
			WHERE
				((item.ScoaShortDesc = 'Opening Balance') AND (item.ScoaCode LIKE 'IL%' OR item.ScoaCode LIKE 'IA%' OR item.ScoaCode LIKE 'LN%'))
				AND (proj.ScoaCode NOT LIKE 'PD%')
		END

		IF (@BudgetValidationRuleID = 11)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Costing_Structure cost ON imp.SCOACostingCode = cost.ScoaCode
			WHERE
				((item.ScoaShortDesc = 'Opening Balance') AND (item.ScoaCode LIKE 'IL%' OR item.ScoaCode LIKE 'IA%' OR item.ScoaCode LIKE 'LN%'))
				AND (cost.ScoaCode NOT LIKE 'CO003%')
		END

		IF (@BudgetValidationRuleID = 12)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Fund_Structure fund ON imp.SCOAFundCode = fund.ScoaCode
			WHERE
				((item.ScoaShortDesc = 'Opening Balance') AND (item.ScoaCode LIKE 'IL%' OR item.ScoaCode LIKE 'IA%' OR item.ScoaCode LIKE 'LN%'))
				AND (fund.ScoaCode NOT LIKE 'FD003%')
		END

		IF (@BudgetValidationRuleID = 13)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Function_Structure func ON imp.SCOAFunctionCode = func.ScoaCode
			WHERE
				item.ScoaCode LIKE 'IA001009005%'
				AND func.ScoaCode NOT LIKE 'FX016%'
		END

		IF (@BudgetValidationRuleID = 14)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Costing_Structure cost ON imp.SCOACostingCode = cost.ScoaCode
			WHERE
				(cost.ScoaCode LIKE 'CO001%' or cost.ScoaCode LIKE 'CO002%')
				AND item.ScoaCode NOT LIKE 'IE018%'
		END

		IF (@BudgetValidationRuleID = 15)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Region_Structure region ON imp.SCOARegionCode = region.ScoaCode
			WHERE
				region.ScoaCode LIKE 'RX001%'
		END

		IF (@BudgetValidationRuleID = 16)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Costing_Structure cost ON imp.SCOACostingCode = cost.ScoaCode
			WHERE
				item.ScoaCode LIKE 'IE018%'
				AND cost.ScoaCode LIKE 'CO003%'
		END

		IF (@BudgetValidationRuleID = 17)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Costing_Structure cost ON imp.SCOACostingCode = cost.ScoaCode
			WHERE
				item.ScoaCode LIKE 'IR004%'
				AND cost.ScoaCode  LIKE 'CO003%'
		END

		IF (@BudgetValidationRuleID = 19)
		BEGIN
			INSERT INTO Plan_BudgetZeroImportVersion_DetailException
			SELECT BudgetZeroImportVersionDetail_ID, @BudgetValidationRuleDesc
			FROM
				#Import imp
				LEFT JOIN #Const_SCOA_Structure item ON imp.SCOAItemCode = item.ScoaCode
				LEFT JOIN #Const_SCOA_Fund_Structure fund ON imp.SCOAFundCode = fund.ScoaCode
			WHERE
				item.scoacode LIKE 'IR%' AND fund.ScoaCode LIKE 'FD003%'
		END		

		SET @Counter = @Counter + 1

	END

	DROP TABLE #Import, #Const_SCOA_Structure, #Const_SCOA_Costing_Structure, #Const_SCOA_Function_Structure, #Const_SCOA_Fund_Structure, #Const_SCOA_Project_Structure, #Const_SCOA_Region_Structure, #BudgetValidationRule

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_CheckCategoryBalance_sp]    Script Date: 2026/03/10 7:23:29 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 21 Mar 2016
-- Description:	Check Category Balance for EMS and Extracted Amount
-- CALL : CheckCategoryBalance_sp '2016/2017','glscapprj17.xls'
-- RC 6/5/2016 : Fixed issue of ambiquoes column name 'HistoricalProjectCode'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_CheckCategoryBalance_sp]
	-- Add the parameters for the stored procedure here
	@FinYear NVARCHAR(9),
	@FileName NVARCHAR(MAX)
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;
	
    -- Insert statements for procedure here
	SELECT DISTINCT CategoryDesc ,
        EMSCurrentBudget ,
        ExtractCurrentBudget ,
        ExtractCurrentBudget - CategoryCheck.EMSCurrentBudget AS VarianceCurrentBudget ,
        EMSCurrentPlus1 ,
        ExtractCurrentPlus1 ,
        ExtractCurrentPlus1 - CategoryCheck.EMSCurrentPlus1 AS VarianceCurrentPlus1 ,
        EMSCurrentPlus2 ,
        ExtractCurrentPlus2 ,
        ExtractCurrentPlus2 - CategoryCheck.EMSCurrentPlus2 AS VarianceCurrentPlus2
FROM    ( SELECT    INCI.NMBMCategoryDesc AS CategoryDesc ,
                    PrjItmByCategory.EMSCurrentBudget ,
                    PrjItmByCategory.EMSCurrentPlus1 ,
                    PrjItmByCategory.EMSCurrentPlus2 ,
                    ExldtlByCategory.ExtractCurrentBudget ,
                    ExldtlByCategory.ExtractCurrentPlus1 ,
                    ExldtlByCategory.ExtractCurrentPlus2
          FROM      Import_NMBMCategoryItem AS INCI
                    INNER JOIN ( SELECT n.NMBMCategoryDesc ,
                                        SUM(i.BudgetAmount) AS EMSCurrentBudget ,
                                        SUM(i.BudgetAmountCurP1) AS EMSCurrentPlus1 ,
                                        SUM(i.BudgetAmountCurP2) AS EMSCurrentPlus2
                                 FROM   Plan_ProjectItem i
                                        INNER JOIN Const_ProjectItem c ON i.ProjectItemID = c.ProjectItem_ID
                                        INNER JOIN Plan_Project p ON i.ProjectID = p.Project_ID
                                        INNER JOIN Import_NMBMCategoryItem n ON SUBSTRING(c.ItemDescription,
                                                              1, 4) = n.NMBMCategoryCode
                                 WHERE  ( ISNULL(i.HistoricalProjectCode, '') <> ''
                                          AND i.FinYear = @FinYear
                                        )
                                 GROUP BY n.NMBMCategoryDesc
                               ) AS PrjItmByCategory ON PrjItmByCategory.NMBMCategoryDesc = INCI.NMBMCategoryDesc
                    INNER JOIN ( SELECT SUM(ISNULL(Month1Budget, 0)
                                            + Month2Budget + Month3Budget
                                            + Month4Budget + Month5Budget
                                            + Month6Budget + Month7Budget
                                            + Month8Budget + Month9Budget
                                            + Month10Budget + Month11Budget
                                            + Month12Budget) AS ExtractCurrentBudget ,
                                        SUM(ISNULL(BudgetCurrentYearPlus1, 0)) AS ExtractCurrentPlus1 ,
                                        SUM(ISNULL(BudgetCurrentYearPlus2, 0)) AS ExtractCurrentPlus2 ,
                                        n.NMBMCategoryDesc AS ExlCategoryDesc
                                 FROM   Import_ProjectRegisterImportLog AS PrjReglog INNER JOIN Import_NMBMCategoryItem n ON SUBSTRING(PrjReglog.ItemDescription,
                                                              1, 4) = n.NMBMCategoryCode
                                 WHERE  ( ISNULL(PrjReglog.ExceptionDetails, N'') = '' )
                                        AND (PrjReglog.FinYear = @FinYear )
										AND (PrjReglog.FileName = @FileName)
                                 GROUP BY n.NMBMCategoryDesc
                               ) AS ExldtlByCategory ON ExldtlByCategory.ExlCategoryDesc = INCI.NMBMCategoryDesc
        ) AS CategoryCheck;
END

GO

