-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 21 Mar 2016
-- Description:	Check Costing Balance for EMS and Extracted Amount
-- CALL : CheckCostingBalance_sp '2016/2017','glscapprj17.xls'
-- 22/11/2016 RChetty: Multiple Scoa Costing
-- =============================================
CREATE PROCEDURE [dbo].[Plan_CheckCostingBalance_sp]
	-- Add the parameters for the stored procedure here
	@FinYear NVARCHAR(9),
	@FileName NVARCHAR(MAX)
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	-- For NMBM Default Costing is given
	DECLARE @DefaultCosting NVARCHAR(50) = '50990F96-C65D-4AC6-AA43-C6D697CEBEDC';

    -- Insert statements for procedure here
	SELECT  CostingScoaID ,
        CostingScoaCode ,
        CostingScoaDesc ,
        EMSCurrentBudget ,
        ExtractCurrentBudget ,
        ExtractCurrentBudget - CostingCheck.EMSCurrentBudget AS VarianceCurrentBudget ,
        EMSCurrentPlus1 ,
        ExtractCurrentPlus1 ,
        ExtractCurrentPlus1 - CostingCheck.EMSCurrentPlus1 AS VarianceCurrentPlus1 ,
        EMSCurrentPlus2 ,
        ExtractCurrentPlus2 ,
        ExtractCurrentPlus2 - CostingCheck.EMSCurrentPlus2 AS VarianceCurrentPlus2
FROM    ( SELECT    CSCS.ScoaID AS CostingScoaID ,
                    CSCS.ScoaCode AS CostingScoaCode ,
                    CSCS.ScoaDesc AS CostingScoaDesc ,
                    PrjItmByCosting.EMSCurrentBudget ,
                    PrjItmByCosting.EMSCurrentPlus1 ,
                    PrjItmByCosting.EMSCurrentPlus2 ,
                    ExldtlByCosting.ExtractCurrentBudget ,
                    ExldtlByCosting.ExtractCurrentPlus1 ,
                    ExldtlByCosting.ExtractCurrentPlus2
          FROM      Const_SCOA_Costing_Structure AS CSCS
                    INNER JOIN ( SELECT i.SCOACostingId AS PrjSCOACostingID ,
                                        ISNULL(SUM(BudgetAmount), 0) AS EMSCurrentBudget ,
                                        ISNULL(SUM(BudgetAmountCurP1), 0) AS EMSCurrentPlus1 ,
                                        ISNULL(SUM(BudgetAmountCurP2), 0) AS EMSCurrentPlus2
                                 FROM   Plan_ProjectItem AS i INNER JOIN dbo.Plan_Project AS p ON p.Project_ID = i.ProjectID
                                 WHERE  ( i.FinYear = @FinYear AND p.HistoricalProjectCode IS NOT NULL)
                                 GROUP BY i.SCOACostingId
                               ) AS PrjItmByCosting ON PrjItmByCosting.PrjSCOACostingID = CSCS.ScoaID
                    INNER JOIN ( SELECT SUM(ISNULL(Month1Budget, 0)
                                            + Month2Budget + Month3Budget
                                            + Month4Budget + Month5Budget
                                            + Month6Budget + Month7Budget
                                            + Month8Budget + Month9Budget
                                            + Month10Budget + Month11Budget
                                            + Month12Budget) AS ExtractCurrentBudget ,
                                        SUM(ISNULL(BudgetCurrentYearPlus1, 0)) AS ExtractCurrentPlus1 ,
                                        SUM(ISNULL(BudgetCurrentYearPlus2, 0)) AS ExtractCurrentPlus2 ,
                                        SCOACostingID AS ExlSCOACostingID
                                 FROM   Import_ProjectRegisterImportLog AS PrjReglog
                                 WHERE  ( ISNULL(ExceptionDetails, N'') = '' )
                                        AND ( FinYear = @FinYear )
										AND (PrjReglog.FileName = @FileName)
                                 GROUP BY SCOACostingID
                               ) AS ExldtlByCosting ON CASE WHEN ISNULL(ExldtlByCosting.ExlSCOACostingID,'')='' THEN @DefaultCosting ELSE ExldtlByCosting.ExlSCOACostingID END	= CAST(CSCS.NTScoaID AS NVARCHAR(MAX))
        ) AS CostingCheck;
END

GO

