-- =============================================
-- Author:		Maulik Peshavariya
-- Create date: 03/09/2016
-- Description:	Check length of fields
-- =============================================
CREATE PROCEDURE [dbo].[Plan_CheckFieldsLength_sp]
	-- Add the parameters for the stored procedure here
	@TableName VARCHAR(255),
	@columnName VARCHAR(255)
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE @pQuery VARCHAR(MAX), @len INT

	SET @columnName = REPLACE(REPLACE(@columnName, '[', ''), ']','')
	SET @TableName = REPLACE(REPLACE(@TableName, '[', ''), ']','')

	SET @pQuery = 'INSERT INTO ExceptionDetails ( FILENAME, [rownumber], ExceptionDetail)'

	SELECT @len = CASE WHEN TY.name = 'NVARCHAR' THEN cl.max_length / 2 ELSE cl.max_length END 
			FROM sys.objects obj INNER JOIN sys.columns cl ON obj.object_id = cl.object_id
		INNER JOIN sys.systypes TY ON TY.xtype = CL.system_type_id
	 WHERE obj.name = @TableName AND cl.name = @columnName AND (TY.name = 'text' OR ty.name = 'varchar' OR ty.name = 'nvarchar') 
	 
	 IF(ISNULL(@len,0) > 0)
		SET @pQuery = @pQuery  +  ' SELECT FILENAME, [rownumber], ''' + @columnName + '  '' + '' - length exceed'' FROM ' + @TableName
			+ ' where LEN(' + @columnName + ') > ' + CAST(ISNULL(@len,0)  AS VARCHAR(50))
	 
	EXEC (@pQuery)	

END



GO

