-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 21 Mar 2016
-- Description:	Check Function Balance for EMS and Extracted Amount
-- CALL : CheckFunctionBalance_sp '2016/2017','glscapprj17.xls'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_CheckFunctionBalance_sp]
	-- Add the parameters for the stored procedure here
	@FinYear NVARCHAR(9),
	@FileName NVARCHAR(MAX)
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	SELECT  FunctionScoaID ,
        FunctionScoaCode ,
        FunctionScoaDesc ,
        EMSCurrentBudget ,
        ExtractCurrentBudget ,
        ExtractCurrentBudget - FunctionCheck.EMSCurrentBudget AS VarianceCurrentBudget ,
        EMSCurrentPlus1 ,
        ExtractCurrentPlus1 ,
        ExtractCurrentPlus1 - FunctionCheck.EMSCurrentPlus1 AS VarianceCurrentPlus1 ,
        EMSCurrentPlus2 ,
        ExtractCurrentPlus2 ,
        ExtractCurrentPlus2 - FunctionCheck.EMSCurrentPlus2 AS VarianceCurrentPlus2
FROM    ( SELECT    CSFS.ScoaID AS FunctionScoaID ,
                    CSFS.ScoaCode AS FunctionScoaCode ,
                    CSFS.ScoaDesc AS FunctionScoaDesc ,
                    PrjItmByFunction.EMSCurrentBudget ,
                    PrjItmByFunction.EMSCurrentPlus1 ,
                    PrjItmByFunction.EMSCurrentPlus2 ,
                    ExldtlByFunction.ExtractCurrentBudget ,
                    ExldtlByFunction.ExtractCurrentPlus1 ,
                    ExldtlByFunction.ExtractCurrentPlus2
          FROM      Const_SCOA_Function_Structure AS CSFS
                    INNER JOIN ( SELECT i.SCOAFunctionId AS PrjSCOAFunctionID ,
                                        ISNULL(SUM(BudgetAmount), 0) AS EMSCurrentBudget ,
                                        ISNULL(SUM(BudgetAmountCurP1), 0) AS EMSCurrentPlus1 ,
                                        ISNULL(SUM(BudgetAmountCurP2), 0) AS EMSCurrentPlus2
                                 FROM   Plan_ProjectItem AS i
								 INNER JOIN Plan_Project p ON i.ProjectID=p.Project_ID
                                 WHERE  ( i.FinYear = @FinYear AND p.HistoricalProjectCode is not null)
                                 GROUP BY i.SCOAFunctionId
                               ) AS PrjItmByFunction ON PrjItmByFunction.PrjSCOAFunctionID = CSFS.ScoaID
                    INNER JOIN ( SELECT SUM(ISNULL(Month1Budget, 0)
                                            + Month2Budget + Month3Budget
                                            + Month4Budget + Month5Budget
                                            + Month6Budget + Month7Budget
                                            + Month8Budget + Month9Budget
                                            + Month10Budget + Month11Budget
                                            + Month12Budget) AS ExtractCurrentBudget ,
                                        SUM(ISNULL(BudgetCurrentYearPlus1, 0)) AS ExtractCurrentPlus1 ,
                                        SUM(ISNULL(BudgetCurrentYearPlus2, 0)) AS ExtractCurrentPlus2 ,
                                        SCOAFunctionID AS ExlSCOAFunctionID
                                 FROM   Import_ProjectRegisterImportLog AS PrjReglog
                                 WHERE  ( ISNULL(ExceptionDetails, N'') = '' )
                                        AND ( FinYear = @FinYear )
										AND (PrjReglog.FileName = @FileName)
                                 GROUP BY SCOAFunctionID
                               ) AS ExldtlByFunction ON ExldtlByFunction.ExlSCOAFunctionID = CAST(CSFS.NTScoaID AS NVARCHAR(MAX))
        ) AS FunctionCheck; 
END

GO

/****** Object:  StoredProcedure [dbo].[Plan_CheckFundAvailableAmount_sp]    Script Date: 2026/03/10 7:23:29 AM ******/
