-- =============================================
-- Author:  Jignesh Prajapati
-- Create date: 14/03/2016
-- Description: Check Fund Available Amount
-- 01-02-2017 By SNagpal: Pass @CurFinYear as Parameter in Plan_FundingSourceBudgetAvailableAmtPerYear_fxn 
-- 12-03-2021 By CM: Fix parameter issue for Plan_FundingSourceBudgetAvailableAmtPerYear_fxn
-- =============================================
CREATE PROCEDURE [dbo].[Plan_CheckFundAvailableAmount_sp]
 -- Add the parameters for the stored procedure here
 @FinYear NVARCHAR(9)
AS
BEGIN
 -- SET NOCOUNT ON added to prevent extra result sets from
 -- interfering with SELECT statements.
 SET NOCOUNT ON;

 DECLARE @CurrentYear NVARCHAR(9),
   @CurrentYearPlus1 NVARCHAR(9),
   @CurrentYearPlus2 NVARCHAR(9)

 SET @CurrentYear= @FinYear
 SET @CurrentYearPlus1 = CAST(RIGHT(@FinYear,4) AS VARCHAR(50)) + '/' + CAST((RIGHT(@FinYear,4) + 1) AS VARCHAR(50))
 SET @CurrentYearPlus2 = CAST((RIGHT(@FinYear,4) +1) AS VARCHAR(50)) + '/' + CAST((RIGHT(@FinYear,4) + 2) AS VARCHAR(50))

    --Check Fund Exist for Current Financial year 
 INSERT INTO ExceptionDetails ( FILENAME, [rownumber], ExceptionDetail)
 SELECT PRI.FileName, PRI.rownumber, 'Fund does not exist for FinancialYear - ' + @FinYear  FROM  dbo.ProjectRegisterImport AS PRI 
 INNER JOIN Const_SCOA_Funds_Structure AS CSFS ON PRI.ScoaFundID = CAST(CSFS.NTScoaID AS NVARCHAR(MAX))
 LEFT OUTER JOIN dbo.Plan_FundingSourceBudgetAvailableAmtPerYear_fxn(@CurrentYear) AS PFS ON CAST(CSFS.ScoaCode AS NVARCHAR(MAX)) = CAST(PFS.ScoaCode AS NVARCHAR(MAX)) 
 WHERE PFS.ScoaCode IS NULL

 --Check Fund Exist for Current Financial year + 1
 INSERT INTO ExceptionDetails ( FILENAME, [rownumber], ExceptionDetail)
 SELECT PRI.FileName, PRI.rownumber, 'Fund does not exist for FinancialYear - ' + @CurrentYearPlus1  FROM  dbo.ProjectRegisterImport AS PRI 
 INNER JOIN Const_SCOA_Funds_Structure AS CSFS ON PRI.ScoaFundID = CAST(CSFS.NTScoaID AS NVARCHAR(MAX))
 LEFT OUTER JOIN dbo.Plan_FundingSourceBudgetAvailableAmtPerYear_fxn(@CurrentYearPlus1) AS PFS ON CSFS.ScoaCode = PFS.ScoaCode 
 WHERE PFS.ScoaCode IS NULL

 --Check Fund Exist for Current Financial year + 2
 INSERT INTO ExceptionDetails ( FILENAME, [rownumber], ExceptionDetail)
 SELECT PRI.FileName, PRI.rownumber, 'Fund does not exist for FinancialYear - ' + @CurrentYearPlus2  FROM  dbo.ProjectRegisterImport AS PRI 
 INNER JOIN Const_SCOA_Funds_Structure AS CSFS ON PRI.ScoaFundID = CAST(CSFS.NTScoaID AS NVARCHAR(MAX))
 LEFT OUTER JOIN dbo.Plan_FundingSourceBudgetAvailableAmtPerYear_fxn(@CurrentYearPlus2) AS PFS ON CSFS.ScoaCode = PFS.ScoaCode 
 WHERE PFS.ScoaCode IS NULL

 --Check Fund Amount for Current Financial year
 INSERT INTO ExceptionDetails ( FILENAME, [rownumber], ExceptionDetail)
 SELECT PRI.FileName, PRI.rownumber, 'No Enough Fund Available for FinancialYear - ' + @FinYear FROM  dbo.ProjectRegisterImport AS PRI 
 INNER JOIN Const_SCOA_Funds_Structure AS CSFS ON PRI.ScoaFundID = CAST(CSFS.NTScoaID AS NVARCHAR(MAX))
 LEFT OUTER JOIN dbo.Plan_FundingSourceBudgetAvailableAmtPerYear_fxn(@CurrentYear) AS PFS ON CSFS.ScoaCode = PFS.ScoaCode 
 INNER JOIN (
  SELECT SUM(ISNULL(p.Month1Budget, 0)
                                    + ISNULL(p.Month2Budget, 0)
                                    + ISNULL(p.Month3Budget, 0)
                                    + ISNULL(p.Month4Budget, 0)
                                    + ISNULL(p.Month5Budget, 0)
                                    + ISNULL(p.Month6Budget, 0)
                                    + ISNULL(p.Month7Budget, 0)
                                    + ISNULL(p.Month8Budget, 0)
                                    + ISNULL(p.Month9Budget, 0)
                                    + ISNULL(p.Month10Budget, 0)
                                    + ISNULL(p.Month11Budget, 0)
                                    + ISNULL(p.Month12Budget, 0)) AS CurrentYearAmount,p.ScoaFundID FROM dbo.ProjectRegisterImport AS p GROUP BY p.ScoaFundID
 ) AS T ON T.ScoaFundID = CAST(CSFS.NTScoaID AS NVARCHAR(MAX))
 WHERE T.CurrentYearAmount > PFS.AvailableAmt AND PFS.ScoaCode IS NOT NULL

 --Check Fund Amount for Current Financial year + 1 
 INSERT INTO ExceptionDetails ( FILENAME, [rownumber], ExceptionDetail)
 SELECT PRI.FileName, PRI.rownumber, 'No Enough Fund Available for FinancialYear - ' + @CurrentYearPlus1  FROM  dbo.ProjectRegisterImport AS PRI 
 INNER JOIN Const_SCOA_Funds_Structure AS CSFS ON PRI.ScoaFundID = CAST(CSFS.NTScoaID AS NVARCHAR(MAX))
 LEFT OUTER JOIN dbo.Plan_FundingSourceBudgetAvailableAmtPerYear_fxn(@CurrentYearPlus1) AS PFS ON CSFS.ScoaCode = PFS.ScoaCode 
 INNER JOIN (
  SELECT SUM(ISNULL(p.BudgetCurrentYearPlus1, 0)) AS CurrentYearPlus1Amount,p.ScoaFundID FROM dbo.ProjectRegisterImport AS p GROUP BY p.ScoaFundID
 ) AS T ON T.ScoaFundID = CAST(CSFS.NTScoaID AS NVARCHAR(MAX))
 WHERE T.CurrentYearPlus1Amount > PFS.AvailableAmt AND PFS.ScoaCode IS NOT NULL

 --Check Fund Amount for Current Financial year + 2
 INSERT INTO ExceptionDetails ( FILENAME, [rownumber], ExceptionDetail)
 SELECT PRI.FileName, PRI.rownumber, 'No Enough Fund Available for FinancialYear - ' + @CurrentYearPlus2  FROM  dbo.ProjectRegisterImport AS PRI 
 INNER JOIN Const_SCOA_Funds_Structure AS CSFS ON PRI.ScoaFundID = CAST(CSFS.NTScoaID AS NVARCHAR(MAX))
 LEFT OUTER JOIN dbo.Plan_FundingSourceBudgetAvailableAmtPerYear_fxn(@CurrentYearPlus2) AS PFS ON CSFS.ScoaCode = PFS.ScoaCode 
 INNER JOIN (
  SELECT SUM(ISNULL(p.BudgetCurrentYearPlus2, 0)) AS CurrentYearPlus2Amount,p.ScoaFundID FROM dbo.ProjectRegisterImport AS p GROUP BY p.ScoaFundID
 ) AS T ON T.ScoaFundID = CAST(CSFS.NTScoaID AS NVARCHAR(MAX))
 WHERE T.CurrentYearPlus2Amount > PFS.AvailableAmt AND PFS.ScoaCode IS NOT NULL

END
GO

