                                        SUM(ISNULL(BudgetCurrentYearPlus2, 0)) AS ExtractCurrentPlus2 ,
                                        SCOAFundID AS ExlSCOAFundID
                                 FROM   Import_ProjectRegisterImportLog AS PrjReglog
                                 WHERE  ( ISNULL(ExceptionDetails, N'') = '' )
                                        AND ( FinYear = @FinYear )
										AND (PrjReglog.FileName = @FileName)
                                 GROUP BY SCOAFundID
                               ) AS ExldtlByFund ON ExldtlByFund.ExlSCOAFundID = CAST(CSFS.NTScoaID AS NVARCHAR(MAX))
        ) AS FundCheck;
