-- =============================================
-- Author:		Maulik Peshavariya
-- Create date: 03/09/2016
-- Description:	Check mendatory fields
-- =============================================
CREATE PROCEDURE [dbo].[Plan_CheckMendatoryFields_sp]
	-- Add the parameters for the stored procedure here
	@TableName VARCHAR(255),
	@columnName VARCHAR(255)
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE @pQuery VARCHAR(MAX)

	SET @columnName = REPLACE(REPLACE(@columnName, '[', ''), ']','')
	SET @TableName = REPLACE(REPLACE(@TableName, '[', ''), ']','')

	SET @pQuery = 'INSERT INTO ExceptionDetails ( FILENAME, [rownumber], ExceptionDetail)'

	IF EXISTS(SELECT * FROM sys.objects obj INNER JOIN sys.columns cl ON obj.object_id = cl.object_id
		INNER JOIN sys.systypes TY ON TY.xtype = CL.system_type_id
	 WHERE obj.name = @TableName AND cl.name = @columnName AND (TY.name = 'DECIMAL' OR ty.name = 'int' OR ty.name = 'tinyint' OR ty.name = 'bigint') )
	 BEGIN
			
		SET @pQuery = @pQuery  +  ' SELECT FILENAME, [rownumber], ''' + @columnName + '  '' + '' is Missing'' FROM ' + @TableName
			+ ' where ' + @columnName + ' IS NULL '
	 END
     ELSE
     BEGIN
			SET @pQuery = @pQuery  +  ' SELECT FILENAME, [rownumber], ''' + @columnName + '  '' + '' is Missing'' FROM ' + @TableName
			+ ' where ISNULL(' + @columnName + ', '''') = '''''
	 END
     

	EXEC (@pQuery)	

END



GO

