-- =============================================
-- Author:	SAHIL NAGPAL
-- Create date: 08/11/2017
-- Description:	#63164 2.3.6 National Treasury Validations
-- Calls: execute Plan_CheckNTValidations 916,26940,'2016/2017'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_CheckNTValidations]
	 @ProjectID INT,
	 @ScoaItemId INT,
	 @FinYear NVARCHAR(9)
AS
BEGIN

SELECT DISTINCT 
                ppf.ProjectID AS ProjectId,
                ppf.ScoaFunctionID AS ScoaFunctionID,
                csfs.ScoaDesc AS SCOAFunctionDesc,
                csfs.ScoaShortDesc AS SCOAFunctionShortDesc ,
                cpnv.ScoaItemId AS SCOAItemId,
                cpnv.IsEnable AS IsEnableNTValidations,
                cpnv.FinYear AS FinYearNTValidation,
                css.ScoaDesc AS SCOAItemDesc,
                css.ScoaShortDesc AS SCOAItemShortDesc
				FROM  Const_PlanNTValidations cpnv
				INNER JOIN dbo.Const_SCOA_Structure css ON css.ScoaID = cpnv.ScoaItemId
				INNER JOIN dbo.Plan_ProjectFunctions ppf ON cpnv.ScoaFunctionId = ppf.ScoaFunctionID
				INNER JOIN dbo.Const_SCOA_Function_Structure csfs ON csfs.ScoaID = ppf.ScoaFunctionID
				WHERE ppf.ProjectID=@ProjectID AND cpnv.ScoaItemId=@ScoaItemId AND cpnv.FinYear=@FinYear
END;
GO

