/****** Object:  StoredProcedure [dbo].[Plan_CheckPendingAdjudstmentApproval_sp]    Script Date: 2026/03/10 7:23:29 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 2016-04-19
-- Description:	Check Adjustment Approval is Pending or not
--				Considered that only one version number would be there for Approval
-- CALL SP: Plan_CheckPendingAdjudstmentApproval_sp '2015/2016'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_CheckPendingAdjudstmentApproval_sp] @Finyear NVARCHAR(9)
AS
    BEGIN
        SET NOCOUNT ON;

        SELECT  PA.VersionNumber ,
                COUNT(PA.AdjustmentBudget_Id) PendingAdjustments
        FROM    dbo.Plan_Adjustment PA
                INNER JOIN dbo.Const_Status CS ON CS.Status_ID = PA.Status
        WHERE   PA.[Status] = 101 -- 101 = Pending for Approval
                AND PA.FinYear = @Finyear
        GROUP BY PA.VersionNumber
        HAVING  COUNT(PA.AdjustmentBudget_Id) > 0;
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_CheckProjectBalance_sp]    Script Date: 2026/03/10 7:23:29 AM ******/
SET ANSI_NULLS ON
