-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 21 Mar 2016
-- Description:	Check Project Balance for EMS and Extracted Amount
-- CALL : CheckProjectBalance_sp '2016/2017','glscapprj17.xls'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_CheckProjectBalance_sp]
	-- Add the parameters for the stored procedure here
	@FinYear NVARCHAR(9),
	@FileName NVARCHAR(MAX)
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	SELECT  ProjectScoaID ,
        ProjectScoaCode ,
        ProjectScoaDesc ,
        EMSCurrentBudget ,
        ExtractCurrentBudget ,
        ExtractCurrentBudget - ProjectCheck.EMSCurrentBudget AS VarianceCurrentBudget ,
        EMSCurrentPlus1 ,
        ExtractCurrentPlus1 ,
        ExtractCurrentPlus1 - ProjectCheck.EMSCurrentPlus1 AS VarianceCurrentPlus1 ,
        EMSCurrentPlus2 ,
        ExtractCurrentPlus2 ,
        ExtractCurrentPlus2 - ProjectCheck.EMSCurrentPlus2 AS VarianceCurrentPlus2
FROM    ( SELECT    CSPS.ScoaID AS ProjectScoaID ,
                    CSPS.ScoaCode AS ProjectScoaCode ,
                    CSPS.ScoaDesc AS ProjectScoaDesc ,
                    PrjItmByProject.EMSCurrentBudget ,
                    PrjItmByProject.EMSCurrentPlus1 ,
                    PrjItmByProject.EMSCurrentPlus2 ,
                    ExldtlByProject.ExtractCurrentBudget ,
                    ExldtlByProject.ExtractCurrentPlus1 ,
                    ExldtlByProject.ExtractCurrentPlus2
          FROM      Const_SCOA_Project_Structure AS CSPS
                    INNER JOIN ( SELECT p.SCOAProjectId AS PrjSCOAProjectID ,
                                        ISNULL(SUM(BudgetAmount), 0) AS EMSCurrentBudget ,
                                        ISNULL(SUM(BudgetAmountCurP1), 0) AS EMSCurrentPlus1 ,
                                        ISNULL(SUM(BudgetAmountCurP2), 0) AS EMSCurrentPlus2
                                 FROM   Plan_ProjectItem AS i INNER JOIN Plan_Project p ON i.ProjectID=p.Project_ID
                                 WHERE  ( i.FinYear = @FinYear AND p.HistoricalProjectCode IS NOT NULL)
                                 GROUP BY p.SCOAProjectId
                               ) AS PrjItmByProject ON PrjItmByProject.PrjSCOAProjectID = CSPS.ScoaID
                    INNER JOIN ( SELECT SUM(ISNULL(Month1Budget, 0)
                                            + Month2Budget + Month3Budget
                                            + Month4Budget + Month5Budget
                                            + Month6Budget + Month7Budget
                                            + Month8Budget + Month9Budget
                                            + Month10Budget + Month11Budget
                                            + Month12Budget) AS ExtractCurrentBudget ,
                                        SUM(ISNULL(BudgetCurrentYearPlus1, 0)) AS ExtractCurrentPlus1 ,
                                        SUM(ISNULL(BudgetCurrentYearPlus2, 0)) AS ExtractCurrentPlus2 ,
                                        SCOAProjectID AS ExlSCOAProjectID
                                 FROM   Import_ProjectRegisterImportLog AS PrjReglog
                                 WHERE  ( ISNULL(ExceptionDetails, N'') = '' )
                                        AND ( FinYear = @FinYear )
										AND (PrjReglog.FileName = @FileName)
                                 GROUP BY SCOAProjectID
                               ) AS ExldtlByProject ON ExldtlByProject.ExlSCOAProjectID = CAST(CSPS.NTScoaID AS NVARCHAR(MAX))
        ) AS ProjectCheck;
END

