/****** Object:  StoredProcedure [dbo].[Plan_CheckReferanceFields_sp]    Script Date: 2026/03/10 7:23:29 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO





-- =============================================
-- Author:		Maulik Peshavariya
-- Create date: 03/09/2016
-- Description:	Check foreign key for data
-- =============================================
CREATE PROCEDURE [dbo].[Plan_CheckReferanceFields_sp]
	-- Add the parameters for the stored procedure here
	@TableName VARCHAR(255),
	@columnName VARCHAR(255),
	@RefTableName VARCHAR(255),
	@RefColumnName VARCHAR(255),
	@whereCondition VARCHAR(MAX),
	@OuterWhereQuery VARCHAR(MAX) = ''
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE @pQuery VARCHAR(MAX), @UNIQUECL INT 
	SET @UNIQUECL = 0

	IF (ISNULL(@OuterWhereQuery,'') != '')
		SET @OuterWhereQuery = ' AND ' + @OuterWhereQuery

	SET @columnName = REPLACE(REPLACE(@columnName, '[', ''), ']','')
	SET @TableName = REPLACE(REPLACE(@TableName, '[', ''), ']','')
	SET @RefTableName= REPLACE(REPLACE(@RefTableName, '[', ''), ']','')
	SET @RefColumnName = REPLACE(REPLACE(@RefColumnName, '[', ''), ']','')

	SET @pQuery = 'INSERT INTO ExceptionDetails ( FILENAME, [rownumber], ExceptionDetail)'

	IF (ISNULL(@whereCondition,'') = '')
		SET @whereCondition = '1=1'
	
	IF EXISTS (SELECT * FROM SYS.columns CL INNER JOIN SYS.systypes TY ON TY.xtype = CL.system_type_id WHERE CL.name = @RefColumnName AND TY.name = 'uniqueidentifier')
	BEGIN
		SET @pQuery = @pQuery  +  ' SELECT FILENAME, [rownumber], ''' + @columnName + '  '' + '' is not exists in system'' FROM ' + @TableName + 
			' LEFT JOIN ' + @RefTableName + ' ON ' +
			'CAST(' + @RefTableName  +'.' + @RefColumnName +  ' AS VARCHAR(MAX))' +
			 ' = ' + @TableName +  '.' + @columnName + ' AND ' + @whereCondition
			+ ' where ' + @RefColumnName + ' IS NULL ' + @OuterWhereQuery 
	END 
	ELSE
    BEGIN
		SET @pQuery = @pQuery  +  ' SELECT FILENAME, [rownumber], ''' + @columnName + '  '' + '' is not exists in system'' FROM ' + @TableName +
			' LEFT JOIN ' + @RefTableName + ' ON ' + @RefTableName +'.' + @RefColumnName + 
			' = ' + @TableName +  '.' + @columnName + ' AND ' + @whereCondition
			+ ' where ' + @RefColumnName + ' IS NULL ' + @OuterWhereQuery 
	END
    
	--IF EXISTS(SELECT * FROM sys.objects obj INNER JOIN sys.columns cl ON obj.object_id = cl.object_id
	--	INNER JOIN sys.systypes TY ON TY.xtype = CL.system_type_id
	-- WHERE obj.name = @TableName AND cl.name = @columnName AND (TY.name = 'DECIMAL' OR ty.name = 'int' OR ty.name = 'tinyint' OR ty.name = 'bigint') )
	-- BEGIN
		
	 --END
    
     PRINT @pQuery

	EXEC (@pQuery)	

END





GO

/****** Object:  StoredProcedure [dbo].[Plan_CheckSCOACostingExceptions_sp]    Script Date: 2026/03/10 7:23:29 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 2018-09-04
-- Description:	#61596 Planning Financial Year Budget rollover
-- Exec Plan_CheckSCOACostingExceptions_sp 1,'2018/2019', '2019/2020'
-- 2018-12-31 Chirag Patel: Get All SCOA segment based upon FinYear
-- 2019-02-19 SNagpal: Change SCOAItemMsg from “is Missing” to “is no longer available”
-- 2019-02-21 SNagpal: Change PostingLevelMsg from “Posting Level is mismatch” to “Posting level changed”
-- OShiri 06-06-2019 : Add multiyear concept to SCOA segments based upon financial year
-- 2023-10-13 CM: 98664 - Only look at enabled SCOA segments
-- =============================================
CREATE   PROCEDURE [dbo].[Plan_CheckSCOACostingExceptions_sp]
    @UserId INT = 1,
	@currFinYear NVARCHAR(9) = '2017/2018', 
	@nextFinYear NVARCHAR(9) = '2018/2019'
AS

BEGIN 

	SET XACT_ABORT ON
	SET FMTONLY OFF;
	BEGIN TRY
		BEGIN TRANSACTION ExceptionTran

			DECLARE 
				@SCOAItemMsg VARCHAR(50) ='SCOA Costing is no longer available',
				@BreakDownMsg VARCHAR(50) ='Breakdown allowed is mismatch',
				@PostingLevelMsg VARCHAR(50) ='Posting level changed',
				@ErrorResult NVARCHAR(MAX);

			CREATE TABLE #TempException
            (
              ScoaID INT ,
              ScoaParentID INT ,
              LevelID INT ,
              PostingLevel NVARCHAR(12) ,
              BreakDownAllowed NVARCHAR(12) ,
              ScoaShortDesc NVARCHAR(500) ,
              ScoaDesc NVARCHAR(1000) ,
              scoacode NVARCHAR(1000) ,
              NTScoaID NVARCHAR(1000) ,
              NTParentScoaId NVARCHAR(1000) ,
              [ENABLED] BIT ,
              [Version] NVARCHAR(20)
            );

			INSERT INTO #TempException
			SELECT 
				ScoaID,
				ScoaParentID,
				LevelID,
				PostingLevel,
				BreakDownAllowed,
				ScoaShortDesc,
				ScoaDesc,
				ScoaCode,
				NTScoaID,
				NTParentScoaId,
				[Enabled],
				[Version] 
			FROM dbo.Const_SCOA_Costing_Structure_ByYear(@currFinYear)
			WHERE [Enabled] = 1;

			CREATE TABLE #TempExceptionNext 
			(
				ScoaID INT,
				ScoaParentID INT,
				LevelID INT,
				PostingLevel NVARCHAR(12),
				BreakDownAllowed NVARCHAR(12),
				ScoaShortDesc NVARCHAR(500),
				ScoaDesc NVARCHAR(1000),
				scoacode NVARCHAR(1000),
				NTScoaID NVARCHAR(1000),
				NTParentScoaId NVARCHAR(1000),
				[ENABLED] BIT,
				[Version] NVARCHAR(20)
			);
        
		
			INSERT INTO #TempExceptionNext
			SELECT 
				ScoaID,
				ScoaParentID,
				LevelID,
				PostingLevel,
				BreakDownAllowed,
				ScoaShortDesc,
				ScoaDesc,
				ScoaCode,
				NTScoaID,
				NTParentScoaId,
				[Enabled],
				[Version] 
			FROM dbo.Const_SCOA_Costing_Structure_ByYear(@nextFinYear)
			WHERE [Enabled] = 1;
        
			CREATE TABLE #tmpSCOA 
			( SCOACostingId INT, NTSCOAIDTemp UNIQUEIDENTIFIER, BreakDownAllowed NVARCHAR(3) NULL, 
			PostingLevel NVARCHAR(3) NULL)


			INSERT INTO #tmpSCOA
			SELECT DISTINCT ppi.ScoaCostingID, csp.NTScoaID, csp.BreakDownAllowed, csp.PostingLevel FROM dbo.Plan_Project pp
			INNER JOIN dbo.Plan_ProjectItem ppi ON ppi.ProjectID = pp.Project_ID
			INNER JOIN #TempException csp ON ppi.ScoaCostingID = csp.ScoaID
			WHERE pp.FinYear = @currFinYear AND ISNULL(pp.IsDeleted,0) = 0
			AND ppi.ScoaCostingID NOT IN (SELECT ActiveSCOAId FROM Plan_SCOACostingExceptions WHERE FinYear = @nextFinYear)


			IF EXISTS (SELECT 1 FROM #tmpSCOA)
			BEGIN
				--To get missing SCOA
				INSERT INTO dbo.Plan_SCOACostingExceptions
					( FinYear ,
					  ActiveSCOAId ,
					  IsSCOAMissing ,
					  IsBreakdownMismatch ,
					  IsPostingLevelMismatch ,
					  ExceptionDescription ,
					  NewSCOAId ,
					  IsExceptionHandled ,
					  CapturerID ,
					  DateCaptured
					)
				SELECT @nextFinYear,SCOACostingId, 1,0,0,@SCOAItemMsg,NULL,0, @UserId, GETDATE() FROM #tmpSCOA t WHERE t.NTSCOAIDTemp NOT IN (
				SELECT cspp.NTScoaID FROM #TempExceptionNext cspp )
				AND t.SCOACostingId NOT IN (SELECT ActiveSCOAId FROM Plan_SCOACostingExceptions WHERE FinYear = @nextFinYear)

				--To get Breakdown Mismatch SCOA
				INSERT INTO dbo.Plan_SCOACostingExceptions
					( FinYear ,
					  ActiveSCOAId ,
					  IsSCOAMissing ,
					  IsBreakdownMismatch ,
					  IsPostingLevelMismatch ,
					  ExceptionDescription ,
					  NewSCOAId ,
					  IsExceptionHandled ,
					  CapturerID ,
					  DateCaptured
					)
				SELECT @nextFinYear,SCOACostingId, 0,1,0,@BreakDownMsg,NULL,0, @UserId, GETDATE() FROM #tmpSCOA t WHERE NTSCOAIDTemp IN (
				SELECT cspp.NTScoaID FROM #TempExceptionNext cspp 
				WHERE t.BreakDownAllowed <> cspp.BreakDownAllowed)
				AND t.SCOACostingId NOT IN (SELECT ActiveSCOAId FROM Plan_SCOACostingExceptions WHERE FinYear = @nextFinYear)

				--To get Posting Level Mismatch SCOA
				INSERT INTO dbo.Plan_SCOACostingExceptions
					( FinYear ,
					  ActiveSCOAId ,
					  IsSCOAMissing ,
					  IsBreakdownMismatch ,
					  IsPostingLevelMismatch ,
					  ExceptionDescription ,
					  NewSCOAId ,
					  IsExceptionHandled ,
					  CapturerID ,
					  DateCaptured
					)
				SELECT @nextFinYear,SCOACostingId, 0,0,1,@PostingLevelMsg,NULL,0, @UserId, GETDATE() FROM #tmpSCOA t WHERE NTSCOAIDTemp IN (
				SELECT cspp.NTScoaID FROM #TempExceptionNext cspp 
				WHERE t.PostingLevel <> cspp.PostingLevel)
				AND t.SCOACostingId NOT IN (SELECT ActiveSCOAId FROM Plan_SCOACostingExceptions WHERE FinYear = @nextFinYear)

			END

			/*Insert into Plan_TrackExceptions*/
			IF NOT EXISTS(SELECT 1 FROM dbo.Plan_TrackExceptions WHERE FinYear = @nextFinYear)
			BEGIN
				INSERT INTO dbo.Plan_TrackExceptions
				(
					FinYear,
					IsSCOACosting,
					CapturerID,
					DateCaptured
				)
				VALUES
				(   @nextFinYear,1,@UserId,GETDATE()
				)
			END
			ELSE
			BEGIN
				UPDATE dbo.Plan_TrackExceptions SET IsSCOACosting = 1, ModifierID=@UserId, DateModified=GETDATE() WHERE FinYear = @nextFinYear
			END

		COMMIT TRANSACTION ExceptionTran

		DROP TABLE #tmpSCOA

		SET @ErrorResult = 'Success'

	END TRY
	BEGIN CATCH
	
		SET @ErrorResult = ERROR_MESSAGE()
		RAISERROR(@ErrorResult, 16, 1)
		ROLLBACK TRANSACTION ExceptionTran

	END CATCH

	SELECT 'VerifySCOACostingExceptions' AS VerifySCOACostingExceptions, @ErrorResult AS Result

END
GO

