-- OShiri 06-06-2019 : Add multiyear concept to SCOA segments based upon financial year
-- 2023-10-13 CM: 98664 - Only look at enabled SCOA segments
-- =============================================
CREATE   PROCEDURE [dbo].[Plan_CheckSCOAFunctionExceptions_sp]
    @UserId INT = 1,
	@currFinYear NVARCHAR(9) = '2017/2018', 
	@nextFinYear NVARCHAR(9) = '2018/2019'
AS

BEGIN

	SET XACT_ABORT ON
	SET FMTONLY OFF;
	BEGIN TRY
		BEGIN TRANSACTION ExceptionTran

			DECLARE 
				@SCOAItemMsg VARCHAR(50) ='SCOA Function is no longer available',
				@BreakDownMsg VARCHAR(50) ='Breakdown allowed is mismatch',
				@PostingLevelMsg VARCHAR(50) ='Posting level changed',
				@ErrorResult NVARCHAR(MAX);

			CREATE TABLE #TempException
            (
              ScoaID INT ,
              ScoaParentID INT ,
              LevelID INT ,
              PostingLevel NVARCHAR(12) ,
              BreakDownAllowed NVARCHAR(12) ,
              ScoaShortDesc NVARCHAR(500) ,
              ScoaDesc NVARCHAR(1000) ,
              scoacode NVARCHAR(1000) ,
              NTScoaID NVARCHAR(1000) ,
              NTParentScoaId NVARCHAR(1000) ,
              [ENABLED] BIT ,
              [Version] NVARCHAR(20) 
            );

			INSERT  INTO #TempException
            SELECT 
				ScoaID,
				ScoaParentID,
				LevelID,
				PostingLevel,
				BreakDownAllowed,
				ScoaShortDesc,
				ScoaDesc,
				ScoaCode,
				NTScoaID,
				NTParentScoaId,
				[Enabled],
				[Version] 
			FROM dbo.Const_SCOA_Function_Structure_ByYear(@currFinYear)
			WHERE [Enabled] = 1;

			CREATE TABLE #TempExceptionNext
            (
              ScoaID INT ,
              ScoaParentID INT ,
              LevelID INT ,
              PostingLevel NVARCHAR(12) ,
              BreakDownAllowed NVARCHAR(12) ,
              ScoaShortDesc NVARCHAR(500) ,
              ScoaDesc NVARCHAR(1000) ,
              scoacode NVARCHAR(1000) ,
              NTScoaID NVARCHAR(1000) ,
              NTParentScoaId NVARCHAR(1000) ,
              [ENABLED] BIT ,
              [Version] NVARCHAR(20) 
            );

			INSERT  INTO #TempExceptionNext
            SELECT 
				ScoaID,
				ScoaParentID,
				LevelID,
				PostingLevel,
				BreakDownAllowed,
				ScoaShortDesc,
				ScoaDesc,
				ScoaCode,
				NTScoaID,
				NTParentScoaId,
				[Enabled],
				[Version] 
			FROM dbo.Const_SCOA_Function_Structure_ByYear(@nextFinYear)
			WHERE [Enabled] = 1;

			CREATE TABLE #tmpSCOA 
			( SCOAFunctionId INT, NTSCOAIDTemp UNIQUEIDENTIFIER, BreakDownAllowed NVARCHAR(3) NULL, 
			PostingLevel NVARCHAR(3) NULL)


			INSERT INTO #tmpSCOA
			SELECT DISTINCT ppi.ScoaFunctionID, csp.NTScoaID, csp.BreakDownAllowed, csp.PostingLevel FROM dbo.Plan_Project pp
			INNER JOIN dbo.Plan_ProjectItem ppi ON ppi.ProjectID = pp.Project_ID
			INNER JOIN #TempException csp ON ppi.ScoaFunctionID = csp.ScoaID
			WHERE pp.FinYear = @currFinYear AND ISNULL(pp.IsDeleted,0) = 0
			AND ppi.ScoaFunctionID NOT IN (SELECT ActiveSCOAId FROM Plan_SCOAFunctionExceptions WHERE FinYear = @nextFinYear)


			IF EXISTS (SELECT 1 FROM #tmpSCOA)
			BEGIN
				--To get missing SCOA
				INSERT INTO dbo.Plan_SCOAFunctionExceptions
				( FinYear ,
				  ActiveSCOAId ,
				  IsSCOAMissing ,
				  IsBreakdownMismatch ,
				  IsPostingLevelMismatch ,
				  ExceptionDescription ,
				  NewSCOAId ,
				  IsExceptionHandled ,
				  CapturerID ,
				  DateCaptured
				)
				SELECT @nextFinYear,SCOAFunctionId, 1,0,0,@SCOAItemMsg,NULL,0, @UserId, GETDATE() FROM #tmpSCOA t WHERE t.NTSCOAIDTemp NOT IN (
				SELECT cspp.NTScoaID FROM #TempExceptionNext cspp )
				AND t.SCOAFunctionId NOT IN (SELECT ActiveSCOAId FROM Plan_SCOAFunctionExceptions WHERE FinYear = @nextFinYear)

				--To get Breakdown Mismatch SCOA
				INSERT INTO dbo.Plan_SCOAFunctionExceptions
						( FinYear ,
						  ActiveSCOAId ,
						  IsSCOAMissing ,
						  IsBreakdownMismatch ,
						  IsPostingLevelMismatch ,
						  ExceptionDescription ,
						  NewSCOAId ,
						  IsExceptionHandled ,
						  CapturerID ,
						  DateCaptured
						)
				SELECT @nextFinYear,SCOAFunctionId, 0,1,0,@BreakDownMsg,NULL,0, @UserId, GETDATE() FROM #tmpSCOA t WHERE NTSCOAIDTemp IN (
				SELECT cspp.NTScoaID FROM #TempExceptionNext cspp 
				WHERE t.BreakDownAllowed <> cspp.BreakDownAllowed)
				AND t.SCOAFunctionId NOT IN (SELECT ActiveSCOAId FROM Plan_SCOAFunctionExceptions WHERE FinYear = @nextFinYear)

				--To get Posting Level Mismatch SCOA
