-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 2018-09-04
-- Description:	#61596 Planning Financial Year Budget rollover
-- Exec Plan_CheckSCOAFundExceptions_sp 1,'2018/2019', '2019/2020'
-- 2018-12-31 Chirag Patel: Get All SCOA segment based upon FinYear
-- 2019-02-19 SNagpal: Change SCOAItemMsg from “is Missing” to “is no longer available”
-- 2019-02-21 SNagpal: Change PostingLevelMsg from “Posting Level is mismatch” to “Posting level changed”
-- OShiri 06-06-2019 : Add multiyear concept to SCOA segments based upon financial year
-- 2023-10-13 CM: 98664 - Only look at enabled SCOA segments
-- =============================================
CREATE   PROCEDURE [dbo].[Plan_CheckSCOAFundExceptions_sp]
    @UserId INT = 1,
	@currFinYear NVARCHAR(9) = '2017/2018', 
	@nextFinYear NVARCHAR(9) = '2018/2019'
AS

BEGIN 
	
	SET XACT_ABORT ON
	SET FMTONLY OFF;
	BEGIN TRY
		BEGIN TRANSACTION ExceptionTran

			DECLARE 
				@SCOAItemMsg VARCHAR(50) ='SCOA Fund is no longer available',
				@BreakDownMsg VARCHAR(50) ='Breakdown allowed is mismatch',
				@PostingLevelMsg VARCHAR(50) ='Posting level changed',
				@ErrorResult NVARCHAR(MAX);

			CREATE TABLE #TempException
            (
              ScoaID INT ,
              ScoaParentID INT ,
              LevelID INT ,
              PostingLevel NVARCHAR(12) ,
              BreakDownAllowed NVARCHAR(12) ,
              ScoaShortDesc NVARCHAR(500) ,
              ScoaDesc NVARCHAR(1000) ,
              scoacode NVARCHAR(1000) ,
              NTScoaID NVARCHAR(1000) ,
              NTParentScoaId NVARCHAR(1000) ,
              [ENABLED] BIT ,
              [Version] NVARCHAR(20) 
            );

			INSERT  INTO #TempException
			SELECT 
				ScoaID,
				ScoaParentID,
				LevelID,
				PostingLevel,
				BreakDownAllowed,
				ScoaShortDesc,
				ScoaDesc,
				ScoaCode,
				NTScoaID,
				NTParentScoaId,
				[Enabled],
				[Version] 
			FROM dbo.Const_SCOA_Funds_Structure_ByYear(@currFinYear)
			WHERE [Enabled] = 1;


			CREATE TABLE #TempExceptionNext
            (
              ScoaID INT ,
              ScoaParentID INT ,
              LevelID INT ,
              PostingLevel NVARCHAR(12) ,
              BreakDownAllowed NVARCHAR(12) ,
              ScoaShortDesc NVARCHAR(500) ,
              ScoaDesc NVARCHAR(1000) ,
              scoacode NVARCHAR(1000) ,
              NTScoaID NVARCHAR(1000) ,
              NTParentScoaId NVARCHAR(1000) ,
              [ENABLED] BIT ,
              [Version] NVARCHAR(20) 
            );

			INSERT  INTO #TempExceptionNext
			SELECT 
				ScoaID,
				ScoaParentID,
				LevelID,
				PostingLevel,
				BreakDownAllowed,
				ScoaShortDesc,
				ScoaDesc,
				ScoaCode,
				NTScoaID,
				NTParentScoaId,
				[Enabled],
				[Version] 
			FROM dbo.Const_SCOA_Funds_Structure_ByYear(@nextFinYear)
			WHERE [Enabled] = 1;

			CREATE TABLE #tmpSCOA 
			( SCOAFundId INT, NTSCOAIDTemp UNIQUEIDENTIFIER, BreakDownAllowed NVARCHAR(3) NULL, 
			PostingLevel NVARCHAR(3) NULL)


			INSERT INTO #tmpSCOA
			SELECT DISTINCT ppi.ScoaFundID, csp.NTScoaID, csp.BreakDownAllowed, csp.PostingLevel FROM dbo.Plan_Project pp
			INNER JOIN dbo.Plan_ProjectItem ppi ON ppi.ProjectID = pp.Project_ID
			INNER JOIN #TempException csp ON ppi.ScoaFundID = csp.ScoaID
			WHERE pp.FinYear = @currFinYear AND ISNULL(pp.IsDeleted,0) = 0
			AND ppi.ScoaFundID NOT IN (SELECT ActiveSCOAId FROM Plan_SCOAFundingExceptions WHERE FinYear = @nextFinYear)


			IF EXISTS (SELECT 1 FROM #tmpSCOA)
			BEGIN
				--To get missing SCOA
				INSERT INTO dbo.Plan_SCOAFundingExceptions
					( FinYear ,
					  ActiveSCOAId ,
					  IsSCOAMissing ,
					  IsBreakdownMismatch ,
					  IsPostingLevelMismatch ,
					  ExceptionDescription ,
					  NewSCOAId ,
					  IsExceptionHandled ,
					  CapturerID ,
					  DateCaptured
					)
				SELECT @nextFinYear,SCOAFundId, 1,0,0,@SCOAItemMsg,NULL,0, @UserId, GETDATE() FROM #tmpSCOA t WHERE t.NTSCOAIDTemp NOT IN (
				SELECT cspp.NTScoaID FROM #TempExceptionNext cspp )
				AND t.SCOAFundId NOT IN (SELECT ActiveSCOAId FROM Plan_SCOAFundingExceptions WHERE FinYear = @nextFinYear)

				--To get Breakdown Mismatch SCOA
				INSERT INTO dbo.Plan_SCOAFundingExceptions
					( FinYear ,
					  ActiveSCOAId ,
					  IsSCOAMissing ,
					  IsBreakdownMismatch ,
					  IsPostingLevelMismatch ,
					  ExceptionDescription ,
					  NewSCOAId ,
					  IsExceptionHandled ,
					  CapturerID ,
					  DateCaptured
					)
				SELECT @nextFinYear,SCOAFundId, 0,1,0,@BreakDownMsg,NULL,0, @UserId, GETDATE() FROM #tmpSCOA t WHERE NTSCOAIDTemp IN (
				SELECT cspp.NTScoaID FROM #TempExceptionNext cspp 
				WHERE t.BreakDownAllowed <> cspp.BreakDownAllowed)
				AND t.SCOAFundId NOT IN (SELECT ActiveSCOAId FROM Plan_SCOAFundingExceptions WHERE FinYear = @nextFinYear)

				--To get Posting Level Mismatch SCOA
				INSERT INTO dbo.Plan_SCOAFundingExceptions
						( FinYear ,
						  ActiveSCOAId ,
						  IsSCOAMissing ,
						  IsBreakdownMismatch ,
						  IsPostingLevelMismatch ,
						  ExceptionDescription ,
						  NewSCOAId ,
						  IsExceptionHandled ,
						  CapturerID ,
						  DateCaptured
						)
				SELECT @nextFinYear,SCOAFundId, 0,0,1,@PostingLevelMsg,NULL,0, @UserId, GETDATE() FROM #tmpSCOA t WHERE NTSCOAIDTemp IN (
				SELECT cspp.NTScoaID FROM #TempExceptionNext cspp 
				WHERE t.PostingLevel <> cspp.PostingLevel)
				AND t.SCOAFundId NOT IN (SELECT ActiveSCOAId FROM Plan_SCOAFundingExceptions WHERE FinYear = @nextFinYear)

			END

			/*Insert into Plan_TrackExceptions*/
			IF NOT EXISTS(SELECT 1 FROM dbo.Plan_TrackExceptions WHERE FinYear = @nextFinYear)
			BEGIN
				INSERT INTO dbo.Plan_TrackExceptions
				(
					FinYear,
					IsSCOAFunding,
					CapturerID,
					DateCaptured
				)
				VALUES
				(   @nextFinYear,1,@UserId,GETDATE()
				)
			END
			ELSE
			BEGIN
				UPDATE dbo.Plan_TrackExceptions SET IsSCOAFunding = 1, ModifierID=@UserId, DateModified=GETDATE() WHERE FinYear = @nextFinYear
			END

		COMMIT TRANSACTION ExceptionTran

		DROP TABLE #tmpSCOA

		SET @ErrorResult = 'Success'

	END TRY
	BEGIN CATCH
	
		SET @ErrorResult = ERROR_MESSAGE()
		RAISERROR(@ErrorResult, 16, 1)
		ROLLBACK TRANSACTION ExceptionTran

	END CATCH

	SELECT 'VerifySCOAFundExceptions' AS VerifySCOAFundExceptions, @ErrorResult AS Result

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_CheckSCOAItemExceptions_sp]    Script Date: 2026/03/10 7:23:30 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 2018-09-04
-- Description:	#61596 Planning Financial Year Budget rollover
-- Exec Plan_CheckSCOAItemExceptions_sp 1,'2018/2019', '2019/2020','IL'
-- 2018-12-31 Chirag Patel: Get All SCOA segment based upon FinYear
-- 2019-02-19 SNagpal: Change SCOAItemMsg from “is Missing” to “is no longer available”
-- 2019-02-21 SNagpal: Change PostingLevelMsg from “Posting Level is mismatch” to “Posting level changed”
-- 2019-03-13 SNagpal: Optimize the Stored procedure
-- OShiri 06-06-2019 : Add multiyear concept to SCOA segments based upon financial year
-- 2023-10-13 CM: 98664 - Only look at enabled SCOA segments
-- =============================================
CREATE   PROCEDURE [dbo].[Plan_CheckSCOAItemExceptions_sp]
	@UserId INT = 1,
	@currFinYear NVARCHAR(9) = '2018/2019', 
	@nextFinYear NVARCHAR(9) = '2019/2020',
	@Type NVARCHAR(10) = 'IL'

AS 
BEGIN 

	SET XACT_ABORT ON
	SET FMTONLY OFF;
	BEGIN TRY
		BEGIN TRANSACTION ExceptionTran

			DECLARE 
				@SCOAItemMsg VARCHAR(50) ='SCOA Item is no longer available',
				@BreakDownMsg VARCHAR(50) ='Breakdown allowed is mismatch',
				@PostingLevelMsg VARCHAR(50) ='Posting level changed',
				@ErrorResult NVARCHAR(MAX);


			CREATE TABLE #tmpSCOA 
			( SCOAItemId INT, NTSCOAIDTemp UNIQUEIDENTIFIER, BreakDownAllowed NVARCHAR(3) COLLATE Latin1_General_CI_AS NULL, 
			PostingLevel NVARCHAR(3) COLLATE Latin1_General_CI_AS NULL)

			INSERT INTO #tmpSCOA
			SELECT DISTINCT ppi.ScoaItemID, csp.NTScoaID, csp.BreakDownAllowed, csp.PostingLevel FROM dbo.Plan_Project pp
			INNER JOIN dbo.Plan_ProjectItem ppi ON ppi.ProjectID = pp.Project_ID
			INNER JOIN dbo.Const_Scoa_Structure_ByYear(@currFinYear) csp ON ppi.ScoaItemID = csp.ScoaID
			WHERE pp.FinYear = @currFinYear AND ISNULL(pp.IsDeleted,0) = 0 AND csp.ScoaCode LIKE @Type + '%' AND [Enabled] = 1
			AND ppi.ScoaItemID NOT IN (SELECT ActiveSCOAId FROM Plan_SCOAItemExceptions WHERE FinYear =  @nextFinYear)


			IF EXISTS (SELECT 1 FROM #tmpSCOA)
			BEGIN
			--To get missing SCOA
			INSERT INTO dbo.Plan_SCOAItemExceptions
					( FinYear ,
					  SCOAItemType,
					  ActiveSCOAId ,
					  IsSCOAMissing ,
					  IsBreakdownMismatch ,
					  IsPostingLevelMismatch ,
					  ExceptionDescription ,
					  NewSCOAId ,
					  IsExceptionHandled ,
					  CapturerID ,
					  DateCaptured
					)
			SELECT @nextFinYear, @Type, SCOAItemId, 1,0,0,@SCOAItemMsg,NULL,0, @UserId, GETDATE() FROM #tmpSCOA t WHERE t.NTSCOAIDTemp NOT IN (
			SELECT cspp.NTScoaID FROM dbo.Const_Scoa_Structure_ByYear(@nextFinYear) cspp WHERE cspp.ScoaCode LIKE @Type + '%' AND [Enabled] = 1) 
			AND t.SCOAItemId NOT IN (SELECT ActiveSCOAId FROM Plan_SCOAItemExceptions WHERE FinYear = @nextFinYear)

			--To get Breakdown Mismatch SCOA
			INSERT INTO dbo.Plan_SCOAItemExceptions
					( FinYear ,
					  SCOAItemType ,
					  ActiveSCOAId ,
					  IsSCOAMissing ,
					  IsBreakdownMismatch ,
					  IsPostingLevelMismatch ,
					  ExceptionDescription ,
					  NewSCOAId ,
					  IsExceptionHandled ,
					  CapturerID ,
					  DateCaptured
					)
			SELECT @nextFinYear, @Type, SCOAItemId, 0,1,0,@BreakDownMsg,NULL,0, @UserId, GETDATE() FROM #tmpSCOA t WHERE NTSCOAIDTemp IN (
			SELECT cspp.NTScoaID FROM dbo.Const_Scoa_Structure_ByYear(@nextFinYear) cspp WHERE cspp.ScoaCode LIKE @Type + '%' AND [Enabled] = 1
			AND t.BreakDownAllowed <> cspp.BreakDownAllowed)
			AND t.SCOAItemId NOT IN (SELECT ActiveSCOAId FROM Plan_SCOAItemExceptions WHERE FinYear = @nextFinYear)

			--To get Posting Level Mismatch SCOA
			INSERT INTO dbo.Plan_SCOAItemExceptions
					( FinYear ,
					  SCOAItemType ,
					  ActiveSCOAId ,
					  IsSCOAMissing ,
					  IsBreakdownMismatch ,
					  IsPostingLevelMismatch ,
					  ExceptionDescription ,
					  NewSCOAId ,
					  IsExceptionHandled ,
					  CapturerID ,
					  DateCaptured
					)
			SELECT @nextFinYear, @Type,SCOAItemId, 0,0,1,@PostingLevelMsg,NULL,0, @UserId, GETDATE() 
			FROM #tmpSCOA t WHERE NTSCOAIDTemp IN (
			SELECT cspp.NTScoaID FROM dbo.Const_Scoa_Structure_ByYear(@nextFinYear) cspp WHERE cspp.ScoaCode LIKE @Type + '%' AND [Enabled] = 1
			AND t.PostingLevel <> cspp.PostingLevel)
			AND t.SCOAItemId NOT IN (SELECT ActiveSCOAId FROM Plan_SCOAItemExceptions WHERE FinYear = @nextFinYear)

			DROP TABLE #tmpSCOA
			END;

			/*Insert into Plan_TrackExceptions*/
			IF NOT EXISTS(SELECT 1 FROM dbo.Plan_TrackExceptions WHERE FinYear = @nextFinYear)
			BEGIN
			IF @Type ='IR' 
				BEGIN
					INSERT INTO dbo.Plan_TrackExceptions (FinYear,IsSCOAItemIR,CapturerID,DateCaptured)
					VALUES (@nextFinYear,1,@UserId,GETDATE())
				END
			ELSE IF @Type ='IE' 
				BEGIN
				INSERT INTO dbo.Plan_TrackExceptions (FinYear,IsSCOAItemIE,CapturerID,DateCaptured)
				VALUES (@nextFinYear,1,@UserId,GETDATE())
				END
			ELSE IF @Type ='IA' 
				BEGIN
				INSERT INTO dbo.Plan_TrackExceptions (FinYear,IsSCOAItemIA,CapturerID,DateCaptured)
				VALUES (@nextFinYear,1,@UserId,GETDATE())
				END
			ELSE IF @Type ='IL' 
				BEGIN
				INSERT INTO dbo.Plan_TrackExceptions (FinYear,IsSCOAItemIL,CapturerID,DateCaptured)
				VALUES (@nextFinYear,1,@UserId,GETDATE())
				END
			ELSE IF @Type ='IZ' 
				BEGIN
				INSERT INTO dbo.Plan_TrackExceptions (FinYear,IsSCOAItemIZ,CapturerID,DateCaptured)
				VALUES (@nextFinYear,1,@UserId,GETDATE())
				END
			ELSE IF @Type ='LN' 
				BEGIN
				INSERT INTO dbo.Plan_TrackExceptions (FinYear,IsSCOAItemLN,CapturerID,DateCaptured)
				VALUES (@nextFinYear,1,@UserId,GETDATE())
				END
			END
			ELSE
			BEGIN
			IF @Type ='IR' 
				BEGIN
					UPDATE dbo.Plan_TrackExceptions SET IsSCOAItemIR = 1, ModifierID=@UserId, DateModified=GETDATE() WHERE FinYear = @nextFinYear
				END
			ELSE IF @Type ='IE'
				BEGIN
					UPDATE dbo.Plan_TrackExceptions SET IsSCOAItemIE = 1, ModifierID=@UserId, DateModified=GETDATE() WHERE FinYear = @nextFinYear
				END 
			ELSE IF @Type ='IA' 
				BEGIN
					UPDATE dbo.Plan_TrackExceptions SET IsSCOAItemIA = 1, ModifierID=@UserId, DateModified=GETDATE() WHERE FinYear = @nextFinYear
				END
			ELSE IF @Type ='IL' 
				BEGIN
					UPDATE dbo.Plan_TrackExceptions SET IsSCOAItemIL = 1, ModifierID=@UserId, DateModified=GETDATE() WHERE FinYear = @nextFinYear
				END
			ELSE IF @Type ='IZ' 
				BEGIN
					UPDATE dbo.Plan_TrackExceptions SET IsSCOAItemIZ = 1, ModifierID=@UserId, DateModified=GETDATE() WHERE FinYear = @nextFinYear
				END
			ELSE IF @Type ='LN' 
				BEGIN
					UPDATE dbo.Plan_TrackExceptions SET IsSCOAItemLN = 1, ModifierID=@UserId, DateModified=GETDATE() WHERE FinYear = @nextFinYear
				END
			END

		COMMIT TRANSACTION ExceptionTran

		SET @ErrorResult = 'Success'

	END TRY
	BEGIN CATCH
	
		SET @ErrorResult = ERROR_MESSAGE()
		RAISERROR(@ErrorResult, 16, 1)
		ROLLBACK TRANSACTION ExceptionTran

	END CATCH

	SELECT 'VerifySCOAItemExceptions' AS VerifySCOAItemExceptions, @ErrorResult AS Result

END
GO

