-- OShiri 06-06-2019 : Add multiyear concept to SCOA segments based upon financial year
-- 2023-10-13 CM: 98664 - Only look at enabled SCOA segments
-- =============================================
CREATE   PROCEDURE [dbo].[Plan_CheckSCOAProjectExceptions_sp]
    @UserId INT = 1,
	@currFinYear NVARCHAR(9) = '2017/2018', 
	@nextFinYear NVARCHAR(9) = '2018/2019'
AS

BEGIN 

	SET XACT_ABORT ON
	SET FMTONLY OFF;
	BEGIN TRY
		BEGIN TRANSACTION ExceptionTran

			DECLARE 
				@SCOAItemMsg VARCHAR(50) ='SCOA Project is no longer available',
				@BreakDownMsg VARCHAR(50) ='Breakdown allowed is mismatch',
				@PostingLevelMsg VARCHAR(50) ='Posting level changed',
				@ErrorResult NVARCHAR(MAX);

			CREATE TABLE #TempException
            (
              ScoaID INT ,
              ScoaParentID INT ,
              LevelID INT ,
              PostingLevel NVARCHAR(12) ,
              BreakDownAllowed NVARCHAR(12) ,
              ScoaShortDesc NVARCHAR(500) ,
              ScoaDesc NVARCHAR(1000) ,
              scoacode NVARCHAR(1000) ,
              NTScoaID NVARCHAR(1000) ,
              NTParentScoaId NVARCHAR(1000) ,
              [ENABLED] BIT ,
              [Version] NVARCHAR(20)
            );

			INSERT  INTO #TempException
			SELECT 
				ScoaID,
				ScoaParentID,
				LevelID,
				PostingLevel,
				BreakDownAllowed,
				ScoaShortDesc,
				ScoaDesc,
				ScoaCode,
				NTScoaID,
				NTParentScoaId,
				[Enabled],
				[Version] 
				FROM dbo.Const_SCOA_Project_Structure_ByYear(@currFinYear)
				WHERE [Enabled] = 1;

			CREATE TABLE #TempExceptionNext
            (
              ScoaID INT ,
              ScoaParentID INT ,
              LevelID INT ,
              PostingLevel NVARCHAR(12) ,
              BreakDownAllowed NVARCHAR(12) ,
              ScoaShortDesc NVARCHAR(500) ,
              ScoaDesc NVARCHAR(1000) ,
              scoacode NVARCHAR(1000) ,
              NTScoaID NVARCHAR(1000) ,
              NTParentScoaId NVARCHAR(1000) ,
              [ENABLED] BIT ,
              [Version] NVARCHAR(20)
            );

			INSERT  INTO #TempExceptionNext
			SELECT 
				ScoaID,
				ScoaParentID,
				LevelID,
				PostingLevel,
				BreakDownAllowed,
				ScoaShortDesc,
				ScoaDesc,
				ScoaCode,
				NTScoaID,
				NTParentScoaId,
				[Enabled],
				[Version] 
			FROM dbo.Const_SCOA_Project_Structure_ByYear(@nextFinYear)
			WHERE [Enabled] = 1;

			CREATE TABLE #tmpSCOA 
			( SCOAProjectId INT, NTSCOAIDTemp UNIQUEIDENTIFIER, BreakDownAllowed NVARCHAR(3) NULL, 
			PostingLevel NVARCHAR(3) NULL)


			INSERT INTO #tmpSCOA
			SELECT DISTINCT pp.ScoaProjectID, csp.NTScoaID, csp.BreakDownAllowed, csp.PostingLevel FROM dbo.Plan_Project pp
			INNER JOIN #TempException csp ON pp.ScoaProjectID = csp.ScoaID
			WHERE pp.FinYear = @currFinYear AND ISNULL(pp.IsDeleted,0) = 0
			AND pp.SCOAProjectId NOT IN (SELECT ActiveSCOAId FROM Plan_SCOAProjectExceptions WHERE FinYear = @nextFinYear)


			IF EXISTS (SELECT 1 FROM #tmpSCOA)
			BEGIN
				--To get missing SCOA
				INSERT INTO dbo.Plan_SCOAProjectExceptions
					( FinYear ,
					  ActiveSCOAId ,
					  IsSCOAMissing ,
					  IsBreakdownMismatch ,
					  IsPostingLevelMismatch ,
					  ExceptionDescription ,
					  NewSCOAId ,
					  IsExceptionHandled ,
					  CapturerID ,
					  DateCaptured
					)
				SELECT @nextFinYear,SCOAProjectId, 1,0,0,@SCOAItemMsg,NULL,0, @UserId, GETDATE() FROM #tmpSCOA t WHERE t.NTSCOAIDTemp NOT IN (
				SELECT cspp.NTScoaID FROM #TempExceptionNext cspp)
				AND t.SCOAProjectId NOT IN (SELECT ActiveSCOAId FROM Plan_SCOAProjectExceptions WHERE FinYear = @nextFinYear)

				--To get Breakdown Mismatch SCOA
				INSERT INTO dbo.Plan_SCOAProjectExceptions
					( FinYear ,
					  ActiveSCOAId ,
					  IsSCOAMissing ,
					  IsBreakdownMismatch ,
					  IsPostingLevelMismatch ,
					  ExceptionDescription ,
					  NewSCOAId ,
					  IsExceptionHandled ,
					  CapturerID ,
					  DateCaptured
					)
				SELECT @nextFinYear,SCOAProjectId, 0,1,0,@BreakDownMsg,NULL,0, @UserId, GETDATE() FROM #tmpSCOA t WHERE NTSCOAIDTemp IN (
				SELECT cspp.NTScoaID FROM #TempExceptionNext cspp 
				WHERE t.BreakDownAllowed <> cspp.BreakDownAllowed)
				AND t.SCOAProjectId NOT IN (SELECT ActiveSCOAId FROM Plan_SCOAProjectExceptions WHERE FinYear = @nextFinYear)

				--To get Posting Level Mismatch SCOA
				INSERT INTO dbo.Plan_SCOAProjectExceptions
					( FinYear ,
					  ActiveSCOAId ,
					  IsSCOAMissing ,
					  IsBreakdownMismatch ,
					  IsPostingLevelMismatch ,
					  ExceptionDescription ,
					  NewSCOAId ,
					  IsExceptionHandled ,
					  CapturerID ,
					  DateCaptured
					)
				SELECT @nextFinYear,SCOAProjectId, 0,0,1,@PostingLevelMsg,NULL,0, @UserId, GETDATE() FROM #tmpSCOA t WHERE NTSCOAIDTemp IN (
				SELECT cspp.NTScoaID FROM #TempExceptionNext cspp 
				WHERE t.PostingLevel <> cspp.PostingLevel)
				AND t.SCOAProjectId NOT IN (SELECT ActiveSCOAId FROM Plan_SCOAProjectExceptions WHERE FinYear = @nextFinYear)

			END


			/*Insert into Plan_TrackExceptions*/
			IF NOT EXISTS(SELECT 1 FROM dbo.Plan_TrackExceptions WHERE FinYear = @nextFinYear)
			BEGIN
				INSERT INTO dbo.Plan_TrackExceptions
				(
					FinYear,
					IsSCOAProject,
					CapturerID,
					DateCaptured
				)
				VALUES
				(   @nextFinYear,1,@UserId,GETDATE()
				)
			END
			ELSE
			BEGIN
				UPDATE dbo.Plan_TrackExceptions SET IsSCOAProject = 1, ModifierID=@UserId, DateModified=GETDATE() WHERE FinYear = @nextFinYear
			END

		COMMIT TRANSACTION ExceptionTran

		DROP TABLE #tmpSCOA

		SET @ErrorResult = 'Success'

	END TRY
	BEGIN CATCH
	
		SET @ErrorResult = ERROR_MESSAGE()
		RAISERROR(@ErrorResult, 16, 1)
		ROLLBACK TRANSACTION ExceptionTran

	END CATCH

	SELECT 'VerifySCOAProjectExceptions' AS VerifySCOAProjectExceptions, @ErrorResult AS Result

END
