/****** Object:  StoredProcedure [dbo].[Plan_CheckUserIsLastApproverForAdjustmentProject_sp]    Script Date: 2026/03/10 7:23:30 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Sahil Nagpal
-- Create date: 2017-12-25
-- Description:	Check User is last approver or not
-- CALL SP: Plan_CheckUserIsLastApproverForAdjustmentProject_sp 2318
-- 2018-04-23 by SNagpal : Update Condition for checking LastApprover
-- =============================================
CREATE PROCEDURE [dbo].[Plan_CheckUserIsLastApproverForAdjustmentProject_sp] 
@AdjustmentProjectId INT
AS
    BEGIN
        DECLARE @LastApprover INT = 0;

        SET NOCOUNT ON;

        IF ( ( SELECT   COUNT(1)
               FROM     dbo.Plan_AdjustmentProjectRecommendation
               WHERE    IsRejected = 1
                        AND AdjustmentProjectId = @AdjustmentProjectId
             ) >= 1 )
            BEGIN
                SET @LastApprover = 0;
            END;
        ELSE
            BEGIN
                SELECT  @LastApprover = CASE WHEN COUNT(PAP.AdjustmentProject_ID) = 1
                                             THEN 1
                                             ELSE 0
                                        END
                FROM    dbo.Plan_AdjustmentProject PAP
                        INNER JOIN dbo.Plan_AdjustmentProjectRecommendUsers PAPRU ON PAPRU.AdjustmentProjectId = PAP.AdjustmentProject_ID
                        INNER JOIN dbo.User_UserDetail UUD ON UUD.User_ID = PAPRU.UserId
                        LEFT OUTER JOIN dbo.Plan_AdjustmentProjectRecommendation PVAR ON PVAR.AdjustmentProjectId = PAP.AdjustmentProject_ID
                                                              AND UUD.User_ID = PVAR.RecommendBy 
                WHERE   PAP.AdjustmentProject_ID = @AdjustmentProjectId
                        AND PVAR.RecommendBy IS NULL
                GROUP BY PVAR.AdjustmentProjectId;
            END;

        SELECT  @LastApprover AS LastApprover ,
                @AdjustmentProjectId AS AdjustmentProjectId;
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_CheckUserIsLastApproverForVirement_sp]    Script Date: 2026/03/10 7:23:30 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 2016-04-18
-- Description:	Check User is last approver or not
-- CALL SP: Plan_CheckUserIsLastApproverForVirement_sp 1021
-- 2016-04-21 by JP : Update Condition for checking user with Virement Employees
-- 2016-04-22 by SN: Plan_VirementApprovalEmployees table is renamed to Plan_VirementApprovalUsers, And EmployeeId => UserId
-- =============================================
CREATE PROCEDURE [dbo].[Plan_CheckUserIsLastApproverForVirement_sp] @VirementId INT
AS
    BEGIN
        DECLARE @LastApprover INT = 0;

        SET NOCOUNT ON;

        IF ( ( SELECT   COUNT(1)
               FROM     Plan_VirementApprovalRejections
               WHERE    IsRejected = 1
                        AND VirementId = @VirementId
             ) >= 1 )
            BEGIN
                SET @LastApprover = 0;
            END;
        ELSE
            BEGIN
                SELECT  @LastApprover = CASE WHEN COUNT(V.VirementId) = 1
                                             THEN 1
                                             ELSE 0
                                        END
                FROM    dbo.Plan_Virements V
                        INNER JOIN dbo.Plan_VirementApprovalUsers PVAE ON PVAE.VirementId = V.VirementId
                        INNER JOIN dbo.User_UserDetail UUD ON UUD.User_ID = PVAE.UserId
                        LEFT OUTER JOIN dbo.Plan_VirementApprovalRejections PVAR ON PVAR.VirementId = V.VirementId
                                                              AND UUD.User_ID = PVAR.ApprovedBy --
                WHERE   V.VirementId = @VirementId
                        AND PVAR.IsApproved IS NULL
                GROUP BY PVAR.VirementId;
            END;

        SELECT  @LastApprover AS LastApprover ,
                @VirementId AS VirementId;
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_CreateAdjustmentBudgetVersion_sp]    Script Date: 2026/03/10 7:23:30 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Nirav Parikh
-- Create date: 2017-11-22
-- Description:	Create Adjustment Budget Version
-- 04-06-2018 SNagpal: Fix Joins
-- 07-08-2023 CMoodley: #105236 Include CostingProject field
-- =============================================
CREATE PROCEDURE [dbo].[Plan_CreateAdjustmentBudgetVersion_sp]
    @VersionNumber NVARCHAR(50),
    @VersionName NVARCHAR(1000),
    @Comments NVARCHAR(1000),
    @FinYear NVARCHAR(18),
    @userId INT,
	@CreateAdjustmentBudgetVersionResult NVARCHAR(MAX) = '' OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @AdjustmentBudgetVersionId INT = 0

    BEGIN TRY
	BEGIN TRANSACTION
        IF NOT EXISTS
        (
            SELECT 1
            FROM dbo.Plan_AdjustmentBudgetVersion
            WHERE VersionNumber = @VersionNumber
        )
        BEGIN
			DECLARE @CurrentAdjustmentVersionId INT
			SELECT TOP 1 @CurrentAdjustmentVersionId = AdjustmentBudgetVersion_ID FROM dbo.Plan_AdjustmentBudgetVersion WHERE VersionName LIKE @FinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

            INSERT INTO dbo.Plan_AdjustmentBudgetVersion
            (
                VersionNumber,
                VersionName,
                Comments,
                CapturerID,
                DateCaptured
            )
            VALUES
            (@VersionNumber, @VersionName, @Comments, @userId, GETDATE());

            SELECT @AdjustmentBudgetVersionId = SCOPE_IDENTITY();

            IF (@AdjustmentBudgetVersionId <> 0)
            BEGIN
                INSERT INTO dbo.Plan_AdjustmentBudgetVersionDetail
                (
                    AdjustmentBudgetVersionID,
                    ProjectID,
                    FinYear,
                    IDPItemID,
                    CapitalOperation,
                    ScoaProjectID,
                    SCOACostingID,
                    ProjectTypeID,
                    PlanProjectItemID,
                    ProjectItemID,
                    SCOAItemID,
                    SCOAFundId,
                    BudgetAmount,
                    BudgetAmountCurP1,
                    BudgetAmountCurP2,
                    SCOAFunctionId,
                    SCOARegionId,
                    DivisionId,
                    BudgetSplitID,
                    VirementId,
                    AdjustmentId,
                    ModificationNumber,
                    IsItemLocked,
                    CreditDebit,
                    AdjutmentType,
                    LegislativeReasonAdjustment,
                    ReasonForAdjustment,
                    CapturerID,
                    DateCaptured,
					GRAPClassification,
					GRAPClassificationNote,
					MainSegmentReporting,
					SubSegmentReporting,
					CostingProject
                )
                SELECT @AdjustmentBudgetVersionId,
					PP.AdjustmentProject_ID,
					PP.FinYear,
					0,
					ISNULL(PP.CapitalOperation, 0),
					ISNULL(PP.ScoaProjectID, 0),
					ISNULL(PPI.SCOACostingID, 0),
					ISNULL(PP.ProjectTypeID, 0),
					ISNULL(PPI.PlanAdjustmentProjectItem_ID, 0),
					ISNULL(PPI.ProjectItemID, 0),
					ISNULL(PPI.SCOAItemID, 0),
					ISNULL(PPI.SCOAFundId, 0),
					ISNULL(PPI.BudgetAmount, 0),
					ISNULL(PPI.BudgetAmountCurP1, 0),
					ISNULL(PPI.BudgetAmountCurP2, 0),
					ISNULL(PPI.SCOAFunctionId, 0),
					ISNULL(PPI.SCOARegionId, 0),
					ISNULL(PPI.DivisionId, 0),
					ISNULL(PPI.BudgetSplitID, 0),
					ISNULL(PPI.VirementId, 0),
					ISNULL(PPI.AdjustmentId, 0),
					ISNULL(PPI.ModificationNumber, 0),
					ISNULL(PPI.IsItemLocked, 0),
					ISNULL(PPI.CreditDebit, ''),
					ISNULL(PPI.AdjutmentType, 0),
					ISNULL(PPI.LegislativeReasonAdjustment, 0),
					ISNULL(PPI.ReasonForAdjustment, ''),
					@userId,
					GETDATE(),
					GRAPClassification,
					GRAPClassificationNote,
					MainSegmentReporting,
					SubSegmentReporting,
					CostingProject
                FROM dbo.Plan_AdjustmentProject AS PP
                    INNER JOIN dbo.Plan_AdjustmentProjectItem AS PPI ON PP.AdjustmentProject_ID = PPI.AdjustmentProjectID
                WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PP.AdjustmentVersionId = @CurrentAdjustmentVersionId

                INSERT INTO dbo.Plan_AdjustmentBudgetVersionMonths
                (
                    AdjustmentBudgetVersionID,
					AdjustmentProjectItemMonth_ID,
                    PlanAdjustmentProjectItemID,
                    MonthID,
                    UnitQuantity,
                    UnitPrice,
                    CaptureID,
                    DateCaptured,
                    VirementId,
                    AdjustmentId
                )
                SELECT @AdjustmentBudgetVersionId,
                       ppim.AdjustmentProjectItemMonth_ID,
					   PPI.PlanAdjustmentProjectItem_ID,
                       ppim.MonthID,
                       ppim.UnitQuantity,
                       ppim.UnitPrice,
                       @userId,
                       GETDATE(),
                       ppim.VirementId,
                       ppim.AdjustmentId
                FROM dbo.Plan_AdjustmentProject AS PP
                    INNER JOIN dbo.Plan_AdjustmentProjectItem AS PPI ON  PP.AdjustmentProject_ID = PPI.AdjustmentProjectID
                    INNER JOIN dbo.Plan_AdjustmentProjectItemMonth ppim ON PPI.PlanAdjustmentProjectItem_ID = ppim.PlanAdjustmentProjectItemID
                WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PP.AdjustmentVersionId = @CurrentAdjustmentVersionId

                SET @CreateAdjustmentBudgetVersionResult = 'Success';
				COMMIT TRANSACTION
            END;
            ELSE
            BEGIN
                SET @CreateAdjustmentBudgetVersionResult = 'Adjustment Budget Version id not found & Adjustment Budget Version Detail Entry Skipped';
				ROLLBACK TRANSACTION
            END;
        END;
        ELSE
		BEGIN
			SET @CreateAdjustmentBudgetVersionResult = 'Adjustment Budget Version - ' + @VersionNumber + ' is already generated';
			COMMIT TRANSACTION
		END;
    END TRY
    BEGIN CATCH

        SET @CreateAdjustmentBudgetVersionResult = ERROR_MESSAGE();
        RAISERROR(@CreateAdjustmentBudgetVersionResult, 16, 1);
		ROLLBACK TRANSACTION

    END CATCH;
END;
GO

