-- =============================================
-- Author:		Nirav Parikh
-- Create date: 2017-11-22
-- Description:	Create Adjustment Funding Budget Version
-- =============================================
CREATE PROCEDURE [dbo].[Plan_CreateAdjustmentFundingBudgetVersion_sp]
    @VersionNumber NVARCHAR(50),
    @VersionName NVARCHAR(1000),
    @Comments NVARCHAR(1000),
    @FinYear NVARCHAR(18),
    @userId INT,
	@CreateAdjustmentBudgetVersionResult NVARCHAR(MAX) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @AdjustmentBudgetVersionId INT = 0;

    BEGIN TRY
	BEGIN TRANSACTION
        DECLARE @FinYearP1 NVARCHAR(9),
                @FinYearP2 NVARCHAR(9),
                @yearp1 INT,
                @yearp2 INT,
                @yearp3 INT;

        SELECT @yearp1 = CAST(SUBSTRING(@FinYear, 6, 4) AS INT);
        SELECT @yearp2 = @yearp1 + 1;
        SELECT @yearp3 = @yearp1 + 2;
        SELECT @FinYearP1 = CONVERT(VARCHAR(4), @yearp1) + '/' + CONVERT(VARCHAR(4), @yearp2);
        SELECT @FinYearP2 = CONVERT(VARCHAR(4), @yearp2) + '/' + CONVERT(VARCHAR(4), @yearp3);

        --Insert into Plan_AdjustmentFundingBudgetVersion
        IF NOT EXISTS
        (
            SELECT 1
            FROM dbo.Plan_AdjustmentFundingBudgetVersion
            WHERE VersionNumber = @VersionNumber
        )
        BEGIN
			DECLARE @CurrentAdjustmentVersionId INT
			SELECT TOP 1 @CurrentAdjustmentVersionId = AdjustmentBudgetVersion_ID FROM dbo.Plan_AdjustmentBudgetVersion WHERE VersionName LIKE @FinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

            INSERT INTO dbo.Plan_AdjustmentFundingBudgetVersion
            (
                VersionNumber,
                VersionName,
                Comments,
                CapturerID,
                DateCaptured
            )
            VALUES
            (@VersionNumber, @VersionName, @Comments, @userId, GETDATE());

            SELECT @AdjustmentBudgetVersionId = SCOPE_IDENTITY();

            --Insert into Plan_AdjustmentFundingBudgetVersionDetails
            IF (@AdjustmentBudgetVersionId <> 0)
            BEGIN
                INSERT INTO dbo.Plan_AdjustmentFundingBudgetVersionDetails
                (
                    AdjustmentFundingBudgetVersionId,
                    AdjustmentFundingSourceBudgetDetail_ID,
                    AdjustmentFundingSourceBudgetHeaderID,
                    FinancialYear,
                    FundingSourceID,
                    ScoaID,
                    FundingSourceBudget,
                    DateCaptured,
                    CapturerID,
                    UploadedDocument
                )
                SELECT @AdjustmentBudgetVersionId,
                       pfsb.AdjustmentFundingSourceBudgetDetail_ID,
                       pfsb.AdjustmentFundingSourceBudgetHeaderID,
                       pfsbh.FinancialYear,
                       pfsb.AdjustmentFundingSourceID,
                       pfsb.ScoaID,
                       pfsb.FundingSourceBudget,
                       GETDATE(),
                       @userId,
                       pfsb.UploadedDocument
                FROM dbo.Plan_AdjustmentFundingSourceBudget_Header pfsbh
                    INNER JOIN dbo.Plan_AdjustmentFundingSourceBudget_Detail pfsb ON pfsb.AdjustmentFundingSourceBudgetHeaderID = pfsbh.AdjustmentFundingSourceBudgetHeader_ID
                WHERE pfsbh.FinancialYear IN ( @FinYear, @FinYearP1, @FinYearP2 ) AND pfsbh.AdjustmentFundingVersionId = @CurrentAdjustmentVersionId;

                SET @CreateAdjustmentBudgetVersionResult = 'Success';
				COMMIT TRANSACTION
            END;
            ELSE
            BEGIN
                SET @CreateAdjustmentBudgetVersionResult = 'Adjustment Funding Budget Version id not found & Adjustment Funding Budget Version Detail Entry Skipped';
				ROLLBACK TRANSACTION
            END;
        END;
        ELSE
			BEGIN
				SET @CreateAdjustmentBudgetVersionResult = 'Adjustment Funding Budget Version - ' + @VersionNumber + ' is already generated';
				COMMIT TRANSACTION
			END;
    END TRY
    BEGIN CATCH

        SET @CreateAdjustmentBudgetVersionResult = ERROR_MESSAGE();
        RAISERROR(@CreateAdjustmentBudgetVersionResult, 16, 1);
		ROLLBACK TRANSACTION
    
	END CATCH;
END;

GO

/****** Object:  StoredProcedure [dbo].[Plan_CreateBudgetVersion_sp]    Script Date: 2026/03/10 7:23:30 AM ******/
SET ANSI_NULLS ON
