-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 2016-04-25
-- Description:	Create Budget Version
-- 23-08-2016: Fix Spelling Mistake of Entry in static message
-- SNagpal 22/11/2016: Getting SCOACostingId from Plan_ProjectItem Table instead of Plan_Project
-- Snagpal 28/03/2017 #53397: IDPItemId is removed from Plan_project table and as per gansen no more needed in ProjectBudgetReport, so saving as 0
-- SNagpal 10/10/2017 #63159: Also Insert Month Budget values in Plan_BudgetVersionMonths
-- CMoodley 07/08/2023 #105236 Include CostingProject field
-- =============================================
CREATE PROCEDURE [dbo].[Plan_CreateBudgetVersion_sp]
    @VersionNumber NVARCHAR(50) ,
    @VersionName NVARCHAR(1000) ,
    @Comments NVARCHAR(1000) ,
    @FinYear NVARCHAR(18) ,
    @userId INT
AS
    BEGIN
        SET NOCOUNT ON;

        DECLARE @BudgetVersionId INT = 0 ,
            @CreateBudgetVersionResult NVARCHAR(MAX)= '';

        BEGIN TRY
            BEGIN TRANSACTION;

            IF NOT EXISTS ( SELECT  1
                            FROM    dbo.Plan_BudgetVersion
                            WHERE   VersionNumber = @VersionNumber )
                BEGIN
                    INSERT  INTO dbo.Plan_BudgetVersion
                            ( VersionNumber ,
                              VersionName ,
                              Comments ,
                              CapturerID ,
                              DateCaptured
	                        )
                    VALUES  ( @VersionNumber ,
                              @VersionName ,
                              @Comments ,
                              @userId ,
                              GETDATE()
                            );
                

                    SELECT  @BudgetVersionId = SCOPE_IDENTITY();

                    IF ( @BudgetVersionId <> 0 )
                        BEGIN
                            INSERT  INTO dbo.Plan_BudgetVersionDetail
                                    ( BudgetVersionID ,
                                      ProjectID ,
                                      FinYear ,
                                      IDPItemID ,
                                      CapitalOperation ,
                                      ScoaProjectID ,
                                      SCOACostingID ,
                                      ProjectTypeID ,
                                      PlanProjectItemID ,
                                      ProjectItemID ,
                                      SCOAItemID ,
                                      SCOAFundId ,
                                      BudgetAmount ,
                                      BudgetAmountCurP1 ,
                                      BudgetAmountCurP2 ,
                                      SCOAFunctionId ,
                                      SCOARegionId ,
                                      DivisionId ,
                                      CapturerID ,
                                      DateCaptured ,
									  CostingProject
				                    )
                                    SELECT  @BudgetVersionId , -- BudgetVersionID - int
                                            PP.Project_ID , -- ProjectID - int
                                            PP.FinYear , -- FinYear - nvarchar(18)
											0, -- ISNULL(PP.IDPItemID,0) , -- IDPItemID - int
                                            ISNULL(PP.CapitalOperation,0) , -- CapitalOperation - int
                                            ISNULL(PP.ScoaProjectID,0) , -- ScoaProjectID - int
                                            ISNULL(PPI.SCOACostingID,0) , -- SCOACostingID - int
                                            ISNULL(PP.ProjectTypeID,0) , -- ProjectTypeID - int
                                            ISNULL(PPI.PlanProjectItem_ID,0) , -- PlanProjectItemID - int
                                            ISNULL(PPI.ProjectItemID,0) , -- ProjectItemID - int
                                            ISNULL(PPI.SCOAItemID,0) , -- SCOAItemID - int
                                            ISNULL(PPI.SCOAFundId,0) , -- SCOAFundId - int
                                            ISNULL(PPI.BudgetAmount,0) , -- BudgetAmount - decimal
                                            ISNULL(PPI.BudgetAmountCurP1,0) , -- BudgetAmountCurP1 - decimal
                                            ISNULL(PPI.BudgetAmountCurP2,0) , -- BudgetAmountCurP2 - decimal
                                            ISNULL(PPI.SCOAFunctionId,0) , -- SCOAFunctionId - int
                                            ISNULL(PPI.SCOARegionId,0) , -- SCOARegionId - int
                                            ISNULL(PPI.DivisionId,0) , -- DivisionId - int
                                            @userId , -- CapturerID - int
                                            GETDATE() ,  -- DateCaptured - datetime
											CostingProject
                                    FROM    dbo.Plan_Project AS PP
                                            INNER JOIN Plan_ProjectItem AS PPI ON PP.Project_ID = PPI.ProjectID
                                    WHERE   PP.FinYear = @FinYear
                                            AND ISNULL(PP.IsDeleted, 0) = 0;

							INSERT INTO dbo.Plan_BudgetVersionMonths
							        (BudgetVersionID, 
									  ProjectItemMonth_ID ,
							          PlanProjectItemID ,
							          MonthID ,
							          UnitQuantity ,
							          UnitPrice ,
							          CaptureID ,
							          DateCaptured ,
							          VirementId ,
							          AdjustmentId
							        )
							SELECT @BudgetVersionId ,
									ppim.ProjectItemMonth_ID ,
									ppim.PlanProjectItemID ,
									ppim.MonthID ,
									ppim.UnitQuantity ,
									ppim.UnitPrice ,
									@userId , -- CapturerID - int
									GETDATE(),  -- DateCaptured - datetime
									ppim.VirementId ,
									ppim.AdjustmentId 
									FROM    dbo.Plan_Project AS PP
                                            INNER JOIN Plan_ProjectItem AS PPI ON PP.Project_ID = PPI.ProjectID
											INNER JOIN dbo.Plan_ProjectItemMonth ppim ON ppim.PlanProjectItemID = PPI.PlanProjectItem_ID
                                    WHERE   PP.FinYear = @FinYear
                                            AND ISNULL(PP.IsDeleted, 0) = 0;

                            COMMIT TRANSACTION;
                            SET @CreateBudgetVersionResult = 'success';
                        END;
                    ELSE
                        BEGIN
                            ROLLBACK TRANSACTION;
                            SET @CreateBudgetVersionResult = 'Budget Version id not found & Budget Version Detail Entry Skipped';
                        END;
                END;
            ELSE
                BEGIN
                    ROLLBACK TRANSACTION;
                    SET @CreateBudgetVersionResult = 'Budget Version - '
                        + @VersionNumber + ' is already generated';
                END;
        END TRY
        BEGIN CATCH
            SET @CreateBudgetVersionResult = ERROR_MESSAGE();
            RAISERROR (@CreateBudgetVersionResult, 16,1);
            ROLLBACK TRANSACTION;
        END CATCH;

        SELECT  @CreateBudgetVersionResult AS Result ,
                @BudgetVersionId AS BudgetVersionId ,
                @VersionNumber AS VersionNumber;

    END;
GO

