-- =============================================
-- Author:		Sahil Nagpal 
-- Create date: 2016-12-26
-- Description:	Get Lastest Virement Policy Version Number
-- CALL SP: Plan_CreateVirementPolicyVersion_sp '2018/2019','2018/2019_VP001','Version Name','Comments','1'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_CreateVirementPolicyVersion_sp]
	@FinYear NVARCHAR(18) ,
    @VersionNumber NVARCHAR(50) ,
    @VersionName NVARCHAR(1000) ,
    @Comments NVARCHAR(1000) ,
	@IsCouncilApproved BIT,
	@FileName NVARCHAR(500),

    @userId INT
AS
    BEGIN
        SET NOCOUNT ON;

        DECLARE @VirementVersionId INT = 0 ,
            @CreateVirementVersionResult NVARCHAR(MAX)= '';

        BEGIN TRY
            BEGIN TRANSACTION;

            IF NOT EXISTS ( SELECT  1
                            FROM    dbo.Plan_VirementPolicyVersion
                            WHERE   VersionNumber = @VersionNumber )
                BEGIN
                   INSERT INTO dbo.Plan_VirementPolicyVersion
                   (
                       FinancialYear,VersionNumber,VersionName,Comments,
                       IsCouncilApprovedPolicy,ApprovedVirementPolicyFileName,DateCaptured,CapturerID
                   )
                   VALUES
                   (  @FinYear,@VersionNumber,@VersionName, @Comments,
                      @IsCouncilApproved, @FileName, GETDATE(),@userId
                   )
                

                    SELECT  @VirementVersionId = SCOPE_IDENTITY();

                    IF ( @VirementVersionId <> 0 )
                        BEGIN
                            INSERT INTO dbo.Plan_VirementPolicyVersionDetail
                            (
                                VirementPolicyVersionID,VirementRule_ID,[Priority],VirementDesc,VirementDefinition,
                                VirementRuleDesc,BusinessRule,[Enabled],[Option],Lockdown,FinYear,PreviousReferenceId,
                                DateCaptured,CapturerID
                            )
                            SELECT @VirementVersionId,VirementRule_ID,[Priority],VirementDesc,VirementDefinition,
                                   VirementRuleDesc,BusinessRule,[Enabled],[Option],Lockdown, FinYear,PreviousReferenceId,
								   GETDATE(),@userId
							FROM dbo.Const_PlanVirementRules_sys WHERE FinYear= @FinYear

							--Update current Virement policy to Latest Version
							UPDATE Const_PlanVirementRules_sys SET VirementPolicyVersionID = @VirementVersionId WHERE FinYear= @FinYear

                            COMMIT TRANSACTION;
                            SET @CreateVirementVersionResult = 'success';
                        END;
                    ELSE
                        BEGIN
                            ROLLBACK TRANSACTION;
                            SET @CreateVirementVersionResult = 'Virement Policy Version id not found & Virement Policy Version Detail Entry Skipped';
                        END;
                END;
            ELSE
                BEGIN
                    ROLLBACK TRANSACTION;
                    SET @CreateVirementVersionResult = 'Virement Policy Version - '
                        + @VersionNumber + ' is already generated';
                END;
        END TRY
        BEGIN CATCH
            SET @CreateVirementVersionResult = ERROR_MESSAGE();
            RAISERROR (@CreateVirementVersionResult, 16,1);
            ROLLBACK TRANSACTION;
        END CATCH;

        SELECT  @CreateVirementVersionResult AS Result ,
                @VirementVersionId AS VirementVersionId ,
                @VersionNumber AS VersionNumber;

				 --SELECT TOP 1  'result' AS Result ,1 AS VirementVersionId , '123' AS VersionNumber 
				 --FROM Plan_VirementPolicyVersionDetail;

    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_DailyBudgetConsumption_sp]    Script Date: 2026/03/10 7:23:30 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- Author: NParikh 30-07-2019  - Plan_BudgetRegister Order by should be DateCaptured
CREATE PROCEDURE [dbo].[Plan_DailyBudgetConsumption_sp]
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRAN;
    BEGIN TRY

        DECLARE @BudgetFileName NVARCHAR(1000);
        SELECT TOP 1
               @BudgetFileName = FileName
        FROM GL_TransactionsImport;


        IF NOT EXISTS
        (
            SELECT 1
            FROM Plan_BudgetRegister
            WHERE BudgetTransactionTypeID = 5
                  AND PK_TransactionID IN
                      (
                          SELECT ID
                          FROM Led_GeneralLedger_NTSCOAReport
                          WHERE FileName = @BudgetFileName
                      )
        )
        BEGIN

            DECLARE @BudgetTxnTypeId INT,
                    @ModuleId INT,
                    @CapturedDate DATETIME = GETDATE(),
                    @strScript NVARCHAR(MAX);

            SELECT @BudgetTxnTypeId = BudgetTransactionType_ID
            FROM dbo.Const_BudgetTransactionType_sys
            WHERE BudgetTransDesc = 'Imported';
            SELECT @ModuleId = Module_ID
            FROM dbo.User_Module
            WHERE ModuleDesc = 'Planning';

            SELECT RowNumber
            INTO #ControlTable
            FROM GL_TransactionsImport;

            DECLARE @TableID INT;


            WHILE EXISTS (SELECT * FROM #ControlTable)
            BEGIN

                SELECT TOP 1
                       @TableID = RowNumber
                FROM #ControlTable
                ORDER BY RowNumber ASC;
                --inserting of budget cosumption will go here  
                INSERT INTO dbo.Plan_BudgetRegister
                (
                    PlanProjectItemID,
                    BudgetTransactionTypeID,
                    ModuleID,
                    PK_TransactionID,
                    TransactionTableName,
                    TransactionAmount,
                    AvailableBudget,
                    CapturerID,
                    DateCaptured,
                    FinYear
                )
                SELECT PlanProjectItemID,
                       @BudgetTxnTypeId,
                       @ModuleId,
                       ID,
                       'Led_GeneralLedger_NTSCOAReport',
                       CreditDebitAmount,
                       (AvailableBudget + CreditDebitAmount),
                       1,
                       DATEADD(ss, RowNumber, GETDATE()),
                       FinYear
                FROM
                (
                    SELECT TOP 1
                           BudgetRegister_ID,
                           PlanProjectItemID,
                           AvailableBudget
                    FROM Plan_BudgetRegister
                    WHERE PlanProjectItemID =
                    (
                        SELECT Optional1 FROM GL_TransactionsImport WHERE RowNumber = @TableID
                    )
                    ORDER BY DateCaptured DESC
                ) availbud
                    INNER JOIN
                    (
                        SELECT glm.ID,
                               gti.Optional1,
                               gti.RowNumber,
                               gti.FinYear,
                               (CASE
                                    WHEN ISNULL(gti.Credit, 0) = 0
                                         AND pbr.AvailableBudget > 0 THEN
                                        -ABS(gti.Debit)
                                    WHEN ISNULL(gti.Credit, 0) <> 0
                                         AND pbr.AvailableBudget > 0 THEN
                                        ABS(gti.Credit)
                                    WHEN ISNULL(gti.Credit, 0) = 0
                                         AND pbr.AvailableBudget < 0 THEN
                                        ABS(gti.Debit)
                                    WHEN ISNULL(gti.Credit, 0) <> 0
                                         AND pbr.AvailableBudget < 0 THEN
                                        -ABS(gti.Credit)
                                END
                               ) AS CreditDebitAmount
                        FROM GL_TransactionsImport gti
                            INNER JOIN Led_GeneralLedger_NTSCOAReport glm
                                ON gti.RowNumber = glm.RowNumber
                                   AND gti.[FileName] = glm.[FileName]
                            INNER JOIN Plan_BudgetRegister pbr
                                ON pbr.PlanProjectItemID = gti.Optional1
                                   AND pbr.BudgetTransactionTypeID = 1
                        WHERE gti.RowNumber = @TableID
                    ) Consum
                        ON availbud.PlanProjectItemID = Consum.Optional1;

                DELETE #ControlTable
                WHERE RowNumber = @TableID;

            END;
            DROP TABLE #ControlTable;
        END;
        ELSE
        BEGIN
            PRINT ('File already Imported');
        END;
        COMMIT TRAN;

    END TRY
    BEGIN CATCH
        DECLARE @ErrorNumber INT = ERROR_NUMBER();
        DECLARE @ErrorLine INT = ERROR_LINE();
        DECLARE @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
        DECLARE @ErrorSeverity INT = ERROR_SEVERITY();
        DECLARE @ErrorState INT = ERROR_STATE();

        PRINT 'Actual error number: ' + CAST(@ErrorNumber AS VARCHAR(10));
        PRINT 'Actual line number: ' + CAST(@ErrorLine AS VARCHAR(10));
        PRINT 'Actual line MESSAGE: ' + CAST(@ErrorMessage AS VARCHAR(1000));
        RAISERROR(@ErrorMessage, @ErrorSeverity, @ErrorState);
        ROLLBACK;
    END CATCH;
END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_DailyBudgetReport]    Script Date: 2026/03/10 7:23:31 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:			Chris Moodley
-- Create date:	January 2026
-- Description:		Returns data for daily budget report for BI
-- Plan_DailyBudgetReport '2025/2026', 1, 6, '1,2'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_DailyBudgetReport]
	-- Add the parameters for the stored procedure here
	@finYear NVARCHAR(10) = '2025/2026',
	@fromMonth INT = 1,
	@toMonth INT = 6,
	--@department to be passed as comma separated list of Department IDs
	@department NVARCHAR(1000) = '1,2'
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	SELECT	
		 ppi.FinYear
		,dept.DepartmentDesc AS Directorate
		,div.DivisionDesc AS Division
		,ISNULL(ppi.HistoricalProjectCode, '') AS UKey
		,ppi.PlanProjectItem_ID AS PPID
		,SUBSTRING(item.ScoaCode, 1, 2) AS ItemType
		,ISNULL(cpi.ItemDescription, item.ScoaShortDesc) AS ItemDescription
		,ISNULL(ob.Actual, 0) AS OpeningBalance
		,ISNULL(ppi.BudgetAmount, 0) AS CurrentYearBudget
		,ISNULL(bc.ReserveToDate, 0) AS Reservations
		,ISNULL(bc.CommitToDate, 0) AS Commitments
		,ISNULL(bc.ActualToDate, 0) AS Actual
		,ISNULL(bc.AvailableBudget, 0) AS BudgetAvailable
		,ABS(CASE WHEN bc.ActualToDate = 1 AND ppi.BudgetAmount = 0 THEN 101.00 ELSE CONVERT(DECIMAL(18,2), (bc.ActualToDate * 100) / (CASE WHEN ppi.BudgetAmount = 0 THEN 1 ELSE ppi.BudgetAmount END)) END) AS PercentActualVsBudget
		,ISNULL(ppi.BudgetAmountCurP1, 0) AS BudgetYearPlus1
		,ISNULL(ppi.BudgetAmountCurP2, 0) AS BudgetYearPlus2
		,ISNULL(ActualPeriod1, 0) AS ActualPeriod1
		,ISNULL(ActualPeriod2, 0) AS ActualPeriod2
		,ISNULL(ActualPeriod3, 0) AS ActualPeriod3
		,ISNULL(ActualPeriod4, 0) AS ActualPeriod4
		,ISNULL(ActualPeriod5, 0) AS ActualPeriod5
		,ISNULL(ActualPeriod6, 0) AS ActualPeriod6
		,ISNULL(ActualPeriod7, 0) AS ActualPeriod7
		,ISNULL(ActualPeriod8, 0) AS ActualPeriod8
		,ISNULL(ActualPeriod9, 0) AS ActualPeriod9
		,ISNULL(ActualPeriod10, 0) AS ActualPeriod10
		,ISNULL(ActualPeriod11, 0) AS ActualPeriod11
		,ISNULL(ActualPeriod12, 0) AS ActualPeriod12
		,ISNULL(ActualPeriod13, 0) AS ActualPeriod13
		,ISNULL(ActualPeriod14, 0) AS ActualPeriod14
		,ISNULL(ActualPeriod15, 0) AS ActualPeriod15
		,ISNULL(ppim1.UnitPrice, 0) AS BudgetPeriod1
		,ISNULL(ppim2.UnitPrice, 0) AS BudgetPeriod2
		,ISNULL(ppim3.UnitPrice, 0) AS BudgetPeriod3
		,ISNULL(ppim4.UnitPrice, 0) AS BudgetPeriod4
		,ISNULL(ppim5.UnitPrice, 0) AS BudgetPeriod5
		,ISNULL(ppim6.UnitPrice, 0) AS BudgetPeriod6
		,ISNULL(ppim7.UnitPrice, 0) AS BudgetPeriod7
		,ISNULL(ppim8.UnitPrice, 0) AS BudgetPeriod8
		,ISNULL(ppim9.UnitPrice, 0) AS BudgetPeriod9
		,ISNULL(ppim10.UnitPrice, 0) AS BudgetPeriod10
		,ISNULL(ppim11.UnitPrice, 0) AS BudgetPeriod11
		,ISNULL(ppim12.UnitPrice, 0) AS BudgetPeriod12
		,pp.ProjectName
		,proj.ScoaShortDesc AS Project
		,func.ScoaShortDesc AS [Function]
		,fund.ScoaShortDesc AS Fund
		,region.ScoaShortDesc AS Region
		,cost.ScoaShortDesc AS Cost
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](item.ScoaDesc, ':') WHERE ID = 1), '')  AS Level1
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](item.ScoaDesc, ':') WHERE ID = 2), '')  AS Level2
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](item.ScoaDesc, ':') WHERE ID = 3), '')  AS Level3
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](item.ScoaDesc, ':') WHERE ID = 4), '')  AS Level4
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](item.ScoaDesc, ':') WHERE ID = 5), '')  AS Level5
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](item.ScoaDesc, ':') WHERE ID = 6), '')  AS Level6
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](item.ScoaDesc, ':') WHERE ID = 7), '')  AS Level7
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](item.ScoaDesc, ':') WHERE ID = 8), '')  AS Level8
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](item.ScoaDesc, ':') WHERE ID = 9), '')  AS Level9
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](item.ScoaDesc, ':') WHERE ID = 10), '') AS Level10
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](item.ScoaDesc, ':') WHERE ID = 11), '') AS Level11
		,ISNULL((SELECT [Value] FROM [dbo].[Split_fxn](item.ScoaDesc, ':') WHERE ID = 12), '') AS Level12
		,proj.ScoaCode AS ProjectCode
		,func.ScoaCode AS FunctionCode
		,fund.ScoaCode AS FundCode
		,item.ScoaCode AS ItemCode
		,region.ScoaCode AS RegionCode
		,cost.ScoaCode AS CostingCode
		,div.DivisionCode AS MSCCode
		,proj.ScoaDesc AS mScoaProject
		,func.ScoaDesc AS mScoaFunction
	FROM
		Plan_ProjectItem ppi
		INNER JOIN Plan_Project pp ON ppi.ProjectID = pp.Project_ID
		INNER JOIN Const_SCOA_Project_Structure_Consolidated proj ON pp.ScoaProjectID = proj.ScoaID AND proj.FinYearText = @finYear
		INNER JOIN Const_Division div ON ppi.DivisionId = div.Division_ID
		INNER JOIN Const_Department dept ON div.DepartmentID = dept.Department_ID
		INNER JOIN Plan_Const_SCOA_Structure_Consolidated_vw item ON ppi.SCOAItemID = item.ScoaID AND item.FinYearText = @finYear
		LEFT JOIN Const_ProjectItem cpi ON ppi.ProjectItemID = cpi.ProjectItem_ID
		INNER JOIN Const_SCOA_Function_Structure_Consolidated func ON ppi.SCOAFunctionId = func.ScoaID AND func.FinYearText = @finYear
		INNER JOIN Const_SCOA_Funds_Structure_Consolidated fund ON ppi.SCOAFundId = fund.ScoaID and fund.FinYearText = @finYear
		INNER JOIN Const_SCOA_Regional_Structure_Consolidated region ON ppi.SCOARegionId = region.ScoaID AND region.FinYearText = @finYear
		INNER JOIN Const_SCOA_Costing_Structure_Consolidated cost ON ppi.SCOACostingID = cost.ScoaID AND cost.FinYearText = @finYear
		INNER JOIN Plan_ProjectItemMonth ppim1 ON ppi.PlanProjectItem_ID = ppim1.PlanProjectItemID AND ppim1.MonthID = 7
		INNER JOIN Plan_ProjectItemMonth ppim2 ON ppi.PlanProjectItem_ID = ppim2.PlanProjectItemID AND ppim2.MonthID = 8
		INNER JOIN Plan_ProjectItemMonth ppim3 ON ppi.PlanProjectItem_ID = ppim3.PlanProjectItemID AND ppim3.MonthID = 9
		INNER JOIN Plan_ProjectItemMonth ppim4 ON ppi.PlanProjectItem_ID = ppim4.PlanProjectItemID AND ppim4.MonthID = 10
		INNER JOIN Plan_ProjectItemMonth ppim5 ON ppi.PlanProjectItem_ID = ppim5.PlanProjectItemID AND ppim5.MonthID = 11
		INNER JOIN Plan_ProjectItemMonth ppim6 ON ppi.PlanProjectItem_ID = ppim6.PlanProjectItemID AND ppim6.MonthID = 12
		INNER JOIN Plan_ProjectItemMonth ppim7 ON ppi.PlanProjectItem_ID = ppim7.PlanProjectItemID AND ppim7.MonthID = 1 
		INNER JOIN Plan_ProjectItemMonth ppim8 ON ppi.PlanProjectItem_ID = ppim8.PlanProjectItemID AND ppim8.MonthID = 2 
		INNER JOIN Plan_ProjectItemMonth ppim9 ON ppi.PlanProjectItem_ID = ppim9.PlanProjectItemID AND ppim9.MonthID = 3
		INNER JOIN Plan_ProjectItemMonth ppim10 ON ppi.PlanProjectItem_ID = ppim10.PlanProjectItemID AND ppim10.MonthID = 4 
		INNER JOIN Plan_ProjectItemMonth ppim11 ON ppi.PlanProjectItem_ID = ppim11.PlanProjectItemID AND ppim11.MonthID = 5 
		INNER JOIN Plan_ProjectItemMonth ppim12 ON ppi.PlanProjectItem_ID = ppim12.PlanProjectItemID AND ppim12.MonthID = 6
		LEFT JOIN
			(
				SELECT SUM(Debit) - SUM(Credit) Actual, PlanProjectItemID
				FROM Led_GeneralLedger
				WHERE FinYear = @finYear AND ProcessingMonth BETWEEN @fromMonth AND @toMonth AND TransactionTypeID = 14
				GROUP BY PlanProjectItemID
			) ob ON ppi.PlanProjectItem_ID = ob.PlanProjectItemID
		LEFT JOIN
			(
				SELECT MAX(BudgetConsumption_ID) BudgetConsumptionID, PlanProjectItemID
				FROM Plan_BudgetConsumption
				WHERE FinYear = @finYear AND ProcessingMonth BETWEEN @fromMonth AND @toMonth
				GROUP BY PlanProjectItemID
			) bcMax ON ppi.PlanProjectItem_ID = bcMax.PlanProjectItemID
		LEFT JOIN Plan_BudgetConsumption bc ON bcMax.BudgetConsumptionID = bc.BudgetConsumption_ID
		LEFT JOIN
			(
				SELECT
				 PlanProjectItemID
				,ISNULL(SUM(CASE ProcessingMonth WHEN 1 THEN Actual END), 0) AS ActualPeriod1
				,ISNULL(SUM(CASE ProcessingMonth WHEN 2 THEN Actual END), 0) AS ActualPeriod2
				,ISNULL(SUM(CASE ProcessingMonth WHEN 3 THEN Actual END), 0) AS ActualPeriod3
				,ISNULL(SUM(CASE ProcessingMonth WHEN 4 THEN Actual END), 0) AS ActualPeriod4
				,ISNULL(SUM(CASE ProcessingMonth WHEN 5 THEN Actual END), 0) AS ActualPeriod5
				,ISNULL(SUM(CASE ProcessingMonth WHEN 6 THEN Actual END), 0) AS ActualPeriod6
				,ISNULL(SUM(CASE ProcessingMonth WHEN 7 THEN Actual END), 0) AS ActualPeriod7
				,ISNULL(SUM(CASE ProcessingMonth WHEN 8 THEN Actual END), 0) AS ActualPeriod8
				,ISNULL(SUM(CASE ProcessingMonth WHEN 9 THEN Actual END), 0) AS ActualPeriod9
				,ISNULL(SUM(CASE ProcessingMonth WHEN 10 THEN Actual END), 0) AS ActualPeriod10
				,ISNULL(SUM(CASE ProcessingMonth WHEN 11 THEN Actual END), 0) AS ActualPeriod11
				,ISNULL(SUM(CASE ProcessingMonth WHEN 12 THEN Actual END), 0) AS ActualPeriod12
				,ISNULL(SUM(CASE ProcessingMonth WHEN 13 THEN Actual END), 0) AS ActualPeriod13
				,ISNULL(SUM(CASE ProcessingMonth WHEN 14 THEN Actual END), 0) AS ActualPeriod14
				,ISNULL(SUM(CASE ProcessingMonth WHEN 15 THEN Actual END), 0) AS ActualPeriod15
			FROM
				(
					SELECT
						 gl.PlanProjectItemID
						,ProcessingMonth
						,ABS (
									SUM(CASE 
											WHEN css.ScoaCode LIKE '%IE%' OR css.ScoaCode LIKE '%IA%'
												THEN ISNULL(gl.Debit,0) - ISNULL(gl.Credit,0)
											WHEN css.ScoaCode LIKE '%IR%' OR css.ScoaCode LIKE '%IL%'
												THEN ISNULL(gl.Credit,0) - ISNULL(gl.Debit,0)
											ELSE 0
										END)
							) AS Actual
						FROM 
							Led_GeneralLedger gl
							INNER JOIN Plan_Const_SCOA_Structure_Consolidated_vw css ON gl.ScoaItemID = css.ScoaID AND css.FinYearText = @finYear
						WHERE 
							gl.FinYear = @finYear
							AND gl.ExtraLinkID_3 IS NULL
							AND ISNULL(gl.ExtraLinkDesc, '') <> 'GRN ID'
						GROUP BY 
							gl.PlanProjectItemID, gl.ProcessingMonth
				) gl
			GROUP BY
				PlanProjectItemID
		) glMonth ON ppi.PlanProjectItem_ID = glMonth.PlanProjectItemID
	WHERE
		ppi.FinYear = @finYear
		AND ProjectStatus =24 
		AND ISNULL(IsDeleted, 0) <> 1
		AND DepartmentID IN (SELECT [Value] FROM dbo.Split_fxn(@department, ','))

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_DeleteProject_sp]    Script Date: 2026/03/10 7:23:31 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Raindree Chetty
-- Create date: 23/12/2015
-- Description:	Delete project
-- Calls: Plan_DeleteProject_sp 61
-- 2015 12 28  by RC :Added delete of Plan_ProjectRegions
-- 2017 03 28 by SNagpal: Changes into delete Plan_ProjectIDP
-- 2017 05 18 by SNagpal: Add delete functionality for Plan_ProjectIDP, Plan_ProjectFunctions, Plan_ProjectDivisions, Plan_ProjectCosting
-- =============================================
CREATE PROCEDURE [dbo].[Plan_DeleteProject_sp]
	@ProjectID int
AS
BEGIN
	BEGIN TRY
	BEGIN TRANSACTION
		DELETE IDP_Item
		WHERE Item_ID IN (
			SELECT idp.Item_ID
			FROM dbo.Plan_ProjectIDP project
			INNER JOIN IDP_Item idp ON project.ProjectIDPItemID=idp.Item_ID
			WHERE project.ProjectID=@ProjectID
		)

		DELETE FROM Plan_ProjectIDP
		WHERE ProjectID=@ProjectID

		DELETE FROM Plan_ProjectItemMonth
		WHERE ProjectItemMonth_ID IN (
			SELECT ProjectItemMonth_ID
			FROM Plan_ProjectItemMonth m
			INNER JOIN Plan_ProjectItem i ON m.PlanProjectItemID=i.PlanProjectItem_ID
			WHERE i.ProjectID=@ProjectID
		)

		DELETE FROM Plan_ProjectItem
		WHERE ProjectID=@ProjectID

		DELETE FROM Plan_ProjectFundYear
		WHERE ProjectFundYear_ID IN (
			SELECT ProjectFundYear_ID
			FROM Plan_ProjectFundYear fy
			INNER JOIN Plan_ProjectFund f ON fy.ProjectFundID=f.ProjectFund_ID
			WHERE ProjectID=@ProjectID
		)		
		
		DELETE FROM Plan_ProjectFunctions
		WHERE ProjectID=@ProjectID

		DELETE FROM Plan_ProjectDivisions
		WHERE ProjectID=@ProjectID

		DELETE FROM Plan_ProjectCosting
		WHERE ProjectID=@ProjectID

		DELETE FROM Plan_ProjectRegions
		WHERE ProjectID=@ProjectID

		DELETE FROM Plan_ProjectFund
		WHERE ProjectID=@ProjectID

		DELETE FROM Plan_project
		WHERE Project_ID=@ProjectID

	COMMIT TRANSACTION
	
	Select 'No Errors' as 'Result'
end try
begin catch
	if @@Trancount > 0 
	begin 
		rollback transaction
		Insert into Sys_ErrorLog (moduleName, pageName, procedureName, errorMessage, errorType, detailedErrorMessage, errorDate, userName)
		Values ('Planning','SQL Server','Plan_DeleteProject_sp', ERROR_MESSAGE(), 'SQL', ERROR_MESSAGE(), GETDATE(), 'SQL')
		
		declare @Err nvarchar(1000)
		Set @err = Error_message()
		Raiserror (@Err, 16,1)
		
		Select @Err as 'Result'
	end
 end catch
END

GO

/****** Object:  StoredProcedure [dbo].[Plan_FundAvailablityReport]    Script Date: 2026/03/10 7:23:31 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- ==============================================================
-- Author:  Niren P
-- Create date: 02/22/2016
-- Description: Get report data
--Plan_FundAvailablityReport '2019/2020,2020/2021,2021/2022,'
--SN 04/04/2016 -- Add Distinct
-- JPrajapati 08/03/2016 - Show Only Records that are not hidden by Administrator
--01-02-2017 By RChetty: Added curfinyear and passed into Planing_GetFundAllocatedAmount as a Parameter
-- SNagpal 21r-02-2019 : 84009, Get SCOA Segments based upon FinYear, 
-- OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- SNagpal 07-06-2019 : Replace Const_SCOA_Funds_Structure with Const_SCOA_Funds_StructureByyear(@crFinYear)
-- ==============================================================
CREATE PROCEDURE [dbo].[Plan_FundAvailablityReport]
    @FinancialYear VARCHAR(50)
-- WITH ENCRYPTION, RECOMPILE, EXECUTE AS CALLER|SELF|OWNER| 'user_name'
AS
SET NOCOUNT ON;
DECLARE @crFinYear NVARCHAR(10);
SELECT TOP 1  @crFinYear = splitdata FROM    dbo.fnSplitString(@FinancialYear, ',')

    SELECT DISTINCT
            T.ScoaShortDesc AS ShortDescription ,
            T.Budget AS Available ,
            T.Allocated AS Allocated ,
            ( T.Budget - T.Allocated ) AS Remain ,
            T.FinancialYear AS FinancialYear
    FROM    ( SELECT    CSS.ScoaShortDesc ,
                        dbo.Planing_GetFundAvailableAmount(Plan_FundingSourceBudget_Detail.ScoaID,
                                                           FinancialYear) AS Budget ,
                        dbo.Planing_GetFundAllocatedAmount(Plan_FundingSourceBudget_Detail.ScoaID,
                                                           FinancialYear,@crFinYear) AS Allocated ,
                        FinancialYear
              FROM      dbo.Plan_FundingSourceBudget_Header
                        INNER JOIN Plan_FundingSourceBudget_Detail ON Plan_FundingSourceBudget_Detail.FundingSourceBudgetHeaderID = Plan_FundingSourceBudget_Header.FundingSourceBudgetHeader_ID
                        INNER JOIN dbo.Const_Scoa_Funds_Structure_ByYear(@crFinYear) AS CSS ON CSS.ScoaID = Plan_FundingSourceBudget_Detail.ScoaID
              WHERE     FinancialYear IN (
                        SELECT  splitdata
                        FROM    dbo.fnSplitString(@FinancialYear, ',') )
                        AND ISNULL(Plan_FundingSourceBudget_Detail.IsHidden, 0) = 0
            ) AS T
    ORDER BY FinancialYear;




GO

/****** Object:  StoredProcedure [dbo].[Plan_FundingSourceBudget_sp]    Script Date: 2026/03/10 7:23:31 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- ==============================================================
-- Author:		Chris Moodley
-- Create date: 09 November 2014
-- Description:	Return funding source budgets per financial year
-- 11/02/2016 Nomalizo Funding source is not mandatory anymore inner join changed to left join. (TP #31782)
-- SNagpal 03-05-2019 : 88070, Get SCOA Segments based upon FinYear. Add new parameter @strActiveFinyear
-- Plan_FundingSourceBudget_sp '2018/2019','2018/2019'
-- SNagpal 17-05-2019: Add new MultiYear concept
-- ==============================================================
CREATE PROCEDURE [dbo].[Plan_FundingSourceBudget_sp] 
	-- Add the parameters for the stored procedure here
	@financialYear NVARCHAR(50),
	@strActiveFinyear NVARCHAR(10)
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;


    -- Insert statements for procedure here
	SELECT
		FundingSourceBudgetHeader_ID,
		FundingSourceBudgetDetail_ID,
		FinancialYear,
		FundingSourceID, 
		ISNULL(FundingSourceDesc,'') AS FundingSourceDesc,
		fundBudgetDetail.ScoaID,
		ScoaCode,
		ScoaDesc,
		FundingSourceBudget,
		ScoaShortDesc,
		Submitted
	FROM
		Plan_FundingSourceBudget_Header fundBudgetHeader LEFT JOIN			
		Plan_FundingSourceBudget_Detail fundBudgetDetail ON fundBudgetHeader.FundingSourceBudgetHeader_ID = fundBudgetDetail.FundingSourceBudgetHeaderID 
		LEFT JOIN Const_FundingSource fundSource ON fundBudgetDetail.FundingSourceID = fundSource.FundingSource_ID 
		INNER JOIN dbo.Const_Scoa_Funds_Structure_ByYear(@strActiveFinyear) scoaFund ON fundBudgetDetail.ScoaID = scoaFund.ScoaID
		WHERE FinancialYear = @financialYear OR ISNULL(FinancialYear, '') = ISNULL(@financialYear, ISNULL(FinancialYear, ''));
		
END




GO

/****** Object:  StoredProcedure [dbo].[Plan_FundingSourceBudgetMultiYear_sp]    Script Date: 2026/03/10 7:23:31 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- ==============================================================
-- Author:    Nomalizo Nomganga/Raindree Chetty
-- Create date: 22 February 2016 (TP #31782)
-- Calls: Plan_FundingSourceBudgetMultiYear_sp '2015/2016',0   -- Show All Funds
-- Calls: Plan_FundingSourceBudgetMultiYear_sp '2016/2017',1   -- Show Funds having R0 value for All 3 years
-- Calls: Plan_FundingSourceBudgetMultiYear_sp '2018/2019',0   -- Show Funds having budget > 0 for atleast one of Fund Year
-- Description: Return funding source budgets for multiple years given cuurent finyear
-- update date: 02 March 2016 (TP #30331) Jignesh Prajapati
-- Description: Update Fields with values in case of NULL results
-- update date: 20 July 2016 (TP #38202) Jignesh Prajapati
-- Description: Add Category Field - SCOA Fund Desc with Level1 added
-- update date: 28 July 2016 (TP #38202) Jignesh Prajapati
-- Description: Add Parameter to Show/Hide Details only for Zero Valued Funds
-- update date: 29 July 2016 (TP #38202) Jignesh Prajapati
-- Description: Show Only Record having budget > 0 for atleast one of Fund Year
-- update date: 03 Aug 2016 (TP #38202) Jignesh Prajapati
-- Description: IsHidden Flag is considered as false if found Null 
-- update date: 28 Nov 2016 change the where condition where  @ShowOnlyZerovaluedFunds =-1
-- Description: #49194 Users that do not have access to see R0funding will only be able to see R0 funding that is not hidden.
-- update date: 08 Dec 2016 Remove LEVEL1_FUND concept and Add Split function to get Category
-- 21/02/2017 SNagpal: Add Column for UploadedDocument
-- 06/10/2017 SNagpal: #63157 2.1 Remove functionality of ShowOnlyZerovaluedFunds
--						Add columns for Allocated and Remaining amounts. Also remove unwanted columns
-- 04/02/2018 SNagpal: Remove fundingsource conditions --AND D.FundingSourceID = currentYear.FundingSourceID
-- 10/12/2018 SNagpal: #82739 As fundingsource conditions are removed previously, So No need that in group by. Comment --D.FundingSourceID ,
-- SNagpal 20-02-2019 : 84009, Get SCOA Segments based upon FinYear
-- OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- ==============================================================
CREATE PROCEDURE [dbo].[Plan_FundingSourceBudgetMultiYear_sp] 
       -- Add the parameters for the stored procedure here
    @FinYear NVARCHAR(50) ,
    @ShowOnlyZerovaluedFunds INT = 0
AS
    BEGIN
       -- SET NOCOUNT ON added to prevent extra result sets from
       -- interfering with SELECT statements.
        SET NOCOUNT ON;
        DECLARE @FinYearP1 NVARCHAR(9) ,
            @FinYearP2 NVARCHAR(9) ,
            @yearp1 INT ,
            @yearp2 INT ,
            @yearp3 INT;

        SELECT  @yearp1 = CAST(SUBSTRING(@FinYear, 6, 4) AS INT);
        SELECT  @yearp2 = @yearp1 + 1;
        SELECT  @yearp3 = @yearp1 + 2;
        SELECT  @FinYearP1 = CONVERT(VARCHAR(4), @yearp1) + '/'
                + CONVERT(VARCHAR(4), @yearp2);
        SELECT  @FinYearP2 = CONVERT(VARCHAR(4), @yearp2) + '/'
                + CONVERT(VARCHAR(4), @yearp3);
  
            -- Insert statements for procedure here
		SELECT  *, (ISNULL(FundingSourceBudget,0) - ISNULL(AllocatedCurrFinYear,0)) AS RemainingCurrFinYear
			,(ISNULL(FundingSourceBudgetCurrYearPlus1,0) - ISNULL(AllocatedCurrYearPlus1,0)) AS RemainingCurrFinYearPlus1,
			(ISNULL(FundingSourceBudgetCurrYearPlus2,0) - ISNULL(AllocatedCurrYearPlus2,0)) AS RemainingCurrFinYearPlus2
            FROM    ( SELECT    currentYear.FundingSourceBudgetHeader_ID ,
                                currentYear.FundingSourceBudgetDetail_ID ,
                                currentYear.FinancialYear ,
                                currentYear.FundingSourceID ,
                                ISNULL(currentYear.FundingSourceDesc, '''') AS FundingSourceDesc ,
                                currentYear.ScoaID ,
                                currentYear.ScoaCode ,
                                currentYear.ScoaDesc ,
                                currentYear.FundingSourceBudget ,
								dbo.Planing_GetFundAllocatedAmount(currentYear.ScoaID,currentYear.FinancialYear, currentYear.FinancialYear) AS AllocatedCurrFinYear,
                                currentYear.ScoaShortDesc ,
                                ISNULL(currentYear.Submitted,0) AS Submitted,
								currentYear.UploadedDocument AS UploadedDocument,
                                @FinYearP1 AS FinancialYearCurrYearPlus1 ,
                                ISNULL(( SELECT SUM(D.FundingSourceBudget)
                                         FROM   dbo.Plan_FundingSourceBudget_Detail
                                                AS D
                                                INNER JOIN dbo.Plan_FundingSourceBudget_Header
                                                AS H ON D.FundingSourceBudgetHeaderID = H.FundingSourceBudgetHeader_ID
                                                        AND H.FinancialYear = @FinYearP1
                                                        AND D.ScoaID = currentYear.ScoaID
                                         GROUP BY D.FundingSourceBudgetHeaderID ,
                                                D.ScoaID
                                       ), 0) AS FundingSourceBudgetCurrYearPlus1 ,
									    dbo.Planing_GetFundAllocatedAmount(currentYear.ScoaID,
                                                              @FinYearP1 , currentYear.FinancialYear) AS AllocatedCurrYearPlus1,
                                @FinYearP2 AS FinancialYearCurrYearPlus2 ,
                                ISNULL(( SELECT SUM(D.FundingSourceBudget)
                                         FROM   dbo.Plan_FundingSourceBudget_Detail
                                                AS D
                                                INNER JOIN dbo.Plan_FundingSourceBudget_Header
                                                AS H ON D.FundingSourceBudgetHeaderID = H.FundingSourceBudgetHeader_ID
                                                        AND H.FinancialYear = @FinYearP2 
                                                        AND D.ScoaID = currentYear.ScoaID
                                         GROUP BY D.FundingSourceBudgetHeaderID ,
                                                D.ScoaID
                                       ), 0) AS FundingSourceBudgetCurrYearPlus2 ,
									   dbo.Planing_GetFundAllocatedAmount(currentYear.ScoaID,
                                                              @FinYearP2 , currentYear.FinancialYear) AS AllocatedCurrYearPlus2,
							   (SELECT Value FROM dbo.Split_fxn(currentYear.ScoaDesc,':') WHERE id = 2) AS Category
				
                      FROM      ( SELECT    FundingSourceBudgetHeader_ID ,
                                            FundingSourceBudgetDetail_ID ,
                                            FinancialYear ,
                                            FundingSourceID ,
                                            ISNULL(FundingSourceDesc, '') AS FundingSourceDesc ,
                                            fundBudgetDetail.ScoaID ,
                                            ScoaCode ,
                                            ScoaDesc ,
                                            FundingSourceBudget ,
                                            ScoaShortDesc ,
                                            ISNULL(fundBudgetDetail.IsHidden,0) AS Submitted,
											fundBudgetDetail.UploadedDocument
                                  FROM      Plan_FundingSourceBudget_Header fundBudgetHeader
                                            LEFT JOIN Plan_FundingSourceBudget_Detail fundBudgetDetail ON fundBudgetHeader.FundingSourceBudgetHeader_ID = fundBudgetDetail.FundingSourceBudgetHeaderID
                                            LEFT JOIN Const_FundingSource fundSource ON fundBudgetDetail.FundingSourceID = fundSource.FundingSource_ID
                                            INNER JOIN dbo.Const_SCOA_Funds_Structure_ByYear(@FinYear) scoaFund ON fundBudgetDetail.ScoaID = scoaFund.ScoaID
                                  WHERE     fundBudgetHeader.FinancialYear = @FinYear
                                ) currentYear
                    ) AS FundDetails
            WHERE   ( ( FundingSourceBudget = 0 AND FundingSourceBudgetCurrYearPlus1 = 0 AND FundingSourceBudgetCurrYearPlus2 = 0)
					  OR( (ISNULL(FundDetails.Submitted,0) = 0)));

					--  PRINT (@SCOASegmentPart + @SCOASegmentPart2);
    END;

GO

/****** Object:  StoredProcedure [dbo].[Plan_FundingSourceChangeReport_sp]    Script Date: 2026/03/10 7:23:31 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:  Niren Patel
-- Create date: 02 Mar 2016
-- Description: 
-- Call SP:  Plan_FundingSourceChangeReport_sp '2017/2018'
-- 2016-04-30 by JP Set Left outer join for Const_FundingSource beacuse Funding Source may be null
-- 2018-05-24 Chirag Patel,Duplicated Recored Remove add DISTINCT conditions,#72066
-- 2018-07-06 Chirag Patel,Remove fundingsource conditions --AND D.FundingSourceID = currentYear.FundingSourceID,#75540
-- 2020-10-02 Chris M, Change ORDER BY to reference column name
-- =============================================
CREATE PROCEDURE [dbo].[Plan_FundingSourceChangeReport_sp] 
	@FinYear NVARCHAR(50)
AS
    BEGIN
        DECLARE @FinYearP1 NVARCHAR(9) ,
            @FinYearP2 NVARCHAR(9) ,
            @yearp1 INT ,
            @yearp2 INT ,
            @yearp3 INT;

        SELECT  @yearp1 = CAST(SUBSTRING(@FinYear, 6, 4) AS INT);
        SELECT  @yearp2 = @yearp1 + 1;
        SELECT  @yearp3 = @yearp1 + 2;
        SELECT  @FinYearP1 = CONVERT(VARCHAR(4), @yearp1) + '/'
                + CONVERT(VARCHAR(4), @yearp2);
        SELECT  @FinYearP2 = CONVERT(VARCHAR(4), @yearp2) + '/'
                + CONVERT(VARCHAR(4), @yearp3);
       
    -- Insert statements for procedure here
        WITH    PlanBudget
                  AS ( SELECT   currentYear.FundingSourceBudgetDetail_ID AS FundingSourceBudgetDetailId ,
                                currentYear.ScoaID AS ScoaFundId ,
                                ISNULL(currentYear.FundingSourceDesc, '') AS FundingSourceDesc ,
                                currentYear.ScoaDesc AS ScoaFundDesc ,
                                currentYear.ScoaShortDesc AS ScoaFundShortDesc ,
                                currentYear.ScoaCode AS ScoaFundCode ,
                                currentYear.FundingSourceBudget AS FundingSourceBudgetCurrYear ,
                                ISNULL(( SELECT TOP 1
                                                FundingSourceBudget
                                         FROM   Plan_FundingSourceBudget_Detail
                                                AS D
                                                INNER JOIN dbo.Plan_FundingSourceBudget_Header
                                                AS H ON D.FundingSourceBudgetHeaderID = H.FundingSourceBudgetHeader_ID
                                                        AND D.ScoaID = currentYear.ScoaID
                                                        AND H.FinancialYear = @FinYearP1
                                       ), 0) AS FundingSourceBudgetCurrYearPlus1 ,
                                ISNULL(( SELECT TOP 1
                                                FundingSourceBudget
                                         FROM   Plan_FundingSourceBudget_Detail
                                                AS D
                                                INNER JOIN dbo.Plan_FundingSourceBudget_Header
                                                AS H ON D.FundingSourceBudgetHeaderID = H.FundingSourceBudgetHeader_ID
                                                        AND D.ScoaID = currentYear.ScoaID
                                                        AND H.FinancialYear = @FinYearP2
                                       ), 0) AS FundingSourceBudgetCurrYearPlus2
                       FROM     ( SELECT    FundingSourceBudgetHeader_ID ,
                                            FundingSourceBudgetDetail_ID ,
                                            FinancialYear ,
                                            FundingSourceID ,
                                            ISNULL(FundingSourceDesc, '') AS FundingSourceDesc ,
                                            fundBudgetDetail.ScoaID ,
                                            ScoaCode ,
                                            ScoaDesc ,
                             FundingSourceBudget ,
                                            ScoaShortDesc ,
                                            Submitted
                                  FROM      Plan_FundingSourceBudget_Header fundBudgetHeader
                                            INNER JOIN Plan_FundingSourceBudget_Detail fundBudgetDetail ON fundBudgetHeader.FundingSourceBudgetHeader_ID = fundBudgetDetail.FundingSourceBudgetHeaderID
                                            LEFT OUTER JOIN Const_FundingSource fundSource ON fundBudgetDetail.FundingSourceID = fundSource.FundingSource_ID
                                            INNER JOIN Const_SCOA_Funds_Structure scoaFund ON fundBudgetDetail.ScoaID = scoaFund.ScoaID
                                  WHERE     fundBudgetHeader.FinancialYear = @FinYear
                                ) currentYear
                     )
            SELECT DISTINCT
                    PlanBudget.ScoaFundId AS SCOAFundID ,
                    PlanBudget.ScoaFundDesc AS SCOAFundDesc ,
                    PlanBudget.ScoaFundShortDesc AS SCOAFundShortDesc ,
                    PlanBudget.ScoaFundCode AS SCOAFundCode ,
                    PlanBudget.FundingSourceBudgetCurrYear AS FundingSourceBudgetYear1 ,
                    PlanBudget.FundingSourceBudgetCurrYearPlus1 AS FundingSourceBudgetYear2 ,
                    PlanBudget.FundingSourceBudgetCurrYearPlus2 AS FundingSourceBudgetYear3 ,
                    dbo.Const_FundSourceChange.FundSourceChangeDesc AS FundSourceChangeDesc
            FROM    Plan_FundingSourceChanges
                    INNER JOIN PlanBudget ON PlanBudget.FundingSourceBudgetDetailId = Plan_FundingSourceChanges.FundingSourceDetailsID
                    INNER JOIN Const_FundSourceChange ON Const_FundSourceChange.FundSourceChange_ID = Plan_FundingSourceChanges.FundSourceChangeID
            ORDER BY SCOAFundID ASC;	
    END;
GO

