-- ==============================================================
-- Author:  Raindree Chetty
-- Create date: 21 February 2018
-- Description: Return Actual Amount per PlanProjectItemID
-- Calls: exec [Plan_GetActualAmountByPlanProjectItemID_sp] '2018/2019',1813
-- 27022019 : Snagpal: #84074 Greater Letaba adjustment error
-- 05032019: #85129 Mnquma: Adjustment budget - Expensed amount not correctly allocated -- Modify Month_Id to SysMonthID
-- ==============================================================
CREATE PROCEDURE [dbo].[Plan_GetActualAmountByPlanProjectItemID_sp]
    @FinancialYear NVARCHAR(50),
	@PlanProjectItemID int
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE  @FinYearStartMonth INT;
	
	SELECT @FinYearStartMonth= CAST(KeyValue AS int) FROM AAAA_ConfigSettings WHERE KeyName ='FinYearStartMonth';

	SELECT 
		ppim.PlanProjectItemID
		,ppim.MonthID
		, CAST(SUM(ISNULL(g.Debit,0))-SUM(ISNULL(g.Credit,0)) AS DECIMAL(16,0)) AS ActualAmount
	FROM 
		Plan_ProjectItemMonth ppim
		INNER JOIN YearStartingAtMonth_fxn(@FinYearStartMonth) m ON m.SysMonthID=ppim.MonthID
		INNER JOIN Plan_ProjectItem ppi ON ppim.PlanProjectItemID=ppi.PlanProjectItem_ID
		LEFT JOIN Led_GeneralLedger g ON g.PlanProjectItemID=ppi.PlanProjectItem_ID AND g.ScoaItemID=ppi.SCOAItemID AND g.ProcessingMonth=m.Month_ID
	WHERE 
		(ppim.PlanProjectItemID=@PlanProjectItemID OR @PlanProjectItemID=0)
		AND ppi.FinYear=@FinancialYear
	GROUP BY ppim.PlanProjectItemID,ppim.MonthID 
   
END;


GO

