SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:  RChetty
-- Create date: 1-Feb-2018
-- Description: Get Adjustment Budget Amount by FinYear with Grand Total
-- CALL SP: Plan_GetAdjustmentBudgetAmountByFinYear_sp '2017/2018'
-- 04 June 2018 Chirag Patel: #73754 Add VersionID for remove Dupblication Of FundingSourceBudget.
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetAdjustmentBudgetAmountByFinYear_sp] @CurrYear NVARCHAR(50)
AS
    BEGIN
 -- SET NOCOUNT ON added to prevent extra result sets from
 -- interfering with SELECT statements.
        SET NOCOUNT ON;

        DECLARE @FinYearAsNumber INT = SUBSTRING(@CurrYear, 6, 4);

        DECLARE @VersionID INT;
        SET @VersionID = ( SELECT TOP 1
                                    PAF.AdjustmentFundingBudgetVersion_ID
                           FROM     [dbo].[Plan_AdjustmentFundingSourceBudget_Detail] d
                                    INNER JOIN [dbo].[Plan_AdjustmentFundingSourceBudget_Header] h ON d.AdjustmentFundingSourceBudgetHeaderID = h.AdjustmentFundingSourceBudgetHeader_ID
                                    INNER JOIN dbo.Plan_AdjustmentFundingBudgetVersion PAF ON PAF.AdjustmentFundingBudgetVersion_ID = d.AdjustmentFundingVersionId
                           WHERE    h.FinancialYear = @CurrYear
                           ORDER BY AdjustmentFundingBudgetVersion_ID DESC
                         );

        DECLARE @CurrYearPlus1 NVARCHAR(50) = CAST(@FinYearAsNumber AS NVARCHAR(4))
            + '/' + CAST(@FinYearAsNumber + 1 AS NVARCHAR(4)) ,
            @CurrYearPlus2 NVARCHAR(50) = CAST(@FinYearAsNumber + 1 AS NVARCHAR(4))
            + '/' + CAST(@FinYearAsNumber + 2 AS NVARCHAR(4));

    -- Insert statements for procedure here
        WITH    BudgetDetails
                  AS ( SELECT   ( SELECT    ISNULL(SUM(d.FundingSourceBudget),
                                                   0)
                                  FROM      [dbo].[Plan_AdjustmentFundingSourceBudget_Detail] d
                                            INNER JOIN [dbo].[Plan_AdjustmentFundingSourceBudget_Header] h ON d.AdjustmentFundingSourceBudgetHeaderID = h.AdjustmentFundingSourceBudgetHeader_ID
                                  WHERE     h.FinancialYear = @CurrYear
                                            AND d.AdjustmentFundingVersionId = @VersionID
                                ) AS CurrYearAmt ,
                                ( SELECT    ISNULL(SUM(d.FundingSourceBudget),
                                                   0)
                                  FROM      [dbo].[Plan_AdjustmentFundingSourceBudget_Detail] d
                                            INNER JOIN [dbo].[Plan_AdjustmentFundingSourceBudget_Header] h ON d.AdjustmentFundingSourceBudgetHeaderID = h.AdjustmentFundingSourceBudgetHeader_ID
                                  WHERE     h.FinancialYear = @CurrYearPlus1
                                            AND d.AdjustmentFundingVersionId = @VersionID
                                ) AS CurrYearPlus1Amt ,
                                ( SELECT    ISNULL(SUM(d.FundingSourceBudget),
                                                   0)
                                  FROM      [dbo].[Plan_AdjustmentFundingSourceBudget_Detail] d
                                            INNER JOIN [dbo].[Plan_AdjustmentFundingSourceBudget_Header] h ON d.AdjustmentFundingSourceBudgetHeaderID = h.AdjustmentFundingSourceBudgetHeader_ID
                                  WHERE     h.FinancialYear = @CurrYearPlus2
                                            AND d.AdjustmentFundingVersionId = @VersionID
                                ) AS CurrYearPlus2Amt
                     )
            SELECT  CurrYearAmt ,
                    BudgetDetails.CurrYearPlus1Amt ,
                    BudgetDetails.CurrYearPlus2Amt ,
                    ( CurrYearAmt + BudgetDetails.CurrYearPlus1Amt
                      + BudgetDetails.CurrYearPlus2Amt ) AS BudgetTotal
            FROM    BudgetDetails;
    END;
GO

