GO

-- =============================================
-- Author:		SAHIL NAGPAL
-- Create date: 2018-02-09
-- Description:	Get Budget Split Details using Adjustment
-- Exec Plan_GetAdjustmentBudgetSplitDetailsReport_sp 333876,677,'2018/2019'
-- 11-Feb-2018 : 67484 Bug No72: Blocking - Specification requirement not met
-- 22-Jan-2018 : #60259 Comment Static Case When condition of  ppi.BudgetSplitId = 1 - 'Manually'
-- 29-April-2018: #87846 Add condition in case no Adjustment & no ORGB found.
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetAdjustmentBudgetSplitDetailsReport_sp]
	-- Add the parameters for the stored procedure here
    @AdjustmentProjectItemId INT = 0,
	 @ReferenceProjectItemId INT = 0,
	@FinYear NVARCHAR(9)
AS
    SET NOCOUNT ON;
    BEGIN
	DECLARE @BudgetVerionID INT;


		SELECT TOP 1 @BudgetVerionID = BudgetVersion_ID FROM dbo.Plan_BudgetVersion pbv
		INNER JOIN dbo.Plan_BudgetVersionDetail pbvd ON pbvd.BudgetVersionID = pbv.BudgetVersion_ID
		WHERE VersionName LIKE '%ORGB%' AND pbvd.FinYear=@FinYear ORDER BY pbv.DateCaptured DESC

		IF EXISTS(SELECT 1 FROM  dbo.Plan_AdjustmentProjectItem ppi WHERE PlanAdjustmentProjectItem_ID = @AdjustmentProjectItemId AND ppi.AdjustedBudgetAmount IS NOT NULL)
			BEGIN  
        SELECT  ppi.AdjustmentProjectID ,
                ppi.PlanAdjustmentProjectItem_ID ,
				----(CASE WHEN
    ----            ppi.BudgetSplitId = 1
				----THEN 'Manually'
				----ELSE cbso.BudgetSplitDesc
				----END) 
				cbso.BudgetSplitDesc AS BudgetSplitDesc,
                (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim1.AdjustedUnitPrice ELSE ppim1.AdjustedUnitPrice END) AS Month1Price ,
                (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim2.AdjustedUnitPrice ELSE ppim2.AdjustedUnitPrice END) AS Month2Price ,
                (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim3.AdjustedUnitPrice ELSE ppim3.AdjustedUnitPrice END) AS Month3Price ,
                (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim4.AdjustedUnitPrice ELSE ppim4.AdjustedUnitPrice END) AS Month4Price ,
                (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim5.AdjustedUnitPrice ELSE ppim5.AdjustedUnitPrice END) AS Month5Price ,
                (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim6.AdjustedUnitPrice ELSE ppim6.AdjustedUnitPrice END) AS Month6Price ,
                (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim7.AdjustedUnitPrice ELSE ppim7.AdjustedUnitPrice END) AS Month7Price ,
                (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim8.AdjustedUnitPrice ELSE ppim8.AdjustedUnitPrice END) AS Month8Price ,
                (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim9.AdjustedUnitPrice ELSE ppim9.AdjustedUnitPrice END) AS Month9Price ,
                 (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim10.AdjustedUnitPrice ELSE ppim10.AdjustedUnitPrice END) AS Month10Price ,
                 (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim11.AdjustedUnitPrice ELSE ppim11.AdjustedUnitPrice END) AS Month11Price ,
                 (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim12.AdjustedUnitPrice ELSE ppim12.AdjustedUnitPrice END) AS Month12Price
               
        FROM    dbo.Plan_AdjustmentProjectItem ppi
				INNER JOIN Plan_AdjustmentProjectItemMonth ppim1 ON ppi.PlanAdjustmentProjectItem_ID= ppim1.PlanAdjustmentProjectItemID and ppim1.MonthID=7
				INNER JOIN Plan_AdjustmentProjectItemMonth ppim2 ON ppi.PlanAdjustmentProjectItem_ID= ppim2.PlanAdjustmentProjectItemID and ppim2.MonthID=8
				INNER JOIN Plan_AdjustmentProjectItemMonth ppim3 ON ppi.PlanAdjustmentProjectItem_ID= ppim3.PlanAdjustmentProjectItemID and ppim3.MonthID=9
				INNER JOIN Plan_AdjustmentProjectItemMonth ppim4 ON ppi.PlanAdjustmentProjectItem_ID= ppim4.PlanAdjustmentProjectItemID and ppim4.MonthID=10
				INNER JOIN Plan_AdjustmentProjectItemMonth ppim5 ON ppi.PlanAdjustmentProjectItem_ID= ppim5.PlanAdjustmentProjectItemID and ppim5.MonthID=11
				INNER JOIN Plan_AdjustmentProjectItemMonth ppim6 ON ppi.PlanAdjustmentProjectItem_ID= ppim6.PlanAdjustmentProjectItemID and ppim6.MonthID=12
				INNER JOIN Plan_AdjustmentProjectItemMonth ppim7 ON ppi.PlanAdjustmentProjectItem_ID= ppim7.PlanAdjustmentProjectItemID and ppim7.MonthID=1
				INNER JOIN Plan_AdjustmentProjectItemMonth ppim8 ON ppi.PlanAdjustmentProjectItem_ID= ppim8.PlanAdjustmentProjectItemID and ppim8.MonthID=2
				INNER JOIN Plan_AdjustmentProjectItemMonth ppim9 ON ppi.PlanAdjustmentProjectItem_ID= ppim9.PlanAdjustmentProjectItemID and ppim9.MonthID=3
				INNER JOIN Plan_AdjustmentProjectItemMonth ppim10 ON ppi.PlanAdjustmentProjectItem_ID= ppim10.PlanAdjustmentProjectItemID and ppim10.MonthID=4
				INNER JOIN Plan_AdjustmentProjectItemMonth ppim11 ON ppi.PlanAdjustmentProjectItem_ID= ppim11.PlanAdjustmentProjectItemID and ppim11.MonthID=5
				INNER JOIN Plan_AdjustmentProjectItemMonth ppim12 ON ppi.PlanAdjustmentProjectItem_ID= ppim12.PlanAdjustmentProjectItemID and ppim12.MonthID=6
                LEFT JOIN dbo.Const_BudgetSplitOptions cbso ON cbso.DivideBy_ID= ppi.BudgetSplitID AND cbso.Enabled=1
        WHERE   ppi.PlanAdjustmentProjectItem_ID = @AdjustmentProjectItemId AND ppi.AdjustedBudgetAmount IS NOT NULL
			END
		ELSE IF EXISTS (SELECT 1 FROM Plan_BudgetVersionDetail WHERE PlanProjectItemID = @ReferenceProjectItemId AND BudgetVersionID = @BudgetVerionID)
            BEGIN
                SELECT DISTINCT  ppi.ProjectID AS AdjustmentProjectID,
                ppi.PlanProjectItemID AS PlanAdjustmentProjectItem_ID,
				--(CASE WHEN
    --            ppim.BudgetSplitId = 1
				--THEN 'Manually'
				--ELSE cbso.BudgetSplitDesc
				--END) 
				cbso.BudgetSplitDesc AS BudgetSplitDesc,
                (CASE WHEN ISNULL(ppim.CreditDebit,'') = 'C' THEN -ppim1.UnitPrice ELSE ppim1.UnitPrice END) AS Month1Price ,
                (CASE WHEN ISNULL(ppim.CreditDebit,'') = 'C' THEN -ppim2.UnitPrice ELSE ppim2.UnitPrice END) AS Month2Price ,
                (CASE WHEN ISNULL(ppim.CreditDebit,'') = 'C' THEN -ppim3.UnitPrice ELSE ppim3.UnitPrice END) AS Month3Price ,
                (CASE WHEN ISNULL(ppim.CreditDebit,'') = 'C' THEN -ppim4.UnitPrice ELSE ppim4.UnitPrice END) AS Month4Price ,
                (CASE WHEN ISNULL(ppim.CreditDebit,'') = 'C' THEN -ppim5.UnitPrice ELSE ppim5.UnitPrice END) AS Month5Price ,
                (CASE WHEN ISNULL(ppim.CreditDebit,'') = 'C' THEN -ppim6.UnitPrice ELSE ppim6.UnitPrice END) AS Month6Price ,
                (CASE WHEN ISNULL(ppim.CreditDebit,'') = 'C' THEN -ppim7.UnitPrice ELSE ppim7.UnitPrice END) AS Month7Price ,
                (CASE WHEN ISNULL(ppim.CreditDebit,'') = 'C' THEN -ppim8.UnitPrice ELSE ppim8.UnitPrice END) AS Month8Price ,
                (CASE WHEN ISNULL(ppim.CreditDebit,'') = 'C' THEN -ppim9.UnitPrice ELSE ppim9.UnitPrice END) AS Month9Price ,
                 (CASE WHEN ISNULL(ppim.CreditDebit,'') = 'C' THEN -ppim10.UnitPrice ELSE ppim10.UnitPrice END) AS Month10Price ,
                 (CASE WHEN ISNULL(ppim.CreditDebit,'') = 'C' THEN -ppim11.UnitPrice ELSE ppim11.UnitPrice END) AS Month11Price ,
                 (CASE WHEN ISNULL(ppim.CreditDebit,'') = 'C' THEN -ppim12.UnitPrice ELSE ppim12.UnitPrice END) AS Month12Price
               
        FROM    dbo.Plan_BudgetVersionDetail ppi
				INNER JOIN dbo.Plan_ProjectItem ppim ON ppi.ProjectID = ppim.ProjectID AND ppi.PlanProjectItemID = ppim.PlanProjectItem_ID
				INNER JOIN Plan_BudgetVersionMonths ppim1 ON ppi.PlanProjectItemID= ppim1.PlanProjectItemID and ppim1.MonthID=7 AND ppim1.BudgetVersionID= @BudgetVerionID
				INNER JOIN Plan_BudgetVersionMonths ppim2 ON ppi.PlanProjectItemID= ppim2.PlanProjectItemID and ppim2.MonthID=8 AND ppim1.BudgetVersionID= @BudgetVerionID
				INNER JOIN Plan_BudgetVersionMonths ppim3 ON ppi.PlanProjectItemID= ppim3.PlanProjectItemID and ppim3.MonthID=9 AND ppim1.BudgetVersionID= @BudgetVerionID
				INNER JOIN Plan_BudgetVersionMonths ppim4 ON ppi.PlanProjectItemID= ppim4.PlanProjectItemID and ppim4.MonthID=10 AND ppim1.BudgetVersionID= @BudgetVerionID
				INNER JOIN Plan_BudgetVersionMonths ppim5 ON ppi.PlanProjectItemID= ppim5.PlanProjectItemID and ppim5.MonthID=11 AND ppim1.BudgetVersionID= @BudgetVerionID
				INNER JOIN Plan_BudgetVersionMonths ppim6 ON ppi.PlanProjectItemID= ppim6.PlanProjectItemID and ppim6.MonthID=12 AND ppim1.BudgetVersionID= @BudgetVerionID
				INNER JOIN Plan_BudgetVersionMonths ppim7 ON ppi.PlanProjectItemID= ppim7.PlanProjectItemID and ppim7.MonthID=1 AND ppim1.BudgetVersionID= @BudgetVerionID
				INNER JOIN Plan_BudgetVersionMonths ppim8 ON ppi.PlanProjectItemID= ppim8.PlanProjectItemID and ppim8.MonthID=2 AND ppim1.BudgetVersionID= @BudgetVerionID
				INNER JOIN Plan_BudgetVersionMonths ppim9 ON ppi.PlanProjectItemID= ppim9.PlanProjectItemID and ppim9.MonthID=3 AND ppim1.BudgetVersionID= @BudgetVerionID
				INNER JOIN Plan_BudgetVersionMonths ppim10 ON ppi.PlanProjectItemID= ppim10.PlanProjectItemID and ppim10.MonthID=4 AND ppim1.BudgetVersionID= @BudgetVerionID
				INNER JOIN Plan_BudgetVersionMonths ppim11 ON ppi.PlanProjectItemID= ppim11.PlanProjectItemID and ppim11.MonthID=5 AND ppim1.BudgetVersionID= @BudgetVerionID
				INNER JOIN Plan_BudgetVersionMonths ppim12 ON ppi.PlanProjectItemID= ppim12.PlanProjectItemID and ppim12.MonthID=6 AND ppim1.BudgetVersionID= @BudgetVerionID
                LEFT JOIN dbo.Const_BudgetSplitOptions cbso ON cbso.DivideBy_ID= ppim.BudgetSplitID AND cbso.Enabled=1
        WHERE   ppi.PlanProjectItemID = @ReferenceProjectItemId AND ppi.BudgetVersionID = @BudgetVerionID
           END
		ELSE
		BEGIN
		     SELECT DISTINCT  ppim.AdjustmentProjectID AS AdjustmentProjectID,
                ppim.PlanAdjustmentProjectItem_ID AS PlanAdjustmentProjectItem_ID,
				cbso.BudgetSplitDesc AS BudgetSplitDesc,
                0.00 AS Month1Price ,0.00 AS Month2Price ,
                0.00 AS Month3Price ,0.00 AS Month4Price ,
                0.00 AS Month5Price ,0.00 AS Month6Price ,
                0.00 AS Month7Price ,0.00 AS Month8Price ,
                0.00 AS Month9Price ,0.00 AS Month10Price ,
                0.00 AS Month11Price ,0.00 AS Month12Price
			FROM  dbo.Plan_AdjustmentProjectItem ppim 
			LEFT JOIN dbo.Const_BudgetSplitOptions cbso ON cbso.DivideBy_ID= ppim.BudgetSplitID AND cbso.Enabled=1
			WHERE PlanAdjustmentProjectItem_ID = @AdjustmentProjectItemId;
		END;
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetAdjustmentFundingBudgetSCOAFundByFinYears_sp]    Script Date: 2026/03/10 7:23:31 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 27/11/2017
-- Description:	Get funding budget scoa fund by finyear/s
-- Calls: execute Plan_GetAdjustmentFundingBudgetSCOAFundByFinYears_sp '2018/2019,2019/2020,2020/2021,','','2018/2019'
-- SNagpal 18-02-2019 : 84009, Get SCOA Segments based upon FinYear, Also Optimize the SP. Remove Functions and add new functionality
-- SNagpal 30-05-2019: Revert All changes of 84009, Append new changes of #89269 - Add multiyear concept to SCOA segments based upon financial year
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetAdjustmentFundingBudgetSCOAFundByFinYears_sp]
	 @FinYearlst varchar(400),
	 @BudgetType VARCHAR(10),
	@UserFinYear NVARCHAR(10) 
AS
BEGIN
SET NOCOUNT ON;

DECLARE @AdjustmentVersionId INT, @AdjustmentFundingVersionId INT;

		SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion WHERE VersionName 
		LIKE @UserFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

		SELECT TOP 1 @AdjustmentFundingVersionId = AdjustmentFundingBudgetVersion_ID FROM Plan_AdjustmentFundingBudgetVersion WHERE VersionName 
		LIKE @UserFinYear + '%' ORDER BY AdjustmentFundingBudgetVersion_ID DESC


DECLARE @sqlCommand varchar(1000)
DECLARE @Valuelst varchar(200)
SET @Valuelst = 'a,b,c,d,e,f,g,h,i,j,k,l,m,n,o,p,q,r,s,'
SET @sqlCommand = ''
DECLARE @pos INT
DECLARE @len INT
set @pos = 0
set @len = 0
DECLARE @pospt INT
DECLARE @lenpt INT
set @pospt = 0
set @lenpt = 0
DECLARE @crFinYear NVARCHAR(10);
SELECT TOP 1  @crFinYear = splitdata FROM    dbo.fnSplitString(@FinYearlst, ',')

WHILE CHARINDEX(',', @FinYearlst, @pos+1)>0
BEGIN
  set @len = CHARINDEX(',', @FinYearlst, @pos+1) - @pos
  set @lenpt = CHARINDEX(',', @Valuelst, @pospt+1) - @pospt
  IF (@sqlCommand='')
  BEGIN
	SET @sqlCommand = 'SELECT DISTINCT  a.ParentID,a.SCOAFundID,	a.SCOADesc,	a.ScoaCode,	a.ScoaShortDesc,
(a.RemainingFundAmount + b.RemainingFundAmount + c.RemainingFundAmount) AS RemainingFundAmount FROM
	(SELECT * FROM Plan_AdjustmentFundingSourceBudgetPerYear_fxn(''' + SUBSTRING(@FinYearlst, @pos, @len) +''',''' + @crFinYear +''',''' + @BudgetType +''',' + CAST(@AdjustmentVersionId AS VARCHAR(10)) + ',' + CAST( @AdjustmentFundingVersionId AS VARCHAR(10)) +' )) ' + SUBSTRING(@Valuelst, @pospt, @lenpt)
  END
  ELSE
  BEGIN
	SET @sqlCommand = @sqlCommand +
	' INNER JOIN  (SELECT * FROM Plan_AdjustmentFundingSourceBudgetPerYear_fxn(''' + SUBSTRING(@FinYearlst, @pos, @len) +''',''' + @crFinYear +''',''' + @BudgetType +''',' + CAST(@AdjustmentVersionId AS VARCHAR(10)) +',' + CAST( @AdjustmentFundingVersionId AS VARCHAR(10)) +')) ' + SUBSTRING(@Valuelst, @pospt, @lenpt)  +' ON a' +'.SCOAFundID='+ SUBSTRING(@Valuelst, @pospt, @lenpt) +'.SCOAFundID'
  END
  set @pos = CHARINDEX(',', @FinYearlst, @pos+@len) +1
  set @pospt = CHARINDEX(',', @Valuelst, @pospt+@lenpt) +1
END
--select @sqlCommand as result
EXEC (@sqlCommand)
--print (@sqlCommand)

-- SELECT Distinct a.* FROM
-- (SELECT * FROM Plan_AdjustmentFundingSourceBudgetPerYear_fxn('2016/2017','2016/2017','O',0,0)) a
-- INNER JOIN  (SELECT * FROM Plan_AdjustmentFundingSourceBudgetPerYear_fxn('2015/2016','2016/2017','O',0,0)) b ON a.SCOAFundID=b.SCOAFundID

END

GO

/****** Object:  StoredProcedure [dbo].[Plan_GetAdjustmentFundWidgetDetails_sp]    Script Date: 2026/03/10 7:23:31 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 28/11/2017
-- Description:	Get Fund Widget Details
-- CALL SP:	Plan_GetAdjustmentFundWidgetDetails_sp '2016/2017',3986,1029
-- 05 Apr 2018 SNagpal: 70472 Inner join with Plan_AdjustmentProject & Plan_AdjustmentFundingSourceBudget_Detail to get related Verion
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetAdjustmentFundWidgetDetails_sp]
    @FinYear NVARCHAR(50),
    @SCOAID BIGINT ,
    @FundingSource BIGINT,
	@UserFinYear NVARCHAR(10) 
AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;

		DECLARE @AdjustmentVersionId INT, @AdjustmentFundingVersionId INT;

		SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion papv
		INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentVersionId = papv.AdjustmentBudgetVersion_ID
		WHERE VersionName LIKE @UserFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

    SELECT TOP 1
        @AdjustmentFundingVersionId = AdjustmentFundingBudgetVersion_ID FROM Plan_AdjustmentFundingBudgetVersion papv
		INNER JOIN dbo.Plan_AdjustmentFundingSourceBudget_Detail pap ON pap.AdjustmentFundingVersionId = papv.AdjustmentFundingBudgetVersion_ID
         WHERE VersionName LIKE @UserFinYear + '%' ORDER BY AdjustmentFundingBudgetVersion_ID DESC;

        DECLARE @FinYearAsNumber INT = SUBSTRING(@FinYear, 6, 4);

        DECLARE @FinYear1 NVARCHAR(50) = CAST(@FinYearAsNumber AS NVARCHAR(4))
            + '/' + CAST(@FinYearAsNumber + 1 AS NVARCHAR(4)) ,
            @FinYear2 NVARCHAR(50) = CAST(@FinYearAsNumber + 1 AS NVARCHAR(4))
            + '/' + CAST(@FinYearAsNumber + 2 AS NVARCHAR(4));

        WITH    FundDetails
                  AS ( SELECT   @FinYear AS FinancialYear ,
                                ISNULL(dbo.Plan_GetAdjustmentFundAvailableAmount_fxn(@SCOAID,
                                                              @FinYear,@AdjustmentFundingVersionId),0) AS Available ,
                                 ISNULL(dbo.Plan_GetAdjustmentFundAllocatedAmount_fxn(@SCOAID,
                                                              @FinYear, @FinYear,@AdjustmentVersionId),0) AS Allocated
                       UNION
                       SELECT   @FinYear1 AS FinancialYear ,
                                ISNULL(dbo.Plan_GetAdjustmentFundAvailableAmount_fxn(@SCOAID,
                                                              @FinYear1,@AdjustmentFundingVersionId),0) AS Available ,
                                ISNULL(dbo.Plan_GetAdjustmentFundAllocatedAmount_fxn(@SCOAID,
                                                              @FinYear1, @FinYear,@AdjustmentVersionId),0) AS Allocated
                       UNION
                       SELECT   @FinYear2 AS FinancialYear ,
                                ISNULL(dbo.Plan_GetAdjustmentFundAvailableAmount_fxn(@SCOAID,
                                                              @FinYear2,@AdjustmentFundingVersionId),0) AS Available ,
                                ISNULL(dbo.Plan_GetAdjustmentFundAllocatedAmount_fxn(@SCOAID,
                                                              @FinYear2, @FinYear,@AdjustmentVersionId),0) AS Allocated
                     )
            SELECT  FinancialYear ,
                    Available ,
                    Allocated ,
                    Available - Allocated AS Remaining
            FROM    FundDetails;
				  
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetAdjustmentProjectBudgetingReport_sp]    Script Date: 2026/03/10 7:23:31 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- ============================================= 
-- Author:	Nirav Parikh
-- Create date: 15/Dec/2017
-- Description:	Get project budgeting details
-- Calls: Plan_GetAdjustmentProjectBudgetingReport_sp '', 0, 0, '2022/2023','0,1,2,3,4,5', 0, 0, 0, 0, 0, 0, '', 0,0,0
-- 04 Feb 2018 JigneshP: 67238 Adjustment Report - Field headings aren't according to spec
-- 10 Feb 2018 SNagpal: 67484 Bug No72: Blocking - Specification requirement not met
-- 11 Feb 2018 SNagpal: 67484 Bug No72: Blocking - Specification requirement not met
-- 11 Feb 2018 SNagpal: 67484 Fix Filters
-- 13 Feb 2018 SNagpal: 67484 Fix Adjustment Calculations
-- 14 Feb 2018 SNagpal: 67484 Fix Adjustment Calculations
-- 16 Feb 2018 SNagpal: 67484 Fix Credit/Debit Calculations
-- 19 Feb 2018 SNagpal: 67985 Fix Credit/Debit Calculations
-- 07 Mar 2018 SNagpal: 69116 Add Filters for SCOAProject & SCOACosting
-- 09 Mar 2018 SNagpal: 69311 Add ISNULL(pp.ReferenceProject_ID,pp.AdjustmentProject_ID)
-- 12 Mar 2018 SNagpal: 69333 Add logic to get Transferred Virement amounts
--						LEFT JOIN Plan_BudgetRegister br on api.ReferencePlanProjectItem_ID=br.PlanProjectItemID AND br.TransactionTableName='Plan_ProjectItem' AND api.VirementId IS NOT NULL
-- 27 Mar 2018 ChrisM:  Handle case where Adjusted Budget Amount = zero for calculating SCOAItemAdjustment,SCOAItemAdjustment1, SCOAItemAdjustment2
-- 06 Apr 2018 SNagpal: 70563 INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentVersionId = papv.AdjustmentBudgetVersion_ID
-- 30 Apr 2018 SNagpal: Fix issue of ISNULL(ppi.AdjustedBudgetAmountCurP2, -1)
-- 24 May 2018 RChetty: 73040 Calculation issue fixed
-- 01 Nov 2018 SNagpal: 81515 Fix Where condition for @Information to get all adjusted projects
-- 24-Jan-2019 SNagpal: #61596 - #83633 - Add functionality to get ProjectCode
-- 05-April-2019 SNagpal: #85469 - Fix virement calculation issues
-- 25-April-2019 SNagpal: #86104 -Add condition if Sum of BudgetAmount from ORGB is also greater than zero then also show
-- 20-May-2019 SNagpal: Add multiyear concept to get SCOA segments based upon finyear & also add ,ISNULL(ppi.ProjectItemID,0) AS ProjectItemID to get distinct results
-- 17-Aug-2019 ChrisM: #90878 - Adjustment budget calculated directly from Plan_AdjustmentProjectItem table and ItemAdjustment calculation changed to AdjustedBudget - (OriginalBudget + Virement)
-- 23-Nov-2019 Chrism: 24674 - Fix so that adjustment budgets returned correctly for outer years 
-- 13-Aug-2020 ChrisM: 4727 - Standardise formatting for project name
-- 07-Aug-2023 ChrisM: #105236 Include CostingProject field
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetAdjustmentProjectBudgetingReport_sp]
    @strDivisionID NVARCHAR(10) = '' ,
    @ProjectID INT = 0,
    @ScoaFunctionID INT = 0,
    @FinYear NVARCHAR(9) = '2018/2019' ,
    @BudgetType NVARCHAR(20) = '0,1,2,3,4,5',
    @DepartmentID INT = 0,
    @ProjectTypeID INT = 0,
    @ScoaRegionID INT = 0,
    @ScoaFundID INT = 0,
    @ScoaItemID INT = 0,
    @ProjectStatusId INT = 0,
    @SingleMultiYear VARCHAR(5) = '',
	@Information INT = 0,
	@ScoaCostingID INT = 0,
    @ScoaProjectID INT = 0,
	@ShowCostingProject INT = 0
AS
    BEGIN

	SET NOCOUNT ON; 

	---------PLEASE INFORM LEDGER THAT FINPOS NEEDS TO CHANGE IF DEBITCREDIT LOGIC CHANGES-------
        DECLARE @FinYearP1 NVARCHAR(9) ,
            @FinYearP2 NVARCHAR(9) ,
            @FinYearP3 NVARCHAR(9) ,
            @yearp1 INT ,
            @yearp2 INT ,
            @yearp3 INT ,
            @yearp4 INT ,
            @DivisionID INT,
			@BudgetVerionID INT;


		SELECT TOP 1 @BudgetVerionID = BudgetVersion_ID FROM dbo.Plan_BudgetVersion pbv
		INNER JOIN dbo.Plan_BudgetVersionDetail pbvd ON pbvd.BudgetVersionID = pbv.BudgetVersion_ID
		WHERE VersionName LIKE '%ORGB%' AND pbvd.FinYear=@FinYear ORDER BY pbv.DateCaptured DESC

		DECLARE @AdjustmentVersionId INT;

		SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion papv
		INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentVersionId = papv.AdjustmentBudgetVersion_ID
		WHERE VersionName LIKE @FinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

        SELECT  @yearp1 = CAST(SUBSTRING(@FinYear, 6, 4) AS INT);
        SELECT  @yearp2 = @yearp1 + 1;
        SELECT  @yearp3 = @yearp1 + 2;
        SELECT  @yearp4 = @yearp1 + 3;
        SELECT  @FinYearP1 = CONVERT(VARCHAR(4), @yearp1) + '/'
                + CONVERT(VARCHAR(4), @yearp2);
        SELECT  @FinYearP2 = CONVERT(VARCHAR(4), @yearp2) + '/'
                + CONVERT(VARCHAR(4), @yearp3);
        SELECT  @FinYearP3 = CONVERT(VARCHAR(4), @yearp3) + '/'
                + CONVERT(VARCHAR(4), @yearp4);

		CREATE TABLE #Const_SCOA_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100), ScoaShortDesc NVARCHAR(800))
		CREATE INDEX idxItemScoaID ON #Const_SCOA_Structure(ScoaID)
		CREATE INDEX idxItemNTScoaID ON #Const_SCOA_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode, ScoaShortDesc FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Function_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100), ScoaShortDesc NVARCHAR(800))
		CREATE INDEX idxFunctionScoaID ON #Const_SCOA_Function_Structure(ScoaID)
		CREATE INDEX idxFunctionNTScoaID ON #Const_SCOA_Function_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Function_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode, ScoaShortDesc FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Costing_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
		CREATE INDEX idxCostingScoaID ON #Const_SCOA_Costing_Structure(ScoaID)
		CREATE INDEX idxCostingNTScoaID ON #Const_SCOA_Costing_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Costing_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Const_SCOA_Costing_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Project_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
		CREATE INDEX idxProjectScoaID ON #Const_SCOA_Project_Structure(ScoaID)
		CREATE INDEX idxProjectNTScoaID ON #Const_SCOA_Project_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Project_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Fund_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100), ScoaShortDesc NVARCHAR(800))
		CREATE INDEX idxFundScoaID ON #Const_SCOA_Fund_Structure(ScoaID)
		CREATE INDEX idxFundNTScoaID ON #Const_SCOA_Fund_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Fund_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode, ScoaShortDesc FROM Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Region_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100), ScoaShortDesc NVARCHAR(800))
		CREATE INDEX idxRegionScoaID ON #Const_SCOA_Fund_Structure(ScoaID)
		CREATE INDEX idxRegionNTScoaID ON #Const_SCOA_Fund_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Region_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode, ScoaShortDesc FROM Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @FinYear
		
		DECLARE @tblBudgetType TABLE ( BudgetTypeID INT );

        IF ISNULL(@BudgetType, '') <> ''
            BEGIN
                INSERT  INTO @tblBudgetType
                        SELECT  Data
                        FROM    dbo.Split(@BudgetType, ',');
            END;

        SELECT  @DivisionID = IIF(@strDivisionID = '', NULL, CAST(@strDivisionID AS INT));--To get all parent child divisions 
        DECLARE @temp TABLE ( tblDivisionId INT );
        WITH    temp
                  AS ( SELECT   Division_ID ,
                                DivisionParentID
                       FROM     Const_Division
                       WHERE    ( Division_ID = @DivisionID
                                  OR @DivisionID IS NULL
                                )
                       UNION ALL
                       SELECT   t.Division_ID ,
                                t.DivisionParentID
                       FROM     Const_Division t
                                JOIN temp ON temp.Division_ID = t.DivisionParentID
                     )
            INSERT  INTO @temp
                    SELECT  temp.Division_ID
                    FROM    temp;

       SELECT DISTINCT  ProjectDetails.* ,
				SCOAItemAdjustmentBudget, SCOAItemAdjustmentBudgetP1 AS SCOAItemAdjustmentBudget1, SCOAItemAdjustmentBudgetP2 AS SCOAItemAdjustmentBudget2,
				SCOAItemAdjustmentBudget - (ReqCurrentYearAmt + ISNULL(VirementAmount.TotalVirementAmount,0)) AS ScoaItemAdjustment,
				SCOAItemAdjustmentBudgetP1 - ReqCurrentYearP1Amt AS ScoaItemAdjustment1,
				SCOAItemAdjustmentBudgetP2 - ReqCurrentYearP2Amt AS ScoaItemAdjustment2,
				ISNULL(VirementAmount.TotalVirementAmount,0) AS SCOAItemVirementTotal,
                AdjustmentApprover.[1] FirstRecommender,
                AdjustmentApprover.[2] SecondRecommender,
				AdjustmentApprover.[3] FinalRecommender
        FROM    
                (  SELECT DISTINCT       
				 
				 pp.AdjustmentProject_ID AS Project_ID,pp.AdjustmentProjectName AS AdjustmentProjectName,
				 ppi.ReferencePlanProjectItem_ID,pppi.PlanProjectItem_ID, ppi.PlanAdjustmentProjectItem_ID,
                 ( CAST( COALESCE(pp.ProjectCode,pp.ReferenceProject_ID,pp.AdjustmentProject_ID) AS VARCHAR(50)) + ' | '
                    + pp.AdjustmentProjectName ) AS ProjectName ,
                REPLACE(REPLACE(REPLACE(pp.AdjustmentProjectDesc, CHAR(10), ' '),
                                CHAR(13), ' '), CHAR(09), ' ') AS ProjectDesc ,
                pp.CostEstimate ,
                pp.CapitalOperation ,
                ( SELECT    TypeName
                    FROM      dbo.Const_PlanCapitalOperationalTypes_sys
                    WHERE     TypeValue = pp.CapitalOperation
                ) AS CapitalOperationDesc ,
                pp.ProjectStatus ,
                cs.StatusDesc ,
                dep.Department_ID ,
                cd.Division_ID ,
                pp.ProjectTypeID ,
                ( CAST(cd.Division_ID AS VARCHAR(10)) + ' '
                    + cd.DivisionDesc + ' / ' + cd.DivisionCode ) AS MuniClassification ,
                cpt.ProjectTypeDescrip ,
               func.ScoaCode AS SCOAFuncCode ,
                func.ScoaShortDesc AS SCOAFuncDesc ,
                func.ScoaDesc AS SCOAFunctions ,
                region.ScoaCode AS SCOARegionCode ,
                region.ScoaDesc AS SCOARegionDesc ,
                region.ScoaDesc AS SCOARegions ,
                costing.ScoaCode AS SCOACostingCode ,
                costing.ScoaDesc AS SCOACostingDesc ,
                project.ScoaCode AS SCOAProjectCode ,
                project.ScoaDesc AS SCOAProjectDesc ,
                fs.ScoaCode AS SCOAFundCode ,
                fs.ScoaDesc AS SCOAFundDesc ,
                fs.ScoaDesc AS SCOAFundings ,
                ISNULL(ppi.BudgetAmount,0) AS FUNDCurrentYearAmt ,
                ISNULL(ppi.BudgetAmountCurP1,0) AS FUNDCurrentP1YearAmt ,
                ISNULL(ppi.BudgetAmountCurP2,0) AS FUNDCurrentP2YearAmt ,
                cpi.ItemDescription ,
                css.ScoaCode ,
                css.ScoaDesc AS ScoaShortDesc ,
                CASE WHEN ( ppi.CreditDebit = 'C'
                            ) THEN -ISNULL(pbvd.BudgetAmount, 0)
                        ELSE ISNULL(pbvd.BudgetAmount, 0)
                END AS ReqCurrentYearAmt ,
                CASE WHEN ( ppi.CreditDebit = 'C'
                            ) THEN -ISNULL(pbvd.BudgetAmountCurP1, 0)
                        ELSE ISNULL(pbvd.BudgetAmountCurP1, 0)
                END AS ReqCurrentYearP1Amt ,
                CASE WHEN ( ppi.CreditDebit = 'C'
                            ) THEN -ISNULL(pbvd.BudgetAmountCurP2, 0)
                        ELSE ISNULL(pbvd.BudgetAmountCurP2, 0)
                END AS ReqCurrentYearP2Amt ,
				
				  CASE WHEN ( ppi.CreditDebit = 'C'
                            ) THEN -ISNULL(ppi.AdjustedBudgetAmount, 0)
                        ELSE ISNULL(ppi.AdjustedBudgetAmount, 0)
                END AS SCOAItemAdjustmentBudgetAmt ,
                CASE WHEN ( ppi.CreditDebit = 'C'
                            ) THEN -ISNULL(ppi.AdjustedBudgetAmountCurP1, 0)
                        ELSE ISNULL(ppi.AdjustedBudgetAmountCurP1, 0)
                END AS SCOAItemAdjustmentBudgetP1Amt ,
                CASE WHEN ( ppi.CreditDebit = 'C'
                            ) THEN -ISNULL(ppi.AdjustedBudgetAmountCurP2, 0)
                        ELSE ISNULL(ppi.AdjustedBudgetAmountCurP2, 0)
                END AS SCOAItemAdjustmentBudgetP2Amt ,
				CASE WHEN ( ppi.CreditDebit = 'C'
                            ) THEN -ISNULL(ppi.AdjustedBudgetAmount, ppi.BudgetAmount)
                        ELSE ISNULL(ppi.AdjustedBudgetAmount, ppi.BudgetAmount)
                END AS ScoaItemAdjustmentBudget ,
                CASE WHEN ( ppi.CreditDebit = 'C'
                            ) THEN -ISNULL(ppi.AdjustedBudgetAmountCurP1, ppi.BudgetAmountCurP1)
                        ELSE ISNULL(ppi.AdjustedBudgetAmountCurP1, ppi.BudgetAmountCurP1)
                END AS ScoaItemAdjustmentBudgetP1 ,
                CASE WHEN ( ppi.CreditDebit = 'C'
                            ) THEN -ISNULL(ppi.AdjustedBudgetAmountCurP2, ppi.BudgetAmountCurP2)
                        ELSE ISNULL(ppi.AdjustedBudgetAmountCurP2, ppi.BudgetAmountCurP2)
                END AS ScoaItemAdjustmentBudgetP2 ,				
				CAST(0 AS DECIMAL(18,0)) AS ReqCurrentYearP3Amt ,
                0 AS ShowColumn ,
				cpa.AdjustmentType AS AdjustmentType ,
				cpar.AdjustmentReason AS LegislativeReasonforAdjustment ,
				ppi.ReasonForAdjustment AS ReasonforAdjustment ,
				pp.AdjustmentVersionId, ISNULL(ppi.ProjectItemID, 0) AS ProjectItemID ,
				@ShowCostingProject ShowCostingProject ,
				CASE WHEN ISNULL(pp.CostingProject, 0) = 0 THEN 'No' ELSE 'Yes' END CostingProject
        FROM    dbo.Plan_AdjustmentProject pp
				LEFT JOIN  Plan_Project ppp  ON pp.AdjustmentProjectName = ppp.ProjectName
                LEFT OUTER JOIN dbo.Plan_AdjustmentProjectItem ppi ON pp.AdjustmentProject_ID = ppi.AdjustmentProjectID
				LEFT JOIN  Plan_Projectitem pppi  ON pppi.ProjectID = ppp.Project_ID AND 
				ppi.PlanAdjustmentProjectItem_ID = pppi.AdjustmentId
				LEFT JOIN Plan_BudgetVersionDetail pbvd ON ppi.ReferencePlanProjectItem_ID = pbvd.PlanProjectItemID
				AND pbvd.BudgetVersionID = @BudgetVerionID
				LEFT JOIN dbo.Const_PlanAdjustmentType_sys cpa ON cpa.AdjustmentType_ID = ppi.AdjutmentType
				LEFT JOIN dbo.Const_PlanAdjustmentReason_sys cpar ON cpar.AdjustmentReason_ID = ppi.LegislativeReasonAdjustment
                LEFT OUTER JOIN Const_Status cs ON cs.Status_ID = pp.ProjectStatus
                LEFT OUTER JOIN Const_Division cd ON cd.Division_ID = ppi.DivisionId
                LEFT OUTER JOIN Const_Department dep ON cd.DepartmentID = dep.Department_ID
                LEFT OUTER JOIN #Const_SCOA_Function_Structure AS func ON func.ScoaID = ppi.SCOAFunctionId
                LEFT OUTER JOIN #Const_SCOA_Region_Structure AS region ON region.ScoaID = ppi.SCOARegionId
                LEFT OUTER JOIN #Const_SCOA_Costing_Structure AS costing ON costing.ScoaID = ppi.SCOACostingID
                LEFT OUTER JOIN #Const_SCOA_Project_Structure AS project ON project.ScoaID = pp.ScoaProjectID
                LEFT OUTER JOIN Const_ProjectItem cpi ON ppi.ProjectItemID = cpi.ProjectItem_ID
                LEFT OUTER JOIN #Const_SCOA_Structure AS css ON ppi.SCOAItemID = css.ScoaID
                LEFT OUTER JOIN Const_ProjectType cpt ON pp.ProjectTypeID = cpt.ProjectType_ID
                LEFT OUTER JOIN #Const_SCOA_Fund_Structure AS fs ON ppi.SCOAFundId = fs.ScoaID
                INNER JOIN @temp t ON t.tblDivisionId = cd.Division_ID
        WHERE   
			( CASE WHEN @ProjectID = 0 THEN 0
                        ELSE pp.AdjustmentProject_ID
                    END = @ProjectID )
                AND ( CASE WHEN @ScoaFundID = 0 THEN 0
                            ELSE fs.ScoaID
                        END = @ScoaFundID )
                AND ( CASE WHEN @ScoaFunctionID = 0 THEN 0
                            ELSE func.ScoaID
                        END = @ScoaFunctionID )
                AND ( CASE WHEN @ScoaRegionID = 0 THEN 0
                            ELSE region.ScoaID
                        END = @ScoaRegionID )
                AND ( CASE WHEN @ScoaItemID = 0 THEN 0
                            ELSE css.ScoaID
                        END = @ScoaItemID )
                AND ( CASE WHEN @DepartmentID = 0 THEN 0
                            ELSE dep.Department_ID
                        END = @DepartmentID )
                AND ( CASE WHEN @ProjectTypeID = 0 THEN 0
                            ELSE pp.ProjectTypeID
                        END = @ProjectTypeID )
                AND ( CASE WHEN @FinYear = '' THEN ''
                            ELSE pp.FinYear
                        END = @FinYear )
                AND ( CASE WHEN @FinYear = '' THEN ''
                            ELSE ppi.FinYear
                        END = @FinYear )
                AND ( CASE WHEN @ProjectStatusId = 0 THEN 0
                            ELSE pp.ProjectStatus
                        END = @ProjectStatusId )
						AND ( CASE WHEN @ScoaCostingID = 0 THEN 0
                            ELSE ppi.SCOACostingID
                        END = @ScoaCostingID )
						AND ( CASE WHEN @ScoaProjectID = 0 THEN 0
                            ELSE pp.ScoaProjectID
                        END = @ScoaProjectID )
                AND ( CASE WHEN @SingleMultiYear = '' THEN ''
                            ELSE pp.SingleMultiYear
                        END = @SingleMultiYear )
				AND (CASE WHEN @ShowCostingProject = 1 THEN @ShowCostingProject
							ELSE ISNULL(pp.CostingProject, 0) END = @ShowCostingProject )
                AND ( pp.CapitalOperation IN (SELECT BudgetTypeID FROM @tblBudgetType) )
				AND (
						(@Information = 1 AND ISNULL(pp.ReferenceProject_ID,0) >= 0 
						AND (( ISNULL(ppi.AdjustedBudgetAmount, 0) + ISNULL(ppi.AdjustedBudgetAmountCurP1, 0) + ISNULL(ppi.AdjustedBudgetAmountCurP2, 0) ) <> 0 or ppi.AdjustedBudgetAmount IS NOT NULL)
						
					)
						 OR (@Information <> 1)
					)

                AND 
				ISNULL(pp.IsDeleted, 0) <> 1
				AND pp.AdjustmentVersionId = @AdjustmentVersionId
				AND (ISNULL(ppp.IsDeleted, 0) <> 1 OR ppp.IsDeleted IS NULL) AND (ppp.FinYear= @FinYear OR ppp.FinYear IS NULL)
				)
				AS ProjectDetails
                LEFT JOIN ( SELECT *
                             FROM   ( SELECT    PV.AdjustmentProject_ID ,
                                                UUD.FirstName + ' '
                                                + UUD.LastName AS Approver ,
                                                ROW_NUMBER() OVER ( PARTITION BY PV.AdjustmentProject_ID ORDER BY PVAU.AdjustmentProjectRecommendUser_Id ) AS ApproverNo
                                      FROM      dbo.Plan_AdjustmentProject AS PV
                                                INNER JOIN dbo.Plan_AdjustmentProjectRecommendUsers PVAU ON PV.AdjustmentProject_ID = PVAU.AdjustmentProjectId
                                                INNER JOIN dbo.User_UserDetail UUD ON UUD.User_ID = PVAU.UserId
                                      WHERE     
									  ( CASE WHEN @ProjectID = 0 THEN 0 ELSE PV.AdjustmentProject_ID END = @ProjectID )
                                               
                                    ) S PIVOT
				( MAX(Approver) FOR ApproverNo IN ( [1], [2], [3] ) ) piv
                           ) AS AdjustmentApprover ON ProjectDetails.Project_ID = AdjustmentApprover.AdjustmentProject_ID
				LEFT JOIN		
					(SELECT  SUM(virementFromTo.VirementAmount) AS TotalVirementAmount, 
					virementFromTo.PlanProjectItem_ID, virementFromTo.ProjectID FROM 
					(SELECT -ISNULL(V.FromVirementAmount, 0) AS VirementAmount, PPIFrom.PlanProjectItem_ID,PPIFrom.ProjectID,V.VirementId
					 FROM  dbo.Plan_Project PrjFrom
					 INNER JOIN dbo.Plan_ProjectItem PPIFrom ON PPIFrom.ProjectID = PrjFrom.Project_ID
					INNER JOIN dbo.Plan_Virements V ON V.FromProjectId = PrjFrom.Project_ID
					AND V.FromSCOAProjectID = PrjFrom.ScoaProjectID AND v.FromSCOAFunctionId = PPIFrom.SCOAFunctionId
					AND v.FromDivisionId = PPIFrom.DivisionId AND V.FromSCOAFundID = PPIFrom.SCOAFundId
					AND v.FromSCOARegion = PPIFrom.SCOARegionId AND v.FromSCOAItem = PPIFrom.SCOAItemID
					AND v.FromSCOACostingId = PPIFrom.SCOACostingID 
					WHERE V.FromProjectID <> V.ToProjectID 
					UNION
					SELECT ISNULL(V.ToVirementAmount, 0) AS VirementAmount, PPITo.PlanProjectItem_ID,PPITo.ProjectID,V.VirementId
					FROM  dbo.Plan_Project PrjTo
					 INNER JOIN dbo.Plan_ProjectItem PPITo ON PPITo.ProjectID = PrjTo.Project_ID
					INNER JOIN dbo.Plan_Virements V ON V.ToProjectId = PrjTo.Project_ID
					AND V.ToSCOAProjectID = PrjTo.ScoaProjectID AND v.ToSCOAFunctionId = PPITo.SCOAFunctionId
					AND v.ToDivisionId = PPITo.DivisionId AND V.ToSCOAFundID = PPITo.SCOAFundId
					AND v.ToSCOARegion = PPITo.SCOARegionId AND v.ToSCOAItem = PPITo.SCOAItemID
					AND v.ToSCOACostingId = PPITo.SCOACostingID 
					WHERE V.FromProjectID <> V.ToProjectID
					) AS virementFromTo LEFT JOIN
						Plan_VirementApprovalRejections vrej ON virementFromTo.VirementID = vrej.VirementID
					WHERE ISNULL(IsRejected, 1) <> 1
					GROUP BY virementFromTo.PlanProjectItem_ID,ProjectID) 
					AS VirementAmount ON ISNULL(ProjectDetails.ReferencePlanProjectItem_ID,ProjectDetails.PlanProjectItem_ID) = VirementAmount.PlanProjectItem_ID
        ORDER BY MuniClassification;
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetAdjustmentProjectBudgetingReportByVersion_sp]    Script Date: 2026/03/10 7:23:31 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Nirav Parikh
-- Create date: 15/Dec/2017	
-- Description:	Project Budget Report By Version
-- CALL SP: Plan_GetAdjustmentProjectBudgetingReportByVersion_sp '',0,0,'2022/2023','2,3,1,5,4,0',0,0,0,0,0,0,285,'',0,0,0,0
-- 04 Feb 2018 JigneshP: 67238 Adjustment Report - Field headings aren't according to spec
-- 09 Feb 2018 SNagpal: Add Some missing columns
-- 07 Mar 2018 SNagpal: 69116 Add Filters for SCOAProject & SCOACosting
-- 09 Mar 2018 SNagpal: 69311 Add ISNULL(pp.ReferenceProject_ID,pp.AdjustmentProject_ID)
-- 27 Mar 2018 ChrisM:  Handle case where Adjusted Budget Amount = zero for calculating SCOAItemAdjustment,SCOAItemAdjustment1, SCOAItemAdjustment2
-- 30 Apr 2018 SNagpal: Fix issue of ISNULL(ppi.AdjustedBudgetAmountCurP2, -1)
-- 24 May 2018 RChetty: 73040 Calculation issue fixed
-- 01 Nov 2018 SNagpal: 81515 Fix Where condition for @Information to get all adjusted projects
-- 24-Jan-2019 SNagpal: #61596 - #83633 - Add functionality to get ProjectCode
-- 05-April-2019 SNagpal: #85469 - Fix virement calculation issues
-- 24-April-2019 SNagpal: #86104 -Add condition if Sum of BudgetAmount from ORGB is also greater than zero then also show
-- 20-May-2019 SNagpal: #88958 Add multiyear concept to get SCOA segments based upon finyear & also add ,ISNULL(ppi.ProjectItemID,0) AS ProjectItemID to get distinct results
-- 04-Dec-2019 ChrisM: Fix issue where rejected virements are being returned
-- 13-Aug-2020 ChrisM: 4727 - Standardise formatting for project name
-- 07-Aug-2023 ChrisM: #105236 Include CostingProject field
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetAdjustmentProjectBudgetingReportByVersion_sp]
    @strDivisionID NVARCHAR(10) ,
    @ProjectID INT ,
    @ScoaFunctionID INT ,
    @FinYear NVARCHAR(9) ,
    @BudgetType NVARCHAR(20) = '',
    @DepartmentID INT ,
    @ProjectTypeID INT ,
    @ScoaRegionID INT ,
    @ScoaFundID INT ,
    @ScoaItemID INT ,
    @ProjectStatusId INT ,
	@VersionId INT ,
    @SingleMultiYear VARCHAR(5),
	@Information INT,
	@ScoaCostingID INT ,
    @ScoaProjectID INT,
	@ShowCostingProject INT
AS
    BEGIN

	SET NOCOUNT ON; 

	---------PLEASE INFORM LEDGER THAT FINPOS NEEDS TO CHANGE IF DEBITCREDIT LOGIC CHANGES-------
        DECLARE @FinYearP1 NVARCHAR(9) ,
            @FinYearP2 NVARCHAR(9) ,
            @FinYearP3 NVARCHAR(9) ,
            @yearp1 INT ,
            @yearp2 INT ,
            @yearp3 INT ,
            @yearp4 INT ,
            @DivisionID INT,
			@BudgetVerionID INT;


		SELECT TOP 1 @BudgetVerionID = BudgetVersion_ID FROM dbo.Plan_BudgetVersion pbv
		INNER JOIN dbo.Plan_BudgetVersionDetail pbvd ON pbvd.BudgetVersionID = pbv.BudgetVersion_ID
		WHERE VersionName LIKE '%ORGB%' AND pbvd.FinYear=@FinYear ORDER BY pbv.DateCaptured DESC

		DECLARE @AdjustmentVersionId INT;

		SET @AdjustmentVersionId = @VersionId;
		IF(@VersionId = 0)
		BEGIN
			SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion papv 
			INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentVersionId = papv.AdjustmentBudgetVersion_ID
			WHERE VersionName LIKE @FinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC	    
		END

        SELECT  @yearp1 = CAST(SUBSTRING(@FinYear, 6, 4) AS INT);
        SELECT  @yearp2 = @yearp1 + 1;
        SELECT  @yearp3 = @yearp1 + 2;
        SELECT  @yearp4 = @yearp1 + 3;
        SELECT  @FinYearP1 = CONVERT(VARCHAR(4), @yearp1) + '/'
                + CONVERT(VARCHAR(4), @yearp2);
        SELECT  @FinYearP2 = CONVERT(VARCHAR(4), @yearp2) + '/'
                + CONVERT(VARCHAR(4), @yearp3);
        SELECT  @FinYearP3 = CONVERT(VARCHAR(4), @yearp3) + '/'
                + CONVERT(VARCHAR(4), @yearp4);

		CREATE TABLE #Const_SCOA_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100), ScoaShortDesc NVARCHAR(800))
		CREATE INDEX idxItemScoaID ON #Const_SCOA_Structure(ScoaID)
		CREATE INDEX idxItemNTScoaID ON #Const_SCOA_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode, ScoaShortDesc FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Function_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100), ScoaShortDesc NVARCHAR(800))
		CREATE INDEX idxFunctionScoaID ON #Const_SCOA_Function_Structure(ScoaID)
		CREATE INDEX idxFunctionNTScoaID ON #Const_SCOA_Function_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Function_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode, ScoaShortDesc FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Costing_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
		CREATE INDEX idxCostingScoaID ON #Const_SCOA_Costing_Structure(ScoaID)
		CREATE INDEX idxCostingNTScoaID ON #Const_SCOA_Costing_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Costing_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Const_SCOA_Costing_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Project_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
		CREATE INDEX idxProjectScoaID ON #Const_SCOA_Project_Structure(ScoaID)
		CREATE INDEX idxProjectNTScoaID ON #Const_SCOA_Project_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Project_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Fund_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100), ScoaShortDesc NVARCHAR(800))
		CREATE INDEX idxFundScoaID ON #Const_SCOA_Fund_Structure(ScoaID)
		CREATE INDEX idxFundNTScoaID ON #Const_SCOA_Fund_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Fund_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode, ScoaShortDesc FROM Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Region_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100), ScoaShortDesc NVARCHAR(800))
		CREATE INDEX idxRegionScoaID ON #Const_SCOA_Fund_Structure(ScoaID)
		CREATE INDEX idxRegionNTScoaID ON #Const_SCOA_Fund_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Region_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode, ScoaShortDesc FROM Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @FinYear
		
		DECLARE @tblBudgetType TABLE ( BudgetTypeID INT );

        IF ISNULL(@BudgetType, '') <> ''
            BEGIN
                INSERT  INTO @tblBudgetType
                        SELECT  Data
                        FROM    dbo.Split(@BudgetType, ',');
            END;

        SELECT  @DivisionID = IIF(@strDivisionID = '', NULL, CAST(@strDivisionID AS INT));--To get all parent child divisions 
        DECLARE @temp TABLE ( tblDivisionId INT );
        WITH    temp
                  AS ( SELECT   Division_ID ,
                                DivisionParentID
                       FROM     Const_Division
                       WHERE    ( Division_ID = @DivisionID
                                  OR @DivisionID IS NULL
                                )
                       UNION ALL
                       SELECT   t.Division_ID ,
                                t.DivisionParentID
                       FROM     Const_Division t
                                JOIN temp ON temp.Division_ID = t.DivisionParentID
 )
            INSERT  INTO @temp
                    SELECT  temp.Division_ID
                    FROM    temp;
					
       SELECT DISTINCT  ProjectDetails.* ,
				(ReqCurrentYearAmt + ISNULL(VirementAmount.TotalVirementAmount,0) + SCOAItemAdjustment) AS SCOAItemAdjustmentBudget,
				(ReqCurrentYearP1Amt + SCOAItemAdjustment1) AS SCOAItemAdjustmentBudget1,
				(ReqCurrentYearP2Amt + SCOAItemAdjustment2) AS SCOAItemAdjustmentBudget2,
				ISNULL(VirementAmount.TotalVirementAmount,0) AS SCOAItemVirementTotal,
                AdjustmentApprover.[1] FirstRecommender,
                AdjustmentApprover.[2] SecondRecommender,
				AdjustmentApprover.[3] FinalRecommender
        FROM    
                (  SELECT DISTINCT  pp.AdjustmentProject_ID AS Project_ID,pp.AdjustmentProjectName AS AdjustmentProjectName,
				ppi.ReferencePlanProjectItem_ID,pppi.PlanProjectItem_ID, ppi.PlanAdjustmentProjectItem_ID, ISNULL(ppi.ProjectItemID,0) AS ProjectItemID,
                ( CAST( COALESCE(pp.ProjectCode,pp.ReferenceProject_ID,pp.AdjustmentProject_ID) AS VARCHAR(50)) + ' | '
                    + pp.AdjustmentProjectName ) AS ProjectName ,
                REPLACE(REPLACE(REPLACE(pp.AdjustmentProjectDesc, CHAR(10), ' '),
                                CHAR(13), ' '), CHAR(09), ' ') AS ProjectDesc ,
                pp.CostEstimate ,
                pp.CapitalOperation ,
                ( SELECT    TypeName
                    FROM      dbo.Const_PlanCapitalOperationalTypes_sys
                    WHERE     TypeValue = pp.CapitalOperation
                ) AS CapitalOperationDesc ,
                pp.ProjectStatus ,
                cs.StatusDesc ,
                dep.Department_ID ,
                cd.Division_ID ,
                pp.ProjectTypeID ,
                ( CAST(cd.Division_ID AS VARCHAR(10)) + ' '
                    + cd.DivisionDesc + ' / ' + cd.DivisionCode ) AS MuniClassification ,
                cpt.ProjectTypeDescrip ,
               func.ScoaCode AS SCOAFuncCode ,
                func.ScoaShortDesc AS SCOAFuncDesc ,
                func.ScoaDesc AS SCOAFunctions ,
                region.ScoaCode AS SCOARegionCode ,
                region.ScoaDesc AS SCOARegionDesc ,
                region.ScoaDesc AS SCOARegions ,
                costing.ScoaCode AS SCOACostingCode ,
                costing.ScoaDesc AS SCOACostingDesc ,
                project.ScoaCode AS SCOAProjectCode ,
                project.ScoaDesc AS SCOAProjectDesc ,
                fs.ScoaCode AS SCOAFundCode ,
                fs.ScoaDesc AS SCOAFundDesc ,
                fs.ScoaDesc AS SCOAFundings ,
                ISNULL(ppi.BudgetAmount,0) AS FUNDCurrentYearAmt ,
                ISNULL(ppi.BudgetAmountCurP1,0) AS FUNDCurrentP1YearAmt ,
                ISNULL(ppi.BudgetAmountCurP2,0) AS FUNDCurrentP2YearAmt ,
                cpi.ItemDescription ,
                css.ScoaCode ,
                css.ScoaDesc AS ScoaShortDesc ,
                CASE WHEN ( ppi.CreditDebit = 'C'
                            ) THEN -ISNULL(pbvd.BudgetAmount, 0)
                        ELSE ISNULL(pbvd.BudgetAmount, 0)
                END AS ReqCurrentYearAmt ,
                CASE WHEN ( ppi.CreditDebit = 'C'
                            ) THEN -ISNULL(pbvd.BudgetAmountCurP1, 0)
                        ELSE ISNULL(pbvd.BudgetAmountCurP1, 0)
                END AS ReqCurrentYearP1Amt ,
                CASE WHEN ( ppi.CreditDebit = 'C'
                            ) THEN -ISNULL(pbvd.BudgetAmountCurP2, 0)
                        ELSE ISNULL(pbvd.BudgetAmountCurP2, 0)
                END AS ReqCurrentYearP2Amt ,
				
				  CASE WHEN ( ppi.CreditDebit = 'C'
                            ) THEN -ISNULL(ppi.AdjustedBudgetAmount, 0)
                        ELSE ISNULL(ppi.AdjustedBudgetAmount, 0)
                END AS SCOAItemAdjustmentBudgetAmt ,
                CASE WHEN ( ppi.CreditDebit = 'C'
                            ) THEN -ISNULL(ppi.AdjustedBudgetAmountCurP1, 0)
                        ELSE ISNULL(ppi.AdjustedBudgetAmountCurP1, 0)
                END AS SCOAItemAdjustmentBudgetP1Amt ,
                CASE WHEN ( ppi.CreditDebit = 'C'
                            ) THEN -ISNULL(ppi.AdjustedBudgetAmountCurP2, 0)
                        ELSE ISNULL(ppi.AdjustedBudgetAmountCurP2, 0)
                END AS SCOAItemAdjustmentBudgetP2Amt ,
				
				CAST(0 AS DECIMAL(18,0)) AS ReqCurrentYearP3Amt ,
                0 AS ShowColumn,
				 ISNULL(pbv.VersionNumber, '') AS VersionNumber ,
                ISNULL(pbv.VersionName, '') AS VersionName ,
                ISNULL(pbv.Comments, '') AS Comments,
				(CASE WHEN ( ppi.CreditDebit = 'C')
				THEN -(ISNULL((CASE 
				WHEN  ISNULL(ppi.BudgetAmount,0) = 0
				THEN ISNULL(ppi.AdjustedBudgetAmount, 0)
				WHEN ISNULL(ppi.AdjustedBudgetAmount, -1) >= 0
				THEN ISNULL(ppi.AdjustedBudgetAmount,0) - ISNULL(ppi.BudgetAmount, 0)
				ELSE 0 END),0))
				ELSE
				(ISNULL((CASE 
				WHEN  ISNULL(ppi.BudgetAmount,0) = 0
				THEN ISNULL(ppi.AdjustedBudgetAmount, 0)
				WHEN ISNULL(ppi.AdjustedBudgetAmount, -1) >= 0
				THEN ISNULL(ppi.AdjustedBudgetAmount,0) - ISNULL(ppi.BudgetAmount, 0)
				ELSE 0 END),0)) END) AS SCOAItemAdjustment,
				
				(CASE WHEN ( ppi.CreditDebit = 'C')
				THEN -(ISNULL((CASE 
				WHEN ISNULL(ppi.BudgetAmountCurP1,0) = 0
				THEN ISNULL(ppi.AdjustedBudgetAmountCurP1, 0)
				WHEN ISNULL(ppi.AdjustedBudgetAmountCurP1, -1) >= 0
				THEN ISNULL(ppi.AdjustedBudgetAmountCurP1,0) - ISNULL(ppi.BudgetAmountCurP1, 0) 
				ELSE 0 END),0))
				ELSE
				(ISNULL((CASE 
				WHEN ISNULL(ppi.BudgetAmountCurP1,0) = 0
				THEN ISNULL(ppi.AdjustedBudgetAmountCurP1, 0)
				WHEN ISNULL(ppi.AdjustedBudgetAmountCurP1, -1) >= 0
				THEN ISNULL(ppi.AdjustedBudgetAmountCurP1,0) - ISNULL(ppi.BudgetAmountCurP1, 0) 
				ELSE 0 END),0)) END) AS SCOAItemAdjustment1,

				(CASE WHEN ( ppi.CreditDebit = 'C')
				THEN -(ISNULL((CASE 
				WHEN  ISNULL(ppi.BudgetAmountCurP2,0) = 0
				THEN ISNULL(ppi.AdjustedBudgetAmountCurP2, 0)
				WHEN ISNULL(ppi.AdjustedBudgetAmountCurP2, -1) >= 0
				THEN ISNULL(ppi.AdjustedBudgetAmountCurP2,0) - ISNULL(ppi.BudgetAmountCurP2, 0) 
				ELSE 0 END),0))
				ELSE
				(ISNULL((CASE 
				WHEN  ISNULL(ppi.BudgetAmountCurP2,0) = 0
				THEN ISNULL(ppi.AdjustedBudgetAmountCurP2, 0)
				WHEN ISNULL(ppi.AdjustedBudgetAmountCurP2, -1) >= 0
				THEN ISNULL(ppi.AdjustedBudgetAmountCurP2,0) - ISNULL(ppi.BudgetAmountCurP2, 0) 
				ELSE 0 END),0)) END) AS SCOAItemAdjustment2,
				cpa.AdjustmentType AS AdjustmentType,
				cpar.AdjustmentReason AS LegislativeReasonforAdjustment,
				ppi.ReasonForAdjustment AS ReasonforAdjustment,
				pp.AdjustmentVersionId,
				@ShowCostingProject ShowCostingProject,
				CASE WHEN ISNULL(pp.CostingProject, 0) = 0 THEN 'No' ELSE 'Yes' END CostingProject
        FROM    dbo.Plan_AdjustmentProject pp
				LEFT JOIN  Plan_Project ppp  ON pp.AdjustmentProjectName = ppp.ProjectName
				INNER JOIN dbo.Plan_AdjustmentBudgetVersion pbv ON pbv.AdjustmentBudgetVersion_ID = pp.AdjustmentVersionId AND pbv.AdjustmentBudgetVersion_ID = @AdjustmentVersionId
                LEFT OUTER JOIN dbo.Plan_AdjustmentProjectItem ppi ON pp.AdjustmentProject_ID = ppi.AdjustmentProjectID
				LEFT JOIN  Plan_Projectitem pppi  ON pppi.ProjectID = ppp.Project_ID AND ppi.PlanAdjustmentProjectItem_ID = pppi.AdjustmentId
				LEFT JOIN Plan_BudgetVersionDetail pbvd ON ppi.ReferencePlanProjectItem_ID = pbvd.PlanProjectItemID AND pbvd.BudgetVersionID = @BudgetVerionID
				LEFT JOIN dbo.Const_PlanAdjustmentType_sys cpa ON cpa.AdjustmentType_ID = ppi.AdjutmentType
				LEFT JOIN dbo.Const_PlanAdjustmentReason_sys cpar ON cpar.AdjustmentReason_ID = ppi.LegislativeReasonAdjustment
                LEFT OUTER JOIN Const_Status cs ON cs.Status_ID = pp.ProjectStatus
                LEFT OUTER JOIN Const_Division cd ON cd.Division_ID = ppi.DivisionId
                LEFT OUTER JOIN Const_Department dep ON cd.DepartmentID = dep.Department_ID
                LEFT OUTER JOIN #Const_SCOA_Function_Structure AS func ON func.ScoaID = ppi.SCOAFunctionId
                LEFT OUTER JOIN #Const_SCOA_Region_Structure AS region ON region.ScoaID = ppi.SCOARegionId
                LEFT OUTER JOIN #Const_SCOA_Costing_Structure AS costing ON costing.ScoaID = ppi.SCOACostingID
                LEFT OUTER JOIN #Const_SCOA_Project_Structure AS project ON project.ScoaID = pp.ScoaProjectID
                LEFT OUTER JOIN Const_ProjectItem cpi ON ppi.ProjectItemID = cpi.ProjectItem_ID
                LEFT OUTER JOIN #Const_SCOA_Structure AS css ON ppi.SCOAItemID = css.ScoaID
                LEFT OUTER JOIN Const_ProjectType cpt ON pp.ProjectTypeID = cpt.ProjectType_ID
                LEFT OUTER JOIN #Const_SCOA_Fund_Structure AS fs ON ppi.SCOAFundId = fs.ScoaID
                INNER JOIN @temp t ON t.tblDivisionId = cd.Division_ID
        WHERE   ( CASE WHEN @ProjectID = 0 THEN 0
                        ELSE pp.AdjustmentProject_ID
                    END = @ProjectID )
                AND ( CASE WHEN @ScoaFundID = 0 THEN 0
                            ELSE fs.ScoaID
                        END = @ScoaFundID )
                AND ( CASE WHEN @ScoaFunctionID = 0 THEN 0
                            ELSE func.ScoaID
                        END = @ScoaFunctionID )
                AND ( CASE WHEN @ScoaRegionID = 0 THEN 0
                            ELSE region.ScoaID
                        END = @ScoaRegionID )
                AND ( CASE WHEN @ScoaItemID = 0 THEN 0
                            ELSE css.ScoaID
                        END = @ScoaItemID )
                AND ( CASE WHEN @DepartmentID = 0 THEN 0
                            ELSE dep.Department_ID
                        END = @DepartmentID )
                AND ( CASE WHEN @ProjectTypeID = 0 THEN 0
                            ELSE pp.ProjectTypeID
                        END = @ProjectTypeID )
                AND ( CASE WHEN @FinYear = '' THEN ''
                            ELSE pp.FinYear
                        END = @FinYear )
                AND ( CASE WHEN @FinYear = '' THEN ''
                            ELSE ppi.FinYear
                        END = @FinYear )
                AND ( CASE WHEN @ProjectStatusId = 0 THEN 0
                            ELSE pp.ProjectStatus
                        END = @ProjectStatusId )
				AND ( CASE WHEN @ScoaCostingID = 0 THEN 0
                            ELSE ppi.SCOACostingID
                        END = @ScoaCostingID )
				AND ( CASE WHEN @ScoaProjectID = 0 THEN 0
                            ELSE pp.ScoaProjectID
                        END = @ScoaProjectID )
                AND ( CASE WHEN @SingleMultiYear = '' THEN ''
                            ELSE pp.SingleMultiYear
                        END = @SingleMultiYear )
				AND (CASE WHEN @ShowCostingProject = 1 THEN @ShowCostingProject
							ELSE ISNULL(pp.CostingProject, 0) END = @ShowCostingProject  )
                AND ( pp.CapitalOperation IN (SELECT BudgetTypeID FROM @tblBudgetType) )
				AND ((@Information = 1 AND ISNULL(pp.ReferenceProject_ID,0) >= 0 AND (( ISNULL(ppi.AdjustedBudgetAmount, 0)
                        + ISNULL(ppi.AdjustedBudgetAmountCurP1, 0)
                        + ISNULL(ppi.AdjustedBudgetAmountCurP2, 0) ) <> 0 or ppi.AdjustedBudgetAmount IS NOT NULL))
						 OR 
					(@Information <> 1 AND (( ISNULL(ppi.BudgetAmount, 0)
                        + ISNULL(ppi.BudgetAmountCurP1, 0)
                        + ISNULL(ppi.BudgetAmountCurP2, 0) ) <> 0 
						OR 
						( ISNULL(pbvd.BudgetAmount, 0)
                        + ISNULL(pbvd.BudgetAmountCurP1, 0)
                        + ISNULL(pbvd.BudgetAmountCurP2, 0) ) <> 0

						OR (( ISNULL(ppi.AdjustedBudgetAmount, 0)
                        + ISNULL(ppi.AdjustedBudgetAmountCurP1, 0)
                        + ISNULL(ppi.AdjustedBudgetAmountCurP2, 0) ) <> 0) OR ppi.AdjustedBudgetAmount IS NOT NULL)))

                AND ISNULL(pp.IsDeleted, 0) <> 1
				AND (ISNULL(ppp.IsDeleted, 0) <> 1 OR ppp.IsDeleted IS NULL) AND (ppp.FinYear= @FinYear OR ppp.FinYear IS NULL)
				)
				AS ProjectDetails
                LEFT JOIN ( SELECT *
                             FROM   ( SELECT    PV.AdjustmentProject_ID ,
                                                UUD.FirstName + ' '
                                                + UUD.LastName AS Approver ,
                                                ROW_NUMBER() OVER ( PARTITION BY PV.AdjustmentProject_ID ORDER BY PVAU.AdjustmentProjectRecommendUser_Id ) AS ApproverNo
                                      FROM      dbo.Plan_AdjustmentProject AS PV
                                                INNER JOIN dbo.Plan_AdjustmentProjectRecommendUsers PVAU ON PV.AdjustmentProject_ID = PVAU.AdjustmentProjectId
                                                INNER JOIN dbo.User_UserDetail UUD ON UUD.User_ID = PVAU.UserId
                                      WHERE     
									  ( CASE WHEN @ProjectID = 0 THEN 0 ELSE PV.AdjustmentProject_ID END = @ProjectID )
                                               
                                    ) S PIVOT
								( MAX(Approver) FOR ApproverNo IN ( [1], [2], [3] ) ) piv
                           ) AS AdjustmentApprover ON ProjectDetails.Project_ID = AdjustmentApprover.AdjustmentProject_ID
				LEFT JOIN
				(SELECT  SUM(virementFromTo.VirementAmount) AS TotalVirementAmount, 
					virementFromTo.PlanProjectItem_ID, virementFromTo.ProjectID FROM 
					(SELECT -ISNULL(V.FromVirementAmount, 0) AS VirementAmount, PPIFrom.PlanProjectItem_ID,PPIFrom.ProjectID,V.VirementId
					 FROM  dbo.Plan_Project PrjFrom
					 INNER JOIN dbo.Plan_ProjectItem PPIFrom ON PPIFrom.ProjectID = PrjFrom.Project_ID
					INNER JOIN dbo.Plan_Virements V ON V.FromProjectId = PrjFrom.Project_ID
					AND V.FromSCOAProjectID = PrjFrom.ScoaProjectID AND v.FromSCOAFunctionId = PPIFrom.SCOAFunctionId
					AND v.FromDivisionId = PPIFrom.DivisionId AND V.FromSCOAFundID = PPIFrom.SCOAFundId
					AND v.FromSCOARegion = PPIFrom.SCOARegionId AND v.FromSCOAItem = PPIFrom.SCOAItemID
					AND v.FromSCOACostingId = PPIFrom.SCOACostingID  
					WHERE V.FromProjectID <> V.ToProjectID 
					UNION
					SELECT ISNULL(V.ToVirementAmount, 0) AS VirementAmount, PPITo.PlanProjectItem_ID,PPITo.ProjectID,V.VirementId
					FROM  dbo.Plan_Project PrjTo
					 INNER JOIN dbo.Plan_ProjectItem PPITo ON PPITo.ProjectID = PrjTo.Project_ID
					INNER JOIN dbo.Plan_Virements V ON V.ToProjectId = PrjTo.Project_ID
					AND V.ToSCOAProjectID = PrjTo.ScoaProjectID AND v.ToSCOAFunctionId = PPITo.SCOAFunctionId
					AND v.ToDivisionId = PPITo.DivisionId AND V.ToSCOAFundID = PPITo.SCOAFundId
					AND v.ToSCOARegion = PPITo.SCOARegionId AND v.ToSCOAItem = PPITo.SCOAItemID
					AND v.ToSCOACostingId = PPITo.SCOACostingID 
					WHERE V.FromProjectID <> V.ToProjectID 
					) AS virementFromTo LEFT JOIN
					Plan_VirementApprovalRejections vrej ON virementFromTo.VirementID = vrej.VirementID
					WHERE ISNULL(IsRejected, 1) <> 1
					GROUP BY virementFromTo.PlanProjectItem_ID,ProjectID) 
					AS VirementAmount ON ISNULL(ProjectDetails.ReferencePlanProjectItem_ID,ProjectDetails.PlanProjectItem_ID) = VirementAmount.PlanProjectItem_ID
        ORDER BY MuniClassification;
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetAdjustmentProjectByDepartmentId_sp]    Script Date: 2026/03/10 7:23:32 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 27/11/2017
-- Description:	Get AdjustmentProject using DepartmentId
-- Calls: Plan_GetAdjustmentProjectByDepartmentId_sp '1,2,3,4','2016/2017','2016/2017'
-- 13-Aug-2020 ChrisM: 4727 - Standardise formatting for project name
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetAdjustmentProjectByDepartmentId_sp]
@DepartmentId NVARCHAR(200) ='1,2,3,4',
@FinYear NVARCHAR(9),
@UserFinYear NVARCHAR(10) 
	AS
    BEGIN
	
	SET NOCOUNT ON;
	
	DECLARE @AdjustmentVersionId INT;

	SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion WHERE VersionName 
	LIKE @UserFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC


				--To get all parent child divisions 
        DECLARE @temp TABLE ( tblDivisionId INT NULL);

        WITH    temp
                  AS ( SELECT   Division_ID ,
                                DivisionParentID
                       FROM     dbo.Const_Division
                       WHERE    (@DepartmentId = '0' OR DepartmentID IN (
						SELECT CAST(Data AS INT) FROM dbo.Split(@DepartmentId, ',')
					   ))
                       UNION ALL
                       SELECT   t.Division_ID ,
                                t.DivisionParentID
                       FROM     dbo.Const_Division t
                                JOIN temp ON temp.Division_ID = t.DivisionParentID
                     )
            INSERT  INTO @temp
                    SELECT  temp.Division_ID
                    FROM    temp;

			SELECT DISTINCT
		   pp.AdjustmentProject_ID ,
           CAST( COALESCE(pp.ProjectCode,pp.ReferenceProject_ID,pp.AdjustmentProject_ID) AS VARCHAR(50)) + ' | ' + pp.AdjustmentProjectName AS AdjustmentProjectName,
		   CAST( COALESCE(pp.ProjectCode,pp.ReferenceProject_ID,pp.AdjustmentProject_ID) AS VARCHAR(50)) + ' | ' + pp.AdjustmentProjectName + '(' + csps.ScoaCode + ')' AS AdjustmentProjectScoaShortDesc ,
           pp.AdjustmentProjectDesc ,
           pp.ProjectManagerID ,
           pp.CapitalOperation ,
           pp.ScoaProjectID ,
           pp.ProjectStatus ,
           pp.FinYear ,
           pp.ProjectTypeID ,
           pp.IsDeleted,
		   0 AS Division_ID -- Division_ID is not using on code, So for distinct result Make it 0
		    FROM dbo.Plan_AdjustmentProject pp
			INNER HASH JOIN dbo.Const_SCOA_Project_Structure csps ON csps.ScoaID = pp.ScoaProjectID
			INNER JOIN dbo.Plan_AdjustmentProjectDivisions ppd ON ppd.AdjustmentProjectID = pp.AdjustmentProject_ID
			INNER JOIN dbo.Const_Division cd ON cd.Division_ID = ppd.DivisionID
			WHERE (pp.FinYear=@FinYear OR @FinYear='0') AND
			cd.Division_ID IN  (SELECT DISTINCT tblDivisionId FROM @temp) AND ISNULL(pp.IsDeleted,0)=0
			AND pp.AdjustmentVersionId= @AdjustmentVersionId
END;
GO

