/****** Object:  StoredProcedure [dbo].[Plan_GetAdjustmentProjectDetailsForDashboard_sp]    Script Date: 2026/03/10 7:23:32 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Nirav Parikh
-- Create date: 26 Dec 2017
-- Description:	Get Adjustment Project Details for dashboard data
-- Calls: [Plan_GetAdjustmentProjectDetailsForDashboard_sp] '2017/2018'
-- 05-Feb-18 SNagpal: #67262 Change Status Desc 'Initiated/Adjusted' -> 'Adjusted/Recommended'
-- 05-Feb-18 SNagpal: Default return 1 so replace count(1) with COUNT(pp.AdjustmentProject_ID)
-- NParikh 05-Feb-2017 67338 Bug Nr 50: Planning dashboard indication incorrect when budget is copied over
-- SNagpal 10-Apr-2018 : Add @AdjustmentVersionId logic
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetAdjustmentProjectDetailsForDashboard_sp]
@FYear NVARCHAR(9)
AS
BEGIN
    SET NOCOUNT ON;

	DECLARE @AdjustmentVersionId INT;

				SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion papv 
				INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentVersionId = papv.AdjustmentBudgetVersion_ID
				WHERE VersionName LIKE @FYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC	    

    SELECT ISNULL([Capture Project], 0) AS Captured,
           ISNULL([Registered/IDP], 0) AS Registered,
		   ISNULL([Adjusted/Recommended], 0) AS Adjusted,
		   ISNULL([Initiated], 0) AS Initiated		   
    FROM
    (
        SELECT cs.StatusDesc,
               COUNT(pp.AdjustmentProject_ID) tot
        FROM dbo.Plan_AdjustmentProject pp
            RIGHT JOIN dbo.Const_Status cs
                ON pp.ProjectStatus = cs.Status_ID
        WHERE ISNULL(pp.IsDeleted, 0) = 0 AND cs.UsedBy ='ProjectRegister' AND cs.Enabled = 1 AND pp.FinYear = @FYear
		AND pp.AdjustmentVersionId = @AdjustmentVersionId
		GROUP BY cs.StatusDesc
    ) T
    PIVOT
    (
        MIN(tot)
        FOR StatusDesc IN ([Capture Project], [Registered/IDP], [Adjusted/Recommended], [Initiated])
    ) P;
END;
GO

