-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 25/11/2017
-- Description:	Get AdjustmentProject Division details by AdjustmentProject id, DivisionID
-- Used in : Adjustment Project Capture Screen
-- Plan_GetAdjustmentProjectDivisions_sp 0 ,0,0,'2016/2017'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetAdjustmentProjectDivisions_sp] 
	@AdjustmentProjectID int,
	@DivisionID INT,
	@UserId INT,
	@UserFinYear NVARCHAR(10) 
AS
BEGIN
SET FMTONLY OFF
SET NOCOUNT ON

	DECLARE @AdjustmentVersionId INT;

	SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion WHERE VersionName 
	LIKE @UserFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

	 create table #temp2
	 (TID int identity(1,1),
	  DivisionParentID int,
	  Division_ID int,
	  DivisionDesc nvarchar(200) COLLATE Latin1_General_CI_AS,
	  DivisionCode nvarchar(50) COLLATE Latin1_General_CI_AS,
	  DepartmentID int,
	  DivEnabled bit,
	  DeptEnabled bit);

	--Recursive code found on net
	  WITH DeptDivGroup (DivisionParentID, Division_ID, DivisionDesc, DivisionCode, DepartmentID)
	AS
	(
	-- Anchor member definition
		SELECT e.DivisionParentID, e.Division_ID, e.DivisionDesc,e.DivisionCode, e.DepartmentID
		FROM dbo.Const_Division AS e
		WHERE ISNULL(DivisionParentID,0) = 0
		UNION ALL
	-- Recursive member definition
		SELECT e.DivisionParentID,e.Division_ID, e.DivisionDesc,e.DivisionCode, e.DepartmentID 
		FROM dbo.Const_Division AS e
		INNER JOIN DeptDivGroup AS d
			ON e.DivisionParentID = d.Division_ID 
	)


	Insert into #temp2 (DivisionParentID, Division_ID, DivisionDesc, DivisionCode, DepartmentID)
	Select
		DivisionParentID, Division_ID, DivisionDesc, DivisionCode, DepartmentID
	From 
		DeptDivGroup


	SELECT DISTINCT pd.AdjustmentProjectDivision_ID 
	, pd.AdjustmentProjectID
	, pd.ReferenceProjectDivisionID
	, pd.DivisionID
	,(DivisionDesc + ' / ' + DivisionCode) as MunicipalClassification
	,(DivisionCode + ' / ' + DivisionDesc 
	+  ISNULL(' ( ' + dbo.Plan_DivisionDescDirectorate_fxn(pd.DivisionID) + ' )', '')
	) AS MunicipalClassDesc
	, rs.DivisionDesc
	, rs.DivisionCode
	,rs.DepartmentID
	--FROM Const_Division rs  --Uncomment this while update edmx
	FROM #temp2 rs  
	INNER JOIN dbo.Plan_AdjustmentProjectDivisions pd ON pd.DivisionID=rs.Division_ID
	INNER JOIN dbo.Const_Department cd on rs.DepartmentID = cd.Department_ID
	LEFT JOIN dbo.User_UserDivisions uud ON uud.DivisionID = pd.DivisionID
	WHERE 
		(CASE WHEN @AdjustmentProjectID = 0 THEN 0
				   ELSE pd.AdjustmentProjectID END = @AdjustmentProjectID)
		AND (CASE WHEN @DivisionID = 0 THEN 0
				   ELSE pd.DivisionID END = @DivisionID)
		AND (CASE WHEN @UserId = 0 THEN 0
				   ELSE uud.UserID END = @UserId)
        AND pd.AdjustmentVersionId = @AdjustmentVersionId
			drop table #temp2
END


GO

