-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 27/11/2017
-- Description:	Get AdjustmentProject item funds details by AdjustmentProject id, ScoaFundID and fin year
-- Plan_GetAdjustmentProjectItemFunds_sp 0,0,'2018/2019','2018/2019'
-- OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetAdjustmentProjectItemFunds_sp]
	@AdjustmentProjectID int,
	@ScoaFundID int,
	@FinYear nvarchar(9),
	@UserFinYear NVARCHAR(10) 
AS
BEGIN
SET NOCOUNT ON

	DECLARE @AdjustmentVersionId INT

	SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion WHERE VersionName 
	LIKE @UserFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

	SELECT DISTINCT
	pf.AdjustmentProjectFund_ID,pf.ReferenceProjectFundID, pf.AdjustmentProjectID, pf.ScoaFundID, pf.FundAmount
	, pf.FundReference, pfy.FinYear, pfy.AdjustmentProjectFundYear_ID, pfy.YearFundAmount	
	, ppi.SCOAItemID, ppi.ProjectItemID, p.ItemDescription, ss.ScoaCode
	, ss.ScoaShortDesc AS SCOAItemDesc, fs.ScoaCode AS SCOAFundCode, fs.ScoaShortDesc AS SCOAFundDesc
	FROM Plan_AdjustmentProjectFund pf 
	INNER JOIN Plan_AdjustmentProjectFundYear pfy ON  pf.AdjustmentProjectFund_ID=pfy.AdjustmentProjectFundID
	INNER JOIN Plan_AdjustmentProjectItem ppi on  ppi.AdjustmentProjectID= pf.AdjustmentProjectID
	AND ppi.SCOAFundId = pf.ScoaFundID
	LEFT JOIN Const_ProjectItem p ON p.ProjectItem_ID=ppi.ProjectItemID
	INNER JOIN dbo.Const_SCOA_Structure_ByYear(@FinYear) ss ON ss.ScoaID=ppi.SCOAItemID
	INNER JOIN dbo.Const_SCOA_Funds_Structure_ByYear(@FinYear) fs ON fs.ScoaID=pf.ScoaFundID
	WHERE (pf.AdjustmentProjectID=@AdjustmentProjectID  OR  @AdjustmentProjectID =0)
		AND (pf.ScoaFundID=@ScoaFundID  OR @ScoaFundID  = 0)
		AND (pfy.FinYear= @FinYear OR @FinYear  ='') AND pf.AdjustmentVersionId= @AdjustmentVersionId;

END
GO

