/****** Object:  StoredProcedure [dbo].[Plan_GetAdjustmentProjectSearch_sp]    Script Date: 2026/03/10 7:23:32 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 29/11/2017
-- Description: Get list of AdjustmentProjects based on search criteria
-- [dbo].[Plan_GetAdjustmentProjectSearch_sp] 0,3,'2025/2026',327,0,0,0,0,41198,0,0,'0','2025/2026'
-- 06-02-2018 SNagpal: 67399 SCOA Item description column on project search grid to be removed to enhance page response when searching for projects
-- 14-02-2018: SNagpal: 67819 SCOA Funding description column on project search grid to be removed to enhance page response when searching for projects
-- 15-02-2018: SNagpal: 67819As per suggestion from Travis;  Add If Else Condition if There is Project Id Parameter
-- 26-02-2018: SNagpal: Optimize the stored procedure, As its taking long time to load when execute for large results.
-- 05-07-2018: SNagpal: Fix FinYear filter
-- 24-01-2019: SNagpal: #61596 - #83633 - Add functionality to get ProjectCode
-- SNagpal 18-02-2019 : 84009, Get SCOA Segments based upon FinYear
-- 24-May-2019 SNagpal: Add multiyear concept to get SCOA segments based upon finyear
-- 20-Oct-2025 CMoodley: 124313 - Optimise SP
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetAdjustmentProjectSearch_sp]
    @IDPItemID INT = 0,
    @AdjustmentProjectID INT = 0,
    @FinYear NVARCHAR(10) ='2017/2018',
    @ScoaFunctionID INT = 0,
	@ScoaCostingID INT = 0,
    @ScoaAdjustmentProjectID INT = 0 ,
    @ScoaRegionID INT = 0 ,
    @DivisionID INT = 0 ,
	@SCOAItemID INT = 0,
	@SCOAFundID INT = 0,
    @StatusId INT = 0 ,
	@DepartmentId NVARCHAR(200) = '0',
	@UserFinYear NVARCHAR(10) ='2017/2018'
AS
BEGIN
    SET NOCOUNT ON;

    ----------------------------------------------------------------------
    -- Get latest AdjustmentVersionId for the supplied UserFinYear
    ----------------------------------------------------------------------
    DECLARE @AdjustmentVersionId INT;
    SELECT TOP (1)
        @AdjustmentVersionId = AdjustmentBudgetVersion_ID
    FROM dbo.Plan_AdjustmentBudgetVersion
    WHERE VersionName LIKE @UserFinYear + '%'
    ORDER BY AdjustmentBudgetVersion_ID DESC;

    ----------------------------------------------------------------------
    -- FinYear used for SCOA lookup (fallback to config setting)
    ----------------------------------------------------------------------
    DECLARE @FinYearForSCOA VARCHAR(9) = @FinYear;

    IF (@FinYearForSCOA IS NULL OR LTRIM(RTRIM(@FinYearForSCOA)) = '' OR @FinYearForSCOA = '0')
    BEGIN
        SELECT @FinYearForSCOA = KeyValue
        FROM dbo.AAAA_ConfigSettings
        WHERE KeyName = 'ActiveFinYear';
    END

    ----------------------------------------------------------------------
    -- Build allowed division list once (recursive).  
    -- Note: dbo.Split is left as-is; it must return a column named "Data".
    ----------------------------------------------------------------------
    DECLARE @AllowedDivisions TABLE ( DivisionId INT NOT NULL PRIMARY KEY );

    IF (@DivisionID <> 0)
    BEGIN
        INSERT INTO @AllowedDivisions (DivisionId) VALUES (@DivisionID);
    END
    ELSE IF (ISNULL(@DepartmentId, '0') <> '0')
    BEGIN
        ;WITH CTEtempDivision AS
        (
            -- seed: divisions for provided department ids
            SELECT d.Division_ID, d.DivisionParentID
            FROM dbo.Const_Division d
            WHERE (CASE WHEN @DepartmentId = '0' THEN '0' ELSE d.DepartmentID END) IN
                  (SELECT CAST(Data AS INT) FROM dbo.Split(@DepartmentId, ','))
            UNION ALL
            SELECT child.Division_ID, child.DivisionParentID
            FROM dbo.Const_Division child
            INNER JOIN CTEtempDivision parent ON parent.Division_ID = child.DivisionParentID
        )
        INSERT INTO @AllowedDivisions (DivisionId)
        SELECT DISTINCT Division_ID FROM CTEtempDivision;
    END
    -- else: leave @AllowedDivisions empty => no division filtering applied

    ----------------------------------------------------------------------
    -- Main result set: one row per AdjustmentProject with aggregated
    -- descriptive columns obtained from correlated subqueries.
    ----------------------------------------------------------------------
    SELECT
        p.AdjustmentProject_ID,
        p.ReferenceProject_ID,
        -- Item descriptions aggregated from AdjustmentProjectIDP -> IDP_Item
        ItemDesc = STUFF((
            SELECT DISTINCT ',' + ISNULL(i2.ItemDesc, '')
            FROM dbo.Plan_AdjustmentProjectIDP apid2
            LEFT JOIN dbo.IDP_Item i2 ON apid2.ParentIDPItemID = i2.Item_ID
            WHERE apid2.AdjustmentProjectID = p.AdjustmentProject_ID
              AND (@IDPItemID = 0 OR apid2.ParentIDPItemID = @IDPItemID)
            FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),
		IDPItemID = 0,
        p.ScoaProjectID,
        SCOAProjectCode = sp.ScoaCode,
        SCOAProjDesc = sp.ScoaDesc,
        AdjustmentProjectName = p.AdjustmentProjectName,
        AdjustmentProjectDesc = REPLACE(REPLACE(REPLACE(p.AdjustmentProjectDesc, CHAR(10), ' '), CHAR(13), ' '), CHAR(9), ' '),
        p.FinYear,
        DepartmentId = 0, 
        -- SCOA function descriptions (from AdjustmentProjectItem)
        ScoaShortDesc = STUFF((
            SELECT DISTINCT ',' + ISNULL(sf2.ScoaDesc, '')
            FROM dbo.Plan_AdjustmentProjectItem ppi2
            LEFT JOIN dbo.Const_SCOA_Function_Structure_Consolidated sf2
                ON ppi2.ScoaFunctionID = sf2.ScoaID AND sf2.FinYearText = @FinYearForSCOA
            WHERE ppi2.AdjustmentProjectID = p.AdjustmentProject_ID
              AND (@ScoaFunctionID = 0 OR ppi2.ScoaFunctionID = @ScoaFunctionID)
            FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),

        ScoaCostingShortDesc = STUFF((
            SELECT DISTINCT ',' + ISNULL(scs2.ScoaDesc, '')
            FROM dbo.Plan_AdjustmentProjectItem ppi2
            LEFT JOIN dbo.Const_SCOA_Costing_Structure_Consolidated scs2
                ON ppi2.ScoaCostingID = scs2.ScoaID AND scs2.FinYearText = @FinYearForSCOA
            WHERE ppi2.AdjustmentProjectID = p.AdjustmentProject_ID
              AND (@ScoaCostingID = 0 OR ppi2.ScoaCostingID = @ScoaCostingID)
            FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),

        ScoaRegionShortDesc = STUFF((
            SELECT DISTINCT ',' + ISNULL(sr2.ScoaDesc, '') + ' (' + CONVERT(NVARCHAR(300), ISNULL(ppr2.RegionPercent, '0')) + ')'
            FROM dbo.Plan_AdjustmentProjectRegions ppr2
            LEFT JOIN dbo.Const_SCOA_Regional_Structure_Consolidated sr2
                ON ppr2.ScoaRegionID = sr2.ScoaID AND sr2.FinYearText = @FinYearForSCOA
            WHERE ppr2.AdjustmentProjectID = p.AdjustmentProject_ID
              AND (@ScoaRegionID = 0 OR ppr2.ScoaRegionID = @ScoaRegionID)
            FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),

        -- Funds description
        ScoaFundsShortDesc = STUFF((
            SELECT DISTINCT ',' + ISNULL(sfnd.ScoaDesc, '')
            FROM dbo.Plan_AdjustmentProjectItem ppiF
            LEFT JOIN dbo.Const_SCOA_Funds_Structure_Consolidated sfnd
                ON ppiF.ScoaFundID = sfnd.ScoaID AND sfnd.FinYearText = @FinYearForSCOA
            WHERE ppiF.AdjustmentProjectID = p.AdjustmentProject_ID
              AND (@SCOAFundID = 0 OR ppiF.ScoaFundID = @SCOAFundID)
            FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),

        -- Division descriptions (from AdjustmentProjectItem)
        ScoaDivisionShortDesc = STUFF((
            SELECT DISTINCT ',' + ISNULL(cd2.DivisionDesc, '')
            FROM dbo.Plan_AdjustmentProjectItem ppi2
            LEFT JOIN dbo.Const_Division cd2 ON ppi2.DivisionID = cd2.Division_ID
            WHERE ppi2.AdjustmentProjectID = p.AdjustmentProject_ID
              AND (
                    (@DivisionID = 0 AND ISNULL(@DepartmentId,'0') = '0')
                    OR cd2.Division_ID IN (SELECT DivisionId FROM @AllowedDivisions)
                  )
            FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),

        -- Item descriptions 
        ScoaItemDesc = STUFF((
            SELECT DISTINCT ',' + ISNULL(si.ScoaDesc, '')
            FROM dbo.Plan_AdjustmentProjectItem ppi3
            LEFT JOIN dbo.Plan_Const_SCOA_Structure_Consolidated_vw si
                ON ppi3.ScoaItemID = si.ScoaID AND si.FinYearText = @FinYearForSCOA
            WHERE ppi3.AdjustmentProjectID = p.AdjustmentProject_ID
              AND (@SCOAItemID = 0 OR ppi3.ScoaItemID = @SCOAItemID)
            FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),

        ProjectStatus = p.ProjectStatus,
        SCOAAdjustmentProjectDesc = sp.ScoaShortDesc,
        AdjustmentProjectStatusDesc = cs.StatusDesc,
        CapitalOperationDesc = (SELECT TOP (1) TypeName FROM dbo.Const_PlanCapitalOperationalTypes_sys WHERE TypeValue = p.CapitalOperation),
        ProjectCode = p.ProjectCode
    FROM dbo.Plan_AdjustmentProject p
    INNER JOIN dbo.Const_SCOA_Project_Structure_Consolidated sp
        ON p.ScoaProjectID = sp.ScoaID AND sp.FinYearText = @FinYearForSCOA
    LEFT JOIN dbo.Const_Status cs ON cs.Status_ID = p.ProjectStatus
    WHERE
        -- required: same AdjustmentVersion as the caller expects
        p.AdjustmentVersionId = @AdjustmentVersionId

        -- project-level (SARGable) filters
        AND (@AdjustmentProjectID = 0 OR p.AdjustmentProject_ID = @AdjustmentProjectID)
        AND (@FinYear = '' OR p.FinYear = @FinYear)
        AND (@ScoaAdjustmentProjectID = 0 OR sp.ScoaID = @ScoaAdjustmentProjectID)
        AND (@StatusId = 0 OR p.ProjectStatus = @StatusId)
        AND ISNULL(p.IsDeleted, 0) = CASE WHEN (@StatusId = 5) THEN 1 ELSE 0 END

        -- SCOA-level filters expressed as EXISTS on AdjustmentProjectItem / AdjustmentProjectRegions
        AND (
            @ScoaFunctionID = 0
            OR EXISTS (SELECT 1 FROM dbo.Plan_AdjustmentProjectItem ppi WHERE ppi.AdjustmentProjectID = p.AdjustmentProject_ID AND ppi.ScoaFunctionID = @ScoaFunctionID)
        )
        AND (
            @ScoaCostingID = 0
            OR EXISTS (SELECT 1 FROM dbo.Plan_AdjustmentProjectItem ppi WHERE ppi.AdjustmentProjectID = p.AdjustmentProject_ID AND ppi.ScoaCostingID = @ScoaCostingID)
        )
        AND (
            @ScoaRegionID = 0
            OR EXISTS (SELECT 1 FROM dbo.Plan_AdjustmentProjectRegions pr WHERE pr.AdjustmentProjectID = p.AdjustmentProject_ID AND pr.ScoaRegionID = @ScoaRegionID)
        )
        AND (
            @SCOAItemID = 0
            OR EXISTS (SELECT 1 FROM dbo.Plan_AdjustmentProjectItem ppi WHERE ppi.AdjustmentProjectID = p.AdjustmentProject_ID AND ppi.ScoaItemID = @SCOAItemID)
        )
        AND (
            @SCOAFundID = 0
            OR EXISTS (SELECT 1 FROM dbo.Plan_AdjustmentProjectItem ppi WHERE ppi.AdjustmentProjectID = p.AdjustmentProject_ID AND ppi.ScoaFundID = @SCOAFundID)
        )
        AND (
            @IDPItemID = 0
            OR EXISTS (SELECT 1 FROM dbo.Plan_AdjustmentProjectIDP apid WHERE apid.AdjustmentProjectID = p.AdjustmentProject_ID AND apid.ParentIDPItemID = @IDPItemID)
        )
        -- Division/Department filter: only apply when there's a filter requested
        AND (
            (@DivisionID = 0 AND ISNULL(@DepartmentId,'0') = '0')
            OR EXISTS (
                SELECT 1
                FROM dbo.Plan_AdjustmentProjectItem apix
                LEFT JOIN dbo.Const_Division cdx ON apix.DivisionID = cdx.Division_ID
                WHERE apix.AdjustmentProjectID = p.AdjustmentProject_ID
                  AND cdx.Division_ID IN (SELECT DivisionId FROM @AllowedDivisions)
            )
        );

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetAdjustmentProjectWithDeptDivisions_sp]    Script Date: 2026/03/10 7:23:32 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 08/02/2019
-- Description:	Get AdjustmentProject Division details by AdjustmentProject id, DivisionID
-- Used in : Adjustment Project Capture Screen
-- Plan_GetAdjustmentProjectWithDeptDivisions_sp 25920,0,'2018/2019'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetAdjustmentProjectWithDeptDivisions_sp] 
	@AdjustmentProjectID INT = 25982,
	@UserId INT = 0,
	@UserFinYear NVARCHAR(10) ='2018/2019'
	AS
BEGIN
SET FMTONLY OFF
SET NOCOUNT ON

	DECLARE @AdjustmentVersionId INT,
			@DivisionID INT = 0,
			@AdjustmentProjectDivision_ID INT,
			--@AdjustmentProjectID INT,
			@ReferenceProjectDivisionID INT,
			@DepartmentCode VARCHAR(50),
			@DepartmentDesc VARCHAR(200);

	SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion WHERE VersionName 
	LIKE @UserFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC
	
	  CREATE TABLE #tempAdjustDivision
	  (	DivisionId INT,
		AdjustmentProjectDivision_ID INT,
		AdjustmentProjectID INT,
		ReferenceProjectDivisionID INT,
		DepartmentCode VARCHAR(50),
		DepartmentDesc VARCHAR(200));

	  CREATE TABLE #tempStuffedDivision
	  (	DivisionId VARCHAR(Max),
		StuffedDivisionDesc VARCHAR(MAx),
		StuffedDivisionCode VARCHAR(MAx),
		AdjustmentProjectDivision_ID INT,
		AdjustmentProjectID INT,
		ReferenceProjectDivisionID INT,
		DepartmentCode VARCHAR(50),
		DepartmentDesc VARCHAR(200));

	  INSERT INTO #tempAdjustDivision
	  (
	      DivisionId,
		  AdjustmentProjectDivision_ID,
		  AdjustmentProjectID,
		  ReferenceProjectDivisionID,
		  DepartmentCode,
		  DepartmentDesc
	  )
	  SELECT DISTINCT DivisionId,pd.AdjustmentProjectDivision_ID , pd.AdjustmentProjectID, pd.ReferenceProjectDivisionID, cdd.DepartmentCode, cdd.DepartmentDesc
	  FROM dbo.Const_Division cd
	  INNER JOIN dbo.Const_Department cdd ON cdd.Department_ID = cd.DepartmentID
	  INNER JOIN dbo.Plan_AdjustmentProjectDivisions pd ON pd.DivisionID=cd.Division_ID
	  WHERE pd.AdjustmentVersionId = @AdjustmentVersionId AND pd.AdjustmentProjectID = @AdjustmentProjectID

	  WHILE EXISTS ( SELECT 1 FROM #tempAdjustDivision)
	  BEGIN

	  SELECT TOP 1	@DivisionID = DivisionId, 
					@AdjustmentProjectDivision_ID = AdjustmentProjectDivision_ID,
					@AdjustmentProjectID = AdjustmentProjectID,
					@ReferenceProjectDivisionID = ReferenceProjectDivisionID,
					@DepartmentCode = DepartmentCode,
					@DepartmentDesc = DepartmentDesc
					FROM #tempAdjustDivision

	;WITH CTE AS 
					(
						SELECT 1 AS rn, DivisionParentID, DivisionDesc,cdd.DivisionCode
						FROM dbo.Const_Division cdd
						WHERE Division_ID = @DivisionID
						UNION ALL
						SELECT rn + 1 AS rn, D.DivisionParentID, D.DivisionDesc,D.DivisionCode  
						FROM dbo.Const_Division D
						INNER JOIN CTE C ON D.Division_ID = C.DivisionParentID
					)
					INSERT INTO #tempStuffedDivision
					SELECT
					@DivisionID,
					@DepartmentDesc + ':' + STUFF((SELECT ': ' + CTE.DivisionDesc FROM CTE ORDER BY CTE.rn DESC FOR XML PATH('')) , 1,2,''),
					@DepartmentCode + '' + STUFF((SELECT '-' + CTE.DivisionCode FROM CTE  ORDER BY CTE.rn DESC FOR XML PATH('')) , 1,0,''),
					@AdjustmentProjectDivision_ID,@AdjustmentProjectID,@ReferenceProjectDivisionID,@DepartmentCode,@DepartmentDesc

    
		   DELETE  FROM #tempAdjustDivision WHERE AdjustmentProjectDivision_ID = @AdjustmentProjectDivision_ID;
	  END

	  SELECT DISTINCT
             AdjustmentProjectDivision_ID,
             AdjustmentProjectID,
             ReferenceProjectDivisionID,
			 t.DivisionId,
             StuffedDivisionCode + ' / ' + REPLACE(StuffedDivisionDesc,'&amp;', '&') AS MunicipalClassification,
             DepartmentCode,
             DepartmentDesc FROM #tempStuffedDivision t
			 LEFT JOIN dbo.User_UserDivisions uud ON uud.DivisionID = t.DivisionId
			 WHERE (CASE WHEN @UserId = 0 THEN 0 ELSE uud.UserID END = @UserId )

			 --  DROP TABLE #tempStuffedDivision
			 --DROP TABLE #tempAdjustDivision
END

GO

/****** Object:  StoredProcedure [dbo].[Plan_GetAllAdjustmentFundingBudgetsByFinYears_sp]    Script Date: 2026/03/10 7:23:32 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 27/11/2017
-- Description:	Get funding budget scoa fund by finyear/s
-- Calls: execute Plan_GetAllAdjustmentFundingBudgetsByFinYears_sp '2018/2019,2019/2020,2020/2021,','2018/2019'
-- 19-02-2019: SNagpal: #84009, Get SCOA Segments based upon FinYear
-- 24-May-2019 SNagpal: Add multiyear concept to get SCOA segments based upon finyear
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetAllAdjustmentFundingBudgetsByFinYears_sp]
	 @FinancialYear varchar(400),
	@UserFinYear NVARCHAR(10) 
AS
BEGIN
SET NOCOUNT ON;
SET FMTONLY OFF;
		DECLARE @AdjustmentFundingVersionId INT;

		SELECT TOP 1 @AdjustmentFundingVersionId = AdjustmentFundingBudgetVersion_ID FROM Plan_AdjustmentFundingBudgetVersion WHERE VersionName 
		LIKE @UserFinYear + '%' ORDER BY AdjustmentFundingBudgetVersion_ID DESC

	DECLARE @FinYear VARCHAR(10);

	SELECT TOP 1 @FinYear = splitdata FROM  dbo.fnSplitString(@FinancialYear, ',')

	SELECT f.ScoaParentID as ParentID
	,f.ScoaID as SCOAFundID
	,f.ScoaDesc + ' (' + left(f.PostingLevel,1) + '/ ' + f.ScoaCode + ')' as SCOADesc
	,f.ScoaCode 
	,f.ScoaShortDesc
	 ,ISNULL(SUM(ISNULL(d.FundingSourceBudget,0)),0) as AvailFundAmt
	FROM Plan_AdjustmentFundingSourceBudget_Detail d
	INNER JOIN Plan_AdjustmentFundingSourceBudget_Header h ON d.AdjustmentFundingSourceBudgetHeaderID = h.AdjustmentFundingSourceBudgetHeader_ID
	INNER JOIN dbo.Const_SCOA_Funds_Structure_ByYear(@FinYear) f ON d.ScoaID=f.ScoaID
	WHERE h.FinancialYear IN ( SELECT splitdata FROM  dbo.fnSplitString('' + @FinancialYear + '', ',') ) 
	AND d.AdjustmentFundingVersionId = @AdjustmentFundingVersionId
	GROUP BY f.ScoaParentID 
	,f.ScoaID 
	,f.ScoaDesc ,f.PostingLevel,f.ScoaCode 
	,f.ScoaCode 
	,f.ScoaShortDesc;


 END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetAllAdjustmentProjectsWithScoaProject_sp]    Script Date: 2026/03/10 7:23:33 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 27/11/2017
-- Description:	Get all AdjustmentProject for AdjustmentProject Dropdown
-- Used in : AdjustmentProject Capture Screen
-- Plan_GetAllAdjustmentProjectsWithScoaProject_sp 0
-- 26 Jun 2018 SNagpal: 73242 INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentVersionId = papv.AdjustmentBudgetVersion_ID
-- 13 Aug 2020 CMoodley: 4727 - Standardise formatting for project name, get AdjustmentVersionID from @FinYear and multiyear concept for SCOA
-- 07 Aug 2023 CMoodley: 105236 Include CostingProject field
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetAllAdjustmentProjectsWithScoaProject_sp]
	@FinYear NVARCHAR(9),
	@UserFinYear NVARCHAR(10) 
AS
BEGIN
SET NOCOUNT ON;
DECLARE @AdjustmentVersionId INT;

	SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion papv
		INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentVersionId = papv.AdjustmentBudgetVersion_ID
	 WHERE VersionName LIKE @FinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

	SELECT pp.AdjustmentProject_ID ,
           0 AS IDPItemID ,
           pp.AdjustmentProjectName ,
		   CAST(COALESCE(pp.ProjectCode, pp.ReferenceProject_ID, pp.AdjustmentProject_ID) AS VARCHAR(50)) + ' | ' + pp.AdjustmentProjectName + '(' + csps.ScoaCode + ')' AS AdjustmentProjectScoaShortDesc ,
           pp.AdjustmentProjectDesc ,
           pp.ProjectManagerID ,
           pp.CapitalOperation ,
           pp.ScoaProjectID ,
           pp.ProjectStatus ,
           pp.FinYear ,
           0 AS ItemID ,
           pp.ProjectTypeID ,
           pp.IsDeleted ,
		   CAST(COALESCE(pp.ProjectCode, pp.ReferenceProject_ID, pp.AdjustmentProject_ID) AS VARCHAR(50)) + ' | ' + pp.AdjustmentProjectName AS AdjustmentProjectField ,
		   ISNULL(CostingProject, 0) AS CostingProject
	FROM dbo.Plan_AdjustmentProject pp
	INNER JOIN dbo.Const_SCOA_Project_Structure_Consolidated csps ON csps.ScoaID = pp.ScoaProjectID AND csps.FinYearText = @FinYear
	WHERE (pp.FinYear=@FinYear OR @FinYear='0') AND ISNULL(pp.IsDeleted,0) = 0
	AND pp.AdjustmentVersionId = @AdjustmentVersionId

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetAllFundingBudgetsByFinYears_sp]    Script Date: 2026/03/10 7:23:33 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO



-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 16/03/2017
-- Description:	Get funding budget scoa fund by finyear/s
-- Calls: execute Plan_GetAllFundingBudgetsByFinYears_sp '2018/2019,2019/2020,2020/2021,'
-- 19-02-2019: SNagpal : #84009, Get SCOA Segments based upon FinYear
-- 27-05-2019: OShiri  : Add multiyear concept to SCOA segments based upon financial year
-- 19-06-2019: CMoodley: #90481 Include character to split by in dbo.fnSplitString
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetAllFundingBudgetsByFinYears_sp]
	 @FinancialYear varchar(400)
AS
BEGIN
SET NOCOUNT ON;
SET FMTONLY OFF;
	DECLARE @FinYear VARCHAR(10);

	SELECT TOP 1 @FinYear = splitdata FROM  dbo.fnSplitString(@FinancialYear, ',')

SELECT f.ScoaParentID as ParentID
	,f.ScoaID as SCOAFundID
	,f.ScoaDesc + ' (' + left(f.PostingLevel,1) + '/ ' + f.ScoaCode + ')' as SCOADesc
	,f.ScoaCode 
	,f.ScoaShortDesc
	,ISNULL(SUM(ISNULL(d.FundingSourceBudget,0)),0) as AvailFundAmt
	FROM Plan_FundingSourceBudget_Detail d
	INNER JOIN Plan_FundingSourceBudget_Header h ON d.FundingSourceBudgetHeaderID=h.FundingSourceBudgetHeader_ID
	INNER JOIN dbo.Const_SCOA_Funds_Structure_ByYear(@FinYear)  f ON d.ScoaID=f.ScoaID
	WHERE h.FinancialYear IN ( SELECT splitdata FROM  dbo.fnSplitString( @FinancialYear,',') )
	GROUP BY 
	f.ScoaParentID ,f.ScoaID, 
	f.ScoaDesc ,f.PostingLevel,f.ScoaCode, 
	f.ScoaCode ,f.ScoaShortDesc

 END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetAllProjectsWithScoaProject_sp]    Script Date: 2026/03/10 7:23:33 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================    
-- Author: Sahil Nagpal    
-- Create date: 06/12/2016    
-- Description: Get all project for Project Dropdown    
-- Used in : Project Capture Screen    
-- Plan_GetAllProjectsWithScoaProject_sp 0    
-- 28-03-2017 SNagpal: As IDPItemID and ItemId no more exists in Plan_Project Table. In Future If needed apply join with Plan_ProjectIDP    
-- 02 AUG 2018 Rajesh : TP# 76774 - Added the DetailedProjectName column 
-- NP 21 JAN 2020 - WI 27154
-- CM 29 SEP 2023 - 105236 - Return CostingProject
-- =============================================    
CREATE PROCEDURE [dbo].[Plan_GetAllProjectsWithScoaProject_sp] @FinYear NVARCHAR(9)
AS
BEGIN
    SET NOCOUNT ON;
    SELECT pp.Project_ID,
           0 AS IDPItemID,
           pp.ProjectName,
           CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS VARCHAR(50)) + ' | ' + pp.ProjectName + '(' + csps.ScoaCode
           + ')' AS ProjectScoaShortDesc,
           pp.ProjectDesc,
           pp.ProjectManagerID,
           pp.CapitalOperation,
           pp.ScoaProjectID,
           pp.ProjectStatus,
           pp.FinYear,
           0 AS ItemID,
           pp.ProjectTypeID,
           pp.IsDeleted,
           CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS VARCHAR(50)) + ' | ' + pp.ProjectName AS DetailedProjectName, -- TP# 76774    
           CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS VARCHAR(50)) + ' | ' + pp.ProjectName AS ProjectField,
           ISNULL(pp.CostingProject, 0) AS CostingProject
    FROM dbo.Plan_Project pp
        INNER JOIN dbo.Const_SCOA_Project_Structure csps
            ON csps.ScoaID = pp.ScoaProjectID
    WHERE (
              pp.FinYear = @FinYear
              OR @FinYear = '0'
          )
          AND ISNULL(pp.IsDeleted, 0) = 0
    ORDER BY pp.ProjectCode;
END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetApprovedAdjustment_sp]    Script Date: 2026/03/10 7:23:33 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 2016-04-18
-- Description:	Get Pending Adjustement 
-- CALL SP: Plan_GetApprovedAdjustment_sp ''
-- 2016-04-19 by JP : Update Fields and Condition for Adjustments
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetApprovedAdjustment_sp] @FinYear NVARCHAR(9)
AS
    BEGIN
        SET NOCOUNT ON;

        SELECT  MIN(PA.AdjustmentBudget_Id) AdjustmentBudget_Id,
                PA.VersionNumber AS VersionNumber ,
                ISNULL(PAAR.ApprovalRejectionFileName, '') AS ApprovedFileName ,
                COUNT(PAAR.AdjustmentBudgetId) AS ApprovedAdjustments ,
                PAAR.ApprovedOn AS ApprovedOn ,
                UUD.UserName AS ApprovedBy
        FROM    dbo.Plan_Project PrjFrom
                INNER JOIN dbo.Plan_Adjustment PA ON PrjFrom.Project_ID = PA.FromProjectId
                LEFT OUTER JOIN Plan_Project PrjTo ON PA.ToProjectId = PrjTo.Project_ID
                INNER JOIN dbo.Plan_AdjustmentApprovalRejections PAAR ON PAAR.AdjustmentBudgetId = PA.AdjustmentBudget_Id
                                                              AND PAAR.IsApproved = 1
                                                              AND PA.Status = 102
                INNER JOIN dbo.User_UserDetail UUD ON UUD.User_ID = PAAR.ApprovedBy
        WHERE   ( PA.FinYear = @FinYear
                  OR @FinYear = ''
                )
        GROUP BY PA.VersionNumber ,
                ISNULL(PAAR.ApprovalRejectionFileName, '') ,
                PAAR.ApprovedOn ,
                UUD.UserName;
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetApprovedAdjustmentBudgetVersions_sp]    Script Date: 2026/03/10 7:23:33 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Sahil Nagpal
-- Create date: 2018-05-31
-- Description:	Get Approved Adjustment Budget Version : #73220
-- CALL SP: Plan_GetApprovedAdjustmentBudgetVersions_sp '2017/2018'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetApprovedAdjustmentBudgetVersions_sp] 
@FinYear NVARCHAR(18)
AS
BEGIN
    SET NOCOUNT ON;

    SELECT DISTINCT a.AdjustmentBudgetVersion_ID ,a.VersionNumber ,a.VersionName ,a.Comments ,a.CapturerID ,a.DateCaptured
	FROM Plan_AdjustmentBudgetVersion a
	LEFT JOIN dbo.Plan_AdjustmentBudgetPolicyApproval b ON a.AdjustmentBudgetVersion_ID = b.AdjustmentVersionId
	LEFT JOIN dbo.Plan_SupplementaryAdjustment d ON a.AdjustmentBudgetVersion_ID = d.AdjustmentVersionId
	INNER JOIN Plan_AdjustmentProject c ON c.AdjustmentVersionId = a.AdjustmentBudgetVersion_ID 
	WHERE a.VersionNumber LIKE '%' + @FinYear + '%' 
	AND (ISNULL(b.IsAdjustmentFinalApproved,0) = 1 OR ISNULL(d.IsAdjustmentFinalApproved,0) = 1)
	ORDER BY AdjustmentBudgetVersion_ID

END;

GO

/****** Object:  StoredProcedure [dbo].[Plan_GetApprovedVirementByDate_SP]    Script Date: 2026/03/10 7:23:33 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 23/05/2017
-- Description : Get Approved Virement
-- 25-05-2015 SNagpal: Add Logic to insert value into Table Plan_GetApprovedVirementFromSP_Temp
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetApprovedVirementByDate_SP]
@FromVirementDate DATETIME = '28-FEB-2017',
@ToVirementDate DATETIME = '16-MAY-2017'

AS
BEGIN
SET NOCOUNT ON;

--First Trunctate table
TRUNCATE TABLE Plan_GetApprovedVirementFromSP_Temp

--Insert approved values into table
INSERT INTO Plan_GetApprovedVirementFromSP_Temp
SELECT (ROW_NUMBER() OVER(ORDER BY VirementId)) AS Rownumber, FinYear,VirementAmount, ReasonForVirement, 
		piv.[Approver1] AS FirstApprover, piv.[Approver2] SecondApprover, piv.[Approver3] AS ThirdApprover,
	   FileName, FromHistoricalProjectCode,FromProjectName,FromCapitalOperation,FromScoaProjectID,
	   FromDivisionID,FromSCOAFunctionID,FromSCOARegionID,FromSCOACostingID,FromSCOAItemID,FromScoaFundID,FromProjectItemID,
	   ToHistoricalProjectCode,ToProjectName,ToCapitalOperation,ToScoaProjectID,
	   ToDivisionID,ToSCOAFunctionID,ToSCOARegionID,ToSCOACostingID,ToSCOAItemID,ToScoaFundID,ToProjectItemID
		FROM (SELECT V.VirementId,
		V.FinYear,V.ToVirementAmount AS VirementAmount, V.ReasonForVirement, (uuda.FirstName + ' ' + uuda.LastName) AS Approver, V.UploadedVirementDoc AS FileName, 
		ppItemFrom.HistoricalProjectCode AS FromHistoricalProjectCode, ppItemTo.HistoricalProjectCode AS ToHistoricalProjectCode, 
		ppFrom.ProjectName AS FromProjectName, ppTo.ProjectName AS ToProjectName, 
		ppFrom.CapitalOperation AS FromCapitalOperation, ppTo.CapitalOperation AS ToCapitalOperation, 
		CSPSFrom.NTScoaID AS FromScoaProjectID, CSPSTo.NTScoaID AS ToScoaProjectID,
		CDFrom.Division_ID AS FromDivisionID, CDTo.Division_ID AS ToDivisionID,
		CSFSFrom.NTScoaID AS FromSCOAFunctionID, CSFSTo.NTScoaID  AS ToSCOAFunctionID,
		CSRSFrom.NTScoaID AS FromSCOARegionID, CSRSTo.NTScoaID  AS ToSCOARegionID,
		CSCSFrom.NTScoaID AS FromSCOACostingID, CSCSTo.NTScoaID  AS ToSCOACostingID,
		CSSFrom.NTScoaID AS FromSCOAItemID, CSSTo.NTScoaID  AS ToSCOAItemID,
		CSFDSFrom.NTScoaID AS FromScoaFundID, CSFDSTo.NTScoaID  AS ToScoaFundID,
		ppItemFrom.ProjectItemID AS FromProjectItemID, ppItemTo.ProjectItemID AS ToProjectItemID,
		'Approver' +CAST(ROW_NUMBER() OVER(PARTITION BY V.VirementId ORDER BY V.VirementId) AS VARCHAR(20)) AS VirementApprovers
		FROM dbo.Plan_Virements V
		INNER JOIN dbo.Plan_Project ppFrom ON ppFrom.Project_ID = V.FromProjectId
		INNER JOIN dbo.Plan_Project ppTo ON ppTo.Project_ID = V.ToProjectId
		LEFT JOIN dbo.Plan_ProjectItem ppItemFrom ON ppItemFrom.ProjectItemID = V.FromProjectItemId
		LEFT JOIN dbo.Plan_ProjectItem ppItemTo ON ppItemTo.ProjectItemID = V.FromProjectItemId
		INNER JOIN dbo.Const_SCOA_Project_Structure CSPSFrom ON CSPSFrom.ScoaID = V.FromScoaProjectId
		INNER JOIN dbo.Const_SCOA_Project_Structure CSPSTo ON CSPSTo.ScoaID = V.ToScoaProjectId
		INNER JOIN dbo.Const_SCOA_Function_Structure CSFSFrom ON CSFSFrom.ScoaID = V.FromScoaFunctionId
		INNER JOIN dbo.Const_SCOA_Function_Structure CSFSTo ON CSFSTo.ScoaID = V.ToScoaFunctionId
		INNER JOIN dbo.Const_Division CDFrom ON CDFrom.Division_ID = V.FromDivisionId
		INNER JOIN dbo.Const_Division CDTo ON CDTo.Division_ID = V.ToDivisionId
		INNER JOIN dbo.Const_SCOA_Funds_Structure CSFDSFrom ON CSFDSFrom.ScoaID = V.FromSCOAFundID
		INNER JOIN dbo.Const_SCOA_Funds_Structure CSFDSTo ON CSFDSTo.ScoaID = V.ToSCOAFundID
		INNER JOIN dbo.Const_SCOA_Regional_Structure CSRSFrom ON CSRSFrom.ScoaID = V.FromSCOARegion
		INNER JOIN dbo.Const_SCOA_Regional_Structure CSRSTo ON CSRSTo.ScoaID = V.ToSCOARegion
		INNER JOIN dbo.Const_SCOA_Structure CSSFrom ON CSSFrom.ScoaID = V.FromSCOAItem
		INNER JOIN dbo.Const_SCOA_Structure CSSTo ON CSSTo.ScoaID = V.ToSCOAItem
		INNER JOIN dbo.Const_SCOA_Costing_Structure CSCSFrom ON CSCSFrom.ScoaID = V.FromSCOACostingId
		INNER JOIN dbo.Const_SCOA_Costing_Structure CSCSTo ON CSCSTo.ScoaID = V.ToSCOACostingId
		INNER JOIN Plan_VirementApprovalUsers PVAU ON PVAU.VirementId = V.VirementId
		INNER JOIN dbo.Plan_VirementApprovalRejections PVAR ON V.VirementId = PVAR.VirementId 
		INNER JOIN dbo.User_UserDetail uuda ON uuda.User_ID = PVAR.ApprovedBy
		WHERE ISNULL(PVAU.UserId,0) > 0
		AND V.VirementId <>
		(CASE WHEN ISNULL(PVAR.IsRejected,0) = 1
		THEN pvar.VirementId ELSE 0 END)
		AND CAST(V.DateCaptured AS DATE) BETWEEN CAST(@FromVirementDate AS DATE) AND CAST(@ToVirementDate AS DATE)
		GROUP BY V.VirementId, V.FinYear, V.ToVirementAmount, uuda.FirstName,uuda.LastName, V.ReasonForVirement, V.UploadedVirementDoc,
		ppItemFrom.HistoricalProjectCode, ppItemTo.HistoricalProjectCode,ppFrom.ProjectName,ppTo.ProjectName,
		ppFrom.CapitalOperation,ppTo.CapitalOperation,CSPSFrom.NTScoaID,CSPSTo.NTScoaID,CDFrom.Division_ID, CDTo.Division_ID,
		CSFSFrom.NTScoaID,CSFSTo.NTScoaID,CSRSFrom.NTScoaID,CSRSTo.NTScoaID,CSCSFrom.NTScoaID, CSCSTo.NTScoaID,
		CSSFrom.NTScoaID, CSSTo.NTScoaID,CSFDSFrom.NTScoaID, CSFDSTo.NTScoaID,ppItemFrom.ProjectItemID, ppItemTo.ProjectItemID 
		HAVING COUNT(PVAR.ApprovedBy) = COUNT(PVAU.UserId)
		) S PIVOT
		( MAX(Approver) FOR VirementApprovers IN ( [Approver1], [Approver2], [Approver3] ) ) piv

		SELECT * FROM Plan_GetApprovedVirementFromSP_Temp

		END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetBTOReport_sp]    Script Date: 2026/03/10 7:23:33 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Raindre Chetty
-- Create date: 26 10 2015
-- Description:	Get BTO report based on search criteria
-- Calls: Plan_GetBTOReport_sp '',0
-- 10-12-2019 Volodymyr Stovba: 7334 CR_Project Code Change throughout system_SCM Screens as per document attached. Added ProjectNameWithCode.
-- 04-02-2020 Volodymyr Stovba: 27190 Alpha02: Please add a space between the project code and the pipe and the pipe and project name 
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetBTOReport_sp] 
	  @FinYear VARCHAR(9),
	  @VendorID INT 
AS
BEGIN
-- tenders
SELECT  v.Vendor_ID AS VendorID, i.Invoice_ID,InvDet.InvoiceDetail_ID, p.Project_ID, v.VendorName, p.FinYear, ps.ScoaCode +' - ' + ps.ScoaDesc AS ProjectScoaCode
 ,LTRIM(STR(p.ProjectCode))+' | '+REPLACE(REPLACE(REPLACE(p.ProjectName,CHAR(10),' '),CHAR(13),' '),CHAR(09),' ') AS ProjectNameWithCode
 ,REPLACE(REPLACE(REPLACE(p.ProjectName,CHAR(10),' '),CHAR(13),' '),CHAR(09),' ') AS ProjectName, '' as Contract
 , s.AppointmentDate, s.AppointmentAmount
 ,ISNULL(InvDet.TotalAmount,0) as AmountPaid,(ISNULL(InvDet.Amount,0)-ISNULL(InvDet.TotalAmount,0)) as AmountOutstanding
 --select y.*
FROM Plan_Project p
INNER JOIN Const_SCOA_Project_Structure ps ON p.ScoaProjectID=ps.ScoaID
INNER JOIN Plan_ProjectServiceProvider s ON p.Project_ID=s.ProjectID
INNER JOIN Cons_Vendor v ON s.VendorID=v.Vendor_ID
INNER JOIN [SCM_Order] o ON s.TenderID=o.TenderId
INNER JOIN [SCM_Invoice] i ON o.Order_ID=i.OrderID
INNER JOIN [SCM_InvoiceDetail] InvDet ON i.Invoice_ID=InvDet.InvoiceID

WHERE 
 ((p.FinYear = @FinYear) OR (@FinYear='')) AND
  ((v.Vendor_ID =@VendorID)  OR (@VendorID=0)) 
  AND InvDet.InvoiceDetail_ID IS NOT NULL
UNION
-- quotations
SELECT  v.Vendor_ID AS VendorID, i.Invoice_ID,InvDet.InvoiceDetail_ID,p.Project_ID, v.VendorName, p.FinYear, ps.ScoaCode +' - ' + ps.ScoaDesc AS ProjectScoaCode
  ,LTRIM(STR(p.ProjectCode))+' | '+REPLACE(REPLACE(REPLACE(p.ProjectName,CHAR(10),' '),CHAR(13),' '),CHAR(09),' ') AS ProjectNameWithCode
 ,REPLACE(REPLACE(REPLACE(p.ProjectName,CHAR(10),' '),CHAR(13),' '),CHAR(09),' ') AS ProjectName, '' as Contract
 , s.AppointmentDate, s.AppointmentAmount
 ,ISNULL(InvDet.TotalAmount,0) as AmountPaid,(ISNULL(InvDet.Amount,0)-ISNULL(InvDet.TotalAmount,0)) as AmountOutstanding
 --select y.*
FROM Plan_Project p
INNER JOIN Const_SCOA_Project_Structure ps ON p.ScoaProjectID=ps.ScoaID
INNER JOIN Plan_ProjectServiceProvider s ON p.Project_ID=s.ProjectID
INNER JOIN Cons_Vendor v ON s.VendorID=v.Vendor_ID
left JOIN [SCM_Order] o ON s.QuotationID=o.QuotationId
LEFT JOIN [SCM_Invoice] i ON o.Order_ID=i.OrderID
LEFT JOIN [SCM_InvoiceDetail] InvDet ON i.Invoice_ID=InvDet.InvoiceID
WHERE 
   ((p.FinYear = @FinYear) OR (@FinYear='')) AND
  ((v.Vendor_ID =@VendorID)  OR (@VendorID=0)) 
  AND InvDet.InvoiceDetail_ID IS NOT NULL
END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetBudgetActualComparisonHistoricalCurrentReport_sp]    Script Date: 2026/03/10 7:23:33 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


/*
Created by:			Richard Bothma
Date:				2017-02-14
Description:		This report compares Budget for Current Year, and 2 Years ahead,
					along with Actuals for Previous and Current Year,
					and shows Commitments made .
					It is for Items of Revenue and Expenditure only.

Modified By:		Richard Bothma
Date:				2017-02-16
Description:		Fixed issue with balancing, with regards to different grains of data sources.

Modified By:		Richard Bothma
Date:				2017-03-01
Description:		Changed Filter for Function to work at lowest posting level.

Modified By:		Richard Bothma
Date:				2017-03-27
Description:		Updated method of filtering on Division. If parent level passed in will obtain child items as well.
					Also applied same logic to Scoa Function filter, in case a parent ID is passed in.
					
EXEC dbo.Plan_GetBudgetActualComparisonHistoricalCurrentReport_sp '2015/2016','%','327'
EXEC dbo.Plan_GetBudgetActualComparisonHistoricalCurrentReport_sp '2017/2018','%','%'
08-03-2017 SNagpal #50942: Change the format of CD.DivisionDesc 
07-05-2017 Rchetty #71358: Original budget per year saved as Finyear_OrgbXXX dont use comment description.
*/
			
CREATE PROCEDURE [dbo].[Plan_GetBudgetActualComparisonHistoricalCurrentReport_sp]
(
@FinYear NVARCHAR(9)
, @Div NVARCHAR(50)
, @Func NVARCHAR(50)
)
AS
BEGIN

SET ANSI_NULLS ON

--DECLARE @FinYear NVARCHAR(9) = '2017/2018' -- @FinancialYear --Will be passed in
--DECLARE @Div NVARCHAR(50) = '1198'
--DECLARE @Func NVARCHAR(50) = '%'

DECLARE @PrevYear NVARCHAR(9)
DECLARE @CP1Year NVARCHAR(9)
DECLARE @CP2Year NVARCHAR(9)

-- Generate previous and future Financial Year values, based current FinancialYear passed in
SELECT @PrevYear =
	 CASE WHEN LEN(LTRIM(RTRIM(@FinYear))) = 9
				AND SUBSTRING(LTRIM(RTRIM(@FinYear)),5,1) = '/'
			THEN CONVERT(NVARCHAR(9),CONVERT(INT,LEFT(LTRIM(RTRIM(@FinYear)),4))-1)
				+ '/'
				+ CONVERT(NVARCHAR(9),CONVERT(INT,RIGHT(LTRIM(RTRIM(@FinYear)),4))-1)
			END

	, @CP1Year =
		CASE WHEN LEN(LTRIM(RTRIM(@FinYear))) = 9
				AND SUBSTRING(LTRIM(RTRIM(@FinYear)),5,1) = '/'
			THEN CONVERT(NVARCHAR(9),CONVERT(INT,LEFT(LTRIM(RTRIM(@FinYear)),4))+1)
				+ '/'
				+ CONVERT(NVARCHAR(9),CONVERT(INT,RIGHT(LTRIM(RTRIM(@FinYear)),4))+1)
			END
			
	, @CP2Year =
		CASE WHEN LEN(LTRIM(RTRIM(@FinYear))) = 9
				AND SUBSTRING(LTRIM(RTRIM(@FinYear)),5,1) = '/'
			THEN CONVERT(NVARCHAR(9),CONVERT(INT,LEFT(LTRIM(RTRIM(@FinYear)),4))+2)
				+ '/'
				+ CONVERT(NVARCHAR(9),CONVERT(INT,RIGHT(LTRIM(RTRIM(@FinYear)),4))+2)
			END
			
-- Prepare divisions to work with
DECLARE @Division TABLE
(
DivisionID INT NULL
)

IF @Div = '%'
	
		INSERT INTO @Division 
		(
		DivisionID
		)
		SELECT DISTINCT Division_ID --Populate all available divisions
		FROM Const_Division WITH (NOLOCK)
	
	ELSE 
		-- Get all Child Divisions, in case of a Parent passed in
		 WITH    DeptDivGroup ( DivisionParentID, Division_ID, DivisionDesc, DivisionCode, DepartmentID )
						  AS (
		 -- Anchor member definition
								SELECT   e.DivisionParentID ,
										e.Division_ID ,
										e.DivisionDesc ,
										e.DivisionCode ,
				e.DivisionParentID 
										--e.DepartmentID
								FROM     dbo.Const_Division AS e
								WHERE    DivisionParentID in (@Div)
								UNION ALL
		 -- Recursive member definition
							   SELECT   e.DivisionParentID ,
										e.Division_ID , 
										e.DivisionDesc ,
										e.DivisionCode ,
				d.DepartmentID
										--e.DepartmentID
							   FROM     dbo.Const_Division AS e
										INNER JOIN DeptDivGroup AS d ON e.DivisionParentID = d.Division_ID
							 )
		INSERT INTO @Division
		(
		 DivisionID
		)
		SELECT CONVERT(INT,@Div) AS DivisionID
		UNION
		SELECT DISTINCT Division_ID AS DivisionID from DeptDivGroup


-- Prepare Functions to work with
DECLARE @Function TABLE
(
FunctionID INT NULL
)

IF @Func = '%'
	
		INSERT INTO @Function
		(
		FunctionID
		)
		SELECT DISTINCT ScoaID --Populate all available divisions
		FROM Const_SCOA_Function_Structure WITH (NOLOCK)
	
	ELSE 
		-- Get all Child Divisions, in case of a Parent passed in
		 WITH    Func ( ScoaParentID, ScoaID, ScoaShortDesc, ScoaCode )
						  AS (
		 -- Anchor member definition
								SELECT   e.ScoaParentID ,
										e.ScoaID , 
										e.ScoaShortDesc ,
										e.ScoaCode 
								FROM     dbo.Const_SCOA_Function_Structure AS e
								WHERE    ScoaParentID in (@Func)
								UNION ALL
		 -- Recursive member definition
							   SELECT   e.ScoaParentID ,
										e.ScoaID , 
										e.ScoaShortDesc ,
										e.ScoaCode 
							   FROM     dbo.Const_SCOA_Function_Structure AS e
										INNER JOIN Func AS d ON e.ScoaParentID = d.ScoaID
							 )
		INSERT INTO @Function
		(
		 FunctionID
		)
		SELECT CONVERT(INT,@Func) AS FunctionID
		UNION
		SELECT DISTINCT ScoaID AS FunctionID from Func



--Get SCOA Hierarchy for ITEM - Expenditure and Revenue

DECLARE @SCOAITEM_HIERARCHY TABLE
(
ScoaCodeLowestLevel		NVARCHAR(50) NULL
,ScoaIDLowestLevel		INT NULL
,ScoaShortDescLowestLevel		NVARCHAR(200) NULL
,L0ScoaCode				NVARCHAR(50) NULL	
, L0ScoaShortDesc		NVARCHAR(200) NULL	
, L0ScoaID					INT NULL
, L1ScoaCode		 NVARCHAR(50) NULL
, L1ScoaShortDesc	 NVARCHAR(200) NULL	
, L1ScoaID					INT NULL
, L2ScoaCode		 NVARCHAR(50) NULL
, L2ScoaShortDesc	 NVARCHAR(200) NULL	
, L2ScoaID					INT NULL
, L3ScoaCode		 NVARCHAR(50) NULL
, L3ScoaShortDesc		 NVARCHAR(200) NULL
, L3ScoaID					INT NULL
, L4ScoaCode		 NVARCHAR(50) NULL
, L4ScoaShortDesc	 NVARCHAR(200) NULL
, L4ScoaID					INT NULL
, L5ScoaCode		 NVARCHAR(50) NULL
, L5ScoaShortDesc		 NVARCHAR(200) NULL
, L5ScoaID					INT NULL
, L6ScoaCode		 NVARCHAR(50) NULL
, L6ScoaShortDesc	 NVARCHAR(200) NULL	
, L6ScoaID					INT NULL
, L7ScoaCode		 NVARCHAR(50) NULL
, L7ScoaShortDesc	 NVARCHAR(200) NULL	
, L7ScoaID					INT NULL
, L8ScoaCode		 NVARCHAR(50) NULL
, L8ScoaShortDesc	 NVARCHAR(200) NULL	
, L8ScoaID					INT NULL
)

INSERT INTO @SCOAITEM_HIERARCHY
(
ScoaCodeLowestLevel	
, ScoaIDLowestLevel	
, ScoaShortDescLowestLevel
, L0ScoaCode			
, L0ScoaShortDesc	
, L0ScoaID				
, L1ScoaCode		
, L1ScoaShortDesc	
, L1ScoaID				
, L2ScoaCode		
, L2ScoaShortDesc	
, L2ScoaID				
, L3ScoaCode		
, L3ScoaShortDesc	
, L3ScoaID				
, L4ScoaCode		
, L4ScoaShortDesc	
, L4ScoaID				
, L5ScoaCode		
, L5ScoaShortDesc	
, L5ScoaID				
, L6ScoaCode		
, L6ScoaShortDesc	
, L6ScoaID				
, L7ScoaCode		
, L7ScoaShortDesc	
, L7ScoaID				
, L8ScoaCode		
, L8ScoaShortDesc	
, L8ScoaID				
)
SELECT DISTINCT 
		-- COALESCE FROM LOWEST LEVEL TO HIGHEST, TO OBTAIN THE LOWEST AVAILABLE LEVEL
		COALESCE(L8.ScoaCode, L7.ScoaCode, L6.ScoaCode, L5.ScoaCode, L4.ScoaCode, L3.ScoaCode, L2.ScoaCode, L1.ScoaCode, L0.ScoaCode,NULL) AS ScoaCodeLowestLevel
		, COALESCE(L8.ScoaID, L7.ScoaID, L6.ScoaID, L5.ScoaID, L4.ScoaID, L3.ScoaID, L2.ScoaID, L1.ScoaID, L0.ScoaID,NULL) AS ScoaIDLowestLevel
		, COALESCE(L8.ScoaShortDesc, L7.ScoaShortDesc, L6.ScoaShortDesc, L5.ScoaShortDesc, L4.ScoaShortDesc, L3.ScoaShortDesc, L2.ScoaShortDesc, L1.ScoaShortDesc, L0.ScoaShortDesc,NULL)AS ScoaShortDescLowestLevel
		, L0.ScoaCode AS L0ScoaCode
		, L0.ScoaShortDesc AS L0ScoaShortDesc
		, L0.ScoaID AS L0ScoaID
		, L1.ScoaCode AS L1ScoaCode
		, L1.ScoaShortDesc AS L1ScoaShortDesc
		, L1.ScoaID AS L1ScoaID
		, L2.ScoaCode AS L2ScoaCode
		, L2.ScoaShortDesc AS L2ScoaShortDesc
		, L2.ScoaID AS L2ScoaID
		, L3.ScoaCode AS L3ScoaCode
		, L3.ScoaShortDesc AS L3ScoaShortDesc
		, L3.ScoaID AS L3ScoaID
		, L4.ScoaCode AS L4ScoaCode
		, L4.ScoaShortDesc AS L4ScoaShortDesc
		, L4.ScoaID AS L4ScoaID
		, L5.ScoaCode AS L5ScoaCode
		, L5.ScoaShortDesc AS L5ScoaShortDesc
		, L5.ScoaID AS L5ScoaID
		, L6.ScoaCode AS L6ScoaCode
		, L6.ScoaShortDesc AS L6ScoaShortDesc
		, L6.ScoaID AS L6ScoaID
		, L7.ScoaCode AS L7ScoaCode
		, L7.ScoaShortDesc AS L7ScoaShortDesc
		, L7.ScoaID AS L7ScoaID
		, L8.ScoaCode AS L8ScoaCode
		, L8.ScoaShortDesc AS L8ScoaShortDesc
		, L8.ScoaID AS L8ScoaID
	
	--INTO #SCOA_Hierarchy

	FROM Const_SCOA_Structure L0 WITH (NOLOCK)
		LEFT JOIN Const_SCOA_Structure L1 WITH (NOLOCK)			ON L0.ScoaID = L1.ScoaParentID			AND L0.LevelID = L1.LevelID-1
		LEFT JOIN Const_SCOA_Structure L2 WITH (NOLOCK)			ON L1.ScoaID = L2.ScoaParentID			AND L1.LevelID = L2.LevelID-1
		LEFT JOIN Const_SCOA_Structure L3 WITH (NOLOCK)			ON L2.ScoaID = L3.ScoaParentID			AND L2.LevelID = L3.LevelID-1
		LEFT JOIN Const_SCOA_Structure L4 WITH (NOLOCK)			ON L3.ScoaID = L4.ScoaParentID			AND L3.LevelID = L4.LevelID-1
		LEFT JOIN Const_SCOA_Structure L5 WITH (NOLOCK)			ON L4.ScoaID = L5.ScoaParentID			AND L4.LevelID = L5.LevelID-1
		LEFT JOIN Const_SCOA_Structure L6 WITH (NOLOCK)			ON L5.ScoaID = L6.ScoaParentID			AND L5.LevelID = L6.LevelID-1
		LEFT JOIN Const_SCOA_Structure L7 WITH (NOLOCK)			ON L6.ScoaID = L7.ScoaParentID			AND L6.LevelID = L7.LevelID-1
		LEFT JOIN Const_SCOA_Structure L8 WITH (NOLOCK)			ON L7.ScoaID = L8.ScoaParentID			AND L7.LevelID = L8.LevelID-1
	WHERE LEFT(LTRIM(L0.ScoaCode),2) IN ('IE','IR') -- Revenue and Expenditure Items only
	AND L0.LevelID = 0 -- Make sure Hierarchy is being built from the highest level down
	ORDER BY ScoaCodeLowestLevel


--- ORIGINAL BUDGETS - HIGHLIGHT LATEST APPROVED VERSION ONLY - AS PER CURRENT FINANCIAL YEAR PARAMETER PASSED IN
DECLARE @BUDGETS_ORIG TABLE
(
BudgetVersionID INT NULL
, SCOACodeType_Item NVARCHAR(2) NULL
, SCOACode_Item NVARCHAR(50) NULL
, NTScoaID_Item uniqueidentifier NULL
, SCOAID_Item int NULL
, SCOAID_Function int NULL
, SCOACode_Function NVARCHAR(50) NULL
, NTScoaID_Function uniqueidentifier NULL
, FinYear NVARCHAR(9) NULL
, SCOADesc_Function NVARCHAR(200) NULL
, BudgetAmount DECIMAL(16,2) NULL
, BudgetAmountCurP1 DECIMAL(16,2) NULL
, BudgetAmountCurP2 DECIMAL(16,2) NULL
--, PlanProjectItemID INT NULL
, DivisionId INT NULL
)

INSERT INTO @BUDGETS_ORIG
(
BudgetVersionID 
, SCOACodeType_Item 
, SCOACode_Item 
, NTScoaID_Item
, SCOAID_Item 
, SCOAID_Function 
, SCOACode_Function
, NTScoaID_Function
, FinYear 
, SCOADesc_Function 
, BudgetAmount 
, BudgetAmountCurP1 
, BudgetAmountCurP2
--, PlanProjectItemID 
, DivisionId
)
SELECT BudgetVersionID
	, LEFT(LTRIM(cs.ScoaCode),2) AS SCOACodeType_Item
	, LTRIM(RTRIM(cs.ScoaCode)) AS SCOACode_Item
	, LTRIM(RTRIM(cs.NTScoaID)) AS NTScoaID_Item
	, cs.ScoaID AS SCOAID_Item
	, csfs.ScoaID AS SCOAID_Function 
	, LTRIM(RTRIM(csfs.ScoaCode)) AS SCOACode_Function
	, LTRIM(RTRIM(csfs.NTScoaID)) AS NTScoaID_Function
	, bvd.FinYear
	, csfs.ScoaShortDesc AS SCOADesc_Function
	, SUM(ISNULL(bvd.BudgetAmount,0.0)) AS OriginalBudget 
	, SUM(ISNULL(BudgetAmountCurP1,0.0)) AS BudgetAmountCurP1
	, SUM(ISNULL(BudgetAmountCurP2,0.0)) AS BudgetAmountCurP2
	--, PlanProjectItemID 
	, DivisionId

from dbo.Plan_BudgetVersionDetail  bvd
inner join Const_SCOA_Function_Structure csfs 
	on bvd.SCOAFunctionId=csfs.ScoaId
inner join Const_SCOA_Structure cs 
	on cs.ScoaID = bvd.SCOAItemID
inner join Plan_BudgetVersion bv
	on bv.BudgetVersion_ID = bvd.BudgetVersionId

	--Get latest version of budget
	INNER JOIN 
	(
		SELECT 
			 bvd_sub.FinYear
			, MAX(BudgetVersionID) AS MAX_BudgetVersionID
			
		FROM Plan_BudgetVersionDetail bvd_sub

			inner join Plan_BudgetVersion bv_sub 
				on bv_sub.BudgetVersion_ID = bvd_sub.BudgetVersionId
					--This comments description below is stamped by the system when approved and so should be used to highlight the approved budget
		WHERE --bv_sub.Comments like 'Budget approved by council in terms of the legislative requirements on MFMA' --RC 71358
				bv_sub.VersionNumber LIKE (@FinYear+ '_ORGB%')
		GROUP BY 
			 bvd_sub.FinYear

		) SUB_LATEST_VERSION
			ON SUB_LATEST_VERSION.FinYear = bvd.FinYear
			AND SUB_LATEST_VERSION.MAX_BudgetVersionID = bvd.BudgetVersionID
		
WHERE bvd.FinYear = @FinYear

AND  LEFT(LTRIM(cs.ScoaCode),2) IN ('IE',    --Limit SCOA Items to types "Expenditure" and "Revenue"
										'IR')	

GROUP BY BudgetVersionID
	, LEFT(LTRIM(cs.ScoaCode),2) 
	, LTRIM(RTRIM(cs.ScoaCode)) 
	, LTRIM(RTRIM(cs.NTScoaID)) 
	, cs.ScoaID
	, csfs.ScoaID 
	, LTRIM(RTRIM(csfs.ScoaCode)) 
	, LTRIM(RTRIM(csfs.NTScoaID)) 
	, bvd.FinYear
	, csfs.ScoaShortDesc 
	, DivisionId

ORDER BY bvd.FinYear, SCOACODE_ITEM, BudgetVersionID, csfs.ScoaShortDesc

