--- REVISED BUDGETS - AS IT STANDS IN Plan_ProjectItem

DECLARE @BUDGETS_REVISED TABLE
(
BudgetVersionID INT NULL
, SCOACodeType_Item NVARCHAR(2) NULL
, SCOACode_Item NVARCHAR(50) NULL
, NTScoaID_Item uniqueidentifier NULL
, SCOAID_Item int NULL
, SCOAID_Function int NULL
, SCOACode_Function NVARCHAR(50) NULL
, NTScoaID_Function uniqueidentifier NULL
, FinYear NVARCHAR(9) NULL
, SCOADesc_Function NVARCHAR(200) NULL
, BudgetAmount DECIMAL(16,2) NULL
, BudgetAmountCurP1 DECIMAL(16,2) NULL
, BudgetAmountCurP2 DECIMAL(16,2) NULL
--, PlanProjectItemID INT NULL
, DivisionId INT NULL
)

INSERT INTO @BUDGETS_REVISED
(
BudgetVersionID 
, SCOACodeType_Item 
, SCOACode_Item 
, NTScoaID_Item
, SCOAID_Item 
, SCOAID_Function 
, SCOACode_Function
, NTScoaID_Function
, FinYear 
, SCOADesc_Function 
, BudgetAmount 
, BudgetAmountCurP1 
, BudgetAmountCurP2
--, PlanProjectItemID 
, DivisionId 
)

SELECT 0 AS BudgetVersionID --Defaulting to 0 for consistent table variable structure
	, LEFT(LTRIM(cs.ScoaCode),2) AS SCOACodeType_Item
	, LTRIM(RTRIM(cs.ScoaCode)) AS SCOACode_Item
	, LTRIM(RTRIM(cs.NTScoaID)) AS NTScoaID_Item
	, cs.ScoaID AS SCOAID_Item
	, csfs.ScoaID AS SCOAID_Function 
	, LTRIM(RTRIM(csfs.ScoaCode)) AS SCOACode_Function
	, LTRIM(RTRIM(csfs.NTScoaID)) AS NTScoaID_Function
	, bvd.FinYear
	, csfs.ScoaShortDesc AS SCOADesc_Function
	, SUM(ISNULL(bvd.BudgetAmount,0.0)) AS revisedBudget
	, SUM(ISNULL(bvd.BudgetAmountCurP1,0.0)) AS BudgetAmountCurP1
	, SUM(ISNULL(bvd.BudgetAmountCurP2,0.0)) AS BudgetAmountCurP2
	--, bvd.PlanProjectItem_ID AS PlanProjectItemID
	, bvd.DivisionId  

FROM dbo.Plan_ProjectItem  bvd
	inner join Const_SCOA_Function_Structure csfs
		ON bvd.SCOAFunctionId=csfs.ScoaId
	inner join Const_SCOA_Structure cs
		on cs.ScoaID = bvd.SCOAItemID
WHERE  LEFT(LTRIM(cs.ScoaCode),2) IN ('IE',    --Limit SCOA Items to types "Expenditure" and "Revenue"
										'IR')
AND  bvd.FinYear = @FinYear

GROUP BY -- AS BudgetVersionID 
	 LEFT(LTRIM(cs.ScoaCode),2)
	, LTRIM(RTRIM(cs.ScoaCode))
	, LTRIM(RTRIM(cs.NTScoaID))
	, cs.ScoaID
	, csfs.ScoaID
	, LTRIM(RTRIM(csfs.ScoaCode))
	, LTRIM(RTRIM(csfs.NTScoaID))
	, bvd.FinYear
	, csfs.ScoaShortDesc
	, bvd.DivisionId  


ORDER BY bvd.FinYear, SCOACODE_ITEM, csfs.ScoaShortDesc

