-- Build distinct list of Item > Function > Division structure working with between Original Budget and Revised
DECLARE @ALLITEMS TABLE
(
SCOACodeType_Item NVARCHAR(2) NULL
, SCOACode_Item NVARCHAR(50) NULL
, NTScoaID_Item uniqueidentifier NULL
, SCOAID_Item int NULL
, SCOAID_Function  int NULL
, SCOACode_Function NVARCHAR(50) NULL
, NTScoaID_Function uniqueidentifier NULL
, FinYear NVARCHAR(9) NULL
, SCOADesc_Function NVARCHAR(200) NULL
, DivisionId INT NULL
)
INSERT INTO @ALLITEMS
(
SCOACodeType_Item
, SCOACode_Item
, NTScoaID_Item
, SCOAID_Item
, SCOAID_Function 
, SCOACode_Function
, NTScoaID_Function
, FinYear
, SCOADesc_Function
, DivisionId 
)
SELECT SCOACodeType_Item
		, SCOACode_Item
		, NTScoaID_Item
		, SCOAID_Item
		, SCOAID_Function 
		, SCOACode_Function
		, NTScoaID_Function
		, FinYear
		, SCOADesc_Function
		, DivisionId 
FROM
(
	SELECT DISTINCT 
		 SCOACodeType_Item
		, SCOACode_Item
		, NTScoaID_Item
		, SCOAID_Item
		, SCOAID_Function 
		, SCOACode_Function
		, NTScoaID_Function
		, FinYear
		, SCOADesc_Function
		, DivisionId
	FROM @BUDGETS_ORIG
	UNION
	SELECT DISTINCT
		 SCOACodeType_Item
		, SCOACode_Item
		, NTScoaID_Item
		, SCOAID_Item
		, SCOAID_Function 
		, SCOACode_Function
		, NTScoaID_Function
		, FinYear
		, SCOADesc_Function
		, DivisionId 
	FROM @BUDGETS_REVISED
) ALLITEMS

