-- Get GL Figures - Actuals - Previous Year and Current Financial Year
-- First Apply aggregation to data before joining GL to final report data set, due to different grains

-- Previous Year GL
DECLARE @GL_PrevYear TABLE
(
FinYear NVARCHAR(9) NULL
, SCOACodeType_Item NVARCHAR(2) NULL
, SCOADesc_Function NVARCHAR(200) NULL
, SCOACode_Item NVARCHAR(50) NULL
, NTScoaID_Item UNIQUEIDENTIFIER NULL
, NTScoaID_Function UNIQUEIDENTIFIER NULL
, SCOAID_Item INT NULL
, SCOAID_Function INT NULL
, DivisionId INT NULL
, ActualGL DECIMAL(16,2) NULL
)
INSERT INTO @GL_PrevYear
(
FinYear
, SCOACodeType_Item 
, SCOADesc_Function
, SCOACode_Item
, NTScoaID_Item 
, NTScoaID_Function
, SCOAID_Item
, SCOAID_Function
, DivisionId 
, ActualGL
)
SELECT @PrevYear AS FinYear 
	, ALLITEMS.SCOACodeType_Item
	, ALLITEMS.SCOADesc_Function 
	, ALLITEMS.SCOACode_Item
	, ALLITEMS.NTScoaID_Item 
	, ALLITEMS.NTScoaID_Function
	, ALLITEMS.SCOAID_Item
	, ALLITEMS.SCOAID_Function
	, ALLITEMS.DivisionId 
	, (SUM(ISNULL(GL.Credit,0.0))*(-1)) + SUM(ISNULL(GL.Debit,0.0)) AS ActualGL
FROM @ALLITEMS ALLITEMS

LEFT JOIN Led_GeneralLedger GL
		ON GL.FinYear = @PrevYear
		AND GL.SCOAItemID = ALLITEMS.SCOAID_Item
		AND GL.SCOAFunctionID = ALLITEMS.SCOAID_Function
		AND GL.DivisionId = ALLITEMS.DivisionId

WHERE GL.FinYear IS NOT NULL

GROUP BY ALLITEMS.SCOACodeType_Item
	, ALLITEMS.SCOADesc_Function 
	, ALLITEMS.SCOACode_Item
	, ALLITEMS.NTScoaID_Item 
	, ALLITEMS.NTScoaID_Function
	, ALLITEMS.SCOAID_Item
	, ALLITEMS.SCOAID_Function
	, ALLITEMS.DivisionId 

-- Current Year GL
DECLARE @GL_FinYear TABLE
(
FinYear NVARCHAR(9) NULL
, SCOACodeType_Item NVARCHAR(2) NULL
, SCOADesc_Function NVARCHAR(200) NULL
, SCOACode_Item NVARCHAR(50) NULL
, NTScoaID_Item UNIQUEIDENTIFIER NULL
, NTScoaID_Function UNIQUEIDENTIFIER NULL
, SCOAID_Item INT NULL
, SCOAID_Function INT NULL
, DivisionId INT NULL
, ActualGL DECIMAL(16,2) NULL
)
INSERT INTO @GL_FinYear
(
FinYear
, SCOACodeType_Item 
, SCOADesc_Function
, SCOACode_Item
, NTScoaID_Item 
, NTScoaID_Function
, SCOAID_Item
, SCOAID_Function
, DivisionId
, ActualGL
)
SELECT @FinYear AS FinYear --GL.FinYear
	, ALLITEMS.SCOACodeType_Item
	, ALLITEMS.SCOADesc_Function 
	, ALLITEMS.SCOACode_Item
	, ALLITEMS.NTScoaID_Item 
	, ALLITEMS.NTScoaID_Function
	, ALLITEMS.SCOAID_Item
	, ALLITEMS.SCOAID_Function
	, ALLITEMS.DivisionId
	, (SUM(ISNULL(GL.Credit,0.0))*(-1)) + SUM(ISNULL(GL.Debit,0.0)) AS ActualGL
FROM @ALLITEMS ALLITEMS

LEFT JOIN Led_GeneralLedger GL 
		ON GL.FinYear = @FinYear
		AND GL.SCOAItemID = ALLITEMS.SCOAID_Item
		AND GL.SCOAFunctionID = ALLITEMS.SCOAID_Function
		AND GL.DivisionID = ALLITEMS.DivisionId

WHERE GL.FinYear IS NOT NULL

GROUP BY ALLITEMS.SCOACodeType_Item
	, ALLITEMS.SCOADesc_Function 
	, ALLITEMS.SCOACode_Item
	, ALLITEMS.NTScoaID_Item 
	, ALLITEMS.NTScoaID_Function
	, ALLITEMS.SCOAID_Item
	, ALLITEMS.SCOAID_Function
	, ALLITEMS.DivisionId
	
