-- Get Commitments data

DECLARE @COMMITMENTS TABLE
(
 FinYear			NVARCHAR(9) NULL
, BudgetTransDesc   NVARCHAR(100) NULL
, SCOAFunctionID	INT NULL
, SCOAItemID		INT NULL
, DivisionID		INT NULL
, TransactionAmount	DECIMAL(16,2) NULL
)
INSERT INTO @COMMITMENTS
(
 FinYear			
, BudgetTransDesc  	
, SCOAFunctionID	
, SCOAItemID			
, DivisionID		
, TransactionAmount
)
SELECT 
	 PBR.FinYear
	, BTT.BudgetTransDesc
	, PPI.SCOAFunctionID
	, PPI.SCOAItemID
	, PPI.DivisionID
	, SUM(ISNULL(TransactionAmount,0.0)) AS TransactionAmount

FROM Plan_BudgetRegister PBR 
	
	INNER JOIN Const_BudgetTransactionType_sys BTT
		ON PBR.BudgetTransactionTypeID = BTT.BudgetTransactionType_ID

	INNER JOIN Plan_ProjectItem PPI
		ON PBR.PlanProjectItemID = PPI.PlanProjectItem_ID

WHERE BTT.BudgetTransDesc = 'Committed' 
GROUP BY 
	 PBR.FinYear
	, BTT.BudgetTransDesc
	, PPI.SCOAFunctionID
	, PPI.SCOAItemID
	, PPI.DivisionID
	
