-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 03/03/2017
-- Description:	Get Division for Track Changes
-- Used in : Planning Module
--Plan_GetDivisionsForTrackChanges_sp
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetDivisionsForTrackChanges_sp]
AS
    BEGIN
        SET NOCOUNT ON;

		 SELECT  cd.Division_ID , ptc.ProjectID AS ProjectId,
                        cdp.Department_ID ,
                        --cdp.DepartmentDesc + ' / ' + DepartmentCode + ' / ' + DivisionDesc + ' / ' + DivisionCode AS DivisionDesc ,
						DivisionDesc + ' / ' + DivisionCode AS DivisionDesc ,
                        cd.DivisionDesc AS  DivisionShortDesc,
                        cd.DivisionCode 
                FROM    dbo.Plan_TrackChanges ptc
				INNER JOIN dbo.Const_Division cd ON cd.Division_ID = ptc.DivisionId
                        INNER JOIN Const_Department cdp ON cd.DepartmentID = cdp.Department_ID
                WHERE   cdp.Enabled = 1 AND cd.Enabled = 1
						ORDER BY cdp.DepartmentDesc ,
                        cd.DivisionDesc;
    END;
GO

