/****** Object:  StoredProcedure [dbo].[Plan_GetFundingBudgetSCOAFundByFinYears_sp]    Script Date: 2026/03/10 7:23:34 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Raindree Chetty
-- Create date: 19/05/2015
-- Description:	Get funding budget scoa fund by finyear/s
-- Calls: execute Plan_GetFundingBudgetSCOAFundByFinYears_sp '2018/2019,2019/2020,2020/2021,',''
-- 07-12-2016 By SNagpal: Add column for Remaining Amount
-- 01-02-2017 By RChetty: Pass @CurFinYear as Parameter in Plan_FundingSourceBudgetPerYear_fxn 
-- 06-11-2017 By SNagpal: #63164 : Add Parameter BudgetType, Based upon SCOAFunds loaded from Constants
-- SNagpal 18-02-2019 : 84009, Get SCOA Segments based upon FinYear, Also Optimize the SP. Remove Functions and add new functionality
-- SNagpal 30-05-2019: Revert All changes of 84009, Append new changes of #89269 - Add multiyear concept to SCOA segments based upon financial year
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetFundingBudgetSCOAFundByFinYears_sp]
	 @FinYearlst varchar(400),
	 @BudgetType VARCHAR(10)
AS
BEGIN
SET NOCOUNT ON;
DECLARE @sqlCommand varchar(1000)
DECLARE @Valuelst varchar(200)
SET @Valuelst = 'a,b,c,d,e,f,g,h,i,j,k,l,m,n,o,p,q,r,s,'
SET @sqlCommand = ''
DECLARE @pos INT
DECLARE @len INT
set @pos = 0
set @len = 0
DECLARE @pospt INT
DECLARE @lenpt INT
set @pospt = 0
set @lenpt = 0
DECLARE @crFinYear NVARCHAR(10);
SELECT TOP 1  @crFinYear = splitdata FROM    dbo.fnSplitString(@FinYearlst, ',')

WHILE CHARINDEX(',', @FinYearlst, @pos+1)>0
BEGIN
  set @len = CHARINDEX(',', @FinYearlst, @pos+1) - @pos
  set @lenpt = CHARINDEX(',', @Valuelst, @pospt+1) - @pospt
  IF (@sqlCommand='')
  BEGIN
	SET @sqlCommand = 'SELECT DISTINCT  a.ParentID,a.SCOAFundID,	a.SCOADesc,	a.ScoaCode,	a.ScoaShortDesc,
(a.RemainingFundAmount + b.RemainingFundAmount + c.RemainingFundAmount) AS RemainingFundAmount FROM
	(SELECT * FROM Plan_FundingSourceBudgetPerYear_fxn(''' + SUBSTRING(@FinYearlst, @pos, @len) +''',''' + @crFinYear +''',''' + @BudgetType +''')) ' + SUBSTRING(@Valuelst, @pospt, @lenpt)
  END
  ELSE
  BEGIN
	SET @sqlCommand = @sqlCommand +
	' INNER JOIN  (SELECT * FROM Plan_FundingSourceBudgetPerYear_fxn(''' + SUBSTRING(@FinYearlst, @pos, @len) +''',''' + @crFinYear +''',''' + @BudgetType +''')) ' + SUBSTRING(@Valuelst, @pospt, @lenpt)  +' ON a' +'.SCOAFundID='+ SUBSTRING(@Valuelst, @pospt, @lenpt) +'.SCOAFundID'
  END
  set @pos = CHARINDEX(',', @FinYearlst, @pos+@len) +1
  set @pospt = CHARINDEX(',', @Valuelst, @pospt+@lenpt) +1
END
--select @sqlCommand as result
EXEC (@sqlCommand)
--print (@sqlCommand)

--SELECT Distinct a.* FROM
--(SELECT * FROM Plan_FundingSourceBudgetPerYear_fxn('2016/2017','2016/2017','O')) a
--INNER JOIN  (SELECT * FROM Plan_FundingSourceBudgetPerYear_fxn('2015/2016','2016/2017','O')) b ON a.SCOAFundID=b.SCOAFundID

END

GO

/****** Object:  StoredProcedure [dbo].[Plan_GetFundWidgetDetails_sp]    Script Date: 2026/03/10 7:23:35 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 25 July 2016
-- Description:	Get Fund Widget Details
-- CALL SP:	Plan_GetFundWidgetDetails_sp '2015/2016',3986,1029
-- Updated by Jignesh Prajapati on 26 July 2016, 
--			  Remove Grand Total of Funds & Remove Default values; 
--			  UPDATE Calcualtion for Available/Allocated/Remaining; 
-- Updated by Jignesh Prajapati on 30 July 2016, 
--			  Return 0 in case of no Amount allocated
-- 25-Aug-2016 by Jignesh Prajapati - Update Query to match Fund Availabilty Amount
-- 25-Aug-2016 by Jignesh Prajapati - Remove Commented Code
-- 01-Feb-2017 By Raindree Chetty - Pass current finyear to Planing_GetFundAllocatedAmount
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetFundWidgetDetails_sp]
    @FinYear NVARCHAR(50) = '2015/2016' ,
    @SCOAID BIGINT = 0 ,
    @FundingSource BIGINT = 0
AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;

        DECLARE @FinYearAsNumber INT = SUBSTRING(@FinYear, 6, 4);

        DECLARE @FinYear1 NVARCHAR(50) = CAST(@FinYearAsNumber AS NVARCHAR(4))
            + '/' + CAST(@FinYearAsNumber + 1 AS NVARCHAR(4)) ,
            @FinYear2 NVARCHAR(50) = CAST(@FinYearAsNumber + 1 AS NVARCHAR(4))
            + '/' + CAST(@FinYearAsNumber + 2 AS NVARCHAR(4));

        WITH    FundDetails
                  AS ( SELECT   @FinYear AS FinancialYear ,
                                dbo.Planing_GetFundAvailableAmount(@SCOAID,
                                                              @FinYear) AS Available ,
                                dbo.Planing_GetFundAllocatedAmount(@SCOAID,
                                                              @FinYear, @FinYear) AS Allocated
                       UNION
                       SELECT   @FinYear1 AS FinancialYear ,
                                dbo.Planing_GetFundAvailableAmount(@SCOAID,
                                                              @FinYear1) AS Available ,
                                dbo.Planing_GetFundAllocatedAmount(@SCOAID,
                                                              @FinYear1, @FinYear) AS Allocated
                       UNION
                       SELECT   @FinYear2 AS FinancialYear ,
                                dbo.Planing_GetFundAvailableAmount(@SCOAID,
                                                              @FinYear2) AS Available ,
                                dbo.Planing_GetFundAllocatedAmount(@SCOAID,
                                                              @FinYear2, @FinYear) AS Allocated
                     )
            SELECT  FinancialYear ,
                    Available ,
                    Allocated ,
                    Available - Allocated AS Remaining
            FROM    FundDetails;
				  
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetFundWidgetDetailsForAdjustmentProjectItems_sp]    Script Date: 2026/03/10 7:23:35 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 27/11/2017
-- Description:	Get Fund Widget Details For AdjustmentProject Items
-- CALL SP:	Plan_GetFundWidgetDetailsForAdjustmentProjectItems_sp 2292,2810,'2016/2017'
-- 10/02/2018 RChetty/SNagpal : tp 67541 - fund value duplicating.
-- 11/11/2025 CMoodley : 124586 - Do not return funding with sign
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetFundWidgetDetailsForAdjustmentProjectItems_sp]
	-- Add the parameters for the stored procedure here
    @AdjustmentProjectID INT = 0,
	@SCOAFundID INT = 0 ,
	@UserFinYear NVARCHAR(10) 

AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;
		DECLARE @AdjustmentVersionId INT;

	    SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion WHERE VersionName 
	    LIKE @UserFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC
;
        WITH    Available
                  AS ( SELECT   ROW_NUMBER() OVER ( ORDER BY pfy.FinYear ) AS RecordNo ,
                                pf.AdjustmentProjectID ,
                                pf.ScoaFundID ,
                                pfy.YearFundAmount ,
                                pfy.FinYear
                       FROM     Plan_AdjustmentProjectFund pf
                                INNER JOIN Plan_AdjustmentProjectFundYear pfy ON pf.AdjustmentProjectFund_ID = pfy.AdjustmentProjectFundID
                       WHERE    AdjustmentProjectID = @AdjustmentProjectID
                                AND ScoaFundID = @SCOAFundID AND pf.AdjustmentVersionId = @AdjustmentVersionId
                     ),
                Allocated
                  AS ( SELECT   1 AS RecordNo ,
                                AdjustmentProjectID ,
                                SCOAFundId ,
								SUM(ISNULL(AdjustedBudgetAmount, BudgetAmount)) AS FundByYear
                       FROM     Plan_AdjustmentProjectItem
                       WHERE    AdjustmentProjectID = @AdjustmentProjectID
                                AND SCOAFundId = @SCOAFundID AND AdjustmentVersionId = @AdjustmentVersionId
                       GROUP BY AdjustmentProjectID ,
                                SCOAFundId
                       UNION
                       SELECT   2 AS RecordNo ,
                                AdjustmentProjectID ,
                                SCOAFundId ,
								SUM(ISNULL(AdjustedBudgetAmountCurP1, BudgetAmountCurP1)) AS FundByYear
                       FROM     Plan_AdjustmentProjectItem
                       WHERE    AdjustmentProjectID = @AdjustmentProjectID
                                AND SCOAFundId = @SCOAFundID AND AdjustmentVersionId = @AdjustmentVersionId
                       GROUP BY AdjustmentProjectID ,
                                SCOAFundId
                       UNION
                       SELECT   3 AS RecordNo ,
                                AdjustmentProjectID ,
                                SCOAFundId ,
								SUM(ISNULL(AdjustedBudgetAmountCurP2, BudgetAmountCurP2)) AS FundByYear
                       FROM     Plan_AdjustmentProjectItem
                       WHERE    AdjustmentProjectID = @AdjustmentProjectID
                                AND SCOAFundId = @SCOAFundID AND AdjustmentVersionId = @AdjustmentVersionId
                       GROUP BY AdjustmentProjectID ,
                                SCOAFundId
                     )
             SELECT  Available.RecordNo ,
                    Available.AdjustmentProjectID ,
                    Available.ScoaFundID ,
                    SUM(ISNULL(Available.YearFundAmount,0)) AS AvailableAmount ,
                    Available.FinYear ,
                   SUM(ISNULL(Allocated.FundByYear,0)) AS AllocatedFunds ,
                    (SUM((ISNULL(Available.YearFundAmount,0))) - SUM(ISNULL(Allocated.FundByYear,0)) ) AS RemainingAmount
            FROM    Available
                    LEFT JOIN 
					( SELECT RecordNo ,
                             AdjustmentProjectID ,
                             SCOAFundId,
							 sum(FundByYear) as FundByYear 
					  FROM  Allocated
					  GROUP BY RecordNo,
                               AdjustmentProjectID ,
                               SCOAFundId ) as Allocated 
			        ON Allocated.AdjustmentProjectID = Available.AdjustmentProjectID
                    AND Allocated.RecordNo = Available.RecordNo
                    AND Allocated.SCOAFundId = Available.ScoaFundID 
			GROUP BY
                        Available.RecordNo ,
                        Available.AdjustmentProjectID ,
                        Available.ScoaFundID ,
                        Available.FinYear
			ORDER BY Available.RecordNo;			

    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetFundWidgetDetailsForProjectItems_sp]    Script Date: 2026/03/10 7:23:35 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Sahil Nagpal
-- Create date: 17 Aug 2016
-- Description:	Get Fund Widget Details For Project Items
-- CALL SP:	Plan_GetFundWidgetDetailsForProjectItems_sp 26734, 7442
-- SNagpal 03-11-2017: Add Case when statement for Credit Debit
-- SNagpal 18-01-2018: Add ORDER BY Available.RecordNo; 
-- SNagpal 11-04-2019: Add ISNULL(CreditDebit,'D') for CreditDebit
-- R Mills 13-04-2020: Fix Display issue for different FinYears
-- CMoodley 11-11-2025 : 124586 - Do not return funding with sign
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetFundWidgetDetailsForProjectItems_sp] 
	-- Add the parameters for the stored procedure here
    @ProjectID INT = 0 ,
    @SCOAFundID INT = 0
AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;

		DECLARE @CurrentFinyear varchar(10)
		DECLARE @Fin1 varchar(10)
		DECLARE @Fin2 varchar(10)
		DECLARE @Fin3 varchar(10)

		SELECT @CurrentFinyear = (SELECT TOP 1 FinYear FROM Plan_ProjectItem WHERE ProjectID = @ProjectID) 
		SELECT @fin1 = CAST(RIGHT(@CurrentFinyear,4) as int)
		SELECT @fin2 = CAST(@fin1 as varchar(4)) + '/' + Cast(@fin1 + 1 as varchar(4))
		SELECT @fin3 = CAST(@fin1 + 1 as varchar(4)) + '/' + Cast(@fin1 + 2 as varchar(4))

		;
        WITH    Available
                  AS ( SELECT   ROW_NUMBER() OVER ( ORDER BY pfy.FinYear ) AS RecordNo ,
                                pf.ProjectID ,
                                pf.ScoaFundID ,
                                pfy.YearFundAmount ,
                                pfy.FinYear
                       FROM     Plan_ProjectFund pf
                                INNER JOIN Plan_ProjectFundYear pfy ON pf.ProjectFund_ID = pfy.ProjectFundID
                       WHERE    ProjectID = @ProjectID
                                AND ScoaFundID = @SCOAFundID
                     ),
                Allocated
                  AS ( SELECT   1 AS RecordNo ,
                                ProjectID ,
                                SCOAFundId ,
                                @CurrentFinyear FinYear,
								SUM(BudgetAmount) AS FundByYear
                       FROM     Plan_ProjectItem
                       WHERE    ProjectID = @ProjectID
                                AND SCOAFundId = @SCOAFundID
                       GROUP BY ProjectID ,
                                SCOAFundId ,
                                FinYear
                       UNION
                       SELECT   2 AS RecordNo ,
                                ProjectID ,
                                SCOAFundId ,
                                @Fin2 FinYear,
								 SUM(BudgetAmountCurP1) AS FundByYear
                       FROM     Plan_ProjectItem
                       WHERE    ProjectID = @ProjectID
                                AND SCOAFundId = @SCOAFundID
                       GROUP BY ProjectID ,
                                SCOAFundId ,
                                FinYear
                       UNION
                       SELECT   3 AS RecordNo ,
                                ProjectID ,
                                SCOAFundId ,
                                @Fin3 FinYear,
 								 SUM(BudgetAmountCurP2) AS FundByYear
                       FROM     Plan_ProjectItem
                       WHERE    ProjectID = @ProjectID
                                AND SCOAFundId = @SCOAFundID
                       GROUP BY ProjectID ,
                                SCOAFundId ,
                                FinYear
                     )
            SELECT  Available.RecordNo ,
                    Available.ProjectID ,
                    Available.ScoaFundID ,
                    SUM(ISNULL(Available.YearFundAmount, 0)) AS AvailableAmount ,
                    Available.FinYear ,
                    SUM(ISNULL(Allocated.FundByYear, 0)) AS AllocatedFunds ,
                    ( SUM(( ISNULL(Available.YearFundAmount, 0) ))
                      - SUM(ISNULL(Allocated.FundByYear, 0)) ) AS RemainingAmount
            FROM    Available
                    LEFT JOIN Allocated ON Allocated.ProjectID = Available.ProjectID
                                           AND Allocated.FinYear = Available.FinYear
                                           AND Allocated.SCOAFundId = Available.ScoaFundID
                                           AND Allocated.FinYear = Available.FinYear
            GROUP BY ISNULL(Available.YearFundAmount, 0) ,
                    Available.RecordNo ,
                    Available.ProjectID ,
                    Available.ScoaFundID ,
                    Available.FinYear
            ORDER BY Available.RecordNo;

    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetIDPFullDescription_sp]    Script Date: 2026/03/10 7:23:35 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =========================================================
-- Author:		Sahil Nagpal
-- Create date: 05 July 2015
-- Description:	Returns full Parent Child Descriptions based upon IDPLevel Number
-- Exec Plan_GetIDPFullDescription_sp 3,'2017/2018'
-- 23-12-2016 SNagpal : Optimize the Execution time of Query. Before it taking long time to load, Now it runs at fine speed. Add 'AND i2.IDPLevelNumber <= @IDPLevelNumber'
-- =========================================================
CREATE PROCEDURE [dbo].[Plan_GetIDPFullDescription_sp]
	-- Add the parameters for the stored procedure here
    @IDPLevelNumber INT ,
    @FinancialYear NVARCHAR(10)
AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;

        WITH    parentChildResult (Item_ID, ItemDesc, ItemParentID,	IDPLevelNumber ,	FinancialYear,	ItemNames)
                  AS ( SELECT   Item_ID ,
                                ItemDesc ,
                                ItemParentID ,
                                IDPLevelNumber ,
                                FinancialYear ,
                                CAST('' AS NVARCHAR(MAX)) AS ItemNames
                       FROM     IDP_Item
                       WHERE    ItemParentID IS NULL
								AND FinancialYear = @FinancialYear
                       UNION ALL
                       SELECT   i2.Item_ID ,
                                i2.ItemDesc ,
                                i2.ItemParentID ,
                                i2.IDPLevelNumber ,
                                i2.FinancialYear ,
                                parentChildResult.ItemNames + ' : '
                                + parentChildResult.ItemDesc
                       FROM     IDP_Item AS i2
                                INNER JOIN parentChildResult ON parentChildResult.Item_ID = i2.ItemParentID
					   WHERE i2.FinancialYear = @FinancialYear AND i2.IDPLevelNumber <= @IDPLevelNumber
                     )
			SELECT Item_ID,
                    STUFF(ItemNames, 1, 3, '') + ' : ' + ItemDesc AS ItemNames
            FROM    parentChildResult
            WHERE   STUFF(ItemNames, 1, 3, '') + ' : ' + ItemDesc IS NOT NULL
                    AND parentChildResult.IDPLevelNumber = @IDPLevelNumber
                    AND parentChildResult.FinancialYear = @FinancialYear
            ORDER BY ItemNames;

    END;
GO

