CREATE PROCEDURE [dbo].[Plan_GetKpiPerDepartment_sp]
	  @ScoreCardType BIGINT = 1
	, @Quarter BIGINT = 1
	, @FinYear VARCHAR(9) = '2015/2016'
AS
BEGIN

	SELECT 
		 DepartmentID as DeptID
