-- =============================================
-- Author:	Vincent Majatladi
-- Create date: 21 August 2014
-- Description: Used for Indiviual Scorecard per employee	
-- done this way to keep Columns as Vincent had them so dont have to do an edmx update
-- Calls: Plan_GetKpiPerEmployee_sp 1,4,'2015/2016'
-- 12/11/2015 RC: changed because calculations did not include tasks and monthly tasks and weighting
-- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetKpiPerEmployee_sp]
	  @ScoreCardType BIGINT = 3
	, @Quarter BIGINT = 4
	, @FinYear VARCHAR(9) = '2015/2016'
AS
BEGIN

	SELECT ResponsiblePost AS EmpResponsibleID
,  employ.FirstName+' '+employ.Surname + ' (' + JobTitle + ')' AS EmpResponsible
, Total=100
, [Quarter]=1
, CONVERT(INT,ROUND(ISNULL(SUM(KPIPerformance)/Count(*),0),0),0) AS [TotalAchieved]
, 0 AS [TotalPartiallyAchieved]
, 0 AS [TotalNotAchieved]
, 0 AS [TotalOverAchieved]
, 0 AS [TotalOnhold]
FROM PMS_Indicator Indi 
LEFT JOIN  [dbo].[PMS_IndicatorPerformancePerQuarter_fxn](1) Q1 ON Q1.KpiID=Indi.Kpi_ID
INNER JOIN [dbo].[PMS_IndicatorScorecardType] IndiScore ON IndiScore.KpiID=Indi.Kpi_ID 
INNER JOIN Payroll_Employee employ ON Indi.ResponsiblePost=employ.Employee_ID
INNER JOIN Payroll_Position PP ON employ.PositionID = PP.Position_ID
INNER JOIN Payroll_JobProfile jProfile ON PP.JobProfileID = jProfile.JobProfile_ID
INNER JOIN IDP_Item IDP ON IDP.Item_ID=Indi.ItemID
WHERE IDP.FinancialYear=@FinYear and IndiScore.ScorecardTypeID=@ScoreCardType
GROUP BY ResponsiblePost,employ.Surname,employ.FirstName, JobTitle
UNION
SELECT ResponsiblePost AS EmpResponsibleID
,  employ.FirstName+' '+employ.Surname + ' (' + JobTitle + ')' AS EmpResponsible
, Total=100
, [Quarter]=2
, CONVERT(INT,ROUND(ISNULL(SUM(KPIPerformance)/Count(*),0),0),0) AS [TotalAchieved]
, 0 AS [TotalPartiallyAchieved]
, 0 AS [TotalNotAchieved]
, 0 AS [TotalOverAchieved]
, 0 AS [TotalOnhold]
FROM  PMS_Indicator Indi
LEFT JOIN [dbo].[PMS_IndicatorPerformancePerQuarter_fxn](2) Q1  ON Q1.KpiID=Indi.Kpi_ID
INNER JOIN [dbo].[PMS_IndicatorScorecardType] IndiScore ON IndiScore.KpiID=Indi.Kpi_ID 
INNER JOIN Payroll_Employee employ ON Indi.ResponsiblePost=employ.Employee_ID
INNER JOIN Payroll_Position PP ON employ.PositionID = PP.Position_ID
INNER JOIN Payroll_JobProfile jProfile ON PP.JobProfileID= jProfile.JobProfile_ID
INNER JOIN IDP_Item IDP ON IDP.Item_ID=Indi.ItemID
WHERE IDP.FinancialYear=@FinYear and IndiScore.ScorecardTypeID=@ScoreCardType
GROUP BY ResponsiblePost,employ.Surname,employ.FirstName, JobTitle
UNION
SELECT ResponsiblePost AS EmpResponsibleID
,  employ.FirstName+' '+employ.Surname + ' (' + JobTitle + ')'  AS EmpResponsible
, Total=100
, [Quarter]=3
, CONVERT(INT,ROUND(ISNULL(SUM(KPIPerformance)/Count(*),0),0),0) AS [TotalAchieved]
, 0 AS [TotalPartiallyAchieved]
, 0 AS [TotalNotAchieved]
, 0 AS [TotalOverAchieved]
, 0 AS [TotalOnhold]
FROM  PMS_Indicator Indi
LEFT JOIN [dbo].[PMS_IndicatorPerformancePerQuarter_fxn](3) Q1  ON Q1.KpiID=Indi.Kpi_ID
INNER JOIN [dbo].[PMS_IndicatorScorecardType] IndiScore ON IndiScore.KpiID=Indi.Kpi_ID 
INNER JOIN Payroll_Employee employ ON Indi.ResponsiblePost=employ.Employee_ID
INNER JOIN Payroll_Position PP ON employ.PositionID = PP.Position_ID
INNER JOIN Payroll_JobProfile jProfile ON PP.JobProfileID = jProfile.JobProfile_ID
INNER JOIN IDP_Item IDP ON IDP.Item_ID=Indi.ItemID
WHERE IDP.FinancialYear=@FinYear and IndiScore.ScorecardTypeID=@ScoreCardType
GROUP BY ResponsiblePost,employ.Surname,employ.FirstName, JobTitle
UNION
SELECT ResponsiblePost AS EmpResponsibleID
,  employ.FirstName+' '+employ.Surname + ' (' + JobTitle + ')' AS EmpResponsible
, Total=100
, [Quarter]=4
, CONVERT(INT,ROUND(ISNULL(SUM(KPIPerformance)/Count(*),0),0),0) AS [TotalAchieved]
, 0 AS [TotalPartiallyAchieved]
, 0 AS [TotalNotAchieved]
, 0 AS [TotalOverAchieved]
, 0 AS [TotalOnhold]
FROM  PMS_Indicator Indi
LEFT JOIN [dbo].[PMS_IndicatorPerformancePerQuarter_fxn](4) Q1  ON Q1.KpiID=Indi.Kpi_ID
INNER JOIN [dbo].[PMS_IndicatorScorecardType] IndiScore ON IndiScore.KpiID=Indi.Kpi_ID 
INNER JOIN Payroll_Employee employ ON Indi.ResponsiblePost=employ.Employee_ID
INNER JOIN Payroll_Position PP ON employ.PositionID = PP.Position_ID
INNER JOIN Payroll_JobProfile jProfile ON PP.JobProfileID = jProfile.JobProfile_ID
INNER JOIN IDP_Item IDP ON IDP.Item_ID=Indi.ItemID
WHERE IDP.FinancialYear=@FinYear and IndiScore.ScorecardTypeID=@ScoreCardType
GROUP BY ResponsiblePost,employ.Surname,employ.FirstName, JobTitle
END

GO

