-- =============================================
-- Author:		Nirav Parikh
-- Create date: 2017-11-22
-- Description:	Get Lastest Adjustment Budget Version Number
-- CALL SP: Plan_GetLatestAdjustmentBudgetVersionNumber_sp '2015/2016'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetLatestAdjustmentBudgetVersionNumber_sp] @FinYear NVARCHAR(18)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @NewVersionNumber NVARCHAR(50) = '',
            @CurrVersionNumber NVARCHAR(50) = '',
            @LastVersion INT,
            @NewVersion INT;

    -- Insert statements for procedure here
    SELECT @CurrVersionNumber = VersionNumber
    FROM dbo.Plan_AdjustmentBudgetVersion
    WHERE VersionNumber LIKE @FinYear + '_ADJB%';

    IF (@CurrVersionNumber <> '')
    BEGIN
        SELECT @LastVersion = REPLACE(@CurrVersionNumber, @FinYear + '_ADJB', '');
        SELECT @NewVersion = @LastVersion + 1;
        SELECT @NewVersionNumber = @FinYear + '_ADJB' + REPLICATE('0', 3 - LEN(RTRIM(@NewVersion))) + RTRIM(@NewVersion);
    END;
    ELSE
    BEGIN
        SELECT @NewVersionNumber = @FinYear + '_ADJB001';
    END;

    SELECT @NewVersionNumber AS NewVersionNumber,
           @FinYear AS FinYear;
END;

GO

