-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 2016-04-25
-- Description:	Get Lastest Budget Version Number
-- CALL SP: Plan_GetLatestBudgetVersionNumber_sp '2017/2018'
-- Snagpal: 68253: Add Or condition for ORGB
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetLatestBudgetVersionNumber_sp] @FinYear NVARCHAR(18)
AS
    BEGIN
        SET NOCOUNT ON;

        DECLARE @NewVersionNumber NVARCHAR(50)='' ,
            @CurrVersionNumber NVARCHAR(50)='',
			@LastVersion INT,
			@NewVersion INT;

    -- Insert statements for procedure here
        SELECT TOP 1 @CurrVersionNumber = VersionNumber
        FROM    dbo.Plan_BudgetVersion
        WHERE   VersionNumber LIKE @FinYear + '_B%' OR VersionNumber LIKE @FinYear + '_ORGB%'
		ORDER BY BudgetVersion_ID DESC;

		IF(@CurrVersionNumber <> '')
		BEGIN
			IF(CHARINDEX(@FinYear + '_B', @CurrVersionNumber) > 0)
			BEGIN
			SELECT @LastVersion = REPLACE(@CurrVersionNumber,@FinYear + '_B','')    
			END
			ELSE IF(CHARINDEX(@FinYear + '_ORGB', @CurrVersionNumber) > 0)
			BEGIN
			SELECT @LastVersion = REPLACE(@CurrVersionNumber,@FinYear + '_ORGB','')    
			END

			SELECT @NewVersion = @LastVersion + 1
			SELECT @NewVersionNumber = @FinYear + '_B' + REPLICATE('0',3-LEN(RTRIM(@NewVersion))) + RTRIM(@NewVersion)
		END
		ELSE
		BEGIN
			SELECT @NewVersionNumber = @FinYear + '_B001'
		END

		SELECT @NewVersionNumber AS NewVersionNumber, @FinYear AS FinYear
    END;
GO

