-- =============================================
-- Author:		Sahil Nagpal
-- Create date: 2017-01-11
-- Description:	Get Projects used in Virement
-- Call SP: Plan_GetListProjectUsedInVirement_sp ''
-- 14 Aug 2020 CMoodley: 4727 - Standardise formatting for project name
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetListProjectUsedInVirement_sp]
    @FinancialYear VARCHAR(10)
AS
BEGIN
-- SET NOCOUNT ON added to prevent extra result sets from
-- interfering with SELECT statements.
	SET NOCOUNT ON;       

	SELECT  DISTINCT V.FromProjectId,
			V.ToProjectId,
			CAST(ISNULL(PrjFrom.ProjectCode, PrjFrom.Project_ID) AS VARCHAR(50)) + ' | ' + PrjFrom.ProjectName AS FROMProject,
			CAST(ISNULL(pv.ProjectCode, pv.Project_ID) AS VARCHAR(50)) + ' | ' + pv.ProjectName AS  TOProject, 
			V.FinYear
	FROM    dbo.Plan_Virements V
			INNER JOIN dbo.Plan_Project PrjFrom ON V.FromProjectId = PrjFrom.Project_ID
			INNER JOIN dbo.Plan_Project PV ON V.ToProjectId = PV.Project_ID               
	WHERE  ( CASE WHEN @FinancialYear = '' THEN ''
					ELSE v.FinYear
				END = @FinancialYear )
END;
GO

