-- =============================================
-- Author: SAHIL NAGPAL
-- Create date: 20 JUN 2017
-- Description: Get list of SCOAID, SCOADESC
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetMultipleSCOASegments_sp]
@SegmentType VARCHAR(20)
AS  
BEGIN
   SET NOCOUNT ON; 
   IF(@SegmentType = 'SCOAItem')
	BEGIN
		SELECT ScoaID ,ScoaDesc,NTScoaID
		FROM dbo.Const_SCOA_Structure WHERE Enabled = 1
	END;
	ELSE IF (@SegmentType='SCOAFunction')
	BEGIN
		SELECT ScoaID ,ScoaDesc,NTScoaID
		FROM dbo.Const_SCOA_Function_Structure WHERE Enabled = 1
	END;
	ELSE IF (@SegmentType='SCOACosting')
	BEGIN
		SELECT ScoaID ,ScoaDesc,NTScoaID
		FROM dbo.Const_SCOA_Costing_Structure WHERE Enabled = 1
	END;
END
GO

