/****** Object:  StoredProcedure [dbo].[Plan_GetNextVirementApprover_sp]    Script Date: 2026/03/10 7:23:36 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- ===================================================
-- Author:		Chris Moodley
-- Create date: October 2025
-- Description:	Get next approver for virement as per virement approval level setup
-- ===================================================
CREATE PROCEDURE [dbo].[Plan_GetNextVirementApprover_sp] 
    @FinYear NVARCHAR(9) = '' ,
    @FromProjectId INT = 0 ,
	@UserId INT = NULL
AS
BEGIN
    SET NOCOUNT ON;

	DECLARE @StatusId INT;

	SELECT @StatusId = Status_ID FROM dbo.Const_Status WHERE UsedBy='Virement' AND StatusDesc='Capture Virement'

	SELECT ScoaID,BreakDownAllowed,NTScoaID,ScoaDesc INTO #projectTable FROM dbo.Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @FinYear
	SELECT ScoaID,BreakDownAllowed,NTScoaID,ScoaDesc  INTO #functionTable FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @FinYear
	SELECT ScoaID,BreakDownAllowed,NTScoaID,ScoaCode,ScoaDesc INTO #itemTable FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @FinYear
	SELECT ScoaID,BreakDownAllowed,NTScoaID,ScoaDesc INTO #fundsTable FROM dbo.Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @FinYear
	SELECT ScoaID,BreakDownAllowed,NTScoaID,ScoaDesc INTO #regionalTable FROM dbo.Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @FinYear

    ;WITH Approvals AS (
        SELECT 
            vu.VirementApprovalUserId,
            vu.VirementId,
            vu.UserId,
            vu.DateCaptured,
            ROW_NUMBER() OVER (PARTITION BY vu.VirementId ORDER BY vu.DateCaptured, vu.VirementApprovalUserId) AS ApprovalOrder
        FROM Plan_VirementApprovalUsers vu
    ),
    Status AS (
        SELECT 
            a.VirementId,
            a.UserId,
            a.ApprovalOrder,
            CASE 
                WHEN EXISTS (
                    SELECT 1 
                    FROM Plan_VirementApprovalRejections r
                    WHERE r.VirementId = a.VirementId
                      AND (r.ApprovedBy = a.UserId OR r.RejectedBy = a.UserId)
                ) THEN 1
                ELSE 0
            END AS HasActed
        FROM Approvals a
    ),
    NextApprover AS (
        SELECT 
            s1.VirementId,
            s1.UserId,
            s1.ApprovalOrder
        FROM Status s1
        WHERE s1.HasActed = 0
          AND NOT EXISTS (
                SELECT 1
                FROM Status s2
                WHERE s2.VirementId = s1.VirementId
                  AND s2.ApprovalOrder < s1.ApprovalOrder
                  AND s2.HasActed = 0
          )
    )
    SELECT 
        n.VirementId,
        n.UserId,
        u.FirstName + ' ' + u.LastName AS ApproverName,
        n.ApprovalOrder,
		CAST(ISNULL(PrjFrom.ProjectCode, PrjFrom.Project_ID) AS VARCHAR(50)) + ' | ' + PrjFrom.ProjectName AS FromProject ,
        CAST(ISNULL(PrjTo.ProjectCode, PrjTo.Project_ID) AS VARCHAR(50)) + ' | ' + PrjTo.ProjectName AS ToProject ,
        ISNULL(CSPSFrom.ScoaDesc,'') AS FromSCOAProject ,
        ISNULL(CSPSTo.ScoaDesc,'') AS ToSCOAProject ,
        ISNULL(CSFSFrom.ScoaDesc,'') AS FromSCOAFunction ,
        ISNULL(CSFSTo.ScoaDesc,'') AS ToSCOAFunction ,
        ISNULL(CDFrom.DivisionDesc,'') AS FromDivision ,
        ISNULL(CDTo.DivisionDesc,'') AS ToDivision ,
        ISNULL(CSFDSFrom.ScoaDesc,'') AS FromSCOAFund ,
        ISNULL(CSFDSTo.ScoaDesc,'') AS ToSCOAFund ,
        ISNULL(CSRSFrom.ScoaDesc,'') AS FromSCOARegion ,
        ISNULL(CSRSTo.ScoaDesc,'') AS ToSCOARegion ,
        ISNULL(CSSFrom.ScoaDesc,'') AS FromSCOAItem ,
        ISNULL(CSSTo.ScoaDesc,'') AS ToSCOAItem,
		ISNULL(V.FromVirementAmount,0) AS FromVirementAmount,
		ISNULL(V.ToVirementAmount,0) AS ToVirementAmount,
		V.IsNewItemAdded, V.UploadedVirementDoc ,
		ISNULL(V.FromUkey, '') AS FromUkey,
		ISNULL(V.ToUkey, '') AS ToUkey
    FROM 
		NextApprover n
		INNER JOIN dbo.Plan_Virements V ON V.VirementId = n.VirementId
		INNER JOIN dbo.Plan_Project PrjFrom ON V.FromProjectId = PrjFrom.Project_ID
		LEFT OUTER JOIN Plan_Project PrjTo ON V.ToProjectId = PrjTo.Project_ID
        LEFT OUTER JOIN #projectTable CSPSFrom ON CSPSFrom.ScoaID = V.FromScoaProjectId
        LEFT OUTER JOIN #projectTable CSPSTo ON CSPSTo.ScoaID = V.ToScoaProjectId
        LEFT OUTER JOIN #functionTable CSFSFrom ON CSFSFrom.ScoaID = V.FromScoaFunctionId
        LEFT OUTER JOIN #functionTable CSFSTo ON CSFSTo.ScoaID = V.ToScoaFunctionId
        LEFT OUTER JOIN dbo.Const_Division CDFrom ON CDFrom.Division_ID = V.FromDivisionId
        LEFT OUTER JOIN dbo.Const_Division CDTo ON CDTo.Division_ID = V.ToDivisionId
        LEFT OUTER JOIN #fundsTable CSFDSFrom ON CSFDSFrom.ScoaID = V.FromSCOAFundID
        LEFT OUTER JOIN #fundsTable CSFDSTo ON CSFDSTo.ScoaID = V.ToSCOAFundID
        LEFT OUTER JOIN #regionalTable CSRSFrom ON CSRSFrom.ScoaID = V.FromSCOARegion
        LEFT OUTER JOIN #regionalTable CSRSTo ON CSRSTo.ScoaID = V.ToSCOARegion
        LEFT OUTER JOIN #itemTable CSSFrom ON CSSFrom.ScoaID = V.FromSCOAItem
        LEFT OUTER JOIN #itemTable CSSTo ON CSSTo.ScoaID = V.ToSCOAItem
		INNER JOIN User_UserDetail u ON u.User_ID = n.UserId
    WHERE 
		(@FinYear = '' OR V.FinYear = @FinYear )
		AND (@UserId IS NULL OR n.UserId = @UserId)
		AND ISNULL(V.VirementStatus,0) <> @StatusId 
		AND
				(( CASE WHEN @FromProjectId  = 0 THEN 0 ELSE V.FromProjectId END = @FromProjectId )
				OR
				(CASE WHEN @FromProjectId  = 0 THEN 0 ELSE V.ToProjectId END = @FromProjectId ))
    ORDER BY 
		n.VirementId, n.ApprovalOrder;
END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetNTStringSCOAProjects_sp]    Script Date: 2026/03/10 7:23:36 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- =================================================
-- Author:		Sahil Nagpal
-- Create date: 2017-Sept-29
-- Description:	#62905 CR_ IDP String
-- Plan_GetNTStringSCOAProjects_sp 0, 0,'2019/2020'
-- SNagpal 16-04-2019 : 84009, Get SCOA Segments based upon FinYear, 
-- OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- =================================================
CREATE PROCEDURE [dbo].[Plan_GetNTStringSCOAProjects_sp]
    @NTStringSCOAProjectID INT,
	@SCOAId INT,
    @FinYear NVARCHAR(9)
AS
    BEGIN
	SET NOCOUNT ON;
SET FMTONLY OFF;

	SELECT cnt.NTStringSCOAProject_ID ,
       cnt.SCOAProjectId ,
	   csp.ScoaCode,
	   csp.NTScoaID,
	   csp.ScoaDesc,
	   csp.ScoaShortDesc,
       cnt.FinYear ,
       cnt.IsEnable ,
       cnt.CapturerID ,
       cnt.DateCaptured FROM dbo.Const_NTStringSCOAProject cnt
	   INNER JOIN dbo.Const_SCOA_Project_Structure_ByYear(@FinYear)  csp ON csp.ScoaID = cnt.SCOAProjectId
	   WHERE
 ( CASE WHEN @NTStringSCOAProjectID  = 0 THEN 0
                       ELSE cnt.NTStringSCOAProject_ID
                  END = @NTStringSCOAProjectID )
				  
				   AND ( CASE WHEN @SCOAId = 0 THEN 0
                           ELSE cnt.SCOAProjectId
                      END = @SCOAId  )
				   AND ( CASE WHEN @FinYear = '' THEN ''
                           ELSE cnt.FinYear
                      END =  @FinYear   );

END;
GO

