-- =================================================
-- Author:		Nirav Parikh
-- Create date: 2017-Nov-08
-- Description:	#63164 Budget Register Changes
-- Plan_GetNTValidations_sp 0, 0, 0, '2019/2020'
-- SNagpal 15-04-2019 : 84009, Get SCOA Segments based upon FinYear, 
-- OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- =================================================
CREATE PROCEDURE [dbo].[Plan_GetNTValidations_sp]
    @SCOAFundOperationalID INT ,
    @SCOAItemId INT ,
	@SCOAFunctionId INT ,
    @FinYear NVARCHAR(9)
AS
    BEGIN
        SET NOCOUNT ON;
		SET FMTONLY OFF;

       SELECT  cnt.NTValidation_Id ,
                cnt.ScoaItemId ,
				cnt.ScoaFunctionId ,
                cnt.IsEnable ,
                cnt.FinYear ,

				css.ScoaCode AS ScoaCodeItem,
                css.NTScoaID AS NTScoaIDItem,
                css.ScoaDesc AS ScoaDescItem,
                css.ScoaShortDesc AS ScoaShortDescItem,
                css.PostingLevel AS PostingLevelItem,
                css.BreakDownAllowed AS BreakDownAllowedItem,
				
				csfs.ScoaCode AS ScoaFunctionCode,
                csfs.NTScoaID AS NTScoaIDFunction,
                csfs.ScoaDesc AS ScoaDescFunction,
                csfs.ScoaShortDesc AS ScoaShortDescFunction,
                csfs.PostingLevel AS PostingLevelFunction,
                csfs.BreakDownAllowed AS BreakDownAllowedFunction,
                
				cnt.CapturerID ,
                cnt.DateCaptured
        FROM    dbo.Const_PlanNTValidations cnt
                INNER JOIN dbo.Const_SCOA_Structure_ByYear(@FinYear) css ON css.ScoaID = cnt.ScoaItemId
				INNER JOIN dbo.Const_SCOA_Function_Structure_ByYear(@FinYear) csfs ON csfs.ScoaID = cnt.ScoaFunctionId
        WHERE   ( CASE WHEN @SCOAFundOperationalID = 0 THEN 0
                       ELSE cnt.NTValidation_Id
                  END = @SCOAFundOperationalID  )
                AND ( CASE WHEN @SCOAItemId  = 0 THEN 0
                           ELSE cnt.ScoaItemId
                      END = @SCOAItemId )
				AND ( CASE WHEN @SCOAFunctionId = 0 THEN 0
                           ELSE cnt.ScoaFunctionId
                      END = @SCOAFunctionId )
                AND ( CASE WHEN @FinYear = '' THEN ''
                           ELSE cnt.FinYear
                      END = @FinYear )
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetPartialAvailableBudgetByAdjustmentProjectId_sp]    Script Date: 2026/03/10 7:23:36 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 27/11/2017
-- Description:	Get Fund Widget Details For Project Items
-- CALL SP:	Plan_GetPartialAvailableBudgetByAdjustmentProjectId_sp 3229,'2016/2017'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetPartialAvailableBudgetByAdjustmentProjectId_sp]
	@ProjectID INT,
	@UserFinYear NVARCHAR(10) 

AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;
			DECLARE @AdjustmentVersionId INT;

	SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion WHERE VersionName 
	LIKE @UserFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

	SELECT ISNULL(A.TotalAllocatedBudget,0) AS TotalAllocatedBudget ,ISNULL(ppf.FundAmount,0) AS TotalFundAmount  FROM 
	dbo.Plan_AdjustmentProjectFund ppf
	LEFT JOIN  
		(
		SELECT  ( ISNULL(SUM(ISNULL(AdjustedBudgetAmount, BudgetAmount)), 0) + ISNULL(SUM(ISNULL(AdjustedBudgetAmountCurP1, BudgetAmountCurP1)), 0)
          + ISNULL(SUM(ISNULL(AdjustedBudgetAmountCurP2, BudgetAmountCurP2)), 0) ) AS TotalAllocatedBudget, 
        ppi.AdjustmentProjectID , ppi.SCOAFundId
		FROM    dbo.Plan_AdjustmentProjectItem ppi
		GROUP BY ppi.AdjustmentProjectID ,ppi.SCOAFundId
		) AS A

	ON A.AdjustmentProjectID = ppf.AdjustmentProjectID AND A.SCOAFundId = ppf.ScoaFundID
	WHERE  ppf.AdjustmentProjectID = @ProjectID and (ISNULL(A.TotalAllocatedBudget,0) = 0 OR ISNULL(A.TotalAllocatedBudget,0) <> ISNULL(ppf.FundAmount,0))
	AND ppf.AdjustmentVersionId = @AdjustmentVersionId

    END;
GO

