-- =============================================
-- Author:		Sahil Nagpal
-- Create date: 17 November 2016
-- Description:	Get Fund Widget Details For Project Items
-- CALL SP:	Plan_GetPartialAvailableBudgetByProjectId_sp 61
-- 22-11-2016 SNagpal: Apply Left Join and Add or A.TotalAllocatedBudget = 0 Condition
-- 17-01-2017 SNagpal: Add IsNull Condition for fund amount
-- 24-04-2017 SNagpal: Fix the SP in case of multiple funds per Project
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetPartialAvailableBudgetByProjectId_sp]
	@ProjectID INT

AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;

	SELECT ISNULL(A.TotalAllocatedBudget,0) AS TotalAllocatedBudget ,ISNULL(ppf.FundAmount,0) AS TotalFundAmount  FROM 
	dbo.Plan_ProjectFund ppf
	LEFT JOIN  
		(
		SELECT  ( ISNULL(SUM(BudgetAmount), 0) + ISNULL(SUM(BudgetAmountCurP1), 0)
          + ISNULL(SUM(BudgetAmountCurP2), 0) ) AS TotalAllocatedBudget, 
        ppi.ProjectID , ppi.SCOAFundId
		FROM    dbo.Plan_ProjectItem ppi
		GROUP BY ppi.ProjectID ,ppi.SCOAFundId
		) AS A

	ON A.ProjectID = ppf.ProjectID AND A.SCOAFundId = ppf.ScoaFundID
	WHERE  ppf.ProjectID = @ProjectID and (ISNULL(A.TotalAllocatedBudget,0) = 0 OR ISNULL(A.TotalAllocatedBudget,0) <> ISNULL(ppf.FundAmount,0))
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetPaymentFrameworkApproval_sp]    Script Date: 2026/03/10 7:23:36 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Raindree Chetty
-- Create date: 17 February 2015
-- Description:	Get list of project payment framework based on search criteria
-- 10-12-2019 Volodymyr Stovba: 7334 CR_Project Code Change throughout system_SCM Screens as per document attached. Added ProjectNameWithCode.
-- 04-02-2020 Volodymyr Stovba: 27190 Alpha02: Please add a space between the project code and the pipe and the pipe and project name 
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetPaymentFrameworkApproval_sp] --''
  @ProjectName nvarchar(500)
AS
BEGIN
	SELECT 
		  f.PaymentFramework_ID
		, s.VendorID
		, f.StatusSetByID
		, f.ApprovalStatus
		, p.ProjectName
		, STR(p.ProjectCode) + ' | ' + p.ProjectName as ProjectNameWithCode
		, v.VendorName
		, f.MaximumRetention
		, f.OriginalBudget
		, f.PaymentCumulative
		, ISNULL(f.StatusComment,'') AS StatusComment
		, ISNULL(e.FirstName,'') + ' ' + ISNULL(e.Surname,'') AS StatusSetBy
		, ISNULL(convert(varchar,f.StatusSetDate,103),'') as StatusSetDate  
		, f.SuretyPercentage 
		, ISNULL(c.StatusDesc,'Not Approved') AS StatusDesc
	FROM Plan_ProjectPaymentFramework f
		INNER JOIN Plan_ProjectServiceProvider s ON f.PlanProjectServiceProviderID=s.PlanProjectServiceProvider_ID
		INNER JOIN Plan_Project p ON s.ProjectID=p.Project_ID
		INNER JOIN Cons_Vendor v ON s.VendorID=v.Vendor_ID
		LEFT JOIN Payroll_Employee e ON e.Employee_ID=f.StatusSetByID
		LEFT JOIN Const_Status c ON f.ApprovalStatus=c.Status_ID
	WHERE 
		(p.ProjectName LIKE  '%' + @ProjectName + '%' OR p.ProjectCode LIKE  '%' + @ProjectName + '%')
		AND f.ApprovalStatus IS NOT NULL
END
GO

