-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 2016-04-18
-- Description:	Get Pending Adjustement 
-- CALL SP: Plan_GetPendingAdjustment_sp '',0
-- 2016-04-19 by JP Add Adjustment Type for this list
-- 2016-04-20 by JP Update Condition to check status
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetPendingAdjustment_sp]
    @FinYear NVARCHAR(9) ,
    @ProjectId INT
AS
    BEGIN
        SET NOCOUNT ON;

        SELECT  PA.AdjustmentBudget_Id ,
                PrjFrom.ProjectName AS FromProject ,
                PrjTo.ProjectName AS ToProject ,
                ISNULL(CSPSFrom.ScoaDesc, '') AS FromSCOAProject ,
                ISNULL(CSPSTo.ScoaDesc, '') AS ToSCOAProject ,
                ISNULL(CSFSFrom.ScoaDesc, '') AS FromSCOAFunction ,
                ISNULL(CSFSTo.ScoaDesc, '') AS ToSCOAFunction ,
                ISNULL(CDFrom.DivisionDesc, '') AS FromDivision ,
                ISNULL(CDTo.DivisionDesc, '') AS ToDivision ,
                ISNULL(CSFDSFrom.ScoaDesc, '') AS FromSCOAFund ,
                ISNULL(CSFDSTo.ScoaDesc, '') AS ToSCOAFund ,
                ISNULL(CSRSFrom.ScoaDesc, '') AS FromSCOARegion ,
                ISNULL(CSRSTo.ScoaDesc, '') AS ToSCOARegion ,
                ISNULL(CSSFrom.ScoaDesc, '') AS FromSCOAItem ,
                ISNULL(CSSTo.ScoaDesc, '') AS ToSCOAItem ,
                ISNULL(PA.FromAdjustmentAmount, 0) AS FromAdjustmentAmount ,
                ISNULL(PA.ToAdjustmentAmount, 0) AS ToAdjustmentAmount ,
                CPAT.AdjustmentType AS AdjustmentType
        FROM    dbo.Plan_Project PrjFrom
                INNER JOIN dbo.Plan_Adjustment PA ON PrjFrom.Project_ID = PA.FromProjectId
                INNER JOIN Const_PlanAdjustmentType_sys CPAT ON CPAT.AdjustmentType_ID = PA.TypeOfAdjustment
                LEFT OUTER JOIN Plan_Project PrjTo ON PA.ToProjectId = PrjTo.Project_ID
                LEFT OUTER JOIN dbo.Const_SCOA_Project_Structure CSPSFrom ON CSPSFrom.ScoaID = PA.FromSCOAProjectID
                LEFT OUTER JOIN dbo.Const_SCOA_Project_Structure CSPSTo ON CSPSTo.ScoaID = PA.ToSCOAProjectID
                LEFT OUTER JOIN dbo.Const_SCOA_Function_Structure CSFSFrom ON CSFSFrom.ScoaID = PA.FromSCOAFunctionId
                LEFT OUTER JOIN dbo.Const_SCOA_Function_Structure CSFSTo ON CSFSTo.ScoaID = PA.ToSCOAFunctionId
                LEFT OUTER JOIN dbo.Const_Division CDFrom ON CDFrom.Division_ID = PA.FromDivisionId
                LEFT OUTER JOIN dbo.Const_Division CDTo ON CDTo.Division_ID = PA.ToDivisionId
                LEFT OUTER JOIN dbo.Const_SCOA_Funds_Structure CSFDSFrom ON CSFDSFrom.ScoaID = PA.FromSCOAFundID
                LEFT OUTER JOIN dbo.Const_SCOA_Funds_Structure CSFDSTo ON CSFDSTo.ScoaID = PA.ToSCOAFundID
                LEFT OUTER JOIN dbo.Const_SCOA_Regional_Structure CSRSFrom ON CSRSFrom.ScoaID = PA.FromSCOARegion
                LEFT OUTER JOIN dbo.Const_SCOA_Regional_Structure CSRSTo ON CSRSTo.ScoaID = PA.ToSCOARegion
                LEFT OUTER JOIN dbo.Const_SCOA_Structure CSSFrom ON CSSFrom.ScoaID = PA.FromSCOAItem
                LEFT OUTER JOIN dbo.Const_SCOA_Structure CSSTo ON CSSTo.ScoaID = PA.ToSCOAItem
                LEFT OUTER JOIN dbo.Plan_AdjustmentApprovalRejections PAAR ON PAAR.AdjustmentBudgetId = PA.AdjustmentBudget_Id                          
        WHERE   ( PA.FinYear = @FinYear
                  OR @FinYear = ''
                )
                AND ( @ProjectId = 0
                      OR PA.FromProjectId = @ProjectId
                    )
				AND PA.Status = 101
                AND PAAR.AdjustmentBudgetId IS NULL;
    END;
GO

