-- =============================================
-- Author:	Raindree Chetty
-- Create date: 12/12/2014
-- Description:	Get project budgeting details
-- Plan_GetProjectBudgetingReport_sp '',0,0,'2022/2023',0,0,0,0,0,0,0,'',0
-- RC 02/03/2015 Added Capital/Operation flag as per Gansen
-- RC 02/04/2015 Start fuinyear changed and removed from where clause
-- RC 14/04/2015 Added Project Type and department removed items with no values
-- RC 01/05/2015 Full description required on Item, fund and function and add region filter and details to report
-- RC 18/05/2015 Added funding and costing filters.  Costing column added.
-- RC 22/05/2015 Added Revenue TP 20024
-- RC 11/02/2015 Added Scoa Project details amd Scoa Fund code 
-- RC 24/12/2015 Added function for multiple regions.  NMB Issue list Multiple wards per project.
-- RC 13/02/2016 Budget for outer years now saved in Plan_ProjectItem.  Only 2 outer years needed as per MTEF
-- NP 19/02/2016 IDP Parameter Added
-- RC 23/02/2016 Exclude Projects flagged as deleted (32186)
-- MP 24/02/2016 Replace condition ISNULL(pp.IsDeleted,0)<>1 Previously condition is pp.IsDeleted<>1 
-- NP 09/03/2016 ScoaFunction comma seprated added extra column
-- MP 09/03/2016 Need to calculated data
-- SN 04/04/2016 
-- 1.Change  pp.ItemID -->  pp.IDPItemID as previously it join on ItemId which was wrong.
-- 2.Change  Operation -->  Operational
-- 3.Remove  SCOACostingId from Filteration and Add SCOAItemId in where conditions.
-- SN 05/04/2016 1.Remove functions for SCOAREgion and SCOAFunction, And merge from existing fields.
-- SN 05/04/2016 2.Remove views of ProjectFundingPerYear and Add budgetingamount from existing tables.
-- SN 05/04/2016 3.Add SCOAFunds and also its left outerjoin.
-- SN 20/04/2016 1.Change  pp.ItemID -->  pp.IDPItemID in where conditions.
-- SN 30/04/2016: Modify Names of Operation and Revenue --> Operational Expenditure and Operational Revenue
-- SN 04/05/2016 : Add Fin Year Constraint for Plan_ProjectItems
-- SNagpal 22/06/2016: Add CTE To get parent division ids
-- SNagpal 22/06/2016: As per Discussion, Comment out ScoaCodes from Funding,Region and Functions and desc Remains (38549)
-- RChetty 25/10/2016: Issue when divisionID is 0.
-- SNagpal 14/11/2016: Fix the Issue with divisionID. Change Datatype of DivisionID in parameter & make changes accordingly
-- SNagpal 22/11/2016: Getting SCOACostingId from Plan_ProjectItem Table instead of Plan_Project
-- SNagpal 07/02/2017: Add Filter for SCOA funds & apply case when in where constraints for fast output
-- SNagpal 27/02/2017: Add Filter for Project Status
-- 03-03-2017 SNagpal: Change format for MuniClassification
-- 07-03-2017 SNagpal: Change @CapitalOperational = 4 for All types
-- 08-03-2017 SNagpal: Add Case when for CapitalOperational = 4 .i.e 'Financial Position'
-- 17-03-2017 SNagpal: As per discussion with Gansen;  Add Prefix of pp.Project_ID in ProjectName && Division_Id for Municipal Classification 
-- 29-03-2017 SNagpal: #53397 IDP Removed as per spec
-- 11/04/2017 SNagpal: #55110 Add Filter for SingleMultiYear
-- 09/05/2017 SNagpal: #55994 Capital Operational Types are now managed in Const_PlanCapitalOperationalTypes_sys
-- 14/06/2017 Rchetty: Melanien - Changed logic to change sign only for CapitalOperation in (0,1,2)
-- 21/06/2017 SNagpal: #58698 - Add logic to change sign for CreditDebit if ppi.CreditDebit = 'C'
-- 20/07/2017 NParikh: SCOA Desc Calling Extra Function Remove because of that function getting Timeout error (#59859)
-- 24-Jan-2019 SNagpal: #61596 - #83633 - Add functionality to get ProjectCode
-- 20-02-2019: SNagpal: #84009, Get SCOA Segments based upon FinYear
-- 20-May-2019 SNagpal: Add multiyear concept to get SCOA segments based upon finyear & also add ,ISNULL(ppi.ProjectItemID,0) AS ProjectItemID to get distinct results
-- 31-01-2020 Stepan Len: Bug 28148: Alpha 01: Project Code in Ledger Module should be the same as the Project Code in Planning Module
-- 03-03-2020 ChrisM: 29538 - Handle issue where project code is null
-- 07-08-2023 ChrisM: #105236 Include CostingProject field
-- 13-05-2024 ChrisM: #111849 Return SCOA Function short description
-- 11-09-2025 ChrisM: #122522 Return Ukey
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectBudgetingReport_sp]
	@strDivisionID NVARCHAR(10) ='',
    @ProjectID INT = 0,
    @ScoaFunctionID INT = 0,
    @FinYear NVARCHAR(9) ='2019/2020',
    @CapitalOperational INT = 0,
    @DepartmentID INT = 0,
    @ProjectTypeID INT = 0,
    @ScoaRegionID INT = 0,
    @ScoaFundID INT = 0,
    @ScoaItemID INT ,
    @ProjectStatusId INT = 0,
    @SingleMultiYear VARCHAR(5) = '',
	@ShowCostingProject INT = 0
AS
    BEGIN
	---------PLEASE INFORM LEDGER THAT FINPOS NEEDS TO CHANGE IF DEBITCREDIT LOGIC CHANGES-------
        DECLARE @FinYearP1 NVARCHAR(9) ,
            @FinYearP2 NVARCHAR(9) ,
            @FinYearP3 NVARCHAR(9) ,
            @yearp1 INT ,
            @yearp2 INT ,
            @yearp3 INT ,
            @yearp4 INT ,
            @DivisionID INT;
        SELECT  @yearp1 = CAST(SUBSTRING(@FinYear, 6, 4) AS INT);
        SELECT  @yearp2 = @yearp1 + 1;
        SELECT  @yearp3 = @yearp1 + 2;
        SELECT  @yearp4 = @yearp1 + 3;
        SELECT  @FinYearP1 = CONVERT(VARCHAR(4), @yearp1) + '/'
                + CONVERT(VARCHAR(4), @yearp2);
        SELECT  @FinYearP2 = CONVERT(VARCHAR(4), @yearp2) + '/'
                + CONVERT(VARCHAR(4), @yearp3);
        SELECT  @FinYearP3 = CONVERT(VARCHAR(4), @yearp3) + '/'
                + CONVERT(VARCHAR(4), @yearp4);
	
		CREATE TABLE #Const_SCOA_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
		CREATE INDEX idxItemScoaID ON #Const_SCOA_Structure(ScoaID)
		CREATE INDEX idxItemNTScoaID ON #Const_SCOA_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Function_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100), ScoaShortDesc NVARCHAR(800))
		CREATE INDEX idxFunctionScoaID ON #Const_SCOA_Function_Structure(ScoaID)
		CREATE INDEX idxFunctionNTScoaID ON #Const_SCOA_Function_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Function_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode, ScoaShortDesc FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Costing_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
		CREATE INDEX idxCostingScoaID ON #Const_SCOA_Costing_Structure(ScoaID)
		CREATE INDEX idxCostingNTScoaID ON #Const_SCOA_Costing_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Costing_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Const_SCOA_Costing_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Project_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
		CREATE INDEX idxProjectScoaID ON #Const_SCOA_Project_Structure(ScoaID)
		CREATE INDEX idxProjectNTScoaID ON #Const_SCOA_Project_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Project_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Fund_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100), ScoaShortDesc NVARCHAR(800))
		CREATE INDEX idxFundScoaID ON #Const_SCOA_Fund_Structure(ScoaID)
		CREATE INDEX idxFundNTScoaID ON #Const_SCOA_Fund_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Fund_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode, ScoaShortDesc FROM Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Region_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100), ScoaShortDesc NVARCHAR(800))
		CREATE INDEX idxRegionScoaID ON #Const_SCOA_Fund_Structure(ScoaID)
		CREATE INDEX idxRegionNTScoaID ON #Const_SCOA_Fund_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Region_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode, ScoaShortDesc FROM Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @FinYear

        SELECT  @DivisionID = IIF(@strDivisionID = '', 0, CAST(@strDivisionID AS INT));--To get all parent child divisions 
        
		DECLARE @temp TABLE ( tblDivisionId INT );
        WITH    temp
                  AS ( SELECT   Division_ID ,
                                DivisionParentID
                       FROM     Const_Division
                       WHERE    ( Division_ID = @DivisionID 
                                  OR @DivisionID = 0
                                )
                       UNION ALL
                       SELECT   t.Division_ID ,
                                t.DivisionParentID
                       FROM     Const_Division t
                                JOIN temp ON temp.Division_ID = t.DivisionParentID
                     )
            INSERT  INTO @temp
                    SELECT  temp.Division_ID
                    FROM    temp; 
	
	
	IF @CapitalOperational = 5
	BEGIN
        SELECT DISTINCT
                        pp.Project_ID ,
						ISNULL(pp.ProjectCode, pp.Project_ID) AS ProjectCode ,
                        ( CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS VARCHAR(50)) + ' | '
                          + pp.ProjectName ) AS ProjectName ,
                        REPLACE(REPLACE(REPLACE(pp.ProjectDesc, CHAR(10), ' '),
                                        CHAR(13), ' '), CHAR(09), ' ') AS ProjectDesc ,
                        pp.CostEstimate ,
                        pp.CapitalOperation ,
                        ( SELECT    TypeName
                          FROM      dbo.Const_PlanCapitalOperationalTypes_sys
                          WHERE     TypeValue = pp.CapitalOperation
                        ) AS CapitalOperationDesc ,
                        pp.ProjectStatus ,
                        cs.StatusDesc ,
                        dep.Department_ID ,
                        cd.Division_ID ,
                        pp.ProjectTypeID ,
                        ( CAST(cd.Division_ID AS VARCHAR(10)) + ' '
                          + cd.DivisionDesc + ' / ' + cd.DivisionCode ) AS MuniClassification ,
                        cpt.ProjectTypeDescrip ,
                        ppi.PlanProjectItem_ID AS PlanProjectItemID,
                        func.ScoaCode AS SCOAFuncCode ,
                        func.ScoaDesc AS SCOAFuncDesc ,
                        func.ScoaDesc AS SCOAFunctions ,
                        region.ScoaCode AS SCOARegionCode ,
                        region.ScoaDesc AS SCOARegionDesc ,
                        region.ScoaDesc AS SCOARegions ,
                        costing.ScoaCode AS SCOACostingCode ,
                        costing.ScoaDesc AS SCOACostingDesc ,
                        project.ScoaCode AS SCOAProjectCode ,
                        project.ScoaDesc AS SCOAProjectDesc ,
                        fs.ScoaCode AS SCOAFundCode ,
                        fs.ScoaDesc AS SCOAFundDesc ,
                        fs.ScoaDesc AS SCOAFundings ,
                        ppi.BudgetAmount AS FUNDCurrentYearAmt ,
                        ppi.BudgetAmountCurP1 AS FUNDCurrentP1YearAmt ,
                        ppi.BudgetAmountCurP2 AS FUNDCurrentP2YearAmt ,
                        cpi.ItemDescription ,
                        css.ScoaCode ,
                        css.ScoaDesc AS ScoaShortDesc ,
                        CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                        OR css.ScoaCode LIKE 'IL%'
                                      )
                                      AND pp.CapitalOperation IN ( 0, 1, 2 )
                                    )
                                    OR ppi.CreditDebit = 'C'
                                  ) THEN -ISNULL(ppi.BudgetAmount, 0)
                             ELSE ISNULL(ppi.BudgetAmount, 0)
                        END AS ReqCurrentYearAmt ,
                        CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                        OR css.ScoaCode LIKE 'IL%'
                                      )
                                      AND pp.CapitalOperation IN ( 0, 1, 2 )
                                    )
                                    OR ppi.CreditDebit = 'C'
                                  ) THEN -ISNULL(ppi.BudgetAmountCurP1, 0)
                             ELSE ISNULL(ppi.BudgetAmountCurP1, 0)
                        END AS ReqCurrentYearP1Amt ,
                        CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                        OR css.ScoaCode LIKE 'IL%'
                                      )
                                      AND pp.CapitalOperation IN ( 0, 1, 2 )
                                    )
                                    OR ppi.CreditDebit = 'C'
                                  ) THEN -ISNULL(ppi.BudgetAmountCurP2, 0)
                             ELSE ISNULL(ppi.BudgetAmountCurP2, 0)
                        END AS ReqCurrentYearP2Amt ,
                        0 AS ReqCurrentYearP3Amt ,
                        0 AS ShowColumn , 
						ISNULL(ppi.ProjectItemID, 0) AS ProjectItemID ,
						@ShowCostingProject ShowCostingProject ,
						CASE WHEN ISNULL(pp.CostingProject, 0) = 0 THEN 'No' ELSE 'Yes' END CostingProject,
						ISNULL(ppi.HistoricalProjectCode, '') AS Ukey
                FROM    Plan_Project pp 
						LEFT OUTER  JOIN Const_Status cs ON cs.Status_ID = pp.ProjectStatus
                        LEFT OUTER JOIN Plan_ProjectItem ppi ON pp.Project_ID = ppi.ProjectID
                        LEFT OUTER JOIN Const_Division cd ON cd.Division_ID = ppi.DivisionId
                        LEFT OUTER JOIN Const_Department dep ON cd.DepartmentID = dep.Department_ID
                        LEFT OUTER JOIN #Const_SCOA_Function_Structure AS func ON func.ScoaID = ppi.SCOAFunctionId
                        LEFT OUTER JOIN #Const_SCOA_Region_Structure AS region ON region.ScoaID = ppi.SCOARegionId
                        LEFT OUTER JOIN #Const_SCOA_Costing_Structure AS costing ON costing.ScoaID = ppi.SCOACostingID
                        LEFT OUTER JOIN #Const_SCOA_Project_Structure AS project ON project.ScoaID = pp.ScoaProjectID
                        LEFT OUTER JOIN Const_ProjectItem cpi ON ppi.ProjectItemID = cpi.ProjectItem_ID
                        LEFT OUTER JOIN #Const_SCOA_Structure AS css ON ppi.SCOAItemID = css.ScoaID
                        LEFT OUTER JOIN Const_ProjectType cpt ON pp.ProjectTypeID = cpt.ProjectType_ID
                        LEFT OUTER JOIN #Const_SCOA_Fund_Structure AS fs ON ppi.SCOAFundId = fs.ScoaID
                        INNER JOIN @temp t ON t.tblDivisionId = cd.Division_ID
				 WHERE   ( CASE WHEN @ProjectID = 0 THEN 0
                               ELSE pp.Project_ID END = @ProjectID )
                        AND (CASE WHEN @ScoaFundID  = 0 THEN 0
                                  ELSE fs.ScoaID END = @ScoaFundID )
                        AND (CASE WHEN @ScoaFunctionID  = 0 THEN 0
                                  ELSE func.ScoaID END = @ScoaFunctionID  )
                        AND (CASE WHEN @ScoaRegionID  = 0 THEN 0
                                  ELSE region.ScoaID END = @ScoaRegionID  )
                        AND (CASE WHEN @ScoaItemID  = 0 THEN 0
                                  ELSE css.ScoaID END = @ScoaItemID  )
                        AND (CASE WHEN @DepartmentID  = 0 THEN 0
                                  ELSE dep.Department_ID END = @DepartmentID  )
                        AND (CASE WHEN @ProjectTypeID  = 0 THEN 0
                                  ELSE pp.ProjectTypeID END = @ProjectTypeID  )
                        AND (CASE WHEN @FinYear = '' THEN ''
                                  ELSE pp.FinYear END = @FinYear  )
                        AND (CASE WHEN  @FinYear = '' THEN ''
                                  ELSE ppi.FinYear END = @FinYear)
                        AND (CASE WHEN @ProjectStatusId  = 0 THEN 0
                                  ELSE pp.ProjectStatus END = @ProjectStatusId  )
                        AND (CASE WHEN @SingleMultiYear = '' THEN ''
                                  ELSE pp.SingleMultiYear END = @SingleMultiYear)
						AND (CASE WHEN @ShowCostingProject = 1 THEN @ShowCostingProject
								  ELSE ISNULL(pp.CostingProject, 0) END = @ShowCostingProject  )
                        AND (ISNULL(ppi.BudgetAmount, 0) + ISNULL(ppi.BudgetAmountCurP1, 0) + ISNULL(ppi.BudgetAmountCurP2, 0) ) <> 0
                        AND ISNULL(pp.IsDeleted, 0) <> 1 
				ORDER BY MuniClassification; 
            END;
        ELSE
            BEGIN
             SELECT DISTINCT pp.Project_ID ,
						ISNULL(pp.ProjectCode, pp.Project_ID) AS ProjectCode ,
                        ( CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS VARCHAR(50)) + ' | '
                          + pp.ProjectName ) AS ProjectName ,
                        REPLACE(REPLACE(REPLACE(pp.ProjectDesc, CHAR(10), ' '),
                                        CHAR(13), ' '), CHAR(09), ' ') AS ProjectDesc ,
                        pp.CostEstimate ,
                        pp.CapitalOperation ,
                        ( SELECT    TypeName
                          FROM      dbo.Const_PlanCapitalOperationalTypes_sys
                          WHERE     TypeValue = pp.CapitalOperation
                        ) AS CapitalOperationDesc ,
                        pp.ProjectStatus ,
                        cs.StatusDesc ,
                        dep.Department_ID ,
                        cd.Division_ID ,
                        pp.ProjectTypeID ,
                        ( CAST(cd.Division_ID AS VARCHAR(10)) + ' '
                          + cd.DivisionDesc + ' / ' + cd.DivisionCode ) AS MuniClassification ,
                        cpt.ProjectTypeDescrip ,
                         ppi.PlanProjectItem_ID AS PlanProjectItemID,
                        func.ScoaCode AS SCOAFuncCode ,
                        func.ScoaShortDesc AS SCOAFuncDesc ,
                        func.ScoaDesc AS SCOAFunctions ,
                        region.ScoaCode AS SCOARegionCode ,
                        region.ScoaDesc AS SCOARegionDesc ,
                        region.ScoaDesc AS SCOARegions ,
                        costing.ScoaCode AS SCOACostingCode ,
                        costing.ScoaDesc AS SCOACostingDesc ,
                        project.ScoaCode AS SCOAProjectCode ,
                        project.ScoaDesc AS SCOAProjectDesc ,
                        fs.ScoaCode AS SCOAFundCode ,
                        fs.ScoaDesc AS SCOAFundDesc ,
                        fs.ScoaDesc AS SCOAFundings ,
                        ppi.BudgetAmount AS FUNDCurrentYearAmt ,
                        ppi.BudgetAmountCurP1 AS FUNDCurrentP1YearAmt ,
                        ppi.BudgetAmountCurP2 AS FUNDCurrentP2YearAmt ,
                        cpi.ItemDescription ,
                        css.ScoaCode ,
                        css.ScoaDesc AS ScoaShortDesc ,
                        CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                        OR css.ScoaCode LIKE 'IL%'
                                      )
                                      AND pp.CapitalOperation IN ( 0, 1, 2 )
                                    )
                                    OR ppi.CreditDebit = 'C'
                                  ) THEN -ISNULL(ppi.BudgetAmount, 0)
                             ELSE ISNULL(ppi.BudgetAmount, 0)
                        END AS ReqCurrentYearAmt ,
                        CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                        OR css.ScoaCode LIKE 'IL%'
                                      )
                                      AND pp.CapitalOperation IN ( 0, 1, 2 )
                                    )
                                    OR ppi.CreditDebit = 'C'
                                  ) THEN -ISNULL(ppi.BudgetAmountCurP1, 0)
                             ELSE ISNULL(ppi.BudgetAmountCurP1, 0)
                        END AS ReqCurrentYearP1Amt ,
                        CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                        OR css.ScoaCode LIKE 'IL%'
                                      )
                                      AND pp.CapitalOperation IN ( 0, 1, 2 )
                                    )
                                    OR ppi.CreditDebit = 'C'
                                  ) THEN -ISNULL(ppi.BudgetAmountCurP2, 0)
                             ELSE ISNULL(ppi.BudgetAmountCurP2, 0)
                        END AS ReqCurrentYearP2Amt ,
                        0 AS ReqCurrentYearP3Amt ,
                        0 AS ShowColumn , 
						ISNULL(ppi.ProjectItemID,0) AS ProjectItemID ,
						@ShowCostingProject ShowCostingProject ,
						CASE WHEN ISNULL(pp.CostingProject, 0) = 0 THEN 'No' ELSE 'Yes' END CostingProject,
						ISNULL(ppi.HistoricalProjectCode, '') AS Ukey
                FROM    Plan_Project pp 
                         LEFT OUTER JOIN Plan_ProjectItem ppi ON pp.Project_ID = ppi.ProjectID
                        LEFT OUTER JOIN Const_Status cs ON cs.Status_ID = pp.ProjectStatus
                        LEFT OUTER JOIN Const_Division cd ON cd.Division_ID = ppi.DivisionId
                        LEFT OUTER JOIN Const_Department dep ON cd.DepartmentID = dep.Department_ID
                        LEFT OUTER JOIN #Const_SCOA_Function_Structure AS func ON func.ScoaID = ppi.SCOAFunctionId
                        LEFT OUTER JOIN #Const_SCOA_Region_Structure AS region ON region.ScoaID = ppi.SCOARegionId
                        LEFT OUTER JOIN #Const_SCOA_Costing_Structure AS costing ON costing.ScoaID = ppi.SCOACostingID
                        LEFT OUTER JOIN #Const_SCOA_Project_Structure AS project ON project.ScoaID = pp.ScoaProjectID
                        LEFT OUTER JOIN Const_ProjectItem cpi ON ppi.ProjectItemID = cpi.ProjectItem_ID
                        LEFT OUTER JOIN #Const_SCOA_Structure AS css ON ppi.SCOAItemID = css.ScoaID
                        LEFT OUTER JOIN Const_ProjectType cpt ON pp.ProjectTypeID = cpt.ProjectType_ID
                        LEFT OUTER JOIN #Const_SCOA_Fund_Structure AS fs ON ppi.SCOAFundId = fs.ScoaID
                        INNER JOIN @temp t ON t.tblDivisionId = cd.Division_ID 
						WHERE   ( CASE WHEN @ProjectID  = 0 THEN 0
                               ELSE pp.Project_ID END = @ProjectID  )
                        AND ( CASE WHEN @ScoaFundID  = 0 THEN 0
                                   ELSE fs.ScoaID END = @ScoaFundID  )
                        AND ( CASE WHEN  @ScoaFunctionID  = 0 THEN 0
                                   ELSE func.ScoaID END =  @ScoaFunctionID  )
                        AND ( CASE WHEN @ScoaRegionID  = 0 THEN 0
                                   ELSE region.ScoaID END = @ScoaRegionID  )
                        AND ( CASE WHEN @ScoaItemID  = 0 THEN 0
                                   ELSE css.ScoaID END = @ScoaItemID  )
                        AND ( CASE WHEN @DepartmentID  = 0 THEN 0
                                   ELSE dep.Department_ID END = @DepartmentID  )
                        AND ( CASE WHEN @ProjectTypeID  = 0 THEN 0
                                   ELSE pp.ProjectTypeID END = @ProjectTypeID  )
                        AND ( CASE WHEN @FinYear = '' THEN ''
                                   ELSE pp.FinYear END = @FinYear )
                        AND ( CASE WHEN @FinYear = '' THEN ''
                                   ELSE ppi.FinYear END = @FinYear )
                        AND ( CASE WHEN  @ProjectStatusId  = 0 THEN 0
                                   ELSE pp.ProjectStatus END =  @ProjectStatusId  )
                        AND ( CASE WHEN @SingleMultiYear = '' THEN ''
                                   ELSE pp.SingleMultiYear END = @SingleMultiYear)
                        AND ( pp.CapitalOperation = @CapitalOperational  )
						AND (CASE WHEN @ShowCostingProject = 1 THEN @ShowCostingProject
								  ELSE ISNULL(pp.CostingProject, 0) END = @ShowCostingProject  )
                        AND ( ISNULL(ppi.BudgetAmount, 0) + ISNULL(ppi.BudgetAmountCurP1, 0) + ISNULL(ppi.BudgetAmountCurP2, 0) ) <> 0
                        AND ISNULL(pp.IsDeleted, 0) <> 1 ORDER BY MuniClassification
            END;
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectBudgetingReportByVersion_sp]    Script Date: 2026/03/10 7:23:36 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 2016-04-26
-- Description:	Project Budget Report By Version
-- CALL SP: Plan_GetProjectBudgetingReportByVersion_sp '',21321,0,'2025/2026',5,0,0,0,0,0,0,20,'', 1
--			Plan_GetProjectBudgetingReportByVersion_sp '',0,0,'2018/2019',4,0,0,0,0,0,0,1,'S'
-- SNagpal 05/07/2016: Modify Names of Operation and Revenue --> Operational Expenditure and Operational Revenue
-- SNagpal 05/07/2016: Add CTE To get parent division ids
-- SNagpal 05/07/2016: As per Discussion, Comment out ScoaCodes from Funding,Region and Functions and desc Remains (38549)
-- SNagpal 14/11/2016: Fix the Issue with divisionID. Change Datatype of DivisionID in parameter & make changes accordingly
-- SNagpal 02/03/2016: Add option (maxrecursion 0) in CTE
-- SNagpal 07/02/2017: Add Filter for SCOA funds & apply case when in where constraints for fast output
-- SNagpal 27/02/2017: Add Filter for Project Status
-- 03-03-2017 SNagpal: Change format for MuniClassification
-- 07-03-2017 SNagpal: Change @CapitalOperational = 4 for All types
-- 08-03-2017 SNagpal: Add Case when for CapitalOperational = 4 .i.e 'Financial Position'
-- 17-03-2017 SNagpal: As per discussion with Gansen;  Add Prefix of pp.Project_ID in ProjectName && Division_Id for Municipal Classification 
-- 29-03-2017 SNagpal: #53397 IDP Removed as per spec
-- 11/04/2017 SNagpal: #55110 Add Filter for SingleMultiYear
-- 04/05/2017 SNagpal: #55994 Capital Operational Types are now managed in Const_PlanCapitalOperationalTypes_sys
-- 14/06/2017 Rchetty: Melanien - Changed logic to change sign only for CapitalOperation in (0,1,2)
-- 26/06/2017 SNagpal: #58698 - Add logic to change sign for CreditDebit if ppi.CreditDebit = 'C'
-- 20/07/2017 NParikh: SCOA Desc Calling Extra Function Remove because of that function getting Timeout error (#59859)
-- 24/10/2017 SNagpal: Fix Budget balancing and Add "AND ppi.PlanProjectItemID = ppit.planprojectitem_id" with Plan_BudgetVersionDetail
-- 24-Jan-2019 SNagpal: #61596 - #83633 - Add functionality to get ProjectCode
-- 20-May-2019 SNagpal: Add multiyear concept to get SCOA segments based upon finyear & also add ,ISNULL(ppi.ProjectItemID,0) AS ProjectItemID to get distinct results
-- 03-03-2020 ChrisM: 29538 - Return project code for report, Handle issue where project code is null
-- 07-08-2023 ChrisM: #105236 Include CostingProject field
-- 11-09-2025 ChrisM: #122522 Return Ukey
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectBudgetingReportByVersion_sp]
    @strDivisionID NVARCHAR(10) ,
    @ProjectID INT ,
    @ScoaFunctionID INT ,
    @FinYear NVARCHAR(9) ,
    @CapitalOperational INT ,
    @DepartmentID INT ,
    @ProjectTypeID INT ,
    @ScoaRegionID INT ,
    @ScoaFundID INT ,
    @ScoaItemID INT ,
    @ProjectStatusId INT ,
    @VersionId INT ,
    @SingleMultiYear VARCHAR(5),
	@ShowCostingProject INT
AS
    BEGIN
	---------PLEASE INFORM LEDGER THAT FINPOS NEEDS TO CHANGE IF DEBITCREDIT LOGIC CHANGES-------

	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;

        DECLARE @FinYearP1 NVARCHAR(9) ,
            @FinYearP2 NVARCHAR(9) ,
            @FinYearP3 NVARCHAR(9) ,
            @yearp1 INT ,
            @yearp2 INT ,
            @yearp3 INT ,
            @yearp4 INT ,
            @DivisionID INT;
        SELECT  @yearp1 = CAST(SUBSTRING(@FinYear, 6, 4) AS INT);
        SELECT  @yearp2 = @yearp1 + 1;
        SELECT  @yearp3 = @yearp1 + 2;
        SELECT  @yearp4 = @yearp1 + 3;
        SELECT  @FinYearP1 = CONVERT(VARCHAR(4), @yearp1) + '/'
                + CONVERT(VARCHAR(4), @yearp2);
        SELECT  @FinYearP2 = CONVERT(VARCHAR(4), @yearp2) + '/'
                + CONVERT(VARCHAR(4), @yearp3);
        SELECT  @FinYearP3 = CONVERT(VARCHAR(4), @yearp3) + '/'
                + CONVERT(VARCHAR(4), @yearp4);

		CREATE TABLE #Const_SCOA_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
		CREATE INDEX idxItemScoaID ON #Const_SCOA_Structure(ScoaID)
		CREATE INDEX idxItemNTScoaID ON #Const_SCOA_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Function_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
		CREATE INDEX idxFunctionScoaID ON #Const_SCOA_Function_Structure(ScoaID)
		CREATE INDEX idxFunctionNTScoaID ON #Const_SCOA_Function_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Function_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Costing_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
		CREATE INDEX idxCostingScoaID ON #Const_SCOA_Costing_Structure(ScoaID)
		CREATE INDEX idxCostingNTScoaID ON #Const_SCOA_Costing_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Costing_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Const_SCOA_Costing_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Project_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
		CREATE INDEX idxProjectScoaID ON #Const_SCOA_Project_Structure(ScoaID)
		CREATE INDEX idxProjectNTScoaID ON #Const_SCOA_Project_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Project_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Fund_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100), ScoaShortDesc NVARCHAR(800))
		CREATE INDEX idxFundScoaID ON #Const_SCOA_Fund_Structure(ScoaID)
		CREATE INDEX idxFundNTScoaID ON #Const_SCOA_Fund_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Fund_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode, ScoaShortDesc FROM Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Region_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100), ScoaShortDesc NVARCHAR(800))
		CREATE INDEX idxRegionScoaID ON #Const_SCOA_Fund_Structure(ScoaID)
		CREATE INDEX idxRegionNTScoaID ON #Const_SCOA_Fund_Structure(NTScoaID)
		INSERT INTO #Const_SCOA_Region_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode, ScoaShortDesc FROM Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @FinYear

        SELECT  @DivisionID = IIF(@strDivisionID = '', NULL, CAST(@strDivisionID AS INT));--To get all parent child divisions 
        DECLARE @temp TABLE ( tblDivisionId INT );

        WITH    temp
                  AS ( SELECT   Division_ID ,
                                DivisionParentID
                       FROM     Const_Division
                       WHERE    ( Division_ID = @DivisionID
                                  OR @DivisionID IS NULL
                                )
                       UNION ALL
                       SELECT   t.Division_ID ,
                                t.DivisionParentID
                       FROM     Const_Division t
                                JOIN temp ON temp.Division_ID = t.DivisionParentID
                     )
            INSERT  INTO @temp
                    SELECT  temp.Division_ID
                    FROM    temp
            OPTION  ( MAXRECURSION 0 );


        IF @CapitalOperational = 5
            BEGIN
                SELECT DISTINCT     
                        pp.Project_ID ,
                        ISNULL(pp.ProjectCode, pp.Project_ID) AS ProjectCode ,
                        ( CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS VARCHAR(50)) + ' | '
                          + pp.ProjectName ) AS ProjectName ,
                        REPLACE(REPLACE(REPLACE(pp.ProjectDesc, CHAR(10), ' '),
                                        CHAR(13), ' '), CHAR(09), ' ') AS ProjectDesc ,
                        ppi.CapitalOperation ,
                        ( SELECT    TypeName
                          FROM      dbo.Const_PlanCapitalOperationalTypes_sys
                          WHERE     TypeValue = pp.CapitalOperation
                        ) AS CapitalOperationDesc ,
                        pp.ProjectStatus ,
                        cs.StatusDesc ,
                        dep.Department_ID ,
                        cd.Division_ID ,
                        ppi.ProjectTypeID ,
                        ( CAST(cd.Division_ID AS VARCHAR(10)) + ' '
                          + cd.DivisionDesc + ' / ' + cd.DivisionCode ) AS MuniClassification ,
                        cpt.ProjectTypeDescrip ,
						ppit.PlanProjectItem_ID AS PlanProjectItemID,
                        func.ScoaCode AS SCOAFuncCode ,
                        func.ScoaDesc AS SCOAFuncDesc ,
                        func.ScoaDesc AS SCOAFunctions ,
                        region.ScoaCode AS SCOARegionCode ,
                        region.ScoaDesc AS SCOARegionDesc ,
                        region.ScoaDesc AS SCOARegions ,
                        costing.ScoaCode AS SCOACostingCode ,
                        costing.ScoaDesc AS SCOACostingDesc ,
                        project.ScoaCode AS SCOAProjectCode ,
                        project.ScoaDesc AS SCOAProjectDesc ,
                        fs.ScoaCode AS SCOAFundCode ,
                        fs.ScoaDesc AS SCOAFundDesc ,
                        fs.ScoaDesc AS SCOAFundings ,
                        cpi.ItemDescription ,
                        css.ScoaCode ,
                        css.ScoaDesc AS ScoaShortDesc ,
                        CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                        OR css.ScoaCode LIKE 'IL%'
                                      )
                                      AND pp.CapitalOperation IN ( 0, 1, 2 )
                                    )
                                    OR ppit.CreditDebit = 'C'
                                  ) THEN -ISNULL(ppi.BudgetAmount, 0)
                             ELSE ISNULL(ppi.BudgetAmount, 0)
                        END AS ReqCurrentYearAmt ,
                        CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                        OR css.ScoaCode LIKE 'IL%'
                                      )
                                      AND pp.CapitalOperation IN ( 0, 1, 2 )
                                    )
                                    OR ppit.CreditDebit = 'C'
                                  ) THEN -ISNULL(ppi.BudgetAmountCurP1, 0)
                             ELSE ISNULL(ppi.BudgetAmountCurP1, 0)
                        END AS ReqCurrentYearP1Amt ,
                        CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                        OR css.ScoaCode LIKE 'IL%'
                                      )
                                      AND pp.CapitalOperation IN ( 0, 1, 2 )
                                    )
                                    OR ppit.CreditDebit = 'C'
                                  ) THEN -ISNULL(ppi.BudgetAmountCurP2, 0)
                             ELSE ISNULL(ppi.BudgetAmountCurP2, 0)
                        END AS ReqCurrentYearP2Amt ,
                        0 AS ShowColumn ,
                        ISNULL(pbv.VersionNumber, '') AS VersionNumber ,
                        ISNULL(pbv.VersionName, '') AS VersionName ,
                        ISNULL(pbv.Comments, '') AS Comments ,
						ISNULL(ppi.ProjectItemID,0) AS ProjectItemID ,
						@ShowCostingProject ShowCostingProject ,
						CASE WHEN ISNULL(pp.CostingProject, 0) = 0 THEN 'No' ELSE 'Yes' END CostingProject,
						ISNULL(ppit.HistoricalProjectCode, '') AS Ukey
                FROM    Plan_Project pp
                        LEFT OUTER JOIN dbo.Plan_ProjectItem ppit ON pp.Project_ID = ppit.ProjectID
                        LEFT OUTER JOIN Plan_BudgetVersionDetail ppi ON pp.Project_ID = ppi.ProjectID AND ppi.PlanProjectItemID = ppit.planprojectitem_id
                        LEFT OUTER  JOIN Const_Status cs ON cs.Status_ID = pp.ProjectStatus
                        LEFT OUTER JOIN Plan_BudgetVersion pbv ON ppi.BudgetVersionID = pbv.BudgetVersion_ID
                        LEFT OUTER JOIN Const_Division cd ON cd.Division_ID = ppi.DivisionId
                        LEFT OUTER JOIN Const_Department dep ON cd.DepartmentID = dep.Department_ID
                        LEFT OUTER JOIN #Const_SCOA_Function_Structure AS func ON func.ScoaID = ppi.SCOAFunctionId 
                        LEFT OUTER JOIN #Const_SCOA_Region_Structure AS region ON region.ScoaID = ppi.SCOARegionId 
                        LEFT OUTER JOIN #Const_SCOA_Costing_Structure AS costing ON costing.ScoaID = ppi.SCOACostingID
                        LEFT OUTER JOIN #Const_SCOA_Project_Structure AS project ON project.ScoaID = pp.ScoaProjectID
                        LEFT OUTER JOIN Const_ProjectItem cpi ON ppi.ProjectItemID = cpi.ProjectItem_ID
                        LEFT OUTER JOIN #Const_SCOA_Structure AS css ON ppi.SCOAItemID = css.ScoaID
                        LEFT OUTER JOIN Const_ProjectType cpt ON pp.ProjectTypeID = cpt.ProjectType_ID
                        LEFT OUTER JOIN #Const_SCOA_Fund_Structure AS fs ON ppi.SCOAFundId = fs.ScoaID 
                        INNER JOIN @temp t ON t.tblDivisionId = cd.Division_ID
                WHERE   ppi.BudgetVersionID = @VersionId
                        AND ( CASE WHEN @ProjectID = 0 THEN 0
                                   ELSE pp.Project_ID
                              END = @ProjectID )
                        AND ( CASE WHEN @ScoaFundID = 0 THEN 0
                                   ELSE fs.ScoaID
                              END = @ScoaFundID )
                        AND ( CASE WHEN @ScoaFunctionID = 0 THEN 0
                                   ELSE func.ScoaID
                              END = @ScoaFunctionID )
                        AND ( CASE WHEN @ScoaRegionID = 0 THEN 0
                                   ELSE region.ScoaID
                              END = @ScoaRegionID )
                        AND ( CASE WHEN @ScoaItemID = 0 THEN 0
                                   ELSE css.ScoaID
                              END = @ScoaItemID )
                        AND ( CASE WHEN @DepartmentID = 0 THEN 0
                                   ELSE dep.Department_ID
                              END = @DepartmentID )
                        AND ( CASE WHEN @ProjectTypeID = 0 THEN 0
                                   ELSE pp.ProjectTypeID
                              END = @ProjectTypeID )
                        AND ( CASE WHEN @FinYear = '' THEN ''
                                   ELSE pp.FinYear
                              END = @FinYear )
                        AND ( CASE WHEN @FinYear = '' THEN ''
                                   ELSE ppi.FinYear
                              END = @FinYear )
                        AND ( CASE WHEN @ProjectStatusId = 0 THEN 0
                                   ELSE pp.ProjectStatus
                              END = @ProjectStatusId )
                        AND ( CASE WHEN @SingleMultiYear = '' THEN ''
                                   ELSE pp.SingleMultiYear
                              END = @SingleMultiYear )
						AND (CASE WHEN @ShowCostingProject = 1 THEN @ShowCostingProject
								   ELSE ISNULL(pp.CostingProject, 0) END = @ShowCostingProject  )
                        AND ( ISNULL(ppi.BudgetAmount, 0)
                              + ISNULL(ppi.BudgetAmountCurP1, 0)
                              + ISNULL(ppi.BudgetAmountCurP2, 0) ) > 0
                        AND ISNULL(pp.IsDeleted, 0) <> 1
                ORDER BY MuniClassification;
            END;
        ELSE
            BEGIN
                SELECT DISTINCT    
                        pp.Project_ID ,
                        ISNULL(pp.ProjectCode, pp.Project_ID) AS ProjectCode ,
                        ( CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS VARCHAR(50)) + ' | '
                          + pp.ProjectName ) AS ProjectName ,
                        REPLACE(REPLACE(REPLACE(pp.ProjectDesc, CHAR(10), ' '),
                                        CHAR(13), ' '), CHAR(09), ' ') AS ProjectDesc ,
                        ppi.CapitalOperation ,
                        ( SELECT    TypeName
                          FROM      dbo.Const_PlanCapitalOperationalTypes_sys
                          WHERE     TypeValue = pp.CapitalOperation
                        ) AS CapitalOperationDesc ,
                        pp.ProjectStatus ,
                        cs.StatusDesc ,
                        dep.Department_ID ,
                        cd.Division_ID ,
                        ppi.ProjectTypeID ,
                        ( CAST(cd.Division_ID AS VARCHAR(10)) + ' '
                          + cd.DivisionDesc + ' / ' + cd.DivisionCode ) AS MuniClassification ,
                        cpt.ProjectTypeDescrip ,
						ppit.PlanProjectItem_ID AS PlanProjectItemID,
                        func.ScoaCode AS SCOAFuncCode ,
                        func.ScoaShortDesc AS SCOAFuncDesc ,
                        func.ScoaDesc AS SCOAFunctions ,
                        region.ScoaCode AS SCOARegionCode ,
                        region.ScoaDesc AS SCOARegionDesc ,
                        region.ScoaDesc AS SCOARegions ,
                        costing.ScoaCode AS SCOACostingCode ,
                        costing.ScoaDesc AS SCOACostingDesc ,
                        project.ScoaCode AS SCOAProjectCode ,
                        project.ScoaDesc AS SCOAProjectDesc ,
                        fs.ScoaCode AS SCOAFundCode ,
                        fs.ScoaDesc AS SCOAFundDesc ,
                        fs.ScoaDesc AS SCOAFundings ,
                        cpi.ItemDescription ,
                        css.ScoaCode ,
                        css.ScoaDesc AS ScoaShortDesc ,
                        CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                        OR css.ScoaCode LIKE 'IL%'
                                      )
                                      AND pp.CapitalOperation IN ( 0, 1, 2 )
                                    )
                                    OR ppit.CreditDebit = 'C'
                                  ) THEN -ISNULL(ppi.BudgetAmount, 0)
                             ELSE ISNULL(ppi.BudgetAmount, 0)
                        END AS ReqCurrentYearAmt ,
                        CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                        OR css.ScoaCode LIKE 'IL%'
                                      )
                                      AND pp.CapitalOperation IN ( 0, 1, 2 )
                                    )
                                    OR ppit.CreditDebit = 'C'
                                  ) THEN -ISNULL(ppi.BudgetAmountCurP1, 0)
                             ELSE ISNULL(ppi.BudgetAmountCurP1, 0)
                        END AS ReqCurrentYearP1Amt ,
                        CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                        OR css.ScoaCode LIKE 'IL%'
                                      )
                                      AND pp.CapitalOperation IN ( 0, 1, 2 )
                                    )
                                    OR ppit.CreditDebit = 'C'
                                  ) THEN -ISNULL(ppi.BudgetAmountCurP2, 0)
                             ELSE ISNULL(ppi.BudgetAmountCurP2, 0)
                        END AS ReqCurrentYearP2Amt ,
                        0 AS ShowColumn ,
                        ISNULL(pbv.VersionNumber, '') AS VersionNumber ,
                        ISNULL(pbv.VersionName, '') AS VersionName ,
                        ISNULL(pbv.Comments, '') AS Comments ,
						ISNULL(ppi.ProjectItemID, 0) AS ProjectItemID ,
						@ShowCostingProject ShowCostingProject ,
						CASE WHEN ISNULL(pp.CostingProject, 0) = 0 THEN 'No' ELSE 'Yes' END CostingProject,
						ISNULL(ppit.HistoricalProjectCode, '') AS Ukey
                FROM    Plan_Project pp
                        LEFT OUTER JOIN dbo.Plan_ProjectItem ppit ON pp.Project_ID = ppit.ProjectID
                        LEFT OUTER JOIN dbo.Plan_BudgetVersionDetail ppi ON pp.Project_ID = ppi.ProjectID AND ppi.PlanProjectItemID = ppit.planprojectitem_id
                        LEFT OUTER JOIN Plan_BudgetVersion pbv ON ppi.BudgetVersionID = pbv.BudgetVersion_ID
                        LEFT OUTER JOIN Const_Status cs ON cs.Status_ID = pp.ProjectStatus
                        LEFT OUTER JOIN Const_Division cd ON cd.Division_ID = ppi.DivisionId
                        LEFT OUTER JOIN Const_Department dep ON cd.DepartmentID = dep.Department_ID
                        LEFT OUTER JOIN #Const_SCOA_Function_Structure AS func ON func.ScoaID = ppi.SCOAFunctionId 
                        LEFT OUTER JOIN #Const_SCOA_Region_Structure AS region ON region.ScoaID = ppi.SCOARegionId 
                        LEFT OUTER JOIN #Const_SCOA_Costing_Structure AS costing ON costing.ScoaID = ppi.SCOACostingID
                        LEFT OUTER JOIN #Const_SCOA_Project_Structure AS project ON project.ScoaID = pp.ScoaProjectID
                        LEFT OUTER JOIN Const_ProjectItem cpi ON ppi.ProjectItemID = cpi.ProjectItem_ID
                        LEFT OUTER JOIN #Const_SCOA_Structure AS css ON ppi.SCOAItemID = css.ScoaID
                        LEFT OUTER JOIN Const_ProjectType cpt ON pp.ProjectTypeID = cpt.ProjectType_ID
                        LEFT OUTER JOIN #Const_SCOA_Fund_Structure AS fs ON ppi.SCOAFundId = fs.ScoaID 
                        INNER JOIN @temp t ON t.tblDivisionId = cd.Division_ID
                WHERE   ppi.BudgetVersionID = @VersionId
                        AND ( CASE WHEN @ProjectID = 0 THEN 0
                                   ELSE pp.Project_ID
                              END = @ProjectID )
                        AND ( CASE WHEN @ScoaFundID = 0 THEN 0
                                   ELSE fs.ScoaID
                              END = @ScoaFundID )
                        AND ( CASE WHEN @ScoaFunctionID = 0 THEN 0
                                   ELSE func.ScoaID
                              END = @ScoaFunctionID )
                        AND ( CASE WHEN @ScoaRegionID = 0 THEN 0
                                   ELSE region.ScoaID
                              END = @ScoaRegionID )
                        AND ( CASE WHEN @ScoaItemID = 0 THEN 0
                                   ELSE css.ScoaID
                              END = @ScoaItemID )
                        AND ( CASE WHEN @DepartmentID = 0 THEN 0
                                   ELSE dep.Department_ID
                              END = @DepartmentID )
                        AND ( CASE WHEN @ProjectTypeID = 0 THEN 0
                                   ELSE pp.ProjectTypeID
                              END = @ProjectTypeID )
                        AND ( CASE WHEN @FinYear = '' THEN ''
                                   ELSE pp.FinYear
                              END = @FinYear )
                        AND ( CASE WHEN @FinYear = '' THEN ''
                                   ELSE ppi.FinYear
                              END = @FinYear )
                        AND ( CASE WHEN @ProjectStatusId = 0 THEN 0
                                   ELSE pp.ProjectStatus
                              END = @ProjectStatusId )
                        AND ( CASE WHEN @SingleMultiYear = '' THEN ''
                                   ELSE pp.SingleMultiYear
                              END = @SingleMultiYear )
                        AND ( pp.CapitalOperation = @CapitalOperational )
						AND (CASE WHEN @ShowCostingProject = 1 THEN @ShowCostingProject
								   ELSE ISNULL(pp.CostingProject, 0) END = @ShowCostingProject  )
                        AND ( ISNULL(ppi.BudgetAmount, 0)
                              + ISNULL(ppi.BudgetAmountCurP1, 0)
                              + ISNULL(ppi.BudgetAmountCurP2, 0) ) > 0
                        AND ISNULL(pp.IsDeleted, 0) <> 1
                ORDER BY MuniClassification;
            END;
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectByDepartmentId_sp]    Script Date: 2026/03/10 7:23:36 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 08-Dec-2016
-- Description:	Get project using DepartmentId
-- Calls: Plan_GetProjectByDepartmentId_sp '1,2,3,4','2015/2016'
-- 28-03-2017 SNagpal: As IDPItemID and ItemId no more exists in Plan_Project Table. In Future If needed apply join with Plan_ProjectIDP
-- 29-04-2017 SNagpal: Pass multiple DepartmentId in paramater, As Single user may have multiple Department And Removed IDP columns
-- 12-08-2020 CMoodley: 4757 - Return ProjectField to include ProjectCode and ProjectName
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectByDepartmentId_sp]
@DepartmentId NVARCHAR(200) ='1,2,3,4',
@FinYear NVARCHAR(9)
	AS
    BEGIN
	
	SET NOCOUNT ON;    
				--To get all parent child divisions 
    DECLARE @temp TABLE ( tblDivisionId INT NULL);

    WITH temp AS 
		(   
			SELECT   Division_ID , DivisionParentID
			FROM     dbo.Const_Division
			WHERE    (@DepartmentId = '0' OR DepartmentID IN (SELECT CAST(Data AS INT) FROM dbo.Split(@DepartmentId, ',')))
            UNION ALL
            SELECT   t.Division_ID , t.DivisionParentID
            FROM     dbo.Const_Division t
                    JOIN temp ON temp.Division_ID = t.DivisionParentID
        )


	INSERT  INTO @temp
	SELECT  temp.Division_ID
	FROM    temp;

	SELECT DISTINCT
		pp.Project_ID ,
        pp.ProjectName ,
		CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS VARCHAR(50)) + ' | ' + pp.ProjectName + '(' + csps.ScoaCode + ')' AS ProjectScoaShortDesc,
        pp.ProjectDesc ,
        pp.ProjectManagerID ,
        pp.CapitalOperation ,
        pp.ScoaProjectID ,
        pp.ProjectStatus ,
        pp.FinYear ,
        pp.ProjectTypeID ,
        pp.IsDeleted,
		0 AS Division_ID, -- Division_ID is not using on code, So for distinct result Make it 0
		CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS VARCHAR(10)) + ' | ' + pp.ProjectName AS ProjectField
	FROM dbo.Plan_Project pp
		INNER HASH JOIN dbo.Const_SCOA_Project_Structure_ByYear(@FinYear) csps ON csps.ScoaID = pp.ScoaProjectID
		INNER JOIN dbo.Plan_ProjectDivisions ppd ON ppd.ProjectID = pp.Project_ID
		INNER JOIN dbo.Const_Division cd ON cd.Division_ID = ppd.DivisionID
	WHERE (pp.FinYear=@FinYear OR @FinYear='0') AND
		 cd.Division_ID IN  (SELECT DISTINCT tblDivisionId FROM @temp) AND ISNULL(pp.IsDeleted,0)=0
END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectCashflowBalances_sp]    Script Date: 2026/03/10 7:23:36 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Vincent Majatladi
-- Create date: 21 October 2015
-- Description:	--
-- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.
-- 2016-04-05 TP34537 Raindree: Division can be multiple so removed from filter
-- 2016-04-06 TP34537 Sahil: Remove comments of DepartmentID and DivisionId
-- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions
-- 29/03/2017 SNagpal: As IDPItemID,IsNonIDP and ItemId no more exists in Plan_Project Table. So apply function Plan_ProjectIDP_fxn to get IDPItemDesc
-- Plan_GetProjectCashflowBalances_sp '2016/2017',0,0,0,0
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectCashflowBalances_sp] 
	  @FinYear VARCHAR(9) = '2015/2016'
	, @IDPID INT = 0
	, @ResponsiblePersonID INT = 0
	, @ProjectTypeID INT = 0
	, @FunderID INT = 0
AS
BEGIN

	DECLARE @Amount TABLE (
		[ProjectID] [int] NOT NULL,
		[AmountType] [int] NOT NULL,
		[Amount] [decimal](38, 2) NULL,
		[Month] [int] NULL,
		[FinancialYear] [nvarchar](50) NULL
	)

	INSERT INTO @Amount
	SELECT *--ISNULL(a.ProjectID, b.ProjectID) AS ProjectID, Planned, PlannedMonth, Actual, ActualMonth, 0.00 AS [Commited], 0 AS [CommitedMonth], ISNULL(PlannedYear, ActualYear) AS FinancialYear
	FROM
		(SELECT	ProjectID, 1 AS AmountType, [Amount] =
			SUM(CASE 
					WHEN (ISNULL([RevDirect],0) + ISNULL([RevIndirect],0)) = 0 THEN (ISNULL([PlanDirect],0) + ISNULL([PlanIndirect],0))
					ELSE (ISNULL([PlanDirect],0) + ISNULL([PlanIndirect],0))
				END)
				, MONTH(PeriodEnd) AS [Month], prj.FinYear AS FinancialYear
		FROM 	[dbo].[Plan_Project_CashFlow] pc
		LEFT JOIN [dbo].[Plan_Project] prj ON prj.Project_ID = pc.ProjectID
		--WHERE 	[PeriodEnd] < @AsAtDate
		GROUP BY ProjectID, MONTH(PeriodEnd), FinYear
		HAVING FinYear = @FinYear
		) a
		UNION ALL
		(SELECT p.[Project_ID] AS [ProjectID], 3 AS AmountType, SUM(isNull(cv.VoteAmount, 0) + ISNULL(cv.VoteVATAmount,0) - ISNULL(cv.VoteVATClaimable,0)) As [Amount], MONTH(c.TransactionDate) AS [Month], r.FinancialYear
			FROM [dbo].[Plan_Project] p
			LEFT JOIN [dbo].[SCM_ProcurementPlanNew] pp ON pp.[PlanProjectID] = p.[Project_ID]
			INNER JOIN [dbo].[SCM_Requisition] r ON r.[ProcurementID] = pp.[ProcurementPlan_ID]
			LEFT JOIN [dbo].[SCM_QuotationRequistion] qr ON qr.[RequisitionID] = r.[Requisition_ID] --[QuotationID]
			LEFT JOIN [dbo].[SCM_ServiceInvoice] si ON si.[RequisitionID] = r.[Requisition_ID]--[ServiceInvoice_ID]
			LEFT JOIN [dbo].[SCM_Tender] t ON t.[RequisitionID] = r.[Requisition_ID] --[Tender_ID]
			INNER JOIN [dbo].[SCM_Order] o ON (o.[QuotationId] = qr.QuotationID OR o.[TenderId] = t.Tender_ID) --AND o.[RequisitionId] = r.Requisition_ID
			INNER JOIN [dbo].[SCM_Invoice] i ON i.[OrderID] = o.[Order_ID] --OR i.[ServiceInvoiceID] = si.[ServiceInvoice_ID]
			INNER JOIN [dbo].[SCM_CashbookVote] cv ON cv.[InvoiceID] = i.[Invoice_ID]
			INNER JOIN [dbo].[SCM_Cashbook] c ON c.[SCMTransaction_ID] = [SCMTransactionID]
			GROUP BY p.[Project_ID], MONTH(c.TransactionDate), r.FinancialYear
			HAVING r.FinancialYear = @FinYear
		)

	;WITH 
	CTE_Jan AS
	(
		SELECT [ProjectID], [Amount], [AmountType] FROM @Amount a WHERE [Month] = 1
	),
	CTE_Feb AS
	(
		SELECT [ProjectID], [Amount], [AmountType] FROM @Amount a WHERE [Month] = 2
	),
	CTE_Mar AS
	(
		SELECT [ProjectID], [Amount], [AmountType] FROM @Amount a WHERE [Month] = 3
	),
	CTE_Apr AS
	(
		SELECT [ProjectID], [Amount], [AmountType] FROM @Amount a WHERE [Month] = 4
	),
	CTE_May AS
	(
		SELECT [ProjectID], [Amount], [AmountType] FROM @Amount a WHERE [Month] = 5
	),
	CTE_Jun AS
	(
		SELECT [ProjectID], [Amount], [AmountType] FROM @Amount a WHERE [Month] = 6
	),
	CTE_Jul AS
	(
		SELECT [ProjectID], [Amount], [AmountType] FROM @Amount a WHERE [Month] = 7
	),
	CTE_Aug AS
	(
		SELECT [ProjectID], [Amount], [AmountType] FROM @Amount a WHERE [Month] = 8
	),
	CTE_Sep AS
	(
		SELECT [ProjectID], [Amount], [AmountType] FROM @Amount a WHERE [Month] = 9
	),
	CTE_Oct AS
	(
		SELECT [ProjectID], [Amount], [AmountType] FROM @Amount a WHERE [Month] = 10
	),
	CTE_Nov AS
	(
		SELECT [ProjectID], [Amount], [AmountType] FROM @Amount a WHERE [Month] = 11
	),
	CTE_Dec AS
	(
		SELECT [ProjectID], [Amount], [AmountType] FROM @Amount a WHERE [Month] = 12
	)
	SELECT [Project_ID] AS [ProjectID]
		 , 1 AS [BalanceOrderID]
		 , 'Planned/Revised' AS [BalanceName]
		 , [ProjectName]
		 , resp.EmpJobProfile AS [ResponsiblePerson]
		 , ISNULL(dbo.Plan_ProjectIDP_fxn(p.Project_ID, @IDPID),'') AS [IDPCluster] --i.ItemDesc AS [IDPCluster]
		 , ISNULL(CTE_Jul.[Amount], 0) AS [Jul]
		 , ISNULL(CTE_Aug.[Amount], 0) AS [Aug]
		 , ISNULL(CTE_Sep.[Amount], 0) AS [Sep]
		 , ISNULL(CTE_Oct.[Amount], 0) AS [Oct]
		 , ISNULL(CTE_Nov.[Amount], 0) AS [Nov]
		 , ISNULL(CTE_Dec.[Amount], 0) AS [Dec]
		 , ISNULL(CTE_Jan.[Amount], 0) AS [Jan]
		 , ISNULL(CTE_Feb.[Amount], 0) AS [Feb]
		 , ISNULL(CTE_Mar.[Amount], 0) AS [Mar]
		 , ISNULL(CTE_Apr.[Amount], 0) AS [Apr]
		 , ISNULL(CTE_May.[Amount], 0) AS [May]
		 , ISNULL(CTE_Jun.[Amount], 0) AS [Jun]
		 , ISNULL(CTE_Jul.[Amount], 0) + ISNULL(CTE_Aug.[Amount], 0) + ISNULL(CTE_Sep.[Amount], 0) + ISNULL(CTE_Oct.[Amount], 0) + ISNULL(CTE_Nov.[Amount], 0) + ISNULL(CTE_Dec.[Amount], 0) + ISNULL(CTE_Jan.[Amount], 0) + ISNULL(CTE_Feb.[Amount], 0) + ISNULL(CTE_Mar.[Amount], 0) + ISNULL(CTE_Apr.[Amount], 0) + ISNULL(CTE_May.[Amount], 0) + ISNULL(CTE_Jun.[Amount], 0) AS [Total]
	FROM [dbo].[Plan_Project] p
	LEFT JOIN CTE_Jul ON CTE_Jul.ProjectID = p.Project_ID AND CTE_Jul.[AmountType] = 1
	LEFT JOIN CTE_Aug ON CTE_Aug.ProjectID = p.Project_ID AND CTE_Aug.[AmountType] = 1
	LEFT JOIN CTE_Sep ON CTE_Sep.ProjectID = p.Project_ID AND CTE_Sep.[AmountType] = 1
	LEFT JOIN CTE_Oct ON CTE_Oct.ProjectID = p.Project_ID AND CTE_Oct.[AmountType] = 1
	LEFT JOIN CTE_Nov ON CTE_Nov.ProjectID = p.Project_ID AND CTE_Nov.[AmountType] = 1
	LEFT JOIN CTE_Dec ON CTE_Dec.ProjectID = p.Project_ID AND CTE_Dec.[AmountType] = 1
	LEFT JOIN CTE_Jan ON CTE_Jan.ProjectID = p.Project_ID AND CTE_Jan.[AmountType] = 1
	LEFT JOIN CTE_Feb ON CTE_Feb.ProjectID = p.Project_ID AND CTE_Feb.[AmountType] = 1
	LEFT JOIN CTE_Mar ON CTE_Mar.ProjectID = p.Project_ID AND CTE_Mar.[AmountType] = 1
	LEFT JOIN CTE_Apr ON CTE_Apr.ProjectID = p.Project_ID AND CTE_Apr.[AmountType] = 1
	LEFT JOIN CTE_May ON CTE_May.ProjectID = p.Project_ID AND CTE_May.[AmountType] = 1
	LEFT JOIN CTE_Jun ON CTE_Jun.ProjectID = p.Project_ID AND CTE_Jun.[AmountType] = 1
	LEFT JOIN
			(SELECT emp.Employee_ID, Surname + ' ' + FirstName + ' (' + JobTitle + ')' AS EmpJobProfile
				FROM Payroll_Employee emp
				INNER JOIN Payroll_Position PP ON emp.PositionID = PP.Position_ID
				INNER JOIN Payroll_JobProfile jProfile ON PP.JobProfileID = jProfile.JobProfile_ID
			) resp ON resp.Employee_ID = p.ProjectManagerID
	--LEFT JOIN IDP_Item i ON i.Item_ID = p.IDPItemID
	WHERE p.FinYear = @FinYear 
	AND p.ProjectManagerID = CASE WHEN ISNULL(@ResponsiblePersonID, 0) = 0 THEN p.ProjectManagerID ELSE @ResponsiblePersonID END
	--AND p.IDPItemID = CASE WHEN ISNULL(@IDPID, 0) = 0 THEN p.IDPItemID ELSE @IDPID END
	AND (CASE WHEN @IDPID > 0 THEN ISNULL(dbo.Plan_ProjectIDP_fxn(p.Project_ID, @IDPID),'') ELSE 'IDP' END != '')
	AND p.ProjectTypeID = CASE WHEN ISNULL(@ProjectTypeID, 0) = 0 THEN p.ProjectTypeID ELSE @ProjectTypeID END
	AND p.[Project_ID] IN (SELECT [Project_ID] 
						   FROM [dbo].[Plan_Project] prj
						   INNER JOIN [dbo].[Plan_ProjectFund] pf ON pf.[ProjectID] = prj.[Project_ID]
						   WHERE (ScoaFundID = CASE WHEN ISNULL(@FunderID, 0) = 0 THEN ScoaFundID ELSE @FunderID END
						   AND FinYear = @FinYear) OR ISNULL(@FunderID, 0) = 0)
	UNION ALL
	SELECT [Project_ID] AS [ProjectID]
		 , 2 AS [BalanceOrderID]
		 , 'Committed' AS [BalanceName]
		 , [ProjectName]
		 , resp.EmpJobProfile AS [ResponsiblePerson]
		 , ISNULL(dbo.Plan_ProjectIDP_fxn(p.Project_ID, @IDPID),'') AS [IDPCluster] -- i.ItemDesc AS [IDPCluster]
		 , ISNULL(CTE_Jul.[Amount], 0) AS [Jul]
		 , ISNULL(CTE_Aug.[Amount], 0) AS [Aug]
		 , ISNULL(CTE_Sep.[Amount], 0) AS [Sep]
		 , ISNULL(CTE_Oct.[Amount], 0) AS [Oct]
		 , ISNULL(CTE_Nov.[Amount], 0) AS [Nov]
		 , ISNULL(CTE_Dec.[Amount], 0) AS [Dec]
		 , ISNULL(CTE_Jan.[Amount], 0) AS [Jan]
		 , ISNULL(CTE_Feb.[Amount], 0) AS [Feb]
		 , ISNULL(CTE_Mar.[Amount], 0) AS [Mar]
		 , ISNULL(CTE_Apr.[Amount], 0) AS [Apr]
		 , ISNULL(CTE_May.[Amount], 0) AS [May]
		 , ISNULL(CTE_Jun.[Amount], 0) AS [Jun]
		 , ISNULL(CTE_Jul.[Amount], 0) + ISNULL(CTE_Aug.[Amount], 0) + ISNULL(CTE_Sep.[Amount], 0) + ISNULL(CTE_Oct.[Amount], 0) + ISNULL(CTE_Nov.[Amount], 0) + ISNULL(CTE_Dec.[Amount], 0) + ISNULL(CTE_Jan.[Amount], 0) + ISNULL(CTE_Feb.[Amount], 0) + ISNULL(CTE_Mar.[Amount], 0) + ISNULL(CTE_Apr.[Amount], 0) + ISNULL(CTE_May.[Amount], 0) + ISNULL(CTE_Jun.[Amount], 0) AS [Total]
	FROM [dbo].[Plan_Project] p
	LEFT JOIN CTE_Jul ON CTE_Jul.ProjectID = p.Project_ID AND CTE_Jul.[AmountType] = 2
	LEFT JOIN CTE_Aug ON CTE_Aug.ProjectID = p.Project_ID AND CTE_Aug.[AmountType] = 2
	LEFT JOIN CTE_Sep ON CTE_Sep.ProjectID = p.Project_ID AND CTE_Sep.[AmountType] = 2
	LEFT JOIN CTE_Oct ON CTE_Oct.ProjectID = p.Project_ID AND CTE_Oct.[AmountType] = 2
	LEFT JOIN CTE_Nov ON CTE_Nov.ProjectID = p.Project_ID AND CTE_Nov.[AmountType] = 2
	LEFT JOIN CTE_Dec ON CTE_Dec.ProjectID = p.Project_ID AND CTE_Dec.[AmountType] = 2
	LEFT JOIN CTE_Jan ON CTE_Jan.ProjectID = p.Project_ID AND CTE_Jan.[AmountType] = 2
	LEFT JOIN CTE_Feb ON CTE_Feb.ProjectID = p.Project_ID AND CTE_Feb.[AmountType] = 2
