				INNER JOIN Payroll_JobProfile jProfile ON PP.JobProfileID = jProfile.JobProfile_ID
			) resp ON resp.Employee_ID = p.ProjectManagerID
	--LEFT JOIN IDP_Item i ON i.Item_ID = p.IDPItemID
	WHERE p.FinYear = @FinYear 
	AND p.ProjectManagerID = CASE WHEN ISNULL(@ResponsiblePersonID, 0) = 0 THEN p.ProjectManagerID ELSE @ResponsiblePersonID END
	--AND p.IDPItemID = CASE WHEN ISNULL(@IDPID, 0) = 0 THEN p.IDPItemID ELSE @IDPID END
