-- =============================================
-- Author:	Raindree Chetty
-- Create date: 2 February 2015
-- Description:	Get list of project Cession based on search criteria
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectCession_sp] --'15
  @PlanProjectServiceProviderID int
AS
BEGIN
	SELECT pc.PlanProjectCession_ID
	, pc.PlanProjectServiceProviderID
	, pc.CessionVendorID
	, pc.CessionName 
	, v.VendorName
	, ISNULL(pc.CessionBudget,0) AS CessionBudget
	FROM 
	Plan_ProjectCession pc
	INNER JOIN Cons_Vendor v ON pc.CessionVendorID=v.Vendor_ID
	WHERE 
		pc.PlanProjectServiceProviderID = @PlanProjectServiceProviderID
END
GO

