SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 21/11/2015
-- Description:	Get project Costing details by project id, ScoaCostingID
-- Used in : Project Capture Screen
-- SNagpal 18-02-2019 : 84009, Get SCOA Segments based upon FinYear
-- Plan_GetProjectCosting_sp 1993,0,'2018/2019'
-- OShiri 24-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- CMoodley 16-01-2020 : 26850, Include financial year in where clause
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectCosting_sp]
	@ProjectID int,
	@ScoaCostingID int,
	@FinYear NVARCHAR(9)
AS
BEGIN

	SET NOCOUNT ON;

	SELECT pc.ProjectCosting_ID
	, pc.ProjectID
	, pc.ScoaCostingID
	, rs.ScoaDesc
	, rs.ScoaCode
	, rs.ScoaShortDesc
	FROM Plan_ProjectCosting pc
	INNER JOIN dbo.Const_SCOA_Costing_Structure_ByYear(@FinYear) rs ON rs.ScoaID=pc.ScoaCostingID
	INNER JOIN dbo.Plan_Project pp ON pp.Project_ID = pc.ProjectID
	WHERE (pc.ProjectID= @ProjectID OR @ProjectID =0)
	AND (pc.ScoaCostingID=@ScoaCostingID  OR  @ScoaCostingID = 0)
	AND FinYear = CASE WHEN @FinYear IS NULL OR @FinYear = '' OR @FinYear = '0' THEN FinYear ELSE @FinYear END

END
GO

