-- =============================================
-- Author:	Raindree Chetty
-- Create date: 8 December 2014
-- Description:	Get list of project detail based on search criteria
-- 20/01/2015 RC : Spec changed.  Need to display just project and project status
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectDetailSearch_sp] --''
 @ProjectName nvarchar(500)
 , @StatusID int 
AS
BEGIN
SELECT pp.Project_ID
, pp.ProjectStatus
, cs.StatusDesc 
, pp.ProjectName
, pp.ProjectDetailDesc
FROM 
Plan_Project pp
INNER JOIN Const_Status cs ON pp.ProjectStatus = cs.Status_ID
WHERE 
  pp.ProjectName LIKE  '%' + @ProjectName + '%' 
  AND pp.ProjectStatus>@StatusID    
END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectDetailsForDashboard_sp]    Script Date: 2026/03/10 7:23:37 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	SAHIL NAGPAL
-- Create date: 01 MARCH 2017
-- Description:	Get Project Details for dashboard data
-- Calls: [Plan_GetProjectDetailsForDashboard_sp]
-- SNagpal 28-04-2017 : Add IsNull to Fields
-- NParikh 05-Feb-2017 67338 Bug Nr 50: Planning dashboard indication incorrect when budget is copied over
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectDetailsForDashboard_sp]
@FYear NVARCHAR(9)
AS
    BEGIN
        SET NOCOUNT ON;
        SELECT  ISNULL([Capture Project],0) AS Captured ,
                 ISNULL([Registered/IDP],0) AS Registered ,
                ISNULL([Initiated],0) AS Initiated
        FROM    ( SELECT    cs.StatusDesc ,
                            COUNT(1) tot
                  FROM      dbo.Plan_Project pp
                            INNER JOIN dbo.Const_Status cs ON pp.ProjectStatus = cs.Status_ID
                  WHERE     ISNULL(pp.IsDeleted, 0) = 0 AND pp.FinYear = @FYear
                  GROUP BY  cs.StatusDesc
                ) T PIVOT 
				(MIN(tot) FOR StatusDesc IN ( [Capture Project], [Initiated], [Registered/IDP] ) ) P;
    END;
                               
GO

