-- =============================================
-- Author:		 Chris Moodley
-- Create date: October 2025
-- Description:	 Return Project Details of Virement for Report
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectDetailsforVirementReportApprovalLevel_sp]
	-- Add the parameters for the stored procedure here
    @FinYear NVARCHAR(9) = '2017/2018',
    @Status NVARCHAR(15) = 'All' ,
	@FromProjectId INT = 0,
	@ToProjectId INT = 0,
    @VirementId INT = 0
AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;

		CREATE TABLE #Const_SCOA_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100), ScoaShortDesc NVARCHAR(400))
		CREATE INDEX idxItemScoaID ON #Const_SCOA_Structure(ScoaID)
		INSERT INTO #Const_SCOA_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode, ScoaShortDesc FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Function_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
		CREATE INDEX idxFunctionScoaID ON #Const_SCOA_Function_Structure(ScoaID)
		INSERT INTO #Const_SCOA_Function_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Costing_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
		CREATE INDEX idxCostingScoaID ON #Const_SCOA_Costing_Structure(ScoaID)
		INSERT INTO #Const_SCOA_Costing_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Const_SCOA_Costing_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Project_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
		CREATE INDEX idxProjectScoaID ON #Const_SCOA_Project_Structure(ScoaID)
		INSERT INTO #Const_SCOA_Project_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Regional_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
		CREATE INDEX idxRegionalScoaID ON #Const_SCOA_Regional_Structure(ScoaID)
		INSERT INTO #Const_SCOA_Regional_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @FinYear

		CREATE TABLE #Const_SCOA_Fund_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100), ScoaShortDesc NVARCHAR(800))
		CREATE INDEX idxFundScoaID ON #Const_SCOA_Fund_Structure(ScoaID)
		INSERT INTO #Const_SCOA_Fund_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode, ScoaShortDesc FROM Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @FinYear
	
        SELECT  ROW_NUMBER() OVER (ORDER BY Virement.VirementId, virement.DetailFor) AS ROWNumber,
		Virement.* ,
                VirementApprover.[1] FirstApprover ,
                VirementApprover.[2] SecondApprover ,
				VirementApprover.[3] ThirdApprover ,
				VirementApprover.[4] FourthApprover ,
				VirementApprover.[5] FifthApprover ,
				VirementApprover.[6] SixthApprover ,
				VirementApprover.[7] SeventhApprover ,
                VirementStatusResult.VirementStatus,
				VirementStatusResult.RejectReason
        FROM    -- Insert statements for procedure here
                ( SELECT    V.VirementId ,
                            V.FinYear ,
                            V.DateCaptured AS VirementDate ,
                            V.VirementReferenceNumber ,
                            'From' AS DetailFor ,
                            CAST(ISNULL(PrjFrom.ProjectCode, PrjFrom.Project_ID) AS VARCHAR(50)) + ' | ' + PrjFrom.ProjectName AS ProjectName ,
                            ISNULL(PrjFrom.ProjectCode, PrjFrom.Project_ID) AS ProjectCode ,
                            CASE V.FromCapitalOperation
                              WHEN 0 THEN 'Operational Expenditure'
                              WHEN 1 THEN 'Capital'
                              WHEN 2 THEN 'Operational Revenue'
                              ELSE ''
                            END AS CapitalOperation ,
                            ISNULL(CSPSFrom.ScoaDesc, '') AS SCOAProject ,
                            dbo.Plan_ProjectMunicipalClass_fxn(PrjFrom.Project_ID,
                                                              1) AS MunicipalClassification ,
                            ISNULL(CSFSFrom.ScoaDesc, '') AS SCOAFunction ,
                            ISNULL(CSFDSFrom.ScoaDesc, '') AS SCOAFund ,
                            ISNULL(CSRSFrom.ScoaDesc, '') AS SCOARegion ,
                            ISNULL(CSSFrom.ScoaDesc, '') AS SCOAItem ,
							ISNULL(CSCSFrom.ScoaDesc, '') AS SCOACosting ,
                            ISNULL(V.FromAvailableFund, 0) AS AvailableFund ,
                            ISNULL(V.FromVirementAmount, 0) AS VirementAmount ,
                            ISNULL(V.FromNewAvailableBudget, 0) AS NewAvailableBudget ,
                            ISNULL(V.ReasonForVirement, '') AS ReasonForVirement ,
							ISNULL(VBS.BudgetSplitId,0) AS BudgetSplitAvailable ,
							uDet.FirstName + ' ' + uDet.LastName AS Capturer,
							ISNULL(V.FromUkey, '') AS Ukey
                  FROM      dbo.Plan_Project PrjFrom
                            INNER JOIN dbo.Plan_Virements V ON V.FromProjectId = PrjFrom.Project_ID
							LEFT JOIN dbo.Plan_VirementBudgetSplit VBS ON VBS.VirementId = V.VirementId AND VBS.TransferFromTo ='From'
                            LEFT OUTER JOIN #Const_SCOA_Project_Structure CSPSFrom ON CSPSFrom.ScoaID = V.FromSCOAProjectID
                            LEFT OUTER JOIN #Const_SCOA_Function_Structure CSFSFrom ON CSFSFrom.ScoaID = V.FromSCOAFunctionId
                            LEFT OUTER JOIN #Const_SCOA_Fund_Structure CSFDSFrom ON CSFDSFrom.ScoaID = V.FromSCOAFundID
                            LEFT OUTER JOIN #Const_SCOA_Regional_Structure CSRSFrom ON CSRSFrom.ScoaID = V.FromSCOARegion
                            LEFT OUTER JOIN #Const_SCOA_Structure CSSFrom ON CSSFrom.ScoaID = V.FromSCOAItem
							LEFT OUTER JOIN #Const_SCOA_Costing_Structure CSCSFrom ON CSCSFrom.ScoaID = V.FromSCOACostingId
							INNER JOIN User_UserDetail uDet ON V.CapturerID = uDet.User_ID
                  WHERE     V.FinYear = @FinYear
							 AND ( CASE WHEN @VirementId = 0 THEN 0
							      ELSE V.VirementId
							 END = @VirementId )
							 AND
							 ( CASE WHEN @FromProjectId = 0 THEN 0
							      ELSE V.FromProjectId
							 END = @FromProjectId )
                            AND
							 ( CASE WHEN @ToProjectId = 0 THEN 0
							      ELSE V.ToProjectId
							 END = @ToProjectId )
                  UNION
                  SELECT    V.VirementId ,
                            V.FinYear ,
                            V.DateCaptured AS VirementDate ,
                            V.VirementReferenceNumber ,
                            'To' AS DetailFor ,
                            CAST(ISNULL(PrjTo.ProjectCode, PrjTo.Project_ID) AS VARCHAR(50)) + ' | ' + PrjTo.ProjectName AS ProjectNaem ,
                            ISNULL(PrjTo.ProjectCode, PrjTo.Project_ID) AS ProjectCode ,
                            CASE V.ToCapitalOperation
                              WHEN 0 THEN 'Operational Expenditure'
                              WHEN 1 THEN 'Capital'
                              WHEN 2 THEN 'Operational Revenue'
                              ELSE ''
                            END AS CapitalOperation ,
                            ISNULL(CSPSTo.ScoaDesc, '') AS SCOAProject ,
                            dbo.Plan_ProjectMunicipalClass_fxn(PrjTo.Project_ID,
                                                              1) AS MunicipalClassification ,
                            ISNULL(CSFSTo.ScoaDesc, '') AS SCOAFunction ,
                            ISNULL(CSFDSTo.ScoaDesc, '') AS SCOAFund ,
                            ISNULL(CSRSTo.ScoaDesc, '') AS SCOARegion ,
                            ISNULL(CSSTo.ScoaDesc, '') AS SCOAItem ,
							ISNULL(CSCSTo.ScoaDesc, '') AS SCOACosting ,
                            ISNULL(V.ToAvailableFund, 0) AS AvailableFund ,
                            ISNULL(V.ToVirementAmount, 0) AS VirementAmount ,
                            ISNULL(V.ToNewAvailableBudget, 0) AS NewAvailableBudget ,
                            ISNULL(V.ReasonForVirement, '') AS ReasonForVirement ,
							ISNULL(VBS.BudgetSplitId,0) AS BudgetSplitAvailable ,
							uDet.FirstName + ' ' + uDet.LastName AS Capturer,
							ISNULL(V.ToUkey, '') AS Ukey
                  FROM      dbo.Plan_Project PrjTo
                            INNER JOIN dbo.Plan_Virements V ON V.ToProjectId = PrjTo.Project_ID
							LEFT JOIN dbo.Plan_VirementBudgetSplit VBS ON VBS.VirementId = V.VirementId AND VBS.TransferFromTo ='To'
                            LEFT OUTER JOIN #Const_SCOA_Project_Structure CSPSFrom ON CSPSFrom.ScoaID = V.FromSCOAProjectID
                            LEFT OUTER JOIN #Const_SCOA_Project_Structure CSPSTo ON CSPSTo.ScoaID = V.ToSCOAProjectID
                            LEFT OUTER JOIN #Const_SCOA_Function_Structure CSFSFrom ON CSFSFrom.ScoaID = V.FromSCOAFunctionId
                            LEFT OUTER JOIN #Const_SCOA_Function_Structure CSFSTo ON CSFSTo.ScoaID = V.ToSCOAFunctionId
                            LEFT OUTER JOIN dbo.Const_Division CDFrom ON CDFrom.Division_ID = V.FromDivisionId
                            LEFT OUTER JOIN dbo.Const_Division CDTo ON CDTo.Division_ID = V.ToDivisionId
                            LEFT OUTER JOIN #Const_SCOA_Fund_Structure CSFDSFrom ON CSFDSFrom.ScoaID = V.FromSCOAFundID
                            LEFT OUTER JOIN #Const_SCOA_Fund_Structure CSFDSTo ON CSFDSTo.ScoaID = V.ToSCOAFundID
                            LEFT OUTER JOIN #Const_SCOA_Regional_Structure CSRSFrom ON CSRSFrom.ScoaID = V.FromSCOARegion
                            LEFT OUTER JOIN #Const_SCOA_Regional_Structure CSRSTo ON CSRSTo.ScoaID = V.ToSCOARegion
                            LEFT OUTER JOIN #Const_SCOA_Structure CSSFrom ON CSSFrom.ScoaID = V.FromSCOAItem
                            LEFT OUTER JOIN #Const_SCOA_Structure CSSTo ON CSSTo.ScoaID = V.ToSCOAItem
							LEFT OUTER JOIN #Const_SCOA_Costing_Structure CSCSFrom ON CSCSFrom.ScoaID = V.FromSCOACostingId
							LEFT OUTER JOIN #Const_SCOA_Costing_Structure CSCSTo ON CSCSTo.ScoaID = V.ToSCOACostingId
							INNER JOIN User_UserDetail uDet ON V.CapturerID = uDet.User_ID
                  WHERE     V.FinYear = @FinYear
                           AND ( CASE WHEN @VirementId = 0 THEN 0
							      ELSE V.VirementId
							 END = @VirementId )
							 AND
							 ( CASE WHEN @FromProjectId = 0 THEN 0
							      ELSE V.FromProjectId
							 END = @FromProjectId )
                            AND
							 ( CASE WHEN @ToProjectId = 0 THEN 0
							      ELSE V.ToProjectId
							 END = @ToProjectId )
                ) AS Virement
                INNER JOIN ( SELECT *
                             FROM   ( SELECT    PV.VirementId ,
                                                UUD.FirstName + ' '
                                                + UUD.LastName AS Approver ,
                                                ROW_NUMBER() OVER ( PARTITION BY PV.VirementId ORDER BY PVAU.VirementApprovalUserId ) AS ApproverNo
                                      FROM      dbo.Plan_Virements AS PV
                                                INNER JOIN dbo.Plan_VirementApprovalUsers PVAU ON PV.VirementId = PVAU.VirementId
                                                INNER JOIN dbo.User_UserDetail UUD ON UUD.User_ID = PVAU.UserId
                                      WHERE     PV.FinYear = @FinYear
                                                AND ( CASE WHEN @VirementId = 0 THEN 0
													      ELSE PV.VirementId
													 END = @VirementId )
                                    ) S PIVOT
								( MAX(Approver) FOR ApproverNo IN ( [1], [2], [3], [4], [5], [6], [7] ) ) piv
                           ) AS VirementApprover ON Virement.VirementId = VirementApprover.VirementId
                INNER JOIN ( SELECT PV.VirementId ,
                                    COUNT(PVAR.ApprovedBy) AS Approver ,
                                    'Approved' AS VirementStatus,
									'' AS RejectReason
                             FROM   dbo.Plan_Virements AS PV
                                    INNER JOIN dbo.Plan_VirementApprovalUsers PVAU ON PV.VirementId = PVAU.VirementId
                                    INNER JOIN dbo.Plan_VirementApprovalRejections PVAR ON PV.VirementId = PVAR.VirementId
                                                              AND PVAU.UserId = PVAR.ApprovedBy
                             WHERE  PV.FinYear = @FinYear AND ISNULL(PVAU.UserId,0) > 0
                                    AND ( CASE WHEN @VirementId = 0 THEN 0
													      ELSE PV.VirementId
													 END = @VirementId )
                             GROUP BY PV.VirementId
                             HAVING COUNT(PVAR.ApprovedBy) = COUNT(PVAU.UserId)
                             UNION
                             SELECT PV.VirementId ,
                                    COUNT(PVAR.RejectedBy) AS Approver ,
                                    'Rejected' AS VirementStatus,
									PVAR.RejectReason AS RejectReason
                             FROM   dbo.Plan_Virements AS PV
                                    INNER JOIN dbo.Plan_VirementApprovalUsers PVAU ON PV.VirementId = PVAU.VirementId
                                    INNER JOIN dbo.Plan_VirementApprovalRejections PVAR ON PV.VirementId = PVAR.VirementId
                                                              AND PVAU.UserId = PVAR.RejectedBy
                             WHERE  PV.FinYear = @FinYear
                                    AND ( CASE WHEN @VirementId = 0 THEN 0
													      ELSE PV.VirementId
													 END = @VirementId )
                             GROUP BY PV.VirementId,PVAR.RejectReason
                             HAVING ( COUNT(PVAR.RejectedBy) >= 1 )
                             UNION
                             SELECT  DISTINCT
                                    PV.VirementId ,
                                    0 AS Approver ,
                                    'Pending' AS VirementStatus,
									'' AS RejectReason
                             FROM   dbo.Plan_Virements AS PV
                                    INNER JOIN dbo.Plan_VirementApprovalUsers PVAU ON PV.VirementId = PVAU.VirementId
                                    LEFT OUTER JOIN dbo.Plan_VirementApprovalRejections PVAR ON PV.VirementId = PVAR.VirementId
                                                              AND PVAU.UserId = PVAR.ApprovedBy
                                    LEFT OUTER JOIN dbo.Plan_VirementApprovalRejections PVAR1 ON PV.VirementId = PVAR1.VirementId
                                                              AND PVAU.UserId = PVAR1.RejectedBy
                             WHERE  PVAR.ApprovedBy IS NULL
                                    AND PVAR1.RejectedBy IS NULL
                                    AND PV.FinYear = @FinYear AND ISNULL(PVAU.UserId,0) > 0
                                     AND ( CASE WHEN @VirementId = 0 THEN 0
													      ELSE PV.VirementId
													 END = @VirementId )
                                    AND PV.VirementId NOT IN (
                                    SELECT DISTINCT
                                            VirementId
                                    FROM    dbo.Plan_VirementApprovalRejections
                                    WHERE   VirementId = PV.VirementId
                                            AND IsRejected = 1 )
                           ) AS VirementStatusResult ON VirementStatusResult.VirementId = Virement.VirementId
                                                        AND VirementStatusResult.VirementId = VirementApprover.VirementId
        WHERE   ( VirementStatusResult.VirementStatus = @Status
                  OR @Status = 'All'
                );
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectDivisions_sp]    Script Date: 2026/03/10 7:23:37 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 18/03/2016
-- Description:	Get project Division details by project id, DivisionID
-- Used in : ProjectRegister Screen
--Reference from: Const_DepartmentDivision_sp Stored procedure to get division details
-- SNagpal 26-07-2016: Increase datatype lenght of Division code from varchar(10) - varchar (50)
-- SNagpal 03-03-2017: Change the Display Format of MunicipalClassification & MunicipalClassDesc & Add ParentDesc to MunicipalClassDesc
-- Plan_GetProjectDivisions_sp 0,0,0,'2018/2019'
-- SNagpal 04-03-2017: Add ISNULL(DivisionParentID,0) = 0 in CTE
-- SNagpal 06-03-2017: Add function Plan_DivisionDescDirectorate_fxn
-- SNagpal 01-03-2017: Add Parameter @UserId to get Division based upon UserId
-- Chirag Patel 27-07-2017: Optimize the Querry #76103
-- SNagpal 14-12-2018: #61596 Add FinYear Parameter & add conditions accordingly
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectDivisions_sp]
    @ProjectID INT ,
    @DivisionID INT ,
    @UserId INT,
	@FinYear VARCHAR(9)
AS
    BEGIN
        SET FMTONLY OFF;
        CREATE TABLE #temp2
            (
              TID INT IDENTITY(1, 1) ,
              DivisionParentID INT ,
              Division_ID INT ,
              DivisionDesc NVARCHAR(200) COLLATE Latin1_General_CI_AS ,
              DivisionCode NVARCHAR(50) COLLATE Latin1_General_CI_AS ,
              DepartmentID INT ,
              DivEnabled BIT ,
              DeptEnabled BIT
            );

DECLARE @StartDate datetime = null, @UntilDate datetime = NULL
		SET @StartDate = cast(LEFT(@FinYear, 4) + '-07-01 00:00:00' as datetime)
		SET @UntilDate = cast(RIGHT(@FinYear, 4) + '-06-30 00:00:00' as datetime)
		 DECLARE @tblFilteredDivision TABLE
                (
                  DivisionParentId INT,
				  Division_ID INT
                );
	--Recursive code found on net
        WITH    DeptDivGroup ( DivisionParentID, Division_ID, DivisionDesc, DivisionCode, DepartmentID )
                  AS (
	-- Anchor member definition
                       SELECT   e.DivisionParentID ,
                                e.Division_ID ,
                                e.DivisionDesc ,
                                e.DivisionCode ,
                                e.DepartmentID
                       FROM     dbo.Const_Division AS e
                       WHERE    ISNULL(DivisionParentID, 0) = 0
                       UNION ALL
	-- Recursive member definition
                       SELECT   e.DivisionParentID ,
                                e.Division_ID ,
                                e.DivisionDesc ,
                                e.DivisionCode ,
                                e.DepartmentID
                       FROM     dbo.Const_Division AS e
                                INNER JOIN DeptDivGroup AS d ON e.DivisionParentID = d.Division_ID
                     )
            INSERT  INTO #temp2
                    ( DivisionParentID ,
                      Division_ID ,
                      DivisionDesc ,
                      DivisionCode ,
                      DepartmentID
                    )
                    SELECT  DivisionParentID ,
                            Division_ID ,
                            DivisionDesc ,
                            DivisionCode ,
                            DepartmentID
                    FROM    DeptDivGroup;

	
        SELECT  Division_ID ,
                ISNULL(' ( '
                       + dbo.Plan_DivisionDescDirectorate_fxn(Division_ID)
                       + ' )', '') AS MunicipalClassDesc
        INTO    #Temp3
        FROM    ( SELECT DISTINCT
                            Division_ID
                  FROM      #temp2
                ) A;

				/*Added by Sahil for US 61596*/
				 INSERT INTO @tblFilteredDivision (DivisionParentId, Division_ID)
					 SELECT cd.DivisionParentID, cd.Division_ID  FROM   [Const_DivisionHistory] as [CDH] with(nolock)
						INNER JOIN [Const_Division] as [CD] with(nolock) on [CD].[Division_ID] = [CDH].[DivisionID] and [CD].[Enabled] = 1
                        INNER JOIN Const_Department cdp ON cd.DepartmentID = cdp.Department_ID
						INNER JOIN [Const_DepartmentHistory] as [CDPH] with(nolock) on [CDP].[Department_ID] = [CDPH].[DepartmentID]
                WHERE   cdp.Enabled = 1 AND cd.Enabled = 1
						AND [CDH].[StartDate] <= @UntilDate and [CDH].[EndDate] >= @StartDate
						AND [CDPH].[StartDate] <= @UntilDate and [CDPH].[EndDate] >= @StartDate
				/*Added by Sahil for US 61596*/
        SELECT DISTINCT
                pd.ProjectDivision_ID ,
                pd.ProjectID ,
                pd.DivisionID ,
                ( DivisionDesc + ' / ' + DivisionCode ) AS MunicipalClassification ,
                ( DivisionCode + ' / ' + DivisionDesc + M.MunicipalClassDesc ) AS MunicipalClassDesc ,
                rs.DivisionDesc ,
                rs.DivisionCode ,
                rs.DepartmentID
        FROM    #temp2 rs
				INNER JOIN @tblFilteredDivision td ON (td.Division_ID = rs.Division_ID OR td.DivisionParentId = rs.Division_ID)
                INNER JOIN dbo.Plan_ProjectDivisions pd ON pd.DivisionID = rs.Division_ID
                INNER JOIN #Temp3 M ON pd.DivisionID = M.Division_ID
                LEFT JOIN dbo.User_UserDivisions uud ON uud.DivisionID = pd.DivisionID
                                                        AND ( @UserId = 0
                                                              OR uud.UserID = @UserId
                                                            )
        WHERE   ( ( @ProjectID = 0
                    OR pd.ProjectID = @ProjectID
                  )
                  AND ( @DivisionID = 0
                        OR pd.DivisionID = @DivisionID
                      )
                );
        
        DROP TABLE #temp2;
        DROP TABLE #Temp3;


	 
    END;


GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectforAdjustmentProjectApproval_sp]    Script Date: 2026/03/10 7:23:37 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Sahil Nagpal
-- Create date: 2017-12-21
-- Description:	Get Project for Adjustment Approval
-- Call SP: Plan_GetProjectforAdjustmentProjectApproval_sp '',4770,'2016/2017',385
-- SNagpal: Add Capture Project in Where condition
-- 05-Feb-18 SNagpal: #67262 Remove Status Desc 'Initiated/Adjusted', 'Capture Project' from Where Conditions
-- 22-Feb-18 SNagpal: Add ProjectId Parameter
-- 13 Aug 2020 CMoodley: 4727 - Standardise formatting for project name
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectforAdjustmentProjectApproval_sp]
	-- Add the parameters for the stored procedure here
    @FinYear NVARCHAR(9) = '' ,
    @UserId INT ,
	@UserFinYear NVARCHAR(10) ,
	@ProjecId INT
AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;

		DECLARE @AdjustmentVersionId INT, @AdjustmentFundingVersionId INT;

		SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion WHERE VersionName 
		LIKE @UserFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

    -- Insert statements for procedure here
        SELECT  pap.AdjustmentProject_ID,
				CAST( COALESCE(pap.ProjectCode,pap.ReferenceProject_ID,pap.AdjustmentProject_ID) AS VARCHAR(50)) + ' | ' + pap.AdjustmentProjectName AS AdjustmentProjectName,
				pap.FinYear,
				pabv.VersionName
				FROM    dbo.Plan_AdjustmentProject pap
				INNER JOIN dbo.Plan_AdjustmentBudgetVersion pabv ON pabv.AdjustmentBudgetVersion_ID = pap.AdjustmentVersionId
                INNER JOIN dbo.Plan_AdjustmentProjectRecommendUsers PAPRU ON PAPRU.AdjustmentProjectId = pap.AdjustmentProject_ID
                LEFT OUTER JOIN dbo.Plan_AdjustmentProjectRecommendation PAPR ON PAPR.AdjustmentProjectId = pap.AdjustmentProject_ID
                                                              AND ( PAPR.RejectedBy = @UserId
                                                              OR PAPR.RecommendBy = @UserId
              )
        WHERE   
		 ( CASE WHEN @ProjecId = 0 THEN 0
                       ELSE pap.AdjustmentProject_ID
                  END = @ProjecId )
				  AND
				( @FinYear = '' OR pap.FinYear = @FinYear)
                AND PAPRU.UserId = @UserId
                AND PAPR.AdjustmentProjectId IS NULL AND ISNULL(pap.ProjectStatus,0) IN (
				SELECT Status_ID FROM dbo.Const_Status WHERE UsedBy='ProjectRegister' AND 
				(StatusDesc IN ('Registered/IDP')
				OR Status_ID IN (23)))
				AND pap.AdjustmentVersionId = @AdjustmentVersionId
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectforVirementApproval_sp]    Script Date: 2026/03/10 7:23:37 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 2016-04-13
-- Description:	Get Project for Virement Approval
-- Call SP: Plan_GetProjectforVirementApproval_sp '2025/2026',0,204
-- 2016-04-14 by JP: Add Virement From-To Amount in List, Set each From-To columns value in case of Null Value
-- 2016-04-14 by JP: Add Condition to Remove virement if an employee has approved virement
-- 2016-04-16 by JP: Update Condition to get Pending Virement for user
-- 2016-04-22 by SN: Plan_VirementApprovalEmployees table is renamed to Plan_VirementApprovalUsers, And EmployeeId => UserId
-- 2017-01-04 by SNagpal: Add two fields V.IsNewItemAdded, V.UploadedVirementDoc
-- 2017-03-06 by SNagpal: Add VirementStatus
-- 2018-01-17 by SNagpal: Add Missing ProjectID condition
-- SNagpal 20-02-2019 : 84009, Get SCOA Segments based upon FinYear
-- OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- 13 Aug 2020 CMoodley: 4727 - Standardise formatting for project name
-- 11 Sep 2025 CMoodley: 122522 - Return Ukey
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectforVirementApproval_sp] 
	-- Add the parameters for the stored procedure here
    @FinYear NVARCHAR(9) = '' ,
    @FromProjectId INT = 0 ,
    @UserId INT 
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
    SET NOCOUNT ON;

	DECLARE @StatusId INT;

	SELECT @StatusId = Status_ID FROM dbo.Const_Status WHERE UsedBy='Virement' AND StatusDesc='Capture Virement'

	SELECT ScoaID,BreakDownAllowed,NTScoaID,ScoaDesc INTO #projectTable FROM dbo.Const_SCOA_Project_Structure_ByYear(@FinYear)
	SELECT ScoaID,BreakDownAllowed,NTScoaID,ScoaDesc  INTO #functionTable FROM Const_SCOA_Function_Structure_ByYear(@FinYear)
	SELECT ScoaID,BreakDownAllowed,NTScoaID,ScoaCode,ScoaDesc INTO #itemTable FROM dbo.Const_SCOA_Structure_ByYear(@FinYear)
	SELECT ScoaID,BreakDownAllowed,NTScoaID,ScoaDesc INTO #fundsTable FROM dbo.Const_SCOA_Funds_Structure_ByYear(@FinYear)
	SELECT ScoaID,BreakDownAllowed,NTScoaID,ScoaDesc INTO #regionalTable FROM dbo.Const_SCOA_Regional_Structure_ByYear(@FinYear)
		
    SELECT  V.VirementId ,
                CAST(ISNULL(PrjFrom.ProjectCode, PrjFrom.Project_ID) AS VARCHAR(50)) + ' | ' + PrjFrom.ProjectName AS FromProject ,
                CAST(ISNULL(PrjTo.ProjectCode, PrjTo.Project_ID) AS VARCHAR(50)) + ' | ' + PrjTo.ProjectName AS ToProject ,
                ISNULL(CSPSFrom.ScoaDesc,'') AS FromSCOAProject ,
                ISNULL(CSPSTo.ScoaDesc,'') AS ToSCOAProject ,
                ISNULL(CSFSFrom.ScoaDesc,'') AS FromSCOAFunction ,
                ISNULL(CSFSTo.ScoaDesc,'') AS ToSCOAFunction ,
                ISNULL(CDFrom.DivisionDesc,'') AS FromDivision ,
                ISNULL(CDTo.DivisionDesc,'') AS ToDivision ,
                ISNULL(CSFDSFrom.ScoaDesc,'') AS FromSCOAFund ,
                ISNULL(CSFDSTo.ScoaDesc,'') AS ToSCOAFund ,
                ISNULL(CSRSFrom.ScoaDesc,'') AS FromSCOARegion ,
                ISNULL(CSRSTo.ScoaDesc,'') AS ToSCOARegion ,
                ISNULL(CSSFrom.ScoaDesc,'') AS FromSCOAItem ,
                ISNULL(CSSTo.ScoaDesc,'') AS ToSCOAItem,
				ISNULL(V.FromVirementAmount,0) AS FromVirementAmount,
				ISNULL(V.ToVirementAmount,0) AS ToVirementAmount,
				V.IsNewItemAdded, V.UploadedVirementDoc,
				ISNULL(V.FromUkey, '') AS FromUkey,
				ISNULL(V.ToUkey, '') AS ToUkey
        FROM    dbo.Plan_Project PrjFrom
                INNER JOIN dbo.Plan_Virements V ON V.FromProjectId = PrjFrom.Project_ID
                LEFT OUTER JOIN Plan_Project PrjTo ON V.ToProjectId = PrjTo.Project_ID
                LEFT OUTER JOIN #projectTable CSPSFrom ON CSPSFrom.ScoaID = V.FromScoaProjectId
                LEFT OUTER JOIN #projectTable CSPSTo ON CSPSTo.ScoaID = V.ToScoaProjectId
                LEFT OUTER JOIN #functionTable CSFSFrom ON CSFSFrom.ScoaID = V.FromScoaFunctionId
                LEFT OUTER JOIN #functionTable CSFSTo ON CSFSTo.ScoaID = V.ToScoaFunctionId
                LEFT OUTER JOIN dbo.Const_Division CDFrom ON CDFrom.Division_ID = V.FromDivisionId
                LEFT OUTER JOIN dbo.Const_Division CDTo ON CDTo.Division_ID = V.ToDivisionId
                LEFT OUTER JOIN #fundsTable CSFDSFrom ON CSFDSFrom.ScoaID = V.FromSCOAFundID
                LEFT OUTER JOIN #fundsTable CSFDSTo ON CSFDSTo.ScoaID = V.ToSCOAFundID
                LEFT OUTER JOIN #regionalTable CSRSFrom ON CSRSFrom.ScoaID = V.FromSCOARegion
                LEFT OUTER JOIN #regionalTable CSRSTo ON CSRSTo.ScoaID = V.ToSCOARegion
                LEFT OUTER JOIN #itemTable CSSFrom ON CSSFrom.ScoaID = V.FromSCOAItem
                LEFT OUTER JOIN #itemTable CSSTo ON CSSTo.ScoaID = V.ToSCOAItem
                INNER JOIN dbo.Plan_VirementApprovalUsers PVAE ON PVAE.VirementId = V.VirementId
                LEFT OUTER JOIN dbo.Plan_VirementApprovalRejections PVAR ON PVAR.VirementId = V.VirementId 
				AND ( PVAR.RejectedBy = @UserId OR PVAR.ApprovedBy = @UserId )
        WHERE   (@FinYear = '' OR V.FinYear = @FinYear )
                AND PVAE.UserId = @UserId 
                AND PVAR.VirementId IS NULL AND ISNULL(V.VirementStatus,0) <> @StatusId  
				AND
				(( CASE WHEN @FromProjectId  = 0 THEN 0 ELSE V.FromProjectId END = @FromProjectId )
				OR
				(CASE WHEN @FromProjectId  = 0 THEN 0 ELSE V.ToProjectId END = @FromProjectId ))

    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectFunctions_sp]    Script Date: 2026/03/10 7:23:37 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 24/12/2015
-- Description:	Get project Function details by project id, ScoaFunctionID
-- Used in : ProjectCapture
-- SNagpal 18-02-2019 : 84009, Get SCOA Segments based upon FinYear
-- Plan_GetProjectFunctions_sp 0,353,'2018/2019'
-- OShiri 24-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- CMoodley 16-01-2020 : 26850, Include financial year in where clause
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectFunctions_sp]
	@ProjectID int,
	@ScoaFunctionID int,
	@FinYear NVARCHAR(9)
AS
BEGIN

	SET NOCOUNT ON;

	SELECT pf.ProjectFunction_ID 
	, pf.ProjectID
	, pf.ScoaFunctionID
	, rs.ScoaDesc
	, rs.ScoaCode
	, rs.ScoaShortDesc
	FROM Plan_ProjectFunctions pf
	INNER JOIN dbo.Const_SCOA_Function_Structure_ByYear(@FinYear) rs ON rs.ScoaID=pf.ScoaFunctionID
	INNER JOIN dbo.Plan_Project pp ON pf.ProjectID = pp.Project_ID
	WHERE (pf.ProjectID= @ProjectID  OR @ProjectID =0)
	AND (pf.ScoaFunctionID=@ScoaFunctionID  OR  @ScoaFunctionID= 0)
	AND FinYear = CASE WHEN @FinYear IS NULL OR @FinYear = '' OR @FinYear = '0' THEN FinYear ELSE @FinYear END

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectFundAllocAmtByScoaFundIDYear_sp]    Script Date: 2026/03/10 7:23:37 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- =============================================
-- Author:	Raindree Chetty
-- Create date: 23/03/2015
-- Description:	Get project funds by project id and fin year
-- 23/02/2016  by RC :Exclude deleted projects (32186)
-- 22/03/2016 by JP: replace p.IsDelete with ISNULL(p.IsDeleted,0)
-- Plan_GetProjectFundAllocAmtByScoaFundIDYear_sp 4011,'2015/2016'
-- 07/02/2017 SNagpal: Add Current FinYear as parameter
-- 24/03/2021 By CM: 61107 - Only include CapitalOperation projects in 0, 1, 4
-- 20/05/2021 By CM: 64327 - Only include CapitalOperation projects in 0, 1, 4
-- 22/04/2023 By CM: 99648 - Return allocated fund amount as per Plan_ProjectItem table
-- =============================================
CREATE   PROCEDURE [dbo].[Plan_GetProjectFundAllocAmtByScoaFundIDYear_sp] 
	@ScoaFundID int,
	@FinYear nvarchar(9),
	@CurrFinYear nvarchar(9)
AS
BEGIN

	DECLARE @CurFinYearAsNumber INT = CAST(SUBSTRING(@CurrFinYear, 1, 4) AS INT);
	DECLARE @FinYearAsNumber INT = CAST(SUBSTRING(@FinYear, 1, 4) AS INT);

	SELECT 
		ppi.ScoaFundID, 
		FundAllocAmt = CASE WHEN @FinYearAsNumber = @CurFinYearAsNumber THEN SUM(ISNULL(BudgetAmount, 0))
						ELSE CASE WHEN @FinYearAsNumber = @CurFinYearAsNumber + 1 THEN SUM(ISNULL(BudgetAmountCurP1, 0))
							ELSE CASE WHEN @FinYearAsNumber = @CurFinYearAsNumber + 2 THEN SUM(ISNULL(BudgetAmountCurP2, 0))
							END
						END
					END 
	FROM 
		Plan_ProjectItem ppi
		INNER JOIN Plan_Project p on ppi.ProjectID = p.Project_ID
	WHERE 
		ppi.FinYear = @CurrFinYear 
		AND ppi.ScoaFundID = @ScoaFundID
		AND CapitalOperation IN (0, 1, 4)
		AND ISNULL(p.IsDeleted,0)<>1
	GROUP BY 
		ppi.ScoaFundID

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectFundAllocAmtByScoaFundIDYearForAdjustment_sp]    Script Date: 2026/03/10 7:23:37 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Nirav Parikh
-- Create date: 14/11/2017
-- Description:	Get project funds by project id and fin year for Adjustment
-- 27/03/2017 Rchetty : Must use Adjustment tables not project tables
-- 11/04/2018 : 70718 Add @AdjustmentVersionId conditions
-- 22/04/2023 By CM: 99648 - Return allocated fund amount as per Plan_AdjustmentProjectItem table
-- =============================================
CREATE   PROCEDURE [dbo].[Plan_GetProjectFundAllocAmtByScoaFundIDYearForAdjustment_sp] 
    @ScoaFundID INT,
    @FinYear NVARCHAR(9),
    @CurrFinYear NVARCHAR(9)
AS
BEGIN

	DECLARE @AdjustmentVersionId INT;
	DECLARE @CurFinYearAsNumber INT = CAST(SUBSTRING(@CurrFinYear, 1, 4) AS INT);
	DECLARE @FinYearAsNumber INT = CAST(SUBSTRING(@FinYear, 1, 4) AS INT);

	SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion papv
	INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentVersionId = papv.AdjustmentBudgetVersion_ID
	WHERE VersionName LIKE @CurrFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

	SELECT 
		papi.ScoaFundID,
        FundAllocAmt = CASE WHEN @FinYearAsNumber = @CurFinYearAsNumber THEN SUM(ISNULL(AdjustedBudgetAmount, BudgetAmount))
						ELSE CASE WHEN @FinYearAsNumber = @CurFinYearAsNumber + 1 THEN SUM(ISNULL(AdjustedBudgetAmountCurP1, BudgetAmountCurP1))
							ELSE CASE WHEN @FinYearAsNumber = @CurFinYearAsNumber + 2 THEN SUM(ISNULL(AdjustedBudgetAmountCurP2, BudgetAmountCurP2))
							END
						END
					END
    FROM 
		Plan_AdjustmentProjectItem papi
        INNER JOIN Plan_AdjustmentProject p ON papi.AdjustmentProjectID = p.AdjustmentProject_ID
    WHERE 
		papi.FinYear = @CurrFinYear
        AND papi.ScoaFundID = @ScoaFundID
        AND ISNULL(p.IsDeleted, 0) <> 1 AND p.AdjustmentVersionId = @AdjustmentVersionId
        AND CapitalOperation IN (0, 1, 4)
    GROUP BY 
		papi.ScoaFundID;

END;
GO

