-- =============================================
-- Author:	Raindree Chetty
-- Create date: 27 November 2014
-- Description:	Get project funds by project id and fin year
-- Calls: execute Plan_GetProjectFundByProjectIDYear_sp 58, '2014/2015'
-- 06/05/2015 By RC: Added ScoaID and SCOA Desc for project items funding
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectFundByProjectIDYear_sp]
	@ProjectID int,
	@FinYear nvarchar(9)
AS
BEGIN
SELECT 
 p.Project_ID
 ,p.ProjectName
 ,fy.FinYear
 ,SUM(fy.YearFundAmount) AS FundYearAmt 
 ,SCOAID = s.ScoaID
 ,ScoaDesc = s.ScoaShortDesc + ' - ' + s.ScoaCode
FROM Plan_Project p
INNER JOIN Plan_ProjectFund f ON p.Project_ID=f.ProjectID
INNER JOIN Plan_ProjectFundYear fy ON f.ProjectFund_ID=fy.ProjectFundID
INNER JOIN Const_SCOA_Funds_Structure s ON f.ScoaFundID=s.ScoaID
WHERE p.Project_ID=@ProjectID
AND (fy.FinYear=@FinYear)
GROUP BY p.Project_ID,p.ProjectName,fy.FinYear,s.ScoaID,s.ScoaShortDesc,s.ScoaCode

END

GO

