-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 27/11/2017
-- Description:	Get AdjustmentProject funds by AdjustmentProject id.
-- Plan_GetProjectFundsByAdjustmentProjectID_sp 0,0,'2016/2017'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectFundsByAdjustmentProjectID_sp]
	@AdjustmentProjectID INT,
	@ScoaFundID int,
	@UserFinYear NVARCHAR(10) 
AS
BEGIN
	SET NOCOUNT ON

	DECLARE @AdjustmentVersionId INT;

	SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion WHERE VersionName 
	LIKE @UserFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC
SELECT 
 AdjustmentProjectFund_ID
 ,AdjustmentProjectID
 ,ScoaFundID
 ,sp.ScoaCode as AdjustmentProjectCode
 ,sp.ScoaShortDesc as AdjustmentProjectName
 ,sf.ScoaCode as FundCode
 ,sf.ScoaShortDesc as FundDesc
 ,sf.ScoaDesc AS FundFullDesc
 ,pf.FundAmount,
 (SELECT dbo.ConcateString('Plan_AdjustmentProjectFundYear',pf.AdjustmentProjectFund_ID))  AS FUNDYearAmt
FROM Plan_AdjustmentProject p
INNER JOIN Plan_AdjustmentProjectFund pf ON p.AdjustmentProject_ID=pf.AdjustmentProjectID
INNER JOIN Const_SCOA_Funds_Structure sf ON pf.ScoaFundID=sf.ScoaID
INNER JOIN Const_SCOA_Project_Structure sp ON p.ScoaProjectID=sp.ScoaID
WHERE 
( CASE WHEN @AdjustmentProjectID = 0 THEN 0
                       ELSE pf.AdjustmentProjectID
                  END = @AdjustmentProjectID )
				  AND ( CASE WHEN @ScoaFundID = 0 THEN 0
                       ELSE sf.ScoaID
                  END = @ScoaFundID ) AND p.AdjustmentVersionId = @AdjustmentVersionId
END

GO

