-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 27/11/2017
-- Description:	Get AdjustmentProject funds by AdjustmentProject id. Used in AdjustmentProject Capture and AdjustmentProjectItems screens
-- Calls: Execute Plan_GetProjectFundsByAdjustmentProjectIDFinYear_sp 25941,'2018/2019','2018/2019'
--- NP - 2 FEB 2018 - 67202 SCOA Funding doesn’t have the “Add” button to add the Non Funding Transaction - Inner Join Replace with Left Join fro Plan_AdjustmentProjectFundYear fy1
-- SNagpal 19-02-2019 : 84009, Get SCOA Segments based upon FinYear, 
-- OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- SNagpal 19-06-2019 : 90498, Fix issue of Const_SCOA_Funds_Structure_ByYear
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectFundsByAdjustmentProjectIDFinYear_sp]
    @AdjustmentProjectID INT,
    @FinYear NVARCHAR(9),
    @UserFinYear NVARCHAR(10)
AS
BEGIN
SET NOCOUNT ON;
SET FMTONLY OFF;

    SET NOCOUNT ON;
    DECLARE @FinYearP1 NVARCHAR(9),
            @FinYearP2 NVARCHAR(9),
            @yearp1 INT,
            @yearp2 INT,
            @yearp3 INT;

    SELECT @yearp1 = CAST(SUBSTRING(@FinYear, 6, 4) AS INT);
    SELECT @yearp2 = @yearp1 + 1;
    SELECT @yearp3 = @yearp1 + 2;
    SELECT @FinYearP1 = CONVERT(VARCHAR(4), @yearp1) + '/' + CONVERT(VARCHAR(4), @yearp2);
    SELECT @FinYearP2 = CONVERT(VARCHAR(4), @yearp2) + '/' + CONVERT(VARCHAR(4), @yearp3);


    DECLARE @AdjustmentVersionId INT;

    SELECT TOP 1
        @AdjustmentVersionId = AdjustmentBudgetVersion_ID
    FROM Plan_AdjustmentBudgetVersion
    WHERE VersionName LIKE @UserFinYear + '%'
    ORDER BY AdjustmentBudgetVersion_ID DESC;

SELECT AdjustmentProjectFund_ID,
           pf.ReferenceProjectFundID,
           AdjustmentProjectID,
           ScoaFundID,
           sp.ScoaCode AS ProjectCode,
           sp.ScoaShortDesc AS ProjectName,
           sf.ScoaCode AS FundCode,
           sf.ScoaShortDesc AS FundDesc,
           sf.ScoaDesc AS FundFullDesc,
           pf.FundAmount,
           ISNULL(fy1.YearFundAmount, 0) AS Year1FundAmt,
           ISNULL(fy2.YearFundAmount, 0) AS Year2FundAmt,
           ISNULL(fy3.YearFundAmount, 0) AS Year3FundAmt
FROM Plan_AdjustmentProject p
	INNER JOIN Plan_AdjustmentProjectFund pf ON p.AdjustmentProject_ID = pf.AdjustmentProjectID
	INNER JOIN dbo.Const_SCOA_Funds_Structure_ByYear(@FinYear) sf ON pf.ScoaFundID = sf.ScoaID
	INNER JOIN dbo.Const_SCOA_Project_Structure_ByYear(@FinYear) sp ON p.ScoaProjectID = sp.ScoaID
	LEFT JOIN Plan_AdjustmentProjectFundYear fy1 ON pf.AdjustmentProjectFund_ID = fy1.AdjustmentProjectFundID AND fy1.FinYear =  @FinYear 
	LEFT JOIN Plan_AdjustmentProjectFundYear fy2 ON pf.AdjustmentProjectFund_ID = fy2.AdjustmentProjectFundID AND fy2.FinYear =  @FinYearP1
	LEFT JOIN Plan_AdjustmentProjectFundYear fy3 ON pf.AdjustmentProjectFund_ID = fy3.AdjustmentProjectFundID AND fy3.FinYear =  @FinYearP2
WHERE pf.AdjustmentProjectID = @AdjustmentProjectID  AND p.AdjustmentVersionId = @AdjustmentVersionId ;

END;
GO

