-- =============================================
-- Author:	Raindree Chetty
-- Create date: 11 February 2016
-- Description:	Get project funds by project id. Used in ProjectRegster and ProjectItems screens
-- Calls: Execute Plan_GetProjectFundsByProjectIDFinYear_sp 1050,'2018/2019'
-- 10-08-2017:60720 SNagpal: Add SCOADesc instead of sf.ScoaShortDesc
-- SNagpal 19-02-2019 : 84009, Get SCOA Segments based upon FinYear, 
-- OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectFundsByProjectIDFinYear_sp]
	@ProjectID int,
	@FinYear nvarchar(9)
AS
BEGIN
SET NOCOUNT ON;
SET FMTONLY OFF;
DECLARE 
	@FinYearP1 nvarchar(9),
	@FinYearP2 nvarchar(9),
	@yearp1 int,
	@yearp2 int,
	@yearp3 int

	SELECT @yearp1=CAST(SUBSTRING(@FinYear, 6,4)AS INT)
	SELECT @yearp2= @yearp1+1
	SELECT @yearp3= @yearp1+2
	SELECT @FinYearP1= CONVERT(varchar(4), @yearp1) +'/' + CONVERT(varchar(4), @yearp2)
	SELECT @FinYearP2= CONVERT(varchar(4), @yearp2) +'/' + CONVERT(varchar(4), @yearp3)

SELECT 
 ProjectFund_ID
 ,ProjectID
 ,ScoaFundID
 ,sp.ScoaCode as ProjectCode
 ,sp.ScoaShortDesc as ProjectName
 ,sf.ScoaCode as FundCode
 ,sf.ScoaShortDesc as FundDesc
 ,sf.ScoaDesc as FundFullDesc
 ,pf.FundAmount
 ,fy1.YearFundAmount as Year1FundAmt
 ,ISNULL(fy2.YearFundAmount ,0) as Year2FundAmt
 ,ISNULL(fy3.YearFundAmount ,0) as Year3FundAmt 
FROM Plan_Project p
INNER JOIN Plan_ProjectFund pf ON p.Project_ID=pf.ProjectID
INNER JOIN dbo.Const_SCOA_Funds_Structure_ByYear(@FinYear) sf ON pf.ScoaFundID=sf.ScoaID
INNER JOIN dbo.Const_SCOA_Project_Structure_ByYear(@FinYear) sp ON p.ScoaProjectID=sp.ScoaID
Inner JOIN Plan_ProjectFundYear fy1 ON pf.ProjectFund_ID=fy1.ProjectFundID and fy1.FinYear=@FinYear 
Left JOIN Plan_ProjectFundYear fy2 ON pf.ProjectFund_ID=fy2.ProjectFundID and fy2.FinYear= @FinYearP1  
Left JOIN Plan_ProjectFundYear fy3 ON pf.ProjectFund_ID=fy3.ProjectFundID and fy3.FinYear=@FinYearP2
WHERE pf.ProjectID=@ProjectID;


END
GO

