/****** Object:  StoredProcedure [dbo].[Plan_GetProjectInitialisationbyFilter_sp]    Script Date: 2026/03/10 7:23:38 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


/****************************************************
 * Author: Jaco Bosman								*
 * Create date: 26 November 2014					*
 * Description: Get all the outstading project		*
 *              initialisation by filter options	*
 ****************************************************/ 
CREATE PROCEDURE [dbo].[Plan_GetProjectInitialisationbyFilter_sp]
	@DepartmentID INT,
	@ProjectType INT,
	@FunderID INT

AS  
BEGIN

	DECLARE @ProjectsToKeep TABLE	( [Project_ID] INT )

	DECLARE @ProjectDetails TABLE
	(
		[Project_ID] INT,
		[ProjectName] NVARCHAR(500),
		[ProjectDesc] NVARCHAR(500),
		[DepartmentID] INT,
		[ProjectTypeID] INT
	)

	INSERT INTO @ProjectDetails
	SELECT	[Project_ID]
			,[ProjectName]
			,[ProjectDesc]
			,null
			,[ProjectTypeID]
	FROM [dbo].[Plan_Project]
	--Vincent Majatladi - Changed the FROM Clause to remove the DB name reference
	--FROM [FMS].[dbo].[Plan_Project]

	IF (@DepartmentID > 0)
	BEGIN
		DELETE FROM @ProjectDetails
		WHERE	DepartmentID <> @DepartmentID
			OR DepartmentID IS NULL
	END

	IF (@ProjectType > 0)
	BEGIN
		DELETE FROM @ProjectDetails
		WHERE	ProjectTypeID <> @ProjectType
			OR ProjectTypeID IS NULL
	END

	IF (@FunderID > 0)
	BEGIN
		INSERT INTO @ProjectsToKeep
		SELECT	P.ProjectID
		FROM	Plan_FundingSourceBudget_Detail F
		JOIN	Plan_ProjectFund P
			ON	P.ScoaFundID = F.ScoaID
		WHERE	F.FundingSourceID = @FunderID

		DELETE	@ProjectDetails
		WHERE	Project_ID NOT IN (SELECT Project_ID FROM @ProjectsToKeep)
	END

	SELECT	[Project_ID],
			[ProjectName],
			REPLACE(REPLACE(REPLACE(ProjectDesc,CHAR(10),' '),CHAR(13),' '),CHAR(09),' ') AS [ProjectDesc]
	FROM	@ProjectDetails

END
GO

