-- =============================================
-- Author:	Raindree Chetty
-- Create date: 12 February 2014
-- Description:	Get project item budgets by project id
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectItemBudgetByProjectID_sp] 
	@ProjectID int
AS
BEGIN
SELECT ppi.ProjectID
	, ppi.PlanProjectItem_ID
	, ppi.ProjectItemID
	, i.ItemDescription
	, ppi.FinYear
	, s.ScoaCode
	, s.ScoaShortDesc
	, BudgetAmount= SUM(m.UnitPrice)
FROM Plan_ProjectItem ppi 
	INNER JOIN Const_ProjectItem i ON ppi.ProjectItemID=i.ProjectItem_ID
	INNER JOIN Const_SCOA_Structure s ON ppi.SCOAItemID=s.ScoaID
	INNER JOIN Plan_ProjectItemMonth m ON ppi.PlanProjectItem_ID=m.PlanProjectItemID
WHERE ppi.ProjectID=@ProjectID
GROUP BY 
	ppi.ProjectID
	, ppi.PlanProjectItem_ID
	, ppi.ProjectItemID
	, i.ItemDescription
	, ppi.FinYear
	, s.ScoaCode
	, s.ScoaShortDesc
END

GO

