-- =============================================
-- Author:	Raindree Chetty
-- Create date: 24/03/2015
-- Description:	Get project item funds details by project id, ScoaFundID and fin year
-- SNagpal 19-02-2019 : 84009, Get SCOA Segments based upon FinYear, 
-- Plan_GetProjectItemFunds_sp 0,4787,'2018/2019'
-- SNagpal 19-02-2019 : 84009, Get SCOA Segments based upon FinYear, 
-- OShiri 24-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectItemFunds_sp]
	@ProjectID int,
	@ScoaFundID int,
	@FinYear nvarchar(9)
AS
BEGIN

SET NOCOUNT ON;
SET FMTONLY OFF;

	SELECT 
	pf.ProjectFund_ID, pf.ProjectID, pf.ScoaFundID, pf.FundAmount
	, pf.FundReference, pfy.FinYear, pfy.ProjectFundYear_ID, pfy.YearFundAmount	
	, ppi.SCOAItemID, ppi.ProjectItemID, p.ItemDescription, ss.ScoaCode
	, ss.ScoaShortDesc AS SCOAItemDesc, fs.ScoaCode AS SCOAFundCode, fs.ScoaShortDesc AS SCOAFundDesc
	FROM Plan_ProjectFund pf 
	INNER JOIN Plan_ProjectFundYear pfy on pf.ProjectFund_ID=pfy.ProjectFundID
	INNER JOIN Plan_ProjectItem ppi on pfy.ProjectFundYear_ID= ppi.ProjectFundYearID
	INNER JOIN Const_ProjectItem p ON p.ProjectItem_ID=ppi.ProjectItemID
	INNER JOIN dbo.Const_SCOA_Structure_ByYear(@FinYear) ss ON ss.ScoaID=ppi.SCOAItemID
	INNER JOIN dbo.Const_SCOA_Funds_Structure_ByYear(@FinYear) fs ON fs.ScoaID=pf.ScoaFundID
	WHERE 
		 (pf.ProjectID=@ProjectID  OR @ProjectID = 0)
		AND (pf.ScoaFundID=@ScoaFundID  OR @ScoaFundID= 0)
		AND (pfy.FinYear= @FinYear   OR  @FinYear   ='');
END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectItemID]    Script Date: 2026/03/10 7:23:38 AM ******/
SET ANSI_NULLS ON
GO

