GO

-- =============================================    
-- Author:  RC  
-- Create date: 11 November 2014
-- Description: Returns project Type Item search results    
-- 2018-08-22 Chirag Patel-- Finyear  Add--#77062
-- 2018-12-18 SNagpal: Add FinYear conditions in IF EXISTS conditions
-- 2020-08-03 CMoodley: 36983 - Return TOP 1 ProjectItem_ID if there are multiple entries of the same description
-- ============================================= 

CREATE PROCEDURE [dbo].[Plan_GetProjectItemID] 
    @ProjectItemDescription NVARCHAR(200) ,
    @CapturerID INT ,
    @ReturnProjectItemID INT OUTPUT ,
    @FinYear NVARCHAR(9) = NULL
AS
    BEGIN
        SET NOCOUNT ON;

        IF EXISTS ( SELECT  ProjectItem_ID
                    FROM    Const_ProjectItem
                    WHERE   ItemDescription = @ProjectItemDescription AND FinYear = @FinYear)
            BEGIN
                SELECT  @ReturnProjectItemID = ( SELECT TOP 1 ProjectItem_ID
                                                 FROM   Const_ProjectItem
                                                 WHERE  ItemDescription = @ProjectItemDescription AND FinYear = @FinYear
                                               );
            END;
        ELSE
            BEGIN
                INSERT  INTO [dbo].[Const_ProjectItem]
                        ( [ItemDescription] ,
                          [Enabled] ,
                          [DateCaptured] ,
                          [CapturerID] ,
                          FinYear
		                )
                VALUES  ( @ProjectItemDescription ,
                          1 ,
                          GETDATE() ,
                          @CapturerID ,
                          @FinYear
		                );

                SELECT  @ReturnProjectItemID = SCOPE_IDENTITY();
            END;
    END;
GO

