-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 27/11/2017
-- Description:	Get list of AdjustmentProject items based on AdjustmentProject id and finyear.  
-- Calls : Plan_GetProjectItemsByAdjustmentProjectID_sp 1393,'2025/2026',0,'2025/2026'
-- 05/02/2018 RChetty: Added IDP details TP 67252
-- 11-May-2018 SNagpal: Remove IsNull Condition from AdjustmentBudgetAmount for correct calculations
-- 18-02-2019: SNagpal: #84009, Get SCOA Segments based upon FinYear
-- SNagpal 24-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- CMoodley 02-12-2019: 25527 - Include multiyear concept to SCOA segments based upon financial year
-- SN 18-02-2023: #58285, Block Scoa item from being available for selection during procurement processes
-- CM 11-11-2025: #124586 - Return budget signs as per standard 
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectItemsByAdjustmentProjectID_sp]
	@AdjustmentProjectID int,
	@FinYear nvarchar(9),
	@AdjustmentProjectItemId INT = 0,
	@UserFinYear NVARCHAR(10)
AS
BEGIN

	DECLARE @AdjustmentVersionId INT;

	SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion WHERE VersionName 
	LIKE @UserFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

	DECLARE  @FinYearForSCOA NVARCHAR(9);

	SET @FinYearForSCOA = @FinYear;
	IF(@FinYearForSCOA IS NULL OR @FinYearForSCOA = '' OR @FinYearForSCOA = '0')
		BEGIN SELECT @FinYearForSCOA = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'ActiveFinYear' END;

	SELECT 	
		ppi.PlanAdjustmentProjectItem_ID, ppi.ReferencePlanProjectItem_ID, ppi.AdjustmentProjectID,ppi.ProjectItemID,ppi.FinYear,(SELECT dbo.Plan_AdjustmentProjectIDP_fxn(ppi.AdjustmentProjectID,0)) as IDP,ppi.SCOAItemID
		,ISNULL(ppi.ProjectFundYearID,0) AS AdjustmentProjectFundYearID
		,ppi.SCOAFundId as SCOAFundID, ppi.SCOAFunctionId,ppi.SCOARegionId, ppi.SCOACostingID, ppi.DivisionId, ppi.BudgetSplitID
		,ISNULL(i.ItemDescription,'') AS ItemDescription,s.ScoaShortDesc + ' ' + s.ScoaCode AS ScoaDesc , s.ScoaCode AS ScoaItemCode
		,sfs.ScoaShortDesc AS SCOAFundDesc,sfs.ScoaDesc AS SCOAFundFullDesc, sfus.ScoaDesc AS SCOAFunctionDesc ,srs.ScoaDesc AS SCOARegionDesc, scs.ScoaDesc AS SCOACostingDesc,  
		( cdep.DepartmentCode + '/' + cd.DivisionCode + ' ' + cdep.DepartmentDesc + ' / ' + cd.DivisionDesc ) AS MunicipalClassification,
		 STUFF((SELECT ',' + pt.Comment FROM dbo.Plan_AdjustmentTrackChanges pt WHERE pt.AdjustmentPlanProjectItem_ID = ppi.PlanAdjustmentProjectItem_ID FOR XML PATH('')),1,1,'') AS Comment
		,ppim1.UnitQuantity AS Month1Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim1.UnitPrice ELSE ppim1.UnitPrice END AS Month1Price
		,ppim2.UnitQuantity AS Month2Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim2.UnitPrice ELSE ppim2.UnitPrice END AS Month2Price
		,ppim3.UnitQuantity AS Month3Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim3.UnitPrice ELSE ppim3.UnitPrice END AS Month3Price
		,ppim4.UnitQuantity AS Month4Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim4.UnitPrice ELSE ppim4.UnitPrice END AS Month4Price
		,ppim5.UnitQuantity AS Month5Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim5.UnitPrice ELSE ppim5.UnitPrice END AS Month5Price
		,ppim6.UnitQuantity AS Month6Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim6.UnitPrice ELSE ppim6.UnitPrice END AS Month6Price
		,ppim7.UnitQuantity AS Month7Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim7.UnitPrice ELSE ppim7.UnitPrice END AS Month7Price
		,ppim8.UnitQuantity AS Month8Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim8.UnitPrice ELSE ppim8.UnitPrice END AS Month8Price
		,ppim9.UnitQuantity AS Month9Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim9.UnitPrice ELSE ppim9.UnitPrice END AS Month9Price
		,ppim10.UnitQuantity AS Month10Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim10.UnitPrice ELSE ppim10.UnitPrice END AS Month10Price
		,ppim11.UnitQuantity AS Month11Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim11.UnitPrice ELSE ppim11.UnitPrice END AS Month11Price
		,ppim12.UnitQuantity AS Month12Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim12.UnitPrice ELSE ppim12.UnitPrice END AS Month12Price
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim1.AdjustedUnitPrice ELSE ppim1.AdjustedUnitPrice END AS AdjustedMonth1Price
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim2.AdjustedUnitPrice ELSE ppim2.AdjustedUnitPrice END AS AdjustedMonth2Price
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim3.AdjustedUnitPrice ELSE ppim3.AdjustedUnitPrice END AS AdjustedMonth3Price
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim4.AdjustedUnitPrice ELSE ppim4.AdjustedUnitPrice END AS AdjustedMonth4Price
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim5.AdjustedUnitPrice ELSE ppim5.AdjustedUnitPrice END AS AdjustedMonth5Price
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim6.AdjustedUnitPrice ELSE ppim6.AdjustedUnitPrice END AS AdjustedMonth6Price
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim7.AdjustedUnitPrice ELSE ppim7.AdjustedUnitPrice END AS AdjustedMonth7Price
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim8.AdjustedUnitPrice ELSE ppim8.AdjustedUnitPrice END AS AdjustedMonth8Price
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim9.AdjustedUnitPrice ELSE ppim9.AdjustedUnitPrice END AS AdjustedMonth9Price
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim10.AdjustedUnitPrice ELSE ppim10.AdjustedUnitPrice END AS AdjustedMonth10Price
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim11.AdjustedUnitPrice ELSE ppim11.AdjustedUnitPrice END AS AdjustedMonth11Price
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim12.AdjustedUnitPrice ELSE ppim12.AdjustedUnitPrice END AS AdjustedMonth12Price
		,Quantity =1
		,PriceUnit=(ppim1.UnitPrice +ppim2.UnitPrice +ppim3.UnitPrice +ppim4.UnitPrice
					+ppim5.UnitPrice +ppim6.UnitPrice +ppim7.UnitPrice +ppim8.UnitPrice
					+ppim9.UnitPrice +ppim10.UnitPrice +ppim11.UnitPrice +ppim12.UnitPrice)
		,AdjustedPriceUnit=(ppim1.AdjustedUnitPrice +ppim2.AdjustedUnitPrice +ppim3.AdjustedUnitPrice +ppim4.AdjustedUnitPrice
					+ppim5.AdjustedUnitPrice +ppim6.AdjustedUnitPrice +ppim7.AdjustedUnitPrice +ppim8.AdjustedUnitPrice
					+ppim9.AdjustedUnitPrice +ppim10.AdjustedUnitPrice +ppim11.AdjustedUnitPrice +ppim12.AdjustedUnitPrice)
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppi.BudgetAmount ELSE ppi.BudgetAmount END AS BudgetAmount
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppi.BudgetAmountCurP1 ELSE ppi.BudgetAmountCurP1 END AS BudgetAmountCurP1
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppi.BudgetAmountCurP2 ELSE ppi.BudgetAmountCurP2 END AS BudgetAmountCurP2
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppi.AdjustedBudgetAmount ELSE ppi.AdjustedBudgetAmount END AS AdjustedBudgetAmount
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppi.AdjustedBudgetAmountCurP1 ELSE ppi.AdjustedBudgetAmountCurP1 END AS AdjustedBudgetAmountCurP1
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppi.AdjustedBudgetAmountCurP2 ELSE ppi.AdjustedBudgetAmountCurP2 END AS AdjustedBudgetAmountCurP2
		,ISNULL(ppi.ModificationNumber,0) AS ModificationNumber
		,ISNULL(ppi.IsItemLocked,0) AS IsItemLocked
		,ppi.CreditDebit AS CreditDebit
		,ppi.AdjutmentType
		,ppi.LegislativeReasonAdjustment
		,ppi.ReasonForAdjustment
		,ISNULL(ppi.GRAPClassification, '') AS GRAPClassification
		,ISNULL(ppi.GRAPClassificationNote, '') AS GRAPClassificationNote
		,ISNULL(ppi.MainSegmentReporting, '') AS MainSegmentReporting
		,ISNULL(ppi.SubSegmentReporting, '') AS SubSegmentReporting
		,ISNULL(ppi.IsActiveForSCM,0) AS IsActiveForSCM
	FROM 
		Plan_AdjustmentProjectItem ppi 
		INNER JOIN Plan_AdjustmentProject pp ON ppi.AdjustmentProjectID = pp.AdjustmentProject_ID
		INNER JOIN Plan_Const_SCOA_Structure_Consolidated_vw s ON ppi.SCOAItemID=s.ScoaID AND s.FinYearText = @FinYearForSCOA
		INNER JOIN Plan_AdjustmentProjectItemMonth ppim1 ON ppi.PlanAdjustmentProjectItem_ID = ppim1.PlanAdjustmentProjectItemID and ppim1.MonthID=7
		INNER JOIN Plan_AdjustmentProjectItemMonth ppim2 ON ppi.PlanAdjustmentProjectItem_ID= ppim2.PlanAdjustmentProjectItemID and ppim2.MonthID=8
		INNER JOIN Plan_AdjustmentProjectItemMonth ppim3 ON ppi.PlanAdjustmentProjectItem_ID= ppim3.PlanAdjustmentProjectItemID and ppim3.MonthID=9
		INNER JOIN Plan_AdjustmentProjectItemMonth ppim4 ON ppi.PlanAdjustmentProjectItem_ID= ppim4.PlanAdjustmentProjectItemID and ppim4.MonthID=10
		INNER JOIN Plan_AdjustmentProjectItemMonth ppim5 ON ppi.PlanAdjustmentProjectItem_ID= ppim5.PlanAdjustmentProjectItemID and ppim5.MonthID=11
		INNER JOIN Plan_AdjustmentProjectItemMonth ppim6 ON ppi.PlanAdjustmentProjectItem_ID= ppim6.PlanAdjustmentProjectItemID and ppim6.MonthID=12
		INNER JOIN Plan_AdjustmentProjectItemMonth ppim7 ON ppi.PlanAdjustmentProjectItem_ID= ppim7.PlanAdjustmentProjectItemID and ppim7.MonthID=1
		INNER JOIN Plan_AdjustmentProjectItemMonth ppim8 ON ppi.PlanAdjustmentProjectItem_ID= ppim8.PlanAdjustmentProjectItemID and ppim8.MonthID=2
		INNER JOIN Plan_AdjustmentProjectItemMonth ppim9 ON ppi.PlanAdjustmentProjectItem_ID= ppim9.PlanAdjustmentProjectItemID and ppim9.MonthID=3
		INNER JOIN Plan_AdjustmentProjectItemMonth ppim10 ON  ppi.PlanAdjustmentProjectItem_ID= ppim10.PlanAdjustmentProjectItemID and ppim10.MonthID=4
		INNER JOIN Plan_AdjustmentProjectItemMonth ppim11 ON  ppi.PlanAdjustmentProjectItem_ID= ppim11.PlanAdjustmentProjectItemID and ppim11.MonthID=5
		INNER JOIN Plan_AdjustmentProjectItemMonth ppim12 ON  ppi.PlanAdjustmentProjectItem_ID= ppim12.PlanAdjustmentProjectItemID and ppim12.MonthID=6
		LEFT JOIN Const_ProjectItem i ON ppi.ProjectItemID=i.ProjectItem_ID
		LEFT JOIN Const_SCOA_Funds_Structure_Consolidated sfs ON ppi.SCOAFundId =sfs.ScoaID AND sfs.FinYearText = @FinYearForSCOA
		LEFT JOIN Const_SCOA_Function_Structure_Consolidated sfus ON ppi.SCOAFunctionID=sfus.ScoaID AND sfus.FinYearText = @FinYearForSCOA
		LEFT JOIN Const_SCOA_Regional_Structure_Consolidated srs ON ppi.SCOARegionID=srs.ScoaID AND srs.FinYearText = @FinYearForSCOA
		LEFT JOIN Const_SCOA_Costing_Structure_Consolidated scs ON ppi.SCOACostingID=scs.ScoaID AND scs.FinYearText = @FinYearForSCOA
		LEFT JOIN dbo.Const_Division cd ON cd.Division_ID = ppi.DivisionId
		LEFT JOIN dbo.Const_Department cdep ON cdep.Department_ID = cd.DepartmentID
	WHERE 
		ppi.AdjustmentProjectID= @AdjustmentProjectID 
		AND (ppi.FinYear='' + @FinYear + '' OR '' + @FinYear + '' = '0')
		AND (ppi.PlanAdjustmentProjectItem_ID = @AdjustmentProjectItemId OR @AdjustmentProjectItemId = 0)
		AND ppi.AdjustmentVersionId = @AdjustmentVersionId
	ORDER BY 
		i.ItemDescription,s.ScoaShortDesc;

END
GO

