CREATE PROCEDURE [dbo].[Plan_GetProjectItemsByFinYearsToUpdate]
@ProjectID INT,
@ProjectItemID INT,
@FinYearToBeExcluded NVARCHAR(9)
	
AS
BEGIN
	SET NOCOUNT ON;


SELECT PlanProjectItem_ID [PlanPRojectItemID],
	   ProjectID [ProjectID],
	   ProjectItemID [ProjectItemID],
	   FinYear [FinYear]
FROM [Plan_ProjectItem]
WHERE ProjectID = @ProjectID
AND ProjectItemID = @ProjectItemID
AND FinYear NOT IN (@FinYearToBeExcluded)

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectItemsByProjectID_sp]    Script Date: 2026/03/10 7:23:39 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Raindree Chetty
-- Create date: 2 February 2015
-- Description:	Get list of project items based on project id and finyear.  
-- Used in: ProjectItem.aspx
-- Calls : Plan_GetProjectItemsByProjectID_sp 24277,'2025/2026',0
-- 13/02/2016 RC: 30023 add budget for outer years
--07/03/2016 SN : 1.)Remove SCOAAssetID and also inner join related to same
--07/03/2016 SN : 2.)Add Columns SCOAFunctionId, SCOAFundId,SCOARegionId
--09/03/2016 SN: Comment left joins on Plan_ProjectFund and Const_SCOA_Funds_Structure as of now we already have SCOAFundId in projectItem Table
--22/03/2016 SN: Make left joins on Const_ProjectItem as for null values inner join didn't works
--24/03/2016 SN : Add Columns DivisionId
--24/03/2016 SN : Add Columns BudgetSplitID
--25/04/2016 SN : Add Column ModificationNumber
--19/08/2016 Snagpal: Add Left join of SCOAFunction, SCOAFunds, SCOARegion, Division,Plan_TrackChanges as requirement of desc from the same. & Add Function - Plan_GetProjectDivisionByDivisionId_fxn
--24/08/2016 SNagpal: Get Comma Seperated comments to Avoid Duplicate issue AND Add one more parameter named @ProjectItemId to get specific project Item Id
--30/08/2016 SNagpal: modify Inner join on SCOAFunction, SCOAFunds, SCOARegion to LEFT joins
--21/11/2016 SNagpal: Add stuff related to SCOACosting
--23/12/2016 SNagpal: Commented out Plan_GetProjectDivisionByDivisionId_fxn and add Left joins for getting Department/Divisions
--17/01/2017 SNagpal: Apply Left join to Const_Department
--02/02/2017 RChetty: Added "order  by i.ItemDescription,s.ScoaShortDesc"
--25/04/2017 SN : Add Column IsItemLocked
--21/06/2017 SN : Add Column CreditDebit
--10-08-2017:60720 SNagpal: Add sfs.ScoaDesc AS SCOAFundFullDesc
--03-11-2017: 63164 SNagpal: Add Stuff to show +ve -ve amounts based upon Credit Debit
--18-02-2019: SNagpal: #84009, Get SCOA Segments based upon FinYear
--OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
--16-07-2022: SN: #58285, Block Scoa item from being available for selection during procurement processes
--11-11-2025: CM: #124586 - Return budget signs as per standard 
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectItemsByProjectID_sp]
	@ProjectID int,
	@FinYear nvarchar(9),
	@ProjectItemId INT = 0
AS
BEGIN
	
	SET NOCOUNT ON

	SELECT 
		 ppi.PlanProjectItem_ID, ppi.ProjectID,ppi.ProjectItemID,ppi.FinYear,ppi.SCOAItemID
		,ISNULL(ppi.ProjectFundYearID,0) AS ProjectFundYearID
		,ppi.SCOAFundId as SCOAFundID, ppi.SCOAFunctionId,ppi.SCOARegionId, ppi.SCOACostingID, ppi.DivisionId, ppi.BudgetSplitID
		,ISNULL(i.ItemDescription,'') AS ItemDescription,s.ScoaShortDesc + ' ' + s.ScoaCode AS ScoaDesc
		,s.ScoaCode AS ScoaItemCode,
		sfs.ScoaShortDesc AS SCOAFundDesc,sfs.ScoaDesc AS SCOAFundFullDesc, sfus.ScoaDesc AS SCOAFunctionDesc ,srs.ScoaDesc AS SCOARegionDesc, scs.ScoaDesc AS SCOACostingDesc
		,( cdep.DepartmentCode + '/' + cd.DivisionCode + ' ' + cdep.DepartmentDesc + ' / ' + cd.DivisionDesc ) AS MunicipalClassification
		,STUFF((SELECT ',' + pt.Comment FROM dbo.Plan_TrackChanges pt WHERE pt.PlanProjectItem_ID = ppi.PlanProjectItem_ID FOR XML PATH('')),1,1,'') AS Comment
		,ppim1.UnitQuantity AS Month1Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim1.UnitPrice ELSE ppim1.UnitPrice END AS Month1Price
		,ppim2.UnitQuantity AS Month2Qty 
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim2.UnitPrice ELSE ppim2.UnitPrice END AS Month2Price
		,ppim3.UnitQuantity AS Month3Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim3.UnitPrice ELSE ppim3.UnitPrice END AS Month3Price
		,ppim4.UnitQuantity AS Month4Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim4.UnitPrice ELSE ppim4.UnitPrice END AS Month4Price
		,ppim5.UnitQuantity AS Month5Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim5.UnitPrice ELSE ppim5.UnitPrice END AS Month5Price
		,ppim6.UnitQuantity AS Month6Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim6.UnitPrice ELSE ppim6.UnitPrice END AS Month6Price
		,ppim7.UnitQuantity AS Month7Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim7.UnitPrice ELSE ppim7.UnitPrice END AS Month7Price
		,ppim8.UnitQuantity AS Month8Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim8.UnitPrice ELSE ppim8.UnitPrice END AS Month8Price
		,ppim9.UnitQuantity AS Month9Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim9.UnitPrice ELSE ppim9.UnitPrice END AS Month9Price
		,ppim10.UnitQuantity AS Month10Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim10.UnitPrice ELSE ppim10.UnitPrice END AS Month10Price
		,ppim11.UnitQuantity AS Month11Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim11.UnitPrice ELSE ppim11.UnitPrice END AS Month11Price
		,ppim12.UnitQuantity AS Month12Qty
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppim12.UnitPrice ELSE ppim12.UnitPrice END AS Month12Price
		,Quantity =1
		,PriceUnit=(ppim1.UnitPrice +ppim2.UnitPrice +ppim3.UnitPrice +ppim4.UnitPrice
					+ppim5.UnitPrice +ppim6.UnitPrice +ppim7.UnitPrice +ppim8.UnitPrice
					+ppim9.UnitPrice +ppim10.UnitPrice +ppim11.UnitPrice +ppim12.UnitPrice)
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppi.BudgetAmount ELSE ppi.BudgetAmount END AS BudgetAmount
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppi.BudgetAmountCurP1 ELSE ppi.BudgetAmountCurP1 END AS BudgetAmountCurP1
		,CASE WHEN (((s.ScoaCode LIKE 'IR%' OR s.ScoaCode LIKE 'IL%') AND CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -ppi.BudgetAmountCurP2 ELSE ppi.BudgetAmountCurP2 END AS BudgetAmountCurP2
		,ISNULL(ppi.ModificationNumber,0) AS ModificationNumber
		,ISNULL(ppi.IsItemLocked,0) AS IsItemLocked
		,ppi.CreditDebit AS CreditDebit
		,ISNULL(ppi.GRAPClassification, '') AS GRAPClassification
		,ISNULL(ppi.GRAPClassificationNote, '') AS GRAPClassificationNote
		,ISNULL(ppi.MainSegmentReporting, '') AS MainSegmentReporting
		,ISNULL(ppi.SubSegmentReporting, '') AS SubSegmentReporting
		,ISNULL(ppi.IsActiveForSCM,0) AS IsActiveForSCM
	FROM 
		Plan_ProjectItem ppi 
		INNER JOIN Plan_Project pp ON ppi.ProjectID = pp.Project_ID
		INNER JOIN Plan_Const_SCOA_Structure_Consolidated_vw s ON ppi.SCOAItemID=s.ScoaID AND s.FinYearText = @FinYear
		INNER JOIN Plan_ProjectItemMonth ppim1 ON ppi.PlanProjectItem_ID= ppim1.PlanProjectItemID and ppim1.MonthID=7
		INNER JOIN Plan_ProjectItemMonth ppim2 ON ppi.PlanProjectItem_ID= ppim2.PlanProjectItemID and ppim2.MonthID=8
		INNER JOIN Plan_ProjectItemMonth ppim3 ON ppi.PlanProjectItem_ID= ppim3.PlanProjectItemID and ppim3.MonthID=9
		INNER JOIN Plan_ProjectItemMonth ppim4 ON ppi.PlanProjectItem_ID= ppim4.PlanProjectItemID and ppim4.MonthID=10
		INNER JOIN Plan_ProjectItemMonth ppim5 ON ppi.PlanProjectItem_ID= ppim5.PlanProjectItemID and ppim5.MonthID=11
		INNER JOIN Plan_ProjectItemMonth ppim6 ON ppi.PlanProjectItem_ID= ppim6.PlanProjectItemID and ppim6.MonthID=12
		INNER JOIN Plan_ProjectItemMonth ppim7 ON ppi.PlanProjectItem_ID= ppim7.PlanProjectItemID and ppim7.MonthID=1
		INNER JOIN Plan_ProjectItemMonth ppim8 ON ppi.PlanProjectItem_ID= ppim8.PlanProjectItemID and ppim8.MonthID=2
		INNER JOIN Plan_ProjectItemMonth ppim9 ON ppi.PlanProjectItem_ID= ppim9.PlanProjectItemID and ppim9.MonthID=3
		INNER JOIN Plan_ProjectItemMonth ppim10 ON ppi.PlanProjectItem_ID= ppim10.PlanProjectItemID and ppim10.MonthID=4
		INNER JOIN Plan_ProjectItemMonth ppim11 ON ppi.PlanProjectItem_ID= ppim11.PlanProjectItemID and ppim11.MonthID=5
		INNER JOIN Plan_ProjectItemMonth ppim12 ON ppi.PlanProjectItem_ID= ppim12.PlanProjectItemID and ppim12.MonthID=6
		LEFT JOIN Const_ProjectItem i ON ppi.ProjectItemID=i.ProjectItem_ID
		LEFT JOIN Const_SCOA_Funds_Structure_Consolidated sfs ON ppi.SCOAFundId =sfs.ScoaID AND sfs.FinYearText = @FinYear
		LEFT JOIN Const_SCOA_Function_Structure_Consolidated sfus ON ppi.SCOAFunctionID=sfus.ScoaID AND sfus.FinYearText = @FinYear
		LEFT JOIN Const_SCOA_Regional_Structure_Consolidated srs ON ppi.SCOARegionID=srs.ScoaID AND srs.FinYearText = @FinYear
		LEFT JOIN Const_SCOA_Costing_Structure_Consolidated scs ON ppi.SCOACostingID=scs.ScoaID AND scs.FinYearText = @FinYear
		LEFT JOIN dbo.Const_Division cd ON cd.Division_ID = ppi.DivisionId
		LEFT JOIN dbo.Const_Department cdep ON cdep.Department_ID = cd.DepartmentID
	WHERE 
		ppi.ProjectID= @ProjectID 
		AND (ppi.FinYear=@FinYear OR @FinYear  = '0')
		AND (ppi.PlanProjectItem_ID = @ProjectItemId OR @ProjectItemId  = 0)
	ORDER BY 
		i.ItemDescription,s.ScoaShortDesc

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectItemsByProjectIDAndKpiId_sp]    Script Date: 2026/03/10 7:23:39 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

          
-- =============================================          
-- Author: anand narwade          
-- Create date: 2 February 2015          
-- Description: Get list of project items based on project id and finyear.            
        
-- =============================================          
CREATE PROCEDURE [dbo].[Plan_GetProjectItemsByProjectIDAndKpiId_sp]          
 @FinYear nvarchar(9),         
 @KpiId INT = 0          
AS          
BEGIN          
SET FMTONLY OFF;          
SET NOCOUNT ON               
SELECT DISTINCT(pkp.Id), ppi.PlanProjectItem_ID, ppi.ProjectID, pp.ProjectName, ppi.ProjectItemID,ppi.FinYear,ppi.SCOAItemID          
,  ISNULL(ppi.ProjectFundYearID,0) AS ProjectFundYearID,          
 ppi.SCOAFundId as SCOAFundID, ppi.SCOAFunctionId,ppi.SCOARegionId, ppi.SCOACostingID, ppi.DivisionId, ppi.BudgetSplitID          
,ISNULL(i.ItemDescription,'') AS ItemDescription,s.ScoaShortDesc + ' ' + s.ScoaCode AS ScoaDesc          
, s.ScoaCode AS ScoaItemCode,          
sfs.ScoaShortDesc AS SCOAFundDesc,sfs.ScoaDesc AS SCOAFundFullDesc, sfus.ScoaDesc AS SCOAFunctionDesc ,srs.ScoaDesc AS SCOARegionDesc, scs.ScoaDesc AS SCOACostingDesc,            
( cdep.DepartmentCode + '/' + cd.DivisionCode + ' ' + cdep.DepartmentDesc + ' / ' + cd.DivisionDesc ) AS MunicipalClassification,          
 STUFF((SELECT ',' + pt.Comment FROM dbo.Plan_TrackChanges pt WHERE pt.PlanProjectItem_ID = ppi.PlanProjectItem_ID FOR XML PATH('')),1,1,'') AS Comment          
,ppim1.UnitQuantity AS Month1Qty, (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim1.UnitPrice ELSE ppim1.UnitPrice END) AS Month1Price          
,ppim2.UnitQuantity AS Month2Qty, (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim2.UnitPrice ELSE ppim2.UnitPrice END) AS Month2Price           
,ppim3.UnitQuantity AS Month3Qty, (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim3.UnitPrice ELSE ppim3.UnitPrice END) AS Month3Price          
,ppim4.UnitQuantity AS Month4Qty, (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim4.UnitPrice ELSE ppim4.UnitPrice END) AS Month4Price          
,ppim5.UnitQuantity AS Month5Qty, (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim5.UnitPrice ELSE ppim5.UnitPrice END) AS Month5Price           
,ppim6.UnitQuantity AS Month6Qty, (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim6.UnitPrice ELSE ppim6.UnitPrice END) AS Month6Price           
,ppim7.UnitQuantity AS Month7Qty, (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim7.UnitPrice ELSE ppim7.UnitPrice END) AS Month7Price           
,ppim8.UnitQuantity AS Month8Qty, (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim8.UnitPrice ELSE ppim8.UnitPrice END) AS Month8Price           
,ppim9.UnitQuantity AS Month9Qty, (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim9.UnitPrice ELSE ppim9.UnitPrice END) AS Month9Price           
,ppim10.UnitQuantity AS Month10Qty, (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim10.UnitPrice ELSE ppim10.UnitPrice END) AS Month10Price           
,ppim11.UnitQuantity AS Month11Qty, (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim11.UnitPrice ELSE ppim11.UnitPrice END) AS Month11Price          
,ppim12.UnitQuantity AS Month12Qty, (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim12.UnitPrice ELSE ppim12.UnitPrice END) AS Month12Price           
,Quantity =1          
,PriceUnit=(ppim1.UnitPrice +ppim2.UnitPrice +ppim3.UnitPrice +ppim4.UnitPrice          
   +ppim5.UnitPrice +ppim6.UnitPrice +ppim7.UnitPrice +ppim8.UnitPrice          
   +ppim9.UnitPrice +ppim10.UnitPrice +ppim11.UnitPrice +ppim12.UnitPrice)          
,(CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ISNULL(ppi.BudgetAmount,0) ELSE ISNULL(ppi.BudgetAmount,0) END) AS BudgetAmount          
,(CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ISNULL(ppi.BudgetAmountCurP1,0) ELSE ISNULL(ppi.BudgetAmountCurP1,0) END) AS BudgetAmountCurP1          
,(CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ISNULL(ppi.BudgetAmountCurP2,0) ELSE ISNULL(ppi.BudgetAmountCurP2,0) END) AS BudgetAmountCurP2          
,ISNULL(ppi.ModificationNumber,0) AS ModificationNumber,          
ISNULL(ppi.IsItemLocked,0) AS IsItemLocked, ppi.CreditDebit AS CreditDebit  ,        
  
((CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim1.UnitPrice ELSE ppim1.UnitPrice END) + (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim2.UnitPrice ELSE ppim2.UnitPrice END) + (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim3.UnitPrice ELSE ppim3.UnitPrice END)) AS Quarter1,  
((CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim4.UnitPrice ELSE ppim4.UnitPrice END) + (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim5.UnitPrice ELSE ppim5.UnitPrice END) + (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim6.UnitPrice ELSE ppim6.UnitPrice END)) AS Quarter2,  
((CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim7.UnitPrice ELSE ppim7.UnitPrice END) + (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim8.UnitPrice ELSE ppim8.UnitPrice END) + (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim9.UnitPrice ELSE ppim9.UnitPrice END)) AS Quarter3,  
((CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim10.UnitPrice ELSE ppim10.UnitPrice END) + (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim11.UnitPrice ELSE ppim11.UnitPrice END) + (CASE WHEN ISNULL(ppi.CreditDebit,'') = 'C' THEN -ppim12.UnitPrice ELSE ppim12.UnitPrice END)) AS Quarter4  
FROM Plan_ProjectItem ppi WITH (NOLOCK)           
INNER JOIN Const_SCOA_Structure_ByYear(@FinYear) s ON ppi.SCOAItemID=s.ScoaID          
INNER JOIN Plan_ProjectItemMonth ppim1 ON ppi.PlanProjectItem_ID= ppim1.PlanProjectItemID and ppim1.MonthID=7          
INNER JOIN Plan_ProjectItemMonth ppim2 ON ppi.PlanProjectItem_ID= ppim2.PlanProjectItemID and ppim2.MonthID=8          
INNER JOIN Plan_ProjectItemMonth ppim3 ON ppi.PlanProjectItem_ID= ppim3.PlanProjectItemID and ppim3.MonthID=9          
INNER JOIN Plan_ProjectItemMonth ppim4 ON ppi.PlanProjectItem_ID= ppim4.PlanProjectItemID and ppim4.MonthID=10          
INNER JOIN Plan_ProjectItemMonth ppim5 ON ppi.PlanProjectItem_ID= ppim5.PlanProjectItemID and ppim5.MonthID=11          
INNER JOIN Plan_ProjectItemMonth ppim6 ON ppi.PlanProjectItem_ID= ppim6.PlanProjectItemID and ppim6.MonthID=12          
INNER JOIN Plan_ProjectItemMonth ppim7 ON ppi.PlanProjectItem_ID= ppim7.PlanProjectItemID and ppim7.MonthID=1          
INNER JOIN Plan_ProjectItemMonth ppim8 ON ppi.PlanProjectItem_ID= ppim8.PlanProjectItemID and ppim8.MonthID=2          
INNER JOIN Plan_ProjectItemMonth ppim9 ON ppi.PlanProjectItem_ID= ppim9.PlanProjectItemID and ppim9.MonthID=3          
INNER JOIN Plan_ProjectItemMonth ppim10 ON ppi.PlanProjectItem_ID= ppim10.PlanProjectItemID and ppim10.MonthID=4          
INNER JOIN Plan_ProjectItemMonth ppim11 ON ppi.PlanProjectItem_ID= ppim11.PlanProjectItemID and ppim11.MonthID=5          
INNER JOIN Plan_ProjectItemMonth ppim12 ON ppi.PlanProjectItem_ID= ppim12.PlanProjectItemID and ppim12.MonthID=6          
LEFT JOIN Const_ProjectItem i ON ppi.ProjectItemID=i.ProjectItem_ID               
LEFT JOIN dbo.Const_SCOA_Funds_Structure_ByYear(@FinYear) sfs ON ppi.SCOAFundId =sfs.ScoaID          
LEFT JOIN dbo.Const_SCOA_Function_Structure_ByYear(@FinYear)  sfus ON ppi.SCOAFunctionID=sfus.ScoaID          
LEFT JOIN dbo.Const_SCOA_Regional_Structure_ByYear(@FinYear) srs ON ppi.SCOARegionID=srs.ScoaID          
LEFT JOIN dbo.Const_SCOA_Costing_Structure_ByYear(@FinYear) scs ON ppi.SCOACostingID=scs.ScoaID          
LEFT JOIN dbo.Const_Division cd WITH (NOLOCK)    ON cd.Division_ID = ppi.DivisionId          
LEFT JOIN dbo.Const_Department cdep WITH (NOLOCK)    ON cdep.Department_ID = cd.DepartmentID          
  INNER JOIN Plan_Project pp WITH (NOLOCK)    ON pp.Project_ID = ppi.ProjectID        
  RIGHT JOIN dbo.PMS_KPI_ProjectLink  AS pkp WITH (NOLOCK)    ON pkp.planProjectItem_ID = ppi.PlanProjectItem_ID      
WHERE   
(ppi.FinYear=@FinYear OR @FinYear  = '0')             
AND     
pkp.kpiID = @KpiId          
END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectItemsTotalAllocPerFund_sp]    Script Date: 2026/03/10 7:23:39 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- =============================================
-- Author:	Raindree Chetty
-- Create date: 23/12/2015
-- Description:	Get the total item allocation per fund for the project
-- Used in the project Items screen to validate item allocation against the fund allocation for the project
--   by  :
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectItemsTotalAllocPerFund_sp]
	@ProjectID int,
	@ScoaFundID int,
	@FinYear nvarchar(9)
AS
BEGIN
	SELECT i.ProjectID
		, i.ProjectFundYearID
		, f.ScoaFundID
		, i.FinYear
		, SUM(m.UnitQuantity*m.UnitPrice) as ItemFundAllocation
	FROM Plan_ProjectItem i
		INNER JOIN Plan_ProjectItemMonth m ON i.PlanProjectItem_ID=m.PlanProjectItemID
		INNER JOIN Plan_ProjectFundYear fy ON i.ProjectFundYearID=fy.ProjectFundYear_ID
		INNER JOIN Plan_ProjectFund f ON fy.ProjectFundID=f.ProjectFund_ID
	WHERE 
		i.ProjectID =@ProjectID
		AND fy.FinYear=@FinYear 
		AND f.ScoaFundID=@ScoaFundID
	GROUP BY i.ProjectID, i.ProjectFundYearID, f.ScoaFundID,i.FinYear
END

GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectManagers_sp]    Script Date: 2026/03/10 7:23:39 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
