-- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.
-- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions
CREATE PROCEDURE [dbo].[Plan_GetProjectManagers_sp]
AS

	SELECT DISTINCT pm.* 
	FROM [dbo].[Plan_Project] p
	LEFT JOIN
	  (SELECT emp.Employee_ID,
			  Surname + ' ' + FirstName + ' (' + JobTitle + ')' AS EmpJobProfile
	   FROM Payroll_Employee emp
	    INNER JOIN Payroll_Position PP ON emp.PositionID = PP.Position_ID
	   INNER JOIN Payroll_JobProfile jProfile ON PP.JobProfileID = jProfile.JobProfile_ID) pm ON p.ProjectManagerID = pm.Employee_ID


GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectPaymentFramework_sp]    Script Date: 2026/03/10 7:23:39 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Raindree Chetty
-- Create date: 11 February 2015
-- Description:	Get list of project Service Provider based on search criteria
-- 10-12-2019 Volodymyr Stovba: 7334 CR_Project Code Change throughout system_SCM Screens as per document attached. Added ProjectNameWithCode.
-- 04-02-2020 Volodymyr Stovba: 27190 Alpha02: Please add a space between the project code and the pipe and the pipe and project name 
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectPaymentFramework_sp] --'15
  @ProjectName nvarchar(500)
AS
BEGIN
	SELECT 
		p.Project_ID
		, p.ProjectName
		, STR(p.ProjectCode) + ' | ' + p.ProjectName as ProjectNameWithCode
		, psp.PlanProjectServiceProvider_ID
		, v.Vendor_ID
		, psp.TenderQuote
		, psp.TenderQuoteNumber
		, psp.AppointmentAmount
		, ISNULL(convert(varchar,psp.AppointmentDate,103),'') as AppointmentDate  
		, e.FirstName + ' ' + e.Surname AS ApprovedBy
		, cpi.ItemDescription
		, v.VendorName
		, ISNULL(ppf.PaymentFramework_ID,0) AS PaymentFramework_ID
	FROM Plan_Project p
		INNER JOIN Plan_ProjectServiceProvider psp ON psp.ProjectID=p.Project_ID
		INNER JOIN Plan_ProjectItem pim ON pim.PlanProjectItem_ID = psp.PlanProjectItemID
		INNER JOIN Const_ProjectItem cpi ON cpi.ProjectItem_ID = pim.ProjectItemID
		INNER JOIN Cons_Vendor v ON v.Vendor_ID=psp.VendorID
		INNER JOIN Payroll_Employee e ON e.Employee_ID=psp.ApprovedByID
		LEFT JOIN Plan_ProjectPaymentFramework ppf ON ppf.PlanProjectServiceProviderID= psp.PlanProjectServiceProvider_ID
	WHERE 
		p.ProjectName LIKE  '%' + @ProjectName + '%' OR p.ProjectCode LIKE  '%' + @ProjectName + '%'
END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectRegions_sp]    Script Date: 2026/03/10 7:23:39 AM ******/
SET ANSI_NULLS ON
