/****** Object:  StoredProcedure [dbo].[Plan_GetProjectSCOAFundsForDropdown_sp]    Script Date: 2026/03/10 7:23:39 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 14/02/2018
-- Description:	Get SCOAFund details by project id, @ScoaFundID
-- Plan_GetProjectSCOAFundsForDropdown_sp 0,0,'Project','2018/2019'
-- SNagpal 19-02-2019 : 84009, Get SCOA Segments based upon FinYear, 
-- OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- CMoodley 16-01-2020 : 26850, Include financial year in where clause
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectSCOAFundsForDropdown_sp]
	@ProjectID INT,
	@ScoaFundID INT,
	@Type VARCHAR(20),
	@FinYear VARCHAR(10)
	
AS
BEGIN

	SET NOCOUNT ON;

	IF(@Type = 'Project')
	BEGIN
		SELECT DISTINCT ScoaFundID
		,sf.ScoaCode as FundCode
		,sf.ScoaShortDesc as FundDesc
		,sf.ScoaDesc AS FundFullDesc
		FROM dbo.Plan_ProjectFund pf
		INNER JOIN dbo.Const_SCOA_Funds_Structure_ByYear(@FinYear) sf ON sf.ScoaID=pf.ScoaFundID
		INNER JOIN dbo.Plan_Project pp ON pf.ProjectID = pp.Project_ID
		WHERE ( CASE WHEN @ProjectID = 0 THEN 0 ELSE pf.ProjectID END = @ProjectID )
		AND ( CASE WHEN @ScoaFundID = 0 THEN 0 ELSE sf.ScoaID END = @ScoaFundID )
		AND FinYear = CASE WHEN @FinYear IS NULL OR @FinYear = '' OR @FinYear = '0' THEN FinYear ELSE @FinYear END

	END;
	ELSE
	BEGIN
		SELECT DISTINCT ScoaFundID
		,sf.ScoaCode as FundCode
		,sf.ScoaShortDesc as FundDesc
		,sf.ScoaDesc AS FundFullDesc
		FROM dbo.Plan_AdjustmentProjectFund pf
		INNER JOIN dbo.Const_SCOA_Funds_Structure_ByYear(@FinYear) sf ON sf.ScoaID=pf.ScoaFundID
		INNER JOIN dbo.Plan_AdjustmentProject pap ON pf.AdjustmentProjectID = pap.AdjustmentProject_ID
		WHERE ( CASE WHEN @ProjectID  = 0 THEN 0 ELSE pf.AdjustmentProjectID END = @ProjectID )
		AND ( CASE WHEN @ScoaFundID  = 0 THEN 0 ELSE sf.ScoaID END = @ScoaFundID  )
		AND FinYear = CASE WHEN @FinYear IS NULL OR @FinYear = '' OR @FinYear = '0' THEN FinYear ELSE @FinYear END
	END

END
GO

