-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 11/02/2017
-- Description:	Get project SCOA Item details by project id, ScoaItemID
-- Used in : Project Capture Screen
-- Plan_GetProjectSCOAItems_sp 0,0,'2018/2019'
-- SNagpal 19-02-2019 : 84009, Get SCOA Segments based upon FinYear, 
-- OShiri 24-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- CMoodley 16-01-2020 : 26850, Include financial year in where clause
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectSCOAItems_sp]
	@ProjectID int,
	@ScoaItemID INT,
	@FinYear NVARCHAR(9)
AS
BEGIN

	SET NOCOUNT ON;

	SELECT DISTINCT
		ppi.SCOAItemID
		, rs.ScoaDesc
		, rs.ScoaCode
		, rs.ScoaShortDesc
		, (rs.ScoaCode + ' ' + rs.ScoaShortDesc) AS SCOACodeWithDesc
	FROM dbo.Plan_ProjectItem ppi
	INNER JOIN dbo.Const_SCOA_Structure_ByYear(@FinYear) rs ON rs.ScoaID=ppi.SCOAItemID
	WHERE 
		 (ppi.ProjectID=@ProjectID  OR @ProjectID =0)
		AND (ppi.SCOAItemID=@ScoaItemID  OR @ScoaItemID =0)
		AND FinYear = CASE WHEN @FinYear IS NULL OR @FinYear = '' OR @FinYear = '0' THEN FinYear ELSE @FinYear END
		ORDER BY rs.ScoaShortDesc, rs.ScoaCode
	
END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectSearch_sp]    Script Date: 2026/03/10 7:23:39 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author: Raindree Chetty
-- Create date: 16 July 2014
-- Description: Get list of projects based on search criteria
-- 03/01/2015 By RC : Added user department id filter as per NMB issue list 22 Dec 2015
-- 05/01/2016 by CB : Added in the IsDeleted flag - must be 0 or null to display
-- 27/01/2016 by RC : TP 30452.  Project name and SCM Official allowed to be null.
--01/03/2016 by SN : TP 32351. Add Financial Year as FinYear and SCOA description AS ScoaShortDesc And remove parameters @DateFrom & @DateTo and Add Parameter @FinYear & @ScoaID
--01/03/2016 by SN : Add Left join on Const_SCOA_Function_Structure to get ScoaShortDesc
--03/03/2016 by SN : Add dbo.Plan_ProjectFunction_fxn(p.Project_ID, 0) function to get ScoaShortDesc
--05/04/2016 by JP : Remove ProjectManagerId, DepartmentId from Parameter and Columns in Result CostEstimate, EstimatedEndDate, EstimatedStartDate, ProjectManager, SupplyChainOfficial also removed
-- [dbo].[Plan_GetProjectSearch_sp] 0,23626,'2025/2026',0,0,0,0,0,33172,4805,0,'0'
--03/08/2016 by SNagpal: Add Filter for SCOARegion,Division,SCOAProject & Status and also add their respective Left joins to get the data from the same.
--05/08/2016 by Snagpal: Add ProjectStatus and apply left join with const_status
--16/08/2016 by SNagpal: Add Case when for IsDeleted
--21/11/2016 by SNagpal: Add ScoaCosting Related Stuff
--06/12/2016 by SNagpal: Add XML function to get multiple SCOA segments and include HASH function in inner join
--13/12/2016 by SNAGPAL: AS PER REQUEST FROM GANSEN, COMMENTED OUT ALL THE FILTERS CONDITIONS EXCEPT PROJECTID, & WILL FIX EVERYTHING WHEN RAINDREE BACK (REVERTED)
--21/12/2016 by SNagpal: Add CapitalOperation Desc, ScoaItemDesc & commented out payroll left joins
--22/12/2016 by SNagpal: Optimize query by adding #table, As this query was previously taking long time to load. Create cluster index. Apply Case When in where condition
--23/12/2016 By SNagpal: Add Department Filter as well, reason: If User don''t Have Rights, Then project associated with Department will shown.
--24/12/2016 By SNagpal: Add @tempDivision table to get parent Child division linked with Department
--03/02/2017 By SNagpal: Modify Where constrain of Division & apply Case When in Select Statement for @tempDivision
--11/02/2017 By SNagpal: Add filter option for SCOAItemID
--10/03/2016 By Snagpal: Add  WHEN [CapitalOperation] = 3 for Financial position
--28/03/2017 SNagpal: As IDPItemID and ItemId no more exists in Plan_Project Table. So apply join with Plan_ProjectIDP and managed accordingly
--29-04-2017 SNagpal: Pass multiple DepartmentId in paramater, As Single user may have multiple Department
--11/02/2017 SNagpal: Add filter option for SCOAFundId
--14-08-2017 SNagpal: 60572 Add query to get CapitaloperationTypes from Const_PlanCapitalOperationalTypes_sys
--06-02-2018 SNagpal: 67399 SCOA Item description column on project search grid to be removed to enhance page response when searching for projects
--14-02-2018: SNagpal: 67819 SCOA Funding description column on project search grid to be removed to enhance page response when searching for projects
--15-02-2018: SNagpal: 67819As per suggestion from Travis;  Add If Else Condition if There is Project Id Parameter
--26-02-2018: SNagpal: Optimize the stored procedure, As its taking long time to load when execute for large results.
--05-07-2018: SNagpal: #75477 Fix FinYear filter
--05-07-2018: SNagpal: #75479 Fix Filter Search issue
--24-01-2019: SNagpal: #61596 - #83633 - Add functionality to get ProjectCode
--18-02-2019: SNagpal: #84009, Get SCOA Segments based upon FinYear
-- 24-May-2019 SNagpal: Add multiyear concept to get SCOA segments based upon finyear
-- 20-Oct-2025 CMoodley: 124313 - Optimise SP
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectSearch_sp]
    @IDPItemID INT = 0,
    @ProjectID INT = 0,
    @FinYear NVARCHAR(10) ='2017/2018',
    @ScoaFunctionID INT = 0,
	@ScoaCostingID INT = 0,
    @ScoaProjectID INT = 0 ,
    @ScoaRegionID INT = 0 ,
    @DivisionID INT = 0 ,
	@SCOAItemID INT = 0,
	@SCOAFundID INT = 0,
    @StatusId INT = 0 ,
	@DepartmentId NVARCHAR(200) = '0'
AS
BEGIN

	SET NOCOUNT ON;

    DECLARE @FinYearForSCOA NVARCHAR(10) = @FinYear;

    IF (@FinYearForSCOA IS NULL OR LTRIM(RTRIM(@FinYearForSCOA)) = '' OR @FinYearForSCOA = '0')
    BEGIN
        SELECT @FinYearForSCOA = KeyValue
        FROM dbo.AAAA_ConfigSettings
        WHERE KeyName = 'ActiveFinYear';
    END

    -- Build allowed divisions (either single DivisionID or recursive from DepartmentId)
    DECLARE @AllowedDivisions TABLE ( DivisionId INT NOT NULL PRIMARY KEY );

    IF (@DivisionID <> 0)
    BEGIN
        INSERT INTO @AllowedDivisions (DivisionId) VALUES (@DivisionID);
    END
    ELSE IF (ISNULL(@DepartmentId, '0') <> '0')
    BEGIN
        ;WITH CTE_Dep AS
        (
            SELECT d.Division_ID, d.DivisionParentID
            FROM dbo.Const_Division d
            WHERE d.DepartmentID IN (SELECT CAST(Data AS INT) FROM dbo.Split(@DepartmentId, ','))
            UNION ALL
            SELECT child.Division_ID, child.DivisionParentID
            FROM dbo.Const_Division child
            INNER JOIN CTE_Dep parent ON parent.Division_ID = child.DivisionParentID
        )
        INSERT INTO @AllowedDivisions (DivisionId)
        SELECT DISTINCT Division_ID FROM CTE_Dep;
    END
    -- else: leave @AllowedDivisions empty => no division filter

    SELECT
        p.Project_ID,
        -- aggregated ItemDesc(s) from IDP items linked to the project (respecting @IDPItemID if provided)
        ItemDesc = STUFF((
            SELECT DISTINCT ',' + ISNULL(i2.ItemDesc,'')
            FROM dbo.Plan_ProjectIDP ppid2
            LEFT JOIN dbo.IDP_Item i2 ON ppid2.ParentIDPItemID = i2.Item_ID
            WHERE ppid2.ProjectID = p.Project_ID
              AND (@IDPItemID = 0 OR ppid2.ParentIDPItemID = @IDPItemID)
            FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),
		IDPItemID = 0,
        p.ScoaProjectID,
        SCOAProjectCode = sp.ScoaCode,
        SCOAProjDesc = sp.ScoaDesc,
        p.ProjectName,
        ProjectDesc = REPLACE(REPLACE(REPLACE(p.ProjectDesc, CHAR(10), ' '), CHAR(13), ' '), CHAR(9), ' '),
        p.FinYear,
        DepartmentId = 0,
        ScoaShortDesc = STUFF((
            SELECT DISTINCT ',' + ISNULL(sf2.ScoaDesc,'')
            FROM dbo.Plan_ProjectItem ppi2
            LEFT JOIN dbo.Const_SCOA_Function_Structure_Consolidated sf2
              ON ppi2.ScoaFunctionID = sf2.ScoaID AND sf2.FinYearText = @FinYearForSCOA
            WHERE ppi2.ProjectID = p.Project_ID
              AND (@ScoaFunctionID = 0 OR ppi2.ScoaFunctionID = @ScoaFunctionID)
            FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),

        ScoaCostingShortDesc = STUFF((
            SELECT DISTINCT ',' + ISNULL(scs2.ScoaDesc,'')
            FROM dbo.Plan_ProjectItem ppi2
            LEFT JOIN dbo.Const_SCOA_Costing_Structure_Consolidated scs2
              ON ppi2.ScoaCostingID = scs2.ScoaID AND scs2.FinYearText = @FinYearForSCOA
            WHERE ppi2.ProjectID = p.Project_ID
              AND (@ScoaCostingID = 0 OR ppi2.ScoaCostingID = @ScoaCostingID)
            FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),

        ScoaRegionShortDesc = STUFF((
            SELECT DISTINCT ',' + ISNULL(sr2.ScoaDesc,'') + ' (' + CONVERT(NVARCHAR(300), ISNULL(ppr2.RegionPercent,'0')) + ')'
            FROM dbo.Plan_ProjectRegions ppr2
            LEFT JOIN dbo.Const_SCOA_Regional_Structure_Consolidated sr2
              ON ppr2.ScoaRegionID = sr2.ScoaID AND sr2.FinYearText = @FinYearForSCOA
            WHERE ppr2.ProjectID = p.Project_ID
              AND (@ScoaRegionID = 0 OR ppr2.ScoaRegionID = @ScoaRegionID)
            FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),

        -- populate fund short desc from SCOA fund consolidated table
        ScoaFundsShortDesc = STUFF((
            SELECT DISTINCT ',' + ISNULL(sfnd.ScoaDesc,'')
            FROM dbo.Plan_ProjectItem ppi3
            LEFT JOIN dbo.Const_SCOA_Funds_Structure_Consolidated sfnd
              ON ppi3.ScoaFundID = sfnd.ScoaID AND sfnd.FinYearText = @FinYearForSCOA
            WHERE ppi3.ProjectID = p.Project_ID
              AND (@SCOAFundID = 0 OR ppi3.ScoaFundID = @SCOAFundID)
            FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),

        ScoaDivisionShortDesc = STUFF((
            SELECT DISTINCT ',' + ISNULL(cd2.DivisionDesc,'')
            FROM dbo.Plan_ProjectItem ppi2
            LEFT JOIN dbo.Const_Division cd2 ON ppi2.DivisionID = cd2.Division_ID
            WHERE ppi2.ProjectID = p.Project_ID
              AND (
                      (@DivisionID = 0 AND ISNULL(@DepartmentId,'0') = '0')
                      OR cd2.Division_ID IN (SELECT DivisionId FROM @AllowedDivisions)
                  )
            FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),

        -- populate item desc from SCOA item consolidated table
        ScoaItemDesc = STUFF((
            SELECT DISTINCT ',' + ISNULL(si.ScoaDesc,'')
            FROM dbo.Plan_ProjectItem ppi4
            LEFT JOIN dbo.Plan_Const_SCOA_Structure_Consolidated_vw si
              ON ppi4.ScoaItemID = si.ScoaID AND si.FinYearText = @FinYearForSCOA
            WHERE ppi4.ProjectID = p.Project_ID
              AND (@SCOAItemID = 0 OR ppi4.ScoaItemID = @SCOAItemID)
            FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),

        ProjectStatus = p.ProjectStatus,
        SCOAProjectDesc = sp.ScoaShortDesc,
        ProjectStatusDesc = cs.StatusDesc,
        CapitalOperationDesc = (SELECT TOP(1) TypeName FROM dbo.Const_PlanCapitalOperationalTypes_sys WHERE TypeValue = p.CapitalOperation),
        ProjectCode = p.ProjectCode
    FROM dbo.Plan_Project p
    INNER JOIN dbo.Const_SCOA_Project_Structure_Consolidated sp
        ON p.ScoaProjectID = sp.ScoaID AND sp.FinYearText = @FinYearForSCOA
    LEFT JOIN dbo.Const_Status cs ON cs.Status_ID = p.ProjectStatus
    WHERE
        (@ProjectID = 0 OR p.Project_ID = @ProjectID)
        AND (@FinYear = '' OR p.FinYear = @FinYear)
        AND (@ScoaProjectID = 0 OR sp.ScoaID = @ScoaProjectID)
        AND (@StatusId = 0 OR p.ProjectStatus = @StatusId)
        AND ISNULL(p.IsDeleted, 0) = CASE WHEN (@StatusId = 5) THEN 1 ELSE 0 END
        -- ensure any SCOA-level filters that are project-level are applied (project item level filters are in subqueries)
        AND (
            (@ScoaFunctionID = 0)
            OR EXISTS (SELECT 1 FROM dbo.Plan_ProjectItem ppi WHERE ppi.ProjectID = p.Project_ID AND ppi.ScoaFunctionID = @ScoaFunctionID)
        )
        AND (
            (@ScoaCostingID = 0)
            OR EXISTS (SELECT 1 FROM dbo.Plan_ProjectItem ppi WHERE ppi.ProjectID = p.Project_ID AND ppi.ScoaCostingID = @ScoaCostingID)
        )
        AND (
            (@ScoaRegionID = 0)
            OR EXISTS (SELECT 1 FROM dbo.Plan_ProjectRegions pr WHERE pr.ProjectID = p.Project_ID AND pr.ScoaRegionID = @ScoaRegionID)
        )
        AND (
            (@SCOAItemID = 0)
            OR EXISTS (SELECT 1 FROM dbo.Plan_ProjectItem ppi WHERE ppi.ProjectID = p.Project_ID AND ppi.ScoaItemID = @SCOAItemID)
        )
        AND (
            (@SCOAFundID = 0)
            OR EXISTS (SELECT 1 FROM dbo.Plan_ProjectItem ppi WHERE ppi.ProjectID = p.Project_ID AND ppi.ScoaFundID = @SCOAFundID)
        )
        -- IDPItem filter (apply if provided)
        AND (
            @IDPItemID = 0
            OR EXISTS (SELECT 1 FROM dbo.Plan_ProjectIDP ppid WHERE ppid.ProjectID = p.Project_ID AND ppid.ParentIDPItemID = @IDPItemID)
        )
        -- Division/Department existence check if filtering requested
        AND (
            (@DivisionID = 0 AND ISNULL(@DepartmentId,'0') = '0')
            OR EXISTS (
                SELECT 1
                FROM dbo.Plan_ProjectItem ppix
                LEFT JOIN dbo.Const_Division cdx ON ppix.DivisionID = cdx.Division_ID
                WHERE ppix.ProjectID = p.Project_ID
                  AND cdx.Division_ID IN (SELECT DivisionId FROM @AllowedDivisions)
            )
        );

END
GO

