-- =============================================
-- Author:	Raindree Chetty
-- Create date: 27/01/2015
-- Description:	Get project stakeholders by project id
-- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.
-- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectStakeholderByProjectID_sp]
	@ProjectID int
AS
BEGIN
SELECT 
ProjectStakeholders_ID
 ,S.ProjectID
 ,StakeholderID
 ,FirstName + ' ' + Surname AS EmployeeName 
 ,DepartmentCode + ' - ' + DepartmentDesc AS Department
FROM Plan_Project p
INNER JOIN Plan_ProjectStakeholder s ON p.Project_ID=s.ProjectID
INNER JOIN dbo.Payroll_Employee E ON Employee_ID = s.StakeholderID
INNER JOIN dbo.Payroll_Position PP ON PP.Position_ID = E.PositionID
INNER JOIN dbo.Payroll_JobProfile P_JP ON PP.JobProfileID = JobProfile_ID
INNER JOIN dbo.Const_Department ON Department_ID = PP.DepartmentID
WHERE 
s.ProjectID=@ProjectID
END
                


GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectsToInitialise_sp]    Script Date: 2026/03/10 7:23:40 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- =============================================
-- Author:	Raindree Chetty
-- Create date: 25/08/2015
-- Description:	Get projects to be initialised
-- Calls: execute Plan_GetProjectsToInitialise_sp '',0,0,0,0
-- 04/05/2016 by JP : Remove DepartmentId from Input Parameter and Result Column DepartmentDesc & Reference for Dept and Division
-- 07/04/2016 by JP : Add DepartmentId and Column for DepartmentDesc & Filter for Department ID
-- 22/04/2016 by SN : Apply LEFT join instead on inner join for Const_ProjectType t ON p.ProjectTypeID = t.ProjectType_ID
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectsToInitialise_sp]
    @ProjectName NVARCHAR(500) ,
    @ProjectID INT ,
    @DepartmentID INT ,
    @ProjectType INT ,
    @FunderID INT
AS
    BEGIN
        SELECT DISTINCT
                p.Project_ID ,
                p.ProjectName ,
                REPLACE(REPLACE(REPLACE(p.ProjectDesc, CHAR(10), ' '),
                                CHAR(13), ' '), CHAR(09), ' ') AS ProjectDesc ,
                dbo.Plan_ProjectDepartment_fxn(p.Project_ID, 0) DepartmentDesc ,
                t.ProjectTypeDescrip ,
                fs.FundDesc
--select * 
        FROM    Plan_Project p
                LEFT JOIN Const_ProjectType t ON p.ProjectTypeID = t.ProjectType_ID
                INNER JOIN ( SELECT ProjectID ,
                                    STUFF((SELECT   ', '
                                                    + CAST(fs.FundingSourceDesc AS VARCHAR(MAX))
                                           FROM     ( SELECT DISTINCT
                                                              f.ProjectID ,
                                                              fs.FundingSourceDesc
                                                      FROM    Plan_ProjectFund f
                                                              INNER JOIN Plan_FundingSourceBudget_Detail sb ON sb.ScoaID = f.ScoaFundID
                                                              INNER JOIN Const_FundingSource fs ON sb.FundingSourceID = fs.FundingSource_ID
                                                      WHERE   ( sb.FundingSourceID = @FunderID
                                                              OR @FunderID = 0
                                                              )
                                                    ) AS fs
                                           WHERE    ( ProjectID = Results.ProjectID )
                                    FOR   XML PATH('') ,
                                              TYPE 
     /* Use .value to uncomment XML entities e.g. &gt; &lt; etc*/
    ).value('.', 'VARCHAR(MAX)'), 1, 2, '') AS FundDesc
                             FROM   Plan_ProjectFund Results
                             GROUP BY ProjectID
                           ) fs ON fs.ProjectID = p.Project_ID
        WHERE   ( p.ProjectName LIKE '%' + @ProjectName + '%'
                  OR @ProjectName LIKE ''
                )
                AND ( p.Project_ID = @ProjectID
                      OR @ProjectID = 0
                    )
                AND ( p.ProjectTypeID = @ProjectType
                      OR @ProjectType = 0
                    )
                AND p.ProjectStatus = 23
                AND ( @DepartmentID IN (
                      SELECT    cd.DepartmentID
                      FROM      dbo.Const_Division AS cd
                                INNER JOIN dbo.Plan_ProjectDivisions AS ppd ON ppd.DivisionID = cd.Division_ID
                                                              AND ppd.ProjectID = p.Project_ID )
                      OR @DepartmentID = 0
                    )
                AND ( p.IsDeleted IS NULL
                      OR p.IsDeleted = 0
                    );
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectWithDeptDivisions_sp]    Script Date: 2026/03/10 7:23:40 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 08/02/2019
-- Description:	Get Project Division details by Project id, DivisionID
-- Used in :  Project Capture Screen
-- Plan_GetProjectWithDeptDivisions_sp 2921,0,'2018/2019'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectWithDeptDivisions_sp]
	@ProjectID INT = 0,
	@UserId INT = 0,
	@UserFinYear NVARCHAR(10) ='2018/2019'
	AS
BEGIN
SET FMTONLY OFF
SET NOCOUNT ON

	DECLARE 
			@DivisionID INT = 0,
			@ProjectDivision_ID INT,
			@ReferenceProjectDivisionID INT,
			@DepartmentCode VARCHAR(50),
			@DepartmentDesc VARCHAR(200);

	
	  CREATE TABLE #tempAdjustDivision
	  (	DivisionId INT,
		ProjectDivision_ID INT,
		ProjectID INT,
		DepartmentCode VARCHAR(50),
		DepartmentDesc VARCHAR(200));

	  CREATE TABLE #tempStuffedDivision
	  (	DivisionId VARCHAR(Max),
		StuffedDivisionDesc VARCHAR(MAx),
		StuffedDivisionCode VARCHAR(MAx),
		ProjectDivision_ID INT,
		ProjectID INT,
		DepartmentCode VARCHAR(50),
		DepartmentDesc VARCHAR(200));

	  INSERT INTO #tempAdjustDivision
	  (
	      DivisionId,
		  ProjectDivision_ID,
		  ProjectID,
		  DepartmentCode,
		  DepartmentDesc
	  )
	  SELECT DISTINCT DivisionId,pd.ProjectDivision_ID , pd.ProjectID, cdd.DepartmentCode, cdd.DepartmentDesc
	  FROM dbo.Const_Division cd
	  INNER JOIN dbo.Const_Department cdd ON cdd.Department_ID = cd.DepartmentID
	  INNER JOIN dbo.Plan_ProjectDivisions pd ON pd.DivisionID=cd.Division_ID
	  WHERE 
	  (CASE
               WHEN @ProjectID = 0 THEN
                   0
               ELSE
                   pd.ProjectID
           END = @ProjectID)

	  WHILE EXISTS ( SELECT 1 FROM #tempAdjustDivision)
	  BEGIN

	  SELECT TOP 1	@DivisionID = DivisionId, 
					@ProjectDivision_ID = ProjectDivision_ID,
					@ProjectID = ProjectID,
					@DepartmentCode = DepartmentCode,
					@DepartmentDesc = DepartmentDesc
					FROM #tempAdjustDivision

	;WITH CTE AS 
					(
						SELECT 1 AS rn, DivisionParentID, DivisionDesc,cdd.DivisionCode
						FROM dbo.Const_Division cdd
						WHERE Division_ID = @DivisionID
						UNION ALL
						SELECT rn + 1 AS rn, D.DivisionParentID, D.DivisionDesc,D.DivisionCode  
						FROM dbo.Const_Division D
						INNER JOIN CTE C ON D.Division_ID = C.DivisionParentID
					)
					INSERT INTO #tempStuffedDivision
					SELECT
					@DivisionID,
					@DepartmentDesc + ':' + STUFF((SELECT ': ' + CTE.DivisionDesc FROM CTE ORDER BY CTE.rn DESC FOR XML PATH('')) , 1,2,''),
					@DepartmentCode + '' + STUFF((SELECT '-' + CTE.DivisionCode FROM CTE  ORDER BY CTE.rn DESC FOR XML PATH('')) , 1,0,''),
					@ProjectDivision_ID,@ProjectID,@DepartmentCode,@DepartmentDesc

    
		   DELETE  FROM #tempAdjustDivision WHERE ProjectDivision_ID = @ProjectDivision_ID;
	  END

	  SELECT DISTINCT
             ProjectDivision_ID,
             ProjectID,
			 t.DivisionId,
             StuffedDivisionCode + ' / ' + REPLACE(StuffedDivisionDesc,'&amp;', '&') AS MunicipalClassification,
             DepartmentCode,
             DepartmentDesc FROM #tempStuffedDivision t
			 LEFT JOIN dbo.User_UserDivisions uud ON uud.DivisionID = t.DivisionId
			 WHERE (CASE WHEN @UserId = 0 THEN 0 ELSE uud.UserID END = @UserId )

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetProjectWithLockedSCOAItem_sp]    Script Date: 2026/03/10 7:23:40 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author: Sahil Nagpal
-- Create date: 24 April 2017
-- Description: Get list of projects based on search criteria
-- 15-03-2018 SNagpal: #61596 Add csil.FinYear = @FinYear
-- SNagpal 20-02-2019 : 84009, Get SCOA Segments based upon FinYear
-- OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- 13 Aug 2020 CMoodley: 4727 - Standardise formatting for project field
-- 18 Apr 2024 CMoodley: 87595 - Return projects in all statuses (except deleted) and use SCOA consolidated tables
-- [Plan_GetProjectWithLockedSCOAItem_sp] 0, '2023/2024', 0, 0, 0, 0, 0
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectWithLockedSCOAItem_sp] 
    @ProjectID INT = 0,
    @FinYear NVARCHAR(10) ='' ,
    @ScoaFunctionID INT = 0,
    @ScoaRegionID INT = 0 ,
    @DivisionID INT = 0 ,
	@SCOAItemID INT = 0,
    @SCOAFundId INT = 0 
AS
BEGIN

	SET NOCOUNT ON
	   
	SELECT DISTINCT
		p.Project_ID,
		ppi.PlanProjectItem_ID,
		p.ProjectName,
		p.FinYear,
		CPI.ItemDescription AS ProjectItemDesc,
		sf.ScoaDesc AS ScoaFunctionDesc,
		sr.ScoaDesc AS ScoaRegionDesc,
		cd.DivisionDesc AS DivisionDesc,
		sfs.ScoaDesc AS ScoaFundsDesc,
		CSSPPI.ScoaDesc AS ScoaItemDesc ,
		scs.ScoaDesc AS SCOACostingDesc,
		p.ProjectStatus ,
		cs.StatusDesc AS ProjectStatusDesc,
		cpco.TypeName AS CapitalOperationDesc,
		PPI.BudgetAmount AS OriginalBudgetAmount,
		PPI.BudgetAmountCurP1 AS OriginalBudgetAmountCurrP1,
		PPI.BudgetAmountCurP2 AS OriginalBudgetAmountCurrP2,
		csil.LockEnabled, ISNULL(ppi.IsItemLocked,0) AS IsItemLocked,
		CAST(ISNULL(p.ProjectCode, p.Project_ID) AS VARCHAR(50)) + ' | ' + p.ProjectName AS ProjectField
	FROM dbo.Plan_Project p
		INNER JOIN dbo.Plan_ProjectItem PPI ON PPI.ProjectID = p.Project_ID
		INNER JOIN dbo.Const_PlanCapitalOperationalTypes_sys cpco ON cpco.TypeValue = p.CapitalOperation
		LEFT JOIN dbo.Const_ProjectItem CPI ON CPI.ProjectItem_ID = PPI.ProjectItemID
		INNER JOIN dbo.Const_SCOAItemLock csil ON csil.SCOAItemID = PPI.SCOAItemID
		INNER JOIN dbo.Plan_Const_SCOA_Structure_Consolidated_vw CSSPPI ON CSSPPI.ScoaID = PPI.SCOAItemID AND CSSPPI.FinYearText = @FinYear
		INNER JOIN dbo.Const_SCOA_Function_Structure_Consolidated sf ON ppi.ScoaFunctionID = sf.ScoaID AND sf.FinYearText = @FinYear
		INNER JOIN dbo.Const_SCOA_Regional_Structure_Consolidated sr ON ppi.ScoaRegionID = sr.ScoaID AND sr.FinYearText = @FinYear
		INNER JOIN dbo.Const_SCOA_Funds_Structure_Consolidated sfs ON ppi.ScoaFundID = sfs.ScoaID AND sfs.FinYearText = @FinYear
		INNER JOIN dbo.Const_Division cd ON ppi.DivisionID = cd.Division_ID
		INNER JOIN dbo.Const_SCOA_Costing_Structure_Consolidated scs ON ppi.ScoaCostingID = scs.ScoaID AND scs.FinYearText = @FinYear
		INNER JOIN dbo.Const_Status cs ON cs.Status_ID = p.ProjectStatus
	WHERE  
		(CASE WHEN @ProjectID  = 0 THEN 0 ELSE p.Project_ID END = @ProjectID )
		AND (CASE WHEN @FinYear= '' THEN '' ELSE p.FinYear END = @FinYear )
		AND (CASE WHEN @ScoaFunctionID = 0 THEN 0 ELSE sf.ScoaID END = @ScoaFunctionID)
		AND (CASE WHEN @ScoaFundID = 0 THEN 0 ELSE sfs.ScoaID END = @ScoaFundID)
		AND ( CASE WHEN @ScoaRegionID  = 0 THEN 0 ELSE sr.ScoaID END = @ScoaRegionID  )
		AND ( CASE WHEN @SCOAItemID = 0 THEN 0 ELSE CSSPPI.ScoaID END = @SCOAItemID)
		AND ( CASE WHEN @DivisionID = 0 THEN 0 ELSE cd.Division_ID END = @DivisionID)
		AND ISNULL(p.IsDeleted, 0) = 0 AND ISNULL(csil.LockEnabled, 0) = 1
		AND csil.FinYear = @FinYear;

END;
GO

