-- 10-12-2019 Volodymyr Stovba: 7334 CR_Project Code Change throughout system_SCM Screens as per document attached. Added ProjectNameWithCode.
-- 04-02-2020 Volodymyr Stovba: 27190 Alpha02: Please add a space between the project code and the pipe and the pipe and project name 
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetProjectWorkOrderDetails_sp]
	 @FinYear VARCHAR(9) = ''
	,@ProjectStatus BIGINT = 0
	,@SearchText VARCHAR(50) = ''
AS
BEGIN

	SELECT pwob.ProjectID
		  ,p.ProjectName AS [ProjectName]
		  ,LTRIM(STR(p.ProjectCode))+' | '+p.ProjectName AS [ProjectNameWithCode]
		  ,p.ProjectDesc AS [ProjectDesc]
		  ,pwob.WorkOrderDescription AS [WorkOrderDesc]
		  ,pwob.WorkOrderbudget AS [WorkOrderBudget]
		  ,pwob.WorkOrderVariationAmt AS [WorkOrderVariation]
		  ,0.00 AS [WorkOrderExpenditure]
		  ,pwob.WorkOrderPlanCompletionDate AS [PlannedCompletion]
		  ,pwob.WorkOrderRevCompletionDate AS [RevisedCompletion]
		  ,pwob.WorkOrderActCompletionDate AS [ActualCompletion]
		  ,stat.StatusDesc AS [Status]
		  ,p.FinYear
	FROM [dbo].[Plan_Project] p
	INNER JOIN [dbo].[Plan_Project_WorkOrderBreakdowns] pwob ON p.Project_ID = pwob.ProjectID
	INNER JOIN Const_Status stat ON p.ProjectStatus=stat.Status_ID
	WHERE p.FinYear = CASE WHEN ISNULL(@FinYear, '') = '' THEN p.FinYear ELSE @FinYear END
	AND (p.ProjectName LIKE '%' + ISNULL(@SearchText, '') + '%' OR
		 p.ProjectDesc LIKE '%' + ISNULL(@SearchText, '') + '%' OR
		 pwob.WorkOrderDescription LIKE '%' + ISNULL(@SearchText, '') + '%')
	AND ((stat.Status_ID=@ProjectStatus) OR (@ProjectStatus=0))
	--UNION ALL
	--SELECT 0 AS [ProjectID],'Project 1' AS [ProjectName],'Project Desc 1' AS [ProjectDesc],'Work Order 1' AS [WorkOrderDesc],0.00 AS [WorkOrderBudget],0.00 AS [WorkOrderVariation],0.00 AS [WorkOrderExpenditure],'17/10/2015' AS [PlannedCompletion],'17/10/2015' AS [RevisedCompletion],'17/10/2015' AS [ActualCompletion],'' AS [Status]
	--UNION ALL
	--SELECT 0 AS [ProjectID],'Project 1' AS [ProjectName],'Project Desc 1' AS [ProjectDesc],'Work Order 1' AS [WorkOrderDesc],0.00 AS [WorkOrderBudget],0.00 AS [WorkOrderVariation],0.00 AS [WorkOrderExpenditure],'17/10/2015' AS [PlannedCompletion],'17/10/2015' AS [RevisedCompletion],'17/10/2015' AS [ActualCompletion],'' AS [Status]
	--UNION ALL
	--SELECT 0 AS [ProjectID],'Project 1' AS [ProjectName],'Project Desc 1' AS [ProjectDesc],'Work Order 1' AS [WorkOrderDesc],0.00 AS [WorkOrderBudget],0.00 AS [WorkOrderVariation],0.00 AS [WorkOrderExpenditure],'17/10/2015' AS [PlannedCompletion],'17/10/2015' AS [RevisedCompletion],'17/10/2015' AS [ActualCompletion],'' AS [Status]
	--UNION ALL
	--SELECT 0 AS [ProjectID],'Project 1' AS [ProjectName],'Project Desc 1' AS [ProjectDesc],'Work Order 1' AS [WorkOrderDesc],0.00 AS [WorkOrderBudget],0.00 AS [WorkOrderVariation],0.00 AS [WorkOrderExpenditure],'17/10/2015' AS [PlannedCompletion],'17/10/2015' AS [RevisedCompletion],'17/10/2015' AS [ActualCompletion],'' AS [Status]
	--UNION ALL
	--SELECT 0 AS [ProjectID],'Project 1' AS [ProjectName],'Project Desc 1' AS [ProjectDesc],'Work Order 1' AS [WorkOrderDesc],0.00 AS [WorkOrderBudget],0.00 AS [WorkOrderVariation],0.00 AS [WorkOrderExpenditure],'17/10/2015' AS [PlannedCompletion],'17/10/2015' AS [RevisedCompletion],'17/10/2015' AS [ActualCompletion],'' AS [Status]
	--UNION ALL
	--SELECT 0 AS [ProjectID],'Project 1' AS [ProjectName],'Project Desc 1' AS [ProjectDesc],'Work Order 1' AS [WorkOrderDesc],0.00 AS [WorkOrderBudget],0.00 AS [WorkOrderVariation],0.00 AS [WorkOrderExpenditure],'17/10/2015' AS [PlannedCompletion],'17/10/2015' AS [RevisedCompletion],'17/10/2015' AS [ActualCompletion],'' AS [Status]

