/****** Object:  StoredProcedure [dbo].[Plan_GetRecentAdjustmentProjectByUserId_sp]    Script Date: 2026/03/10 7:23:40 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 27/11/2017
-- Description:	Get list of AdjustmentProject detail based on loggedIn UserId
-- 13 Aug 2020 CMoodley: 4727 - Standardise formatting for project name
-- dbo.Plan_GetRecentAdjustmentProjectByUserId_sp 165,'2020/2021'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetRecentAdjustmentProjectByUserId_sp] 
 @loggedInUserId INT,
@UserFinYear NVARCHAR(10) 
AS
BEGIN
	SET NOCOUNT ON

	DECLARE @AdjustmentVersionId INT;

	SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion WHERE VersionName 
	LIKE @UserFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

	SELECT TOP 5 AdjustmentProject_ID,AdjustmentProjectDesc FROM (
	SELECT pp.AdjustmentProject_ID, (pp.FinYear + ';' + CAST( COALESCE(pp.ProjectCode,pp.ReferenceProject_ID,pp.AdjustmentProject_ID) AS VARCHAR(50)) + ' | ' + pp.AdjustmentProjectName + ';' + dbo.Plan_AdjustmentProjectFunction_fxn(pp.AdjustmentProject_ID, 0)) AS AdjustmentProjectDesc,
	pp.DateModified,pp.DateCaptured
	 FROM dbo.Plan_AdjustmentProject pp
	WHERE (pp.ModifierID = @loggedInUserId or pp.CapturerID = @loggedInUserId) AND ISNULL(pp.IsDeleted,0) = 0
	AND pp.AdjustmentVersionId=@AdjustmentVersionId
	) A

	GROUP BY AdjustmentProject_ID,AdjustmentProjectDesc,DateModified,DateCaptured
	ORDER BY 
	CASE WHEN (DateModified IS NULL) THEN DateCaptured 
	WHEN (DateModified < DateCaptured) THEN DateCaptured 
	ELSE
	DateModified
	END DESC

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetRecentProjectByUserId_sp]    Script Date: 2026/03/10 7:23:40 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 04 Aug 2016
-- Description:	Get list of project detail based on loggedIn UserId
-- dbo.Plan_GetRecentProjectByUserId_sp 2655
-- 05-08-2016 SNagpal: Add IsDeleted Condition
-- 07-12-2016 SNagpal: Remove Unnecessary Left Joins
-- 13 Aug 2020 CMoodley: 4727 - Standardise formatting for project name
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetRecentProjectByUserId_sp]
 @loggedInUserId INT
AS
BEGIN

	SELECT TOP 5 Project_ID,ProjectDesc 
	FROM 
		(
			SELECT pp.Project_ID, (pp.FinYear + ';' + CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS VARCHAR(50)) + ' | ' + pp.ProjectName + ';' + dbo.Plan_ProjectFunction_fxn(pp.Project_ID, 0)) AS ProjectDesc, pp.DateModified,pp.DateCaptured
			FROM dbo.Plan_Project pp
			WHERE (pp.ModifierID = @loggedInUserId or pp.CapturerID = @loggedInUserId) AND ISNULL(pp.IsDeleted,0) = 0
		) A
	GROUP BY Project_ID,ProjectDesc,DateModified,DateCaptured
	ORDER BY 
		CASE 
			WHEN (DateModified IS NULL) THEN DateCaptured 
			WHEN (DateModified < DateCaptured) THEN DateCaptured 
		ELSE
			DateModified
		END DESC

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetRecommendedAdjustment_sp]    Script Date: 2026/03/10 7:23:40 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Sahil Nagpal
-- Create date: 2017-12-29
-- Description:	Get Recommended Adjustement 
-- CALL SP: Plan_GetRecommendedAdjustment_sp '2025/2026'
-- 23-Mar-2018 RChetty: #69995 Add reference project id
-- 26-Mar-2018 RChetty: #69995 Any changes made need to be recommended
-- 17-Dec-2025 CMoodley: #125770 Optimise SP
-- =============================================
CREATE   PROCEDURE [dbo].[Plan_GetRecommendedAdjustment_sp] 

@FinYear NVARCHAR(9)

AS

BEGIN
	SET NOCOUNT ON
		
	DECLARE @AdjustmentVersionId INT;
		
	SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID 
	FROM Plan_AdjustmentBudgetVersion 
	WHERE VersionName LIKE @FinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

    CREATE TABLE #TEMP 
	(
		Id INT IDENTITY(1,1) NOT NULL,
		AdjustmentProject_ID INT , 
		AdjustmentProjectName NVARCHAR(500),
		RecommendOn DATETIME,
		RecommendBy VARCHAR(500),
		ItemDesc VARCHAR(500),
		ScoaProjectID INT,
		ProjectCode VARCHAR(255),
		SCOAProjDesc VARCHAR(500),
		AdjustmentProjectDesc	NVARCHAR(500),
		FinYear VARCHAR(20),
		ScoaShortDesc VARCHAR(700),
		ScoaCostingShortDesc VARCHAR(700),
		ScoaRegionShortDesc VARCHAR(700),
		ScoaFundsShortDesc VARCHAR(700),
		ScoaDivisionShortDesc VARCHAR(700),
		ScoaItemDesc VARCHAR(700),
		ProjectStatus INT,
		SCOAProjectDesc VARCHAR(255),
		ProjectStatusDesc VARCHAR(255),
		CapitalOperationDesc VARCHAR(50),
		ReferenceProject_ID INT 
	)

	CREATE CLUSTERED INDEX IX_Temp ON #TEMP(Id ASC,AdjustmentProject_ID ASC) 
	CREATE NONCLUSTERED INDEX IX_Temp1 ON #TEMP(AdjustmentProject_ID) 
	INCLUDE (ItemDesc, ScoaProjectID, ProjectCode,SCOAProjDesc ,AdjustmentProjectName ,AdjustmentProjectDesc	,FinYear ,ScoaShortDesc ,ScoaCostingShortDesc ,ScoaRegionShortDesc ,ScoaFundsShortDesc ,ScoaDivisionShortDesc ,ScoaItemDesc ,ProjectStatus ,SCOAProjectDesc ,ProjectStatusDesc ,CapitalOperationDesc, ReferenceProject_ID )

	INSERT INTO #TEMP
    SELECT DISTINCT
        p.AdjustmentProject_ID ,
		p.AdjustmentProjectName ,
		PAAR.RecommendOn AS RecommendOn,
        UUD.UserName AS RecommendBy,
        i.ItemDesc ,
        p.ScoaProjectID ,
        sp.ScoaCode AS ProjectCode ,
        sp.ScoaDesc AS SCOAProjDesc ,
        REPLACE(REPLACE(REPLACE(p.AdjustmentProjectDesc, CHAR(10), ' '), CHAR(13), ' '), CHAR(09), ' ') AS AdjustmentProjectDesc ,
        p.FinYear ,
		sf.ScoaDesc ScoaShortDesc,
		scs.ScoaDesc ScoaCostingShortDesc,
		sr.ScoaDesc + ' ('+CONVERT(NVARCHAR(300),ISNULL(RegionPercent,'0'))+ ')' ScoaRegionShortDesc,
		sfs.ScoaDesc AS ScoaFundsShortDesc,
		cd.DivisionDesc AS ScoaDivisionShortDesc,
		CSSPPI.ScoaDesc AS ScoaItemDesc ,
        p.ProjectStatus ,
        sp.ScoaShortDesc AS SCOAProjectDesc ,
        cs.StatusDesc AS ProjectStatusDesc,
		TypeName CapitalOperationDesc,
		ISNULL(p.ReferenceProject_ID, p.AdjustmentProject_ID) AS ReferenceProject_ID
    FROM    
		dbo.Plan_AdjustmentProject P
		INNER JOIN dbo.Const_PlanCapitalOperationalTypes_sys budgetType ON P.CapitalOperation = budgetType.TypeValue
        INNER JOIN dbo.Const_SCOA_Project_Structure_Consolidated sp ON p.ScoaProjectID = sp.ScoaID AND sp.FinYearText = @FinYear
		INNER JOIN dbo.Plan_AdjustmentProjectRecommendation PAAR ON PAAR.AdjustmentProjectId = P.AdjustmentProject_ID AND PAAR.IsRecommend = 1
        INNER JOIN dbo.User_UserDetail UUD ON UUD.User_ID = PAAR.RecommendBy
		LEFT JOIN dbo.Plan_AdjustmentProjectIDP ppid ON ppid.AdjustmentProjectID = p.AdjustmentProject_ID
        LEFT JOIN dbo.IDP_Item i ON ppid.ParentIDPItemID = i.Item_ID
		LEFT JOIN dbo.Plan_AdjustmentProjectItem PPI ON PPI.AdjustmentProjectID = p.AdjustmentProject_ID
		LEFT JOIN dbo.Plan_Const_SCOA_Structure_Consolidated_vw CSSPPI ON PPI.SCOAItemID = CSSPPI.ScoaID   AND CSSPPI.FinYearText = @FinYear
        LEFT JOIN dbo.Const_SCOA_Function_Structure_Consolidated sf ON PPI.ScoaFunctionID = sf.ScoaID AND sf.FinYearText = @FinYear
		LEFT JOIN dbo.Const_SCOA_Costing_Structure_Consolidated scs ON PPI.ScoaCostingID = scs.ScoaID  AND scs.FinYearText = @FinYear
        LEFT JOIN dbo.Plan_AdjustmentProjectRegions ppr ON p.AdjustmentProject_ID = ppr.AdjustmentProjectID
        LEFT JOIN dbo.Const_SCOA_Regional_Structure_Consolidated sr ON PPI.ScoaRegionID = sr.ScoaID AND sr.FinYearText = @FinYear
        LEFT JOIN dbo.Const_SCOA_Funds_Structure_Consolidated sfs ON PPI.ScoaFundID = sfs.ScoaID AND sfs.FinYearText = @FinYear
        LEFT JOIN dbo.Const_Division cd ON PPI.DivisionID = cd.Division_ID
		LEFT JOIN dbo.Const_Status cs ON cs.Status_ID = p.ProjectStatus
    WHERE   
		( P.FinYear = @FinYear OR @FinYear = '' )
		AND P.AdjustmentVersionId = @AdjustmentVersionId;

	SELECT DISTINCT
		AdjustmentProject_ID,
		A.RecommendOn,
		A.RecommendBy,
		STUFF((SELECT DISTINCT ',' + ItemDesc FROM #Temp T WHERE T.AdjustmentProject_ID = A.AdjustmentProject_ID FOR XML PATH('')),1,1,'') ItemDesc,
		ScoaProjectID,
		ProjectCode,
		SCOAProjDesc,
		AdjustmentProjectName,
		AdjustmentProjectDesc,
		FinYear,
		STUFF((SELECT DISTINCT ',' + ScoaShortDesc FROM #Temp T WHERE T.AdjustmentProject_ID = A.AdjustmentProject_ID FOR XML PATH('')),1,1,'') ScoaShortDesc,
		STUFF((SELECT DISTINCT ',' + ScoaCostingShortDesc FROM #Temp T WHERE T.AdjustmentProject_ID = A.AdjustmentProject_ID FOR XML PATH('')),1,1,'') ScoaCostingShortDesc,
		STUFF((SELECT DISTINCT ',' + ScoaRegionShortDesc FROM #Temp T WHERE T.AdjustmentProject_ID = A.AdjustmentProject_ID FOR XML PATH('')),1,1,'') ScoaRegionShortDesc,
		STUFF((SELECT DISTINCT ',' + ScoaFundsShortDesc FROM #Temp T WHERE T.AdjustmentProject_ID = A.AdjustmentProject_ID FOR XML PATH('')),1,1,'') ScoaFundsShortDesc,
		STUFF((SELECT DISTINCT ',' + ScoaDivisionShortDesc FROM #Temp T WHERE T.AdjustmentProject_ID = A.AdjustmentProject_ID FOR XML PATH('')),1,1,'') ScoaDivisionShortDesc,
		STUFF((SELECT DISTINCT ',' + ScoaItemDesc FROM #Temp T WHERE T.AdjustmentProject_ID = A.AdjustmentProject_ID FOR XML PATH('')),1,1,'') ScoaItemDesc,
		ProjectStatus,
		SCOAProjectDesc, 
		ProjectStatusDesc , 
		CapitalOperationDesc, 
		ReferenceProject_ID
	FROM 
		#Temp A
		
	DROP TABLE #Temp		 
    
END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetRejectedAdjustment_sp]    Script Date: 2026/03/10 7:23:40 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 2016-04-18
-- Description:	Get Pending Adjustement 
-- CALL SP: Plan_GetRejectedAdjustment_sp ''
-- 2016-04-19 by JP : Update Fields and Condition for Adjustments
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetRejectedAdjustment_sp] @FinYear NVARCHAR(9)
AS
    BEGIN
        SET NOCOUNT ON;

        SELECT  MIN(PA.AdjustmentBudget_Id) AdjustmentBudget_Id ,
                PA.VersionNumber AS VersionNumber ,
                ISNULL(PAAR.ApprovalRejectionFileName, '') AS RejectedFileName ,
                COUNT(PAAR.AdjustmentBudgetId) AS RejectedAdjustments ,
                PAAR.RejectReason AS RejectReason ,
                PAAR.RejectedOn AS RejectedOn ,
                UUD.UserName AS RejectedBy
        FROM    dbo.Plan_Project PrjFrom
                INNER JOIN dbo.Plan_Adjustment PA ON PrjFrom.Project_ID = PA.FromProjectId
                LEFT OUTER JOIN Plan_Project PrjTo ON PA.ToProjectId = PrjTo.Project_ID
                INNER JOIN dbo.Plan_AdjustmentApprovalRejections PAAR ON PAAR.AdjustmentBudgetId = PA.AdjustmentBudget_Id
                                                              AND PAAR.IsRejected = 1
                                                              AND PA.Status = 102
                INNER JOIN dbo.User_UserDetail UUD ON UUD.User_ID = PAAR.RejectedBy
        WHERE   ( PA.FinYear = @FinYear
                  OR @FinYear = ''
                )
        GROUP BY PA.VersionNumber ,
                ISNULL(PAAR.ApprovalRejectionFileName, '') ,
                PAAR.RejectReason ,
                PAAR.RejectedOn ,
                UUD.UserName;
    END;
GO

