-- =============================================
-- Author:	Raindree Chetty
-- Create date: 20 July 2014
-- Description:	Get scoa funds not used by project
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetRemainingFundsByProjectID_sp]
	@ProjectID int
AS
BEGIN
SELECT 
ScoaID, ScoaCode + '-' + ScoaShortDesc as ScoaShortDesc  
FROM Const_SCOA_Funds_Structure
WHERE 
PostingLevel='Yes' AND
ScoaID NOT IN (SELECT ScoaFundID FROM Plan_ProjectFund WHERE ProjectID=@ProjectID)
END
GO

