-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 27/11/2017
-- Description:	Get SCOAAdjustmentProject details by AdjustmentProject id, @ScoaAdjustmentProjectID
-- Used in : AdjustmentProject Capture Screen
-- Plan_GetSCOAAdjustmentProject_sp 0,445,'2018/2019','2018/2019'
-- SNagpal 18-02-2019 : 84009, Get SCOA Segments based upon FinYear
-- OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetSCOAAdjustmentProject_sp]
	@AdjustmentProjectID int,
	@ScoaAdjustmentProjectID int,
	@UserFinYear NVARCHAR(10) ,
	@FinYear NVARCHAR(9)
AS
BEGIN
	SET NOCOUNT ON

	DECLARE @AdjustmentVersionId INT;

	SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion WHERE VersionName 
	LIKE @UserFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

	SET FMTONLY OFF;

	SELECT pr.ScoaProjectID 
	, pr.AdjustmentProject_ID
	, rs.ScoaDesc
	, rs.ScoaCode
	, rs.ScoaShortDesc
	FROM dbo.Plan_AdjustmentProject pr
	INNER JOIN dbo.Const_SCOA_Project_Structure_ByYear(@FinYear) rs ON rs.ScoaID=pr.ScoaProjectID
	WHERE 
		 (pr.AdjustmentProject_ID=@AdjustmentProjectID  OR @AdjustmentProjectID  =0)
		AND (pr.ScoaProjectID=@ScoaAdjustmentProjectID  OR @ScoaAdjustmentProjectID  =0)
		AND pr.AdjustmentVersionId = @AdjustmentVersionId 


	--SELECT pr.ScoaProjectID , pr.AdjustmentProject_ID, rs.ScoaDesc, rs.ScoaCode, rs.ScoaShortDesc
	--FROM dbo.Plan_AdjustmentProject pr
	--INNER JOIN dbo.Const_SCOA_Project_Structure rs ON rs.ScoaID=pr.ScoaProjectID
END
GO

