/****** Object:  StoredProcedure [dbo].[Plan_GetSCOAFundCapital_sp]    Script Date: 2026/03/10 7:23:41 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- =================================================
-- Author:		Nirav Parikh
-- Create date: 2017-Nov-02
-- Description:	#63164 Budget Register Changes
-- Plan_GetSCOAFundCapital_sp 0, 0, '2019/2020'
-- SNagpal 15-04-2019 : 84009, Get SCOA Segments based upon FinYear, 
-- OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- =================================================
CREATE PROCEDURE [dbo].[Plan_GetSCOAFundCapital_sp]
    @SCOAFundCapitalID INT ,
    @SCOAId INT ,
    @FinYear NVARCHAR(9)
AS
    BEGIN
        SET NOCOUNT ON;
		SET FMTONLY OFF;

	SELECT  cnt.SCOAFundCapital_Id ,
                cnt.ScoaFundId ,
                cnt.IsEnable ,
                cnt.FinYear ,
                csp.ScoaCode ,
                csp.NTScoaID ,
                csp.ScoaDesc ,
                csp.ScoaShortDesc ,
                csp.PostingLevel ,
                csp.BreakDownAllowed ,
                cnt.CapturerID ,
                cnt.DateCaptured
        FROM    dbo.Const_PlanSCOAFundCapital cnt
                INNER JOIN dbo.Const_SCOA_Funds_Structure_ByYear(@FinYear) csp ON csp.ScoaID = cnt.ScoaFundId
        WHERE   ( CASE WHEN @SCOAFundCapitalID = 0 THEN 0 ELSE cnt.SCOAFundCapital_Id
                  END = @SCOAFundCapitalID)
                AND ( CASE WHEN @SCOAId  = 0 THEN 0
                           ELSE cnt.ScoaFundId
                      END = @SCOAId )
                AND ( CASE WHEN  @FinYear  = '' THEN ''
                           ELSE cnt.FinYear
                      END = @FinYear);
   
    END;
GO

