-- =================================================
-- Author:		Nirav Parikh
-- Create date: 2017-Nov-02
-- Description:	#63164 Budget Register Changes
-- Plan_GetSCOAFundOperational_sp 0, 0, '2019/2020'
-- SNagpal 15-04-2019 : 84009, Get SCOA Segments based upon FinYear, 
-- OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- =================================================
CREATE PROCEDURE [dbo].[Plan_GetSCOAFundOperational_sp]
    @SCOAFundOperationalID INT ,
    @SCOAId INT ,
    @FinYear NVARCHAR(9)
AS
    BEGIN
        SET NOCOUNT ON;
		SET FMTONLY OFF;
       SELECT  cnt.SCOAFundOperational_Id ,
                cnt.ScoaFundId ,
                cnt.IsEnable ,
                cnt.FinYear ,
                csp.ScoaCode ,
                csp.NTScoaID ,
                csp.ScoaDesc ,
                csp.ScoaShortDesc ,
                csp.PostingLevel ,
                csp.BreakDownAllowed ,
                cnt.CapturerID ,
                cnt.DateCaptured
        FROM    dbo.Const_PlanSCOAFundOperational cnt
              INNER JOIN dbo.Const_SCOA_Funds_Structure_ByYear(@FinYear) csp ON csp.ScoaID = cnt.ScoaFundId
        WHERE   ( CASE WHEN @SCOAFundOperationalID = 0 THEN 0 ELSE cnt.SCOAFundOperational_Id
                  END = @SCOAFundOperationalID )
                AND ( CASE WHEN @SCOAId   = 0 THEN 0
                           ELSE cnt.ScoaFundId
                      END = @SCOAId )
                AND ( CASE WHEN @FinYear = '' THEN ''
                           ELSE cnt.FinYear
                      END = @FinYear)


    END;
GO

