-- =================================================
-- Author:		Sahil Nagpal
-- Create date: 2017-Oct-31
-- Description:	#63164 Budget Register Changes
-- Plan_GetSCOAItemAssetFBS_sp 0, 0, '2019/2020'
-- 2018 05 28, Chirag Patel, Add Credit/Debit Column add #73217
-- SNagpal 16-04-2019 : 84009, Get SCOA Segments based upon FinYear, 
-- OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- =================================================
CREATE PROCEDURE [dbo].[Plan_GetSCOAItemAssetFBS_sp]
    @SCOAItemAssetFBSID INT ,
    @SCOAId INT ,
    @FinYear NVARCHAR(9)
AS
    BEGIN
        SET NOCOUNT ON;
		SET FMTONLY OFF;

	SELECT  cnt.SCOAItemAssetFBS_Id ,
                cnt.ScoaItemId ,
                cnt.IsEnable ,
                cnt.FinYear ,
                csp.ScoaCode ,
                csp.NTScoaID ,
                csp.ScoaDesc ,
                csp.ScoaShortDesc ,
                csp.PostingLevel ,
                csp.BreakDownAllowed ,
                cnt.CapturerID ,
                cnt.DateCaptured ,
                cnt.CreditDebit ,
               CASE WHEN cnt.CreditDebit = 'D' THEN 'Debit'
                     WHEN cnt.CreditDebit = 'C' THEN 'Credit'
                     ELSE ''
                END AS CreditDebitStatus
        FROM    dbo.Const_PlanSCOAItemAssetFBS cnt
                INNER JOIN dbo.Const_SCOA_Structure_ByYear(@FinYear) csp ON csp.ScoaID = cnt.ScoaItemId
        WHERE   ( CASE WHEN @SCOAItemAssetFBSID  = 0 THEN 0
                       ELSE cnt.SCOAItemAssetFBS_Id
                  END = @SCOAItemAssetFBSID )
                AND ( CASE WHEN @SCOAId = 0 THEN 0
                           ELSE cnt.ScoaItemId
                      END = @SCOAId)
                AND ( CASE WHEN @FinYear= '' THEN ''
                           ELSE cnt.FinYear
                      END = @FinYear);

    END;
GO

