CREATE PROCEDURE [dbo].[Plan_GetSCOAItemDescription]
@SCOAItemID INT
	
AS
BEGIN
	SET NOCOUNT ON;

	SELECT  ScoaID [SCOAID],
	ScoaShortDesc + '' + CHAR(13) + CHAR(10) +  ScoaCode [SCOAItem]
			--ScoaShortDesc + ' (' + PostingLevel + ') ' + ScoaCode [SCOADescription]
	FROM Const_SCOA_Structure
