-- ============================================= 
-- Author:		Chirag Patel
-- Create date: 2018-09-14
-- Description:	#61596 Planning Financial Year Budget rollover
-- EXEC Plan_GetSCOAItemExceptionDetailsByID_sp '1','2018/2019','IR'
-- 2018-12-31 Chirag Patel: Get All SCOA segment based upon FinYear
-- 2019-03-13 SNagpal: Optimize the Stored procedure
-- 2019-03-18 SNagpal: Budget Rollover - SCOA Item Revenue - Error Message
-- 06-06-2019 OShiri: Add multiyear concept to SCOA segments based upon financial year
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetSCOAItemExceptionDetailsByID_sp]
   @ExceptionID INT = 45,
	@CurrentFinyear NVARCHAR(9) = '2018/2019' ,
	@SCOAType NVARCHAR(10) = 'IR'
	AS
    BEGIN
	SET FMTONLY OFF	


		DECLARE @NextFinYear NVARCHAR(9),
				@yearp1 INT,
				@yearp2 INT;
		SELECT @yearp1 = CAST(SUBSTRING(@CurrentFinyear, 6, 4) AS INT);
		SELECT @yearp2 = @yearp1 + 1;
		SELECT @NextFinYear = CONVERT(VARCHAR(4), @yearp1) + '/' + CONVERT(VARCHAR(4), @yearp2);

        SELECT  
                PE.SCOAItemExceptionId AS SCOAItemExceptionId ,
                ISNULL(PS.ScoaID,0) AS ActiveSCOAID ,
                ISNULL(PSA.ScoaID,0) AS NewSCOAID ,
                @CurrentFinyear AS ActiveFinyear ,                
                ISNULL(PS.ScoaDesc,'') AS ActiveSCOADescription ,
                ISNULL(PSA.ScoaDesc,'') AS NewSCOADescription ,
                PE.ExceptionDescription AS ExceptionDescription ,
                PE.IsSCOAMissing ,
                PE.FinYear ,
                PE.IsBreakdownMismatch ,
                PE.IsPostingLevelMismatch ,
                PE.IsExceptionHandled ,
                PE.CapturerID ,
                PE.DateCaptured ,
                PE.ModifierID ,
                PE.DateModified
        FROM    Plan_SCOAItemExceptions PE
                LEFT JOIN dbo.Const_Scoa_Structure_ByYear(@CurrentFinyear) PS ON PS.ScoaID = PE.ActiveSCOAId  AND PS.ScoaCode LIKE  @SCOAType + '%'
                LEFT JOIN dbo.Const_Scoa_Structure_ByYear(@NextFinYear) PSA ON PSA.ScoaID = PE.NewSCOAId AND PSA.ScoaCode LIKE @SCOAType + '%'
        WHERE   PE.SCOAItemExceptionId=@ExceptionID  AND PE.SCOAItemType =@SCOAType;

		--PRINT (@SCOASegmentPart);
    END;


	
GO

