-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 03/03/2017
-- Description:	Get project SCOA Item details
-- Used in : Track Changes
-- Plan_GetSCOAItemForTrackChanges_sp
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetSCOAItemForTrackChanges_sp]
AS
BEGIN
	SELECT --ppi.PlanProjectItem_ID, ppi.ProjectID
	DISTINCT
	ProjectId,
	 ppi.SCOAItemID AS ScoaItemId
	, rs.ScoaDesc AS SCOAItemDesc
	, rs.ScoaCode
	, rs.ScoaShortDesc
	, (rs.ScoaCode + ' ' + rs.ScoaShortDesc) AS SCOACodeWithDesc
	FROM dbo.Plan_TrackChanges ppi
	INNER JOIN dbo.Const_SCOA_Structure rs ON rs.ScoaID=ppi.SCOAItemID
		ORDER BY rs.ScoaShortDesc, rs.ScoaCode
END
GO

