-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 26/12/2016
-- Description:	Get SCOA Items by all SCOA Segments
-- 05-01-2017 SNagpal: Add SCOACostingFilter
-- Plan_GetSCOAItemUsingAllSCOAFields_sp 1,26,267,4011,1200,130,'2018/2019'
-- 06-02-2017 SNagpal: Add ProjectItem & Its Left Join
-- SNagpal 20-02-2019 : 84009, Get SCOA Segments based upon FinYear
-- OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- SNagpal 07-06-2019 : Replace Const_SCOA_Structure by Const_Scoa_Structure_ByYear
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetSCOAItemUsingAllSCOAFields_sp]
	@ProjectID int,
	@DivisionId INT,
	@SCOAFunctionId INT,
	@SCOAFundId INT,
	@SCOARegionId INT,
	@SCOACostingId INT,
	@FinYear VARCHAR(10)
AS
BEGIN
SET NOCOUNT ON;
SET FMTONLY OFF;
	SELECT css.ScoaID
	, css.ScoaCode
	, css.ScoaDesc
	, css.ScoaShortDesc
	, ppi.ProjectItemID
	, cpi.ItemDescription
	FROM Plan_ProjectItem ppi
	INNER JOIN dbo.Const_Scoa_Structure_ByYear(@FinYear) css ON css.ScoaID = ppi.SCOAItemID
	LEFT JOIN dbo.Const_ProjectItem cpi ON cpi.ProjectItem_ID = ppi.ProjectItemID
	WHERE css.PostingLevel = 'Yes' AND
	 ppi.ProjectID = @ProjectID  AND ppi.SCOAFunctionId = @SCOAFunctionId 
		AND ppi.SCOAFundId = @SCOAFundId  AND ppi.SCOARegionId = @SCOARegionId 
		AND ppi.DivisionId = @DivisionId 
		AND (CASE WHEN @SCOACostingId  = 0 THEN 0 ELSE ppi.SCOACostingID END) = @SCOACostingId 


	--SELECT css.ScoaID, css.ScoaCode
	--, css.ScoaDesc, css.ScoaShortDesc, ppi.ProjectItemID, cpi.ItemDescription
	--FROM Plan_ProjectItem ppi
	--INNER JOIN dbo.Const_SCOA_Structure css ON css.ScoaID = ppi.SCOAItemID
	--LEFT JOIN dbo.Const_ProjectItem cpi ON cpi.ProjectItem_ID = ppi.ProjectItemID
END
GO

