-- ============================================= 
-- Author:		Chirag Patel
-- Create date: 2018-09-04
-- Description:	#61596 Planning Financial Year Budget rollover
-- EXEC Plan_GetSCOAProjectExceptionDetails_Sp '2017/2018','2018/2019',''
-- 2018-12-31 Chirag Patel: Get All SCOA segment based upon FinYear
-- 06-06-2019 OShiri: Add multiyear concept to SCOA segments based upon financial year
-- =============================================

CREATE  PROCEDURE [dbo].[Plan_GetSCOAProjectExceptionDetails_sp]
    @CurrentFinyear NVARCHAR(9) = NULL ,
    @NewFinyear NVARCHAR(9) = NULL ,
    @ExceptionType NVARCHAR(10) = NULL
AS
    BEGIN	
	SET FMTONLY OFF;
  

        CREATE TABLE #TempException
            (
              ScoaID INT ,
              ScoaParentID INT ,
              LevelID INT ,
              PostingLevel NVARCHAR(12) ,
              BreakDownAllowed NVARCHAR(12) ,
              ScoaShortDesc NVARCHAR(500) ,
              ScoaDesc NVARCHAR(1000) ,
              scoacode NVARCHAR(1000) ,
              NTScoaID NVARCHAR(1000) ,
              NTParentScoaId NVARCHAR(1000) ,
              [ENABLED] BIT ,
              [Version] NVARCHAR(20)
            );




        INSERT  INTO #TempException
		SELECT 
				ScoaID,
				ScoaParentID,
				LevelID,
				PostingLevel,
				BreakDownAllowed,
				ScoaShortDesc,
				ScoaDesc,
				ScoaCode,
				NTScoaID,
				NTParentScoaId,
				[Enabled],
				[Version] 
				FROM dbo.Const_SCOA_Project_Structure_ByYear(@CurrentFinyear);

		CREATE TABLE #TempExceptionNext
            (
              ScoaID INT ,
              ScoaParentID INT ,
              LevelID INT ,
              PostingLevel NVARCHAR(12) ,
              BreakDownAllowed NVARCHAR(12) ,
              ScoaShortDesc NVARCHAR(500) ,
              ScoaDesc NVARCHAR(1000) ,
              scoacode NVARCHAR(1000) ,
              NTScoaID NVARCHAR(1000) ,
              NTParentScoaId NVARCHAR(1000) ,
              [ENABLED] BIT ,
              [Version] NVARCHAR(20)
            );




        INSERT  INTO #TempExceptionNext
		SELECT 
				ScoaID,
				ScoaParentID,
				LevelID,
				PostingLevel,
				BreakDownAllowed,
				ScoaShortDesc,
				ScoaDesc,
				ScoaCode,
				NTScoaID,
				NTParentScoaId,
				[Enabled],
				[Version] 
				FROM dbo.Const_SCOA_Project_Structure_ByYear(@NewFinyear);



        SELECT  PE.SCOAProjectExceptionId AS SCOAProjectExceptionId ,
                ISNULL(PS.ScoaID, 0) AS ActiveSCOAID ,
                ISNULL(PSA.ScoaID, 0) AS NewSCOAID ,
                @CurrentFinyear AS ActiveFinyear ,
                @NewFinyear AS NewFinYear ,
                ISNULL(PS.ScoaDesc, '') AS ActiveSCOADescription ,
                ISNULL(PSA.ScoaDesc, '') AS NewSCOADescription ,
                PE.ExceptionDescription AS ExceptionDescription ,
                PE.IsSCOAMissing ,
                PE.FinYear ,
                PE.IsBreakdownMismatch ,
                PE.IsPostingLevelMismatch ,
                PE.IsExceptionHandled ,
                PE.CapturerID ,
                PE.DateCaptured ,
                PE.ModifierID ,
                PE.DateModified
        FROM    Plan_SCOAProjectExceptions PE
                LEFT JOIN #TempException PS ON PS.ScoaID = PE.ActiveSCOAId
                LEFT JOIN #TempExceptionNext PSA ON PSA.ScoaID = PE.NewSCOAId
        WHERE   PE.FinYear = @NewFinyear
                AND ( ISNULL(PE.IsExceptionHandled, '') = @ExceptionType
                      OR '' = @ExceptionType
                    );



    END;
GO

