-- =============================================

CREATE  PROCEDURE [dbo].[Plan_GetSCOAProjectExceptionDetailsByID_sp]
    @ExceptionID INT,
	@CurrentFinyear NVARCHAR(9) = NULL 
AS
    BEGIN
	SET FMTONLY OFF;
	

		DECLARE @NextFinYear NVARCHAR(9),
				@yearp1 INT,
				@yearp2 INT;
		SELECT @yearp1 = CAST(SUBSTRING(@CurrentFinyear, 6, 4) AS INT);
		SELECT @yearp2 = @yearp1 + 1;
		SELECT @NextFinYear = CONVERT(VARCHAR(4), @yearp1) + '/' + CONVERT(VARCHAR(4), @yearp2);

		 CREATE TABLE #TempException
            (
              ScoaID INT ,
              ScoaParentID INT ,
              LevelID INT ,
              PostingLevel NVARCHAR(12) ,
              BreakDownAllowed NVARCHAR(12) ,
              ScoaShortDesc NVARCHAR(500) ,
              ScoaDesc NVARCHAR(1000) ,
              scoacode NVARCHAR(1000) ,
              NTScoaID NVARCHAR(1000) ,
              NTParentScoaId NVARCHAR(1000) ,
              [ENABLED] BIT ,
              [Version] NVARCHAR(20)
            );
		

         INSERT  INTO #TempException
		 SELECT 
				ScoaID,
				ScoaParentID,
				LevelID,
				PostingLevel,
				BreakDownAllowed,
				ScoaShortDesc,
				ScoaDesc,
				ScoaCode,
				NTScoaID,
				NTParentScoaId,
				[Enabled],
				[Version] 
				FROM dbo.Const_SCOA_Project_Structure_ByYear(@CurrentFinyear);


			
			CREATE TABLE #TempExceptionNext
            (
              ScoaID INT ,
              ScoaParentID INT ,
              LevelID INT ,
              PostingLevel NVARCHAR(12) ,
              BreakDownAllowed NVARCHAR(12) ,
              ScoaShortDesc NVARCHAR(500) ,
              ScoaDesc NVARCHAR(1000) ,
              scoacode NVARCHAR(1000) ,
              NTScoaID NVARCHAR(1000) ,
              NTParentScoaId NVARCHAR(1000) ,
              [ENABLED] BIT ,
              [Version] NVARCHAR(20)
            );
		

         INSERT  INTO #TempExceptionNext
		 SELECT 
				ScoaID,
				ScoaParentID,
				LevelID,
				PostingLevel,
				BreakDownAllowed,
				ScoaShortDesc,
				ScoaDesc,
				ScoaCode,
				NTScoaID,
				NTParentScoaId,
				[Enabled],
				[Version] 
				FROM dbo.Const_SCOA_Project_Structure_ByYear(@NextFinYear);

        SELECT  
                PE.SCOAProjectExceptionId AS SCOAProjectExceptionId ,
                ISNULL(PS.ScoaID,0) AS ActiveSCOAID ,
                ISNULL(PSA.ScoaID,0) AS NewSCOAID ,
                @CurrentFinyear AS ActiveFinyear ,                
                ISNULL(PS.ScoaDesc,'') AS ActiveSCOADescription ,
                ISNULL(PSA.ScoaDesc,'') AS NewSCOADescription ,
                PE.ExceptionDescription AS ExceptionDescription ,
                PE.IsSCOAMissing ,
                PE.FinYear ,
                PE.IsBreakdownMismatch ,
                PE.IsPostingLevelMismatch ,
                PE.IsExceptionHandled ,
                PE.CapturerID ,
                PE.DateCaptured ,
                PE.ModifierID ,
                PE.DateModified
        FROM    Plan_SCOAProjectExceptions PE
                LEFT JOIN #TempException PS ON PS.ScoaID = PE.ActiveSCOAId 
                LEFT JOIN #TempExceptionNext PSA ON PSA.ScoaID = PE.NewSCOAId
        WHERE   PE.SCOAProjectExceptionId=@ExceptionID;
    END;


	
GO

