-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 03/08/2016
-- Description:	Get SCOAproject details by project id, @ScoaProjectID
-- Used in : Project Capture Screen
-- SNagpal 18-02-2019 : 84009, Get SCOA Segments based upon FinYear
-- Plan_GetSCOAProjects_sp 0,0,'2018/2019'
-- OShiri 24-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- CMoodley 16-01-2020 : 26850, Include financial year in where clause
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetSCOAProjects_sp]
	@ProjectID int,
	@ScoaProjectID INT,
	@FinYear NVARCHAR(9)
AS
BEGIN

	SET NOCOUNT ON;

	SELECT pr.ScoaProjectID 
	, pr.Project_ID
	, rs.ScoaDesc
	, rs.ScoaCode
	, rs.ScoaShortDesc
	FROM dbo.Plan_Project pr
	INNER JOIN dbo.Const_SCOA_Project_Structure_ByYear(@FinYear) rs ON rs.ScoaID=pr.ScoaProjectID
	WHERE (pr.Project_ID= @ProjectID  OR @ProjectID=0)
		AND (pr.ScoaProjectID=@ScoaProjectID  OR @ScoaProjectID= 0)
		AND FinYear = CASE WHEN @FinYear IS NULL OR @FinYear = '' OR @FinYear = '0' THEN FinYear ELSE @FinYear END

END
GO

