-- =================================================
-- Author:		Sahil Nagpal
-- Create date: 2017-Oct-27
-- Description:	#63164 Budget Register Changes
-- Plan_GetSCOAProjectsFBS_sp 0, 0, '2019/2020'
-- SNagpal 16-04-2019 : 84009, Get SCOA Segments based upon FinYear, 
-- OShiri 27-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- =================================================
CREATE PROCEDURE [dbo].[Plan_GetSCOAProjectsFBS_sp]
    @SCOAProjectFBSID INT,
	@SCOAId INT,
	@FinYear NVARCHAR(9)
AS
    BEGIN
	SET NOCOUNT ON;
	SET FMTONLY OFF;

	SELECT cnt.SCOAProjectFBS_Id ,
       cnt.ScoaId ,
	   cnt.IsEnable ,
	   cnt.FinYear,
	   csp.ScoaCode,
	   csp.NTScoaID,
	   csp.ScoaDesc,
	   csp.ScoaShortDesc,
	   csp.PostingLevel,
	   csp.BreakDownAllowed,
       cnt.CapturerID ,
       cnt.DateCaptured FROM dbo.Const_PlanSCOAProjectFBS cnt
	   INNER JOIN dbo.Const_SCOA_Project_Structure_ByYear(@FinYear) csp ON csp.ScoaID = cnt.ScoaId
	   WHERE
 ( CASE WHEN @SCOAProjectFBSID = 0 THEN 0
                       ELSE cnt.SCOAProjectFBS_Id
                  END = @SCOAProjectFBSID )
				  AND ( CASE WHEN @SCOAId= 0 THEN 0
                           ELSE cnt.SCOAId
                      END = @SCOAId )
				   AND ( CASE WHEN @FinYear = '' THEN ''
                           ELSE cnt.FinYear
                      END = @FinYear )

END;
GO

