/****** Object:  StoredProcedure [dbo].[Plan_GetSCOASegmentCountsByAdjustmentProjectId_sp]    Script Date: 2026/03/10 7:23:42 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 27/11/2017
-- Description: Get counts of SCOA Segments
-- dbo.Plan_GetSCOASegmentCountsByAdjustmentProjectId_sp 2310,'2016/2017'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetSCOASegmentCountsByAdjustmentProjectId_sp] 
@AdjustmentProjectID INT,
@UserFinYear NVARCHAR(10)
AS
    BEGIN
        SET NOCOUNT ON;

		DECLARE @AdjustmentVersionId INT;

		SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion WHERE VersionName 
		LIKE @UserFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

 SELECT  p.AdjustmentProject_ID ,
                COUNT(p.AdjustmentProject_ID) AS AdjustmentProjectCount 
                 ,(SELECT  COUNT(ppc.AdjustmentProjectCosting_ID) FROM dbo.Plan_AdjustmentProjectCosting ppc
				WHERE  p.AdjustmentProject_ID = ppc.AdjustmentProjectID AND ppc.AdjustmentVersionId = @AdjustmentVersionId) AS AdjustmentProjectCostingCount
                ,(SELECT  COUNT(ppf.AdjustmentProjectFunction_ID) FROM dbo.Plan_AdjustmentProjectFunctions ppf
				WHERE p.AdjustmentProject_ID = ppf.AdjustmentProjectID AND ppf.AdjustmentVersionId = @AdjustmentVersionId) AS AdjustmentProjectFunctionCount
				,(SELECT  COUNT(ppr.AdjustmentProjectRegion_ID) FROM dbo.Plan_AdjustmentProjectRegions ppr
				WHERE p.AdjustmentProject_ID = ppr.AdjustmentProjectID AND ppr.AdjustmentVersionId = @AdjustmentVersionId) AS AdjustmentProjectRegionCount
				,(SELECT  COUNT(ppfu.AdjustmentProjectFund_ID) FROM dbo.Plan_AdjustmentProjectFund ppfu
				WHERE  p.AdjustmentProject_ID = ppfu.AdjustmentProjectID AND ppfu.AdjustmentVersionId = @AdjustmentVersionId) AS AdjustmentProjectFundCount
				,(SELECT  COUNT(ppd.AdjustmentProjectDivision_ID) FROM dbo.Plan_AdjustmentProjectDivisions ppd
				WHERE  p.AdjustmentProject_ID = ppd.AdjustmentProjectID AND ppd.AdjustmentVersionId = @AdjustmentVersionId) AS AdjustmentProjectDivisionCount
                ,(SELECT  COUNT(ppi.PlanAdjustmentProjectItem_ID)  FROM dbo.Plan_AdjustmentProjectItem ppi
				WHERE p.AdjustmentProject_ID = ppi.AdjustmentProjectID AND ppi.AdjustmentVersionId = @AdjustmentVersionId) AS AdjustmentProjectItemCount
				,(SELECT (CASE WHEN (SUM(ppid.Percentage) = 100.00)
							   THEN  COUNT(ppid.ParentIDPItemID)
							   ELSE  0 END) AS idpCount FROM Plan_AdjustmentProjectIDP ppid
				 WHERE p.AdjustmentProject_ID = ppid.AdjustmentProjectID AND ppid.AdjustmentVersionId = @AdjustmentVersionId) AS AdjustmentProjectIDPCount
                ,(SELECT  COUNT(papr.AdjustmentProjectRecommendUser_Id)  FROM dbo.Plan_AdjustmentProjectRecommendUsers papr
				WHERE  p.AdjustmentProject_ID = papr.AdjustmentProjectId AND papr.AdjustmentVersionId = @AdjustmentVersionId) AS AdjustmentProjectRecommenderCount
				,p.ProjectStatus
        FROM    dbo.Plan_AdjustmentProject p
        WHERE   ( CASE WHEN @AdjustmentProjectID = 0 THEN 0
                       ELSE p.AdjustmentProject_ID
                  END = @AdjustmentProjectID ) AND p.AdjustmentVersionId = @AdjustmentVersionId
        GROUP BY p.AdjustmentProject_ID ,p.ReferenceProject_ID,
                p.ProjectStatus;

    END;

GO

/****** Object:  StoredProcedure [dbo].[Plan_GetSCOASegmentCountsByProjectId_sp]    Script Date: 2026/03/10 7:23:42 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author: Sahil Nagpal
-- Create date: 22 Dec 2016
-- Description: Get counts of SCOA Segments
-- dbo.Plan_GetSCOASegmentCountsByProjectId_sp 0
-- 28-Mar-2017 Snagpal #53397 : Add Left Join with Plan_ProjectIDP and calculate count accordingly and change the way of getting counts
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetSCOASegmentCountsByProjectId_sp] @ProjectID INT
AS
    BEGIN
        SET NOCOUNT ON;
 SELECT  p.Project_ID ,
                COUNT(p.Project_ID) AS ProjectCount 
                 ,(SELECT  COUNT(ppc.ProjectCosting_ID) FROM dbo.Plan_ProjectCosting ppc
				WHERE p.Project_ID = ppc.ProjectID) AS ProjectCostingCount
                ,(SELECT  COUNT(ppf.ProjectFunction_ID) FROM dbo.Plan_ProjectFunctions ppf
				WHERE p.Project_ID = ppf.ProjectID) AS ProjectFunctionCount
				,(SELECT  COUNT(ppr.ProjectRegion_ID) FROM dbo.Plan_ProjectRegions ppr
				WHERE p.Project_ID = ppr.ProjectID) AS ProjectRegionCount
				,(SELECT  COUNT(ppfu.ProjectFund_ID) FROM dbo.Plan_ProjectFund ppfu
				WHERE p.Project_ID = ppfu.ProjectID) AS ProjectFundCount
				,(SELECT  COUNT(ppd.ProjectDivision_ID) FROM dbo.Plan_ProjectDivisions ppd
				WHERE p.Project_ID = ppd.ProjectID) AS ProjectDivisionCount
                ,(SELECT  COUNT(ppi.PlanProjectItem_ID)  FROM dbo.Plan_ProjectItem ppi
				WHERE p.Project_ID = ppi.ProjectID) AS ProjectItemCount
				,(SELECT (CASE WHEN (SUM(ppid.Percentage) = 100.00)
							   THEN  COUNT(ppid.ParentIDPItemID)
							   ELSE  0 END) AS idpCount FROM Plan_ProjectIDP ppid
				 WHERE p.Project_ID = ppid.ProjectID) AS ProjectIDPCount
                ,p.ProjectStatus
        FROM    dbo.Plan_Project p
        WHERE   ( CASE WHEN @ProjectID = 0 THEN 0
                       ELSE p.Project_ID
                  END = @ProjectID )
        GROUP BY p.Project_ID ,
                p.ProjectStatus;

    END;

GO

/****** Object:  StoredProcedure [dbo].[Plan_GetSCOASegmentsCreditDebitDetails_sp]    Script Date: 2026/03/10 7:23:42 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- ============================================================================================          
-- Author:  Sahil Nagpal       
-- Create date: 01-Nov-2017
-- Description: #63164  Budget Register Changes  
-- exec Plan_GetSCOASegmentsCreditDebitDetails_sp 0,'SCOAItemAssetRevenueFBS','2016/2017'
-- SNagpal 06-11-2017 : Add Script for SegmentType = SCOAItemGainsLossesOR
-- 200422 by CM: 31990 - Reference multi year concept for SCOA item
-- ============================================================================================          
CREATE PROCEDURE [dbo].[Plan_GetSCOASegmentsCreditDebitDetails_sp]
    @ScoaID INT ,
    @SegmentType NVARCHAR(50) ,
    @FinYear NVARCHAR(9)
AS
    BEGIN
        IF ( @SegmentType = 'SCOAItemAssetRevenueFBS' )
		BEGIN
			SELECT  scoa.ScoaID, scoa.ScoaCode, scoa.NTScoaID,ISNULL(cps.CreditDebit,cpsa.CreditDebit)  AS SCOAItemCreditDebit
			FROM    Const_SCOA_Structure_ByYear(@FinYear) scoa
				LEFT JOIN dbo.Const_PlanSCOAItemRevenueFBS cps ON cps.ScoaItemId = scoa.ScoaID
				LEFT JOIN dbo.Const_PlanSCOAItemAssetFBS cpsa ON cpsa.ScoaItemId = scoa.ScoaID
				WHERE   scoa.ScoaID = @ScoaID AND
		(cps.IsEnable = 1 OR cpsa.IsEnable = 1) AND ( cps.FinYear = @FinYear OR cpsa.FinYear = @FinYear);
		END
		ELSE
         IF ( @SegmentType = 'SCOAItemGainsLossesOR' )
		BEGIN
			SELECT  scoa.ScoaID, scoa.ScoaCode, scoa.NTScoaID,ISNULL(cps.CreditDebit,cpsa.CreditDebit)  AS SCOAItemCreditDebit
			FROM    Const_SCOA_Structure_ByYear(@FinYear) scoa
				LEFT JOIN dbo.Const_PlanSCOAItemGainOR cps ON cps.ScoaItemId = scoa.ScoaID
				LEFT JOIN dbo.Const_PlanSCOAItemLossOE cpsa ON cpsa.ScoaItemId = scoa.ScoaID
				WHERE   scoa.ScoaID = @ScoaID AND
		(cps.IsEnable = 1 OR cpsa.IsEnable = 1) AND ( cps.FinYear = @FinYear OR cpsa.FinYear = @FinYear);
		END
	END
GO

