-- Create date: 13 Nov 2017
-- Description:	Get Supporting Documents For Funding Source
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetSupportingDocumentsForAdjustmentFundingSource_sp]
    @FundingSourceBudgetDetailID INT = 0,
    @SupportingDocID INT = 0
AS
BEGIN
    SET NOCOUNT ON;

    SELECT pfs.SupportingDocsID,
           pfs.AdjustmentFundingSourceBudgetDetailID,
           pfs.ScoaID,
           ss.Filename
    FROM dbo.Plan_AdjustmentFundingSourceDocs pfs
        INNER JOIN dbo.Sys_SupportingDocs ss
            ON pfs.SupportingDocsID = ss.SupportingDocs_ID
    WHERE (CASE
               WHEN @FundingSourceBudgetDetailID = 0 THEN
                   0
               ELSE
                   pfs.AdjustmentFundingSourceBudgetDetailID
           END = @FundingSourceBudgetDetailID
          )
          AND (CASE
                   WHEN @SupportingDocID = 0 THEN
                       0
                   ELSE
                       pfs.SupportingDocsID
               END = @SupportingDocID
              );
END;

GO

