-- =============================================
-- Author:		Sahil Nagpal
-- Create date: 2016-04-26
-- Description:	Get Track Changes for Project item changes
-- Call SP: Plan_GetTrackChangesForProjectItems_sp 0
-- SN: 28/04/2016 --Add DivisionId
-- SN: 09/05/2016 --Add INNER JOIN Plan_Project
-- CM: 12/08/2020 --4757: Return ProjectName in format ProjectCode + ' | ' + ProjectName
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetTrackChangesForProjectItems_sp]
	-- Add the parameters for the stored procedure here
    @ProjectId INT
AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets 
	-- interfering with SELECT statements.
        SET NOCOUNT ON;
        SELECT  ptc.PlanProjectItem_ID ,
                ptc.SCOAItemID ,
                ptc.ProjectID ,
                ptc.DivisionId ,
                CAST(ISNULL(Ppj.ProjectCode, Ppj.Project_ID) AS VARCHAR(50)) + ' | ' + Ppj.ProjectName AS ProjectName ,
                ptc.FinYear ,
                ISNULL(i.ItemDescription, '') AS ItemDescription ,
                ISNULL(CSS.ScoaDesc, '') AS SCOAItem ,
                ISNULL(CSFS.ScoaDesc, '') AS SCOAFunction ,
                ISNULL(CSFDS.ScoaDesc, '') AS SCOAFund ,
                ISNULL(CSRS.ScoaDesc, '') AS SCOARegion ,
                ISNULL(CD.DivisionDesc, '') AS Division ,
                ISNULL(ptc.OriginalBudgetAmount, 0) AS OriginalBudgetAmount ,
                ISNULL(ptc.OriginalBudgetAmountCurP1, 0) AS OriginalBudgetAmountCurP1 ,
                ISNULL(ptc.OriginalBudgetAmountCurP2, 0) AS OriginalBudgetAmountCurP2 ,
                ISNULL(ptc.RevisedBudgetAmount, 0) AS RevisedBudgetAmount ,
                ISNULL(ptc.RevisedBudgetAmountCurP1, 0) AS RevisedBudgetAmountCurP1 ,
                ISNULL(ptc.RevisedBudgetAmountCurP2, 0) AS RevisedBudgetAmountCurP2 ,
                ( uud.FirstName + ' ' + uud.LastName ) AS ChangedBy ,
                ptc.DateCaptured AS ChangedOn ,
                ptc.Comment ,
                ptc.CommentFor ,
                ptc.IsProjectDeleted
        FROM    dbo.Plan_TrackChanges ptc
                INNER JOIN dbo.User_UserDetail uud ON ptc.CapturerID = uud.User_ID
                INNER JOIN Plan_Project Ppj ON ptc.ProjectID = Ppj.Project_ID
                LEFT JOIN Const_ProjectItem i ON ptc.ProjectItemID = i.ProjectItem_ID
                LEFT OUTER JOIN dbo.Const_SCOA_Function_Structure CSFS ON CSFS.ScoaID = ptc.SCOAFunctionId
                LEFT OUTER JOIN dbo.Const_Division CD ON CD.Division_ID = ptc.DivisionId
                LEFT OUTER JOIN dbo.Const_SCOA_Funds_Structure CSFDS ON CSFDS.ScoaID = ptc.SCOAFundId
                LEFT OUTER JOIN dbo.Const_SCOA_Regional_Structure CSRS ON CSRS.ScoaID = ptc.SCOARegionId
                LEFT OUTER JOIN dbo.Const_SCOA_Structure CSS ON CSS.ScoaID = ptc.SCOAItemID
        WHERE   ( ptc.ProjectID = @ProjectId
                  OR @ProjectId = 0
                );
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetUpdateBudgetMigrationOfReservationCommitments_sp]    Script Date: 2026/03/10 7:23:43 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

 
 -- =============================================          
-- Author: Sahil Nagpal      
-- Create date:  04 Jun 2022  
-- Description: Script is for Migration of Reservation and Commitments 
-- Insert migration processes into Const_BudgetConsumptionProcess_Sys table
-- As per request by Nicola, Added Multiyear conditions, So only multiyear contract 
-- will be included in script and also added 127 BudgetConsumptionProcessID to balance void contracts
-- Added multiyear conditions on InitialLine -- PARSENAME(REPLACE(InitialLine , '_' , '.'),1) by Sahil
-- [Plan_GetUpdateBudgetMigrationOfReservationCommitments_sp] '2021/2022', '2022/2023',0
-- 21 Jul 2022 : SN : #89123 Modify PARSENAME(REPLACE(REPLACE(InitialLine , '_' , '.'),'-','.'),1)
-- 28 July 2022 : SN #89380  Manage logic of Initialine in case of Null
-- 26 SEPT 2022 : SN #90471 Fix Void Contract Issue
-- 01 Feb 2024 : SN #109998 Regression testing test case 101505
-- =============================================    
CREATE PROCEDURE [dbo].[Plan_GetUpdateBudgetMigrationOfReservationCommitments_sp] 
 @FromFinyear NVARCHAR(50) , 
@MigrationFinyear NVARCHAR(50),
@UpdateMigrationOnly Bit = 0

AS
BEGIN 

set nocount on;


   DECLARE @ErrorCode INT ,
            @OutputResult NVARCHAR(MAX)= '';
BEGIN TRY


Declare @ReservationMigration INT = 203,@CommitmentMigration INT = 204, 
@ContractCaptureProcessId INT = 125, @ContractVoidProcessId INT = 127
 
drop table if exists #ProjectsToMigrate
drop table if exists #ConsumptionProcessIdsToMigrate

Select distinct pp.Project_ID  into #ProjectsToMigrate from Plan_Project pp
inner join Plan_ProjectItem ppi on pp.Project_ID = ppi.ProjectID
Inner join SCM_RequisitionServiceDetails ss on ss.PlanProjectItemId = ppi.PlanProjectItem_ID
inner join SCM_Requisition sr on sr.Requisition_ID = ss.RequisitionID
where isnull(sr.MultiYear,0) = 1 and pp.FinYear = @FromFinyear

select BudgetConsumptionProcess_ID into #ConsumptionProcessIdsToMigrate
from Const_BudgetConsumptionProcess_Sys 
where BudgetConsumptionProcess_ID in (126, 164, 165, 127, 166, 131, 162, 163, 132, 133, 
									 135, 156, 134, 160, 161, 128, 129, 169, 130, 136, 137, 138, 139, 140, 141, 142, 143)

IF NOT EXISTS(SELECT 1 FROM Const_BudgetConsumptionProcess_Sys WHERE BudgetConsumptionProcess_ID = @ReservationMigration)
BEGIN
	INSERT INTO Const_BudgetConsumptionProcess_Sys (BudgetConsumptionProcess_ID, BudgetConsumptionProcessDesc, 
	BudgetConsumptionProcessEnabled, DateCaptured, CapturerID, DateModified, ModifierID)
	SELECT @ReservationMigration, 'Reservation Migration', 1, GETDATE(), 1, NULL, NULL
END

IF NOT EXISTS(SELECT 1 FROM Const_BudgetConsumptionProcess_Sys WHERE BudgetConsumptionProcess_ID = @CommitmentMigration)
BEGIN
	INSERT INTO Const_BudgetConsumptionProcess_Sys (BudgetConsumptionProcess_ID, BudgetConsumptionProcessDesc, 
	BudgetConsumptionProcessEnabled, DateCaptured, CapturerID, DateModified, ModifierID)
	SELECT @CommitmentMigration, 'Commitment Migration', 1, GETDATE(), 1, NULL, NULL
END


IF NOT EXISTS (SELECT 1 FROM Plan_BudgetConsumption 
				WHERE BudgetConsumptionProcessID IN (203, 204) and FinYear=@MigrationFinyear)
BEGIN

    -- At the request of Dore, I left only the calculation part here to customers can see previous fin year reservations and commitments without migration
    -- When they will be ready to migrate them just uncomment commented code and 
	--add ":r .\Updates\210406-DATA-SCM-000-63147_Update_BudgetsMigrationAfterRollover.sql" in PostDeployment script

	DROP TABLE IF EXISTS #RolloverResults
 
	CREATE TABLE #RolloverResults
	(
		PlanProjectItem_ID INT,
		ReservationsToRollover DECIMAL(18, 2),
		ReservationsMultiyearToRollover DECIMAL(18, 2),
		CommitmentsToRollover DECIMAL(18, 2)
	)
	
	INSERT INTO #RolloverResults
	SELECT
		PPINew.PlanProjectItem_ID,
		(ConsumedAmounts.ReservationsConsumed + Deltas.ReservationsDelta) + 
			IIF(ConsumedAmounts.ReservationsMultiyearConsumed + Deltas.ReservationsMultiyearDelta > PPINew.BudgetAmountCurP1, 
			PPINew.BudgetAmountCurP1, ConsumedAmounts.ReservationsMultiyearConsumed) AS ReservationsToRollover,
		IIF(ConsumedAmounts.ReservationsMultiyearConsumed + Deltas.ReservationsMultiyearDelta > PPINew.BudgetAmountCurP1,
			ConsumedAmounts.ReservationsMultiyearConsumed + Deltas.ReservationsMultiyearDelta - PPINew.BudgetAmountCurP1, 0) AS ReservationsMultiyearToRollover,
		ConsumedAmounts.CommitmentsConsumed + Deltas.CommitmentsDelta AS CommitmentsToRollover
	FROM Plan_ProjectItem PPI
	INNER JOIN Plan_ProjectItem PPINew
		ON PPINew.PreviousReferenceId = PPI.PlanProjectItem_ID
	INNER JOIN 
	(	
		SELECT 
			PlanProjectItemID,
			SUM(CASE WHEN BudgetConsumptionProcessID = @ContractVoidProcessId
			THEN -ABS(ConsumingTransactionAmount) ELSE -ConsumingTransactionAmount END) ReservationsConsumed,
			SUM(CASE WHEN BudgetConsumptionProcessID = @ContractVoidProcessId
			THEN -ABS(ISNULL(ConsumingTransactionAmountMultiyear, 0)) ELSE -ISNULL(ConsumingTransactionAmountMultiyear, 0) END) ReservationsMultiyearConsumed,
			0 AS CommitmentsConsumed
		FROM Plan_BudgetConsumption PBCInn
		INNER JOIN Plan_BudgetRollover BRInn
			ON BRInn.FromFinYear = PBCInn.FinYear
		WHERE BudgetConsumptionProcessID in( @ContractCaptureProcessId,@ContractVoidProcessId) --= 125 #Added 127 to balance the void contract by Sahil
			--AND PBCInn.DateCaptured < BRInn.DateCaptured
				AND PBCInn.PlanProjectItemID in (select ss.PlanProjectItemId from SCM_Requisition s
				inner join SCM_RequisitionServiceDetails ss on s.Requisition_ID = ss.RequisitionID where  s.MultiYear = 1)
				and (CASE WHEN TRY_CAST(PARSENAME(REPLACE(REPLACE(InitialLine , '_' , '.'),'-','.'),1) AS bigint) IS NULL   
				THEN PK_TransactionID  
				ELSE PARSENAME(REPLACE(REPLACE(InitialLine , '_' , '.'),'-','.'),1) END)
				in (select ss.RequisitionDetail_ID from SCM_Requisition s
				inner join SCM_RequisitionServiceDetails ss on s.Requisition_ID = ss.RequisitionID where  s.MultiYear = 1)
		GROUP BY 
			PBCInn.PlanProjectItemID
	) ConsumedAmounts
		ON ConsumedAmounts.PlanProjectItemID = PPI.PlanProjectItem_ID
	INNER JOIN 
	(
		SELECT
			PlanProjectItemID,
			SUM(ReservationsDelta) AS ReservationsDelta,
			SUM(ReservationsMultiyearDelta) AS ReservationsMultiyearDelta,
			SUM(CommitmentsDelta) AS CommitmentsDelta
		FROM
		(
			SELECT
				BudgetConsumptionProcessID,
				 (CASE WHEN TRY_CAST(PARSENAME(REPLACE(REPLACE(InitialLine , '_' , '.'),'-','.'),1) AS bigint) IS NULL   
				THEN PK_TransactionID  
				ELSE PARSENAME(REPLACE(REPLACE(InitialLine , '_' , '.'),'-','.'),1) END) as ReqDtlId,
				InitialLine,
				FinYear,
				DateCaptured,
				PlanProjectItemID,
				ReserveToDate - (LAG(ReserveToDate, 1, 0) 
				OVER (PARTITION BY PlanProjectItemID ORDER BY BudgetConsumption_ID)) AS ReservationsDelta,
				ReserveToDateMultiyear - (LAG(ReserveToDateMultiyear, 1, 0)
				OVER (PARTITION BY PlanProjectItemID ORDER BY BudgetConsumption_ID)) AS ReservationsMultiyearDelta,
				CommitToDate - (LAG(CommitToDate, 1, 0) OVER (PARTITION BY PlanProjectItemID ORDER BY BudgetConsumption_ID)) AS CommitmentsDelta
			FROM Plan_BudgetConsumption PBCInn
			--where PBCInn.PlanProjectItemID in (select ss.PlanProjectItemId from SCM_Requisition s
			--	inner join SCM_RequisitionServiceDetails ss on s.Requisition_ID = ss.RequisitionID where  isnull(s.MultiYear,0) = 1)
		) Details
		INNER JOIN Plan_BudgetRollover BRInn
			ON BRInn.FromFinYear = Details.FinYear
		WHERE BudgetConsumptionProcessID IN (Select BudgetConsumptionProcess_ID from #ConsumptionProcessIdsToMigrate)
			AND Details.InitialLine IN (SELECT pb.InitialLine FROM Plan_BudgetConsumption pb WHERE BudgetConsumptionProcessID = @ContractCaptureProcessId)
			and ReqDtlId in (select ss.RequisitionDetail_ID from SCM_Requisition s
			inner join SCM_RequisitionServiceDetails ss on s.Requisition_ID = ss.RequisitionID where  s.MultiYear = 1)
			--AND Details.DateCaptured < BRInn.DateCaptured
		GROUP BY PlanProjectItemID
	) Deltas
		ON Deltas.PlanProjectItemID = PPI.PlanProjectItem_ID
		where PPI.PlanProjectItem_ID in (select ss.PlanProjectItemId from SCM_Requisition s
		inner join SCM_RequisitionServiceDetails ss on s.Requisition_ID = ss.RequisitionID where  s.MultiYear = 1)
		and PPI.ProjectID  IN ( select Project_ID from #ProjectsToMigrate ) 
		
		--AND PPINew.PlanProjectItem_ID =19017 -- #where condition added by Sahil for MULTIYEAR Requisitions
 
 if(@UpdateMigrationOnly = 1)
	BEGIN

		-- Reservations Migration
	INSERT INTO Plan_BudgetConsumption
	(
		FinYear
        ,PlanProjectItemID
        ,BudgetTransactionTypeID
        ,ModuleID
        ,PK_TransactionID
        ,TransactionTableName
        ,ConsumingTransactionAmount
        ,ConsumingTransactionAmountMultiyear
        ,AdjustedTansactionAmount
        ,AvailableBudget
        ,AvailableBudgetMultiyear
        ,ProcessingMonth
        ,BudgetConsumptionProcessID
        ,OriginalBudgetToDate
        ,AdjustedBudgetToDate
        ,CapturedExpenditureToDate
        ,CapturedExpenditureToDateMultiyear
        ,ReserveToDate
        ,ReserveToDateMultiyear
        ,CommitToDate
        ,ActualToDate
        ,CurrentlyConsumedAmount
        ,CurrentlyConsumedAmountMultiyear
        ,InitialLine
        ,CapturerID
        ,DateCaptured
        ,ModifierID
        ,DateModified
	)
	SELECT FinYear
        ,PlanProjectItemID
        ,2										--BudgetTransactionTypeID
        ,10										--ModuleID
        ,PlanProjectItemID						--PK_TransactionID
        ,'Plan_ProjectItem'						--TransactionTableName
        ,-RR.ReservationsToRollover				--ConsumingTransactionAmount
        ,-RR.ReservationsMultiyearToRollover	--ConsumingTransactionAmountMultiyear
        ,0										--AdjustedTansactionAmount
        ,AvailableBudget - RR.ReservationsToRollover
        ,AvailableBudgetMultiyear - RR.ReservationsMultiyearToRollover
        ,1										--ProcessingMonth
        ,@ReservationMigration									--BudgetConsumptionProcessID
        ,OriginalBudgetToDate
        ,AdjustedBudgetToDate
        ,CapturedExpenditureToDate
        ,CapturedExpenditureToDateMultiyear
        ,ReserveToDate + RR.ReservationsToRollover
        ,ReserveToDateMultiyear + RR.ReservationsMultiyearToRollover
        ,CommitToDate
        ,ActualToDate
        ,RR.ReservationsToRollover + RR.ReservationsMultiyearToRollover		--CurrentlyConsumedAmount
        ,0											--CurrentlyConsumedAmountMultiyear
        ,'Plan_ProjectItem_' + CAST(PlanProjectItemID AS VARCHAR(16))		--InitialLine
        ,1											--CapturerID
        ,GETDATE()									--DateCaptured
        ,NULL										--ModifierID
        ,NULL										--DateModified
	FROM 
		#RolloverResults RR
		OUTER APPLY
			(
				SELECT TOP 1 * 
				FROM dbo.Plan_BudgetConsumption b
				WHERE b.PlanProjectItemID = RR.PlanProjectItem_ID 
				ORDER BY b.BudgetConsumption_ID DESC
			) BC		
	WHERE ABS(RR.ReservationsToRollover) + ABS(RR.ReservationsMultiyearToRollover) <> 0

	
			
	---- Commitments Migration
	INSERT INTO Plan_BudgetConsumption
	(
		FinYear
        ,PlanProjectItemID
        ,BudgetTransactionTypeID
        ,ModuleID
        ,PK_TransactionID
        ,TransactionTableName
        ,ConsumingTransactionAmount
        ,ConsumingTransactionAmountMultiyear
        ,AdjustedTansactionAmount
        ,AvailableBudget
        ,AvailableBudgetMultiyear
        ,ProcessingMonth
        ,BudgetConsumptionProcessID
        ,OriginalBudgetToDate
        ,AdjustedBudgetToDate
        ,CapturedExpenditureToDate
        ,CapturedExpenditureToDateMultiyear
        ,ReserveToDate
        ,ReserveToDateMultiyear
        ,CommitToDate
        ,ActualToDate
        ,CurrentlyConsumedAmount
        ,CurrentlyConsumedAmountMultiyear
        ,InitialLine
        ,CapturerID
        ,DateCaptured
        ,ModifierID
        ,DateModified
	)
	SELECT 
		FinYear
        ,PlanProjectItemID
        ,3										--BudgetTransactionTypeID
        ,10										--ModuleID
        ,PlanProjectItemID						--PK_TransactionID
        ,'Plan_ProjectItem'						--TransactionTableName
        ,-RR.CommitmentsToRollover				--ConsumingTransactionAmount
        ,0										--ConsumingTransactionAmountMultiyear
        ,0										--AdjustedTansactionAmount
        ,AvailableBudget - RR.CommitmentsToRollover
        ,AvailableBudgetMultiyear
        ,1										--ProcessingMonth
        ,@CommitmentMigration									--BudgetConsumptionProcessID
        ,OriginalBudgetToDate
        ,AdjustedBudgetToDate
        ,CapturedExpenditureToDate
        ,CapturedExpenditureToDateMultiyear
        ,ReserveToDate
        ,ReserveToDateMultiyear
        ,CommitToDate + RR.CommitmentsToRollover
        ,ActualToDate
        ,RR.CommitmentsToRollover		--CurrentlyConsumedAmount
        ,0											--CurrentlyConsumedAmountMultiyear
        ,'Plan_ProjectItem_' + CAST(PlanProjectItemID AS VARCHAR(16))		--InitialLine
        ,1											--CapturerID
        ,GETDATE()									--DateCaptured
        ,NULL										--ModifierID
        ,NULL										--DateModified
	FROM 
		#RolloverResults RR
		OUTER APPLY
			(
				SELECT TOP 1 * 
				FROM dbo.Plan_BudgetConsumption b
				WHERE b.PlanProjectItemID = RR.PlanProjectItem_ID 
				ORDER BY b.BudgetConsumption_ID DESC
			) BC
	WHERE RR.CommitmentsToRollover != 0
	END

set @OutputResult = 'Success';

END

END TRY
BEGIN CATCH
		IF @@Trancount > 0 
		BEGIN 
			INSERT INTo Sys_ErrorLog (moduleName, pageName, procedureName, errorMessage, errorType, detailedErrorMessage, errorDate, userName)
			VALUES ('Planning','SQL Server','Plan_GetBudgetMigrationOfReservationCommitments_sp', ERROR_MESSAGE(), 'SQL', ERROR_MESSAGE(), GETDATE(), 'SQL')
			
			DECLARE  @Err NVARCHAR(1000)
			Set @err = Error_message()
			Raiserror (@Err, 16,1)
			set @OutputResult = @Err
		END
END CATCH

select pp.Project_ID, pp.ProjectCode, pp.ProjectName, rr.PlanProjectItem_ID,
		(cd.DivisionCode + ' / ' + cd.DivisionDesc + ':' + dep.DepartmentDesc) AS MuniClassification,
		   func.ScoaCode AS SCOAFuncCode,
           func.ScoaDesc AS SCOAFuncDesc,
           region.ScoaCode AS SCOARegionCode,
           region.ScoaDesc AS SCOARegionDesc,
           costing.ScoaCode AS SCOACostingCode,
           costing.ScoaDesc AS SCOACostingDesc,
           project.ScoaCode AS SCOAProjectCode,
           project.ScoaDesc AS SCOAProjectDesc,
           fs.ScoaCode AS SCOAFundCode,
           fs.ScoaDesc AS SCOAFundDesc,
           item.ScoaCode AS SCOAItemCode,
           item.ScoaDesc AS SCOAItemDesc,
		   ppi.BudgetAmount as CurrentYearBudget,
		   rr.ReservationsToRollover as ReservationsAmountToRollover,
		   rr.ReservationsMultiyearToRollover as ReservationsAmountToRollover1,
		   rr.CommitmentsToRollover as CommitmentsAmountToRollover,
		   CASE WHEN (ISNULL(ppi.BudgetAmount,0) - rr.ReservationsToRollover) < 0 THEN 0 ELSE 1 END as IsSufficientBudget,
		   @OutputResult as MigrationResult
		from #RolloverResults rr
		INNER JOIN Plan_ProjectItem ppi on rr.PlanProjectItem_ID = ppi.PlanProjectItem_ID
		INNER JOIN Plan_Project pp on pp.Project_ID = ppi.ProjectID
		INNER JOIN Const_Division cd
            ON cd.Division_ID = ppi.DivisionId
        INNER JOIN Const_Department dep
            ON cd.DepartmentID = dep.Department_ID
        INNER JOIN Const_SCOA_Function_Structure_ByYear(@MigrationFinyear) func
            ON func.ScoaID = ppi.SCOAFunctionId
        INNER JOIN Const_SCOA_Regional_Structure_ByYear(@MigrationFinyear) region
            ON region.ScoaID = ppi.SCOARegionId
        INNER JOIN Const_SCOA_Costing_Structure_ByYear(@MigrationFinyear) costing
            ON costing.ScoaID = ppi.SCOACostingID
        INNER JOIN Const_SCOA_Project_Structure_ByYear(@MigrationFinyear) project
            ON project.ScoaID = pp.ScoaProjectID
        INNER JOIN Const_SCOA_Structure_ByYear(@MigrationFinyear) item
            ON item.ScoaID = ppi.SCOAItemID
        INNER JOIN dbo.Const_SCOA_Funds_Structure_ByYear(@MigrationFinyear) fs
            ON ppi.SCOAFundId = fs.ScoaID
			order by pp.Project_ID;

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetVirementBudgetSplitDetailsReport_sp]    Script Date: 2026/03/10 7:23:43 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		SAHIL NAGPAL
-- Create date: 2017-01-12
-- Description:	Get Budget Split Details using Virement
-- Plan_GetVirementBudgetSplitDetailsReport_sp 11,'From'
-- 10-02-2017 SNagpal: Add TransferFromTo to filter the results
-- 22-Jan-2018 : #60259 Comment Static Case When condition of  ppi.BudgetSplitId = 1 - 'Manually'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetVirementBudgetSplitDetailsReport_sp]
	-- Add the parameters for the stored procedure here
    @VirementId INT = 0,
	@TransferFromto VARCHAR(10)
AS
    SET NOCOUNT ON;
    BEGIN
        SELECT  pvs.VirementId ,
                pvs.AdjustmentId ,
				--(CASE WHEN
    --            PVS.BudgetSplitId = 1
				--THEN 'Manually'
				--ELSE cbso.BudgetSplitDesc
				--END) 
				cbso.BudgetSplitDesc AS BudgetSplitDesc,
				pvs.TransferFromTo,
                pvs.Month1Price ,
                pvs.Month2Price ,
                pvs.Month3Price ,
                pvs.Month4Price ,
                pvs.Month5Price ,
                pvs.Month6Price ,
                pvs.Month7Price ,
                pvs.Month8Price ,
                pvs.Month9Price ,
                pvs.Month10Price ,
                pvs.Month11Price ,
                pvs.Month12Price ,
                pvs.Month13Price ,
                pvs.Month14Price
        FROM    dbo.Plan_VirementBudgetSplit pvs
                LEFT JOIN dbo.Const_BudgetSplitOptions cbso ON cbso.DivideBy_ID= pvs.BudgetSplitId AND cbso.Enabled=1
        WHERE   VirementId = @VirementId AND pvs.TransferFromTo=@TransferFromto;
    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetVirementCountsByVirementId_sp]    Script Date: 2026/03/10 7:23:43 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author: Sahil Nagpal
-- Create date: 27 Jan 2017
-- Description: Get counts of Virement
-- dbo.Plan_GetVirementCountsByVirementId_sp 0
-- 06-02-2017 SNagpal: Modify Where Constraint for VirementId
-- 09-08-2017 SNagpal: Add If condition in case of @VirementID =0
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetVirementCountsByVirementId_sp] @VirementID INT
AS
    BEGIN
        SET NOCOUNT ON;
		IF(@VirementID = 0)
		SET @VirementID = -1

        SELECT  p.VirementId ,
                COUNT(p.VirementId) AS VirementCount ,
                COUNT(pvb.VirementBudgetSplit_Id) AS BudgetSplitCount ,
                COUNT(pva.VirementApprovalUserId) AS ProjectFunctionCount,
				p.VirementStatus 
        FROM    dbo.Plan_Virements p
                LEFT JOIN dbo.Plan_VirementBudgetSplit pvb ON pvb.VirementId = p.VirementId
                LEFT JOIN dbo.Plan_VirementApprovalUsers pva ON pva.VirementId = p.VirementId
		WHERE    p.VirementId = @VirementID
        GROUP BY p.VirementId,p.VirementStatus 

    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_GetVirementDetailsById_sp]    Script Date: 2026/03/10 7:23:43 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Sahil Nagpal
-- Create date: 2017-01-23
-- Description:	Get Virement Details
-- Call SP: Plan_GetVirementDetailsById_sp 0
-- 06-02-2017 SNagpal: Add Left Join with Const_ProjectItem as requirement of ItemDescription & also add FromProjectItemId , ToProjectItemId
-- =============================================
CREATE PROCEDURE [dbo].[Plan_GetVirementDetailsById_sp]
    @VirementId INT
AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;       

		SELECT V.VirementId ,V.FinYear,
		V.FromProjectId,V.ToProjectId,
		V.FromSCOAProjectID,V.ToSCOAProjectID,	
		V.FromSCOAFunctionId,V.ToSCOAFunctionId,
		V.FromDivisionId, V.ToDivisionId,
		V.FromSCOAFundID,V.ToSCOAFundID,	
		V.FromSCOARegion AS FromSCOARegionId ,
		V.ToSCOARegion AS ToSCOARegionId ,
		V.FromSCOAItem AS FromSCOAItemId, 
		V.ToSCOAItem AS ToSFromSCOAItemId ,
		V.FromSCOACostingId, ToSCOACostingId,
        ISNULL(V.FromAvailableFund, 0) AS FromAvailableFund ,
        ISNULL(V.ToAvailableFund, 0) AS ToAvailableFund,
		ISNULL(V.FromVirementAmount, 0) AS FromVirementAmount ,
        ISNULL(V.ToVirementAmount, 0) AS ToVirementAmount,
		ISNULL(V.FromNewAvailableBudget, 0) AS FromNewAvailableBudget ,
        ISNULL(V.ToNewAvailableBudget, 0) AS ToNewAvailableBudget,
		V.VirementReferenceNumber,V.FromCapitalOperation,V.ToCapitalOperation,
		V.VirementStatus, V.UploadedVirementDoc,V.IsNewItemAdded, V.ReasonForVirement, V.FromProjectItemId, V.ToProjectItemId, cpiTo.ItemDescription
        FROM    dbo.Plan_Virements V 
		LEFT JOIN dbo.Const_ProjectItem cpiTo ON cpiTo.ProjectItem_ID = V.ToProjectItemId
        WHERE  ( CASE WHEN @VirementId = 0 THEN 0
                       ELSE V.VirementId
                  END = @VirementId )
    END;

	
GO

/****** Object:  StoredProcedure [dbo].[Plan_ImportAssetBudgetReportResults_sp]    Script Date: 2026/03/10 7:23:43 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author: Raindree C and Nkanyiso S 		
-- Create date: 30 Apr 2016
-- Description:	Import Asset Budget Report Results
-- 2016-05-05 by SN: Make FundingSourceID  -> 0 in insert Statement
-- 2016-05-05 by SN: Add update Statement for PLan_project
-- 2016-05-09 by SN: Add script to insert data for future year as well in Funding detail table
-- 2016-05-09 by RC: Only look at items that have budget value>0
-- 2016-05-26 by SN: Add join contraints of PBR.SCOAItemID = PPI.SCOAItemID; AND PBR.SCOAFunctionID = PPI.SCOAFunctionId AND PBR.DivisionID = PPI.DivisionId 
-- 2016-05-26 by SN: AND PBR.SCOARegionID = PPI.SCOARegionId AND PBR.SCOAFundsID = PPI.SCOAFundId while inserting data into Plan_projectItemMonth
-- 2016-05-26 by SN: Set BudgetSplitID = 12 for Plan_ProjectItem
-- 2016-11-22 by SNagpal: Change the way of getting SCOA Costing, Before it was from Plan_Project . but now one project have multiple SCOA Costing, So make changes accordingly
-- 01-02-2017 By SNagpal: Passed FinYear into Planing_GetFundAllocatedAmount function as a parameter
-- 18-02-2017 by DRS: Discuss with Tshikedi, add new parameter to select the budget type 
-- =============================================
CREATE PROCEDURE [dbo].[Plan_ImportAssetBudgetReportResults_sp]

	@Type nvarchar(100)
AS
	

    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;

        DECLARE @Result NVARCHAR(MAX);


        BEGIN TRY

            BEGIN TRAN;

    ---------------------------------------------------------
	-- DELETE DATA 
	---------------------------------------------------------

	-- DELETE DATA FROM Plan_ProjectCosting
            --SELECT  * FROM    
            DELETE  PPC
            FROM    Plan_ProjectCosting PPC
                    INNER JOIN Assets_BudgetReportForPlanning ABR ON ABR.ProjectID = PPC.ProjectID And ABR.[Type] = @Type
                    INNER JOIN Plan_Project PP ON PP.Project_ID = ABR.ProjectID;


	-- DELETE DATA FROM Plan_ProjectFunctions
            --SELECT  * FROM    
            DELETE  PPF
            FROM    Plan_ProjectFunctions PPF
                    INNER JOIN Assets_BudgetReportForPlanning ABR ON ABR.ProjectID = PPF.ProjectID And ABR.[Type] = @Type
                    INNER JOIN Plan_Project PP ON PP.Project_ID = ABR.ProjectID;

-- DELETE DATA FROM PLAN_ProjectRegions
            --SELECT  *  FROM    
            DELETE  PPR
            FROM    Plan_ProjectRegions PPR 
                    INNER JOIN Assets_BudgetReportForPlanning ABR ON ABR.ProjectID = PPR.ProjectID And ABR.[Type] = @Type
                    INNER JOIN Plan_Project PP ON PP.Project_ID = ABR.ProjectID;

-- DELETE DATA FROM PLAN_ProjectDivisions
          --  SELECT  * FROM    
            DELETE  PPD
            FROM    Plan_ProjectDivisions PPD
                    INNER JOIN Assets_BudgetReportForPlanning ABR ON ABR.ProjectID = PPD.ProjectID
                    INNER JOIN Plan_Project PP ON PP.Project_ID = ABR.ProjectID;

-- DELETE DATA FROM Plan_ProjectFundYear
            --SELECT  *
            --FROM    --
            DELETE  PPFY
            FROM    dbo.Plan_ProjectFundYear PPFY
                    INNER JOIN dbo.Plan_ProjectFund PPF ON PPF.ProjectFund_ID = PPFY.ProjectFundID
                    INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPF.ProjectID
                    INNER JOIN dbo.Assets_BudgetReportForPlanning ABR ON ABR.ProjectID = PP.Project_ID And ABR.[Type] = @Type;

-- DELETE DATA FROM Plan_ProjectFund
            --SELECT  *  FROM    
            DELETE  PPF
            FROM    dbo.Plan_ProjectFund PPF
                    INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPF.ProjectID
                    INNER JOIN dbo.Assets_BudgetReportForPlanning ABR ON ABR.ProjectID = PP.Project_ID And ABR.[Type] = @Type;

-- DELETE DATA FROM Plan_ProjectItemMonth
            --SELECT  * FROM    
            DELETE  PPIM
            FROM    dbo.Plan_ProjectItemMonth PPIM
                    INNER JOIN dbo.Plan_ProjectItem PPI ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                    INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                    INNER JOIN dbo.Assets_BudgetReportForPlanning ABR ON ABR.ProjectID = PP.Project_ID And ABR.[Type] = @Type;

-- DELETE DATA FROM Plan_ProjectItem
            --SELECT  *            FROM    
            DELETE  PPI
            FROM    dbo.Plan_ProjectItem PPI
                    INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                    INNER JOIN dbo.Assets_BudgetReportForPlanning ABR ON ABR.ProjectID = PP.Project_ID And ABR.[Type] = @Type;

-- INSERT DATA FROM Plan_ProjectCosting
            INSERT  INTO dbo.Plan_ProjectCosting
                    ( ProjectID ,
                      ScoaCostingID ,
                      CapturerID ,
                      DateCaptured ,
                      ModifierID ,
                      DateModified
                    )
                    SELECT DISTINCT
                            ABR.ProjectID ,
                            ABR.SCOACostingID ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    Assets_BudgetReportForPlanning ABR
                            INNER JOIN Plan_Project PP ON PP.Project_ID = ABR.ProjectID And ABR.[Type] = @Type;


-- INSERT DATA FROM Plan_ProjectFunctions
            INSERT  INTO dbo.Plan_ProjectFunctions
                    ( ProjectID ,
                      ScoaFunctionID ,
                      CapturerID ,
                      DateCaptured ,
                      ModifierID ,
                      DateModified
                    )
                    SELECT DISTINCT
                            ABR.ProjectID ,
                            ABR.SCOAFunctionID ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    Assets_BudgetReportForPlanning ABR
                            INNER JOIN Plan_Project PP ON PP.Project_ID = ABR.ProjectID And ABR.[Type] = @Type;

-- INSERT DATA FROM PLAN_ProjectRegions
            INSERT  INTO dbo.Plan_ProjectRegions
                    ( ProjectID ,
                      ScoaRegionID ,
                      RegionPercent ,
                      CapturerID ,
                      DateCaptured ,
                      ModifierID ,
                      DateModified
                    )
                    SELECT DISTINCT
                            ABR.ProjectID ,
                            ABR.SCOARegionID ,
                            100 ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    Assets_BudgetReportForPlanning ABR
                            INNER JOIN Plan_Project PP ON PP.Project_ID = ABR.ProjectID And ABR.[Type] = @Type;

-- INSERT DATA FROM PLAN_ProjectDivisions
            INSERT  INTO dbo.Plan_ProjectDivisions
                    ( ProjectID ,
                      DivisionID ,
                      CapturerID ,
                      DateCaptured ,
                      ModifierID ,
                      DateModified
                    )
                    SELECT DISTINCT
                            ABR.ProjectID ,
                            ABR.DivisionID ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    Assets_BudgetReportForPlanning ABR
                            INNER JOIN Plan_Project PP ON PP.Project_ID = ABR.ProjectID And ABR.[Type] = @Type;

-- INSERT DATA FROM Plan_ProjectFund
            INSERT  INTO dbo.Plan_ProjectFund
                    ( ProjectID ,
                      ScoaFundID ,
                      FundAmount ,
                      CapturerID ,
                      DateCaptured ,
                      ModifierID ,
                      DateModified ,
                      FundReference
                    )
                    SELECT  ABR.ProjectID ,
                            ABR.SCOAFundsID ,
                            SUM(ISNULL(ABR.BudgetCurrentYear, 0)
                                + ISNULL(ABR.BudgetCurrentYearPlus1, 0)
                                + ISNULL(ABR.BudgetCurrentYearPlus2, 0)) AS FundAmount ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL ,
                            NULL AS FundReference
                    FROM    dbo.Plan_Project PP
                            INNER JOIN dbo.Assets_BudgetReportForPlanning ABR ON ABR.ProjectID = PP.Project_ID
                    GROUP BY ABR.ProjectID ,
                            ABR.SCOAFundsID;

-- INSERT DATA FROM Plan_ProjectFundYear
            INSERT  INTO dbo.Plan_ProjectFundYear
                    ( ProjectFundID ,
                      FinYear ,
                      YearFundAmount ,
                      CapturerID ,
                      DateCaptured ,
                      ModifierID ,
                      DateModified
                    )
                    SELECT  PPF.ProjectFund_ID ,
                            PP.FinYear ,
                            SUM(ISNULL(ABR.BudgetCurrentYear, 0)) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectFund PPF
                            INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPF.ProjectID
                            INNER JOIN dbo.Assets_BudgetReportForPlanning ABR ON ABR.ProjectID = PP.Project_ID
                                                              AND ABR.SCOAFundsID = PPF.ScoaFundID And ABR.[Type] = @Type
                    GROUP BY ABR.ProjectID ,
                            ABR.SCOAFundsID ,
                            PPF.ProjectFund_ID ,
                            PP.FinYear
                    UNION
                    SELECT  PPF.ProjectFund_ID ,
                            SUBSTRING(PP.FinYear, 6, 4) + '/'
                            + CAST(CAST(SUBSTRING(PP.FinYear, 6, 4) AS INT)
                            + 1 AS NVARCHAR(10)) AS CurrYear1 ,
                            SUM(ISNULL(ABR.BudgetCurrentYearPlus1, 0)) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectFund PPF
                            INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPF.ProjectID
                            INNER JOIN dbo.Assets_BudgetReportForPlanning ABR ON ABR.ProjectID = PP.Project_ID
                                                              AND ABR.SCOAFundsID = PPF.ScoaFundID And ABR.[Type] = @Type
                    GROUP BY ABR.ProjectID ,
                            ABR.SCOAFundsID ,
                            PPF.ProjectFund_ID ,
                            PP.FinYear
                    UNION
                    SELECT  PPF.ProjectFund_ID ,
                            CAST(CAST(SUBSTRING(PP.FinYear, 6, 4) AS INT) + 1 AS NVARCHAR(10))
                            + '/'
                            + CAST(CAST(SUBSTRING(PP.FinYear, 6, 4) AS INT)
                            + 2 AS NVARCHAR(10)) AS CurrYear2 ,
                            SUM(ISNULL(ABR.BudgetCurrentYearPlus2, 0)) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectFund PPF
                            INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPF.ProjectID
                            INNER JOIN dbo.Assets_BudgetReportForPlanning ABR ON ABR.ProjectID = PP.Project_ID
                                                              AND ABR.SCOAFundsID = PPF.ScoaFundID 
							Where ABR.[Type] = @Type
                    GROUP BY ABR.ProjectID ,
                            ABR.SCOAFundsID ,
                            PPF.ProjectFund_ID ,
                            PP.FinYear;

--Update ScoaProjectID,SCOACostingID in  Plan_Project Table

            UPDATE  Plan_Project
            SET     ScoaProjectID = newPP.SCOAProjectID 
                   -- SCOACostingID = newPP.SCOACostingID
--select * 
            FROM    Plan_Project origPP
                    INNER JOIN ( SELECT DISTINCT
                                        pb.SCOAProjectID ,
                                        --pb.SCOACostingID ,
                                        ProjectID
                                 FROM   Plan_Project pp
                                        INNER JOIN Assets_BudgetReportForPlanning pb ON pp.Project_ID = pb.ProjectID
										Where pb.[Type] = @Type
                               ) newPP ON origPP.Project_ID = newPP.ProjectID;




-- INSERT DATA FROM Plan_ProjectItem
            INSERT  INTO dbo.Plan_ProjectItem
                    ( ProjectID ,
                      ProjectItemID ,
                      SCOAItemID ,
                      FinYear ,
                      CapturerID ,
                      DateCaptured ,
                      ModifierID ,
                      DateModified ,
                      ProjectFundYearID ,
                      BudgetAmount ,
                      BudgetAmountCurP1 ,
                      BudgetAmountCurP2 ,
                      SCOAFunctionId ,
					  SCOACostingID,
                      SCOAFundId ,
                      SCOARegionId ,
