                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectItem PPI --  INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                            INNER JOIN dbo.Assets_BudgetReportForPlanning ABR ON ABR.ProjectID = PPI.ProjectID
                                                              AND ABR.SCOAItemID = PPI.SCOAItemID --Add by SN
															   AND ABR.SCOACostingID = PPI.SCOACostingID
                                                              AND ABR.SCOAFunctionID = PPI.SCOAFunctionId
                                                              AND ABR.DivisionID = PPI.DivisionId --Add by SN
                                                              AND ABR.SCOARegionID = PPI.SCOARegionId
                                                              AND ABR.SCOAFundsID = PPI.SCOAFundId --Add by SN
															  And ABR.[Type] = @Type -- DRS
                    GROUP BY PPI.PlanProjectItem_ID
                    HAVING  SUM(ABR.BudgetCurrentYear)
                            + SUM(ABR.BudgetCurrentYearPlus1)
                            + SUM(ABR.BudgetCurrentYearPlus2) > 0
                    UNION
                    SELECT  PPI.PlanProjectItem_ID ,
                            10 ,
                            1 ,
                            SUM(ABR.Month10Budget) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectItem PPI --   INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                            INNER JOIN dbo.Assets_BudgetReportForPlanning ABR ON ABR.ProjectID = PPI.ProjectID
                                                              AND ABR.SCOAItemID = PPI.SCOAItemID --Add by SN
															   AND ABR.SCOACostingID = PPI.SCOACostingID
                                                              AND ABR.SCOAFunctionID = PPI.SCOAFunctionId
                                                              AND ABR.DivisionID = PPI.DivisionId --Add by SN
                                                              AND ABR.SCOARegionID = PPI.SCOARegionId
                                                              AND ABR.SCOAFundsID = PPI.SCOAFundId --Add by SN
															  And ABR.[Type] = @Type -- DRS
                    GROUP BY PPI.PlanProjectItem_ID
                    HAVING  SUM(ABR.BudgetCurrentYear)
                            + SUM(ABR.BudgetCurrentYearPlus1)
                            + SUM(ABR.BudgetCurrentYearPlus2) > 0
                    UNION
                    SELECT  PPI.PlanProjectItem_ID ,
                            11 ,
                            1 ,
                            SUM(ABR.Month11Budget) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectItem PPI --   INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                            INNER JOIN dbo.Assets_BudgetReportForPlanning ABR ON ABR.ProjectID = PPI.ProjectID
                                                              AND ABR.SCOAItemID = PPI.SCOAItemID --Add by SN
															   AND ABR.SCOACostingID = PPI.SCOACostingID
                                                              AND ABR.SCOAFunctionID = PPI.SCOAFunctionId
                                                              AND ABR.DivisionID = PPI.DivisionId --Add by SN
                                                              AND ABR.SCOARegionID = PPI.SCOARegionId
                                                              AND ABR.SCOAFundsID = PPI.SCOAFundId --Add by SN
															  And ABR.[Type] = @Type -- DRS
                    GROUP BY PPI.PlanProjectItem_ID
                    HAVING  SUM(ABR.BudgetCurrentYear)
                            + SUM(ABR.BudgetCurrentYearPlus1)
                            + SUM(ABR.BudgetCurrentYearPlus2) > 0
                    UNION
                    SELECT  PPI.PlanProjectItem_ID ,
                            12 ,
                            1 ,
                            SUM(ABR.Month12Budget) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectItem PPI --  INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                            INNER JOIN dbo.Assets_BudgetReportForPlanning ABR ON ABR.ProjectID = PPI.ProjectID
                                                              AND ABR.SCOAItemID = PPI.SCOAItemID --Add by SN
															   AND ABR.SCOACostingID = PPI.SCOACostingID
                                                              AND ABR.SCOAFunctionID = PPI.SCOAFunctionId
                                                              AND ABR.DivisionID = PPI.DivisionId --Add by SN
                                                              AND ABR.SCOARegionID = PPI.SCOARegionId
                                                              AND ABR.SCOAFundsID = PPI.SCOAFundId --Add by SN
															  And ABR.[Type] = @Type -- DRS
                    GROUP BY PPI.PlanProjectItem_ID
                    HAVING  SUM(ABR.BudgetCurrentYear)
                            + SUM(ABR.BudgetCurrentYearPlus1)
                            + SUM(ABR.BudgetCurrentYearPlus2) > 0;

------------------------------------------------------------------------------
-- Set FundingSourceBudget for New Allocation of Budget Amount
------------------------------------------------------------------------------

            DECLARE @FinYear NVARCHAR(9) = '' ,
                @FundSourceHeaderID INT = 0;

            SELECT TOP 1
                    @FinYear = pp.FinYear
            FROM    Assets_BudgetReportForPlanning pb
                    INNER JOIN dbo.Plan_Project pp ON pb.ProjectID = pp.Project_ID And pb.[Type] = @Type ;-- DRS

            DECLARE @StartFinYear INT = 0;
            DECLARE @CurrFinYear VARCHAR(20);
            WHILE ( @StartFinYear <= 2 )
                BEGIN

                    SELECT  @CurrFinYear = CASE WHEN @StartFinYear = 0
                                                THEN @FinYear
                                                WHEN @StartFinYear = 1
                                                THEN CAST(CAST(SUBSTRING(@FinYear,
                                                              0, 5) AS INT)
                                                     + 1 AS NVARCHAR(10))
                                                     + '/'
                                                     + CAST(CAST(SUBSTRING(@FinYear,
                                                              0, 5) AS INT)
                                                     + 2 AS NVARCHAR(10))
                                                WHEN @StartFinYear = 2
                                                THEN CAST(CAST(SUBSTRING(@FinYear,
                                                              0, 5) AS INT)
                                                     + 2 AS NVARCHAR(10))
                                                     + '/'
                                                     + CAST(CAST(SUBSTRING(@FinYear,
                                                              0, 5) AS INT)
                                                     + 3 AS NVARCHAR(10))
                                                ELSE '2015/2016'
                                           END;


                    SELECT TOP 1
                            @FundSourceHeaderID = FundingSourceBudgetHeader_ID
                    FROM    Plan_FundingSourceBudget_Header
                    WHERE   FinancialYear = @CurrFinYear;

                    PRINT @FundSourceHeaderID;
                    PRINT @CurrFinYear;

------------------------------------------------------------------------------
-- Update Budget Amount for Existing Fund Id
------------------------------------------------------------------------------

                    UPDATE  dbo.Plan_FundingSourceBudget_Detail
                    SET     FundingSourceBudget = FundingSourceBudget
                            + CASE WHEN FundBal.Remain < 0
                                   THEN ( FundBal.Remain * -1 )
                                        + FundBal.NwAllocAmount
                                   WHEN FundBal.Remain > 0
                                        AND FundBal.Actual < FundBal.NwAllocAmount
                                   THEN FundBal.NwAllocAmount
                                   ELSE 0
                              END
--SELECT  * ,
--        CASE WHEN FundBal.Remain < 0
--             THEN ( FundBal.Remain * -1 ) + FundBal.NwAllocAmount
--             WHEN FundBal.Remain > 0
--                  AND FundBal.Actual < FundBal.NwAllocAmount
--             THEN FundBal.NwAllocAmount
--             ELSE 0
--        END AS UpdateAmount
                    FROM    ( SELECT    SCOAFundsID ,
                                        @FundSourceHeaderID AS FundSourceHeaderId ,
                                        HRBudget.NwAllocAmount ,
                                        HRBudget.Budget AS Actual ,
                                        HRBudget.Budget - HRBudget.Allocated AS Remain
                              FROM      ( SELECT    R.SCOAFundsID ,
                                                    ( CASE WHEN @StartFinYear = 0
                                                           THEN SUM(BudgetCurrentYear)
                                                           WHEN @StartFinYear = 1
                                                           THEN SUM(R.BudgetCurrentYearPlus1)
                                                           WHEN @StartFinYear = 2
                                                           THEN SUM(R.BudgetCurrentYearPlus2)
                                                      END ) AS NwAllocAmount ,
                                                    ISNULL(dbo.Planing_GetFundAvailableAmount(R.SCOAFundsID,
                                                              @CurrFinYear), 0) AS Budget ,
                                                    ISNULL(dbo.Planing_GetFundAllocatedAmount(R.SCOAFundsID,
                                                              @CurrFinYear,@FinYear), 0) AS Allocated
                                          FROM      [dbo].[Assets_BudgetReportForPlanning] R
										  Where R.[Type] = @Type
                                          GROUP BY  R.SCOAFundsID
                                          HAVING    SUM(R.BudgetCurrentYear)
                                                    + SUM(R.BudgetCurrentYearPlus1)
                                                    + SUM(R.BudgetCurrentYearPlus2) > 0
                                        ) AS HRBudget
                            ) AS FundBal
                            INNER JOIN ( SELECT ScoaID AS FundId ,
                                                FundingSourceBudgetHeaderID AS BudgetHeaderId ,
                                                MIN(FundingSourceBudgetDetail_ID) AS UpdateFundingSourceBudgetDetailID
                                         FROM   Plan_FundingSourceBudget_Detail
                                         WHERE  FundingSourceBudgetHeaderID = @FundSourceHeaderID
                                         GROUP BY ScoaID ,
                                                FundingSourceBudgetHeaderID
                                       ) AS UpdateBal ON FundBal.SCOAFundsID = UpdateBal.FundId
                                                         AND FundBal.FundSourceHeaderId = UpdateBal.BudgetHeaderId
-- Condition to get Data to be Updated for Plan_FundingSourceBudget_Detail
                    WHERE   Plan_FundingSourceBudget_Detail.FundingSourceBudgetHeaderID = @FundSourceHeaderID
                            AND ScoaID = FundBal.SCOAFundsID
                            AND Plan_FundingSourceBudget_Detail.FundingSourceBudgetDetail_ID = UpdateFundingSourceBudgetDetailID;

------------------------------------------------------------------------------
-- Create Budget Detail for Budget Amount for Fund Id not found 
------------------------------------------------------------------------------
                    INSERT  INTO dbo.Plan_FundingSourceBudget_Detail
                            ( FundingSourceBudgetHeaderID ,
                              FundingSourceID ,
                              ScoaID ,
                              FundingSourceBudget ,
                              DateCaptured ,
                              CapturerID ,
                              DateModified ,
                              ModifierID
                            )
                            SELECT  @FundSourceHeaderID ,
                                    0 ,
                                    R.SCOAFundsID ,
                                    ( CASE WHEN @StartFinYear = 0
                                           THEN SUM(BudgetCurrentYear)
                                           WHEN @StartFinYear = 1
                                           THEN SUM(R.BudgetCurrentYearPlus1)
                                           WHEN @StartFinYear = 2
                                           THEN SUM(R.BudgetCurrentYearPlus2)
                                      END ) AS NwAllocAmount ,
                                    GETDATE() ,
                                    1 ,
                                    NULL ,
                                    NULL
                            FROM    [dbo].[Assets_BudgetReportForPlanning] R
                            WHERE   ISNULL(dbo.Planing_GetFundAvailableAmount(R.SCOAFundsID,
                                                              @CurrFinYear), 0) = 0 And R.[Type] = @Type
                            GROUP BY R.SCOAFundsID
                            HAVING  SUM(R.BudgetCurrentYear)
                                    + SUM(R.BudgetCurrentYearPlus1)
                                    + SUM(R.BudgetCurrentYearPlus2) > 0;
                    SET @StartFinYear = @StartFinYear + 1;
                END;
            COMMIT TRAN;

            SELECT  @Result = 'Data Imported Successfully';

        END TRY
        BEGIN CATCH
            ROLLBACK TRAN;

            SELECT  @Result = ERROR_MESSAGE();
        END CATCH;

        SELECT  @Result AS Result;

    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_ImportBudgetAmountIntoPlanBudgetRegister_sp]    Script Date: 2026/03/10 7:23:43 AM ******/
