GO

-- =============================================
-- THIS STORED PROCEDURE IS ONLY FOR NMBM DATABASE-- Don't DELETE--
-- Author:	Sahil Nagpal
-- Create date: 25/05/2017
-- Description : Import Budget Amount Into Plan_BudgetRegister
-- THIS STORED PROCEDURE IS ONLY FOR NMBM DATABASE-- Don't DELETE--
-- THIS STORED PROCEDURE IS ONLY FOR NMBM DATABASE-- Don't DELETE--
-- EXEC Plan_ImportBudgetAmountIntoPlanBudgetRegister_sp
-- 23/08/2017 RChetty/SNagpal : change script to use Optional1 and not ProjectID as PlanProjectItemID.
-- =============================================
CREATE PROCEDURE [dbo].[Plan_ImportBudgetAmountIntoPlanBudgetRegister_sp]
@TableName VARCHAR(50) = 'GL_TransactionsImport',
@TableNameExp VARCHAR(50) = 'EMS_SenquBudget_Live_Exceptions'

AS
BEGIN
SET NOCOUNT ON;

BEGIN TRAN
BEGIN TRY

DECLARE @BudgetTxnTypeId INT, @ModuleId INT, @CapturedDate DATETIME = GETDATE(), @strScript NVARCHAR(MAX);

SELECT  @BudgetTxnTypeId = BudgetTransactionType_ID FROM dbo.Const_BudgetTransactionType_sys WHERE BudgetTransDesc = 'Imported'
SELECT @ModuleId = Module_ID FROM dbo.User_Module WHERE ModuleDesc='Planning';

SET @strScript = '
IF NOT EXISTS (SELECT 1 FROM [dbo].' + @TableNameExp + ' WHERE ExceptionDetail IS NOT NULL AND ExceptionDetail <> '''')
BEGIN
INSERT INTO dbo.Plan_BudgetRegister
	        ( PlanProjectItemID ,BudgetTransactionTypeID ,ModuleID , PK_TransactionID ,TransactionTableName ,
	          TransactionAmount , AvailableBudget , CapturerID , DateCaptured , FinYear
	        )
	
        SELECT  PlanProjectItemID,' + CAST (@BudgetTxnTypeId AS VARCHAR(20)) + ',' + CAST (@ModuleId AS VARCHAR(20)) + ',RowNumber,''' + @TableName + ''',
		CreditDebitAmount, (AvailableBudget + CreditDebitAmount), 1,
		 DATEADD(ms,D.RowNumber, GETDATE())
		 ,FinYear
        FROM    ( SELECT    A.BudgetRegister_ID ,
                            A.PlanProjectItemID ,
                            A.AvailableBudget ,
                            ROW_NUMBER() OVER ( PARTITION BY A.PlanProjectItemID ORDER BY DateCaptured DESC ) AS RN
                  FROM      Plan_BudgetRegister A
                ) M
                INNER JOIN ( SELECT Optional1 , RowNumber,FinYear,
                                    (CASE WHEN ABS(ISNULL(Credit,0)) = 0 THEN -ABS(Debit) ELSE ABS(Credit) END) AS CreditDebitAmount
                             FROM   ' + @TableName + '
                             
                           ) D ON M.RN = 1
                AND M.PlanProjectItemID = D.Optional1; END;
				ELSE
				BEGIN
				PRINT (''Import not processed as Sum of Credit Debit Amount is greater than Available budget for some records.'');
				END'
				--PRINT (@strScript);
				EXEC(@strScript);
COMMIT TRAN;

END TRY
BEGIN CATCH
    DECLARE @ErrorNumber INT = ERROR_NUMBER();
    DECLARE @ErrorLine INT = ERROR_LINE();
    DECLARE @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
    DECLARE @ErrorSeverity INT = ERROR_SEVERITY();
    DECLARE @ErrorState INT = ERROR_STATE();

    PRINT 'Actual error number: ' + CAST(@ErrorNumber AS VARCHAR(10));
    PRINT 'Actual line number: ' + CAST(@ErrorLine AS VARCHAR(10));
    PRINT 'Actual line MESSAGE: ' + CAST(@ErrorMessage AS VARCHAR(1000));
    RAISERROR(@ErrorMessage, @ErrorSeverity, @ErrorState);
    ROLLBACK;
END CATCH; 

END;
GO

