-- Description : Import Budget Amount Into Plan_BudgetRegister
-- THIS STORED PROCEDURE IS ONLY FOR NMBM DATABASE-- Don't DELETE--
-- THIS STORED PROCEDURE IS ONLY FOR NMBM DATABASE-- Don't DELETE--
-- EXEC Plan_ImportBudgetAmountValidation_sp
-- 23/08/2017 RChetty/SNagpal : change script to use Optional1 and not ProjectID as PlanProjectItemID.  Addition exception table is now being used not exception on same table
--                              exclude SCOAProjectCode<>''63348E37-464E-4AC0-A13A-E577838FF961'' from Validation as per Gansen and Martin
-- =============================================
CREATE PROCEDURE [dbo].[Plan_ImportBudgetAmountValidation_sp]
@TableName VARCHAR(50) = 'GL_TransactionsImport',
@TableNameExp VARCHAR(50) = 'EMS_SenquBudget_Live_Exceptions',
@RunBy VARCHAR(50) = 'Christian Khanyezi'

AS
BEGIN
SET NOCOUNT ON;

BEGIN TRAN
BEGIN TRY

DECLARE @strScript VARCHAR(Max);

SET @strScript = 'INSERT INTO ' + @TableNameExp + ' 

SELECT [RowNumber]
      ,[PostingDate]
      ,[ProcessingMonth]
      ,[SCOAItem]
      ,[FinYear]
      ,[TransactionTypeID]
      ,[TransactionDetails]
      ,[DocumentNumber]
      ,[Debit]
      ,[Credit]
      ,[SCOAFundsCode]
      ,[SCOARegionCode]
      ,[SCOACostingCode]
      ,[SCOAProjectCode]
      ,[SCOAFunctionCode]
      ,[CaptureDate]
      ,[SourceModuleID]
      ,[DivisionID]
      ,[EntryType]
      ,[SourceCode]
      ,[TransActRef]
      ,[ProjectID]
      ,[AssetID]
      ,[ItemCode]
      ,[ItemDesc]
      ,[DocType]
      ,[DocDesc]
      ,[Reference]
      ,[CategoryID]
      ,[SubCatID]
      ,[Optional1]
      ,[Optional2]
      ,[DateStamp]
      ,[UploadedBy]
      ,[FileName]
      ,[ScriptRunStartDate]=GetDate()
      ,[ScriptRunEndDate]=GetDate()
      ,[ScriptRunByName]=''' + @RunBy +'''
      ,[ExceptionDetail]=''Sum of Credit Debit Amount is greater than Available budget''
 FROM ' + @TableName + ' 
 WHERE Optional1 IN (
  SELECT PlanProjectItemID 
 FROM 
 (SELECT A.BudgetRegister_ID, A.PlanProjectItemID, A.AvailableBudget, ROW_NUMBER() OVER (PARTITION BY A.PlanProjectItemID ORDER BY DateCaptured  DESC) AS RN
 FROM Plan_BudgetRegister A
 ) M
 INNER JOIN  
 (
 SELECT Optional1, (SUM(Credit) + SUM(-ABS(Debit))) AS Budget
 FROM ' + @TableName + ' 
 WHERE SCOAProjectCode<>''63348E37-464E-4AC0-A13A-E577838FF961''
 GROUP BY Optional1
 ) D ON M.RN = 1 AND M.PlanProjectItemID = D.Optional1
WHERE M.AvailableBudget < D.Budget
 )'

 EXEC (@strScript)
COMMIT TRAN;

END TRY
BEGIN CATCH
    DECLARE @ErrorNumber INT = ERROR_NUMBER();
    DECLARE @ErrorLine INT = ERROR_LINE();
    DECLARE @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
    DECLARE @ErrorSeverity INT = ERROR_SEVERITY();
    DECLARE @ErrorState INT = ERROR_STATE();

    PRINT 'Actual error number: ' + CAST(@ErrorNumber AS VARCHAR(10));
    PRINT 'Actual line number: ' + CAST(@ErrorLine AS VARCHAR(10));
    PRINT 'Actual line MESSAGE: ' + CAST(@ErrorMessage AS VARCHAR(1000));
    RAISERROR(@ErrorMessage, @ErrorSeverity, @ErrorState);
    ROLLBACK;
END CATCH; 

END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_ImportHRBudgetReportResults_sp]    Script Date: 2026/03/10 7:23:43 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
