-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 11 Apr 2016
-- Description:	Import HR Budget Report Results
-- CALL SP: Plan_ImportHRBudgetReportResults_sp
-- 2016-04-12 by JP: Add Sum of (CurrentYear + CurrentPlus1 + CurrentPlus2) Budget and Group by for Plan_ProjectFund, Plan_ProjectFundYear
-- 2016-04-12 by JP: Set BudgetSplitID = null for Plan_ProjectItem
-- 2016-04-12 by JP: Add Script for Updating Funding Source Budget Amount in case where Actual Budget for Fund is less than what is needed
-- 2016-04-14 by RC: Issues with Project item amount sorted.
-- 2016-05-05 by SN: Make FundingSourceID  -> 0 in insert Statement
-- 2016-05-05 by SN: Add update Statement for PLan_project
-- 2016-05-06 by SN: Add  Payroll_BudgetReportResultsForPlanning pb INNER JOIN dbo.Plan_Project pp ON pb.ProjectID = pp.Project_ID
-- 2016-05-06 by SN: Add script to insert data for future year as well in Funding detail table
-- 2016-05-26 by SN: Add join contraints of PBR.SCOAItemID = PPI.SCOAItemID; AND PBR.SCOAFunctionID = PPI.SCOAFunctionId AND PBR.DivisionID = PPI.DivisionId 
-- 2016-05-26 by SN: AND PBR.SCOARegionID = PPI.SCOARegionId AND PBR.SCOAFundsID = PPI.SCOAFundId while inserting data into Plan_projectItemMonth
-- 2016-05-26 by SN: Set BudgetSplitID = 12 for Plan_ProjectItem
-- 2016-11-22 by SNagpal: Change the way of getting SCOA Costing, Before it was from Plan_Project . but now one project have multiple SCOA Costing, So make changes accordingly
-- 01-02-2017 By SNagpal: Passed FinYear into Planing_GetFundAllocatedAmount function as a parameter
-- =============================================
CREATE PROCEDURE [dbo].[Plan_ImportHRBudgetReportResults_sp]
AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;

        DECLARE @Result NVARCHAR(MAX);


        BEGIN TRY

            BEGIN TRAN;

    ---------------------------------------------------------
	-- DELETE DATA 
	---------------------------------------------------------
	-- DELETE DATA FROM Plan_ProjectCosting
            --SELECT  * FROM    
            DELETE  PPC
            FROM    Plan_ProjectCosting PPC
                    INNER JOIN Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PPC.ProjectID
                    INNER JOIN Plan_Project PP ON PP.Project_ID = PBR.ProjectID;

	-- DELETE DATA FROM Plan_ProjectFunctions
            --SELECT  * FROM    
            DELETE  PPF
            FROM    Plan_ProjectFunctions PPF
                    INNER JOIN Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PPF.ProjectID
                    INNER JOIN Plan_Project PP ON PP.Project_ID = PBR.ProjectID;

-- DELETE DATA FROM PLAN_ProjectRegions
            --SELECT  *  FROM    
            DELETE  PPR
            FROM    Plan_ProjectRegions PPR
                    INNER JOIN Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PPR.ProjectID
                    INNER JOIN Plan_Project PP ON PP.Project_ID = PBR.ProjectID;

-- DELETE DATA FROM PLAN_ProjectDivisions
          --  SELECT  * FROM    
            DELETE  PPD
            FROM    Plan_ProjectDivisions PPD
                    INNER JOIN Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PPD.ProjectID
                    INNER JOIN Plan_Project PP ON PP.Project_ID = PBR.ProjectID;

-- DELETE DATA FROM Plan_ProjectFundYear
            --SELECT  *
            --FROM    --
            DELETE  PPFY
            FROM    dbo.Plan_ProjectFundYear PPFY
                    INNER JOIN dbo.Plan_ProjectFund PPF ON PPF.ProjectFund_ID = PPFY.ProjectFundID
                    INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPF.ProjectID
                    INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PP.Project_ID;

-- DELETE DATA FROM Plan_ProjectFund
            --SELECT  *  FROM    
            DELETE  PPF
            FROM    dbo.Plan_ProjectFund PPF
     INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPF.ProjectID
                    INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PP.Project_ID;

-- DELETE DATA FROM Plan_ProjectItemMonth
            --SELECT  * FROM    
            DELETE  PPIM
            FROM    dbo.Plan_ProjectItemMonth PPIM
                    INNER JOIN dbo.Plan_ProjectItem PPI ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                    INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                    INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PP.Project_ID;

-- DELETE DATA FROM Plan_ProjectItem
            --SELECT  *            FROM    
            DELETE  PPI
            FROM    dbo.Plan_ProjectItem PPI
                    INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                    INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PP.Project_ID;

					-- INSERT DATA FROM Plan_ProjectCosting
            INSERT  INTO dbo.Plan_ProjectCosting
                    ( ProjectID ,
                      ScoaCostingID ,
                      CapturerID ,
                      DateCaptured ,
                      ModifierID ,
                      DateModified
                    )
                    SELECT DISTINCT
                            PBR.ProjectID ,
                            PBR.SCOACostingID ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    Payroll_BudgetReportResultsForPlanning PBR
                            INNER JOIN Plan_Project PP ON PP.Project_ID = PBR.ProjectID;


-- INSERT DATA FROM Plan_ProjectFunctions
            INSERT  INTO dbo.Plan_ProjectFunctions
                    ( ProjectID ,
                      ScoaFunctionID ,
                      CapturerID ,
                      DateCaptured ,
                      ModifierID ,
                      DateModified
                    )
                    SELECT DISTINCT
                            PBR.ProjectID ,
                            PBR.SCOAFunctionID ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    Payroll_BudgetReportResultsForPlanning PBR
                            INNER JOIN Plan_Project PP ON PP.Project_ID = PBR.ProjectID;

-- INSERT DATA FROM PLAN_ProjectRegions
            INSERT  INTO dbo.Plan_ProjectRegions
                    ( ProjectID ,
                      ScoaRegionID ,
                      RegionPercent ,
                      CapturerID ,
                      DateCaptured ,
                      ModifierID ,
                      DateModified
                    )
                    SELECT DISTINCT
                            PBR.ProjectID ,
                            PBR.SCOARegionID ,
                            100 ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    Payroll_BudgetReportResultsForPlanning PBR
                            INNER JOIN Plan_Project PP ON PP.Project_ID = PBR.ProjectID;

-- INSERT DATA FROM PLAN_ProjectDivisions
            INSERT  INTO dbo.Plan_ProjectDivisions
                    ( ProjectID ,
                      DivisionID ,
                      CapturerID ,
                      DateCaptured ,
                      ModifierID ,
                      DateModified
                    )
                    SELECT DISTINCT
                            PBR.ProjectID ,
                            PBR.DivisionID ,
                            1 ,
                            GETDATE() ,
                            NULL ,
       NULL
                    FROM    Payroll_BudgetReportResultsForPlanning PBR
                            INNER JOIN Plan_Project PP ON PP.Project_ID = PBR.ProjectID;

-- INSERT DATA FROM Plan_ProjectFund
            INSERT  INTO dbo.Plan_ProjectFund
                    ( ProjectID ,
                      ScoaFundID ,
                      FundAmount ,
                      CapturerID ,
                      DateCaptured ,
                      ModifierID ,
                      DateModified ,
                      FundReference
                    )
                    SELECT  PBR.ProjectID ,
                            PBR.SCOAFundsID ,
                            SUM(ISNULL(PBR.BudgetCurrentYear, 0)
                                + ISNULL(PBR.BudgetCurrentYearPlus1, 0)
                                + ISNULL(PBR.BudgetCurrentYearPlus2, 0)) AS FundAmount ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL ,
                            NULL AS FundReference
                    FROM    dbo.Plan_Project PP
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PP.Project_ID
                    GROUP BY PBR.ProjectID ,
                            PBR.SCOAFundsID;

-- INSERT DATA FROM Plan_ProjectFundYear
            INSERT  INTO dbo.Plan_ProjectFundYear
                    ( ProjectFundID ,
                      FinYear ,
                      YearFundAmount ,
                      CapturerID ,
                      DateCaptured ,
                      ModifierID ,
                      DateModified
                    )
                    SELECT  PPF.ProjectFund_ID ,
                            PP.FinYear ,
                            SUM(ISNULL(PBR.BudgetCurrentYear, 0)) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectFund PPF
                            INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPF.ProjectID
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PP.Project_ID
                                                              AND PBR.SCOAFundsID = PPF.ScoaFundID
                    GROUP BY PBR.ProjectID ,
                            PBR.SCOAFundsID ,
                            PPF.ProjectFund_ID ,
                            PP.FinYear
                    UNION
                    SELECT  PPF.ProjectFund_ID ,
                            SUBSTRING(PP.FinYear, 6, 4) + '/'
                            + CAST(CAST(SUBSTRING(PP.FinYear, 6, 4) AS INT)
                            + 1 AS NVARCHAR(10)) AS CurrYear1 ,
                            SUM(ISNULL(PBR.BudgetCurrentYearPlus1, 0)) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectFund PPF
                            INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPF.ProjectID
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PP.Project_ID
                                                              AND PBR.SCOAFundsID = PPF.ScoaFundID
                    GROUP BY PBR.ProjectID ,
                            PBR.SCOAFundsID ,
                            PPF.ProjectFund_ID ,
                            PP.FinYear
                    UNION
                    SELECT  PPF.ProjectFund_ID ,
                            CAST(CAST(SUBSTRING(PP.FinYear, 6, 4) AS INT) + 1 AS NVARCHAR(10))
                            + '/'
                            + CAST(CAST(SUBSTRING(PP.FinYear, 6, 4) AS INT)
                            + 2 AS NVARCHAR(10)) AS CurrYear2 ,
               SUM(ISNULL(PBR.BudgetCurrentYearPlus2, 0)) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectFund PPF
                            INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPF.ProjectID
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PP.Project_ID
                                                              AND PBR.SCOAFundsID = PPF.ScoaFundID
                    GROUP BY PBR.ProjectID ,
                            PBR.SCOAFundsID ,
                            PPF.ProjectFund_ID ,
                            PP.FinYear;

--Update ScoaProjectID,SCOACostingID in  Plan_Project Table

            UPDATE  Plan_Project
            SET     ScoaProjectID = newPP.SCOAProjectID 
                 --   SCOACostingID = newPP.SCOACostingID
--select * 
            FROM    Plan_Project origPP
                    INNER JOIN ( SELECT DISTINCT
                                        pb.SCOAProjectID ,
                                        --pb.SCOACostingID ,
                                        ProjectID
                                 FROM   Plan_Project pp
                                        INNER JOIN Payroll_BudgetReportResultsForPlanning pb ON pp.Project_ID = pb.ProjectID
                               ) newPP ON origPP.Project_ID = newPP.ProjectID;


-- INSERT DATA FROM Plan_ProjectItem
            INSERT  INTO dbo.Plan_ProjectItem
                    ( ProjectID ,
                      ProjectItemID ,
                      SCOAItemID ,
                      FinYear ,
                      CapturerID ,
                      DateCaptured ,
                      ModifierID ,
                      DateModified ,
                      ProjectFundYearID ,
                      BudgetAmount ,
                      BudgetAmountCurP1 ,
                      BudgetAmountCurP2 ,
					  SCOACostingID,
                      SCOAFunctionId ,
                      SCOAFundId ,
                      SCOARegionId ,
                      DivisionId ,
                      BudgetSplitID
                    )
                    SELECT  PBR.ProjectID ,
                            NULL AS ProjectItemID ,
                            PBR.SCOAItemID ,
                            PP.FinYear ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL ,
                            PPFY.ProjectFundYear_ID AS ProjectFundYearID ,
                            SUM(PBR.BudgetCurrentYear) ,
                            SUM(PBR.BudgetCurrentYearPlus1) ,
                            SUM(PBR.BudgetCurrentYearPlus2) ,
							PBR.SCOACostingID,
                            PBR.SCOAFunctionID ,
                            PBR.SCOAFundsID ,
                            PBR.SCOARegionID ,
                            PBR.DivisionID ,
                            12
                    FROM    dbo.Plan_Project PP
                            INNER JOIN dbo.Plan_ProjectFund PPF ON PPF.ProjectID = PP.Project_ID
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PP.Project_ID
                                                              AND PBR.SCOAFundsID = PPF.ScoaFundID
                            INNER JOIN dbo.Plan_ProjectFundYear PPFY ON PPFY.ProjectFundID = PPF.ProjectFund_ID
                                                              AND PPFY.FinYear = PP.FinYear
                                                            --  AND PP.FinYear = PBR.FinYear
                    GROUP BY PBR.ProjectID ,
                            PBR.SCOAItemID ,
                            PP.FinYear ,
                            PPFY.ProjectFundYear_ID ,
                  PBR.SCOACostingID ,
							PBR.SCOAFunctionID ,
                            PBR.SCOAFundsID ,
                            PBR.SCOARegionID ,
                            PBR.DivisionID;

-- INSERT DATA FROM Plan_ProjectItemMonth
            INSERT  INTO dbo.Plan_ProjectItemMonth
                    ( PlanProjectItemID ,
                      MonthID ,
                      UnitQuantity ,
                      UnitPrice ,
                      CaptureID ,
                      DateCaptured ,
                      ModifierID ,
                      DateModified
                    )
                    SELECT  PPI.PlanProjectItem_ID ,
                            1 ,
                            1 ,
                            SUM(PBR.Month1Budget) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectItem PPI --  INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PPI.ProjectID
                                                              AND PBR.SCOAItemID = PPI.SCOAItemID --Add by SN
															  AND PBR.SCOACostingID = PPI.SCOACostingID
                                                              AND PBR.SCOAFunctionID = PPI.SCOAFunctionId
                                                              AND PBR.DivisionID = PPI.DivisionId --Add by SN
                                                              AND PBR.SCOARegionID = PPI.SCOARegionId
                                                              AND PBR.SCOAFundsID = PPI.SCOAFundId --Add by SN
                    GROUP BY PPI.PlanProjectItem_ID
                    UNION
                    SELECT  PPI.PlanProjectItem_ID ,
                            2 ,
                            1 ,
                            SUM(PBR.Month2Budget) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectItem PPI --  INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PPI.ProjectID
                                                              AND PBR.SCOAItemID = PPI.SCOAItemID --Add by SN
															  AND PBR.SCOACostingID = PPI.SCOACostingID
                                                              AND PBR.SCOAFunctionID = PPI.SCOAFunctionId
                                                              AND PBR.DivisionID = PPI.DivisionId --Add by SN
                                                              AND PBR.SCOARegionID = PPI.SCOARegionId
                                                              AND PBR.SCOAFundsID = PPI.SCOAFundId --Add by SN
                    GROUP BY PPI.PlanProjectItem_ID
                    UNION
                    SELECT  PPI.PlanProjectItem_ID ,
                            3 ,
                            1 ,
                            SUM(PBR.Month3Budget) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectItem PPI --     INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PPI.ProjectID
                                                              AND PBR.SCOAItemID = PPI.SCOAItemID --Add by SN
															  AND PBR.SCOACostingID = PPI.SCOACostingID
                                                              AND PBR.SCOAFunctionID = PPI.SCOAFunctionId
          AND PBR.DivisionID = PPI.DivisionId --Add by SN
                                                              AND PBR.SCOARegionID = PPI.SCOARegionId
                                                              AND PBR.SCOAFundsID = PPI.SCOAFundId --Add by SN
                    GROUP BY PPI.PlanProjectItem_ID
                    UNION
                    SELECT  PPI.PlanProjectItem_ID ,
                            4 ,
                            1 ,
                            SUM(PBR.Month4Budget) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectItem PPI --     INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PPI.ProjectID
                                                              AND PBR.SCOAItemID = PPI.SCOAItemID --Add by SN
															  AND PBR.SCOACostingID = PPI.SCOACostingID
                                                              AND PBR.SCOAFunctionID = PPI.SCOAFunctionId
                                                              AND PBR.DivisionID = PPI.DivisionId --Add by SN
                                                              AND PBR.SCOARegionID = PPI.SCOARegionId
                                                              AND PBR.SCOAFundsID = PPI.SCOAFundId --Add by SN
                    GROUP BY PPI.PlanProjectItem_ID
                    UNION
                    SELECT  PPI.PlanProjectItem_ID ,
                            5 ,
                            1 ,
                            SUM(PBR.Month5Budget) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectItem PPI --    INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PPI.ProjectID
                                                              AND PBR.SCOAItemID = PPI.SCOAItemID --Add by SN
															  AND PBR.SCOACostingID = PPI.SCOACostingID
                                                              AND PBR.SCOAFunctionID = PPI.SCOAFunctionId
                                                              AND PBR.DivisionID = PPI.DivisionId --Add by SN
                                                              AND PBR.SCOARegionID = PPI.SCOARegionId
                                                              AND PBR.SCOAFundsID = PPI.SCOAFundId --Add by SN
                    GROUP BY PPI.PlanProjectItem_ID
                    UNION
                    SELECT  PPI.PlanProjectItem_ID ,
                            6 ,
                            1 ,
                            SUM(PBR.Month6Budget) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectItem PPI -- INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PPI.ProjectID
                                                              AND PBR.SCOAItemID = PPI.SCOAItemID --Add by SN
															  AND PBR.SCOACostingID = PPI.SCOACostingID
                                                              AND PBR.SCOAFunctionID = PPI.SCOAFunctionId
                                                              AND PBR.DivisionID = PPI.DivisionId --Add by SN
                                                              AND PBR.SCOARegionID = PPI.SCOARegionId
                                                              AND PBR.SCOAFundsID = PPI.SCOAFundId --Add by SN
                    GROUP BY PPI.PlanProjectItem_ID
                    UNION
                    SELECT  PPI.PlanProjectItem_ID ,
                            7 ,
                            1 ,
                            SUM(PBR.Month7Budget) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectItem PPI -- INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PPI.ProjectID
                                                              AND PBR.SCOAItemID = PPI.SCOAItemID --Add by SN
															  AND PBR.SCOACostingID = PPI.SCOACostingID
                                                              AND PBR.SCOAFunctionID = PPI.SCOAFunctionId
                                                              AND PBR.DivisionID = PPI.DivisionId --Add by SN
                                                              AND PBR.SCOARegionID = PPI.SCOARegionId
                                                              AND PBR.SCOAFundsID = PPI.SCOAFundId --Add by SN
                    GROUP BY PPI.PlanProjectItem_ID
                    UNION
                    SELECT  PPI.PlanProjectItem_ID ,
                            8 ,
                            1 ,
                            SUM(PBR.Month8Budget) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectItem PPI --    INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PPI.ProjectID
                                                              AND PBR.SCOAItemID = PPI.SCOAItemID --Add by SN
															  AND PBR.SCOACostingID = PPI.SCOACostingID
                                                              AND PBR.SCOAFunctionID = PPI.SCOAFunctionId
                                                              AND PBR.DivisionID = PPI.DivisionId --Add by SN
                                                              AND PBR.SCOARegionID = PPI.SCOARegionId
                                                              AND PBR.SCOAFundsID = PPI.SCOAFundId --Add by SN
                    GROUP BY PPI.PlanProjectItem_ID
                    UNION
                    SELECT  PPI.PlanProjectItem_ID ,
                            9 ,
                            1 ,
                            SUM(PBR.Month9Budget) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectItem PPI --  INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PPI.ProjectID
                                                              AND PBR.SCOAItemID = PPI.SCOAItemID --Add by SN
															  AND PBR.SCOACostingID = PPI.SCOACostingID
                                                              AND PBR.SCOAFunctionID = PPI.SCOAFunctionId
                                                              AND PBR.DivisionID = PPI.DivisionId --Add by SN
                                                              AND PBR.SCOARegionID = PPI.SCOARegionId
                                                              AND PBR.SCOAFundsID = PPI.SCOAFundId --Add by SN
                    GROUP BY PPI.PlanProjectItem_ID
                    UNION
                    SELECT  PPI.PlanProjectItem_ID ,
                            10 ,
                            1 ,
                            SUM(PBR.Month10Budget) ,
                    1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectItem PPI --   INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PPI.ProjectID
                                                              AND PBR.SCOAItemID = PPI.SCOAItemID --Add by SN
															  AND PBR.SCOACostingID = PPI.SCOACostingID
                                                              AND PBR.SCOAFunctionID = PPI.SCOAFunctionId
                                                              AND PBR.DivisionID = PPI.DivisionId --Add by SN
                                                              AND PBR.SCOARegionID = PPI.SCOARegionId
                                                              AND PBR.SCOAFundsID = PPI.SCOAFundId --Add by SN
                    GROUP BY PPI.PlanProjectItem_ID
                    UNION
                    SELECT  PPI.PlanProjectItem_ID ,
                            11 ,
                            1 ,
                            SUM(PBR.Month11Budget) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectItem PPI --   INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PPI.ProjectID
                                                              AND PBR.SCOAItemID = PPI.SCOAItemID --Add by SN
															  AND PBR.SCOACostingID = PPI.SCOACostingID
                                                              AND PBR.SCOAFunctionID = PPI.SCOAFunctionId
                                                              AND PBR.DivisionID = PPI.DivisionId --Add by SN
                                                              AND PBR.SCOARegionID = PPI.SCOARegionId
                                                              AND PBR.SCOAFundsID = PPI.SCOAFundId --Add by SN
                    GROUP BY PPI.PlanProjectItem_ID
                    UNION
                    SELECT  PPI.PlanProjectItem_ID ,
                            12 ,
                            1 ,
                            SUM(PBR.Month12Budget) ,
                            1 ,
                            GETDATE() ,
                            NULL ,
                            NULL
                    FROM    dbo.Plan_ProjectItem PPI --  INNER JOIN dbo.Plan_Project PP ON PP.Project_ID = PPI.ProjectID
                            INNER JOIN dbo.Payroll_BudgetReportResultsForPlanning PBR ON PBR.ProjectID = PPI.ProjectID
                                                              AND PBR.SCOAItemID = PPI.SCOAItemID --Add by SN
															  AND PBR.SCOACostingID = PPI.SCOACostingID
                                                              AND PBR.SCOAFunctionID = PPI.SCOAFunctionId
                                                              AND PBR.DivisionID = PPI.DivisionId --Add by SN
                                                              AND PBR.SCOARegionID = PPI.SCOARegionId
                                                              AND PBR.SCOAFundsID = PPI.SCOAFundId --Add by SN
                    GROUP BY PPI.PlanProjectItem_ID;

------------------------------------------------------------------------------
-- Set FundingSourceBudget for New Allocation of Budget Amount
------------------------------------------------------------------------------

            DECLARE @FinYear NVARCHAR(9) = '' ,
                @FundSourceHeaderID INT = 0;


            SELECT TOP 1
                    @FinYear = pp.FinYear
            FROM    Payroll_BudgetReportResultsForPlanning pb
       INNER JOIN dbo.Plan_Project pp ON pb.ProjectID = pp.Project_ID;
		
            DECLARE @StartFinYear INT = 0;
            DECLARE @CurrFinYear VARCHAR(20);
            WHILE ( @StartFinYear <= 2 )
                BEGIN
				
				
                    SELECT  @CurrFinYear = CASE WHEN @StartFinYear = 0
                                                THEN @FinYear
                                                WHEN @StartFinYear = 1
                                                THEN CAST(CAST(SUBSTRING(@FinYear,
                                                              0, 5) AS INT)
                                                     + 1 AS NVARCHAR(10))
                                                     + '/'
                                                     + CAST(CAST(SUBSTRING(@FinYear,
                                                              0, 5) AS INT)
                                                     + 2 AS NVARCHAR(10))
                                                WHEN @StartFinYear = 2
                                                THEN CAST(CAST(SUBSTRING(@FinYear,
                                                              0, 5) AS INT)
                                                     + 2 AS NVARCHAR(10))
                                                     + '/'
                                                     + CAST(CAST(SUBSTRING(@FinYear,
                                                              0, 5) AS INT)
                                                     + 3 AS NVARCHAR(10))
                                                ELSE '2015/2016'
                                           END;

                    SELECT TOP 1
                            @FundSourceHeaderID = FundingSourceBudgetHeader_ID
                    FROM    Plan_FundingSourceBudget_Header
                    WHERE   FinancialYear = @CurrFinYear;

                    PRINT @FundSourceHeaderID;
                    PRINT @CurrFinYear;

------------------------------------------------------------------------------
-- Update Budget Amount for Existing Fund Id
------------------------------------------------------------------------------

                    UPDATE  dbo.Plan_FundingSourceBudget_Detail
                    SET     FundingSourceBudget = FundingSourceBudget
                            + CASE WHEN FundBal.Remain < 0
                                   THEN ( FundBal.Remain * -1 )
                                        + FundBal.NwAllocAmount
                                   WHEN FundBal.Remain > 0
                                        AND FundBal.Actual < FundBal.NwAllocAmount
                                   THEN FundBal.NwAllocAmount
                                   ELSE 0
                              END
--SELECT  * ,
--        CASE WHEN FundBal.Remain < 0
--             THEN ( FundBal.Remain * -1 ) + FundBal.NwAllocAmount
--             WHEN FundBal.Remain > 0
--                  AND FundBal.Actual < FundBal.NwAllocAmount
--             THEN FundBal.NwAllocAmount
--             ELSE 0
--        END AS UpdateAmount
                    FROM    ( SELECT    SCOAFundsID ,
                                        @FundSourceHeaderID AS FundSourceHeaderId ,
                                        HRBudget.NwAllocAmount ,
                                        HRBudget.Budget AS Actual ,
                                        HRBudget.Budget - HRBudget.Allocated AS Remain
                              FROM      ( SELECT    R.SCOAFundsID ,
                                                   -- SUM(BudgetCurrentYear) 
                                                    ( CASE WHEN @StartFinYear = 0
                                                           THEN SUM(BudgetCurrentYear)
                                                           WHEN @StartFinYear = 1
   THEN SUM(R.BudgetCurrentYearPlus1)
                                                           WHEN @StartFinYear = 2
                                                           THEN SUM(R.BudgetCurrentYearPlus2)
                                                      END ) AS NwAllocAmount ,
                                                    ISNULL(dbo.Planing_GetFundAvailableAmount(R.SCOAFundsID,
                                                              @CurrFinYear), 0) AS Budget ,
                                                    ISNULL(dbo.Planing_GetFundAllocatedAmount(R.SCOAFundsID,
                                                              @CurrFinYear,@FinYear), 0) AS Allocated
                                          FROM      [dbo].[Payroll_BudgetReportResultsForPlanning] R
                                          GROUP BY  R.SCOAFundsID
                                        ) AS HRBudget
                            ) AS FundBal
                            INNER JOIN ( SELECT ScoaID AS FundId ,
                                                FundingSourceBudgetHeaderID AS BudgetHeaderId ,
                                                MIN(FundingSourceBudgetDetail_ID) AS UpdateFundingSourceBudgetDetailID
                                         FROM   Plan_FundingSourceBudget_Detail
                                         WHERE  FundingSourceBudgetHeaderID = @FundSourceHeaderID
                                         GROUP BY ScoaID ,
                                                FundingSourceBudgetHeaderID
                                       ) AS UpdateBal ON FundBal.SCOAFundsID = UpdateBal.FundId
                                                         AND FundBal.FundSourceHeaderId = UpdateBal.BudgetHeaderId
-- Condition to get Data to be Updated for Plan_FundingSourceBudget_Detail
                    WHERE   Plan_FundingSourceBudget_Detail.FundingSourceBudgetHeaderID = @FundSourceHeaderID
                            AND ScoaID = FundBal.SCOAFundsID
                            AND Plan_FundingSourceBudget_Detail.FundingSourceBudgetDetail_ID = UpdateFundingSourceBudgetDetailID;
							
------------------------------------------------------------------------------
-- Create Budget Detail for Budget Amount for Fund Id not found 
------------------------------------------------------------------------------
                    INSERT  INTO dbo.Plan_FundingSourceBudget_Detail
                            ( FundingSourceBudgetHeaderID ,
                              FundingSourceID ,
                              ScoaID ,
                              FundingSourceBudget ,
                              DateCaptured ,
                              CapturerID ,
                              DateModified ,
                              ModifierID
                            )
                            SELECT  @FundSourceHeaderID ,
                                    0 ,
                                    R.SCOAFundsID ,
                                    ( CASE WHEN @StartFinYear = 0
                                           THEN SUM(BudgetCurrentYear)
                                           WHEN @StartFinYear = 1
                                           THEN SUM(R.BudgetCurrentYearPlus1)
                                           WHEN @StartFinYear = 2
                                           THEN SUM(R.BudgetCurrentYearPlus2)
                                      END ) AS NwAllocAmount ,
                                    GETDATE() ,
                                    1 ,
                                    NULL ,
                                    NULL
                            FROM    [dbo].[Payroll_BudgetReportResultsForPlanning] R
                            WHERE   ISNULL(dbo.Planing_GetFundAvailableAmount(R.SCOAFundsID,
                                                              @CurrFinYear), 0) = 0
                            GROUP BY R.SCOAFundsID;

                    SET @StartFinYear = @StartFinYear + 1;
                END;
            COMMIT TRAN;

            SELECT  @Result = 'Data Imported Successfully';

        END TRY
        BEGIN CATCH
            ROLLBACK TRAN;

            SELECT  @Result = ERROR_MESSAGE();
        END CATCH;

        SELECT  @Result AS Result;

    END;

GO

