-- =============================================
-- Author:	Nirav Parikh
-- Create date: 08/11/2017
-- Description:	update NTValidations
-- Plan_InsertNTValidations_sp 1250, 1250, 1, '2017/2018', 1, 'admin'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_InsertNTValidations_sp]
    @SCOAItemId INT ,
	@SCOAFunctionId INT ,
    @UserId INT ,
    @FinYear VARCHAR(9) ,
    @IsEnable BIT ,
    @AuditUser NVARCHAR(200)
AS
    BEGIN
        SET NOCOUNT ON;
        BEGIN TRY
            BEGIN TRANSACTION;
            DECLARE @ParentId INT = 0 ,
                @CurrDate DATETIME = GETDATE() ,
                @BudgetType INT;

            WHILE @SCOAItemId > 0 AND @SCOAFunctionId > 0
                BEGIN
	     
                    IF NOT EXISTS ( SELECT  1
                                    FROM    dbo.Const_PlanNTValidations
                                    WHERE   ScoaItemId = @SCOAItemId AND ScoaFunctionId = @SCOAFunctionId
                                            AND FinYear = @FinYear )
                        BEGIN

                            SELECT  @BudgetType = TypeValue
                            FROM    dbo.Const_PlanCapitalOperationalTypes_sys
                            WHERE   TypeName = 'Financial Position';

                            INSERT  INTO dbo.Const_PlanNTValidations
									(
										ScoaItemId,
										ScoaFunctionId,
										IsEnable,
										BudgetType,
										FinYear,
										CapturerID,
										DateCaptured
									)
                            VALUES  ( @SCOAItemId , -- ScoaId - int
									  @SCOAFunctionId , -- ScoaFunctionId - int
                                      @IsEnable , -- IsEnable - bit
                                      @BudgetType ,
                                      @FinYear ,
                                      @UserId , -- CapturerID - int
                                      GETDATE()
                                    );
						
                            INSERT  INTO dbo.Sys_AuditLog
                                    ( UserID ,
                                      AuditDesc ,
                                      AuditDate ,
                                      AuditComment ,
                                      ActiveFinYear_UserFinYear ,
                                      TableName ,
                                      ModuleID ,
                                      RecordID
                                    )
                            VALUES  ( @UserId ,
                                      'Insert Const_PlanNTValidations' ,
                                      '' + CONVERT(NVARCHAR(100), @CurrDate, 121)
                                      + '' ,
                                      'Insert NT Validations' ,
                                      @FinYear ,
                                      'Const_PlanNTValidations' ,
                                      10 ,
                                      @SCOAItemId
                                    );
		
                        END;
    
                    SELECT  @SCOAItemId = ISNULL(A.ScoaItemId, 0) ,
                            @ParentId = ISNULL(B.ScoaParentID, 0)
                    FROM    dbo.Const_PlanNTValidations A
                            INNER JOIN dbo.Const_SCOA_Structure B ON B.ScoaID = A.ScoaItemId
                    WHERE   A.ScoaItemId = @SCOAItemId AND A.ScoaFunctionId = @SCOAFunctionId AND A.FinYear = @FinYear;

                    SET @SCOAItemId = @ParentId;
                END;

            COMMIT TRANSACTION;
	
            SELECT  'Success' AS Result ,
                    'NT Validations Inserted' AS SuccessMessage;
        END TRY
        BEGIN CATCH
            IF @@Trancount > 0
                BEGIN 
                    ROLLBACK TRANSACTION;
                    INSERT  INTO Sys_ErrorLog
                            ( moduleName ,
                              pageName ,
                              procedureName ,
                              errorMessage ,
                              errorType ,
                              detailedErrorMessage ,
                              errorDate ,
                              userName
                            )
                    VALUES  ( 'Planning' ,
                              'SQL Server' ,
                              'Plan_InsertNTValidations_sp' ,
                              ERROR_MESSAGE() ,
                              'SQL' ,
                              ERROR_MESSAGE() ,
                              '' + CONVERT(NVARCHAR(100), @CurrDate, 121) + '' ,
                              @AuditUser
                            );
		
                    DECLARE @Err NVARCHAR(1000);
                    SET @Err = ERROR_MESSAGE();
                    RAISERROR (@Err, 16,1);
		
                    SELECT  @Err AS 'Result' ,
                            'An Error Occured' AS SuccessMessage;
                END;
        END CATCH;
    END;

GO

