-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 31/10/2017
-- Description:	update SCOAItemAssetFBS
-- Plan_InsertSCOAItemAssetFBS_sp 1250,1,'2017/2018',1,'D','admin'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_InsertSCOAItemAssetFBS_sp]
	@SCOAId INT,
	@UserId INT,
	@FinYear VARCHAR(9),
	@IsEnable BIT,
	@CreditDebit VARCHAR(5),
	@AuditUser NVARCHAR(200)
AS
BEGIN
	SET NOCOUNT ON;
	BEGIN TRY
	BEGIN TRANSACTION
DECLARE @ParentId INT = 0, @CurrDate DATETIME = GETDATE(), @BudgetType INT;

WHILE @SCOAId > 0
    BEGIN
	     
        IF NOT EXISTS ( SELECT  1
                        FROM    Const_PlanSCOAItemAssetFBS
                        WHERE   ScoaItemId = @SCOAId AND FinYear=@FinYear )
						BEGIN

						SELECT @BudgetType = TypeValue FROM dbo.Const_PlanCapitalOperationalTypes_sys 
						WHERE TypeName='Free Basic Services/Asset Foregone'

                        INSERT INTO dbo.Const_PlanSCOAItemAssetFBS
                                ( ScoaItemId ,IsEnable ,BudgetType, CreditDebit, FinYear,CapturerID ,DateCaptured
                                )
                        VALUES  ( @SCOAId , -- ScoaId - int
                                  @IsEnable , -- IsEnable - bit
								  @BudgetType,
								  @CreditDebit,
								  @FinYear,
                                  @UserId , -- CapturerID - int
                                  GETDATE()
                                )
						
		INSERT into dbo.Sys_AuditLog
          ( UserID ,AuditDesc ,AuditDate ,AuditComment ,ActiveFinYear_UserFinYear ,TableName ,ModuleID ,RecordID)
		Values (@UserId,'Insert Const_PlanSCOAItemAssetFBS','' + CONVERT(NVARCHAR(100), @CurrDate, 121) + '','Insert SCOA Item Asset for FBS', @FinYear,'Const_PlanSCOAItemAssetFBS',10,@SCOAId)
		
						END;
    
	    SELECT  @SCOAId = ISNULL(A.ScoaItemId,0) ,
                @ParentId = ISNULL(B.ScoaParentID,0)
        FROM    dbo.Const_PlanSCOAItemAssetFBS A
                INNER JOIN dbo.Const_SCOA_Structure B ON B.ScoaID = A.ScoaItemId
        WHERE   A.ScoaItemId = @SCOAId AND A.FinYear=@FinYear;

		SET @SCOAId = @ParentId;
    END;

COMMIT TRANSACTION
	
	Select 'Success' AS Result, 'SCOA Item Assets Inserted' AS SuccessMessage
end try
begin catch
	if @@Trancount > 0 
	begin 
		rollback transaction
		Insert into Sys_ErrorLog (moduleName, pageName, procedureName, errorMessage, errorType, detailedErrorMessage, errorDate, userName)
		Values ('Planning','SQL Server','Plan_InsertSCOAItemAssetFBS_sp', ERROR_MESSAGE(), 'SQL', ERROR_MESSAGE(), '' + CONVERT(NVARCHAR(100), @CurrDate, 121) + '', @AuditUser)
		
		declare @Err nvarchar(1000)
		Set @err = Error_message()
		Raiserror (@Err, 16,1)
		
		Select @Err as 'Result', 'An Error Occured' AS SuccessMessage
	end
 end catch
END;
GO

