-- =============================================
-- Author:	Nirav Parikh
-- Create date: 01/11/2017
-- Description:	update SCOAItemGainOR
-- Plan_InsertSCOAItemGainOR_sp 1250,1,'2017/2018',1,'D','admin'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_InsertSCOAItemGainOR_sp]
    @SCOAId INT ,
    @UserId INT ,
    @FinYear VARCHAR(9) ,
    @IsEnable BIT ,
    @CreditDebit VARCHAR(5) ,
    @AuditUser NVARCHAR(200)
	--@CurrDate DATETIME
AS
    BEGIN
        SET NOCOUNT ON;
        BEGIN TRY
            BEGIN TRANSACTION;
            DECLARE @ParentId INT = 0 ,
                @CurrDate DATETIME = GETDATE() ,
                @BudgetType INT;

            WHILE @SCOAId > 0
                BEGIN
	     
                    IF NOT EXISTS ( SELECT  1
                                    FROM    Const_PlanSCOAItemGainOR
                                    WHERE   ScoaItemId = @SCOAId
                                            AND FinYear = @FinYear )
                        BEGIN

                            SELECT  @BudgetType = TypeValue
                            FROM    dbo.Const_PlanCapitalOperationalTypes_sys
                            WHERE   TypeName = 'Operational Revenue';

                            INSERT  INTO dbo.Const_PlanSCOAItemGainOR
                                    ( ScoaItemId ,
                                      IsEnable ,
                                      BudgetType ,
                                      CreditDebit ,
                                      FinYear ,
                                      CapturerID ,
                                      DateCaptured
                                    )
                            VALUES  ( @SCOAId , -- ScoaId - int
                                      @IsEnable , -- IsEnable - bit
                                      @BudgetType ,
                                      @CreditDebit ,
                                      @FinYear ,
                                      @UserId , -- CapturerID - int
                                      GETDATE()
                                    );
						
                            INSERT  INTO dbo.Sys_AuditLog
                                    ( UserID ,
                                      AuditDesc ,
                                      AuditDate ,
                                      AuditComment ,
                                      ActiveFinYear_UserFinYear ,
                                      TableName ,
                                      ModuleID ,
                                      RecordID
                                    )
                            VALUES  ( @UserId ,
                                      'Insert Const_PlanSCOAItemGainOR' ,
                                      '' + CONVERT(NVARCHAR(100), @CurrDate, 121)
                                      + '' ,
                                      'Insert SCOA Item Gain for OR' ,
                                      @FinYear ,
                                      'Const_PlanSCOAItemGainOR' ,
                                      10 ,
                                      @SCOAId
                                    );
		
                        END;
    
                    SELECT  @SCOAId = ISNULL(A.ScoaItemId, 0) ,
                            @ParentId = ISNULL(B.ScoaParentID, 0)
                    FROM    dbo.Const_PlanSCOAItemGainOR A
                            INNER JOIN dbo.Const_SCOA_Structure B ON B.ScoaID = A.ScoaItemId
                    WHERE   A.ScoaItemId = @SCOAId
                            AND A.FinYear = @FinYear;

                    SET @SCOAId = @ParentId;
                END;

            COMMIT TRANSACTION;
	
            SELECT  'Success' AS Result ,
                    'SCOA Item Gain Inserted' AS SuccessMessage;
        END TRY
        BEGIN CATCH
            IF @@Trancount > 0
                BEGIN 
                    ROLLBACK TRANSACTION;
                    INSERT  INTO Sys_ErrorLog
                            ( moduleName ,
                              pageName ,
                              procedureName ,
                              errorMessage ,
                              errorType ,
                              detailedErrorMessage ,
                              errorDate ,
                              userName
                            )
                    VALUES  ( 'Planning' ,
                              'SQL Server' ,
                              'Plan_InsertSCOAItemGainOR_sp' ,
                              ERROR_MESSAGE() ,
                              'SQL' ,
                              ERROR_MESSAGE() ,
                              '' + CONVERT(NVARCHAR(100), @CurrDate, 121) + '' ,
                              @AuditUser
                            );
		
                    DECLARE @Err NVARCHAR(1000);
                    SET @Err = ERROR_MESSAGE();
                    RAISERROR (@Err, 16,1);
		
                    SELECT  @Err AS 'Result' ,
                            'An Error Occured' AS SuccessMessage;
                END;
        END CATCH;
    END;
GO

