	--@CurrDate DATETIME
AS
    BEGIN
        SET NOCOUNT ON;
        BEGIN TRY
            BEGIN TRANSACTION;
            DECLARE @ParentId INT = 0 ,
                @CurrDate DATETIME = GETDATE() ,
                @BudgetType INT;

            WHILE @SCOAId > 0
                BEGIN
	     
                    IF NOT EXISTS ( SELECT  1
                                    FROM    Const_PlanSCOAItemLossOE
                                    WHERE   ScoaItemId = @SCOAId
                                            AND FinYear = @FinYear )
                        BEGIN

                            SELECT  @BudgetType = TypeValue
                            FROM    dbo.Const_PlanCapitalOperationalTypes_sys
                            WHERE   TypeName = 'Operational Revenue';

                            INSERT  INTO dbo.Const_PlanSCOAItemLossOE
                                    ( ScoaItemId ,
                                      IsEnable ,
                                      BudgetType ,
