                                      @BudgetType ,
                                      @CreditDebit ,
                                      @FinYear ,
                                      @UserId , -- CapturerID - int
                                      GETDATE()
                                    );
						
                            INSERT  INTO dbo.Sys_AuditLog
                                    ( UserID ,
                                      AuditDesc ,
                                      AuditDate ,
                                      AuditComment ,
                                      ActiveFinYear_UserFinYear ,
                                      TableName ,
                                      ModuleID ,
                                      RecordID
                                    )
                            VALUES  ( @UserId ,
                                      'Insert Const_PlanSCOAItemLossOE' ,
                                      '' + CONVERT(NVARCHAR(100), @CurrDate, 121)
                                      + '' ,
                                      'Insert SCOA Item Loss for OE' ,
                                      @FinYear ,
                                      'Const_PlanSCOAItemLossOE' ,
                                      10 ,
                                      @SCOAId
                                    );
		
                        END;
    
                    SELECT  @SCOAId = ISNULL(A.ScoaItemId, 0) ,
                            @ParentId = ISNULL(B.ScoaParentID, 0)
                    FROM    dbo.Const_PlanSCOAItemLossOE A
                            INNER JOIN dbo.Const_SCOA_Structure B ON B.ScoaID = A.ScoaItemId
                    WHERE   A.ScoaItemId = @SCOAId
                            AND A.FinYear = @FinYear;

                    SET @SCOAId = @ParentId;
                END;

            COMMIT TRANSACTION;
	
            SELECT  'Success' AS Result ,
                    'SCOA Item Loss Inserted' AS SuccessMessage;
        END TRY
        BEGIN CATCH
            IF @@Trancount > 0
                BEGIN 
                    ROLLBACK TRANSACTION;
                    INSERT  INTO Sys_ErrorLog
                            ( moduleName ,
                              pageName ,
                              procedureName ,
                              errorMessage ,
                              errorType ,
                              detailedErrorMessage ,
                              errorDate ,
                              userName
                            )
                    VALUES  ( 'Planning' ,
                              'SQL Server' ,
                              'Plan_InsertSCOAItemLossOE_sp' ,
                              ERROR_MESSAGE() ,
                              'SQL' ,
                              ERROR_MESSAGE() ,
                              '' + CONVERT(NVARCHAR(100), @CurrDate, 121) + '' ,
                              @AuditUser
                            );
		
                    DECLARE @Err NVARCHAR(1000);
                    SET @Err = ERROR_MESSAGE();
                    RAISERROR (@Err, 16,1);
		
                    SELECT  @Err AS 'Result' ,
                            'An Error Occured' AS SuccessMessage;
                END;
        END CATCH;
    END;
GO

