/****** Object:  StoredProcedure [dbo].[Plan_NTBudgetValidations]    Script Date: 2026/03/10 7:23:44 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author: Gansen 
-- Create Date: 26 April 2021
-- Description:	NTBudgetValidations
-- 211005 by CM: 74961 - Exclude Revenue Items vs Funding check for fin years prior to 2021/2022
-- 211105 by Martin Botes: 78155 - Year & Month Totals Balance to Zero: Correct Unit Price to take AdjustedUnitPrice in consideration
-- 220404 by CM: 85577 - Exclude projects in Plan_ProjectReportExclude for Trial Balance, Year and Month budgets balance to zero checks
-- 230221 by CM: 97608 - Get max adjustment version ID per fin year. Filter by AdjustmentVersionID for Inventory water must use Function: Water, and IA IL LN Opening Balance
-- 230920 by CM:106310 - Fix validation rule:Cost/Revenue Projects for Free Services vs Items (PO003057 PO003058 PO003059 only against IR or IA001010 OR IA001004 is valid)
--								   - Use SCOA Consolidated tables
-- 240213 by CM: 110254 - Fix validation rules: Charges and Recoveries must balance (CO001 and CO002 must balance) and Capital Project vs Scoa Item (PC only against IA and IL001006011 and IL001006006 is valid)
-- 240524 by CM: 112433 - Fix validation rules: Charges and Recoveries must balance (CO001 and CO002 must balance) applied for outer years
-- 241017 by CM: 115265 - Fix validation rule 1 - Add the following item.ScoaCode NOT LIKE 'IL001006023%' AND item.ScoaCode NOT LIKE 'IL001006024%' 
-- =============================================
CREATE PROCEDURE [dbo].[Plan_NTBudgetValidations] 
   
   @finYear NVARCHAR(10)

AS
BEGIN

DECLARE @ChargesY1 decimal(18,2), @ChargesY2 decimal(18,2), @ChargesY3 decimal(18,2)
DECLARE @RecoveriesY1 decimal(18,2), @RecoveriesY2 decimal(18,2), @RecoveriesY3 decimal(18,2)
DECLARE @FinYearStart INT
DECLARE @FinYearStart_RevenueDefaultFundingCheckValid INT = 2021
DECLARE @BudgetVersionID INT

SELECT @FinYearStart = CONVERT(INT, SUBSTRING(@finYear, 1, 4))
SELECT @BudgetVersionID = ISNULL(dbo.Section71_BudgetOriginalVersionID_fxn(@Finyear), -1)

CREATE TABLE #Const_SCOA_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100), ScoaShortDesc NVARCHAR(400), PostingLevel NVARCHAR(6))
CREATE INDEX idxItemScoaID ON #Const_SCOA_Structure(ScoaID)
CREATE INDEX idxItemNTScoaID ON #Const_SCOA_Structure(NTScoaID)
INSERT INTO #Const_SCOA_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode, ScoaShortDesc, PostingLevel FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @finYear


Select 
	@ChargesY1 = SUM(CASE WHEN (((d.ScoaCode LIKE 'IR%' OR d.ScoaCode LIKE 'IL%') AND b.CapitalOperation in (0,1,2)) OR [a].CreditDebit = 'C') THEN -isnull([a].AdjustedBudgetAmount,[a].BudgetAmount) ELSE isnull([a].AdjustedBudgetAmount,[a].BudgetAmount) END),
	@ChargesY2 = SUM(CASE WHEN (((d.ScoaCode LIKE 'IR%' OR d.ScoaCode LIKE 'IL%') AND b.CapitalOperation in (0,1,2)) OR [a].CreditDebit = 'C') THEN -isnull([a].AdjustedBudgetAmountCurP1,[a].BudgetAmountCurP1) ELSE isnull([a].AdjustedBudgetAmountCurP1,[a].BudgetAmountCurP1) END),
	@ChargesY3 = SUM(CASE WHEN (((d.ScoaCode LIKE 'IR%' OR d.ScoaCode LIKE 'IL%') AND b.CapitalOperation in (0,1,2)) OR [a].CreditDebit = 'C') THEN -isnull([a].AdjustedBudgetAmountCurP2,[a].BudgetAmountCurP2) ELSE isnull([a].AdjustedBudgetAmountCurP2,[a].BudgetAmountCurP2) END)
from  
		      Plan_AdjustmentProjectItem a left join
              Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
			  Const_SCOA_Costing_structure_Consolidated c on  a.SCOACostingID = c.scoaid and c.FinYearText = @finYear left join
			  Plan_Const_SCOA_Structure_Consolidated_vw d on a.SCOAItemID = d.ScoaID and d.FinYearText = @finYear
 where   b.finyear = @Finyear
         and isnull(isdeleted,0) <> 1
         and c.scoacode like'CO001%'
		 and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)


Select 
	@RecoveriesY1 = SUM(CASE WHEN (((d.ScoaCode LIKE 'IR%' OR d.ScoaCode LIKE 'IL%') AND b.CapitalOperation in (0,1,2)) OR [a].CreditDebit = 'C') THEN -isnull([a].AdjustedBudgetAmount,[a].BudgetAmount) ELSE isnull([a].AdjustedBudgetAmount,[a].BudgetAmount) END),
	@RecoveriesY2 = SUM(CASE WHEN (((d.ScoaCode LIKE 'IR%' OR d.ScoaCode LIKE 'IL%') AND b.CapitalOperation in (0,1,2)) OR [a].CreditDebit = 'C') THEN -isnull([a].AdjustedBudgetAmountCurP1,[a].BudgetAmountCurP1) ELSE isnull([a].AdjustedBudgetAmountCurP1,[a].BudgetAmountCurP1) END),
	@RecoveriesY3 = SUM(CASE WHEN (((d.ScoaCode LIKE 'IR%' OR d.ScoaCode LIKE 'IL%') AND b.CapitalOperation in (0,1,2)) OR [a].CreditDebit = 'C') THEN -isnull([a].AdjustedBudgetAmountCurP2,[a].BudgetAmountCurP2) ELSE isnull([a].AdjustedBudgetAmountCurP2,[a].BudgetAmountCurP2) END)
from  
		      Plan_AdjustmentProjectItem a left join
              Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
			  Const_SCOA_Costing_structure_Consolidated c on  a.SCOACostingID = c.scoaid and c.FinYearText = @finYear left join
			  Plan_Const_SCOA_Structure_Consolidated_vw d on a.SCOAItemID = d.ScoaID and d.FinYearText = @finYear
where   b.finyear = @Finyear
         and isnull(isdeleted,0) <> 1
         and c.scoacode like'CO002%'
		 and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)



Select ExceptionDetail, Cast(AdjustmentProjectID as Varchar(50)) as AdjustmentProjectID,Cast(cast (PlanAdjustmentProjectItem_ID as  decimal(10,0))as Varchar(50)) as PlanAdjustmentProjectItem_ID
From

(
--Budget Value vs Projections M01 to M12 Value 
select a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'ProjectItem Year Amt vs Monthly Total Amt' as ExceptionDetail
from Plan_AdjustmentProjectItem a
left join Plan_AdjustmentProjectItemMonth b on a.PlanAdjustmentProjectItem_ID = b.PlanAdjustmentProjectItemID
where a.FinYear = @Finyear and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)
group by a.PlanAdjustmentProjectItem_ID, a.BudgetAmount,a.AdjustmentProjectID,AdjustedBudgetAmount
having (isnull(AdjustedBudgetAmount,BudgetAmount)) <> sum(isnull(b.AdjustedUnitPrice,unitprice))



Union All


--Capital Projects vs Item Assets
select   a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID,'Capital Project vs Scoa Item (PC only against IA and IL001006011 23 24 and IL001006006 is valid)' as ExceptionDetail
from [dbo].[Plan_AdjustmentProjectItem] a left join
	 #Const_SCOA_Structure c on a.ScoaItemid  = c.ScoaID left join
	 Plan_AdjustmentProject e on a.AdjustmentProjectID = e.AdjustmentProject_ID left join
	 Const_SCOA_Project_Structure_Consolidated d on e.ScoaProjectID = d.scoaid and d.FinYearText = @finYear
where  (c.Scoacode not like 'IA%' AND c.ScoaCode not like 'IL001006011%' AND c.ScoaCode not like 'IL001006023%' AND c.ScoaCode not like 'IL001006024%' AND c.ScoaCode not like 'IL001006006%')
		and d.ScoaDesc like 'Capital%' 
		and a.finyear = @Finyear and isnull(e.IsDeleted,0) <> 1
		and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

Union All

-- Operational Projects vs Items 
select    a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'Operation Project vs Scoa Item (PO not valid against IA002 level acquisitions or additions)' as ExceptionDetail
from Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	 #Const_SCOA_Structure c on  a.ScoaItemID = c.scoaid left join
	 Const_SCOA_Project_structure_Consolidated d on b.ScoaProjectID = d.scoaid and d.FinYearText = @finYear
where b.finyear = @Finyear and (isnull(BudgetAmount,BudgetAmount) + (isnull(BudgetAmountCurP1,BudgetAmountCurP1) +isnull(BudgetAmountCurP2, BudgetAmountCurP2) ) > 0)
	      and isnull(isdeleted,0) <> 1
		  and d.ScoaDesc like 'Operational%'
		  and (  (c.scoacode like 'IA002%' and c.scoadesc like '%additions%') or
		   (c.scoacode like 'IA002%' and c.scoadesc like '%acquisitions')) 
		  and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

Union All


-- Cost of free basic services, Revenue Cost of Free Services and Property Rebates  vs Items 
select   a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'Cost/Revenue Projects for Free Services vs Items (PO003057 PO003058 PO003059 only against IR or IA001010 OR IA001004 is valid)' as ExceptionDetail  
from Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	 #Const_SCOA_Structure c on  a.ScoaItemID = c.scoaid left join
	 Const_SCOA_Project_structure_Consolidated d on b.ScoaProjectID = d.scoaid and d.FinYearText = @finYear
where b.finyear = @Finyear and (isnull(BudgetAmount,BudgetAmount) + (isnull(BudgetAmountCurP1,BudgetAmountCurP1) +isnull(BudgetAmountCurP2, BudgetAmountCurP2) ) > 0)
	    and isnull(isdeleted,0) <> 1
		  and ( d.ScoaCode like 'PO003057%' or d.ScoaCode like 'PO003058%' or d.ScoaCode like 'PO003059%')
		  and ( c.ScoaCode not like 'IR%' and c.ScoaCode not like 'IA001010%' and c.ScoaCode not like 'IA001004%') and SCOAItemID <> '' 
		  and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

Union All

 -- Operational Project vs Scoa Item (PO not valid against Revenue Item if not FBS/Rebates Project
select   a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'Operational Project vs Scoa Item (PO not valid against Revenue Item if not FBS/Rebates Project)' as ExceptionDetail  
from Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	 #Const_SCOA_Structure c on  a.ScoaItemID = c.scoaid left join
	 Const_SCOA_Project_structure_Consolidated d on b.ScoaProjectID = d.scoaid and d.FinYearText = @finYear
where b.finyear = @Finyear and (isnull(BudgetAmount,BudgetAmount) + (isnull(BudgetAmountCurP1,BudgetAmountCurP1) +isnull(BudgetAmountCurP2, BudgetAmountCurP2) ) > 0)
	    and isnull(isdeleted,0) <> 1
		  and d.ScoaDesc not like '%Cost of Free Basic Services%' and  d.ScoaDesc not like '%Revenue Cost of Free Services%'
		     and  d.ScoaDesc not  like '%property rates rebate%' and d.scoacode like 'PO%'
		  and  c.scoadesc  like 'Revenue%' and SCOAItemID <> '' 
		  and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

Union All

-- Default Projects vs Items 
Select distinct a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'Default Projects vs Items (PD not valid against IE or IA except IA001 or IA002011 or IE018 or IE019)' as ExceptionDetail 
from [dbo].[Plan_AdjustmentProjectItem] a left join
       (select   AdjustmentProjectName,PlanAdjustmentProjectItem_ID, a.Scoaitemid, c.ScoaCode, d.ScoaDesc as ScoaProject, a.SCOAFundId, c.scoadesc as scoaitemdesc
        from [dbo].[Plan_AdjustmentProjectItem] a left join
	         #Const_SCOA_Structure c on  a.ScoaItemid = c.scoaid left join
	         Plan_AdjustmentProject e on a.AdjustmentProjectID = e.AdjustmentProject_ID left join
			 Const_SCOA_Project_Structure_Consolidated d on e.ScoaProjectID = d.scoaid and d.FinYearText = @finYear
        where (c.ScoaDesc like 'Expenditure%' or c.ScoaDesc like 'Assets%') and isnull(isdeleted,0) <> 1 and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)
		and d.ScoaDesc like 'default%' and a.SCOAItemID <> '0' and e.ScoaProjectID <> '0') xy on a.PlanAdjustmentProjectItem_ID = xy.PlanAdjustmentProjectItem_ID and a.SCOAItemID =xy.ScoaItemid and a.scoafundid =xy.Scoafundid
where xy.scoaitemdesc not like 'Expenditure:Default%'
      and xy.scoaitemdesc not like 'Assets:current Assets%' 
	  and xy.scoaitemdesc not like 'Assets:Non-current Assets%' 
	  and xy.scoaitemdesc not like '%Accumulated%'
	  and xy.scoaitemdesc not like '%Opening Balance'
	  and finyear = @Finyear
	  and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

Union All	  

-- Default Projects vs Items Part 2
Select distinct a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'Default Projects vs Items (PD not valid against IE or IA except IA001 or IA002011 or IE018 or IE019)' as ExceptionDetail 
from [dbo].[Plan_AdjustmentProjectItem] a left join
       (select   AdjustmentProjectName,PlanAdjustmentProjectItem_ID, a.Scoaitemid, c.ScoaCode, d.ScoaDesc as ScoaProject, a.SCOAFundId, c.scoadesc as scoaitemdesc
        from [dbo].[Plan_AdjustmentProjectItem] a left join
	         #Const_SCOA_Structure c on  a.ScoaItemid = c.scoaid left join
	         Plan_AdjustmentProject e on a.AdjustmentProjectID = e.AdjustmentProject_ID left join
			 Const_SCOA_Project_Structure_Consolidated d on e.ScoaProjectID = d.scoaid and d.FinYearText = @finYear 
        where (c.ScoaDesc like 'Expenditure%' or c.ScoaDesc like 'Assets%') and isnull(isdeleted,0) <> 1 and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)
		and d.ScoaDesc like 'default%' and a.SCOAItemID <> '0' and e.ScoaProjectID <> '0') xy on a.PlanAdjustmentProjectItem_ID = xy.PlanAdjustmentProjectItem_ID and a.SCOAItemID =xy.ScoaItemid and a.scoafundid =xy.Scoafundid
where (xy.scoaitemdesc like 'Assets:Non-current Assets%' and xy.scoaitemdesc  like '%acquisitions%'  and xy.scoaitemdesc not like '%Work-in-progress%')
	  and finyear = @Finyear
	  and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)



Union All

-- Remuneration of Councillors not against Mayor and Council
select  a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'Item Remuneration of Councillors not against Function Mayor and Council (IE008 must use FX004)' as ExceptionDetail  
from Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	 #Const_SCOA_Structure c on  a.ScoaItemID = c.scoaid left join
	 Const_SCOA_Function_Structure_Consolidated d on a.ScoafunctionID = d.scoaid and d.FinYearText = @finYear 
where b.finyear = @Finyear 
	    and isnull(isdeleted,0) <> 1
		and c.ScoaCode like 'IE008%'
		and d.Scoadesc  not like 'Function:Executive and Council:Core Function:Mayor and Council'	
		and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

Union All


-- Bulk electricity Purchases items vs Functions
select a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'Item: Bulk purchase electricity must use Function: Electricity (IE002001 must use FX002001001 or FX002002001)' as ExceptionDetail  
from Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	 #Const_SCOA_Structure c on  a.ScoaItemID = c.scoaid left join
	 Const_SCOA_Function_Structure_Consolidated d on a.ScoafunctionID = d.scoaid and d.FinYearText = @finYear
where b.finyear = @Finyear 
	    and isnull(isdeleted,0) <> 1
		and c.ScoaCode like 'IE002001%'
		and d.ScoaCode not  like 'FX002001001%' and  d.ScoaCode  not like 'FX002002001%'
		and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

Union All


-- Bulk Water Purchases items vs Functions
select a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'Item: Bulk purchases water must use Function: Water (IE002002 must use FX016001002 or FX016002002)' as ExceptionDetail  
from Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	  #Const_SCOA_Structure c on  a.ScoaItemID = c.scoaid left join
	 Const_SCOA_Function_Structure_Consolidated d on a.ScoafunctionID = d.scoaid and d.FinYearText = @finYear 
where b.finyear = @Finyear 
	    and isnull(isdeleted,0) <> 1
		and c.ScoaCode like 'IE002002%'
		and d.ScoaCode  not like 'FX016001002%'
		and d.ScoaCode  not like 'FX016002002%'
		and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

Union All


	 -- Inventory consumed: Water items vs Functions
select  a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'Item: Inventory consumed water must use Function: Water (IE007004 must use FX016001002 or FX016002002)' as ExceptionDetail  
from Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	  #Const_SCOA_Structure c on  a.ScoaItemID = c.scoaid left join
	 Const_SCOA_Function_Structure_Consolidated d on a.ScoafunctionID = d.scoaid and d.FinYearText = @finYear 
where b.finyear = @Finyear 
