--IA IL LN Opening Balance must use Costing Default
select  a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'Item: IA IL LN Opening Balance must use Costing Default (IA IL LN Opening Balance must use CO003)' as ExceptionDetail  
from Plan_AdjustmentProjectItem a left join
	 #Const_SCOA_Structure c on  a.ScoaItemID = c.scoaid left join
	 Const_SCOA_Funds_Structure_Consolidated d on a.ScoafundID = d.scoaid and d.FinYearText = @finYear left join
	 Const_SCOA_Costing_Structure_Consolidated e on a.ScoaCostingID = e.ScoaID and e.FinYearText = @finYear 
where  ((c.ScoaShortDesc = 'Opening Balance') and (c.ScoaCode like 'IL%' or c.ScoaCode like 'IA%' or c.ScoaCode like 'LN%'))
		and (e.ScoaCode not like 'CO003%')
		and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

Union All

--IA IL LN Opening Balance must use Non-Funding
select  a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'Item: IA IL LN Opening Balance must use Non-Funding (IA IL LN Opening Balance must use FD003)' as ExceptionDetail  
from Plan_AdjustmentProjectItem a left join
	 #Const_SCOA_Structure c on  a.ScoaItemID = c.scoaid left join
	 Const_SCOA_Funds_Structure_Consolidated d on a.ScoafundID = d.scoaid and d.FinYearText = @finYear left join
	 Const_SCOA_Costing_Structure_Consolidated e on a.ScoaCostingID = e.ScoaID and e.FinYearText = @finYear 
where  ((c.ScoaShortDesc = 'Opening Balance') and (c.ScoaCode like 'IL%' or c.ScoaCode like 'IA%' or c.ScoaCode like 'LN%'))
		and (d.ScoaCode not like 'FD003%')
		and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

Union All

--IA IL LN Opening Balance must use Project Default
select  a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'Item: IA IL LN Opening Balance must use Project Default(IA IL LN Opening Balance must use PD)' as ExceptionDetail  
from Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	 #Const_SCOA_Structure c on  a.ScoaItemID = c.scoaid left join
	 Const_SCOA_Funds_Structure_Consolidated d on a.ScoafundID = d.scoaid and d.FinYearText = @finYear left join
	 Const_SCOA_Costing_Structure_Consolidated e on a.ScoaCostingID = e.ScoaID and e.FinYearText = @finYear  left join
	Const_SCOA_Project_Structure_Consolidated f on b.ScoaProjectID = f.ScoaID and f.FinYearText = @finYear
where  ((c.ScoaShortDesc = 'Opening Balance') and (c.ScoaCode like 'IL%' or c.ScoaCode like 'IA%' or c.ScoaCode like 'LN%'))
		and (f.ScoaCode not like 'PD%')
		and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

