--Item: Inventory water must use Function: Water
select  a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'Item: Inventory water must use Function: Water (IA001009005 must use FX016)' as ExceptionDetail  
from Plan_AdjustmentProjectItem a left join
	   #Const_SCOA_Structure c on  a.ScoaItemID = c.scoaid left join
	 Const_SCOA_Function_Structure_Consolidated d on a.ScoaFunctionID = d.scoaid and d.FinYearText = @finYear
where  c.ScoaCode like 'IA001009005%'
		and d.ScoaCode not like 'FX016%'
