--Small Differences Tolerances must be zero (IE010053 must be zero) 
 select   a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'Small Differences Tolerances must be zero (IE010053 must be zero)' as ExceptionDetail 
from Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	 #Const_SCOA_Structure c on  a.ScoaItemID = c.scoaid 
where b.finyear = @Finyear
	    and isnull(isdeleted,0) <> 1
		and c.ScoaCode like 'IE010053%' 
		and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)
group by a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID
Having  sum(isnull([a].AdjustedBudgetAmount,[a].BudgetAmount)+isnull([a].AdjustedBudgetAmountCurP1,a.BudgetAmountCurP1)+isnull([a].AdjustedBudgetAmountCurP2,a.BudgetAmountCurP2)) <> 0

Union All


--No IDP Projects
Select pp.AdjustmentProject_ID, pp.AdjustmentProject_ID, 'Project with No IDP details' as ExceptionDetail 
from Plan_AdjustmentProject pp
where PP.AdjustmentProject_ID not in (select AdjustmentProjectID From Plan_AdjustmentProjectIDP  where finyear =@Finyear)
and pp.FinYear = @Finyear and pp.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)


Union All


--Missing Debit/Credit flag
Select  a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'Incorrect or Missing Credit/Debit Flag' as ExceptionDetail 
From Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID 
Where a.FinYear = @Finyear and CreditDebit not in ('C', 'D') and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

Union All

-- Revenue Items vs Funding
Select a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'ScoaItem Segment is Revenue with Default Funding' as ExceptionDetail   
From Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	 #Const_SCOA_Structure c on  a.ScoaItemID = c.scoaid  left join 
	 Const_SCOA_Funds_structure_Consolidated d on  a.SCOAFundId =d.scoaid and d.FinYearText = @finYear  
Where a.FinYear = @Finyear 
     and c.scoacode like 'IR%' and d.ScoaCode like 'FD003%'
     and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)
	 and @FinYearStart >= @FinYearStart_RevenueDefaultFundingCheckValid

Union All

--Scoa Items is at Posting Level or Breakdown Allowed
-- Item Segement
Select a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'ScoaItem Segment not in chart or not at Postinglevel' as ExceptionDetail   
From Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	 #Const_SCOA_Structure c on  a.ScoaItemID = c.scoaid and c.PostingLevel = 'Yes'
Where a.FinYear = @Finyear and c.scoaid is null and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

Union All


-- Project Segement
Select a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'ScoaProject Segment not in chart or not at Postinglevel' as ExceptionDetail   
From Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	 Const_SCOA_Project_structure_Consolidated c on  b.ScoaProjectID = c.scoaid and (c.PostingLevel = 'Yes' or c.BreakDownAllowed = 'Yes') and c.FinYearText = @finYear
Where a.FinYear = @Finyear and c.scoaid is null and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

Union All

-- Fund Segement
Select a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'ScoaFund Segment not in chart or not at Postinglevel' as ExceptionDetail   
From Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	 Const_SCOA_Funds_structure_Consolidated c on  a.ScoaFundID = c.scoaid and c.PostingLevel = 'Yes' and c.FinYearText = @finYear
Where a.FinYear = @Finyear and c.scoaid is null and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

Union All


-- Function Segement
Select a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'ScoaFunction Segment not in chart or not at Postinglevel' as ExceptionDetail   
From Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	 Const_SCOA_Function_structure_Consolidated c on  a.ScoaFunctionID = c.scoaid and c.PostingLevel = 'Yes' and c.FinYearText = @finYear
Where a.FinYear = @Finyear and c.scoaid is null and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

Union All

-- Region Segement
Select a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'ScoaRegion Segment not in chart or not at Postinglevel' as ExceptionDetail   
From Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	 Const_SCOA_Regional_structure_Consolidated c on   a.ScoaRegionID= c.scoaid and c.PostingLevel = 'Yes' and c.FinYearText = @finYear
Where a.FinYear = @Finyear and c.scoaid is null and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

Union All


-- Costing Segement
Select a.AdjustmentProjectID, a.PlanAdjustmentProjectItem_ID, 'ScoaCosting Segment not in chart or not at Postinglevel' as ExceptionDetail   
From Plan_AdjustmentProjectItem a left join
     Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	 Const_SCOA_Costing_structure_Consolidated c on a.ScoaCostingID  = c.scoaid and c.PostingLevel = 'Yes' and c.FinYearText = @finYear
Where a.FinYear = @Finyear and c.scoaid is null and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)

) Expt



Union All


--Trial Balance (sum of all items - IE018 and IR004)
select 'Trial Balance (sum of all items - IE018 and IR004)' as ExceptionDetail ,'Trial Balance Difference' , cast(sum(Budgetamount) as nvarchar(50)) 
from
		( select 
				 ( CASE WHEN (((c.ScoaCode LIKE 'IR%' OR c.ScoaCode LIKE 'IL%') AND b.CapitalOperation in (0,1,2)) OR [a].CreditDebit = 'C')
								THEN -isnull([a].AdjustedBudgetAmount,[a].BudgetAmount) ELSE isnull([a].AdjustedBudgetAmount,[a].BudgetAmount)END ) as BudgetAmount 
		from  
		      Plan_AdjustmentProjectItem a left join
              Plan_AdjustmentProject b   on a.AdjustmentProjectID =  b.AdjustmentProject_ID left join
	          #Const_SCOA_Structure c on  a.ScoaItemID = c.scoaid 
        where   b.finyear = @Finyear 
	            and isnull(isdeleted,0) <> 1 and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)
				and isnull(b.ReferenceProject_ID, -1) not in (select ProjectID from Plan_ProjectReportExclude)) TB 
Having sum(Budgetamount) <> 0

Union All


--Year & Month Totals Balance to Zero
Select 
 'Year & Month Totals Dont Balance to Zero' as ExceptionDetail ,
 'CurrentYear = '+cast(CurrentYear as varchar(50)) +'/OuterYear1 = '+cast(OuterYear1 as varchar(50))+'/OuterYear2 = '+cast(OuterYear2 as varchar(50))
  As YearTotals,
 'Month1Budget = '+cast(Month1Budget as varchar(50))+'/Month2Budget = '+cast(Month2Budget as varchar(50))+'/Month3Budget = '+cast(Month3Budget as varchar(50))+'/Month4Budget = '+cast(Month4Budget as varchar(50))
 +'/Month5Budget = '+cast(Month5Budget as varchar(50))+'/Month6Budget = '+cast(Month6Budget as varchar(50))+'/Month7Budget = '+cast(Month7Budget as varchar(50))+'/Month8Budget = '+cast(Month8Budget as varchar(50))
 +'/Month9Budget = '+cast(Month9Budget as varchar(50))+'/Month10Budget = '+cast(Month10Budget as varchar(50))+'/Month11Budget = '+cast(Month11Budget as varchar(50))+'/Month12Budget = '+cast(Month12Budget as varchar(50))
  As MonthTotals

From 
(select 

sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
								OR a.CreditDebit = 'C')
																	  THEN -isnull([a].AdjustedBudgetAmount,[a].BudgetAmount)
																	  ELSE isnull([a].AdjustedBudgetAmount,[a].BudgetAmount)
																	  END )) as CurrentYear,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
								OR a.CreditDebit = 'C')
																	  THEN -isnull([a].AdjustedBudgetAmountCurP1,a.BudgetAmountCurP1)
																	  ELSE isnull([a].AdjustedBudgetAmountCurP1,a.BudgetAmountCurP1)
																	  END )) as OuterYear1,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
								OR a.CreditDebit = 'C')
																	  THEN -isnull([a].AdjustedBudgetAmountCurP2,a.BudgetAmountCurP2)
																	  ELSE isnull([a].AdjustedBudgetAmountCurP2,a.BudgetAmountCurP2)
																	  END )) as OuterYear2,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
								OR a.CreditDebit = 'C')
																	  THEN -isnull(h.AdjustedUnitPrice,h.UnitPrice)
																	  ELSE isnull(h.AdjustedUnitPrice,h.UnitPrice)
																	  END )) as Month1Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
								OR a.CreditDebit = 'C')
																	  THEN -isnull(i.AdjustedUnitPrice,i.UnitPrice)
																	  ELSE isnull(i.AdjustedUnitPrice,i.UnitPrice)
																	  END )) as Month2Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
								OR a.CreditDebit = 'C')
																	  THEN -isnull(j.AdjustedUnitPrice,j.UnitPrice)
																	  ELSE isnull(j.AdjustedUnitPrice,j.UnitPrice)
																	  END )) as Month3Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
								OR a.CreditDebit = 'C')
																	  THEN -isnull(k.AdjustedUnitPrice,k.UnitPrice)
																	  ELSE isnull(k.AdjustedUnitPrice,k.UnitPrice)
																	  END )) as Month4Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
								OR a.CreditDebit = 'C')
																	  THEN -isnull(l.AdjustedUnitPrice,l.UnitPrice)
																	  ELSE isnull(l.AdjustedUnitPrice,l.UnitPrice)
																	  END )) as Month5Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
								OR a.CreditDebit = 'C')
																	  THEN -isnull(m.AdjustedUnitPrice,m.UnitPrice)
																	  ELSE isnull(m.AdjustedUnitPrice,m.UnitPrice)
																	  END )) as Month6Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
								OR a.CreditDebit = 'C')
																	  THEN -isnull(b.AdjustedUnitPrice,b.UnitPrice)
																	  ELSE isnull(b.AdjustedUnitPrice,b.UnitPrice)
																	  END )) as Month7Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
								OR a.CreditDebit = 'C')
																	  THEN -isnull(c.AdjustedUnitPrice,c.UnitPrice)
																	  ELSE isnull(c.AdjustedUnitPrice,c.UnitPrice)
																	  END )) as Month8Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
								OR a.CreditDebit = 'C')
																	  THEN -isnull(d.AdjustedUnitPrice,d.UnitPrice)
																	  ELSE isnull(d.AdjustedUnitPrice,d.UnitPrice)
																	  END )) as Month9Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
								OR a.CreditDebit = 'C')
																	  THEN -isnull(e.AdjustedUnitPrice,e.UnitPrice)
																	  ELSE isnull(e.AdjustedUnitPrice,e.UnitPrice)
																	  END )) as Month10Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
								OR a.CreditDebit = 'C')
																	  THEN -isnull(f.AdjustedUnitPrice,f.UnitPrice)
																	  ELSE isnull(f.AdjustedUnitPrice,f.UnitPrice)
																	  END )) as Month11Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation in (0,1,2))
								OR a.CreditDebit = 'C')
																	  THEN -isnull(g.AdjustedUnitPrice,g.UnitPrice)
																	  ELSE isnull(g.AdjustedUnitPrice,g.UnitPrice)
																	  END )) as Month12Budget
from Plan_AdjustmentProjectItem a
left join Plan_AdjustmentProjectItemMonth b on a.PlanAdjustmentProjectItem_ID = b.PlanAdjustmentProjectItemID and b.monthid = 1
left join Plan_AdjustmentProjectItemMonth c on a.PlanAdjustmentProjectItem_ID = c.PlanAdjustmentProjectItemID and c.monthid = 2
left join Plan_AdjustmentProjectItemMonth d on a.PlanAdjustmentProjectItem_ID = d.PlanAdjustmentProjectItemID and d.monthid = 3
left join Plan_AdjustmentProjectItemMonth e on a.PlanAdjustmentProjectItem_ID = e.PlanAdjustmentProjectItemID and e.monthid = 4
left join Plan_AdjustmentProjectItemMonth f on a.PlanAdjustmentProjectItem_ID = f.PlanAdjustmentProjectItemID and f.monthid = 5
left join Plan_AdjustmentProjectItemMonth g on a.PlanAdjustmentProjectItem_ID = g.PlanAdjustmentProjectItemID and g.monthid = 6
left join Plan_AdjustmentProjectItemMonth h on a.PlanAdjustmentProjectItem_ID = h.PlanAdjustmentProjectItemID and h.monthid = 7
left join Plan_AdjustmentProjectItemMonth i on a.PlanAdjustmentProjectItem_ID = i.PlanAdjustmentProjectItemID and i.monthid = 8
left join Plan_AdjustmentProjectItemMonth j on a.PlanAdjustmentProjectItem_ID = j.PlanAdjustmentProjectItemID and j.monthid = 9
left join Plan_AdjustmentProjectItemMonth k on a.PlanAdjustmentProjectItem_ID = k.PlanAdjustmentProjectItemID and k.monthid = 10
left join Plan_AdjustmentProjectItemMonth l on a.PlanAdjustmentProjectItem_ID = l.PlanAdjustmentProjectItemID and l.monthid = 11
left join Plan_AdjustmentProjectItemMonth m on a.PlanAdjustmentProjectItem_ID = m.PlanAdjustmentProjectItemID and m.monthid = 12
left join #Const_SCOA_Structure css on a.SCOAItemID = css.scoaid
left join Plan_AdjustmentProject pp on a.AdjustmentProjectID = pp.AdjustmentProject_ID

where a.FinYear = @Finyear AND ISNULL(pp.IsDeleted,0)<>1 and a.AdjustmentVersionId = (select max(adjustmentversionID) from Plan_AdjustmentProjectitem where FinYear = @finYear)
		 and isnull(pp.ReferenceProject_ID, -1) not in (select ProjectID from Plan_ProjectReportExclude)
group by a.FinYear ) Totals
Where  CurrentYear <> 0 or OuterYear1 <> 0 or  OuterYear2 <> 0 or Month1Budget <> 0 or Month2Budget <> 0 or Month3Budget <> 0 or Month4Budget <> 0 or Month5Budget <> 0 or Month6Budget <> 0 or Month7Budget <> 0 
         or Month8Budget <> 0 or Month9Budget <> 0 or Month10Budget <> 0 or Month11Budget <> 0 or Month12Budget <> 0 

Union All

---Charges and Recoveries must balance - CurrentYear

Select 'Charges and Recoveries must balance (CO001 and CO002 must balance) - CurrentYear' as ExceptionDetail,'CO001 and CO002 must balance - CurrentYear',cast(isnull(@ChargesY1,0) - isnull(@RecoveriesY1,0) as nVarchar(50))
Having isnull(@ChargesY1,0) + isnull(@RecoveriesY1,0) <> 0

Union All

---Charges and Recoveries must balance - CurrentYear

Select 'Charges and Recoveries must balance (CO001 and CO002 must balance) - OuterYear1' as ExceptionDetail,'CO001 and CO002 must balance - OuterYear1',cast(isnull(@ChargesY2,0) - isnull(@RecoveriesY2,0) as nVarchar(50))
Having isnull(@ChargesY2,0) + isnull(@RecoveriesY2,0) <> 0

Union All

---Charges and Recoveries must balance - CurrentYear

Select 'Charges and Recoveries must balance (CO001 and CO002 must balance) - OuterYear2' as ExceptionDetail,'CO001 and CO002 must balance - OuterYear2',cast(isnull(@ChargesY3,0) - isnull(@RecoveriesY3,0) as nVarchar(50))
Having isnull(@ChargesY3,0) + isnull(@RecoveriesY3,0) <> 0

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_NTLedgertValidations]    Script Date: 2026/03/10 7:23:44 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- ================================================================================================================================================
-- Author: Gansen 
-- Create Date: 26 April 2021
-- Description:	NTBudgetValidations 
-- 20220128 by CM: 80373 - Return validations only for PlanProjectItemIDs that has nett value <> 0 
-- 20220913 by CM: 90607 - Validation for Invalid string, ProjectId and PlanProjectItemID out of date to be check only from 22/23 fin year onwards
-- 20230920 by CM:106310 - Fix validation rule:Cost/Revenue Projects for Free Services vs Items (PO003057 PO003058 PO003059 only against IR or IA001010 OR IA001004 is valid)
--					                  - Use SCOA Consolidated tables
-- 20231220 GN:109026_108964 - add OB validations 
-- 20240213 by CM: 110254 - Fix validation rules: Capital Project vs Scoa Item (PC only against IA and IL001006011 and IL001006006 is valid)
-- 04/09/2024 SFS : 115176 update @recoveries to abs
-- 20241017 by CM: 115265 - Fix validation rule 1 - Add the following item.ScoaCode NOT LIKE 'IL001006023%' AND item.ScoaCode NOT LIKE 'IL001006024%' 
-- ================================================================================================================================================
CREATE PROCEDURE [dbo].[Plan_NTLedgertValidations]  
    @finYear NVARCHAR(10),
    @fromMonth INT, 
    @toMonth INT   

AS
BEGIN

	DECLARE @Charges decimal(18,2)
	DECLARE @Recoveries decimal(18,2)

	DECLARE @BudgetVersionID INT
	SELECT @BudgetVersionID = ISNULL(dbo.Section71_BudgetOriginalVersionID_fxn(@Finyear), -1)

	DECLARE @FinYearStart INT
	SELECT @FinYearStart = CONVERT(INT, SUBSTRING(@finYear, 1, 4))


	CREATE TABLE [dbo].[#Plan_BudgetVersionDetail](
     
			 [ProjectID]               int
			,[GenLedgerID]             Decimal(18,2)
		   , [ScoaProjectID]           [nvarchar](500)
		   , [ScoaFunctionID]          [nvarchar](500)
		   , [ScoaItemID]              [nvarchar](500)
		   , [ScoaFundID]              [nvarchar](500)
		   , [ScoaCostingID]           [nvarchar](500)
		   , [ScoaRegionID]            [nvarchar](500)
		   ,[DivisionID]               INT
			,[LEdAmount]               Decimal(18,2)
		   , [Debit]                   Decimal(18,2)
		   , [Credit]                  Decimal(18,2)
		   , [Finyear]                 [nvarchar](500)
		   , [PlanProjectItemID]	   [int]
		 )



		INSERT INTO #Plan_BudgetVersionDetail 
		SELECT
		  ProjectID
		 ,cast(GenLedger_ID as decimal(18,0))
		 ,SCOAProjectID
		 ,SCOAFunctionID
		 ,SCOAItemID
		 ,SCOAFundsID
		 ,SCOACostingID
		 ,SCOARegionID,DivisionID
		 ,ISNULL(Debit, 0.00) - ISNULL(Credit, 0.00)  as LedAmount
		 ,Debit
		 ,Credit
		 ,finyear
		 ,PlanProjectItemID
		FROM Led_GeneralLedger gl
		WHERE gl.FinYear =@FinYear
		  AND gl.ProcessingMonth BETWEEN @FromMonth AND @toMonth


	SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,scoadesc INTO #projectTable FROM Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @Finyear
	SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,scoadesc  INTO #functionTable FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @Finyear
	SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,scoadesc,ScoaShortDesc INTO #itemTable FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @Finyear
	SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,scoadesc INTO #fundsTable FROM Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @Finyear
	SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,scoadesc INTO #costingTable FROM Const_SCOA_Costing_Structure_Consolidated WHERE FinYearText = @Finyear
	SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,scoadesc INTO #regionalTable FROM Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @Finyear

	Select @Charges = sum(LedAmount)
	from  
				  #Plan_BudgetVersionDetail a left join
				  #costingTable c on  a.SCOACostingID = c.scoaid 
	 where    c.scoacode like'CO001%'
		
	Select @Recoveries = abs (sum (LedAmount))
	from  
				  #Plan_BudgetVersionDetail a left join
				  #costingTable c on  a.SCOACostingID = c.scoaid 
	where   c.scoacode like'CO002%'


	Select ExceptionDetail, Cast(ProjectID as Varchar(50)) as ProjectID,Cast(cast(GenLedgerID as decimal(18,0)) as Varchar(50)) as GenLedgerID
	From

	(
	
	---GL vs Budget PlanProjectItems
	select gl.ProjectID as ProjectID, GenLedgerID as GenLedgerID ,'Invalid string' ExceptionDetail

from
(select * from #Plan_BudgetVersionDetail where FinYear = @Finyear and IsNULL(PlanProjectItemID,0) <> 0)GL
join Plan_projectItem PPI ON ppi.PlanProjectItem_ID = gl.PlanProjectItemID
join Plan_Project PR ON PR.Project_ID = gl.ProjectID 
Left join const_scoa_structure_ByYear(@Finyear) scoa on scoa.ScoaID = gl.scoaitemID
Left join const_scoa_structure_ByYear(@Finyear) scoappi on scoappi.ScoaID =ppi.scoaitemID
where
(ISNULL(GL.ScoaRegionId, 0) <> PPI.SCOARegionId OR
ISNULL(GL.SCOACostingID, 0) <> PPI.SCOACostingID OR
ISNULL(GL.SCOAFunctionID, 0) <> ppi.SCOAFunctionId OR
ISNULL(GL.DivisionID, 0) <> ppi.DivisionId OR
ISNULL(GL.SCOAFundID, 0) <> ppi.SCOAFundId OR
ISNULL(GL.SCOAProjectID, 0) <> PR.ScoaProjectID OR
ISNULL(Gl.SCOAItemID, 0) <> ppi.SCOAItemID OR
ISNULL(Gl.ProjectID, 0) <> ppi.ProjectID)
and @FinYearStart >= 2022
union 
select gl.ProjectID as ProjectID, GenLedgerID as GenledgerID,'PlanprojectItemId out of date' ExceptionDetail

from #Plan_BudgetVersionDetail gl
Left join const_scoa_structure_ByYear(@Finyear) scoa on scoa.ScoaID = gl.scoaitemID
where finyear = @Finyear and isnull(planprojectitemId,0) not in (select PlanProjectItem_id from Plan_ProjectItem where FinYear = @Finyear) and @FinYearStart >= 2022

union 
select gl.ProjectID as ProjectID, GenLedgerID as GenLedgerID,'ProjectId out of date' ExceptionDetail
from #Plan_BudgetVersionDetail gl  
Left join const_scoa_structure_ByYear(@Finyear) scoa on scoa.ScoaID = gl.scoaitemID
where finyear = @Finyear and isnull(ProjectID,0) not in (select Project_Id from Plan_project where FinYear = @Finyear) and @FinYearStart >= 2022

UNION ALL

	--Capital Projects vs Item Assets
	select ProjectID, GenLedgerID,'Capital Project vs Scoa Item (PC only against IA and IL001006011 23 24 and IL001006006 is valid)' as ExceptionDetail
	from
		(
			select   PlanProjectItemID
			from #Plan_BudgetVersionDetail a left join
				 #itemTable c on a.ScoaItemid  = c.ScoaID  left join
				 #projectTable d on a.ScoaProjectID = d.scoaid 
			where  (c.Scoacode not like 'IA%' AND c.ScoaCode not like 'IL001006011%' AND c.ScoaCode not like 'IL001006023%' AND c.ScoaCode not like 'IL001006024%' AND c.ScoaCode not like 'IL001006006%')
					and d.ScoaDesc like 'Capital%' 
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID


	Union All

	-- Operational Projects vs Items 
	select ProjectID, GenLedgerID, 'Operation Project vs Scoa Item (PO not valid against IA002 level acquisitions or additions)' as ExceptionDetail 
	from
		(
			select PlanProjectItemID 
			from #Plan_BudgetVersionDetail a left join
				 #itemTable c on  a.ScoaItemID = c.scoaid left join
				 #ProjectTable d on a.ScoaProjectID = d.scoaid 
			where     d.ScoaDesc like 'Operational%'
					  and (  (c.scoacode like 'IA002%' and c.scoadesc like '%additions%') or
					   (c.scoacode like 'IA002%' and c.scoadesc like '%acquisitions')) 
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID

	Union All

	-- Cost of free basic services, Revenue Cost of Free Services and Property Rebates  vs Items 
	select ProjectID, GenLedgerID, 'Cost/Revenue Projects for Free Services vs Items (PO003057 PO003058 PO003059 only against IR or IA001010 OR IA001004 is valid)' as ExceptionDetail  
	from
		(
			select PlanProjectItemID
			from #Plan_BudgetVersionDetail a left join
				 #ItemTable c on  a.ScoaItemID = c.scoaid left join
				 #ProjectTable d on a.ScoaProjectID = d.scoaid 
			where     ( d.ScoaCode like 'PO003057%' or d.ScoaCode like 'PO003058%' or d.ScoaCode like 'PO003059%')
					   and ( c.ScoaCode not like 'IR%' and c.ScoaCode not like 'IA001010%' and c.ScoaCode not like 'IA001004%') and SCOAItemID <> '' 
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID


	Union All

	-- IA IL LN Opening Balance must use Project Default
	select ProjectID, GenLedgerID, 'IA IL LN Opening Balance must use Project Default' as ExceptionDetail  
	from
		(
			select PlanProjectItemID
			from #Plan_BudgetVersionDetail a left join
				 #ItemTable c on  a.ScoaItemID = c.scoaid left join
				 #ProjectTable d on a.ScoaProjectID = d.scoaid 
			where  ((c.ScoaShortDesc = 'Opening Balance') and (c.ScoaCode like 'IL%' or c.ScoaCode like 'IA%' or c.ScoaCode like 'LN%'))
                                and (d.ScoaCode not like 'PD%')

			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID


	Union All

		-- IA IL LN Opening Balance must use Costing Default
	select ProjectID, GenLedgerID, 'IA IL LN Opening Balance must use Costing Default' as ExceptionDetail  
	from
		(
			select PlanProjectItemID
			from #Plan_BudgetVersionDetail a left join
				 #ItemTable c on  a.ScoaItemID = c.scoaid left join
				 #CostingTable d on a.ScoaCostingID = d.scoaid 
			where  ((c.ScoaShortDesc = 'Opening Balance') and (c.ScoaCode like 'IL%' or c.ScoaCode like 'IA%' or c.ScoaCode like 'LN%'))
                                and (d.ScoaCode not like 'CO003%')

			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID

  Union All

		-- IA IL LN Opening Balance must use Non-Funding
	select ProjectID, GenLedgerID, 'IA IL LN Opening Balance must use Non-Funding' as ExceptionDetail  
	from
		(
			select PlanProjectItemID
			from #Plan_BudgetVersionDetail a left join
				 #ItemTable c on  a.ScoaItemID = c.scoaid left join
				 #fundsTable d on a.ScoaFundID = d.scoaid 
			where  ((c.ScoaShortDesc = 'Opening Balance') and (c.ScoaCode like 'IL%' or c.ScoaCode like 'IA%' or c.ScoaCode like 'LN%'))
                                and (d.ScoaCode not like 'FD003%')

			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID

	Union All

	 -- Operational Project vs Scoa Item (PO not valid against Revenue Item if not FBS/Rebates Project
	select ProjectID, GenLedgerID, 'Operational Project vs Scoa Item (PO not valid against Revenue Item if not FBS/Rebates Project)' as ExceptionDetail 
	from
		(
			select  PlanProjectItemID 
			from #Plan_BudgetVersionDetail a left join
				 #ItemTable c on  a.ScoaItemID = c.scoaid left join
				 #ProjectTable d on a.ScoaProjectID = d.scoaid 
			where    d.ScoaDesc not like '%Cost of Free Basic Services%' and  d.ScoaDesc not like '%Revenue Cost of Free Services%'
						 and  d.ScoaDesc not  like '%property rates rebate%' and d.scoacode like 'PO%'
					  and  c.scoadesc  like 'Revenue%' and SCOAItemID <> '' 
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID


	Union All

	---- Default Projects vs Items 
	Select distinct ProjectID, GenLedgerID, 'Default Projects vs Items (PD not valid against IE or IA except IA001 or IA002011 or IE018 or IE019)' as ExceptionDetail
	from
		(
			Select PlanProjectItemID
			from [dbo].[#Plan_BudgetVersionDetail] b left join
				   (select   GenLedgerID, a.Scoaitemid, c.ScoaCode, d.ScoaDesc as ScoaProject, a.SCOAFundId, c.scoadesc as scoaitemdesc
					from [dbo].[#Plan_BudgetVersionDetail] a left join
						 #ItemTable c on  a.ScoaItemid = c.scoaid left join
						 #ProjectTable d on a.ScoaProjectID = d.scoaid 
					where (c.ScoaDesc like 'Expenditure%' or c.ScoaDesc like 'Assets%') 
					and d.ScoaDesc like 'default%' and a.SCOAItemID <> '0' and a.ScoaProjectID <> '0') xy on b.GenLedgerID = xy.GenLedgerID and b.SCOAItemID =xy.ScoaItemid and b.scoafundid =xy.Scoafundid
			where (xy.scoaitemdesc not like 'Expenditure:Default%'
				  and xy.scoaitemdesc not like 'Assets:current Assets%' 
				  and xy.scoaitemdesc not like 'Assets:Non-current Assets%' 
				  and xy.scoaitemdesc not like '%Accumulated%'
				  and xy.scoaitemdesc not like '%Opening Balance')	
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID


	Union All	  

	-- Default Projects vs Items Part 2
	select distinct ProjectID, GenLedgerID,'Default Projects vs Items (PD not valid against IE or IA except IA001 or IA002011 or IE018 or IE019)' as ExceptionDetail
	from 
		(
			select PlanProjectItemID
			from #Plan_BudgetVersionDetail
			where PlanProjectItemID in 
				(
					select distinct PlanProjectItemID -- a.ProjectID, a.GenLedgerID,'Default Projects vs Items (PD not valid against IE or IA except IA001 or IA002011 or IE018 or IE019)' as ExceptionDetail
					from #Plan_BudgetVersionDetail a left join
						 #itemTable c on a.ScoaItemid  = c.ScoaID  left join
						 #projectTable d on a.ScoaProjectID = d.scoaid 
					where  (c.ScoaDesc like 'Assets:Non-current Assets%' and c.ScoaDesc  like '%acquisitions%'  and c.ScoaDesc not like '%Work-in-progress%')
							and d.ScoaDesc like 'Default%' 
				) 
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID


	Union All

	-- Remuneration of Councillors not against Mayor and Council
	select ProjectID, GenLedgerID, 'Item Remuneration of Councillors not against Function Mayor and Council (IE008 must use FX004)' as ExceptionDetail  
	from
		(
			select  PlanProjectItemID
			from #Plan_BudgetVersionDetail a left join
				 #ItemTable c on  a.ScoaItemID = c.scoaid left join
				 #FunctionTable d on a.ScoafunctionID = d.scoaid 
			where   c.ScoaCode like 'IE008%'
					and d.Scoadesc  not like 'Function:Executive and Council:Core Function:Mayor and Council'	
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID


	Union All


	-- Bulk electricity Purchases items vs Functions
	select ProjectID, GenLedgerID, 'Item: Bulk purchase electricity must use Function: Electricity (IE002001 must use FX002001001 or FX002002001)' as ExceptionDetail  
	from
		(
			select PlanProjectItemID
			from #Plan_BudgetVersionDetail a left join
				 #ItemTable c on  a.ScoaItemID = c.scoaid left join
				 #FunctionTable d on a.ScoafunctionID = d.scoaid 
			where  c.ScoaCode like 'IE002001%'
					and d.ScoaCode not  like 'FX002001001%' and  d.ScoaCode  not like 'FX002002001%'
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID
	

	Union All


	-- Bulk Water Purchases items vs Functions
	select ProjectID, GenLedgerID, 'Item: Bulk purchases water must use Function: Water (IE002002 must use FX016001002 or FX016002002)' as ExceptionDetail  
	from
		(
			select PlanProjectItemID
			from #Plan_BudgetVersionDetail a left join
				  #ItemTable c on  a.ScoaItemID = c.scoaid left join
				 #FunctionTable d on a.ScoafunctionID = d.scoaid 
			where  c.ScoaCode like 'IE002002%'
					and d.ScoaCode  not like 'FX016001002%'
					and d.ScoaCode  not like 'FX016002002%'
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID


	Union All


	-- Inventory consumed: Water items vs Functions
	select ProjectID, GenLedgerID, 'Item: Inventory consumed water must use Function: Water (IE007004 must use FX016001002 or FX016002002)' as ExceptionDetail 
	from
		(
			select  PlanProjectItemID 
			from #Plan_BudgetVersionDetail a left join
				  #ItemTable c on  a.ScoaItemID = c.scoaid left join
				 #FunctionTable d on a.ScoafunctionID = d.scoaid 
			where  c.ScoaCode like 'IE007004%' 
					and d.ScoaCode  not like 'FX016001002%'
					and d.ScoaCode  not like 'FX016002002%'
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID


	Union All


		-- Inventory consumed: Water items vs Functions
	select ProjectID, GenLedgerID, 'Item: Inventory consumed water must use Function: Water (IA001009005% must use FX01)' as ExceptionDetail 
	from
		(
			select  PlanProjectItemID 
			from #Plan_BudgetVersionDetail a left join
				  #ItemTable c on  a.ScoaItemID = c.scoaid left join
				 #FunctionTable d on a.ScoafunctionID = d.scoaid 
			where   c.ScoaCode like 'IA001009005%'
					and d.ScoaCode  not like 'FX016%'
					
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID


	Union All

	-- Region Segment cant be defualt 
	select ProjectID, GenLedgerID, 'Default Region not valid (RX001 not valid)' as ExceptionDetail  
	from
		(
			select PlanProjectItemID
			from #Plan_BudgetVersionDetail a left join
				 #regionalTable d on a.ScoaRegionID = d.scoaid 
			where  d.ScoaCode  like 'RX001%'
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID


	Union All


	--Default Costing and default Expenditure not valid (CO003 and IE018 not valid) 
	select ProjectID, GenLedgerID, 'Default Costing and default Expenditure not valid (CO003 and IE018 not valid)' as ExceptionDetail
	from
		(
			select PlanProjectItemID 
			from #Plan_BudgetVersionDetail a left join
				 #ItemTable c on  a.ScoaItemID = c.scoaid left join
				 #costingTable d on a.ScoaCostingID = d.scoaid 
			where   c.ScoaCode like 'IE018%'
					and d.ScoaCode  like 'CO003%'
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID

		
	Union All

		
	--Default Costing and default Revenue not valid(CO003 and IR004 not valid)  
	select ProjectID, GenLedgerID, 'Default Costing and default Revenue not valid(CO003 and IR004 not valid) ' as ExceptionDetail 
	from
		(
			select  PlanProjectItemID
			from #Plan_BudgetVersionDetail a left join
				 #ItemTable c on  a.ScoaItemID = c.scoaid left join
				 #costingTable d on a.ScoaCostingID = d.scoaid 
			where  c.ScoaCode like 'IR004%'
					and d.ScoaCode  like 'CO003%'
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID


	Union All


	--Small Differences Tolerances must be zero (IE010053 must be zero) 
	select   a.ScoaItemID, a.ScoaItemID, 'Small Differences Tolerances must be zero (IE010053 must be zero)' as ExceptionDetail 
	from #Plan_BudgetVersionDetail a left join
		 #ItemTable c on  a.ScoaItemID = c.scoaid 
	where  c.ScoaCode like 'IE010053%' 
	group by a.ScoaItemID
	Having  sum(LedAmount) <> 0


	Union All


	--Scoa Items is at Posting Level or Breakdown Allowed
	-- Item Segement
	select ProjectID, GenLedgerID, 'ScoaItem Segment not in chart or not at Postinglevel' as ExceptionDetail   
	from
		(
			select PlanProjectItemID
			From #Plan_BudgetVersionDetail a left join
				 #ItemTable c on  a.ScoaItemID = c.scoaid and c.PostingLevel = 'Yes'
			Where  c.scoaid is null
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID

	Union All

	-- Project Segement
	select ProjectID, GenLedgerID, 'ScoaProject Segment not in chart or not at Postinglevel' as ExceptionDetail
	from
		(
			Select PlanProjectItemID   
			From #Plan_BudgetVersionDetail a left join
				 #ProjectTable c on  a.ScoaProjectID = c.scoaid and (c.PostingLevel = 'Yes' or c.BreakDownAllowed = 'Yes')
			Where  c.scoaid is null
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID

	Union All

	-- Fund Segement
	select ProjectID, GenLedgerID, 'ScoaFund Segment not in chart or not at Postinglevel' as ExceptionDetail 
	from
		(
			Select PlanProjectItemID  
			From #Plan_BudgetVersionDetail a Left Join
				 #fundsTable c on  a.ScoaFundID = c.scoaid and c.PostingLevel = 'Yes'
			Where  c.scoaid is null 
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID

	Union All


	-- Function Segement
	select ProjectID, GenLedgerID, 'ScoaFunction Segment not in chart or not at Postinglevel' as ExceptionDetail  
	from
		(
			Select PlanProjectItemID 
			From #Plan_BudgetVersionDetail a left join
				 #FunctionTable c on  a.ScoaFunctionID = c.scoaid and c.PostingLevel = 'Yes'
			Where  c.scoaid is null 
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID

	Union All

	-- Region Segement
	select ProjectID, GenLedgerID, 'ScoaRegion Segment not in chart or not at Postinglevel' as ExceptionDetail 
	from
		(
			Select PlanProjectItemID  
			From #Plan_BudgetVersionDetail a left join
				 #regionalTable c on   a.ScoaRegionID= c.scoaid and c.PostingLevel = 'Yes'
			Where c.scoaid is null 
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID

	Union All


	-- Costing Segement
	select ProjectID, GenLedgerID, 'ScoaCosting Segment not in chart or not at Postinglevel' as ExceptionDetail  
	from
		(
			Select PlanProjectItemID 
			From #Plan_BudgetVersionDetail a left join
				 #costingTable c on a.ScoaCostingID  = c.scoaid and c.PostingLevel = 'Yes'
			Where  c.scoaid is null
			group by PlanProjectItemID
			having sum(debit) - sum(credit) <> 0
		) ppi

		inner join #Plan_BudgetVersionDetail led on ppi.PlanProjectItemID = led.PlanProjectItemID

	) Expt




Union All


	--Trial Balance (sum of all items - IE018 and IR004)
	select 'Trial Balance (sum of all items - IE018 and IR004)' as ExceptionDetail ,'Trial Balance Difference' , cast(sum(ledAmount) as decimal(18,0))
	from	
				  #Plan_BudgetVersionDetail a left join
				  #ItemTable c on  a.ScoaItemID = c.scoaid 
	Having sum(LedAmount) <> 0

	Union All

	---Charges and Recoveries must balance

	Select 'Charges and Recoveries must balance (CO001 and CO002 must balance)' as ExceptionDetail,'CO001 and CO002 must balance',cast(isnull(@Charges,0) - isnull(@Recoveries,0) as nVarchar(50))
	Having isnull(@Charges,0) - isnull(@Recoveries,0) <> 0



    DROP TABLE #projectTable
	DROP TABLE #functionTable
	DROP TABLE #itemTable
	DROP TABLE #fundsTable
	DROP TABLE #costingTable
	DROP TABLE #regionalTable
	DROP TABLE #Plan_BudgetVersionDetail


END
GO

/****** Object:  StoredProcedure [dbo].[Plan_NTORGBudgetValidations]    Script Date: 2026/03/10 7:23:44 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author: Gansen 
-- Create Date: 26 April 2021
-- Description:	NT ORGB Budget Validations
-- 210729 by CM: Fix join on calculation for Year & Month Totals Dont Balance to Zero
-- 211005 by CM: 74961 - Exclude Revenue Items vs Funding check for fin years prior to 2021/2022
-- 220401 by CM: 85467 - Include additional validations as per NT
--						 Both Capital and Operating projects must be used
--						 IA IL LN Opening Balance must use Project and Costing Default and Non-Funding
--						 Item: Inventory water must use Function: Water
--						 Charges and Recoveries must use default Expenditure (CO001 and CO002 must use IE018)
-- 220404 by CM: 85577 - Exclude projects in Plan_ProjectReportExclude for Trial Balance, Year and Month budgets balance to zero checks
-- 230403 by CM: 99168 - Optimise Default Projects vs Items validation
-- 230601 by CM: 103219 - Sum and Group monthly breakdown by PlanProjectItemID and MonthID to pinpoint duplication issue
-- 230920 by CM: 106310 - Fix validation rule:Cost/Revenue Projects for Free Services vs Items (PO003057 PO003058 PO003059 only against IR or IA001010 OR IA001004 is valid)
--								   - Use SCOA Consolidated tables
-- 240213 by CM: 110254 - Fix validation rules: Charges and Recoveries must balance (CO001 and CO002 must balance) and Capital Project vs Scoa Item (PC only against IA and IL001006011 and IL001006006 is valid)
-- 240524 by CM: 112433 - Fix validation rules: Charges and Recoveries must balance (CO001 and CO002 must balance) applied for outer years
-- 241017 by CM: 115265 - Fix validation rule 1 - Add the following item.ScoaCode NOT LIKE 'IL001006023%' AND item.ScoaCode NOT LIKE 'IL001006024%' 
-- [dbo].[Plan_NTORGBudgetValidations] '2024/2025'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_NTORGBudgetValidations]
   
@finYear NVARCHAR(10)

AS
BEGIN

DECLARE @ChargesY1 decimal(18,2), @ChargesY2 decimal(18,2), @ChargesY3 decimal(18,2)
DECLARE @RecoveriesY1 decimal(18,2), @RecoveriesY2 decimal(18,2), @RecoveriesY3 decimal(18,2)
DECLARE @FinYearStart INT
DECLARE @FinYearStart_RevenueDefaultFundingCheckValid INT = 2021
DECLARE @BudgetVersionID INT, @CountOperationalProject INT, @CountCapitalProject INT

SELECT @FinYearStart = CONVERT(INT, SUBSTRING(@finYear, 1, 4))
SELECT @BudgetVersionID = ISNULL(dbo.Section71_BudgetOriginalVersionID_fxn(@Finyear), -1)

CREATE TABLE [dbo].[#Plan_BudgetVersionDetail](
         [ProjectID]               INT 
	   , [PlanProjectItemID]           INT  
       , [CapitalOperation]        INT
	   , [ScoaProjectID]           [nvarchar](500)
	   , [ScoaItemID]               [nvarchar](500)
       , [ScoaCostingID]           [nvarchar](500)
       , [ScoaFunctionID]          [nvarchar](500)
       , [ScoaFundID]              [nvarchar](500)
       , [ScoaRegionID]            [nvarchar](500)
	    ,[BudgetAmount]             Decimal(18,2)
       , [BudgetAmountCurP1]        Decimal(18,2)
       , [BudgetAmountCurP2]        Decimal(18,2)
	   , [Finyear]           [nvarchar](500)
     )

CREATE TABLE [dbo].[#Plan_BudgetVersionMonths](
		 PlanProjectItemID INT
		,MonthID		   INT
		,UnitQuantity	   DECIMAL(18,2)
		,UnitPrice		   DECIMAL(18,2)
     )

IF (@BudgetVersionID = -1)
BEGIN
	INSERT INTO #Plan_BudgetVersionDetail 
	SELECT 
		ppi.ProjectID,ppi.PlanProjectItem_ID, p.CapitalOperation, p.ScoaProjectID, 
		ppi.SCOAItemID,ppi.SCOACostingID,ppi.SCOAFunctionId,ppi.SCOAFundId,ppi.SCOARegionId, BudgetAmount,BudgetAmountCurP1, BudgetAmountCurP2,ppi.Finyear
    FROM  
		Plan_ProjectItem  ppi left join
        Plan_Project p on ppi.ProjectID = p.Project_ID
    WHERE isnull(isdeleted,0) <> 1 and ppi.Finyear = @finYear

	INSERT INTO #Plan_BudgetVersionMonths
    SELECT PlanProjectItemID, MonthId, sum(isnull(UnitQuantity,0)) AS UnitQuantity, sum(isnull(UnitPrice,0)) AS UnitPrice
	FROM Plan_ProjectItemMonth
	WHERE PlanProjectItemID in (Select PlanProjectItem_ID from Plan_ProjectItem where Finyear = @Finyear) 
	GROUP BY PlanProjectItemID, MonthId

END 
ELSE 
BEGIN
	INSERT INTO #Plan_BudgetVersionDetail 
	SELECT 
		bvd.ProjectID, bvd.PlanProjectItemID, bvd.CapitalOperation, bvd.ScoaProjectID, 
		bvd.SCOAItemID,bvd.SCOACostingID, bvd.SCOAFunctionId,bvd.SCOAFundId,bvd.SCOARegionId, BudgetAmount,BudgetAmountCurP1, BudgetAmountCurP2,BVD.FinYear
    FROM  
		Plan_BudgetVersionDetail bvd
		LEFT JOIN Plan_Project p on bvd.ProjectID = p.Project_ID
    WHERE isnull(isdeleted,0) <> 1 and BudgetVersionID = @BudgetVersionID

	INSERT INTO #Plan_BudgetVersionMonths
    SELECT PlanProjectItemID, MonthId,sum(isnull(UnitQuantity,0)) AS UnitQuantity, sum(isnull(UnitPrice,0)) AS UnitPrice
	FROM Plan_BudgetVersionMonths
	WHERE BudgetVersionID = @BudgetVersionID 
	GROUP BY PlanProjectItemID, MonthId
END
 
SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,scoadesc INTO #projectTable FROM Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @Finyear
SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,scoadesc  INTO #functionTable FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @Finyear
SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,scoadesc,ScoaShortDesc INTO #itemTable FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @Finyear
SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,scoadesc INTO #fundsTable FROM dbo.Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @Finyear
SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,scoadesc INTO #costingTable FROM dbo.Const_SCOA_Costing_Structure_Consolidated WHERE FinYearText = @Finyear
SELECT ScoaID,PostingLevel,BreakDownAllowed,NTScoaID,ScoaCode,scoadesc INTO #regionalTable FROM dbo.Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @Finyear

Select 
	@ChargesY1 = SUM(CASE WHEN (((b.ScoaCode LIKE 'IR%' OR b.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -isnull([a].BudgetAmount,0) ELSE isnull([a].BudgetAmount,0) END),
	@ChargesY2 = SUM(CASE WHEN (((b.ScoaCode LIKE 'IR%' OR b.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -isnull([a].BudgetAmountCurP1,0) ELSE isnull([a].BudgetAmountCurP1,0) END),
	@ChargesY3 = SUM(CASE WHEN (((b.ScoaCode LIKE 'IR%' OR b.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -isnull([a].BudgetAmountCurP2,0) ELSE isnull([a].BudgetAmountCurP2,0) END)
from  
	#Plan_BudgetVersionDetail a left join
	#itemTable b on a.ScoaItemID = b.ScoaID left join
	#costingTable c on  a.SCOACostingID = c.scoaid left join
	Plan_ProjectItem ppi on a.PlanProjectItemID = ppi.PlanProjectItem_ID
 where    c.scoacode like'CO001%'
		
Select 
	@RecoveriesY1 = SUM(CASE WHEN (((b.ScoaCode LIKE 'IR%' OR b.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -isnull([a].BudgetAmount,0) ELSE isnull([a].BudgetAmount,0) END),
	@RecoveriesY2 = SUM(CASE WHEN (((b.ScoaCode LIKE 'IR%' OR b.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -isnull([a].BudgetAmountCurP1,0) ELSE isnull([a].BudgetAmountCurP1,0) END),
	@RecoveriesY3 = SUM(CASE WHEN (((b.ScoaCode LIKE 'IR%' OR b.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2)) OR CreditDebit = 'C') THEN -isnull([a].BudgetAmountCurP2,0) ELSE isnull([a].BudgetAmountCurP2,0) END)						 
from  
		      #Plan_BudgetVersionDetail a left join
			  #itemTable b on a.ScoaItemID = b.ScoaID left join
			  #costingTable c on  a.SCOACostingID = c.scoaid left join
			  Plan_ProjectItem ppi on a.PlanProjectItemID = ppi.PlanProjectItem_ID
where   c.scoacode like'CO002%'

select @CountCapitalProject = count(ProjectID) 
from #Plan_BudgetVersionDetail pp
		left join #projectTable scoaProject on pp.ScoaProjectID = scoaProject.ScoaID
where 
	ScoaCode like 'PC%'


select @CountOperationalProject = count(ProjectID) 
from #Plan_BudgetVersionDetail pp
	 left join #projectTable scoaProject on pp.ScoaProjectID = scoaProject.ScoaID
where 
	ScoaCode like 'PO%'

Select ExceptionDetail, Cast(ProjectID as Varchar(50)) as ProjectID,Cast(cast (PlanProjectItemID as  decimal(10,0))as Varchar(50)) as PlanProjectItemID
From

(
--Budget Value vs Projections M01 to M12 Value 
select a.ProjectID, a.PlanProjectItemID, 'ProjectItem Year Amt vs Monthly Total Amt' as ExceptionDetail
from #Plan_BudgetVersionDetail a
left join #Plan_BudgetVersionMonths b on a.PlanProjectItemID = b.PlanProjectItemID
group by a.PlanProjectItemID, a.BudgetAmount,a.ProjectID
having (isnull(BudgetAmount,0)) <> sum(isnull(unitprice,0))

Union All

--Capital Projects vs Item Assets
select   a.ProjectID, a.PlanProjectItemID,'Capital Project vs Scoa Item (PC only against IA and IL001006011 23 24 and IL001006006 is valid)' as ExceptionDetail
from #Plan_BudgetVersionDetail a left join
	 #itemTable c on a.ScoaItemid  = c.ScoaID  left join
	 #projectTable d on a.ScoaProjectID = d.scoaid 
where  (c.Scoacode not like 'IA%' AND c.ScoaCode not like 'IL001006011%' AND c.ScoaCode not like 'IL001006023%' AND c.ScoaCode not like 'IL001006024%' AND c.ScoaCode not like 'IL001006006%')
		and d.ScoaDesc like 'Capital%' 


Union All

-- Operational Projects vs Items 
select    a.ProjectID, a.PlanProjectItemID, 'Operation Project vs Scoa Item (PO not valid against IA002 level acquisitions or additions)' as ExceptionDetail
--AdjustmentProjectName, d.ScoaDesc as ScoaFunction , c.scoadesc as ScoaItem , isnull(BudgetAmount,BudgetAmount) as [2019/2020] , isnull(BudgetAmount,BudgetAmountCurP1) as [2020/2021], isnull(BudgetAmount,BudgetAmountCurP2) as [2021/2022] 
from #Plan_BudgetVersionDetail a left join
	 #itemTable c on  a.ScoaItemID = c.scoaid left join
	 #ProjectTable d on a.ScoaProjectID = d.scoaid 
where  (isnull(BudgetAmount,BudgetAmount) + (isnull(BudgetAmountCurP1,BudgetAmountCurP1) +isnull(BudgetAmountCurP2, BudgetAmountCurP2) ) > 0)
		  and d.ScoaDesc like 'Operational%'
		  and (  (c.scoacode like 'IA002%' and c.scoadesc like '%additions%') or
		   (c.scoacode like 'IA002%' and c.scoadesc like '%acquisitions')) 

Union All

-- Cost of free basic services, Revenue Cost of Free Services and Property Rebates  vs Items 
select   a.ProjectID, a.PlanProjectItemID, 'Cost/Revenue Projects for Free Services vs Items (PO003057 PO003058 PO003059 only against IR or IA001010 OR IA001004 is valid)' as ExceptionDetail  
from #Plan_BudgetVersionDetail a left join
	 #ItemTable c on  a.ScoaItemID = c.scoaid left join
	 #ProjectTable d on a.ScoaProjectID = d.scoaid 
where  (isnull(BudgetAmount,BudgetAmount) + (isnull(BudgetAmountCurP1,BudgetAmountCurP1) +isnull(BudgetAmountCurP2, BudgetAmountCurP2) ) > 0)
		  and ( d.ScoaCode like 'PO003057%' or d.ScoaCode like 'PO003058%' or d.ScoaCode like 'PO003059%')
		  and ( c.ScoaCode not like 'IR%' and c.ScoaCode not like 'IA001010%' and c.ScoaCode not like 'IA001004%') and SCOAItemID <> '' 


Union All

 -- Operational Project vs Scoa Item (PO not valid against Revenue Item if not FBS/Rebates Project
select   a.ProjectID, a.PlanProjectItemID, 'Operational Project vs Scoa Item (PO not valid against Revenue Item if not FBS/Rebates Project)' as ExceptionDetail  
from #Plan_BudgetVersionDetail a left join
	 #ItemTable c on  a.ScoaItemID = c.scoaid left join
	 #ProjectTable d on a.ScoaProjectID = d.scoaid 
where  (isnull(BudgetAmount,BudgetAmount) + (isnull(BudgetAmountCurP1,BudgetAmountCurP1) +isnull(BudgetAmountCurP2, BudgetAmountCurP2) ) > 0)
		  and d.ScoaDesc not like '%Cost of Free Basic Services%' and  d.ScoaDesc not like '%Revenue Cost of Free Services%'
		     and  d.ScoaDesc not  like '%property rates rebate%' and d.scoacode like 'PO%'
		  and  c.scoadesc  like 'Revenue%' and SCOAItemID <> '' 


Union All

-- Default Projects vs Items 
select xy.ProjectID, xy.PlanProjectItemID, 'Default Projects vs Items (PD not valid against IE or IA except IA001 or IA002011 or IE018 or IE019)' as ExceptionDetail 
from
       (
	     select   a.ProjectID, a.PlanProjectItemID, a.Scoaitemid, c.scoadesc as scoaitemdesc
         from 
			 [dbo].[#Plan_BudgetVersionDetail] a left join
	         #ItemTable c on  a.ScoaItemid = c.scoaid left join
			 #ProjectTable d on a.ScoaProjectID = d.scoaid 
         where 
			(c.ScoaDesc like 'Expenditure%' or c.ScoaDesc like 'Assets%') 
			and (isnull(BudgetAmount,0) + isnull(BudgetAmountCurP1,0 +isnull(BudgetAmountCurP2, 0) ) > 0)
			and d.ScoaDesc like 'default%' and isnull(a.SCOAItemID, 0) <> 0 and isnull(a.ScoaProjectID, 0) <> 0
		) xy
where (xy.scoaitemdesc not like 'Expenditure:Default%'
      and xy.scoaitemdesc not like 'Assets:current Assets%' 
	  and xy.scoaitemdesc not like 'Assets:Non-current Assets%' 
	  and xy.scoaitemdesc not like '%Accumulated%'
	  and xy.scoaitemdesc not like '%Opening Balance')


Union All	  

-- Default Projects vs Items Part 2
select   a.ProjectID, a.PlanProjectItemID,'Default Projects vs Items (PD not valid against IE or IA except IA001 or IA002011 or IE018 or IE019)' as ExceptionDetail
from #Plan_BudgetVersionDetail a left join
	 #itemTable c on a.ScoaItemid  = c.ScoaID  left join
	 #projectTable d on a.ScoaProjectID = d.scoaid 
where  (c.ScoaDesc like 'Assets:Non-current Assets%' and c.ScoaDesc  like '%acquisitions%'  and c.ScoaDesc not like '%Work-in-progress%')
		and d.ScoaDesc like 'Default%' and 
		(isnull(BudgetAmount,BudgetAmount) + (isnull(BudgetAmountCurP1,BudgetAmountCurP1) +isnull(BudgetAmountCurP2, BudgetAmountCurP2) ) > 0)

Union All

-- Remuneration of Councillors not against Mayor and Council
select  a.ProjectID, a.PlanProjectItemID, 'Item Remuneration of Councillors not against Function Mayor and Council (IE008 must use FX004)' as ExceptionDetail  
from #Plan_BudgetVersionDetail a left join
	 #ItemTable c on  a.ScoaItemID = c.scoaid left join
	 #FunctionTable d on a.ScoafunctionID = d.scoaid 
where   c.ScoaCode like 'IE008%'
		and d.Scoadesc  not like 'Function:Executive and Council:Core Function:Mayor and Council'	


Union All


-- Bulk electricity Purchases items vs Functions
select a.ProjectID, a.PlanProjectItemID, 'Item: Bulk purchase electricity must use Function: Electricity (IE002001 must use FX002001001 or FX002002001)' as ExceptionDetail  
from #Plan_BudgetVersionDetail a left join
	 #ItemTable c on  a.ScoaItemID = c.scoaid left join
	 #FunctionTable d on a.ScoafunctionID = d.scoaid 
where  c.ScoaCode like 'IE002001%'
		and d.ScoaCode not  like 'FX002001001%' and  d.ScoaCode  not like 'FX002002001%'
	

Union All


-- Bulk Water Purchases items vs Functions
select a.ProjectID, a.PlanProjectItemID, 'Item: Bulk purchases water must use Function: Water (IE002002 must use FX016001002 or FX016002002)' as ExceptionDetail  
from #Plan_BudgetVersionDetail a left join
	  #ItemTable c on  a.ScoaItemID = c.scoaid left join
	 #FunctionTable d on a.ScoafunctionID = d.scoaid 
where  c.ScoaCode like 'IE002002%'
		and d.ScoaCode  not like 'FX016001002%'
		and d.ScoaCode  not like 'FX016002002%'


Union All


-- Inventory consumed: Water items vs Functions
select  a.ProjectID, a.PlanProjectItemID, 'Item: Inventory consumed water must use Function: Water (IE007004 must use FX016001002 or FX016002002)' as ExceptionDetail  
from #Plan_BudgetVersionDetail a left join
	  #ItemTable c on  a.ScoaItemID = c.scoaid left join
	 #FunctionTable d on a.ScoafunctionID = d.scoaid 
where  c.ScoaCode like 'IE007004%'
		and d.ScoaCode  not like 'FX016001002%'
		and d.ScoaCode  not like 'FX016002002%'

Union All

--IA IL LN Opening Balance must use Project Default
select  a.ProjectID, a.PlanProjectItemID, 'Item: IA IL LN Opening Balance must use Project Default(IA IL LN Opening Balance must use PD)' as ExceptionDetail  
from #Plan_BudgetVersionDetail a left join
	 #ItemTable c on  a.ScoaItemID = c.scoaid left join
	 #fundsTable d on a.ScoafundID = d.scoaid left join
	 #costingTable e on a.ScoaCostingID = e.ScoaID left join
	 #projectTable f on a.ScoaProjectID = f.ScoaID
where  ((c.ScoaShortDesc = 'Opening Balance') and (c.ScoaCode like 'IL%' or c.ScoaCode like 'IA%' or c.ScoaCode like 'LN%'))
		and (f.ScoaCode not like 'PD%')

Union All

--IA IL LN Opening Balance must use Costing Default
select  a.ProjectID, a.PlanProjectItemID, 'Item: IA IL LN Opening Balance must use Costing Default (IA IL LN Opening Balance must use CO003)' as ExceptionDetail  
from #Plan_BudgetVersionDetail a left join
	 #ItemTable c on  a.ScoaItemID = c.scoaid left join
	 #fundsTable d on a.ScoafundID = d.scoaid left join
	 #costingTable e on a.ScoaCostingID = e.ScoaID left join
	 #projectTable f on a.ScoaProjectID = f.ScoaID
where  ((c.ScoaShortDesc = 'Opening Balance') and (c.ScoaCode like 'IL%' or c.ScoaCode like 'IA%' or c.ScoaCode like 'LN%'))
		and (e.ScoaCode not like 'CO003%')

Union All

--IA IL LN Opening Balance must use Non-Funding
select  a.ProjectID, a.PlanProjectItemID, 'Item: IA IL LN Opening Balance must use Non-Funding (IA IL LN Opening Balance must use FD003)' as ExceptionDetail  
from #Plan_BudgetVersionDetail a left join
	 #ItemTable c on  a.ScoaItemID = c.scoaid left join
	 #fundsTable d on a.ScoafundID = d.scoaid left join
	 #costingTable e on a.ScoaCostingID = e.ScoaID left join
	 #projectTable f on a.ScoaProjectID = f.ScoaID
where  ((c.ScoaShortDesc = 'Opening Balance') and (c.ScoaCode like 'IL%' or c.ScoaCode like 'IA%' or c.ScoaCode like 'LN%'))
		and (d.ScoaCode not like 'FD003%')

Union All

--Item: Inventory water must use Function: Water
select  a.ProjectID, a.PlanProjectItemID, 'Item: Inventory water must use Function: Water (IA001009005 must use FX016)' as ExceptionDetail  
from #Plan_BudgetVersionDetail a left join
	  #ItemTable c on  a.ScoaItemID = c.scoaid left join
	 #FunctionTable d on a.ScoafunctionID = d.scoaid 
where  c.ScoaCode like 'IA001009005%'
		and d.ScoaCode not like 'FX016%'

Union All

--Charges and Recoveries must use default Expenditure (CO001 and CO002 must use IE018)
select  a.ProjectID, a.PlanProjectItemID, 'Charges and Recoveries must use default Expenditure (CO001 and CO002 must use IE018)' as ExceptionDetail  
from #Plan_BudgetVersionDetail a left join
	  #ItemTable c on  a.ScoaItemID = c.scoaid left join
	 #costingTable d on a.ScoaCostingID = d.scoaid 
where  (d.ScoaCode like 'CO001%' or d.ScoaCode like 'CO002%')
		and c.ScoaCode not like 'IE018%'

Union All


-- Region Segment cant be defualt ---
select a.ProjectID, a.PlanProjectItemID, 'Default Region not valid (RX001 not valid)' as ExceptionDetail  
from #Plan_BudgetVersionDetail a left join
	 #regionalTable d on a.ScoaRegionID = d.scoaid 
where  d.ScoaCode  like 'RX001%'


Union All


--Default Costing and default Expenditure not valid (CO003 and IE018 not valid) 
select a.ProjectID, a.PlanProjectItemID, 'Default Costing and default Expenditure not valid (CO003 and IE018 not valid)' as ExceptionDetail   
from #Plan_BudgetVersionDetail a left join
	 #ItemTable c on  a.ScoaItemID = c.scoaid left join
	 #costingTable d on a.ScoaCostingID = d.scoaid 
where   c.ScoaCode like 'IE018%'
		and d.ScoaCode  like 'CO003%'


		
Union All

		
--Default Costing and default Revenue not valid(CO003 and IR004 not valid)  
 select  a.ProjectID, a.PlanProjectItemID, 'Default Costing and default Revenue not valid(CO003 and IR004 not valid) ' as ExceptionDetail 
from #Plan_BudgetVersionDetail a left join
	 #ItemTable c on  a.ScoaItemID = c.scoaid left join
	 #costingTable d on a.ScoaCostingID = d.scoaid 
where  c.ScoaCode like 'IR004%'
		and d.ScoaCode  like 'CO003%'


Union All


--Small Differences Tolerances must be zero (IE010053 must be zero) 
select   a.ProjectID, a.PlanProjectItemID, 'Small Differences Tolerances must be zero (IE010053 must be zero)' as ExceptionDetail 
from #Plan_BudgetVersionDetail a inner join 
		#ItemTable c on  a.ScoaItemID = c.scoaid  
where  c.ScoaCode like 'IE010053%' 
group by a.ProjectID, a.PlanProjectItemID
having sum(isnull([a].BudgetAmount,0)+isnull(a.BudgetAmountCurP1,0)+isnull(a.BudgetAmountCurP2,0)) <> 0


Union All


--No IDP Projects
Select a.ProjectID, a.ProjectID, 'Project with No IDP details' as ExceptionDetail 
from   #Plan_BudgetVersionDetail a left join
       Plan_Project pp on a.ProjectID = pp.Project_ID
where PP.Project_ID not in (select ProjectID From Plan_ProjectIDP )


Union All

--Missing Debit/Credit flag
Select  a.ProjectID, a.PlanProjectItemID, 'Incorrect or Missing Credit/Debit Flag' as ExceptionDetail 
From #Plan_BudgetVersionDetail a 
Where   (select isnull(CreditDebit,' ') from Plan_ProjectItem where PlanProjectItem_ID = a.PlanProjectItemID ) not in ('C', 'D') 

Union All

-- Revenue Items vs Funding
Select a.ProjectID, a.PlanProjectItemID, 'ScoaItem Segment is Revenue with Default Funding' as ExceptionDetail   
From #Plan_BudgetVersionDetail a left join
	 #ItemTable c on  a.ScoaItemID = c.scoaid  left join 
	 #fundsTable d on  a.SCOAFundId =d.scoaid  
Where c.scoacode like 'IR%' and d.ScoaCode like 'FD003%'
	      and @FinYearStart >= @FinYearStart_RevenueDefaultFundingCheckValid


Union All

--Scoa Items is at Posting Level or Breakdown Allowed
-- Item Segement
Select a.ProjectID, a.PlanProjectItemID, 'ScoaItem Segment not in chart or not at Postinglevel' as ExceptionDetail   
From #Plan_BudgetVersionDetail a left join
	 #ItemTable c on  a.ScoaItemID = c.scoaid and c.PostingLevel = 'Yes'
Where  c.scoaid is null

Union All

-- Project Segement
Select a.ProjectID, a.PlanProjectItemID, 'ScoaProject Segment not in chart or not at Postinglevel' as ExceptionDetail   
From #Plan_BudgetVersionDetail a left join
	 #ProjectTable c on  a.ScoaProjectID = c.scoaid and (c.PostingLevel = 'Yes' or c.BreakDownAllowed = 'Yes')
Where  c.scoaid is null

Union All

-- Fund Segement
Select a.ProjectID, a.PlanProjectItemID, 'ScoaFund Segment not in chart or not at Postinglevel' as ExceptionDetail   
From #Plan_BudgetVersionDetail a Left Join
	 #fundsTable c on  a.ScoaFundID = c.scoaid and c.PostingLevel = 'Yes'
Where  c.scoaid is null 

Union All


-- Function Segement
Select a.ProjectID, a.PlanProjectItemID, 'ScoaFunction Segment not in chart or not at Postinglevel' as ExceptionDetail   
From #Plan_BudgetVersionDetail a left join
	 #FunctionTable c on  a.ScoaFunctionID = c.scoaid and c.PostingLevel = 'Yes'
Where  c.scoaid is null 

Union All

-- Region Segement
Select a.ProjectID, a.PlanProjectItemID, 'ScoaRegion Segment not in chart or not at Postinglevel' as ExceptionDetail   
From #Plan_BudgetVersionDetail a left join
	 #regionalTable c on   a.ScoaRegionID= c.scoaid and c.PostingLevel = 'Yes'
Where c.scoaid is null 

Union All


-- Costing Segement
Select a.ProjectID, a.PlanProjectItemID, 'ScoaCosting Segment not in chart or not at Postinglevel' as ExceptionDetail   
From #Plan_BudgetVersionDetail a left join
	 #costingTable c on a.ScoaCostingID  = c.scoaid and c.PostingLevel = 'Yes'
Where  c.scoaid is null 

) Expt



Union All


--Trial Balance (sum of all items - IE018 and IR004)
select 'Trial Balance (sum of all items - IE018 and IR004)' as ExceptionDetail ,'Trial Balance Difference' , cast(sum(Budgetamount) as nvarchar(50)) 
from
		( select 
				 ( CASE WHEN (((c.ScoaCode LIKE 'IR%' OR c.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2)) OR (select isnull(CreditDebit,' ') from Plan_ProjectItem where PlanProjectItem_ID = a.PlanProjectItemID ) = 'C')
								THEN -isnull([a].BudgetAmount,0) ELSE isnull([a].BudgetAmount,0)END ) as BudgetAmount 
		from  
		      #Plan_BudgetVersionDetail a left join
	          #ItemTable c on  a.ScoaItemID = c.scoaid 
		where  a.ProjectID not in (select ProjectID from Plan_ProjectReportExclude)
) TB 
Having sum(Budgetamount) <> 0

Union All


--Year & Month Totals Balance to Zero
Select 
 'Year & Month Totals Dont Balance to Zero' as ExceptionDetail ,
 'CurrentYear = '+cast(CurrentYear as varchar(50)) +'/OuterYear1 = '+cast(OuterYear1 as varchar(50))+'/OuterYear2 = '+cast(OuterYear2 as varchar(50))
  As YearTotals,
 'Month1Budget = '+cast(Month1Budget as varchar(50))+'/Month2Budget = '+cast(Month2Budget as varchar(50))+'/Month3Budget = '+cast(Month3Budget as varchar(50))+'/Month4Budget = '+cast(Month4Budget as varchar(50))
 +'/Month5Budget = '+cast(Month5Budget as varchar(50))+'/Month6Budget = '+cast(Month6Budget as varchar(50))+'/Month7Budget = '+cast(Month7Budget as varchar(50))+'/Month8Budget = '+cast(Month8Budget as varchar(50))
 +'/Month9Budget = '+cast(Month9Budget as varchar(50))+'/Month10Budget = '+cast(Month10Budget as varchar(50))+'/Month11Budget = '+cast(Month11Budget as varchar(50))+'/Month12Budget = '+cast(Month12Budget as varchar(50))
  As MonthTotals

From 
(select 

sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2))
								OR isnull(CreditDebit,' ')  = 'C')
																	  THEN -isnull([a].BudgetAmount,0)
																	  ELSE isnull([a].BudgetAmount,0)
																	  END )) as CurrentYear,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2))
								OR isnull(CreditDebit,' ')  = 'C')
																	  THEN -isnull(a.BudgetAmountCurP1,0)
																	  ELSE isnull(a.BudgetAmountCurP1,0)
																	  END )) as OuterYear1,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2))
								OR isnull(CreditDebit,' ')  = 'C')
																	  THEN -isnull(a.BudgetAmountCurP2,0)
																	  ELSE  isnull(a.BudgetAmountCurP2,0)
																	  END )) as OuterYear2,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2))
								OR isnull(CreditDebit,' ')  = 'C')
																	  THEN -h.UnitPrice
																	  ELSE h.UnitPrice
																	  END )) as Month1Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2))
								OR isnull(CreditDebit,' ')  = 'C')
																	  THEN -i.UnitPrice
																	  ELSE i.UnitPrice
																	  END )) as Month2Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2))
								OR isnull(CreditDebit,' ')  = 'C')
																	  THEN -j.UnitPrice
																	  ELSE j.UnitPrice
																	  END )) as Month3Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2))
								OR isnull(CreditDebit,' ')  = 'C')
																	  THEN -k.UnitPrice
																	  ELSE k.UnitPrice
																	  END )) as Month4Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2))
								OR isnull(CreditDebit,' ')  = 'C')
																	  THEN -L.UnitPrice
																	  ELSE L.UnitPrice
																	  END )) as Month5Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2))
								OR isnull(CreditDebit,' ')  = 'C')
																	  THEN -m.UnitPrice
																	  ELSE m.UnitPrice
																	  END )) as Month6Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2))
								OR isnull(CreditDebit,' ')  = 'C')
																	  THEN -b.UnitPrice
																	  ELSE b.UnitPrice
																	  END )) as Month7Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2))
								OR isnull(CreditDebit,' ')  = 'C')
																	  THEN -c.UnitPrice
																	  ELSE c.UnitPrice
																	  END )) as Month8Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2))
								OR isnull(CreditDebit,' ')  = 'C')
																	  THEN -d.UnitPrice
																	  ELSE d.UnitPrice
																	  END )) as Month9Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2))
								OR isnull(CreditDebit,' ')  = 'C')
																	  THEN -e.UnitPrice
																	  ELSE e.UnitPrice
																	  END )) as Month10Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2))
								OR isnull(CreditDebit,' ')  = 'C')
																	  THEN -f.UnitPrice
																	  ELSE f.UnitPrice
																	  END )) as Month11Budget,
sum(( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND a.CapitalOperation in (0,1,2))
								OR isnull(CreditDebit,' ')  = 'C')
																	  THEN -g.UnitPrice
																	  ELSE g.UnitPrice
																	  END )) as Month12Budget
from #Plan_BudgetVersionDetail a
left Join Plan_ProjectItem ppi on a.PlanProjectItemID = ppi.PlanProjectItem_ID
left join #Plan_BudgetVersionMonths b on a.PlanProjectItemID = b.PlanProjectItemID and b.monthid = 1
left join #Plan_BudgetVersionMonths c on a.PlanProjectItemID = c.PlanProjectItemID and c.monthid = 2
left join #Plan_BudgetVersionMonths d on a.PlanProjectItemID = d.PlanProjectItemID and d.monthid = 3
left join #Plan_BudgetVersionMonths e on a.PlanProjectItemID = e.PlanProjectItemID and e.monthid = 4
left join #Plan_BudgetVersionMonths f on a.PlanProjectItemID = f.PlanProjectItemID and f.monthid = 5
left join #Plan_BudgetVersionMonths g on a.PlanProjectItemID = g.PlanProjectItemID and g.monthid = 6
left join #Plan_BudgetVersionMonths h on a.PlanProjectItemID = h.PlanProjectItemID and h.monthid = 7
left join #Plan_BudgetVersionMonths i on a.PlanProjectItemID = i.PlanProjectItemID and i.monthid = 8
left join #Plan_BudgetVersionMonths j on a.PlanProjectItemID = j.PlanProjectItemID and j.monthid = 9
left join #Plan_BudgetVersionMonths k on a.PlanProjectItemID = k.PlanProjectItemID and k.monthid = 10
left join #Plan_BudgetVersionMonths l on a.PlanProjectItemID = l.PlanProjectItemID and l.monthid = 11
left join #Plan_BudgetVersionMonths m on a.PlanProjectItemID = m.PlanProjectItemID and m.monthid = 12
left join #ItemTable css on a.SCOAItemID = css.scoaid
where  a.ProjectID not in (select ProjectID from Plan_ProjectReportExclude)
group by a.FinYear ) Totals
Where  CurrentYear <> 0 or OuterYear1 <> 0 or  OuterYear2 <> 0 or Month1Budget <> 0 or Month2Budget <> 0 or Month3Budget <> 0 or Month4Budget <> 0 or Month5Budget <> 0 or Month6Budget <> 0 or Month7Budget <> 0 
         or Month8Budget <> 0 or Month9Budget <> 0 or Month10Budget <> 0 or Month11Budget <> 0 or Month12Budget <> 0 

Union All

---Charges and Recoveries must balance

Select 'Charges and Recoveries must balance (CO001 and CO002 must balance) - CurrentYear' as ExceptionDetail,'CO001 and CO002 must balance - CurrentYear',cast(isnull(@ChargesY1,0) + isnull(@RecoveriesY1,0) as nVarchar(50))
Having isnull(@ChargesY1,0) + isnull(@RecoveriesY1,0) <> 0

Union All

---Charges and Recoveries must balance

Select 'Charges and Recoveries must balance (CO001 and CO002 must balance) - OuterYear1' as ExceptionDetail,'CO001 and CO002 must balance - OuterYear1',cast(isnull(@ChargesY2,0) + isnull(@RecoveriesY2,0) as nVarchar(50))
Having isnull(@ChargesY1,0) + isnull(@RecoveriesY1,0) <> 0

Union All

---Charges and Recoveries must balance

Select 'Charges and Recoveries must balance (CO001 and CO002 must balance) - OuterYear2' as ExceptionDetail,'CO001 and CO002 must balance - OuterYear2',cast(isnull(@ChargesY3,0) + isnull(@RecoveriesY3,0) as nVarchar(50))
Having isnull(@ChargesY3,0) + isnull(@RecoveriesY3,0) <> 0

Union All

--Both Capital and Operating projects must be used
select 'Both Capital and Operating projects must be used (Both PC and PO must be used)' as ExceptionDetail, 'Both Capital and Operating projects must be used', 'Number of Operational Projects = ' + convert(varchar, @CountOperationalProject) + '/Number of Capital Projects = ' + convert(varchar, @CountCapitalProject)
where (@CountCapitalProject = 0 or @CountOperationalProject = 0)


    DROP TABLE #projectTable
	DROP TABLE #functionTable
	DROP TABLE #itemTable
	DROP TABLE #fundsTable
	DROP TABLE #costingTable
	DROP TABLE #regionalTable
	DROP TABLE #Plan_BudgetVersionDetail
	DROP TABLE #Plan_BudgetVersionMonths

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_PendingVirementByApproverID_sp]    Script Date: 2026/03/10 7:23:44 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 2016-04-14
-- Description:	Get Rejected Virement
-- Call SP: Plan_PendingVirementByApproverID_sp '',2647
-- 2016-04-16 by JP: Update Condition to get Pending Virement for user
-- 2016-04-21 by JP: Update Condition to Check EmployeeId, Reference updated from employee Id to User Id
-- 2016-04-22 by SN: Plan_VirementApprovalEmployees table is renamed to Plan_VirementApprovalUsers, AND modify -> INNER JOIN dbo.User_UserDetail change EmployeeId => UserId 
-- 2017-03-06 by SNagpal: Add VirementStatus
-- =============================================
CREATE PROCEDURE [dbo].[Plan_PendingVirementByApproverID_sp]
	-- Add the parameters for the stored procedure here
    @FinYear NVARCHAR(9) = '' ,
    @UserId INT
AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;       
		DECLARE @StatusId INT;

		SELECT @StatusId = Status_ID FROM dbo.Const_Status WHERE UsedBy='Virement' AND StatusDesc='Capture Virement'
    -- Insert statements for procedure here
        SELECT  V.VirementId ,
                PrjFrom.ProjectName AS FromProject ,
                PrjTo.ProjectName AS ToProject ,
                ISNULL(CSPSFrom.ScoaDesc, '') AS FromSCOAProject ,
                ISNULL(CSPSTo.ScoaDesc, '') AS ToSCOAProject ,
                ISNULL(CSFSFrom.ScoaDesc, '') AS FromSCOAFunction ,
                ISNULL(CSFSTo.ScoaDesc, '') AS ToSCOAFunction ,
                ISNULL(CDFrom.DivisionDesc, '') AS FromDivision ,
                ISNULL(CDTo.DivisionDesc, '') AS ToDivision ,
                ISNULL(CSFDSFrom.ScoaDesc, '') AS FromSCOAFund ,
                ISNULL(CSFDSTo.ScoaDesc, '') AS ToSCOAFund ,
                ISNULL(CSRSFrom.ScoaDesc, '') AS FromSCOARegion ,
                ISNULL(CSRSTo.ScoaDesc, '') AS ToSCOARegion ,
                ISNULL(CSSFrom.ScoaDesc, '') AS FromSCOAItem ,
                ISNULL(CSSTo.ScoaDesc, '') AS ToSCOAItem ,
                ISNULL(V.FromVirementAmount, 0) AS FromVirementAmount ,
                ISNULL(V.ToVirementAmount, 0) AS ToVirementAmount
        FROM    dbo.Plan_Project PrjFrom
                INNER JOIN dbo.Plan_Virements V ON V.FromProjectId = PrjFrom.Project_ID
                LEFT OUTER JOIN Plan_Project PrjTo ON V.ToProjectId = PrjTo.Project_ID
                LEFT OUTER JOIN dbo.Const_SCOA_Project_Structure CSPSFrom ON CSPSFrom.ScoaID = V.FromSCOAProjectID
                LEFT OUTER JOIN dbo.Const_SCOA_Project_Structure CSPSTo ON CSPSTo.ScoaID = V.ToSCOAProjectID
                LEFT OUTER JOIN dbo.Const_SCOA_Function_Structure CSFSFrom ON CSFSFrom.ScoaID = V.FromSCOAFunctionId
                LEFT OUTER JOIN dbo.Const_SCOA_Function_Structure CSFSTo ON CSFSTo.ScoaID = V.ToSCOAFunctionId
                LEFT OUTER JOIN dbo.Const_Division CDFrom ON CDFrom.Division_ID = V.FromDivisionId
                LEFT OUTER JOIN dbo.Const_Division CDTo ON CDTo.Division_ID = V.ToDivisionId
                LEFT OUTER JOIN dbo.Const_SCOA_Funds_Structure CSFDSFrom ON CSFDSFrom.ScoaID = V.FromSCOAFundID
                LEFT OUTER JOIN dbo.Const_SCOA_Funds_Structure CSFDSTo ON CSFDSTo.ScoaID = V.ToSCOAFundID
                LEFT OUTER JOIN dbo.Const_SCOA_Regional_Structure CSRSFrom ON CSRSFrom.ScoaID = V.FromSCOARegion
                LEFT OUTER JOIN dbo.Const_SCOA_Regional_Structure CSRSTo ON CSRSTo.ScoaID = V.ToSCOARegion
                LEFT OUTER JOIN dbo.Const_SCOA_Structure CSSFrom ON CSSFrom.ScoaID = V.FromSCOAItem
                LEFT OUTER JOIN dbo.Const_SCOA_Structure CSSTo ON CSSTo.ScoaID = V.ToSCOAItem
                INNER JOIN dbo.Plan_VirementApprovalUsers PVAE ON PVAE.VirementId = V.VirementId
                INNER JOIN dbo.User_UserDetail UUD ON UUD.User_ID = PVAE.UserId
                LEFT OUTER JOIN dbo.Plan_VirementApprovalRejections PVAR ON PVAR.VirementId = V.VirementId
                                                              AND ( PVAR.RejectedBy = @UserId
                                                              OR PVAR.ApprovedBy = @UserId
                                                              )
        WHERE   ( @FinYear = ''
                  OR V.FinYear = @FinYear
                )
                AND ( PVAE.UserId = @UserId )
                AND PVAR.VirementId IS NULL AND ISNULL(V.VirementStatus,0) <> @StatusId;;
    END;

	
GO

/****** Object:  StoredProcedure [dbo].[Plan_PendingVirementByApproverIDPerApprovalLevel_sp]    Script Date: 2026/03/10 7:23:44 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Chris Moodley
-- Create date: October 2025
-- Description:	 Return virements requiring approval
-- =============================================
CREATE PROCEDURE [dbo].[Plan_PendingVirementByApproverIDPerApprovalLevel_sp] 
	-- Add the parameters for the stored procedure here
	@FinYear NVARCHAR(9) = '' ,
    @UserId INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE @StatusId INT;

	SELECT @StatusId = Status_ID FROM dbo.Const_Status WHERE UsedBy='Virement' AND StatusDesc='Capture Virement'

	SELECT ScoaID,BreakDownAllowed,NTScoaID,ScoaDesc INTO #projectTable FROM dbo.Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @FinYear
	SELECT ScoaID,BreakDownAllowed,NTScoaID,ScoaDesc  INTO #functionTable FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @FinYear
	SELECT ScoaID,BreakDownAllowed,NTScoaID,ScoaCode,ScoaDesc INTO #itemTable FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @FinYear
	SELECT ScoaID,BreakDownAllowed,NTScoaID,ScoaDesc INTO #fundsTable FROM dbo.Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @FinYear
	SELECT ScoaID,BreakDownAllowed,NTScoaID,ScoaDesc INTO #regionalTable FROM dbo.Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @FinYear

    ;WITH Approvals AS (
        SELECT 
            vu.VirementApprovalUserId,
            vu.VirementId,
            vu.UserId,
            vu.DateCaptured,
            ROW_NUMBER() OVER (PARTITION BY vu.VirementId ORDER BY vu.DateCaptured, vu.VirementApprovalUserId) AS ApprovalOrder
        FROM Plan_VirementApprovalUsers vu
    ),
    Status AS (
        SELECT 
            a.VirementId,
            a.UserId,
            a.ApprovalOrder,
            CASE 
                WHEN EXISTS (
                    SELECT 1 
                    FROM Plan_VirementApprovalRejections r
                    WHERE r.VirementId = a.VirementId
                      AND (r.ApprovedBy = a.UserId OR r.RejectedBy = a.UserId)
                ) THEN 1
                ELSE 0
            END AS HasActed
        FROM Approvals a
    ),
    NextApprover AS (
        SELECT 
            s1.VirementId,
            s1.UserId,
            s1.ApprovalOrder
        FROM Status s1
        WHERE s1.HasActed = 0
          AND NOT EXISTS (
                SELECT 1
                FROM Status s2
                WHERE s2.VirementId = s1.VirementId
                  AND s2.ApprovalOrder < s1.ApprovalOrder
                  AND s2.HasActed = 0
          )
    )
    SELECT 
        n.VirementId,
        n.UserId,
        u.FirstName + ' ' + u.LastName AS ApproverName,
        n.ApprovalOrder,
		CAST(ISNULL(PrjFrom.ProjectCode, PrjFrom.Project_ID) AS VARCHAR(50)) + ' | ' + PrjFrom.ProjectName AS FromProject ,
        CAST(ISNULL(PrjTo.ProjectCode, PrjTo.Project_ID) AS VARCHAR(50)) + ' | ' + PrjTo.ProjectName AS ToProject ,
        ISNULL(CSPSFrom.ScoaDesc,'') AS FromSCOAProject ,
        ISNULL(CSPSTo.ScoaDesc,'') AS ToSCOAProject ,
        ISNULL(CSFSFrom.ScoaDesc,'') AS FromSCOAFunction ,
        ISNULL(CSFSTo.ScoaDesc,'') AS ToSCOAFunction ,
        ISNULL(CDFrom.DivisionDesc,'') AS FromDivision ,
        ISNULL(CDTo.DivisionDesc,'') AS ToDivision ,
        ISNULL(CSFDSFrom.ScoaDesc,'') AS FromSCOAFund ,
        ISNULL(CSFDSTo.ScoaDesc,'') AS ToSCOAFund ,
        ISNULL(CSRSFrom.ScoaDesc,'') AS FromSCOARegion ,
        ISNULL(CSRSTo.ScoaDesc,'') AS ToSCOARegion ,
        ISNULL(CSSFrom.ScoaDesc,'') AS FromSCOAItem ,
        ISNULL(CSSTo.ScoaDesc,'') AS ToSCOAItem,
		ISNULL(V.FromVirementAmount,0) AS FromVirementAmount,
		ISNULL(V.ToVirementAmount,0) AS ToVirementAmount,
		V.IsNewItemAdded, V.UploadedVirementDoc ,
		ISNULL(V.FromUkey, '') AS FromUkey,
		ISNULL(V.ToUkey, '') AS ToUkey
    FROM 
		NextApprover n
		INNER JOIN dbo.Plan_Virements V ON V.VirementId = n.VirementId
		INNER JOIN dbo.Plan_Project PrjFrom ON V.FromProjectId = PrjFrom.Project_ID
		LEFT OUTER JOIN Plan_Project PrjTo ON V.ToProjectId = PrjTo.Project_ID
        LEFT OUTER JOIN #projectTable CSPSFrom ON CSPSFrom.ScoaID = V.FromScoaProjectId
        LEFT OUTER JOIN #projectTable CSPSTo ON CSPSTo.ScoaID = V.ToScoaProjectId
        LEFT OUTER JOIN #functionTable CSFSFrom ON CSFSFrom.ScoaID = V.FromScoaFunctionId
        LEFT OUTER JOIN #functionTable CSFSTo ON CSFSTo.ScoaID = V.ToScoaFunctionId
        LEFT OUTER JOIN dbo.Const_Division CDFrom ON CDFrom.Division_ID = V.FromDivisionId
        LEFT OUTER JOIN dbo.Const_Division CDTo ON CDTo.Division_ID = V.ToDivisionId
        LEFT OUTER JOIN #fundsTable CSFDSFrom ON CSFDSFrom.ScoaID = V.FromSCOAFundID
        LEFT OUTER JOIN #fundsTable CSFDSTo ON CSFDSTo.ScoaID = V.ToSCOAFundID
        LEFT OUTER JOIN #regionalTable CSRSFrom ON CSRSFrom.ScoaID = V.FromSCOARegion
        LEFT OUTER JOIN #regionalTable CSRSTo ON CSRSTo.ScoaID = V.ToSCOARegion
        LEFT OUTER JOIN #itemTable CSSFrom ON CSSFrom.ScoaID = V.FromSCOAItem
        LEFT OUTER JOIN #itemTable CSSTo ON CSSTo.ScoaID = V.ToSCOAItem
		INNER JOIN User_UserDetail u ON u.User_ID = n.UserId
    WHERE 
		(@FinYear = '' OR V.FinYear = @FinYear )
		AND (@UserId IS NULL OR n.UserId = @UserId)
		AND ISNULL(V.VirementStatus,0) <> @StatusId
    ORDER BY 
		n.VirementId, n.ApprovalOrder;

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_Project_CashFlow_sp]    Script Date: 2026/03/10 7:23:44 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

   
    
/* =============================================    
-- Author:  CB  
-- Create date: 14/01/2015
-- Description: Returns project's cash flow
Plan_Project_CashFlow_sp 11,1
------------------------------------------------
--  by  : 
-- =============================================    */
CREATE PROCEDURE [dbo].[Plan_Project_CashFlow_sp]    
 @ProjectID int,
 @UserID int
AS    
BEGIN  
	
	SELECT [ProjectCashFlow_ID]
		,Cashflow.[ProjectID]
		,[ProjectFundID]
		,[PeriodEnd]
		,[PlanDirect]
		,[PlanIndirect]
		,Isnull([PlanDirect],0) + Isnull([PlanIndirect],0) as PlanTotal
		--,0.00 as PlanCumulative
		,(Select Sum(Isnull([PlanDirect],0) + Isnull([PlanIndirect],0)) From [Plan_Project_CashFlow] A
		  where A.ProjectID = Cashflow.ProjectID And A.ProjectFundID = Cashflow.ProjectFundID
		  and A.PeriodEnd <= Cashflow.PeriodEnd) as PlanCumulative
		,[RevDirect]
		,[RevIndirect]
		,Isnull([RevDirect],0) + Isnull([RevIndirect],0) as RevTotal
		--,0.00 as RevCumulative
		,(Select Sum(Isnull([RevDirect],0) + Isnull([RevIndirect],0)) From [Plan_Project_CashFlow] A
		  where A.ProjectID = Cashflow.ProjectID And A.ProjectFundID = Cashflow.ProjectFundID
		  and A.PeriodEnd <= Cashflow.PeriodEnd) as RevCumulative
		,0.00 as CommDirect
		,0.00 as CommIndirect
		,0.00 as CommTotal
		,0.00 as CommCumulative

		,[RevComment]
		,Cashflow.[CapturerID]
		,Cashflow.[DateCaptured]
		,Cashflow.[ModifierID]
		,Cashflow.[DateModified]
		,SCOAFund.ScoaCode
		,SCOAFund.ScoaCode + ' - ' + SCOAFund.ScoaShortDesc as ScoaShortDesc
	FROM [dbo].[Plan_Project_CashFlow] Cashflow
	INNER JOIN [dbo].[Plan_ProjectFund] Fund
		ON Cashflow.ProjectfundID = Fund.ProjectFund_ID
	LEFT JOIN [dbo].[Const_SCOA_Funds_Structure]  SCOAFund
		ON Fund.ScoaFundID = SCOAFund.ScoaID
	WHERE
		Cashflow.ProjectID = @ProjectID
	ORDER BY
		SCOAFund.ScoaCode, [PeriodEnd] desc


END    
    

GO

/****** Object:  StoredProcedure [dbo].[Plan_Project_CashFlowDelete_sp]    Script Date: 2026/03/10 7:23:45 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

/* =============================================    
	Author:  CB  
	Create date: 14/01/2015
	Description: Deletes project's cash flow records based on record selected. 
				Any records after the record selected will be deleted.
	
	Plan_Project_CashFlowDelete_sp 1,1
	Modifications:

-- =============================================    */
CREATE PROCEDURE [dbo].[Plan_Project_CashFlowDelete_sp]    
  @ProjectCashFlow_ID int,
  @UserID int
AS    
BEGIN 
	SET NOCOUNT ON;

	Declare @ProjectID int,
			@ProjectFundID int,
			@PeriodDue datetime,
			@IDs nvarchar(200)

	--Get details of record selected.
	Select @ProjectID = ProjectID,
			@ProjectFundID = ProjectFundID,
			@PeriodDue = PeriodEnd
	From
		Plan_Project_CashFlow
	Where
		ProjectCashFlow_ID = @ProjectCashFlow_ID
 
	--Get details of all records after the record selected as they will have to be deleted
	Create Table #CashflowTemp
	(TID int identity(1,1),
	 TProjectCashFlow_ID int)

	Insert into #CashflowTemp (TProjectCashFlow_ID)
	Select ProjectCashFlow_ID 
	FROM [dbo].[Plan_Project_CashFlow] Cashflow
	WHERE
		Cashflow.ProjectID = @ProjectID
		and Cashflow.ProjectFundID = @ProjectFundID
		and PeriodEnd >= @PeriodDue
	
	Declare @Count int, @ProjCashFlowID int
	SElect @count = 1

	While @count <= (Select Max(TID) from #CashflowTemp)
	begin
		Select @ProjCashFlowID = TProjectCashFlow_ID From #CashflowTemp where TID = @count

		Exec dbo.Plan_Project_CashFlowDeleteAudit_sp @ProjCashFlowID,@UserID

		Select @IDs = @IDs + '|' + convert(nvarchar, @ProjCashFlowID)

		Select @count = @count + 1
	end

	Delete 
	FROM [dbo].[Plan_Project_CashFlow] 
	WHERE
		ProjectID = @ProjectID
		and ProjectFundID = @ProjectFundID
		and PeriodEnd >= @PeriodDue

	Declare @ActiveFinYear nvarchar(20)
	Select @ActiveFinYear = KeyValue From AAAA_ConfigSettings where KeyName = 'ActiveFinYear'
	
	--Write to audit log
	Insert into Sys_AuditLog (UserID, AuditDesc, AuditDate, AuditComment, ActiveFinYear_UserFinYear, TableName, RecordID, ModuleID)
	Values(@UserID, 'Delete Project Cashflows', GETDATE(), left('Deleted IDs = ' + @IDs,300), @ActiveFinYear + '|', 'Plan_Project_CashFlow',@ProjectCashFlow_ID, 10)

	SELECT *
	FROM [dbo].[Plan_Project_CashFlow] Cashflow
	WHERE
		Cashflow.ProjectID = @ProjectID
		and Cashflow.ProjectFundID = @ProjectFundID
		
END

GO

/****** Object:  StoredProcedure [dbo].[Plan_Project_CashFlowDeleteAudit_sp]    Script Date: 2026/03/10 7:23:45 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

/* =============================================
 Author: CB
 Create date: 14/01/2015
 Description:	Writes cashflow records to audit database before deletion
				
 Plan_Project_CashFlow_DeleteAudit_sp 15,1
-- =============================================*/
create PROCEDURE [dbo].[Plan_Project_CashFlowDeleteAudit_sp]
    @ProjectCashFlowID INT ,
    @UserID INT
AS 
    BEGIN
    
        DECLARE @DATABASENAME NVARCHAR(50)    
        DECLARE @SQLQuery NVARCHAR(MAX),@SQLQuery1 NVARCHAR(MAX)
        DECLARE @User NVARCHAR(205)

		Select @User = Isnull(FirstName,'') + ' ' + Isnull(LastName,'') from User_UserDetail
		where User_ID = @UserID

        SELECT  @DATABASENAME = KeyValue
        FROM    AAAA_ConfigSettings
        WHERE   KeyName = 'FMSAuditDatabaseName'
        DECLARE @SQLDetailQuery NVARCHAR(MAX)
    
        SET @SQLQuery = 'INSERT INTO ' + @DATABASENAME + '.dbo.aPlan_Project_CashFlow
           ([AuditUserID]
           ,[AuditDate]
           ,[AuditUser]
           ,[ProjectCashFlow_ID]
           ,[ProjectFundID]
           ,[ProjectID]
           ,[PeriodEnd]
           ,[PlanDirect]
           ,[PlanIndirect]
           ,[RevDirect]
           ,[RevIndirect]
           ,[RevComment]
           ,[CapturerID]
           ,[DateCaptured]
           ,[ModifierID]
           ,[DateModified]
		)'
        SET @SQLQuery1 = 'SELECT ' +
			convert(nvarchar, @UserID) + ',
			GETDATE(),''' + 
		@User
		  + ''',[ProjectCashFlow_ID]
           ,[ProjectFundID]
           ,[ProjectID]
           ,[PeriodEnd]
           ,[PlanDirect]
           ,[PlanIndirect]
           ,[RevDirect]
           ,[RevIndirect]
           ,[RevComment]
           ,[CapturerID]
           ,[DateCaptured]
           ,[ModifierID]
           ,[DateModified]
		FROM Plan_Project_CashFlow
		WHERE ProjectCashFlow_ID = ' + CONVERT(NVARCHAR(50), @ProjectCashFlowID)

        --PRINT @SQLQuery		
        EXEC(@SQLQuery +' '+ @SQLQuery1)
    
END


GO

/****** Object:  StoredProcedure [dbo].[Plan_Project_Employment_Create_sp]    Script Date: 2026/03/10 7:23:45 AM ******/
SET ANSI_NULLS ON
