/* =============================================    
-- Author:  CB  
-- Create date: 14/01/2015
-- Description: Inserts project's employment targets so that user can work with them.
Plan_Project_Employment_Create_sp 2,1
------------------------------------------------
--  by  : 
-- =============================================    */
CREATE PROCEDURE [dbo].[Plan_Project_Employment_Create_sp]    
 @ProjectID int,
 @UserID int
AS    
BEGIN  
	
	--Insert all categories and sections
	Insert into Plan_Project_Employment ([ProjectID],[ProjEmploymentCategoryID],[ProjEmploymentSectionID], CapturerID, DateCaptured)
	Select 
		@ProjectID
		,[ProjEmploymentCategory_ID]
		,[ProjEmployementSecton_ID]
		,@UserID
		,getdate()
	From 
		(Select [ProjEmploymentCategory_ID] from [dbo].[Const_ProjectTargetEmploymentCategories_sys] where Enabled = 1) Cat
	join
		(Select [ProjEmployementSecton_ID] From [dbo].[Const_ProjectTargetEmployementSection_sys] where Enabled = 1) Sect
		ON 1=1 

	--Select info
	SELECT [PlanProjectEmployment_ID]
		  ,[ProjectID]
		  ,[ProjEmploymentCategoryID]
		  ,[ProjEmploymentSectionID]
		  ,[AdultMale]
		  ,[AdultFemale]
		  ,[YouthMale]
		  ,[YouthFemale]
		  ,[DisabledMale]
		  ,[DisableFemale]
		  ,[ProjEmploymentSectionDesc]
		  ,[ProjEmploymentCategoryDesc]
		  ,Section.ListOrder as ListOrder
	  FROM [dbo].[Plan_Project_Employment] Emp
	  INNER JOIN [dbo].[Const_ProjectTargetEmployementSection_sys] Section
		ON Section.[ProjEmployementSecton_ID] = Emp.[ProjEmploymentSectionID]
	  INNER JOIN [dbo].[Const_ProjectTargetEmploymentCategories_sys] category
		ON category.[ProjEmploymentCategory_ID]  = Emp.[ProjEmploymentCategoryID]
	WHERE
		Emp.ProjectID = @ProjectID

Union

	SELECT 0 as [PlanProjectEmployment_ID]
		  ,@ProjectID as [ProjectID]
		  ,[ProjEmploymentCategoryID]
		  ,0 as [ProjEmploymentSectionID]
		  ,EXP (SUM (LOG ([AdultMale])))
		  ,EXP (SUM (LOG ([AdultFemale])))
		  ,EXP (SUM (LOG ([YouthMale])))
		  ,EXP (SUM (LOG ([YouthFemale])))
		  ,EXP (SUM (LOG ([DisabledMale])))
		  ,EXP (SUM (LOG ([DisableFemale])))
		  ,'Planned Person Days' as [ProjEmploymentSectionDesc]
		  ,(Select [ProjEmploymentCategoryDesc] from [dbo].[Const_ProjectTargetEmploymentCategories_sys]
		   where [ProjEmploymentCategory_ID] = Emp.[ProjEmploymentCategoryID])
		   ,3
	  FROM [dbo].[Plan_Project_Employment] Emp
		WHERE
			Emp.ProjectID = @ProjectID
		AND Emp.[ProjEmploymentSectionID] in (1,2)	
		GROUP BY
			[ProjEmploymentCategoryID]
	ORDER BY
		[ProjEmploymentCategoryDesc], ListOrder	--[ProjEmploymentSectionDesc]


END    
    


GO

