/****** Object:  StoredProcedure [dbo].[Plan_Project_Milestones_sp]    Script Date: 2026/03/10 7:23:45 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO



    
    
/* =============================================    
-- Author:  CB  
-- Create date: 14/01/2015
-- Description: Returns project's milestones
Plan_Project_Milestones_sp 2,1
------------------------------------------------
--  by  : 
-- =============================================    */
CREATE PROCEDURE [dbo].[Plan_Project_Milestones_sp]    
 @ProjectID int,
 @UserID int
AS    
BEGIN  
	Declare @ProjDistinctionID int

	Select @ProjDistinctionID = [ProjectDistinctionID] from Plan_Project where Project_ID = @ProjectID

	set FMTOnly Off

	--Check if milestones created (if not then insert before selection)
	If((Select Count(*) From Plan_Project_Milestone where ProjectID = @ProjectID) = 0)
	begin
		Insert into [dbo].[Plan_Project_Milestone] (ProjectID, ProjectMilestoneID, MilestoneRequired, MilestoneOrder, DateCaptured, CapturerID)
		SELECT
			@ProjectID
			,pmd.ProjectMilestoneID
			,pmd.[MilestoneRequired]
			,pmd.OrderNumber
			,getdate()
			,@UserID
		FROM [dbo].[Const_ProjectMilestoneDistinction] pmd
		INNER JOIN Const_ProjectDistinction d ON pmd.ProjectDistinctionID = d.ProjectDistinction_ID
		INNER JOIN Const_ProjectMilestone m ON pmd.ProjectMilestoneID = m.ProjectMilestone_ID
		WHERE    
		  pmd.ProjectDistinctionID = @ProjDistinctionID
		ORDER BY pmd.OrderNumber				
	end

	SELECT
			PlanProjectMilestone_ID
		,0 as ProjectMilestoneDistinction_ID
		,@ProjDistinctionID as ProjectDistinctionID
		,pm.ProjectMilestoneID
		,pm.MilestoneOrder as OrderNumber
		,m.MilestoneName
		,m.MilestoneActivity
		,pm.[PlanDate]
		,pm.[RevisedDate]
		,pm.[ActualDate]
		,pm.[MilestoneRequired]
	FROM	Plan_Project_Milestone pm
	INNER JOIN Const_ProjectMilestone m ON pm.ProjectMilestoneID = m.ProjectMilestone_ID
	WHERE
		ProjectID = @ProjectID

	Union
		SELECT [CustomProjectMilestone_ID]
		,0 as ProjectMilestoneDistinction_ID
		,0
		,-1
		,[MilestoneOrder] as OrderNumber
		,[CustomMilestoneName]
		,[CustomMilestoneActivity]
		,[PlanDate]
		,[RevisedDate]
		,[ActualDate]
		,[MilestoneRequired]
	FROM [dbo].[Plan_Project_Milestone_Custom]
	Where
		[ProjectID] = @ProjectID

	Order by 
		OrderNumber
END    
    
GO

