		  ,EXP (SUM (LOG ([YouthMale])))
		  ,EXP (SUM (LOG ([YouthFemale])))
		  ,EXP (SUM (LOG ([DisabledMale])))
		  ,EXP (SUM (LOG ([DisableFemale])))
		  ,'Planned Person Days' as [ProjEmploymentSectionDesc]
		  ,(Select [ProjTrainingCategoryDesc] from [dbo].[Const_ProjectTargetTrainingCategories_sys]
		   where [ProjTrainingCategory_ID] = Emp.[ProjTrainingCategoryID])
		   ,3
	  FROM [dbo].[Plan_Project_Training] Emp
		WHERE
			Emp.ProjectID = @ProjectID
		AND Emp.[ProjEmploymentSectionID] in (1,2)	
		GROUP BY
			[ProjTrainingCategoryID]
	ORDER BY
		[ProjTrainingCategoryDesc], ListOrder	--[ProjEmploymentSectionDesc]

END    
    

GO

/****** Object:  StoredProcedure [dbo].[Plan_Project_WorkOrderBreakdowns_sp]    Script Date: 2026/03/10 7:23:45 AM ******/
SET ANSI_NULLS ON
GO

