/* =============================================    
-- Author:  CB  
-- Create date: 14/01/2015
-- Description: Returns project's work order breakdown
Plan_Project_WorkOrderBreakdowns_sp 11
------------------------------------------------
--  by  : 
-- =============================================    */
CREATE PROCEDURE [dbo].[Plan_Project_WorkOrderBreakdowns_sp]    
 @ProjectID int
AS    
BEGIN  
	
	SELECT [PlanProjectWorkOrderBreakdowns_ID]
		  ,[ProjectID]
		  ,[WorkOrderDescription]
		  ,[WorkOrderbudget]
		  ,[WorkOrderPlanCompletionDate]
		  ,[WorkOrderRevCompletionDate]
		  ,[WorkOrderActCompletionDate]
		  ,[WorkOrderVariationAmt]
		  ,[WorkOrderComment]
		  ,[CapturerID]
		  ,[DateCaptured]
		  ,[ModifierID]
		  ,[DateModified]
	FROM [dbo].[Plan_Project_WorkOrderBreakdowns] WOBreakdown
	WHERE
		WOBreakdown.ProjectID = @ProjectID
	ORDER BY
		[WorkOrderDescription]


END    
    

