/****** Object:  StoredProcedure [dbo].[Plan_ProjectBudgetingExport_sp]    Script Date: 2026/03/10 7:23:45 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Nirav Parikh
-- Create date: 18 JULY 2017
-- Description:	Get project budgeting details for Export
-- Plan_ProjectBudgetingExport_sp '',0,0,'2025/2026',5,0,0,0,0,0,0,0,''  
-- 18-07-2017 SNagpal: Add logic to get AvailableBudget from Plan_BudgetConsumption
-- 28-07-2017 Rchetty: ScoaDescription have special characters
-- 29-07-2017 SNagpal: Add Replace for all ScoaDescription. As they have special characters
-- 23-03-2018 SNagpal: 70024 Budget on MOC6.1 - Add Replace - REPLACE(cd.DivisionDesc,',','_') AS MSCDivision, REPLACE(cpi.ItemDescription,',',' _') AS ItemDescription
-- 19-04-2018 SNagpal: 71151 Budget report extract is incorrect - Lepelle Nkumpi -- REPLACE(REPLACE(pp.ProjectName, ';', ''),'|','_') AS ProjectName
-- 07-06-2018 Chirag Patel:  REPLACE(REPLACE(pp.ProjectName, ';', ''),'|','_') AS ProjectName and Table Join changes
-- 24-Jan-2019 SNagpal: #61596 - #83633 - Add functionality to get ProjectCode. Replace Project_Id to ProjectCode, As User want to see ProjectCode in report
-- 20-May-2019 SNagpal: Add multiyear concept to get SCOA segments based upon finyear
-- 12-June-2019 SNagpal: #61596 - #83633 - Append ProjectCode with Project Name and Replace ProjectCode to Project_Id
-- 13-Aug-2019 CMoodley: #92299 - Remove space in REPLACE statements ', ', ';' change to ',', ';'
-- 05-Feb-2020 CMoodley: #28288 - Replace ',' with '_' for MSCDepartment field 
-- 03-Mar-2020 CMoodley: #29538 - Return project code for report, Handle issue where project code is null
-- 08-Dec-2020 CMoodley: #50138 - Remove project code from project name
-- 08-Sep-2021 CMoodley: #74175 - Include projects that have zero budget over the three years
-- 22-Mar-2022 CMoodley: #84309 - Optimise SP
-- 07-Aug-2023 CMoodley: #105236 - Include CostingProject field
-- 21-May-2024 CMoodley: #111720 - If version is selected get budget amounts and CapitalOperational flag from Plan_BudgetVersionDetail table
-- 11-Sep-2025 CMoodley: #122522 - Return Ukey
-- 11-Nov-2025 CMoodley: #124586 - Left join to Budget Consumption table to return data if projects not yet initiated
-- 14-Jan-2026 CMoodley: #126073 - Fix join to budget consumption table as is is causing timeout issue
-- =============================================
CREATE PROCEDURE [dbo].[Plan_ProjectBudgetingExport_sp]
    @strDivisionID NVARCHAR(10) = '' ,
    @ProjectID INT = 332 ,
    @ScoaFunctionID INT = 0 ,
    @FinYear NVARCHAR(9) = '2017/2018' ,
    @CapitalOperational INT = 0 ,
    @DepartmentID INT = 0 ,
    @ProjectTypeID INT = 0 ,
    @ScoaRegionID INT = 0 ,
    @ScoaFundID INT = 0 ,
    @ScoaItemID INT = 0 ,
    @ProjectStatusId INT = 0 ,
    @VersionId INT = 0 ,
    @SingleMultiYear VARCHAR(5) = ''
AS
BEGIN

	SET NOCOUNT ON;

    DECLARE @FinYear2 NVARCHAR(9) ,
        @FinYear3 NVARCHAR(9);
    DECLARE @StartFYear INT ,
        @EndFYear INT ,
        @DivisionID INT;
    DECLARE @temp TABLE ( tblDivisionId INT );

	CREATE TABLE #Const_SCOA_Structure (ScoaID INT, NTScoaID UNIQUEIDENTIFIER, ScoaDesc NVARCHAR(1200), ScoaCode NVARCHAR(100))
	CREATE INDEX idxItemScoaID ON #Const_SCOA_Structure(ScoaID)
	CREATE INDEX idxItemNTScoaID ON #Const_SCOA_Structure(NTScoaID)
	INSERT INTO #Const_SCOA_Structure SELECT ScoaID, NTScoaID, ScoaDesc, ScoaCode FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @FinYear

    SELECT  @DivisionID = IIF(@strDivisionID = '', NULL, CAST(@strDivisionID AS INT));
    SELECT  @StartFYear = CAST(Data AS INT)
    FROM    dbo.Split(@FinYear, '/')
    WHERE   Id = 1;
    SELECT  @EndFYear = CAST(Data AS INT)
    FROM    dbo.Split(@FinYear, '/')
    WHERE   Id = 2;

    SET @FinYear2 = CAST(@EndFYear AS NVARCHAR(9)) + '/'
        + CAST(( @EndFYear + 1 ) AS NVARCHAR(9));
    SET @FinYear3 = CAST(( @EndFYear + 1 ) AS NVARCHAR(9)) + '/'
        + CAST(( @EndFYear + 2 ) AS NVARCHAR(9));

	WITH    temp
            AS ( SELECT   Division_ID ,
                        DivisionParentID
                FROM     Const_Division
                WHERE    ( Division_ID = @DivisionID
                            OR @DivisionID IS NULL
                        )
                UNION ALL
                SELECT   t.Division_ID ,
                        t.DivisionParentID
                FROM     Const_Division t
                        JOIN temp ON temp.Division_ID = t.DivisionParentID
                )
    INSERT  INTO @temp
            SELECT  temp.Division_ID
            FROM    temp
    OPTION  ( MAXRECURSION 0 );	

    DECLARE @Tbl TABLE
        (
            FinYear1 NVARCHAR(10) ,
            FinYear2 NVARCHAR(10) ,
            FinYear3 NVARCHAR(10) ,
            ProjectID INT ,
			ProjectCode INT ,
            ProjectName NVARCHAR(500) ,
            BudgetType NVARCHAR(50) ,
			PlanProjectItemID INT,
            SCOAProjectCode NVARCHAR(50) ,
            SCOAProject NVARCHAR(600) ,
            SCOAFuctionCode NVARCHAR(50) ,
            SCOAFunction NVARCHAR(600) ,
            MSCDepartmentCode NVARCHAR(50) ,
            MSCDepartment NVARCHAR(200) ,
            MSCDivisionCode NVARCHAR(50) ,
            MSCDivision NVARCHAR(200) ,
            MunicipleClassification NVARCHAR(600) ,
            SCOAFundCode NVARCHAR(50) ,
            SCOAFund NVARCHAR(600) ,
            SCOARegionCode NVARCHAR(50) ,
            SCOARegion NVARCHAR(600) ,
            SCOACostingCode NVARCHAR(50) ,
            SCOACosting NVARCHAR(600) ,
            SCOAItemCode NVARCHAR(50) ,
            SCOAItem NVARCHAR(600) ,
            ItemDescription NVARCHAR(500) ,
            CurrentBudgetFinYear1 DECIMAL(18, 2) ,
            CurrentBudgetFinYear2 DECIMAL(18, 2) ,
            CurrentBudgetFinYear3 DECIMAL(18, 2) ,
            AvailableBudgetFinYear1 DECIMAL(18, 2) ,
            CapitalOperation INT ,
            BudgetVersionID INT ,
			ProjectItemId INT ,
			CostingProject BIT ,
			Ukey NVARCHAR(100)
        );

    IF @CapitalOperational = 5
        AND @VersionId > 0
        BEGIN
            INSERT  INTO @Tbl
                    ( FinYear1 ,
                        FinYear2 ,
                        FinYear3 ,
                        ProjectId ,
						ProjectCode ,
                        ProjectName ,
                        BudgetType ,
						PlanProjectItemID,
                        SCOAProjectCode ,
                        SCOAProject ,
                        SCOAFuctionCode ,
                        SCOAFunction ,
                        MSCDepartmentCode ,
                        MSCDepartment ,
                        MSCDivisionCode ,
                        MSCDivision ,
                        MunicipleClassification ,
                        SCOAFundCode ,
                        SCOAFund ,
                        SCOARegionCode ,
                        SCOARegion ,
                        SCOACostingCode ,
                        SCOACosting ,
                        SCOAItemCode ,
                        SCOAItem ,
                        ItemDescription ,
                        CurrentBudgetFinYear1 ,
                        CurrentBudgetFinYear2 ,
                        CurrentBudgetFinYear3 ,
                        AvailableBudgetFinYear1 ,
                        CapitalOperation ,
                        BudgetVersionID, 
						ProjectItemId,
						CostingProject,
						Ukey
					)
                    SELECT DISTINCT
                            @FinYear AS FinYear1 ,
                            @FinYear2 AS FinYear2 ,
                            @FinYear3 AS FinYear3 ,
                            pp.Project_ID AS ProjectId ,
							ISNULL(pp.ProjectCode, pp.Project_ID) AS ProjectCode ,
                            REPLACE(REPLACE(REPLACE(pp.ProjectName, ';', ''), '|', '_'), ',', ';') AS ProjectName ,
                            PCOT.TypeName AS BudgetType ,
							ppi.PlanProjectItem_ID AS PlanProjectItemID,
                            project.ScoaCode AS SCOAProjectCode ,
                            REPLACE(REPLACE(REPLACE(REPLACE(project.ScoaDesc,
                                                            CHAR(10), ' '),
                                                    CHAR(13), ' '),
                                            CHAR(09), ' '), ',', ';') AS SCOAProject ,
                            func.ScoaCode AS SCOAFuctionCode ,
                            REPLACE(REPLACE(REPLACE(REPLACE(func.ScoaDesc,
                                                            CHAR(10), ' '),
                                                    CHAR(13), ' '),
                                            CHAR(09), ' '), ',', ';') AS SCOAFunction ,
                            dep.DepartmentCode AS MSCDepartmentCode ,
                            REPLACE(dep.DepartmentDesc, ',', '_') AS MSCDepartment ,
                            cd.DivisionCode AS MSCDivisionCode ,
                            REPLACE(cd.DivisionDesc, ',', ' _') AS MSCDivision ,
                            dep.DepartmentCode + ' - '
                            + REPLACE(dep.DepartmentDesc, ',', '_')
                            + ' / ' + cd.DivisionCode + ' - '
                            + REPLACE(cd.DivisionDesc, ',', '_') AS MunicipleClassification ,
                            fs.ScoaCode AS SCOAFundCode ,
                            REPLACE(REPLACE(REPLACE(REPLACE(fs.ScoaDesc,
                                                            CHAR(10), ' '),
                                                    CHAR(13), ' '),
                                            CHAR(09), ' '), ',', ';') AS SCOAFund ,
                            region.ScoaCode AS SCOARegionCode ,
                            REPLACE(REPLACE(REPLACE(REPLACE(region.ScoaDesc,
                                                            CHAR(10), ' '),
                                                    CHAR(13), ' '),
                                            CHAR(09), ' '), ',', ';') AS SCOARegion ,
                            costing.ScoaCode AS SCOACostingCode ,
                            REPLACE(REPLACE(REPLACE(REPLACE(costing.ScoaDesc,
                                                            CHAR(10), ' '),
                                                    CHAR(13), ' '),
                                            CHAR(09), ' '), ',', ';') AS SCOACosting ,
                            css.ScoaCode AS SCOAItemCode ,
                            REPLACE(REPLACE(REPLACE(REPLACE(css.ScoaDesc,
                                                            CHAR(10), ' '),
                                                    CHAR(13), ' '),
                                            CHAR(09), ' '), ',', ';') AS SCOAItem ,
                            REPLACE(cpi.ItemDescription, ',', ' _') AS ItemDescription ,
                            CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                            OR css.ScoaCode LIKE 'IL%'
                                            )
                                            AND ppid.CapitalOperation IN ( 0,
                                                            1, 2 )
                                        )
                                        OR ppi.CreditDebit = 'C'
                                        ) THEN -ISNULL(ppid.BudgetAmount, 0)
                                    ELSE ISNULL(ppid.BudgetAmount, 0)
                            END AS CurrentBudgetFinYear1 ,
                            CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                            OR css.ScoaCode LIKE 'IL%'
                                            )
                                            AND ppid.CapitalOperation IN ( 0,
                                                            1, 2 )
                                        )
                                        OR ppi.CreditDebit = 'C'
                                        )
                                    THEN -ISNULL(ppid.BudgetAmountCurP1, 0)
                                    ELSE ISNULL(ppid.BudgetAmountCurP1, 0)
                            END AS CurrentBudgetFinYear2 ,
                            CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                            OR css.ScoaCode LIKE 'IL%'
                                            )
                                            AND ppid.CapitalOperation IN ( 0,
                                                            1, 2 )
                                        )
                                        OR ppi.CreditDebit = 'C'
                                        )
                                    THEN -ISNULL(ppid.BudgetAmountCurP2, 0)
                                    ELSE ISNULL(ppid.BudgetAmountCurP2, 0)
                            END AS CurrentBudgetFinYear3 ,
                            ISNULL(bc.AvailableBudget,
                                    CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                                    OR css.ScoaCode LIKE 'IL%'
                                                    )
                                                    AND pp.CapitalOperation IN (
                                                    0, 1, 2 )
                                                )
                                                OR ppi.CreditDebit = 'C'
                                                )
                                        THEN -ISNULL(ppi.BudgetAmount, 0)
                                        ELSE ISNULL(ppi.BudgetAmount, 0)
                                    END) AS AvailableBudgetFinYear1 ,
                            0 ,
                            0 , 
							ISNULL(ppi.ProjectItemID,0) AS ProjectItemID ,
							ISNULL(pp.CostingProject, 0) AS CostingProject ,
							ISNULL(ppi.HistoricalProjectCode, '') AS Ukey

                    FROM    dbo.Plan_Project pp
							INNER JOIN Plan_ProjectItem ppi ON ppi.ProjectID = pp.Project_ID
                            INNER JOIN dbo.Const_Status cs ON cs.Status_ID = pp.ProjectStatus
                            LEFT JOIN
								(
									SELECT MAX(BudgetConsumption_ID) BudgetConsumptionID, PlanProjectItemID 
									FROM Plan_BudgetConsumption 
									WHERE FinYear = @FinYear 
									GROUP BY PlanProjectItemID
								) maxBC ON maxBC.PlanProjectItemID = ppi.PlanProjectItem_ID
							LEFT JOIN Plan_BudgetConsumption bc ON bc.BudgetConsumption_ID = maxBC.BudgetConsumptionID
                            INNER JOIN dbo.Plan_BudgetVersionDetail ppid ON ppid.PlanProjectItemID = ppi.PlanProjectItem_ID
                            INNER JOIN dbo.Const_Division cd ON cd.Division_ID = ppi.DivisionId
                            INNER JOIN dbo.Const_Department dep ON cd.DepartmentID = dep.Department_ID
                            INNER JOIN dbo.Const_SCOA_Function_Structure_Consolidated AS func ON func.ScoaID = ppi.SCOAFunctionId AND func.FinYearText = @FinYear
                            INNER JOIN dbo.Const_SCOA_Regional_Structure_Consolidated AS region ON region.ScoaID = ppi.SCOARegionId AND region.FinYearText = @FinYear
                            INNER JOIN dbo.Const_SCOA_Costing_Structure_Consolidated AS costing ON costing.ScoaID = ppi.SCOACostingID AND costing.FinYearText = @FinYear
                            INNER JOIN dbo.Const_SCOA_Project_Structure_Consolidated AS project ON project.ScoaID = pp.ScoaProjectID AND project.FinYearText = @FinYear
                            LEFT JOIN dbo.Const_ProjectItem cpi ON ppi.ProjectItemID = cpi.ProjectItem_ID
                            INNER JOIN #Const_SCOA_Structure AS css ON ppi.SCOAItemID = css.ScoaID
                            INNER JOIN dbo.Const_SCOA_Funds_Structure_Consolidated AS fs ON ppi.SCOAFundId = fs.ScoaID AND fs.FinYearText = @FinYear
                            INNER JOIN @temp t ON t.tblDivisionId = cd.Division_ID
                            INNER JOIN dbo.Const_PlanCapitalOperationalTypes_sys PCOT ON PCOT.TypeValue = pp.CapitalOperation
                    WHERE   ( CASE WHEN @ProjectID = 0 THEN 0
                                    ELSE pp.Project_ID
                                END = @ProjectID )
                            AND ( CASE WHEN @ScoaFundID = 0 THEN 0
                                        ELSE fs.ScoaID
                                    END = @ScoaFundID )
                            AND ( CASE WHEN @ScoaFunctionID = 0 THEN 0
                                        ELSE func.ScoaID
                                    END = @ScoaFunctionID )
                            AND ( CASE WHEN @ScoaRegionID = 0 THEN 0
                                        ELSE region.ScoaID
                                    END = @ScoaRegionID )
                            AND ( CASE WHEN @ScoaItemID = 0 THEN 0
                                        ELSE css.ScoaID
                                    END = @ScoaItemID )
                            AND ( CASE WHEN @DepartmentID = 0 THEN 0
                                        ELSE dep.Department_ID
                                    END = @DepartmentID )
                            AND ( CASE WHEN @ProjectTypeID = 0 THEN 0
                                        ELSE pp.ProjectTypeID
                                    END = @ProjectTypeID )
                            AND ( CASE WHEN @FinYear = '' THEN ''
                                        ELSE pp.FinYear
                                    END = @FinYear )
                            AND ( CASE WHEN @FinYear = '' THEN ''
                                        ELSE ppi.FinYear
                                    END = @FinYear )
                            AND ( CASE WHEN @ProjectStatusId = 0 THEN 0
                                        ELSE pp.ProjectStatus
                                    END = @ProjectStatusId )
                            AND ( CASE WHEN @SingleMultiYear = '' THEN ''
                                        ELSE pp.SingleMultiYear
                                    END = @SingleMultiYear )
                            AND ISNULL(pp.IsDeleted, 0) <> 1
                            AND ppid.BudgetVersionID = @VersionId
                    ORDER BY MunicipleClassification;
        END;
    ELSE
        IF @VersionId > 0
            BEGIN
                INSERT  INTO @Tbl
                        ( FinYear1 ,
                            FinYear2 ,
                            FinYear3 ,
                            ProjectId ,
							ProjectCode ,
                            ProjectName ,
                            BudgetType ,
							PlanProjectItemID,
                            SCOAProjectCode ,
                            SCOAProject ,
                            SCOAFuctionCode ,
                            SCOAFunction ,
                            MSCDepartmentCode ,
                            MSCDepartment ,
                            MSCDivisionCode ,
                            MSCDivision ,
                            MunicipleClassification ,
                            SCOAFundCode ,
                            SCOAFund ,
                            SCOARegionCode ,
                            SCOARegion ,
                            SCOACostingCode ,
                            SCOACosting ,
                            SCOAItemCode ,
                            SCOAItem ,
                            ItemDescription ,
                            CurrentBudgetFinYear1 ,
                            CurrentBudgetFinYear2 ,
                            CurrentBudgetFinYear3 ,
                            AvailableBudgetFinYear1 ,
                            CapitalOperation ,
                            BudgetVersionID ,
							ProjectItemId ,
							CostingProject ,
							Ukey
					    )
                        SELECT DISTINCT
                                @FinYear AS FinYear1 ,
                                @FinYear2 AS FinYear2 ,
                                @FinYear3 AS FinYear3 ,
                                pp.Project_ID AS ProjectId ,
								ISNULL(pp.ProjectCode, pp.Project_ID) AS ProjectCode ,
								REPLACE(REPLACE(REPLACE(pp.ProjectName, ';', ''), '|', '_'), ',', ';') AS ProjectName ,
                                PCOT.TypeName AS BudgetType ,
								ppi.PlanProjectItem_ID AS PlanProjectItemID,
                                project.ScoaCode AS SCOAProjectCode ,
                                REPLACE(REPLACE(REPLACE(REPLACE(project.ScoaDesc,
                                                            CHAR(10), ' '),
                                                        CHAR(13), ' '),
                                                CHAR(09), ' '), ',', ';') AS SCOAProject ,
                                func.ScoaCode AS SCOAFuctionCode ,
                                REPLACE(REPLACE(REPLACE(REPLACE(func.ScoaDesc,
                                                            CHAR(10), ' '),
                                                        CHAR(13), ' '),
                                                CHAR(09), ' '), ',', ';') AS SCOAFunction ,
                                dep.DepartmentCode AS MSCDepartmentCode ,
                                REPLACE(dep.DepartmentDesc, ',', '_') AS MSCDepartment ,
                                cd.DivisionCode AS MSCDivisionCode ,
                                REPLACE(cd.DivisionDesc, ',', ' _') AS MSCDivision ,
                                dep.DepartmentCode + ' - '
                                + REPLACE(dep.DepartmentDesc, ',', ' _')
                                + ' / ' + cd.DivisionCode + ' - '
                                + REPLACE(cd.DivisionDesc, ',', ' _') AS MunicipleClassification ,
                                fs.ScoaCode AS SCOAFundCode ,
                                REPLACE(REPLACE(REPLACE(REPLACE(fs.ScoaDesc,
                                                            CHAR(10), ' '),
                                                        CHAR(13), ' '),
                                                CHAR(09), ' '), ',', ';') AS SCOAFund ,
                                region.ScoaCode AS SCOARegionCode ,
                                REPLACE(REPLACE(REPLACE(REPLACE(region.ScoaDesc,
                                                            CHAR(10), ' '),
                                                        CHAR(13), ' '),
                                                CHAR(09), ' '), ',', ';') AS SCOARegion ,
                                costing.ScoaCode AS SCOACostingCode ,
                                REPLACE(REPLACE(REPLACE(REPLACE(costing.ScoaDesc,
                                                            CHAR(10), ' '),
                                                        CHAR(13), ' '),
                                                CHAR(09), ' '), ',', ';') AS SCOACosting ,
                                css.ScoaCode AS SCOAItemCode ,
                                REPLACE(REPLACE(REPLACE(REPLACE(css.ScoaDesc,
                                                            CHAR(10), ' '),
                                                        CHAR(13), ' '),
                                                CHAR(09), ' '), ',', ';') AS SCOAItem ,
                                REPLACE(cpi.ItemDescription, ',', ' _') AS ItemDescription ,
                                CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                                OR css.ScoaCode LIKE 'IL%'
                                                )
                                                AND ppid.CapitalOperation IN (
                                                0, 1, 2 )
                                            )
                                            OR ppi.CreditDebit = 'C'
                                            )
                                        THEN -ISNULL(ppid.BudgetAmount, 0)
                                        ELSE ISNULL(ppid.BudgetAmount, 0)
                                END AS CurrentBudgetFinYear1 ,
                                CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                                OR css.ScoaCode LIKE 'IL%'
                                                )
                                                AND ppid.CapitalOperation IN (
                                                0, 1, 2 )
                                            )
                                            OR ppi.CreditDebit = 'C'
                                            )
                                        THEN -ISNULL(ppid.BudgetAmountCurP1, 0)
                                        ELSE ISNULL(ppid.BudgetAmountCurP1, 0)
                                END AS CurrentBudgetFinYear2 ,
                                CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                                OR css.ScoaCode LIKE 'IL%'
                                                )
                                                AND ppid.CapitalOperation IN (
                                                0, 1, 2 )
                                            )
                                            OR ppi.CreditDebit = 'C'
                                            )
                                        THEN -ISNULL(ppid.BudgetAmountCurP2, 0)
                                        ELSE ISNULL(ppid.BudgetAmountCurP2, 0)
                                END AS CurrentBudgetFinYear3 ,
                                ISNULL(bc.AvailableBudget,
                                        CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                                        OR css.ScoaCode LIKE 'IL%'
                                                        )
                                                        AND pp.CapitalOperation IN (
                                                        0, 1, 2 )
                                                    )
                                                    OR ppi.CreditDebit = 'C'
                                                    )
                                            THEN -ISNULL(ppi.BudgetAmount,
                                                            0)
                                            ELSE ISNULL(ppi.BudgetAmount,
                                                        0)
                                        END) AS AvailableBudgetFinYear1 ,
                                0 ,
                                0 , 
								ISNULL(ppi.ProjectItemID, 0) AS ProjectItemID ,
								ISNULL(pp.CostingProject, 0) AS CostingProject ,
								ISNULL(ppi.HistoricalProjectCode, '') AS Ukey
                        FROM    dbo.Plan_Project pp
								INNER JOIN Plan_ProjectItem ppi ON ppi.ProjectID = pp.Project_ID
                                INNER JOIN dbo.Const_Status cs ON cs.Status_ID = pp.ProjectStatus
                                LEFT JOIN
									(
										SELECT MAX(BudgetConsumption_ID) BudgetConsumptionID, PlanProjectItemID 
										FROM Plan_BudgetConsumption 
										WHERE FinYear = @FinYear 
										GROUP BY PlanProjectItemID
									) maxBC ON maxBC.PlanProjectItemID = ppi.PlanProjectItem_ID
								LEFT JOIN Plan_BudgetConsumption bc ON bc.BudgetConsumption_ID = maxBC.BudgetConsumptionID
                                INNER JOIN dbo.Plan_BudgetVersionDetail ppid ON ppid.PlanProjectItemID = ppi.PlanProjectItem_ID
                                INNER JOIN dbo.Const_Division cd ON cd.Division_ID = ppi.DivisionId
                                INNER JOIN dbo.Const_Department dep ON cd.DepartmentID = dep.Department_ID
                                INNER JOIN dbo.Const_SCOA_Function_Structure_Consolidated AS func ON func.ScoaID = ppi.SCOAFunctionId AND func.FinYearText = @FinYear
								INNER JOIN dbo.Const_SCOA_Regional_Structure_Consolidated AS region ON region.ScoaID = ppi.SCOARegionId AND region.FinYearText = @FinYear
								INNER JOIN dbo.Const_SCOA_Costing_Structure_Consolidated AS costing ON costing.ScoaID = ppi.SCOACostingID AND costing.FinYearText = @FinYear
								INNER JOIN dbo.Const_SCOA_Project_Structure_Consolidated AS project ON project.ScoaID = pp.ScoaProjectID AND project.FinYearText = @FinYear
								LEFT JOIN dbo.Const_ProjectItem cpi ON ppi.ProjectItemID = cpi.ProjectItem_ID
								INNER JOIN #Const_SCOA_Structure AS css ON ppi.SCOAItemID = css.ScoaID
								INNER JOIN dbo.Const_SCOA_Funds_Structure_Consolidated AS fs ON ppi.SCOAFundId = fs.ScoaID AND fs.FinYearText = @FinYear
                                INNER JOIN @temp t ON t.tblDivisionId = cd.Division_ID
                                INNER JOIN dbo.Const_PlanCapitalOperationalTypes_sys PCOT ON PCOT.TypeValue = pp.CapitalOperation
                        WHERE   ( CASE WHEN @ProjectID = 0 THEN 0
                                        ELSE pp.Project_ID
                                    END = @ProjectID )
                                AND ( CASE WHEN @ScoaFundID = 0 THEN 0
                                            ELSE fs.ScoaID
                                        END = @ScoaFundID )
                                AND ( CASE WHEN @ScoaFunctionID = 0 THEN 0
                                            ELSE func.ScoaID
                                        END = @ScoaFunctionID )
                                AND ( CASE WHEN @ScoaRegionID = 0 THEN 0
                                            ELSE region.ScoaID
                                        END = @ScoaRegionID )
                                AND ( CASE WHEN @ScoaItemID = 0 THEN 0
                                            ELSE css.ScoaID
                                        END = @ScoaItemID )
                                AND ( CASE WHEN @DepartmentID = 0 THEN 0
                                            ELSE dep.Department_ID
                                        END = @DepartmentID )
                                AND ( CASE WHEN @ProjectTypeID = 0 THEN 0
                                            ELSE pp.ProjectTypeID
                                        END = @ProjectTypeID )
                                AND ( CASE WHEN @FinYear = '' THEN ''
                                            ELSE pp.FinYear
                                        END = @FinYear )
                                AND ( CASE WHEN @FinYear = '' THEN ''
                                            ELSE ppi.FinYear
                                        END = @FinYear )
                                AND ( CASE WHEN @ProjectStatusId = 0
                                            THEN 0
                                            ELSE pp.ProjectStatus
                                        END = @ProjectStatusId )
                                AND ( CASE WHEN @SingleMultiYear = ''
                                            THEN ''
                                            ELSE pp.SingleMultiYear
                                        END = @SingleMultiYear )
                                AND ISNULL(pp.IsDeleted, 0) <> 1
                                AND ppid.BudgetVersionID = @VersionId
                                AND pp.CapitalOperation = @CapitalOperational
                        ORDER BY MunicipleClassification;
            END;
        ELSE
            IF @CapitalOperational = 5
                BEGIN
                    INSERT  INTO @Tbl
                            ( FinYear1 ,
                                FinYear2 ,
                                FinYear3 ,
                                ProjectId ,
								ProjectCode ,
                                ProjectName ,
                                BudgetType ,
								PlanProjectItemID,
                                SCOAProjectCode ,
                                SCOAProject ,
                                SCOAFuctionCode ,
                                SCOAFunction ,
                                MSCDepartmentCode ,
                                MSCDepartment ,
                                MSCDivisionCode ,
                                MSCDivision ,
                                MunicipleClassification ,
                                SCOAFundCode ,
                                SCOAFund ,
                                SCOARegionCode ,
                                SCOARegion ,
                                SCOACostingCode ,
                                SCOACosting ,
                                SCOAItemCode ,
                                SCOAItem ,
                                ItemDescription ,
                                CurrentBudgetFinYear1 ,
                                CurrentBudgetFinYear2 ,
                                CurrentBudgetFinYear3 ,
                                AvailableBudgetFinYear1 ,
                                CapitalOperation ,
                                BudgetVersionID ,
								ProjectItemId ,
								CostingProject ,
								Ukey
					        )
                            SELECT DISTINCT
                                    @FinYear AS FinYear1 ,
                                    @FinYear2 AS FinYear2 ,
                                    @FinYear3 AS FinYear3 ,
									pp.Project_ID AS ProjectId ,
                                    ISNULL(pp.ProjectCode, pp.Project_ID) AS ProjectCode ,
									REPLACE(REPLACE(REPLACE(pp.ProjectName, ';', ''), '|', '_'), ',', ';') AS ProjectName ,
                                    PCOT.TypeName AS BudgetType ,
									ppi.PlanProjectItem_ID AS PlanProjectItemID,
                                    project.ScoaCode AS SCOAProjectCode ,
                                    REPLACE(REPLACE(REPLACE(REPLACE(project.ScoaDesc,
                                                            CHAR(10), ' '),
                                                            CHAR(13), ' '),
                                                    CHAR(09), ' '), ',',
                                            ';') AS SCOAProject ,
                                    func.ScoaCode AS SCOAFuctionCode ,
                                    REPLACE(REPLACE(REPLACE(REPLACE(func.ScoaDesc,
                                                            CHAR(10), ' '),
                                                            CHAR(13), ' '),
                                                    CHAR(09), ' '), ',',
                                            ';') AS SCOAFunction ,
                                    dep.DepartmentCode AS MSCDepartmentCode ,
                                    REPLACE(dep.DepartmentDesc, ',', '_') AS MSCDepartment ,
                                    cd.DivisionCode AS MSCDivisionCode ,
                                    REPLACE(cd.DivisionDesc, ',', ' _') AS MSCDivision ,
                                    dep.DepartmentCode + ' - '
                                    + REPLACE(dep.DepartmentDesc, ',',
                                                ' _') + ' / '
                                    + cd.DivisionCode + ' - '
                                    + REPLACE(cd.DivisionDesc, ',', ' _') AS MunicipleClassification ,
                                    fs.ScoaCode AS SCOAFundCode ,
                                    REPLACE(REPLACE(REPLACE(REPLACE(fs.ScoaDesc,
                                                            CHAR(10), ' '),
                                                            CHAR(13), ' '),
                                                    CHAR(09), ' '), ',',
                                            ';') AS SCOAFund ,
                                    region.ScoaCode AS SCOARegionCode ,
                                    REPLACE(REPLACE(REPLACE(REPLACE(region.ScoaDesc,
                                                            CHAR(10), ' '),
                                                            CHAR(13), ' '),
                                                    CHAR(09), ' '), ',',
                                            ';') AS SCOARegion ,
                                    costing.ScoaCode AS SCOACostingCode ,
                                    REPLACE(REPLACE(REPLACE(REPLACE(costing.ScoaDesc,
                                                            CHAR(10), ' '),
                                                            CHAR(13), ' '),
                                                    CHAR(09), ' '), ',',
                                            ';') AS SCOACosting ,
                                    css.ScoaCode AS SCOAItemCode ,
                                    REPLACE(REPLACE(REPLACE(REPLACE(css.ScoaDesc,
                                                            CHAR(10), ' '),
                                                            CHAR(13), ' '),
                                                    CHAR(09), ' '), ',',
                                            ';') AS SCOAItem ,
                                    REPLACE(cpi.ItemDescription, ',', ' _') AS ItemDescription ,
                                    CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                                    OR css.ScoaCode LIKE 'IL%'
                                                    )
                                                    AND pp.CapitalOperation IN (
                                                    0, 1, 2 )
                                                )
                                                OR ppi.CreditDebit = 'C'
                                                )
                                            THEN -ISNULL(ppi.BudgetAmount, 0)
                                            ELSE ISNULL(ppi.BudgetAmount, 0)
                                    END AS CurrentBudgetFinYear1 ,
                                    CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                                    OR css.ScoaCode LIKE 'IL%'
                                                    )
                                                    AND pp.CapitalOperation IN (
                                                    0, 1, 2 )
                                                )
                                                OR ppi.CreditDebit = 'C'
                                                )
                                            THEN -ISNULL(ppi.BudgetAmountCurP1,
                                                        0)
                                            ELSE ISNULL(ppi.BudgetAmountCurP1,
                                                        0)
                                    END AS CurrentBudgetFinYear2 ,
                                    CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                                    OR css.ScoaCode LIKE 'IL%'
                                                    )
                                                    AND pp.CapitalOperation IN (
                                                    0, 1, 2 )
                                                )
                                                OR ppi.CreditDebit = 'C'
                                                )
                                            THEN -ISNULL(ppi.BudgetAmountCurP2,
                                                        0)
                                            ELSE ISNULL(ppi.BudgetAmountCurP2,
                                                        0)
                                    END AS CurrentBudgetFinYear3 ,
                                    ISNULL(bc.AvailableBudget,
                                            CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                                            OR css.ScoaCode LIKE 'IL%'
                                                            )
                                                            AND pp.CapitalOperation IN (
                                                            0, 1, 2 )
                                                        )
                                                        OR ppi.CreditDebit = 'C'
                                                        )
                                                THEN -ISNULL(ppi.BudgetAmount,
                                                            0)
                                                ELSE ISNULL(ppi.BudgetAmount,
                                                            0)
                                            END) AS AvailableBudgetFinYear1 ,
                                    0 ,
                                    0 , 
									ISNULL(ppi.ProjectItemID, 0) AS ProjectItemID ,
									ISNULL(pp.CostingProject , 0) AS CostingProject ,
									ISNULL(ppi.HistoricalProjectCode, '') AS Ukey
                            FROM    dbo.Plan_Project pp
									INNER JOIN Plan_ProjectItem ppi on ppi.ProjectID = pp.Project_ID
                                    INNER JOIN dbo.Const_Status cs ON cs.Status_ID = pp.ProjectStatus
                                    LEFT JOIN
										(
											SELECT MAX(BudgetConsumption_ID) BudgetConsumptionID, PlanProjectItemID 
											FROM Plan_BudgetConsumption 
											WHERE FinYear = @FinYear 
											GROUP BY PlanProjectItemID
										) maxBC ON maxBC.PlanProjectItemID = ppi.PlanProjectItem_ID
									LEFT JOIN Plan_BudgetConsumption bc ON bc.BudgetConsumption_ID = maxBC.BudgetConsumptionID
                                    INNER JOIN dbo.Const_Division cd ON cd.Division_ID = ppi.DivisionId
                                    INNER JOIN dbo.Const_Department dep ON cd.DepartmentID = dep.Department_ID
                                    INNER JOIN dbo.Const_SCOA_Function_Structure_Consolidated AS func ON func.ScoaID = ppi.SCOAFunctionId AND func.FinYearText = @FinYear
									INNER JOIN dbo.Const_SCOA_Regional_Structure_Consolidated AS region ON region.ScoaID = ppi.SCOARegionId AND region.FinYearText = @FinYear
									INNER JOIN dbo.Const_SCOA_Costing_Structure_Consolidated AS costing ON costing.ScoaID = ppi.SCOACostingID AND costing.FinYearText = @FinYear
									INNER JOIN dbo.Const_SCOA_Project_Structure_Consolidated AS project ON project.ScoaID = pp.ScoaProjectID AND project.FinYearText = @FinYear
									LEFT JOIN dbo.Const_ProjectItem cpi ON ppi.ProjectItemID = cpi.ProjectItem_ID
									INNER JOIN #Const_SCOA_Structure AS css ON ppi.SCOAItemID = css.ScoaID
									INNER JOIN dbo.Const_SCOA_Funds_Structure_Consolidated AS fs ON ppi.SCOAFundId = fs.ScoaID AND fs.FinYearText = @FinYear
                                    INNER JOIN @temp t ON t.tblDivisionId = cd.Division_ID
                                    INNER JOIN dbo.Const_PlanCapitalOperationalTypes_sys PCOT ON PCOT.TypeValue = pp.CapitalOperation
                            WHERE   ( CASE WHEN @ProjectID = 0 THEN 0
                                            ELSE pp.Project_ID
                                        END = @ProjectID )
                                    AND ( CASE WHEN @ScoaFundID = 0 THEN 0
                                                ELSE fs.ScoaID
                                            END = @ScoaFundID )
                                    AND ( CASE WHEN @ScoaFunctionID = 0
                                                THEN 0
                                                ELSE func.ScoaID
                                            END = @ScoaFunctionID )
                                    AND ( CASE WHEN @ScoaRegionID = 0
                                                THEN 0
                                                ELSE region.ScoaID
                                            END = @ScoaRegionID )
                                    AND ( CASE WHEN @ScoaItemID = 0 THEN 0
                                                ELSE css.ScoaID
                                            END = @ScoaItemID )
                                    AND ( CASE WHEN @DepartmentID = 0
                                                THEN 0
                                                ELSE dep.Department_ID
                                            END = @DepartmentID )
                                    AND ( CASE WHEN @ProjectTypeID = 0
                                                THEN 0
                                                ELSE pp.ProjectTypeID
                                            END = @ProjectTypeID )
                                    AND ( CASE WHEN @FinYear = '' THEN ''
                                                ELSE pp.FinYear
                                            END = @FinYear )
                                    AND ( CASE WHEN @FinYear = '' THEN ''
                                                ELSE ppi.FinYear
                                            END = @FinYear )
                                    AND ( CASE WHEN @ProjectStatusId = 0
                                                THEN 0
                                                ELSE pp.ProjectStatus
                                            END = @ProjectStatusId )
                                    AND ( CASE WHEN @SingleMultiYear = ''
                                                THEN ''
                                                ELSE pp.SingleMultiYear
                                            END = @SingleMultiYear )
                                    AND ISNULL(pp.IsDeleted, 0) <> 1
                            ORDER BY MunicipleClassification;
                END;
            ELSE
                BEGIN
                    INSERT  INTO @Tbl
                            ( FinYear1 ,
                                FinYear2 ,
                                FinYear3 ,
                                ProjectId ,
								ProjectCode ,
                                ProjectName ,
                                BudgetType ,
								PlanProjectItemID,
                                SCOAProjectCode ,
                                SCOAProject ,
                                SCOAFuctionCode ,
                                SCOAFunction ,
                                MSCDepartmentCode ,
                                MSCDepartment ,
                                MSCDivisionCode ,
                                MSCDivision ,
                                MunicipleClassification ,
                                SCOAFundCode ,
                                SCOAFund ,
                                SCOARegionCode ,
                                SCOARegion ,
                                SCOACostingCode ,
                                SCOACosting ,
                                SCOAItemCode ,
                                SCOAItem ,
                                ItemDescription ,
                                CurrentBudgetFinYear1 ,
                                CurrentBudgetFinYear2 ,
                                CurrentBudgetFinYear3 ,
                                AvailableBudgetFinYear1 ,
                                CapitalOperation ,
                                BudgetVersionID , 
								ProjectItemId ,
								CostingProject ,
								Ukey
					        )
                            SELECT DISTINCT
                                    @FinYear AS FinYear1 ,
                                    @FinYear2 AS FinYear2 ,
                                    @FinYear3 AS FinYear3 ,
                                    pp.Project_ID AS ProjectId ,
									ISNULL(pp.ProjectCode, pp.Project_ID) AS ProjectCode ,
									REPLACE(REPLACE(REPLACE(pp.ProjectName, ';', ''), '|', '_'), ',', ';') AS ProjectName ,
                                    PCOT.TypeName AS BudgetType ,
									ppi.PlanProjectItem_ID AS PlanProjectItemID,
                                    project.ScoaCode AS SCOAProjectCode ,
                                    REPLACE(REPLACE(REPLACE(REPLACE(project.ScoaDesc,
                                                            CHAR(10), ' '),
                                                            CHAR(13), ' '),
                                                    CHAR(09), ' '), ',',
                                            ';') AS SCOAProject ,
                                    func.ScoaCode AS SCOAFuctionCode ,
                                    REPLACE(REPLACE(REPLACE(REPLACE(func.ScoaDesc,
                                                            CHAR(10), ' '),
                                                            CHAR(13), ' '),
                                                    CHAR(09), ' '), ',',
                                            ';') AS SCOAFunction ,
                                    dep.DepartmentCode AS MSCDepartmentCode ,
                                    REPLACE(dep.DepartmentDesc, ',', '_') AS MSCDepartment ,
                                    cd.DivisionCode AS MSCDivisionCode ,
                                    REPLACE(cd.DivisionDesc, ',', ' _') AS MSCDivision ,
                                    dep.DepartmentCode + ' - '
                                    + REPLACE(dep.DepartmentDesc, ',',
                                                ' _') + ' / '
                                    + cd.DivisionCode + ' - '
                                    + REPLACE(cd.DivisionDesc, ',', ' _') AS MunicipleClassification ,
                                    fs.ScoaCode AS SCOAFundCode ,
                                    REPLACE(REPLACE(REPLACE(REPLACE(fs.ScoaDesc,
                                                            CHAR(10), ' '),
                                                            CHAR(13), ' '),
                                                    CHAR(09), ' '), ',',
                                            ';') AS SCOAFund ,
                                    region.ScoaCode AS SCOARegionCode ,
                                    REPLACE(REPLACE(REPLACE(REPLACE(region.ScoaDesc,
                                                            CHAR(10), ' '),
                                                            CHAR(13), ' '),
                                                    CHAR(09), ' '), ',',
                                            ';') AS SCOARegion ,
                                    costing.ScoaCode AS SCOACostingCode ,
                                    REPLACE(REPLACE(REPLACE(REPLACE(costing.ScoaDesc,
                                                            CHAR(10), ' '),
                                                            CHAR(13), ' '),
                                                    CHAR(09), ' '), ',',
                                            ';') AS SCOACosting ,
                                    css.ScoaCode AS SCOAItemCode ,
                                    REPLACE(REPLACE(REPLACE(REPLACE(css.ScoaDesc,
                                                            CHAR(10), ' '),
                                                            CHAR(13), ' '),
                                                    CHAR(09), ' '), ',',
                                            ';') AS SCOAItem ,
                                    REPLACE(cpi.ItemDescription, ',', ' _') AS ItemDescription ,
                                    CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                                    OR css.ScoaCode LIKE 'IL%'
                                                    )
                                                    AND pp.CapitalOperation IN (
                                                    0, 1, 2 )
                                                )
                                                OR ppi.CreditDebit = 'C'
                                                )
                                            THEN -ISNULL(ppi.BudgetAmount, 0)
                                            ELSE ISNULL(ppi.BudgetAmount, 0)
                                    END AS CurrentBudgetFinYear1 ,
                                    CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                                    OR css.ScoaCode LIKE 'IL%'
                                                    )
                                                    AND pp.CapitalOperation IN (
                                                    0, 1, 2 )
                                                )
                                                OR ppi.CreditDebit = 'C'
                                                )
                                            THEN -ISNULL(ppi.BudgetAmountCurP1,
                                                        0)
                                            ELSE ISNULL(ppi.BudgetAmountCurP1,
                                                        0)
                                    END AS CurrentBudgetFinYear2 ,
                                    CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                                    OR css.ScoaCode LIKE 'IL%'
                                                    )
                                                    AND pp.CapitalOperation IN (
                                                    0, 1, 2 )
                                                )
                                                OR ppi.CreditDebit = 'C'
                                                )
                                            THEN -ISNULL(ppi.BudgetAmountCurP2,
                                                        0)
                                            ELSE ISNULL(ppi.BudgetAmountCurP2,
                                                        0)
                                    END AS CurrentBudgetFinYear3 ,
                                    ISNULL(bc.AvailableBudget,
                                            CASE WHEN ( ( ( css.ScoaCode LIKE 'IR%'
                                                            OR css.ScoaCode LIKE 'IL%'
                                                            )
                                                            AND pp.CapitalOperation IN (
                                                            0, 1, 2 )
                                                        )
                                                        OR ppi.CreditDebit = 'C'
                                                        )
                                                THEN -ISNULL(ppi.BudgetAmount,
                                                            0)
                                                ELSE ISNULL(ppi.BudgetAmount,
                                                            0)
                                            END) AS AvailableBudgetFinYear1 ,
                                    0 ,
                                    0 , 
									ISNULL(ppi.ProjectItemID,0) AS ProjectItemID ,
									ISNULL(pp.CostingProject, 0) AS CostingProject ,
									ISNULL(ppi.HistoricalProjectCode, '') AS Ukey
                            FROM    dbo.Plan_Project pp
									INNER JOIN Plan_ProjectItem ppi ON ppi.ProjectID = pp.Project_ID
                                    INNER JOIN dbo.Const_Status cs ON cs.Status_ID = pp.ProjectStatus
                                    LEFT JOIN
										(
											SELECT MAX(BudgetConsumption_ID) BudgetConsumptionID, PlanProjectItemID 
											FROM Plan_BudgetConsumption 
											WHERE FinYear = @FinYear 
											GROUP BY PlanProjectItemID
										) maxBC ON maxBC.PlanProjectItemID = ppi.PlanProjectItem_ID
									LEFT JOIN Plan_BudgetConsumption bc ON bc.BudgetConsumption_ID = maxBC.BudgetConsumptionID
                                    INNER JOIN dbo.Const_Division cd ON cd.Division_ID = ppi.DivisionId
                                    INNER JOIN dbo.Const_Department dep ON cd.DepartmentID = dep.Department_ID
                                    INNER JOIN dbo.Const_SCOA_Function_Structure_Consolidated AS func ON func.ScoaID = ppi.SCOAFunctionId AND func.FinYearText = @FinYear
									INNER JOIN dbo.Const_SCOA_Regional_Structure_Consolidated AS region ON region.ScoaID = ppi.SCOARegionId AND region.FinYearText = @FinYear
									INNER JOIN dbo.Const_SCOA_Costing_Structure_Consolidated AS costing ON costing.ScoaID = ppi.SCOACostingID AND costing.FinYearText = @FinYear
									INNER JOIN dbo.Const_SCOA_Project_Structure_Consolidated AS project ON project.ScoaID = pp.ScoaProjectID AND project.FinYearText = @FinYear
									LEFT JOIN dbo.Const_ProjectItem cpi ON ppi.ProjectItemID = cpi.ProjectItem_ID
									INNER JOIN #Const_SCOA_Structure AS css ON ppi.SCOAItemID = css.ScoaID
									INNER JOIN dbo.Const_SCOA_Funds_Structure_Consolidated AS fs ON ppi.SCOAFundId = fs.ScoaID AND fs.FinYearText = @FinYear
                                    INNER JOIN @temp t ON t.tblDivisionId = cd.Division_ID
                                    INNER JOIN dbo.Const_PlanCapitalOperationalTypes_sys PCOT ON PCOT.TypeValue = pp.CapitalOperation
                            WHERE   ( CASE WHEN @ProjectID = 0 THEN 0
                                            ELSE pp.Project_ID
                                        END = @ProjectID )
                                    AND ( CASE WHEN @ScoaFundID = 0 THEN 0
                                                ELSE fs.ScoaID
                                            END = @ScoaFundID )
                                    AND ( CASE WHEN @ScoaFunctionID = 0
                                                THEN 0
                                                ELSE func.ScoaID
                                            END = @ScoaFunctionID )
                                    AND ( CASE WHEN @ScoaRegionID = 0
                                                THEN 0
                                                ELSE region.ScoaID
                                            END = @ScoaRegionID )
                                    AND ( CASE WHEN @ScoaItemID = 0 THEN 0
                                                ELSE css.ScoaID
                                            END = @ScoaItemID )
                                    AND ( CASE WHEN @DepartmentID = 0
                                                THEN 0
                                                ELSE dep.Department_ID
                                            END = @DepartmentID )
                                    AND ( CASE WHEN @ProjectTypeID = 0
                                                THEN 0
                                                ELSE pp.ProjectTypeID
                                            END = @ProjectTypeID )
                                    AND ( CASE WHEN @FinYear = '' THEN ''
                                                ELSE pp.FinYear
                                            END = @FinYear )
                                    AND ( CASE WHEN @FinYear = '' THEN ''
                                                ELSE ppi.FinYear
                                            END = @FinYear )
                                    AND ( CASE WHEN @ProjectStatusId = 0
                                                THEN 0
                                                ELSE pp.ProjectStatus
                                            END = @ProjectStatusId )
                                    AND ( CASE WHEN @SingleMultiYear = ''
                                                THEN ''
                                                ELSE pp.SingleMultiYear
                                            END = @SingleMultiYear )
                                        AND ISNULL(pp.IsDeleted, 0) <> 1
                                    AND pp.CapitalOperation = @CapitalOperational
                            ORDER BY MunicipleClassification;
                END;

    SELECT  FinYear1,
            FinYear2,
            FinYear3,
            ProjectId,
			ProjectCode,
            ProjectName,
            BudgetType,
			PlanProjectItemID,
            SCOAProjectCode,
            SCOAProject,
            SCOAFuctionCode,
            SCOAFunction,
            MSCDepartmentCode,
            MSCDepartment,
            MSCDivisionCode,
            MSCDivision,
            MunicipleClassification,
            SCOAFundCode,
            SCOAFund,
            SCOARegionCode,
            SCOARegion,
            SCOACostingCode,
            SCOACosting,
            SCOAItemCode,
            SCOAItem,
            ItemDescription,
            CurrentBudgetFinYear1,
            CurrentBudgetFinYear2,
            CurrentBudgetFinYear3,
            AvailableBudgetFinYear1,
            CapitalOperation,
            BudgetVersionID,
			ProjectItemID,
			CostingProject,
			Ukey
    FROM    @Tbl;

END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_ProjectDetailRpt_1_sp]    Script Date: 2026/03/10 7:23:45 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author: Carol Brooking
-- Create date: 17/02/2015
-- Description: Project Report - First sp to retreive data for full project report.
-- this gets Project Register, Project Details and Project Business Plan
-- This only relates to one project
-- calls : Plan_ProjectDetailRpt_1_sp 514
-- RC 22/05/2015 Added Revenue TP 20024
-- JP 05/04/2016 Remove Joins for Const_SCOA_Regional_Structure, Const_SCOA_Function_Structure, Department and Division
-- JP 05/04/2016 Set Columns (SCOARegionID, SCOAFunctionID to 0) & SCOA Function and Region by Function
-- JP 05/04/2016 Remove Columns EstimatedEndDate, EstimatedStartDate, CostEstimate, EstimatedDuration, CommencementDate
-- SN 30/04/2016: Modify Names of Operation and Revenue --> Operational Expenditure and Operational Revenue
-- SNagpal 22/11/2016: Implement Plan_ProjectCosting_fxn to get multiple SCOA Costing
-- Rchetty 14/02/2017: Quantity is now zero for all project items so cannot multiply by quantity amount
-- 29/03/2017 SNagpal: As IDPItemID,IsNonIDP and ItemId no more exists in Plan_Project Table. So apply function Plan_ProjectIDP_fxn to get IDPItemDesc
-- 12/06/2018 SNagpal: Add  dynamic Budget Type
-- =============================================
CREATE PROCEDURE [dbo].[Plan_ProjectDetailRpt_1_sp] @ProjectID INT
AS
    BEGIN

        SELECT --ProjectRegister
                p.Project_ID ,
                p.ProjectName ,
                REPLACE(REPLACE(REPLACE(p.ProjectDesc, CHAR(10), ' '),
                                CHAR(13), ' '), CHAR(09), ' ') AS ProjectDesc ,
                p.ProjectStatus ,
                cs.StatusDesc ,
                --CASE WHEN p.IsNonIDP = 0 THEN 'No'
                --     WHEN p.IsNonIDP = 1 THEN 'Yes'
                --END IsNonIDP ,
				'No' AS IsNonIDP,
                 0 AS IDPItemID,--p.IDPItemID ,
                ISNULL(dbo.Plan_ProjectIDP_fxn(p.Project_ID, 0),'') AS IDPItemDesc, --i.ItemDesc AS IDPItemDesc ,
                p.ScoaProjectID ,
                sp.ScoaCode AS ProjectCode ,
                0 AS SCOARegionID ,
                dbo.Plan_ProjectRegions_fxn(p.Project_ID, 1) AS SCOARegion ,
                0 AS SCOAFunctionID ,
                dbo.Plan_ProjectFunction_fxn(p.Project_ID, 1) AS SCOAFunction ,
                0 AS SCOACostingID ,
                dbo.Plan_ProjectCosting_fxn(p.Project_ID, 1)  AS SCOACosting,-- Cost.ScoaShortDesc + ' (' + Cost.ScoaCode + ')' AS SCOACosting ,
                p.ProjectTypeID ,
                pt.[ProjectTypeDescrip] ,
                --CASE WHEN [CapitalOperation] = 2 THEN 'Operational Revenue'
                --     WHEN [CapitalOperation] = 1 THEN 'Capital'
                --     WHEN [CapitalOperation] = 0 THEN 'Operational Expenditure'
                --END AS CapitalOperation ,
				( SELECT    TypeName
                          FROM      dbo.Const_PlanCapitalOperationalTypes_sys
                          WHERE     TypeValue = p.CapitalOperation
                        ) AS CapitalOperation, 
                ISNULL(dbo.Plan_ProjectDepartment_fxn(p.Project_ID, 1),
                       'No Department') + ' / '
                + ISNULL(dbo.Plan_ProjectDivision_fxn(p.Project_ID, 1),
                         'No Division') AS MuniClassification ,
                ISNULL(ep.FirstName, '') + ' ' + ISNULL(ep.Surname, '') AS ProjectManager ,
                ISNULL(es.FirstName, '') + ' ' + ISNULL(es.Surname, '') AS SupplyChainOfficial ,
                p.ProjectDistinctionID ,
                Dist.ProjectDistinction

 --Suspect there will be more summing required at some point
                ,
                TotalFunds ,
                ProjItemValues.QuantityandPrice AS TotalProjItemQuantityandPrice ,
                ProjItemValues.Price AS TotalProjItemPrice

 --Project Details
                ,
                p.ProjectDetailDesc ,
                ISNULL(FinCont.FirstName, '') + ' ' + ISNULL(FinCont.Surname,
                                                             '') AS FinancialController ,
                ISNULL(ProgMan.FirstName, '') + ' ' + ISNULL(ProgMan.Surname,
                                                             '') AS ProgrammeManager ,
                ProjectCategory_ID ,
                ProjectCategoryDescrip ,
                p.ProjectImplementAgentID ,
                ImpAgent.ProjectImplementAgentDescrip ,
                Longitude ,
                Latitude

 ---Business plan
                ,
                [ProjectBusinessPlan_ID] ,
                [QualityCheckerID] ,
                ISNULL(QualChecker.FirstName, '') + ' '
                + ISNULL(QualChecker.Surname, '') AS QualityChecker ,
                [LessonsLearnt] ,
                [ExpectedBenefit] ,
                [IdentifiedRisk]
--Need to manage Project Justification
         ,
                ( SELECT    dbo.ConcateString('Plan_ProjectJustification',
                                              p.Project_ID)
                ) AS ProjectJustification ,
                [OtherJustification]
--Stakeholders in another sp
        FROM    Plan_Project p
                INNER JOIN Const_SCOA_Project_Structure sp ON p.ScoaProjectID = sp.ScoaID
               -- LEFT JOIN Const_SCOA_Costing_Structure Cost ON p.SCOACostingID = Cost.ScoaID
                INNER JOIN Const_Status cs ON p.ProjectStatus = cs.Status_ID
                --LEFT JOIN IDP_Item i ON p.IDPItemID = i.Item_ID
                LEFT JOIN Const_ProjectType pt ON p.ProjectTypeID = pt.ProjectType_ID
                LEFT JOIN Const_ProjectDistinction Dist ON p.ProjectDistinctionID = Dist.ProjectDistinction_ID
                LEFT JOIN Payroll_Employee ep ON p.ProjectManagerID = ep.Employee_ID
                LEFT JOIN Payroll_Employee es ON p.SupplyChainOfficialID = es.Employee_ID
                LEFT JOIN Payroll_Employee FinCont ON p.FinancialControllerID = FinCont.Employee_ID
                LEFT JOIN Payroll_Employee ProgMan ON p.ProgrammeManagerID = ProgMan.Employee_ID
                LEFT JOIN Const_ProjectImplementingAgent ImpAgent ON p.ProjectImplementAgentID = ImpAgent.ProjectImplementAgent_ID
                LEFT JOIN Plan_ProjectBusinessPlan BusPlan ON p.Project_ID = BusPlan.ProjectID
                LEFT JOIN Payroll_Employee QualChecker ON BusPlan.QualityCheckerID = QualChecker.Employee_ID
                LEFT JOIN ( SELECT  ISNULL(SUM(YearFundAmount), 0) AS TotalFunds ,
                                    ProjectID
                            FROM    [dbo].[Plan_ProjectFund] fund
                                    LEFT JOIN [dbo].[Plan_ProjectFundYear] fundyear ON fund.ProjectFund_ID = fundyear.ProjectFundID
                            GROUP BY ProjectID
                          ) AS FundValue ON p.Project_ID = FundValue.ProjectID
                LEFT JOIN ( SELECT  SUM(ISNULL([UnitQuantity], 0)
                                     ) AS QuantityandPrice ,
                                    SUM(ISNULL([UnitPrice], 0)) AS Price ,
                                    ProjectID
                            FROM    [dbo].[Plan_ProjectItem] Item
                                    LEFT JOIN [dbo].[Plan_ProjectItemMonth] ItemMonth ON Item.PlanProjectItem_ID = ItemMonth.PlanProjectItemID
                            GROUP BY ProjectID
                          ) AS ProjItemValues ON p.Project_ID = ProjItemValues.ProjectID
                LEFT JOIN Const_ProjectCategory pc ON p.[ProjectCategoryID] = pc.ProjectCategory_ID
        WHERE   Project_ID = @ProjectID;


    END;



GO

