-- =============================================
-- Author:		Maulik Peshavariya
-- Create date: 04/13/2016
-- Description:	Get Project line item data by Projectid
-- Usage: exec Plan_ProjectItembyProjectID_sp 57
-- =============================================
create PROCEDURE [dbo].[Plan_ProjectItembyProjectID_sp]
	-- Add the parameters for the stored procedure here
	@ProjectID INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	SELECT PlanProjectItem_ID,SCOAItemID, SCOAFunctionId, SCOAFundId, SCOARegionId,
	CSS.ScoaCode , CSS.ScoaDesc, CSS.ScoaShortDesc,
	CSFS.ScoaCode FunctionCode, CSFS.ScoaDesc FunctionDesc, CSFS.ScoaShortDesc FunctionShortDesc,
	CSF.ScoaCode FundCode, CSF.ScoaDesc FundDesc, CSF.ScoaShortDesc FundShortDesc,
	CSRS.ScoaCode RegionalCode, CSRS.ScoaDesc RegionalDesc, CSRS.ScoaShortDesc RegionalShortDesc
	FROM dbo.Plan_ProjectItem ppi
	INNER JOIN dbo.Const_SCOA_Structure CSS ON CSS.ScoaID = ppi.SCOAItemID
	INNER JOIN dbo.Const_SCOA_Function_Structure CSFS ON CSFS.ScoaID = PPI.SCOAFunctionId
	INNER JOIN dbo.Const_SCOA_Funds_Structure CSF ON CSF.ScoaID = PPI.SCOAFundId
	INNER JOIN dbo.Const_SCOA_Regional_Structure CSRS ON CSRS.ScoaID = PPI.SCOARegionId
	WHERE SCOAItemID IS NOT NULL AND SCOAFunctionId IS NOT NULL AND SCOAFundId IS NOT NULL AND SCOARegionId IS NOT NULL
	AND ppi.ProjectID = @ProjectID
END
GO

