-- =============================================
-- Author:		Chris Moodley
-- Create date: September 2024
-- Description:	Validate PPI as per NT Validation Rules
-- Plan_ProjectItemNTValidation_sp '2024/2025', 8, 841, 1, 1, 1, 1
-- Plan_ProjectItemNTValidation_sp '2024/2025', 111, 44004, 300, 922, 20, 3976
-- Plan_ProjectItemNTValidation_sp '2024/2025', 111, 8192, 300, 922, 20, 3976
-- Plan_ProjectItemNTValidation_sp '2024/2025', 111, 41255, 300, 922, 20, 3976
-- Plan_ProjectItemNTValidation_sp '2024/2025', 111, 25281, 300, 922, 20, 3976
-- 20241018 by CM : 115265 - Fix budget validation rules 5, 6
-- 20241028 by CM:  115265 - Fix validation rule 1 - Add the following item.ScoaCode NOT LIKE 'IL001006023%' AND item.ScoaCode NOT LIKE 'IL001006024%' 
-- 20241106 by CM:  117294 - Update validation rule 5 as per string validations
-- =============================================
CREATE PROCEDURE [dbo].[Plan_ProjectItemNTValidation_sp]
	-- Add the parameters for the stored procedure here
	@finYear NVARCHAR(10),
	@scoaProjectID INT,
	@scoaItemID INT,
	@scoaFunctionID INT,
	@scoaRegionID INT,
	@scoaCostingID INT,
	@scoaFundID INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	CREATE TABLE #BudgetValidationRule (RowID INT IDENTITY(1,1) NOT NULL, BudgetValidationRuleID INT, BudgetValidationRuleDesc NVARCHAR(500), BudgetValidationRuleApplicableOverallBudget BIT)

	INSERT INTO #BudgetValidationRule
	SELECT BudgetValidationRule_ID, BudgetValidationRuleDesc, BudgetValidationRuleApplicableOverallBudget FROM Const_BudgetValidationRule_Sys WHERE BudgetValidationRuleEnabled = 1 AND BudgetValidationRuleApplicableOverallBudget = 0

	DECLARE @counter INT = 1
	DECLARE @budgetValidationRuleDesc NVARCHAR(500)
	DECLARE @budgetValidationRuleID INT
	DECLARE @validationError NVARCHAR(MAX) = ''
	DECLARE @scoaItemCode NVARCHAR(50), @scoaProjectCode NVARCHAR(50), @scoaFunctionCode NVARCHAR(50), @scoaCostingCode NVARCHAR(50), @scoaFundCode NVARCHAR(50), @scoaRegionCode NVARCHAR(50)
	DECLARE @scoaItemDesc NVARCHAR(500), @scoaProjectDesc NVARCHAR(500), @scoaFunctionDesc NVARCHAR(500)
	DECLARE @scoaItemShortDesc NVARCHAR(150)

	SELECT @scoaItemCode = ScoaCode, @scoaItemDesc = ScoaDesc, @scoaItemShortDesc = ScoaShortDesc FROM Const_SCOA_Structure_Consolidated WHERE ScoaID = @scoaItemID AND FinYearText = @finYear
	SELECT @scoaProjectCode = ScoaCode, @scoaProjectDesc = ScoaDesc FROM Const_SCOA_Project_Structure_Consolidated WHERE ScoaID = @scoaProjectID AND FinYearText = @finYear
	SELECT @scoaFunctionCode = ScoaCode FROM Const_SCOA_Function_Structure_Consolidated WHERE ScoaID = @scoaFunctionID AND FinYearText = @finYear
	SELECT @scoaCostingCode = ScoaCode FROM Const_SCOA_Costing_Structure_Consolidated WHERE ScoaID = @scoaCostingID AND FinYearText = @finYear
	SELECT @scoaFundCode = ScoaCode FROM Const_SCOA_Funds_Structure_Consolidated WHERE ScoaID = @scoaFundID AND FinYearText = @finYear
	SELECT @scoaRegionCode = ScoaCode FROM Const_SCOA_Regional_Structure_Consolidated WHERE ScoaID = @scoaRegionID AND FinYearText = @finYear

	WHILE (@Counter <= (SELECT MAX(RowID) FROM #BudgetValidationRule))
	BEGIN
	
		SELECT @BudgetValidationRuleDesc = BudgetValidationRuleDesc, @budgetValidationRuleID = BudgetValidationRuleID FROM #BudgetValidationRule WHERE RowID = @Counter

		IF (@budgetValidationRuleID = 1)
			IF ((@scoaItemCode NOT LIKE 'IA%' AND @scoaItemCode NOT LIKE 'IL001006011%' AND @scoaItemCode NOT LIKE 'IL001006023%' AND @scoaItemCode NOT LIKE 'IL001006024%' AND @scoaItemCode NOT LIKE 'IL001006006%') AND @scoaProjectDesc LIKE 'Capital%')
				SET @validationError += @BudgetValidationRuleDesc + '|'

		IF (@BudgetValidationRuleID = 2)
			IF (@scoaProjectDesc LIKE 'Operational%' AND ((@scoaItemCode LIKE 'IA002%' AND @scoaItemCode LIKE '%additions%') OR (@scoaItemCode LIKE 'IA002%' AND @scoaItemDesc LIKE '%acquisitions')))
				SET @validationError += @BudgetValidationRuleDesc + '|'

		IF (@BudgetValidationRuleID = 3)
			IF (@scoaProjectCode LIKE 'PO003057%' OR @scoaProjectCode LIKE 'PO003058%' OR @scoaProjectCode LIKE 'PO003059%')
			AND (@scoaItemCode NOT LIKE 'IR%' AND @scoaItemCode NOT LIKE 'IA001010%' AND @scoaItemCode NOT LIKE 'IA001004%')
				SET @validationError += @BudgetValidationRuleDesc + '|'

		IF (@BudgetValidationRuleID = 4)
			IF (@scoaItemDesc NOT LIKE '%Cost of Free Basic Services%' AND  @scoaItemDesc NOT LIKE '%Revenue Cost of Free Services%'
			AND @scoaProjectDesc NOT LIKE '%property rates rebate%' AND @scoaProjectCode LIKE 'PO%' AND @scoaItemDesc LIKE 'Revenue%') 
				SET @validationError += @BudgetValidationRuleDesc + '|'

		IF (@BudgetValidationRuleID = 5)
		BEGIN			
			IF ((@scoaItemDesc LIKE 'Expenditure%' OR @scoaItemDesc LIKE 'Assets%') AND @scoaProjectDesc LIKE 'Default%')
				IF  (@scoaItemDesc NOT LIKE 'Expenditure:Default%' AND @scoaItemDesc NOT LIKE 'Assets:current Assets%' AND @scoaItemDesc NOT LIKE 'Assets:Non-current Assets%' AND @scoaItemDesc NOT LIKE '%Accumulated%' AND @scoaItemDesc NOT LIKE '%Opening Balance')
					SET @validationError += @BudgetValidationRuleDesc + '|'

			IF (@scoaItemDesc LIKE 'Assets:Non-current Assets%' AND @scoaItemDesc LIKE '%acquisitions%' AND @scoaItemDesc NOT LIKE '%Work-in-progress%') AND @scoaProjectDesc LIKE 'Default%'
				SET @validationError += @BudgetValidationRuleDesc + '|'
		END

		IF (@BudgetValidationRuleID = 6)
			IF (@scoaItemCode LIKE 'IE008%' AND @scoaFunctionCode NOT LIKE 'FX004%')
					SET @validationError += @BudgetValidationRuleDesc + '|'

		IF (@BudgetValidationRuleID = 7)
			IF (@scoaItemCode LIKE 'IE002001%' AND @scoaFunctionCode NOT LIKE 'FX002001001%' AND @scoaFunctionCode NOT LIKE 'FX002002001%')
				SET @validationError += @BudgetValidationRuleDesc + '|'

		IF (@BudgetValidationRuleID = 8)
			IF (@scoaItemCode like 'IE002002%' AND @scoaFunctionCode NOT LIKE 'FX016001002%' AND @scoaFunctionCode NOT LIKE 'FX016002002%')
				SET @validationError += @BudgetValidationRuleDesc + '|'

		IF (@BudgetValidationRuleID = 9)
			IF (@scoaItemCode LIKE 'IE007004%' AND @scoaFunctionCode NOT LIKE 'FX016001002%' AND @scoaFunctionCode NOT LIKE 'FX016002002%')
				SET @validationError += @BudgetValidationRuleDesc + '|'

		IF (@BudgetValidationRuleID = 10)
			IF ((@scoaItemShortDesc = 'Opening Balance') AND (@scoaItemCode LIKE 'IL%' OR @scoaItemCode LIKE 'IA%' OR @scoaItemCode LIKE 'LN%')) AND (@scoaProjectCode NOT LIKE 'PD%')
				SET @validationError += @BudgetValidationRuleDesc + '|'

		IF (@BudgetValidationRuleID = 11)
			IF ((@scoaItemShortDesc = 'Opening Balance') AND (@scoaItemCode LIKE 'IL%' OR @scoaItemCode LIKE 'IA%' OR @scoaItemCode LIKE 'LN%')) AND (@scoaCostingCode NOT LIKE 'CO003%')
				SET @validationError += @BudgetValidationRuleDesc + '|'

		IF (@BudgetValidationRuleID = 12)
			IF ((@scoaItemShortDesc = 'Opening Balance') AND (@scoaItemCode LIKE 'IL%' OR @scoaItemCode LIKE 'IA%' OR @scoaItemCode LIKE 'LN%')) AND (@scoaFundCode NOT LIKE 'FD003%')
				SET @validationError += @BudgetValidationRuleDesc + '|'

		IF (@BudgetValidationRuleID = 13)
			IF (@scoaItemCode LIKE 'IA001009005%' AND @scoaFunctionCode NOT LIKE 'FX016%')
				SET @validationError += @BudgetValidationRuleDesc + '|'

		IF (@BudgetValidationRuleID = 14)
			IF (@scoaCostingCode LIKE 'CO001%' OR @scoaCostingCode LIKE 'CO002%') AND @scoaItemCode NOT LIKE 'IE018%'
				SET @validationError += @BudgetValidationRuleDesc + '|'

		IF (@BudgetValidationRuleID = 15)
			IF @scoaRegionCode LIKE 'RX001%'
				SET @validationError += @BudgetValidationRuleDesc + '|'

		IF (@BudgetValidationRuleID = 16)
			IF @scoaItemCode LIKE 'IE018%' AND @scoaCostingCode LIKE 'CO003%'
				SET @validationError += @BudgetValidationRuleDesc + '|'
			
		IF (@BudgetValidationRuleID = 17)
			IF @scoaItemCode LIKE 'IR004%' AND @scoaCostingCode LIKE 'CO003%'
				SET @validationError += @BudgetValidationRuleDesc + '|'

		IF (@BudgetValidationRuleID = 19)
			IF @scoaItemCode LIKE 'IR%' AND @scoaFundCode LIKE 'FD003%'
				SET @validationError += @BudgetValidationRuleDesc + '|'

		SET @Counter = @Counter + 1

	END

	SELECT validationError = @validationError

END
GO

