-- =============================================
-- Author:		Chris Moodley
-- Create date: September 2025
-- Description:	Return HistoricalProjectCode (Ukey) for PPIs per fin year and user
-- [dbo].[Plan_ProjectItemUkey_sp] '2025/2026', 0
-- =============================================
CREATE PROCEDURE [dbo].[Plan_ProjectItemUkey_sp] 
	-- Add the parameters for the stored procedure here
	@finYear NVARCHAR(9) = '2025/2026',
	@userID INT = 0
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	SELECT DISTINCT
		PlanProjectItem_ID,
		ppi.ProjectID,
		ProjectCode,
		ISNULL(ppi.HistoricalProjectCode, '') Ukey,
		ppi.DivisionID
	FROM
		Plan_ProjectItem ppi
		INNER JOIN Plan_Project pp ON ppi.ProjectID = pp.Project_ID
		LEFT  JOIN User_UserDivisions uud ON ppi.DivisionId = uud.DivisionID
	WHERE
		ppi.FinYear = @finYear AND ProjectStatus = 24 AND ISNULL(IsDeleted, 0) <> 1
		AND (CASE WHEN @UserId = 0 THEN 0 ELSE uud.UserID END = @userID)
		AND pp.CapitalOperation IN (0, 1)

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_ProjectRollover_sp]    Script Date: 2026/03/10 7:23:46 AM ******/
SET ANSI_NULLS ON
GO

