/****** Object:  StoredProcedure [dbo].[Plan_ProjectRpt_sp]    Script Date: 2026/03/10 7:23:46 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================  
-- Author: Carol Brooking  
-- Create date: 13/02/2015  
-- Description: Project Report - Over view of reports.  
-- calls : Plan_ProjectRpt_sp '','',0,0,0,0,3,'2016/2017'  
-- 05/04/2016 By JP: Removed ProjectManagerId, CostEstimate, EstimatedEndDate, EstimatedStartDate, ProjectManager, SupplyChainOfficial, TotalProjItemQuantityandPrice, TotalProjItemPrice, SearhProjManager  
-- 05/04/2016 By JP: Add BudgetAmount  
-- 05/04/2016 By JP: Get Department and Division Description using function  
-- 24/11/2016 By SNagpal: Add Parameter for Fin Year.  
-- 29/03/2017 SNagpal: As IDPItemID and ItemId no more exists in Plan_Project Table. So apply functiona Plan_ProjectIDP_fxn to get IDPItemDesc  
-- 13/03/2019 CPatel: #84459 -- to All in report Changes
-- =============================================  
CREATE PROCEDURE [dbo].[Plan_ProjectRpt_sp]  
    @ProjCode NVARCHAR(50) ,  
    @ProjName NVARCHAR(50) ,  
    @StatusID INT ,  
    @IDPItemID INT ,  
    @ProjectTypeID INT ,  
    @ProjectCategoryID INT ,  
    @ProjectID INT,  
 @FinancialYear NVARCHAR(9)   
AS  
    BEGIN  
  
        DECLARE @Status NVARCHAR(50) ,  
            @IDPItem NVARCHAR(200) ,  
            @ProjectType NVARCHAR(50) ,  
            @ProjectCategory NVARCHAR(50) ,  
            @Project NVARCHAR(50);  
  
        IF ( @StatusID = 0 )  
            SELECT  @Status = 'All';  
        ELSE  
            SELECT  @Status = StatusDesc  
            FROM    Const_Status  
            WHERE   Status_ID = @StatusID;  
  
        IF ( @IDPItemID = 0 )  
            SELECT  @IDPItem = 'All';  
        ELSE  
            SELECT  @IDPItem = [ItemDesc]  
            FROM    IDP_Item  
            WHERE   Item_ID = @IDPItemID;  
  
        IF ( @ProjectTypeID = 0 )  
            SELECT  @ProjectType = 'All';  
        ELSE  
            SELECT  @ProjectType = [ProjectTypeDescrip]  
            FROM    Const_ProjectType  
            WHERE   ProjectType_ID = @ProjectTypeID;  
  
        IF ( @ProjectCategoryID = 0 )  
            SELECT  @ProjectCategory = 'All';  
        ELSE  
            SELECT  @ProjectCategory = ProjectCategoryDescrip  
            FROM    Const_ProjectCategory  
            WHERE   ProjectCategory_ID = @ProjectCategoryID;  
  
        IF ( @ProjectID = 0 )  
            SELECT  @Project = 'All';  
        ELSE  
            SELECT  @Project = StatusDesc  
            FROM    Const_Status  
            WHERE   Status_ID = @ProjectID;  
  
        SELECT  p.Project_ID ,  
               0 as IDPItemID ,  
                ISNULL(dbo.Plan_ProjectIDP_fxn(p.Project_ID, @IDPItemID),'') AS IDPItemDesc, --i.ItemDesc AS IDPItemDesc ,  
               CAST(0 AS BIT) as IsNonIDP ,  
                p.ScoaProjectID ,  
                sp.ScoaCode AS ProjectCode ,  
                p.ProjectName ,  
                p.ProjectStatus ,  
                cs.StatusDesc ,  
                p.ProjectDetailDesc ,  
                REPLACE(REPLACE(REPLACE(p.ProjectDesc, CHAR(10), ' '),  
                                CHAR(13), ' '), CHAR(09), ' ') AS ProjectDesc ,  
                p.ProjectTypeID ,  
                pt.[ProjectTypeDescrip] ,  
                dbo.Plan_ProjectDepartment_fxn(p.Project_ID, 1) DepartmentDesc ,  
                dbo.Plan_ProjectDivision_fxn(p.Project_ID, 1) DivisionDesc ,  
                TotalFunds ,  
                ProjItemValues.BudgetAmount ,  
                ProjectCategory_ID ,  
                ProjectCategoryDescrip ,  
                @ProjCode AS SearchProjCode ,  
                @ProjName AS SearchProjName ,  
                @Status AS SearchStatus ,  
                @IDPItem AS SearchIDP ,  
                @ProjectType AS SearchProjType ,  
                @ProjectCategory AS SearchProjCatg ,  
                @Project AS SearchProject  
        FROM    Plan_Project p  
                INNER JOIN Const_SCOA_Project_Structure sp ON p.ScoaProjectID = sp.ScoaID  
                INNER JOIN Const_Status cs ON p.ProjectStatus = cs.Status_ID  
                --LEFT JOIN IDP_Item i ON p.IDPItemID = i.Item_ID  
    LEFT JOIN Const_ProjectType pt ON p.ProjectTypeID = pt.ProjectType_ID  
                LEFT JOIN Payroll_Employee ep ON p.ProjectManagerID = ep.Employee_ID  
                LEFT JOIN Payroll_Employee es ON p.SupplyChainOfficialID = es.Employee_ID  
              LEFT JOIN ( SELECT  ISNULL(SUM(YearFundAmount), 0) AS TotalFunds ,  
                                  ProjectID  
                            FROM    [dbo].[Plan_ProjectFund] fund  
                                    LEFT JOIN [dbo].[Plan_ProjectFundYear] fundyear ON fund.ProjectFund_ID = fundyear.ProjectFundID  
                            GROUP BY ProjectID  
                          ) AS FundValue ON p.Project_ID = FundValue.ProjectID  
                LEFT JOIN ( SELECT  ISNULL(SUM(Item.BudgetAmount), 0) AS BudgetAmount ,  
                                    Item.ProjectID  
                            FROM    [dbo].[Plan_ProjectItem] Item  
                            GROUP BY ProjectID  
                          ) AS ProjItemValues ON p.Project_ID = ProjItemValues.ProjectID  
                LEFT JOIN Const_ProjectCategory pc ON p.[ProjectCategoryID] = pc.ProjectCategory_ID  
        WHERE   ( ( Project_ID = @ProjectID )  
                  OR ( @ProjectID = 0 )  
                )  
     AND ( ( p.FinYear = @FinancialYear )  
                  OR ( @FinancialYear = '0' )  
                )  
  
                AND ( CASE WHEN @IDPItemID > 0 THEN ISNULL(dbo.Plan_ProjectIDP_fxn(p.Project_ID, @IDPItemID),'') ELSE 'IDP' END != '')  
                AND ( ( p.ProjectStatus = @StatusID )  
                      OR ( @StatusID = 0 )  
                    )  
                AND ( ( ProjectTypeID = @ProjectTypeID )  
                      OR ( @ProjectTypeID = 0 )  
                    )  
                AND ( ( ProjectCategoryID = @ProjectCategoryID )  
                      OR ( @ProjectCategoryID = 0 )  
                    )  
                AND ( p.ProjectName LIKE '%' + @ProjName + '%' )  
                AND ( ScoaCode LIKE '%' + @ProjCode + '%' )  
        UNION  
   --Add in the search parameters  
        SELECT  -1 AS Project_ID ,  
                NULL --p.IDPItemID  
                ,  
                NULL --i.ItemDesc as IDPItemDesc  
                ,  
                NULL --p.IsNonIDP   
                ,  
                NULL --p.ScoaProjectID  
                ,  
                NULL --sp.ScoaCode as ProjectCode  
                ,  
                NULL --p.ProjectName  
                ,  
                NULL --p.ProjectStatus  
                ,  
                NULL --cs.StatusDesc   
                ,  
                NULL --p.ProjectDetailDesc  
                ,  
                NULL --p.ProjectDesc  
                ,  
                NULL --p.ProjectTypeID  
                ,  
                NULL --pt.[ProjectTypeDescrip]  
                ,  
                NULL --dept.DepartmentDesc  
                ,  
                NULL --div.DivisionDesc  
                ,  
                NULL --TotalFunds  
                ,  
                NULL --ProjItemValues.BudgetAmount  
                ,  
                NULL --ProjectCategory_ID  
                ,  
                NULL --ProjectCategoryDescrip  
                ,  
                CASE WHEN @ProjCode = '' THEN 'All'  
                     ELSE @ProjCode  
                END AS SearchProjCode ,  
                CASE WHEN @ProjName = '' THEN 'All'  
                     ELSE @ProjName  
                END AS SearchProjName ,  
                @Status AS SearchStatus ,  
                @IDPItem AS SearchIDP ,  
                @ProjectType AS SearchProjType ,  
                @ProjectCategory AS SearchProjCatg ,  
                @Project AS SearchProject  
        ORDER BY Project_ID;            
    END;  
GO

/****** Object:  StoredProcedure [dbo].[Plan_ProjectsBehindSchedule_sp]    Script Date: 2026/03/10 7:23:46 AM ******/
SET ANSI_NULLS ON
