--[dbo].[Plan_ProjectsBehindSchedule_sp] @FinYear = '2014/2015',@DepartmentID = 0,@ProjectTypeID = 0,@ProjectManagerID = 0,@WeeksBehind = 0,@PercentBehind = 0,@AsAtDate = '2015/10/15'
-- 2016-02-29 TP31230 Varun:Job Grading Merging into Job Profiling.
-- 2016-04-05 SN: Remove ProjectManagerID, DepartmenID and related stuff
-- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions


CREATE PROCEDURE [dbo].[Plan_ProjectsBehindSchedule_sp]
	@FinYear VARCHAR(9) = '2014/2015',
	@ProjectTypeID INT = 0,
	@WeeksBehind INT = 0,
	@PercentBehind DECIMAL(19,1) = 0,
	@AsAtDate SMALLDATETIME = '2015/10/15'
AS

	SELECT	ProjectID
	      , ProjectName
		  , ProjectDesc
		  , [WeeksBehind]
		  , [PlannedExpenditure]
		  , [CommittedExpenditure]
		  , [PercentageBehind]
	FROM
	(SELECT	a.Project_ID AS ProjectID
		  , a.ProjectName
		  , a.ProjectDesc
		  , CAST((CAST([dbo].[Plan_ProjectDaysBehind_fn](a.Project_ID, @AsAtDate) AS FLOAT)/7) AS DECIMAL(19, 1)) AS [WeeksBehind]
		  , CAST(Planned AS DECIMAL(19,2)) AS [PlannedExpenditure]
		  , CAST(Actual AS DECIMAL(19,2)) AS [CommittedExpenditure]
		  , CAST(((CASE WHEN ISNULL(Planned, 0) = 0 
						THEN 0.0000001 
						ELSE ISNULL(Planned, 0) 
					END -ISNULL(Actual, 0) / CASE WHEN ISNULL(Planned, 0) = 0 
												THEN 100000 
												ELSE ISNULL(Planned, 0) 
											END) * 100) AS DECIMAL(19,2)) AS [PercentageBehind]
		  , a.ProjectTypeID		  					 
		FROM 	[dbo].[Plan_Project] a INNER JOIN
			(SELECT a.ProjectID, SUM(Planned) AS Planned, SUM(ISNULL(Actual,0)) AS Actual
			FROM
				(SELECT	ProjectID,Planned =
					CASE 
						WHEN (ISNULL([RevDirect],0) + ISNULL([RevIndirect],0)) = 0 THEN (ISNULL([PlanDirect],0) + ISNULL([PlanIndirect],0))
						ELSE (ISNULL([PlanDirect],0) + ISNULL([PlanIndirect],0))
					END
				FROM 	[dbo].[Plan_Project_CashFlow]
				WHERE 	[PeriodEnd] < @AsAtDate) a FULL JOIN
				
				(SELECT p.[Project_ID], ISNULL(cv.VoteVATClaimable,0) - isNull(cv.VoteAmount, 0) + ISNULL(cv.VoteVATAmount,0) As Actual
					FROM [dbo].[Plan_Project] p
					INNER JOIN [dbo].[SCM_ProcurementPlanNew] pp ON pp.[PlanProjectID] = p.[Project_ID]
					INNER JOIN [dbo].[SCM_Requisition] r ON r.[ProcurementID] = pp.[ProcurementPlan_ID]
					LEFT JOIN [dbo].[SCM_QuotationRequistion] qr ON qr.[RequisitionID] = r.[Requisition_ID] --[QuotationID]
					LEFT JOIN [dbo].[SCM_ServiceInvoice] si ON si.[RequisitionID] = r.[Requisition_ID]--[ServiceInvoice_ID]
					LEFT JOIN [dbo].[SCM_Tender] t ON t.[RequisitionID] = r.[Requisition_ID] --[Tender_ID]
					INNER JOIN [dbo].[SCM_Order] o ON (o.[QuotationId] = qr.QuotationID OR o.[TenderId] = t.Tender_ID) --AND o.[RequisitionId] = r.Requisition_ID
					INNER JOIN [dbo].[SCM_Invoice] i ON i.[OrderID] = o.[Order_ID] --OR i.[ServiceInvoiceID] = si.[ServiceInvoice_ID]
					INNER JOIN [dbo].[SCM_CashbookVote] cv ON cv.[InvoiceID] = i.[Invoice_ID]
					INNER JOIN [dbo].[SCM_Cashbook] c ON c.[SCMTransaction_ID] = [SCMTransactionID]) b ON b.[Project_ID] = a.ProjectID
				GROUP BY a.ProjectID) c ON a.[Project_ID] = c.ProjectID LEFT JOIN
			(SELECT emp.Employee_ID,
					Surname + ' ' + FirstName + ' (' + JobTitle + ')' AS EmpJobProfile
			FROM Payroll_Employee emp
			INNER JOIN Payroll_Position pp ON emp.PositionID  = pp.Position_ID
			INNER JOIN Payroll_JobProfile jProfile ON pp.JobProfileID  = jProfile.JobProfile_ID
			) pm ON a.ProjectManagerID = pm.Employee_ID
	) a 

	WHERE	ISNULL(WeeksBehind, 0) >= CASE WHEN ISNULL(@Weeksbehind, 0) = 0 THEN ISNULL(WeeksBehind, 0) ELSE @Weeksbehind END
	AND		ISNULL(PercentageBehind, 0) >= CASE WHEN ISNULL(@PercentBehind, 0) = 0 THEN ISNULL(PercentageBehind, 0) ELSE @PercentBehind END
	AND		ISNULL(ProjectTypeID, 0) = CASE WHEN ISNULL(@ProjectTypeID, 0) = 0 THEN ISNULL(ProjectTypeID, 0) ELSE @ProjectTypeID END
	AND		ProjectID IN (SELECT [ProjectID] 
						  FROM [dbo].[Plan_ProjectFundYear] pfy 
						  INNER JOIN [dbo].[Plan_ProjectFund] pf ON pfy.[ProjectFundID] = pf.[ProjectFund_ID] 
						  WHERE pfy.FinYear = @FinYear OR ISNULL(@FinYear, '') = '')


GO

/****** Object:  StoredProcedure [dbo].[Plan_RecalcBudgetRegister_sp]    Script Date: 2026/03/10 7:23:46 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Richa Mills
-- Create date: 2019/02/19
-- Description:	Budget Register Report
-- CALL : Plan_RecalcBudgetRegister_sp
-- Modified: 2019/04/29 - Fix GRN Created Date
-- NP - 22 Aug 2019 - Budget Consumption Recalculated
-- Modified: 09 Oct 2019 - Jean Snyman - #92929 Nquthu Available Budget
--			 > Now also deleting duplicate opening balances
-- 17 Oct 2019 - #95444 Chief Albert Luthuli - Budget Consumption- Overspending
-- Fixed Sundry Invoice Status Checks
-- 07 Nov 2019 - J Snyman - 24479 - Project Available Budget Calculation Error
-- 30 May 2020 : Savvin M. : #25114 Changed order isVoid column
-- =============================================
CREATE PROCEDURE [dbo].[Plan_RecalcBudgetRegister_sp]
AS
BEGIN
    IF NOT EXISTS
    (
        SELECT TABLE_CATALOG
        FROM INFORMATION_SCHEMA.TABLES
        WHERE TABLE_NAME = N'Plan_BudgetRegisterBackup'
    )
    BEGIN
        CREATE TABLE [dbo].[Plan_BudgetRegisterBackup]
        (
            [BudgetRegister_ID] [BIGINT] IDENTITY(1, 1) NOT NULL,
            [PlanProjectItemID] [INT] NULL,
            [BudgetTransactionTypeID] [INT] NULL,
            [ModuleID] [INT] NULL,
            [PK_TransactionID] [INT] NULL,
            [TransactionTableName] [NVARCHAR](100) NULL,
            [TransactionAmount] [DECIMAL](18, 2) NULL,
            [AvailableBudget] [DECIMAL](18, 2) NULL,
            [CapturerID] [INT] NOT NULL,
            [DateCaptured] [DATETIME] NOT NULL,
            [ModifierID] [INT] NULL,
            [DateModified] [DATETIME] NULL,
            [FinYear] [NVARCHAR](9) NULL,
            CONSTRAINT [PK_Plan_BudgetRegisterBackup]
                PRIMARY KEY CLUSTERED ([BudgetRegister_ID] ASC)
                WITH (PAD_INDEX = OFF, STATISTICS_NORECOMPUTE = OFF, IGNORE_DUP_KEY = OFF, ALLOW_ROW_LOCKS = ON,
                      ALLOW_PAGE_LOCKS = ON
                     ) ON [PRIMARY]
        ) ON [PRIMARY];


        --Make a backup of the current Plan_BudgetRegister
        INSERT INTO dbo.Plan_BudgetRegisterBackup
        (
            PlanProjectItemID,
            BudgetTransactionTypeID,
            ModuleID,
            PK_TransactionID,
            TransactionTableName,
            TransactionAmount,
            AvailableBudget,
            CapturerID,
            DateCaptured,
            ModifierID,
            DateModified,
            FinYear
        )
        SELECT PlanProjectItemID,
               BudgetTransactionTypeID,
               ModuleID,
               PK_TransactionID,
               TransactionTableName,
               TransactionAmount,
               AvailableBudget,
               CapturerID,
               DateCaptured,
               ModifierID,
               DateModified,
               FinYear
        FROM dbo.Plan_BudgetRegister;

        --Delete all SCM Transactions from Pan_BudgetRegister
        DELETE FROM dbo.Plan_BudgetRegister
        WHERE TransactionTableName LIKE 'SCM_%';
		
		-- 24479 - Project Available Budget Calculation Error
		-- Fix any broken Planning entries in the Budget Register table where the transaction amount is 0 but there is a budget
		UPDATE	PBR
		SET		PBR.AvailableBudget = PPI.BudgetAmount,
				PBR.TransactionAmount = PPI.BudgetAmount
		FROM	Plan_ProjectItem PPI
		JOIN	Plan_BudgetRegister PBR
		ON		PPI.PlanProjectItem_ID = PBR.PlanProjectItemID
		AND		PPI.FinYear = PBR.FinYear
		WHERE	PBR.TransactionTableName = 'Plan_ProjectItem'
		AND		ISNULL(PBR.AvailableBudget, 0) = 0 
		AND		ISNULL(PPI.BudgetAmount, 0) <> 0

		-- #92929 Nquthu Available Budget  
        SELECT PlanProjectItemID,
               TransactionAmount,
               FinYear,
               COUNT(1) Total,
               MIN(DateCaptured) EarliestDate,
               MAX(DateCaptured) LatestDate,
               DATEDIFF(MINUTE, MIN(DateCaptured), MAX(DateCaptured)) DateDiffInMinutes
        INTO #AllDuplicatedBudgets
        FROM dbo.Plan_BudgetRegister
        WHERE TransactionAmount <> 0
              AND TransactionTableName = 'Plan_ProjectItem'
        GROUP BY PlanProjectItemID,
                 TransactionAmount,
                 FinYear
        HAVING COUNT(1) > 1;

        DELETE BR
        FROM #AllDuplicatedBudgets AllDups
            JOIN dbo.Plan_BudgetRegister BR
                ON AllDups.PlanProjectItemID = BR.PlanProjectItemID
                   AND AllDups.FinYear = BR.FinYear
                   AND AllDups.TransactionAmount = BR.TransactionAmount
        WHERE BR.TransactionTableName = 'Plan_ProjectItem'
              AND BR.DateCaptured <> AllDups.EarliestDate;

        DROP TABLE #AllDuplicatedBudgets;

        --Set the AvailableBudget = 0
        UPDATE dbo.Plan_BudgetRegister
        SET AvailableBudget = 0;
    END;
    ELSE
    BEGIN
        --Delet all SCM Transactions from Pan_BudgetRegister
        DELETE FROM dbo.Plan_BudgetRegister
        WHERE TransactionTableName LIKE 'SCM_%';
		
		-- #92929 Nquthu Available Budget  
        SELECT PlanProjectItemID,
               TransactionAmount,
               FinYear,
               COUNT(1) Total,
               MIN(DateCaptured) EarliestDate,
               MAX(DateCaptured) LatestDate,
               DATEDIFF(MINUTE, MIN(DateCaptured), MAX(DateCaptured)) DateDiffInMinutes
        INTO #AllDuplicatedBudgets2
        FROM dbo.Plan_BudgetRegister
        WHERE TransactionAmount <> 0
              AND TransactionTableName = 'Plan_ProjectItem'
        GROUP BY PlanProjectItemID,
                 TransactionAmount,
                 FinYear
        HAVING COUNT(1) > 1;

        DELETE BR
        FROM #AllDuplicatedBudgets2 AllDups
            JOIN dbo.Plan_BudgetRegister BR
                ON AllDups.PlanProjectItemID = BR.PlanProjectItemID
                   AND AllDups.FinYear = BR.FinYear
                   AND AllDups.TransactionAmount = BR.TransactionAmount
        WHERE BR.TransactionTableName = 'Plan_ProjectItem'
              AND BR.DateCaptured <> AllDups.EarliestDate;

        DROP TABLE #AllDuplicatedBudgets2;

        --Set the AvailableBudget = 0
        UPDATE dbo.Plan_BudgetRegister
        SET AvailableBudget = 0;
    END;

    DECLARE @NotApprovedInvStatus INT =
            (
                SELECT Status_ID
                FROM Const_SCMVendorStatus_sys
                WHERE Module IN ( 'SCMInvoice', 'Invoice' )
                      AND Status = 'Not Appoved'
            );

    --Rebuild SCM BudgetRegister
    INSERT INTO dbo.Plan_BudgetRegister
    SELECT *
    FROM
    (
        --Requisition
        SELECT RSD.PlanProjectItemId AS PlanProjectItemID,
               2 AS BudgetTransactionTypeID,
               9 AS ModuleID,
               RSD.RequisitionDetail_ID AS PK_TransactionID,
               'SCM_RequisitionServiceDetails' AS TransactionTableName,
               (RSD.EstimatedCost * RSD.Quantity) * -1 AS TransactionAmount,
               0 AS AvailableBudget,
               R.CapturerID,
               RSD.DateCaptured,
               NULL AS ModifierID,
               NULL AS DateModified,
               R.FinancialYear AS FinYear
        FROM dbo.SCM_RequisitionServiceDetails RSD
            JOIN dbo.SCM_Requisition R
                ON R.Requisition_ID = RSD.RequisitionID
        WHERE ISNULL(RSD.CancellationReasonCode, 0) != 'Void'
              AND R.HODApproval != 0
              AND R.SupervisorApproval != 0
        --AND RSD.PlanProjectItemId = @ProjectItemID
        UNION ALL

        --Quotation less than Requisition
        SELECT Q.PlanProjectItemID,
               2,
               9,
               Q.QuotationServiceDel_ID,
               'SCM_QuotationServiceDetail',
               (Q.RequisitionAmount - Q.QuotationAmount) amount,
               0,
               Q.CapturerID,
               Q.DateCaptured,
               NULL,
               NULL,
               Q.FinancialYear
        FROM
        (
            SELECT QSD.PlanProjectItemID,
                   QSD.QuotationServiceDel_ID,
                   CAST((RSD.EstimatedCost * RSD.Quantity) AS DECIMAL(18, 2)) AS RequisitionAmount,
                   QSVD.Cost AS QuotationAmount,
                   Q.CapturerID,
                   QSD.DateCaptured,
                   Q.FinancialYear
            FROM dbo.SCM_RequisitionServiceDetails RSD
                INNER JOIN dbo.SCM_QuotationServiceDetail QSD
                    ON QSD.RequisitionDetailID = RSD.RequisitionDetail_ID
                INNER JOIN dbo.SCM_QuotationServiceVendorDetail QSVD
                    ON QSVD.QuotationServiceDetailID = QSD.QuotationServiceDel_ID
                INNER JOIN dbo.SCM_Quotation Q
                    ON Q.Quotation_ID = QSD.QuotationID
            WHERE QSVD.Successful = 1
                  AND ISNULL(Q.Approved, 0) = 1
                  AND ISNULL(Q.Cancel, 0) = 0
        --AND QSD.PlanProjectItemID = @ProjectItemID
        ) AS Q
        WHERE Q.RequisitionAmount - Q.QuotationAmount > 0
        UNION ALL

        --Quotation more than Requisition
        SELECT Q.PlanProjectItemID,
               2,
               9,
               Q.QuotationServiceDel_ID,
               'SCM_QuotationServiceDetail',
               (Q.QuotationAmount - Q.RequisitionAmount) * -1 amount,
               0,
               Q.CapturerID,
               Q.DateCaptured,
               NULL,
               NULL,
               Q.FinancialYear
        FROM
        (
            SELECT QSD.PlanProjectItemID,
                   QSD.QuotationServiceDel_ID,
                   CAST((RSD.EstimatedCost * RSD.Quantity) AS DECIMAL(18, 2)) AS RequisitionAmount,
                   QSVD.Cost AS QuotationAmount,
                   Q.CapturerID,
                   QSD.DateCaptured,
                   Q.FinancialYear
            FROM dbo.SCM_RequisitionServiceDetails RSD
                INNER JOIN dbo.SCM_QuotationServiceDetail QSD
                    ON QSD.RequisitionDetailID = RSD.RequisitionDetail_ID
                INNER JOIN dbo.SCM_QuotationServiceVendorDetail QSVD
                    ON QSVD.QuotationServiceDetailID = QSD.QuotationServiceDel_ID
                INNER JOIN dbo.SCM_Quotation Q
                    ON Q.Quotation_ID = QSD.QuotationID
            WHERE QSVD.Successful = 1
                  AND ISNULL(Q.Approved, 0) = 1
                  AND ISNULL(Q.Cancel, 0) = 0
        --AND QSD.PlanProjectItemID = @ProjectItemID
        ) AS Q
        WHERE Q.QuotationAmount - Q.RequisitionAmount > 0
        UNION ALL

        --Informal Tender less than Requisition
        SELECT I.PlanProjectItemID,
               2,
               9,
               I.TenderServiceDel_ID,
               'SCM_InformalTenderServiceDetail',
               (I.RequisitionAmount - I.InformalTenderAmount) amount,
               0,
               I.CapturerID,
               I.DateCaptured,
               NULL,
               NULL,
               I.FinancialYear
        FROM
        (
            SELECT ITSD.PlanProjectItemID,
                   ITSD.TenderServiceDel_ID,
                   CAST((RSD.EstimatedCost * RSD.Quantity) AS DECIMAL(18, 2)) AS RequisitionAmount,
                   ITSVD.Cost AS InformalTenderAmount,
                   IT.CapturerID,
                   ITSD.DateCaptured,
                   IT.FinancialYear
            FROM dbo.SCM_RequisitionServiceDetails RSD
                INNER JOIN dbo.SCM_InformalTenderServiceDetail ITSD
                    ON ITSD.RequisitionDetailID = RSD.RequisitionDetail_ID
                INNER JOIN dbo.SCM_InformalTenderServiceVendorDetail ITSVD
                    ON ITSVD.TenderServiceDelID = ITSD.TenderServiceDel_ID
                INNER JOIN dbo.SCM_InformalTender IT
                    ON IT.InformalTender_ID = ITSD.InformalTenderID
            WHERE ITSVD.Successful = 1
                  AND ISNULL(IT.Approved, 0) = 1
                  AND ISNULL(IT.Cancel, 0) = 0
        --AND ITSD.PlanProjectItemID = @ProjectItemID
        ) AS I
        WHERE I.RequisitionAmount - I.InformalTenderAmount > 0
        UNION ALL

        --Informal Tender more than Requisition
        SELECT I.PlanProjectItemID,
               2,
               9,
               I.TenderServiceDel_ID,
               'SCM_InformalTenderServiceDetail',
               (I.InformalTenderAmount - I.RequisitionAmount) * -1 amount,
               0,
               I.CapturerID,
               I.DateCaptured,
               NULL,
               NULL,
               I.FinancialYear
        FROM
        (
            SELECT ITSD.PlanProjectItemID,
                   ITSD.TenderServiceDel_ID,
                   CAST((RSD.EstimatedCost * RSD.Quantity) AS DECIMAL(18, 2)) AS RequisitionAmount,
                   ITSVD.Cost AS InformalTenderAmount,
                   IT.CapturerID,
                   ITSD.DateCaptured,
                   IT.FinancialYear
            FROM dbo.SCM_RequisitionServiceDetails RSD
                INNER JOIN dbo.SCM_InformalTenderServiceDetail ITSD
                    ON ITSD.RequisitionDetailID = RSD.RequisitionDetail_ID
                INNER JOIN dbo.SCM_InformalTenderServiceVendorDetail ITSVD
                    ON ITSVD.TenderServiceDelID = ITSD.TenderServiceDel_ID
                INNER JOIN dbo.SCM_InformalTender IT
                    ON IT.InformalTender_ID = ITSD.InformalTenderID
            WHERE ITSVD.Successful = 1
                  AND ISNULL(IT.Approved, 0) = 1
                  AND ISNULL(IT.Cancel, 0) = 0
        --AND ITSD.PlanProjectItemID = @ProjectItemID
        ) AS I
        WHERE I.InformalTenderAmount - I.RequisitionAmount > 0
        UNION ALL

        --Tender less than Requisition
        SELECT T.PlanProjectItemId,
               2,
               9,
               T.TenderAdjudication_ID,
               'SCM_TenderAdjudication',
               (T.RequisitionAmount - T.TenderAmount) amount,
               0,
               T.CapturerID,
               T.DateCaptured,
               NULL,
               NULL,
               T.FinancialYear
        FROM
        (
            SELECT RSD.PlanProjectItemId,
                   TA.TenderAdjudication_ID,
                   CAST((RSD.EstimatedCost * RSD.Quantity) AS DECIMAL(18, 2)) AS RequisitionAmount,
                   TA.PricePoints AS TenderAmount,
                   T.CapturerID,
                   TA.DateCaptured,
                   T.FinancialYear
            FROM dbo.SCM_RequisitionServiceDetails RSD
                INNER JOIN dbo.SCM_RequisitionBillOfQuantity RBQ
                    ON RBQ.RequisitionDetailID = RSD.RequisitionDetail_ID
                INNER JOIN dbo.SCM_TenderAdjudication TA
                    ON TA.BillOfQuantityId = RBQ.BillOfQuantityId
                INNER JOIN dbo.SCM_TenderAwardedVendor TAV
                    ON TAV.TenderRequisitionLinkID = TA.TenderRequisitionLinkID
                       AND TA.VendorID = TAV.SucessfulVendorID
                INNER JOIN dbo.SCM_Tender T
                    ON T.Tender_ID = TA.TenderID
            WHERE ISNULL(T.TenderCancel, 0) = 0
        --AND RSD.PlanProjectItemId = @ProjectItemID
        ) AS T
        WHERE T.RequisitionAmount - T.TenderAmount > 0
        UNION ALL

        --Tender more than Requisition
        SELECT T.PlanProjectItemId,
               2,
               9,
               T.TenderAdjudication_ID,
               'SCM_TenderAdjudication',
               (T.TenderAmount - T.RequisitionAmount) * -1 amount,
               0,
               T.CapturerID,
               T.DateCaptured,
               NULL,
               NULL,
               T.FinancialYear
        FROM
        (
            SELECT RSD.PlanProjectItemId,
                   TA.TenderAdjudication_ID,
                   CAST((RSD.EstimatedCost * RSD.Quantity) AS DECIMAL(18, 2)) AS RequisitionAmount,
                   TA.PricePoints AS TenderAmount,
                   T.CapturerID,
                   TA.DateCaptured,
                   T.FinancialYear
            FROM dbo.SCM_RequisitionServiceDetails RSD
                INNER JOIN dbo.SCM_RequisitionBillOfQuantity RBQ
                    ON RBQ.RequisitionDetailID = RSD.RequisitionDetail_ID
                INNER JOIN dbo.SCM_TenderAdjudication TA
                    ON TA.BillOfQuantityId = RBQ.BillOfQuantityId
                INNER JOIN dbo.SCM_TenderAwardedVendor TAV
                    ON TAV.TenderRequisitionLinkID = TA.TenderRequisitionLinkID
                       AND TA.VendorID = TAV.SucessfulVendorID
                INNER JOIN dbo.SCM_Tender T
                    ON T.Tender_ID = TA.TenderID
            WHERE ISNULL(T.TenderCancel, 0) = 0
        --AND RSD.PlanProjectItemId = @ProjectItemID
        ) AS T
        WHERE T.TenderAmount - T.RequisitionAmount > 0
        UNION ALL

        --Order
        SELECT OTD.PlanProjectItemID,
               2,
               9,
               OTD.OrderDetailID,
               'SCM_OrderTypeDetail',
               OTD.Amount,
               0,
               O.CapturerID,
               OTD.DateCaptured,
               NULL,
               NULL,
               O.FinancialYear
        FROM dbo.SCM_OrderTypeDetail OTD
            INNER JOIN dbo.SCM_Order O
                ON O.Order_ID = OTD.OrderID
        WHERE O.ApprovedBy IS NOT NULL
              AND ISNULL(OTD.IsVoid, 0) = 0
        --AND OTD.PlanProjectItemID = @ProjectItemID
        UNION ALL

        --Order
        SELECT OTD.PlanProjectItemID,
               3,
               9,
               OTD.OrderDetailID,
               'SCM_OrderTypeDetail',
               OTD.Amount * -1,
               0,
               O.CapturerID,
               DATEADD(SECOND,10, OTD.DateCaptured),
               NULL,
               NULL,
               O.FinancialYear
        FROM dbo.SCM_OrderTypeDetail OTD
            INNER JOIN dbo.SCM_Order O
                ON O.Order_ID = OTD.OrderID
        WHERE O.ApprovedBy IS NOT NULL
              AND ISNULL(OTD.IsVoid, 0) = 0
        --AND OTD.PlanProjectItemID = @ProjectItemID
        UNION ALL

        --GRN
        SELECT OTD.PlanProjectItemID,
               2,
               9,
               GRND.GRNDetail_ID,
               'SCM_GRNDetails',
               GRND.Amount,
               0,
               GRN.CapturerID,
               GRN.DateCaptured,
               NULL,
               NULL,
               GRN.FinancialYear
        FROM dbo.SCM_GRN GRN
            INNER JOIN dbo.SCM_GRNDetails GRND
                ON GRND.GRNID = GRN.GRN_ID
            INNER JOIN dbo.SCM_OrderTypeDetail OTD
                ON OTD.OrderDetailID = GRND.OrderDetailID
        WHERE ISNULL(GRND.IsVoid, 0) = 0
        --AND OTD.PlanProjectItemID = @ProjectItemID
        UNION ALL

        --GRN
        SELECT OTD.PlanProjectItemID,
               3,
               9,
               GRND.GRNDetail_ID,
               'SCM_GRNDetails',
               GRND.Amount * -1,
               0,
               GRN.CapturerID,
               DATEADD(SECOND,10, GRN.DateCaptured),
               NULL,
               NULL,
               GRN.FinancialYear
        FROM dbo.SCM_GRN GRN
            INNER JOIN dbo.SCM_GRNDetails GRND
                ON GRND.GRNID = GRN.GRN_ID
            INNER JOIN dbo.SCM_OrderTypeDetail OTD
                ON OTD.OrderDetailID = GRND.OrderDetailID
        WHERE ISNULL(GRND.IsVoid, 0) = 0
        --AND OTD.PlanProjectItemID = @ProjectItemID
        UNION ALL

        --Invoice
        SELECT ID.PlanProjectItemID,
               3,
               9,
               ID.InvoiceDetail_ID,
               'SCM_InvoiceDetail',
               ID.Amount,
               0,
               I.CapturerID,
               I.DateCaptured,
               NULL,
               NULL,
               I.FinancialYear
        FROM dbo.SCM_Invoice I
            INNER JOIN dbo.SCM_InvoiceDetail ID
                ON ID.InvoiceID = I.Invoice_ID
        WHERE I.ApprovedBy IS NOT NULL
              AND ISNULL(ID.IsVoid, 0) = 0
        --AND ID.PlanProjectItemID = @ProjectItemID
        UNION ALL

        --Invoice
        SELECT ID.PlanProjectItemID,
               4,
               9,
               ID.InvoiceDetail_ID,
               'SCM_InvoiceDetail',
               ID.Amount * -1,
               0,
               I.CapturerID,
               DATEADD(SECOND,10, I.DateCaptured),
               NULL,
               NULL,
               I.FinancialYear
        FROM dbo.SCM_Invoice I
            INNER JOIN dbo.SCM_InvoiceDetail ID
                ON ID.InvoiceID = I.Invoice_ID
        WHERE I.ApprovedBy IS NOT NULL
              AND ISNULL(ID.IsVoid, 0) = 0
        --AND ID.PlanProjectItemID = @ProjectItemID
        UNION ALL

        --Sundry Payment
        SELECT SID.PlanProjectItemID,
               4,
               9,
               SID.SundryPaymentDetail_ID,
               'SCM_SundryPaymentServiceDetails',
               SID.Amount * -1,
               0,
               SI.CapturerID,
               SI.DateCaptured,
               NULL,
               NULL,
               SI.FinancialYear
        FROM dbo.SCM_SundryPayment SI
            INNER JOIN dbo.SCM_SundryPaymentServiceDetails SID
                ON SI.SundryPayment_ID = SID.SundryPaymentID
		WHERE ISNULL(SI.HODApproval, 0) = 1
		AND ISNULL(SI.IsVoid, 0) = 0
    --AND SID.PlanProjectItemID = @ProjectItemID
    ) BudgetRegister;



    --Recalc the running total
    DECLARE @PlanProjectItemId INT;
    DECLARE @BudgetRegisterId INT;
    DECLARE @Amount DECIMAL(18, 2);
    DECLARE @AvailableAmount DECIMAL(18, 2);

    DECLARE ppId_Cursor CURSOR FOR
    SELECT DISTINCT
           PlanProjectItemID
    FROM dbo.Plan_BudgetRegister;
	--WHERE PlanProjectItemID = @ProjectItemID;

    OPEN ppId_Cursor;

    FETCH NEXT FROM ppId_Cursor
    INTO @PlanProjectItemId;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        SET @AvailableAmount = 0;
        DECLARE budget_cursor CURSOR FOR
        SELECT BudgetRegister_ID,
               ISNULL(TransactionAmount, 0)
        FROM dbo.Plan_BudgetRegister
        WHERE PlanProjectItemID = @PlanProjectItemId
        ORDER BY DateCaptured,
                 BudgetRegister_ID;

        OPEN budget_cursor;
        FETCH NEXT FROM budget_cursor
        INTO @BudgetRegisterId,
             @Amount;

        WHILE @@FETCH_STATUS = 0
        BEGIN
            IF @AvailableAmount = 0
            BEGIN
                SET @AvailableAmount = @Amount;
            END;
            ELSE
            BEGIN
                SET @AvailableAmount = @AvailableAmount + @Amount;
            END;

            UPDATE dbo.Plan_BudgetRegister
            SET AvailableBudget = @AvailableAmount
            WHERE BudgetRegister_ID = @BudgetRegisterId;

            FETCH NEXT FROM budget_cursor
            INTO @BudgetRegisterId,
                 @Amount;
        END;

        CLOSE budget_cursor;
        DEALLOCATE budget_cursor;
        -- Get the next vendor.  
        FETCH NEXT FROM ppId_Cursor
        INTO @PlanProjectItemId;
    END;
    CLOSE ppId_Cursor;
    DEALLOCATE ppId_Cursor;
END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_RejectAdjustmentProject_sp]    Script Date: 2026/03/10 7:23:46 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Raindree Chetty
-- Create date: 2018-03-04
-- Description:	Reject Adjustment Project
-- EXEC [Plan_RejectAdjustmentProject_sp] 1,27739,'sahil rejected'
-- DO NOT APPLY REDGATE SQL FORMAT
-- SNagpal: 68561 Fix Update Project Item Issue
-- 16 Apr 2018 : 70840 Fix Issue for Rejection
-- 30 Apr 2019: Add Insert script to handle Error when Any error occured.
-- =============================================
CREATE PROCEDURE [dbo].[Plan_RejectAdjustmentProject_sp]
	@UserId INT,
	@AdjustmentProjectId INT, 
	@RejectReason NVARCHAR(1000)
AS
BEGIN
BEGIN TRY
    BEGIN TRANSACTION
		
		--Declare Variables
		DECLARE @ModuleName NVARCHAR(20) = 'Planning', @PageName NVARCHAR(50) = 'AdjustmentProjectApproval.aspx.cs', @Method NVARCHAR(50) = 'BtnSubmit_Click'


		DECLARE @ErrorResult NVARCHAR(MAX) = ''

		--Declare table
		DECLARE @tblProjectItem TABLE
			( PlanAdjustmentProjectItemID INT, ReferencePlanProjectItem_ID INT )

		--Declare Variables
		DECLARE @ReferencePlanProjectItem_ID INT, @PlanAdjustmentProjectItemID INT

		--Declare table
		DECLARE @tblProjectCosting TABLE
			( AdjustmentProjectCostingID INT, ReferenceProjectCostingID INT )

