							FROM @tblProjectIDP
							EXEC dbo.Inven_InsertAuditLog_sp 'Plan_AdjustmentProjectIDP', @AdjustmentProjectIDPID, @UserId, @ModuleName, @PageName, @Method
						--	EXEC dbo.Inven_InsertAuditLog_sp 'IDP_Item', @AdjustmentProjectIDPItemID, @UserId, @ModuleName, @PageName, @Method
						--					select @AdjustmentProjectIDPID,@ReferenceProjectIDPID,@AdjustmentProjectIDPItemID
