							END

							DELETE FROM @tblProjectRegion WHERE AdjustmentProjectRegionID = @AdjustmentProjectRegionID
						END

				--Reset [Plan_AdjustmentProjectCostings] to orginal
					INSERT INTO @tblProjectCosting
						(  AdjustmentProjectCostingID, ReferenceProjectCostingID )
					SELECT
						PAP.AdjustmentProjectCosting_ID, ISNULL(PAP.ReferenceProjectCostingID,0)
					FROM Plan_AdjustmentProject PAPI (NOLOCK) 
						INNER JOIN Plan_AdjustmentProjectCosting PAP (NOLOCK) ON PAPI.AdjustmentProject_ID=PAP.AdjustmentProjectID
						WHERE PAPI.AdjustmentProject_ID=@AdjustmentProjectID

					WHILE EXISTS (SELECT 1 FROM @tblProjectCosting)
						BEGIN 
							SELECT TOP 1  
