    ROLLBACK TRANSACTION
	GOTO AllGood

END CATCH

	AllGood:

	SELECT @AdjustmentProjectId AS AdjustmentProjectId, @ErrorResult AS Result --Comment whole section From Begin Try to this part when you want to update edmx & Uncomment below part.
	
