-- 15 Mar 2019 SNagpal: #85700 Exclude Amount R0 - HAVING  CAST(ROUND(SUM(ISNULL(AdjustedBudgetAmount,0)),0) AS BIGINT) <> 0
-- 26 Mar 2019 SNagpal: #86098 COALESCE(pp.ProjectCode,pp.ReferenceProject_ID,pp.AdjustmentProject_ID
-- OShiri 28-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- SNagpal 07-06-2019 : Fix multiyear concept to SCOA segments based upon financial year
-- 30-11-2019 CMoodley: 24526 - Exclude projects that are not for NT reporting
-- 18-03-2020 CMoodley: 30744 - Handle ReferenceProject_ID is null where excluding projects for NT reporting
-- 29-09-2020 CMoodley: 45834 - Exclude projects where sum of budget over the 3 years is zero
-- 26-02-2021 CMoodley: 59209 - Exclude projects where budget is zero for current year only
-- 27-02-2023 CMoodley: 97829 - Set ProjectCode to NULL if ProjectCode is zero  
-- 10-03-2023 CMoodley: 98594 - Budget sign to be returned as per other reports/standard
-- 17-10-2023 CMoodley: 107216 - Exclude costing projects, use consolidated SCOA tables
-- ===================================================================================
CREATE PROCEDURE [dbo].[Plan_ReportAdjustmentBudgetString_Rpt_sp] 
   @FinancialYear NVARCHAR(9)

AS
    BEGIN
        SET NOCOUNT ON;

		DECLARE @tempValidations TABLE
          (
			[ExceptionDetail] VARCHAR(500),
			[ProjectID] VARCHAR(500),
			[ProjectItemID] VARCHAR(500)
          );

       INSERT INTO @tempValidations
       EXEC Plan_NTBudgetValidations @FinancialYear

        DECLARE @Startcount INT = 1 , @FinYearStartMonth INT = 7;

		DECLARE @AdjustmentVersionId INT, @BudgetVerionID INT;

		SELECT TOP 1 @BudgetVerionID = BudgetVersion_ID FROM dbo.Plan_BudgetVersion pbv
		INNER JOIN dbo.Plan_BudgetVersionDetail pbvd ON pbvd.BudgetVersionID = pbv.BudgetVersion_ID
		WHERE VersionName LIKE '%ORGB%' AND pbvd.FinYear=@FinancialYear ORDER BY pbv.DateCaptured DESC


		SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion papv
		INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentVersionId = papv.AdjustmentBudgetVersion_ID
		WHERE VersionName LIKE @FinancialYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

		SELECT @FinYearStartMonth = CAST(KeyValue AS INT) from AAAA_ConfigSettings where KeyName='FinYearStartMonth'



        DECLARE @tempScoaString TABLE
            (Id INT IDENTITY(1, 1) ,SCOAString VARCHAR(800));

        IF (SELECT COUNT(ExceptionDetail) FROM @tempValidations ) <> 0 

		BEGIN 

		        INSERT  INTO @tempScoaString
				SELECT 'NT Exception Detail|Project Detail|Project Item Detail'

				INSERT  INTO @tempScoaString
				SELECT
					( ExceptionDetail
					+ '|' + ProjectID
					+ '|' + ProjectItemID
					) AS Exceptiondetails
					FROM @tempValidations

         
        END

        ELSE    

		BEGIN

        INSERT  INTO @tempScoaString
                    SELECT 
						(MunicipalityNo 
						+ '|' + Finyear
						+ '|' + TypeStr
						+ '|' + SCOAProject 
						+ '|' + SCOAFunction 
						+ '|' + SCOAItem 
						+ '|' + SCOAFund 
						+ '|' + SCOACosting
						+ '|' + SCOARegion 
						+ '|' + CAST(CAST(ROUND(SUM(ISNULL(AdjustedBudgetAmount,0)),0) AS BIGINT) AS VARCHAR(40))
						) AS SCOAString
						FROM
						(
						SELECT  CAST(( SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) as MunicipalityNo,
								CAST(SUBSTRING(@FinancialYear , 6, 4) AS VARCHAR(4)) as Finyear, 'ADJB' as TypeStr, 
								p.SCOAProject,			 
								LOWER(CAST(ISNULL(scoaf.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFunction,
								LOWER(CAST(ISNULL(scoai.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAItem,
								LOWER(CAST(ISNULL(scoafnd.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFund,
								LOWER(CAST(ISNULL(scoac.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOACosting,
								LOWER(CAST(ISNULL(scoar.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOARegion,
								scoai.ScoaCode,
								(CASE WHEN (((scoai.ScoaCode LIKE 'IR%' OR scoai.ScoaCode LIKE 'IL%') AND [p].CapitalOperation in (0,1,2)) OR [pi].CreditDebit = 'C')
									THEN -isnull([pi].AdjustedBudgetAmount,[pi].BudgetAmount)
									ELSE isnull([pi].AdjustedBudgetAmount,[pi].BudgetAmount)
									END ) AS AdjustedBudgetAmount,

								(CASE WHEN (((scoai.ScoaCode LIKE 'IR%' OR scoai.ScoaCode LIKE 'IL%') AND [p].CapitalOperation in (0,1,2)) OR [pi].CreditDebit = 'C')
									THEN -isnull([pi].AdjustedBudgetAmountCurP1,[pi].BudgetAmountCurP1)
									ELSE isnull([pi].AdjustedBudgetAmountCurP1,[pi].BudgetAmountCurP1)
									END ) AS AdjustedBudgetAmountCurP1,

								(CASE WHEN (((scoai.ScoaCode LIKE 'IR%' OR scoai.ScoaCode LIKE 'IL%') AND [p].CapitalOperation in (0,1,2)) OR [pi].CreditDebit = 'C')
									THEN -isnull([pi].AdjustedBudgetAmountCurP2,[pi].BudgetAmountCurP2)
									ELSE isnull([pi].AdjustedBudgetAmountCurP2,[pi].BudgetAmountCurP2)
									END ) AS AdjustedBudgetAmountCurP2,
								[pi].ReferencePlanProjectItem_ID
								FROM   dbo.Plan_AdjustmentProjectItem AS [pi]
								LEFT OUTER JOIN (SELECT LOWER(CAST(ISNULL(scoap.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))
								+ CASE WHEN (scoap.BreakDownAllowed='Yes') THEN '_' + right('00000'+CAST(COALESCE(CASE pp.ProjectCode WHEN 0 THEN NULL ELSE pp.ProjectCode END,pp.ReferenceProject_ID,pp.AdjustmentProject_ID) AS NVARCHAR(10)), 5)
								ELSE '' END )  AS SCOAProject, pp.AdjustmentProject_ID, pp.IsDeleted, pp.CapitalOperation, pp.ReferenceProject_ID, pp.CostingProject
								FROM  dbo.Plan_AdjustmentProject AS pp
								LEFT OUTER JOIN  Const_SCOA_Project_Structure_Consolidated AS scoap ON scoap.ScoaID = pp.ScoaProjectID AND scoap.FinYearText = @FinancialYear) AS p 
								ON p.AdjustmentProject_ID = [pi].AdjustmentProjectID
								LEFT JOIN Plan_BudgetVersionDetail pbvd ON p.ReferenceProject_ID = pbvd.ProjectID AND [pi].ReferencePlanProjectItem_ID = pbvd.PlanProjectItemID
								AND pbvd.BudgetVersionID = @BudgetVerionID
								LEFT OUTER JOIN Const_SCOA_Function_Structure_Consolidated AS scoaf ON scoaf.ScoaID = [pi].SCOAFunctionId AND scoaf.FinYearText = @FinancialYear
								LEFT OUTER JOIN Plan_Const_SCOA_Structure_Consolidated_vw AS scoai ON scoai.ScoaID = [pi].SCOAItemID AND scoai.FinYearText = @FinancialYear
								LEFT OUTER JOIN Const_SCOA_Funds_Structure_Consolidated AS scoafnd ON scoafnd.ScoaID = [pi].SCOAFundId AND scoafnd.FinYearText = @FinancialYear
								LEFT OUTER JOIN Const_SCOA_Costing_Structure_Consolidated AS scoac ON scoac.ScoaID = [pi].SCOACostingID AND scoac.FinYearText = @FinancialYear
								LEFT OUTER JOIN Const_SCOA_Regional_Structure_Consolidated AS scoar ON scoar.ScoaID = [pi].SCOARegionId AND scoar.FinYearText = @FinancialYear
						   WHERE   pi.FinYear IS NOT NULL
								AND [pi].FinYear = @FinancialYear 
								AND ISNULL(p.IsDeleted,0) = 0
								AND [pi].AdjustmentVersionId =  @AdjustmentVersionId 
								AND ISNULL(p.ReferenceProject_ID, -1) NOT IN (SELECT ProjectID FROM dbo.Plan_ProjectReportExclude)
								AND ISNULL(p.CostingProject, 0) <> 1
						)as ProjectDetails
					
						GROUP BY MunicipalityNo,Finyear,TypeStr,SCOAProject,SCOAFunction,SCOAItem, SCOAFund,SCOACosting, SCOARegion,ScoaCode 
						HAVING  CAST(ROUND(SUM(ISNULL(AdjustedBudgetAmount,0)),0) AS BIGINT) <> 0
						ORDER BY FinYear; 

		--Month wise
		INSERT  INTO @tempScoaString
					SELECT  
					(MunicipalityNo 
					+ '|' + Finyear
					+ '|' + TypeStr
					+ '|' + SCOAProject 
					+ '|' + SCOAFunction 
					+ '|' + SCOAItem 
					+ '|' + SCOAFund 
					+ '|' + SCOACosting
					+ '|' + SCOARegion 
					+ '|' + CAST(CAST(ROUND(SUM(UnitPrice),0) AS BIGINT) AS VARCHAR(40))) AS SCOAString
					FROM
					(
					SELECT CAST(( SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) as MunicipalityNo,
						   CAST(SUBSTRING(@FinancialYear, 6, 4) AS VARCHAR(4)) as Finyear,
						   CAST(( CASE mon.Month_ID
									WHEN 1 THEN 'AM01'
									WHEN 2 THEN 'AM02'
									WHEN 3 THEN 'AM03'
									WHEN 4 THEN 'AM04'
									WHEN 5 THEN 'AM05'
									WHEN 6 THEN 'AM06'
									WHEN 7 THEN 'AM07'
									WHEN 8 THEN 'AM08'
									WHEN 9 THEN 'AM09'
									WHEN 10 THEN 'AM10'
									WHEN 11 THEN 'AM11'
									WHEN 12 THEN 'AM12'
									ELSE 'Y'
									END ) AS VARCHAR(4))  as TypeStr,
							p.SCOAProject,
							LOWER(CAST(ISNULL(scoaf.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFunction,
							LOWER(CAST(ISNULL(scoai.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAItem,
							LOWER(CAST(ISNULL(scoafnd.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFund,
							LOWER(CAST(ISNULL(scoac.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOACosting,
							LOWER(CAST(ISNULL(scoar.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOARegion,
							(CASE WHEN (((scoai.ScoaCode LIKE 'IR%' OR scoai.ScoaCode LIKE 'IL%') AND [p].CapitalOperation in (0,1,2)) OR [pi].CreditDebit = 'C')
									THEN -isnull([pim].AdjustedUnitPrice,[pim].UnitPrice)
									ELSE isnull([pim].AdjustedUnitPrice,[pim].UnitPrice)
									END ) AS UnitPrice

					   FROM     dbo.Plan_AdjustmentProjectItemMonth AS pim
								LEFT JOIN  YearStartingAtMonth_fxn(@FinYearStartMonth) mon ON pim.MonthID=mon.SysMonthID
								INNER JOIN  dbo.Plan_AdjustmentProjectItem AS [pi] ON [pi].PlanAdjustmentProjectItem_ID = pim.PlanAdjustmentProjectItemID
								LEFT OUTER JOIN (SELECT LOWER(CAST(ISNULL(scoap.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))
										+ CASE WHEN (scoap.BreakDownAllowed='Yes') 
											THEN '_' + right('00000'+CAST(COALESCE(CASE pp.ProjectCode WHEN 0 THEN NULL ELSE pp.ProjectCode END,pp.ReferenceProject_ID,pp.AdjustmentProject_ID) AS NVARCHAR(10)), 5)
											ELSE ''
											END )  AS SCOAProject, pp.AdjustmentProject_ID, pp.IsDeleted ,pp.CapitalOperation, pp.ReferenceProject_ID, pp.CostingProject
											FROM  dbo.Plan_AdjustmentProject AS pp
											LEFT OUTER JOIN  Const_Scoa_Project_Structure_Consolidated AS scoap ON scoap.ScoaID = pp.ScoaProjectID AND scoap.FinYearText = @FinancialYear
											) AS p ON p.AdjustmentProject_ID = [pi].AdjustmentProjectID
								LEFT OUTER JOIN  Const_SCOA_Function_Structure_Consolidated AS scoaf ON scoaf.ScoaID = [pi].SCOAFunctionId AND scoaf.FinYearText = @FinancialYear
								LEFT OUTER JOIN  Plan_Const_SCOA_Structure_Consolidated_vw AS scoai ON scoai.ScoaID = [pi].SCOAItemID AND scoai.FinYearText = @FinancialYear
								LEFT OUTER JOIN  Const_SCOA_Funds_Structure_Consolidated AS scoafnd ON scoafnd.ScoaID = [pi].SCOAFundId AND scoafnd.FinYearText = @FinancialYear
								LEFT OUTER JOIN  Const_SCOA_Costing_Structure_Consolidated AS scoac ON scoac.ScoaID = [pi].SCOACostingID AND scoac.FinYearText = @FinancialYear
								LEFT OUTER JOIN  Const_SCOA_Regional_Structure_Consolidated AS scoar ON scoar.ScoaID = [pi].SCOARegionId AND scoar.FinYearText = @FinancialYear
						WHERE   [pi].FinYear IS NOT NULL
								AND [pi].FinYear = @FinancialYear
								AND ISNULL(p.IsDeleted,0) = 0
								AND [pi].AdjustmentVersionId = @AdjustmentVersionId  AND pim.AdjustmentVersionId = @AdjustmentVersionId 
								AND ISNULL(p.ReferenceProject_ID, -1) NOT IN (SELECT ProjectID FROM dbo.Plan_ProjectReportExclude)
								AND ISNULL(p.CostingProject, 0) <> 1
								) as pp
						GROUP BY
						MunicipalityNo,
						Finyear,
						TypeStr,
						SCOAProject,
						SCOAFunction,
						SCOAItem, 
						SCOAFund,
						SCOACosting, 
						SCOARegion
					HAVING  CAST(ROUND(SUM(UnitPrice), 0) AS BIGINT) <> 0
					ORDER BY FinYear,TypeStr;

		End 
		
		SELECT Id, SCOAString
        FROM    @tempScoaString
        WHERE   SCOAString IS NOT NULL
        ORDER BY Id;

END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_ReportNTIDPString_Rpt_sp]    Script Date: 2026/03/10 7:23:46 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =================================================
-- Author:		Sahil Nagpal
-- Create date: 2017-May-15
-- Description:	#55482 IDP String report
-- 07 June 2017 ChettyR changed to no show 1st(NKPA) and and last(IDP Program) at per email from Melanien
-- 28 June 2017 ChettyR only show project id if Breakdown allowed is "yes"
-- 29 June 2017 ChettyR: duplicates fixed
-- 03 July 2017 SNagpal: Revert change of no show 1st(NKPA) and and last(IDP Program), As this is managed on Code side.
-- 13 July 2017 SNagpal: As per discussion with Melanien, Exclude Default projects & Municipal Running Cost. 
-- ADD condition NOT IN (''53d432c7-5d06-4d53-a785-f29995840060'', ''63348e37-464e-4ac0-a13a-e577838ff961'')
-- 24 July 2017 SNagpal: As per discussion with Melanien,Exclude Projects having BreakDownAllowed=No, So Add Condition scoap.BreakDownAllowed=''Yes'''
-- 21 August 2017 RChetty: 2nd and 3rd IDPlevels to only show first 2 characters
-- Plan_ReportNTIDPString_Rpt_sp '2016/2017'
-- 28 Sept 2017 SNagpal: #62905 Include only project from Const_NTStringSCOAProject
						-- Restrict “Strategic Objective” and “Project Description” to 250 characters 
						-- Longitude and Latitude fields to 0  in case of NULL
						-- Remove Condition of scoap.BreakDownAllowed=''Yes''
-- 29 Sept 2017 Rchetty: 62905 Also include projects from Const_NTStringScoaProject
-- 16 OCT 2017 SNagpal: #63556 Include Distinct SCOA projects from Const_NTStringScoaProject. Write down union script
-- 24-JAN-2019: SNagpal: #61596 - #83633 - Add functionality to get ProjectCode
-- 21-02-2019: SNagpal: #84009, Get SCOA Segments based upon FinYear
-- OShiri 28-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- 25-06-2019 CMoodley: #90808, Handle instance where ProjectCode is null - default to Project_ID
-- 26-06-2019 CMoodley: #90887, @DefaultIDPStringUnion - filter project by Finyear
-- 01-04-2020 CMoodley: #31426, Filter out projects with zero budget and exclude projects from Plan_ProjectReportExclude
-- 30-04-2020 CMoodley: #33017, Filter out projects only if sum of budget over the 3 years  = zero
-- 28-05-2021 CMoodley: #67531, Only return one link to IDP for projects linked to multiple IDP levels
-- 02-04-2025 CMoodley: #119841, Return latitude and longitude for operational projects as captured
-- [dbo].[Plan_ReportNTIDPString_Rpt_sp] '2025/2026'
-- =================================================
CREATE PROCEDURE [dbo].[Plan_ReportNTIDPString_Rpt_sp] 
    @finyear NVARCHAR(9) ='2018/2019' 
AS
BEGIN
	SET NOCOUNT ON;

	DECLARE @alpha varchar(26) = 'abcdefghijklmnopqrstuvwxyz', @IDPNumLevel INT, @StartCount INT = 2;
	DECLARE @selectText NVARCHAR(500), @sqlText NVARCHAR(MAX), @strIDPInnerJoinText NVARCHAR(1500), @MainColumnText NVARCHAR(MAX), @EndColumnText NVARCHAR(500),
	@MunicipilityFinYearText NVARCHAR(600), @DefaultIDPStringUnion NVARCHAR(1700),@Tablename NVARCHAR(250), @StructureName NVARCHAR(50);

	SET @StructureName = 'Project';

	SELECT NTScoaID,BreakDownAllowed,ScoaShortDesc,ScoaID INTO #tableName  FROM dbo.Const_Scoa_Project_Structure_ByYear(@finYear)

	SELECT @IDPNumLevel = IDPNumLevel FROM dbo.Const_IDPLevelDescription_Header WHERE FinancialYear= @finyear

	SET @selectText = 'SELECT DISTINCT ';
	SET @MunicipilityFinYearText = 'CAST((SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) + ''|'' + ''' + SUBSTRING(@finyear, 6, 4) + ''' + ''|TABB|'' + 
									LOWER(CAST(ISNULL(scoap.NTScoaID, ''00000000-0000-0000-0000-000000000000'') AS VARCHAR(50))) 
									+  CASE WHEN (scoap.BreakDownAllowed=''Yes'') 
															THEN  ''_'' + right(''00000''+CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS NVARCHAR(10)), 5)
															ELSE ''''
															END + ''|'' + ';

	SET @DefaultIDPStringUnion = ' UNION SELECT DISTINCT CAST((SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) + ''|''
									+ ''' + SUBSTRING(@finyear, 6, 4) + ''' + ''|TABB|'' + 
									LOWER(CAST(ISNULL(scoap.NTScoaID, ''00000000-0000-0000-0000-000000000000'') AS VARCHAR(50)))  + ''||'' + 
									+ ISNULL(cnsp.MTSFCode, '''') + ''|'' + ISNULL(cnsp.IUDFCode, '''')  
									+ ''|'' + ISNULL(scoap.ScoaShortDesc, '''') + ''|'' + ISNULL(scoap.ScoaShortDesc, '''')
									+ ''|'' + ISNULL(scoap.ScoaShortDesc, '''')
									+ ''|'' + CAST(ISNULL(ppi.Longitude, 0) AS VARCHAR(50)) + ''|'' + CAST(ISNULL(ppi.Latitude, 0) AS VARCHAR(50)) AS NTIDPString , ''Success'' as Success
									FROM     dbo.Plan_Project pp 
									INNER JOIN (SELECT projIDP.* FROM (SELECT MIN(ProjectIDP_ID) minProjectIDP, ProjectID FROM dbo.Plan_ProjectIDP GROUP BY ProjectID) minProjIDP INNER JOIN Plan_ProjectIDP projIDP ON minProjIDP.minProjectIDP = projIDP.ProjectIDP_ID) ppi ON pp.Project_ID = ppi.ProjectID 
									INNER JOIN #tableName  scoap ON scoap.ScoaID = pp.ScoaProjectID
									INNER JOIN dbo.Const_NTStringSCOAProject cnsp ON cnsp.SCOAProjectId = scoap.ScoaID
									INNER JOIN (SELECT ProjectID FROM Plan_ProjectItem WHERE FinYear = ''' + @finYear + ''' GROUP BY ProjectID HAVING CAST(ROUND(SUM([BudgetAmount]) + SUM([BudgetAmountCurP1]) + SUM([BudgetAmountCurP2]), 0) AS BIGINT) <> 0) ppItem ON pp.Project_ID = ppItem.ProjectID
									WHERE   cnsp.IsEnable = 1 AND ISNULL(pp.IsDeleted,0) = 0 AND pp.Project_ID NOT IN (SELECT ProjectID FROM Plan_ProjectReportExclude) AND cnsp.FinYear= ''' + @finyear + ''' AND pp.FinYear=''' + @finyear + '''' ;


	SET @MainColumnText = 'ISNULL(a.ItemDesc,'''')';
	SET @EndColumnText = '+ ''|'' + SUBSTRING(pp.ProjectDesc,1, 250) + ''|'' + CAST(ISNULL(ppi.Longitude, 0) as VARCHAR(50)) + ''|'' + CAST(ISNULL(ppi.Latitude, 0) as VARCHAR(50))';

	SET @sqlText = ' (select Item_ID, ItemDesc, ItemParentID from IDP_Item where IDPLevelNumber = 1 and FinancialYear = ''' + @finyear + ''') as a ';
	WHILE (@StartCount<=@IDPNumLevel)
	BEGIN
		SET @MainColumnText = @MainColumnText + ' + ''|'' + ISNULL(' + SUBSTRING(@alpha,@StartCount , 1) + '.ItemDesc,'''')';

		SET @sqlText = @sqlText + ' left join (select Item_ID, CASE WHEN IDPLevelNumber in (2,3) THEN SUBSTRING( ItemDesc,1,2) ELSE SUBSTRING( ItemDesc,1,250) END AS ItemDesc, ItemParentID from IDP_Item where IDPLevelNumber = ' + CAST (@StartCount AS VARCHAR(10)) + ' ) as ' 
		+ SUBSTRING(@alpha,@StartCount , 1);

		SET @sqlText = @sqlText + ' on ' + SUBSTRING(@alpha,@StartCount , 1) + '.ItemParentID = ' + SUBSTRING(@alpha,@StartCount - 1 , 1) + '.Item_ID';

		SET @StartCount = @StartCount + 1;
	END;

	SET @strIDPInnerJoinText = ' INNER JOIN (SELECT projIDP.* FROM (SELECT MIN(ProjectIDP_ID) minProjectIDP, ProjectID FROM dbo.Plan_ProjectIDP GROUP BY ProjectID) minProjIDP INNER JOIN Plan_ProjectIDP projIDP ON minProjIDP.minProjectIDP = projIDP.ProjectIDP_ID) ppi ON ' + SUBSTRING(@alpha,@IDPNumLevel , 1) + ' .Item_ID = ppi.ParentIDPItemID 
							 INNER JOIN dbo.Plan_Project pp ON pp.Project_ID = ppi.ProjectID
							 INNER JOIN #tableName scoap ON scoap.ScoaID = pp.ScoaProjectID 
							 INNER JOIN (SELECT ProjectID FROM Plan_ProjectItem WHERE FinYear = ''' + @finYear + ''' GROUP BY ProjectID HAVING CAST(ROUND(SUM([BudgetAmount]) + SUM([BudgetAmountCurP1]) + SUM([BudgetAmountCurP2]), 0) AS BIGINT) <> 0) ppItem ON pp.Project_ID = ppItem.ProjectID 
							 WHERE ' + SUBSTRING(@alpha,@IDPNumLevel , 1) + '.Item_ID IS NOT NULL AND ISNULL(pp.IsDeleted,0) = 0 AND pp.Project_ID NOT IN (SELECT ProjectID FROM Plan_ProjectReportExclude) 
							 AND scoap.BreakDownAllowed=''Yes''';

	SET @sqlText = @selectText + @MunicipilityFinYearText + @MainColumnText + @EndColumnText + ' as NTIDPString, ''Success'' as Success FROM ' +  @sqlText + @strIDPInnerJoinText;

	EXEC(@sqlText + @DefaultIDPStringUnion); --Comment this while updating edmx
	
	DROP TABLE #tableName	

END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_ReportNTIDPString_Rpt_sp_Backend]    Script Date: 2026/03/10 7:23:46 AM ******/
SET ANSI_NULLS ON
