-- =================================================
-- Author:		Sahil Nagpal
-- Create date: 2017-May-15
-- Description:	#55482 IDP String report
-- 07 June 2017 RChetty: Need a new IDP String for ORGB
-- 07 June 2017 changed to no show 1st(NKPA) and and last(IDP Program) at per email from Melanien
-- 28 June 2017 ChettyR only show project id if Breakdown allowed is "yes"
-- 29 June 2017 ChettyR: duplicates fixed
-- 13 July 2017 SNagpal: As per discussion with Melanien, Exclude Default projects & Municipal Running Cost. 
-- ADD condition NOT IN (''53d432c7-5d06-4d53-a785-f29995840060'', ''63348e37-464e-4ac0-a13a-e577838ff961'')
-- 24 July 2017 SNagpal: As per discussion with Melanien,Exclude Projects having BreakDownAllowed=No, So Add Condition scoap.BreakDownAllowed=''Yes'''
-- 21 August 2017 RChetty: 2nd and 3rd IDPlevels to only show first 2 characters
-- 28 Sept 2017 SNagpal: #62905 Include only project from Const_NTStringSCOAProject
						-- Restrict “Strategic Objective” and “Project Description” to 250 characters 
						-- Longitude and Latitude fields to 0  in case of NULL
						-- Remove Condition of scoap.BreakDownAllowed=''Yes''
-- 29 Sept 2017 Rchetty: 62905 Also include projects from Const_NTStringScoaProject
-- 16 OCT 2017 SNagpal: #63556 Include Distinct SCOA projects from Const_NTStringScoaProject. Write down union script
-- 24-01-2019: SNagpal: #61596 - #83633 - Add functionality to get ProjectCode
-- 20-02-2019: SNagpal: #84009, Get SCOA Segments based upon FinYear
-- OShiri 28-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- 25-06-2019 CMoodley: #90808, Handle instance where ProjectCode is null - default to Project_ID
-- 26-06-2019 CMoodley: #90887, @DefaultIDPStringUnion - filter project by Finyear
-- 08-06-2020 CMoodley: #34928, Exclude projects with zero budget over the 3 years, deleted projects and water projects in Plan_ProjectReportExclude table
-- 28-05-2021 CMoodley: #67531, Only return one link to IDP for projects linked to multiple IDP levels
-- 05-10-2021 CMoodley: #74982, Return string from budget version tables if version exists for fin year, else look at current budget tables
-- 02-04-2025 CMoodley: #119841, Return latitude and longitude for operational projects as captured
-- [Plan_ReportNTIDPStringORGB_Rpt_sp] '2024/2025'
-- =================================================
CREATE PROCEDURE [dbo].[Plan_ReportNTIDPStringORGB_Rpt_sp] 
    @finyear NVARCHAR(9) ='2018/2019' 
AS
BEGIN

	SET NOCOUNT ON;

	DECLARE @alpha varchar(26) = 'abcdefghijklmnopqrstuvwxyz', @IDPNumLevel INT, @StartCount INT = 2;
	DECLARE @selectText NVARCHAR(500), @sqlText NVARCHAR(MAX), @strIDPInnerJoinText NVARCHAR(1500), @MainColumnText NVARCHAR(MAX), @EndColumnText NVARCHAR(500),
	@MunicipilityFinYearText NVARCHAR(600), @DefaultIDPStringUnion NVARCHAR(2500), @BudgetVersionID INT
	
	SELECT @BudgetVersionID = ISNULL(dbo.Section71_BudgetOriginalVersionID_fxn(@finYear), -1)
	
	SELECT NTScoaID,BreakDownAllowed,ScoaShortDesc,ScoaID INTO #tableName  FROM dbo.Const_Scoa_Project_Structure_ByYear(@finYear)

	SELECT @IDPNumLevel = IDPNumLevel FROM dbo.Const_IDPLevelDescription_Header WHERE FinancialYear= @finyear

	IF (@BudgetVersionID <> -1)
	BEGIN
		SET @selectText = 'SELECT DISTINCT ';
		SET @MunicipilityFinYearText = 'CAST((SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) + ''|'' + ''' + SUBSTRING(@finyear, 6, 4) + ''' + ''|ORGB|'' + 
										LOWER(CAST(ISNULL(scoap.NTScoaID, ''00000000-0000-0000-0000-000000000000'') AS VARCHAR(50))) 
											+  CASE WHEN (scoap.BreakDownAllowed=''Yes'') 
																THEN  ''_'' + right(''00000''+CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS NVARCHAR(10)), 5)
																ELSE ''''
																END + ''|'' + ';

		SET @DefaultIDPStringUnion = ' UNION SELECT DISTINCT CAST((SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) + ''|''
										+ ''' + SUBSTRING(@finyear, 6, 4) + ''' + ''|ORGB|'' + 
										LOWER(CAST(ISNULL(scoap.NTScoaID, ''00000000-0000-0000-0000-000000000000'') AS VARCHAR(50)))  + ''|'' + 
										+ ISNULL(cnsp.MTSFCode, '''') + ''|'' + ISNULL(cnsp.IUDFCode, '''')  
										+ ''|'' + ISNULL(scoap.ScoaShortDesc, '''') + ''|'' + ISNULL(scoap.ScoaShortDesc, '''')
										+ ''|'' + CAST(ISNULL(ppi.Longitude, 0) AS VARCHAR(50)) + ''|'' + CAST(ISNULL(ppi.Latitude, 0) AS VARCHAR(50)) AS NTIDPString , ''Success'' as Success
										FROM  dbo.Plan_BudgetVersionDetail bvd    
										INNER JOIN dbo.Plan_Project pp ON bvd.ProjectID = pp.Project_ID
										INNER JOIN (SELECT projIDP.* FROM (SELECT MIN(ProjectIDP_ID) minProjectIDP, ProjectID FROM dbo.Plan_ProjectIDP GROUP BY ProjectID) minProjIDP INNER JOIN Plan_ProjectIDP projIDP ON minProjIDP.minProjectIDP = projIDP.ProjectIDP_ID) ppi ON pp.Project_ID = ppi.ProjectID 
										INNER JOIN #tableName scoap ON scoap.ScoaID = pp.ScoaProjectID
										INNER JOIN dbo.Const_NTStringSCOAProject cnsp ON cnsp.SCOAProjectId = scoap.ScoaID
										INNER JOIN (SELECT ProjectID FROM Plan_BudgetVersionDetail WHERE FinYear = ''' + @finYear + ''' AND BudgetVersionID = ' + CONVERT(VARCHAR, @BudgetVersionID) + ' GROUP BY ProjectID HAVING CAST(ROUND(SUM([BudgetAmount]) + SUM([BudgetAmountCurP1]) + SUM([BudgetAmountCurP2]), 0) AS BIGINT) <> 0) ppItem ON bvd.ProjectID = ppItem.ProjectID
										WHERE   cnsp.IsEnable = 1 AND ISNULL(pp.IsDeleted,0) = 0 AND BudgetVersionID = ' + CONVERT(VARCHAR, @BudgetVersionID) + ' AND bvd.ProjectID NOT IN (SELECT ProjectID FROM Plan_ProjectReportExclude) AND cnsp.FinYear= ''' + @finyear + '''' ; 

		SET @MainColumnText = '';
		SET @EndColumnText = ' + SUBSTRING(pp.ProjectDesc,1, 250) + ''|'' + CAST(ISNULL(ppi.Longitude, 0) as VARCHAR(50)) + ''|'' + CAST(ISNULL(ppi.Latitude, 0) as VARCHAR(50))';
		SET @sqlText = ' (select Item_ID, ItemDesc, ItemParentID from IDP_Item where IDPLevelNumber = 1 and FinancialYear = ''' + @finyear + ''') as a ';

		WHILE (@StartCount<=@IDPNumLevel)
		BEGIN
			IF (@StartCount<@IDPNumLevel)
			BEGIN
			SET @MainColumnText = @MainColumnText + ' + ISNULL(' + SUBSTRING(@alpha,@StartCount , 1) + '.ItemDesc,'''') + ''|''';
			END
			SET @sqlText = @sqlText + ' left join (select Item_ID, CASE WHEN IDPLevelNumber in (2,3) THEN SUBSTRING( ItemDesc,1,2) ELSE SUBSTRING( ItemDesc,1,250) END AS ItemDesc, ItemParentID from IDP_Item where IDPLevelNumber = ' + CAST (@StartCount AS VARCHAR(10)) + ' ) as ' 
			+ SUBSTRING(@alpha,@StartCount , 1);

			SET @sqlText = @sqlText + ' on ' + SUBSTRING(@alpha,@StartCount , 1) + '.ItemParentID = ' + SUBSTRING(@alpha,@StartCount - 1 , 1) + '.Item_ID';

			SET @StartCount = @StartCount + 1;
		END;


		SET @strIDPInnerJoinText = ' INNER JOIN (SELECT projIDP.* FROM (SELECT MIN(ProjectIDP_ID) minProjectIDP, ProjectID FROM dbo.Plan_ProjectIDP GROUP BY ProjectID) minProjIDP INNER JOIN Plan_ProjectIDP projIDP ON minProjIDP.minProjectIDP = projIDP.ProjectIDP_ID) ppi ON ' + SUBSTRING(@alpha,@IDPNumLevel , 1) + ' .Item_ID = ppi.ParentIDPItemID 
									 INNER JOIN dbo.Plan_BudgetVersionDetail bvd ON bvd.ProjectID = ppi.ProjectID
									 INNER JOIN dbo.Plan_Project pp ON bvd.ProjectID = pp.Project_ID
									 INNER JOIN #tableName scoap ON scoap.ScoaID = pp.ScoaProjectID 
									 INNER JOIN (SELECT ProjectID FROM Plan_BudgetVersionDetail WHERE FinYear = ''' + @finYear + ''' AND BudgetVersionID = ' + CONVERT(VARCHAR, @BudgetVersionID) + ' GROUP BY ProjectID HAVING CAST(ROUND(SUM([BudgetAmount]) + SUM([BudgetAmountCurP1]) + SUM([BudgetAmountCurP2]), 0) AS BIGINT) <> 0) ppItem ON bvd.ProjectID = ppItem.ProjectID
									 WHERE ' + SUBSTRING(@alpha,@IDPNumLevel , 1) + '.Item_ID IS NOT NULL AND bvd.BudgetVersionID = ' + CONVERT(VARCHAR, @BudgetVersionID) + ' AND ISNULL(pp.IsDeleted,0) = 0 AND bvd.ProjectID NOT IN (SELECT ProjectID FROM Plan_ProjectReportExclude) 
									 AND scoap.BreakDownAllowed=''Yes''';

		SET @sqlText = @selectText + @MunicipilityFinYearText + @MainColumnText + @EndColumnText + ' as NTIDPString, ''Success'' as Success FROM ' +  @sqlText + @strIDPInnerJoinText;

	END
	ELSE
	BEGIN
		SET @selectText = 'SELECT DISTINCT ';
		SET @MunicipilityFinYearText = 'CAST((SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) + ''|'' + ''' + SUBSTRING(@finyear, 6, 4) + ''' + ''|ORGB|'' + 
										LOWER(CAST(ISNULL(scoap.NTScoaID, ''00000000-0000-0000-0000-000000000000'') AS VARCHAR(50))) 
											+  CASE WHEN (scoap.BreakDownAllowed=''Yes'') 
																THEN  ''_'' + right(''00000''+CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS NVARCHAR(10)), 5)
																ELSE ''''
																END + ''|'' + ';

		SET @DefaultIDPStringUnion = ' UNION SELECT DISTINCT CAST((SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) + ''|''
										+ ''' + SUBSTRING(@finyear, 6, 4) + ''' + ''|ORGB|'' + 
										LOWER(CAST(ISNULL(scoap.NTScoaID, ''00000000-0000-0000-0000-000000000000'') AS VARCHAR(50)))  + ''|'' + 
										+ ISNULL(cnsp.MTSFCode, '''') + ''|'' + ISNULL(cnsp.IUDFCode, '''')  
										+ ''|'' + ISNULL(scoap.ScoaShortDesc, '''') + ''|'' + ISNULL(scoap.ScoaShortDesc, '''')
										+ ''|'' + CAST(ISNULL(ppi.Longitude, 0) AS VARCHAR(50)) + ''|'' + CAST(ISNULL(ppi.Latitude, 0) AS VARCHAR(50)) AS NTIDPString , ''Success'' as Success
										FROM     dbo.Plan_Project pp 
										INNER JOIN (SELECT projIDP.* FROM (SELECT MIN(ProjectIDP_ID) minProjectIDP, ProjectID FROM dbo.Plan_ProjectIDP GROUP BY ProjectID) minProjIDP INNER JOIN Plan_ProjectIDP projIDP ON minProjIDP.minProjectIDP = projIDP.ProjectIDP_ID) ppi ON pp.Project_ID = ppi.ProjectID 
										INNER JOIN #tableName scoap ON scoap.ScoaID = pp.ScoaProjectID
										INNER JOIN dbo.Const_NTStringSCOAProject cnsp ON cnsp.SCOAProjectId = scoap.ScoaID
										INNER JOIN (SELECT ProjectID FROM Plan_ProjectItem WHERE FinYear = ''' + @finYear + ''' GROUP BY ProjectID HAVING CAST(ROUND(SUM([BudgetAmount]) + SUM([BudgetAmountCurP1]) + SUM([BudgetAmountCurP2]), 0) AS BIGINT) <> 0) ppItem ON pp.Project_ID = ppItem.ProjectID
										WHERE   cnsp.IsEnable = 1 AND ISNULL(pp.IsDeleted,0) = 0 AND pp.Project_ID NOT IN (SELECT ProjectID FROM Plan_ProjectReportExclude) AND cnsp.FinYear= ''' + @finyear + ''' AND pp.FinYear=''' + @finyear + '''' ; 

		SET @MainColumnText = '';
		SET @EndColumnText = ' + SUBSTRING(pp.ProjectDesc,1, 250) + ''|'' + CAST(ISNULL(ppi.Longitude, 0) as VARCHAR(50)) + ''|'' + CAST(ISNULL(ppi.Latitude, 0) as VARCHAR(50))';
		SET @sqlText = ' (select Item_ID, ItemDesc, ItemParentID from IDP_Item where IDPLevelNumber = 1 and FinancialYear = ''' + @finyear + ''') as a ';

		WHILE (@StartCount<=@IDPNumLevel)
		BEGIN
			IF (@StartCount<@IDPNumLevel)
			BEGIN
			SET @MainColumnText = @MainColumnText + ' + ISNULL(' + SUBSTRING(@alpha,@StartCount , 1) + '.ItemDesc,'''') + ''|''';
			END
			SET @sqlText = @sqlText + ' left join (select Item_ID, CASE WHEN IDPLevelNumber in (2,3) THEN SUBSTRING( ItemDesc,1,2) ELSE SUBSTRING( ItemDesc,1,250) END AS ItemDesc, ItemParentID from IDP_Item where IDPLevelNumber = ' + CAST (@StartCount AS VARCHAR(10)) + ' ) as ' 
			+ SUBSTRING(@alpha,@StartCount , 1);

			SET @sqlText = @sqlText + ' on ' + SUBSTRING(@alpha,@StartCount , 1) + '.ItemParentID = ' + SUBSTRING(@alpha,@StartCount - 1 , 1) + '.Item_ID';

			SET @StartCount = @StartCount + 1;
		END;


		SET @strIDPInnerJoinText = ' INNER JOIN (SELECT projIDP.* FROM (SELECT MIN(ProjectIDP_ID) minProjectIDP, ProjectID FROM dbo.Plan_ProjectIDP GROUP BY ProjectID) minProjIDP INNER JOIN Plan_ProjectIDP projIDP ON minProjIDP.minProjectIDP = projIDP.ProjectIDP_ID) ppi ON ' + SUBSTRING(@alpha,@IDPNumLevel , 1) + ' .Item_ID = ppi.ParentIDPItemID 
									 INNER JOIN dbo.Plan_Project pp ON pp.Project_ID = ppi.ProjectID
									 INNER JOIN #tableName scoap ON scoap.ScoaID = pp.ScoaProjectID 
									 INNER JOIN (SELECT ProjectID FROM Plan_ProjectItem WHERE FinYear = ''' + @finYear + ''' GROUP BY ProjectID HAVING CAST(ROUND(SUM([BudgetAmount]) + SUM([BudgetAmountCurP1]) + SUM([BudgetAmountCurP2]), 0) AS BIGINT) <> 0) ppItem ON pp.Project_ID = ppItem.ProjectID
									 WHERE ' + SUBSTRING(@alpha,@IDPNumLevel , 1) + '.Item_ID IS NOT NULL AND ISNULL(pp.IsDeleted,0) = 0 AND pp.Project_ID NOT IN (SELECT ProjectID FROM Plan_ProjectReportExclude) 
									 AND scoap.BreakDownAllowed=''Yes''';

		SET @sqlText = @selectText + @MunicipilityFinYearText + @MainColumnText + @EndColumnText + ' as NTIDPString, ''Success'' as Success FROM ' +  @sqlText + @strIDPInnerJoinText;
	
	END

	EXEC(@sqlText + @DefaultIDPStringUnion); --Comment this while updating edmx

	DROP TABLE #tableName

END;
GO

