 							 INNER JOIN dbo.Const_SCOA_Project_Structure scoap ON scoap.ScoaID = pp.ScoaProjectID 
 							 WHERE ' + SUBSTRING(@alpha,@IDPNumLevel , 1) + '.Item_ID IS NOT NULL AND ISNULL(pp.IsDeleted,0) = 0 
							AND scoap.BreakDownAllowed=''Yes''';
							-- OR scoap.ScoaID IN (SELECT cnt.SCOAProjectId FROM dbo.Const_NTStringSCOAProject cnt WHERE cnt.IsEnable= 1 AND cnt.FinYear= ''' + @finyear + '''))';

SET @sqlText = @selectText + @MunicipilityFinYearText + @MainColumnText + @EndColumnText + ' as NTIDPString, ''Success'' as Success FROM ' +  @sqlText + @strIDPInnerJoinText;

--PRINT @sqlText + @DefaultIDPStringUnion;
EXEC(@sqlText + @DefaultIDPStringUnion); --Comment this while updating edmx

--SELECT Latitude AS NTIDPString , 'Success' AS Success  FROM Plan_ProjectIDP; --Uncomment this while updating edmx

END;

GO

/****** Object:  StoredProcedure [dbo].[Plan_ReportNTPRADAdjustmentIDPString_Rpt_sp]    Script Date: 2026/03/10 7:23:47 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =================================================
-- Author:		Sahil Nagpal
-- Create date: 2018-April-03
-- Description:	#63816 Submit Adjustment Budget IDP String
-- Exec Plan_ReportNTPRADAdjustmentIDPString_Rpt_sp '2019/2020'
-- 13-April-2018 : SNagpal #70809 Add CAST(ISNULL(p.ReferenceProject_ID, p.AdjustmentProject_ID)
-- 24-JAN-2019: SNagpal: #61596 - #83633 - Add functionality to get ProjectCode
-- Plan_ReportNTPRADAdjustmentIDPString_Rpt_sp '2022/2023'
-- 21-02-2019: SNagpal: #84009, Get SCOA Segments based upon FinYear
-- OShiri 28-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- 20200306 by CM - 29604 - Filter out projects that have zero budget for current financial year
-- 20200319 by CM - 29691 - Default ProjectCode to AdjustmentProject_ID if ProjectCode and ReferenceProject_ID is null
-- 20200929 by CM - 45834 - Exclude projects where sum of budget over the 3 years is zero
-- 20210226 by CM - 59209 - Exclude projects where budget is zero for current year only
-- 20210528 by CM - 67531 - Only return one link to IDP for projects linked to multiple IDP levels
-- 20230301 by CM - 97890 - Set ProjectCode to NULL when zero
-- 20231017 by CM - 107216 - Exclude costing projects, use consolidated SCOA tables
-- 20250307 by CM - 119276 - Return latitude and longitude for operational projects as captured
-- =================================================
CREATE   PROCEDURE [dbo].[Plan_ReportNTPRADAdjustmentIDPString_Rpt_sp]
    @finyear NVARCHAR(9) ='2017/2018' 
AS
BEGIN

	SET NOCOUNT ON;

	DECLARE @alpha varchar(26) = 'abcdefghijklmnopqrstuvwxyz', @IDPNumLevel INT, @StartCount INT = 2, @AdjustmentVersionId INT;
	DECLARE @selectText NVARCHAR(500), @sqlText NVARCHAR(MAX), @strIDPInnerJoinText NVARCHAR(1500), @MainColumnText NVARCHAR(MAX), @EndColumnText NVARCHAR(500),
	@MunicipilityFinYearText NVARCHAR(600), @DefaultIDPStringUnion NVARCHAR(1700),@Tablename NVARCHAR(250);

	SELECT NTScoaID,BreakDownAllowed,ScoaShortDesc,ScoaID INTO #tableName FROM Const_Scoa_Project_Structure_Consolidated WHERE FinYearText = @finYear

	SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion papv
			INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentVersionId = papv.AdjustmentBudgetVersion_ID
			WHERE VersionName LIKE @finyear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

	SELECT @IDPNumLevel = IDPNumLevel FROM dbo.Const_IDPLevelDescription_Header WHERE FinancialYear = @finyear

	SET @selectText = 'SELECT DISTINCT ';
	SET @MunicipilityFinYearText = 'CAST((SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) + ''|'' + ''' + SUBSTRING(@finyear, 6, 4) + ''' + ''|ADJB|'' + 
									LOWER(CAST(ISNULL(scoap.NTScoaID, ''00000000-0000-0000-0000-000000000000'') AS VARCHAR(50))) 
										+  CASE WHEN (scoap.BreakDownAllowed=''Yes'') 
															THEN  ''_'' + right(''00000''+ CAST(COALESCE(CASE pp.ProjectCode WHEN 0 THEN NULL ELSE pp.ProjectCode END, pp.ReferenceProject_ID, pp.AdjustmentProject_ID) AS NVARCHAR(10)), 5)
															ELSE ''''
															END + ''|'' + ';

	SET @DefaultIDPStringUnion = ' UNION SELECT DISTINCT CAST((SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) + ''|''
									+ ''' + SUBSTRING(@finyear, 6, 4) + ''' + ''|ADJB|'' + 
									LOWER(CAST(ISNULL(scoap.NTScoaID, ''00000000-0000-0000-0000-000000000000'') AS VARCHAR(50)))  + ''|'' + 
									+ ISNULL(cnsp.MTSFCode, '''') + ''|'' + ISNULL(cnsp.IUDFCode, '''')  
									+ ''|'' + ISNULL(scoap.ScoaShortDesc, '''') + ''|'' + ISNULL(scoap.ScoaShortDesc, '''')
									+ ''|'' + CAST(ISNULL(ppi.Longitude, 0) as VARCHAR(50)) + ''|'' + CAST(ISNULL(ppi.Latitude, 0) as VARCHAR(50)) AS NTIDPString , ''Success'' as Success
									FROM     dbo.Plan_AdjustmentProject pp 
									INNER JOIN #tableName scoap ON scoap.ScoaID = pp.ScoaProjectID
									INNER JOIN (SELECT projIDP.* FROM (SELECT MIN(AdjustmentProjectIDP_ID) minAdjustmentProjectIDP, AdjustmentProjectID FROM dbo.Plan_AdjustmentProjectIDP GROUP BY AdjustmentProjectID) minProjIDP INNER JOIN Plan_AdjustmentProjectIDP projIDP ON minProjIDP.minAdjustmentProjectIDP = projIDP.AdjustmentProjectIDP_ID) ppi ON pp.AdjustmentProject_ID = ppi.AdjustmentProjectID
									INNER JOIN dbo.Const_NTStringSCOAProject cnsp ON cnsp.SCOAProjectId = scoap.ScoaID
									INNER JOIN (SELECT AdjustmentProjectID FROM Plan_AdjustmentProjectItem WHERE FinYear = ''' + @finYear + ''' GROUP BY AdjustmentProjectID HAVING SUM(ISNULL(AdjustedBudgetAmount, BudgetAmount)) <> 0) papi ON pp.AdjustmentProject_ID = papi.AdjustmentProjectID
									WHERE   cnsp.IsEnable = 1 AND ISNULL(pp.CostingProject, 0) <> 1 AND ISNULL(pp.ReferenceProject_ID, -1) NOT IN (SELECT ProjectID FROM dbo.Plan_ProjectReportExclude) AND pp.AdjustmentVersionId = ''' + CAST(@AdjustmentVersionId AS VARCHAR(20)) + ''' AND cnsp.FinYear= ''' + @finyear + '''' ;

	SET @MainColumnText = '';
	SET @EndColumnText = ' + SUBSTRING(pp.AdjustmentProjectDesc,1, 250) + ''|'' + CAST(ISNULL(ppi.Longitude, 0) as VARCHAR(50)) + ''|'' + CAST(ISNULL(ppi.Latitude, 0) as VARCHAR(50))';

	SET @sqlText = ' (select Item_ID, ItemDesc, ItemParentID from IDP_Item where IDPLevelNumber = 1 and FinancialYear = ''' + @finyear + ''') as a ';
	WHILE (@StartCount<=@IDPNumLevel)
	BEGIN
	IF (@StartCount<@IDPNumLevel)
	BEGIN
	SET @MainColumnText = @MainColumnText + ' + ISNULL(' + SUBSTRING(@alpha,@StartCount , 1) + '.ItemDesc,'''') + ''|''';
	END
	SET @sqlText = @sqlText + ' left join (select Item_ID, CASE WHEN IDPLevelNumber in (2,3) THEN SUBSTRING( ItemDesc,1,2) ELSE SUBSTRING( ItemDesc,1,250) END AS ItemDesc, ItemParentID from IDP_Item where IDPLevelNumber = ' + CAST (@StartCount AS VARCHAR(10)) + ' ) as ' 
	+ SUBSTRING(@alpha,@StartCount , 1);

	SET @sqlText = @sqlText + ' on ' + SUBSTRING(@alpha,@StartCount , 1) + '.ItemParentID = ' + SUBSTRING(@alpha,@StartCount - 1 , 1) + '.Item_ID';

	SET @StartCount = @StartCount + 1;
	END;

	SET @strIDPInnerJoinText = ' INNER JOIN (SELECT projIDP.* FROM (SELECT MIN(AdjustmentProjectIDP_ID) minAdjustmentProjectIDP, AdjustmentProjectID FROM dbo.Plan_AdjustmentProjectIDP GROUP BY AdjustmentProjectID) minProjIDP INNER JOIN Plan_AdjustmentProjectIDP projIDP ON minProjIDP.minAdjustmentProjectIDP = projIDP.AdjustmentProjectIDP_ID) ppi ON ' + SUBSTRING(@alpha,@IDPNumLevel , 1) + ' .Item_ID = ppi.ParentIDPItemID 
								 INNER JOIN dbo.Plan_AdjustmentProject pp ON pp.AdjustmentProject_ID = ppi.AdjustmentProjectID
								 INNER JOIN #tableName scoap ON scoap.ScoaID = pp.ScoaProjectID 
								 INNER JOIN (SELECT AdjustmentProjectID FROM Plan_AdjustmentProjectItem WHERE FinYear = ''' + @finYear + ''' GROUP BY AdjustmentProjectID HAVING SUM(ISNULL(AdjustedBudgetAmount, BudgetAmount)) <> 0) papi ON pp.AdjustmentProject_ID = papi.AdjustmentProjectID
								 WHERE ' + SUBSTRING(@alpha,@IDPNumLevel , 1) + '.Item_ID IS NOT NULL AND ISNULL(pp.IsDeleted,0) = 0 AND ISNULL(pp.CostingProject, 0) <> 1 AND ISNULL(pp.ReferenceProject_ID, -1) NOT IN (SELECT ProjectID FROM dbo.Plan_ProjectReportExclude)
								 AND scoap.BreakDownAllowed=''Yes'' AND pp.AdjustmentVersionId = ''' + CAST(@AdjustmentVersionId AS VARCHAR(20)) + '''' ;
							

	SET @sqlText = @selectText + @MunicipilityFinYearText + @MainColumnText + @EndColumnText + ' as NT_PRAD_IDPString, ''Success'' as Success FROM ' +  @sqlText + @strIDPInnerJoinText;

	EXEC(@sqlText + @DefaultIDPStringUnion); --Comment this while updating edmx

	DROP TABLE #tableName

END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_ReportNTSCOAString_Rpt_sp]    Script Date: 2026/03/10 7:23:47 AM ******/
SET ANSI_NULLS ON
