SET QUOTED_IDENTIFIER ON
GO

-- ======================================================================================================================================
-- Author:		James Roodt
-- Create date: 2015-05-21
-- Description:	
-- 2015-06-05 TP20442 & 20441 James Roodt: Added financial year filter, Also removed 3 columns. also combined 4 scoa item columns into 1
-- 2015-06-09 TP20441 James Roodt: Added column to denote project Number and project Name. Also adding summing the values 
-- 2015-06-25 TP13080\20011 Ravindra Jijotia: Added new columns to display descriptions & Municipal Standard Classification
-- 2015-07-08 TP21915	Ravindra Jijotia:	Updated NT SCOA String report with new changes as requested by NT
-- 2015-08-03 TP21915	Ravindra Jijotia:	Updated NT SCOA String report to use code instead of GUID.
-- 2015-08-04 TP21915	Ravindra Jijotia:	Updated NT SCOA String report to display records for next five years.
-- 2015-08-26 TP21915	Ravindra Jijotia:	Updated NT SCOA String report to display records grouped by fin year & scoa codes.
-- 2015-11-27 Critical	Ravindra Jijotia:	Change in Funding Code, Costing Code, Project Code and amounts must be rounded off – no decimal places.
-- EXEC [Plan_ReportNTSCOAString_Rpt_sp] '2018/2019'
-- 06-04-2016 SN modify left outer joins of Const_SCOA_Function_Structure and Const_SCOA_Regional_Structure with Plan_projectItems as previously it was with Plan_project
-- 2016-04-28 TP36127   Ravindra Jijotia:	Change fin totals from INT to BIGINT
-- 2016-05-04 SN : As per discussion with RC : Fix the issue for ORGB,IBY1,IBY2; As of now, Project items have budgets only for curr year and next two years and that three are saving in single row, So thats
-- why there is need to apply while loop.
-- 2016-05-25 RC : Budget values for years where multiplied by 12. Fund string and cost string was not displayed correctly for months
-- 2016-06-14 RC/SN : Change format of casting of Amounts to --> CAST(ROUND(SUM(pim.UnitPrice),0) AS BIGINT)
-- 23-06-2016 SNagpal : As per discussion with Raindree, Need to Add 'Having clause' to avoid non Zero amount in output
-- 24-06-2016 SNagpal : Remove Fin year from Where Clause, As it getting future years as well and apply AND [pi].FinYear = @FinancialYear
-- 28-06-2016 SNagpal #38901: As per gansen Request, Remove Budget Column, Use NTScoaID instead on ScoaCode for all Scoa segments,Negative amts for revenue, Remove Unwanted Code.
-- 18-11-2016 Rchetty/SNagpal: exclude deleted projects
-- SNagpal 22/11/2016: Getting SCOACostingId from Plan_ProjectItem Table instead of Plan_Project
-- 13 02 2017 RChetty: added FinYearStartMonth
-- 23 02 2017 SNagpal: Add ID in select list
-- 27 02 2017 SNagpal: Append p.Project_ID to SCOAProjectIDGUID
-- 01/03/2017 RChetty: scoa guids in lower case as per NT
-- 02/03/2017 Rchetty: demarcation is now 6 varchar
-- 06/03/2017 RChetty: New NT string format required - 53378
-- 04/04/2017 RChetty: Only show Project ID if breakdown allowed on SCOA project segment
-- 17/05/2017 SNagpal: #56497 Change the Sort Order of NTSCOA String. It should be TABB > TM > ITY1 > ITY2
-- 19/05/2017 SNagpal: #57032 Allowed -ve Budget amounts as per management request
-- 23/05/2017 Rchetty: error with conditions on Y1 and Y2 case
-- 24/05/2017 SNagpal: #57032 Fix case statement
-- 29/05/2017 RChetty: #57032 Issue with group by having CapitalOperation flag
-- 22/06/2017 SNagpal: #58698 - Add logic to change sign for CreditDebit if ppi.CreditDebit = 'C'
-- 18/07/2017 SNagpal: #58698 - Add logic to change sign for CreditDebit if ppi.CreditDebit = 'C' in case of months As well
-- 24-01-2019 SNagpal: #61596 - #83633 - Add functionality to get ProjectCode
-- 21-02-2019: SNagpal: #84009, Get SCOA Segments based upon FinYear
-- OShiri 28-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- 25-06-2019 CMoodley: #90808, Handle instance where ProjectCode is null - default to Project_ID
-- 30-11-2019 CMoodley: 24526 - Exclude projects that are not for NT reporting
-- 31-03-2022 CMoodley: 85440 - Include validation as per other strings
-- 17-10-2023 CMoodley: 107216 - Use consolidated SCOA tables
-- [Plan_ReportNTSCOAString_Rpt_sp] '2022/2023'
-- =======================================================================================================================================
CREATE PROCEDURE [dbo].[Plan_ReportNTSCOAString_Rpt_sp] 
	-- Add the parameters for the stored procedure here
    @FinancialYear NVARCHAR(9) 

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from interfering with SELECT statements.
    SET NOCOUNT ON;

    DECLARE @FinYearStartMonth INT = 7;
	SELECT @FinYearStartMonth = CAST(KeyValue AS INT) from AAAA_ConfigSettings where KeyName='FinYearStartMonth'

	SELECT ScoaID, BreakDownAllowed, NTScoaID INTO #projectTable FROM Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @FinancialYear
	SELECT ScoaID, BreakDownAllowed, NTScoaID  INTO #functionTable FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @FinancialYear
	SELECT ScoaID, BreakDownAllowed, NTScoaID, ScoaCode INTO #itemTable FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @FinancialYear
	SELECT ScoaID, BreakDownAllowed, NTScoaID INTO #fundsTable FROM Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @FinancialYear
	SELECT ScoaID, BreakDownAllowed, NTScoaID INTO #costingTable FROM Const_SCOA_Costing_Structure_Consolidated WHERE FinYearText = @FinancialYear
	SELECT ScoaID, BreakDownAllowed, NTScoaID INTO #regionalTable FROM Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @FinancialYear

	DECLARE @tempValidations TABLE
        (
			[ExceptionDetail] VARCHAR(500),
			[ProjectID] VARCHAR(500),
			[ProjectItemID] VARCHAR(500)
        );

	INSERT INTO @tempValidations
	EXEC Plan_NTORGBudgetValidations @FinancialYear

	DECLARE @tempScoaString TABLE
		(
			Id INT IDENTITY(1, 1),
			SCOAString VARCHAR(800)
		);
			 
	DECLARE @Startcount INT = 1 ,@Totalcount INT = 2;

		IF (SELECT COUNT(ExceptionDetail) FROM @tempValidations ) <> 0 
		BEGIN 

			INSERT  INTO @tempScoaString
			SELECT 'NT Exception Detail|Project Detail|Project Item Detail'

			INSERT  INTO @tempScoaString
			SELECT
				( ExceptionDetail
				+ '|' + ProjectID
				+ '|' + ProjectItemID
				) AS Exceptiondetails
				FROM @tempValidations         
		END
		ELSE   	 
		BEGIN
			INSERT  INTO @tempScoaString
            SELECT  
				(MunicipalityNo 
				+ '|' + Finyear
				+ '|' + TypeStr
				+ '|' + SCOAProject 
				+ '|' + SCOAFunction 
				+ '|' + SCOAItem 
				+ '|' + SCOAFund 
				+ '|' + SCOACosting
				+ '|' + SCOARegion 
				+ '|' + CAST(CAST(ROUND(SUM(BudgetAmount),0) AS BIGINT) AS VARCHAR(40)) ) AS SCOAString
				FROM
				(
				SELECT  CAST(( SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) as MunicipalityNo,
				CAST(SUBSTRING(@FinancialYear, 6, 4) AS VARCHAR(4)) as Finyear,
						'TABB' as TypeStr, p.SCOAProject,			 
						LOWER(CAST(ISNULL(scoaf.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFunction,
						LOWER(CAST(ISNULL(scoai.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAItem,
						LOWER(CAST(ISNULL(scoafnd.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFund,
						LOWER(CAST(ISNULL(scoac.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOACosting,
						LOWER(CAST(ISNULL(scoar.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOARegion,
						scoai.ScoaCode
						,( CASE WHEN (((scoai.ScoaCode LIKE 'IR%' OR scoai.ScoaCode LIKE 'IL%') AND p.CapitalOperation in (0,1,2)) OR [pi].CreditDebit = 'C')
						THEN -[pi].BudgetAmount ELSE [pi].BudgetAmount END ) as BudgetAmount
						FROM   dbo.Plan_ProjectItem AS [pi]
						LEFT OUTER JOIN (SELECT LOWER(CAST(ISNULL(scoap.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))
												+ CASE WHEN (scoap.BreakDownAllowed='Yes') 
													THEN '_' + right('00000'+CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS NVARCHAR(10)), 5)
													ELSE ''
													END )  AS SCOAProject, 
													pp.Project_ID, 
													pp.IsDeleted, pp.CapitalOperation  
										FROM  dbo.Plan_Project AS pp
										LEFT OUTER JOIN  #projectTable AS scoap ON scoap.ScoaID = pp.ScoaProjectID) AS p 
						ON p.Project_ID = [pi].ProjectID
						LEFT OUTER JOIN #functionTable AS scoaf ON scoaf.ScoaID = [pi].SCOAFunctionId
						LEFT OUTER JOIN #itemTable AS scoai ON scoai.ScoaID = [pi].SCOAItemID
						LEFT OUTER JOIN #fundsTable AS scoafnd ON scoafnd.ScoaID = [pi].SCOAFundId
						LEFT OUTER JOIN #costingTable AS scoac ON scoac.ScoaID = [pi].SCOACostingID
						LEFT OUTER JOIN #regionalTable AS scoar ON scoar.ScoaID = [pi].SCOARegionId
					WHERE   pi.FinYear IS NOT NULL
						AND [pi].FinYear = @FinancialYear 
						AND ISNULL(p.IsDeleted,0) = 0
						AND p.Project_ID NOT IN (SELECT ProjectID FROM dbo.Plan_ProjectReportExclude)
				) as pp
			GROUP BY
			MunicipalityNo,Finyear,TypeStr,SCOAProject,SCOAFunction,SCOAItem, SCOAFund,SCOACosting, SCOARegion,ScoaCode 
			HAVING  CAST(ROUND(SUM([BudgetAmount]), 0) AS BIGINT) <> 0
			ORDER BY FinYear; 
						
			INSERT  INTO @tempScoaString
			SELECT  
				(MunicipalityNo 
				+ '|' + Finyear
				+ '|' + TypeStr
				+ '|' + SCOAProject 
				+ '|' + SCOAFunction 
				+ '|' + SCOAItem 
				+ '|' + SCOAFund 
				+ '|' + SCOACosting
				+ '|' + SCOARegion 
				+ '|' + CAST(CAST(ROUND(SUM(UnitPrice),0) AS BIGINT) AS VARCHAR(40))) AS SCOAString
				FROM
				(
					SELECT CAST(( SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) as MunicipalityNo,
						CAST(SUBSTRING(@FinancialYear, 6, 4) AS VARCHAR(4)) as Finyear,
						CAST(( CASE mon.Month_ID
								WHEN 1 THEN 'TM01'
								WHEN 2 THEN 'TM02'
								WHEN 3 THEN 'TM03'
								WHEN 4 THEN 'TM04'
								WHEN 5 THEN 'TM05'
								WHEN 6 THEN 'TM06'
								WHEN 7 THEN 'TM07'
								WHEN 8 THEN 'TM08'
								WHEN 9 THEN 'TM09'
								WHEN 10 THEN 'TM10'
								WHEN 11 THEN 'TM11'
								WHEN 12 THEN 'TM12'
								ELSE 'Y'
								END ) AS VARCHAR(4))  as TypeStr,
						p.SCOAProject,
						LOWER(CAST(ISNULL(scoaf.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFunction,
						LOWER(CAST(ISNULL(scoai.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAItem,
						LOWER(CAST(ISNULL(scoafnd.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFund,
						LOWER(CAST(ISNULL(scoac.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOACosting,
						LOWER(CAST(ISNULL(scoar.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOARegion,
						CASE WHEN (((scoai.ScoaCode LIKE 'IR%'  OR scoai.ScoaCode LIKE 'IL%') AND p.CapitalOperation in (0,1,2))
										OR [pi].CreditDebit = 'C')	
										THEN	-pim.UnitPrice
										ELSE pim.UnitPrice
						END AS UnitPrice
					FROM     Plan_ProjectItemMonth AS pim
							LEFT JOIN  YearStartingAtMonth_fxn(@FinYearStartMonth) mon ON pim.MonthID=mon.SysMonthID
							LEFT OUTER JOIN  Plan_ProjectItem AS [pi] ON [pi].PlanProjectItem_ID = pim.PlanProjectItemID
							LEFT OUTER JOIN (SELECT LOWER(CAST(ISNULL(scoap.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))
									+ CASE WHEN (scoap.BreakDownAllowed='Yes') 
										THEN '_' + right('00000'+CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS NVARCHAR(10)), 5)
										ELSE ''
										END )  AS SCOAProject, pp.Project_ID, pp.IsDeleted ,pp.CapitalOperation
										FROM  Plan_Project AS pp
										LEFT OUTER JOIN  #projectTable AS scoap ON scoap.ScoaID = pp.ScoaProjectID
										) AS p ON p.Project_ID = [pi].ProjectID
							LEFT OUTER JOIN #functionTable AS scoaf ON scoaf.ScoaID = [pi].SCOAFunctionId
							LEFT OUTER JOIN #itemTable AS scoai ON scoai.ScoaID = [pi].SCOAItemID
							LEFT OUTER JOIN #fundsTable AS scoafnd ON scoafnd.ScoaID = [pi].SCOAFundId
							LEFT OUTER JOIN #costingTable AS scoac ON scoac.ScoaID = [pi].SCOACostingID
							LEFT OUTER JOIN #regionalTable AS scoar ON scoar.ScoaID = [pi].SCOARegionId 
					WHERE   [pi].FinYear IS NOT NULL
							AND [pi].FinYear = + @FinancialYear
							AND ISNULL(p.IsDeleted,0) = 0
							AND p.Project_ID NOT IN (SELECT ProjectID FROM dbo.Plan_ProjectReportExclude)
				) as pp
			GROUP BY
			MunicipalityNo,Finyear,TypeStr,SCOAProject,SCOAFunction,SCOAItem, SCOAFund,SCOACosting, SCOARegion
			HAVING  CAST(ROUND(SUM(UnitPrice), 0) AS BIGINT) <> 0
			ORDER BY FinYear,TypeStr; 

		--ITY1 and ITY2
		WHILE ( @Startcount <= @Totalcount )
		BEGIN
			INSERT  INTO @tempScoaString
			SELECT  
				(MunicipalityNo 
				+ '|' + Finyear
				+ '|' + TypeStr
				+ '|' + SCOAProject 
				+ '|' + SCOAFunction 
				+ '|' + SCOAItem 
				+ '|' + SCOAFund 
				+ '|' + SCOACosting
				+ '|' + SCOARegion 
				+ '|' +  CAST(CAST(ROUND(SUM(BudgetAmount),0) AS BIGINT) AS VARCHAR(40))) AS SCOAString
			FROM 
				(
					SELECT  CAST(( SELECT MunicipalityNo FROM  Payroll_Municipality) AS VARCHAR(6)) as MunicipalityNo,
						CAST(SUBSTRING(@FinancialYear, 6, 4) AS VARCHAR(4)) as Finyear,
						CAST(( CASE WHEN ( @Startcount = 0 ) THEN 'TABB' 
						WHEN ( @Startcount = 1 ) THEN 'ITY1'
						WHEN ( @Startcount = 2 ) THEN 'ITY2'END ) AS VARCHAR(4)) AS TypeStr,
						p.SCOAProject,
						LOWER(CAST(ISNULL(scoaf.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFunction,
						LOWER(CAST(ISNULL(scoai.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAItem,
						LOWER(CAST(ISNULL(scoafnd.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFund,
						LOWER(CAST(ISNULL(scoac.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOACosting,
						LOWER(CAST(ISNULL(scoar.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOARegion,
						CASE WHEN ( @Startcount = 0 ) AND (((scoai.ScoaCode LIKE 'IR%' OR scoai.ScoaCode LIKE 'IL%' ) AND p.CapitalOperation in (0,1,2)) OR [pi].CreditDebit = 'C')
						THEN -[pi].BudgetAmount
						WHEN ( @Startcount = 0 ) AND (scoai.ScoaCode NOT LIKE 'IR%' AND scoai.ScoaCode NOT LIKE 'IL%')
						THEN [pi].BudgetAmount
						WHEN ( @Startcount = 0 ) AND p.CapitalOperation in (0,1,2,3,4)
						THEN [pi].BudgetAmount
						WHEN ( @Startcount = 1 ) 
						AND (((scoai.ScoaCode LIKE 'IR%'  OR scoai.ScoaCode LIKE 'IL%') AND p.CapitalOperation in (0,1,2))
						OR [pi].CreditDebit = 'C')
						THEN -[pi].BudgetAmountCurP1
						WHEN ( @Startcount = 1 ) 
						AND (scoai.ScoaCode NOT LIKE 'IR%' AND scoai.ScoaCode NOT LIKE 'IL%')
						THEN [pi].BudgetAmountCurP1
						WHEN ( @Startcount = 1 ) AND p.CapitalOperation in (0,1,2,3,4)
						THEN [pi].BudgetAmountCurP1
						WHEN ( @Startcount = 2 ) AND (((scoai.ScoaCode LIKE 'IR%' OR scoai.ScoaCode LIKE 'IL%' ) AND p.CapitalOperation in (0,1,2)) OR [pi].CreditDebit = 'C')
						THEN -[pi].BudgetAmountCurP2
						WHEN ( @Startcount = 2 ) 
						AND (scoai.ScoaCode NOT LIKE 'IR%' AND scoai.ScoaCode NOT LIKE 'IL%')
						THEN [pi].BudgetAmountCurP2
						WHEN ( @Startcount = 2 ) AND p.CapitalOperation in (0,1,2,3,4)
						THEN [pi].BudgetAmountCurP2 END AS BudgetAmount FROM  Plan_ProjectItem AS [pi]
						LEFT OUTER JOIN (SELECT LOWER(CAST(ISNULL(scoap.NTScoaID, '00000000-0000-0000-0000-000000000000') AS VARCHAR(50)) + CASE WHEN (scoap.BreakDownAllowed='Yes') THEN '_' + right('00000'+CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS NVARCHAR(10)), 5)
						ELSE '' END )  AS SCOAProject, pp.Project_ID, pp.IsDeleted ,pp.CapitalOperation 
					FROM  Plan_Project AS pp
						LEFT OUTER JOIN  #projectTable AS scoap ON scoap.ScoaID = pp.ScoaProjectID) AS p ON p.Project_ID = [pi].ProjectID
						LEFT OUTER JOIN #functionTable AS scoaf ON scoaf.ScoaID = [pi].SCOAFunctionId 
						LEFT OUTER JOIN #itemTable AS scoai ON scoai.ScoaID = [pi].SCOAItemID
						LEFT OUTER JOIN #fundsTable AS scoafnd ON scoafnd.ScoaID = [pi].SCOAFundId
						LEFT OUTER JOIN #costingTable AS scoac ON scoac.ScoaID = [pi].SCOACostingID
						LEFT OUTER JOIN #regionalTable AS scoar ON scoar.ScoaID = [pi].SCOARegionId 
					WHERE   
						pi.FinYear IS NOT NULL AND [pi].FinYear = @FinancialYear  AND ISNULL(p.IsDeleted,0) = 0
						AND pi.ProjectID NOT IN (SELECT ProjectID FROM dbo.Plan_ProjectReportExclude)
				) AS prev
			GROUP BY MunicipalityNo,Finyear,TypeStr,SCOAProject,SCOAFunction,SCOAItem, SCOAFund,SCOACosting, SCOARegion
			HAVING  CAST(ROUND(SUM(BudgetAmount), 0) AS BIGINT) <> 0
			ORDER BY FinYear
			SET @Startcount = @Startcount + 1;
		END; 
	END;

	SELECT Id, SCOAString
    FROM    @tempScoaString
    WHERE   SCOAString IS NOT NULL
    ORDER BY Id

	DROP TABLE #projectTable
	DROP TABLE #functionTable
	DROP TABLE #itemTable
	DROP TABLE #fundsTable
	DROP TABLE #costingTable
	DROP TABLE #regionalTable

	--PRINT (@SQLtextMainDiv + @SQLtextSecPart)
	--PRINT (@SQLtextThirPart + @SQLtextLastPart)
   
END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_ReportNTSCOAString_Rpt_sp_backup]    Script Date: 2026/03/10 7:23:47 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- ======================================================================================================================================
-- Author:		James Roodt
-- Create date: 2015-05-21
-- Description:	
-- 2015-06-05 TP20442 & 20441 James Roodt: Added financial year filter, Also removed 3 columns. also combined 4 scoa item columns into 1
-- 2015-06-09 TP20441 James Roodt: Added column to denote project Number and project Name. Also adding summing the values 
-- 2015-06-25 TP13080\20011 Ravindra Jijotia: Added new columns to display descriptions & Municipal Standard Classification
-- 2015-07-08 TP21915	Ravindra Jijotia:	Updated NT SCOA String report with new changes as requested by NT
-- 2015-08-03 TP21915	Ravindra Jijotia:	Updated NT SCOA String report to use code instead of GUID.
-- 2015-08-04 TP21915	Ravindra Jijotia:	Updated NT SCOA String report to display records for next five years.
-- 2015-08-26 TP21915	Ravindra Jijotia:	Updated NT SCOA String report to display records grouped by fin year & scoa codes.
-- 2015-11-27 Critical	Ravindra Jijotia:	Change in Funding Code, Costing Code, Project Code and amounts must be rounded off – no decimal places.
-- EXEC [Plan_ReportNTSCOAString_Rpt_sp] '2017/2018'
-- 06-04-2016 SN modify left outer joins of Const_SCOA_Function_Structure and Const_SCOA_Regional_Structure with Plan_projectItems as previously it was with Plan_project
-- 2016-04-28 TP36127   Ravindra Jijotia:	Change fin totals from INT to BIGINT
-- 2016-05-04 SN : As per discussion with RC : Fix the issue for ORGB,IBY1,IBY2; As of now, Project items have budgets only for curr year and next two years and that three are saving in single row, So thats
-- why there is need to apply while loop.
-- 2016-05-25 RC : Budget values for years where multiplied by 12. Fund string and cost string was not displayed correctly for months
-- 2016-06-14 RC/SN : Change format of casting of Amounts to --> CAST(ROUND(SUM(pim.UnitPrice),0) AS BIGINT)
-- 23-06-2016 SNagpal : As per discussion with Raindree, Need to Add 'Having clause' to avoid non Zero amount in output
-- 24-06-2016 SNagpal : Remove Fin year from Where Clause, As it getting future years as well and apply AND [pi].FinYear = @FinancialYear
-- 28-06-2016 SNagpal #38901: As per gansen Request, Remove Budget Column, Use NTScoaID instead on ScoaCode for all Scoa segments,Negative amts for revenue, Remove Unwanted Code.
-- 18-11-2016 Rchetty/SNagpal: exclude deleted projects
-- SNagpal 22/11/2016: Getting SCOACostingId from Plan_ProjectItem Table instead of Plan_Project
-- 13 02 2017 RChetty: added FinYearStartMonth
-- 23 02 2017 SNagpal: Add ID in select list
-- 27 02 2017 SNagpal: Append p.Project_ID to SCOAProjectIDGUID
-- 01/03/2017 RChetty: scoa guids in lower case as per NT
-- 02/03/2017 Rchetty: demarcation is now 6 varchar
-- 06/03/2017 RChetty: New NT string format required - 53378
-- 04/04/2017 RChetty: Only show Project ID if breakdown allowed on SCOA project segment
-- =======================================================================================================================================
CREATE PROCEDURE [dbo].[Plan_ReportNTSCOAString_Rpt_sp_backup]
	-- Add the parameters for the stored procedure here
    @FinancialYear NVARCHAR(9) 
	--@p2 int = 0
AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;


        DECLARE @Startcount INT = 0 ,
			@FinYearStartMonth INT=7,
            @Totalcount INT = 2;

			SELECT @FinYearStartMonth = CAST(KeyValue AS INT) from AAAA_ConfigSettings where KeyName='FinYearStartMonth'

        DECLARE @tempScoaString TABLE
            (
              Id INT IDENTITY(1, 1) ,
              SCOAString VARCHAR(800)
            );

        WHILE ( @Startcount <= @Totalcount )
            BEGIN

                INSERT  INTO @tempScoaString
                        SELECT  CAST(( SELECT   MunicipalityNo
                                       FROM     Payroll_Municipality
                                     ) AS VARCHAR(6)) + '|'
                                + CAST(SUBSTRING(@FinancialYear, 6, 4) AS VARCHAR(4))
                                + '|'
                                + CAST(( CASE WHEN ( @Startcount = 0 )
                                              THEN 'TABB'
                                              WHEN ( @Startcount = 1 )
                                              THEN 'ITY1'
                                              WHEN ( @Startcount = 2 )
                                              THEN 'ITY2'
                                         END ) AS VARCHAR(4)) + '|'

                                -- + CAST(ISNULL(scoap.ScoaCode, '') AS VARCHAR(40)) + '|' -- Project Code
							    -- + CAST(ISNULL(scoaf.ScoaCode, '') AS VARCHAR(40)) + '|'
                                -- + CAST(ISNULL(scoai.ScoaCode, '') AS VARCHAR(40)) + '|'
                                -- + CAST(STUFF(ISNULL(scoafnd.ScoaCode, 'F006000000000000000000000000000000000'), 1, 1, 'F') AS VARCHAR(40)) + '|' -- Fund
                                -- + CAST(STUFF(ISNULL(scoac.ScoaCode, 'C004000000000000000000000000000000000'), 1, 1, 'C') AS VARCHAR(40)) + '|'
                                -- + CAST(ISNULL(scoar.ScoaCode, '') AS VARCHAR(40)) + '|'
                                + 
								p.SCOAProject
								--LOWER(CAST(ISNULL(scoap.NTScoaID,
        --                                      '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))
        --                        + CASE WHEN (scoap.BreakDownAllowed='Yes') 
								--  THEN '_' + right('00000'+CAST(p.Project_ID AS NVARCHAR(10)), 5)
								--  ELSE ''
								-- END )
								 
								 + '|' -- Project Code 
                                + LOWER(CAST(ISNULL(scoaf.NTScoaID,
                                              '00000000-0000-0000-0000-000000000000') AS VARCHAR(50)))
                                + '|'
                                + LOWER(CAST(ISNULL(scoai.NTScoaID,
                                              '00000000-0000-0000-0000-000000000000') AS VARCHAR(50)))
                                + '|'
                                + LOWER(CAST(ISNULL(scoafnd.NTScoaID,
                                                    '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) + '|' -- Fund
                                + LOWER(CAST(ISNULL(scoac.NTScoaID,
                                                    '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) + '|'
                                + LOWER(CAST(ISNULL(scoar.NTScoaID,
                                              '00000000-0000-0000-0000-000000000000') AS VARCHAR(50)))
                                + '|'
                                + LOWER(CAST(( CASE WHEN ( @Startcount = 0 )
                                                   AND ( (scoai.ScoaCode LIKE 'IR%' ) OR (scoai.ScoaCode LIKE 'IL%'))
                                              THEN '-'
                                                   + CAST(CAST(ROUND(SUM([pi].BudgetAmount),
                                                              0) AS BIGINT) AS VARCHAR(40))
                                              WHEN ( @Startcount = 0 )
                                                  AND  (scoai.ScoaCode NOT LIKE 'IR%' ) AND (scoai.ScoaCode NOT LIKE 'IL%')
                                              THEN CAST(ROUND(SUM([pi].BudgetAmount),
                                                              0) AS BIGINT)
                                              WHEN ( @Startcount = 1 )
                                                   AND ( (scoai.ScoaCode LIKE 'IR%' ) OR (scoai.ScoaCode LIKE 'IL%'))
                                              THEN '-'
                                                   + CAST(CAST(ROUND(SUM([pi].BudgetAmountCurP1),
                                                              0) AS BIGINT) AS VARCHAR(40))
                                              WHEN ( @Startcount = 1 )
                                                   AND  (scoai.ScoaCode NOT LIKE 'IR%' ) AND (scoai.ScoaCode NOT LIKE 'IL%')
                                              THEN CAST(ROUND(SUM([pi].BudgetAmountCurP1),
                                                              0) AS BIGINT)
                                              WHEN ( @Startcount = 2 )
                                                   AND ( (scoai.ScoaCode LIKE 'IR%' ) OR (scoai.ScoaCode LIKE 'IL%'))
                                              THEN '-'
                                                   + CAST(CAST(ROUND(SUM([pi].BudgetAmountCurP2),
                                                              0) AS BIGINT) AS VARCHAR(40))
                                              WHEN ( @Startcount = 2 )
                                                  AND  (scoai.ScoaCode NOT LIKE 'IR%' ) AND (scoai.ScoaCode NOT LIKE 'IL%')
                                              THEN CAST(ROUND(SUM([pi].BudgetAmountCurP2),
                                                              0) AS BIGINT)
                                         END ) AS VARCHAR(40))) AS SCOAString
                        FROM    Plan_ProjectItem AS [pi]
                                LEFT OUTER JOIN (SELECT LOWER(CAST(ISNULL(scoap.NTScoaID,
                                              '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))
                                + CASE WHEN (scoap.BreakDownAllowed='Yes') 
								  THEN '_' + right('00000'+CAST(pp.Project_ID AS NVARCHAR(10)), 5)
								  ELSE ''
								 END )  AS SCOAProject, pp.Project_ID, pp.IsDeleted from Plan_Project AS pp
                                LEFT OUTER JOIN Const_SCOA_Project_Structure
                                AS scoap ON scoap.ScoaID = pp.ScoaProjectID) AS p ON p.Project_ID = [pi].ProjectID
                                LEFT OUTER JOIN Const_SCOA_Function_Structure
                                AS scoaf ON scoaf.ScoaID = [pi].SCOAFunctionId --rain added pi
                                LEFT OUTER JOIN Const_SCOA_Structure AS scoai ON scoai.ScoaID = [pi].SCOAItemID
		--note that for now we simply return the first funding code found but multiple funding codes are possible.
		--however then this query's structure will need to be updated
                                LEFT OUTER JOIN Const_SCOA_Funds_Structure AS scoafnd ON scoafnd.ScoaID = [pi].SCOAFundId
                                LEFT OUTER JOIN Const_SCOA_Costing_Structure
                                AS scoac ON scoac.ScoaID = [pi].SCOACostingID
                                LEFT OUTER JOIN Const_SCOA_Regional_Structure
                                AS scoar ON scoar.ScoaID = [pi].SCOARegionId --rain added pi
                        WHERE   pi.FinYear IS NOT NULL
                                AND [pi].FinYear = @FinancialYear
								AND ISNULL(p.IsDeleted,0) = 0
                        GROUP BY [pi].FinYear ,
                                --p.Project_ID ,
                                --p.ProjectName ,
                                --scoap.ScoaCode ,
                                --scoaf.ScoaCode ,
                                scoai.ScoaCode ,
                                --scoafnd.ScoaCode ,
                                --scoac.ScoaCode ,
                                --scoar.ScoaCode
								p.SCOAProject,
                                --scoap.NTScoaID ,
								--scoap.BreakDownAllowed,
                                scoaf.NTScoaID ,
                                scoai.NTScoaID ,
                                scoafnd.NTScoaID ,
                                scoac.NTScoaID ,
                                scoar.NTScoaID
                        HAVING  ( CASE WHEN ( @Startcount = 0 )
                                       THEN CAST(ROUND(SUM([pi].BudgetAmount),
                                                       0) AS BIGINT)
                                       WHEN ( @Startcount = 1 )
                                       THEN CAST(ROUND(SUM([pi].BudgetAmountCurP1),
                                                       0) AS BIGINT)
                                       WHEN ( @Startcount = 2 )
                                       THEN CAST(ROUND(SUM([pi].BudgetAmountCurP2),
                                                       0) AS BIGINT)
                                  END ) > 0
                        ORDER BY pi.FinYear;

                SET @Startcount = @Startcount + 1;
            END;

	--Month wise

        INSERT  INTO @tempScoaString
                SELECT  CAST(( SELECT   MunicipalityNo
                               FROM     Payroll_Municipality
                             ) AS VARCHAR(6)) + '|'
                        + CAST(SUBSTRING(pi.FinYear, 6, 4) AS VARCHAR(4))
                        + '|' 
						--+ CAST('Budget' AS VARCHAR(6)) + '|'
                        + CAST(( CASE mon.Month_ID
                                   WHEN 1 THEN 'TM01'
                                   WHEN 2 THEN 'TM02'
                                   WHEN 3 THEN 'TM03'
                                   WHEN 4 THEN 'TM04'
                                   WHEN 5 THEN 'TM05'
                                   WHEN 6 THEN 'TM06'
                                   WHEN 7 THEN 'TM07'
                                   WHEN 8 THEN 'TM08'
                                   WHEN 9 THEN 'TM09'
                                   WHEN 10 THEN 'TM10'
                                   WHEN 11 THEN 'TM11'
                                   WHEN 12 THEN 'TM12'
                                   ELSE 'Y'
                                 END ) AS VARCHAR(4)) + '|'
                        -- + CAST(ISNULL(scoap.ScoaCode, '') AS VARCHAR(40))-- Project Code
                        -- + '|' + CAST(ISNULL(scoaf.ScoaCode, '') AS VARCHAR(40)) + '|'
                        -- + CAST(ISNULL(scoai.ScoaCode, '') AS VARCHAR(40)) + '|'
                        -- + CAST(STUFF(ISNULL(scoafnd.ScoaCode,'F006000000000000000000000000000000000'), 1, 1, 'F') AS VARCHAR(40)) + '|' -- Fund
						-- + CAST(STUFF(ISNULL(scoac.ScoaCode, 'C004000000000000000000000000000000000'), 1, 1, 'C') AS VARCHAR(40)) + '|' -- Costing 
						-- + CAST(ISNULL(scoar.ScoaCode, '') AS VARCHAR(40)) + '|'
						+ p.SCOAProject
						--LOWER(CAST(ISNULL(scoap.NTScoaID,
      --                      '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))
      --                      + CASE WHEN (scoap.BreakDownAllowed='Yes') THEN '_' + right('00000'+CAST(p.Project_ID AS NVARCHAR(10)), 5)  ELSE '' END ) -- Project Code 
                        + '|'
                        + LOWER(CAST(ISNULL(scoaf.NTScoaID,
                                      '00000000-0000-0000-0000-000000000000') AS VARCHAR(50)))
                        + '|'
                        + LOWER(CAST(ISNULL(scoai.NTScoaID,
                                      '00000000-0000-0000-0000-000000000000') AS VARCHAR(50)))
                        + '|'
                        + LOWER(CAST(ISNULL(scoafnd.NTScoaID,
                                            '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) + '|' -- Fund
                        + LOWER(CAST(ISNULL(scoac.NTScoaID,
                                            '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) + '|' -- Costing 
                        + LOWER(CAST(ISNULL(scoar.NTScoaID,
                                      '00000000-0000-0000-0000-000000000000') AS VARCHAR(40)))
                        + '|'
                        + LOWER(CAST(CASE WHEN (( scoai.ScoaCode LIKE 'IR%' ) OR (scoai.ScoaCode LIKE 'IL%'))
                       THEN						
						--CAST(ROUND(SUM(pim.UnitPrice), 0) AS BIGINT)
                                         '-'
                                         + CAST(CAST(ROUND(SUM(pim.UnitPrice),
                                                           0) AS BIGINT) AS VARCHAR(40))
                                    ELSE CAST(ROUND(SUM(pim.UnitPrice), 0) AS BIGINT)
                               END AS VARCHAR(40))) AS SCOAString
                FROM    Plan_ProjectItemMonth AS pim
						LEFT JOIN YearStartingAtMonth_fxn(@FinYearStartMonth) mon ON pim.MonthID=mon.SysMonthID
                        LEFT OUTER JOIN Plan_ProjectItem AS [pi] ON [pi].PlanProjectItem_ID = pim.PlanProjectItemID
                        LEFT OUTER JOIN (SELECT LOWER(CAST(ISNULL(scoap.NTScoaID,
                                              '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))
                                + CASE WHEN (scoap.BreakDownAllowed='Yes') 
								  THEN '_' + right('00000'+CAST(pp.Project_ID AS NVARCHAR(10)), 5)
								  ELSE ''
								 END )  AS SCOAProject, pp.Project_ID, pp.IsDeleted from Plan_Project AS pp
                                LEFT OUTER JOIN Const_SCOA_Project_Structure
                                AS scoap ON scoap.ScoaID = pp.ScoaProjectID) AS p ON p.Project_ID = [pi].ProjectID
                        LEFT OUTER JOIN Const_SCOA_Function_Structure AS scoaf ON scoaf.ScoaID = [pi].SCOAFunctionId --rain added pi
                        LEFT OUTER JOIN Const_SCOA_Structure AS scoai ON scoai.ScoaID = [pi].SCOAItemID
		--note that for now we simply return the first funding code found but multiple funding codes are possible.
		--however then this query's structure will need to be updated
                        LEFT OUTER JOIN Const_SCOA_Funds_Structure AS scoafnd ON scoafnd.ScoaID = [pi].SCOAFundId
                        LEFT OUTER JOIN Const_SCOA_Costing_Structure AS scoac ON scoac.ScoaID = [pi].SCOACostingID
                        LEFT OUTER JOIN Const_SCOA_Regional_Structure AS scoar ON scoar.ScoaID = [pi].SCOARegionId --rain added pi
                WHERE   [pi].FinYear IS NOT NULL
                        AND [pi].FinYear = @FinancialYear
						AND ISNULL(p.IsDeleted,0) = 0
                GROUP BY pim.MonthID ,
						mon.Month_ID,
                        pi.FinYear ,
                        --p.Project_ID ,
                        --p.ProjectName ,
                        --scoap.ScoaCode ,
                        --scoaf.ScoaCode ,
                        scoai.ScoaCode ,
                        --scoafnd.ScoaCode ,
                        --scoac.ScoaCode ,
                        --scoar.ScoaCode
                        --scoap.NTScoaID ,
						--scoap.BreakDownAllowed,
						p.SCOAProject,
                        scoaf.NTScoaID ,
                        scoai.NTScoaID ,
                        scoafnd.NTScoaID ,
                        scoac.NTScoaID ,
                        scoar.NTScoaID
                HAVING CAST(ROUND(SUM(pim.UnitPrice),0) AS BIGINT) > 0
                ORDER BY pi.FinYear,mon.Month_ID;

-- SELECT ScoaID AS ID, ScoaDesc AS SCOAString FROM Const_SCOA_Funds_Structure
  SELECT Id, SCOAString
        FROM    @tempScoaString
        WHERE   SCOAString IS NOT NULL
        ORDER BY Id;
    END;
GO

