-- 03-19-2020 CMoodley: 44383 - Return budget from original budget tables if ORGB version exists, else look at CURB tables
-- 17-10-2023 CMoodley: 107216 - Use consolidated SCOA tables
-- [dbo].[Plan_ReportNTSCOAStringORGB_Rpt_sp] '2022/2023'
-- =======================================================================================================================================
CREATE PROCEDURE [dbo].[Plan_ReportNTSCOAStringORGB_Rpt_sp] 
	-- Add the parameters for the stored procedure here
    @FinancialYear NVARCHAR(9) 

AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.

	DECLARE @tempValidations TABLE
          (
			[ExceptionDetail] VARCHAR(500),
			[ProjectID] VARCHAR(500),
			[ProjectItemID] VARCHAR(500)
          );

    INSERT INTO @tempValidations
    EXEC Plan_NTORGBudgetValidations @FinancialYear

    DECLARE @FinYearStartMonth INT = 7;
	SELECT @FinYearStartMonth = CAST(KeyValue AS INT) from AAAA_ConfigSettings where KeyName='FinYearStartMonth'

	DECLARE @BudgetVersionID INT
	SELECT @BudgetVersionID = ISNULL(dbo.Section71_BudgetOriginalVersionID_fxn(@FinancialYear), -1)

	SELECT ScoaID, BreakDownAllowed, NTScoaID INTO #projectTable FROM Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @FinancialYear
	SELECT ScoaID, BreakDownAllowed, NTScoaID  INTO #functionTable FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @FinancialYear
	SELECT ScoaID, BreakDownAllowed, NTScoaID, ScoaCode INTO #itemTable FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @FinancialYear
	SELECT ScoaID, BreakDownAllowed, NTScoaID INTO #fundsTable FROM Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @FinancialYear
	SELECT ScoaID, BreakDownAllowed, NTScoaID INTO #costingTable FROM Const_SCOA_Costing_Structure_Consolidated WHERE FinYearText = @FinancialYear
	SELECT ScoaID, BreakDownAllowed, NTScoaID INTO #regionalTable FROM Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @FinancialYear

    DECLARE @tempScoaString TABLE (Id INT IDENTITY(1, 1) ,SCOAString VARCHAR(800));
	DECLARE @Startcount INT = 1, @Totalcount INT = 2;


	IF (SELECT COUNT(ExceptionDetail) FROM @tempValidations ) <> 0 

	BEGIN 

			INSERT  INTO @tempScoaString
			SELECT 'NT Exception Detail|Project Detail|Project Item Detail'

			INSERT  INTO @tempScoaString
			SELECT
				( ExceptionDetail
				+ '|' + ProjectID
				+ '|' + ProjectItemID
				) AS Exceptiondetails
				FROM @tempValidations
         
	END

	ELSE   
	 
    BEGIN
		
	IF (@BudgetVersionID <> -1)
	BEGIN

		SELECT * INTO #Plan_BudgetVersionDetail FROM Plan_BudgetVersionDetail WHERE BudgetVersionID = @BudgetVersionID
		SELECT * INTO #Plan_BudgetVersionMonths FROM Plan_BudgetVersionMonths WHERE BudgetVersionID = @BudgetVersionID

		INSERT  INTO @tempScoaString
		SELECT  
			(MunicipalityNo 
			+ '|' + Finyear
			+ '|' + TypeStr
			+ '|' + SCOAProject 
			+ '|' + SCOAFunction 
			+ '|' + SCOAItem 
			+ '|' + SCOAFund 
			+ '|' + SCOACosting
			+ '|' + SCOARegion 
			+ '|' + CAST(CAST(ROUND(SUM(BudgetAmount),0) AS BIGINT) AS VARCHAR(40)) ) AS SCOAString
		FROM
			(
				SELECT  CAST(( SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) as MunicipalityNo,
						CAST(SUBSTRING(@FinancialYear, 6, 4) AS VARCHAR(4)) as Finyear,
						'ORGB' as TypeStr, p.SCOAProject,			 
						LOWER(CAST(ISNULL(scoaf.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFunction,
						LOWER(CAST(ISNULL(scoai.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAItem,
						LOWER(CAST(ISNULL(scoafnd.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFund,
						LOWER(CAST(ISNULL(scoac.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOACosting,
						LOWER(CAST(ISNULL(scoar.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOARegion,
						scoai.ScoaCode
						,( CASE WHEN (((scoai.ScoaCode LIKE 'IR%' OR scoai.ScoaCode LIKE 'IL%') AND p.CapitalOperation in (0,1,2)) OR [ppi].CreditDebit = 'C')
						THEN -[pi].BudgetAmount ELSE [pi].BudgetAmount END ) as BudgetAmount
						FROM   #Plan_BudgetVersionDetail AS [pi]
						LEFT OUTER JOIN dbo.Plan_ProjectItem AS [ppi] ON [pi].PlanProjectItemID = [ppi].PlanProjectItem_ID
						LEFT OUTER JOIN (SELECT LOWER(CAST(ISNULL(scoap.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))
												+ CASE WHEN (scoap.BreakDownAllowed='Yes') 
													THEN '_' + right('00000'+CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS NVARCHAR(10)), 5)
													ELSE ''
													END )  AS SCOAProject, 
													pp.Project_ID, 
													pp.IsDeleted, pp.CapitalOperation  
										FROM  dbo.Plan_Project AS pp
										LEFT OUTER JOIN  #projectTable AS scoap ON scoap.ScoaID = pp.ScoaProjectID) AS p 
						ON p.Project_ID = [pi].ProjectID
						LEFT OUTER JOIN #functionTable AS scoaf ON scoaf.ScoaID = [pi].SCOAFunctionId
						LEFT OUTER JOIN #itemTable AS scoai ON scoai.ScoaID = [pi].SCOAItemID
						LEFT OUTER JOIN #fundsTable AS scoafnd ON scoafnd.ScoaID = [pi].SCOAFundId
						LEFT OUTER JOIN #costingTable AS scoac ON scoac.ScoaID = [pi].SCOACostingID
						LEFT OUTER JOIN #regionalTable AS scoar ON scoar.ScoaID = [pi].SCOARegionId
					WHERE   pi.FinYear IS NOT NULL
						AND [pi].FinYear =  @FinancialYear 
						AND ISNULL(p.IsDeleted,0) = 0
						AND p.Project_ID NOT IN (SELECT ProjectID FROM dbo.Plan_ProjectReportExclude)
			)as pp
		GROUP BY
		MunicipalityNo,Finyear,TypeStr,SCOAProject,SCOAFunction,SCOAItem, SCOAFund,SCOACosting, SCOARegion,ScoaCode 
		HAVING  CAST(ROUND(SUM([BudgetAmount]), 0) AS BIGINT) <> 0
		ORDER BY FinYear; 

		WHILE ( @Startcount <= @Totalcount )
		BEGIN
			INSERT  INTO @tempScoaString
			SELECT(MunicipalityNo 
					+ '|' + Finyear
					+ '|' + TypeStr
					+ '|' + SCOAProject 
					+ '|' + SCOAFunction 
					+ '|' + SCOAItem 
					+ '|' + SCOAFund 
					+ '|' + SCOACosting
					+ '|' + SCOARegion 
					+ '|' +  CAST(CAST(ROUND(SUM(BudgetAmount),0) AS BIGINT) AS VARCHAR(40))) AS SCOAString
			FROM  (SELECT  CAST(( SELECT MunicipalityNo FROM  Payroll_Municipality) AS VARCHAR(6)) as MunicipalityNo,
							CAST(SUBSTRING(@FinancialYear , 6, 4) AS VARCHAR(4)) as Finyear,
							CAST(( CASE WHEN ( @Startcount = 0 )
							THEN 'ORGB' WHEN ( @Startcount = 1 ) THEN 'IBY1'
							WHEN ( @Startcount = 2 ) THEN 'IBY2' END ) AS VARCHAR(4)) AS TypeStr,
							p.SCOAProject,
							LOWER(CAST(ISNULL(scoaf.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFunction,
							LOWER(CAST(ISNULL(scoai.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAItem,
							LOWER(CAST(ISNULL(scoafnd.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFund,
							LOWER(CAST(ISNULL(scoac.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOACosting,
							LOWER(CAST(ISNULL(scoar.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOARegion,
							CASE WHEN ( @Startcount = 0 ) AND (((scoai.ScoaCode LIKE 'IR%' OR scoai.ScoaCode LIKE 'IL%' ) AND p.CapitalOperation in (0,1,2)) OR [ppi].CreditDebit = 'C')
							THEN -[pi].BudgetAmount
							WHEN ( @Startcount = 0 ) AND (scoai.ScoaCode NOT LIKE 'IR%' AND scoai.ScoaCode NOT LIKE 'IL%')
							THEN [pi].BudgetAmount
							WHEN ( @Startcount = 0 ) AND p.CapitalOperation in (0,1,2,3,4)
							THEN [pi].BudgetAmount
							WHEN ( @Startcount = 1 ) 
							AND (((scoai.ScoaCode LIKE 'IR%'  OR scoai.ScoaCode LIKE 'IL%') AND p.CapitalOperation in (0,1,2))
							OR [ppi].CreditDebit = 'C')
							THEN -[pi].BudgetAmountCurP1
							WHEN ( @Startcount = 1 ) 
							AND (scoai.ScoaCode NOT LIKE 'IR%' AND scoai.ScoaCode NOT LIKE 'IL%')
							THEN [pi].BudgetAmountCurP1
							WHEN ( @Startcount = 1 ) AND p.CapitalOperation in (0,1,2,3,4)
							THEN [pi].BudgetAmountCurP1
							WHEN ( @Startcount = 2 ) AND (((scoai.ScoaCode LIKE 'IR%' OR scoai.ScoaCode LIKE 'IL%' ) AND p.CapitalOperation in (0,1,2)) OR [ppi].CreditDebit = 'C')
							THEN -[pi].BudgetAmountCurP2
							WHEN ( @Startcount = 2 ) 
							AND (scoai.ScoaCode NOT LIKE 'IR%' AND scoai.ScoaCode NOT LIKE 'IL%')
							THEN [pi].BudgetAmountCurP2
							WHEN ( @Startcount = 2 ) AND p.CapitalOperation in (0,1,2,3,4)
							THEN [pi].BudgetAmountCurP2 END AS BudgetAmount 
							FROM  #Plan_BudgetVersionDetail AS [pi]
							LEFT OUTER JOIN Plan_ProjectItem AS [ppi] ON [pi].PlanProjectItemID = [ppi].PlanProjectItem_ID
							LEFT OUTER JOIN (SELECT LOWER(CAST(ISNULL(scoap.NTScoaID, '00000000-0000-0000-0000-000000000000') AS VARCHAR(50)) + CASE WHEN (scoap.BreakDownAllowed='Yes') THEN '_' + right('00000'+CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS NVARCHAR(10)), 5)
							ELSE '' END )  AS SCOAProject, pp.Project_ID, pp.IsDeleted ,pp.CapitalOperation 
						FROM  Plan_Project AS pp
							LEFT OUTER JOIN  #projectTable AS scoap ON scoap.ScoaID = pp.ScoaProjectID) AS p ON p.Project_ID = [pi].ProjectID
							LEFT OUTER JOIN #functionTable AS scoaf ON scoaf.ScoaID = [pi].SCOAFunctionId 
							LEFT OUTER JOIN #itemTable AS scoai ON scoai.ScoaID = [pi].SCOAItemID
							LEFT OUTER JOIN #fundsTable AS scoafnd ON scoafnd.ScoaID = [pi].SCOAFundId
							LEFT OUTER JOIN #costingTable AS scoac ON scoac.ScoaID = [pi].SCOACostingID
							LEFT OUTER JOIN #regionalTable AS scoar ON scoar.ScoaID = [pi].SCOARegionId 
						WHERE   pi.FinYear IS NOT NULL AND [pi].FinYear = @FinancialYear AND ISNULL(p.IsDeleted,0) = 0
							AND p.Project_ID NOT IN (SELECT ProjectID FROM dbo.Plan_ProjectReportExclude)) AS prev
						GROUP BY MunicipalityNo,Finyear,TypeStr,SCOAProject,SCOAFunction,SCOAItem, SCOAFund,SCOACosting, SCOARegion
						HAVING  CAST(ROUND(SUM(BudgetAmount), 0) AS BIGINT) <> 0
						ORDER BY FinYear
			SET @Startcount = @Startcount + 1;
		END; 

		--Month wise
		INSERT  INTO @tempScoaString
		SELECT  
		(MunicipalityNo 
		+ '|' + Finyear
		+ '|' + TypeStr
		+ '|' + SCOAProject 
		+ '|' + SCOAFunction 
		+ '|' + SCOAItem 
		+ '|' + SCOAFund 
		+ '|' + SCOACosting
		+ '|' + SCOARegion 
		+ '|' + CAST(CAST(ROUND(SUM(UnitPrice),0) AS BIGINT) AS VARCHAR(40))) AS SCOAString
		FROM
		(
		SELECT CAST(( SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) as MunicipalityNo,
				CAST(SUBSTRING(@FinancialYear, 6, 4) AS VARCHAR(4)) as Finyear,
				CAST(( CASE mon.Month_ID
						WHEN 1 THEN 'PM01'
						WHEN 2 THEN 'PM02'
						WHEN 3 THEN 'PM03'
						WHEN 4 THEN 'PM04'
						WHEN 5 THEN 'PM05'
						WHEN 6 THEN 'PM06'
						WHEN 7 THEN 'PM07'
						WHEN 8 THEN 'PM08'
						WHEN 9 THEN 'PM09'
						WHEN 10 THEN 'PM10'
						WHEN 11 THEN 'PM11'
						WHEN 12 THEN 'PM12'
						ELSE 'Y'
						END ) AS VARCHAR(4))  as TypeStr,
				p.SCOAProject,
				LOWER(CAST(ISNULL(scoaf.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFunction,
				LOWER(CAST(ISNULL(scoai.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAItem,
				LOWER(CAST(ISNULL(scoafnd.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFund,
				LOWER(CAST(ISNULL(scoac.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOACosting,
				LOWER(CAST(ISNULL(scoar.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOARegion,
				CASE WHEN (((scoai.ScoaCode LIKE 'IR%'  OR scoai.ScoaCode LIKE 'IL%') AND p.CapitalOperation in (0,1,2))
								OR [ppi].CreditDebit = 'C')	
								THEN	-pim.UnitPrice
								ELSE pim.UnitPrice
				END AS UnitPrice
			FROM    #Plan_BudgetVersionMonths AS pim
					LEFT JOIN  YearStartingAtMonth_fxn(CAST(@FinYearStartMonth AS VARCHAR(10)) ) mon ON pim.MonthID=mon.SysMonthID
					LEFT OUTER JOIN  #Plan_BudgetVersionDetail AS [pi] ON [pi].PlanProjectItemID = pim.PlanProjectItemID
					LEFT OUTER JOIN  Plan_ProjectItem [ppi] ON [pi].PlanProjectItemID = [ppi].PlanProjectItem_ID
					LEFT OUTER JOIN (SELECT LOWER(CAST(ISNULL(scoap.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))
							+ CASE WHEN (scoap.BreakDownAllowed='Yes') 
								THEN '_' + right('00000'+CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS NVARCHAR(10)), 5)
								ELSE ''
								END )  AS SCOAProject, pp.Project_ID, pp.IsDeleted ,pp.CapitalOperation
								FROM  Plan_Project AS pp
								LEFT OUTER JOIN  #projectTable AS scoap ON scoap.ScoaID = pp.ScoaProjectID
								) AS p ON p.Project_ID = [pi].ProjectID
					LEFT OUTER JOIN #functionTable AS scoaf ON scoaf.ScoaID = [pi].SCOAFunctionId
					LEFT OUTER JOIN #itemTable AS scoai ON scoai.ScoaID = [pi].SCOAItemID
					LEFT OUTER JOIN #fundsTable AS scoafnd ON scoafnd.ScoaID = [pi].SCOAFundId
					LEFT OUTER JOIN #costingTable AS scoac ON scoac.ScoaID = [pi].SCOACostingID
					LEFT OUTER JOIN #regionalTable AS scoar ON scoar.ScoaID = [pi].SCOARegionId 
			WHERE   [pi].FinYear IS NOT NULL
					AND [pi].FinYear = @FinancialYear 
					AND ISNULL(p.IsDeleted,0) = 0
					AND p.Project_ID NOT IN (SELECT ProjectID FROM dbo.Plan_ProjectReportExclude)) as pp
			GROUP BY
			MunicipalityNo,Finyear,TypeStr,SCOAProject,SCOAFunction,SCOAItem, SCOAFund,SCOACosting, SCOARegion
			HAVING  CAST(ROUND(SUM(UnitPrice), 0) AS BIGINT) <> 0
			ORDER BY FinYear,TypeStr;

		DROP TABLE #Plan_BudgetVersionDetail, #Plan_BudgetVersionMonths
	END
	ELSE
	BEGIN
		INSERT  INTO @tempScoaString
		SELECT  
			(MunicipalityNo 
			+ '|' + Finyear
			+ '|' + TypeStr
			+ '|' + SCOAProject 
			+ '|' + SCOAFunction 
			+ '|' + SCOAItem 
			+ '|' + SCOAFund 
			+ '|' + SCOACosting
			+ '|' + SCOARegion 
			+ '|' + CAST(CAST(ROUND(SUM(BudgetAmount),0) AS BIGINT) AS VARCHAR(40)) ) AS SCOAString
		FROM
			(
				SELECT  CAST(( SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) as MunicipalityNo,
						CAST(SUBSTRING(@FinancialYear, 6, 4) AS VARCHAR(4)) as Finyear,
						'ORGB' as TypeStr, p.SCOAProject,			 
						LOWER(CAST(ISNULL(scoaf.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFunction,
						LOWER(CAST(ISNULL(scoai.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAItem,
						LOWER(CAST(ISNULL(scoafnd.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFund,
						LOWER(CAST(ISNULL(scoac.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOACosting,
						LOWER(CAST(ISNULL(scoar.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOARegion,
						scoai.ScoaCode
						,( CASE WHEN (((scoai.ScoaCode LIKE 'IR%' OR scoai.ScoaCode LIKE 'IL%') AND p.CapitalOperation in (0,1,2)) OR [pi].CreditDebit = 'C')
						THEN -[pi].BudgetAmount ELSE [pi].BudgetAmount END ) as BudgetAmount
						FROM   dbo.Plan_ProjectItem AS [pi]
						LEFT OUTER JOIN (SELECT LOWER(CAST(ISNULL(scoap.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))
												+ CASE WHEN (scoap.BreakDownAllowed='Yes') 
													THEN '_' + right('00000'+CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS NVARCHAR(10)), 5)
													ELSE ''
													END )  AS SCOAProject, 
													pp.Project_ID, 
													pp.IsDeleted, pp.CapitalOperation  
										FROM  dbo.Plan_Project AS pp
										LEFT OUTER JOIN  #projectTable AS scoap ON scoap.ScoaID = pp.ScoaProjectID) AS p 
						ON p.Project_ID = [pi].ProjectID
						LEFT OUTER JOIN #functionTable AS scoaf ON scoaf.ScoaID = [pi].SCOAFunctionId
						LEFT OUTER JOIN #itemTable AS scoai ON scoai.ScoaID = [pi].SCOAItemID
						LEFT OUTER JOIN #fundsTable AS scoafnd ON scoafnd.ScoaID = [pi].SCOAFundId
						LEFT OUTER JOIN #costingTable AS scoac ON scoac.ScoaID = [pi].SCOACostingID
						LEFT OUTER JOIN #regionalTable AS scoar ON scoar.ScoaID = [pi].SCOARegionId
					WHERE   pi.FinYear IS NOT NULL
						AND [pi].FinYear =  @FinancialYear 
						AND ISNULL(p.IsDeleted,0) = 0
						AND p.Project_ID NOT IN (SELECT ProjectID FROM dbo.Plan_ProjectReportExclude)
			)as pp
		GROUP BY
		MunicipalityNo,Finyear,TypeStr,SCOAProject,SCOAFunction,SCOAItem, SCOAFund,SCOACosting, SCOARegion,ScoaCode 
		HAVING  CAST(ROUND(SUM([BudgetAmount]), 0) AS BIGINT) <> 0
		ORDER BY FinYear; 

		WHILE ( @Startcount <= @Totalcount )
		BEGIN
			INSERT  INTO @tempScoaString
			SELECT(MunicipalityNo 
					+ '|' + Finyear
					+ '|' + TypeStr
					+ '|' + SCOAProject 
					+ '|' + SCOAFunction 
					+ '|' + SCOAItem 
					+ '|' + SCOAFund 
					+ '|' + SCOACosting
					+ '|' + SCOARegion 
					+ '|' +  CAST(CAST(ROUND(SUM(BudgetAmount),0) AS BIGINT) AS VARCHAR(40))) AS SCOAString
			FROM  (SELECT  CAST(( SELECT MunicipalityNo FROM  Payroll_Municipality) AS VARCHAR(6)) as MunicipalityNo,
							CAST(SUBSTRING(@FinancialYear , 6, 4) AS VARCHAR(4)) as Finyear,
							CAST(( CASE WHEN ( @Startcount = 0 )
							THEN 'ORGB' WHEN ( @Startcount = 1 ) THEN 'IBY1'
							WHEN ( @Startcount = 2 ) THEN 'IBY2' END ) AS VARCHAR(4)) AS TypeStr,
							p.SCOAProject,
							LOWER(CAST(ISNULL(scoaf.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFunction,
							LOWER(CAST(ISNULL(scoai.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAItem,
							LOWER(CAST(ISNULL(scoafnd.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFund,
							LOWER(CAST(ISNULL(scoac.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOACosting,
							LOWER(CAST(ISNULL(scoar.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOARegion,
							CASE WHEN ( @Startcount = 0 ) AND (((scoai.ScoaCode LIKE 'IR%' OR scoai.ScoaCode LIKE 'IL%' ) AND p.CapitalOperation in (0,1,2)) OR [pi].CreditDebit = 'C')
							THEN -[pi].BudgetAmount
							WHEN ( @Startcount = 0 ) AND (scoai.ScoaCode NOT LIKE 'IR%' AND scoai.ScoaCode NOT LIKE 'IL%')
							THEN [pi].BudgetAmount
							WHEN ( @Startcount = 0 ) AND p.CapitalOperation in (0,1,2,3,4)
							THEN [pi].BudgetAmount
							WHEN ( @Startcount = 1 ) 
							AND (((scoai.ScoaCode LIKE 'IR%'  OR scoai.ScoaCode LIKE 'IL%') AND p.CapitalOperation in (0,1,2))
							OR [pi].CreditDebit = 'C')
							THEN -[pi].BudgetAmountCurP1
							WHEN ( @Startcount = 1 ) 
							AND (scoai.ScoaCode NOT LIKE 'IR%' AND scoai.ScoaCode NOT LIKE 'IL%')
							THEN [pi].BudgetAmountCurP1
							WHEN ( @Startcount = 1 ) AND p.CapitalOperation in (0,1,2,3,4)
							THEN [pi].BudgetAmountCurP1
							WHEN ( @Startcount = 2 ) AND (((scoai.ScoaCode LIKE 'IR%' OR scoai.ScoaCode LIKE 'IL%' ) AND p.CapitalOperation in (0,1,2)) OR [pi].CreditDebit = 'C')
							THEN -[pi].BudgetAmountCurP2
							WHEN ( @Startcount = 2 ) 
							AND (scoai.ScoaCode NOT LIKE 'IR%' AND scoai.ScoaCode NOT LIKE 'IL%')
							THEN [pi].BudgetAmountCurP2
							WHEN ( @Startcount = 2 ) AND p.CapitalOperation in (0,1,2,3,4)
							THEN [pi].BudgetAmountCurP2 END AS BudgetAmount FROM  Plan_ProjectItem AS [pi]
							LEFT OUTER JOIN (SELECT LOWER(CAST(ISNULL(scoap.NTScoaID, '00000000-0000-0000-0000-000000000000') AS VARCHAR(50)) + CASE WHEN (scoap.BreakDownAllowed='Yes') THEN '_' + right('00000'+CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS NVARCHAR(10)), 5)
							ELSE '' END )  AS SCOAProject, pp.Project_ID, pp.IsDeleted ,pp.CapitalOperation FROM  Plan_Project AS pp
							LEFT OUTER JOIN  #projectTable AS scoap ON scoap.ScoaID = pp.ScoaProjectID) AS p ON p.Project_ID = [pi].ProjectID
							LEFT OUTER JOIN #functionTable AS scoaf ON scoaf.ScoaID = [pi].SCOAFunctionId 
							LEFT OUTER JOIN #itemTable AS scoai ON scoai.ScoaID = [pi].SCOAItemID
							LEFT OUTER JOIN #fundsTable AS scoafnd ON scoafnd.ScoaID = [pi].SCOAFundId
							LEFT OUTER JOIN #costingTable AS scoac ON scoac.ScoaID = [pi].SCOACostingID
							LEFT OUTER JOIN #regionalTable AS scoar ON scoar.ScoaID = [pi].SCOARegionId 
							WHERE   pi.FinYear IS NOT NULL AND [pi].FinYear = @FinancialYear AND ISNULL(p.IsDeleted,0) = 0
							AND p.Project_ID NOT IN (SELECT ProjectID FROM dbo.Plan_ProjectReportExclude)) AS prev
							GROUP BY MunicipalityNo,Finyear,TypeStr,SCOAProject,SCOAFunction,SCOAItem, SCOAFund,SCOACosting, SCOARegion
							HAVING  CAST(ROUND(SUM(BudgetAmount), 0) AS BIGINT) <> 0
							ORDER BY FinYear
			SET @Startcount = @Startcount + 1;
		END; 

		--Month wise
		INSERT  INTO @tempScoaString
		SELECT  
		(MunicipalityNo 
		+ '|' + Finyear
		+ '|' + TypeStr
		+ '|' + SCOAProject 
		+ '|' + SCOAFunction 
		+ '|' + SCOAItem 
		+ '|' + SCOAFund 
		+ '|' + SCOACosting
		+ '|' + SCOARegion 
		+ '|' + CAST(CAST(ROUND(SUM(UnitPrice),0) AS BIGINT) AS VARCHAR(40))) AS SCOAString
		FROM
		(
		SELECT CAST(( SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) as MunicipalityNo,
				CAST(SUBSTRING(@FinancialYear, 6, 4) AS VARCHAR(4)) as Finyear,
				CAST(( CASE mon.Month_ID
						WHEN 1 THEN 'PM01'
						WHEN 2 THEN 'PM02'
						WHEN 3 THEN 'PM03'
						WHEN 4 THEN 'PM04'
						WHEN 5 THEN 'PM05'
						WHEN 6 THEN 'PM06'
						WHEN 7 THEN 'PM07'
						WHEN 8 THEN 'PM08'
						WHEN 9 THEN 'PM09'
						WHEN 10 THEN 'PM10'
						WHEN 11 THEN 'PM11'
						WHEN 12 THEN 'PM12'
						ELSE 'Y'
						END ) AS VARCHAR(4))  as TypeStr,
				p.SCOAProject,
				LOWER(CAST(ISNULL(scoaf.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFunction,
				LOWER(CAST(ISNULL(scoai.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAItem,
				LOWER(CAST(ISNULL(scoafnd.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOAFund,
				LOWER(CAST(ISNULL(scoac.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOACosting,
				LOWER(CAST(ISNULL(scoar.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) as SCOARegion,
				CASE WHEN (((scoai.ScoaCode LIKE 'IR%'  OR scoai.ScoaCode LIKE 'IL%') AND p.CapitalOperation in (0,1,2))
								OR [pi].CreditDebit = 'C')	
								THEN	-pim.UnitPrice
								ELSE pim.UnitPrice
				END AS UnitPrice
			FROM     Plan_ProjectItemMonth AS pim
					LEFT JOIN  YearStartingAtMonth_fxn(CAST(@FinYearStartMonth AS VARCHAR(10)) ) mon ON pim.MonthID=mon.SysMonthID
					LEFT OUTER JOIN  Plan_ProjectItem AS [pi] ON [pi].PlanProjectItem_ID = pim.PlanProjectItemID
					LEFT OUTER JOIN (SELECT LOWER(CAST(ISNULL(scoap.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))
							+ CASE WHEN (scoap.BreakDownAllowed='Yes') 
								THEN '_' + right('00000'+CAST(ISNULL(pp.ProjectCode, pp.Project_ID) AS NVARCHAR(10)), 5)
								ELSE ''
								END )  AS SCOAProject, pp.Project_ID, pp.IsDeleted ,pp.CapitalOperation
								FROM  Plan_Project AS pp
								LEFT OUTER JOIN  #projectTable AS scoap ON scoap.ScoaID = pp.ScoaProjectID
								) AS p ON p.Project_ID = [pi].ProjectID
					LEFT OUTER JOIN #functionTable AS scoaf ON scoaf.ScoaID = [pi].SCOAFunctionId
					LEFT OUTER JOIN #itemTable AS scoai ON scoai.ScoaID = [pi].SCOAItemID
					LEFT OUTER JOIN #fundsTable AS scoafnd ON scoafnd.ScoaID = [pi].SCOAFundId
					LEFT OUTER JOIN #costingTable AS scoac ON scoac.ScoaID = [pi].SCOACostingID
					LEFT OUTER JOIN #regionalTable AS scoar ON scoar.ScoaID = [pi].SCOARegionId 
			WHERE   [pi].FinYear IS NOT NULL
					AND [pi].FinYear = @FinancialYear 
					AND ISNULL(p.IsDeleted,0) = 0
					AND p.Project_ID NOT IN (SELECT ProjectID FROM dbo.Plan_ProjectReportExclude)) as pp
			GROUP BY
			MunicipalityNo,Finyear,TypeStr,SCOAProject,SCOAFunction,SCOAItem, SCOAFund,SCOACosting, SCOARegion
			HAVING  CAST(ROUND(SUM(UnitPrice), 0) AS BIGINT) <> 0
			ORDER BY FinYear,TypeStr; 
	END

 END
	SELECT Id, SCOAString FROM  @tempScoaString
	WHERE   SCOAString IS NOT NULL
	ORDER BY Id;

	DROP TABLE #projectTable
	DROP TABLE #functionTable
	DROP TABLE #itemTable
	DROP TABLE #fundsTable
	DROP TABLE #costingTable
	DROP TABLE #regionalTable

	--PRINT (@SQLtextMainDiv + @SQLtextSecPart)
	--PRINT (@SQLtextThirPart + @SQLtextLastPart)
	--EXEC (@SQLtextMainDiv + @SQLtextSecPart + @SQLtextThirPart + @SQLtextLastPart);

END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_ReportNTVirementString_sp]    Script Date: 2026/03/10 7:23:47 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- ===================================================================
-- Author:			Chris Moodley
-- Create date:	May 2025
-- Description:		NT Virement String
-- Plan_ReportNTVirementString_sp '2025/2026', 1, 15
-- 20250519 by CM : 120569 - Fix where clause to return rejected or not fully approved virements correctly
-- 20251010 by CM : 119246 - Handle up to 7 approval levels
-- ===================================================================
CREATE PROCEDURE [dbo].[Plan_ReportNTVirementString_sp]
	-- Add the parameters for the stored procedure here
	@finYear NVARCHAR(10) = '2024/2025',
	@fromMonth INT = 1,
	@toMonth INT = 15
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	SELECT ScoaID, BreakDownAllowed, NTScoaID INTO #projectTable FROM Const_SCOA_Project_Structure_Consolidated WHERE FinYearText = @finYear
	SELECT ScoaID, BreakDownAllowed, NTScoaID  INTO #functionTable FROM Const_SCOA_Function_Structure_Consolidated WHERE FinYearText = @finYear
	SELECT ScoaID, BreakDownAllowed, NTScoaID, ScoaCode INTO #itemTable FROM Plan_Const_SCOA_Structure_Consolidated_vw WHERE FinYearText = @finYear
	SELECT ScoaID, BreakDownAllowed, NTScoaID INTO #fundsTable FROM Const_SCOA_Funds_Structure_Consolidated WHERE FinYearText = @finYear
	SELECT ScoaID, BreakDownAllowed, NTScoaID INTO #costingTable FROM Const_SCOA_Costing_Structure_Consolidated WHERE FinYearText = @finYear
	SELECT ScoaID, BreakDownAllowed, NTScoaID INTO #regionalTable FROM Const_SCOA_Regional_Structure_Consolidated WHERE FinYearText = @finYear

	SELECT
		(
			MunicipalityNo 
			+ '|' + FinYear
			+ '|' + TypeStr
			+ '|' + SCOAProject 
			+ '|' + SCOAFunction 
			+ '|' + SCOAItem 
			+ '|' + SCOAFund 
			+ '|' + SCOACosting
			+ '|' + SCOARegion 
			+ '|' + CAST(VirementAmount AS VARCHAR(40)) 
		) AS SCOAString
	FROM
		(
			SELECT  
				CAST(( SELECT MunicipalityNo FROM Payroll_Municipality) AS VARCHAR(6)) AS MunicipalityNo,
				SUBSTRING(@FinYear, 6, 9) AS FinYear,
				CASE VirementApprovedMonth
					WHEN 1 THEN 'V01'
					WHEN 2 THEN 'V02'
					WHEN 3 THEN 'V03'
					WHEN 4 THEN 'V04'
					WHEN 5 THEN 'V05'
					WHEN 6 THEN 'V06'
					WHEN 7 THEN 'V07'
					WHEN 8 THEN 'V08'
					WHEN 9 THEN 'V09'
					WHEN 10 THEN 'V10'
					WHEN 11 THEN 'V11'
					ELSE 'V12'
				END AS TypeStr,
				SCOAProject,
				SCOAFunction,
				SCOAItem,
				SCOAFund,
				SCOACosting,
				SCOARegion,
				CAST(ROUND(SUM(VirementAmount),0) AS BIGINT) AS VirementAmount		
			FROM    
				( 
					SELECT  
						V.VirementId ,
						LOWER(CAST(ISNULL(CSPSFrom.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))
							+ CASE WHEN (CSPSFrom.BreakDownAllowed = 'Yes') 
								THEN '_' + RIGHT('00000' + CAST(ISNULL(PP.ProjectCode, PP.Project_ID) AS NVARCHAR(10)), 5)
								ELSE ''
								END) AS SCOAProject,
						LOWER(CAST(ISNULL(CSFSFrom.NTScoaID, '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOAFunction,
						LOWER(CAST(ISNULL(CSFDSFrom.NTScoaID, '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOAFund,
						LOWER(CAST(ISNULL(CSRSFrom.NTScoaID, '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOARegion,
						LOWER(CAST(ISNULL(CSSFrom.NTScoaID, '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOAItem,
						LOWER(CAST(ISNULL(CSCSFrom.NTScoaID, '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOACosting,
						-ISNULL(V.FromVirementAmount, 0) AS VirementAmount 
					FROM      
						dbo.Plan_Virements V 
						INNER JOIN Plan_Project PP ON V.FromProjectID = PP.Project_ID
						LEFT OUTER JOIN #projectTable CSPSFrom ON CSPSFrom.ScoaID = V.FromSCOAProjectID
						LEFT OUTER JOIN #functionTable CSFSFrom ON CSFSFrom.ScoaID = V.FromSCOAFunctionId
						LEFT OUTER JOIN #fundsTable CSFDSFrom ON CSFDSFrom.ScoaID = V.FromSCOAFundID
						LEFT OUTER JOIN #regionalTable CSRSFrom ON CSRSFrom.ScoaID = V.FromSCOARegion
						LEFT OUTER JOIN #itemTable CSSFrom ON CSSFrom.ScoaID = V.FromSCOAItem
						LEFT OUTER JOIN #costingTable CSCSFrom ON CSCSFrom.ScoaID = V.FromSCOACostingId
					WHERE     
						V.FinYear = @finYear
						AND FromProjectID NOT IN (SELECT ProjectID FROM Plan_ProjectReportExclude)
                            
					UNION

					SELECT    
						V.VirementId,
						LOWER(CAST(ISNULL(CSPSTo.NTScoaID,'00000000-0000-0000-0000-000000000000') AS VARCHAR(50))
							+ CASE WHEN (CSPSTo.BreakDownAllowed = 'Yes') 
								THEN '_' + RIGHT('00000' + CAST(ISNULL(PP.ProjectCode, PP.Project_ID) AS NVARCHAR(10)), 5)
								ELSE ''
								END) AS SCOAProject,
						LOWER(CAST(ISNULL(CSFSTo.NTScoaID, '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOAFunction,
						LOWER(CAST(ISNULL(CSFDSTo.NTScoaID, '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOAFund,
						LOWER(CAST(ISNULL(CSRSTo.NTScoaID, '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOARegion,
						LOWER(CAST(ISNULL(CSSTo.NTScoaID, '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOAItem,
						LOWER(CAST(ISNULL(CSCSTo.NTScoaID, '00000000-0000-0000-0000-000000000000') AS VARCHAR(50))) AS SCOACosting,
						ISNULL(V.ToVirementAmount, 0) AS VirementAmount 
					FROM      
						dbo.Plan_Virements V 
						INNER JOIN Plan_Project PP ON V.ToProjectID = PP.Project_ID
						LEFT OUTER JOIN #projectTable CSPSTo ON CSPSTo.ScoaID = V.ToSCOAProjectID
						LEFT OUTER JOIN #functionTable CSFSTo ON CSFSTo.ScoaID = V.ToSCOAFunctionId
						LEFT OUTER JOIN #fundsTable CSFDSTo ON CSFDSTo.ScoaID = V.ToSCOAFundID
						LEFT OUTER JOIN #regionalTable CSRSTo ON CSRSTo.ScoaID = V.ToSCOARegion
						LEFT OUTER JOIN #itemTable CSSTo ON CSSTo.ScoaID = V.ToSCOAItem
						LEFT OUTER JOIN #costingTable CSCSTo ON CSCSTo.ScoaID = V.ToSCOACostingId
					WHERE     
						V.FinYear = @finYear
						AND ToProjectID NOT IN (SELECT ProjectID FROM Plan_ProjectReportExclude)
				) AS Virement
                
				INNER JOIN 

				( 
					SELECT 
						VirementID,
						[dbo].[BudgetReport_GetFinancialMonthFromDate](GREATEST([1], [2], [3], [4], [5], [6], [7]) , 'NOTCHINCREASE', 0) AS VirementApprovedMonth
					FROM   
						( 
							SELECT    
								PV.VirementId , 
								PVAR.DateCaptured,
								ROW_NUMBER() OVER ( PARTITION BY PV.VirementId ORDER BY PVAU.VirementApprovalUserId ) AS ApproverNo
							FROM      
								dbo.Plan_Virements AS PV
								INNER JOIN dbo.Plan_VirementApprovalUsers PVAU ON PV.VirementId = PVAU.VirementId
								INNER JOIN dbo.User_UserDetail UUD ON UUD.User_ID = PVAU.UserId
								LEFT OUTER JOIN dbo.Plan_VirementApprovalRejections PVAR ON PVAU.VirementId = PVAR.VirementId AND PVAU.UserID = PVAR.CapturerID   
							WHERE FinYear = @finYear
						) S 
						PIVOT
						( MAX(DateCaptured) FOR ApproverNo IN ( [1], [2], [3], [4], [5], [6], [7] ) ) piv
				) AS VirementApprover ON Virement.VirementId = VirementApprover.VirementId

			WHERE
				Virement.VirementID NOT IN
					(
						SELECT  DISTINCT PV.VirementId
						FROM   dbo.Plan_Virements AS PV
							INNER JOIN dbo.Plan_VirementApprovalUsers PVAU ON PV.VirementId = PVAU.VirementId
							LEFT OUTER JOIN dbo.Plan_VirementApprovalRejections PVAR ON PV.VirementId = PVAR.VirementId
														AND PVAU.UserId = PVAR.ApprovedBy
							LEFT OUTER JOIN dbo.Plan_VirementApprovalRejections PVAR1 ON PV.VirementId = PVAR1.VirementId
														AND PVAU.UserId = PVAR1.RejectedBy
						WHERE  
							FinYear = @finYear
							AND ISNULL(PVAU.UserId,0) > 0
							AND PVAR.ApprovedBy IS NULL
					)  
				AND
					VirementApprovedMonth BETWEEN @fromMonth AND @toMonth
			GROUP BY
				SCOAProject,SCOAFunction,SCOAItem, SCOAFund,SCOACosting, SCOARegion, VirementApprovedMonth
				
			) virement
	ORDER BY FinYear,TypeStr
		
	DROP TABLE #costingTable, #functionTable, #fundsTable, #itemTable, #projectTable, #regionalTable

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_ReportSCOASegment_sp]    Script Date: 2026/03/10 7:23:47 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Chris Moodley
-- Create date: 27 April 2020
-- Description:	Return SCOA segments that are used per financial year
-- 20211027 by CM - 77994 - Fix long running SP (parameter sniffing)
-- Plan_ReportSCOASegment_sp '2021/2022', 0, 'ITEM', -1
-- =============================================
CREATE PROCEDURE [dbo].[Plan_ReportSCOASegment_sp]
	-- Add the parameters for the stored procedure here
	@FinYear VARCHAR(10),
	@ProjectID INT,
	@ScoaSegmentType VARCHAR(50),
	@BudgetType INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here

	DECLARE
		@ParamFinYear VARCHAR(10),
		@ParamProjectID INT,
		@ParamScoaSegmentType VARCHAR(50),
		@ParamBudgetType INT

	SET @ParamFinYear = @FinYear
	SET @ParamProjectID = @ProjectID
	SET @ParamScoaSegmentType = @ScoaSegmentType
	SET @ParamBudgetType = @BudgetType

	DECLARE @StatusInitiated INT

	SELECT @StatusInitiated = Status_ID FROM Const_Status WHERE UsedBy = 'ProjectRegister' AND StatusDesc = 'Initiated'

	IF (@ScoaSegmentType = 'ITEM')
	BEGIN
		SELECT DISTINCT
			ScoaID, ScoaDesc
		FROM 
			Plan_Project pp
			INNER JOIN Plan_ProjectItem ppi ON pp.Project_ID = ppi.ProjectID
			INNER JOIN Const_SCOA_Structure_ByYear(@ParamFinYear) scoa ON ppi.SCOAItemID = scoa.ScoaID
		WHERE 
			pp.FinYear = @ParamFinYear 
			AND (pp.Project_ID  = @ParamProjectID OR @ProjectID = 0)
			AND pp.ProjectStatus = @StatusInitiated 
			AND (pp.CapitalOperation = @ParamBudgetType OR @ParamBudgetType = -1)
			AND ISNULL(pp.isDeleted, 0) <> 1
		ORDER BY
			ScoaDesc
	END

	IF (@ScoaSegmentType = 'COSTING')
	BEGIN
		SELECT DISTINCT
			ScoaID, ScoaDesc 
		FROM 
			Plan_Project pp
			INNER JOIN Plan_ProjectItem ppi ON pp.Project_ID = ppi.ProjectID
			INNER JOIN Const_SCOA_Costing_Structure_ByYear(@ParamFinYear) scoa ON ppi.SCOACostingID = scoa.ScoaID
		WHERE 
			pp.FinYear = @ParamFinYear 
			AND (pp.Project_ID  = @ParamProjectID OR @ProjectID = 0)
			AND pp.ProjectStatus = @StatusInitiated 
			AND (pp.CapitalOperation = @ParamBudgetType OR @ParamBudgetType = -1)
			AND ISNULL(pp.isDeleted, 0) <> 1
		ORDER BY
			ScoaDesc
	END

	IF (@ScoaSegmentType = 'PROJECT')
	BEGIN
		SELECT DISTINCT
			ScoaID, ScoaDesc 
		FROM 
			Plan_Project pp
			INNER JOIN Plan_ProjectItem ppi ON pp.Project_ID = ppi.ProjectID
			INNER JOIN Const_SCOA_Project_Structure_ByYear(@ParamFinYear) scoa ON pp.SCOAProjectID = scoa.ScoaID
		WHERE 
			pp.FinYear = @ParamFinYear 
			AND (pp.Project_ID  = @ParamProjectID OR @ProjectID = 0)
			AND pp.ProjectStatus = @StatusInitiated 
			AND (pp.CapitalOperation = @ParamBudgetType OR @ParamBudgetType = -1)
			AND ISNULL(pp.isDeleted, 0) <> 1
		ORDER BY
			ScoaDesc
	END

	IF (@ScoaSegmentType = 'FUNCTION')
	BEGIN
		SELECT DISTINCT
			ScoaID, ScoaDesc 
		FROM 
			Plan_Project pp
			INNER JOIN Plan_ProjectItem ppi ON pp.Project_ID = ppi.ProjectID
			INNER JOIN Const_SCOA_Function_Structure_ByYear(@ParamFinYear) scoa ON ppi.SCOAFunctionID = scoa.ScoaID
		WHERE 
			pp.FinYear = @ParamFinYear 
			AND (pp.Project_ID  = @ParamProjectID OR @ProjectID = 0)
			AND pp.ProjectStatus = @StatusInitiated 
			AND (pp.CapitalOperation = @ParamBudgetType OR @ParamBudgetType = -1)
			AND ISNULL(pp.isDeleted, 0) <> 1
		ORDER BY
			ScoaDesc
	END

	IF (@ScoaSegmentType = 'FUND')
	BEGIN
		SELECT DISTINCT
			ScoaID, ScoaDesc 
		FROM 
			Plan_Project pp
			INNER JOIN Plan_ProjectItem ppi ON pp.Project_ID = ppi.ProjectID
			INNER JOIN Const_SCOA_Funds_Structure_ByYear(@ParamFinYear) scoa ON ppi.SCOAFundID = scoa.ScoaID
		WHERE 
			pp.FinYear = @ParamFinYear 
			AND (pp.Project_ID  = @ParamProjectID OR @ProjectID = 0)
			AND pp.ProjectStatus = @StatusInitiated 
			AND (pp.CapitalOperation = @ParamBudgetType OR @ParamBudgetType = -1)
			AND ISNULL(pp.isDeleted, 0) <> 1
		ORDER BY
			ScoaDesc
	END

	IF (@ScoaSegmentType = 'REGION')
	BEGIN
		SELECT DISTINCT
			ScoaID, ScoaDesc 
		FROM 
			Plan_Project pp
			INNER JOIN Plan_ProjectItem ppi ON pp.Project_ID = ppi.ProjectID
			INNER JOIN Const_SCOA_Regional_Structure_ByYear(@ParamFinYear) scoa ON ppi.SCOARegionID = scoa.ScoaID
		WHERE 
			pp.FinYear = @ParamFinYear 
			AND (pp.Project_ID  = @ParamProjectID OR @ProjectID = 0)
			AND pp.ProjectStatus = @StatusInitiated 
			AND (pp.CapitalOperation = @ParamBudgetType OR @ParamBudgetType = -1)
			AND ISNULL(pp.isDeleted, 0) <> 1
		ORDER BY
			ScoaDesc
	END

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_RevenueReconciliationReport]    Script Date: 2026/03/10 7:23:47 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Niren P
-- Create date: 02/22/2016
-- Description:	Get data for Report
-- [Plan_RevenueReconciliationReport] '2015/2016,2016/2017,2017/2018'
-- SN:10/05/2016 : Add Inner query for getting BudgetAmount as per year
-- =============================================
CREATE PROCEDURE [dbo].[Plan_RevenueReconciliationReport]
    @FinancialYear VARCHAR(50)
-- WITH ENCRYPTION, RECOMPILE, EXECUTE AS CALLER|SELF|OWNER| 'user_name'
AS
    DECLARE @StartYear1 VARCHAR(50) ,
        @StartYear2 VARCHAR(50) ,
        @StartYear3 VARCHAR(50);

    SET @StartYear1 = LEFT(@FinancialYear, 9);

    SET @StartYear2 = LEFT(RIGHT(@FinancialYear, 19), 9);

    SET @StartYear3 = RIGHT(@FinancialYear, 9);


    SELECT  T.Total AS Total ,
            --T.Revenue AS Revenue ,
            ( SELECT    ( CASE WHEN @StartYear1 = T.FinancialYear
                               THEN ISNULL(SUM(ppi.BudgetAmount), 0)
                               WHEN @StartYear2 = T.FinancialYear
                               THEN ISNULL(SUM(ppi.BudgetAmountCurP1), 0)
                               WHEN @StartYear3 = T.FinancialYear
                               THEN ISNULL(SUM(ppi.BudgetAmountCurP2), 0)
                          END ) AS Rtotal
              FROM      dbo.Plan_ProjectItem ppi
                        INNER JOIN Plan_Project pp ON pp.Project_ID = ppi.ProjectID
                        INNER JOIN Const_SCOA_Structure s ON ppi.SCOAItemID = s.ScoaID
              WHERE     pp.FinYear = @StartYear1
                        AND ppi.FinYear = @StartYear1
                        AND ISNULL(pp.IsDeleted, 0) <> 1
                        AND s.ScoaCode LIKE 'IR%'
            ) AS Revenue ,
            0 AS Remain ,-- We are calculating Remain amount on Front End SSRS report
            T.FinancialYear AS FinanacialYear
    FROM    ( SELECT    dbo.Planing_GetFundAvailableTotalAmount(FinancialYear) AS Total ,
                       -- dbo.Planing_GetProjectRevenueAmount(FinancialYear) AS Revenue,
                        FinancialYear
              FROM      dbo.Plan_FundingSourceBudget_Header
              WHERE     FinancialYear IN (
                        SELECT  splitdata
                        FROM    dbo.fnSplitString(@FinancialYear, ',') )
            ) AS T;
GO

/****** Object:  StoredProcedure [dbo].[Plan_SaveAdjustmentBudgetApprovalRejection_sp]    Script Date: 2026/03/10 7:23:47 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 2016-04-18
-- Description:	Save Adjustment Budget Approval/Rejection
-- CALL SP: Plan_SaveAdjustmentBudgetApprovalRejection_sp '1','Test.png','Version 1 Rejected', 0,1,2647
-- 2016-04-20 by JP: Add call to SP for updating Balance for Fund and Item (Sp: Plan_UpdateProjectFundAndItemForAdjustment_sp)
-- SNagpal 04-Apr-2019 : #86552 Add [] brackets for Audit database
-- =============================================
CREATE PROCEDURE [dbo].[Plan_SaveAdjustmentBudgetApprovalRejection_sp]
    @VersionNumber NVARCHAR(50) ,
    @FileName NVARCHAR(500) ,
    @RejectReason NVARCHAR(MAX) ,
    @Approved BIT ,
    @Rejected BIT ,
    @UserId INT
AS
    BEGIN
        SET NOCOUNT ON;

        DECLARE @PendingAdjustments TABLE
            (
              AdjustmentId INT ,
              IsUpdated BIT DEFAULT ( 0 )
            );

        DECLARE @Result NVARCHAR(MAX) ,
            @FMSAuditDBName NVARCHAR(50) ,
            @AuditUserID NVARCHAR(50) ,
            @AuditDate NVARCHAR(50) ,
            @AuditUser NVARCHAR(100) ,
            @AdjustmentId INT;

        SELECT  @AuditUser = ISNULL(FirstName, UserName) + ISNULL(LastName, '')
        FROM    dbo.User_UserDetail
        WHERE   [User_ID] = @UserId; 
        SET @AuditDate = CONVERT(NVARCHAR(50), GETDATE());

        SET @AuditUserID = @UserId;

        SELECT  @FMSAuditDBName = KeyValue
        FROM    dbo.AAAA_ConfigSettings
        WHERE   KeyName = 'FMSAuditDatabaseName';

		SET @FMSAuditDBName = '[' + @FMSAuditDBName + ']';

        BEGIN TRY	

            BEGIN TRANSACTION;

            INSERT  INTO @PendingAdjustments
                    ( AdjustmentId ,
                      IsUpdated
                    )
                    SELECT  PA.AdjustmentBudget_Id ,
                            0
                    FROM    Plan_Adjustment PA
                    WHERE   PA.Status = 101 -- Pending Status
                            AND PA.VersionNumber = @VersionNumber;

            INSERT  INTO dbo.Plan_AdjustmentApprovalRejections
                    ( AdjustmentBudgetId ,
                      IsApproved ,
                      ApprovedBy ,
                      ApprovedOn ,
                      ApprovalRejectionFileName ,
                      IsRejected ,
                      RejectReason ,
                      RejectedBy ,
                      RejectedOn ,
                      CapturerID ,
                      DateCaptured ,
                      ModifierID ,
                      DateModified
                    )
                    SELECT  PA.AdjustmentBudget_Id , -- AdjustmentBudgetId - int
                            CASE WHEN @Approved = 1 THEN 1
                                 ELSE NULL
                            END , -- IsApproved - bit
                            CASE WHEN @Approved = 1 THEN @UserId
                                 ELSE NULL
                            END , -- ApprovedBy - int
                            CASE WHEN @Approved = 1 THEN GETDATE()
                                 ELSE NULL
                            END , -- ApprovedOn - datetime
                            @FileName , -- ApprovalFileName - nvarchar(500)
                            CASE WHEN @Rejected = 1 THEN 1
                                 ELSE NULL
                            END , -- IsRejected - bit
                            CASE WHEN @Rejected = 1 THEN @RejectReason
                                 ELSE NULL
                            END , -- RejectReason - nvarchar(max)
                            CASE WHEN @Rejected = 1 THEN @UserId
                                 ELSE NULL
                            END , -- RejectedBy - int
                            CASE WHEN @Rejected = 1 THEN GETDATE()
                                 ELSE NULL
                            END , -- RejectedOn - datetime
                            @UserId , -- CapturerID - int
                            GETDATE() , -- DateCaptured - datetime
                            NULL , -- ModifierID - int
                            NULL  -- DateModified - datetime
                    FROM    Plan_Adjustment PA
                    WHERE   PA.Status = 101 -- Pending Status
                            AND PA.VersionNumber = @VersionNumber;

            DECLARE @sql VARCHAR(MAX)= '';
            SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                + '.[dbo].[aPlan_Adjustment]
                ( 
				[AuditUserID] ,
                [AuditDate] ,
                [AuditUser] ,
				[AdjustmentBudget_Id],
				FinYear ,
				FromProjectId ,
				ToProjectId ,
				FromSCOAProjectID ,
				ToSCOAProjectID ,
				FromSCOAFunctionId ,
				ToSCOAFunctionId ,
				FromDivisionId ,
				ToDivisionId ,
				FromSCOAFundID ,
				ToSCOAFundID ,
				FromSCOARegion ,
				ToSCOARegion ,
				FromSCOAItem ,
				ToSCOAItem ,
				ReasonForAdjustment ,
				TypeOfAdjustment ,
				FromAvailableFund ,
				FromAdjustmentAmount ,
				FromNewAvailableBudget ,
				ToAvailableFund ,
				ToAdjustmentAmount ,
				ToNewAvailableBudget ,
				AdjustmentReferenceNumber ,
				VersionNumber ,
				Status ,
				TransferBy ,
				TransferOn ,
				CapturerID ,
				DateCaptured ,
				ModifierID ,
				DateModified
        )
		SELECT ''' + CAST(@AuditUserID AS VARCHAR(100)) + ''','''
                + CONVERT(NVARCHAR(100), @AuditDate, 121) + ''','''
                + CAST(@AuditUser AS NVARCHAR(200))
                + ''',[AdjustmentBudget_Id]
      ,[FinYear]
      ,[FromProjectId]
      ,[ToProjectId]
      ,[FromSCOAProjectID]
      ,[ToSCOAProjectID]
      ,[FromSCOAFunctionId]
      ,[ToSCOAFunctionId]
      ,[FromDivisionId]
      ,[ToDivisionId]
      ,[FromSCOAFundID]
      ,[ToSCOAFundID]
      ,[FromSCOARegion]
      ,[ToSCOARegion]
      ,[FromSCOAItem]
      ,[ToSCOAItem]
      ,[ReasonForAdjustment]
      ,[TypeOfAdjustment]
      ,[FromAvailableFund]
      ,[FromAdjustmentAmount]
      ,[FromNewAvailableBudget]
      ,[ToAvailableFund]
      ,[ToAdjustmentAmount]
      ,[ToNewAvailableBudget]
      ,[AdjustmentReferenceNumber]
      ,[VersionNumber]
      ,[Status]
      ,[TransferBy]
      ,[TransferOn]
      ,[CapturerID]
      ,[DateCaptured]
      ,[ModifierID]
      ,[DateModified]
  FROM [dbo].[Plan_Adjustment]
				Where Status = 101 AND VersionNumber = ' + @VersionNumber;

            EXEC sp_sqlexec @sql;

            IF ( @Approved = 1 )
                BEGIN
                    WHILE ( ( SELECT    COUNT(AdjustmentId)
                              FROM      @PendingAdjustments
                              WHERE     IsUpdated = 0
                            ) > 0 )
                        BEGIN
                            SELECT TOP 1
                                    @AdjustmentId = AdjustmentId
                            FROM    @PendingAdjustments
                            WHERE   IsUpdated = 0;

                            EXEC Plan_UpdateProjectFundAndItemForAdjustment_sp @AdjustmentId,
                                @UserId;

                            UPDATE  @PendingAdjustments
                            SET     IsUpdated = 1
                            WHERE   AdjustmentId = @AdjustmentId;
                        END;
                END;

            UPDATE  Plan_Adjustment
            SET     Status = 102 -- Set Status to Final
            FROM    dbo.Plan_Adjustment
            WHERE   Plan_Adjustment.Status = 101 -- Pending Status
                    AND Plan_Adjustment.VersionNumber = @VersionNumber;

            SET @Result = 'success';

            COMMIT TRANSACTION;
        END TRY
        BEGIN CATCH
		
            DECLARE @Err NVARCHAR(1000);
            SET @Err = ERROR_MESSAGE();
            RAISERROR (@Err, 16,1);
            SET @Result = @Err;
			
            ROLLBACK TRANSACTION;
        END CATCH;

        SELECT  @Result AS Result ,
                @VersionNumber AS VersionNumber;

    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_SCOASegmentsFilteredList_sp]    Script Date: 2026/03/10 7:23:47 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- ============================================================================================          
-- Author:  Sahil Nagpal       
-- Create date: 26/10/2017
-- Description: #63164  Budget Register Changes  
-- exec Plan_SCOASegmentsFilteredList_sp 0,0,'SCOAItemAssetRevenueFBS','2018/2019'
-- exec Plan_SCOASegmentsFilteredList_sp 15060,1,'SCOAItemAssetRevenueFBS','2018/2019'
-- exec Plan_SCOASegmentsFilteredList_sp 15063,2,'SCOAItemAssetRevenueFBS','2018/2019'
-- exec Plan_SCOASegmentsFilteredList_sp 15078,3,'SCOAItemAssetRevenueFBS','2018/2019'
-- exec Plan_SCOASegmentsFilteredList_sp 15156,4,'SCOAItemAssetRevenueFBS','2018/2019'
-- SNagpal 31-10-2017 : Add Script for SegmentType = SCOAItemAssetRevenueFBS
-- SNagpal 06-11-2017 : Add Script for SegmentType = SCOAItemGainsLossesOR
-- SNagpal 19-02-2017 : Apply finyear in inner join
-- SNagpal 18-02-2019 : 84009, Get SCOA Segments based upon FinYear
-- OShiri 28-05-2019 : Add multiyear concept to SCOA segments based upon financial year
-- ============================================================================================          
CREATE PROCEDURE [dbo].[Plan_SCOASegmentsFilteredList_sp]
    @ScoaID INT ,
    @Level INT ,
    @SegmentType NVARCHAR(50) ,
    @FinYear NVARCHAR(9)
AS
    BEGIN
		
DECLARE @SCOASegmentPart VARCHAR(Max)
	
IF ( @SegmentType = 'SCOAProjectFBS' )
    BEGIN
	
Declare @SCOAInnerId INT, @LevelInner INT;

SET @SCOAInnerId = @ScoaID 
SET @LevelInner = @Level

                IF ( @LevelInner = 0 )
                    SELECT  @SCOAInnerId = NULL;
                ELSE
                    BEGIN
                        WHILE @LevelInner < 0
                            BEGIN
                                SELECT DISTINCT
                                        @SCOAInnerId = ScoaParentID
                                FROM    dbo.Const_SCOA_Project_Structure_ByYear(@FinYear)  csps
                                        INNER JOIN dbo.Const_PlanSCOAProjectFBS cps ON cps.ScoaId = csps.ScoaID
                                WHERE   csps.ScoaID = @SCOAInnerId
                                        AND cps.IsEnable = 1
                                        AND cps.FinYear = @FinYear;
			
                                SELECT  @LevelInner = @LevelInner + 1;
                            END;
                        IF ( @SCOAInnerId IS NULL )
                            BEGIN
                                SELECT  @LevelInner = 0;
                            END;
                        ELSE
                            BEGIN
                                SELECT  @LevelInner = NULL;
                            END;
                    END;
                IF ( @LevelInner <> 0 )
                    SELECT  @LevelInner = NULL;
                SELECT DISTINCT
                        ISNULL(ScoaParentID, 0) AS ScoaParentID ,
                        Scoa.ScoaID ,
                        Scoa.ScoaDesc ,
                        Scoa.LevelID ,
                        Scoa.PostingLevel ,
                        Scoa.ScoaShortDesc ,
                        Scoa.ScoaCode
                FROM    dbo.Const_SCOA_Project_Structure_ByYear(@FinYear)  Scoa
                        INNER JOIN dbo.Const_PlanSCOAProjectFBS cps ON cps.ScoaId = Scoa.ScoaID
                WHERE   LevelID = ISNULL(@LevelInner, LevelID)
                        AND cps.IsEnable = 1
                        AND cps.FinYear = @FinYear
                        AND ISNULL(ScoaParentID, -100) = ISNULL(@SCOAInnerId,ISNULL(ScoaParentID,-100))
                        AND Enabled = 1
                ORDER BY ScoaCode;

            END;
        ELSE
            IF ( @SegmentType = 'SCOAItemAssetRevenueFBS' )
                BEGIN
				
			
			SET @SCOAInnerId =@ScoaID 
			SET @LevelInner = @Level

                    IF ( @LevelInner = 0 )
                        BEGIN
                            SELECT @SCOAInnerId = NULL;
                        END;
                    ELSE
                        BEGIN
                            WHILE @LevelInner < 0
                                BEGIN
                                    SELECT DISTINCT
                                            @SCOAInnerId = ScoaParentID
                                    FROM    dbo.Const_SCOA_Structure_ByYear(@FinYear)  csps
                                            LEFT JOIN dbo.Const_PlanSCOAItemRevenueFBS cps ON cps.ScoaItemId = csps.ScoaID AND cps.FinYear= @FinYear 
                                            LEFT JOIN dbo.Const_PlanSCOAItemAssetFBS cpsa ON cpsa.ScoaItemId = csps.ScoaID AND cpsa.FinYear= @FinYear 
                                    WHERE   csps.ScoaID = @SCOAInnerId
                                            AND ( cps.IsEnable = 1
                                                  OR cpsa.IsEnable = 1
                                                )
                                            AND ( cps.FinYear = @FinYear
                                                  OR cpsa.FinYear = @FinYear
                                                );
			
                                    SELECT  @LevelInner = @LevelInner + 1;
                                END;
                            IF ( @SCOAInnerId IS NULL )
                                BEGIN
                                    SELECT  @LevelInner = 0;
                                END;
                            ELSE
                                BEGIN
                                    SELECT  @LevelInner = NULL;
                                END;
                        END;
                    IF ( @LevelInner <> 0 )
                        SELECT  @LevelInner = NULL;

                    SELECT DISTINCT
                            ISNULL(ScoaParentID, 0) AS ScoaParentID ,
                            Scoa.ScoaID ,
                            Scoa.ScoaDesc ,
                            Scoa.LevelID ,
                            Scoa.PostingLevel ,
                            Scoa.ScoaShortDesc ,
                            Scoa.ScoaCode
                    FROM    dbo.Const_SCOA_Structure_ByYear(@FinYear)  Scoa
                            LEFT JOIN dbo.Const_PlanSCOAItemRevenueFBS cps ON cps.ScoaItemId = Scoa.ScoaID AND cps.FinYear= @FinYear
                            LEFT JOIN dbo.Const_PlanSCOAItemAssetFBS cpsa ON cpsa.ScoaItemId = Scoa.ScoaID AND cpsa.FinYear= @FinYear
                    WHERE   LevelID = ISNULL(@LevelInner, LevelID)
                            AND ( cps.IsEnable = 1
                                  OR cpsa.IsEnable = 1
                                )
                            AND ( cps.FinYear = @FinYear
                                  OR cpsa.FinYear = @FinYear
                                )
                            AND ISNULL(ScoaParentID, -100) = ISNULL(@SCOAInnerId,
                                                              ISNULL(ScoaParentID,
                                                              -100))
                            AND Enabled = 1
                    ORDER BY ScoaCode
                END;
		ELSE
		 IF ( @SegmentType = 'SCOAItemGainsLossesOR' )
                BEGIN
				
			
			SET @SCOAInnerId = @ScoaID 
			SET @LevelInner = @Level

                    IF ( @LevelInner = 0 )
                        BEGIN
                            SELECT @SCOAInnerId = NULL;
                        END;
                    ELSE
                        BEGIN
                            WHILE @LevelInner < 0
                                BEGIN
                                    SELECT DISTINCT
                                            @SCOAInnerId = ScoaParentID
                                    FROM    dbo.Const_SCOA_Structure_ByYear(@FinYear)  csps
											LEFT JOIN dbo.Const_PlanSCOAItemGainOR cps ON cps.ScoaItemId = csps.ScoaID AND cps.FinYear= @FinYear
											LEFT JOIN dbo.Const_PlanSCOAItemLossOE cpsa ON cpsa.ScoaItemId = csps.ScoaID AND cpsa.FinYear= @FinYear
                                    WHERE   csps.ScoaID = @SCOAInnerId
                                            AND ( cps.IsEnable = 1
                                                  OR cpsa.IsEnable = 1
                                                )
                                            AND ( cps.FinYear = @FinYear
                                                  OR cpsa.FinYear = @FinYear
                                                );
			
                                    SELECT  @LevelInner = @LevelInner + 1;
                                END;
                            IF ( @SCOAInnerId IS NULL )
                                BEGIN
                                    SELECT  @LevelInner = 0;
                                END;
                            ELSE
                                BEGIN
                                    SELECT  @LevelInner = NULL;
                                END;
                        END;
                    IF ( @LevelInner <> 0 )
                        SELECT  @LevelInner = NULL;

                    SELECT DISTINCT
                            ISNULL(ScoaParentID, 0) AS ScoaParentID ,
                            Scoa.ScoaID ,
                            Scoa.ScoaDesc ,
                            Scoa.LevelID ,
                            Scoa.PostingLevel ,
                            Scoa.ScoaShortDesc ,
                            Scoa.ScoaCode
                    FROM    dbo.Const_SCOA_Structure_ByYear(@FinYear)  Scoa
                            LEFT JOIN dbo.Const_PlanSCOAItemGainOR cps ON cps.ScoaItemId = Scoa.ScoaID AND cps.FinYear= @FinYear 
                            LEFT JOIN dbo.Const_PlanSCOAItemLossOE cpsa ON cpsa.ScoaItemId = Scoa.ScoaID AND cpsa.FinYear= @FinYear
                    WHERE   LevelID = ISNULL(@LevelInner, LevelID) AND
							(Scoa.ScoaCode LIKE 'IR%' OR
							(Scoa.ScoaCode LIKE 'IZ%' 
                            AND ( cps.IsEnable = 1
                                  OR cpsa.IsEnable = 1
                                )
                            AND ( cps.FinYear = @FinYear
                                  OR cpsa.FinYear = @FinYear
                                )))
                            AND ISNULL(ScoaParentID, -100) = ISNULL(@SCOAInnerId,
                                                              ISNULL(ScoaParentID,
                                                              -100))
                            AND Enabled = 1
                    ORDER BY ScoaCode;
                END;

    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_SDBIPProgressRpt_sp]    Script Date: 2026/03/10 7:23:47 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 2016-03-31
-- Description:	SDBIP Progress Report
-- Plan_SDBIPProgressRpt_sp '2017/2018',0,0,0
-- 2016-04-08 by JP: Reference for Divsion is updated to Plan_ProjectItem
-- 2016-04-22 by JP: Add Fields DepartmentName, Responsible Post
-- 2016-05-25 By RC: Grouping error fixed and link betweenproject and KPI fixed
-- 2016-11-04 TP46156 Varun:Organogram: Job Profile and Positions
-- 2017-03-28 SNagpal: Add inner join with Plan_ProjectIDP and format join structures
-- 2018-06-15 Chirag Patel: IF @Quater=0 so No need to @QuaterStartdate and @QuaterEnddate then Add conditions 
-- =============================================
CREATE PROCEDURE [dbo].[Plan_SDBIPProgressRpt_sp]
	-- Add the parameters for the stored procedure here
    @FinYear NVARCHAR(9) = '2015/2016' ,
    @Quater NVARCHAR(5) = 0 ,
    @Department INT = 0 ,
    @ResponsiblePost INT = 0
AS
    BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
        SET NOCOUNT ON;

        DECLARE @QuaterStartdate DATETIME ,
            @QuaterEnddate DATETIME ,
            @StartDate NVARCHAR(10);

		-- Get Quater Start and End date
        IF ( @Quater <> 0 )
            BEGIN
                SELECT  @QuaterStartdate = StartDate ,
                        @QuaterEnddate = EndDate
                FROM    dbo.Planning_GetQuarterStartEndDate_fxn(SUBSTRING(@FinYear,
                                                              1, 4), @Quater);
           
                SELECT  ProjectID ,
                        ProjectName ,
                        ISNULL(SUM(OriginalBudget), 0) AS OriginalBudget ,
                        ISNULL(SUM(ActualSpending), 0) AS ActualSpending ,
                        ISNULL(SUM(OriginalBudget), 0)
                        - ISNULL(SUM(ActualSpending), 0) AS DiffAmountBuagetAndActual ,
                        DepartmentName ,
                        ResponsiblePost
                FROM    ( SELECT 
				 DISTINCT           p.Project_ID AS ProjectID ,
                                    p.ProjectName ,
                                    BudgetAmount AS OriginalBudget ,
                                    gl.Debit AS ActualSpending ,
                                    ppi.PlanProjectItem_ID ,
                                    CASE WHEN @Department = 0 THEN 'All'
                                         ELSE CDep.DepartmentDesc
                                    END AS DepartmentName ,
                                    CASE WHEN @ResponsiblePost = 0 THEN 'All'
                                         ELSE ISNULL(emp.Surname, '') + ' '
                                              + ISNULL(emp.FirstName, '')
                                              + ' ('
                                              + ISNULL(jProfile.JobTitle, '')
                                              + ')'
                                    END AS ResponsiblePost
                          FROM      Plan_Project p
                                    INNER JOIN Plan_ProjectItem ppi ON p.Project_ID = ppi.ProjectID
                                    INNER JOIN dbo.Plan_ProjectIDP ppid ON ppid.ProjectID = p.Project_ID
                                    INNER JOIN IDP_Item IndIDP ON IndIDP.ItemParentID = ppid.ProjectIDPItemID
                                    INNER JOIN PMS_Indicator PInd ON PInd.ItemID = IndIDP.Item_ID
                                    INNER JOIN [PMS_IndicatorScorecardType] IndScor ON PInd.Kpi_ID = IndScor.KpiID
                                    LEFT JOIN Payroll_Employee AS emp ON emp.Employee_ID = PInd.ResponsiblePost
                                    LEFT JOIN Payroll_Position pp ON emp.PositionID = pp.Position_ID
                                    LEFT JOIN Payroll_JobProfile jProfile ON pp.JobProfileID = jProfile.JobProfile_ID
                                 LEFT JOIN Const_Division AS CDiv ON ppi.DivisionId = CDiv.Division_ID
                                    INNER JOIN Const_Department AS CDep ON CDep.Department_ID = CDiv.DepartmentID
                                    LEFT JOIN SCM_ProcurementPlanNew ppn ON p.Project_ID = ppn.PlanProjectID
                                    LEFT JOIN SCM_ProcurementPlanDetails ppd ON ppn.ProcurementPlan_ID = ppd.ProcurementPlanID
                                    LEFT JOIN SCM_Requisition sr ON ppn.ProcurementPlan_ID = sr.ProcurementID
                                    LEFT JOIN SCM_QuotationRequistion sqr ON sr.Requisition_ID = sqr.RequisitionID
                                    LEFT JOIN SCM_Tender st ON sqr.RequisitionID = st.RequisitionID
                                    LEFT JOIN SCM_Order so ON st.Tender_ID = so.TenderId
                                    LEFT JOIN SCM_Invoice si ON so.Order_ID = si.OrderID
                                    LEFT JOIN SCM_ServiceInvoice ssi ON ssi.RequisitionID = sr.Requisition_ID
                                    LEFT JOIN Led_GeneralLedger gl ON si.Invoice_ID = gl.ExtraLinkID_1
                          WHERE     IndScor.ScorecardTypeID = 1
                                    AND ( p.FinYear = @FinYear
                                          OR @FinYear = '0'
                                        )
                                    AND ( CDep.Department_ID = @Department
                                          OR @Department = 0
                                        )
                                    AND ( CONVERT(DATE, gl.PostingDate) BETWEEN CONVERT(DATE, @QuaterStartdate)
                                                              AND
                                                              CONVERT(DATE, @QuaterEnddate)
                                          OR @Quater = 0 OR gl.PostingDate IS NULL
                                        )
                                    AND ( PInd.ResponsiblePost = @ResponsiblePost
                                          OR @ResponsiblePost = 0
                                        )
                        ) AS Result
                GROUP BY ProjectID ,
                        ProjectName ,
                        DepartmentName ,
                        ResponsiblePost;
            END;
        ELSE
            BEGIN		
                

                SELECT  ProjectID ,
                        ProjectName ,
                        ISNULL(SUM(OriginalBudget), 0) AS OriginalBudget ,
                        ISNULL(SUM(ActualSpending), 0) AS ActualSpending ,
                        ISNULL(SUM(OriginalBudget), 0)
                        - ISNULL(SUM(ActualSpending), 0) AS DiffAmountBuagetAndActual ,
                        DepartmentName ,
                        ResponsiblePost
                FROM    ( SELECT 
				 DISTINCT           p.Project_ID AS ProjectID ,
                                    p.ProjectName ,
                                    BudgetAmount AS OriginalBudget ,
                                    gl.Debit AS ActualSpending ,
                                    ppi.PlanProjectItem_ID ,
                                    CASE WHEN @Department = 0 THEN 'All'
                                         ELSE CDep.DepartmentDesc
                                    END AS DepartmentName ,
                                    CASE WHEN @ResponsiblePost = 0 THEN 'All'
                                         ELSE ISNULL(emp.Surname, '') + ' '
                                              + ISNULL(emp.FirstName, '')
                                              + ' ('
                                              + ISNULL(jProfile.JobTitle, '')
                                              + ')'
                                    END AS ResponsiblePost
                          FROM      Plan_Project p
                                    INNER JOIN Plan_ProjectItem ppi ON p.Project_ID = ppi.ProjectID
                                    INNER JOIN dbo.Plan_ProjectIDP ppid ON ppid.ProjectID = p.Project_ID
                                    INNER JOIN IDP_Item IndIDP ON IndIDP.ItemParentID = ppid.ProjectIDPItemID
                                    INNER JOIN PMS_Indicator PInd ON PInd.ItemID = IndIDP.Item_ID
                                    INNER JOIN [PMS_IndicatorScorecardType] IndScor ON PInd.Kpi_ID = IndScor.KpiID
                                    LEFT JOIN Payroll_Employee AS emp ON emp.Employee_ID = PInd.ResponsiblePost
                                    LEFT JOIN Payroll_Position pp ON emp.PositionID = pp.Position_ID
                                    LEFT JOIN Payroll_JobProfile jProfile ON pp.JobProfileID = jProfile.JobProfile_ID
                                    LEFT JOIN Const_Division AS CDiv ON ppi.DivisionId = CDiv.Division_ID
                                    INNER JOIN Const_Department AS CDep ON CDep.Department_ID = CDiv.DepartmentID
                                    LEFT JOIN SCM_ProcurementPlanNew ppn ON p.Project_ID = ppn.PlanProjectID
                                    LEFT JOIN SCM_ProcurementPlanDetails ppd ON ppn.ProcurementPlan_ID = ppd.ProcurementPlanID
                                    LEFT JOIN SCM_Requisition sr ON ppn.ProcurementPlan_ID = sr.ProcurementID
                                    LEFT JOIN SCM_QuotationRequistion sqr ON sr.Requisition_ID = sqr.RequisitionID
                                    LEFT JOIN SCM_Tender st ON sqr.RequisitionID = st.RequisitionID
                                    LEFT JOIN SCM_Order so ON st.Tender_ID = so.TenderId
                                    LEFT JOIN SCM_Invoice si ON so.Order_ID = si.OrderID
                                    LEFT JOIN SCM_ServiceInvoice ssi ON ssi.RequisitionID = sr.Requisition_ID
                                    LEFT JOIN Led_GeneralLedger gl ON si.Invoice_ID = gl.ExtraLinkID_1
                          WHERE     IndScor.ScorecardTypeID = 1
                                    AND ( p.FinYear = @FinYear
                                          OR @FinYear = '0'
                                        )
                                    AND ( CDep.Department_ID = @Department
                                          OR @Department = 0
                                        )                              
                                    AND ( PInd.ResponsiblePost = @ResponsiblePost
                                          OR @ResponsiblePost = 0
                                        )
                        ) AS Result
                GROUP BY ProjectID ,
                        ProjectName ,
                        DepartmentName ,
                        ResponsiblePost;

            END;


    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_SubmitAdjustmentBudget_sp]    Script Date: 2026/03/10 7:23:47 AM ******/
SET ANSI_NULLS ON
