-- =============================================    
-- Author:  Nirav Parikh    
-- Create date: 2017-11-24    
-- Description: Create Adjustment Budget Approval    
-- EXEC [Plan_SubmitAdjustmentBudget_sp_Temp_16_10_2018] '2018/2019', 1, '06062017095920CR_Budget_String_08052017.docx', '15 October 2018', '2018/2019_ADJB017', '2018/2019_ADJB017', 'Adjustment Budget approved by Council in accordance with legislative requirements'    
-- DO NOT APPLY REDGATE SQL FORMAT    
-- 02-Jan-2018 : Add Plan_BudgetRegister Scripts    
-- 26-Mar-2018 : SNagpal 70001 -> Fix the script. Apply @tblAuditLog & other fixes    
-- 27-Mar-2018 : SNagpal -> Fix issue of ProjectFundYear_Id while new insert into Plan_projectItem table @ObjProjectFundYearID    
-- 28-Mar-2018 : SNagpal -> Fix issue while submiting budget    
-- 09-Apr-2018 : SNagpal -> Fix issue While Updating Plan_ProjectRegions    
