-- 07-May-2018 : SNagpal -> Fix issue of updating AdjustmentId    
-- 16-May-2018 : RChetty -> Fix IDP insert 72565    
-- 05-June-2018: SNagpal -> 70713 Fix issue of Inserting Plan_FundingSourceDocs     
-- 12-Sept-2018: SNagpal -> 77210 Fix issue of Inserting Plan_FundingSourceBudget_Header    
-- 17-Oct-2018 : ChiragPatel -> #61596 SP Optimization    
-- 16-Nov-2018 by SNagpal: #80663 Add logic to save Budget into Budget Consumption Table instead of Budget Register    
-- 24-Jan-2019 by SNagpal: #61596 - #83633 - Add functionality to Update ProjectCode, ProjectParentID    
-- 20-May-2019 by SNagpal: 88917 Add code to disable FK before insert    
-- 03-Jun-2019 by NParikh: #89303 QA Multi - Remaining Budget Exceeds Original Budget - Code Revert  
-- 12-Jun-2019 by NParikh: #82790 Add More Payment types on a vendor and on Payment screen
-- 25 Feb 2020 Pipko V. US 21222 : use the user Processing Month for Ledger Postings
-- 02-Apr-2020 by CMoodley: 31746 - Handle instance where Audit DB name has hyphen
-- 12-May-2020 by CMoodley: 33620 - Increase data type for @AvailableAmountForBudgetRegister, @TxnAmountForBudgetRegister
-- 04-Jun-2020 by CMoodley: 34850 - Fix issue where null budget amounts inserted into Plan_BudgetConsumption and Plan_BudgetRegister table if new plan project item
-- 14-Jun-2020 by CMoodley: 34814 - Pass correct BudgetConsumptionProcessID to Plan_BudgetConsumption table
-- 11-Aug-2020 by CMoodley: 39875 - Write multi-year values to Plan_BudgetConsumption
-- 29-Jan-2021 by CMoodley: 54586 - When inserting where RefFundingSourceDetailId is null, check FundingSourceBudgetHeaderID, FundingSourceID is not null
-- 18-Feb-2023 by SN: 58285 Add IsActiveForSCM flag
-- 07-Aug-2023 by CMoodley: #105236 Include CostingProject field
-- 04-Jun-2025 by CMoodley: #121011 Insert into Plan_FundingSourceBudget_Detail only when FundingSourceBudgetHeaderID IS NOT NULL AND FundingSourceID IS NOT NULL 
-- 29-Jul-2025 By CMoodley: #120736 Optimise SP
-- 08-Mar-2026 by CMoodley: #127606 - Set HistoricalProjectCode to PlanProjectItem_ID|0 for new PPIs in Plan_ProjectItem
-- =============================================    
CREATE PROCEDURE [dbo].[Plan_SubmitAdjustmentBudget_sp]
    @FinancialYear NVARCHAR(9),
    @UserId INT,
    @ApprovedAdjustmentBudgetFileName NVARCHAR(500),
    @CouncilApprovedDate DATETIME,
    @VersionNumber NVARCHAR(50),
    @VersionName NVARCHAR(1000),
    @Comments NVARCHAR(1000)
AS 
BEGIN

    BEGIN TRY

        BEGIN TRANSACTION AdjustmentsTran;

        --=================Disable FK relations    
        IF OBJECT_ID('FK_Plan_Project_Const_SCOA_Project_Structure') IS NOT NULL
        BEGIN
            ALTER TABLE Plan_Project NOCHECK CONSTRAINT FK_Plan_Project_Const_SCOA_Project_Structure;
        END;

        IF OBJECT_ID('FK_Plan_ProjectFunctions_Const_SCOA_Function_Structure') IS NOT NULL
        BEGIN
            ALTER TABLE Plan_ProjectFunctions NOCHECK CONSTRAINT FK_Plan_ProjectFunctions_Const_SCOA_Function_Structure;
        END;

        IF OBJECT_ID('FK_Plan_ProjectItem_Const_SCOA_Structure') IS NOT NULL
        BEGIN
            ALTER TABLE Plan_ProjectItem NOCHECK CONSTRAINT FK_Plan_ProjectItem_Const_SCOA_Structure;
        END;

        IF OBJECT_ID('FK_Plan_ProjectFund_Const_SCOA_Funds_Structure') IS NOT NULL
        BEGIN
            ALTER TABLE Plan_ProjectFund NOCHECK CONSTRAINT FK_Plan_ProjectFund_Const_SCOA_Funds_Structure;
        END;

