        --Declare Variables            
        DECLARE @ReferencePlanProjectItem_ID INT;

		DECLARE @countPlanFundingSourceBudgetDetailNullID INT = 1;
        CREATE TABLE #tblPlanFundingSourceBudgetDetailNull 
        (
			CountPlanFundingSourceBudgetDetailNullID INT IDENTITY(1,1) NOT NULL,
            AdjustmentFundingSourceBudgetDetailID INT,
            FundingSourceBudgetHeaderID INT,
            FundingSourceID INT,
            ScoaID INT,
            FundingSourceBudget DECIMAL(16, 2),
            IsHidden BIT,
            UploadedDocument NVARCHAR(255)
        );

        --GetBudgetTxnType    
        SELECT @BudgetTxnTypeId = BudgetTransactionType_ID
        FROM dbo.Const_BudgetTransactionType_sys
        WHERE BudgetTransDesc = 'Adjusted';

        ----------Plan_FundingSourceBudget_Detail Start    
        --Set Variables    
        SELECT TOP 1
               @AdjustmentFundingVersionId = AdjustmentFundingBudgetVersion_ID
        FROM Plan_AdjustmentFundingBudgetVersion (NOLOCK)
        WHERE VersionName LIKE @FinancialYear + '%'
        ORDER BY AdjustmentFundingBudgetVersion_ID DESC; 

        --New Code Added for Plan_AdjustmentFundingSourceBudget_Header by SNagpal 12-09-2018--    
        INSERT INTO dbo.Plan_FundingSourceBudget_Header
        (
            FinancialYear,
            Submitted,
            DateCaptured,
            CapturerID
        )
        SELECT FinancialYear,
               Submitted,
               GETDATE(),
               @UserId
        FROM dbo.Plan_AdjustmentFundingSourceBudget_Header
        WHERE AdjustmentFundingVersionId = @AdjustmentFundingVersionId
              AND RefFundingSourceHeaderId IS NULL;

        SELECT @RefFundingSourceHeaderId = SCOPE_IDENTITY();
        --New Code Added for Plan_FundingSourceDocs by SNagpal 05-06-2018--    

        --Insert Data into Plan_FundingSourceBudget_Detail, Plan_AdjustmentFundingSourceDocs  where RefFundingSourceDetailId IS NULL    
        INSERT INTO #tblPlanFundingSourceBudgetDetailNull
        (
            AdjustmentFundingSourceBudgetDetailID,
            FundingSourceBudgetHeaderID,
            FundingSourceID,
            ScoaID,
            FundingSourceBudget,
            IsHidden,
            UploadedDocument
        )
        SELECT AdjustmentFundingSourceBudgetDetail_ID,
               ISNULL(pafsbh.RefFundingSourceHeaderId, @RefFundingSourceHeaderId),
               pafsbd.AdjustmentFundingSourceID,
               pafsbd.ScoaID,
               pafsbd.FundingSourceBudget,
               pafsbd.IsHidden,
               pafsbd.UploadedDocument
        FROM dbo.Plan_AdjustmentFundingSourceBudget_Detail pafsbd (NOLOCK)
            INNER JOIN dbo.Plan_AdjustmentFundingSourceBudget_Header pafsbh (NOLOCK)
                ON pafsbh.AdjustmentFundingSourceBudgetHeader_ID = pafsbd.AdjustmentFundingSourceBudgetHeaderID
        WHERE pafsbd.RefFundingSourceDetailId IS NULL
              AND pafsbd.AdjustmentFundingVersionId = @AdjustmentFundingVersionId;

		SET @countPlanFundingSourceBudgetDetailNullID = (SELECT MIN(AdjustmentFundingSourceBudgetDetailID) FROM #tblPlanFundingSourceBudgetDetailNull);
        WHILE EXISTS (SELECT 1 FROM #tblPlanFundingSourceBudgetDetailNull WHERE FundingSourceBudgetHeaderID IS NOT NULL AND FundingSourceID IS NOT NULL)
        BEGIN
			WHILE (@countPlanFundingSourceBudgetDetailNullID <= (SELECT MAX(AdjustmentFundingSourceBudgetDetailID) FROM #tblPlanFundingSourceBudgetDetailNull))
			BEGIN
				SELECT
					   @AdjustmentFundingSourceBudgetDetail_ID = AdjustmentFundingSourceBudgetDetailID,
					   @FundingSourceHeaderId = FundingSourceBudgetHeaderID,
					   @FundingSourceID = FundingSourceID,
					   @ScoaIDFromFunding = ScoaID,
					   @FundingSourceBudgetFromFunding = FundingSourceBudget,
					   @IsHiddenFromFunding = IsHidden,
					   @UploadedDocumentFromFunding = UploadedDocument
				FROM #tblPlanFundingSourceBudgetDetailNull
				WHERE 
					AdjustmentFundingSourceBudgetDetailID = @countPlanFundingSourceBudgetDetailNullID
					AND FundingSourceBudgetHeaderID IS NOT NULL AND FundingSourceID IS NOT NULL;

				--Insert Data into Plan_FundingSourceBudget_Detail    
				INSERT INTO dbo.Plan_FundingSourceBudget_Detail
				(
					FundingSourceBudgetHeaderID,
					FundingSourceID,
					ScoaID,
					FundingSourceBudget,
					IsHidden,
					UploadedDocument,
					DateCaptured,
					CapturerID
				)
				VALUES
				(@FundingSourceHeaderId, @FundingSourceID, @ScoaIDFromFunding, @FundingSourceBudgetFromFunding,
				 @IsHiddenFromFunding, @UploadedDocumentFromFunding, GETDATE(), @UserId);

				SELECT @PlanFundingSourceBudgetDetail_Id = SCOPE_IDENTITY();

				--Insert Data into Plan_FundingSourceDocs    
				INSERT INTO dbo.Plan_FundingSourceDocs
				(
					SupportingDocsID,
					FundingSourceBudgetDetailID,
					ScoaID,
					DateCaptured,
					CapturerID
				)
				SELECT SupportingDocsID,
					   @PlanFundingSourceBudgetDetail_Id,
					   ScoaID,
					   GETDATE(),
					   @UserId
				FROM dbo.Plan_AdjustmentFundingSourceDocs (NOLOCK)
				WHERE AdjustmentFundingSourceBudgetDetailID = @AdjustmentFundingSourceBudgetDetail_ID;

				SET @countPlanFundingSourceBudgetDetailNullID = @countPlanFundingSourceBudgetDetailNullID + 1;
			END;
        END;

        --New Code Added for Plan_FundingSourceDocs by SNagpal 05-06-2018--    
        --Insert Data into @tblFundingSource where RefFundingSourceDetailId IS NOT NULL    
        INSERT INTO #tblFundingSource
        (
            RefFundingSourceDetailId,
            AdjustmentFundingSourceID,
            ScoaID,
            FundingSourceBudget,
            IsHidden,
            UploadedDocument
        )
        SELECT pafsbd.RefFundingSourceDetailId,
               pafsbd.AdjustmentFundingSourceID,
               pafsbd.ScoaID,
               pafsbd.FundingSourceBudget,
               pafsbd.IsHidden,
               pafsbd.UploadedDocument
        FROM dbo.Plan_AdjustmentFundingSourceBudget_Detail pafsbd (NOLOCK)
        WHERE pafsbd.RefFundingSourceDetailId IS NOT NULL
              AND pafsbd.AdjustmentFundingVersionId = @AdjustmentFundingVersionId;

        --Using While Loop Data Update into Plan_FundingSourceBudget_Detail  
		SET @countFundingSourceID = (SELECT MIN(FundingSourceID) FROM #tblFundingSource);
        WHILE (@countFundingSourceID <= (SELECT MAX(FundingSourceID) FROM #tblFundingSource))
        BEGIN
            SELECT
                   @RefFundingSourceDetailId = RefFundingSourceDetailId,
                   @AdjustmentFundingSourceID = AdjustmentFundingSourceID,
                   @ScoaID = ScoaID,
                   @FundingSourceBudget = FundingSourceBudget,
                   @IsHidden = IsHidden,
                   @UploadedDocument = UploadedDocument
            FROM #tblFundingSource
			WHERE  FundingSourceID = @countFundingSourceID;

            IF (@RefFundingSourceDetailId > 0)
            BEGIN

                UPDATE dbo.Plan_FundingSourceBudget_Detail
                SET FundingSourceID = @AdjustmentFundingSourceID,
                    ScoaID = @ScoaID,
                    FundingSourceBudget = @FundingSourceBudget,
                    IsHidden = @IsHidden,
                    UploadedDocument = @UploadedDocument,
                    DateModified = GETDATE(),
                    ModifierID = @UserId
                WHERE FundingSourceBudgetDetail_ID = @RefFundingSourceDetailId;

                --New Code Added for Plan_FundingSourceDocs by SNagpal 05-06-2018--    
                INSERT INTO dbo.Plan_FundingSourceDocs
                (
                    SupportingDocsID,
                    FundingSourceBudgetDetailID,
                    ScoaID,
                    DateCaptured,
                    CapturerID
                )
                SELECT pdocs.SupportingDocsID,
                       PAP.RefFundingSourceDetailId,
                       PAP.ScoaID,
                       GETDATE(),
                       @UserId
                FROM dbo.Plan_AdjustmentFundingSourceDocs pdocs (NOLOCK)
                    INNER JOIN dbo.Plan_AdjustmentFundingSourceBudget_Detail PAP (NOLOCK)
                        ON PAP.AdjustmentFundingSourceBudgetDetail_ID = pdocs.AdjustmentFundingSourceBudgetDetailID
                WHERE PAP.AdjustmentFundingVersionId = @AdjustmentFundingVersionId
                      AND pdocs.RefFundingSourceDocsID IS NULL
                      AND PAP.RefFundingSourceDetailId = @RefFundingSourceDetailId;

                --New Code Added for Plan_FundingSourceDocs by SNagpal 05-06-2018--    
            END;

			SET @countFundingSourceID = @countFundingSourceID + 1

        END;
        ----------Plan_FundingSourceBudget_Detail End    

        ----------Plan_AdjustmentProject Start    
        --Set Variables    
        SELECT TOP 1
               @AdjustmentVersionId = AdjustmentBudgetVersion_ID
        FROM dbo.Plan_AdjustmentBudgetVersion (NOLOCK)
        WHERE VersionName LIKE @FinancialYear + '%'
        ORDER BY AdjustmentBudgetVersion_ID DESC;

        --Insert Data into @tblProject based on AdjustmentVersionId    
        INSERT INTO #tblProject
        (
            ProjectName,
            ProjectDesc,
            ProjectManagerID,
            SupplyChainOfficialID,
            CapitalOperation,
            CostEstimate,
            ScoaProjectID,
            EstimatedStartDate,
            EstimatedEndDate,
            ProjectStatus,
            CommencementDate,
            FinYear,
            ProjectDetailDesc,
            ProjectCategoryID,
            ProjectImplementAgentID,
            Longitude,
            Latitude,
            ProgrammeManagerID,
            FinancialControllerID,
            ProjectTypeID,
            EstimatedDuration,
            ProjectDistinctionID,
            IsDeleted,
            HistoricalProjectCode,
            ProjectParentID,
            SingleMultiYear,
            ReferenceProject_ID,
            ProjectCode,
			CostingProject
        )
        SELECT AdjustmentProjectName,
               AdjustmentProjectDesc,
               ProjectManagerID,
               SupplyChainOfficialID,
               CapitalOperation,
               CostEstimate,
               ScoaProjectID,
               EstimatedStartDate,
               EstimatedEndDate,
               24,
               CommencementDate,
               FinYear,
               ProjectDetailDesc,
               ProjectCategoryID,
               ProjectImplementAgentID,
               Longitude,
               Latitude,
               ProgrammeManagerID,
               FinancialControllerID,
               ProjectTypeID,
               EstimatedDuration,
               ProjectDistinctionID,
               IsDeleted,
               HistoricalProjectCode,
               ProjectParentID,
               SingleMultiYear,
               ReferenceProject_ID,
               ProjectCode,
			   CostingProject
        FROM dbo.Plan_AdjustmentProject (NOLOCK)
        WHERE AdjustmentVersionId = @AdjustmentVersionId
              AND ISNULL(IsDeleted, 0) = 0;

        --Using While Loop Data Update into Plan_Project   
		SET @countProjectID = (SELECT MIN(CountProjectID) FROM #tblProject);
        WHILE (@countProjectID <= (SELECT MAX(CountProjectID) FROM #tblProject))
        BEGIN
            SELECT 
                   @ProjectName = ProjectName,
                   @ProjectDesc = ProjectDesc,
                   @ProjectManagerID = ProjectManagerID,
                   @SupplyChainOfficialID = SupplyChainOfficialID,
                   @CapitalOperation = CapitalOperation,
                   @CostEstimate = CostEstimate,
                   @ScoaProjectID = ScoaProjectID,
                   @EstimatedStartDate = EstimatedStartDate,
                   @EstimatedEndDate = EstimatedEndDate,
                   @ProjectStatus = ProjectStatus,
                   @CommencementDate = CommencementDate,
                   @FinYear = FinYear,
                   @ProjectDetailDesc = @ProjectDetailDesc,
                   @ProjectCategoryID = ProjectCategoryID,
                   @ProjectImplementAgentID = ProjectImplementAgentID,
                   @Longitude = Longitude,
                   @Latitude = Latitude,
                   @ProgrammeManagerID = ProgrammeManagerID,
                   @FinancialControllerID = FinancialControllerID,
                   @ProjectTypeID = ProjectTypeID,
                   @EstimatedDuration = EstimatedDuration,
                   @ProjectDistinctionID = ProjectDistinctionID,
                   @IsDeleted = IsDeleted,
                   @HistoricalProjectCode = HistoricalProjectCode,
                   @ProjectParentID = ProjectParentID,
                   @SingleMultiYear = SingleMultiYear,
                   @ReferenceProject_ID = ISNULL(ReferenceProject_ID, 0),
                   @ProjectCode = ProjectCode,
				   @CostingProject = CostingProject
            FROM #tblProject
			WHERE CountProjectID = @countProjectID;

			PRINT 'CountProjectID = ' + convert(varchar, @countProjectID);

            IF (@ReferenceProject_ID > 0)
            BEGIN

                --Update Data into Plan_Project    
                UPDATE dbo.Plan_Project
                SET ProjectName = @ProjectName,
                    ProjectDesc = @ProjectDesc,
                    ProjectManagerID = @ProjectManagerID,
                    SupplyChainOfficialID = @SupplyChainOfficialID,
                    CapitalOperation = @CapitalOperation,
                    CostEstimate = @CostEstimate,
                    ScoaProjectID = @ScoaProjectID,
                    EstimatedStartDate = @EstimatedStartDate,
                    EstimatedEndDate = @EstimatedEndDate,
                    ProjectStatus = @ProjectStatus,
                    CommencementDate = @CommencementDate,
                    FinYear = @FinYear,
                    ProjectDetailDesc = @ProjectDetailDesc,
                    ProjectCategoryID = @ProjectCategoryID,
                    ProjectImplementAgentID = @ProjectImplementAgentID,
                    Longitude = @Longitude,
                    Latitude = @Latitude,
                    ProgrammeManagerID = @ProgrammeManagerID,
                    FinancialControllerID = @FinancialControllerID,
                    ProjectTypeID = @ProjectTypeID,
                    EstimatedDuration = @EstimatedDuration,
                    ProjectDistinctionID = @ProjectDistinctionID,
                    IsDeleted = @IsDeleted,
                    HistoricalProjectCode = @HistoricalProjectCode,
                    SingleMultiYear = @SingleMultiYear,
                    DateModified = GETDATE(),
                    ModifierID = @UserId,
					CostingProject = @CostingProject
                WHERE Project_ID = @ReferenceProject_ID;

				--Insert into Plan_ProjectReportExclude 
				IF (ISNULL(@CostingProject, 0) = 1)
				BEGIN
					IF NOT EXISTS (SELECT * FROM Plan_ProjectReportExclude WHERE ProjectID = @ProjectID)
					BEGIN
						INSERT INTO Plan_ProjectReportExclude
						(
							ProjectID,
							DateCaptured,
							CapturerID,
							WaterProject
						)
						SELECT
							@ReferenceProject_ID,
							GETDATE(),
							@UserId,
							0
					END
				END
				ELSE
				BEGIN
					DELETE Plan_ProjectReportExclude WHERE ProjectID = @ReferenceProject_ID
				END

                --Insert New SCOA Segments for existing project.    
                ------------=======================================Section Added by Sahil for New Records for Existing Projects=======================================------------    
                INSERT INTO dbo.Plan_ProjectCosting
                (
                    ProjectID,
                    ScoaCostingID,
                    CapturerID,
                    DateCaptured
                )
                SELECT @ReferenceProject_ID,
                       PAPC.ScoaCostingID,
                       @UserId,
                       GETDATE()
                FROM dbo.Plan_AdjustmentProjectCosting PAPC (NOLOCK)
                    INNER JOIN dbo.Plan_AdjustmentProject PAP (NOLOCK)
                        ON PAP.AdjustmentProject_ID = PAPC.AdjustmentProjectID
                WHERE PAPC.AdjustmentVersionId = @AdjustmentVersionId
                      AND PAPC.ReferenceProjectCostingID IS NULL
                      AND PAP.ReferenceProject_ID = @ReferenceProject_ID
                      AND ISNULL(PAP.IsDeleted, 0) = 0;

                --Insert Data into Plan_ProjectDivisions    
                INSERT INTO dbo.Plan_ProjectDivisions
                (
                    ProjectID,
                    DivisionID,
                    CapturerID,
                    DateCaptured
                )
                SELECT @ReferenceProject_ID,
                       PAPD.DivisionID,
                       @UserId,
                       GETDATE()
                FROM dbo.Plan_AdjustmentProjectDivisions PAPD (NOLOCK)
                    INNER JOIN dbo.Plan_AdjustmentProject PAP (NOLOCK)
                        ON PAP.AdjustmentProject_ID = PAPD.AdjustmentProjectID
                WHERE PAPD.AdjustmentVersionId = @AdjustmentVersionId
                      AND PAPD.ReferenceProjectDivisionID IS NULL
                      AND PAP.ReferenceProject_ID = @ReferenceProject_ID
                      AND ISNULL(PAP.IsDeleted, 0) = 0;

                --Insert Data into Plan_ProjectFunctions    
                INSERT INTO dbo.Plan_ProjectFunctions
                (
                    ProjectID,
                    ScoaFunctionID,
                    CapturerID,
                    DateCaptured
                )
                SELECT @ReferenceProject_ID,
                       PAPF.ScoaFunctionID,
                       @UserId,
                       GETDATE()
                FROM dbo.Plan_AdjustmentProjectFunctions PAPF (NOLOCK)
                    INNER JOIN dbo.Plan_AdjustmentProject PAP (NOLOCK)
                        ON PAP.AdjustmentProject_ID = PAPF.AdjustmentProjectID
                WHERE PAPF.AdjustmentVersionId = @AdjustmentVersionId
                      AND PAPF.ReferenceProjectFunctionID IS NULL
                      AND PAP.ReferenceProject_ID = @ReferenceProject_ID
                      AND ISNULL(PAP.IsDeleted, 0) = 0;


                --Rain - This is for a new IDP for exist project    
                --Get all new IDPs for an existing project        
                INSERT INTO #tblProjectIDPExist
                (
                    AdjustmentProjectIDPID,
                    ProjectIDPID,
                    ProjectID,
                    ParentIDPItemID,
                    AdjustmentProjectIDPItemID,
                    Percentage,
                    Latitude,
                    Longitude
                )
                SELECT papidp.AdjustmentProjectIDP_ID,
                       papidp.ReferenceProjectIDPID,
                       pap.ReferenceProject_ID,
                       papidp.ParentIDPItemID,
                       papidp.AdjustmentProjectIDPItemID,
                       papidp.Percentage,
                       papidp.Latitude,
                       papidp.Longitude
                FROM dbo.Plan_AdjustmentProjectIDP papidp (NOLOCK)
                    INNER JOIN dbo.Plan_AdjustmentProject pap (NOLOCK)
                        ON pap.AdjustmentProject_ID = papidp.AdjustmentProjectID
                WHERE papidp.AdjustmentVersionId = @AdjustmentVersionId
                      AND papidp.ReferenceProjectIDPID IS NULL
                      AND pap.ReferenceProject_ID = @ReferenceProject_ID
                      AND ISNULL(pap.IsDeleted, 0) = 0;

                --Using While Loop Data Update into Plan_ProjectIDP    
				SET @countProjectIDPExistID = (SELECT MIN(ProjectIDPExistID) FROM #tblProjectIDPExist);
                WHILE (@countProjectIDPExistID <= (SELECT MAX(ProjectIDPExistID) FROM #tblProjectIDPExist))
                BEGIN
                    SELECT 
                           @AdjustmentProjectIDPID = AdjustmentProjectIDPID,
                           @ReferenceProjectIDPIDExist = ProjectIDPID,
                           @AdjustmentProjectIDExist = ProjectID,
                           @ParentIDPItemIDExist = ParentIDPItemID,
                           @AdjustmentProjectIDPItemIDExist = AdjustmentProjectIDPItemID,
                           @PercentageExist = Percentage,
                           @LatitudeIDPExist = Latitude,
                           @LongitudeIDPExist = Longitude
                    FROM #tblProjectIDPExist
					WHERE ProjectIDPExistID = @countProjectIDPExistID;

                    IF (@AdjustmentProjectIDPItemIDExist = -1) -- new IDP for existing project    
                    BEGIN
                        --IDP_Item insert new entry for project with new parent return Item_ID    
                        INSERT INTO IDP_Item
                        (
                            ItemDesc,
                            FinancialYear,
                            ItemParentID,
                            IDPLevelNumber,
                            ItemOrderID,
                            CapturerID,
                            DateCaptured,
                            ModifierID,
                            DateModified,
                            ActProjID,
                            isProj,
                            KpiID,
                            NationalKPADetailID,
                            IDPInitialized
                        )
                        SELECT @ProjectName + '(' + CAST(@ParentIDPItemIDExist AS VARCHAR(20)) + ')',
                               @FinYear,
                               @ParentIDPItemIDExist,
                               50,
                               0,
                               @UserId,
                               GETDATE(),
                               NULL,
                               NULL,
                               @AdjustmentProjectIDExist,
                               1,
                               NULL,
                               NULL,
                               1;

                        SELECT @AdjustmentProjectIDPItemIDExist = SCOPE_IDENTITY();

                        --Update AdjustmentProjectIDP with ProjectIDPItemID    
                        UPDATE Plan_AdjustmentProjectIDP
                        SET AdjustmentProjectIDPItemID = @AdjustmentProjectIDPItemIDExist
                        WHERE AdjustmentProjectIDP_ID = @AdjustmentProjectIDPID;

                        --Insert Data into Plan_ProjectIDP    
                        INSERT INTO dbo.Plan_ProjectIDP
                        (
                            ProjectID,
                            ParentIDPItemID,
                            ProjectIDPItemID,
                            Percentage,
                            CapturerID,
                            DateCaptured,
                            Latitude,
                            Longitude
                        )
                        SELECT @ReferenceProject_ID,
                               @ParentIDPItemIDExist,
                               @AdjustmentProjectIDPItemIDExist,
                               @PercentageExist,
                               @UserId,
                               GETDATE(),
                               @LatitudeIDPExist,
                               @LongitudeIDPExist;
                    END;

					SET @countProjectIDPExistID = @countProjectIDPExistID + 1;
                END;
                --end Plan_ProjectIDP    

                --Insert Data into Plan_ProjectRegions    
                INSERT INTO dbo.Plan_ProjectRegions
                (
                    ProjectID,
                    ScoaRegionID,
                    RegionPercent,
                    CapturerID,
                    DateCaptured
                )
                SELECT @ReferenceProject_ID,
                       PAPR.ScoaRegionID,
                       PAPR.RegionPercent,
                       @UserId,
                       GETDATE()
                FROM Plan_AdjustmentProjectRegions PAPR (NOLOCK)
                    INNER JOIN dbo.Plan_AdjustmentProject PAP (NOLOCK)
                        ON PAP.AdjustmentProject_ID = PAPR.AdjustmentProjectID
                WHERE PAPR.AdjustmentVersionId = @AdjustmentVersionId
                      AND PAPR.ReferenceProjectRegionID IS NULL
                      AND PAP.ReferenceProject_ID = @ReferenceProject_ID
                      AND ISNULL(PAP.IsDeleted, 0) = 0;

                --Insert Data into Plan_ProjectFund and Plan_ProjectFundYear for existing projects   
				TRUNCATE TABLE #tblProjectFundNull;

                INSERT INTO #tblProjectFundNull
                (
                    ProjectFundID,
                    ScoaFundID,
                    FundAmount,
                    FundReference,
                    VirementId,
                    AdjustmentId
                )
                SELECT PAPF.AdjustmentProjectFund_ID,
                       PAPF.ScoaFundID,
                       PAPF.FundAmount,
                       PAPF.FundReference,
                       PAPF.VirementId,
                       PAPF.AdjustmentProjectFund_ID
                FROM dbo.Plan_AdjustmentProjectFund PAPF (NOLOCK)
                    INNER JOIN dbo.Plan_AdjustmentProject PAP (NOLOCK)
                        ON PAP.AdjustmentProject_ID = PAPF.AdjustmentProjectID
                WHERE PAPF.AdjustmentVersionId = @AdjustmentVersionId
                      AND PAPF.ReferenceProjectFundID IS NULL
                      AND PAP.ReferenceProject_ID = @ReferenceProject_ID
                      AND ISNULL(PAP.IsDeleted, 0) = 0;

				SET @countProjectFundNullID = (SELECT MIN(ProjectFundNullID) FROM #tblProjectFundNull);
                WHILE (@countProjectFundNullID <= (SELECT MAX(ProjectFundNullID) FROM #tblProjectFundNull))
                BEGIN
                    SELECT 
                           @AdjustmentProjectFund_ID = ProjectFundID,
                           @ScoaFundID = ScoaFundID,
                           @FundAmount = FundAmount,
                           @FundReference = FundReference,
                           @VirementId = VirementId,
                           @AdjustmentId = AdjustmentId
                    FROM #tblProjectFundNull
					WHERE ProjectFundNullID = @countProjectFundNullID;

                    --Insert Data into Plan_ProjectFund    
                    INSERT INTO dbo.Plan_ProjectFund
                    (
                        ProjectID,
                        ScoaFundID,
                        FundAmount,
                        CapturerID,
                        DateCaptured,
                        FundReference,
                        VirementId,
                        AdjustmentId
                    )
                    VALUES
                    (@ReferenceProject_ID, @ScoaFundID, @FundAmount, @UserId, GETDATE(), @FundReference, @VirementId,
                     @AdjustmentId);

                    SELECT @ProjectFundID = SCOPE_IDENTITY();

                    --Insert Data into Plan_ProjectFundYear    
                    INSERT INTO dbo.Plan_ProjectFundYear
                    (
                        ProjectFundID,
                        FinYear,
                        YearFundAmount,
                        VirementId,
                        AdjustmentId,
                        CapturerID,
                        DateCaptured
                    )
                    SELECT @ProjectFundID,
                           FinYear,
                           YearFundAmount,
                           VirementId,
                           AdjustmentProjectFundYear_ID,
                           @UserId,
                           GETDATE()
                    FROM dbo.Plan_AdjustmentProjectFundYear (NOLOCK)
                    WHERE AdjustmentProjectFundID = @AdjustmentProjectFund_ID
                          AND ReferenceProjectFundYearID IS NULL
                          AND AdjustmentVersionId = @AdjustmentVersionId;

					SET @countProjectFundNullID = @countProjectFundNullID + 1;

                END;

                --Insert Data into Plan_ProjectItem, Plan_ProjectItemDocs and Plan_ProjectItemMonth  
				TRUNCATE TABLE #tblProjectItemNull

                INSERT INTO #tblProjectItemNull
                (
                    PlanAdjustmentProjectItemID,
                    ProjectItemID,
                    SCOAItemID,
                    FinYear,
                    ProjectFundYearID,
                    SCOAFundId,
                    BudgetAmount,
                    BudgetAmountCurP1,
                    BudgetAmountCurP2,
                    SCOAFunctionId,
                    SCOARegionId,
                    DivisionId,
                    BudgetSplitID,
                    VirementId,
                    HistoricalProjectCode,
                    AdjustmentId,
                    ModificationNumber,
                    SCOACostingID,
                    IsItemLocked,
                    CreditDebit,
                    AdjustedBudgetAmount,
                    AdjustedBudgetAmountCurP1,
                    AdjustedBudgetAmountCurP2,
					GRAPClassification,
					GRAPClassificationNote,
					MainSegmentReporting,
					SubSegmentReporting,
					IsActiveForSCM
                )
                SELECT PAPI.PlanAdjustmentProjectItem_ID,
                       PAPI.ProjectItemID,
                       PAPI.SCOAItemID,
                       PAPI.FinYear,
                       PAPI.ProjectFundYearID,
                       PAPI.SCOAFundId,
                       PAPI.BudgetAmount,
                       PAPI.BudgetAmountCurP1,
                       PAPI.BudgetAmountCurP2,
                       PAPI.SCOAFunctionId,
                       PAPI.SCOARegionId,
                       PAPI.DivisionId,
                       PAPI.BudgetSplitID,
                       PAPI.VirementId,
                       PAPI.HistoricalProjectCode,
                       PAPI.PlanAdjustmentProjectItem_ID,
                       PAPI.ModificationNumber,
                       PAPI.SCOACostingID,
                       PAPI.IsItemLocked,
                       PAPI.CreditDebit,
                       PAPI.AdjustedBudgetAmount,
                       PAPI.AdjustedBudgetAmountCurP1,
                       PAPI.AdjustedBudgetAmountCurP2,
					   PAPI.GRAPClassification,
					   PAPI.GRAPClassificationNote,
					   PAPI.MainSegmentReporting,
					   PAPI.SubSegmentReporting,
					   PAPI.IsActiveForSCM
                FROM Plan_AdjustmentProjectItem PAPI (NOLOCK)
                    INNER JOIN dbo.Plan_AdjustmentProject PAP (NOLOCK)
                        ON PAP.AdjustmentProject_ID = PAPI.AdjustmentProjectID
                WHERE PAPI.AdjustmentVersionId = @AdjustmentVersionId
                      AND PAPI.ReferencePlanProjectItem_ID IS NULL
                      AND PAP.ReferenceProject_ID = @ReferenceProject_ID
                      AND ISNULL(PAP.IsDeleted, 0) = 0;

				SET @countProjectItemNullID = (SELECT MIN(ProjectItemNullID) FROM #tblProjectItemNull);
                WHILE (@countProjectItemNullID < = (SELECT MAX(ProjectItemNullID) FROM #tblProjectItemNull))
                BEGIN
                    SELECT
                           @PlanAdjustmentProjectItemID = PlanAdjustmentProjectItemID,
                           @ProjectItemID = ProjectItemID,
                           @SCOAItemID = SCOAItemID,
                           @FinYear = FinYear,
                           @ProjectFundYearID = ProjectFundYearID,
                           @ScoaFundID = SCOAFundId,
                           @BudgetAmount = BudgetAmount,
                           @BudgetAmountCurP1 = BudgetAmountCurP1,
                           @BudgetAmountCurP2 = BudgetAmountCurP2,
                           @ScoaFunctionID = SCOAFunctionId,
                           @SCOARegionId = SCOARegionId,
                           @DivisionID = DivisionId,
                           @BudgetSplitID = BudgetSplitID,
                           @VirementId = VirementId,
                           @HistoricalProjectCode = HistoricalProjectCode,
                           @AdjustmentId = AdjustmentId,
                           @ModificationNumber = ModificationNumber,
                           @ScoaCostingID = SCOACostingID,
                           @IsItemLocked = IsItemLocked,
                           @CreditDebit = CreditDebit,
                           @AdjustedBudgetAmount = AdjustedBudgetAmount,
                           @AdjustedBudgetAmountCurP1 = AdjustedBudgetAmountCurP1,
                           @AdjustedBudgetAmountCurP2 = AdjustedBudgetAmountCurP2,
						   @GRAPClassification = GRAPClassification,
						   @GRAPClassificationNote = GRAPClassificationNote,
						   @MainSegmentReporting = MainSegmentReporting,
						   @SubSegmentReporting = SubSegmentReporting,
						   @IsActiveForSCM = isnull(IsActiveForSCM,1)
                    FROM #tblProjectItemNull
					WHERE ProjectItemNullID = @countProjectItemNullID;

                    IF (@AdjustedBudgetAmount IS NOT NULL)
                        SET @BudgetAmount = @AdjustedBudgetAmount;
                    IF (@AdjustedBudgetAmountCurP1 IS NOT NULL)
                        SET @BudgetAmountCurP1 = @AdjustedBudgetAmountCurP1;
                    IF (@AdjustedBudgetAmountCurP2 IS NOT NULL)
                        SET @BudgetAmountCurP2 = @AdjustedBudgetAmountCurP2;

					SET @TxnAmountForBudgetRegister = @BudgetAmount;
					SET @TxnAmountForBudgetRegisterMultiYear = @BudgetAmountCurP1 + @BudgetAmountCurP2;

                    DECLARE @ObjGetOriginalProjectFund_ID INT;
                    DECLARE @ObjProjectFundYearID INT;

                    SELECT @ObjGetOriginalProjectFund_ID = ProjectFund_ID
                    FROM Plan_ProjectFund
                    WHERE ProjectID = @ReferenceProject_ID
                          AND ScoaFundID = @ScoaFundID;

                    SELECT @ObjProjectFundYearID = ProjectFundYear_ID
                    FROM Plan_ProjectFundYear
                    WHERE ProjectFundID = @ObjGetOriginalProjectFund_ID
                          AND FinYear = @FinYear;

                    --Insert Data into Plan_ProjectItem    
                    INSERT INTO dbo.Plan_ProjectItem
                    (
                        ProjectID,
                        ProjectItemID,
                        SCOAItemID,
                        FinYear,
                        CapturerID,
                        DateCaptured,
                        ProjectFundYearID,
                        SCOAFundId,
                        BudgetAmount,
                        BudgetAmountCurP1,
                        BudgetAmountCurP2,
                        SCOAFunctionId,
                        SCOARegionId,
                        DivisionId,
                        BudgetSplitID,
                        VirementId,
                        HistoricalProjectCode,
                        AdjustmentId,
                        ModificationNumber,
                        SCOACostingID,
                        IsItemLocked,
                        CreditDebit,
						GRAPClassification,
						GRAPClassificationNote,
						MainSegmentReporting,
						SubSegmentReporting,
						IsActiveForSCM
                    )
                    VALUES
                    (@ReferenceProject_ID, @ProjectItemID, @SCOAItemID, @FinYear, @UserId, GETDATE(),
                     @ObjProjectFundYearID, @ScoaFundID, @BudgetAmount, @BudgetAmountCurP1, @BudgetAmountCurP2,
                     @ScoaFunctionID, @SCOARegionId, @DivisionID, @BudgetSplitID, @VirementId, @HistoricalProjectCode,
                     @AdjustmentId, @ModificationNumber, @ScoaCostingID, @IsItemLocked, @CreditDebit,
					 @GRAPClassification, @GRAPClassificationNote, @MainSegmentReporting, @SubSegmentReporting, @IsActiveForSCM);

                    SELECT @PlanProjectItemID = SCOPE_IDENTITY();

					--Update HistoricalProjectCode
					UPDATE Plan_ProjectItem 
					SET HistoricalProjectCode = CONVERT(VARCHAR, PlanProjectItem_ID) + '|' + ISNULL(HistoricalProjectCode, '0') 
					WHERE PlanProjectItem_ID = @PlanProjectItemID

                    --Insert Data into Plan_ProjectItemDocs    
                    INSERT INTO dbo.Plan_ProjectItemDocs
                    (
                        SupportingDocsID,
                        PlanProjectItemID,
                        DateCaptured,
                        CapturerID
                    )
                    SELECT SupportingDocsID,
                           @PlanProjectItemID,
                           GETDATE(),
                           @UserId
                    FROM dbo.Plan_AdjustmentProjectItemDocs (NOLOCK)
                    WHERE PlanAdjustmentProjectItemID = @PlanAdjustmentProjectItemID;

                    --Insert Data into Plan_ProjectItemMonth    
                    INSERT INTO dbo.Plan_ProjectItemMonth
                    (
                        PlanProjectItemID,
                        MonthID,
                        UnitQuantity,
                        UnitPrice,
                        CaptureID,
                        DateCaptured,
                        VirementId,
                        AdjustmentId
                    )
                    SELECT @PlanProjectItemID,
                           MonthID,
                           UnitQuantity,
                           ISNULL(AdjustedUnitPrice, UnitPrice),
                           @UserId,
                           GETDATE(),
                           VirementId,
                           AdjustmentId
                    FROM dbo.Plan_AdjustmentProjectItemMonth (NOLOCK)
                    WHERE PlanAdjustmentProjectItemID = @PlanAdjustmentProjectItemID;

                    --#80664 Technical CR â€“ Planning Changes for storing and retrieving Budget Consumption - By Sahil 16-11-2018    
                    INSERT INTO dbo.Plan_BudgetConsumption
                    (
                        FinYear,
                        PlanProjectItemID,
                        BudgetTransactionTypeID,
                        ModuleID,
                        PK_TransactionID,
                        TransactionTableName,
                        ConsumingTransactionAmount,
                        AdjustedTansactionAmount,
                        AvailableBudget,
                        ProcessingMonth,
                        BudgetConsumptionProcessID,
                        OriginalBudgetToDate,
                        AdjustedBudgetToDate,
                        CapturedExpenditureToDate,
                        ReserveToDate,
                        CommitToDate,
                        ActualToDate,
                        CapturerID,
                        DateCaptured,
						ConsumingTransactionAmountMultiYear,
						AvailableBudgetMultiYear,
						CapturedExpenditureToDateMultiYear,
						ReserveToDateMultiYear
                    )
                    VALUES
                    (   @FinYear,                      -- FinYear - nvarchar(9)    
                        @PlanProjectItemID,            -- PlanProjectItemID - int    
                        @BudgetTxnTypeId,              -- BudgetTransactionTypeID - int    
                        10,                            -- ModuleID - int    
                        @PlanProjectItemID,            -- PK_TransactionID - int    
                        N'Plan_ProjectItem',           -- TransactionTableName - nvarchar(100)    
                        @TxnAmountForBudgetRegister,   -- ConsumingTransactionAmount - decimal(18, 2)    
                        @TxnAmountForBudgetRegister,   -- AdjustedTansactionAmount - decimal(18, 2)    
                        @TxnAmountForBudgetRegister,   -- AvailableBudget - decimal(18, 2)    
                        @UserProcessingMonth,          -- ProcessingMonth - int    
                        202,                           -- BudgetConsumptionProcessID - int    
                        0,                             -- OriginalBudgetToDate - decimal(18, 2)    
                        @TxnAmountForBudgetRegister,   -- AdjustedBudgetToDate - decimal(18, 2)    
                        0,                             -- CapturedExpenditureToDate - decimal(18, 2)    
                        0,                             -- ReserveToDate - decimal(18, 2)    
                        0,                             -- CommitToDate - decimal(18, 2)    
                        0,                             -- ActualToDate - decimal(18, 2)    
                        @UserId,                       -- CapturerID - int    
                        GETDATE(),                     -- DateCaptured - datetime    
						@TxnAmountForBudgetRegisterMultiYear,
						@TxnAmountForBudgetRegisterMultiYear,
						0,
						0
                        );

					SET @countProjectItemNullID = @countProjectItemNullID + 1;
                END;

                ------------=======================================Section Added by Sahil for New Records for Existing Projects=======================================------------    

				SET @countProjectID = @countProjectID + 1;
            END
            ELSE
            BEGIN
                --Insert Data into Plan_Project    
                INSERT INTO dbo.Plan_Project
                (
                    ProjectName,
                    ProjectDesc,
                    ProjectManagerID,
                    SupplyChainOfficialID,
                    CapitalOperation,
                    CostEstimate,
                    ScoaProjectID,
                    EstimatedStartDate,
                    EstimatedEndDate,
                    ProjectStatus,
                    CommencementDate,
                    FinYear,
                    ProjectDetailDesc,
                    ProjectCategoryID,
                    ProjectImplementAgentID,
                    Longitude,
                    Latitude,
                    ProgrammeManagerID,
                    FinancialControllerID,
                    ProjectTypeID,
                    EstimatedDuration,
                    ProjectDistinctionID,
                    IsDeleted,
                    HistoricalProjectCode,
                    ProjectParentID,
                    SingleMultiYear,
                    CapturerID,
                    DateCaptured,
                    ProjectCode,
					CostingProject
                )
                SELECT ProjectName,
                       ProjectDesc,
                       ProjectManagerID,
                       SupplyChainOfficialID,
                       CapitalOperation,
                       CostEstimate,
                       ScoaProjectID,
                       EstimatedStartDate,
                       EstimatedEndDate,
                       ProjectStatus,
                       CommencementDate,
                       FinYear,
                       ProjectDetailDesc,
                       ProjectCategoryID,
                       ProjectImplementAgentID,
                       Longitude,
                       Latitude,
                       ProgrammeManagerID,
                       FinancialControllerID,
                       ProjectTypeID,
                       EstimatedDuration,
                       ProjectDistinctionID,
                       IsDeleted,
                       HistoricalProjectCode,
                       ProjectParentID,
                       SingleMultiYear,
                       @UserId,
                       GETDATE(),
                       ProjectCode,
					   CostingProject
                FROM #tblProject
                WHERE ProjectName = @ProjectName;

                SELECT @CapitalOperationType = CapitalOperation, @CostingProject = CostingProject
                FROM #tblProject
                WHERE ProjectName = @ProjectName;
                SELECT @ProjectID = SCOPE_IDENTITY();

                -- #61596 - #83633 Update ProjectParentId as per new Primary Key in Table -- By SNagpal 23-Jan-2019    
                UPDATE dbo.Plan_Project
                SET ProjectParentID = @ProjectID
                WHERE Project_ID = @ProjectID;

				--Insert into Plan_ProjectReportExclude 
				IF (ISNULL(@CostingProject, 0) = 1)
				BEGIN
					IF NOT EXISTS (SELECT * FROM Plan_ProjectReportExclude WHERE ProjectID = @ProjectID)
					BEGIN
						INSERT INTO Plan_ProjectReportExclude
						(
							ProjectID,
							DateCaptured,
							CapturerID,
							WaterProject
						)
						SELECT
							@ProjectID,
							GETDATE(),
							@UserId,
							0
					END
				END

                --Insert Data into Plan_ProjectCosting    
                INSERT INTO dbo.Plan_ProjectCosting
                (
                    ProjectID,
                    ScoaCostingID,
                    CapturerID,
                    DateCaptured
                )
                SELECT @ProjectID,
                       PAPC.ScoaCostingID,
                       @UserId,
                       GETDATE()
                FROM dbo.Plan_AdjustmentProjectCosting PAPC (NOLOCK)
                    INNER JOIN dbo.Plan_AdjustmentProject PAP (NOLOCK)
                        ON PAP.AdjustmentProject_ID = PAPC.AdjustmentProjectID
                WHERE PAPC.AdjustmentVersionId = @AdjustmentVersionId
                      AND PAPC.ReferenceProjectCostingID IS NULL
                      AND PAP.AdjustmentProjectName = @ProjectName
                      AND ISNULL(PAP.IsDeleted, 0) = 0;

                --Insert Data into Plan_ProjectDivisions    
                INSERT INTO dbo.Plan_ProjectDivisions
                (
                    ProjectID,
                    DivisionID,
                    CapturerID,
                    DateCaptured
                )
                SELECT @ProjectID,
                       PAPD.DivisionID,
                       @UserId,
                       GETDATE()
                FROM dbo.Plan_AdjustmentProjectDivisions PAPD (NOLOCK)
                    INNER JOIN dbo.Plan_AdjustmentProject PAP (NOLOCK)
                        ON PAP.AdjustmentProject_ID = PAPD.AdjustmentProjectID
                WHERE PAPD.AdjustmentVersionId = @AdjustmentVersionId
                      AND PAPD.ReferenceProjectDivisionID IS NULL
                      AND PAP.AdjustmentProjectName = @ProjectName
                      AND ISNULL(PAP.IsDeleted, 0) = 0;

                --Insert Data into Plan_ProjectFunctions    
                INSERT INTO dbo.Plan_ProjectFunctions
                (
                    ProjectID,
                    ScoaFunctionID,
                    CapturerID,
                    DateCaptured
                )
                SELECT @ProjectID,
                       PAPF.ScoaFunctionID,
                       @UserId,
                       GETDATE()
                FROM dbo.Plan_AdjustmentProjectFunctions PAPF (NOLOCK)
                    INNER JOIN dbo.Plan_AdjustmentProject PAP (NOLOCK)
                        ON PAP.AdjustmentProject_ID = PAPF.AdjustmentProjectID
                WHERE PAPF.AdjustmentVersionId = @AdjustmentVersionId
                      AND PAPF.ReferenceProjectFunctionID IS NULL
                      AND PAP.AdjustmentProjectName = @ProjectName
                      AND ISNULL(PAP.IsDeleted, 0) = 0;

                --Rain -This is for a new Project    

                --Get all new IDPs for an new project        
                INSERT INTO #tblProjectIDPNew
                (
                    AdjustmentProjectIDPID,
                    ProjectIDPID,
                    ProjectID,
                    ParentIDPItemID,
                    AdjustmentProjectIDPItemID,
                    Percentage,
                    Latitude,
                    Longitude
                )
                SELECT papidp.AdjustmentProjectIDP_ID,
                       papidp.ReferenceProjectIDPID,
                       pap.ReferenceProject_ID,
                       papidp.ParentIDPItemID,
                       papidp.AdjustmentProjectIDPItemID,
                       papidp.Percentage,
                       papidp.Latitude,
                       papidp.Longitude
                FROM dbo.Plan_AdjustmentProjectIDP papidp (NOLOCK)
                    INNER JOIN dbo.Plan_AdjustmentProject pap (NOLOCK)
                        ON pap.AdjustmentProject_ID = papidp.AdjustmentProjectID
                WHERE papidp.AdjustmentVersionId = @AdjustmentVersionId
                      AND papidp.ReferenceProjectIDPID IS NULL
                      AND pap.AdjustmentProjectName = @ProjectName
                      AND ISNULL(pap.IsDeleted, 0) = 0;

                --Using While Loop Data Update into Plan_ProjectIDP    
				SET @countProjectIDPNewID = (SELECT MIN(ProjectIDPNewID) FROM #tblProjectIDPNew);
                WHILE (@countProjectIDPNewID <= (SELECT MAX(ProjectIDPNewID) FROM #tblProjectIDPNew))
                BEGIN
                    SELECT
                           @AdjustmentProjectIDPIDNew = AdjustmentProjectIDPID,
                           @ReferenceProjectIDPIDNew = ProjectIDPID,
                           @AdjustmentProjectIDNew = ProjectID,
                           @ParentIDPItemIDNew = ParentIDPItemID,
                           @AdjustmentProjectIDPItemIDNew = AdjustmentProjectIDPItemID,
                           @PercentageNew = Percentage,
                           @LatitudeIDPNew = Latitude,
                           @LongitudeIDPNew = Longitude
                    FROM #tblProjectIDPNew
					WHERE ProjectIDPNewID = @countProjectIDPNewID;

                    IF (@AdjustmentProjectIDPItemIDNew = -1) -- new IDP for New project    
                    BEGIN
                        --IDP_Item insert new entry for project with new parent return Item_ID    
                        INSERT INTO IDP_Item
                        (
                            ItemDesc,
                            FinancialYear,
                            ItemParentID,
                            IDPLevelNumber,
                            ItemOrderID,
                            CapturerID,
                            DateCaptured,
                            ModifierID,
                            DateModified,
                            ActProjID,
                            isProj,
                            KpiID,
                            NationalKPADetailID,
                            IDPInitialized
                        )
                        SELECT @ProjectName + '(' + CAST(@ParentIDPItemIDNew AS VARCHAR(20)) + ')',
                               @FinYear,
                               @ParentIDPItemIDNew,
                               50,
                               0,
                               @UserId,
                               GETDATE(),
                               NULL,
                               NULL,
                               @ProjectID,
                               1,
                               NULL,
                               NULL,
                               1;

                        SELECT @AdjustmentProjectIDPItemIDNew = SCOPE_IDENTITY();

                        --Update AdjustmentProjectIDP with ProjectIDPItemID    
                        UPDATE Plan_AdjustmentProjectIDP
                        SET AdjustmentProjectIDPItemID = @AdjustmentProjectIDPItemIDNew
                        WHERE AdjustmentProjectIDP_ID = @AdjustmentProjectIDPIDNew;

                        --Insert Data into Plan_ProjectIDP    
                        INSERT INTO dbo.Plan_ProjectIDP
                        (
                            ProjectID,
                            ParentIDPItemID,
                            ProjectIDPItemID,
                            Percentage,
                            CapturerID,
                            DateCaptured,
                            Latitude,
                            Longitude
                        )
                        SELECT @ProjectID,
                               @ParentIDPItemIDNew,
                               @AdjustmentProjectIDPItemIDNew,
                               @PercentageNew,
                               @UserId,
                               GETDATE(),
                               @LatitudeIDPNew,
                               @LongitudeIDPNew;

                    END;

					SET @countProjectIDPNewID = @countProjectIDPNewID + 1;
                END;
                --end Plan_ProjectIDP    

                --Insert Data into Plan_ProjectRegions    
                INSERT INTO dbo.Plan_ProjectRegions
                (
                    ProjectID,
                    ScoaRegionID,
                    RegionPercent,
                    CapturerID,
                    DateCaptured
                )
                SELECT @ProjectID,
                       PAPR.ScoaRegionID,
                       PAPR.RegionPercent,
                       @UserId,
                       GETDATE()
                FROM Plan_AdjustmentProjectRegions PAPR (NOLOCK)
                    INNER JOIN dbo.Plan_AdjustmentProject PAP (NOLOCK)
                        ON PAP.AdjustmentProject_ID = PAPR.AdjustmentProjectID
                WHERE PAPR.AdjustmentVersionId = @AdjustmentVersionId
                      AND PAPR.ReferenceProjectRegionID IS NULL
                      AND PAP.AdjustmentProjectName = @ProjectName
                      AND ISNULL(PAP.IsDeleted, 0) = 0;

                --Insert Data into Plan_ProjectFund and Plan_ProjectFundYear  
				TRUNCATE TABLE #tblProjectFundNull
				
                INSERT INTO #tblProjectFundNull
                (
                    ProjectFundID,
                    ScoaFundID,
                    FundAmount,
                    FundReference,
                    VirementId,
                    AdjustmentId
                )
                SELECT PAPF.AdjustmentProjectFund_ID,
                       PAPF.ScoaFundID,
                       PAPF.FundAmount,
                       PAPF.FundReference,
                       PAPF.VirementId,
                       PAPF.AdjustmentProjectFund_ID
                FROM dbo.Plan_AdjustmentProjectFund PAPF (NOLOCK)
                    INNER JOIN dbo.Plan_AdjustmentProject PAP (NOLOCK)
                        ON PAP.AdjustmentProject_ID = PAPF.AdjustmentProjectID
                WHERE PAPF.AdjustmentVersionId = @AdjustmentVersionId
                      AND PAPF.ReferenceProjectFundID IS NULL
                      AND PAP.AdjustmentProjectName = @ProjectName
                      AND ISNULL(PAP.IsDeleted, 0) = 0;

				SET @countProjectFundNullID = (SELECT MIN(ProjectFundNullID) FROM #tblProjectFundNull);
                WHILE (@countProjectFundNullID <= (SELECT MAX(ProjectFundNullID) FROM #tblProjectFundNull))
                BEGIN
                    SELECT 
                           @AdjustmentProjectFund_ID = ProjectFundID,
                           @ScoaFundID = ScoaFundID,
                           @FundAmount = FundAmount,
                           @FundReference = FundReference,
                           @VirementId = VirementId,
                           @AdjustmentId = AdjustmentId
                    FROM #tblProjectFundNull
					WHERE ProjectFundNullID = @countProjectFundNullID;

                    --Insert Data into Plan_ProjectFund    
                    INSERT INTO dbo.Plan_ProjectFund
                    (
                        ProjectID,
                        ScoaFundID,
                        FundAmount,
                        CapturerID,
                        DateCaptured,
                        FundReference,
                        VirementId,
                        AdjustmentId
                    )
                    VALUES
                    (@ProjectID, @ScoaFundID, @FundAmount, @UserId, GETDATE(), @FundReference, @VirementId,
                     @AdjustmentId);

                    SELECT @ProjectFundID = SCOPE_IDENTITY();

                    --Insert Data into Plan_ProjectFundYear    
                    INSERT INTO dbo.Plan_ProjectFundYear
                    (
                        ProjectFundID,
                        FinYear,
                        YearFundAmount,
                        VirementId,
                        AdjustmentId,
                        CapturerID,
                        DateCaptured
                    )
                    SELECT @ProjectFundID,
                           FinYear,
                           YearFundAmount,
                           VirementId,
                           AdjustmentProjectFundYear_ID,
                           @UserId,
                           GETDATE()
                    FROM dbo.Plan_AdjustmentProjectFundYear (NOLOCK)
                    WHERE AdjustmentProjectFundID = @AdjustmentProjectFund_ID
                          AND ReferenceProjectFundYearID IS NULL
                          AND AdjustmentVersionId = @AdjustmentVersionId;

					SET @countProjectFundNullID = @countProjectFundNullID + 1;
                END;

                --Insert Data into Plan_ProjectItem, Plan_ProjectItemDocs and Plan_ProjectItemMonth   
				TRUNCATE TABLE #tblProjectItemNull

                INSERT INTO #tblProjectItemNull
                (
                    PlanAdjustmentProjectItemID,
                    ProjectItemID,
                    SCOAItemID,
                    FinYear,
                    ProjectFundYearID,
                    SCOAFundId,
                    BudgetAmount,
                    BudgetAmountCurP1,
                    BudgetAmountCurP2,
                    SCOAFunctionId,
                    SCOARegionId,
                    DivisionId,
                    BudgetSplitID,
                    VirementId,
                    HistoricalProjectCode,
                    AdjustmentId,
                    ModificationNumber,
                    SCOACostingID,
                    IsItemLocked,
                    CreditDebit,
                    AdjustedBudgetAmount,
                    AdjustedBudgetAmountCurP1,
                    AdjustedBudgetAmountCurP2,
					GRAPClassification,
					GRAPClassificationNote,
					MainSegmentReporting,
					SubSegmentReporting,
					IsActiveForSCM
                )
                SELECT PAPI.PlanAdjustmentProjectItem_ID,
                       PAPI.ProjectItemID,
                       PAPI.SCOAItemID,
                       PAPI.FinYear,
                       PAPI.ProjectFundYearID,
                       PAPI.SCOAFundId,
                       PAPI.BudgetAmount,
                       PAPI.BudgetAmountCurP1,
                       PAPI.BudgetAmountCurP2,
                       PAPI.SCOAFunctionId,
                       PAPI.SCOARegionId,
                       PAPI.DivisionId,
                       PAPI.BudgetSplitID,
                       PAPI.VirementId,
                       PAPI.HistoricalProjectCode,
                       PAPI.PlanAdjustmentProjectItem_ID,
                       PAPI.ModificationNumber,
                       PAPI.SCOACostingID,
                       PAPI.IsItemLocked,
                       PAPI.CreditDebit,
                       PAPI.AdjustedBudgetAmount,
                       PAPI.AdjustedBudgetAmountCurP1,
                       PAPI.AdjustedBudgetAmountCurP2,
					   PAPI.GRAPClassification,
					   PAPI.GRAPClassificationNote,
					   PAPI.MainSegmentReporting,
					   PAPI.SubSegmentReporting,
					   PAPI.IsActiveForSCM
                FROM Plan_AdjustmentProjectItem PAPI (NOLOCK)
                    INNER JOIN dbo.Plan_AdjustmentProject PAP (NOLOCK)
                        ON PAP.AdjustmentProject_ID = PAPI.AdjustmentProjectID
                WHERE PAPI.AdjustmentVersionId = @AdjustmentVersionId
                      AND PAPI.ReferencePlanProjectItem_ID IS NULL
                      AND PAP.AdjustmentProjectName = @ProjectName
                      AND ISNULL(PAP.IsDeleted, 0) = 0;

				SET @countProjectItemNullID = (SELECT MIN(ProjectItemNullID) FROM #tblProjectItemNull);
                WHILE (@countProjectItemNullID <= (SELECT MAX(ProjectItemNullID) FROM #tblProjectItemNull))
                BEGIN
                    SELECT 
                           @PlanAdjustmentProjectItemID = PlanAdjustmentProjectItemID,
                           @ProjectItemID = ProjectItemID,
                           @SCOAItemID = SCOAItemID,
                           @FinYear = FinYear,
                           @ProjectFundYearID = ProjectFundYearID,
                           @ScoaFundID = SCOAFundId,
                           @BudgetAmount = BudgetAmount,
                           @BudgetAmountCurP1 = BudgetAmountCurP1,
                           @BudgetAmountCurP2 = BudgetAmountCurP2,
                           @ScoaFunctionID = SCOAFunctionId,
                           @SCOARegionId = SCOARegionId,
                           @DivisionID = DivisionId,
                           @BudgetSplitID = BudgetSplitID,
                           @VirementId = VirementId,
                           @HistoricalProjectCode = HistoricalProjectCode,
                           @AdjustmentId = AdjustmentId,
                           @ModificationNumber = ModificationNumber,
                           @ScoaCostingID = SCOACostingID,
                           @IsItemLocked = IsItemLocked,
                           @CreditDebit = CreditDebit,
                           @AdjustedBudgetAmount = AdjustedBudgetAmount,
                           @AdjustedBudgetAmountCurP1 = AdjustedBudgetAmountCurP1,
                           @AdjustedBudgetAmountCurP2 = AdjustedBudgetAmountCurP2,
						   @GRAPClassification = GRAPClassification,
						   @GRAPClassificationNote = GRAPClassificationNote,
						   @MainSegmentReporting = MainSegmentReporting,
						   @SubSegmentReporting = SubSegmentReporting,
						   @IsActiveForSCM = ISNULL(IsActiveForSCM,1)
                    FROM #tblProjectItemNull
					WHERE ProjectItemNullID = @countProjectItemNullID;

                    IF (@AdjustedBudgetAmount IS NOT NULL)
                        SET @BudgetAmount = @AdjustedBudgetAmount;
                    IF (@AdjustedBudgetAmountCurP1 IS NOT NULL)
                        SET @BudgetAmountCurP1 = @AdjustedBudgetAmountCurP1;
                    IF (@AdjustedBudgetAmountCurP2 IS NOT NULL)
                        SET @BudgetAmountCurP2 = @AdjustedBudgetAmountCurP2;

					SET @TxnAmountForBudgetRegister = @BudgetAmount;
					SET @TxnAmountForBudgetRegisterMultiYear = @BudgetAmountCurP1 + @BudgetAmountCurP2;

                    DECLARE @ObjGetOriginalProjectFund_IDRef INT;
                    DECLARE @ObjProjectFundYearIDRef INT;

                    SELECT @ObjGetOriginalProjectFund_ID = ProjectFund_ID
                    FROM Plan_ProjectFund
                    WHERE ProjectID = @ProjectID
                          AND ScoaFundID = @ScoaFundID;

                    SELECT @ObjProjectFundYearIDRef = ProjectFundYear_ID
                    FROM Plan_ProjectFundYear
                    WHERE ProjectFundID = @ObjGetOriginalProjectFund_ID
                          AND FinYear = @FinYear;

                    --Insert Data into Plan_ProjectItem    
                    INSERT INTO dbo.Plan_ProjectItem
                    (
                        ProjectID,
                        ProjectItemID,
                        SCOAItemID,
                        FinYear,
                        CapturerID,
                        DateCaptured,
                        ProjectFundYearID,
                        SCOAFundId,
                        BudgetAmount,
                        BudgetAmountCurP1,
                        BudgetAmountCurP2,
                        SCOAFunctionId,
                        SCOARegionId,
                        DivisionId,
                        BudgetSplitID,
                        VirementId,
                        HistoricalProjectCode,
                        AdjustmentId,
                        ModificationNumber,
                        SCOACostingID,
                        IsItemLocked,
                        CreditDebit,
						GRAPClassification,
						GRAPClassificationNote,
						MainSegmentReporting,
						SubSegmentReporting,
						IsActiveForSCM
                    )
                    VALUES
                    (@ProjectID, @ProjectItemID, @SCOAItemID, @FinYear, @UserId, GETDATE(), @ObjProjectFundYearIDRef,
                     @ScoaFundID, @BudgetAmount, @BudgetAmountCurP1, @BudgetAmountCurP2, @ScoaFunctionID,
                     @SCOARegionId, @DivisionID, @BudgetSplitID, @VirementId, @HistoricalProjectCode, @AdjustmentId,
                     @ModificationNumber, @ScoaCostingID, @IsItemLocked, @CreditDebit,
					 @GRAPClassification, @GRAPClassificationNote, @MainSegmentReporting, @SubSegmentReporting, @IsActiveForSCM);

                    SELECT @PlanProjectItemID = SCOPE_IDENTITY();

					--Update HistoricalProjectCode
					UPDATE Plan_ProjectItem 
					SET HistoricalProjectCode = CONVERT(VARCHAR, PlanProjectItem_ID) + '|' + ISNULL(HistoricalProjectCode, '0') 
					WHERE PlanProjectItem_ID = @PlanProjectItemID

                    --Insert Data into Plan_ProjectItemDocs    
                    INSERT INTO dbo.Plan_ProjectItemDocs
                    (
                        SupportingDocsID,
                        PlanProjectItemID,
                        DateCaptured,
                        CapturerID
                    )
                    SELECT SupportingDocsID,
                           @PlanProjectItemID,
                           GETDATE(),
                           @UserId
                    FROM dbo.Plan_AdjustmentProjectItemDocs (NOLOCK)
                    WHERE PlanAdjustmentProjectItemID = @PlanAdjustmentProjectItemID;

                    --Insert Data into Plan_ProjectItemMonth    
                    INSERT INTO dbo.Plan_ProjectItemMonth
                    (
                        PlanProjectItemID,
                        MonthID,
                        UnitQuantity,
                        UnitPrice,
                        CaptureID,
                        DateCaptured,
                        VirementId,
                        AdjustmentId
                    )
                    SELECT @PlanProjectItemID,
                           MonthID,
                           UnitQuantity,
                           ISNULL(AdjustedUnitPrice, UnitPrice),
                           @UserId,
                           GETDATE(),
                           VirementId,
                           AdjustmentProjectItemMonth_ID
                    FROM dbo.Plan_AdjustmentProjectItemMonth (NOLOCK)
                    WHERE PlanAdjustmentProjectItemID = @PlanAdjustmentProjectItemID;

                    ------------Section Added by Sahil for Plan_BudgetRegister - 02-Jan-2018------------    

                    --#80664 Technical CR â€“ Planning Changes for storing and retrieving Budget Consumption: By Sahil    
                    INSERT INTO dbo.Plan_BudgetConsumption
                    (
                        FinYear,
                        PlanProjectItemID,
                        BudgetTransactionTypeID,
                        ModuleID,
                        PK_TransactionID,
                        TransactionTableName,
                        ConsumingTransactionAmount,
                        AdjustedTansactionAmount,
                        AvailableBudget,
                        ProcessingMonth,
                        BudgetConsumptionProcessID,
                        OriginalBudgetToDate,
                        AdjustedBudgetToDate,
                        CapturedExpenditureToDate,
                        ReserveToDate,
                        CommitToDate,
                        ActualToDate,
                        CapturerID,
                        DateCaptured,
						ConsumingTransactionAmountMultiYear,
						AvailableBudgetMultiYear,
						CapturedExpenditureToDateMultiYear,
						ReserveToDateMultiYear
                    )
                    VALUES
                    (   @FinYear,                      -- FinYear - nvarchar(9)    
                        @PlanProjectItemID,            -- PlanProjectItemID - int    
                        @BudgetTxnTypeId,              -- BudgetTransactionTypeID - int    
                        10,                            -- ModuleID - int    
                        @PlanProjectItemID,            -- PK_TransactionID - int    
                        N'Plan_ProjectItem',           -- TransactionTableName - nvarchar(100)    
                        @TxnAmountForBudgetRegister,   -- ConsumingTransactionAmount - decimal(18, 2)    
                        @TxnAmountForBudgetRegister,   -- AdjustedTansactionAmount - decimal(18, 2)    
                        @TxnAmountForBudgetRegister,   -- AvailableBudget - decimal(18, 2)    
                        @UserProcessingMonth,          -- ProcessingMonth - int    
                        202,                            -- BudgetConsumptionProcessID - int    
                        0,                             -- OriginalBudgetToDate - decimal(18, 2)    
                        @TxnAmountForBudgetRegister,   -- AdjustedBudgetToDate - decimal(18, 2)    
                        0,                             -- CapturedExpenditureToDate - decimal(18, 2)    
                        0,                             -- ReserveToDate - decimal(18, 2)    
                        0,                             -- CommitToDate - decimal(18, 2)    
                        0,                             -- ActualToDate - decimal(18, 2)    
                        @UserId,                       -- CapturerID - int    
                        GETDATE(),                      -- DateCaptured - datetime    
						@TxnAmountForBudgetRegisterMultiYear,
						@TxnAmountForBudgetRegisterMultiYear,
						0,
						0
                    );

					SET @countProjectItemNullID = @countProjectItemNullID + 1;

                END;

				SET @countProjectID = @countProjectID + 1;

            END;
			
        END;
        ----------Plan_AdjustmentProject End    

        ----------Plan_AdjustmentProjectCosting Start    
        --Insert Data into @tblProjectCosting where RefFundingSourceDetailId IS NOT NULL AND AdjustmentVersionId 

		UPDATE pc
		SET 
			ScoaCostingID = papc.ScoaCostingID,
			ProjectID = pap.ReferenceProject_ID,
            DateModified = GETDATE(),
            ModifierID = @UserId
		FROM 
			dbo.Plan_AdjustmentProjectCosting papc
			INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentProject_ID = papc.AdjustmentProjectID
			INNER JOIN dbo.Plan_ProjectCosting pc ON papc.ReferenceProjectCostingID = pc.ProjectCosting_ID
		WHERE 
			papc.AdjustmentVersionId = @AdjustmentVersionId
			AND papc.ReferenceProjectCostingID IS NOT NULL
			AND ISNULL(pap.IsDeleted, 0) = 0;

        ----------Plan_AdjustmentProjectCosting End    

        ----------Plan_AdjustmentProjectDivisions Start    
        --Insert Data into @tblProjectDivisions where RefFundingSourceDetailId IS NOT NULL AND AdjustmentVersionId    

		UPDATE pd
		SET 
			DivisionID = papd.DivisionID,
			ProjectID = pap.ReferenceProject_ID,
            DateModified = GETDATE(),
            ModifierID = @UserId
        FROM 
			dbo.Plan_AdjustmentProjectDivisions papd
            INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentProject_ID = papd.AdjustmentProjectID
			INNER JOIN dbo.Plan_ProjectDivisions pd ON papd.ReferenceProjectDivisionID = pd.ProjectDivision_ID
        WHERE 
			papd.AdjustmentVersionId = @AdjustmentVersionId
            AND papd.ReferenceProjectDivisionID IS NOT NULL
            AND ISNULL(pap.IsDeleted, 0) = 0;

        ----------Plan_AdjustmentProjectDivisions Start    

        ----------Plan_AdjustmentProjectFunctions Start    
        --Insert Data into @tblProjectFunctions where RefFundingSourceDetailId IS NOT NULL AND AdjustmentVersionId   

		UPDATE pf
		SET
			ScoaFunctionID = papf.ScoaFunctionID,
			ProjectID = pap.ReferenceProject_ID,
            DateModified = GETDATE(),
            ModifierID = @UserId
        FROM 
			dbo.Plan_AdjustmentProjectFunctions papf 
            INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentProject_ID = papf.AdjustmentProjectID
			INNER JOIN dbo.Plan_ProjectFunctions pf ON papf.ReferenceProjectFunctionID = pf.ProjectFunction_ID
        WHERE 
			papf.AdjustmentVersionId = @AdjustmentVersionId
            AND papf.ReferenceProjectFunctionID IS NOT NULL
            AND ISNULL(pap.IsDeleted, 0) = 0;
        ----------Plan_AdjustmentProjectFunctions End    

        ----------Plan_AdjustmentProjectFund Start    
        --Insert Data into @tblProjectFund where RefFundingSourceDetailId IS NOT NULL AND AdjustmentVersionId

		UPDATE pf
		SET	
			ProjectID = pap.ReferenceProject_ID,
            ScoaFundID = papf.ScoaFundID,
            FundAmount = papf.FundAmount,
            FundReference = papf.FundReference,
            VirementId = papf.VirementId,
            AdjustmentId = papf.AdjustmentId,
            DateModified = GETDATE(),
            ModifierID = @UserId
        FROM 
			dbo.Plan_AdjustmentProjectFund papf
            INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentProject_ID = papf.AdjustmentProjectID
			INNER JOIN dbo.Plan_ProjectFund pf ON papf.ReferenceProjectFundID = pf.ProjectFund_ID
        WHERE 
			papf.AdjustmentVersionId = @AdjustmentVersionId
            AND papf.ReferenceProjectFundID IS NOT NULL
            AND ISNULL(pap.IsDeleted, 0) = 0;

        ----------Plan_AdjustmentProjectFund End    

        ----------Plan_AdjustmentProjectIDP Start    
        --Insert Data into @tblProjectIDP where RefFundingSourceDetailId IS NOT NULL AND AdjustmentVersionId

		UPDATE pidp
		SET 
			ProjectID = pap.ReferenceProject_ID,
            ParentIDPItemID = papidp.ParentIDPItemID,
            ProjectIDPItemID = papidp.AdjustmentProjectIDPItemID,
            Percentage = papidp.Percentage,
            Latitude = papidp.Latitude,
            Longitude = papidp.Longitude,
            DateModified = GETDATE(),
            ModifierID = @UserId
        FROM 
			dbo.Plan_AdjustmentProjectIDP papidp 
            INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentProject_ID = papidp.AdjustmentProjectID
			INNER JOIN dbo.Plan_ProjectIDP pidp ON papidp.ReferenceProjectIDPID = pidp.ProjectIDP_ID
        WHERE 
			papidp.AdjustmentVersionId = @AdjustmentVersionId
            AND papidp.ReferenceProjectIDPID IS NOT NULL
            AND ISNULL(pap.IsDeleted, 0) = 0;

        ----------Plan_AdjustmentProjectIDP End    

        ----------Plan_AdjustmentProjectItem Start     
        --Insert Data into @@tblProjectItem where RefFundingSourceDetailId IS NOT NULL AND AdjustmentVersionId    
        INSERT INTO #tblProjectItem
        (
            ProjectItem_ID,
            ProjectID,
            ProjectItemID,
            SCOAItemID,
            FinYear,
            ProjectFundYearID,
            SCOAFundId,
            BudgetAmount,
            BudgetAmountCurP1,
            BudgetAmountCurP2,
            SCOAFunctionId,
            SCOARegionId,
            DivisionId,
            BudgetSplitID,
            VirementId,
            HistoricalProjectCode,
            AdjustmentId,
            ModificationNumber,
            SCOACostingID,
            IsItemLocked,
            CreditDebit,
            AdjustedBudgetAmount,
            AdjustedBudgetAmountCurP1,
            AdjustedBudgetAmountCurP2,
			GRAPClassification,
			GRAPClassificationNote,
			MainSegmentReporting,
			SubSegmentReporting,
			IsActiveForSCM
        )
        SELECT papi.ReferencePlanProjectItem_ID,
               pap.ReferenceProject_ID,
               papi.ProjectItemID,
               papi.SCOAItemID,
               papi.FinYear,
               papi.ProjectFundYearID,
               papi.SCOAFundId,
               papi.BudgetAmount,
               papi.BudgetAmountCurP1,
               papi.BudgetAmountCurP2,
               papi.SCOAFunctionId,
               papi.SCOARegionId,
               papi.DivisionId,
               papi.BudgetSplitID,
               papi.VirementId,
               papi.HistoricalProjectCode,
               papi.PlanAdjustmentProjectItem_ID,
               papi.ModificationNumber,
               papi.SCOACostingID,
               papi.IsItemLocked,
               papi.CreditDebit,
               papi.AdjustedBudgetAmount,
               papi.AdjustedBudgetAmountCurP1,
               papi.AdjustedBudgetAmountCurP2,
			   papi.GRAPClassification,
			   papi.GRAPClassificationNote,
			   papi.MainSegmentReporting,
			   papi.SubSegmentReporting,
			   papi.IsActiveForSCM
        FROM dbo.Plan_AdjustmentProjectItem papi (NOLOCK)
            INNER JOIN dbo.Plan_AdjustmentProject pap (NOLOCK)
                ON pap.AdjustmentProject_ID = papi.AdjustmentProjectID
        WHERE papi.AdjustmentVersionId = @AdjustmentVersionId
              AND papi.ReferencePlanProjectItem_ID IS NOT NULL
              AND ISNULL(pap.IsDeleted, 0) = 0;

        --Using While Loop Data Update into Plan_ProjectItem    
		SET @countProjectItemID = (SELECT MIN(CountProjectItemID) FROM #tblProjectItem);
        WHILE (@countProjectItemID <= (SELECT MAX(CountProjectItemID) FROM #tblProjectItem))
        BEGIN
            DECLARE @FinalAdjustedBudgetAmount DECIMAL(18, 2), @FinalAdjustedBudgetAmountMultiYear DECIMAL(18, 2);
            SELECT 
                   @ReferencePlanProjectItem_ID = ProjectItem_ID,
                   @AdjustmentProjectID = ProjectID,
                   @ProjectItemID = ProjectItemID,
                   @SCOAItemID = SCOAItemID,
                   @FinYear = FinYear,
                   @ProjectFundYearID = ProjectFundYearID,
                   @ScoaFundID = SCOAFundId,
                   @BudgetAmount = BudgetAmount,
                   @BudgetAmountCurP1 = BudgetAmountCurP1,
                   @BudgetAmountCurP2 = BudgetAmountCurP2,
                   @ScoaFunctionID = SCOAFunctionId,
                   @SCOARegionId = SCOARegionId,
                   @DivisionID = DivisionId,
                   @BudgetSplitID = BudgetSplitID,
                   @VirementId = VirementId,
                   @HistoricalProjectCode = HistoricalProjectCode,
                   @AdjustmentId = AdjustmentId,
                   @ModificationNumber = ModificationNumber,
                   @ScoaCostingID = SCOACostingID,
                   @IsItemLocked = IsItemLocked,
                   @CreditDebit = CreditDebit,
                   @AdjustedBudgetAmount = AdjustedBudgetAmount,
                   @AdjustedBudgetAmountCurP1 = AdjustedBudgetAmountCurP1,
                   @AdjustedBudgetAmountCurP2 = AdjustedBudgetAmountCurP2,
				   @GRAPClassification = GRAPClassification,
				   @GRAPClassificationNote = GRAPClassificationNote,
				   @MainSegmentReporting = MainSegmentReporting,
				   @SubSegmentReporting = SubSegmentReporting,
				   @IsActiveForSCM = ISNULL(IsActiveForSCM,1)
            FROM #tblProjectItem
			WHERE CountProjectItemID = @countProjectItemID;


            SET @FinalAdjustedBudgetAmount = @BudgetAmount - ISNULL(@AdjustedBudgetAmount, 0);
			SET @FinalAdjustedBudgetAmountMultiYear = (@BudgetAmountCurP1 + @BudgetAmountCurP2) - (ISNULL(@AdjustedBudgetAmountCurP1, 0) + ISNULL(@AdjustedBudgetAmountCurP2, 0))

            IF (@AdjustedBudgetAmount IS NOT NULL)
                SET @BudgetAmount = @AdjustedBudgetAmount;
            IF (@AdjustedBudgetAmountCurP1 IS NOT NULL)
                SET @BudgetAmountCurP1 = @AdjustedBudgetAmountCurP1;
            IF (@AdjustedBudgetAmountCurP2 IS NOT NULL)
                SET @BudgetAmountCurP2 = @AdjustedBudgetAmountCurP2;

            IF (@ReferencePlanProjectItem_ID > 0)
            BEGIN
                UPDATE dbo.Plan_ProjectItem
                SET ProjectID = @AdjustmentProjectID,
                    ProjectItemID = @ProjectItemID,
                    SCOAItemID = @SCOAItemID,
                    FinYear = @FinYear,    
                    SCOAFundId = @ScoaFundID,
                    BudgetAmount = @BudgetAmount,
                    BudgetAmountCurP1 = @BudgetAmountCurP1,
                    BudgetAmountCurP2 = @BudgetAmountCurP2,
                    SCOAFunctionId = @ScoaFunctionID,
                    SCOARegionId = @SCOARegionId,
                    DivisionId = @DivisionID,
                    BudgetSplitID = @BudgetSplitID,
                    VirementId = @VirementId,
                    HistoricalProjectCode = @HistoricalProjectCode,
                    AdjustmentId = @AdjustmentId,
                    ModificationNumber = @ModificationNumber,
                    SCOACostingID = @ScoaCostingID,
                    IsItemLocked = @IsItemLocked,
                    CreditDebit = @CreditDebit,
                    DateModified = GETDATE(),
                    ModifierID = @UserId,
					GRAPClassification = @GRAPClassification,
					GRAPClassificationNote = @GRAPClassificationNote,
					MainSegmentReporting = @MainSegmentReporting,
					SubSegmentReporting = @SubSegmentReporting,
					IsActiveForSCM = @IsActiveForSCM
                WHERE PlanProjectItem_ID = @ReferencePlanProjectItem_ID;

                ------------Section Added by Sahil for Plan_BudgetRegister - 02-Jan-2018------------    
                --#80664 Technical CR â€“ Planning Changes for storing and retrieving Budget Consumption - By Sahil 16-11-2018    
                IF (@AdjustedBudgetAmount IS NOT NULL)
                BEGIN

                    IF EXISTS
                    (
                        SELECT 1
                        FROM dbo.Plan_BudgetConsumption
                        WHERE PlanProjectItemID = @ReferencePlanProjectItem_ID
                    )
                    BEGIN
                        --Second Update the amounts with Actual    
                        INSERT INTO dbo.Plan_BudgetConsumption
                        (
                            FinYear,
                            PlanProjectItemID,
                            BudgetTransactionTypeID,
                            ModuleID,
                            PK_TransactionID,
                            TransactionTableName,
                            ConsumingTransactionAmount,
                            AdjustedTansactionAmount,
                            AvailableBudget,
                            ProcessingMonth,
                            BudgetConsumptionProcessID,
                            OriginalBudgetToDate,
                            AdjustedBudgetToDate,
                            CapturedExpenditureToDate,
                            ReserveToDate,
                            CommitToDate,
                            ActualToDate,
                            CapturerID,
                            DateCaptured,
							ConsumingTransactionAmountMultiYear,
							AvailableBudgetMultiYear,
							CapturedExpenditureToDateMultiYear,
							ReserveToDateMultiYear
                        )
                        SELECT TOP 1
                               @FinYear,
                               @ReferencePlanProjectItem_ID,
                               @BudgetTxnTypeId,
                               10,
                               @ReferencePlanProjectItem_ID,
                               N'Plan_ProjectItem',
                               - (@FinalAdjustedBudgetAmount),
                               - (@FinalAdjustedBudgetAmount),
                               (pdc.AvailableBudget - @FinalAdjustedBudgetAmount),
                               @UserProcessingMonth,
                               202,
                               pdc.OriginalBudgetToDate,
                               -@FinalAdjustedBudgetAmount,
                               pdc.CapturedExpenditureToDate,
                               pdc.ReserveToDate,
                               pdc.CommitToDate,
                               pdc.ActualToDate,
                               @UserId,
                               GETDATE(),
							   - (@FinalAdjustedBudgetAmountMultiYear),
							   (pdc.AvailableBudgetMultiYear - (@FinalAdjustedBudgetAmountMultiYear)),
							   pdc.CapturedExpenditureToDateMultiYear,
							   pdc.ReserveToDateMultiYear
                        FROM dbo.Plan_BudgetConsumption pdc
                        WHERE pdc.PlanProjectItemID = @ReferencePlanProjectItem_ID
                        ORDER BY pdc.BudgetConsumption_ID DESC;

                    END;

                END;
                ------------Section Added by Sahil for Plan_BudgetRegister - 02-Jan-2018------------    

				SET @countProjectItemID = @countProjectItemID + 1;
            END;
        END;
        ----------Plan_AdjustmentProjectItem End    

        ----------Plan_AdjustmentProjectRegions Start    
        --Insert Data into @tblProjectRegion where RefFundingSourceDetailId IS NOT NULL AND AdjustmentVersionId    

		UPDATE pr
		SET 
			ProjectID = pap.ReferenceProject_ID,
            ScoaRegionID = papr.ScoaRegionID,
            RegionPercent = papr.RegionPercent,
            DateModified = GETDATE(),
            ModifierID = @UserId
        FROM 
			dbo.Plan_AdjustmentProjectRegions papr 
            INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentProject_ID = papr.AdjustmentProjectID
			INNER JOIN dbo.Plan_ProjectRegions pr ON papr.ReferenceProjectRegionID = pr.ProjectRegion_ID
        WHERE 
			papr.AdjustmentVersionId = @AdjustmentVersionId
            AND papr.ReferenceProjectRegionID IS NOT NULL
            AND ISNULL(pap.IsDeleted, 0) = 0;

        ----------Plan_AdjustmentProjectRegions End    

        ----------Plan_AdjustmentProjectFundYear Start    
        --Insert Data into @tblProjectFundYear where RefFundingSourceDetailId IS NOT NULL AND AdjustmentVersionId    

		UPDATE pfy
		SET 
			ProjectFundID = papf.ReferenceProjectFundID,
            FinYear = papfy.FinYear,
            YearFundAmount = papfy.YearFundAmount,
            VirementId = papfy.VirementId,
            AdjustmentId = papfy.AdjustmentId,
            DateModified = GETDATE(),
            ModifierID = @UserId
        FROM 
			dbo.Plan_AdjustmentProjectFundYear papfy
            INNER JOIN dbo.Plan_AdjustmentProjectFund papf ON papf.AdjustmentProjectFund_ID = papfy.AdjustmentProjectFundID
            INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentProject_ID = papf.AdjustmentProjectID
			INNER JOIN dbo.Plan_ProjectFundYear pfy ON papfy.ReferenceProjectFundYearID = pfy.ProjectFundYear_ID
        WHERE 
			papfy.AdjustmentVersionId = @AdjustmentVersionId
            AND papfy.ReferenceProjectFundYearID IS NOT NULL
            AND ISNULL(pap.IsDeleted, 0) = 0;

        ----------Plan_AdjustmentProjectFundYear End    

        ----------Plan_AdjustmentProjectItemDocs Start    
        --Insert Data into @tblProjectItemDocs where RefFundingSourceDetailId IS NOT NULL AND AdjustmentVersionId   

		UPDATE pid
		SET
			SupportingDocsID = papid.SupportingDocsID,
            PlanProjectItemID = papi.ReferencePlanProjectItem_ID,
            DateModified = GETDATE(),
            ModifierID = @UserId
        FROM 
			dbo.Plan_AdjustmentProjectItemDocs papid
            INNER JOIN dbo.Plan_AdjustmentProjectItem papi ON papi.PlanAdjustmentProjectItem_ID = papid.PlanAdjustmentProjectItemID
            INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentProject_ID = papi.AdjustmentProjectID
			INNER JOIN dbo.Plan_ProjectItemDocs pid ON papid.ReferenceProjectItemDocsID = pid.ProjectItemDocs_ID
        WHERE 
			papid.AdjustmentVersionId = @AdjustmentVersionId
            AND papid.ReferenceProjectItemDocsID IS NOT NULL;

        ----------Plan_AdjustmentProjectItemDocs End    

        ----------Plan_AdjustmentProjectItemMonth Start     
        --Insert Data into @tblProjectItemMonth where RefFundingSourceDetailId IS NOT NULL AND AdjustmentVersionId    

		UPDATE pim
		SET 
			PlanProjectItemID = papi.ReferencePlanProjectItem_ID,
            MonthID = papim.MonthID,
            UnitQuantity = papim.UnitQuantity,
            UnitPrice = ISNULL(papim.AdjustedUnitPrice, papim.UnitPrice),
            VirementId = papim.VirementId,
            AdjustmentId = papim.AdjustmentProjectItemMonth_ID,
            DateModified = GETDATE(),
            ModifierID = @UserId
        FROM 
			dbo.Plan_AdjustmentProjectItemMonth papim
            INNER JOIN dbo.Plan_AdjustmentProjectItem papi ON papi.PlanAdjustmentProjectItem_ID = papim.PlanAdjustmentProjectItemID
            INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentProject_ID = papi.AdjustmentProjectID
			INNER JOIN dbo.Plan_ProjectItemMonth pim ON papim.ReferenceProjectItemMonthID = pim.ProjectItemMonth_ID
        WHERE 
			papim.AdjustmentVersionId = @AdjustmentVersionId
            AND papim.ReferenceProjectItemMonthID IS NOT NULL;

        ----------Plan_AdjustmentProjectItemMonth End    

        --Declare Variables    
        DECLARE @IsAdjustment BIT,
                @AdjustmentBudgetPolicyApproval_Id INT,
                @SupplementaryAdjustment_Id INT,
                @CreateAdjustmentBudgetVersionResult NVARCHAR(MAX),
                @CreateAdjustmentFundingBudgetVersionResult NVARCHAR(MAX);

        --Insert data into Plan_AdjustmentBudgetApproval    
        INSERT INTO dbo.Plan_AdjustmentBudgetApproval
        (
            FinancialYear,
            IsInitializeAdjustmentBudget,
            ApprovedAdjustmentBudgetFileName,
            ApprovedBy,
            ApprovedDate,
            DateCaptured,
            CapturerID,
            CouncilApprovedDate,
            AdjustmentVersionId,
            AdjustmentFundingVersionId
        )
        VALUES
        (@FinancialYear, 1, @ApprovedAdjustmentBudgetFileName, @UserId, GETDATE(), GETDATE(), @UserId,
         @CouncilApprovedDate, @AdjustmentVersionId, @AdjustmentFundingVersionId);

        SELECT @AdjustmentBudgetApprovalId = SCOPE_IDENTITY();

        SELECT @IsAdjustment = IsAdjustmentFinalApproved,
               @AdjustmentBudgetPolicyApproval_Id = AdjustmentBudgetPolicyApproval_Id
        FROM dbo.Plan_AdjustmentBudgetPolicyApproval (NOLOCK)
        WHERE AdjustmentVersionId = @AdjustmentVersionId
              AND AdjustmentFundingVersionId = @AdjustmentFundingVersionId;

        IF (@IsAdjustment = 0)
        BEGIN
            UPDATE Plan_AdjustmentBudgetPolicyApproval
            SET IsAdjustmentFinalApproved = 1,
                ModifierID = @UserId,
                DateModified = GETDATE()
            WHERE AdjustmentVersionId = @AdjustmentVersionId
                  AND AdjustmentFundingVersionId = @AdjustmentFundingVersionId;
        END;
        ELSE
        BEGIN
            SELECT @IsAdjustment = IsAdjustmentFinalApproved,
                   @SupplementaryAdjustment_Id = SupplementaryAdjustment_Id
            FROM dbo.Plan_SupplementaryAdjustment (NOLOCK)
            WHERE AdjustmentVersionId = @AdjustmentVersionId
                  AND AdjustmentFundingVersionId = @AdjustmentFundingVersionId;
            IF (@IsAdjustment = 0)
            BEGIN
                UPDATE Plan_SupplementaryAdjustment
                SET IsAdjustmentFinalApproved = 1,
                    FinalApprovedBy = @UserId,
                    FinalApprovedDate = GETDATE(),
                    ModifierID = @UserId,
                    DateModified = GETDATE()
                WHERE AdjustmentVersionId = @AdjustmentVersionId
                      AND AdjustmentFundingVersionId = @AdjustmentFundingVersionId;
            END;
        END;

        IF NOT EXISTS
        (
            SELECT 1
            FROM dbo.Plan_AdjustmentBudgetVersion
            WHERE VersionNumber = @VersionNumber
        )
        BEGIN


            SELECT TOP 1
                   @CurrentAdjustmentVersionId = AdjustmentBudgetVersion_ID
            FROM dbo.Plan_AdjustmentBudgetVersion
            WHERE VersionName LIKE @FinancialYear + '%'
            ORDER BY AdjustmentBudgetVersion_ID DESC;

            INSERT INTO dbo.Plan_AdjustmentBudgetVersion
            (
                VersionNumber,
                VersionName,
                Comments,
                CapturerID,
                DateCaptured
            )
            VALUES
            (@VersionNumber, @VersionName, @Comments, @UserId, GETDATE());

            SELECT @AdjustmentBudgetVersionId = SCOPE_IDENTITY();

            IF (@AdjustmentBudgetVersionId <> 0)
            BEGIN
                INSERT INTO dbo.Plan_AdjustmentBudgetVersionDetail
                (
                    AdjustmentBudgetVersionID,
                    ProjectID,
                    FinYear,
                    IDPItemID,
                    CapitalOperation,
                    ScoaProjectID,
                    SCOACostingID,
                    ProjectTypeID,
                    PlanProjectItemID,
                    ProjectItemID,
                    SCOAItemID,
                    SCOAFundId,
                    BudgetAmount,
                    BudgetAmountCurP1,
                    BudgetAmountCurP2,
                    SCOAFunctionId,
                    SCOARegionId,
                    DivisionId,
                    BudgetSplitID,
                    VirementId,
                    AdjustmentId,
                    ModificationNumber,
                    IsItemLocked,
                    CreditDebit,
                    AdjutmentType,
                    LegislativeReasonAdjustment,
                    ReasonForAdjustment,
                    CapturerID,
                    DateCaptured,
					GRAPClassification,
					GRAPClassificationNote,
					MainSegmentReporting,
					SubSegmentReporting,
					CostingProject
                )
                SELECT @AdjustmentBudgetVersionId,
                       PP.AdjustmentProject_ID,
                       PP.FinYear,
                       0,
                       ISNULL(PP.CapitalOperation, 0),
                       ISNULL(PP.ScoaProjectID, 0),
                       ISNULL(PPI.SCOACostingID, 0),
                       ISNULL(PP.ProjectTypeID, 0),
                       ISNULL(PPI.PlanAdjustmentProjectItem_ID, 0),
                       ISNULL(PPI.ProjectItemID, 0),
                       ISNULL(PPI.SCOAItemID, 0),
                       ISNULL(PPI.SCOAFundId, 0),
                       ISNULL(PPI.BudgetAmount, 0),
                       ISNULL(PPI.BudgetAmountCurP1, 0),
                       ISNULL(PPI.BudgetAmountCurP2, 0),
                       ISNULL(PPI.SCOAFunctionId, 0),
                       ISNULL(PPI.SCOARegionId, 0),
                       ISNULL(PPI.DivisionId, 0),
                       ISNULL(PPI.BudgetSplitID, 0),
                       ISNULL(PPI.VirementId, 0),
                       ISNULL(PPI.AdjustmentId, 0),
                       ISNULL(PPI.ModificationNumber, 0),
                       ISNULL(PPI.IsItemLocked, 0),
                       ISNULL(PPI.CreditDebit, ''),
                       ISNULL(PPI.AdjutmentType, 0),
                       ISNULL(PPI.LegislativeReasonAdjustment, 0),
                       ISNULL(PPI.ReasonForAdjustment, ''),
                       @UserId,
                       GETDATE(),
					   ISNULL(GRAPClassification, ''),
					   ISNULL(GRAPClassificationNote, ''),
					   ISNULL(MainSegmentReporting, ''),
					   ISNULL(SubSegmentReporting, ''),
					   ISNULL(CostingProject, 0)
                FROM dbo.Plan_AdjustmentProject AS PP
                    INNER JOIN dbo.Plan_AdjustmentProjectItem AS PPI
                        ON PP.AdjustmentProject_ID = PPI.AdjustmentProjectID
                WHERE PP.FinYear = @FinancialYear
                      AND ISNULL(PP.IsDeleted, 0) = 0
                      AND PP.AdjustmentVersionId = @CurrentAdjustmentVersionId;

                INSERT INTO dbo.Plan_AdjustmentBudgetVersionMonths
                (
                    AdjustmentBudgetVersionID,
                    AdjustmentProjectItemMonth_ID,
                    PlanAdjustmentProjectItemID,
                    MonthID,
                    UnitQuantity,
                    UnitPrice,
                    CaptureID,
                    DateCaptured,
                    VirementId,
                    AdjustmentId
                )
                SELECT @AdjustmentBudgetVersionId,
                       ppim.AdjustmentProjectItemMonth_ID,
                       PPI.PlanAdjustmentProjectItem_ID,
                       ppim.MonthID,
                       ppim.UnitQuantity,
                       ppim.UnitPrice,
                       @UserId,
                       GETDATE(),
                       ppim.VirementId,
                       ppim.AdjustmentId
                FROM dbo.Plan_AdjustmentProject AS PP
                    INNER JOIN dbo.Plan_AdjustmentProjectItem AS PPI
                        ON PP.AdjustmentProject_ID = PPI.AdjustmentProjectID
                    INNER JOIN dbo.Plan_AdjustmentProjectItemMonth ppim
                        ON PPI.PlanAdjustmentProjectItem_ID = ppim.PlanAdjustmentProjectItemID
                WHERE PP.FinYear = @FinancialYear
                      AND ISNULL(PP.IsDeleted, 0) = 0
                      AND PP.AdjustmentVersionId = @CurrentAdjustmentVersionId;

                SET @CreateAdjustmentBudgetVersionResult = N'Success';
            END;
            ELSE
            BEGIN
                SET @CreateAdjustmentBudgetVersionResult
                    = N'Adjustment Budget Version id not found & Adjustment Budget Version Detail Entry Skipped';
            END;
        END;
        ELSE
        BEGIN
            SET @CreateAdjustmentBudgetVersionResult
                = N'Adjustment Budget Version - ' + @VersionNumber + N' is already generated';
        END;



        /*======================= Chirag Remove Inner SP (Inven_InsertAuditLog_sp :Plan_CreateAdjustmentBudgetVersion_sp) --END =================*/

        IF (@CreateAdjustmentBudgetVersionResult != 'Success')
        BEGIN
            SET @ErrorResult = @CreateAdjustmentBudgetVersionResult;
            ROLLBACK TRANSACTION AdjustmentsTran;
            GOTO AllGood;
        END;



        /*======================= Chirag Remove Inner SP (Inven_InsertAuditLog_sp :Plan_CreateAdjustmentFundingBudgetVersion_sp) --START =================*/

        DECLARE @FinancialYearP1 NVARCHAR(9),
                @FinancialYearP2 NVARCHAR(9),
                @yearp1 INT,
                @yearp2 INT,
                @yearp3 INT;

        SELECT @yearp1 = CAST(SUBSTRING(@FinancialYear, 6, 4) AS INT);
        SELECT @yearp2 = @yearp1 + 1;
        SELECT @yearp3 = @yearp1 + 2;
        SELECT @FinancialYearP1 = CONVERT(VARCHAR(4), @yearp1) + N'/' + CONVERT(VARCHAR(4), @yearp2);
        SELECT @FinancialYearP2 = CONVERT(VARCHAR(4), @yearp2) + N'/' + CONVERT(VARCHAR(4), @yearp3);

        --Insert into Plan_AdjustmentFundingBudgetVersion    
        IF NOT EXISTS
        (
            SELECT 1
            FROM dbo.Plan_AdjustmentFundingBudgetVersion
            WHERE VersionNumber = @VersionNumber
        )
        BEGIN

            SELECT TOP 1
                   @CurrentAdjustmentVersionId = AdjustmentBudgetVersion_ID
            FROM dbo.Plan_AdjustmentBudgetVersion
            WHERE VersionName LIKE @FinancialYear + '%'
            ORDER BY AdjustmentBudgetVersion_ID DESC;

            INSERT INTO dbo.Plan_AdjustmentFundingBudgetVersion
            (
                VersionNumber,
                VersionName,
                Comments,
                CapturerID,
                DateCaptured
            )
            VALUES
            (@VersionNumber, @VersionName, @Comments, @UserId, GETDATE());

            SELECT @AdjustmentBudgetVersionId = SCOPE_IDENTITY();

            --Insert into Plan_AdjustmentFundingBudgetVersionDetails    
            IF (@AdjustmentBudgetVersionId <> 0)
            BEGIN
                INSERT INTO dbo.Plan_AdjustmentFundingBudgetVersionDetails
                (
                    AdjustmentFundingBudgetVersionId,
                    AdjustmentFundingSourceBudgetDetail_ID,
                    AdjustmentFundingSourceBudgetHeaderID,
                    FinancialYear,
                    FundingSourceID,
                    ScoaID,
                    FundingSourceBudget,
                    DateCaptured,
                    CapturerID,
                    UploadedDocument
                )
                SELECT @AdjustmentBudgetVersionId,
                       pfsb.AdjustmentFundingSourceBudgetDetail_ID,
                       pfsb.AdjustmentFundingSourceBudgetHeaderID,
                       pfsbh.FinancialYear,
                       pfsb.AdjustmentFundingSourceID,
                       pfsb.ScoaID,
                       pfsb.FundingSourceBudget,
                       GETDATE(),
                       @UserId,
                       pfsb.UploadedDocument
                FROM dbo.Plan_AdjustmentFundingSourceBudget_Header pfsbh
                    INNER JOIN dbo.Plan_AdjustmentFundingSourceBudget_Detail pfsb
                        ON pfsb.AdjustmentFundingSourceBudgetHeaderID = pfsbh.AdjustmentFundingSourceBudgetHeader_ID
                WHERE pfsbh.FinancialYear IN ( @FinancialYear, @FinancialYearP1, @FinancialYearP2 )
                      AND pfsbh.AdjustmentFundingVersionId = @CurrentAdjustmentVersionId;

                SET @CreateAdjustmentBudgetVersionResult = N'Success';
            END;
            ELSE
            BEGIN
                SET @CreateAdjustmentBudgetVersionResult
                    = N'Adjustment Funding Budget Version id not found & Adjustment Funding Budget Version Detail Entry Skipped';
            END;
        END;
        ELSE
        BEGIN
            SET @CreateAdjustmentBudgetVersionResult
                = N'Adjustment Funding Budget Version - ' + @VersionNumber + N' is already generated';
        END;


        /*======================= Chirag Remove Inner SP (Inven_InsertAuditLog_sp :Plan_CreateAdjustmentFundingBudgetVersion_sp) --END =================*/

        IF (@CreateAdjustmentFundingBudgetVersionResult != 'Success')
        BEGIN
            SET @ErrorResult = @CreateAdjustmentFundingBudgetVersionResult;
            ROLLBACK TRANSACTION AdjustmentsTran;
            GOTO AllGood;
        END;

        /*================= Chirag Start =======================*/
		DECLARE @countProjectFinalID INT = 1;
        CREATE TABLE #tblProjectFinal 
        (
			CountProjectFinalID INT IDENTITY(1,1) NOT NULL,
            Project_ID INT,
            CapitalOperation INT
        );

        INSERT INTO #tblProjectFinal
        (
            Project_ID,
            CapitalOperation
        )
        SELECT PP.Project_ID,
               PP.CapitalOperation
        FROM dbo.Plan_Project PP (NOLOCK)
        WHERE PP.FinYear = @FinancialYear
              AND ISNULL(PP.IsDeleted, 0) = 0;

		SET @countProjectFinalID = (SELECT MIN(CountProjectFinalID) FROM #tblProjectFinal);
        WHILE (@countProjectFinalID <= (SELECT MAX(CountProjectFinalID) FROM #tblProjectFinal))
        BEGIN
            SELECT 
                   @ProjectID = Project_ID,
                   @CapitalOperation = CapitalOperation
            FROM #tblProjectFinal
			WHERE CountProjectFinalID = @countProjectFinalID;

            IF (@CapitalOperation IN ( 0, 1, 3 ))
            BEGIN

                /*CHIRAG -- START */
                /*--------Create Auto create Procurement Plan--------------*/

                DECLARE @ErrorResultproc NVARCHAR(MAX);
				DECLARE @countTempID INT = 1;
                CREATE TABLE #Temp
                (
					CountTempID INT IDENTITY(1,1) NOT NULL,
                    PlanProjectItemID INT,
                    ItemDescription NVARCHAR(500),
                    EstimatedCost DECIMAL(16, 2),
                    SCOAFunctionID INT,
                    SCOAItemID INT,
                    SCOARegionID INT,
                    SCOACostingID INT,
                    ScoaProjectID INT,
                    Quantity DECIMAL(16, 2)
                );

                INSERT INTO #Temp
                SELECT i.PlanProjectItem_ID,
                       ISNULL(c.ItemDescription, css.ScoaShortDesc) AS ItemDescription,
                       ISNULL(i.BudgetAmount, 0) AS [EstimatedCost],
                       i.SCOAFunctionId,
                       i.SCOAItemID,
                       i.SCOARegionId,
                       i.SCOACostingID,
                       p.ScoaProjectID,
                       1 AS Quantity
                FROM Plan_Project p
                    INNER JOIN [Plan_ProjectItem] i
                        ON p.Project_ID = i.ProjectID
                    INNER JOIN dbo.Const_SCOA_Structure css
                        ON css.ScoaID = i.SCOAItemID
                    LEFT OUTER JOIN [Const_ProjectItem] c
                        ON i.ProjectItemID = c.ProjectItem_ID
                WHERE p.Project_ID = @ProjectID
                      AND i.FinYear = @FinancialYear
                      AND css.ScoaCode NOT LIKE 'IR%'
                      AND PlanProjectItem_ID NOT IN
                          (
                              SELECT d.PlanProjectItemID
                              FROM SCM_ProcurementPlanNew pp
                                  INNER JOIN SCM_ProcurementPlanDetails d
                                      ON pp.ProcurementPlan_ID = d.ProcurementPlanID
                              WHERE pp.PlanProjectID = @ProjectID
                                    AND pp.FinYear = @FinancialYear
                          )
                      AND ISNULL(i.BudgetAmount, 0) > 0;

                DECLARE @ItemDescription NVARCHAR(500),
                        @EstimatedCost DECIMAL(16, 2),
                        @Quantity DECIMAL(16, 2);

                DECLARE @ProcurementPlanID INT;
                DECLARE @ProcurementPlanDetailID INT;

				SET @countTempID = (SELECT MIN(CountTempID) FROM #Temp);
                WHILE (@countTempID <= (SELECT MAX(CountTempID) FROM #Temp))
                BEGIN
                    SELECT 
                           @PlanProjectItemID = PlanProjectItemID,
                           @ItemDescription = ItemDescription,
                           @EstimatedCost = EstimatedCost,
                           @ScoaFunctionID = SCOAFunctionID,
                           @SCOAItemID = SCOAItemID,
                           @SCOARegionId = SCOARegionID,
                           @ScoaCostingID = SCOACostingID,
                           @ScoaProjectID = ScoaProjectID,
                           @Quantity = Quantity
                    FROM #Temp
					WHERE CountTempID = @countTempID;
                    --ORDER BY PlanProjectItemID ASC;

                    INSERT SCM_ProcurementPlanNew
                    (
                        [PlanProjectID],
                        [ProjectID],
                        [ProcurmentStatemnet],
                        [ProcurementType],
                        [ProcessCriteria],
                        [MunicClassificationID], --(=DepartmentID)    
                        [ServiceProvider],
                        [RequestedBy],
                        [ApprovalBy],
                        [SupervisorID],
                        [StatusID],
                        [DateCaptured],
                        [CapturerID],
                        [FinYear]
                    )
                    SELECT DISTINCT
                           p.Project_ID,
                           p.ScoaProjectID,
                           p.ProjectDesc AS ProcurmentStatemnet,   
                           p.CapitalOperation,
                           'N/A',
                           cd.DepartmentID,
                           'N/A',
                           NULL,
                           NULL,
                           NULL,
                           2,
                           p.DateCaptured,
                           p.CapturerID,
                           p.FinYear
                    FROM Plan_Project p
                        INNER JOIN Plan_ProjectItem ppi
                            ON ppi.ProjectID = p.Project_ID
                        INNER JOIN Const_Division cd
                            ON cd.Division_ID = ppi.DivisionId
                        INNER JOIN dbo.Const_SCOA_Structure css
                            ON css.ScoaID = ppi.SCOAItemID
                        LEFT OUTER JOIN [Const_ProjectItem] c
                            ON ppi.ProjectItemID = c.ProjectItem_ID
                    WHERE p.Project_ID = @ProjectID
                          AND css.ScoaCode NOT LIKE 'IR%'
                          AND p.FinYear = @FinancialYear;
                    SELECT @ProcurementPlanID = SCOPE_IDENTITY();
                    -- -- by the end of this stored proc all procurement steps would be done.    

                    INSERT INTO Sys_WorkFlowSectionAudit
                    SELECT @ProcurementPlanID,
                           23,
                           'ProcPlan',
                           pp.CapturerID,
                           pp.DateCaptured,
                           1
                    FROM Plan_Project pp
                    WHERE pp.Project_ID = @ProjectID
                          AND pp.FinYear = @FinancialYear;

                    INSERT INTO Sys_WorkFlowSectionAudit
                    SELECT @ProcurementPlanID,
                           23,
                           'ProcTeam',
                           pp.CapturerID,
                           pp.DateCaptured,
                           1
                    FROM Plan_Project pp
                    WHERE pp.Project_ID = @ProjectID
                          AND pp.FinYear = @FinancialYear;

                    INSERT INTO Sys_WorkFlowSectionAudit
                    SELECT @ProcurementPlanID,
                           23,
                           'ProcDetail',
                           pp.CapturerID,
                           pp.DateCaptured,
                           1
                    FROM Plan_Project pp
                    WHERE pp.Project_ID = @ProjectID
                          AND pp.FinYear = @FinancialYear;

                    INSERT INTO SCM_ProcurementPlanDetails
                    (
                        [ProcurementPlanID],
                        [Description],
                        [EstimatedCost],
                        [SCOAFunctionID],
                        [SCOAItemID],
                        [SCOARegionID],
                        [SCOACostingID],
                        [SCOAProjectID],
                        [PlanProjectItemID],
                        [Quantity]
                    )
                    SELECT @ProcurementPlanID,
                           @ItemDescription,
                           @EstimatedCost,
                           @ScoaFunctionID,
                           @SCOAItemID,
                           @SCOARegionId,
                           @ScoaCostingID,
                           @ScoaProjectID,
                           @PlanProjectItemID,
                           @Quantity;
                    SELECT @ProcurementPlanDetailID = SCOPE_IDENTITY();

                    INSERT INTO SCM_ProcurementPlanDetailsFund
                    (
                        [ProcurementPlanID],
                        [ProcurementPlanDetailID],
                        [SCOAFundID],
                        [PercentageValue]
                    )
                    SELECT @ProcurementPlanID,
                           @ProcurementPlanDetailID,
                           f.ScoaFundID,
                           100
                    FROM Plan_ProjectItem i
                        INNER JOIN Plan_ProjectFundYear fy
                            ON i.ProjectFundYearID = fy.ProjectFundYear_ID
                        INNER JOIN Plan_ProjectFund f
                            ON fy.ProjectFundID = f.ProjectFund_ID
                        INNER JOIN dbo.Const_SCOA_Structure css
                            ON css.ScoaID = i.SCOAItemID
                    WHERE f.ProjectID = @ProjectID
                          AND css.ScoaCode NOT LIKE 'IR%'
                          AND fy.FinYear = @FinancialYear
                          AND i.PlanProjectItem_ID = @PlanProjectItemID;

					SET @countTempID = @countTempID + 1;
                END;

                DROP TABLE #Temp;

            /*CHIRAG -- END */
            END;


            /*--------Create Auto Create Activatation Votes in Ledger--------------*/
            CREATE TABLE #TempVotes
            (
				CountTempVoteID INT IDENTITY(1,1) NOT NULL,
                SCOAItemID INT NULL,
                SCOAItemCode NVARCHAR(500) NULL,
                SCOAItemDescription NVARCHAR(500) NULL,
                VoteStatusId INT NULL,
                FinYear VARCHAR(10) NULL,
                VatIndicatorID INT NULL,
                VoteTypeID INT NULL,
                ControlVote BIT NULL,
                IsBrokenDown BIT NULL,
                CapitalTimePeriodID INT NULL,
                Parent_Vote_ID INT NULL
            );

            INSERT INTO #TempVotes
            SELECT DISTINCT
                   i.SCOAItemID,
                   css.ScoaCode,
                   css.ScoaShortDesc,
                   1,
                   i.FinYear,
                   css.VatIndicatorID,
                   css.VoteTypeID,
                   css.IsControlVote,
                   (CASE
                        WHEN css.BreakDownAllowed = 'Yes' THEN
                            1
                        ELSE
                            0
                    END
                   ) AS BreakDownAllowed,
                   css.CapitalTimePeriodID,
                   css.ScoaParentID
            FROM dbo.Plan_Project pp
                INNER JOIN dbo.[Plan_ProjectItem] i
                    ON i.ProjectID = pp.Project_ID
                INNER JOIN dbo.Const_SCOA_Structure css
                    ON css.ScoaID = i.SCOAItemID
            WHERE pp.Project_ID = @ProjectID
                  AND i.FinYear = @FinancialYear
                  AND i.SCOAItemID NOT IN (
                      (
                          SELECT lv.SCOAItemID
                          FROM dbo.Led_Vote AS lv
                          WHERE lv.FinYear = @FinancialYear
                      )
                                          );
            IF EXISTS (SELECT 1 FROM #TempVotes)
            BEGIN
                --Insert into LED_VOTE    
                INSERT INTO dbo.Led_Vote
                (
                    Vote,
                    VoteDesc,
                    VoteStatusID,
                    FinYear,
                    CapturerID,
                    DateCaptured,
                    VatIndicatorID,
                    VoteTypeID,
                    ControlVote,
                    SCOAItemID,
                    SCOAItemCode,
                    IsBrokenDown,
                    OldVoteNumber,
                    Vote1,
                    OldFms56VoteNumber,
                    CapitalTimePeriodID,
                    Parent_Vote_ID
                )
                SELECT DISTINCT
                       SCOAItemCode,
                       SCOAItemDescription,
                       VoteStatusId,
                       FinYear,
                       1,
                       GETDATE(),
                       VatIndicatorID,
                       VoteTypeID,
                       ControlVote,
                       SCOAItemID,
                       SCOAItemCode,
                       IsBrokenDown,
                       NULL,
                       SCOAItemCode,
                       NULL,
                       CapitalTimePeriodID,
                       NULL
                FROM #TempVotes;

                --Insert into Led_VoteSection    
                INSERT INTO dbo.Led_VoteSection
                (
                    VoteID,
                    VoteSectionID
                )
                SELECT T.Vote_ID,
                       T1.VoteSection_ID
                FROM
                (
                    SELECT lv.Vote_ID
                    FROM dbo.Led_Vote lv
                        INNER JOIN #TempVotes T
                            ON lv.SCOAItemID = T.SCOAItemID
                ) T
                    CROSS APPLY dbo.Const_VoteSection_Sys T1
                EXCEPT
                (SELECT VoteID,
                        VoteSectionID
                 FROM dbo.Led_VoteSection);

                --Insert into Led_Vote_OpeningBalance    
                INSERT INTO dbo.Led_Vote_OpeningBalance
                (
                    VoteID,
                    FinYear,
                    OpeningBalanceAmt,
                    CapturerID,
                    DateCaptured
                )
                SELECT lv.Vote_ID,
                       lv.FinYear,
                       0.00,
                       1,
                       GETDATE()
                FROM dbo.Led_Vote lv
                    INNER JOIN #TempVotes T
                        ON lv.SCOAItemID = T.SCOAItemID
                WHERE lv.Vote_ID NOT IN
                      (
                          SELECT VoteID FROM Led_Vote_OpeningBalance WHERE FinYear = @FinancialYear
                      )
                      AND lv.FinYear = @FinancialYear;
            END;
            DROP TABLE #TempVotes;

            --Insert into Led_GeneralLedger & Position Statement (Led_Project)    

            /*-------Chirag Changes : Led_AutoCreateGLAndPositionStatmentByProject_sp --------------*/

            DECLARE @TransactionType_ID INT,
                    @TransactionDesc NVARCHAR(200) = 'Opening Balance Ledger - Planning',
                    @DocumentTypeID INT,
                    @ExistDocumentNumber NVARCHAR(50);

            INSERT INTO dbo.Led_Project
            (
                FinYear,
                SCOAItemID,
                SCOAFundID,
                SCOARegionID,
                SCOAFunctionID,
                SCOACostingID,
                DivisionID,
                IsActive,
                CapturerID,
                DateCaptured,
                ModifierID,
                DateModified,
                IsDeleted,
                IsImported,
                PositionClassificationID,
                SCOAProjectID,
                Plan_ProjectID
            )
            SELECT DISTINCT
                   @FinancialYear AS FinYear,                                                    -- FinYear - nvarchar(9)    
                   MissingPositionStatemnt.SCOAItemID AS SCOAItemID,                             -- SCOAItemID - int    
                   MissingPositionStatemnt.SCOAFundID AS SCOAFundID,                             -- SCOAFundID - int    
                   MissingPositionStatemnt.SCOARegionID AS SCOARegionID,                         -- SCOARegionID - int    
                   MissingPositionStatemnt.SCOAFunctionID AS SCOAFunctionID,                     -- SCOAFunctionID - int    
                   MissingPositionStatemnt.SCOACostingID AS SCOACostingID,                       -- SCOACostingID - int    
                   MissingPositionStatemnt.DivisionID AS DivisionID,                             -- DivisionID - int    
                   1 AS IsActive,                                                                -- IsActive - bit    
                   1 AS CapturerID,                                                              -- CapturerID - int    
                   GETDATE() AS DateCaptured,                                                    -- DateCaptured - datetime    
                   NULL AS ModifierID,                                                           -- ModifierID - int    
                   NULL AS DateModified,                                                         -- DateModified - datetime    
                   0 AS IsDeleted,                                                               -- IsDeleted - bit    
                   0 AS IsImported,                                                              -- IsImported - bit    
                   MissingPositionStatemnt.PositionClassificationID AS PositionClassificationID, -- PositionClassificationID - int    
                   MissingPositionStatemnt.SCOAProjectID AS SCOAProjectID,                       -- SCOAProjectID - int    
                   MissingPositionStatemnt.Plan_ProjectID
            FROM
            (
                SELECT PPI.SCOAItemID AS SCOAItemID,                                 -- SCOAItemID - int    
                       PPI.SCOAFundId AS SCOAFundID,                                 -- SCOAFundID - int    
                       PPI.SCOARegionId AS SCOARegionID,                             -- SCOARegionID - int    
                       PPI.SCOAFunctionId AS SCOAFunctionID,                         -- SCOAFunctionID - int    
                       PPI.SCOACostingID AS SCOACostingID,                           -- SCOACostingID - int    
                       PPI.DivisionId AS DivisionID,                                 -- DivisionID - int    
                       CSSPositionClassification.ScoaID AS PositionClassificationID, -- PositionClassificationID - int    
                       PP.ScoaProjectID AS SCOAProjectID,                            -- SCOAProjectID - int    
                       PP.Project_ID AS Plan_ProjectID
                FROM Plan_Project AS PP
                    INNER JOIN dbo.Plan_ProjectItem AS PPI
                        ON PPI.ProjectID = PP.Project_ID
                    INNER JOIN Led_Vote AS LV
                        ON LV.SCOAItemID = PPI.SCOAItemID
                           AND LV.FinYear = PPI.FinYear
                    INNER JOIN Const_SCOA_Structure AS CSS
                        ON CSS.ScoaID = PPI.SCOAItemID
                    INNER JOIN Led_ProjectItem AS LPI
                        ON SUBSTRING(LPI.ScoaCode, 1, 2) = SUBSTRING(CSS.ScoaCode, 1, 2)
                    INNER JOIN Const_SCOA_Structure AS CSSPositionClassification
                        ON LPI.ScoaCode = CSSPositionClassification.ScoaCode
                    INNER JOIN Const_VoteType AS CVT
                        ON CVT.VoteType_ID = LV.VoteTypeID
                WHERE PP.FinYear = @FinancialYear
                      AND PPI.FinYear = @FinancialYear
                      AND PP.ProjectStatus = 24
                      AND
                      (
                          PPI.ProjectID = @ProjectID
                          OR @ProjectID = 0
                      )
                      AND ISNULL(PP.IsDeleted, 0) = 0
                      AND CVT.VoteType = 'Balance Sheet'
                      AND (ISNULL(PPI.BudgetAmount, 0) + ISNULL(PPI.BudgetAmountCurP1, 0)
                           + ISNULL(PPI.BudgetAmountCurP2, 0)
                          ) <> 0
                EXCEPT
                SELECT SCOAItemID,
                       SCOAFundID,
                       SCOARegionID,
                       SCOAFunctionID,
                       SCOACostingID,
                       DivisionID,
                       PositionClassificationID,
                       SCOAProjectID,
                       Plan_ProjectID
                FROM Led_Project
                WHERE FinYear = @FinancialYear
                      AND IsActive = 1
                      AND IsDeleted = 0
            ) AS MissingPositionStatemnt;





            /*--------End of Create Auto Create Activatation Votes in Ledger--------------*/

			SET @countProjectFinalID = @countProjectFinalID + 1;
        END;




        /*================= Chirag END =======================*/

        UPDATE dbo.Plan_AdjustmentProject
        SET ProjectStatus = 24
        WHERE AdjustmentVersionId = @AdjustmentVersionId
              AND ProjectStatus IN ( 23, 6 );

        COMMIT TRANSACTION AdjustmentsTran;
        SET @ErrorResult = N'Success';
        GOTO AllGood;

    END TRY
    BEGIN CATCH
		ROLLBACK TRANSACTION AdjustmentsTran;
        SET @ErrorResult = ERROR_MESSAGE();

        INSERT INTO Sys_ErrorLog
        (
            moduleName,
            pageName,
            procedureName,
            errorMessage,
            errorType,
            detailedErrorMessage,
            errorDate,
            userName
        )
        VALUES
        ('Planning', 'SQL Server', 'Plan_SubmitAdjustmentBudget_sp', ERROR_MESSAGE(), 'SQL', ERROR_MESSAGE(),
         GETDATE(), 'SQL');

        RAISERROR(@ErrorResult, 16, 1);
        
        GOTO AllGood;

    END CATCH;

    AllGood:
    IF @AdjustmentBudgetApprovalId IS NULL
        SET @AdjustmentBudgetApprovalId = 0;

    SELECT ISNULL(@AdjustmentBudgetApprovalId, 0) AS AdjustmentBudgetApprovalId,
           @ErrorResult AS Result;  
END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_SubmitAdjustmentBudgetPolicy_sp]    Script Date: 2026/03/10 7:23:47 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Nirav Parikh
-- Create date: 2017-11-24
-- Description:	Create Adjustment Budget Policy
-- EXEC [Plan_SubmitAdjustmentBudgetPolicy_sp] '2016/2017', 4779, '06062017095920CR_Budget_String_08052017.docx'
-- DO NOT APPLY REDGATE SQL FORMATE
-- SNagpal 09-Jan-2018 : Fix Inserting of Plan_AdjustmentProjectItem Issue
-- RChetty 31-Jan-2018 : Fix missing [Plan_AdjustmentFundingSourceDocs] insert TP 67124
-- SNagpal 18-Feb-2018 : Fix Decimal issues
-- SNagpal 28-Mar-2018 : Exclude Items having AND (ISNULL(BudgetAmount,0) + ISNULL(BudgetAmountCurP1,0) + ISNULL(BudgetAmountCurP2,0) ) = 0
-- SNagpal 05-June-2018 : Add two columns for Plan_AdjustmentFundingSourceDocs : RefFundingSourceDocsID, AdjustmentFundingVersionId
-- SNagpal 05-June-2018 : Fix issue of saving Plan_ProjectItemDocs. Issue in Joins
-- SNagpal 23-Oct-2018 : 79279 Add INNER JOIN dbo.Plan_ProjectItem ppi ON  ppi.ProjectID = p.Project_ID to get projects having some of budget amount greater than 0
-- SNagpal 25-Oct-2018 : 81185 QA - Project names are duplicated
-- SNagpal 14-Nov-2018 : 81825 Add logic to save correct SupportDocsGroupId
-- SNagpal 24-Jan-2019 : #61596 - #83633 - Add functionality to Copy ProjectCode
-- SNagpal 25-Apr-2019 : #86104 Include Items having (ISNULL(PPI.BudgetAmount,0) + ISNULL(PPI.BudgetAmountCurP1,0) + ISNULL(PPI.BudgetAmountCurP2,0) ) = 0 with ORGB <> 0
-- SNagpal 26-Apr-2019 :  #87831, Add condition while copying data to Plan_FundingSourceBudget_Detail, Must Only copy data for CurrentFinyear
-- SNagpal 20-May-2019 : 88917 Add code to disable FK before insert
-- SN 18-Feb-2023: 58285 Add IsActiveForSCM flag
-- CMoodley 11-Jan-2024: 83764 All zero budget items included in ADJB
-- =============================================
CREATE PROCEDURE [dbo].[Plan_SubmitAdjustmentBudgetPolicy_sp]
    @FinYear NVARCHAR(9), 
	@UserId INT, 
	@ApprovedAdjustmentBudgetPolicyFileName NVARCHAR(500)
AS
BEGIN
BEGIN TRY
    BEGIN TRANSACTION

		--=================Disable FK relations

		IF OBJECT_ID('FK_Plan_AdjustmentProjectFunctions_Const_SCOA_Function_Structure') IS NOT NULL
		BEGIN
			ALTER TABLE Plan_AdjustmentProjectFunctions 
			NOCHECK CONSTRAINT FK_Plan_AdjustmentProjectFunctions_Const_SCOA_Function_Structure; 
		END

		IF OBJECT_ID('FK_Plan_AdjustmentProjectFund_Const_SCOA_Funds_Structure') IS NOT NULL
		BEGIN
			ALTER TABLE  Plan_AdjustmentProjectFund
			NOCHECK CONSTRAINT FK_Plan_AdjustmentProjectFund_Const_SCOA_Funds_Structure
		END

		IF OBJECT_ID('FK_Plan_AdjustmentProjectRegions_Const_SCOA_Regional_Structure') IS NOT NULL
		BEGIN
			ALTER TABLE  Plan_AdjustmentProjectRegions
			NOCHECK CONSTRAINT FK_Plan_AdjustmentProjectRegions_Const_SCOA_Regional_Structure
		END


		--Declare Variables
		DECLARE @FinYearP1 NVARCHAR(9), @FinYearP2 NVARCHAR(9), @yearp1 INT, @yearp2 INT, @yearp3 INT

		--Set Variables
        SELECT @yearp1 = CAST(SUBSTRING(@FinYear, 6, 4) AS INT)
        SELECT @yearp2 = @yearp1 + 1
        SELECT @yearp3 = @yearp1 + 2
        SELECT @FinYearP1 = CONVERT(VARCHAR(4), @yearp1) + '/' + CONVERT(VARCHAR(4), @yearp2)
        SELECT @FinYearP2 = CONVERT(VARCHAR(4), @yearp2) + '/' + CONVERT(VARCHAR(4), @yearp3)

		--Declare Variables
		DECLARE @BudgetVerionID INT, @Comments NVARCHAR(1000), @NewAdjustmentBudgetVersionNumber NVARCHAR(50), @NewAdjustmentFundingBudgetVersionNumber NVARCHAR(50),
		 @AdjustmentBudgetVersionId INT, @AdjustmentFundingBudgetVersionId INT, @ErrorResult NVARCHAR(MAX) = '', @AdjustmentBudgetPolicyApprovalId INT = 0, @SupportDocsGrpId INT;
		
			SELECT TOP 1 @BudgetVerionID = BudgetVersion_ID FROM dbo.Plan_BudgetVersion pbv
		INNER JOIN dbo.Plan_BudgetVersionDetail pbvd ON pbvd.BudgetVersionID = pbv.BudgetVersion_ID
		WHERE VersionName LIKE '%ORGB%' AND pbvd.FinYear=@FinYear ORDER BY pbv.DateCaptured DESC

		--Set Variables
		SET @Comments = 'Adjustment Budget approved by Council in accordance with legislative requirements'
		SELECT @SupportDocsGrpId = SupportingDocsGroup_ID FROM Const_SupportingDocsGroup WHERE GroupDesc LIKE 'Adjustment Funding Documents'

		--Declare Table
		DECLARE @tblVersionNumber TABLE
		( NewVersionNumber NVARCHAR(50), FinYear NVARCHAR(20) )

		--Execute SP and Insert Output in Declared Table
		INSERT INTO @tblVersionNumber
		( NewVersionNumber, FinYear )
		EXEC Plan_GetLatestAdjustmentBudgetVersionNumber_sp @FinYear

		--Set Value from SP Output
		SELECT @NewAdjustmentBudgetVersionNumber = NewVersionNumber FROM @tblVersionNumber

		--Delete Data from Declared Table
		DELETE FROM @tblVersionNumber

		--Execute SP and Insert Output in Declared Table
		INSERT INTO @tblVersionNumber
		( NewVersionNumber, FinYear )
		EXEC dbo.Plan_GetLatestAdjustmentFundingBudgetVersionNumber_sp @FinYear

		--Set Value from SP Output
		SELECT @NewAdjustmentFundingBudgetVersionNumber = NewVersionNumber FROM @tblVersionNumber

		--Insert Data into Plan_AdjustmentBudgetVersion
		INSERT INTO Plan_AdjustmentBudgetVersion
			( VersionNumber, VersionName, Comments, CapturerID, DateCaptured )
		VALUES
			( @NewAdjustmentBudgetVersionNumber, @NewAdjustmentBudgetVersionNumber, @Comments, @UserId, GETDATE() )

		--Get Inserted ID and Set Value
		SELECT @AdjustmentBudgetVersionId = SCOPE_IDENTITY()
		
		--Insert Data into Plan_AdjustmentBudgetVersionDetail
		INSERT INTO Plan_AdjustmentBudgetVersionDetail
		(
			AdjustmentBudgetVersionID,
			ProjectID,
			FinYear,
			IDPItemID,
			CapitalOperation,
			ScoaProjectID,
			SCOACostingID,
			ProjectTypeID,
			PlanProjectItemID,
			ProjectItemID,
			SCOAItemID,
			SCOAFundId,
			BudgetAmount,
			BudgetAmountCurP1,
			BudgetAmountCurP2,
			SCOAFunctionId,
			SCOARegionId,
			DivisionId,
			BudgetSplitID,
			VirementId,
			AdjustmentId,
			ModificationNumber,
			IsItemLocked,
			CreditDebit,
			AdjutmentType,
			LegislativeReasonAdjustment,
			ReasonForAdjustment,
			CapturerID,
			DateCaptured,
			GRAPClassification, 
			GRAPClassificationNote, 
			MainSegmentReporting, 
			SubSegmentReporting,
			CostingProject
		)     
        SELECT @AdjustmentBudgetVersionId,
                PP.Project_ID,
                PP.FinYear,
                0,
                ISNULL(PP.CapitalOperation, 0),
                ISNULL(PP.ScoaProjectID, 0),
                ISNULL(PPI.SCOACostingID, 0),
                ISNULL(PP.ProjectTypeID, 0),
                ISNULL(PPI.PlanProjectItem_ID, 0),
                ISNULL(PPI.ProjectItemID, 0),
                ISNULL(PPI.SCOAItemID, 0),
                ISNULL(PPI.SCOAFundId, 0),
                ISNULL(PPI.BudgetAmount, 0),
                ISNULL(PPI.BudgetAmountCurP1, 0),
                ISNULL(PPI.BudgetAmountCurP2, 0),
                ISNULL(PPI.SCOAFunctionId, 0),
                ISNULL(PPI.SCOARegionId, 0),
                ISNULL(PPI.DivisionId, 0),
				ISNULL(PPI.BudgetSplitID, 0),
				ISNULL(PPI.VirementId, 0),
				ISNULL(PPI.AdjustmentId, 0),
				ISNULL(PPI.ModificationNumber, 0),
				ISNULL(PPI.IsItemLocked, 0),
				ISNULL(PPI.CreditDebit, ''),
				NULL,
				NULL,
				NULL,
                @UserId,
                GETDATE(),
				GRAPClassification, 
				GRAPClassificationNote, 
				MainSegmentReporting, 
				SubSegmentReporting,
				CostingProject
        FROM Plan_Project AS PP (NOLOCK)
			INNER JOIN Plan_ProjectItem AS PPI (NOLOCK) ON PP.Project_ID = PPI.ProjectID
        WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0

		--Insert Data into Plan_AdjustmentBudgetVersionMonths
        INSERT INTO Plan_AdjustmentBudgetVersionMonths
        (
            AdjustmentBudgetVersionID,
            AdjustmentProjectItemMonth_ID,
            PlanAdjustmentProjectItemID,
            MonthID,
            UnitQuantity,
            UnitPrice,
            CaptureID,
            DateCaptured,
            VirementId,
            AdjustmentId
        )
        SELECT @AdjustmentBudgetVersionId,
                ppim.ProjectItemMonth_ID,
                ppim.PlanProjectItemID,
                ppim.MonthID,
                ppim.UnitQuantity,
                ppim.UnitPrice,
                @UserId,
                GETDATE(),
                ppim.VirementId,
                ppim.AdjustmentId
        FROM Plan_Project AS PP (NOLOCK) 
			INNER JOIN Plan_ProjectItem AS PPI (NOLOCK) ON PP.Project_ID = PPI.ProjectID
            INNER JOIN Plan_ProjectItemMonth ppim (NOLOCK) ON ppim.PlanProjectItemID = PPI.PlanProjectItem_ID
        WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0
		
		--Insert Data into Plan_AdjustmentFundingBudgetVersion
		INSERT INTO Plan_AdjustmentFundingBudgetVersion
            ( VersionNumber, VersionName, Comments, CapturerID, DateCaptured )
        VALUES
            (@NewAdjustmentFundingBudgetVersionNumber, @NewAdjustmentFundingBudgetVersionNumber, @Comments, @UserId, GETDATE())

		--Get Inserted ID and Set Value
		SELECT @AdjustmentFundingBudgetVersionId = SCOPE_IDENTITY()

		--Insert Data into Plan_AdjustmentFundingBudgetVersionDetails
		INSERT INTO Plan_AdjustmentFundingBudgetVersionDetails
		(
		    AdjustmentFundingBudgetVersionId,
		    AdjustmentFundingSourceBudgetDetail_ID,
		    AdjustmentFundingSourceBudgetHeaderID,
		    FinancialYear,
		    FundingSourceID,
		    ScoaID,
		    FundingSourceBudget,
		    DateCaptured,
		    CapturerID,
		    UploadedDocument
		)
        SELECT @AdjustmentFundingBudgetVersionId,
                FundingSourceBudgetDetail_ID,
                FundingSourceBudgetHeaderID,
                pfsbh.FinancialYear,
                FundingSourceID,
                ScoaID,
                FundingSourceBudget,
                GETDATE(),
                @UserId,
                UploadedDocument
        FROM Plan_FundingSourceBudget_Header pfsbh (NOLOCK) 
            INNER JOIN Plan_FundingSourceBudget_Detail pfsb (NOLOCK) ON pfsb.FundingSourceBudgetHeaderID = pfsbh.FundingSourceBudgetHeader_ID
        WHERE pfsbh.FinancialYear IN ( @FinYear, @FinYearP1, @FinYearP2 )
		AND pfsb.ScoaID IN (SELECT pf.ScoaID FROM Plan_FundingSourceBudget_Detail pf 
							INNER JOIN Plan_FundingSourceBudget_Header pfh ON pfh.FundingSourceBudgetHeader_ID = pf.FundingSourceBudgetHeaderID 
							WHERE pfh.FinancialYear = @FinYear)

		--Insert Data into Plan_AdjustmentBudgetPolicyApproval
		INSERT INTO Plan_AdjustmentBudgetPolicyApproval
			( FinancialYear, IsApprovedAdjustmentBudgetPolicy, ApprovedAdjustmentBudgetPolicyFileName, ApprovedBy, ApprovedDate, DateCaptured, CapturerID, AdjustmentVersionId, AdjustmentFundingVersionId, IsAdjustmentFinalApproved )
		VALUES
			( @FinYear, 1, @ApprovedAdjustmentBudgetPolicyFileName, @UserId, GETDATE(), GETDATE(), @UserId, @AdjustmentBudgetVersionId, @AdjustmentFundingBudgetVersionId, 0 )

		--Get Inserted ID and Set Value
		SELECT @AdjustmentBudgetPolicyApprovalId = SCOPE_IDENTITY()

		--Insert Data into Plan_AdjustmentFundingSourceBudget_Header
		INSERT INTO Plan_AdjustmentFundingSourceBudget_Header
		(
		    FinancialYear,
		    Submitted,
		    DateCaptured,
		    CapturerID,
		    RefFundingSourceHeaderId,
		    AdjustmentFundingVersionId
		)
		SELECT 
			FinancialYear,
		    Submitted,
		    GETDATE(),
		    @UserId,
		    FundingSourceBudgetHeader_ID,
		    @AdjustmentFundingBudgetVersionId
		FROM Plan_FundingSourceBudget_Header (NOLOCK) 
		WHERE FinancialYear IN ( @FinYear, @FinYearP1, @FinYearP2 )

		--Insert Data into Plan_AdjustmentFundingSourceBudget_Detail
		INSERT INTO Plan_AdjustmentFundingSourceBudget_Detail
		(
		    AdjustmentFundingSourceBudgetHeaderID,
		    AdjustmentFundingSourceID,
		    ScoaID,
		    FundingSourceBudget,
		    DateCaptured,
		    CapturerID,
		    IsHidden,
		    UploadedDocument,
		    RefFundingSourceDetailId,
		    AdjustmentFundingVersionId
		)
		SELECT 
			pafsbh.AdjustmentFundingSourceBudgetHeader_ID,
		    CASE WHEN pfsb.FundingSourceID = 0 THEN NULL ELSE pfsb.FundingSourceID END,
		    pfsb.ScoaID,
		    pfsb.FundingSourceBudget,
		    GETDATE(),
		    @UserId,
		    pfsb.IsHidden,
		    pfsb.UploadedDocument,
		    pfsb.FundingSourceBudgetDetail_ID,
		    @AdjustmentFundingBudgetVersionId
		FROM  Plan_FundingSourceBudget_Header pfsbh (NOLOCK) 
            INNER JOIN Plan_FundingSourceBudget_Detail pfsb (NOLOCK) ON pfsb.FundingSourceBudgetHeaderID = pfsbh.FundingSourceBudgetHeader_ID
			INNER JOIN Plan_AdjustmentFundingSourceBudget_Header pafsbh (NOLOCK) ON pafsbh.RefFundingSourceHeaderId = pfsbh.FundingSourceBudgetHeader_ID
        WHERE pfsbh.FinancialYear IN ( @FinYear, @FinYearP1, @FinYearP2 ) AND pafsbh.AdjustmentFundingVersionId=@AdjustmentFundingBudgetVersionId
		AND pfsb.ScoaID IN (SELECT pf.ScoaID FROM Plan_FundingSourceBudget_Detail pf 
							INNER JOIN Plan_FundingSourceBudget_Header pfh ON pfh.FundingSourceBudgetHeader_ID = pf.FundingSourceBudgetHeaderID 
							WHERE pfh.FinancialYear = @FinYear)

		--Insert Data into Sys_SupportingDocs
		INSERT INTO Sys_SupportingDocs
		SELECT ssd.Filename
			,'Copied Funding Document'
			,ssd.DocumentAuthor
			,ssd.DocumentDate,10,@SupportDocsGrpId
			,'Plan_AdjustmentFundingSourceBudget_Detail'
			,pafsbd.AdjustmentFundingSourceBudgetDetail_ID
			,ssd.DateImported
			,ssd.ImportedByID
			,GETDATE()
		    ,@UserId
			,NULL
			,NULL
		FROM  Plan_AdjustmentFundingSourceBudget_Detail pafsbd (NOLOCK) 
            INNER JOIN Plan_FundingSourceDocs pfsd (NOLOCK) ON pfsd.FundingSourceBudgetDetailID = pafsbd.RefFundingSourceDetailId
			INNER JOIN Sys_SupportingDocs ssd (NOLOCK) ON ssd.SupportingDocs_ID=pfsd.SupportingDocsID
		WHERE pafsbd.AdjustmentFundingVersionId=@AdjustmentFundingBudgetVersionId

		--Insert Data into Plan_AdjustmentFundingSourceDocs

		INSERT INTO Plan_AdjustmentFundingSourceDocs
		(
		    SupportingDocsID,
		    AdjustmentFundingSourceBudgetDetailID,
		    ScoaID,
		    DateCaptured,
		    CapturerID,
			RefFundingSourceDocsID,
			AdjustmentFundingVersionId
		)
		SELECT 
			ssd.SupportingDocs_ID,
			pafsbd.AdjustmentFundingSourceBudgetDetail_ID,
		    pafsbd.ScoaID,
		    GETDATE(),
		    @UserId,
			pfsd.FundingSourceDocs_ID,
			@AdjustmentFundingBudgetVersionId
		FROM  Plan_AdjustmentFundingSourceBudget_Detail pafsbd (NOLOCK) 
            INNER JOIN Sys_SupportingDocs ssd (NOLOCK) ON ssd.TableLinkedID = pafsbd.AdjustmentFundingSourceBudgetDetail_ID 
			INNER JOIN Plan_FundingSourceDocs pfsd (NOLOCK) ON pfsd.FundingSourceBudgetDetailID = pafsbd.RefFundingSourceDetailId
		WHERE ssd.TableLinkedName ='Plan_AdjustmentFundingSourceBudget_Detail' AND pafsbd.AdjustmentFundingVersionId=@AdjustmentFundingBudgetVersionId
		
		DECLARE @tblPlanProject TABLE 		
		(
			Project_ID INT, AdjustmentProjectName NVARCHAR(500), AdjustmentProjectDesc NVARCHAR(500), ProjectManagerID INT, SupplyChainOfficialID INT, CapitalOperation INT, CostEstimate DECIMAL, ScoaProjectID INT,EstimatedStartDate DATETIME, EstimatedEndDate DATETIME,
			ProjectStatus INT, CommencementDate DATETIME, FinYear NVARCHAR(9), ProjectDetailDesc NVARCHAR(500), ProjectCategoryID INT, ProjectImplementAgentID INT, Longitude NVARCHAR(200), Latitude NVARCHAR(200), ProgrammeManagerID INT, FinancialControllerID INT,
			ProjectTypeID INT, EstimatedDuration INT, ProjectDistinctionID INT, IsDeleted BIT, HistoricalProjectCode NVARCHAR(100), ProjectParentID INT, SingleMultiYear VARCHAR(5), CapturerID INT,DateCaptured DATETIME, AdjustmentVersionId INT, ProjectCode INT, CostingProject BIT
		)
		
		DECLARE @tblProjectFund TABLE
		(
			ProjectFund_ID INT, AdjustmentProjectID INT, ScoaFundID INT, FundAmount DECIMAL(16,2), FundReference NVARCHAR(200), VirementId INT, AdjustmentId INT, CapturerID INT, DateCaptured DATETIME, AdjustmentVersionId INT
		)

		DECLARE @ProjectItem TABLE
		(
		   ProjectItem_ID INT, AdjustmentProjectID INT, ProjectItemID INT, SCOAItemID INT, FinYear NVARCHAR(9), ProjectFundYearID INT, SCOAFundId INT, BudgetAmount DECIMAL(16,2), BudgetAmountCurP1 DECIMAL(16,2), BudgetAmountCurP2 DECIMAL(16,2), SCOAFunctionId INT,
		   SCOARegionId INT, DivisionId INT, BudgetSplitID INT, VirementId INT, HistoricalProjectCode NVARCHAR(100), AdjustmentId INT, ModificationNumber INT, SCOACostingID INT, IsItemLocked BIT, CreditDebit VARCHAR(6), AdjutmentType INT, LegislativeReasonAdjustment INT,
		   ReasonForAdjustment NVARCHAR(MAX), CapturerID INT, DateCaptured DATETIME, AdjustmentVersionId INT, IsActiveForSCM BIT, GRAPClassification NVARCHAR(4000), GRAPClassificationNote NVARCHAR(4000), MainSegmentReporting NVARCHAR(4000), SubSegmentReporting NVARCHAR(4000)
		)

		DECLARE @Project_ID INT = 0, @AdjustmentProject_ID INT, @ProjectFund_ID INT, @AdjustmentProjectFund_ID INT, @ProjectItem_ID INT, @AdjustmentProjectItem_ID INT;

		INSERT INTO @tblPlanProject
		    ( Project_ID, AdjustmentProjectName, AdjustmentProjectDesc, ProjectManagerID, SupplyChainOfficialID, CapitalOperation, CostEstimate, ScoaProjectID, EstimatedStartDate, EstimatedEndDate, ProjectStatus, CommencementDate,
		        FinYear, ProjectDetailDesc, ProjectCategoryID, ProjectImplementAgentID, Longitude, Latitude, ProgrammeManagerID, FinancialControllerID, ProjectTypeID, EstimatedDuration, ProjectDistinctionID, IsDeleted,
		        HistoricalProjectCode, ProjectParentID, SingleMultiYear, CapturerID, DateCaptured, AdjustmentVersionId, ProjectCode, CostingProject
		    )
		SELECT DISTINCT
			Project_ID, ProjectName, ProjectDesc, ProjectManagerID, SupplyChainOfficialID, CapitalOperation, CostEstimate, ScoaProjectID, EstimatedStartDate, EstimatedEndDate, 23, CommencementDate,
			p.FinYear, ProjectDetailDesc, ProjectCategoryID, ProjectImplementAgentID, Longitude, Latitude, ProgrammeManagerID, FinancialControllerID, ProjectTypeID, EstimatedDuration, ProjectDistinctionID, IsDeleted,
		    p.HistoricalProjectCode, ProjectParentID, SingleMultiYear, @UserId, GETDATE(), @AdjustmentBudgetVersionId, ProjectCode, CostingProject
		FROM Plan_Project p (NOLOCK) 
		INNER JOIN dbo.Plan_ProjectItem ppi ON  ppi.ProjectID = p.Project_ID
		WHERE p.FinYear = @FinYear AND ISNULL(IsDeleted, 0) = 0 
		
		WHILE EXISTS (SELECT 1 FROM @tblPlanProject)
			BEGIN 
			
				SELECT TOP 1 
					@Project_ID = TPAP.Project_ID
					 FROM @tblPlanProject AS TPAP
				 
				INSERT INTO Plan_AdjustmentProject
				(
					ReferenceProject_ID, AdjustmentProjectName, AdjustmentProjectDesc, ProjectManagerID, SupplyChainOfficialID, CapitalOperation, CostEstimate, ScoaProjectID, EstimatedStartDate, EstimatedEndDate, ProjectStatus, CommencementDate,
					FinYear, ProjectDetailDesc, ProjectCategoryID, ProjectImplementAgentID, Longitude, Latitude, ProgrammeManagerID, FinancialControllerID, ProjectTypeID, EstimatedDuration, ProjectDistinctionID, IsDeleted, HistoricalProjectCode,
					ProjectParentID, SingleMultiYear, CapturerID, DateCaptured, AdjustmentVersionId, ProjectCode, CostingProject
				)
				SELECT 
					Project_ID, AdjustmentProjectName, AdjustmentProjectDesc, ProjectManagerID, SupplyChainOfficialID, CapitalOperation, CostEstimate, ScoaProjectID, EstimatedStartDate, EstimatedEndDate, ProjectStatus, CommencementDate,
					FinYear, ProjectDetailDesc, ProjectCategoryID, ProjectImplementAgentID, Longitude, Latitude, ProgrammeManagerID, FinancialControllerID, ProjectTypeID, EstimatedDuration, ProjectDistinctionID, IsDeleted, HistoricalProjectCode,
					ProjectParentID, SingleMultiYear, CapturerID, DateCaptured, AdjustmentVersionId,ProjectCode, CostingProject
				FROM @tblPlanProject AS PAP
				 WHERE PAP.Project_ID= @Project_ID

				SET @AdjustmentProject_ID = SCOPE_IDENTITY()

		 	--Insert Data into Plan_AdjustmentProjectCosting
			INSERT INTO Plan_AdjustmentProjectCosting
			(
			    ReferenceProjectCostingID, AdjustmentProjectID, ScoaCostingID, CapturerID, DateCaptured, AdjustmentVersionId
			)
			SELECT 
				PPC.ProjectCosting_ID, @AdjustmentProject_ID, PPC.ScoaCostingID, @UserId, GETDATE(), @AdjustmentBudgetVersionId
			FROM Plan_Project PP (NOLOCK) 
				INNER JOIN Plan_ProjectCosting PPC (NOLOCK) ON PPC.ProjectID = PP.Project_ID
				WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PP.Project_ID = @Project_ID

			--Insert Data into Plan_AdjustmentProjectDivisions
			INSERT INTO Plan_AdjustmentProjectDivisions
			(
				ReferenceProjectDivisionID, AdjustmentProjectID, DivisionID, CapturerID, DateCaptured, AdjustmentVersionId
			)
			SELECT
				PPD.ProjectDivision_ID, @AdjustmentProject_ID, PPD.DivisionID, @UserId, GETDATE(), @AdjustmentBudgetVersionId
			FROM Plan_Project PP (NOLOCK) 
				INNER JOIN Plan_ProjectDivisions PPD (NOLOCK) ON PPD.ProjectID = PP.Project_ID
				WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PP.Project_ID=@Project_ID

			--Insert Data into Plan_AdjustmentProjectFunctions
			INSERT INTO Plan_AdjustmentProjectFunctions
			(
			    ReferenceProjectFunctionID, AdjustmentProjectID, ScoaFunctionID, CapturerID, DateCaptured, AdjustmentVersionId
			)
			SELECT
				PPF.ProjectFunction_ID, @AdjustmentProject_ID, PPF.ScoaFunctionID, @UserId, GETDATE(), @AdjustmentBudgetVersionId
			FROM Plan_Project PP (NOLOCK) 
				INNER JOIN Plan_ProjectFunctions PPF (NOLOCK) ON PPF.ProjectID = PP.Project_ID
				WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PP.Project_ID=@Project_ID
	
			--Insert Data into Plan_AdjustmentProjectIDP
			INSERT INTO Plan_AdjustmentProjectIDP
			(
			    ReferenceProjectIDPID, AdjustmentProjectID, ParentIDPItemID, AdjustmentProjectIDPItemID, Percentage, CapturerID, DateCaptured, Latitude, Longitude, AdjustmentVersionId
			)
			SELECT
				PPIDP.ProjectIDP_ID, @AdjustmentProject_ID, PPIDP.ParentIDPItemID, PPIDP.ProjectIDPItemID, PPIDP.Percentage, @UserId, GETDATE(), PPIDP.Latitude, PPIDP.Longitude, @AdjustmentBudgetVersionId
			FROM Plan_Project PP (NOLOCK) 
			INNER JOIN Plan_ProjectIDP PPIDP (NOLOCK) ON PPIDP.ProjectID = PP.Project_ID
				WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PP.Project_ID=@Project_ID

			--Insert Data into Plan_AdjustmentProjectRegions
			INSERT INTO Plan_AdjustmentProjectRegions
			(
			    ReferenceProjectRegionID, AdjustmentProjectID, ScoaRegionID, RegionPercent, CapturerID, DateCaptured, AdjustmentVersionId
			)
			SELECT
				PPR.ProjectRegion_ID, @AdjustmentProject_ID, PPR.ScoaRegionID, PPR.RegionPercent, @UserId, GETDATE(), @AdjustmentBudgetVersionId
			FROM Plan_Project PP (NOLOCK) 
				INNER JOIN Plan_ProjectRegions PPR (NOLOCK) ON PPR.ProjectID = PP.Project_ID
				WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PP.Project_ID=@Project_ID

			--Insert Data into Plan_AdjustmentProjectFund
			INSERT INTO @tblProjectFund
			    ( 
					ProjectFund_ID, AdjustmentProjectID, ScoaFundID, FundAmount, FundReference, VirementId, AdjustmentId, CapturerID, DateCaptured, AdjustmentVersionId
			    )
			SELECT
				PPF.ProjectFund_ID, @AdjustmentProject_ID, PPF.ScoaFundID, PPF.FundAmount, PPF.FundReference, PPF.VirementId, PPF.AdjustmentId, @UserId, GETDATE(), @AdjustmentBudgetVersionId
			FROM Plan_Project PP (NOLOCK) 
				INNER JOIN Plan_ProjectFund PPF (NOLOCK) ON PPF.ProjectID = PP.Project_ID
				WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PP.Project_ID = @Project_ID

			WHILE EXISTS (SELECT 1 FROM @tblProjectFund)
			BEGIN
				SELECT TOP 1 
					@ProjectFund_ID = TPAP.ProjectFund_ID
				FROM @tblProjectFund AS TPAP

				INSERT INTO dbo.Plan_AdjustmentProjectFund
					(
					ReferenceProjectFundID, AdjustmentProjectID, ScoaFundID, FundAmount, FundReference, VirementId, AdjustmentId, CapturerID, DateCaptured, AdjustmentVersionId
					)
				SELECT 
					ProjectFund_ID, AdjustmentProjectID, ScoaFundID, FundAmount, FundReference, VirementId, AdjustmentId, CapturerID, DateCaptured, AdjustmentVersionId
				FROM @tblProjectFund WHERE ProjectFund_ID = @ProjectFund_ID

				SET @AdjustmentProjectFund_ID = SCOPE_IDENTITY()
									 
				--Insert Data into Plan_AdjustmentProjectFundYear
				INSERT INTO Plan_AdjustmentProjectFundYear
					(
						ReferenceProjectFundYearID, AdjustmentProjectFundID, FinYear, YearFundAmount, VirementId, AdjustmentId, CapturerID, DateCaptured, AdjustmentVersionId
					)
				SELECT
					PPFY.ProjectFundYear_ID, @AdjustmentProjectFund_ID, PPFY.FinYear, PPFY.YearFundAmount, PPFY.VirementId, PPFY.AdjustmentId, @UserId, GETDATE(), @AdjustmentBudgetVersionId
				FROM Plan_ProjectFundYear PPFY (NOLOCK) 
				INNER JOIN dbo.Plan_ProjectFund PPF (NOLOCK) ON PPF.ProjectFund_ID = PPFY.ProjectFundID
				INNER JOIN Plan_Project PP (NOLOCK) ON PPF.ProjectID = PP.Project_ID
					WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PPFY.ProjectFundID = @ProjectFund_ID

					DELETE FROM @tblProjectFund WHERE ProjectFund_ID = @ProjectFund_ID
			END
			
			--Insert Data into @ProjectItem
			INSERT INTO @ProjectItem
				( ProjectItem_ID, AdjustmentProjectID, ProjectItemID, SCOAItemID, FinYear, ProjectFundYearID, SCOAFundId, BudgetAmount, BudgetAmountCurP1, BudgetAmountCurP2, SCOAFunctionId, SCOARegionId, DivisionId, BudgetSplitID, VirementId, HistoricalProjectCode, AdjustmentId, ModificationNumber, SCOACostingID, IsItemLocked, CreditDebit, AdjutmentType, LegislativeReasonAdjustment, 
							ReasonForAdjustment, CapturerID, DateCaptured, AdjustmentVersionId, IsActiveForSCM, GRAPClassification, GRAPClassificationNote, MainSegmentReporting, SubSegmentReporting
				)	
			SELECT
				PPI.PlanProjectItem_ID, @AdjustmentProject_ID, PPI.ProjectItemID, PPI.SCOAItemID, PPI.FinYear, PPI.ProjectFundYearID, PPI.SCOAFundId, PPI.BudgetAmount, PPI.BudgetAmountCurP1, PPI.BudgetAmountCurP2, PPI.SCOAFunctionId, PPI.SCOARegionId,
						PPI.DivisionId, PPI.BudgetSplitID, PPI.VirementId, PPI.HistoricalProjectCode, PPI.AdjustmentId, PPI.ModificationNumber, PPI.SCOACostingID, PPI.IsItemLocked, PPI.CreditDebit, NULL, NULL, NULL, @UserId, GETDATE(), @AdjustmentBudgetVersionId, IsActiveForSCM, GRAPClassification, GRAPClassificationNote, MainSegmentReporting, SubSegmentReporting
			FROM Plan_Project PP (NOLOCK) 
			INNER JOIN Plan_ProjectItem PPI (NOLOCK) ON PPI.ProjectID = PP.Project_ID
			WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PP.Project_ID = @Project_ID

			WHILE EXISTS (SELECT 1 FROM @ProjectItem)
			BEGIN
				SELECT TOP 1 
					@ProjectItem_ID = PJI.ProjectItem_ID
				 FROM @ProjectItem AS PJI

				 INSERT INTO dbo.Plan_AdjustmentProjectItem
				    (  
					ReferencePlanProjectItem_ID, AdjustmentProjectID, ProjectItemID, SCOAItemID, FinYear, ProjectFundYearID, SCOAFundId, BudgetAmount, BudgetAmountCurP1, BudgetAmountCurP2, SCOAFunctionId, SCOARegionId, DivisionId,
						BudgetSplitID, VirementId, HistoricalProjectCode, AdjustmentId, ModificationNumber, SCOACostingID, IsItemLocked, CreditDebit, AdjutmentType, LegislativeReasonAdjustment, ReasonForAdjustment, CapturerID, DateCaptured, AdjustmentVersionId, IsActiveForSCM, GRAPClassification, GRAPClassificationNote, MainSegmentReporting, SubSegmentReporting
				    )
				SELECT
					ProjectItem_ID, AdjustmentProjectID, ProjectItemID, SCOAItemID, FinYear, ProjectFundYearID, SCOAFundId, BudgetAmount, BudgetAmountCurP1, BudgetAmountCurP2, SCOAFunctionId, SCOARegionId, DivisionId,
				        BudgetSplitID, VirementId, HistoricalProjectCode, AdjustmentId, ModificationNumber, SCOACostingID, IsItemLocked, CreditDebit, AdjutmentType, LegislativeReasonAdjustment, ReasonForAdjustment, CapturerID, DateCaptured, AdjustmentVersionId, IsActiveForSCM, GRAPClassification, GRAPClassificationNote, MainSegmentReporting, SubSegmentReporting
				FROM @ProjectItem WHERE ProjectItem_ID=@ProjectItem_ID

				SET @AdjustmentProjectItem_ID=SCOPE_IDENTITY()
				
				INSERT INTO dbo.Plan_AdjustmentProjectItemDocs
				(
				    ReferenceProjectItemDocsID, SupportingDocsID, PlanAdjustmentProjectItemID, DateCaptured, CapturerID, AdjustmentVersionId
				)
				SELECT
					PPID.ProjectItemDocs_ID, PPID.SupportingDocsID, @AdjustmentProjectItem_ID, GETDATE(), @UserId, @AdjustmentBudgetVersionId
				FROM Plan_Project PP (NOLOCK) 
					INNER JOIN Plan_ProjectItem PPI (NOLOCK) ON PPI.ProjectID = PP.Project_ID
					INNER JOIN Plan_ProjectItemDocs PPID (NOLOCK) ON PPID.PlanProjectItemID = PPI.PlanProjectItem_ID
				WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PPI.PlanProjectItem_ID=@ProjectItem_ID

				--Insert Data into Plan_AdjustmentProjectItemMonth
               
				INSERT INTO dbo.Plan_AdjustmentProjectItemMonth
					(
						ReferenceProjectItemMonthID, PlanAdjustmentProjectItemID, MonthID, UnitQuantity, UnitPrice, CaptureID, DateCaptured, VirementId, AdjustmentId, AdjustmentVersionId
					)
				SELECT
					PPIM.ProjectItemMonth_ID, @AdjustmentProjectItem_ID, PPIM.MonthID, PPIM.UnitQuantity, PPIM.UnitPrice, @UserId, GETDATE(), PPIM.VirementId, PPIM.AdjustmentId, @AdjustmentBudgetVersionId 
					FROM Plan_Project PP (NOLOCK) 
					INNER JOIN Plan_ProjectItem PPI (NOLOCK) ON PPI.ProjectID = PP.Project_ID
					INNER JOIN Plan_ProjectItemMonth PPIM (NOLOCK) ON PPIM.PlanProjectItemID = PPI.PlanProjectItem_ID
					WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0
					AND PPIM.PlanProjectItemID = @ProjectItem_ID AND PPIM.ProjectItemMonth_ID IS NOT NULL
				
				 DELETE FROM @ProjectItem WHERE ProjectItem_ID = @ProjectItem_ID
				
			END

			DELETE FROM @tblPlanProject WHERE Project_ID = @Project_ID
		END

		COMMIT TRANSACTION
		SET @ErrorResult = 'Success'

END TRY
BEGIN CATCH
	
	SET @ErrorResult = ERROR_MESSAGE()
    RAISERROR(@ErrorResult, 16, 1)
    ROLLBACK TRANSACTION

END CATCH

	IF @AdjustmentBudgetPolicyApprovalId IS NULL
		SET @AdjustmentBudgetPolicyApprovalId = 0

	SELECT @AdjustmentBudgetPolicyApprovalId AS AdjustmentBudgetPolicyApprovalId, @ErrorResult AS Result
END
GO

/****** Object:  StoredProcedure [dbo].[Plan_SubmitAdjustmentBudgetPolicyTempPart1_sp]    Script Date: 2026/03/10 7:23:47 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO



-- =============================================
-- Author:		Nirav Parikh
-- Create date: 2017-11-24
-- Description:	Create Adjustment Budget Policy
-- EXEC [Plan_SubmitAdjustmentBudgetPolicy_sp] '2016/2017', 4779, '06062017095920CR_Budget_String_08052017.docx'
-- DO NOT APPLY REDGATE SQL FORMATE
-- SNagpal 09-Jan-2018 : Fix Inserting of Plan_AdjustmentProjectItem Issue
-- RChetty 31-Jan-2018 : Fix missing [Plan_AdjustmentFundingSourceDocs] insert TP 67124
-- =============================================
CREATE PROCEDURE [dbo].[Plan_SubmitAdjustmentBudgetPolicyTempPart1_sp] --'2017/2018', 1
    @FinYear NVARCHAR(9), 
	@UserId INT
AS
BEGIN
BEGIN TRY
    --BEGIN TRANSACTION
	
		DECLARE @ParentIDPItemID INT, @ProjectIDPItemID INT

		SELECT TOP 1 @ParentIDPItemID = ParentIDPItemID, @ProjectIDPItemID = ProjectIDPItemID FROM Plan_ProjectIDP


		--Declare Variables
		DECLARE @FinYearP1 NVARCHAR(9), @FinYearP2 NVARCHAR(9), @yearp1 INT, @yearp2 INT, @yearp3 INT

		--Set Variables
        SELECT @yearp1 = CAST(SUBSTRING(@FinYear, 6, 4) AS INT)
        SELECT @yearp2 = @yearp1 + 1
        SELECT @yearp3 = @yearp1 + 2
        SELECT @FinYearP1 = CONVERT(VARCHAR(4), @yearp1) + '/' + CONVERT(VARCHAR(4), @yearp2)
        SELECT @FinYearP2 = CONVERT(VARCHAR(4), @yearp2) + '/' + CONVERT(VARCHAR(4), @yearp3)

		--Declare Variables
		DECLARE @Comments NVARCHAR(1000), @NewAdjustmentBudgetVersionNumber NVARCHAR(50), @NewAdjustmentFundingBudgetVersionNumber NVARCHAR(50), @AdjustmentBudgetVersionId INT, @AdjustmentFundingBudgetVersionId INT, @ErrorResult NVARCHAR(MAX) = '', @AdjustmentBudgetPolicyApprovalId INT = 0
		
		--Set Variables
		SET @Comments = 'Adjustment Budget approved by Council in accordance with legislative requirements'

		--Get Inserted ID and Set Value
		SELECT @AdjustmentBudgetVersionId = MAX(AdjustmentBudgetVersion_ID) FROM Plan_AdjustmentBudgetVersion WHERE SUBSTRING(VersionName, 1, 9) = @FinYear AND Comments LIKE '%Adjustment Budget approved by Council%'
		
		DELETE Plan_AdjustmentProjectCosting

		DELETE Plan_AdjustmentProjectDivisions
		DELETE Plan_AdjustmentProjectFunctions
		DELETE Plan_AdjustmentProjectIDP
		DELETE Plan_AdjustmentProjectRegions
		DELETE Plan_AdjustmentProjectFundYear
		DELETE Plan_AdjustmentProjectFund
		DELETE Plan_AdjustmentProjectItemMonth
		DELETE Plan_AdjustmentProjectItem
		DELETE Plan_AdjustmentProject


		DBCC CHECKIDENT (Plan_AdjustmentProjectDivisions, RESEED, 0)
		DBCC CHECKIDENT (Plan_AdjustmentProjectFunctions, RESEED, 0)
		DBCC CHECKIDENT (Plan_AdjustmentProjectIDP, RESEED, 0)
		DBCC CHECKIDENT (Plan_AdjustmentProjectRegions, RESEED, 0)
		DBCC CHECKIDENT (Plan_AdjustmentProjectFundYear, RESEED, 0)
		DBCC CHECKIDENT (Plan_AdjustmentProjectFund, RESEED, 0)
		DBCC CHECKIDENT (Plan_AdjustmentProjectItemMonth, RESEED, 0)
		DBCC CHECKIDENT (Plan_AdjustmentProjectItem, RESEED, 0)
		DBCC CHECKIDENT (Plan_AdjustmentProject, RESEED, 0)

		
--//
--//
--//
--//
--//
		DECLARE @tblPlanProject TABLE 		
		(
			IDCount INT IDENTITY(1,1), Project_ID INT, AdjustmentProjectName NVARCHAR(500), AdjustmentProjectDesc NVARCHAR(500), ProjectManagerID INT, SupplyChainOfficialID INT, CapitalOperation INT, CostEstimate DECIMAL, ScoaProjectID INT,EstimatedStartDate DATETIME, EstimatedEndDate DATETIME,
			ProjectStatus INT, CommencementDate DATETIME, FinYear NVARCHAR(9), ProjectDetailDesc NVARCHAR(500), ProjectCategoryID INT, ProjectImplementAgentID INT, Longitude NVARCHAR(200), Latitude NVARCHAR(200), ProgrammeManagerID INT, FinancialControllerID INT,



			ProjectTypeID INT, EstimatedDuration INT, ProjectDistinctionID INT, IsDeleted BIT, HistoricalProjectCode NVARCHAR(100), ProjectParentID INT, SingleMultiYear VARCHAR(5), CapturerID INT,DateCaptured DATETIME, AdjustmentVersionId INT 
		)
		
		DECLARE @tblProjectFund TABLE
		(
			FundID INT IDENTITY(1,1), ProjectFund_ID INT, AdjustmentProjectID INT, ScoaFundID INT, FundAmount DECIMAL, FundReference NVARCHAR(200), VirementId INT, AdjustmentId INT, CapturerID INT, DateCaptured DATETIME, AdjustmentVersionId INT
		)

		DECLARE @ProjectItem TABLE
		(
		   IDCountProjectItem INT IDENTITY(1,1), IDCount INT, IDCountItem INT, ProjectItem_ID INT, AdjustmentProjectID INT, ProjectItemID INT, SCOAItemID INT, FinYear NVARCHAR(9), ProjectFundYearID INT, SCOAFundId INT, BudgetAmount DECIMAL, BudgetAmountCurP1 DECIMAL, BudgetAmountCurP2 DECIMAL, SCOAFunctionId INT,
		   SCOARegionId INT, DivisionId INT, BudgetSplitID INT, VirementId INT, HistoricalProjectCode NVARCHAR(100), AdjustmentId INT, ModificationNumber INT, SCOACostingID INT, IsItemLocked BIT, CreditDebit VARCHAR(6), AdjutmentType INT, LegislativeReasonAdjustment INT,
		   ReasonForAdjustment NVARCHAR(MAX), CapturerID INT, DateCaptured DATETIME, AdjustmentVersionId INT
		)

		DECLARE @ProjectItemMonth TABLE
		(
			IDCountItem INT, ProjectID INT, PlanProjectItemId INT, MonthID INT, UnitQuantity DECIMAL(16, 2), UnitPrice DECIMAL(16,2)
		)

		DECLARE @Project_ID INT = 0, @AdjustmentProject_ID INT, @ProjectFund_ID INT, @AdjustmentProjectFund_ID INT, @ProjectItem_ID INT, @AdjustmentProjectItem_ID INT;
		DECLARE @IDCount INT = 0, @IDCountProjectItem INT, @IDCountItem INT, @PlanProjectItemID INT, @FundID INT, @ScoaFundID INT;

		INSERT INTO @tblPlanProject
		    (  Project_ID, AdjustmentProjectName, AdjustmentProjectDesc, ProjectManagerID, SupplyChainOfficialID, CapitalOperation, CostEstimate, ScoaProjectID, EstimatedStartDate, EstimatedEndDate, ProjectStatus, CommencementDate,
		        FinYear, ProjectDetailDesc, ProjectCategoryID, ProjectImplementAgentID, Longitude, Latitude, ProgrammeManagerID, FinancialControllerID, ProjectTypeID, EstimatedDuration, ProjectDistinctionID, IsDeleted,
		        HistoricalProjectCode, ProjectParentID, SingleMultiYear, CapturerID, DateCaptured, AdjustmentVersionId
		    )

		SELECT DISTINCT 
			ProjectID, PP.ProjectName, ISNULL(ProjectDesc, PP.ProjectName), NULL, NULL, ISNULL(CapitalOperation, CapitalOperational), 0.00, scoaProj.ScoaID, NULL, NULL, 23, NULL,
			'2017/2018', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL,
			NULL, ProjectParentID, SingleMulti, 1, GETDATE(), @AdjustmentBudgetVersionId
		FROM Plan_AdjBudgetTemp PP (NOLOCK) 
			INNER JOIN Const_SCOA_Project_Structure scoaProj ON PP.ScoaProject = scoaProj.NTScoaID
			LEFT JOIN Plan_Project PPO ON PP.ProjectID = PPO.Project_ID
		WHERE 
			ProjectID IN (SELECT DISTINCT ProjectID FROM Plan_AdjBudgetTemp WHERE ProjectID IS NOT NULL) AND ABS(BudgetY1) + ABS(BudgetY2) + ABS(BudgetY3) > 0

		UNION ALL

		SELECT DISTINCT
			ProjectID, PP.ProjectName, ISNULL(ProjectDesc, PP.ProjectName), NULL, NULL, ISNULL(CapitalOperation, CapitalOperational), 0.00, scoaProj.ScoaID, NULL, NULL, 23, NULL,
			'2017/2018', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL,
			NULL, ProjectParentID, SingleMulti, 1, GETDATE(), @AdjustmentBudgetVersionId
		FROM Plan_AdjBudgetTemp PP (NOLOCK) 
			INNER JOIN Const_SCOA_Project_Structure scoaProj ON PP.ScoaProject = scoaProj.NTScoaID
			LEFT JOIN Plan_Project PPO ON PP.ProjectID = PPO.Project_ID
		WHERE 
			PP.ProjectName IN (SELECT DISTINCT ProjectName FROM Plan_AdjBudgetTemp WHERE ProjectID IS NULL) AND ABS(BudgetY1) + ABS(BudgetY2) + ABS(BudgetY3) > 0
		

		UPDATE Plan_AdjBudgetTemp 
		SET IDCount = tpp.IDCount
		FROM Plan_AdjbudgetTemp budTemp INNER JOIN @tblPlanProject tpp ON budTemp.ProjectID = tpp.Project_ID
		WHERE Project_ID IS NOT NULL

		UPDATE Plan_AdjBudgetTemp 
		SET IDCount = tpp.IDCount
		FROM Plan_AdjbudgetTemp budTemp INNER JOIN @tblPlanProject tpp ON budTemp.ProjectName = tpp.AdjustmentProjectName
		WHERE Project_ID IS NULL
		
		WHILE EXISTS (SELECT 1 FROM @tblPlanProject)
			BEGIN 
			
				--SELECT TOP 1 
				--	@Project_ID = TPAP.Project_ID
				--	 FROM @tblPlanProject AS TPAP

				SELECT TOP 1
					@IDCount = TPAP.IDCount
						FROM @tblPlanProject AS TPAP

				--PRINT 'IDCount=' + CONVERT(VARCHAR, @IDCount)

				INSERT INTO Plan_AdjustmentProject
				(
					ReferenceProject_ID, AdjustmentProjectName, AdjustmentProjectDesc, ProjectManagerID, SupplyChainOfficialID, CapitalOperation, CostEstimate, ScoaProjectID, EstimatedStartDate, EstimatedEndDate, ProjectStatus, CommencementDate,
					FinYear, ProjectDetailDesc, ProjectCategoryID, ProjectImplementAgentID, Longitude, Latitude, ProgrammeManagerID, FinancialControllerID, ProjectTypeID, EstimatedDuration, ProjectDistinctionID, IsDeleted, HistoricalProjectCode,
					ProjectParentID, SingleMultiYear, CapturerID, DateCaptured, AdjustmentVersionId
				)
				SELECT 
					Project_ID, AdjustmentProjectName, AdjustmentProjectDesc, ProjectManagerID, SupplyChainOfficialID, CapitalOperation, CostEstimate, ScoaProjectID, EstimatedStartDate, EstimatedEndDate, ProjectStatus, CommencementDate,
					FinYear, ProjectDetailDesc, ProjectCategoryID, ProjectImplementAgentID, Longitude, Latitude, ProgrammeManagerID, FinancialControllerID, ProjectTypeID, EstimatedDuration, ProjectDistinctionID, IsDeleted, HistoricalProjectCode,
					ProjectParentID, SingleMultiYear, CapturerID, DateCaptured, AdjustmentVersionId
				FROM @tblPlanProject AS PAP
				 --WHERE PAP.Project_ID= @Project_ID
				 WHERE PAP.IDCount = @IDcount

				SET @AdjustmentProject_ID = SCOPE_IDENTITY()
				--PRINT 'AdjustmentProjectID=' + CONVERT(VARCHAR, @AdjustmentProject_ID)
		 	--Insert Data into Plan_AdjustmentProjectCosting
			INSERT INTO Plan_AdjustmentProjectCosting
			(
			    ReferenceProjectCostingID, AdjustmentProjectID, ScoaCostingID, CapturerID, DateCaptured, AdjustmentVersionId
			)
			SELECT DISTINCT
				PPC.ProjectCosting_ID, @AdjustmentProject_ID, ISNULL(PPC.ScoaCostingID, scoaCost.ScoaID), @UserId, GETDATE(), @AdjustmentBudgetVersionId
			FROM Plan_AdjBudgetTemp PP 
				LEFT JOIN Plan_ProjectCosting PPC (NOLOCK) ON PPC.ProjectID = PP.ProjectID
				LEFT JOIN Const_SCOA_Costing_Structure (NOLOCK) scoaCost ON PP.ScoaCosting = scoaCost.NTScoaID
				WHERE PP.IDCount = @IDcount

			--Insert Data into Plan_AdjustmentProjectDivisions
			INSERT INTO Plan_AdjustmentProjectDivisions
			(
				ReferenceProjectDivisionID, AdjustmentProjectID, DivisionID, CapturerID, DateCaptured, AdjustmentVersionId
			)
			SELECT DISTINCT
				PPD.ProjectDivision_ID, @AdjustmentProject_ID, ISNULL(PPD.DivisionID, PP.DivisionID), @UserId, GETDATE(), @AdjustmentBudgetVersionId
			FROM Plan_AdjBudgetTemp PP (NOLOCK) 
				LEFT JOIN Plan_ProjectDivisions PPD (NOLOCK) ON PPD.ProjectID = PP.ProjectID
			WHERE PP.IDCount = @IDcount

			--Insert Data into Plan_AdjustmentProjectFunctions
			INSERT INTO Plan_AdjustmentProjectFunctions
			(
			    ReferenceProjectFunctionID, AdjustmentProjectID, ScoaFunctionID, CapturerID, DateCaptured, AdjustmentVersionId
			)
			SELECT DISTINCT
				PPF.ProjectFunction_ID, @AdjustmentProject_ID, ISNULL(PPF.ScoaFunctionID, ScoaID), @UserId, GETDATE(), @AdjustmentBudgetVersionId
			FROM Plan_AdjBudgetTemp PP (NOLOCK) 
				LEFT JOIN Plan_ProjectFunctions PPF (NOLOCK) ON PPF.ProjectID = PP.ProjectID
				LEFT JOIN Const_SCOA_Function_Structure (NOLOCK) scoaFunc ON PP.ScoaFunction = scoaFunc.NTScoaID
			WHERE PP.IDCount = @IDcount
	
			--Insert Data into Plan_AdjustmentProjectIDP
			INSERT INTO Plan_AdjustmentProjectIDP
			(
			    ReferenceProjectIDPID, AdjustmentProjectID, ParentIDPItemID, AdjustmentProjectIDPItemID, Percentage, CapturerID, DateCaptured, Latitude, Longitude, AdjustmentVersionId
			)
			SELECT DISTINCT
				PPIDP.ProjectIDP_ID, @AdjustmentProject_ID, ISNULL(PPIDP.ParentIDPItemID, @ParentIDPItemID), ISNULL(PPIDP.ProjectIDPItemID, @ProjectIDPItemID), ISNULL(PPIDP.Percentage, 100.00), @UserId, GETDATE(), PPIDP.Latitude, PPIDP.Longitude, @AdjustmentBudgetVersionId
			FROM Plan_AdjBudgetTemp PP (NOLOCK) 
			LEFT JOIN Plan_ProjectIDP PPIDP (NOLOCK) ON PPIDP.ProjectID = PP.ProjectID
			WHERE PP.IDCount = @IDcount

			--Insert Data into Plan_AdjustmentProjectRegions
			INSERT INTO Plan_AdjustmentProjectRegions
			(
			    ReferenceProjectRegionID, AdjustmentProjectID, ScoaRegionID, RegionPercent, CapturerID, DateCaptured, AdjustmentVersionId
			)
			SELECT DISTINCT
				PPR.ProjectRegion_ID, @AdjustmentProject_ID, ISNULL(PPR.ScoaRegionID, ScoaID), ISNULL(PPR.RegionPercent, 100.00), @UserId, GETDATE(), @AdjustmentBudgetVersionId
			FROM Plan_AdjBudgetTemp PP (NOLOCK) 
				LEFT JOIN Plan_ProjectRegions PPR (NOLOCK) ON PPR.ProjectID = PP.ProjectID
				LEFT JOIN Const_SCOA_Regional_Structure scoaRegion (NOLOCK) ON PP.ScoaRegion = scoaRegion.NtScoaID
			WHERE PP.IDCount = @IDcount

			--Insert Data into Plan_AdjustmentProjectFund
			INSERT INTO @tblProjectFund
			    ( 
					ProjectFund_ID, AdjustmentProjectID, ScoaFundID, FundAmount, FundReference, VirementId, AdjustmentId, CapturerID, DateCaptured, AdjustmentVersionId
			    )
			SELECT 
				PPF.ProjectFund_ID, @AdjustmentProject_ID, projFund.ScoaID, SUM(BudgetTotal), ISNULL(PPF.FundReference, ''), PPF.VirementId, PPF.AdjustmentId, @UserID, GETDATE(), @AdjustmentBudgetVersionId
			FROM 
				(SELECT ProjectID, ScoaID, IDCount, ABS(BudgetY1) + ABS(BudgetY2) + ABS(BudgetY3) AS BudgetTotal FROM Plan_AdjBudgetTemp PP (NOLOCK) INNER JOIN Const_SCOA_Funds_Structure scoaFund ON PP.ScoaFund = scoaFund.NTScoaID WHERE ABS(BudgetY1) + ABS(BudgetY2) + ABS(BudgetY3) > 0) projFund
				LEFT JOIN Plan_ProjectFund PPF (NOLOCK) ON PPF.ProjectID = projFund.ProjectID AND PPF.SCOAFundID = projFund.ScoaID
			WHERE projFund.IDCount = @IDcount
			GROUP BY PPF.ProjectFund_ID, projFund.ScoaID, PPF.ProjectFund_ID, PPF.FundReference, PPF.VirementId, PPF.AdjustmentId

			--SELECT DISTINCT
			--	ISNULL(PPF.ProjectFund_ID, -1), @AdjustmentProject_ID, scoaFund.ScoaID, SUM(PPF.FundAmount), PPF.FundReference, PPF.VirementId, PPF.AdjustmentId, @UserId, GETDATE(), @AdjustmentBudgetVersionId
			--FROM Plan_AdjBudgetTemp PP (NOLOCK) 
			--	LEFT JOIN Plan_ProjectFund PPF (NOLOCK) ON PPF.ProjectID = PP.ProjectID
			--	LEFT JOIN Const_SCOA_Funds_Structure scoaFund (NOLOCK) ON PP.ScoaFund = scoaFund.NTScoaID
			--WHERE PP.IDCount = @IDcount
			--GROUP BY ScoaFund.ScoaID, PPF.ProjectFund_ID, PPF.FundReference, PPF.VirementId, PPF.AdjustmentId

			WHILE EXISTS (SELECT 1 FROM @tblProjectFund)
			BEGIN
				--SELECT TOP 1 
				--	@ProjectFund_ID = TPAP.ProjectFund_ID
				--FROM @tblProjectFund AS TPAP

				SELECT TOP 1 
					@FundID = TPAP.FundID,
					@ProjectFund_ID = TPAP.ProjectFund_ID,
					@ScoaFundID = TPAP.ScoaFundID
				FROM @tblProjectFund AS TPAP

				INSERT INTO dbo.Plan_AdjustmentProjectFund
					(
					ReferenceProjectFundID, AdjustmentProjectID, ScoaFundID, FundAmount, FundReference, VirementId, AdjustmentId, CapturerID, DateCaptured, AdjustmentVersionId
					)
				SELECT 
					ProjectFund_ID, AdjustmentProjectID, ScoaFundID, FundAmount, FundReference, VirementId, AdjustmentId, CapturerID, DateCaptured, AdjustmentVersionId
				FROM @tblProjectFund WHERE FundID = @FundID --ProjectFund_ID = @ProjectFund_ID

				SET @AdjustmentProjectFund_ID = SCOPE_IDENTITY()
				
				--PRINT 'ProjectFundID=' + CONVERT(VARCHAR, @ProjectFund_ID)
				--Insert Data into Plan_AdjustmentProjectFundYearfor exisitng projects

				--IF ((SELECT TOP 1 ProjectID FROM Plan_AdjBudgetTemp WHERE IDCount = @IDCount) IS NOT NULL)
				IF (@ProjectFund_ID IS NOT NULL)
				BEGIN
					INSERT INTO Plan_AdjustmentProjectFundYear
						(
							ReferenceProjectFundYearID, AdjustmentProjectFundID, FinYear, YearFundAmount, VirementId, AdjustmentId, CapturerID, DateCaptured, AdjustmentVersionId
						)
					SELECT
						PPFY.ProjectFundYear_ID, @AdjustmentProjectFund_ID, PPFY.FinYear, 
						CASE 
							WHEN FinYear = '2017/2018' THEN ISNULL(SUM(ISNULL(ABS(BudgetY1), 0)), 0)
							WHEN FinYear = '2018/2019' THEN ISNULL(SUM(ISNULL(ABS(BudgetY2), 0)), 0)
							WHEN FinYear = '2019/2020' THEN ISNULL(SUM(ISNULL(ABS(BudgetY3), 0)), 0)
						END
						,PPFY.VirementId, PPFY.AdjustmentId, @UserId, GETDATE(), @AdjustmentBudgetVersionId
					FROM Plan_ProjectFundYear PPFY (NOLOCK) 
					LEFT JOIN dbo.Plan_ProjectFund PPF (NOLOCK) ON PPF.ProjectFund_ID = PPFY.ProjectFundID
					LEFT JOIN 
						(SELECT ProjectID, ScoaID, BudgetY1, BudgetY2, BudgetY3 FROM Plan_AdjBudgetTemp PP (NOLOCK)LEFT JOIN Const_SCOA_Funds_Structure scoaFund (NOLOCK) ON PP.ScoaFund = scoaFund.NTScoaID) PP 
						 ON PPF.ProjectID = PP.ProjectID AND PPF.ScoaFundID = PP.ScoaID
					WHERE PPFY.ProjectFundID = @ProjectFund_ID 
					--WHERE IDCount = @IDCount 
					GROUP BY PPFY.ProjectFundYear_ID, PPFY.FinYear,PPFY.VirementId, PPFY.AdjustmentId
				END
				ELSE
				BEGIN

					INSERT INTO Plan_AdjustmentProjectFundYear
						(
							ReferenceProjectFundYearID, AdjustmentProjectFundID, FinYear, YearFundAmount, VirementId, AdjustmentId, CapturerID, DateCaptured, AdjustmentVersionId
						)
					SELECT
						NULL, @AdjustmentProjectFund_ID, '2017/2018', ISNULL(SUM(ISNULL(ABS(BudgetY1), 0)), 0),NULL, NULL, @UserId, GETDATE(), @AdjustmentBudgetVersionId
					FROM Plan_AdjustmentProjectFund APF (NOLOCK) 
					LEFT JOIN Plan_AdjustmentProject AP ON APF.AdjustmentProjectID = AP.AdjustmentProject_ID
					LEFT JOIN
						(SELECT ProjectID, IDCount, ScoaID, BudgetY1, BudgetY2, BudgetY3 FROM Plan_AdjBudgetTemp PP (NOLOCK) LEFT JOIN Const_SCOA_Funds_Structure scoaFund (NOLOCK) ON PP.ScoaFund = scoaFund.NTScoaID) PP 
						 ON AP.AdjustmentProject_ID = PP.IDCount AND APF.ScoaFundID = PP.ScoaID
					WHERE PP.IDCount = @IDCount AND ScoaFundID = @ScoaFundID
					--LEFT JOIN Plan_AdjBudgetTemp PP (NOLOCK) ON AP.AdjustmentProject_ID = PP.IDCount
					--WHERE PP.IDCount = @IDCount
					--WHERE ReferenceProjectFundID IS NULL
					-- ???GROUP BY --NOT Required

					INSERT INTO Plan_AdjustmentProjectFundYear
						(
							ReferenceProjectFundYearID, AdjustmentProjectFundID, FinYear, YearFundAmount, VirementId, AdjustmentId, CapturerID, DateCaptured, AdjustmentVersionId
						)
					SELECT
						NULL, @AdjustmentProjectFund_ID, '2018/2019', ISNULL(SUM(ISNULL(ABS(BudgetY2), 0)), 0),NULL, NULL, @UserId, GETDATE(), @AdjustmentBudgetVersionId
					FROM Plan_AdjustmentProjectFund APF (NOLOCK) 
					LEFT JOIN Plan_AdjustmentProject AP ON APF.AdjustmentProjectID = AP.AdjustmentProject_ID
					LEFT JOIN
						(SELECT ProjectID, IDCount, ScoaID, BudgetY1, BudgetY2, BudgetY3 FROM Plan_AdjBudgetTemp PP (NOLOCK) LEFT JOIN Const_SCOA_Funds_Structure scoaFund (NOLOCK) ON PP.ScoaFund = scoaFund.NTScoaID) PP 
						 ON AP.AdjustmentProject_ID = PP.IDCount AND APF.ScoaFundID = PP.ScoaID
					WHERE PP.IDCount = @IDCount AND ScoaFundID = @ScoaFundID
					--WHERE ReferenceProjectFundID IS NULL				
					-- ???GROUP BY --NOT Required

					INSERT INTO Plan_AdjustmentProjectFundYear
						(
							ReferenceProjectFundYearID, AdjustmentProjectFundID, FinYear, YearFundAmount, VirementId, AdjustmentId, CapturerID, DateCaptured, AdjustmentVersionId
						)
					SELECT
						NULL, @AdjustmentProjectFund_ID, '2019/2020', ISNULL(SUM(ISNULL(ABS(BudgetY3), 0)), 0),NULL, NULL, @UserId, GETDATE(), @AdjustmentBudgetVersionId
					FROM Plan_AdjustmentProjectFund APF (NOLOCK) 
					LEFT JOIN Plan_AdjustmentProject AP ON APF.AdjustmentProjectID = AP.AdjustmentProject_ID
					LEFT JOIN
						(SELECT ProjectID, IDCount, ScoaID, BudgetY1, BudgetY2, BudgetY3 FROM Plan_AdjBudgetTemp PP (NOLOCK) LEFT JOIN Const_SCOA_Funds_Structure scoaFund (NOLOCK) ON PP.ScoaFund = scoaFund.NTScoaID) PP 
						 ON AP.AdjustmentProject_ID = PP.IDCount AND APF.ScoaFundID = PP.ScoaID
					WHERE PP.IDCount = @IDCount AND ScoaFundID = @ScoaFundID
					--WHERE ReferenceProjectFundID IS NULL
					-- ???GROUP BY --NOT Required

				END

				--DELETE FROM @tblProjectFund WHERE ProjectFund_ID = @ProjectFund_ID
				DELETE FROM @tblProjectFund WHERE FundID = @FundID
			END
			
			--Insert Data into @ProjectItem
			INSERT INTO @ProjectItem
				( IDCount, IDCountItem, ProjectItem_ID, AdjustmentProjectID, ProjectItemID, SCOAItemID, FinYear, ProjectFundYearID, SCOAFundId, BudgetAmount, BudgetAmountCurP1, BudgetAmountCurP2, SCOAFunctionId, SCOARegionId, DivisionId, BudgetSplitID, VirementId, HistoricalProjectCode, AdjustmentId, ModificationNumber, SCOACostingID, IsItemLocked, CreditDebit, AdjutmentType, LegislativeReasonAdjustment, 
							ReasonForAdjustment, CapturerID, DateCaptured, AdjustmentVersionId
				)	
			SELECT DISTINCT
				PP.IDCount, PP.IDCountItem, PP.PlanProjectItemID, @AdjustmentProject_ID, PPI.ProjectItemID, SI.SCOAID, '2017/2018', isnull(PPI.ProjectFundYearID,APFY.AdjustmentProjectFundYear_ID), SFD.scoaid, ABS(PP.BudgetY1), ABS(PP.BudgetY2), ABS(PP.BudgetY3), SFN.SCOAId, SR.ScoaID,
						PP.DivisionId, 1 , null, PPI.HistoricalProjectCode, null, PPI.ModificationNumber, SC.SCOAID, null, PP.DebitCredit, NULL, NULL, NULL, @UserId, GETDATE(), @AdjustmentBudgetVersionId
			FROM Plan_AdjBudgetTemp PP (NOLOCK) 
					left join Plan_ProjectItem PPI (NOLOCK) ON PPI.PlanProjectItem_ID = PP.PlanProjectItemID
					left join const_scoa_structure SI on SI.NTScoaID = PP.ScoaItem
					left join const_scoa_function_structure SFN on SFN.NTScoaID = PP.ScoaFunction
					left join const_scoa_funds_structure SFD on PP.ScoaFund = SFD.NTSCOAID 
					left join const_scoa_regional_structure SR on PP.ScoaRegion = SR.NTSCOAID 
					left join const_scoa_Costing_structure SC on PP.ScoaCosting = SC.NTSCOAID 
					left join Plan_AdjustmentProject AP (NOLOCK) ON AP.AdjustmentProjectName = PP.ProjectName 
					left join Plan_AdjustmentProjectFund  APF (NOLOCK) ON APF.AdjustmentProjectID = AP.AdjustmentProject_ID and APF.scoafundid = SFD.scoaid
					left join Plan_AdjustmentProjectFundYear  APFY (NOLOCK) ON APF.AdjustmentProjectFund_ID = APFY.AdjustmentProjectFundID  and APFY.finyear = '2017/2018'
				WHERE PP.IDCount = @IDcount AND ABS(BudgetY1) + ABS(BudgetY2) + ABS(BudgetY3) > 0

			--SELECT * FROM @ProjectITem

			WHILE EXISTS (SELECT 1 FROM @ProjectItem)
			BEGIN
				SELECT TOP 1 @PlanProjectItemID = PJI.ProjectItem_ID,
					@IDCountItem = PJI.IDCountItem
				 FROM @ProjectItem AS PJI

				 SELECT TOP 1
					@IDcountProjectItem = IDCountProjectItem --PJI.ProjectItem_ID
				 FROM @ProjectItem AS PJI

				 INSERT INTO dbo.Plan_AdjustmentProjectItem
				    (  
					ReferencePlanProjectItem_ID, AdjustmentProjectID, ProjectItemID, SCOAItemID, FinYear, ProjectFundYearID, SCOAFundId, BudgetAmount, BudgetAmountCurP1, BudgetAmountCurP2, SCOAFunctionId, SCOARegionId, DivisionId,
						BudgetSplitID, VirementId, HistoricalProjectCode, AdjustmentId, ModificationNumber, SCOACostingID, IsItemLocked, CreditDebit, AdjutmentType, LegislativeReasonAdjustment, ReasonForAdjustment, CapturerID, DateCaptured, AdjustmentVersionId,
						AdjustedBudgetAmount, AdjustedBudgetAmountCurP1, AdjustedBudgetAmountCurP2
				    )
				SELECT DISTINCT
					ProjectItem_ID, AdjustmentProjectID, a.ProjectItemID, a.SCOAItemID, a.FinYear, a.ProjectFundYearID, a.SCOAFundId, b.BudgetAmount, b.BudgetAmountCurP1, b.BudgetAmountCurP2, a.SCOAFunctionId, a.SCOARegionId, a.DivisionId,
				        a.BudgetSplitID, a.VirementId, a.HistoricalProjectCode, a.AdjustmentId, a.ModificationNumber, a.SCOACostingID, a.IsItemLocked, a.CreditDebit, AdjutmentType, LegislativeReasonAdjustment, ReasonForAdjustment, a.CapturerID, a.DateCaptured, a.AdjustmentVersionId ,
						ABS(a.BudgetAmount), ABS(a.BudgetAmountCurP1), ABS(a.BudgetAmountCurP2)
				FROM @ProjectItem a LEFT JOIN Plan_ProjectItem b on a.ProjectItem_ID = b.PlanProjectItem_ID
				WHERE IDCountProjectItem = @IDCountProjectItem
				--WHERE ProjectItem_ID = @IDCountItem

				SET @AdjustmentProjectItem_ID=SCOPE_IDENTITY()
				

				--Insert Data into Plan_AdjustmentProjectItemMonth
				--PRINT 'IDcountItem=' + convert(varchar, @IDCountItem)

				IF (@PlanProjectItemID IS NOT NULL)
				BEGIN
					INSERT INTO @ProjectItemMonth
					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 7 AS MonthID, 1.00 AS UnitQuantity, BudgetMonth1 AS UnitPrice
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 8, 1.00, BudgetMonth2
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 9, 1.00, BudgetMonth3
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 10, 1.00, BudgetMonth4
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 11, 1.00, BudgetMonth5
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL
				
					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 12, 1.00, BudgetMonth6
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 1, 1.00, BudgetMonth7
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 2, 1.00, BudgetMonth8
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 3, 1.00, BudgetMonth9
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 4, 1.00, BudgetMonth10
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 5, 1.00, BudgetMonth11
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 6, 1.00, BudgetMonth12
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem
					
               
					INSERT INTO dbo.Plan_AdjustmentProjectItemMonth
						(
							ReferenceProjectItemMonthID, PlanAdjustmentProjectItemID, MonthID, UnitQuantity, UnitPrice, CaptureID, DateCaptured, VirementId, AdjustmentId, AdjustmentVersionId, AdjustedUnitPrice
						)
					SELECT
						PPIM.ProjectItemMonth_ID, @AdjustmentProjectItem_ID, PPIM.MonthID, PPIM.UnitQuantity, PPIM.UnitPrice, @UserId, GETDATE(), PPIM.VirementId, PPIM.AdjustmentId, @AdjustmentBudgetVersionId, ABS(PP.UnitPrice)
						FROM @ProjectItemMonth PP
						INNER JOIN Plan_ProjectItem PPI (NOLOCK) ON PPI.PlanProjectItem_ID = PP.PlanProjectItemId
						INNER JOIN Plan_ProjectItemMonth PPIM (NOLOCK) ON PPIM.PlanProjectItemID = PPI.PlanProjectItem_ID AND PP.MonthID = PPIM.MonthID
					WHERE
						PP.PlanProjectItemId = @PlanProjectItemID
				END
				ELSE
				BEGIN
					
					INSERT INTO @ProjectItemMonth
					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 7 AS MonthID, 1.00 AS UnitQuantity, BudgetMonth1 AS UnitPrice
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 8, 1.00, BudgetMonth2
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 9, 1.00, BudgetMonth3
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 10, 1.00, BudgetMonth4
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 11, 1.00, BudgetMonth5
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL
				
					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 12, 1.00, BudgetMonth6
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 1, 1.00, BudgetMonth7
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 2, 1.00, BudgetMonth8
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 3, 1.00, BudgetMonth9
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 4, 1.00, BudgetMonth10
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 5, 1.00, BudgetMonth11
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem

					UNION ALL

					SELECT
						IDCountItem, ProjectID, PlanProjectItemId, 6, 1.00, BudgetMonth12
					FROM 
						Plan_AdjBudgetTemp
					WHERE 
						IDCountItem = @IDCountItem
					
               
					INSERT INTO dbo.Plan_AdjustmentProjectItemMonth
						(
							ReferenceProjectItemMonthID, PlanAdjustmentProjectItemID, MonthID, UnitQuantity, UnitPrice, CaptureID, DateCaptured, VirementId, AdjustmentId, AdjustmentVersionId, AdjustedUnitPrice
						)
					SELECT
						NULL, @AdjustmentProjectItem_ID, PP.MonthID, 0.00, 1.00, @UserId, GETDATE(), NULL, NULL, @AdjustmentBudgetVersionId, ABS(PP.UnitPrice)
						FROM @ProjectItemMonth PP
					--	INNER JOIN Plan_ProjectItem PPI (NOLOCK) ON PPI.PlanProjectItem_ID = PP.PlanProjectItemId
					--	INNER JOIN Plan_ProjectItemMonth PPIM (NOLOCK) ON PPIM.PlanProjectItemID = PPI.PlanProjectItem_ID AND PP.MonthID = PPIM.MonthID
					--WHERE
					--	PP.PlanProjectItemId = @PlanProjectItemID


				END

				 DELETE FROM @ProjectItemMonth WHERE IDCountItem = @IDCountItem --PlanProjectItemId = @IDCountItem
				 DELETE FROM @ProjectItem WHERE IDCountProjectItem = @IDCountProjectItem --ProjectItem_ID = @ProjectItem_ID
				
			END

			DELETE FROM @tblPlanProject WHERE IDCount = @IDCount --Project_ID = @Project_ID
		END

		--COMMIT TRANSACTION
		SET @ErrorResult = 'Success'

END TRY
BEGIN CATCH
	
	SET @ErrorResult = ERROR_MESSAGE()
    RAISERROR(@ErrorResult, 16, 1)
    --ROLLBACK TRANSACTION

END CATCH

	--IF @AdjustmentBudgetPolicyApprovalId IS NULL
	--	SET @AdjustmentBudgetPolicyApprovalId = 0

	--SELECT @AdjustmentBudgetPolicyApprovalId AS AdjustmentBudgetPolicyApprovalId, @ErrorResult AS Result
END






GO

