-- =============================================
-- Author:		Nirav Parikh
-- Create date: 2017-12-04
-- Description:	Create Supplementary Adjustment
-- EXEC [Plan_SubmitSupplementaryAdjustment_sp] '2017/2018', 4779, '06062017095920CR_Budget_String_08052017.docx'
-- DO NOT APPLY REDGATE SQL FORMATE
-- SNagpal 08-Feb-2018 : Fix Inserting of Plan_AdjustmentProjectItem Issue
-- SNagpal 18-Feb-2018 : Fix Decimal issues
-- SNagpal 28-Mar-2018 : Exclude Items having AND (ISNULL(BudgetAmount,0) + ISNULL(BudgetAmountCurP1,0) + ISNULL(BudgetAmountCurP2,0) ) = 0
-- SNagpal 06-Apr-2018 : 70509 Fix WHILE EXISTS (SELECT 1 FROM @tblProjectFund)
-- SNagpal 11-Apr-2018 : 70713 Fix missing [Plan_AdjustmentFundingSourceDocs] insert
-- SNagpal 17-Apr-2018 : 70995 Fix Inserting of Plan_AdjustmentProjectItem Issue
-- SNagpal 05-June-2018 : Add two columns for Plan_AdjustmentFundingSourceDocs : RefFundingSourceDocsID, AdjustmentFundingVersionId
-- SNagpal 05-June-2018 : Fix issue of saving Plan_ProjectItemDocs. Issue in Joins
-- SNagpal 23-Oct-2018 : 79279 Add INNER JOIN dbo.Plan_ProjectItem ppi ON  ppi.ProjectID = p.Project_ID to get projects having some of budget amount greater than 0
-- SNagpal 25-Oct-2018 : 81185 QA - Project names are duplicated
-- SNagpal 14-Nov-2018 : 81825 Add logic to save correct SupportDocsGroupId
-- SNagpal 24-Jan-2019 : #61596 - #83633 - Add functionality to Copy ProjectCode
-- SNagpal 25-Apr-2019 : #86104 Include Items having (ISNULL(PPI.BudgetAmount,0) + ISNULL(PPI.BudgetAmountCurP1,0) + ISNULL(PPI.BudgetAmountCurP2,0) ) = 0 with ORGB <> 0
-- SNagpal 26-Apr-2019:  #87831, Add condition while copying data to Plan_FundingSourceBudget_Detail, Must Only copy data for CurrentFinyear
-- SNagpal 20-May-2019 : 88917 Add code to disable FK before insert
-- SN 18-Feb-2023: 58285 Add IsActiveForSCM flag
-- CM 07-Aug-2023: #105236 Include CostingProject field
-- CM 11-Jan-2024: 83764 All zero budget items included in ADJB
-- =============================================
CREATE PROCEDURE [dbo].[Plan_SubmitSupplementaryAdjustment_sp]
    @FinYear NVARCHAR(9), 
	@UserId INT, 
	@SupplementaryAdjustmentFileName NVARCHAR(500)
AS
BEGIN
BEGIN TRY
    BEGIN TRANSACTION

		--=================Disable FK relations

		IF OBJECT_ID('FK_Plan_AdjustmentProjectFunctions_Const_SCOA_Function_Structure') IS NOT NULL
		BEGIN
			ALTER TABLE Plan_AdjustmentProjectFunctions 
			NOCHECK CONSTRAINT FK_Plan_AdjustmentProjectFunctions_Const_SCOA_Function_Structure; 
		END

		IF OBJECT_ID('FK_Plan_AdjustmentProjectFund_Const_SCOA_Funds_Structure') IS NOT NULL
		BEGIN
			ALTER TABLE  Plan_AdjustmentProjectFund
			NOCHECK CONSTRAINT FK_Plan_AdjustmentProjectFund_Const_SCOA_Funds_Structure
		END

		IF OBJECT_ID('FK_Plan_AdjustmentProjectRegions_Const_SCOA_Regional_Structure') IS NOT NULL
		BEGIN
			ALTER TABLE  Plan_AdjustmentProjectRegions
			NOCHECK CONSTRAINT FK_Plan_AdjustmentProjectRegions_Const_SCOA_Regional_Structure
		END

		--Declare Variables
		DECLARE @FinYearP1 NVARCHAR(9), @FinYearP2 NVARCHAR(9), @yearp1 INT, @yearp2 INT, @yearp3 INT

		--Set Variables
        SELECT @yearp1 = CAST(SUBSTRING(@FinYear, 6, 4) AS INT)
        SELECT @yearp2 = @yearp1 + 1
        SELECT @yearp3 = @yearp1 + 2
        SELECT @FinYearP1 = CONVERT(VARCHAR(4), @yearp1) + '/' + CONVERT(VARCHAR(4), @yearp2)
        SELECT @FinYearP2 = CONVERT(VARCHAR(4), @yearp2) + '/' + CONVERT(VARCHAR(4), @yearp3)

		--Declare Variables
		DECLARE @BudgetVerionID INT, @Comments NVARCHAR(1000), @NewAdjustmentBudgetVersionNumber NVARCHAR(50), @NewAdjustmentFundingBudgetVersionNumber NVARCHAR(50), 
		@AdjustmentBudgetVersionId INT, @AdjustmentFundingBudgetVersionId INT, @ErrorResult NVARCHAR(MAX) = '', @SupplementaryAdjustmentId INT = 0, @SupportDocsGrpId INT;
		
		SELECT TOP 1 @BudgetVerionID = BudgetVersion_ID FROM dbo.Plan_BudgetVersion pbv
		INNER JOIN dbo.Plan_BudgetVersionDetail pbvd ON pbvd.BudgetVersionID = pbv.BudgetVersion_ID
		WHERE VersionName LIKE '%ORGB%' AND pbvd.FinYear=@FinYear ORDER BY pbv.DateCaptured DESC

		--Set Variables
		SET @Comments = 'Adjustment Budget approved by Council in accordance with legislative requirements'
		SELECT @SupportDocsGrpId = SupportingDocsGroup_ID FROM Const_SupportingDocsGroup WHERE GroupDesc LIKE 'Adjustment Funding Documents'

		--Declare Table
		DECLARE @tblVersionNumber TABLE
		( NewVersionNumber NVARCHAR(50), FinYear NVARCHAR(20) )

		--Execute SP and Insert Output in Declared Table
		INSERT INTO @tblVersionNumber
			( NewVersionNumber, FinYear )
		EXEC Plan_GetLatestAdjustmentBudgetVersionNumber_sp @FinYear

		--Set Value from SP Output
		SELECT @NewAdjustmentBudgetVersionNumber = NewVersionNumber FROM @tblVersionNumber

		--Delete Data from Declared Table
		DELETE FROM @tblVersionNumber

		--Execute SP and Insert Output in Declared Table
		INSERT INTO @tblVersionNumber
			( NewVersionNumber, FinYear )
		EXEC dbo.Plan_GetLatestAdjustmentFundingBudgetVersionNumber_sp @FinYear

		--Set Value from SP Output
		SELECT @NewAdjustmentFundingBudgetVersionNumber = NewVersionNumber FROM @tblVersionNumber

		--Insert Data into Plan_AdjustmentBudgetVersion
		INSERT INTO Plan_AdjustmentBudgetVersion
			( VersionNumber, VersionName, Comments, CapturerID, DateCaptured )
		VALUES
			( @NewAdjustmentBudgetVersionNumber, @NewAdjustmentBudgetVersionNumber, @Comments, @UserId, GETDATE() )

		--Get Inserted ID and Set Value
		SELECT @AdjustmentBudgetVersionId = SCOPE_IDENTITY()
		
		--Insert Data into Plan_AdjustmentBudgetVersionDetail
		INSERT INTO Plan_AdjustmentBudgetVersionDetail
		(
			AdjustmentBudgetVersionID,
			ProjectID,
			FinYear,
			IDPItemID,
			CapitalOperation,
			ScoaProjectID,
			SCOACostingID,
			ProjectTypeID,
			PlanProjectItemID,
			ProjectItemID,
			SCOAItemID,
			SCOAFundId,
			BudgetAmount,
			BudgetAmountCurP1,
			BudgetAmountCurP2,
			SCOAFunctionId,
			SCOARegionId,
			DivisionId,
			BudgetSplitID,
			VirementId,
			AdjustmentId,
			ModificationNumber,
			IsItemLocked,
			CreditDebit,
			AdjutmentType,
			LegislativeReasonAdjustment,
			ReasonForAdjustment,
			CapturerID,
			DateCaptured,
			GRAPClassification, 
			GRAPClassificationNote, 
			MainSegmentReporting, 
			SubSegmentReporting,
			CostingProject
		)     
        SELECT @AdjustmentBudgetVersionId,
                PP.Project_ID,
                PP.FinYear,
                0,
                ISNULL(PP.CapitalOperation, 0),
                ISNULL(PP.ScoaProjectID, 0),
                ISNULL(PPI.SCOACostingID, 0),
                ISNULL(PP.ProjectTypeID, 0),
                ISNULL(PPI.PlanProjectItem_ID, 0),
                ISNULL(PPI.ProjectItemID, 0),
                ISNULL(PPI.SCOAItemID, 0),
                ISNULL(PPI.SCOAFundId, 0),
                ISNULL(PPI.BudgetAmount, 0),
                ISNULL(PPI.BudgetAmountCurP1, 0),
                ISNULL(PPI.BudgetAmountCurP2, 0),
                ISNULL(PPI.SCOAFunctionId, 0),
                ISNULL(PPI.SCOARegionId, 0),
                ISNULL(PPI.DivisionId, 0),
				ISNULL(PPI.BudgetSplitID, 0),
				ISNULL(PPI.VirementId, 0),
				ISNULL(PPI.AdjustmentId, 0),
				ISNULL(PPI.ModificationNumber, 0),
				ISNULL(PPI.IsItemLocked, 0),
				ISNULL(PPI.CreditDebit, ''),
				NULL,
				NULL,
				NULL,
                @UserId,
                GETDATE(),
				GRAPClassification, 
				GRAPClassificationNote, 
				MainSegmentReporting, 
				SubSegmentReporting,
				CostingProject
        FROM Plan_Project AS PP (NOLOCK)
			INNER JOIN Plan_ProjectItem AS PPI (NOLOCK) ON PP.Project_ID = PPI.ProjectID
        WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0

		--Insert Data into Plan_AdjustmentBudgetVersionMonths
        INSERT INTO Plan_AdjustmentBudgetVersionMonths
        (
            AdjustmentBudgetVersionID,
            AdjustmentProjectItemMonth_ID,
            PlanAdjustmentProjectItemID,
            MonthID,
            UnitQuantity,
            UnitPrice,
            CaptureID,
            DateCaptured,
            VirementId,
            AdjustmentId
        )
        SELECT @AdjustmentBudgetVersionId,
                ppim.ProjectItemMonth_ID,
                ppim.PlanProjectItemID,
                ppim.MonthID,
                ppim.UnitQuantity,
                ppim.UnitPrice,
                @UserId,
                GETDATE(),
                ppim.VirementId,
                ppim.AdjustmentId
        FROM Plan_Project AS PP (NOLOCK) 
			INNER JOIN Plan_ProjectItem AS PPI (NOLOCK) ON PP.Project_ID = PPI.ProjectID
            INNER JOIN Plan_ProjectItemMonth ppim (NOLOCK) ON ppim.PlanProjectItemID = PPI.PlanProjectItem_ID
        WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0

		--Insert Data into Plan_AdjustmentFundingBudgetVersion
		INSERT INTO Plan_AdjustmentFundingBudgetVersion
            ( VersionNumber, VersionName, Comments, CapturerID, DateCaptured )
        VALUES
            (@NewAdjustmentFundingBudgetVersionNumber, @NewAdjustmentFundingBudgetVersionNumber, @Comments, @UserId, GETDATE())

		--Get Inserted ID and Set Value
		SELECT @AdjustmentFundingBudgetVersionId = SCOPE_IDENTITY()

		--Insert Data into Plan_AdjustmentFundingBudgetVersionDetails
		INSERT INTO Plan_AdjustmentFundingBudgetVersionDetails
		(
		    AdjustmentFundingBudgetVersionId,
		    AdjustmentFundingSourceBudgetDetail_ID,
		    AdjustmentFundingSourceBudgetHeaderID,
		    FinancialYear,
		    FundingSourceID,
		    ScoaID,
		    FundingSourceBudget,
		    DateCaptured,
		    CapturerID,
		    UploadedDocument
		)
        SELECT @AdjustmentFundingBudgetVersionId,
                FundingSourceBudgetDetail_ID,
                FundingSourceBudgetHeaderID,
                pfsbh.FinancialYear,
                FundingSourceID,
                ScoaID,
                FundingSourceBudget,
                GETDATE(),
                @UserId,
                UploadedDocument
        FROM Plan_FundingSourceBudget_Header pfsbh (NOLOCK) 
            INNER JOIN Plan_FundingSourceBudget_Detail pfsb (NOLOCK) ON pfsb.FundingSourceBudgetHeaderID = pfsbh.FundingSourceBudgetHeader_ID
        WHERE pfsbh.FinancialYear IN ( @FinYear, @FinYearP1, @FinYearP2 )
		AND pfsb.ScoaID IN (SELECT pf.ScoaID FROM Plan_FundingSourceBudget_Detail pf 
							INNER JOIN Plan_FundingSourceBudget_Header pfh ON pfh.FundingSourceBudgetHeader_ID = pf.FundingSourceBudgetHeaderID 
							WHERE pfh.FinancialYear = @FinYear)

		--Insert Data into Plan_SupplementaryAdjustment
		INSERT INTO dbo.Plan_SupplementaryAdjustment
			( FinancialYear, AdjustmentVersionId, AdjustmentFundingVersionId, IsSupplementaryAdjustment, SupplementaryAdjustmentFileName, IsAdjustmentFinalApproved, FinalApprovedBy, FinalApprovedDate, DateCaptured, CapturerID )
		VALUES
			( @FinYear, @AdjustmentBudgetVersionId, @AdjustmentFundingBudgetVersionId, 1, @SupplementaryAdjustmentFileName, 0, @UserId, GETDATE(), GETDATE(), @UserId )

		--Get Inserted ID and Set Value
		SELECT @SupplementaryAdjustmentId = SCOPE_IDENTITY()

		--Insert Data into Plan_AdjustmentFundingSourceBudget_Header
		INSERT INTO Plan_AdjustmentFundingSourceBudget_Header
		(
		    FinancialYear,
		    Submitted,
		    DateCaptured,
		    CapturerID,
		    RefFundingSourceHeaderId,
		    AdjustmentFundingVersionId
		)
		SELECT 
			FinancialYear,
		    Submitted,
		    GETDATE(),
		    @UserId,
		    FundingSourceBudgetHeader_ID,
		    @AdjustmentFundingBudgetVersionId
		FROM Plan_FundingSourceBudget_Header (NOLOCK) 
		WHERE FinancialYear IN ( @FinYear, @FinYearP1, @FinYearP2 )

		--Insert Data into Plan_AdjustmentFundingSourceBudget_Detail
		INSERT INTO Plan_AdjustmentFundingSourceBudget_Detail
		(
		    AdjustmentFundingSourceBudgetHeaderID,
		    AdjustmentFundingSourceID,
		    ScoaID,
		    FundingSourceBudget,
		    DateCaptured,
		    CapturerID,
		    IsHidden,
		    UploadedDocument,
		    RefFundingSourceDetailId,
		    AdjustmentFundingVersionId
		)
		SELECT 
			pafsbh.AdjustmentFundingSourceBudgetHeader_ID,
		    CASE WHEN pfsb.FundingSourceID = 0 THEN NULL ELSE pfsb.FundingSourceID END,
		    pfsb.ScoaID,
		    pfsb.FundingSourceBudget,
		    GETDATE(),
		    @UserId,
		    pfsb.IsHidden,
		    pfsb.UploadedDocument,
		    pfsb.FundingSourceBudgetDetail_ID,
		    @AdjustmentFundingBudgetVersionId
		FROM  Plan_FundingSourceBudget_Header pfsbh (NOLOCK) 
            INNER JOIN Plan_FundingSourceBudget_Detail pfsb (NOLOCK) ON pfsb.FundingSourceBudgetHeaderID = pfsbh.FundingSourceBudgetHeader_ID
			INNER JOIN Plan_AdjustmentFundingSourceBudget_Header pafsbh (NOLOCK) ON pafsbh.RefFundingSourceHeaderId = pfsbh.FundingSourceBudgetHeader_ID
        WHERE pfsbh.FinancialYear IN ( @FinYear, @FinYearP1, @FinYearP2 ) AND pafsbh.AdjustmentFundingVersionId=@AdjustmentFundingBudgetVersionId
		AND pfsb.ScoaID IN (SELECT pf.ScoaID FROM Plan_FundingSourceBudget_Detail pf 
							INNER JOIN Plan_FundingSourceBudget_Header pfh ON pfh.FundingSourceBudgetHeader_ID = pf.FundingSourceBudgetHeaderID 
							WHERE pfh.FinancialYear = @FinYear)

		--Insert Data into Sys_SupportingDocs
		INSERT INTO Sys_SupportingDocs
		SELECT ssd.Filename
			,'Copied Funding Document'
			,ssd.DocumentAuthor
			,ssd.DocumentDate,10,@SupportDocsGrpId
			,'Plan_AdjustmentFundingSourceBudget_Detail'
			,pafsbd.AdjustmentFundingSourceBudgetDetail_ID
			,ssd.DateImported
			,ssd.ImportedByID
			,GETDATE()
		    ,@UserId
			,NULL
			,NULL
		FROM  Plan_AdjustmentFundingSourceBudget_Detail pafsbd (NOLOCK) 
            INNER JOIN Plan_FundingSourceDocs pfsd (NOLOCK) ON pfsd.FundingSourceBudgetDetailID = pafsbd.RefFundingSourceDetailId
			INNER JOIN Sys_SupportingDocs ssd (NOLOCK) ON ssd.SupportingDocs_ID=pfsd.SupportingDocsID
		WHERE pafsbd.AdjustmentFundingVersionId=@AdjustmentFundingBudgetVersionId

		--Insert Data into Plan_AdjustmentFundingSourceDocs

		INSERT INTO Plan_AdjustmentFundingSourceDocs
		(
		    SupportingDocsID,
		    AdjustmentFundingSourceBudgetDetailID,
		    ScoaID,
		    DateCaptured,
		    CapturerID,
			RefFundingSourceDocsID,
			AdjustmentFundingVersionId
		)
		SELECT 
			ssd.SupportingDocs_ID,
			pafsbd.AdjustmentFundingSourceBudgetDetail_ID,
		    pafsbd.ScoaID,
		    GETDATE(),
		    @UserId,
			pfsd.FundingSourceDocs_ID,
			@AdjustmentFundingBudgetVersionId
		FROM  Plan_AdjustmentFundingSourceBudget_Detail pafsbd (NOLOCK) 
            INNER JOIN Sys_SupportingDocs ssd (NOLOCK) ON ssd.TableLinkedID = pafsbd.AdjustmentFundingSourceBudgetDetail_ID 
			INNER JOIN Plan_FundingSourceDocs pfsd (NOLOCK) ON pfsd.FundingSourceBudgetDetailID = pafsbd.RefFundingSourceDetailId
		WHERE ssd.TableLinkedName ='Plan_AdjustmentFundingSourceBudget_Detail' AND pafsbd.AdjustmentFundingVersionId=@AdjustmentFundingBudgetVersionId


		DECLARE @Project_ID INT, @AdjustmentProject_ID INT, @ProjectFund_ID INT, @AdjustmentProjectFund_ID INT, @ProjectItem_ID INT, @AdjustmentProjectItem_ID INT;

		DECLARE @tblPlanProject TABLE 		
		(
			Project_ID INT, AdjustmentProjectName NVARCHAR(500), AdjustmentProjectDesc NVARCHAR(500), ProjectManagerID INT, SupplyChainOfficialID INT, CapitalOperation INT, CostEstimate DECIMAL, ScoaProjectID INT,EstimatedStartDate DATETIME, EstimatedEndDate DATETIME,
			ProjectStatus INT, CommencementDate DATETIME, FinYear NVARCHAR(9), ProjectDetailDesc NVARCHAR(500), ProjectCategoryID INT, ProjectImplementAgentID INT, Longitude NVARCHAR(200), Latitude NVARCHAR(200), ProgrammeManagerID INT, FinancialControllerID INT,
			ProjectTypeID INT, EstimatedDuration INT, ProjectDistinctionID INT, IsDeleted BIT, HistoricalProjectCode NVARCHAR(100), ProjectParentID INT, SingleMultiYear VARCHAR(5), CapturerID INT,DateCaptured DATETIME, AdjustmentVersionId INT, ProjectCode INT, CostingProject BIT
		)

		DECLARE @tblProjectFund TABLE
		(
			ProjectFund_ID INT, AdjustmentProjectID INT, ScoaFundID INT, FundAmount DECIMAL(16,2), FundReference NVARCHAR(200), VirementId INT, AdjustmentId INT, CapturerID INT, DateCaptured DATETIME, AdjustmentVersionId INT
		)

		DECLARE @ProjectItem TABLE
		(
		   ProjectItem_ID INT, AdjustmentProjectID INT, ProjectItemID INT, SCOAItemID INT, FinYear NVARCHAR(9), ProjectFundYearID INT, SCOAFundId INT, BudgetAmount DECIMAL(16,2), BudgetAmountCurP1 DECIMAL(16,2), BudgetAmountCurP2 DECIMAL(16,2), SCOAFunctionId INT,
		   SCOARegionId INT, DivisionId INT, BudgetSplitID INT, VirementId INT, HistoricalProjectCode NVARCHAR(100), AdjustmentId INT, ModificationNumber INT, SCOACostingID INT, IsItemLocked BIT, CreditDebit VARCHAR(6), AdjutmentType INT, LegislativeReasonAdjustment INT,
		   ReasonForAdjustment NVARCHAR(MAX), CapturerID INT, DateCaptured DATETIME, AdjustmentVersionId INT, IsActiveForSCM BIT, GRAPClassification NVARCHAR(4000), GRAPClassificationNote NVARCHAR(4000), MainSegmentReporting NVARCHAR(4000), SubSegmentReporting NVARCHAR(4000)
		)

		INSERT INTO @tblPlanProject
		    (	Project_ID, AdjustmentProjectName, AdjustmentProjectDesc, ProjectManagerID, SupplyChainOfficialID, CapitalOperation, CostEstimate, ScoaProjectID, EstimatedStartDate, EstimatedEndDate, ProjectStatus, CommencementDate,
		        FinYear, ProjectDetailDesc, ProjectCategoryID, ProjectImplementAgentID, Longitude, Latitude, ProgrammeManagerID, FinancialControllerID, ProjectTypeID, EstimatedDuration, ProjectDistinctionID, IsDeleted,
		        HistoricalProjectCode, ProjectParentID, SingleMultiYear, CapturerID, DateCaptured, AdjustmentVersionId, ProjectCode, CostingProject
		    )
		SELECT
			DISTINCT Project_ID, ProjectName, ProjectDesc, ProjectManagerID, SupplyChainOfficialID, CapitalOperation, CostEstimate, ScoaProjectID, EstimatedStartDate, EstimatedEndDate, 23, CommencementDate,
		    p.FinYear, ProjectDetailDesc, ProjectCategoryID, ProjectImplementAgentID, Longitude, Latitude, ProgrammeManagerID, FinancialControllerID, ProjectTypeID, EstimatedDuration, ProjectDistinctionID, IsDeleted, 
			p.HistoricalProjectCode, ProjectParentID, SingleMultiYear, @UserId, GETDATE(), @AdjustmentBudgetVersionId, ProjectCode, CostingProject
		FROM Plan_Project p (NOLOCK) 
		INNER JOIN dbo.Plan_ProjectItem ppi ON  ppi.ProjectID = p.Project_ID
		WHERE p.FinYear = @FinYear AND ISNULL(IsDeleted, 0) = 0 

		WHILE EXISTS (SELECT 1 FROM @tblPlanProject)
			BEGIN 
			
				SELECT TOP 1 
					@Project_ID = TPAP.Project_ID
					 FROM @tblPlanProject AS TPAP
				--Insert Data into Plan_AdjustmentProject
				INSERT INTO Plan_AdjustmentProject
				(
				    ReferenceProject_ID, AdjustmentProjectName, AdjustmentProjectDesc, ProjectManagerID, SupplyChainOfficialID, CapitalOperation, CostEstimate, ScoaProjectID, EstimatedStartDate, EstimatedEndDate, ProjectStatus, CommencementDate,
				    FinYear, ProjectDetailDesc, ProjectCategoryID, ProjectImplementAgentID, Longitude, Latitude, ProgrammeManagerID, FinancialControllerID, ProjectTypeID, EstimatedDuration, ProjectDistinctionID, IsDeleted,
				    HistoricalProjectCode, ProjectParentID, SingleMultiYear, CapturerID, DateCaptured, AdjustmentVersionId, ProjectCode, CostingProject
				)
				SELECT
						Project_ID, AdjustmentProjectName, AdjustmentProjectDesc, ProjectManagerID, SupplyChainOfficialID, CapitalOperation, CostEstimate, ScoaProjectID, EstimatedStartDate, EstimatedEndDate, ProjectStatus, CommencementDate,
				        FinYear, ProjectDetailDesc, ProjectCategoryID, ProjectImplementAgentID, Longitude, Latitude, ProgrammeManagerID, FinancialControllerID, ProjectTypeID, EstimatedDuration, ProjectDistinctionID, IsDeleted,
				        HistoricalProjectCode, ProjectParentID, SingleMultiYear, CapturerID, DateCaptured, AdjustmentVersionId, ProjectCode, CostingProject
				FROM @tblPlanProject AS TPP WHERE TPP.Project_ID=@Project_ID

				SET @AdjustmentProject_ID=SCOPE_IDENTITY()

				--Insert Data into Plan_AdjustmentProjectCosting
				INSERT INTO Plan_AdjustmentProjectCosting
				(
				    ReferenceProjectCostingID, AdjustmentProjectID, ScoaCostingID, CapturerID, DateCaptured, AdjustmentVersionId
				)
				SELECT 
					PPC.ProjectCosting_ID, @AdjustmentProject_ID, PPC.ScoaCostingID, @UserId, GETDATE(), @AdjustmentBudgetVersionId
				FROM Plan_Project PP (NOLOCK) 
					INNER JOIN Plan_ProjectCosting PPC (NOLOCK) ON PPC.ProjectID = PP.Project_ID
					WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PP.Project_ID = @Project_ID

				--Insert Data into Plan_AdjustmentProjectDivisions
				INSERT INTO Plan_AdjustmentProjectDivisions
				(
				    ReferenceProjectDivisionID, AdjustmentProjectID, DivisionID, CapturerID, DateCaptured, AdjustmentVersionId
				)
				SELECT
					PPD.ProjectDivision_ID, @AdjustmentProject_ID, PPD.DivisionID, @UserId, GETDATE(), @AdjustmentBudgetVersionId 
				FROM Plan_Project PP (NOLOCK) 
					INNER JOIN Plan_ProjectDivisions PPD (NOLOCK) ON PPD.ProjectID = PP.Project_ID
					WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PP.Project_ID = @Project_ID
				
				--Insert Data into Plan_AdjustmentProjectFunctions
				INSERT INTO Plan_AdjustmentProjectFunctions
				(
				    ReferenceProjectFunctionID, AdjustmentProjectID, ScoaFunctionID, CapturerID, DateCaptured, AdjustmentVersionId
				)
				SELECT
					PPF.ProjectFunction_ID, @AdjustmentProject_ID, PPF.ScoaFunctionID, @UserId, GETDATE(), @AdjustmentBudgetVersionId
				FROM Plan_Project PP (NOLOCK) 
					INNER JOIN Plan_ProjectFunctions PPF (NOLOCK) ON PPF.ProjectID = PP.Project_ID
					WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PP.Project_ID = @Project_ID

				--Insert Data into Plan_AdjustmentProjectIDP
				INSERT INTO Plan_AdjustmentProjectIDP
				(
				    ReferenceProjectIDPID, AdjustmentProjectID, ParentIDPItemID, AdjustmentProjectIDPItemID, Percentage, CapturerID, DateCaptured, Latitude, Longitude, AdjustmentVersionId
				)
				SELECT
					PPIDP.ProjectIDP_ID, @AdjustmentProject_ID, PPIDP.ParentIDPItemID, PPIDP.ProjectIDPItemID, PPIDP.Percentage, @UserId, GETDATE(), PPIDP.Latitude, PPIDP.Longitude, @AdjustmentBudgetVersionId
				FROM Plan_Project PP (NOLOCK) 
					INNER JOIN Plan_ProjectIDP PPIDP (NOLOCK) ON PPIDP.ProjectID = PP.Project_ID
				WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PP.Project_ID = @Project_ID

				--Insert Data into Plan_AdjustmentProjectRegions
				INSERT INTO Plan_AdjustmentProjectRegions
				(
				    ReferenceProjectRegionID, AdjustmentProjectID, ScoaRegionID, RegionPercent, CapturerID, DateCaptured, AdjustmentVersionId
				)
				SELECT
					PPR.ProjectRegion_ID, @AdjustmentProject_ID, PPR.ScoaRegionID, PPR.RegionPercent, @UserId, GETDATE(), @AdjustmentBudgetVersionId
				FROM Plan_Project PP (NOLOCK) 
					INNER JOIN Plan_ProjectRegions PPR (NOLOCK) ON PPR.ProjectID = PP.Project_ID
					WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PP.Project_ID=@Project_ID
				
				--Insert Data into @tblProjectFund
				INSERT INTO @tblProjectFund
					( 
						ProjectFund_ID, AdjustmentProjectID, ScoaFundID, FundAmount, FundReference, VirementId, AdjustmentId, CapturerID, DateCaptured, AdjustmentVersionId
					)								
				SELECT
					PPF.ProjectFund_ID, @AdjustmentProject_ID, PPF.ScoaFundID, PPF.FundAmount, PPF.FundReference, PPF.VirementId, PPF.AdjustmentId, @UserId, GETDATE(), @AdjustmentBudgetVersionId
				FROM Plan_Project PP (NOLOCK) 
					INNER JOIN Plan_ProjectFund PPF (NOLOCK) ON PPF.ProjectID = PP.Project_ID
					WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PP.Project_ID = @Project_ID

				WHILE EXISTS (SELECT 1 FROM @tblProjectFund)
				BEGIN 
			
					SELECT TOP 1 
					@ProjectFund_ID = TPF.ProjectFund_ID
					 FROM @tblProjectFund AS TPF

					 --Insert Data into Plan_AdjustmentProjectFund
					 INSERT INTO Plan_AdjustmentProjectFund
					(
					    ReferenceProjectFundID, AdjustmentProjectID, ScoaFundID, FundAmount, FundReference, VirementId, AdjustmentId, CapturerID, DateCaptured, AdjustmentVersionId
					)
					SELECT 
						ProjectFund_ID, AdjustmentProjectID, ScoaFundID, FundAmount, FundReference, VirementId, AdjustmentId, CapturerID, DateCaptured, AdjustmentVersionId
					FROM @tblProjectFund 
						WHERE ProjectFund_ID = @ProjectFund_ID

					SET @AdjustmentProjectFund_ID = SCOPE_IDENTITY()

					--Insert Data into Plan_AdjustmentProjectFundYear
					INSERT INTO Plan_AdjustmentProjectFundYear
					(
					    ReferenceProjectFundYearID, AdjustmentProjectFundID, FinYear, YearFundAmount, VirementId, AdjustmentId, CapturerID, DateCaptured, AdjustmentVersionId 
					)
					SELECT
						PPFY.ProjectFundYear_ID, @AdjustmentProjectFund_ID, PPFY.FinYear, PPFY.YearFundAmount, PPFY.VirementId, PPFY.AdjustmentId, @UserId, GETDATE(), @AdjustmentBudgetVersionId
					FROM Plan_ProjectFundYear PPFY (NOLOCK) 
					INNER JOIN Plan_ProjectFund PPF (NOLOCK) ON PPF.ProjectFund_ID = PPFY.ProjectFundID
					INNER JOIN dbo.Plan_Project PP (NOLOCK) ON PPF.ProjectID = PP.Project_ID
					WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PPFY.ProjectFundID = @ProjectFund_ID

					DELETE FROM @tblProjectFund WHERE ProjectFund_ID = @ProjectFund_ID
				END

				--Insert Data into @ProjectItem
				INSERT INTO @ProjectItem
				( 
					ProjectItem_ID, AdjustmentProjectID, ProjectItemID, SCOAItemID, FinYear, ProjectFundYearID, SCOAFundId, BudgetAmount, BudgetAmountCurP1, BudgetAmountCurP2, SCOAFunctionId, SCOARegionId,
					DivisionId, BudgetSplitID, VirementId, HistoricalProjectCode, AdjustmentId, ModificationNumber, SCOACostingID, IsItemLocked, CreditDebit, AdjutmentType, LegislativeReasonAdjustment, 
					ReasonForAdjustment, CapturerID, DateCaptured, AdjustmentVersionId, IsActiveForSCM, GRAPClassification, GRAPClassificationNote, MainSegmentReporting, SubSegmentReporting
				)
				SELECT
					PPI.PlanProjectItem_ID, @AdjustmentProject_ID, PPI.ProjectItemID, PPI.SCOAItemID, PPI.FinYear, PPI.ProjectFundYearID, PPI.SCOAFundId, PPI.BudgetAmount, PPI.BudgetAmountCurP1, PPI.BudgetAmountCurP2, PPI.SCOAFunctionId, PPI.SCOARegionId,
					PPI.DivisionId, PPI.BudgetSplitID, PPI.VirementId, PPI.HistoricalProjectCode, PPI.AdjustmentId, PPI.ModificationNumber, PPI.SCOACostingID, PPI.IsItemLocked, PPI.CreditDebit, NULL, NULL, 
					NULL, @UserId, GETDATE(), @AdjustmentBudgetVersionId, IsActiveForSCM, GRAPClassification, GRAPClassificationNote, MainSegmentReporting, SubSegmentReporting
				FROM Plan_Project PP (NOLOCK) 
				INNER JOIN Plan_ProjectItem PPI (NOLOCK) ON PPI.ProjectID = PP.Project_ID
				WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PP.Project_ID = @Project_ID	

			WHILE EXISTS (SELECT 1 FROM @ProjectItem)
			BEGIN
				SELECT TOP 1 
					@ProjectItem_ID = PJI.ProjectItem_ID
				 FROM @ProjectItem AS PJI
				
				 INSERT INTO dbo.Plan_AdjustmentProjectItem
				    (  
						ReferencePlanProjectItem_ID, AdjustmentProjectID, ProjectItemID, SCOAItemID, FinYear, ProjectFundYearID, SCOAFundId, BudgetAmount, BudgetAmountCurP1, BudgetAmountCurP2, SCOAFunctionId, SCOARegionId, DivisionId,
						BudgetSplitID, VirementId, HistoricalProjectCode, AdjustmentId, ModificationNumber, SCOACostingID, IsItemLocked, CreditDebit, AdjutmentType, LegislativeReasonAdjustment, ReasonForAdjustment, CapturerID, DateCaptured, 
						AdjustmentVersionId, IsActiveForSCM, GRAPClassification, GRAPClassificationNote, MainSegmentReporting, SubSegmentReporting
				    )
				SELECT
					ProjectItem_ID, AdjustmentProjectID, ProjectItemID, SCOAItemID, FinYear, ProjectFundYearID, SCOAFundId, BudgetAmount, BudgetAmountCurP1, BudgetAmountCurP2, SCOAFunctionId, SCOARegionId, DivisionId,
				    BudgetSplitID, VirementId, HistoricalProjectCode, AdjustmentId, ModificationNumber, SCOACostingID, IsItemLocked, CreditDebit, AdjutmentType, LegislativeReasonAdjustment, ReasonForAdjustment, CapturerID, DateCaptured, 
					AdjustmentVersionId, IsActiveForSCM, GRAPClassification, GRAPClassificationNote, MainSegmentReporting, SubSegmentReporting
				FROM @ProjectItem WHERE ProjectItem_ID=@ProjectItem_ID

				SET @AdjustmentProjectItem_ID=SCOPE_IDENTITY()
						
				--Insert Data into Plan_AdjustmentProjectItemDocs
				INSERT INTO dbo.Plan_AdjustmentProjectItemDocs
				(
				    ReferenceProjectItemDocsID, SupportingDocsID, PlanAdjustmentProjectItemID, DateCaptured, CapturerID, AdjustmentVersionId
				)
				SELECT
					PPID.ProjectItemDocs_ID, PPID.SupportingDocsID, @AdjustmentProjectItem_ID, GETDATE(), @UserId, @AdjustmentBudgetVersionId
				FROM Plan_Project PP (NOLOCK) 
					INNER JOIN Plan_ProjectItem PPI (NOLOCK) ON PPI.ProjectID = PP.Project_ID
					INNER JOIN Plan_ProjectItemDocs PPID (NOLOCK) ON PPID.PlanProjectItemID = PPI.PlanProjectItem_ID
				WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0 AND PPI.PlanProjectItem_ID=@ProjectItem_ID

				--Insert Data into Plan_AdjustmentProjectItemMonth
				INSERT INTO dbo.Plan_AdjustmentProjectItemMonth
					(
						ReferenceProjectItemMonthID, PlanAdjustmentProjectItemID, MonthID, UnitQuantity, UnitPrice, CaptureID, DateCaptured, VirementId, AdjustmentId, AdjustmentVersionId
					)
				SELECT
					PPIM.ProjectItemMonth_ID, @AdjustmentProjectItem_ID, PPIM.MonthID, PPIM.UnitQuantity, PPIM.UnitPrice, @UserId, GETDATE(), PPIM.VirementId, PPIM.AdjustmentId, @AdjustmentBudgetVersionId 
					FROM Plan_Project PP (NOLOCK) 
					INNER JOIN Plan_ProjectItem PPI (NOLOCK) ON PPI.ProjectID = PP.Project_ID
					INNER JOIN Plan_ProjectItemMonth PPIM (NOLOCK) ON PPIM.PlanProjectItemID = PPI.PlanProjectItem_ID
					WHERE PP.FinYear = @FinYear AND ISNULL(PP.IsDeleted, 0) = 0
					AND PPIM.PlanProjectItemID = @ProjectItem_ID AND PPIM.ProjectItemMonth_ID IS NOT NULL

				 DELETE FROM @ProjectItem WHERE ProjectItem_ID = @ProjectItem_ID
			END

				DELETE FROM @tblPlanProject WHERE Project_ID = @Project_ID
			END

		COMMIT TRANSACTION
		SET @ErrorResult = 'Success'

END TRY
BEGIN CATCH
	
	SET @ErrorResult = ERROR_MESSAGE()
    RAISERROR(@ErrorResult, 16, 1)
    ROLLBACK TRANSACTION

END CATCH

	IF @SupplementaryAdjustmentId IS NULL
		SET @SupplementaryAdjustmentId = 0

	SELECT @SupplementaryAdjustmentId AS SupplementaryAdjustmentId, @ErrorResult AS Result
END
GO

/****** Object:  StoredProcedure [dbo].[Plan_TariffSearchByServiceDesc_sp]    Script Date: 2026/03/10 7:23:48 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

--Plan_TariffSearchByServiceDesc_sp 'water','2015/2016'
-- 2016 07 22 Niren Patel Remove table Const_Zoning,Const_UnitTypeofUse & use  Const_PropertyTypeofUse, Const_NTPropertyCategory
-- 2017/04/03 RChetty 55059 Billing removed column and did not fix related functionality
-- 2017 05 03 Brooking C: change property type of use from inner join to left join
-- 2017 22 05 Shah H, Update Period ID, Remove Left Join Billing_CyclePeriod not use
-- 2018 08 08 Niren Patel, #56800
-- 2018 11 29 Niren Patel, #56800 - Updated function Parameter
CREATE PROCEDURE [dbo].[Plan_TariffSearchByServiceDesc_sp]
    @ServiceDesc NVARCHAR(100) ,
    @FinYear NVARCHAR(10)
AS
    BEGIN
        SET NOCOUNT ON;

        SELECT CT.TariffDesc AS 'TariffDesc' ,
                CST.ServiceDesc + ' ('
                + CSM.ServiceModeDesc + ')' AS ServiceDesc ,
                CT.TariffCode ,
                SUM(MRH.Consumption) AS 'Consumption' ,
                COUNT(DISTINCT MRH.MeterID) AS 'TotalMeters' ,
                ( SELECT    COUNT(Services_ID)
                  FROM      dbo.Cons_Services
                  WHERE     dbo.Cons_Services.TariffID = CT.Tariff_ID
                            AND dbo.Cons_Services.ServiceStatusID IN ( 1, 21 )
                ) AS 'NumberOfConsumers' ,
                CTR.MinimumConsumption as TariffMinimum ,
                CTRIC.Cost  as TariffBasic ,
                CTRIC.Cost AS 'TariffFixedRate' ,
                CTR.MaximumConsumption AS TariffMaximum ,
				Convert(varchar(10),CTRIC.Interval) AS 'TariffStepLevels'
                ,NT.Description AS 'NTPropertyCategory' ,
                ISNULL(PT.Description,'empty') AS 'PropertyType'
                ,( SELECT    ScoaShortDesc
                  FROM      Const_SCOA_Structure
                  WHERE     ScoaID = SCOADetails.RevenueControlScoaItemID
                ) AS 'RevenueScoaItem'
        FROM    dbo.Const_Tariff CT
				CROSS APPLY dbo.Billing_GetSCOADetailsBySCOAConfiguration(CT.SCOAConfigurationID,@FinYear) SCOADetails
				INNER JOIN dbo.Const_TariffRate CTR ON CT.Tariff_ID=CTR.TariffID
				INNER JOIN dbo.Const_TariffRateIntervalCost CTRIC ON CTR.TariffRate_ID=CTRIC.TariffRateID
                INNER JOIN dbo.Cons_Services CS ON CS.TariffID = CT.Tariff_ID
                INNER JOIN dbo.Const_ServiceType CST ON CST.ServiceType_ID = CT.ServicetypeID
                INNER JOIN dbo.Const_ServiceMode CSM ON CSM.ServiceMode_ID = CST.ServiceModeID
                INNER JOIN dbo.Const_NTPropertyCategory NT ON NT.NTPropertyCategory_ID = CT.NTPropertyCategoryID
                LEFT JOIN dbo.Const_PropertyTypeOfUse PT ON PT.PropertyTypeOfUse_ID = CT.PropertyTypeOfUseID
                LEFT JOIN dbo.Billing_Meter_Reading_History MRH ON CS.AccountID = MRH.AccountID
                                                              AND CS.UnitID = MRH.PropertyID
                                                              AND CS.MeterID = MRH.MeterID
                                                              AND MRH.FinancialYear = @FinYear
        WHERE   CST.ServiceDesc LIKE '%' + @ServiceDesc + '%'	
        GROUP BY CS.TariffID ,
                CST.ServiceDesc ,
                CSM.ServiceModeDesc ,
                CT.TariffDesc ,
                CT.TariffCode ,
                CT.Tariff_ID ,
                NT.Description ,
                CTR.MinimumConsumption ,--as TariffMinimum ,
                CTRIC.Cost,--  as TariffBasic ,
                CTRIC.Cost,-- AS 'TariffFixedRate' ,
                CTR.MaximumConsumption,-- AS TariffMaximum ,
						CTRIC.Interval,-- AS 'TariffStepLevels'
                PT.Description ,
                SCOADetails.RevenueControlScoaItemID
        ORDER BY CT.TariffCode; 
    END;
	--GO
    SET ANSI_WARNINGS OFF;
GO

/****** Object:  StoredProcedure [dbo].[Plan_UpdateAdjustmentProjectCode_sp]    Script Date: 2026/03/10 7:23:48 AM ******/
SET ANSI_NULLS ON
GO

