GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 2019-01-24
-- Description:	#61596 Planning Financial Year Budget rollover
-- Exec Plan_UpdateAdjustmentProjectCode_sp 1
-- 260319: SNagpal #86037 -> Add new query to get correct ProjectCode
-- 041023: CMoodley #106961 -> Remove writing to audit DB as no longer required
-- EXEC Plan_UpdateAdjustmentProjectCode_sp 990,9
-- =============================================
CREATE PROCEDURE [dbo].[Plan_UpdateAdjustmentProjectCode_sp]
    @ProjectId INT,
	@UserId INT
AS

BEGIN 
	SET XACT_ABORT ON
	SET FMTONLY OFF;
	BEGIN TRY
		BEGIN TRANSACTION ProjectTran

			DECLARE 
				@NewProjectCode INT = 0,
				@FinalResult NVARCHAR(MAX),
				@AdjustmentVersionId INT;

			SELECT @AdjustmentVersionId = AdjustmentVersionId FROM dbo.Plan_AdjustmentProject WHERE AdjustmentProject_ID = @ProjectId;

			--Update ProjectParentID,ProjectCode
			IF EXISTS(SELECT 1 FROM dbo.Plan_AdjustmentProject WHERE AdjustmentVersionId = @AdjustmentVersionId AND ProjectCode IS NOT NULL AND ReferenceProject_ID IS NULL)
			BEGIN
				SELECT @NewProjectCode = MAX(ProjectCode) + 1 FROM dbo.Plan_AdjustmentProject WHERE AdjustmentVersionId = @AdjustmentVersionId
			END
			ELSE
			BEGIN
				SELECT @NewProjectCode = MAX(ProjectCode) + 1 FROM dbo.Plan_Project
			END

			UPDATE dbo.Plan_AdjustmentProject SET ProjectParentID = @ProjectId, ProjectCode = @NewProjectCode WHERE AdjustmentProject_ID = @ProjectId

		COMMIT TRANSACTION ProjectTran

		SET @FinalResult = 'Success'

	END TRY
	BEGIN CATCH
	
		SET @FinalResult = ERROR_MESSAGE()
		RAISERROR(@FinalResult, 16, 1)
		ROLLBACK TRANSACTION ProjectTran

	END CATCH

	SELECT @ProjectId AS ProjectId, @NewProjectCode AS ProjectCode, @FinalResult AS Result

END
GO

