-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 27/11/2017
-- Description:	INSERT data to Audit, UPDATE data to Plan_AdjustmentProject
-- EXEC Plan_UpdateAdjustmentProjectPlan_sp 2,1
-- SNagpal 22-Jan-2017 : Fix the Audit Stuff
-- SNagpal 04-Apr-2019 : #86552 Add [] brackets for Audit database
-- =============================================
CREATE PROCEDURE [dbo].[Plan_UpdateAdjustmentProjectPlan_sp]
    @AdjustmentProjectID INT ,
    @ModifierID INT
AS
    BEGIN
        DECLARE @FMSAuditDBName NVARCHAR(100) ,
            @AuditUser NVARCHAR(250);

        SELECT  @FMSAuditDBName = KeyValue
        FROM    dbo.AAAA_ConfigSettings
        WHERE   KeyName = 'FMSAuditDatabaseName';

		SET @FMSAuditDBName = '[' + @FMSAuditDBName + ']';

        SELECT  @AuditUser = FirstName + ' ' + LastName
        FROM    dbo.User_UserDetail
        WHERE   [User_ID] = @ModifierID; 

        SET NOCOUNT ON;
        DECLARE @sql VARCHAR(MAX)= '';
        SET @sql = ' INSERT INTO  ' + @FMSAuditDBName
            + '.[dbo].[aPlan_AdjustmentProject]
	        ( AuditUserID ,
	          AuditDate ,
	          AuditUser ,
	          AdjustmentProject_ID ,
	          AdjustmentProjectName ,
	          AdjustmentProjectDesc ,
	          ProjectManagerID ,
	          SupplyChainOfficialID ,
	          CapitalOperation ,
	          CostEstimate ,
	          ScoaProjectID ,
	          EstimatedStartDate ,
	          EstimatedEndDate ,
	          ProjectStatus ,
	          CommencementDate ,
	          DateCaptured ,
	          CapturerID ,
	          DateModified ,
	          ModifierID ,
	          FinYear ,
	          ProjectCategoryID ,
	          Longitude ,
	          Latitude ,
	          ProgrammeManagerID ,
	          FinancialControllerID ,
	          ProjectTypeID ,
	          EstimatedDuration ,
	          ProjectDistinctionID ,
	          HistoricalProjectCode,
			  IsDeleted,
			  SingleMultiYear,
			  AdjustmentVersionId,
			  IsRecommended
	        )
			SELECT ''' + CAST(@ModifierID AS VARCHAR(100)) + ''','''
            + CONVERT(NVARCHAR(100), GETDATE(), 121) + ''','''
            + CAST(@AuditUser AS NVARCHAR(200)) + ''',
			  AdjustmentProject_ID ,
                AdjustmentProjectName ,
                AdjustmentProjectDesc ,
                ProjectManagerID ,
                SupplyChainOfficialID ,
                CapitalOperation ,
                CostEstimate ,
                ScoaProjectID ,
                EstimatedStartDate ,
                EstimatedEndDate ,
                ProjectStatus ,
                CommencementDate ,
                DateCaptured ,
                CapturerID ,
                DateModified ,
                ModifierID ,
                FinYear ,
                ProjectCategoryID ,
                Longitude ,
                Latitude ,
                ProgrammeManagerID ,
                FinancialControllerID ,
                ProjectTypeID ,
                EstimatedDuration ,
                ProjectDistinctionID ,
                HistoricalProjectCode ,
                IsDeleted,
				SingleMultiYear,
				AdjustmentVersionId,
				IsRecommended
	   
	   FROM dbo.Plan_AdjustmentProject
	   Where AdjustmentProject_ID = ' + CAST(@AdjustmentProjectID AS VARCHAR(10)) + '';

        EXEC sp_sqlexec @sql;	

	--Update ISDelete Key in Plan_AdjustmentProject given AdjustmentProject_ID

        UPDATE  Plan_AdjustmentProject
        SET     [IsDeleted] = 1 , [ProjectStatus]=5,
                DateModified = GETDATE() ,
                ModifierID = @ModifierID
        WHERE   AdjustmentProject_ID = @AdjustmentProjectID;

    END;
GO

