-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 18 April 2016
-- Description:	INSERT data to Audit, UPDATE data to Plan_Adjustment
--EXEC [Plan_UpdateAdjustmentStatus_sp] FMSAUDIT_DEV,2647,'01/01/2016','Sahil','2015/2016'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_UpdateAdjustmentStatus_sp]
    @FMSAuditDBName NVARCHAR(50) ,
    @AuditUserID INT ,
    @AuditDate DATETIME ,
    @AuditUser NVARCHAR(200) ,
    @ActivFinYear NVARCHAR(20) = 0
AS
    BEGIN
        DECLARE @sql VARCHAR(MAX)= '';
        SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
            + '.[dbo].[aPlan_Adjustment]
                ( 
				[AuditUserID] ,
                [AuditDate] ,
                [AuditUser] ,
				[AdjustmentBudget_Id],
				FinYear ,
				FromProjectId ,
				ToProjectId ,
				FromSCOAProjectID ,
				ToSCOAProjectID ,
				FromSCOAFunctionId ,
				ToSCOAFunctionId ,
				FromDivisionId ,
				ToDivisionId ,
				FromSCOAFundID ,
				ToSCOAFundID ,
				FromSCOARegion ,
				ToSCOARegion ,
				FromSCOAItem ,
				ToSCOAItem ,
				ReasonForAdjustment ,
				TypeOfAdjustment ,
				FromAvailableFund ,
				FromAdjustmentAmount ,
				FromNewAvailableBudget ,
				ToAvailableFund ,
				ToAdjustmentAmount ,
				ToNewAvailableBudget ,
				AdjustmentReferenceNumber ,
				VersionNumber ,
				Status ,
				TransferBy ,
				TransferOn ,
				CapturerID ,
				DateCaptured ,
				ModifierID ,
				DateModified
        )
		SELECT ''' + CAST(@AuditUserID AS VARCHAR(100)) + ''','''
            + CONVERT(NVARCHAR(100), @AuditDate, 121) + ''','''
            + CAST(@AuditUser AS NVARCHAR(200)) + ''',[AdjustmentBudget_Id]
      ,[FinYear]
      ,[FromProjectId]
      ,[ToProjectId]
      ,[FromSCOAProjectID]
      ,[ToSCOAProjectID]
      ,[FromSCOAFunctionId]
      ,[ToSCOAFunctionId]
      ,[FromDivisionId]
      ,[ToDivisionId]
      ,[FromSCOAFundID]
      ,[ToSCOAFundID]
      ,[FromSCOARegion]
      ,[ToSCOARegion]
      ,[FromSCOAItem]
      ,[ToSCOAItem]
      ,[ReasonForAdjustment]
      ,[TypeOfAdjustment]
      ,[FromAvailableFund]
      ,[FromAdjustmentAmount]
      ,[FromNewAvailableBudget]
      ,[ToAvailableFund]
      ,[ToAdjustmentAmount]
      ,[ToNewAvailableBudget]
      ,[AdjustmentReferenceNumber]
      ,[VersionNumber]
      ,[Status]
      ,[TransferBy]
      ,[TransferOn]
      ,[CapturerID]
      ,[DateCaptured]
      ,[ModifierID]
      ,[DateModified]
  FROM [dbo].[Plan_Adjustment]
				Where Status = 100';

        
        EXEC sp_sqlexec @sql;

--Update Status and VersionNumber in Plan_Adjustment for whom Status is Draft

        UPDATE  dbo.Plan_Adjustment
        SET     Status = 101 ,
                VersionNumber = ( SELECT    ( ISNULL(MAX(VersionNumber), 0)
                                              + 1 ) AS VersionNumber
                                  FROM      Plan_Adjustment
                                )
        WHERE   Status = 100; -- FinYear = @ActivFinYear AND
				
    END;


GO

/****** Object:  StoredProcedure [dbo].[Plan_UpdateFundingSourceForAdjustedProjects_sp]    Script Date: 2026/03/10 7:23:48 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Sahil Nagpal
-- Create date: 2017-12-25
-- Plan_UpdateFundingSourceForAdjustedProjects_sp  15565,4793,'2018/2019','2018/2019'
-- SNagpal: 26-05-2018 #79279 - Change ISNULL(pap.AdjustedBudgetAmount,0)  > 0 pap.AdjustedBudgetAmount IS NOT NULL AND pap.ReasonForAdjustment IS NOT NULL
-- =============================================
CREATE PROCEDURE [dbo].[Plan_UpdateFundingSourceForAdjustedProjects_sp]
    @AdjustmentProjectId INT ,
    @UserId NVARCHAR(50),
	@FinYear NVARCHAR(10),
	@UserFinYear NVARCHAR(10)
AS
SET NOCOUNT ON;
    BEGIN

CREATE TABLE #PlanAdjustmentTempTable
(
TempDiffBudgetAmountFirstYear decimal(16,2), 
TempDiffBudgetAmountSecondYear decimal(16,2), 
TempDiffBudgetAmountThirdYear decimal(16,2), 
TempSCOAFundId INT
)

	  DECLARE @FinYearP1 NVARCHAR(9) ,
            @FinYearP2 NVARCHAR(9) ,
            @yearp1 INT ,
            @yearp2 INT ,
            @yearp3 INT,
			@FMSAuditDBName NVARCHAR(50) ,
            @AuditUserID NVARCHAR(50) ,
            @AuditDate NVARCHAR(50) ,
            @AuditUser NVARCHAR(100),
			@ApprovalResult NVARCHAR(MAX) ;

BEGIN TRY
BEGIN TRANSACTION;

	SELECT  @yearp1 = CAST(SUBSTRING(@FinYear, 6, 4) AS INT);
	SELECT  @yearp2 = @yearp1 + 1;
	SELECT  @yearp3 = @yearp1 + 2;
	SELECT  @FinYearP1 = CONVERT(VARCHAR(4), @yearp1) + '/'
	        + CONVERT(VARCHAR(4), @yearp2);
	SELECT  @FinYearP2 = CONVERT(VARCHAR(4), @yearp2) + '/'
                + CONVERT(VARCHAR(4), @yearp3);

	DECLARE @AdjustmentVersionId INT;
	DECLARE @AdjustmentFundingVersionId INT;

	
	SELECT TOP 1 @AdjustmentVersionId = AdjustmentBudgetVersion_ID FROM Plan_AdjustmentBudgetVersion WHERE VersionName 
	LIKE @UserFinYear + '%' ORDER BY AdjustmentBudgetVersion_ID DESC

	SELECT TOP 1 @AdjustmentFundingVersionId = AdjustmentFundingBudgetVersion_ID FROM Plan_AdjustmentFundingBudgetVersion WHERE VersionName 
	LIKE @UserFinYear + '%' ORDER BY AdjustmentFundingBudgetVersion_ID DESC



INSERT INTO #PlanAdjustmentTempTable
	SELECT 
	SUM((ISNULL(pap.BudgetAmount,0) - ISNULL(pap.AdjustedBudgetAmount,0))) AS DiffBudgetAmountFirstYear, 
	SUM((ISNULL(pap.BudgetAmountCurP1,0) - ISNULL(pap.AdjustedBudgetAmountCurP1,0))) AS DiffBudgetAmountSecondYear, 
	SUM((ISNULL(pap.BudgetAmountCurP2,0) - ISNULL(pap.AdjustedBudgetAmountCurP2,0))) AS DiffBudgetAmountThirdYear, 
	pap.SCOAFundId
	FROM dbo.Plan_AdjustmentProjectItem pap WHERE pap.AdjustedBudgetAmount IS NOT NULL AND pap.ReasonForAdjustment IS NOT NULL
	AND pap.AdjustmentProjectID = @AdjustmentProjectId AND pap.AdjustmentVersionId = @AdjustmentVersionId
	GROUP BY pap.SCOAFundId
	HAVING SUM((ISNULL(pap.BudgetAmount,0) - ISNULL(pap.AdjustedBudgetAmount,0))) >= 0
		AND SUM((ISNULL(pap.BudgetAmountCurP1,0) - ISNULL(pap.AdjustedBudgetAmountCurP1,0)))  >= 0
		AND SUM((ISNULL(pap.BudgetAmountCurP2,0) - ISNULL(pap.AdjustedBudgetAmountCurP2,0))) >= 0


IF EXISTS(SELECT 1 FROM #PlanAdjustmentTempTable)
BEGIN

 SELECT  @AuditUser = ISNULL(FirstName, UserName) + ISNULL(LastName, '')
        FROM    dbo.User_UserDetail
        WHERE   [User_ID] = @UserId;  
        SET @AuditDate = CONVERT(NVARCHAR(50), GETDATE());

        SET @AuditUserID = @UserId;

 PRINT 'Updating funding Amounts in Plan_AdjustmentFundingSourceBudget_Detail';

                    DECLARE @sql VARCHAR(MAX)= '';
                    SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                        + '.[dbo].[aPlan_AdjustmentFundingSourceBudget_Detail]
                ( AuditUserID ,
				  AuditDate ,
				  AuditUser ,
				  AdjustmentFundingSourceBudgetDetail_ID ,
				  AdjustmentFundingSourceBudgetHeaderID ,
				  AdjustmentFundingSourceID ,
				  ScoaID ,
				  FundingSourceBudget ,
				  DateCaptured,
				  CapturerID ,
				  DateModified ,
				  ModifierID ,
				  UploadedDocument,
				  AdjustmentFundingVersionId
                )
		SELECT ''' + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate
                        + ''',''' + CAST(@AuditUser AS NVARCHAR(200)) + ''',
				  AdjustmentFundingSourceBudgetDetail_ID ,
				  AdjustmentFundingSourceBudgetHeaderID ,
				  AdjustmentFundingSourceID ,
				  ScoaID ,
				  FundingSourceBudget,
				  DateCaptured ,
				  CapturerID ,
				  DateModified ,
				  ModifierID ,
				  UploadedDocument,
				  ' + Cast(@AdjustmentFundingVersionId AS varchar(500)) + ' FROM Plan_AdjustmentFundingSourceBudget_Detail
                WHERE   ScoaID in ( Select TempSCOAFundId from #PlanAdjustmentTempTable)';
			
                    EXEC sp_sqlexec @sql;

UPDATE pafsd SET pafsd.FundingSourceBudget = (pafsd.FundingSourceBudget - TempDiffBudgetAmountFirstYear)
 FROM dbo.Plan_AdjustmentFundingSourceBudget_Header pafsh
INNER JOIN dbo.Plan_AdjustmentFundingSourceBudget_Detail pafsd ON pafsd.AdjustmentFundingSourceBudgetHeaderID = pafsh.AdjustmentFundingSourceBudgetHeader_ID
INNER JOIN #PlanAdjustmentTempTable patt on patt.TempSCOAFundId = pafsd.ScoaID
WHERE pafsh.FinancialYear= @FinYear AND pafsd.AdjustmentFundingVersionId=@AdjustmentFundingVersionId 

UPDATE pafsd SET pafsd.FundingSourceBudget = (pafsd.FundingSourceBudget - TempDiffBudgetAmountSecondYear)
 FROM dbo.Plan_AdjustmentFundingSourceBudget_Header pafsh
INNER JOIN dbo.Plan_AdjustmentFundingSourceBudget_Detail pafsd ON pafsd.AdjustmentFundingSourceBudgetHeaderID = pafsh.AdjustmentFundingSourceBudgetHeader_ID
INNER JOIN #PlanAdjustmentTempTable patt on patt.TempSCOAFundId = pafsd.ScoaID
WHERE pafsh.FinancialYear= @FinYearP1 AND pafsd.AdjustmentFundingVersionId=@AdjustmentFundingVersionId 

UPDATE pafsd SET pafsd.FundingSourceBudget = (pafsd.FundingSourceBudget - TempDiffBudgetAmountThirdYear)
 FROM dbo.Plan_AdjustmentFundingSourceBudget_Header pafsh
INNER JOIN dbo.Plan_AdjustmentFundingSourceBudget_Detail pafsd ON pafsd.AdjustmentFundingSourceBudgetHeaderID = pafsh.AdjustmentFundingSourceBudgetHeader_ID
INNER JOIN #PlanAdjustmentTempTable patt on patt.TempSCOAFundId = pafsd.ScoaID
WHERE pafsh.FinancialYear= @FinYearP2 AND pafsd.AdjustmentFundingVersionId=@AdjustmentFundingVersionId 

END;

            SET @ApprovalResult = 'success';
            COMMIT TRANSACTION;
        END TRY
        BEGIN CATCH
            DECLARE @Err NVARCHAR(1000);
            SET @Err = ERROR_MESSAGE();
            RAISERROR (@Err, 16,1);
            SET @ApprovalResult = @Err;
            ROLLBACK TRAN;
        END CATCH;

DROP TABLE #PlanAdjustmentTempTable
SELECT  @ApprovalResult AS Result ,@AdjustmentProjectId AS AdjustmentProjectId , CAST(@UserId AS INT) AS Approver;
--SELECT  'resut' AS Result ,1 AS AdjustmentProjectId , CAST(1 AS INT) AS Approver;

    END;
	
GO

/****** Object:  StoredProcedure [dbo].[Plan_UpdateIDPItemInitialization_sp]    Script Date: 2026/03/10 7:23:48 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 26 Feb 2016
-- Description:	INSERT data to Audit, UPDATE data to IDP_Items
--EXEC Plan_UpdateIDPItemInitialization_sp FMSAUDIT_DEV,2647,'01/01/2016','Sahil','2015/2016'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_UpdateIDPItemInitialization_sp]
    @FMSAuditDBName NVARCHAR(50) ,
    @AuditUserID INT ,
    @AuditDate DATETIME ,
    @AuditUser NVARCHAR(200) ,
    @ActivFinYear NVARCHAR(20)
AS
    BEGIN
        DECLARE @sql VARCHAR(MAX)= '';
        SET @sql = ' INSERT  INTO ' + @FMSAuditDBName + '.[dbo].[aIDP_ITEM]
                ( [AuditUserID] ,
                  [AuditDate] ,
                  [AuditUser] ,
                  [Item_ID] ,
                  [ItemDesc] ,
                  [FinancialYear] ,
                  [ItemParentID] ,
                  [IDPLevelNumber] ,
                  [ItemOrderID] ,
                  [CapturerID] ,
                  [DateCaptured] ,
                  [ModifierID] ,
                  [DateModified] ,
                  [NationalKPADetailID],
				  [IDPInitialized]
                )
		SELECT ''' + CAST(@AuditUserID AS VARCHAR(100)) + ''','''
            + CONVERT(NVARCHAR(100), @AuditDate, 121)
            + ''',''' + CAST(@AuditUser AS NVARCHAR(200))
            + ''',Item_ID,ItemDesc,FinancialYear,
				ItemParentID,IDPLevelNumber,ItemOrderID,CapturerID
				,DateCaptured,ModifierID,DateModified,NationalKPADetailID,IDPInitialized FROM IDP_ITEM
				Where FinancialYear = ''' + @ActivFinYear + '''';

        
        EXEC sp_sqlexec @sql;

--Update IDPInitialization in IDPITEM for Active Fin Year

        UPDATE  dbo.IDP_Item
        SET     IDPInitialized = 1
        WHERE   FinancialYear = @ActivFinYear;
    END;

GO

/****** Object:  StoredProcedure [dbo].[Plan_UpdateNTValidations_sp]    Script Date: 2026/03/10 7:23:48 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Nirav Parikh
-- Create date: 08/11/2017
-- Description:	update NTValidations
-- Plan_UpdateNTValidations_sp 5370,5370,1,'2016/2017',1,'EMS_QA_Audit','admin'
-- SNagpal 19-01-2018 -Fix some issues in Stored procedure while inserting And Auditing of NTValidations
-- SNagpal 17-12-2018 - Add FinYear Condition while Auditing.
-- =============================================
CREATE PROCEDURE [dbo].[Plan_UpdateNTValidations_sp]
    @SCOAItemId INT ,
	@SCOAFunctionId INT ,
    @UserId INT ,
    @FinYear VARCHAR(9) ,
    @IsEnable BIT ,
    @FMSAuditDBName NVARCHAR(50) ,
    @AuditUser NVARCHAR(200)
AS
    BEGIN

        SET NOCOUNT ON;
        BEGIN TRY
            BEGIN TRANSACTION;
            DECLARE @ParentId INT = 0 ,
                @AuditGUID UNIQUEIDENTIFIER ,
                @Auditsql VARCHAR(MAX)= '' ,
                @CurrDate DATETIME = GETDATE();

            DECLARE @tempSCOATable AS TABLE
                (
                  RESULT VARCHAR(10) ,
                  SuccessMessage VARCHAR(100)
                );

			--Insert NTValidations If not Exists
            INSERT  INTO @tempSCOATable
                    EXEC Plan_InsertNTValidations_sp @SCOAItemId, @SCOAFunctionId, @UserId,
                        @FinYear, @IsEnable, @AuditUser;

            WHILE @SCOAItemId > 0 AND @SCOAFunctionId > 0
                BEGIN

                    SELECT  @SCOAItemId = A.ScoaItemId ,
							@SCOAFunctionId = A.ScoaFunctionId ,
                            @ParentId = B.ScoaParentID
                    FROM    dbo.Const_PlanNTValidations A
                            INNER JOIN dbo.Const_SCOA_Structure B ON B.ScoaID = A.ScoaItemId
							INNER JOIN dbo.Const_SCOA_Function_Structure C ON C.ScoaID = A.ScoaFunctionId
                    WHERE   A.ScoaItemId = @SCOAItemId AND A.ScoaFunctionId = @SCOAFunctionId AND A.FinYear = @FinYear;

                    DECLARE @ActiveCnt INT = 0;

                    SELECT  @ActiveCnt = COUNT(A.ScoaItemId)
                    FROM    dbo.Const_PlanNTValidations A
                            INNER JOIN dbo.Const_SCOA_Structure B ON B.ScoaID = A.ScoaItemId
							INNER JOIN dbo.Const_SCOA_Function_Structure C ON C.ScoaID = A.ScoaFunctionId
                    WHERE   A.ScoaItemId <> @SCOAItemId AND A.ScoaFunctionId <> @SCOAFunctionId
                            AND B.ScoaParentID = @ParentId AND A.IsEnable = 1 AND A.FinYear = @FinYear;

                    SET @AuditGUID = NEWID();
					--Insert into Audit Table
                    SET @Auditsql = ' INSERT  INTO ' + @FMSAuditDBName
                        + '.dbo.aConst_PlanNTValidations
							( AuditUserID, AuditDate, AuditUser, AuditGuid,
							  NTValidation_Id, ScoaItemId, ScoaFunctionId, IsEnable,BudgetType,FinYear,
							  CapturerID, DateCaptured, ModifierID, DateModified
							)
								SELECT ''' + CAST(@UserId AS VARCHAR(100)) + ''','''
											+ CONVERT(NVARCHAR(100), @CurrDate, 121) + ''','''
											+ CAST(@AuditUser AS NVARCHAR(200)) + ''','''
											+ CAST(@AuditGUID AS NVARCHAR(200))
											+ ''',
								 NTValidation_Id, ScoaItemId, ScoaFunctionId, IsEnable,BudgetType,FinYear,
								CapturerID, DateCaptured, ModifierID, DateModified
								FROM Const_PlanNTValidations WHERE ScoaItemId= '''
											+ CAST(@SCOAItemId AS NVARCHAR(200)) + ''' and ScoaFunctionId= '''
											+ CAST(@SCOAFunctionId AS NVARCHAR(200)) + '''  and FinYear = ''' + CAST(@FinYear AS NVARCHAR(200)) + '''';;

                    EXEC sp_sqlexec @Auditsql;

					-- Update to Disable @SCOAItemId
                    UPDATE  Const_PlanNTValidations
                    SET     IsEnable = @IsEnable ,
                            ModifierID = @UserId ,
                            DateModified = ''
                            + CONVERT(NVARCHAR(100), @CurrDate, 121) + ''
                    WHERE   ScoaItemId = @SCOAItemId AND ScoaFunctionId = @SCOAFunctionId
                            AND FinYear = @FinYear;
  
                    INSERT  INTO dbo.Sys_AuditLog
                            ( UserID ,
                              AuditDesc ,
                              AuditDate ,
                              AuditComment ,
                              ActiveFinYear_UserFinYear ,
                              TableName ,
                              ModuleID ,
                              RecordID ,
                              AuditGuid
                            )
                    VALUES  ( @UserId ,
                              'Update Const_PlanNTValidations' ,
                              '' + CONVERT(NVARCHAR(100), @CurrDate, 121) + '' ,
                              'Update NT Validations' ,
                              @FinYear ,
                              'Const_PlanNTValidations' ,
                              10 ,
                              @SCOAItemId ,
                              @AuditGUID
                            );

                    IF @ActiveCnt = 0
                        BEGIN
                            SET @SCOAItemId = @ParentId;
 
                        END;
                    ELSE
                        BEGIN
                            SET @SCOAItemId = 0;
                            SET @ParentId = 0;
                        END;
                END;

            COMMIT TRANSACTION;
	
            SELECT  'Success' AS Result ,
                    'NT Validations Updated' AS SuccessMessage;
        END TRY
        BEGIN CATCH
            IF @@Trancount > 0
                BEGIN 
                    ROLLBACK TRANSACTION;
                    INSERT  INTO Sys_ErrorLog
                            ( moduleName ,
                              pageName ,
                              procedureName ,
                              errorMessage ,
                              errorType ,
                              detailedErrorMessage ,
                              errorDate ,
                              userName
                            )
                    VALUES  ( 'Planning' ,
                              'SQL Server' ,
                              'Plan_UpdateNTValidations_sp' ,
                              ERROR_MESSAGE() ,
                              'SQL' ,
                              ERROR_MESSAGE() ,
                              '' + CONVERT(NVARCHAR(100), @CurrDate, 121) + '' ,
                              @AuditUser
                            );
		
                    DECLARE @Err NVARCHAR(1000);
                    SET @Err = ERROR_MESSAGE();
                    RAISERROR (@Err, 16,1);
		
                    SELECT  @Err AS 'Result' ,
                            'An Error Occured' AS SuccessMessage;
                END;
        END CATCH;
    END;

GO

/****** Object:  StoredProcedure [dbo].[Plan_UpdateProjectCode_sp]    Script Date: 2026/03/10 7:23:48 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: 2019-01-23
-- Description:	#61596 Planning Financial Year Budget rollover
-- 041023: CMoodley #106961 -> Remove writing to audit DB as no longer required
-- Exec Plan_UpdateProjectCode_sp 1
-- =============================================
CREATE PROCEDURE [dbo].[Plan_UpdateProjectCode_sp]
    @ProjectId INT,
	@UserId INT
AS

BEGIN 
	SET XACT_ABORT ON
	SET FMTONLY OFF;
	BEGIN TRY
		BEGIN TRANSACTION ProjectTran

			DECLARE 
				@NewProjectCode INT = 0,
				@FinalResult NVARCHAR(MAX);

			--Update ProjectParentID,ProjectCode
			SELECT @NewProjectCode = MAX(ProjectCode) + 1 FROM dbo.Plan_Project

			UPDATE dbo.Plan_Project SET ProjectParentID = @ProjectId, ProjectCode = @NewProjectCode WHERE Project_ID = @ProjectId

		COMMIT TRANSACTION ProjectTran

		SET @FinalResult = 'Success'

	END TRY
	BEGIN CATCH
	
		SET @FinalResult = ERROR_MESSAGE()
		RAISERROR(@FinalResult, 16, 1)
		ROLLBACK TRANSACTION ProjectTran

	END CATCH

	SELECT @ProjectId AS ProjectId, @NewProjectCode AS ProjectCode, @FinalResult AS Result

END
GO

/****** Object:  StoredProcedure [dbo].[Plan_UpdateProjectFundAndItemForAdjustment_sp]    Script Date: 2026/03/10 7:23:48 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Jignesh Prajapati
-- Create date: 2016-04-20
-- Description:	Transfer Adjustment Amount to Fund and Item Details with AdjustmentId to Audit tables 
--				Update Tables Plan_ProjectFund, Plan_ProjectFundYear, Plan_ProjectItem, Plan_ProjectItemMonth for From-To Project 
-- NOTE: this SP is used with Plan_SaveAdjustmentBudgetApprovalRejection_sp with Transaction, so no Transaction statement added Here
-- CALL SP: Plan_UpdateProjectFundAndItemForAdjustment_sp 17,2647
-- 2016-04-22 by JP : Add Update logic for Project Item in CASE 2
-- 2017-03-18 by SNagpal: Rename CaptureID column name into aPlan_ProjectItemMonth
-- SNagpal 04-Apr-2019 : #86552 Add [] brackets for Audit database
-- =============================================
CREATE PROCEDURE [dbo].[Plan_UpdateProjectFundAndItemForAdjustment_sp]
    @AdjustmentId NVARCHAR(50) ,
    @UserId NVARCHAR(50)
AS
    BEGIN
	
-----------------------------------------------------------------------------
-- GET Adjustment Details
-- VARIABLE FOR SETTING VALUE OF Adjustment
-----------------------------------------------------------------------------
        DECLARE @FinYear NVARCHAR(9) ,
            @FromProjectId NVARCHAR(50) ,
            @ToProjectId NVARCHAR(50) ,
            @FromSCOAProjectID NVARCHAR(50) ,
            @ToSCOAProjectID NVARCHAR(50) ,
            @FromSCOAFunctionId NVARCHAR(50) ,
            @ToSCOAFunctionId NVARCHAR(50) ,
            @FromDivisionId NVARCHAR(50) ,
            @ToDivisionId NVARCHAR(50) ,
            @FromSCOAFundID NVARCHAR(50) ,
            @ToSCOAFundID NVARCHAR(50) ,
            @FromSCOARegion NVARCHAR(50) ,
            @ToSCOARegion NVARCHAR(50) ,
            @FromSCOAItem NVARCHAR(50) ,
            @ToSCOAItem NVARCHAR(50) ,
            @ReasonForAdjustment NVARCHAR(MAX) ,
            @FromAvailableFund NVARCHAR(50) ,
            @FromAdjustmentAmount NVARCHAR(50) ,
            @FromNewAvailableBudget NVARCHAR(50) ,
            @ToAvailableFund NVARCHAR(50) ,
            @ToAdjustmentAmount NVARCHAR(50) ,
            @ToNewAvailableBudget NVARCHAR(50);

        SELECT  @FinYear = FinYear ,
                @FromProjectId = FromProjectId ,
                @ToProjectId = ToProjectId ,
                @FromSCOAProjectID = FromSCOAProjectID ,
                @ToSCOAProjectID = ToSCOAProjectID ,
                @FromSCOAFunctionId = FromSCOAFunctionId ,
                @ToSCOAFunctionId = ToSCOAFunctionId ,
                @FromDivisionId = FromDivisionId ,
                @ToDivisionId = ToDivisionId ,
                @FromSCOAFundID = FromSCOAFundID ,
                @ToSCOAFundID = ToSCOAFundID ,
                @FromSCOARegion = FromSCOARegion ,
                @ToSCOARegion = ToSCOARegion ,
                @FromSCOAItem = FromSCOAItem ,
                @ToSCOAItem = ToSCOAItem ,
                @FromAvailableFund = FromAvailableFund ,
                @FromAdjustmentAmount = FromAdjustmentAmount ,
                @FromNewAvailableBudget = FromNewAvailableBudget ,
                @ToAvailableFund = ToAvailableFund ,
                @ToAdjustmentAmount = ToAdjustmentAmount ,
                @ToNewAvailableBudget = ToNewAvailableBudget
        FROM    dbo.Plan_Adjustment
        WHERE   AdjustmentBudget_Id = @AdjustmentId;	 

        DECLARE @CalcAvailableBudget DECIMAL(18, 2) ,
            @ApprovalResult NVARCHAR(MAX) ,
            @DeductAdjustmentAmount DECIMAL(18, 2) ,
            @ItemMonthAmount DECIMAL(18, 2) ,
            @Month NVARCHAR(50) ,
            @ProjectItemMonthId NVARCHAR(50) ,
            @FMSAuditDBName NVARCHAR(50) ,
            @AuditUserID NVARCHAR(50) ,
            @AuditDate NVARCHAR(50) ,
            @AuditUser NVARCHAR(100);


        SELECT  @FMSAuditDBName = KeyValue
        FROM    dbo.AAAA_ConfigSettings
        WHERE   KeyName = 'FMSAuditDatabaseName';

		SET @FMSAuditDBName = '[' + @FMSAuditDBName + ']';

        SELECT  @AuditUser = ISNULL(FirstName, UserName) + ISNULL(LastName, '')
        FROM    dbo.User_UserDetail
        WHERE   [User_ID] = @UserId;  
        SET @AuditDate = CONVERT(NVARCHAR(50), GETDATE());

        SET @AuditUserID = @UserId;

        IF ( @FromProjectId <> @ToProjectId )
            BEGIN
                PRINT 'CASE 1';

                PRINT 'Updating From Project Details in Plan_ProjectFund and Plan_ProjectFundYear';

                DECLARE @sql VARCHAR(MAX)= '';
                SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                    + '.[dbo].[aPlan_ProjectFund]
                ( AuditUserID ,
				  AuditDate ,
				  AuditUser ,
				  ProjectFund_ID ,
				  ProjectID ,
				  ScoaFundID ,
				  FundAmount ,
				  DateCaptured ,
				  CapturerID ,
				  DateModified ,
				  ModifierID ,
				  AdjustmentId
                )
		SELECT ''' + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate
                    + ''',''' + CAST(@AuditUser AS NVARCHAR(200)) + ''',
				  ProjectFund_ID ,
				  ProjectID ,
				  ScoaFundID ,
				  FundAmount ,
				  DateCaptured ,
				  CapturerID ,
				  DateModified ,
				  ModifierID ,
				  ' + @AdjustmentId + ' FROM Plan_ProjectFund
                WHERE   ProjectID =' + @FromProjectId + ' AND ScoaFundID = '
                    + @FromSCOAFundID;
			
                EXEC sp_sqlexec @sql;
				
                --SELECT  * 
                UPDATE  Plan_ProjectFund
                SET     FundAmount = FundAmount - @ToAdjustmentAmount
                FROM    Plan_ProjectFund
                WHERE   ProjectID = @FromProjectId
                        AND ScoaFundID = @FromSCOAFundID;
				
                SET @sql = '';
                SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                    + '.[dbo].[aPlan_ProjectFundYear]
                (	AuditUserID ,
					AuditDate ,
					AuditUser ,
					ProjectFundYear_ID ,
					ProjectFundID ,
					FinYear ,
					YearFundAmount ,
					CapturerID ,
					DateCaptured ,
					ModifierID ,
					DateModified ,
					AdjustmentId
                )
		SELECT ''' + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate
                    + ''',''' + CAST(@AuditUser AS NVARCHAR(200)) + ''',
					PPFY.ProjectFundYear_ID ,
					PPFY.ProjectFundID ,
					PPFY.FinYear ,
					PPFY.YearFundAmount ,
					PPFY.CapturerID ,
					PPFY.DateCaptured ,
					PPFY.ModifierID ,
					PPFY.DateModified ,
				  ' + @AdjustmentId
                    + ' FROM    Plan_ProjectFundYear PPFY
                        INNER JOIN Plan_ProjectFund PPF ON PPF.ProjectFund_ID = PPFY.ProjectFundID
                WHERE   PPF.ProjectID = ' + @FromProjectId
                    + ' AND PPF.ScoaFundID = ' + @FromSCOAFundID
                    + ' AND PPFY.FinYear = ''' + @FinYear + '''';

                EXEC sp_sqlexec @sql;

                --SELECT TOP 1 *
                UPDATE  Plan_ProjectFundYear
                SET     YearFundAmount = YearFundAmount - @ToAdjustmentAmount
                FROM    Plan_ProjectFundYear
                        INNER JOIN Plan_ProjectFund PPF ON PPF.ProjectFund_ID = Plan_ProjectFundYear.ProjectFundID
                WHERE   PPF.ProjectID = @FromProjectId
                        AND PPF.ScoaFundID = @FromSCOAFundID
                        AND Plan_ProjectFundYear.FinYear = @FinYear;

                SET @sql = '';
                SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                    + '.[dbo].[aPlan_ProjectItem]
                (	AuditUserID ,
					AuditDate ,
					AuditUser ,
					PlanProjectItem_ID ,
					ProjectID ,
					ProjectItemID ,
					SCOAItemID ,
					FinYear ,
					CapturerID ,
					DateCaptured ,
					ModifierID ,
					DateModified ,
					ProjectFundYearID ,
					BudgetAmount ,
					BudgetAmountCurP1 ,
					BudgetAmountCurP2 ,
					SCOAFunctionId ,
					SCOAFundId ,
					SCOARegionId ,
					HistoricalProjectCode ,
					DivisionId ,
					BudgetSplitID ,
					AdjustmentId
                )
		SELECT ''' + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate
                    + ''',''' + CAST(@AuditUser AS NVARCHAR(200)) + ''',
					PlanProjectItem_ID ,
					ProjectID ,
					ProjectItemID ,
					SCOAItemID ,
					FinYear ,
					CapturerID ,
					DateCaptured ,
					ModifierID ,
					DateModified ,
					ProjectFundYearID ,
					BudgetAmount ,
					BudgetAmountCurP1 ,
					BudgetAmountCurP2 ,
					SCOAFunctionId ,
					SCOAFundId ,
					SCOARegionId ,
					'''' ,
					DivisionId ,
					BudgetSplitID ,
				  ' + @AdjustmentId + ' FROM    dbo.Plan_ProjectItem 
                WHERE   ProjectID = ' + @FromProjectId + ' AND SCOAItemID = '
                    + @FromSCOAItem + ' AND FinYear = ''' + @FinYear + ''''
                    + ' AND SCOAFunctionId =' + @FromSCOAFunctionId
                    + ' AND SCOAFundId =' + @FromSCOAFundID
                    + ' AND SCOARegionId =' + @FromSCOARegion
                    + ' AND DivisionId =' + @FromDivisionId;

                EXEC sp_sqlexec @sql;

				--SELECT TOP 1  *
                UPDATE  Plan_ProjectItem
                SET     BudgetAmount = BudgetAmount - @ToAdjustmentAmount
                FROM    dbo.Plan_ProjectItem
                WHERE   ProjectID = @FromProjectId
                        AND SCOAItemID = @FromSCOAItem
                        AND FinYear = @FinYear
                        AND SCOAFunctionId = @FromSCOAFunctionId
                        AND SCOAFundId = @FromSCOAFundID
                        AND SCOARegionId = @FromSCOARegion
                        AND DivisionId = @FromDivisionId;

                SET @Month = 1;
                SET @DeductAdjustmentAmount = @ToAdjustmentAmount;
                
                WHILE ( @Month <= 12
                        AND @DeductAdjustmentAmount > 0
                      )
                    BEGIN

                        SELECT  @ItemMonthAmount = ISNULL(UnitPrice, 0) ,
                                @ProjectItemMonthId = ProjectItemMonth_ID
                        FROM    dbo.Plan_ProjectItemMonth PPIM
                                INNER JOIN dbo.Plan_ProjectItem PPI ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                        WHERE   PPI.ProjectID = @FromProjectId
                                AND PPI.SCOAItemID = @FromSCOAItem
                                AND PPI.FinYear = @FinYear
                                AND PPI.SCOAFunctionId = @FromSCOAFunctionId
                                AND PPI.SCOAFundId = @FromSCOAFundID
                                AND PPI.SCOARegionId = @FromSCOARegion
                                AND PPI.DivisionId = @FromDivisionId
                                AND PPIM.MonthID = @Month;
				
                        IF ( @ItemMonthAmount > 0 )
                            BEGIN
                                SET @sql = '';
                                SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                                    + '.[dbo].[aPlan_ProjectItemMonth]
											(	AuditUserID ,
												AuditDate ,
												AuditUser ,
												ProjectItemMonth_ID ,
												PlanProjectItemID ,
												MonthID ,
												UnitQuantity ,
												UnitPrice ,
												CaptureID ,
												DateCaptured ,
												ModifierID ,
												DateModified ,
												AdjustmentId
											)
										SELECT '''
                                    + CAST(@AuditUserID AS VARCHAR(100))
                                    + ''',''' + @AuditDate + ''','''
                                    + CAST(@AuditUser AS NVARCHAR(200)) + ''',
												PPIM.ProjectItemMonth_ID ,
												PPIM.PlanProjectItemID ,
												PPIM.MonthID ,
												PPIM.UnitQuantity ,
												PPIM.UnitPrice ,
												PPIM.CaptureID ,
												PPIM.DateCaptured ,
												PPIM.ModifierID ,
												PPIM.DateModified ,
								' + @AdjustmentId
                                    + ' FROM    dbo.Plan_ProjectItemMonth PPIM
                                WHERE   PPIM.ProjectItemMonth_ID = '
                                    + @ProjectItemMonthId;

                                --PRINT @sql;

                                EXEC sp_sqlexec @sql;
                            END;
		

                        IF ( @DeductAdjustmentAmount >= @ItemMonthAmount
                             AND @ItemMonthAmount > 0
                           )
                            BEGIN
                                UPDATE  dbo.Plan_ProjectItemMonth
                                SET     UnitPrice = UnitPrice
                                        - @ItemMonthAmount
                                FROM    dbo.Plan_ProjectItemMonth PPIM
                                WHERE   PPIM.ProjectItemMonth_ID = @ProjectItemMonthId; 

                                SET @DeductAdjustmentAmount = @DeductAdjustmentAmount
                                    - @ItemMonthAmount;
                            END;
                        ELSE
                            IF ( @DeductAdjustmentAmount < @ItemMonthAmount )
                                BEGIN
                                    UPDATE  dbo.Plan_ProjectItemMonth
                                    SET     UnitPrice = UnitPrice
                                            - @DeductAdjustmentAmount
                                    FROM    dbo.Plan_ProjectItemMonth PPIM
                                            INNER JOIN dbo.Plan_ProjectItem PPI ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                                    WHERE   PPIM.ProjectItemMonth_ID = @ProjectItemMonthId; 

                                    SET @DeductAdjustmentAmount = 0;
                                END;

                        SET @Month = @Month + 1;
                    END;

                SET @DeductAdjustmentAmount = 0;
                SET @ProjectItemMonthId = 0;
                SET @ItemMonthAmount = 0;
                SET @Month = 0;

                PRINT 'Updating To Project Details in Plan_ProjectFund and Plan_ProjectFundYear';

                SET @sql = '';
                SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                    + '.[dbo].[aPlan_ProjectFund]
                ( AuditUserID ,
				  AuditDate ,
				  AuditUser ,
				  ProjectFund_ID ,
				  ProjectID ,
				  ScoaFundID ,
				  FundAmount ,
				  DateCaptured ,
				  CapturerID ,
				  DateModified ,
				  ModifierID ,
				  AdjustmentId
                )
		SELECT ''' + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate
                    + ''',''' + CAST(@AuditUser AS NVARCHAR(200)) + ''',
				  ProjectFund_ID ,
				  ProjectID ,
				  ScoaFundID ,
				  FundAmount ,
				  DateCaptured ,
				  CapturerID ,
				  DateModified ,
				  ModifierID ,
				  ' + @AdjustmentId + ' FROM Plan_ProjectFund
                WHERE   ProjectID =' + @ToProjectId + ' AND ScoaFundID = '
                    + @ToSCOAFundID;
        
                EXEC sp_sqlexec @sql;

                --SELECT TOP 1  *
                UPDATE  Plan_ProjectFund
                SET     FundAmount = FundAmount + @ToAdjustmentAmount
                FROM    Plan_ProjectFund
                WHERE   ProjectID = @ToProjectId
                        AND ScoaFundID = @ToSCOAFundID;

                SET @sql = '';
                SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                    + '.[dbo].[aPlan_ProjectFundYear]
                (	AuditUserID ,
					AuditDate ,
					AuditUser ,
					ProjectFundYear_ID ,
					ProjectFundID ,
					FinYear ,
					YearFundAmount ,
					CapturerID ,
					DateCaptured ,
					ModifierID ,
					DateModified ,
					AdjustmentId
                )
		SELECT ''' + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate
                    + ''',''' + CAST(@AuditUser AS NVARCHAR(200)) + ''',
					PPFY.ProjectFundYear_ID ,
					PPFY.ProjectFundID ,
					PPFY.FinYear ,
					PPFY.YearFundAmount ,
					PPFY.CapturerID ,
					PPFY.DateCaptured ,
					PPFY.ModifierID ,
					PPFY.DateModified ,
				  ' + @AdjustmentId
                    + ' FROM    Plan_ProjectFundYear PPFY
                        INNER JOIN Plan_ProjectFund PPF ON PPF.ProjectFund_ID = PPFY.ProjectFundID
                WHERE   PPF.ProjectID = ' + @ToProjectId
                    + ' AND PPF.ScoaFundID = ' + @ToSCOAFundID
                    + ' AND PPFY.FinYear = ''' + @FinYear + '''';

                EXEC sp_sqlexec @sql;

                --SELECT TOP 1  *
                UPDATE  Plan_ProjectFundYear
                SET     Plan_ProjectFundYear.YearFundAmount = YearFundAmount
                        + @ToAdjustmentAmount
                FROM    Plan_ProjectFundYear PPFY
                        INNER JOIN Plan_ProjectFund PPF ON PPF.ProjectFund_ID = PPFY.ProjectFundID
                WHERE   PPF.ProjectID = @ToProjectId
                        AND PPF.ScoaFundID = @ToSCOAFundID
                        AND PPFY.FinYear = @FinYear;

                SET @sql = '';
                SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                    + '.[dbo].[aPlan_ProjectItem]
                (	AuditUserID ,
					AuditDate ,
					AuditUser ,
					PlanProjectItem_ID ,
					ProjectID ,
					ProjectItemID ,
					SCOAItemID ,
					FinYear ,
					CapturerID ,
					DateCaptured ,
					ModifierID ,
					DateModified ,
					ProjectFundYearID ,
					BudgetAmount ,
					BudgetAmountCurP1 ,
					BudgetAmountCurP2 ,
					SCOAFunctionId ,
					SCOAFundId ,
					SCOARegionId ,
					HistoricalProjectCode ,
					DivisionId ,
					BudgetSplitID ,
					AdjustmentId
                )
		SELECT ''' + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate
                    + ''',''' + CAST(@AuditUser AS NVARCHAR(200)) + ''',
					PlanProjectItem_ID ,
					ProjectID ,
					ProjectItemID ,
					SCOAItemID ,
					FinYear ,
					CapturerID ,
					DateCaptured ,
					ModifierID ,
					DateModified ,
					ProjectFundYearID ,
					BudgetAmount ,
					BudgetAmountCurP1 ,
					BudgetAmountCurP2 ,
					SCOAFunctionId ,
					SCOAFundId ,
					SCOARegionId ,
					'''' ,
					DivisionId ,
					BudgetSplitID ,
				  ' + @AdjustmentId + ' FROM    dbo.Plan_ProjectItem
                WHERE   ProjectID = ' + @ToProjectId + ' AND SCOAItemID ='
                    + @ToSCOAItem + ' AND FinYear = ''' + @FinYear + ''''
                    + ' AND SCOAFunctionId =' + @ToSCOAFunctionId
                    + ' AND SCOAFundId =' + @ToSCOAFundID
                    + ' AND SCOARegionId =' + @ToSCOARegion
                    + ' AND DivisionId =' + @ToDivisionId;

                EXEC sp_sqlexec @sql;

                --SELECT TOP 1  *
                UPDATE  Plan_ProjectItem
                SET     BudgetAmount = BudgetAmount + @ToAdjustmentAmount
                FROM    dbo.Plan_ProjectItem
                WHERE   ProjectID = @ToProjectId
                        AND SCOAItemID = @ToSCOAItem
                        AND FinYear = @FinYear
                        AND SCOAFunctionId = @ToSCOAFunctionId
                        AND SCOAFundId = @ToSCOAFundID
                        AND SCOARegionId = @ToSCOARegion
                        AND DivisionId = @ToDivisionId;

                SET @sql = '';
                SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                    + '.[dbo].[aPlan_ProjectItemMonth]
											(	AuditUserID ,
												AuditDate ,
												AuditUser ,
												ProjectItemMonth_ID ,
												PlanProjectItemID ,
												MonthID ,
												UnitQuantity ,
												UnitPrice ,
												CaptureID ,
												DateCaptured ,
												ModifierID ,
												DateModified ,
												AdjustmentId
											)
										SELECT '''
                    + CAST(@AuditUserID AS VARCHAR(100)) + ''','''
                    + @AuditDate + ''',''' + CAST(@AuditUser AS NVARCHAR(200))
                    + ''',
												PPIM.ProjectItemMonth_ID ,
												PPIM.PlanProjectItemID ,
												PPIM.MonthID ,
												PPIM.UnitQuantity ,
												PPIM.UnitPrice ,
												PPIM.CaptureID ,
												PPIM.DateCaptured ,
												PPIM.ModifierID ,
												PPIM.DateModified ,
								' + @AdjustmentId
                    + ' FROM    dbo.Plan_ProjectItemMonth PPIM
                        INNER JOIN dbo.Plan_ProjectItem PPI ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                WHERE   PPI.ProjectID = ' + @ToProjectId
                    + ' AND PPI.SCOAItemID = ' + @ToSCOAItem
                    + ' AND PPI.FinYear = ''' + @FinYear + ''''
                    + ' AND PPI.SCOAFunctionId = ' + @ToSCOAFunctionId
                    + ' AND PPI.SCOAFundId = ' + @ToSCOAFundID
                    + ' AND PPI.SCOARegionId = ' + @ToSCOARegion
                    + ' AND PPI.DivisionId = ' + @ToDivisionId
                    + ' AND PPIM.MonthID = 12';

                EXEC sp_sqlexec @sql;

                --SELECT TOP 1  *
                UPDATE  dbo.Plan_ProjectItemMonth
                SET     UnitPrice = UnitPrice + @ToAdjustmentAmount
                FROM    dbo.Plan_ProjectItemMonth PPIM
                        INNER JOIN dbo.Plan_ProjectItem PPI ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                WHERE   PPI.ProjectID = @ToProjectId
                        AND PPI.SCOAItemID = @ToSCOAItem
                        AND PPI.FinYear = @FinYear
                        AND PPI.SCOAFunctionId = @ToSCOAFunctionId
                        AND PPI.SCOAFundId = @ToSCOAFundID
                        AND PPI.SCOARegionId = @ToSCOARegion
                        AND PPI.DivisionId = @ToDivisionId
                        AND PPIM.MonthID = 12;

            END;
        ELSE
            BEGIN 
                PRINT 'CASE 2';

                PRINT 'Updating Project Details in Plan_ProjectFund, Plan_ProjectFundYear, Plan_ProjectRegions, Plan_ProjectFunctions, Plan_ProjectDivisions, Plan_ProjectItem, Plan_ProjectItemMonth';

				-----------------------------------------------------------------------------------------------------
				-- WHEN SCOA Fund ID are different then Udpate Plan_ProjectFund and Plan_ProjectFund
				-----------------------------------------------------------------------------------------------------
                IF ( @FromSCOAFundID <> @ToSCOAFundID )
                    BEGIN
                        SET @sql = '';
                        SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                            + '.[dbo].[aPlan_ProjectFund]
                ( AuditUserID ,
				  AuditDate ,
				  AuditUser ,
				  ProjectFund_ID ,
				  ProjectID ,
				  ScoaFundID ,
				  FundAmount ,
				  DateCaptured ,
				  CapturerID ,
				  DateModified ,
				  ModifierID ,
				  AdjustmentId
                )
		SELECT ''' + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate
                            + ''',''' + CAST(@AuditUser AS NVARCHAR(200))
                            + ''',
				  ProjectFund_ID ,
				  ProjectID ,
				  ScoaFundID ,
				  FundAmount ,
				  DateCaptured ,
				  CapturerID ,
				  DateModified ,
				  ModifierID ,
				  ' + @AdjustmentId + ' FROM Plan_ProjectFund
                WHERE   ProjectID =' + @FromProjectId + ' AND ScoaFundID = '
                            + @FromSCOAFundID;

					--SELECT TOP 1  * 
                        UPDATE  Plan_ProjectFund
                        SET     FundAmount = FundAmount - @ToAdjustmentAmount
                        FROM    Plan_ProjectFund
                        WHERE   ProjectID = @FromProjectId
                                AND ScoaFundID = @FromSCOAFundID;

                        SET @sql = '';
                        SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                            + '.[dbo].[aPlan_ProjectFund]
                ( AuditUserID ,
				  AuditDate ,
				  AuditUser ,
				  ProjectFund_ID ,
				  ProjectID ,
				  ScoaFundID ,
				  FundAmount ,
				  DateCaptured ,
				  CapturerID ,
				  DateModified ,
				  ModifierID ,
				  AdjustmentId
                )
		SELECT ''' + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate
                            + ''',''' + CAST(@AuditUser AS NVARCHAR(200))
                            + ''',
				  ProjectFund_ID ,
				  ProjectID ,
				  ScoaFundID ,
				  FundAmount ,
				  DateCaptured ,
				  CapturerID ,
				  DateModified ,
				  ModifierID ,
				  ' + @AdjustmentId + ' FROM Plan_ProjectFund
                WHERE   ProjectID =' + @ToProjectId + ' AND ScoaFundID = '
                            + @ToSCOAFundID;

						--SELECT TOP 1  *
                        UPDATE  Plan_ProjectFund
                        SET     FundAmount = FundAmount + @ToAdjustmentAmount
                        FROM    Plan_ProjectFund
                        WHERE   ProjectID = @ToProjectId
                                AND ScoaFundID = @ToSCOAFundID;
						
                        SET @sql = '';
                        SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                            + '.[dbo].[aPlan_ProjectFundYear]
                (	AuditUserID ,
					AuditDate ,
					AuditUser ,
					ProjectFundYear_ID ,
					ProjectFundID ,
					FinYear ,
					YearFundAmount ,
					CapturerID ,
					DateCaptured ,
					ModifierID ,
					DateModified ,
					AdjustmentId
                )
		SELECT ''' + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate
                            + ''',''' + CAST(@AuditUser AS NVARCHAR(200))
                            + ''',
					PPFY.ProjectFundYear_ID ,
					PPFY.ProjectFundID ,
					PPFY.FinYear ,
					PPFY.YearFundAmount ,
					PPFY.CapturerID ,
					PPFY.DateCaptured ,
					PPFY.ModifierID ,
					PPFY.DateModified ,
				  ' + @AdjustmentId
                            + ' FROM    Plan_ProjectFundYear PPFY
                        INNER JOIN Plan_ProjectFund PPF ON PPF.ProjectFund_ID = PPFY.ProjectFundID
                WHERE   PPF.ProjectID = ' + @FromProjectId
                            + ' AND PPF.ScoaFundID = ' + @FromSCOAFundID
                            + ' AND PPFY.FinYear = ''' + @FinYear + '''';

                        EXEC sp_sqlexec @sql;

						--SELECT TOP 1 *
                        UPDATE  Plan_ProjectFundYear
                        SET     YearFundAmount = YearFundAmount
                                - @ToAdjustmentAmount
                        FROM    Plan_ProjectFundYear
                                INNER JOIN Plan_ProjectFund PPF ON PPF.ProjectFund_ID = Plan_ProjectFundYear.ProjectFundID
                        WHERE   PPF.ProjectID = @FromProjectId
                                AND PPF.ScoaFundID = @FromSCOAFundID
                                AND Plan_ProjectFundYear.FinYear = @FinYear;
				
                        SET @sql = '';
                        SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                            + '.[dbo].[aPlan_ProjectFundYear]
                (	AuditUserID ,
					AuditDate ,
					AuditUser ,
					ProjectFundYear_ID ,
					ProjectFundID ,
					FinYear ,
					YearFundAmount ,
					CapturerID ,
					DateCaptured ,
					ModifierID ,
					DateModified ,
					AdjustmentId
                )
		SELECT ''' + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate
                            + ''',''' + CAST(@AuditUser AS NVARCHAR(200))
                            + ''',
					PPFY.ProjectFundYear_ID ,
					PPFY.ProjectFundID ,
					PPFY.FinYear ,
					PPFY.YearFundAmount ,
					PPFY.CapturerID ,
					PPFY.DateCaptured ,
					PPFY.ModifierID ,
					PPFY.DateModified ,
				  ' + @AdjustmentId
                            + ' FROM    Plan_ProjectFundYear PPFY
                        INNER JOIN Plan_ProjectFund PPF ON PPF.ProjectFund_ID = PPFY.ProjectFundID
                WHERE   PPF.ProjectID = ' + @ToProjectId
                            + ' AND PPF.ScoaFundID = ' + @ToSCOAFundID
                            + ' AND PPFY.FinYear = ''' + @FinYear + '''';

                        EXEC sp_sqlexec @sql;

						--SELECT TOP 1  *
                        UPDATE  Plan_ProjectFundYear
                        SET     Plan_ProjectFundYear.YearFundAmount = YearFundAmount
                                + @ToAdjustmentAmount
                        FROM    Plan_ProjectFundYear PPFY
                                INNER JOIN Plan_ProjectFund PPF ON PPF.ProjectFund_ID = PPFY.ProjectFundID
                        WHERE   PPF.ProjectID = @ToProjectId
                                AND PPF.ScoaFundID = @ToSCOAFundID
                                AND PPFY.FinYear = @FinYear;
                    END;

				-----------------------------------------------------------------------------------------------------
				-- WHEN SCOA Item ID are different then Udpate Plan_ProjectItem and Project Item Month
				-----------------------------------------------------------------------------------------------------
                IF ( @FromSCOAItem <> @ToSCOAItem )
                    BEGIN
						
                        SET @sql = '';
                        SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                            + '.[dbo].[aPlan_ProjectItem]
                (	AuditUserID ,
					AuditDate ,
					AuditUser ,
					PlanProjectItem_ID ,
					ProjectID ,
					ProjectItemID ,
					SCOAItemID ,
					FinYear ,
					CapturerID ,
					DateCaptured ,
					ModifierID ,
					DateModified ,
					ProjectFundYearID ,
					BudgetAmount ,
					BudgetAmountCurP1 ,
					BudgetAmountCurP2 ,
					SCOAFunctionId ,
					SCOAFundId ,
					SCOARegionId ,
					HistoricalProjectCode ,
					DivisionId ,
					BudgetSplitID ,
					AdjustmentId
                )
		SELECT ''' + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate
                            + ''',''' + CAST(@AuditUser AS NVARCHAR(200))
                            + ''',
					PlanProjectItem_ID ,
					ProjectID ,
					ProjectItemID ,
					SCOAItemID ,
					FinYear ,
					CapturerID ,
					DateCaptured ,
					ModifierID ,
					DateModified ,
					ProjectFundYearID ,
					BudgetAmount ,
					BudgetAmountCurP1 ,
					BudgetAmountCurP2 ,
					SCOAFunctionId ,
					SCOAFundId ,
					SCOARegionId ,
					'''' ,
					DivisionId ,
					BudgetSplitID ,
				  ' + @AdjustmentId + ' FROM    dbo.Plan_ProjectItem
                WHERE   ProjectID = ' + @FromProjectId + ' AND SCOAItemID ='
                            + @FromSCOAItem + ' AND FinYear = ''' + @FinYear
                            + '''' + ' AND SCOAFunctionId ='
                            + @FromSCOAFunctionId + ' AND SCOAFundId ='
                            + @FromSCOAFundID + ' AND SCOARegionId ='
                            + @FromSCOARegion + ' AND DivisionId ='
                            + @FromDivisionId;

                        EXEC sp_sqlexec @sql;
						
						--SELECT TOP 1  *
                        UPDATE  Plan_ProjectItem
                        SET     BudgetAmount = BudgetAmount
                                - @ToAdjustmentAmount
                        FROM    dbo.Plan_ProjectItem
                        WHERE   ProjectID = @FromProjectId
                                AND SCOAItemID = @FromSCOAItem
                                AND FinYear = @FinYear
                                AND SCOAFunctionId = @FromSCOAFunctionId
                                AND SCOAFundId = @FromSCOAFundID
                                AND SCOARegionId = @FromSCOARegion
                                AND DivisionId = @FromDivisionId;

                        SET @Month = 1;
                        SET @DeductAdjustmentAmount = @ToAdjustmentAmount;
                
                        WHILE ( @Month <= 12
                                AND @DeductAdjustmentAmount > 0
                              )
                            BEGIN

                                SELECT  @ItemMonthAmount = ISNULL(UnitPrice, 0) ,
                                        @ProjectItemMonthId = ProjectItemMonth_ID
                                FROM    dbo.Plan_ProjectItemMonth PPIM
                                        INNER JOIN dbo.Plan_ProjectItem PPI ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                                WHERE   PPI.ProjectID = @FromProjectId
                                        AND PPI.SCOAItemID = @FromSCOAItem
                                        AND PPI.FinYear = @FinYear
                                        AND PPI.SCOAFunctionId = @FromSCOAFunctionId
                                        AND PPI.SCOAFundId = @FromSCOAFundID
                                        AND PPI.SCOARegionId = @FromSCOARegion
                                        AND PPI.DivisionId = @FromDivisionId
                                        AND PPIM.MonthID = @Month;
				
                                IF ( @ItemMonthAmount > 0 )
                                    BEGIN
                                        SET @sql = '';
                                        SET @sql = ' INSERT  INTO '
                                            + @FMSAuditDBName
                                            + '.[dbo].[aPlan_ProjectItemMonth]
											(	AuditUserID ,
												AuditDate ,
												AuditUser ,
												ProjectItemMonth_ID ,
												PlanProjectItemID ,
												MonthID ,
												UnitQuantity ,
												UnitPrice ,
												CaptureID ,
												DateCaptured ,
												ModifierID ,
												DateModified ,
												AdjustmentId
											)
										SELECT '''
                                            + CAST(@AuditUserID AS VARCHAR(100))
                                            + ''',''' + @AuditDate + ''','''
                                            + CAST(@AuditUser AS NVARCHAR(200))
                                            + ''',
												PPIM.ProjectItemMonth_ID ,
												PPIM.PlanProjectItemID ,
												PPIM.MonthID ,
												PPIM.UnitQuantity ,
												PPIM.UnitPrice ,
												PPIM.CaptureID ,
												PPIM.DateCaptured ,
												PPIM.ModifierID ,
												PPIM.DateModified ,
								' + @AdjustmentId
                                            + ' FROM    dbo.Plan_ProjectItemMonth PPIM
                                WHERE   PPIM.ProjectItemMonth_ID = '
                                            + @ProjectItemMonthId;

                                        EXEC sp_sqlexec @sql;
                                    END;
		

                                IF ( @DeductAdjustmentAmount >= @ItemMonthAmount
                                     AND @ItemMonthAmount > 0
                                   )
                                    BEGIN
                                        UPDATE  dbo.Plan_ProjectItemMonth
                                        SET     UnitPrice = UnitPrice
                                                - @ItemMonthAmount
                                        FROM    dbo.Plan_ProjectItemMonth PPIM
                                        WHERE   PPIM.ProjectItemMonth_ID = @ProjectItemMonthId; 

                                        SET @DeductAdjustmentAmount = @DeductAdjustmentAmount
                                            - @ItemMonthAmount;
                                    END;
                                ELSE
                                    IF ( @DeductAdjustmentAmount < @ItemMonthAmount )
                                        BEGIN
                                            UPDATE  dbo.Plan_ProjectItemMonth
                                            SET     UnitPrice = UnitPrice
                                                    - @DeductAdjustmentAmount
                                            FROM    dbo.Plan_ProjectItemMonth PPIM
                                                    INNER JOIN dbo.Plan_ProjectItem PPI ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                                            WHERE   PPIM.ProjectItemMonth_ID = @ProjectItemMonthId; 

                                            SET @DeductAdjustmentAmount = 0;
                                        END;

                                SET @Month = @Month + 1;
                            END;

                        SET @DeductAdjustmentAmount = 0;
                        SET @ProjectItemMonthId = 0;
                        SET @ItemMonthAmount = 0;
                        SET @Month = 0;

                        SET @sql = '';
                        SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                            + '.[dbo].[aPlan_ProjectItem]
                (	AuditUserID ,
					AuditDate ,
					AuditUser ,
					PlanProjectItem_ID ,
					ProjectID ,
					ProjectItemID ,
					SCOAItemID ,
					FinYear ,
					CapturerID ,
					DateCaptured ,
					ModifierID ,
					DateModified ,
					ProjectFundYearID ,
					BudgetAmount ,
					BudgetAmountCurP1 ,
					BudgetAmountCurP2 ,
					SCOAFunctionId ,
					SCOAFundId ,
					SCOARegionId ,
					HistoricalProjectCode ,
					DivisionId ,
					BudgetSplitID ,
					AdjustmentId
                )
		SELECT ''' + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate
                            + ''',''' + CAST(@AuditUser AS NVARCHAR(200))
                            + ''',
					PlanProjectItem_ID ,
					ProjectID ,
					ProjectItemID ,
					SCOAItemID ,
					FinYear ,
					CapturerID ,
					DateCaptured ,
					ModifierID ,
					DateModified ,
					ProjectFundYearID ,
					BudgetAmount ,
					BudgetAmountCurP1 ,
					BudgetAmountCurP2 ,
					SCOAFunctionId ,
					SCOAFundId ,
					SCOARegionId ,
					'''' ,
					DivisionId ,
					BudgetSplitID ,
				  ' + @AdjustmentId + ' FROM    dbo.Plan_ProjectItem
                WHERE   ProjectID = ' + @ToProjectId + ' AND SCOAItemID ='
                            + @ToSCOAItem + ' AND FinYear = ''' + @FinYear
                            + '''' + ' AND SCOAFunctionId ='
                            + @ToSCOAFunctionId + ' AND SCOAFundId ='
                            + @ToSCOAFundID + ' AND SCOARegionId ='
                            + @ToSCOARegion + ' AND DivisionId ='
                            + @ToDivisionId;

                        EXEC sp_sqlexec @sql;

                --SELECT TOP 1  *
                        UPDATE  Plan_ProjectItem
                        SET     BudgetAmount = BudgetAmount
                                + @ToAdjustmentAmount
                        FROM    dbo.Plan_ProjectItem
                        WHERE   ProjectID = @ToProjectId
                                AND SCOAItemID = @ToSCOAItem
                                AND FinYear = @FinYear
                                AND SCOAFunctionId = @ToSCOAFunctionId
                                AND SCOAFundId = @ToSCOAFundID
                                AND SCOARegionId = @ToSCOARegion
                                AND DivisionId = @ToDivisionId;

                        SET @sql = '';
                        SET @sql = ' INSERT  INTO ' + @FMSAuditDBName
                            + '.[dbo].[aPlan_ProjectItemMonth]
											(	AuditUserID ,
												AuditDate ,
												AuditUser ,
												ProjectItemMonth_ID ,
												PlanProjectItemID ,
												MonthID ,
												UnitQuantity ,
												UnitPrice ,
												CaptureID ,
												DateCaptured ,
												ModifierID ,
												DateModified ,
												AdjustmentId
											)
										SELECT '''
                            + CAST(@AuditUserID AS VARCHAR(100)) + ''','''
                            + @AuditDate + ''','''
                            + CAST(@AuditUser AS NVARCHAR(200)) + ''',
												PPIM.ProjectItemMonth_ID ,
												PPIM.PlanProjectItemID ,
												PPIM.MonthID ,
												PPIM.UnitQuantity ,
												PPIM.UnitPrice ,
												PPIM.CaptureID ,
												PPIM.DateCaptured ,
												PPIM.ModifierID ,
												PPIM.DateModified ,
								' + @AdjustmentId
                            + ' FROM    dbo.Plan_ProjectItemMonth PPIM
                        INNER JOIN dbo.Plan_ProjectItem PPI ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                WHERE   PPI.ProjectID = ' + @ToProjectId
                            + ' AND PPI.SCOAItemID = ' + @ToSCOAItem
                            + ' AND PPI.FinYear = ''' + @FinYear + ''''
                            + ' AND PPI.SCOAFunctionId = ' + @ToSCOAFunctionId
                            + ' AND PPI.SCOAFundId = ' + @ToSCOAFundID
                            + ' AND PPI.SCOARegionId = ' + @ToSCOARegion
                            + ' AND PPI.DivisionId = ' + @ToDivisionId
                            + ' AND PPIM.MonthID = 12';

                        EXEC sp_sqlexec @sql;

                --SELECT TOP 1  *
                        UPDATE  dbo.Plan_ProjectItemMonth
                        SET     UnitPrice = UnitPrice + @ToAdjustmentAmount
                        FROM    dbo.Plan_ProjectItemMonth PPIM
                                INNER JOIN dbo.Plan_ProjectItem PPI ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                        WHERE   PPI.ProjectID = @ToProjectId
                                AND PPI.SCOAItemID = @ToSCOAItem
                                AND PPI.FinYear = @FinYear
                                AND PPI.SCOAFunctionId = @ToSCOAFunctionId
                                AND PPI.SCOAFundId = @ToSCOAFundID
                                AND PPI.SCOARegionId = @ToSCOARegion
                                AND PPI.DivisionId = @ToDivisionId
                                AND PPIM.MonthID = 12;
                    END;

            END;
    END;

GO

/****** Object:  StoredProcedure [dbo].[Plan_UpdateProjectFundAndItemForVirement_sp]    Script Date: 2026/03/10 7:23:48 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================  
-- Author:  Jignesh Prajapati  
-- Create date: 2016-04-18  
-- Description: Transfer Virement Amount to Fund and Item Details with VirementId to Audit tables   
--    Update Tables Plan_ProjectFund, Plan_ProjectFundYear, Plan_ProjectItem, Plan_ProjectItemMonth for From-To Project   
-- 2016-04-19 by JP: Add User FirstName and last name instead of username for Audit User  
-- 2016-04-22 by JP: Add Update Amount logic for Project Item in CASE 2  
-- CALL SP: Plan_UpdateProjectFundAndItemForVirement_sp 2,6772  
-- 2017-01-04 by SNagpal: Add @IsNewItemAdded field  
-- 2017-01-05 by SNagpal: Add SCOACosting fields in all the cases  
-- 2017-01-13 by SNagpal:For To Transaction:- Add Code to update Budget in Month table using VirementBudgetSplit table. For the same, did Pivoting on VirementBudgetSplit table & Create @tempVirementTable.  
--2017-01-13 by SNagpal: For From Transaction:- Add Code to update Budget in Month table using VirementBudgetSplit table. For the same, did Pivoting on VirementBudgetSplit table & Create @tempVirementTable.  
--2017-01-13 by SNagpal: For From Transaction:- Change Where Constraint for TransferFromTo  
--2017-02-28 by SNagpal: Add insert script for Plan_BudgetRegister , If any changes in budgetamount via Virement, then it should effect remaining budget in Plan_BudgetRegister  
--2017-10-26 by SNagpal: #64026 Remove Condition IF(@AvailableBudgetFromBudgetRegister > 0 while saving Plan_BudgetRegister  
--2018-11-07 by SNagpal: #81152 Add logic to calculate the Budget amounts and other validations with ProjectItemID too. Add various conditions  
--2018-11-15 by SNagpal: #80663 Add logic to save Budget into Budget Consumption Table instead of Budget Register  
--2019-04-04 by SNagpal: #86552 Add [] brackets for Audit database  
--2019-24-05 by SNagpal: #89203 Update SCOA funding after approval.  
-- 03 JUN 2019 by NParikh: #89303 QA Multi - Remaining Budget Exceeds Original Budget
-- 25 Feb 2020 Pipko V. US 21222 : use the user Processing Month for Ledger Postings
-- 2020-06-15 CMoodley: Pass correct BudgetConsumptionProcessID to Budget Consumption table
-- =============================================  
CREATE PROCEDURE [dbo].[Plan_UpdateProjectFundAndItemForVirement_sp]
   @VirementId NVARCHAR(50),
    @UserId NVARCHAR(50)
as
BEGIN

    -----------------------------------------------------------------------------  
    -- GET Virement Details  
    -- VARIABLE FOR SETTING VALUE OF VIREMENT  
    -----------------------------------------------------------------------------  
    DECLARE @FinYear NVARCHAR(9),
            @FromProjectId NVARCHAR(50),
            @ToProjectId NVARCHAR(50),
            @FromSCOAProjectID NVARCHAR(50),
            @ToSCOAProjectID NVARCHAR(50),
            @FromSCOACostingId NVARCHAR(50),
            @ToSCOACostingId NVARCHAR(50),
            @FromSCOAFunctionId NVARCHAR(50),
            @ToSCOAFunctionId NVARCHAR(50),
            @FromDivisionId NVARCHAR(50),
            @ToDivisionId NVARCHAR(50),
            @FromSCOAFundID NVARCHAR(50),
            @ToSCOAFundID NVARCHAR(50),
            @FromSCOARegion NVARCHAR(50),
            @ToSCOARegion NVARCHAR(50),
            @FromSCOAItem NVARCHAR(50),
            @ToSCOAItem NVARCHAR(50),
            @ReasonForVirement NVARCHAR(MAX),
            @FromAvailableFund NVARCHAR(50),
            @FromVirementAmount NVARCHAR(50),
            @FromNewAvailableBudget NVARCHAR(50),
            @ToAvailableFund NVARCHAR(50),
            @ToVirementAmount NVARCHAR(50),
            @ToNewAvailableBudget NVARCHAR(50),
            @IsNewItemAdded BIT,
            @FromProjectItemId NVARCHAR(10),
            @ToProjectItemId NVARCHAR(10);

    SELECT @FinYear = FinYear,
           @FromProjectId = FromProjectId,
           @ToProjectId = ToProjectId,
           @FromSCOAProjectID = FromSCOAProjectID,
           @ToSCOAProjectID = ToSCOAProjectID,
           @FromSCOACostingId = FromSCOACostingId,
           @ToSCOACostingId = ToSCOACostingId,
           @FromSCOAFunctionId = FromSCOAFunctionId,
           @ToSCOAFunctionId = ToSCOAFunctionId,
           @FromDivisionId = FromDivisionId,
           @ToDivisionId = ToDivisionId,
           @FromSCOAFundID = FromSCOAFundID,
           @ToSCOAFundID = ToSCOAFundID,
           @FromSCOARegion = FromSCOARegion,
           @ToSCOARegion = ToSCOARegion,
           @FromSCOAItem = FromSCOAItem,
           @ToSCOAItem = ToSCOAItem,
           @FromAvailableFund = FromAvailableFund,
           @FromVirementAmount = FromVirementAmount,
           @FromNewAvailableBudget = FromNewAvailableBudget,
           @ToAvailableFund = ToAvailableFund,
           @ToVirementAmount = ToVirementAmount,
           @ToNewAvailableBudget = ToNewAvailableBudget,
           @IsNewItemAdded = IsNewItemAdded,
           @FromProjectItemId = ISNULL(FromProjectItemId, 0),
           @ToProjectItemId = ISNULL(ToProjectItemId, 0)
    FROM dbo.Plan_Virements
    WHERE VirementId = @VirementId;

    DECLARE @CalcAvailableBudget DECIMAL(18, 2),
            @ApprovalResult NVARCHAR(MAX),
            @DeductVirementAmount DECIMAL(18, 2),
            @AddVirementAmount DECIMAL(18, 2),
            @ItemMonthAmount DECIMAL(18, 2),
            @Month NVARCHAR(50),
            @ProjectItemMonthId NVARCHAR(50),
            @FMSAuditDBName NVARCHAR(50),
            @AuditUserID NVARCHAR(50),
            @AuditDate NVARCHAR(50),
            @AuditUser NVARCHAR(100),
            @FinYearStartMonth INT,
            @AvailableBudgetFromBudgetRegister DECIMAL(18, 2),
            @planProjectItemIdForBudgetRegister INT,
            @BudgetTransactionTypeId INT,
            @DecToVirementAmount DECIMAL(18, 2),
            @UserProcessingMonth INT, -- must be queried for the current user id @CapturerID when required
			@BudgetTransactionTypeIDAdjusted INT= 6;

    SET @DecToVirementAmount = CONVERT(DECIMAL(18, 2), @ToVirementAmount);
    DECLARE @tempVirementTableFrom TABLE
    (
        MonthId INT,
        VirementId INT,
        VirementAmount DECIMAL(16, 2)
    );
    DECLARE @tempVirementTable TABLE
    (
        MonthId INT,
        VirementId INT,
        VirementAmount DECIMAL(16, 2)
    );

    SELECT @FinYearStartMonth = KeyValue - 1
    FROM dbo.AAAA_ConfigSettings
    WHERE KeyName = 'FinYearStartMonth';
    SELECT @FMSAuditDBName = KeyValue
    FROM dbo.AAAA_ConfigSettings
    WHERE KeyName = 'FMSAuditDatabaseName';

    SET @FMSAuditDBName = N'[' + @FMSAuditDBName + N']';

    SET @UserProcessingMonth = dbo.[GetProcessingMonthByUserID_fxn](@UserId);

    SELECT @AuditUser = ISNULL(FirstName, UserName) + ISNULL(LastName, '')
    FROM dbo.User_UserDetail
    WHERE [User_ID] = @UserId;
    SET @AuditDate = CONVERT(NVARCHAR(50), GETDATE());

    SET @AuditUserID = @UserId;

    BEGIN TRY
        BEGIN TRANSACTION;

        IF (@FromProjectId <> @ToProjectId)
        BEGIN
            PRINT 'CASE 1';

            PRINT 'Updating From Project Details in Plan_ProjectFund and Plan_ProjectFundYear';

            DECLARE @sql VARCHAR(MAX) = '';
            SET @sql
                = ' INSERT  INTO ' + @FMSAuditDBName
                  + '.[dbo].[aPlan_ProjectFund]  
                ( AuditUserID ,  
      AuditDate ,  
      AuditUser ,  
      ProjectFund_ID ,  
      ProjectID ,  
      ScoaFundID ,  
      FundAmount ,  
      DateCaptured ,  
      CapturerID ,  
      DateModified ,  
      ModifierID ,  
      VirementId  
                )  
  SELECT '''           + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate + ''','''
                  + CAST(@AuditUser AS NVARCHAR(200))
                  + ''',  
      ProjectFund_ID ,  
      ProjectID ,  
      ScoaFundID ,  
      FundAmount ,  
      DateCaptured ,  
      CapturerID ,  
      DateModified ,  
      ModifierID ,  
      '                + @VirementId + ' FROM Plan_ProjectFund  
           WHERE   ProjectID =' + @FromProjectId + ' AND ScoaFundID = ' + @FromSCOAFundID;

            EXEC sp_sqlexec @sql;

            UPDATE Plan_ProjectFund
            SET FundAmount = FundAmount - @ToVirementAmount
            FROM Plan_ProjectFund
            WHERE ProjectID = @FromProjectId
                  AND ScoaFundID = @FromSCOAFundID;

            SET @sql = '';
            SET @sql
                = ' INSERT  INTO ' + @FMSAuditDBName
                  + '.[dbo].[aPlan_ProjectFundYear]  
                ( AuditUserID ,  
     AuditDate ,  
     AuditUser ,  
     ProjectFundYear_ID ,  
     ProjectFundID ,  
     FinYear ,  
     YearFundAmount ,  
     CapturerID ,  
     DateCaptured ,  
     ModifierID ,  
     DateModified ,  
     VirementId  
                )  
  SELECT '''           + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate + ''','''
                  + CAST(@AuditUser AS NVARCHAR(200))
                  + ''',  
     PPFY.ProjectFundYear_ID ,  
     PPFY.ProjectFundID ,  
     PPFY.FinYear ,  
     PPFY.YearFundAmount ,  
     PPFY.CapturerID ,  
     PPFY.DateCaptured ,  
     PPFY.ModifierID ,  
     PPFY.DateModified ,  
      '                + @VirementId
                  + ' FROM    Plan_ProjectFundYear PPFY  
                        INNER JOIN Plan_ProjectFund PPF ON PPF.ProjectFund_ID = PPFY.ProjectFundID  
                WHERE   PPF.ProjectID = ' + @FromProjectId + ' AND PPF.ScoaFundID = ' + @FromSCOAFundID
                  + ' AND PPFY.FinYear = ''' + @FinYear + '''';

            EXEC sp_sqlexec @sql;

            UPDATE Plan_ProjectFundYear
            SET YearFundAmount = YearFundAmount - @ToVirementAmount
            FROM Plan_ProjectFundYear
                INNER JOIN Plan_ProjectFund PPF
                    ON PPF.ProjectFund_ID = Plan_ProjectFundYear.ProjectFundID
            WHERE PPF.ProjectID = @FromProjectId
                  AND PPF.ScoaFundID = @FromSCOAFundID
                  AND Plan_ProjectFundYear.FinYear = @FinYear;

            SET @sql = '';
            SET @sql
                = ' INSERT  INTO ' + @FMSAuditDBName
                  + '.[dbo].[aPlan_ProjectItem]  
                ( AuditUserID ,  
     AuditDate ,  
     AuditUser ,  
     PlanProjectItem_ID ,  
     ProjectID ,  
     ProjectItemID ,  
     SCOAItemID ,  
     FinYear ,  
     CapturerID ,  
     DateCaptured ,  
     ModifierID ,  
     DateModified ,  
     ProjectFundYearID ,  
     BudgetAmount ,  
     BudgetAmountCurP1 ,  
     BudgetAmountCurP2 ,  
     SCOAFunctionId ,  
     SCOAFundId ,  
     SCOARegionId ,  
     HistoricalProjectCode ,  
     DivisionId ,  
     BudgetSplitID ,  
     VirementId,  
     SCOACostingID  
                )  
  SELECT '''           + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate + ''','''
                  + CAST(@AuditUser AS NVARCHAR(200))
                  + ''',  
     PlanProjectItem_ID ,  
     ProjectID ,  
     ProjectItemID ,  
     SCOAItemID ,  
     FinYear ,  
     CapturerID ,  
     DateCaptured ,  
     ModifierID ,  
     DateModified ,  
     ProjectFundYearID ,  
     BudgetAmount ,  
     BudgetAmountCurP1 ,  
     BudgetAmountCurP2 ,  
     SCOAFunctionId ,  
     SCOAFundId ,  
     SCOARegionId ,  
     '''' ,  
     DivisionId ,  
     BudgetSplitID ,  
      '                + @VirementId
                  + ', SCOACostingID FROM    dbo.Plan_ProjectItem   
                WHERE   ProjectID = ' + @FromProjectId + ' AND SCOAItemID = ' + @FromSCOAItem + ' AND FinYear = '''
                  + @FinYear + '''' + ' AND SCOAFunctionId =' + @FromSCOAFunctionId + ' AND SCOAFundId ='
                  + @FromSCOAFundID + ' AND SCOARegionId =' + @FromSCOARegion + ' AND DivisionId =' + @FromDivisionId
                  + ' AND SCOACostingID =' + @FromSCOACostingId;

            EXEC sp_sqlexec @sql;
 
            UPDATE Plan_ProjectItem
            SET BudgetAmount = BudgetAmount - @ToVirementAmount
            FROM dbo.Plan_ProjectItem
            WHERE ProjectID = @FromProjectId
                  AND SCOAItemID = @FromSCOAItem
                  AND FinYear = @FinYear
                  AND SCOAFunctionId = @FromSCOAFunctionId
                  AND SCOAFundId = @FromSCOAFundID
                  AND SCOARegionId = @FromSCOARegion
                  AND DivisionId = @FromDivisionId
                  AND SCOACostingID = @FromSCOACostingId
                  AND ISNULL(ProjectItemID, 0) = @FromProjectItemId;

            SET @Month = 1;

            IF EXISTS
            (
                SELECT 1
                FROM dbo.Plan_VirementBudgetSplit
                WHERE VirementId = @VirementId
                      AND TransferFromTo = 'From'
            )
            BEGIN
                --If Budget split available in Virement, Then insert into Temp table & use amount from the same to update into Plan_ProjectItemMonth table  
                INSERT INTO @tempVirementTableFrom
                SELECT DATEPART(m, DATEADD(MONTH, @FinYearStartMonth + A.RN, -1)) AS Months,
                       VirementId,
                       Amount
                FROM
                (
                    SELECT ROW_NUMBER() OVER (ORDER BY VirementBudgetSplit_Id DESC) AS RN,
                           VirementId,
                           unpvt.Amount,
                           unpvt.Months
                    FROM
                    (
                        SELECT VirementBudgetSplit_Id,
                               VirementId,
                               Month1Price,
                               Month2Price,
                               Month3Price,
                               Month4Price,
                               Month5Price,
                               Month6Price,
                               Month7Price,
                               Month8Price,
                               Month9Price,
                               Month10Price,
                               Month11Price,
                               Month12Price
                        FROM dbo.Plan_VirementBudgetSplit
                        WHERE VirementId = @VirementId
                              AND TransferFromTo = 'From'
                    ) p
                        UNPIVOT
                        (
                            Amount
                            FOR Months IN (Month1Price, Month2Price, Month3Price, Month4Price, Month5Price,
                                           Month6Price, Month7Price, Month8Price, Month9Price, Month10Price,
                                           Month11Price, Month12Price
                                          )
                        ) AS unpvt
                ) A;
            END;
            WHILE (@Month <= 12)
            BEGIN

                SELECT @ItemMonthAmount = ISNULL(UnitPrice, 0),
                       @ProjectItemMonthId = ProjectItemMonth_ID
                FROM dbo.Plan_ProjectItemMonth PPIM
                    INNER JOIN dbo.Plan_ProjectItem PPI
                        ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                WHERE PPI.ProjectID = @FromProjectId
                      AND PPI.SCOAItemID = @FromSCOAItem
                      AND PPI.FinYear = @FinYear
                      AND PPI.SCOAFunctionId = @FromSCOAFunctionId
                      AND PPI.SCOAFundId = @FromSCOAFundID
                      AND PPI.SCOARegionId = @FromSCOARegion
                      AND PPI.DivisionId = @FromDivisionId
                      AND PPI.SCOACostingID = @FromSCOACostingId
                      AND PPIM.MonthID = @Month
                      AND ISNULL(PPI.ProjectItemID, 0) = @FromProjectItemId;

                IF (@ItemMonthAmount > 0)
                BEGIN
                    SET @sql = '';
                    SET @sql
                        = ' INSERT  INTO ' + @FMSAuditDBName
                          + '.[dbo].[aPlan_ProjectItemMonth]  
           ( AuditUserID ,  
            AuditDate ,  
            AuditUser ,  
            ProjectItemMonth_ID ,  
            PlanProjectItemID ,  
            MonthID ,  
            UnitQuantity ,  
            UnitPrice ,  
            CaptureID ,  
            DateCaptured ,  
            ModifierID ,  
            DateModified ,  
            VirementId  
           )  
          SELECT '''           + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate + ''','''
                          + CAST(@AuditUser AS NVARCHAR(200))
                          + ''',  
            PPIM.ProjectItemMonth_ID ,  
            PPIM.PlanProjectItemID ,  
            PPIM.MonthID ,  
            PPIM.UnitQuantity ,  
            PPIM.UnitPrice ,  
            PPIM.CaptureID ,  
            PPIM.DateCaptured ,  
            PPIM.ModifierID ,  
            PPIM.DateModified ,  
        '                      + @VirementId
                          + ' FROM    dbo.Plan_ProjectItemMonth PPIM  
                                WHERE   PPIM.ProjectItemMonth_ID = ' + @ProjectItemMonthId;

                    PRINT @sql;

                    EXEC sp_sqlexec @sql;
                END;

                SELECT @DeductVirementAmount = VirementAmount
                FROM @tempVirementTableFrom
                WHERE MonthId = @Month;

                IF (@DeductVirementAmount > 0)
                BEGIN
                    UPDATE dbo.Plan_ProjectItemMonth
                    SET UnitPrice = UnitPrice - @DeductVirementAmount
                    FROM dbo.Plan_ProjectItemMonth PPIM
                        INNER JOIN dbo.Plan_ProjectItem PPI
                            ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                    WHERE PPI.ProjectID = @FromProjectId
                          AND PPI.SCOAItemID = @FromSCOAItem
                          AND PPI.FinYear = @FinYear
                          AND PPI.SCOAFunctionId = @FromSCOAFunctionId
                          AND PPI.SCOAFundId = @FromSCOAFundID
                          AND PPI.SCOARegionId = @FromSCOARegion
                          AND PPI.DivisionId = @FromDivisionId
                          AND PPI.SCOACostingID = @FromSCOACostingId
                          AND PPIM.MonthID = @Month
                          AND ISNULL(PPI.ProjectItemID, 0) = @FromProjectItemId;

                    SET @DeductVirementAmount = 0;
                END;
                SET @Month = @Month + 1;

            END;

            --Insert into Plan_budgetRegister Table  
            SELECT @planProjectItemIdForBudgetRegister = PlanProjectItem_ID
            FROM dbo.Plan_ProjectItem
            WHERE ProjectID = @FromProjectId
                  AND SCOAItemID = @FromSCOAItem
                  AND FinYear = @FinYear
                  AND SCOAFunctionId = @FromSCOAFunctionId
                  AND SCOAFundId = @FromSCOAFundID
                  AND SCOARegionId = @FromSCOARegion
                  AND DivisionId = @FromDivisionId
                  AND SCOACostingID = @FromSCOACostingId
                  AND ISNULL(ProjectItemID, 0) = @FromProjectItemId;

            --By Sahil For US 80663  

            SELECT TOP 1
                   @AvailableBudgetFromBudgetRegister = AvailableBudget,
                   @BudgetTransactionTypeId = BudgetTransactionTypeID
            FROM dbo.Plan_BudgetRegister
            WHERE PlanProjectItemID = @planProjectItemIdForBudgetRegister
            ORDER BY DateCaptured DESC;

            IF (@planProjectItemIdForBudgetRegister > 0)
            BEGIN

                INSERT INTO dbo.Plan_BudgetConsumption
                (
                    FinYear,
                    PlanProjectItemID,
                    BudgetTransactionTypeID,
                    ModuleID,
                    PK_TransactionID,
                    TransactionTableName,
                    ConsumingTransactionAmount,
                    AdjustedTansactionAmount,
                    AvailableBudget,
                    ProcessingMonth,
                    BudgetConsumptionProcessID,
                    OriginalBudgetToDate,
                    AdjustedBudgetToDate,
                    CapturedExpenditureToDate,
                    ReserveToDate,
                    CommitToDate,
                    ActualToDate,
                    CapturerID,
                    DateCaptured,
					ConsumingTransactionAmountMultiYear,
					AvailableBudgetMultiYear,
					CapturedExpenditureToDateMultiYear,
					ReserveToDateMultiYear
                )
                SELECT TOP 1
                       @FinYear,
                       @planProjectItemIdForBudgetRegister,
                       @BudgetTransactionTypeIDAdjusted,
                       10,
                       @VirementId,
                       N'Plan_Virements',
                       -@DecToVirementAmount,
                       -@DecToVirementAmount,
                       (pdc.AvailableBudget - @DecToVirementAmount),
                       @UserProcessingMonth,
                       201,
                       pdc.OriginalBudgetToDate,
                       ISNULL(pdc.AdjustedBudgetToDate, 0) - @DecToVirementAmount,
                       pdc.CapturedExpenditureToDate,
                       pdc.ReserveToDate,
                       pdc.CommitToDate,
                       pdc.ActualToDate,
                       @UserId,
                       GETDATE(),
					   pdc.ConsumingTransactionAmountMultiYear,
					   pdc.AvailableBudgetMultiYear,
					   pdc.CapturedExpenditureToDateMultiYear,
					   pdc.ReserveToDateMultiYear
                FROM dbo.Plan_BudgetConsumption pdc
                WHERE pdc.PlanProjectItemID = @planProjectItemIdForBudgetRegister
                ORDER BY pdc.BudgetConsumption_ID DESC;

                INSERT INTO dbo.Plan_BudgetRegister
                (
                    PlanProjectItemID,
                    BudgetTransactionTypeID,
                    ModuleID,
                    PK_TransactionID,
                    TransactionTableName,
                    TransactionAmount,
                    AvailableBudget,
                    CapturerID,
                    DateCaptured,
                    FinYear
                )
                VALUES
                (@planProjectItemIdForBudgetRegister, @BudgetTransactionTypeId, 10, @VirementId, N'Plan_Virements',
                 -@DecToVirementAmount, (@AvailableBudgetFromBudgetRegister - @DecToVirementAmount), @UserId,
                 GETDATE(), @FinYear);

            END;

            SET @planProjectItemIdForBudgetRegister = 0;
            SET @AvailableBudgetFromBudgetRegister = 0;
            SET @DeductVirementAmount = 0;
            SET @ProjectItemMonthId = 0;
            SET @ItemMonthAmount = 0;
            SET @Month = 0;

            PRINT 'Updating To Project Details in Plan_ProjectFund and Plan_ProjectFundYear';

            SET @sql = '';
            SET @sql
                = ' INSERT  INTO ' + @FMSAuditDBName
                  + '.[dbo].[aPlan_ProjectFund]  
                ( AuditUserID ,  
      AuditDate ,  
      AuditUser ,  
      ProjectFund_ID ,  
      ProjectID ,  
      ScoaFundID ,  
      FundAmount ,  
      DateCaptured ,  
      CapturerID ,  
      DateModified ,  
      ModifierID ,  
      VirementId  
                )  
  SELECT '''           + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate + ''','''
                  + CAST(@AuditUser AS NVARCHAR(200))
                  + ''',  
      ProjectFund_ID ,  
      ProjectID ,  
      ScoaFundID ,  
      FundAmount ,  
      DateCaptured ,  
      CapturerID ,  
      DateModified ,  
      ModifierID ,  
      '                + @VirementId + ' FROM Plan_ProjectFund  
                WHERE   ProjectID =' + @ToProjectId + ' AND ScoaFundID = ' + @ToSCOAFundID;

            EXEC sp_sqlexec @sql;

            UPDATE Plan_ProjectFund
            SET FundAmount = FundAmount + @ToVirementAmount
            FROM Plan_ProjectFund
            WHERE ProjectID = @ToProjectId
                  AND ScoaFundID = @ToSCOAFundID;

            SET @sql = '';
            SET @sql
                = ' INSERT  INTO ' + @FMSAuditDBName
                  + '.[dbo].[aPlan_ProjectFundYear]  
                ( AuditUserID ,  
     AuditDate ,  
     AuditUser ,  
     ProjectFundYear_ID ,  
     ProjectFundID ,  
     FinYear ,  
     YearFundAmount ,  
     CapturerID ,  
     DateCaptured ,  
     ModifierID ,  
     DateModified ,  
     VirementId  
                )  
  SELECT '''           + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate + ''','''
                  + CAST(@AuditUser AS NVARCHAR(200))
                  + ''',  
     PPFY.ProjectFundYear_ID ,  
     PPFY.ProjectFundID ,  
     PPFY.FinYear ,  
     PPFY.YearFundAmount ,  
     PPFY.CapturerID ,  
     PPFY.DateCaptured ,  
     PPFY.ModifierID ,  
     PPFY.DateModified ,  
      '                + @VirementId
                  + ' FROM    Plan_ProjectFundYear PPFY  
                        INNER JOIN Plan_ProjectFund PPF ON PPF.ProjectFund_ID = PPFY.ProjectFundID  
                WHERE   PPF.ProjectID = ' + @ToProjectId + ' AND PPF.ScoaFundID = ' + @ToSCOAFundID
                  + ' AND PPFY.FinYear = ''' + @FinYear + '''';

            EXEC sp_sqlexec @sql;

            UPDATE Plan_ProjectFundYear
            SET Plan_ProjectFundYear.YearFundAmount = YearFundAmount + @ToVirementAmount
            FROM Plan_ProjectFundYear PPFY
                INNER JOIN Plan_ProjectFund PPF
                    ON PPF.ProjectFund_ID = PPFY.ProjectFundID
            WHERE PPF.ProjectID = @ToProjectId
                  AND PPF.ScoaFundID = @ToSCOAFundID
                  AND PPFY.FinYear = @FinYear;

            SET @sql = '';
            IF (@IsNewItemAdded = 0)
            BEGIN

                SET @sql
                    = ' INSERT  INTO ' + @FMSAuditDBName
                      + '.[dbo].[aPlan_ProjectItem]  
                ( AuditUserID ,  
     AuditDate ,  
     AuditUser ,  
     PlanProjectItem_ID ,  
     ProjectID ,  
     ProjectItemID ,  
     SCOAItemID ,  
     FinYear ,  
     CapturerID ,  
     DateCaptured ,  
     ModifierID ,  
     DateModified ,  
     ProjectFundYearID ,  
     BudgetAmount ,  
     BudgetAmountCurP1 ,  
     BudgetAmountCurP2 ,  
     SCOAFunctionId ,  
     SCOAFundId ,  
     SCOARegionId ,  
     HistoricalProjectCode ,  
     DivisionId ,  
     BudgetSplitID ,  
     VirementId,  
     SCOACostingID  
                )  
  SELECT '''               + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate + ''','''
                      + CAST(@AuditUser AS NVARCHAR(200))
                      + ''',  
     PlanProjectItem_ID ,  
     ProjectID ,  
     ProjectItemID ,  
     SCOAItemID ,  
     FinYear ,  
     CapturerID ,  
     DateCaptured ,  
     ModifierID ,  
     DateModified ,  
     ProjectFundYearID ,  
     BudgetAmount ,  
     BudgetAmountCurP1 ,  
     BudgetAmountCurP2 ,  
     SCOAFunctionId ,  
     SCOAFundId ,  
     SCOARegionId ,  
     '''' ,  
     DivisionId ,  
     BudgetSplitID ,  
      '                    + @VirementId
                      + ',SCOACostingID FROM    dbo.Plan_ProjectItem  
                WHERE   ProjectID = ' + @ToProjectId + ' AND SCOAItemID =' + @ToSCOAItem + ' AND FinYear = '''
                      + @FinYear + '''' + ' AND SCOAFunctionId =' + @ToSCOAFunctionId + ' AND SCOAFundId ='
                      + @ToSCOAFundID + ' AND SCOARegionId =' + @ToSCOARegion + ' AND DivisionId =' + @ToDivisionId
                      + ' AND SCOACostingID =' + @ToSCOACostingId;

                EXEC sp_sqlexec @sql;

                UPDATE Plan_ProjectItem
                SET BudgetAmount = BudgetAmount + @ToVirementAmount
                FROM dbo.Plan_ProjectItem
                WHERE ProjectID = @ToProjectId
                      AND SCOAItemID = @ToSCOAItem
                      AND FinYear = @FinYear
                      AND SCOAFunctionId = @ToSCOAFunctionId
                      AND SCOAFundId = @ToSCOAFundID
                      AND SCOARegionId = @ToSCOARegion
                      AND DivisionId = @ToDivisionId
                      AND SCOACostingID = @ToSCOACostingId
                      AND ISNULL(ProjectItemID, 0) = @ToProjectItemId;

                SET @sql = '';
                SET @sql
                    = ' INSERT  INTO ' + @FMSAuditDBName
                      + '.[dbo].[aPlan_ProjectItemMonth]  
           ( AuditUserID ,  
            AuditDate ,  
            AuditUser ,  
            ProjectItemMonth_ID ,  
            PlanProjectItemID ,  
            MonthID ,  
            UnitQuantity ,  
            UnitPrice ,  
            CaptureID ,  
            DateCaptured ,  
            ModifierID ,  
            DateModified ,  
            VirementId  
           )  
          SELECT '''       + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate + ''','''
                      + CAST(@AuditUser AS NVARCHAR(200))
                      + ''',  
            PPIM.ProjectItemMonth_ID ,  
            PPIM.PlanProjectItemID ,  
            PPIM.MonthID ,  
            PPIM.UnitQuantity ,  
            PPIM.UnitPrice ,  
            PPIM.CaptureID ,  
            PPIM.DateCaptured ,  
            PPIM.ModifierID ,  
            PPIM.DateModified ,  
        '                  + @VirementId
                      + ' FROM    dbo.Plan_ProjectItemMonth PPIM  
                        INNER JOIN dbo.Plan_ProjectItem PPI ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID  
                WHERE   PPI.ProjectID = ' + @ToProjectId + ' AND PPI.SCOAItemID = ' + @ToSCOAItem
                      + ' AND PPI.FinYear = ''' + @FinYear + '''' + ' AND PPI.SCOAFunctionId = ' + @ToSCOAFunctionId
                      + ' AND PPI.SCOAFundId = ' + @ToSCOAFundID + ' AND PPI.SCOARegionId = ' + @ToSCOARegion
                      + ' AND PPI.DivisionId = ' + @ToDivisionId + ' AND PPI.SCOACostingID = ' + @ToSCOACostingId
                      + ' AND PPIM.MonthID = 12';

                EXEC sp_sqlexec @sql;

                IF EXISTS
                (
                    SELECT 1
                    FROM dbo.Plan_VirementBudgetSplit
                    WHERE VirementId = @VirementId
                          AND TransferFromTo = 'To'
                )
                BEGIN
                    --If Budget split available in Virement, Then insert into Temp table & use amount from the same to update into Plan_ProjectItemMonth table  
                    INSERT INTO @tempVirementTable
                    SELECT DATEPART(m, DATEADD(MONTH, @FinYearStartMonth + A.RN, -1)) AS Months,
                           VirementId,
                           Amount
                    FROM
                    (
                        SELECT ROW_NUMBER() OVER (ORDER BY VirementBudgetSplit_Id DESC) AS RN,
                               VirementId,
                               unpvt.Amount,
                               unpvt.Months
                        FROM
                        (
                            SELECT VirementBudgetSplit_Id,
                                   VirementId,
                                   Month1Price,
                                   Month2Price,
                                   Month3Price,
                                   Month4Price,
                                   Month5Price,
                                   Month6Price,
                                   Month7Price,
                                   Month8Price,
                                   Month9Price,
                                   Month10Price,
                                   Month11Price,
                                   Month12Price
                            FROM dbo.Plan_VirementBudgetSplit
                            WHERE VirementId = @VirementId
                                  AND TransferFromTo = 'To'
                        ) p
                            UNPIVOT
                            (
                                Amount
                                FOR Months IN (Month1Price, Month2Price, Month3Price, Month4Price, Month5Price,
                                               Month6Price, Month7Price, Month8Price, Month9Price, Month10Price,
                                               Month11Price, Month12Price
                                              )
                            ) AS unpvt
                    ) A;

                    SET @Month = 1;
                    WHILE (@Month <= 12)
                    BEGIN
                        SELECT @AddVirementAmount = VirementAmount
                        FROM @tempVirementTable
                        WHERE MonthId = @Month;

                        IF (@AddVirementAmount > 0)
                        BEGIN
                            UPDATE dbo.Plan_ProjectItemMonth
                            SET UnitPrice = UnitPrice + @AddVirementAmount
                            FROM dbo.Plan_ProjectItemMonth PPIM
                                INNER JOIN dbo.Plan_ProjectItem PPI
                                    ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                            WHERE PPI.ProjectID = @ToProjectId
                                  AND PPI.SCOAItemID = @ToSCOAItem
                                  AND PPI.FinYear = @FinYear
                                  AND PPI.SCOAFunctionId = @ToSCOAFunctionId
                                  AND PPI.SCOAFundId = @ToSCOAFundID
                                  AND PPI.SCOARegionId = @ToSCOARegion
                                  AND PPI.DivisionId = @ToDivisionId
                                  AND PPI.SCOACostingID = @ToSCOACostingId
                                  AND PPIM.MonthID = @Month
                                  AND ISNULL(PPI.ProjectItemID, 0) = @ToProjectItemId;

                            SET @AddVirementAmount = 0;
                        END;
                        SET @Month = @Month + 1;
                    END;
                    SET @Month = 0;
                END;
                ELSE
                BEGIN
                    UPDATE dbo.Plan_ProjectItemMonth
                    SET UnitPrice = UnitPrice + @ToVirementAmount
                    FROM dbo.Plan_ProjectItemMonth PPIM
                        INNER JOIN dbo.Plan_ProjectItem PPI
                            ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                    WHERE PPI.ProjectID = @ToProjectId
                          AND PPI.SCOAItemID = @ToSCOAItem
                          AND PPI.FinYear = @FinYear
                          AND PPI.SCOAFunctionId = @ToSCOAFunctionId
                          AND PPI.SCOAFundId = @ToSCOAFundID
                          AND PPI.SCOARegionId = @ToSCOARegion
                          AND PPI.DivisionId = @ToDivisionId
                          AND PPI.SCOACostingID = @ToSCOACostingId
                          AND PPIM.MonthID = 12
                          AND ISNULL(PPI.ProjectItemID, 0) = @ToProjectItemId;
                END;

                SELECT @planProjectItemIdForBudgetRegister = PlanProjectItem_ID
                FROM dbo.Plan_ProjectItem
                WHERE ProjectID = @ToProjectId
                      AND SCOAItemID = @ToSCOAItem
                      AND FinYear = @FinYear
                      AND SCOAFunctionId = @ToSCOAFunctionId
                      AND SCOAFundId = @ToSCOAFundID
                      AND SCOARegionId = @ToSCOARegion
                      AND DivisionId = @ToDivisionId
                      AND SCOACostingID = @ToSCOACostingId
                      AND ISNULL(ProjectItemID, 0) = @ToProjectItemId;
                --By Sahil For US 80663  

               -- INSERT INTO Plan_BudgetRegister
                SELECT TOP 1
                       @AvailableBudgetFromBudgetRegister = AvailableBudget,
                       @BudgetTransactionTypeId = BudgetTransactionTypeID
                FROM dbo.Plan_BudgetRegister
                WHERE PlanProjectItemID = @planProjectItemIdForBudgetRegister
                ORDER BY DateCaptured DESC;

                IF (@planProjectItemIdForBudgetRegister > 0)
                BEGIN

                    INSERT INTO dbo.Plan_BudgetConsumption
                    (
                        FinYear,
                        PlanProjectItemID,
                        BudgetTransactionTypeID,
                        ModuleID,
                        PK_TransactionID,
                        TransactionTableName,
                        ConsumingTransactionAmount,
                        AdjustedTansactionAmount,
                        AvailableBudget,
                        ProcessingMonth,
                        BudgetConsumptionProcessID,
                        OriginalBudgetToDate,
                        AdjustedBudgetToDate,
                        CapturedExpenditureToDate,
                        ReserveToDate,
                        CommitToDate,
                        ActualToDate,
                        CapturerID,
                        DateCaptured,
						ConsumingTransactionAmountMultiYear,
						AvailableBudgetMultiYear,
						CapturedExpenditureToDateMultiYear,
						ReserveToDateMultiYear
                    )
                    SELECT TOP 1
                           @FinYear,
                           @planProjectItemIdForBudgetRegister,
                           @BudgetTransactionTypeIDAdjusted,
                           10,
                           @VirementId,
                           N'Plan_Virements',
                           @ToVirementAmount,
                           @ToVirementAmount,
                           (pdc.AvailableBudget + @ToVirementAmount),
                           @UserProcessingMonth,
                           201,
                           pdc.OriginalBudgetToDate,
                           ISNULL(pdc.AdjustedBudgetToDate, 0) + @ToVirementAmount,
                           pdc.CapturedExpenditureToDate,
                           pdc.ReserveToDate,
                           pdc.CommitToDate,
                           pdc.ActualToDate,
                           @UserId,
                           GETDATE(),
						   pdc.ConsumingTransactionAmountMultiYear,
						   pdc.AvailableBudgetMultiYear,
						   pdc.CapturedExpenditureToDateMultiYear,
						   pdc.ReserveToDateMultiYear
                    FROM dbo.Plan_BudgetConsumption pdc
                    WHERE pdc.PlanProjectItemID = @planProjectItemIdForBudgetRegister
                    ORDER BY pdc.BudgetConsumption_ID DESC;


                    INSERT INTO dbo.Plan_BudgetRegister
                    (
                        PlanProjectItemID,
                        BudgetTransactionTypeID,
                        ModuleID,
                        PK_TransactionID,
                        TransactionTableName,
                        TransactionAmount,
                        AvailableBudget,
                        CapturerID,
                        DateCaptured,
                        FinYear
                    )
                    VALUES
                    (@planProjectItemIdForBudgetRegister, @BudgetTransactionTypeId, 10, @VirementId, N'Plan_Virements',
                     @ToVirementAmount, (@AvailableBudgetFromBudgetRegister + @ToVirementAmount), @UserId, GETDATE(),
                     @FinYear);

                END;

                SET @planProjectItemIdForBudgetRegister = 0;
                SET @AvailableBudgetFromBudgetRegister = 0;
            END;
        END;
        ELSE
        BEGIN
            PRINT 'CASE 2';

            PRINT 'Updating Project Details in Plan_ProjectFund, Plan_ProjectFundYear, Plan_ProjectRegions, Plan_ProjectFunctions, Plan_ProjectDivisions, Plan_ProjectItem, Plan_ProjectItemMonth';

            -----------------------------------------------------------------------------------------------------  
            -- WHEN SCOA Fund ID are different then Udpate Plan_ProjectFund and Plan_ProjectFund  
            -----------------------------------------------------------------------------------------------------  
            IF (@FromSCOAFundID <> @ToSCOAFundID)
            BEGIN
                SET @sql = '';
                SET @sql
                    = ' INSERT  INTO ' + @FMSAuditDBName
                      + '.[dbo].[aPlan_ProjectFund]  
                ( AuditUserID ,  
      AuditDate ,  
      AuditUser ,  
      ProjectFund_ID ,  
      ProjectID ,  
      ScoaFundID ,  
      FundAmount ,  
      DateCaptured ,  
      CapturerID ,  
      DateModified ,  
      ModifierID ,  
      VirementId  
                )  
  SELECT '''               + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate + ''','''
                      + CAST(@AuditUser AS NVARCHAR(200))
                      + ''',  
      ProjectFund_ID ,  
      ProjectID ,  
      ScoaFundID ,  
      FundAmount ,  
      DateCaptured ,  
      CapturerID ,  
      DateModified ,  
      ModifierID ,  
      '                    + @VirementId + ' FROM Plan_ProjectFund  
                WHERE   ProjectID =' + @FromProjectId + ' AND ScoaFundID = ' + @FromSCOAFundID;

                UPDATE Plan_ProjectFund
                SET FundAmount = FundAmount - @ToVirementAmount
                FROM Plan_ProjectFund
                WHERE ProjectID = @FromProjectId
                      AND ScoaFundID = @FromSCOAFundID;

                SET @sql = '';
                SET @sql
                    = ' INSERT  INTO ' + @FMSAuditDBName
                      + '.[dbo].[aPlan_ProjectFund]  
                ( AuditUserID ,  
      AuditDate ,  
      AuditUser ,  
      ProjectFund_ID ,  
      ProjectID ,  
      ScoaFundID ,  
      FundAmount ,  
      DateCaptured ,  
      CapturerID ,  
      DateModified ,  
      ModifierID ,  
      VirementId  
                )  
  SELECT '''               + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate + ''','''
                      + CAST(@AuditUser AS NVARCHAR(200))
                      + ''',  
      ProjectFund_ID ,  
      ProjectID ,  
      ScoaFundID ,  
      FundAmount ,  
      DateCaptured ,  
      CapturerID ,  
      DateModified ,  
      ModifierID ,  
      '                    + @VirementId + ' FROM Plan_ProjectFund  
                WHERE   ProjectID =' + @ToProjectId + ' AND ScoaFundID = ' + @ToSCOAFundID;

                UPDATE Plan_ProjectFund
                SET FundAmount = FundAmount + @ToVirementAmount
                FROM Plan_ProjectFund
                WHERE ProjectID = @ToProjectId
                      AND ScoaFundID = @ToSCOAFundID;

                SET @sql = '';
                SET @sql
                    = ' INSERT  INTO ' + @FMSAuditDBName
                      + '.[dbo].[aPlan_ProjectFundYear]  
                ( AuditUserID ,  
     AuditDate ,  
     AuditUser ,  
     ProjectFundYear_ID ,  
     ProjectFundID ,  
     FinYear ,  
     YearFundAmount ,  
     CapturerID ,  
     DateCaptured ,  
     ModifierID ,  
     DateModified ,  
     VirementId  
                )  
  SELECT '''               + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate + ''','''
                      + CAST(@AuditUser AS NVARCHAR(200))
                      + ''',  
     PPFY.ProjectFundYear_ID ,  
     PPFY.ProjectFundID ,  
     PPFY.FinYear ,  
     PPFY.YearFundAmount ,  
     PPFY.CapturerID ,  
     PPFY.DateCaptured ,  
     PPFY.ModifierID ,  
     PPFY.DateModified ,  
      '                    + @VirementId
                      + ' FROM    Plan_ProjectFundYear PPFY  
                        INNER JOIN Plan_ProjectFund PPF ON PPF.ProjectFund_ID = PPFY.ProjectFundID  
                WHERE   PPF.ProjectID = ' + @FromProjectId + ' AND PPF.ScoaFundID = ' + @FromSCOAFundID
                      + ' AND PPFY.FinYear = ''' + @FinYear + '''';

                EXEC sp_sqlexec @sql;

                UPDATE Plan_ProjectFundYear
                SET YearFundAmount = YearFundAmount - @ToVirementAmount
                FROM Plan_ProjectFundYear
                    INNER JOIN Plan_ProjectFund PPF
                        ON PPF.ProjectFund_ID = Plan_ProjectFundYear.ProjectFundID
                WHERE PPF.ProjectID = @FromProjectId
                      AND PPF.ScoaFundID = @FromSCOAFundID
                      AND Plan_ProjectFundYear.FinYear = @FinYear;

                SET @sql = '';
                SET @sql
                    = ' INSERT  INTO ' + @FMSAuditDBName
                      + '.[dbo].[aPlan_ProjectFundYear]  
                ( AuditUserID ,  
     AuditDate ,  
     AuditUser ,  
     ProjectFundYear_ID ,  
     ProjectFundID ,  
     FinYear ,  
     YearFundAmount ,  
     CapturerID ,  
     DateCaptured ,  
     ModifierID ,  
     DateModified ,  
     VirementId  
                )  
  SELECT '''               + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate + ''','''
                      + CAST(@AuditUser AS NVARCHAR(200))
                      + ''',  
     PPFY.ProjectFundYear_ID ,  
     PPFY.ProjectFundID ,  
     PPFY.FinYear ,  
     PPFY.YearFundAmount ,  
     PPFY.CapturerID ,  
     PPFY.DateCaptured ,  
     PPFY.ModifierID ,  
     PPFY.DateModified ,  
      '                    + @VirementId
                      + ' FROM    Plan_ProjectFundYear PPFY  
                        INNER JOIN Plan_ProjectFund PPF ON PPF.ProjectFund_ID = PPFY.ProjectFundID  
                WHERE   PPF.ProjectID = ' + @ToProjectId + ' AND PPF.ScoaFundID = ' + @ToSCOAFundID
                      + ' AND PPFY.FinYear = ''' + @FinYear + '''';

                EXEC sp_sqlexec @sql;

                UPDATE Plan_ProjectFundYear
                SET Plan_ProjectFundYear.YearFundAmount = YearFundAmount + @ToVirementAmount
                FROM Plan_ProjectFundYear PPFY
                    INNER JOIN Plan_ProjectFund PPF
                        ON PPF.ProjectFund_ID = PPFY.ProjectFundID
                WHERE PPF.ProjectID = @ToProjectId
                      AND PPF.ScoaFundID = @ToSCOAFundID
                      AND PPFY.FinYear = @FinYear;
            END;

            -----------------------------------------------------------------------------------------------------  
            -- WHEN SCOA Item ID are different then Udpate Plan_ProjectItem and Project Item Month  
            -----------------------------------------------------------------------------------------------------  
            IF (
                   (@FromSCOAItem <> @ToSCOAItem)
                   OR (@FromSCOAProjectID <> @ToSCOAProjectID)
                   OR (@FromSCOAFunctionId <> @ToSCOAFunctionId)
                   OR (@FromSCOARegion <> @ToSCOARegion)
                   OR (@FromDivisionId <> @ToDivisionId)
                   OR (@FromSCOACostingId <> @ToSCOACostingId)
                   OR (@FromSCOAFundID <> @ToSCOAFundID)
                   OR (@FromProjectItemId <> @ToProjectItemId)
               )
            BEGIN

                SET @sql = '';
                SET @sql
                    = ' INSERT  INTO ' + @FMSAuditDBName
                      + '.[dbo].[aPlan_ProjectItem]  
                ( AuditUserID ,  
     AuditDate ,  
     AuditUser ,  
     PlanProjectItem_ID ,  
     ProjectID ,  
     ProjectItemID ,  
     SCOAItemID ,  
     FinYear ,  
     CapturerID ,  
     DateCaptured ,  
     ModifierID ,  
     DateModified ,  
     ProjectFundYearID ,  
     BudgetAmount ,  
     BudgetAmountCurP1 ,  
     BudgetAmountCurP2 ,  
     SCOAFunctionId ,  
     SCOAFundId ,  
     SCOARegionId ,  
     HistoricalProjectCode ,  
     DivisionId ,  
     BudgetSplitID ,  
     VirementId,  
     SCOACostingID  
                )  
  SELECT '''               + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate + ''','''
                      + CAST(@AuditUser AS NVARCHAR(200))
                      + ''',  
     PlanProjectItem_ID ,  
     ProjectID ,  
     ProjectItemID ,  
     SCOAItemID ,  
     FinYear ,  
     CapturerID ,  
     DateCaptured ,  
     ModifierID ,  
     DateModified ,  
     ProjectFundYearID ,  
     BudgetAmount ,  
     BudgetAmountCurP1 ,  
     BudgetAmountCurP2 ,  
     SCOAFunctionId ,  
     SCOAFundId ,  
     SCOARegionId ,  
     '''' ,  
     DivisionId ,  
     BudgetSplitID ,  
      '                    + @VirementId
                      + ', SCOACostingID FROM    dbo.Plan_ProjectItem   
                WHERE   ProjectID = ' + @FromProjectId + ' AND SCOAItemID = ' + @FromSCOAItem + ' AND FinYear = '''
                      + @FinYear + '''' + ' AND SCOAFunctionId =' + @FromSCOAFunctionId + ' AND SCOAFundId ='
                      + @FromSCOAFundID + ' AND SCOARegionId =' + @FromSCOARegion + ' AND DivisionId ='
                      + @FromDivisionId + ' AND SCOACostingID =' + @FromSCOACostingId;

                EXEC sp_sqlexec @sql;

                UPDATE Plan_ProjectItem
                SET BudgetAmount = BudgetAmount - @ToVirementAmount
                FROM dbo.Plan_ProjectItem
                WHERE ProjectID = @FromProjectId
                      AND SCOAItemID = @FromSCOAItem
                      AND FinYear = @FinYear
                      AND SCOAFunctionId = @FromSCOAFunctionId
                      AND SCOAFundId = @FromSCOAFundID
                      AND SCOARegionId = @FromSCOARegion
                      AND DivisionId = @FromDivisionId
                      AND SCOACostingID = @FromSCOACostingId
                      AND ISNULL(ProjectItemID, 0) = @FromProjectItemId;

                SET @Month = 1;

                IF EXISTS
                (
                    SELECT 1
                    FROM dbo.Plan_VirementBudgetSplit
                    WHERE VirementId = @VirementId
                          AND TransferFromTo = 'From'
                )
                BEGIN
                    --If Budget split available in Virement, Then insert into Temp table & use amount from the same to update into Plan_ProjectItemMonth table  
                    INSERT INTO @tempVirementTableFrom
                    SELECT DATEPART(m, DATEADD(MONTH, @FinYearStartMonth + A.RN, -1)) AS Months,
                           VirementId,
                           Amount
                    FROM
                    (
                        SELECT ROW_NUMBER() OVER (ORDER BY VirementBudgetSplit_Id DESC) AS RN,
                               VirementId,
                               unpvt.Amount,
                               unpvt.Months
                        FROM
                        (
                            SELECT VirementBudgetSplit_Id,
                                   VirementId,
                                   Month1Price,
                                   Month2Price,
                                   Month3Price,
                                   Month4Price,
                                   Month5Price,
                                   Month6Price,
                                   Month7Price,
                                   Month8Price,
                                   Month9Price,
                                   Month10Price,
                                   Month11Price,
                                   Month12Price
                            FROM dbo.Plan_VirementBudgetSplit
                            WHERE VirementId = @VirementId
                                  AND TransferFromTo = 'From'
                        ) p
                            UNPIVOT
                            (
                                Amount
                                FOR Months IN (Month1Price, Month2Price, Month3Price, Month4Price, Month5Price,
                                               Month6Price, Month7Price, Month8Price, Month9Price, Month10Price,
                                               Month11Price, Month12Price
                                              )
                            ) AS unpvt
                    ) A;
                END;

                WHILE (@Month <= 12)
                BEGIN

                    SELECT @ItemMonthAmount = ISNULL(UnitPrice, 0),
                           @ProjectItemMonthId = ProjectItemMonth_ID
                    FROM dbo.Plan_ProjectItemMonth PPIM
                        INNER JOIN dbo.Plan_ProjectItem PPI
                            ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                    WHERE PPI.ProjectID = @FromProjectId
                          AND PPI.SCOAItemID = @FromSCOAItem
                          AND PPI.FinYear = @FinYear
                          AND PPI.SCOAFunctionId = @FromSCOAFunctionId
                          AND PPI.SCOAFundId = @FromSCOAFundID
                          AND PPI.SCOARegionId = @FromSCOARegion
                          AND PPI.DivisionId = @FromDivisionId
                          AND PPI.SCOACostingID = @FromSCOACostingId
                          AND PPIM.MonthID = @Month
                          AND ISNULL(PPI.ProjectItemID, 0) = @FromProjectItemId;

                    IF (@ItemMonthAmount > 0)
                    BEGIN
                        SET @sql = '';
                        SET @sql
                            = ' INSERT  INTO ' + @FMSAuditDBName
                              + '.[dbo].[aPlan_ProjectItemMonth]  
           ( AuditUserID ,  
            AuditDate ,  
            AuditUser ,  
            ProjectItemMonth_ID ,  
            PlanProjectItemID ,  
            MonthID ,  
            UnitQuantity ,  
            UnitPrice ,  
            CaptureID ,  
            DateCaptured ,  
            ModifierID ,  
            DateModified ,  
            VirementId  
           )  
          SELECT '''               + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate + ''','''
                              + CAST(@AuditUser AS NVARCHAR(200))
                              + ''',  
            PPIM.ProjectItemMonth_ID ,  
            PPIM.PlanProjectItemID ,  
            PPIM.MonthID ,  
            PPIM.UnitQuantity ,  
            PPIM.UnitPrice ,  
            PPIM.CaptureID ,  
            PPIM.DateCaptured ,  
            PPIM.ModifierID ,  
            PPIM.DateModified ,  
        '                          + @VirementId
                              + ' FROM    dbo.Plan_ProjectItemMonth PPIM  
                                WHERE   PPIM.ProjectItemMonth_ID = ' + @ProjectItemMonthId;

                        EXEC sp_sqlexec @sql;
                    END;

                    SELECT @DeductVirementAmount = VirementAmount
                    FROM @tempVirementTableFrom
                    WHERE MonthId = @Month;

                    IF (@DeductVirementAmount > 0)
                    BEGIN
                        UPDATE dbo.Plan_ProjectItemMonth
                        SET UnitPrice = UnitPrice - @DeductVirementAmount
                        FROM dbo.Plan_ProjectItemMonth PPIM
                            INNER JOIN dbo.Plan_ProjectItem PPI
                                ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                        WHERE PPI.ProjectID = @FromProjectId
                              AND PPI.SCOAItemID = @FromSCOAItem
                              AND PPI.FinYear = @FinYear
                              AND PPI.SCOAFunctionId = @FromSCOAFunctionId
                              AND PPI.SCOAFundId = @FromSCOAFundID
                              AND PPI.SCOARegionId = @FromSCOARegion
                              AND PPI.DivisionId = @FromDivisionId
                              AND PPI.SCOACostingID = @FromSCOACostingId
                              AND PPIM.MonthID = @Month
                              AND ISNULL(PPI.ProjectItemID, 0) = @FromProjectItemId;

                        SET @DeductVirementAmount = 0;
                    END;
                    SET @Month = @Month + 1;
                END;

                --Insert into Plan_budgetRegister Table  
                SELECT @planProjectItemIdForBudgetRegister = PlanProjectItem_ID
                FROM dbo.Plan_ProjectItem
                WHERE ProjectID = @FromProjectId
                      AND SCOAItemID = @FromSCOAItem
                      AND FinYear = @FinYear
                      AND SCOAFunctionId = @FromSCOAFunctionId
                      AND SCOAFundId = @FromSCOAFundID
                      AND SCOARegionId = @FromSCOARegion
                      AND DivisionId = @FromDivisionId
                      AND SCOACostingID = @FromSCOACostingId
                      AND ISNULL(ProjectItemID, 0) = @FromProjectItemId;;

                SELECT TOP 1
                       @AvailableBudgetFromBudgetRegister = AvailableBudget,
                       @BudgetTransactionTypeId = BudgetTransactionTypeID
                FROM dbo.Plan_BudgetRegister
                WHERE PlanProjectItemID = @planProjectItemIdForBudgetRegister
                ORDER BY DateCaptured DESC;

                IF (@planProjectItemIdForBudgetRegister > 0)
                BEGIN

                    INSERT INTO dbo.Plan_BudgetConsumption
                    (
                        FinYear,
                        PlanProjectItemID,
                        BudgetTransactionTypeID,
                        ModuleID,
                        PK_TransactionID,
                        TransactionTableName,
                        ConsumingTransactionAmount,
                        AdjustedTansactionAmount,
                        AvailableBudget,
                        ProcessingMonth,
                        BudgetConsumptionProcessID,
                        OriginalBudgetToDate,
                        AdjustedBudgetToDate,
                        CapturedExpenditureToDate,
                        ReserveToDate,
                        CommitToDate,
                        ActualToDate,
                        CapturerID,
                        DateCaptured,
						ConsumingTransactionAmountMultiYear,
						AvailableBudgetMultiYear,
						CapturedExpenditureToDateMultiYear,
						ReserveToDateMultiYear
                    )
                    SELECT TOP 1
                           @FinYear,
                           pdc.PlanProjectItemID,
                           @BudgetTransactionTypeIDAdjusted,
                           10,
                           @VirementId,
                           N'Plan_Virements',
                           -@DecToVirementAmount,
                           -@DecToVirementAmount,
                           (pdc.AvailableBudget - @DecToVirementAmount),
                           @UserProcessingMonth,
                           201,
                           pdc.OriginalBudgetToDate,
						   ISNULL(pdc.AdjustedBudgetToDate, 0) - @DecToVirementAmount,
                           pdc.CapturedExpenditureToDate,
                           pdc.ReserveToDate,
                           pdc.CommitToDate,
                           pdc.ActualToDate,
                           @UserId,
                           GETDATE(),
						  pdc.ConsumingTransactionAmountMultiYear,
						  pdc.AvailableBudgetMultiYear,
						  pdc.CapturedExpenditureToDateMultiYear,
						  pdc.ReserveToDateMultiYear
                    FROM dbo.Plan_BudgetConsumption pdc
                    WHERE pdc.PlanProjectItemID = @planProjectItemIdForBudgetRegister
                    ORDER BY pdc.BudgetConsumption_ID DESC;

                    INSERT INTO dbo.Plan_BudgetRegister
                    (
                        PlanProjectItemID,
                        BudgetTransactionTypeID,
                        ModuleID,
                        PK_TransactionID,
                        TransactionTableName,
                        TransactionAmount,
                        AvailableBudget,
                        CapturerID,
                        DateCaptured,
                        FinYear
                    )
                    VALUES
                    (@planProjectItemIdForBudgetRegister, @BudgetTransactionTypeId, 10, @VirementId, N'Plan_Virements',
                     -@DecToVirementAmount, (@AvailableBudgetFromBudgetRegister - @DecToVirementAmount), @UserId,
                     GETDATE(), @FinYear);

                END;

                SET @planProjectItemIdForBudgetRegister = 0;
                SET @AvailableBudgetFromBudgetRegister = 0;

                SET @DeductVirementAmount = 0;
                SET @ProjectItemMonthId = 0;
                SET @ItemMonthAmount = 0;
                SET @Month = 0;

                SET @sql = '';
                IF (@IsNewItemAdded = 0)
                BEGIN

                    SET @sql
                        = ' INSERT  INTO ' + @FMSAuditDBName
                          + '.[dbo].[aPlan_ProjectItem]  
                ( AuditUserID ,  
     AuditDate ,  
     AuditUser ,  
     PlanProjectItem_ID ,  
     ProjectID ,  
     ProjectItemID ,  
     SCOAItemID ,  
     FinYear ,  
     CapturerID ,  
     DateCaptured ,  
     ModifierID ,  
     DateModified ,  
     ProjectFundYearID ,  
     BudgetAmount ,  
     BudgetAmountCurP1 ,  
     BudgetAmountCurP2 ,  
     SCOAFunctionId ,  
     SCOAFundId ,  
     SCOARegionId ,  
     HistoricalProjectCode ,  
     DivisionId ,  
     BudgetSplitID ,  
     VirementId,  
     SCOACostingID  
                )  
  SELECT '''                   + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate + ''','''
                          + CAST(@AuditUser AS NVARCHAR(200))
                          + ''',  
     PlanProjectItem_ID ,  
     ProjectID ,  
     ProjectItemID ,  
     SCOAItemID ,  
     FinYear ,  
     CapturerID ,  
     DateCaptured ,  
     ModifierID ,  
     DateModified ,  
     ProjectFundYearID ,  
     BudgetAmount ,  
     BudgetAmountCurP1 ,  
     BudgetAmountCurP2 ,  
     SCOAFunctionId ,  
     SCOAFundId ,  
     SCOARegionId ,  
     '''' ,  
     DivisionId ,  
     BudgetSplitID ,  
      '                        + @VirementId
                          + ', SCOACostingID FROM    dbo.Plan_ProjectItem  
                WHERE   ProjectID = ' + @ToProjectId + ' AND SCOAItemID =' + @ToSCOAItem + ' AND FinYear = '''
                          + @FinYear + '''' + ' AND SCOAFunctionId =' + @ToSCOAFunctionId + ' AND SCOAFundId ='
                          + @ToSCOAFundID + ' AND SCOARegionId =' + @ToSCOARegion + ' AND DivisionId =' + @ToDivisionId
                          + ' AND SCOACostingID =' + @ToSCOACostingId;

                    EXEC sp_sqlexec @sql;

                    UPDATE Plan_ProjectItem
                    SET BudgetAmount = BudgetAmount + @ToVirementAmount
                    FROM dbo.Plan_ProjectItem
                    WHERE ProjectID = @ToProjectId
                          AND SCOAItemID = @ToSCOAItem
                          AND FinYear = @FinYear
                          AND SCOAFunctionId = @ToSCOAFunctionId
                          AND SCOAFundId = @ToSCOAFundID
                          AND SCOARegionId = @ToSCOARegion
                          AND DivisionId = @ToDivisionId
                          AND SCOACostingID = @ToSCOACostingId
                          AND ISNULL(ProjectItemID, 0) = @ToProjectItemId;

                    SET @sql = '';
                    SET @sql
                        = ' INSERT  INTO ' + @FMSAuditDBName
                          + '.[dbo].[aPlan_ProjectItemMonth]  
           ( AuditUserID ,  
            AuditDate ,  
            AuditUser ,  
            ProjectItemMonth_ID ,  
            PlanProjectItemID ,  
            MonthID ,  
            UnitQuantity ,  
            UnitPrice ,  
            CaptureID ,  
            DateCaptured ,  
            ModifierID ,  
            DateModified ,  
            VirementId  
           )  
          SELECT '''           + CAST(@AuditUserID AS VARCHAR(100)) + ''',''' + @AuditDate + ''','''
                          + CAST(@AuditUser AS NVARCHAR(200))
                          + ''',  
            PPIM.ProjectItemMonth_ID ,  
            PPIM.PlanProjectItemID ,  
            PPIM.MonthID ,  
            PPIM.UnitQuantity ,  
            PPIM.UnitPrice ,  
            PPIM.CaptureID ,  
            PPIM.DateCaptured ,  
            PPIM.ModifierID ,  
            PPIM.DateModified ,  
        '                      + @VirementId
                          + ' FROM    dbo.Plan_ProjectItemMonth PPIM  
                        INNER JOIN dbo.Plan_ProjectItem PPI ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID  
                WHERE   PPI.ProjectID = ' + @ToProjectId + ' AND PPI.SCOAItemID = ' + @ToSCOAItem
                          + ' AND PPI.FinYear = ''' + @FinYear + '''' + ' AND PPI.SCOAFunctionId = '
                          + @ToSCOAFunctionId + ' AND PPI.SCOAFundId = ' + @ToSCOAFundID + ' AND PPI.SCOARegionId = '
                          + @ToSCOARegion + ' AND PPI.DivisionId = ' + @ToDivisionId + ' AND PPI.SCOACostingID = '
                          + @ToSCOACostingId + ' AND PPIM.MonthID = 12';

                    EXEC sp_sqlexec @sql;

                    IF EXISTS
                    (
                        SELECT 1
                        FROM dbo.Plan_VirementBudgetSplit
                        WHERE VirementId = @VirementId
                    )
                    BEGIN
                        --If Budget split available in Virement, Then insert into Temp table & use amount from the same to update into Plan_ProjectItemMonth table  
                        INSERT INTO @tempVirementTable
                        SELECT DATEPART(m, DATEADD(MONTH, @FinYearStartMonth + A.RN, -1)) AS Months,
                               VirementId,
                               Amount
                        FROM
                        (
                            SELECT ROW_NUMBER() OVER (ORDER BY VirementBudgetSplit_Id DESC) AS RN,
                                   VirementId,
                                   unpvt.Amount,
                                   unpvt.Months
                            FROM
                            (
                                SELECT VirementBudgetSplit_Id,
                                       VirementId,
                                       Month1Price,
                                       Month2Price,
                                       Month3Price,
                                       Month4Price,
                                       Month5Price,
                                       Month6Price,
                                       Month7Price,
                                       Month8Price,
                                       Month9Price,
                                       Month10Price,
                                       Month11Price,
                                       Month12Price
                                FROM dbo.Plan_VirementBudgetSplit
                                WHERE VirementId = @VirementId
                            ) p
                                UNPIVOT
                                (
                                    Amount
                                    FOR Months IN (Month1Price, Month2Price, Month3Price, Month4Price, Month5Price,
                                                   Month6Price, Month7Price, Month8Price, Month9Price, Month10Price,
                                                   Month11Price, Month12Price
                                                  )
                                ) AS unpvt
                        ) A;

                        SET @Month = 1;
                        WHILE (@Month <= 12)
                        BEGIN
                            SELECT @AddVirementAmount = VirementAmount
                            FROM @tempVirementTable
                            WHERE MonthId = @Month;

                            IF (@AddVirementAmount > 0)
                            BEGIN
                                UPDATE dbo.Plan_ProjectItemMonth
                                SET UnitPrice = UnitPrice + @AddVirementAmount
                                FROM dbo.Plan_ProjectItemMonth PPIM
                                    INNER JOIN dbo.Plan_ProjectItem PPI
                                        ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                                WHERE PPI.ProjectID = @ToProjectId
                                      AND PPI.SCOAItemID = @ToSCOAItem
                                      AND PPI.FinYear = @FinYear
                                      AND PPI.SCOAFunctionId = @ToSCOAFunctionId
                                      AND PPI.SCOAFundId = @ToSCOAFundID
                                      AND PPI.SCOARegionId = @ToSCOARegion
                                      AND PPI.DivisionId = @ToDivisionId
                                      AND PPI.SCOACostingID = @ToSCOACostingId
                                      AND PPIM.MonthID = @Month
                                      AND ISNULL(PPI.ProjectItemID, 0) = @ToProjectItemId;

                                SET @AddVirementAmount = 0;
                            END;
                            SET @Month = @Month + 1;
                        END;
                        SET @Month = 0;
                    END;
                    ELSE
                    BEGIN
                        UPDATE dbo.Plan_ProjectItemMonth
                        SET UnitPrice = UnitPrice + @ToVirementAmount
                        FROM dbo.Plan_ProjectItemMonth PPIM
                            INNER JOIN dbo.Plan_ProjectItem PPI
                                ON PPI.PlanProjectItem_ID = PPIM.PlanProjectItemID
                        WHERE PPI.ProjectID = @ToProjectId
                              AND PPI.SCOAItemID = @ToSCOAItem
                              AND PPI.FinYear = @FinYear
                              AND PPI.SCOAFunctionId = @ToSCOAFunctionId
                              AND PPI.SCOAFundId = @ToSCOAFundID
                              AND PPI.SCOARegionId = @ToSCOARegion
                              AND PPI.DivisionId = @ToDivisionId
                              AND PPI.SCOACostingID = @ToSCOACostingId
                              AND PPIM.MonthID = 12
                              AND ISNULL(PPI.ProjectItemID, 0) = @ToProjectItemId;
                    END;

                    SELECT @planProjectItemIdForBudgetRegister = PlanProjectItem_ID
                    FROM dbo.Plan_ProjectItem
                    WHERE ProjectID = @ToProjectId
                          AND SCOAItemID = @ToSCOAItem
                          AND FinYear = @FinYear
                          AND SCOAFunctionId = @ToSCOAFunctionId
                          AND SCOAFundId = @ToSCOAFundID
                          AND SCOARegionId = @ToSCOARegion
                          AND DivisionId = @ToDivisionId
                          AND SCOACostingID = @ToSCOACostingId
                          AND ISNULL(ProjectItemID, 0) = @ToProjectItemId;;

                    --Insert into Plan_BudgetRegister  
                    SELECT TOP 1
                           @AvailableBudgetFromBudgetRegister = AvailableBudget,
                           @BudgetTransactionTypeId = BudgetTransactionTypeID
                    FROM dbo.Plan_BudgetRegister
                    WHERE PlanProjectItemID = @planProjectItemIdForBudgetRegister
                    ORDER BY DateCaptured DESC;

                    IF (@planProjectItemIdForBudgetRegister > 0)
                    BEGIN

                        INSERT INTO dbo.Plan_BudgetConsumption
                        (
                            FinYear,
                            PlanProjectItemID,
                            BudgetTransactionTypeID,
                            ModuleID,
                            PK_TransactionID,
                            TransactionTableName,
                            ConsumingTransactionAmount,
                            AdjustedTansactionAmount,
                            AvailableBudget,
                            ProcessingMonth,
                            BudgetConsumptionProcessID,
                            OriginalBudgetToDate,
                            AdjustedBudgetToDate,
                            CapturedExpenditureToDate,
                            ReserveToDate,
                            CommitToDate,
                            ActualToDate,
                            CapturerID,
                            DateCaptured,
							ConsumingTransactionAmountMultiYear,
							AvailableBudgetMultiYear,
							CapturedExpenditureToDateMultiYear,
							ReserveToDateMultiYear
                        )
                        SELECT TOP 1
                               @FinYear,
                               pdc.PlanProjectItemID,
                               @BudgetTransactionTypeIDAdjusted,
                               10,
                               @VirementId,
                               N'Plan_Virements',
                               @ToVirementAmount,
                               @ToVirementAmount,
                               (pdc.AvailableBudget + @ToVirementAmount),
                               @UserProcessingMonth,
                               201,
                               pdc.OriginalBudgetToDate,
						       ISNULL(pdc.AdjustedBudgetToDate, 0) + @DecToVirementAmount,
                               pdc.CapturedExpenditureToDate,
                               pdc.ReserveToDate,
                               pdc.CommitToDate,
                               pdc.ActualToDate,
                               @UserId,
                               GETDATE(),
							   pdc.ConsumingTransactionAmountMultiYear,
							   pdc.AvailableBudgetMultiYear,
							   pdc.CapturedExpenditureToDateMultiYear,
							   pdc.ReserveToDateMultiYear
                        FROM dbo.Plan_BudgetConsumption pdc
                        WHERE pdc.PlanProjectItemID = @planProjectItemIdForBudgetRegister
                        ORDER BY pdc.BudgetConsumption_ID DESC;

                        INSERT INTO dbo.Plan_BudgetRegister
                        (
                            PlanProjectItemID,
                            BudgetTransactionTypeID,
                            ModuleID,
                            PK_TransactionID,
                            TransactionTableName,
                            TransactionAmount,
                            AvailableBudget,
                            CapturerID,
                            DateCaptured,
                            FinYear
                        )
                        VALUES
                        (@planProjectItemIdForBudgetRegister, @BudgetTransactionTypeId, 10, @VirementId,
                         N'Plan_Virements', @ToVirementAmount,
                         (@AvailableBudgetFromBudgetRegister + @ToVirementAmount), @UserId, GETDATE(), @FinYear);

                    END;

                    SET @planProjectItemIdForBudgetRegister = 0;
                    SET @AvailableBudgetFromBudgetRegister = 0;

                END;
            END;

        END;

        /*UPDATE FUNDING SOURCE IN CASE SCOA FUND ID IS DIFFERENT*/
        IF (@FromSCOAFundID <> @ToSCOAFundID)
        BEGIN

            --Debit Transferred Funds  
            UPDATE pfs
            SET pfs.FundingSourceBudget = pfs.FundingSourceBudget - @FromVirementAmount
            FROM dbo.Plan_FundingSourceBudget_Detail pfs
                INNER JOIN dbo.Plan_FundingSourceBudget_Header pfsh
                    ON pfsh.FundingSourceBudgetHeader_ID = pfs.FundingSourceBudgetHeaderID
            WHERE pfsh.FinancialYear = @FinYear
                  AND pfs.ScoaID = @FromSCOAFundID;

            --Credit Transferred Funds  
            UPDATE pfs
            SET pfs.FundingSourceBudget = pfs.FundingSourceBudget + @ToVirementAmount
            FROM dbo.Plan_FundingSourceBudget_Detail pfs
                INNER JOIN dbo.Plan_FundingSourceBudget_Header pfsh
                    ON pfsh.FundingSourceBudgetHeader_ID = pfs.FundingSourceBudgetHeaderID
            WHERE pfsh.FinancialYear = @FinYear
                  AND pfs.ScoaID = @ToSCOAFundID;

        END;

        SET @ApprovalResult = N'success';
        COMMIT TRANSACTION;
    END TRY
    BEGIN CATCH
        DECLARE @Err NVARCHAR(1000);
        SET @Err = ERROR_MESSAGE();
        RAISERROR(@Err, 16, 1);
        SET @ApprovalResult = @Err;
        ROLLBACK TRAN;
    END CATCH;

    SELECT @ApprovalResult AS Result,
           @VirementId AS VirementId,
           @UserId AS Approver;


END;
GO

