/****** Object:  StoredProcedure [dbo].[Plan_UpdateProjectPlan]    Script Date: 2026/03/10 7:23:48 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:	Sahil Nagpal
-- Create date: --
-- Description:	INSERT data to Audit, UPDATE data to Plan_Project
-- EXEC Plan_UpdateProjectPlan 5304,2659
-- 20-06-2016 - SNagpal - Add Auditing Code
-- 16-08-2016 - SNagpal -- Add [ProjectStatus] ==5 for delete project
-- 22-11-2016 - Snagpal -- Remove SCOACosting as its now exist in Plan_projectItem
-- 28-04-2017 - Snagpal -- #53397 Remove IDPItemID,IsNonIDP,ItemID
-- 04-04-2019 - SNagpal : #86552 Add [] brackets for Audit database
-- =============================================
CREATE PROCEDURE [dbo].[Plan_UpdateProjectPlan]
    @ProjectID INT ,
    @ModifierID INT
AS
    BEGIN
        DECLARE @FMSAuditDBName NVARCHAR(100) ,
            @AuditUser NVARCHAR(250);

        SELECT  @FMSAuditDBName = KeyValue
        FROM    dbo.AAAA_ConfigSettings
        WHERE   KeyName = 'FMSAuditDatabaseName';

		SET @FMSAuditDBName = '[' + @FMSAuditDBName + ']';

        SELECT  @AuditUser = FirstName + ' ' + LastName
        FROM    dbo.User_UserDetail
        WHERE   [User_ID] = @ModifierID; 

        SET NOCOUNT ON;
        DECLARE @sql VARCHAR(MAX)= '';
        SET @sql = ' INSERT INTO  ' + @FMSAuditDBName
            + '.[dbo].[aPlan_Project]
	        ( AuditUserID ,
	          AuditDate ,
	          AuditUser ,
	          Project_ID ,
	          ProjectName ,
	          ProjectDesc ,
	          ProjectManagerID ,
	          SupplyChainOfficialID ,
	          CapitalOperation ,
	          CostEstimate ,
	          ScoaProjectID ,
	          EstimatedStartDate ,
	          EstimatedEndDate ,
	          ProjectStatus ,
	          CommencementDate ,
	          DateCaptured ,
	          CapturerID ,
	          DateModified ,
	          ModifierID ,
	          FinYear ,
	          ProjectCategoryID ,
	          Longitude ,
	          Latitude ,
	          ProgrammeManagerID ,
	          FinancialControllerID ,
	          ProjectTypeID ,
	          EstimatedDuration ,
	          ProjectDistinctionID ,
	          HistoricalProjectCode,
			  IsDeleted
	        )
			SELECT ''' + CAST(@ModifierID AS VARCHAR(100)) + ''','''
            + CONVERT(NVARCHAR(100), GETDATE(), 121) + ''','''
            + CAST(@AuditUser AS NVARCHAR(200)) + ''',
			  Project_ID ,
                ProjectName ,
                ProjectDesc ,
                ProjectManagerID ,
                SupplyChainOfficialID ,
                CapitalOperation ,
                CostEstimate ,
                ScoaProjectID ,
                EstimatedStartDate ,
                EstimatedEndDate ,
                ProjectStatus ,
                CommencementDate ,
                DateCaptured ,
                CapturerID ,
                DateModified ,
                ModifierID ,
                FinYear ,
                ProjectCategoryID ,
                Longitude ,
                Latitude ,
                ProgrammeManagerID ,
                FinancialControllerID ,
                ProjectTypeID ,
                EstimatedDuration ,
                ProjectDistinctionID ,
                HistoricalProjectCode ,
                IsDeleted
	   
	   FROM dbo.Plan_Project
	   Where Project_ID = ' + CAST(@ProjectID AS VARCHAR(10)) + '';

        EXEC sp_sqlexec @sql;	

	--Update ISDelete Key in Plan_Project given Project_ID

        UPDATE  Plan_Project
        SET     [IsDeleted] = 1 , [ProjectStatus]=5,
                DateModified = GETDATE() ,
                ModifierID = @ModifierID
        WHERE   Project_ID = @ProjectID;

    END;
GO

/****** Object:  StoredProcedure [dbo].[Plan_UpdateSCOAFundCapital_sp]    Script Date: 2026/03/10 7:23:49 AM ******/
SET ANSI_NULLS ON
GO

SET QUOTED_IDENTIFIER ON
GO


-- =============================================
-- Author:	Nirav Parikh
-- Create date: 02/11/2017
-- Description:	update SCOAFundCapital
-- Plan_UpdateSCOAFundCapital_sp 5370,1,'2016/2017',1,'D','EMS_QA_Audit','admin'
-- =============================================
CREATE PROCEDURE [dbo].[Plan_UpdateSCOAFundCapital_sp]
    @SCOAId INT ,
    @UserId INT ,
    @FinYear VARCHAR(9) ,
    @IsEnable BIT ,
    @FMSAuditDBName NVARCHAR(50) ,
    @AuditUser NVARCHAR(200)
AS
    BEGIN

        SET NOCOUNT ON;
        BEGIN TRY
            BEGIN TRANSACTION;
            DECLARE @ParentId INT = 0 ,
                @AuditGUID UNIQUEIDENTIFIER ,
                @Auditsql VARCHAR(MAX)= '' ,
                @CurrDate DATETIME = GETDATE();

            DECLARE @tempSCOATable AS TABLE
                (
                  RESULT VARCHAR(10) ,
                  SuccessMessage VARCHAR(100)
                );

			--Insert SCOAFundCapital If not Exists
            INSERT  INTO @tempSCOATable
                    EXEC Plan_InsertSCOAFundCapital_sp @SCOAId, @UserId,
                        @FinYear, @IsEnable, @AuditUser;

            WHILE @SCOAId > 0
                OR @ParentId > 0
                BEGIN

                    SELECT  @SCOAId = A.ScoaFundId ,
                            @ParentId = B.ScoaParentID
                    FROM    dbo.Const_PlanSCOAFundCapital A
                            INNER JOIN dbo.Const_SCOA_Funds_Structure B ON B.ScoaID = A.ScoaFundId
                    WHERE   A.ScoaFundId = @SCOAId
                            AND A.FinYear = @FinYear;

                    DECLARE @ActiveCnt INT = 0;

                    SELECT  @ActiveCnt = COUNT(A.ScoaFundId)
                    FROM    dbo.Const_PlanSCOAFundCapital A
                            INNER JOIN dbo.Const_SCOA_Funds_Structure B ON B.ScoaID = A.ScoaFundId
                    WHERE   A.ScoaFundId <> @SCOAId
                            AND B.ScoaParentID = @ParentId
                            AND A.IsEnable = 1
                            AND A.FinYear = @FinYear;

                    SET @AuditGUID = NEWID();
					--Insert into Audit Table
                    SET @Auditsql = ' INSERT  INTO ' + @FMSAuditDBName
                        + '.dbo.aConst_PlanSCOAFundCapital
							( AuditUserID, AuditDate, AuditUser, AuditGuid,
							  SCOAFundCapital_Id, ScoaFundId, IsEnable,BudgetType,FinYear,
							  CapturerID, DateCaptured, ModifierID, DateModified
							)
								SELECT ''' + CAST(@UserId AS VARCHAR(100))
                        + ''',''' + CONVERT(NVARCHAR(100), @CurrDate, 121)
                        + ''',''' + CAST(@AuditUser AS NVARCHAR(200))
                        + ''',''' + CAST(@AuditGUID AS NVARCHAR(200))
                        + ''',
								 SCOAFundCapital_Id, ScoaFundId, IsEnable,BudgetType,FinYear,
								CapturerID, DateCaptured, ModifierID, DateModified
								FROM Const_PlanSCOAFundCapital WHERE ScoaFundId= '''
                        + CAST(@SCOAId AS NVARCHAR(200)) + '''';

                    EXEC sp_sqlexec @Auditsql;

					-- Update to Disable @ScoaID
                    UPDATE  Const_PlanSCOAFundCapital
                    SET     IsEnable = @IsEnable ,
                            ModifierID = @UserId ,
                            DateModified = ''
                            + CONVERT(NVARCHAR(100), @CurrDate, 121) + ''
                    WHERE   ScoaFundId = @SCOAId
                            AND FinYear = @FinYear;
  
                    INSERT  INTO dbo.Sys_AuditLog
                            ( UserID ,
                              AuditDesc ,
                              AuditDate ,
                              AuditComment ,
                              ActiveFinYear_UserFinYear ,
                              TableName ,
                              ModuleID ,
                              RecordID ,
                              AuditGuid
                            )
                    VALUES  ( @UserId ,
                              'Update Const_PlanSCOAFundCapital' ,
                              '' + CONVERT(NVARCHAR(100), @CurrDate, 121) + '' ,
                              'Update SCOA Fund for Capital' ,
                              @FinYear ,
                              'Const_PlanSCOAFundCapital' ,
                              10 ,
                              @SCOAId ,
                              @AuditGUID
                            );

                    IF @ActiveCnt = 0
                        BEGIN
                            SET @SCOAId = @ParentId;
 
                        END;
                    ELSE
                        BEGIN
                            SET @SCOAId = 0;
                            SET @ParentId = 0;
                        END;
                END;

            COMMIT TRANSACTION;
	
            SELECT  'Success' AS Result ,
                    'SCOA Fund Capital Updated' AS SuccessMessage;
        END TRY
        BEGIN CATCH
            IF @@Trancount > 0
                BEGIN 
                    ROLLBACK TRANSACTION;
                    INSERT  INTO Sys_ErrorLog
                            ( moduleName ,
                              pageName ,
                              procedureName ,
                              errorMessage ,
                              errorType ,
                              detailedErrorMessage ,
                              errorDate ,
                              userName
                            )
                    VALUES  ( 'Planning' ,
                              'SQL Server' ,
                              'Plan_UpdateSCOAFundCapital_sp' ,
                              ERROR_MESSAGE() ,
                              'SQL' ,
                              ERROR_MESSAGE() ,
                              '' + CONVERT(NVARCHAR(100), @CurrDate, 121) + '' ,
                              @AuditUser
                            );
		
                    DECLARE @Err NVARCHAR(1000);
                    SET @Err = ERROR_MESSAGE();
                    RAISERROR (@Err, 16,1);
		
                    SELECT  @Err AS 'Result' ,
                            'An Error Occured' AS SuccessMessage;
                END;
        END CATCH;
    END;
GO

