	@FinYear VARCHAR(9),
	@IsEnable BIT,
	@CreditDebit VARCHAR(50),
	@FMSAuditDBName NVARCHAR(50) ,
	@AuditUser NVARCHAR(200)
AS
BEGIN

	SET NOCOUNT ON;
	BEGIN TRY
	BEGIN TRANSACTION
DECLARE @ParentId INT = 0, @AuditGUID UNIQUEIDENTIFIER, @Auditsql VARCHAR(MAX)= '', @CurrDate DATETIME = GETDATE();

DECLARE @tempSCOATable AS TABLE (
RESULT VARCHAR(10), SuccessMessage VARCHAR(100))

--Insert SCOAItemAssets If not Exists
INSERT INTO @tempSCOATable
EXEC Plan_InsertSCOAItemAssetFBS_sp @SCOAId,@UserId,@FinYear,@IsEnable,@CreditDebit,@AuditUser;

WHILE @SCOAId > 0
    OR @ParentId > 0
    BEGIN

        SELECT  @SCOAId = A.ScoaItemId ,
                @ParentId = B.ScoaParentID
        FROM    dbo.Const_PlanSCOAItemAssetFBS A
                INNER JOIN dbo.Const_SCOA_Structure B ON B.ScoaID = A.ScoaItemId
        WHERE   A.ScoaItemId = @SCOAId AND A.FinYear=@FinYear;

        DECLARE @ActiveCnt INT = 0;

        SELECT  @ActiveCnt = COUNT(A.ScoaItemId)
        FROM    dbo.Const_PlanSCOAItemAssetFBS A
                INNER JOIN dbo.Const_SCOA_Structure B ON B.ScoaID = A.ScoaItemId
        WHERE   A.ScoaItemId <> @SCOAId
                AND B.ScoaParentID = @ParentId
                AND A.IsEnable = 1 AND A.FinYear=@FinYear;

SET @AuditGUID = NEWID();
--Insert into Audit Table
SET @Auditsql = ' INSERT  INTO ' + @FMSAuditDBName
            + '.dbo.aConst_PlanSCOAItemAssetFBS
        ( AuditUserID, AuditDate, AuditUser, AuditGuid,
          SCOAItemAssetFBS_Id, ScoaItemId, IsEnable,BudgetType,CreditDebit,FinYear,
          CapturerID, DateCaptured, ModifierID, DateModified
        )
			SELECT ''' + CAST(@UserId AS VARCHAR(100)) + ''','''
            + CONVERT(NVARCHAR(100), @CurrDate, 121) + ''','''
            + CAST(@AuditUser AS NVARCHAR(200)) + ''','''
            + CAST(@AuditGUID AS NVARCHAR(200)) + ''',
			 SCOAItemAssetFBS_Id, ScoaItemId, IsEnable,BudgetType,CreditDebit,FinYear,
            CapturerID, DateCaptured, ModifierID, DateModified
		    FROM Const_PlanSCOAItemAssetFBS WHERE ScoaItemId= '''+ CAST(@SCOAId AS NVARCHAR(200)) + '''';

EXEC sp_sqlexec @Auditsql;

  -- Update to Disable @ScoaID
  UPDATE Const_PlanSCOAItemAssetFBS SET IsEnable=@IsEnable, CreditDebit = @CreditDebit, ModifierID=@UserId, DateModified='' + CONVERT(NVARCHAR(100), @CurrDate, 121) + '' 
  WHERE ScoaItemId=@SCOAId AND FinYear=@FinYear
  
