          ( UserID ,AuditDesc ,AuditDate ,AuditComment ,ActiveFinYear_UserFinYear ,TableName ,ModuleID ,RecordID ,AuditGuid
          )
		Values (@UserId,'Update Const_PlanSCOAItemAssetFBS','' + CONVERT(NVARCHAR(100), @CurrDate, 121) + '','Update SCOA Item Assets for FBS', @FinYear,'Const_PlanSCOAItemAssetFBS',10,@SCOAId,@AuditGUID)

        IF @ActiveCnt = 0
